INSERT INTO public.movies VALUES (965, 310, '브루스 올마이티', '["Fantasy", "Comedy"]', NULL, '[]', '무능한 소시민이 전지전능한 능력을 얻어 능력을 남발하고 다니다 곧 "신의 일에도 여러 가지 힘든 일이 따른다"는 걸 알게 되는 것. 또한 전지전능한 능력으로도 사랑하는 사람의 마음과 자유 의지는 자기 뜻대로 할 수 없다는 것을 깨닫고 자신의 곁을 떠난 애인을 위해 신의 자리를 포기하기로 한다. 그때 마침 휴가 간 신이 돌아오고, 다시 평범한 리포터로 돌아와 깨달음을 얻고 행복한 삶을 되찾는다.', 'https://image.tmdb.org/t/p/w500/bIqFRqtvE3pDSgamXGIAbVCxAKG.jpg', 2003, 0, 0, '2026-06-06 13:25:33.477431', 'US');
INSERT INTO public.movies VALUES (5, 1380291, '톰 클랜시의 잭 라이언: 고스트 워', '["Action", "Thriller"]', 'Andrew Bernstein', '["John Krasinski", "Wendell Pierce", "Sienna Miller", "Michael Kelly", "Max Beesley"]', '잭 라이언은 국제 비밀 작전으로 치명적인 음모의 실체가 드러나면서 마지못해 다시 첩보의 세계로 끌려 들어간다. 시간과의 싸움 속에서 그는 CIA 동료 마이크 노벰버, 제임스 그리어, 그리고 냉철한 MI6 요원 에마 말로와 함께 통제권을 벗어난 블랙옵스 부대에 맞서며, 지금껏 가장 뼈아프고 혹독한 작전을 펼쳐나간다.', 'https://image.tmdb.org/t/p/w500/3PufRWSVgSVwIr9M5YOmx4gu5Fu.jpg', 2026, 0, 0, '2026-06-06 13:24:56.330954', 'US');
INSERT INTO public.movies VALUES (3, 1304313, '리 크로닌의 미이라', '["Horror", "Mystery"]', 'Lee Cronin', '["Jack Reynor", "Laia Costa", "May Calamawy", "Natalie Grace", "Shylo Molina"]', '한 기자의 어린 딸이 흔적도 없이 사막으로 사라진다. 그리고 8년 후, 산산이 부서진 가족은 그녀가 다시 돌아왔다는 소식에 충격을 받는다. 하지만 기쁨으로 가득해야 할 재회는 곧 살아 있는 악몽으로 변해간다.', 'https://image.tmdb.org/t/p/w500/zXlwtzXP80yc3X0VokdxvmsFQfw.jpg', 2026, 0, 0, '2026-06-06 13:24:56.323183', 'US');
INSERT INTO public.movies VALUES (16, 1228710, '만달로리안과 그로구', '["Action", "Adventure", "Sci-Fi"]', 'Jon Favreau', '["Pedro Pascal", "Jeremy Allen White", "Sigourney Weaver", "Brendan Wayne", "Lateef Crowder"]', '은하계를 누비는 현상금 사냥꾼 ‘딘 자린’ & 치명적인 귀여움의 ‘그로구’', 'https://image.tmdb.org/t/p/w500/tMP99wq45GQMoeZwITgjAS8Wihm.jpg', 2026, 0, 0, '2026-06-06 13:24:56.375925', 'US');
INSERT INTO public.movies VALUES (4, 1083381, '백룸', '["Horror", "Mystery", "Sci-Fi"]', 'Kane Parsons', '["Chiwetel Ejiofor", "Renate Reinsve", "Mark Duplass", "Finn Bennett", "Lukita Maxwell"]', '존재해서는 안 될 미지의 공간 ‘백룸’ 속으로 사라진 사람들의 극한 상황을 그린 공간 스릴러', 'https://image.tmdb.org/t/p/w500/c3Cb7h4ecFsGfUM02KF638kbbtC.jpg', 2026, 0, 0, '2026-06-06 13:24:56.327334', 'US');
INSERT INTO public.movies VALUES (909, 568949, 'Khejdi', '[]', 'Rohit Dwivedi', '[]', NULL, 'https://image.tmdb.org/t/p/w500/e25BBKlSQjRKQFCcLhyIABSD90O.jpg', 2018, 0, 0, '2026-06-06 13:25:31.170324', 'IN');
INSERT INTO public.movies VALUES (12, 1007757, '뒤바뀐 친구들의 신비한 모험', '["Adventure", "Animation", "Family", "Fantasy"]', 'Nathan Greno', '["Michael B. Jordan", "Juno Temple", "Tracy Morgan", "Cedric the Entertainer", "Justina Machado"]', '갑자기 몸이 뒤바뀌게 된 작은 숲속 생물과 위풍당당한 새. 일생일대의 모험을 헤쳐나가기 위해 어쩔 수 없이 힘을 합친다.', 'https://image.tmdb.org/t/p/w500/uv0iRQXDbtWHo1zPk3TZNo4Biti.jpg', 2026, 5, 1, '2026-06-06 13:24:56.359062', 'US');
INSERT INTO public.movies VALUES (15, 1430077, '호쿰', '["Horror"]', 'Damian McCarthy', '["Adam Scott", "Peter Coonan", "David Wilmot", "Florence Ordesh", "Will O''Connell"]', '소설가 옴 바우만은 부모님의 유골을 뿌리기 위해 외딴 숙소를 찾지만, 이내 허니문 스위트룸에 출몰한다는 마녀의 이야기에 사로잡힌다. 기괴한 환영과 충격적인 실종 사건이 이어지면서, 그는 결국 자신의 과거 속 어두운 구석을 마주해야만 하는 상황에 직면한다.', 'https://image.tmdb.org/t/p/w500/jKPWwsbAM6HKURPYQ1eG8DmKMKn.jpg', 2026, 0, 0, '2026-06-06 13:24:56.371934', 'US');
INSERT INTO public.movies VALUES (9, 1065834, 'കാട്ടാളൻ', '["Action", "Thriller"]', 'Paul George', '["Antony Varghese", "Sunil Varma", "Dushara Vijayan", "Jagadish", "Kabir Duhan Singh"]', NULL, 'https://image.tmdb.org/t/p/w500/9OA6y2GdbXuJ5PAMMMawNBIkrZA.jpg', 2026, 0, 0, '2026-06-06 13:24:56.34652', 'IN');
INSERT INTO public.movies VALUES (3924, 246403, '터스크', '["Comedy", "Horror"]', NULL, '[]', '팟캐스터인 월레스는 전 세계를 탐험한 베테랑 하워드를 인터뷰하러 캐나다로 떠난다.  전혀 들어 본 적 없는 놀라운 이야기를 풀어내는 하워드의 이야기에 월레스는 감탄한다.  월레스는 술을 몇 잔 마신 후 다음 날 하워드의 집에서 깨어나지만 몸이 잘 움직여지지 않는 것을 깨닫는다.', 'https://image.tmdb.org/t/p/w500/qqBBInpwKF0HqaatUwEal1me5xE.jpg', 2014, 0, 0, '2026-06-08 06:24:39.423151', 'US');
INSERT INTO public.movies VALUES (13, 1122573, '인 더 그레이', '["Action", "Thriller"]', 'Guy Ritchie', '["Henry Cavill", "Jake Gyllenhaal", "Eiza González", "Carlos Bardem", "Michael Vu"]', '그림자 속에서 은밀히 살아가는 최정예 비밀 작전팀이 있다. 냉혹한 독재자가 10억 달러에 달하는 재산을 훔치자 그들은 그것을 되찾기 위해 투입된다. 그러나 그 임무는 전략과 기만, 생존이 뒤엉킨 치명적인 게임으로 번지는 불가능한 강탈 작전이 된다.', 'https://image.tmdb.org/t/p/w500/dQgIcW6Th08kMRf2HBoYWoFE6OD.jpg', 2026, 0, 0, '2026-06-06 13:24:56.363304', 'GB');
INSERT INTO public.movies VALUES (11, 1523145, 'Твоё сердце будет разбито', '["Romance", "Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/iGpMm603GUKH2SiXB2S5m4sZ17t.jpg', 2026, 0, 0, '2026-06-06 13:24:56.354903', 'US');
INSERT INTO public.movies VALUES (89, 1198994, '직장상사 길들이기', '["Horror", "Thriller", "Comedy"]', 'Sam Raimi', '["Rachel McAdams", "Dylan O''Brien", "Edyll Ismail", "Dennis Haysbert", "Xavier Samuel"]', '승진만을 꿈꾸는 7년차 직장인 린다(레이첼 맥아담스)는 자신을 무시하는 상사 브래들리(딜런 오브라이언)와  출장 도중 비행기 추락 사고로 무인도에 단둘이 고립된다. 하지만 와이파이도, 인사팀도, 직급도 없는 야생의 섬에서 두 사람의 권력관계는 완전히 뒤집히기 시작한다. 회사에서는 절대적인 권력자였던 브래들리가 부상으로 인해 생존 능력 제로로 전락한다. 반면 그동안  억눌려 있던 린다는 뛰어난 생존 능력으로 상황을 장악하기 시작한다. 그러던 어느 날, 누군가 섬을 찾아오면서  상황은 예측 불가능하게 흘러가는데….', 'https://image.tmdb.org/t/p/w500/kpOHAiCiIBa0yPtOqSp99NxhwUF.jpg', 2026, 0, 0, '2026-06-06 13:24:59.475931', 'US');
INSERT INTO public.movies VALUES (14, 1057265, 'పెద్ది', '["Action", "Drama"]', 'Buchi Babu Sana', '["Ram Charan", "Janhvi Kapoor", "Shiva Rajkumar", "Jagapati Babu", "Divyendu Sharma"]', NULL, 'https://image.tmdb.org/t/p/w500/kJAJNNBYlbqAcpTDxBNnaILSMTy.jpg', 2026, 0, 0, '2026-06-06 13:24:56.367475', 'IN');
INSERT INTO public.movies VALUES (966, 50014, '헬프', '["Drama"]', NULL, '[]', '1963년, 미국 남부 미시시피 잭슨  흑인 가정부는 백인 주인과 화장실도 같이 쓸 수 없다?!  아무도 가정부의 삶에 대해 묻지 않았다. 그녀가 책을 쓰기 전까지는…  돈 많은 남자와 결혼해 정원과 가정부가 딸린 집의 안주인이 되는 게 최고의 삶이라 여기는 친구들과 달리 대학 졸업 후 작가의 꿈을 이루기 위해 지역 신문사에 취직한 ‘스키터(엠마 스톤)’. 살림 정보 칼럼의 대필을 맡게 된 그녀는 베테랑 가정부 ‘에이빌린(바이올라 데이비스)’에게 도움을 요청한다.  다른 인생은 꿈꿔보지도 못한 채 가정부가 되어 17명의 백인 아이를 헌신적으로 돌봤지만 정작 자신의 아들은 사고로 잃은 ‘에이빌린’. ‘스키터’에게 살림 노하우를 알려주던 그녀는 어느 누구도 관심 갖지 않았던 자신과 흑인 가정부들의 인생을 책으로 써보자는 위험한 제안을 받는다.  때 마침 주인집의 화장실을 썼다는 황당한 이유로 쫓겨난 가정부 ‘미니(옥타비아 스펜서)’가 두 여자의 아슬아슬하지만 유쾌한 반란에 합류한다. 차별과 불만을 이야기 하는 것조차 불법이 되고 생명을 위협받는 일이 되는 시대에, 태어나 처음으로 누군가에게 자신들의 이야기를 털어 놓기 시작하는 ‘에이빌린’과 ‘미니’. 그녀들의 용기 있는 고백은 세상을 발칵 뒤집을 만한 책을 탄생시키는데…', 'https://image.tmdb.org/t/p/w500/qMVZtwZIU9oussRb8al2Gb0YPQL.jpg', 2011, 0, 0, '2026-06-06 13:25:33.480327', 'US');
