INSERT INTO public.movies VALUES (31, 405818, '도어 2: 도쿄 다이어리', '["Drama", "Thriller"]', 'Banmei Takahashi', '["Chikako Aoyama", "Joe Yamanaka", "Shingo Kazami", "Chiharu Iwamoto", "Yukino Tobita"]', NULL, 'https://image.tmdb.org/t/p/w500/4AMv53knrYIdBStpldgRY8eQ7Bx.jpg', 1991, 4.5, 1, '2026-06-06 13:24:57.145822', 'JP');
INSERT INTO public.movies VALUES (25, 976912, '그래픽 디자이어', '["Thriller", "Crime"]', 'Andy Edwards', '["David Wayman", "Sian Altman", "May Kelly", "Ocean M Harris", "Valis Volkova"]', '친구의 소개로 데이팅 앱에 가입한 ''프랭크''  연인 몰래 앱을 통해 만난 여성에게 강한 성적 끌림을 느낀 그는 다시 그녀를 찾지만 여자는 사라지고 계정도 비활성화된다.  현실과 가상을 넘나들며 그녀를 찾아 헤매는 동안 그는 점점 데이팅 앱에 중독되고 결국 예기치 못한 사건에 휘말리고 마는데∙∙∙', 'https://image.tmdb.org/t/p/w500/8EHehEMsJVIPp2n2ROhZU8dbpJC.jpg', 2023, 0, 0, '2026-06-06 13:24:57.128841', 'GB');
INSERT INTO public.movies VALUES (28, 1367220, 'கருப்பு', '["Action", "Fantasy"]', 'RJ Balaji', '["Suriya", "Trisha Krishnan", "RJ Balaji", "Indrans", "Anagha Maya Ravi"]', NULL, 'https://image.tmdb.org/t/p/w500/4KZXlZ5tTT6ghbW77gS4hSLkCd7.jpg', 2026, 5, 1, '2026-06-06 13:24:57.136272', 'IN');
INSERT INTO public.movies VALUES (30, 1241752, '홀로 남은 아내: 리타', '["Drama"]', NULL, '[]', '해외로 떠난 남편을 기다리며 홀로 남겨진 리타. 끝없는 외로움은 그녀를 서서히 다른 사람의 품으로 이끌고, 남편 역시 타국에서 비밀스러운 위안을 찾는다. 재회한 두 사람은 아무 일도 없었던 듯 일상을 이어가려 하는데, 둘의 결혼은 결국 파국을 맞는다.', 'https://image.tmdb.org/t/p/w500/grIFQLXXwQmjvYYfXVXCgGTMUWw.jpg', 2024, 0, 0, '2026-06-06 13:24:57.143007', 'US');
INSERT INTO public.movies VALUES (22, 1371023, 'चाँद मेरा दिल', '["Romance", "Drama"]', 'Vivek Soni', '["Ananya Panday", "Lakshya Lalwani", "Aastha Singh", "Paresh Pahuja", "Manish Chaudhary"]', NULL, 'https://image.tmdb.org/t/p/w500/9LPkXJustudEBgPZEm9tgDx5KtC.jpg', 2026, 0, 0, '2026-06-06 13:24:57.121108', 'IN');
INSERT INTO public.movies VALUES (8681, 1154215, '엘리야스', '["Action", "Thriller"]', 'Florent-Emilio Siri', '["Roschdy Zem", "Laëtitia Eïdo", "Nabil Elouahabi", "Sherwan Haji", "Dimitri Storoge"]', '중동 VIP 가족의 경호를 맡은 특수부대 출신 ''엘리야스''  의외의 순간 VIP의 딸을 노리는 암살단의 습격을 받는다.  피 튀기는 총격전이 이어지고, 저택은 초토화된다.  자살 암살단으로부터 필사적으로 가족을 경호하지만,  이내 VIP의 딸이 납치되고 마는데…  한계 없는 미친 액션을 만난다!', 'https://image.tmdb.org/t/p/w500/lZ8IXEkaNhZRDLQ0P3oF7cDAigC.jpg', 2024, 0, 0, '2026-06-08 07:26:59.618605', 'FR');
INSERT INTO public.movies VALUES (136, 1368337, '오디세이', '["Adventure", "Action", "Fantasy"]', 'Christopher Nolan', '["Matt Damon", "Tom Holland", "Anne Hathaway", "Robert Pattinson", "Lupita Nyong''o"]', '현시대 영화계 최고의 거장 크리스토퍼 놀란 감독 최초의 시대극. 영화 전편을 IMAX 필름 카메라로 촬영한 최초의 영화. 호메로스의 고전이 전세계를 배경으로 한 신화적인 액션 대서사시로 다시 탄생하다.', 'https://image.tmdb.org/t/p/w500/8ze9OcVuFiy94s6FFPvsn4oC2e1.jpg', 2026, 0, 0, '2026-06-06 13:25:01.043211', 'GB');
INSERT INTO public.movies VALUES (3986, 8363, '슈퍼배드', '["Comedy"]', NULL, '[]', '머리 속엔 오직 “SEX” 생각뿐인 단세포 녀석들!  고등학교 졸업을 2주 앞둔 단짝 친구 세스와 에반은, 서로 다른 대학으로 진학하여 헤어지기 전에 마지막으로 기억에 남을 이벤트인 총각딱지 떼기를 계획한다.  하지만 변변한 여자친구 조차 없는 이들에게는 불가능해 보이는 계획이다.  우연히 세스가 짝사랑하는 줄스의 집에서 열리는 와일드 파티에 초대되는데, 조건은 파티에 사용될 술을 사가지고 와야 한다는 것이다.  이때 역시 어리버리한 친구 포겔이 가짜 신분증을 이용해 술을 사는 것을 제안한다.  주류가게에서 가짜 신분증으로 술을 살 때까지 만해도 모든 것이 순조롭게 풀리는 것처럼 보였지만, 현장에 도둑이 들어오면서 갑자기 모든 일이 꼬이기 시작하는데...', 'https://image.tmdb.org/t/p/w500/ek8e8txUyUwd2BNqj6lFEerJfbq.jpg', 2007, 0, 0, '2026-06-08 06:24:42.007232', 'US');
INSERT INTO public.movies VALUES (35, 460465, '모탈 컴뱃', '["Action", "Fantasy", "Adventure"]', 'Simon McQuoid', '["Lewis Tan", "Jessica McNamee", "Mehcad Brooks", "Josh Lawson", "Ludi Lin"]', '어스렐름와 아웃월드의 최강 챔피언들이 지구의 운명을 걸고 벌이는 서바이벌 대혈전 모탈 컴뱃. MMA 격투 선수 콜 영은 대전을 앞두고 선택 받은 전사들을 사전에 제거하려는 서브제로의 공격을 받는다. 지구와 가족을 보호하고 자기 혈통의 비밀을 알아내기 위해 모탈 컴뱃 토너먼트에 참가해 죽음의 전투를 치러야 한다!', 'https://image.tmdb.org/t/p/w500/3dTg1pgasstOa0XJTwt3dBFHjFf.jpg', 2021, 0, 0, '2026-06-06 13:24:57.156708', 'US');
INSERT INTO public.movies VALUES (36, 28322, 'Vacanze per un massacro', '["Thriller", "Action", "Crime"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/arRNmW27fs1TFsIBOwPYCfZQFJC.jpg', 1980, 0, 0, '2026-06-06 13:24:57.159239', 'US');
INSERT INTO public.movies VALUES (296, 346698, '바비', '["Comedy", "Adventure", "Fantasy"]', 'Greta Gerwig', '["Margot Robbie", "Ryan Gosling", "America Ferrera", "Ariana Greenblatt", "Issa Rae"]', '원하는 무엇이든 될 수 있는 바비랜드에서 살아가던 바비가 현실 세계와 이어진 포털의 균열을 발견하게 되고, 이를 해결하기 위해 켄과 예기치 못한 여정을 떠나면서 펼쳐지는 이야기', 'https://image.tmdb.org/t/p/w500/h3mUJ9WEJ8PzA450ad4hrjsaiqG.jpg', 2023, 0, 0, '2026-06-06 13:25:07.188625', 'US');
INSERT INTO public.movies VALUES (47, 235271, '애딕티드', '["Drama", "Thriller"]', 'Bille Woodruff', '["Sharon Leal", "Boris Kodjoe", "John Newberg", "Brandon Gonzales", "Cameron Mills"]', '성적 욕망에 사로잡혀 불륜을 일삼는 여자가 파멸직전 상황에 이르지만 가족의 사랑으로 제자리로 돌아가 치료를 시작하게 된다는 내용', 'https://image.tmdb.org/t/p/w500/fAERrD6vvmznDoL99wlgjhSfPcH.jpg', 2014, 0, 0, '2026-06-06 13:24:57.908427', 'US');
INSERT INTO public.movies VALUES (37, 1472951, '킬링 미션', '["Action", "Thriller"]', NULL, '[]', '베테랑 요원 릴리가 납치된 남편을 구하고자 범죄 조직 심장부로 잠입하지만, 이어지는 의문의 지시에 따라 지하 세계의 잔혹한 음모에 휘말린다, 정교한 함정 속에서 목숨을 건 추격전이 펼쳐지고 마주한 진실이 모든 것을 뒤흔든다.', 'https://image.tmdb.org/t/p/w500/HjapTwwYaWBz4qC2Lg3mKqFlNJ.jpg', 2026, 0, 0, '2026-06-06 13:24:57.161655', 'US');
INSERT INTO public.movies VALUES (44, 1103473, 'ಕೆಡಿ - ದಿ ಡೆವಿಲ್', '["History", "Crime", "Action", "Fantasy"]', 'Prem', '["Dhruva Sarja", "Shilpa Shetty Kundra", "Sanjay Dutt", "Reeshma Nanaiah", "V. Ravichandran"]', NULL, 'https://image.tmdb.org/t/p/w500/9cgwiPHZ57NjI0RKb2yIu8mUnNs.jpg', 2026, 0, 0, '2026-06-06 13:24:57.901401', 'IN');
INSERT INTO public.movies VALUES (45, 1318447, '정점', '["Action", "Thriller"]', 'Baltasar Kormákur', '["Charlize Theron", "Taron Egerton", "Eric Bana", "Caitlin Stasey", "Bessie Holland"]', '슬픔에 잠긴 채 호주 오지로 모험을 떠난 여성. 홀로 자신의 한계를 밀어붙이던 중 목숨을 노리는 살인마를 맞닥뜨리고, 그가 교활하게 설계한 뒤틀린 게임에 속수무책으로 휘말린다.', 'https://image.tmdb.org/t/p/w500/wGHGVAJGTn2BqsuFfPK8lzPiKjH.jpg', 2026, 0, 0, '2026-06-06 13:24:57.903754', 'US');
INSERT INTO public.movies VALUES (40, 1390300, '오버 유어 데드 바디', '["Action", "Comedy", "Thriller"]', 'Jorma Taccone', '["Samara Weaving", "Jason Segel", "Paul Guilfoyle", "Timothy Olyphant", "Keith Jardine"]', '관계가 삐걱거리는 한 커플이 ‘다시 가까워지기’ 위해 외딴 산장으로 향하지만, 사실 둘 다 서로를 죽이려는 은밀한 속셈을 품고 있다.', 'https://image.tmdb.org/t/p/w500/kZCauMzAt9eMAhLMopCqnFw1Q5k.jpg', 2026, 0, 0, '2026-06-06 13:24:57.16865', 'US');
INSERT INTO public.movies VALUES (3987, 526024, '보이 언던', '["Drama"]', NULL, '[]', '전날 밤 게이 클럽에서 만난 두 청년이 밤을 함께 보낸다. 하지만 다음 날 자신의 이름이나 과거를 기억하지 못한채 깨어난 주인공은, 자신의 신원이나 기억의 조각들 사이에서 진실을 찾기 위해 노력하는데...', 'https://image.tmdb.org/t/p/w500/eB96AxyybCIWVKNJYDRp7okiH1X.jpg', 2017, 0, 0, '2026-06-08 06:24:42.009832', 'US');
INSERT INTO public.movies VALUES (8682, 416148, '로코', '["Documentary"]', 'Alban Teurlai', '["Rocco Siffredi", "Kelly Stafford", "Rosa Caracciolo", "Gabriele Galetta", "Mark Spiegler"]', '이탈리아의 포르노 스타 로코 시프레디가 주인공인 다큐멘터리 영화. 전설적 배우로 평가받는 그가 은퇴 전 마지막 해에 벌인 활동을 밀착 취재한다.', 'https://image.tmdb.org/t/p/w500/wGVnyKJm37uXqL1wAeLfnGuYw0m.jpg', 2016, 0, 0, '2026-06-08 07:27:00.275532', 'FR');
INSERT INTO public.movies VALUES (46, 1297842, '고트: 더 레전드', '["Animation", "Comedy", "Family"]', 'Tyree Dillihay', '["Caleb McLaughlin", "Gabrielle Union", "Stephen Curry", "Aaron Pierre", "Nicola Coughlan"]', '큰 꿈을 품은 작은 염소 윌은 세계에서 가장 빠르고 사나운 동물들이 지배하는 고강도 혼성 풀컨택트 스포츠 ‘로어볼’의 프로 리그에 합류할 단 한 번의 기회를 얻게 된다. 새 팀의 동료들은 작은 염소가 팀 명단에 오른 것을 탐탁지 않게 여기지만, 윌은 ‘작아도 충분히 해낼 수 있다’는 것을 증명하고 스포츠의 판도를 바꾸겠다는 굳은 결의를 다진다. 이를 위해 그는 지금까지 한 번도 해본 적 없는 도전에 나서야 한다.', 'https://image.tmdb.org/t/p/w500/otP94vckeMXAgQxzhcRkZSeSmYv.jpg', 2026, 0, 0, '2026-06-06 13:24:57.906011', 'US');
INSERT INTO public.movies VALUES (8683, 1266781, 'Natacha (presque) hôtesse de l''air', '["Comedy", "Adventure"]', 'Noémie Saglio', '["Camille Lou", "Vincent Dedienne", "Didier Bourdon", "Elsa Zylberstein", "Antoine Gouy"]', NULL, 'https://image.tmdb.org/t/p/w500/mvqZY9g8yxwlCLLLvOIupQEwjzw.jpg', 2025, 0, 0, '2026-06-08 07:27:00.941328', 'FR');
INSERT INTO public.movies VALUES (42, 936075, '마이클', '["Drama"]', 'Antoine Fuqua', '["Jaafar Jackson", "Colman Domingo", "Nia Long", "Juliano Krue Valdi", "Miles Teller"]', '어린 나이에 형제들과 ‘잭슨 파이브’ 그룹의 막내로 데뷔하자마자 음악적 천재성과 스타성으로 주목을 받은 ‘마이클 잭슨’. 전세계적인 스타로 성공하지만, 그는 가족에 대한 책임감과 자신의 음악적 정체성 사이에서 고민에 빠지게 된다.', 'https://image.tmdb.org/t/p/w500/piMZqtd0gGS7OgkhDwiQ7vVViBQ.jpg', 2026, 0, 0, '2026-06-06 13:24:57.896461', 'US');
INSERT INTO public.movies VALUES (43, 104594, '盤絲洞', '["Fantasy", "Adventure", "Action"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/lEvNC9J2UzWc3PkptXMGcGVxSNq.jpg', 1967, 0, 0, '2026-06-06 13:24:57.898929', 'US');
INSERT INTO public.movies VALUES (8684, 42726, '남과 여', '["Drama", "Romance"]', 'Claude Lelouch', '["Anouk Aimée", "Jean-Louis Trintignant", "Pierre Barouh", "Valérie Lagrange", "Antoine Sire"]', '배우자를 잃은 파리 출신의 두 남녀가 새로운 감정적 교감을 시도하는 를루슈의 1966년 고전 로맨틱 드라마. 끌림과 죄책감, 그리고 기억의 교차가 분명하게 드러나는 수작으로 아누크 에메와 장루이 트랭티냥은 과거의 괴로움을 안은 채 조심스럽게 사랑을 시작하는 연인을 아름답게 연기한다. 주제음악으로 전세계 시네필들의 뇌리에 각인된 고전 중의 고전.', 'https://image.tmdb.org/t/p/w500/qHC9nCGPeoNmw41zKWk1lBqElqq.jpg', 1966, 0, 0, '2026-06-08 07:27:01.599267', 'FR');
INSERT INTO public.movies VALUES (38, 1320660, 'पति पत्नी और वो दो', '["Comedy"]', 'Mudassar Aziz', '["Ayushmann Khurrana", "Wamiqa Gabbi", "Rakul Preet Singh", "Sara Ali Khan", "Vijay Raaz"]', NULL, 'https://image.tmdb.org/t/p/w500/5MweEeMzPbueb65BcJpdiy0ihwU.jpg', 2026, 0, 0, '2026-06-06 13:24:57.163944', 'IN');
INSERT INTO public.movies VALUES (4253, 611861, '음란 과외2', '["Romance", "Drama"]', 'Choi Woo-seong', '["Kim Soo-ji", "Yoo Jung"]', '사수생 유정은 공부 보다는 섹스에 관심이 많다. 남친이 소개 시켜준 과외 선생님의 은밀하고 특별한 과외 덕에 성적이 쑥쑥 올라간다.INSERT INTO public.movies VALUES (985, 141052, '저스티스 리그', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '인류의 수호자인 슈퍼맨이 사라진 틈을 노리고 ‘마더박스’를 차지하기 위해 빌런 스테픈울프가 악마군단을 이끌고 지구에 온다. 마더박스는 시간과 공간, 에너지, 중력을 통제하는 범우주적인 능력으로 행성의 파괴마저도 초래하는 물체로 이 강력한 힘을 통제하기 위해 고대부터 총 3개로 분리되어 보관되고 있던 것. 인류에 대한 믿음을 되찾고 슈퍼맨의 희생 정신에 마음이 움직인 브루스 웨인은 새로운 동료인 다이애나 프린스에게 도움을 청해 이 거대한 적에 맞서기로 한다. 배트맨과 원더 우먼은 새로이 등장한 위협에 맞서기 위해 아쿠아맨, 사이보그, 플래시를 찾아 신속히 팀을 꾸린다. 이들 슈퍼히어로 완전체는 스테픈울프로부터 마더박스를 지키기 위해 지구의 운명을 건 전투를 벌인다!', 'https://image.tmdb.org/t/p/w500/m4Zlx3sE8BNenwgWMRC995pQYub.jpg', 2017, 0, 0, '2026-06-06 13:25:34.243358', 'US');
INSERT INTO public.movies VALUES (50, 1084242, '주토피아 2', '["Adventure", "Animation", "Comedy", "Family", "Mystery"]', 'Jared Bush', '["Ginnifer Goodwin", "Jason Bateman", "Ke Huy Quan", "Fortune Feimster", "Andy Samberg"]', '미스터리한 뱀 게리가 나타난 순간, 주토피아가 다시 흔들리기 시작했다! 혼란에 빠진 도시를 구하기 위해 환상의 콤비 주디와 닉이 잠입 수사에 나서고 상상 그 이상의 진실과 위협을 마주하게 되는데...!', 'https://image.tmdb.org/t/p/w500/ib6v6qUXzez1x2qIOLN7C0yJNPQ.jpg', 2025, 0, 0, '2026-06-06 13:24:57.916021', 'US');
