INSERT INTO public.movies VALUES (60, 1252051, 'Disforia', '["Horror", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/49pzxbf1Eftz7wQZdVDVl8OM9bg.jpg', 2025, 0, 0, '2026-06-06 13:24:57.943729', 'US');
INSERT INTO public.movies VALUES (55, 1292415, '비스트', '["Action", "Drama"]', 'Tyler Atkins', '["Daniel MacPherson", "Luke Hemsworth", "Russell Crowe", "Mojean Aria", "Kelly Gale"]', 'MMA의 전설 패튼 제임스는 현재 상업 어부로 일하고 있지만, 동생이 위험에 처하자 다시 옥타곤으로 돌아온다. 옛 코치 새미와 재회한 그는 잔혹한 챔피언 자비에르 그라우를 상대로 단 한 번의 챔피언십 경기를 치르기로 결심한다.', 'https://image.tmdb.org/t/p/w500/7NrvUI3vnW8H3rD7ExKcTL7KRcQ.jpg', 2026, 0, 0, '2026-06-06 13:24:57.931071', 'US');
INSERT INTO public.movies VALUES (57, 980431, '아앙: 더 라스트 에어벤더', '["Action", "Adventure", "Animation", "Fantasy"]', 'Lauren Montgomery', '["Eric Nam", "Dave Bautista", "Jessica Matten", "Román Zaragoza", "Steven Yeun"]', NULL, 'https://image.tmdb.org/t/p/w500/29Jdsak3SrwGds5k1t43kH6Khed.jpg', 2026, 0, 0, '2026-06-06 13:24:57.936225', 'US');
