INSERT INTO public.movies VALUES (61, 1515729, 'Blast', '["Action", "Drama", "Family"]', 'Subash K Raj', '["Arjun Sarja", "Abhirami", "Preity Mukhundhan", "Vivek Prasanna", "John Kokken"]', NULL, 'https://image.tmdb.org/t/p/w500/ho824aZtnBzE6FuJRn2znQCq4qQ.jpg', 2026, 4.5, 1, '2026-06-06 13:24:58.674344', 'IN');
INSERT INTO public.movies VALUES (8685, 1294698, '사건번호 137', '["Crime", "Drama"]', 'Dominik Moll', '["Léa Drucker", "Jonathan Turnbull", "Mathilde Riu", "Guslagie Malanda", "Stanislas Merhar"]', 'IGPN 조사관 스테파니는 파리의 격렬한 시위 도중 중상을 입은 한 청년의 사건을 맡게 된다. 불법적인 경찰 폭력에 대한 증거는 발견되지 않고, 피해자가 자신의 고향 출신임을 알게 되면서, 수사는 예상치 못한 방향으로 흘러간다.', 'https://image.tmdb.org/t/p/w500/jhRAlfP8cmvUNyop4jttvJ6xtxm.jpg', 2025, 0, 0, '2026-06-08 07:27:02.256113', 'FR');
INSERT INTO public.movies VALUES (993, 57214, '프로젝트 X', '["Comedy"]', NULL, '[]', '고등학교에 다니고 있는 토마스, J.B., 코스타는 절친한 친구다. 코스타와 J.B.는 토마스의 생일을 위해 특별한 생일 프로젝트를 계획한다. 마침 생일날 토마스의 부모님이 오랜만에 여행을 떠나게 되면서 코스타와 J.B는 토마스 집에서 고등학교에 다니고 있는 학생들을 전부 초대하기로 한다. 그런데 코스타가 인터넷이며 방송, 라디오까지 토마스 생일을 위해 파티를 연다고 대대적인 홍보를 하고 나선다. 토마스는 설마 친구들이 얼마나 오겠느냐 하며 반문을 가지지만 친구들이 그룹으로 몰려오고 심지어 플레이보이 모델들과 영화배우들까지 속속들이 등장한다. 100여명에서 무려 2000명에서 3000명까지 몰려오는 토마스 인생 최대의 생일 파티를 열게 된다. 하지만 시간이 지날수록 점점 초대인들은 망가져가고, 흥분을 주체 못하는 젊은 세대들이기에 작게나마 기획했던 토마스의 생일은 웃지 못 할 상황까지 오게 되고 마는데……', 'https://image.tmdb.org/t/p/w500/lUPDGT3lyRrq8SvWuNWG2DP64bR.jpg', 2012, 0, 0, '2026-06-06 13:25:34.262978', 'US');
INSERT INTO public.movies VALUES (5958, 878667, 'ਚਲ ਮੇਰਾ ਪੁੱਟ 3', '["Comedy", "Drama"]', 'Janjot Singh', '["Amrinder Gill", "Simi Chahal", "Nasir Chinyoti", "Gurshabad Singh", "Rubi Anam"]', NULL, 'https://image.tmdb.org/t/p/w500/vhlwENeB4bDPl1YeSiPLNfDAJnz.jpg', 2021, 0, 0, '2026-06-08 06:52:11.172965', 'IN');
INSERT INTO public.movies VALUES (119, 1292695, '데이 윌 킬 유', '["Action", "Comedy", "Horror"]', 'Kirill Sokolov', '["Zazie Beetz", "Myha''la", "Patricia Arquette", "Paterson Joseph", "Heather Graham"]', '한 여성이 뉴욕의 한 고층 아파트에서 가사도우미로 일을 시작하지만, 그 건물에 오래전부터 ‘실종’의 역사가 있었다는 사실을 알지 못한다. 곧 그녀는 이곳의 공동체 전체가 알 수 없는 비밀과 미스터리에 감싸여 있음을 깨닫는다.', 'https://image.tmdb.org/t/p/w500/6oI4oQKTWMVUlr8Ivqydp28Ruu6.jpg', 2026, 0, 0, '2026-06-06 13:25:00.291028', 'US');
INSERT INTO public.movies VALUES (73, 1522126, '1000 Men and Me: The Bonnie Blue Story', '["Documentary"]', 'Victoria Silver', '["Bonnie Blue", "Victoria Silver", "Belle Delphine", "Lily Phillips", "Annie Knight"]', NULL, 'https://image.tmdb.org/t/p/w500/5dcgoyf8nt6Xt4VSR6Nrn6nwhuz.jpg', 2025, 0, 0, '2026-06-06 13:24:58.712608', 'GB');
INSERT INTO public.movies VALUES (75, 1325734, '더 드라마', '["Romance", "Comedy", "Drama"]', 'Kristoffer Borgli', '["Zendaya", "Robert Pattinson", "Mamoudou Athie", "Alana Haim", "Jordyn Curet"]', '결혼식을 코앞에 둔 한 쌍의 연인. 서로에 대해 결코 마주하고 싶지 않았던 진실을 알게 되면서 관계가 흔들리기 시작한다.', 'https://image.tmdb.org/t/p/w500/rnIOUhzwJDfgQakx8EjoNyItKgs.jpg', 2026, 0, 0, '2026-06-06 13:24:58.718173', 'US');
INSERT INTO public.movies VALUES (78, 1002398, '어린 아내', '["Drama", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/iVS3ZiPsKy8Hhc5Dipqgrjmoj2b.jpg', 2024, 0, 0, '2026-06-06 13:24:58.727096', 'US');
INSERT INTO public.movies VALUES (65, 1275779, '디스클로저 데이', '["Mystery", "Sci-Fi", "Thriller"]', 'Steven Spielberg', '["Emily Blunt", "Josh O''Connor", "Colin Firth", "Eve Hewson", "Colman Domingo"]', '우리가 혼자가 아니라는 사실을 알게 된다면, 누군가가 그것을 증명한다면, 그게 당신을 두렵게 하나요? 진실은 70억 인류 모두의 것입니다.', 'https://image.tmdb.org/t/p/w500/86EdVHOEFjFNPeE0sWjpCqcUORj.jpg', 2026, 0, 0, '2026-06-06 13:24:58.689013', 'US');
