INSERT INTO public.movies VALUES (67, 848116, '발리우드 러브스토리', '["Comedy", "Drama", "Family", "Romance"]', 'Karan Johar', '["Alia Bhatt", "Ranveer Singh", "Jaya Bachchan", "Shabana Azmi", "Dharmendra"]', NULL, 'https://image.tmdb.org/t/p/w500/vTQIqlxUkOuyf2UKhlM2OUaFGKz.jpg', 2023, 0, 0, '2026-06-06 13:24:58.695212', 'IN');
INSERT INTO public.movies VALUES (74, 1431071, '시스템', '["Thriller"]', 'Ashwiny Iyer Tiwari', '["Sonakshi Sinha", "Jyothika", "Ashutosh Gowariker", "Adinath Kothare", "Aashriya Mishra"]', '상류층 검사 네하 라지반시는 자신과 전혀 다른 환경에 사는 법정 속기사 사리카 라와트의 도움으로 대형 사건을 맡아 성공 가도를 달린다. 두 사람이 승승장구할수록 권력이 곧 진실이 되는 현대 인도 사회의 현실에 묻혀 있던 부정부패가 드러나고, 네하는 유산을 그대로 물려받을 것인지, 아니면 정의를 위해 싸우며 새 역사를 쓸 것인지를 선택해야 한다.', 'https://image.tmdb.org/t/p/w500/ddSTqsxOoXs77xnKpP7XBPqiero.jpg', 2026, 0, 0, '2026-06-06 13:24:58.715577', 'IN');
INSERT INTO public.movies VALUES (732, 335983, '베놈', '["Sci-Fi", "Action"]', NULL, '[]', '진실을 위해서라면 몸을 사리지 않고 사회의 부조리를 취재하는 정의로운 열혈 기자 에디 브록. 거대 기업 라이프 파운데이션의 생체실험에 의혹을 품고 뒤를 쫓던 그는 이들의 사무실에 잠입했다가 실험실에서 외계 생물체 심비오트의 기습 공격을 받게 된다. 심비오트가 숙주의 몸과 정신을 지배할 때 능력을 발휘하는 베놈은 에디의 몸에 기생하며 갖가지 소동을 일으킨다. 한편 비밀리에 인간과 심비오트를 결합해 새로운 생명체를 만들려는 시도를 계속하던 라이프 파운데이션의 회장 드레이크 또한 심비오트의 숙주가 된다.', 'https://image.tmdb.org/t/p/w500/x4ojC59pYfPlAP4mmy2LSkCCuK2.jpg', 2018, 0, 0, '2026-06-06 13:25:24.189977', 'US');
INSERT INTO public.movies VALUES (68, 1426822, 'Mortal Game', '["Horror", "Action"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/iCvucorbs3hFqWshDbLe0fHzB71.jpg', 2025, 0, 0, '2026-06-06 13:24:58.698032', 'US');
INSERT INTO public.movies VALUES (66, 441168, 'From Straight A''s to XXX', '["Drama"]', 'Vanessa Parise', '["Haley Pullos", "Sasha Clements", "Judd Nelson", "Alyson Bath", "Jacky Lai"]', NULL, 'https://image.tmdb.org/t/p/w500/kvcdaGcres9pGDwZfPN9jOKfZh.jpg', 2017, 0, 0, '2026-06-06 13:24:58.691982', 'US');
INSERT INTO public.movies VALUES (3852, 838209, '파묘', '["Mystery", "Horror", "Thriller"]', 'Jang Jae-hyun', '["Choi Min-sik", "Kim Go-eun", "Yoo Hai-jin", "Lee Do-hyun", "Kim Jae-chul"]', '미국 LA, 거액의 의뢰를 받은 무당 화림과 봉길은 기이한 병이 대물림되는 집안의 장손을 만난다. 조상의 묫자리가 화근임을 알아챈 화림은 이장을 권하고, 돈 냄새를 맡은 최고의 풍수사 상덕과 장의사 영근이 합류한다. 절대 사람이 묻힐 수 없는 악지에 자리한 기이한 묘. 상덕은 불길한 기운을 느끼고 제안을 거절하지만, 화림의 설득으로 결국 파묘가 시작되고… 나와서는 안될 것이 나왔다.', 'https://image.tmdb.org/t/p/w500/tw0i3kkmOTjDjGFZTLHKhoeXVvA.jpg', 2024, 0, 0, '2026-06-08 06:24:36.785656', 'KR');
INSERT INTO public.movies VALUES (2792, 1078023, '저격지왕: 암살', '["Action", "Crime", "Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/r5C85R0Bc6RL51PnPv2HIvpSMJ7.jpg', 2023, 0, 0, '2026-06-07 12:17:48.251711', 'US');
INSERT INTO public.movies VALUES (8686, 803, '밤과 안개', '["Documentary", "History"]', 'Alain Resnais', '["Michel Bouquet", "Reinhard Heydrich", "Heinrich Himmler", "Adolf Hitler", "Julius Streicher"]', '제2차 세계대전이 끝난 지 10여년이 지나 버려진 수용소의 현재 모습은 흑백의 기록화면으로 이어진다. 12년 전 빈 들판엔 수용소 건설이 진행되었고 ‘밤과 안개’ 작전으로 유대인들이 수감되기 시작했다.', 'https://image.tmdb.org/t/p/w500/c0eZtYCYOe4XV55dOZ016XesKg3.jpg', 1956, 0, 0, '2026-06-08 07:27:02.914452', 'FR');
INSERT INTO public.movies VALUES (983, 16859, '마녀배달부 키키', '["Animation", "Family", "Fantasy"]', 'Hayao Miyazaki', '["Minami Takayama", "Rei Sakuma", "Kappei Yamaguchi", "Keiko Toda", "Mieko Nobusawa"]', '마녀 엄마와 인간 아빠 사이에서 태어난 소녀 키키는 13살이 되던 만월의 어느 밤, 검은 고양이 지지와 함께 집을 나와 마녀 수업을 떠난다. 평소 바다를 동경하던 키키는 바다에 떠있는 커다란 마을에 정착하게 되고, 그 곳에서 갑자기 도로에 뛰어들게 되어 경찰에게 잡히지만 돔보라는 친구를 만나 도망을 치게 된다. 키키는 빵가게 앞을 지나가다 마음씨 좋은 아주머니를 만나게 되고 그 빵집에서 첫 배달이 시작된다. 어느날 비행선 사고가 일어나는데, 거기에 돔보가 포함되어있다는 것을 알고 급히 현장으로 가게 되고, 청소부의 대걸레를 빌려 마법을 사용, 돔보를 구출하려 하는데...', 'https://image.tmdb.org/t/p/w500/yEbyzK1cLDoZVIJV6auSr9yN5fG.jpg', 1989, 0, 0, '2026-06-06 13:25:34.238704', 'JP');
INSERT INTO public.movies VALUES (80, 1330021, '아쿠아리움이 문을 닫으면', '["Drama", "Mystery"]', 'Olivia Newman', '["Sally Field", "Lewis Pullman", "Colm Meaney", "Alfred Molina", "Joan Chen"]', '작은 마을의 아쿠아리움에서 야간 근무를 하는 여자. 남편과 사별한 그녀는 영리한 문어와 삶의 방향을 잃은 젊은 남자와 친구가 된다. 베스트셀러를 원작으로 한 감동적인 드라마 영화.', 'https://image.tmdb.org/t/p/w500/mUt0SnTp0oAN38BHD7NGX8hmwAT.jpg', 2026, 0, 0, '2026-06-06 13:24:58.732436', 'US');
INSERT INTO public.movies VALUES (87, 1301421, 'The Sheep Detectives', '["Comedy", "Family", "Mystery"]', 'Kyle Balda', '["Hugh Jackman", "Julia Louis-Dreyfus", "Emma Thompson", "Nicholas Braun", "Chris O''Dowd"]', NULL, 'https://image.tmdb.org/t/p/w500/hTirV44jiLh6NqdiB6jtxPsDIoG.jpg', 2026, 0, 0, '2026-06-06 13:24:59.471111', 'GB');
INSERT INTO public.movies VALUES (85, 1632181, 'Socias por accidente', '["Comedy", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/sr1Yoj6XLPTWYcbDoBy67xivW4I.jpg', 2026, 0, 0, '2026-06-06 13:24:59.466032', 'US');
INSERT INTO public.movies VALUES (128, 120, '반지의 제왕: 반지 원정대', '["Adventure", "Fantasy", "Action"]', 'Peter Jackson', '["Elijah Wood", "Ian McKellen", "Viggo Mortensen", "Sean Astin", "Ian Holm"]', '호빗이라 불리우는 난장이 종족 중의 한 명인 프로도는 자신의 삼촌에게서 우연히 절대 반지를 물려받게 되고, 마법사 간달프를 통해서 절대반지가 사우론의 손에 들어가면 악의 세력이 세상을 지배하게 된다는 것을 알게 된다. 하지만 절대반지를 영원히 파괴할 수 있는 유일한 방법은 반지가 만들어진 불의 산의 용암에 그것을 던져 넣는 길 뿐이다. 마침내 프로도와 그의 친구들, 엘프족인 레골라스, 난장이족 김리, 두명의 인간 전사 아라곤과 보로미르, 그리고 마법사 간달프로 구성된 반지 원정대가 길고도 험난한 여정을 떠나게 되는데...', 'https://image.tmdb.org/t/p/w500/r18JdjImbWDRwkbVDIzWoLQqkCo.jpg', 2001, 0, 0, '2026-06-06 13:25:01.025054', 'US');
INSERT INTO public.movies VALUES (2013, 1358005, '오피스 로맨스', '["Romance", "Comedy"]', 'Ol Parker', '["Jennifer Lopez", "Brett Goldstein", "Betty Gilpin", "Edward James Olmos", "Bradley Whitford"]', '비밀스러운 사내 연애에 빠진 두 워커홀릭이 감정에 이끌리며 예상치 못한 곤경에 빠진다.', 'https://image.tmdb.org/t/p/w500/udcNzdIqZMiVYYvq50XDEPhpJks.jpg', 2026, 0, 0, '2026-06-07 12:17:13.710415', 'US');
INSERT INTO public.movies VALUES (91, 48650, '룸 인 로마', '["Drama", "Romance"]', NULL, '[]', '로마의 6월 여름 첫날밤,  술집에서 러시아 여인 나타샤와 스페인 여인 알바가 우연히 만나 서로에게 호감을 갖는다. 그녀들은 이후, 로마의 한 호텔에서 하룻밤을 보내며, 자신이 레즈비언이라는 알바는 이성애자인 나타샤에게 서서히 접근을 하고,  차츰 각자 진실된 자신의 이야기를 시작하게 되는데..', 'https://image.tmdb.org/t/p/w500/4kF4qRXFd7MqX2bAJX3e3zQSxhV.jpg', 2010, 0, 0, '2026-06-06 13:24:59.48061', 'US');
