INSERT INTO public.movies VALUES (3988, 412117, '마이펫의 이중생활  2', '["Animation", "Comedy", "Family", "Adventure"]', NULL, '[]', '집을 비우면 다시 시작되는 펫들의 시크릿 라이프!  집구석 걱정에 하루도 편할 날이 없는 ‘맥스’ 캣닢을 사랑하는 자유로운 영혼 ‘클로이’ 슈퍼히어로를 따라 하는 토끼 ‘스노우볼’ 완벽하게 고양이가 되고픈 강아지 ‘기젯’까지 아직도 나만 몰랐던 마이펫들의 속마음이 공개된다!  “우릴 키운다고? 그건 니 생각이고~”', 'https://image.tmdb.org/t/p/w500/wiqA4SaY4ndT0TD75CDz4cEKfe3.jpg', 2019, 0, 0, '2026-06-08 06:24:42.012799', 'US');
INSERT INTO public.movies VALUES (82, 64641, 'La ragazzina', '["Romance", "Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/eb4mMyocL1XdaI6DPexyZGMo0sF.jpg', 1974, 0, 0, '2026-06-06 13:24:59.45714', 'US');
INSERT INTO public.movies VALUES (4124, 801604, '샤크: 더 비기닝', '["Action", "Drama"]', 'Johnny Chae', '["Kim Min-seok", "Wi Ha-jun", "Jung Won-chang", "Lee Jae-kyoon", "Bae Myeong-jin"]', '뜻밖의 사고로 모든 것을 잃은 학교폭력 피해자 차우솔. 소년교도소에 수감된 뒤 우연히 종합격투기 챔피언 정도현을 만나게 되고, 자신 안의 두려움과 마주한 채 육체적, 정신적 한계를 하나씩 극복해 나간다. 교도소에서 출소해도, 자신을 괴롭힐 배석찬을 두려워하던 차우솔은 고된 훈련을 통해 점차 강력한 상어의 공격 본능을 일깨우기 시작하는데…', 'https://image.tmdb.org/t/p/w500/r3zWv3Ly1Y2NZrGHFaQntCS4MT7.jpg', 2021, 0, 0, '2026-06-08 06:27:22.077865', 'KR');
INSERT INTO public.movies VALUES (94, 299536, '어벤져스: 인피니티 워', '["Adventure", "Action", "Sci-Fi"]', 'Joe Russo', '["Robert Downey Jr.", "Chris Evans", "Chris Hemsworth", "Josh Brolin", "Mark Ruffalo"]', '타노스는 6개의 인피니티 스톤을 획득해 신으로 군림하려 한다. 그것은 곧 인류의 절반을 학살해 우주의 균형을 맞추겠다는 뜻. 타노스는 닥터 스트레인지가 소유한 타임 스톤, 비전의 이마에 박혀 있는 마인드 스톤을 차지하기 위해 지구를 침략한다. 아이언맨과 스파이더맨은 가디언즈 오브 갤럭시의 멤버들과 타노스를 상대한다. 지구에선 캡틴 아메리카, 완다, 블랙 위도우, 블랙 팬서 등이 비전을 지키기 위해 뭉친다.', 'https://image.tmdb.org/t/p/w500/kmP6viwzcEkZeoi1LaVcQemcvZh.jpg', 2018, 0, 0, '2026-06-06 13:24:59.489313', 'US');
INSERT INTO public.movies VALUES (96, 1266127, '레디 오어 낫 2', '["Thriller", "Horror", "Comedy"]', 'Matt Bettinelli-Olpin', '["Samara Weaving", "Kathryn Newton", "Elijah Wood", "Sarah Michelle Gellar", "Shawn Hatosy"]', '르 도마스 가문의 공격에서 간신히 살아남은 지 몇 분도 되지 않아 그레이스는 자신이 이 악몽 같은 게임의 ‘다음 레벨’에 도달했다는 사실을 깨닫는다. 이번에는 오랫동안 왕래 없던 여동생 페이스까지 함께다.', 'https://image.tmdb.org/t/p/w500/13ZcJzSGEqVgDSqsS9U5EkQwPkV.jpg', 2026, 0, 0, '2026-06-06 13:24:59.495628', 'US');
INSERT INTO public.movies VALUES (102, 1628367, '카르타비아, 나의 의무', '["Crime", "Drama", "Thriller"]', 'Pulkit', '["Saif Ali Khan", "Rasika Dugal", "Sanjay Mishra", "Saurabh Dwivedi", "Zakir Hussain"]', '한 경찰관의 가족이 위기에 처하고 위협이 목을 죄어 오는 상황. 경찰관은 자신의 의무를 다하기 위해 어디까지 희생할 수 있을 것인가.', 'https://image.tmdb.org/t/p/w500/doTwMyAphlDL5Z8WqE3elWWvj8M.jpg', 2026, 0, 0, '2026-06-06 13:25:00.238402', 'IN');
