INSERT INTO public.movies VALUES (99, 1639398, 'Psicópata: El Asesino del Conejo Blanco', '["Thriller", "Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/7tIgfsTWuzXKR2kLRUPrLRTbcuo.jpg', 2026, 0, 0, '2026-06-06 13:24:59.503952', 'US');
INSERT INTO public.movies VALUES (938, 76, '비포 선라이즈', '["Drama", "Romance"]', NULL, '[]', '프랑스 파리의 소르본느 대학생인 셀린느는 헝가리 부다페스트에 사는 할머니를 만나고, 가을 학기 개강에 맞춰 파리로 돌아가는 길이다. 셀린느는 옆자리의 독일인 부부가 시끄럽게 말다툼하는 소리를 피해 뒷좌석으로 자리를 옮기는데, 거기서 제시라는 미국인 청년과 우연히 얘기를 나누게 된다. 우연히 만난 그들은 짧은 시간에 서로에게 빠져든다. 그림 같은 도시와 꿈같은 대화 속에서 발견한  서로를 향한 강한 이끌림은 풋풋한 사랑으로 물들어 간다. 밤새도록 계속된 그들의 사랑 이야기 끝에 해가 떠오르기 시작하고 그들은 헤어져야만 하는데...', 'https://image.tmdb.org/t/p/w500/o7mLGNdzY1z6w2bQv0NJNOoVKks.jpg', 1995, 0, 0, '2026-06-06 13:25:31.963756', 'US');
INSERT INTO public.movies VALUES (97, 337167, '50가지 그림자: 해방', '["Drama", "Romance"]', 'James Foley', '["Dakota Johnson", "Jamie Dornan", "Eric Johnson", "Eloise Mumford", "Rita Ora"]', '모든 과거를 잊고 서로에게 더 깊게 빠져든 ‘크리스찬 그레이’와 ‘아나스타샤’.  그레이의 독특한 취향으로 시작된 이 비밀스러운 관계는  더 큰 자극을 원하는 아나스타샤로 인해 역전되고,  마침내 그녀의 본능이 지배하는 마지막 절정의 순간을 맞이하게 되는데…', 'https://image.tmdb.org/t/p/w500/kdN58uXDV5D0RWdMjdO9jtdFjxg.jpg', 2018, 0, 0, '2026-06-06 13:24:59.498462', 'US');
INSERT INTO public.movies VALUES (146, 1156594, '우리의 잘못', '["Romance", "Drama"]', 'Domingo González', '["Nicole Wallace", "Gabriel Guevara", "Gabriela Andrada", "Marta Hazas", "Goya Toledo"]', '헤어진 후 오랫동안 기다려온 노아와 닉은 예나와 라이온의 결혼식에서 재회한다. 노아를 용서하지 못하는 닉의 마음은 넘을 수 없는 장벽처럼 단단하다. 할아버지의 사업을 물려받은 닉과 사회생활을 시작한 노아는 아직 꺼지지 않은 불꽃에 다시 불붙는 것을 애써 피하려 한다. 하지만 두 사람의 길이 다시 만난 지금, 사랑이 원망보다 더 강해질 수 있을까?', 'https://image.tmdb.org/t/p/w500/yCbT1nKemh1AuQgdbns5Cf1RmRj.jpg', 2025, 0, 0, '2026-06-06 13:25:01.786027', 'US');
INSERT INTO public.movies VALUES (62, 462183, '와일드 어웨이크닝', '["Drama", "Romance", "Thriller"]', NULL, '[]', '토니와 엠마는 안정된 농장을 소유한 남매다. 라몬과 그의 아들 아론은 그들을 위해 일한다. 토니는 공공연히 알려진 게이고 파티를 좋아하고, 엠마는 아론을 좋아하는데 아론은 게이지만 아빠한테 비밀을 숨기고 있다. 하지만 아론의 아빠 또한 비밀을 갖고 있는데...', 'https://image.tmdb.org/t/p/w500/qWkWESVyw1nsX89AXshyRa31Bk6.jpg', 2016, 0, 0, '2026-06-06 13:24:58.678273', 'US');
