INSERT INTO public.movies VALUES (5977, 1093966, 'வேட்டையன்', '["Action", "Crime", "Drama"]', 'T. J. Gnanavel', '["Rajinikanth", "Amitabh Bachchan", "Fahadh Faasil", "Rana Daggubati", "Manju Warrier"]', NULL, 'https://image.tmdb.org/t/p/w500/1q0dAC3OJZVKQcV2dG5sGvdUGqN.jpg', 2024, 0, 0, '2026-06-08 06:52:26.243771', 'IN');
INSERT INTO public.movies VALUES (4164, 688297, '스폰서 X', '["Drama"]', 'EROPING', '["Ah Reum", "Tae Joo", "Sung Yeon", "Im Cho-hee", "Kang Min-woo"]', '럭셔리한 삶을 위해 고양이 처럼 항상 꼬리를 흔들어야 하는 여인 반지는 스폰서의 무관심에 점점 무기력해진다. 외로운 밤을 손으로 달래길 여러 날. 빈곤하게 힙합 음악을 하는 옛 남자친구에게 전화를 걸어보지만, 그 역시 이미 새로운 삶과 새로운 사랑에 빠져있다. 길들여지는 것에 익숙해져버린 이들의 각자 다른 이야기.', 'https://image.tmdb.org/t/p/w500/elY0uzIciDgbx6ef2KnosT0LQdI.jpg', 2020, 0, 0, '2026-06-08 06:27:54.239594', 'KR');
INSERT INTO public.movies VALUES (2811, 1285959, 'The Passenger', '["Thriller"]', 'Vadim Perelman', '["Djimon Hounsou", "Kodi Smit-McPhee", "Leigh-Ann Rose", "Carolina Campos", "Tegan Couchman"]', NULL, 'https://image.tmdb.org/t/p/w500/heFjHLMVmYZWC4uhvPNI0idckwU.jpg', 2026, 0, 0, '2026-06-07 12:17:49.172782', 'US');
