INSERT INTO public.movies VALUES (116, 533535, '데드풀과 울버린', '["Action", "Comedy", "Sci-Fi"]', 'Shawn Levy', '["Ryan Reynolds", "Hugh Jackman", "Emma Corrin", "Matthew Macfadyen", "Dafne Keen"]', '히어로 생활에서 은퇴한 후, 평범한 중고차 딜러로 살아가던 데드풀이 예상치 못한 거대한 위기를 맞아 모든 면에서 상극인 울버린을 찾아가게 되며 펼쳐지는 도파민 폭발 액션 블록버스터.', 'https://image.tmdb.org/t/p/w500/dsfAcQ5J7TPOpJgcX8R1lRBqiMK.jpg', 2024, 0, 0, '2026-06-06 13:25:00.281355', 'US');
