INSERT INTO public.movies VALUES (108, 1242265, '퓨즈', '["Action", "Crime", "Drama", "Thriller"]', 'David Mackenzie', '["Aaron Taylor-Johnson", "Theo James", "Gugu Mbatha-Raw", "Elham Ehsas", "Sam Worthington"]', NULL, 'https://image.tmdb.org/t/p/w500/oMFdQE5hMJ9JjhNORegwTo0GKmh.jpg', 2026, 0, 0, '2026-06-06 13:25:00.255973', 'GB');
INSERT INTO public.movies VALUES (819, 11770, '소림축구', '["Action", "Comedy"]', NULL, '[]', '퇴물 취급받는 왕년의 스타 플레이어 명봉(오맹달). 축구 코치가 되고 싶지만 어느 구단에서도 그를 받아주지 않는다. 소림사에서 무공을 익혔던 씽씽(주성치)은 사부가 죽자 하릴없이 빈둥빈둥 가난한 백수로 지내며 만두가게 처녀 아매(조미)를 흠모하는게 유일한 낙. 우연히 씽씽의 힘을 발견한 명봉은 씽씽에게 축구단을 결성하자고 제안한다. 일단은 정예 멤버를 모으는게 가장 급선무, 씽씽은 소림사에서 함께 무예를 다졌던 동료들을 차례차례 찾아가지만, 날렵했던 무사들은 온데간데 없고 하나같이 삶의 의욕을 잃어버린 이들 뿐. 이들은 씽씽의 제안을 처음엔 거절하지만 나중엔 차례차례 씽씽을 찾아오게 되는데...', 'https://image.tmdb.org/t/p/w500/86r8Fe9WuleUh5BLn0VIQhbfemB.jpg', 2001, 0, 0, '2026-06-06 13:25:27.329759', 'US');
INSERT INTO public.movies VALUES (115, 1662414, '''LA로 가는 밤 비행기'' - Propeller One-Way Night Coach', '["Adventure", "Drama", "Family"]', 'John Travolta', '["Clark Shotwell", "Kelly Eviston-Quinnett", "Ella Bleu Travolta", "Olga Hoffmann", "Charlie Berger"]', '항공 황금시대, 비행기를 사랑하는 소년과 그의 어머니가 할리우드로 향하는 대륙 횡단 여정에 오른다. 평범했던 비행은 이내 인생 최고의 여행으로 바뀐다.', 'https://image.tmdb.org/t/p/w500/qVTOSEC5djHlm3ahGS4tcVmsiOR.jpg', 2026, 0, 0, '2026-06-06 13:25:00.278216', 'US');
INSERT INTO public.movies VALUES (109, 1280738, '분노의 추격', '["Action", "Crime", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/zP19YO60jwEsfKd5Qf1UvA5uJu8.jpg', 2026, 0, 0, '2026-06-06 13:25:00.259065', 'US');
INSERT INTO public.movies VALUES (107, 1265609, '워 머신: 전쟁 기계', '["Action", "Sci-Fi", "Thriller"]', NULL, '[]', '미 육군 레인저 훈련에서 마지막 혹독한 임무를 받은 전투 공병. 자신이 속한 부대를 이끌고 거대한 외계 살상 병기에 맞서 싸워야 한다.', 'https://image.tmdb.org/t/p/w500/cfeIYPthWgq5XFZnx7cbpr7xFTp.jpg', 2026, 0, 0, '2026-06-06 13:25:00.252809', 'US');
INSERT INTO public.movies VALUES (5978, 1434543, 'एक दीवाने की दीवानियत', '["Romance", "Drama", "Thriller"]', 'Milap Zaveri', '["Harshvardhan Rane", "Sonam Bajwa", "Shaad Randhawa", "Sachin Khedekar", "Ananth Narayan Mahadevan"]', NULL, 'https://image.tmdb.org/t/p/w500/eQGzsELM0n6FOngNRGEIx9nqDwV.jpg', 2025, 0, 0, '2026-06-08 06:52:27.002806', 'IN');
INSERT INTO public.movies VALUES (5979, 962640, 'K.G.F: Chapter 3', '["Action", "Drama", "Thriller"]', 'Prashanth Neel', '["Yash", "Srinidhi Shetty", "Raveena Tandon", "Achyuth Kumar"]', NULL, 'https://image.tmdb.org/t/p/w500/ex2zyM6LVd31h9TlAi9RaR7QARK.jpg', NULL, 0, 0, '2026-06-08 06:52:27.742379', 'IN');
INSERT INTO public.movies VALUES (110, 1613798, '복수', '["Action", "Thriller"]', NULL, '[]', '훈장을 받은 특수부대 영웅 카를로스 에스트라다. 아내가 잔인하게 살해당한 그에게 이제 남은 단 하나는 목표는 바로 복수다. 예상치 못한 운명의 장난으로 백만장자가 된 카를로스는 자신의 재산을 군수 물자로 바꾼다. 그리고 가장 신뢰하는 부하들과 함께, 사건의 배후를 향한 끈질긴 추격전을 시작한다.', 'https://image.tmdb.org/t/p/w500/26milocWotfItrjwnadk4gyHwyi.jpg', 2026, 0, 0, '2026-06-06 13:25:00.262375', 'US');
INSERT INTO public.movies VALUES (5980, 1160018, '킬', '["Action", "Crime", "Thriller", "Drama"]', 'Nikhil Nagesh Bhat', '["Lakshya Lalwani", "Raghav Juyal", "Tanya Maniktala", "Ashish Vidhyarthi", "Abhishek Chauhan"]', '질주하는 야간열차에 잠입한 무장 강도 집단.열차 승객들을 구하기 위해 나선 특수 요원. 문, 커튼, 손잡이. 손에 잡히는 모든 것이 무기가 된다!  40명의 빌런, 52개의 무기, 9번의 위기! 용서도, 자비도 없다! 짜릿하고 무자비한 복수가 시작된다!', 'https://image.tmdb.org/t/p/w500/hJxdfkQVSzM67uKjInnZA2mJTua.jpg', 2024, 0, 0, '2026-06-08 06:52:28.479768', 'IN');
INSERT INTO public.movies VALUES (114, 1171145, '크라임 101', '["Crime", "Thriller"]', 'Bart Layton', '["Chris Hemsworth", "Mark Ruffalo", "Halle Berry", "Barry Keoghan", "Monica Barbaro"]', '101번 국도를 따라 흔적도 없이 사라지는 보석들. 전설적인 절도범 ‘데이비스’는 자신만의 규칙 아래 완벽한 범죄를 설계한다. 모두가 혼란에 빠진 사이, 원칙과 집념의 형사 ‘루’만이 범인의 실체를 포착하며 포위망을 좁혀간다. 거대한 보험금을 노린 ‘데이비스’는 보험중개인 ‘샤론’에게 위험한 거래를 제안하고 완벽했던 계획과 정교한 수사는 예상치 못한 국면으로 치닫는데…', 'https://image.tmdb.org/t/p/w500/77ggpowGO0ORQY9x33NeBIPajm1.jpg', 2026, 0, 0, '2026-06-06 13:25:00.275057', 'GB');
INSERT INTO public.movies VALUES (4527, 652837, '조제, 호랑이 그리고 물고기들', '["Animation", "Drama", "Romance"]', 'Kotaro Tamura', '["Taishi Nakagawa", "Kaya Kiyohara", "Yume Miyamoto", "Kazuyuki Okitsu", "Lynn"]', '지체장애인인 조제는 그림 그리기를 좋아하며, 미처 경험해 보지 못한 세상에 대한 호기심과 두려움을 동시에 가지고 살아간다. 해양생물학을 전공하며 유학을 준비 중인 츠네오는 바다를 사랑하는 대학생으로 조제와 비슷한 또래이다. 조제를 온실 속 화초처럼 키워온 할머니는 츠네오를 아르바이트생으로 고용하여 조제를 일정 시간 돌보게 한다. 조제는 할머니의 눈을 피해, 혹은 할머니의 묵인하에, 츠네오와 함께 바깥나들이를 시작하고 조금씩 세상을 향해 마음을 열어간다.', 'https://image.tmdb.org/t/p/w500/v60S8rPRCQRYSeCtmLiuRpQqIfC.jpg', 2020, 0, 0, '2026-06-08 06:32:50.69699', 'JP');
INSERT INTO public.movies VALUES (135, 803796, '케이팝 데몬 헌터스', '["Fantasy", "Comedy", "Animation"]', 'Chris Appelhans', '["Arden Cho", "May Hong", "Ji-young Yoo", "Ahn Hyo-seop", "Yunjin Kim"]', '케이팝 슈퍼스타 루미, 미라, 조이. 매진을 기록하는 대형 스타디움 공연이 없을 때면 이들은 또 다른 활동에 나선다. 바로 비밀 능력을 이용해 팬들을 초자연적 위협으로부터 보호하는 것.', 'https://image.tmdb.org/t/p/w500/5fqcLmrgVDicMuGLOa9PKErFP72.jpg', 2025, 0, 0, '2026-06-06 13:25:01.040892', 'US');
