INSERT INTO public.movies VALUES (2822, 1035259, '총알 탄 사나이', '["Action", "Comedy", "Crime"]', NULL, '[]', '단 한 사람만이 경찰 특공대를 이끌고 세상을 구할 특별한 기술을 지녔다… 그는 바로 프랭크 드레빈이다.', 'https://image.tmdb.org/t/p/w500/rwla9vqzrKVVKVKiOuROTIXGsxj.jpg', 2025, 0, 0, '2026-06-07 12:17:50.111761', 'US');
