INSERT INTO public.movies VALUES (126, 1631017, 'ಕರಿಕಾಡ', '["Action", "Comedy"]', 'Gulla Venkatesh', '["Kriti Verma", "Yash Shetty", "Kari Subbu", "Kaada Natraj", "Niriksha Shetty"]', NULL, 'https://image.tmdb.org/t/p/w500/tL0skwRWivuNZHQD89baWynksct.jpg', 2026, 0, 0, '2026-06-06 13:25:01.020346', 'IN');
INSERT INTO public.movies VALUES (129, 879945, '무명의 남자', '["Drama"]', 'Anthony Schatteman', '["Geert Van Rampelberg", "Samuel Suchod", "Anna Sacuto", "Cathy Ruiz"]', '내리쬐는 여름 태양 아래, 거센 파도 속에서 돋아나는 사랑. 이 작품에는 여름의 뜨거움과 고요함이 담겨있다. 색감과 노래에서 묻어 나오는 감정들은 영화에 더욱 몰입하게 한다.', 'https://image.tmdb.org/t/p/w500/4TpBhdaSl5ALHbgeaYOLF8Q3haz.jpg', 2021, 0, 0, '2026-06-06 13:25:01.027345', 'FR');
