INSERT INTO public.movies VALUES (842, 330459, '로그 원: 스타워즈 스토리', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '희망이 사라진 세상. 반군 소속의 진은 적의 최종병기 데스 스타 개발에 아버지가 참여했단 과거 때문에  데스 스타의 약점을 캐내는 임무를 떠맡게 된다. 단숨에 행성 하나를 파괴할 위력을 지닌 데스 스타가 완성되기 전에 설계도를 훔쳐내야 하는 이번 작전의 성공 확률은 고작 2.4%. 생사도 모르는 아버지에 얽힌 비밀을 밝히려는 진을 비롯해 유능한 정보 요원 카시안, 두 눈이 멀었지만 탁월한 무술 실력을 지닌 치루트, 전투 베테랑 베이즈, 파일럿 보디, 시니컬한 드로이드 K-2SO까지 합류, 거대한 전쟁을 끝낼 가장 비밀스런 작전이 시작되는데...', 'https://image.tmdb.org/t/p/w500/44oic6PRJVeGUWNrpzlmuVVKWyv.jpg', 2016, 0, 0, '2026-06-06 13:25:28.839855', 'US');
