INSERT INTO public.movies VALUES (140, 27, '나인 송즈', '["Drama", "Romance"]', 'Michael Winterbottom', '["Kieran O''Brien", "Margo Stilley", "Courtney Taylor-Taylor", "Alex Kapranos", "Guy Garvey"]', '미국에서 온 교환 학생 리사와 영국인 매트는 한눈에 서로 사랑에 빠진다. 21살 리사의 매트에 대한 사랑은 격정적이며 정열적이다. 9번의 공연 실황 장면과 그들이 나누는 아홉 번의 사랑. 흔히 젊은 연인들이 그러하듯이, 이들은 사랑하지만, 미래를 이야기 하지 않는다. 9번의 공연이 끝난 후, 리사는 크리스마스를 앞두고 미국으로 돌아가겠다며 매트에게 기약없는 작별을 고하는데...', 'https://image.tmdb.org/t/p/w500/tWkyDY78MAtemlCLJNQmlXUo1Iu.jpg', 2004, 0, 0, '2026-06-06 13:25:01.052569', 'GB');
INSERT INTO public.movies VALUES (144, 1038392, '컨저링: 마지막 의식', '["Horror"]', 'Michael Chaves', '["Patrick Wilson", "Vera Farmiga", "Mia Tomlinson", "Ben Hardy", "Rebecca Calder"]', '1986년 미국 펜실베이니아. 자신의 집에 사악한 존재가 들어왔다고 주장하는 스멀 일가를 찾은 워렌 부부. 이들은 그 곳에서 지금껏 마주한 적 없는 가장 위험하고 강력한 악령을 만나게 되고, 그것이 자신들의 과거와 연결된 충격적인 진실을 알게 되는데…', 'https://image.tmdb.org/t/p/w500/y9jKDJuf5WCDjSPsqkt1cb0JHGm.jpg', 2025, 0, 0, '2026-06-06 13:25:01.780659', 'US');
