INSERT INTO public.movies VALUES (64, 1290821, '쉘터', '["Action", "Crime", "Thriller"]', 'Ric Roman Waugh', '["Jason Statham", "Bodhi Rae Breathnach", "Naomi Ackie", "Daniel Mays", "Harriet Walter"]', '등대에 홀로 숨어살던 한 남자. 그 앞에 홀로 나타난 한 소녀. 이제 소녀를 지키기 위해, 그 남자의 숨겨왔던 액션 본능이 깨어난다!', 'https://image.tmdb.org/t/p/w500/tS3UZlVfESO4z8inIZXGiHNgDfE.jpg', 2026, 0, 0, '2026-06-06 13:24:58.68571', 'GB');
INSERT INTO public.movies VALUES (911, 1357459, 'Tatsulok: Tatlo Magkasalo', '["Drama", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/15B2oabjTSiydkqsV05jX2IV1Dq.jpg', 2024, 0, 0, '2026-06-06 13:25:31.176015', 'US');
INSERT INTO public.movies VALUES (148, 1414413, '시에라 마드레: 카르텔 전쟁', '["Action", "Thriller", "Mystery", "Drama"]', 'Justin Chadwick', '["Kiefer Sutherland", "Tommy Martinez", "Ashton Sanders", "Solly McLeod", "Laura Osma"]', '멕시코에서 열린 결혼식에 참석하기 위해 휴가를 떠난 특수부대원 조던과 그의 동료들은, 우연히 잔혹한 카르텔과 마주치며 순식간에 생존 전쟁에 휘말린다. 조던은 흩어진 동료들과 민간인들을 이끌고 탈출을 시도하지만, 사막 한복판에서 카르텔과의 치열한 추격과 전투가 벌어지며 상황은 점점 극한으로 치닫는다.', 'https://image.tmdb.org/t/p/w500/pRix7i1lrSOFr34sjvFIFQb5E66.jpg', 2026, 0, 0, '2026-06-06 13:25:01.792027', 'US');
INSERT INTO public.movies VALUES (902, 62211, '몬스터 대학교', '["Animation", "Family"]', NULL, '[]', '매사에 열심이지만 이론만 빠삭한 마이크와 무늬만 엄친아인 허세 몬스터 설리는 몬스터 주식회사 입사의 꿈을 안고 취업 100% 보장 특성화 대학 몬스터 대학교에 입학한다. 하지만 성격도 재능도 정반대인 둘은 첫날부터 삐걱거리며 급기야는 개교이래 최악의 라이벌이 되고야 만다. 하지만 그들이 힘을 합쳐야 하는 순간이 찾아온다. 부푼 꿈을 안고 몬스터 대학교에 진학한 그들이 전공 퇴출 위기에 몰리면서, 교내 겁주기 대회에 팀을 이뤄 출전하기로 한 것. 그렇게 그들은 엄한 학장의 경계 속에 최약체 팀으로 대회에 나선다. 하지만 초반의 실수를 딛고 이내 승승장구하며 교내의 영웅으로 떠오르기 시작한다.', 'https://image.tmdb.org/t/p/w500/7K5BqOlgDOs2DI2PKDUGlMtYheL.jpg', 2013, 0, 0, '2026-06-06 13:25:31.150756', 'US');
INSERT INTO public.movies VALUES (3990, 1232889, 'Malta', '["Drama", "Sci-Fi"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/pPaakmxnJl4hS4AMa1zc27KfD1b.jpg', 2024, 0, 0, '2026-06-08 06:24:42.828101', 'US');
INSERT INTO public.movies VALUES (142, 259872, '밤보다 더 아름다운 낮', '["Romance", "Documentary"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/uCkANtG6ezb7hjRKVudY3PUcbvn.jpg', 2009, 0, 0, '2026-06-06 13:25:01.77454', 'US');
INSERT INTO public.movies VALUES (3997, 1111873, '애비게일', '["Horror", "Thriller"]', NULL, '[]', '오직 돈을 위해서 업계 최고들로만 모인 납치범들. 정체를 알 수 없는 거부의 딸이자 평범한 소녀 애비게일을 납치하고, 24시간 동안 저택에서 그녀를 감시하고 거액의 돈을 받기로 한다. 하지만 평범한 소녀 애비게일은 발레리나 뱀파이어였고 오히려 납치범들은 역으로 저택에 갇혀 그녀의 장난감과 먹이가 되었다. 납치범들은 이제 24시간 안에 살기 위해 저택을 탈출해야 한다.', 'https://image.tmdb.org/t/p/w500/l0d3sJuF4KCl4Y4Z9n06hgF5f7g.jpg', 2024, 0, 0, '2026-06-08 06:24:42.847593', 'US');
INSERT INTO public.movies VALUES (4003, 15356, '더 걸 넥스트 도어', '["Thriller", "Crime", "Drama", "Horror"]', NULL, '[]', '1958년의 조용한 교외의 한 작은마을. 사고로 부모를 잃은 매기와 수잔 자매가. 고모인 루스 집에 맡겨진다. 정신적으로 분안정한 루스고모는 매기 자매들을 훈계한다는. 핑계로 잔인한 학대와 고문을 일삼고 심지어 자신의 아들들과 동네 아이들까지 시켜서. 자매를 괴롭히고 입에 담지 못할 행동들을 시킨다.', 'https://image.tmdb.org/t/p/w500/dXjLp7k7ILyg22T0s9VvpPKc9jn.jpg', 2007, 0, 0, '2026-06-08 06:24:42.862959', 'US');
INSERT INTO public.movies VALUES (156, 1168190, '더 레킹 크루', '["Action", "Comedy", "Crime", "Mystery"]', 'Ángel Manuel Soto', '["Dave Bautista", "Jason Momoa", "Temuera Morrison", "Morena Baccarin", "Roimata Fox"]', '''더 레킹 크루''는 사이가 멀어진 이복형제의 이야기를 다룬다. 조니와 제임스는 아버지의 의문스러운 죽음 이후 다시 뭉치게 된다. 진실을 쫓는 과정에서 묻혀 있던 비밀들이 밝혀지고, 가족을 갈라놓을 수 있는 거대한 음모가 드러난다.', 'https://image.tmdb.org/t/p/w500/bG8BPNRoOvTC9wIos7DIH1YWOqN.jpg', 2026, 0, 0, '2026-06-06 13:25:01.812429', 'US');
INSERT INTO public.movies VALUES (162, 1207162, 'Rise of the Conqueror', '["History", "Action", "Adventure"]', 'Jacob Schwarz', '["Christian Mortensen", "Mahesh Jadu", "Joshua Jo", "Sayed Badreya", "Yulduz Rajabova"]', NULL, 'https://image.tmdb.org/t/p/w500/9cRE0DsM6CNIiY9Ah3cd8oc3n1Y.jpg', 2026, 0, 0, '2026-06-06 13:25:02.547397', 'US');
INSERT INTO public.movies VALUES (2835, 516632, '엠티맨', '["Horror", "Mystery"]', NULL, '[]', '10대 아이들의 연이은 실종사건으로 공포에 빠진 마을. 은퇴한 전직 경찰 제임스는 친구의 딸 아만다의 실종에 의문을 품고 사건을 조사하기 시작한다. 그는 사건을 파헤치던 중, 전설로 기록된 공포의 존재 ‘엠티맨’과 그를 추종하는 비밀 단체가 아이들의 실종에 연루되어 있음을 깨닫게 된다. 엠티맨의 실체에 다가설수록 목숨마저 위협당하는 공포와 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/kfP5mBkAicN23vihkKHWlxUoLnO.jpg', 2020, 0, 0, '2026-06-07 12:17:50.147239', 'US');
INSERT INTO public.movies VALUES (153, 1470130, '더 모추어리 어시스턴트', '["Horror", "Mystery"]', 'Jeremiah Kipp', '["Willa Holland", "Paul Sparks", "John Adams", "Mark Steger", "Shelly Gibson"]', '최근 장례학을 졸업한 레베카 오웬스는 리버 필즈 장례식장에서 야간 근무를 하게 된다. 처음에는 시신 방부 처리, 서류 작업, 정리 정돈 등 단순한 일처럼 보였다. 하지만 레베카가 야간 근무를 시작하면서 상황은 어둡게 변하기 시작한다.', 'https://image.tmdb.org/t/p/w500/72AoFPC5TY4DfJwXXS9rPwPeReD.jpg', 2026, 0, 0, '2026-06-06 13:25:01.80551', 'US');
INSERT INTO public.movies VALUES (163, 1641319, '스나이퍼: 국경 없는 전쟁', '["Action", "Thriller"]', 'Trevor Calverley', '["Chad Michael Collins", "Ryan Robbins", "Manuel Rodriguez-Saenz", "Josh Brener", "Tom Berenger"]', '코스타 베르데에서 벌어진 비밀 작전이 국제적 스캔들로 번지자, 미국 정부는 글로벌 대응·정보팀(G.R.I.T.)과의 관계를 부인하며 그 요원들을 테러리스트로 낙인찍는다. 자신이 헌신해 온 조국으로부터 쫓기는 신세가 된 에이스 저격수 브랜든 베켓은 무단이탈을 감행하지만, 마지막으로 남은 동맹이었던 ‘피닉스 리벨리온’이 코스타 베르데의 냉혹한 총리를 위해 일하는 용병 부대 ‘아이언 리전’에 의해 궤멸되었다는 사실을 알게 되고, 동료 병사들은 투옥되는데...', 'https://image.tmdb.org/t/p/w500/tUmARo0TZEK1EaSuS6dU35FhDyU.jpg', 2026, 0, 0, '2026-06-06 13:25:02.549967', 'US');
INSERT INTO public.movies VALUES (160, 137051, 'Midnight Matinee', '["Horror", "Mystery", "Thriller"]', 'Richard Martin', '["Ron White", "Gillian Barber", "Jeff Schultz", "Beatrice Boepple", "Timothy Webber"]', NULL, 'https://image.tmdb.org/t/p/w500/czam6wq46B9UCZvq85vicElckFq.jpg', 1988, 0, 0, '2026-06-06 13:25:01.82172', 'US');
INSERT INTO public.movies VALUES (6000, 206324, '달려라 밀카 달려', '["History", "Drama"]', 'Rakeysh Omprakash Mehra', '["Farhan Akhtar", "Sonam Kapoor Ahuja", "Divya Dutta", "Pavan Malhotra", "Rebecca Breeds"]', '“날으는 시크” 로 명성을 날리던 밀카 싱은 1960년 로마 올림픽에서 그의 인생에 최대 경주를 망친다. 이 망신의 어둠을 뚧고 밀카는 그를 처음으로 달리기 시작하게 만든 과거를 직면하고 실수를 만회한다.', 'https://image.tmdb.org/t/p/w500/bXywc0CEzS1fIshPWWi4V8A58U3.jpg', 2013, 0, 0, '2026-06-08 06:52:44.473911', 'IN');
INSERT INTO public.movies VALUES (6001, 1441301, 'সপ্তডিঙার গুপ্তধন', '["Adventure", "Mystery", "Thriller"]', 'Dhrubo Banerjee', '["Abir Chatterjee", "Arjun Chakrabarty", "Ishaa Saha", "Rajatabha Dutta", "Kaushik Ganguly"]', NULL, 'https://image.tmdb.org/t/p/w500/vpsMRdcrXE4iQpOasSNtlZyhgrN.jpg', 2026, 0, 0, '2026-06-08 06:52:45.242024', 'IN');
INSERT INTO public.movies VALUES (6002, 564147, '케이.지.에프 : 전설의 시작', '["Action", "Thriller", "Adventure", "Crime"]', 'Prashanth Neel', '["Yash", "Srinidhi Shetty", "Ramachandra Raju", "Archana Jois", "Anant Nag"]', 'K.G.F. 지역의 가난한 미혼모에게서 태어난 소년 ‘록키’는 힘과 부를 갖기 위해 황금의 도시 봄베이로 떠나고, 시간이 지나 누구나 두려워하는 막강한 존재로 자라 악명을 떨치게 된다. 봄베이의 금 밀수 세력은 ‘록키’에게 거절할 수 없는 조건과 함께 라이벌 조직의 후계자인 ‘가루다’의 암살을 제안한다. ‘록키’는 ‘가루다’의 요새에서 착취당하는 수천명의 노예를 발견하고 참을 수 없는 분노를 느끼게 되는데...', 'https://image.tmdb.org/t/p/w500/r2wFKW50QV2gVyIs81HuY9Cv4ub.jpg', 2018, 0, 0, '2026-06-08 06:52:46.037741', 'IN');
INSERT INTO public.movies VALUES (6003, 1196364, 'थम्मा', '["Horror", "Comedy"]', 'Aditya Sarpotdar', '["Ayushmann Khurrana", "Rashmika Mandanna", "Nawazuddin Siddiqui", "Paresh Rawal", "Faisal Malik"]', NULL, 'https://image.tmdb.org/t/p/w500/udkbDwBbysCGEydt0FHnl9dVO2k.jpg', 2025, 0, 0, '2026-06-08 06:52:46.765772', 'IN');
INSERT INTO public.movies VALUES (2836, 1083884, '리틀마우스', '["Mystery", "Sci-Fi"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/bi7Aeaozl51cd5K6vAn8tI1lOW0.jpg', 2026, 0, 0, '2026-06-07 12:17:50.149609', 'US');
INSERT INTO public.movies VALUES (159, 1075175, '하우 투 해브 섹스', '["Drama"]', 'Molly Manning Walker', '["Mia McKenna-Bruce", "Lara Peake", "Enva Lewis", "Samuel Bottomley", "Shaun Thomas"]', '영국 십 대 소녀 태라, 스카이, 엠은 아무 제약 없이 자유롭게 즐기기 위해 그리스의 한 유명 휴양지에 도착한다. 매일 밤 술과 파티가 난무하는 그곳에서 그들은 한 무리의 젊은 친구들을 만나게 된다. 태라는 그 무리 중 하나인 소년을 마음에 두지만 쉽사리 그에게 표현하지 못하던 중에, 또 다른 소년 하나가 태라에게 관심을 보이기 시작하는데...', 'https://image.tmdb.org/t/p/w500/yQyoFCBLGJH5HXESmJAzaiXw9zU.jpg', 2023, 0, 0, '2026-06-06 13:25:01.819424', 'GB');
INSERT INTO public.movies VALUES (86, 1010581, '나의 잘못', '["Drama", "Romance", "Thriller"]', NULL, '[]', '노아는 남자 친구와 친구들이 있는 동네를 뒤로하고 엄마의 새 부자 남편 저택으로 이사를 가게 된다. 의붓오빠 닉과는 첫 만남부터 삐걱댔지만 곧 서로에게 이끌려 금지된 관계를 맺는다. 반항심과 고뇌로 가득 찬 그들의 인생은 송두리째 흔들리고 둘은 결국 뜨거운 사랑에 빠진다.', 'https://image.tmdb.org/t/p/w500/duT8Vks5FXwDkpxoR84xb2a6VB6.jpg', 2023, 0, 0, '2026-06-06 13:24:59.468651', 'US');
INSERT INTO public.movies VALUES (139, 597, '타이타닉', '["Drama", "Romance"]', 'James Cameron', '["Leonardo DiCaprio", "Kate Winslet", "Billy Zane", "Kathy Bates", "Frances Fisher"]', '"내 인생의 가장 큰 행운은 당신을 만난 거야" 우연한 기회로 티켓을 구해 타이타닉호에 올라탄 자유로운 영혼을 가진 화가 ‘잭’(레오나르도 디카프리오)은 막강한 재력의 약혼자와 함께 1등실에 승선한 ‘로즈’(케이트 윈슬렛)에게 한눈에 반한다. 진실한 사랑을 꿈꾸던 ‘로즈’ 또한 생애 처음 황홀한 감정에 휩싸이고, 둘은 운명 같은 사랑에 빠지는데… 가장 차가운 곳에서 피어난 뜨거운 사랑! 영원히 가라앉지 않는 세기의 사랑이 펼쳐진다!', 'https://image.tmdb.org/t/p/w500/132KjhVrWUqKFVfMAKKNkherytA.jpg', 1997, 0, 0, '2026-06-06 13:25:01.050223', 'US');
INSERT INTO public.movies VALUES (4065, 11423, '살인의 추억', '["Crime", "Drama", "Thriller"]', 'Bong Joon Ho', '["Song Kang-ho", "Kim Sang-kyung", "Kim Roi-ha", "Song Jae-ho", "Byun Hee-bong"]', '1986년 경기도. 젊은 여인이 무참히 강간, 살해당한 시체로 발견된다. 2개월 후 비슷한 수법의 강간살인사건이 연이어 발생하면서 사건은 세간의 주목을 받기 시작하고, 일대는 연쇄살인이라는 생소한 범죄의 공포에 휩싸인다. 사건 발생 지역에 특별수사본부가 설치되고, 수사본부는 구희봉 반장을 필두로 지역토박이 형사 박두만과 조용구, 그리고 서울 시경에서 자원해 온 서태윤이 배치된다. 육감과 폭력으로 수사를 진행하는 박형사와 증거와 과학수사를 추구하는 서형사는 수사 내내 마찰을 일으키는데...', 'https://image.tmdb.org/t/p/w500/3I1Ng4sxDUyPOdVu3lQ20N14PGE.jpg', 2003, 0, 0, '2026-06-08 06:26:33.858463', 'KR');
INSERT INTO public.movies VALUES (174, 773543, 'Соври мне правду', '["Drama", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/fPUI4KHQKggOdJg9YIBCFEecuU5.jpg', 2021, 0, 0, '2026-06-06 13:25:02.580241', 'US');
INSERT INTO public.movies VALUES (785, 1084199, '컴패니언', '["Horror", "Sci-Fi", "Thriller"]', NULL, '[]', '서로에게 딱 맞는 커플 ‘아이리스’와 ‘조시’는 친구들과 함께 호숫가의 별장으로 호화로운 휴가를 떠난다. 하지만 그곳에는 충격적인 사건이 기다리고 있는데…', 'https://image.tmdb.org/t/p/w500/dq7CEYFCvQPfYIpAXOvJr3w6VLY.jpg', 2025, 0, 0, '2026-06-06 13:25:26.518463', 'US');
INSERT INTO public.movies VALUES (4004, 11422, '미드웨이', '["Action", "Drama", "History"]', NULL, '[]', '영화는 미군의 두리틀 공습으로 시작된다. 일본의 진주만 공격이 있은 지 6개월 후인 1942년 6월. 미드웨이 대 해전이 발발했다. 일본 해군의 미드웨이 침공작전을 알아내 미 해군은 전격적인 대비를 펼치지만, 목숨을 바치며 항고모함에 달려드는 일본 해군비행단의 공격앞에 미군은 큰 피해를 입는데.', 'https://image.tmdb.org/t/p/w500/vCzGV28YFmWubUn1jh8ytagYocR.jpg', 1976, 0, 0, '2026-06-08 06:24:42.865771', 'US');
INSERT INTO public.movies VALUES (168, 1272837, '28년 후: 뼈의 사원', '["Horror", "Thriller", "Sci-Fi"]', 'Nia DaCosta', '["Ralph Fiennes", "Jack O''Connell", "Alfie Williams", "Erin Kellyman", "Chi Lewis-Parry"]', '분노 바이러스로부터 격리된 섬 홀리아일랜드로 돌아가지 않고 본토에 남기로 한 스파이크, 감염자와 공존하며 살아가는 켈슨 박사, 정체불명 인간 집단의 리더 지미가 얽히고 설키며 벌어지는 이야기', 'https://image.tmdb.org/t/p/w500/ubgOSHAEhv1ds8BNHodhCcI13oH.jpg', 2026, 0, 0, '2026-06-06 13:25:02.56352', 'GB');
INSERT INTO public.movies VALUES (3962, 619803, '범죄도시 2', '["Action", "Crime", "Thriller", "Adventure"]', 'Lee Sang-yong', '["Don Lee", "Son Suk-ku", "Choi Gwi-hwa", "Park Ji-hwan", "Heo Dong-won"]', '가리봉동 소탕작전으로부터 4년이 지난 2008년, 금천경찰서 강력반은 베트남으로 도주한 용의자를 인도받아 오라는 미션을 받는다. 그렇게 현지를 물색하던 마석도와 전일만은 용의자에게 미심쩍음을 느껴 추궁한 끝에, 악랄한 강해상의 존재를 알게 된다. 두 형사는 수사권이 없는 상황에도 한국과 베트남을 오가며 역대급 범죄를 저지르는 그를 잡겠다는 일념 하나로 호찌민 이곳저곳을 거침없이 누빈다.', 'https://image.tmdb.org/t/p/w500/9XkAF2pl2uliiuAORaWTgPmr6zG.jpg', 2022, 0, 0, '2026-06-08 06:24:41.136601', 'KR');
INSERT INTO public.movies VALUES (165, 1266990, 'Kulong', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/bZ8xfM705sK59dA1UCdRkEj7LHN.jpg', 2024, 0, 0, '2026-06-06 13:25:02.554726', 'US');
INSERT INTO public.movies VALUES (840, 770, '바람과 함께 사라지다', '["Drama", "Romance"]', NULL, '[]', '옛 전통과 관습에 묻혀 살아가는 미국 남부. 그러나 북부가 노예 제도를 폐지하고 이를 남부에도 강요하자 두 지역은 남북전쟁이란 소용돌이에 휘말린다. 아름다운 미모와 당당한 성격으로 마을 청년들의 선망의 대상이 되던 스칼렛 오하라는 애슐리 윌크스를 사랑하고 있었다. 그러나 그녀가 사랑하는 애슐리는 멜라니와 결혼을 해버리고 화가 난 스칼렛은 자신의 여동생이 좋아하는 멜라니의 남동생 찰스와 결혼을 한다. 얼마 후 애슐리와 찰스는 입대를 하게 되고, 결국 찰스는 전사하고 마는데...', 'https://image.tmdb.org/t/p/w500/s7nCZSELEAHO6xIcVj2ONolmC59.jpg', 1939, 0, 0, '2026-06-06 13:25:28.125915', 'US');
INSERT INTO public.movies VALUES (169, 216015, '그레이의 50가지 그림자', '["Drama", "Romance", "Thriller"]', 'Sam Taylor-Johnson', '["Dakota Johnson", "Jamie Dornan", "Jennifer Ehle", "Eloise Mumford", "Victor Rasuk"]', '순수한 사회 초년생인 여대생 ‘아나스타샤’는 어느 날, 아픈 친구를 대신해 모든 것을 다 가진 매력적인 CEO ‘크리스찬 그레이’의 인터뷰를 맡게 된다. 단숨에 사람을 매료시키는 ‘크리스찬 그레이’의 마력에 ‘아나스타샤’는 순식간에 빠져들고, 그 역시 순수한 아나스타샤를 점점 더 알고 싶어지게 된다.  내 취향은 아주 분명해.  한편, 원하는 것을 모두 들어줄 만큼 완벽한 ‘그레이’의 숨겨진 비밀을 알게 된 ‘아나스타샤’는 거부할 수 없는 본능에 눈을 뜨게 되는데…', 'https://image.tmdb.org/t/p/w500/iQaLakvYBzpmdHUB2h6h2aVY5nE.jpg', 2015, 0, 0, '2026-06-06 13:25:02.56621', 'US');
INSERT INTO public.movies VALUES (4066, 549649, '귀신과 함께 춤을', '["Fantasy", "Drama", "Comedy"]', 'Director Baek', '["Lee Kwang-hoon", "Ju Min-ha", "Jung Joo-ri", "Hong Hae-sol", "Geum Na-rang"]', '외로운 여자들의 밤을 책임져 주는 호스트 동재의 꿈에 유진이 나타난다. 하지만 곧 현실에서 그녀가 등장하여 본인을 도와 달라고 하는데. 도와 달라는 일이 사실 한번 자자고 하는 것이다. 처녀귀신으로 살아온 유진이 저승으로 가기 위해서는 동재와의 사랑이 필요한 것이었다. 하지만 동재는 그녀와의 잠자리를 꺼려한다. 사실 그녀는 동재가 혼자 짝사랑 하던 상대였던 것으로, 동재는 꿈에서도 현실에서도 그녀를 만나기를 기다려 왔기에 잠자리를 허락하게 되면 그녀를 잃게 될까 두렵다. 과연 그녀와 그는 잠자리를 할 것인가 아니면 아찔하고 무서운 동거를 계속 할 것인가?', 'https://image.tmdb.org/t/p/w500/mDmMjGuO93Z8bpSqiK0UaqhXhEC.jpg', 2018, 0, 0, '2026-06-08 06:26:34.529778', 'KR');
INSERT INTO public.movies VALUES (178, 1061474, '슈퍼맨', '["Sci-Fi", "Adventure", "Action"]', 'James Gunn', '["David Corenswet", "Rachel Brosnahan", "Nicholas Hoult", "Edi Gathegi", "Nathan Fillion"]', '슈퍼맨은 오늘도 세계 곳곳의 위협에 맞서 싸우지만, 시민들의 반응은 극과 극으로 갈린다. 한편, 렉스 루터는 슈퍼맨을 무너뜨릴 비밀을 손에 넣고 역대 최강의 슈퍼-빌런들과 함께 총 공격에 나선다. 슈퍼맨은 첫 패배와 함께 이들의 계속된 공세에 직면하고 모든 것을 바로잡기 위해 슈퍼독 크립토와 함께 맞서게 되는데... 과연 그는 이 전례 없는 위기에서 다시 날아오를 수 있을까?', 'https://image.tmdb.org/t/p/w500/kCXGCEsDqjzWJVDyHgBUg0AMetT.jpg', 2025, 0, 0, '2026-06-06 13:25:02.590951', 'US');
INSERT INTO public.movies VALUES (177, 1306368, '더 립', '["Action", "Thriller", "Crime"]', 'Joe Carnahan', '["Matt Damon", "Ben Affleck", "Teyana Taylor", "Steven Yeun", "Catalina Sandino Moreno"]', '허름한 은닉처에서 수백만 달러의 현금을 발견한 마이애미 경찰. 신뢰에 금이 가기 시작하면서 모든 사람, 모든 것이 의심의 대상이 된다.', 'https://image.tmdb.org/t/p/w500/o0d6Us9VWOW0nHhoB7ZNIwigARG.jpg', 2026, 0, 0, '2026-06-06 13:25:02.587955', 'US');
INSERT INTO public.movies VALUES (876, 103, '택시 드라이버', '["Crime", "Drama"]', NULL, '[]', '트래비스는 베트남전에서 귀환한 후 불면증에 시달리며 사회에 적응하지 못하고 있다. 그래서 그는 택시 운전기사로 일하며 뉴욕의 밤거리를 다니며 타락한 사회를 보고 자신이 직접 이 악들을 제거하려고 마음 먹는다. 어느 날 트래비스는 우연히 12살 짜리 창녀 아이리스를 만나게 되고 그녀의 인생을 구하려 하지만 그녀는 집으로 돌아가길 꺼려 한다. 자신은 아무 것도 할 수 없다는 생각에 무기력해진 트래비스는 4개의 권총을 구입하고 상원의원 팔렌타인을 저격하러 나선다. 하지만 엉뚱하게도 사창가에서 피비린내 나는 총격전을 벌인 끝에 아이리스를 묶어두고 있던 포주 스포츠를 살해하고 마는데...', 'https://image.tmdb.org/t/p/w500/yS66Q86Nfxs279o3kVZV29DEJ2Z.jpg', 1976, 0, 0, '2026-06-06 13:25:29.65781', 'US');
INSERT INTO public.movies VALUES (111, 1110034, '크라켄', '["Horror", "Action", "Thriller"]', NULL, '[]', '"깊은 피오르드 아래, 전설의 공포가 깨어난다"INSERT INTO public.movies VALUES (2099, 1530510, '멕시코 1986', '["Comedy", "History", "Drama"]', NULL, '[]', '풍자와 블랙 유머가 짙게 밴 《멕시코 1986》. 오직 멕시코 특유의 재치로 가능했던 무모하면서도 대담한 승부수를 통해 멕시코가 1986년 월드컵을 개최하게 된 과정을 그려낸다.', 'https://image.tmdb.org/t/p/w500/xOL58rwFCq7Zw0yg8OeLTU59NSt.jpg', 2026, 0, 0, '2026-06-07 12:17:17.245457', 'US');
INSERT INTO public.movies VALUES (6004, 1146210, 'हाउसफ़ूल 5', '["Comedy", "Mystery", "Thriller"]', 'Tarun Mansukhani', '["Akshay Kumar", "Abhishek Bachchan", "Riteish Deshmukh", "Jacqueline Fernandez", "Sonam Bajwa"]', NULL, 'https://image.tmdb.org/t/p/w500/iGvGkVOfsooO0ZBrhN5i6zXYUCy.jpg', 2025, 0, 0, '2026-06-08 06:52:48.396768', 'IN');
INSERT INTO public.movies VALUES (179, 1081003, '슈퍼걸', '["Action", "Adventure", "Sci-Fi"]', 'Craig Gillespie', '["Milly Alcock", "Matthias Schoenaerts", "Eve Ridley", "David Krumholtz", "Emily Beecham"]', '무자비한 적의 등장으로 인해 뜻밖의 동반자와 힘을 합치는 ''슈퍼걸''의 이야기를 그린 액션 블록버스터', 'https://image.tmdb.org/t/p/w500/2LSzCgS4StdD2hizIzwgLLCNVnN.jpg', 2026, 0, 0, '2026-06-06 13:25:02.593702', 'US');
INSERT INTO public.movies VALUES (6005, 811941, '데바라', '["Action", "Drama"]', 'Koratala Siva', '["N.T. Rama Rao Jr.", "Saif Ali Khan", "Prakash Raj", "Srikanth", "Kalaiyarasan"]', '전사의 후예들이 밀수꾼으로 전락하고 말았다. 마을의 명예를 회복하려는 리더의 핏빛 대장정을 그린 영화.', 'https://image.tmdb.org/t/p/w500/lQfuaXjANoTsdx5iS0gCXlK9D2L.jpg', 2024, 0, 0, '2026-06-08 06:52:49.158224', 'IN');
INSERT INTO public.movies VALUES (176, 226674, 'L''Adolescente', '["Drama"]', 'Jeanne Moreau', '["Simone Signoret", "Francis Huster", "Laetitia Chauveau", "Edith Clever", "Jacques Weber"]', NULL, 'https://image.tmdb.org/t/p/w500/v7yCEzF9BCF82lbp42X5ZLjIieo.jpg', 1979, 0, 0, '2026-06-06 13:25:02.585345', 'FR');
INSERT INTO public.movies VALUES (181, 1197306, '워킹맨', '["Action", "Crime", "Thriller"]', 'David Ayer', '["Jason Statham", "Jason Flemyng", "Merab Ninidze", "Maximilian Osinski", "Cokey Falkow"]', '전직 블랙 옵스 요원이었던 레본 케이드(제이슨 스타뎀)는 평범한 건설 노동자로 살아가며 딸과 함께 조용한 삶을 추구하고 있었으나 그의 상사의 딸이 인신매매 조직에 의해 납치되면서, 다시 과거의 전투 기술을 사용해 그녀를 구하기 위해 나서게 된다. 이 과정에서 시카고의 범죄 조직과 러시아 마피아와 얽히며, 부패와 폭력으로 가득 찬 어두운 세계를 마주하게 되는데...', 'https://image.tmdb.org/t/p/w500/pPokyKVPve6HNSgVliOlrMwU1lM.jpg', 2025, 0, 0, '2026-06-06 13:25:03.315499', 'GB');
INSERT INTO public.movies VALUES (186, 550, '파이트 클럽', '["Drama", "Thriller"]', 'David Fincher', '["Edward Norton", "Brad Pitt", "Helena Bonham Carter", "Meat Loaf", "Jared Leto"]', '자동차 회사의 리콜 심사관으로 일하는 주인공은 일상의 무료함과 공허함 속에서 늘 새로운 탈출을 꿈꾼다. 그는 비행기에서 자신을 비누 제조업자라고 소개하는 타일러 더든을 만난다. 집에 돌아온 주인공은 아파트가 누군가에 의해 폭파되었음을 발견하고, 타일러에게 도움을 청해 함께 생활하게 된다. 어느 날 밤 타일러는 주인공에게 자신을 때려달라고 부탁한다. 사람은 싸워봐야 진정한 자신을 알 수 있다는 것이다. 결국 이들은 매주 토요일 밤 술집 지하에서 맨주먹으로 격투를 벌이는 파이트 클럽을 결성하기에 이르는데...', 'https://image.tmdb.org/t/p/w500/eKZ07Ted7VHxQjbuZrRBFOamcKJ.jpg', 1999, 0, 0, '2026-06-06 13:25:03.329189', 'US');
INSERT INTO public.movies VALUES (191, 872585, '오펜하이머', '["Drama", "History"]', 'Christopher Nolan', '["Cillian Murphy", "Emily Blunt", "Matt Damon", "Robert Downey Jr.", "Florence Pugh"]', '세상을 구하기 위해 세상을 파괴할 지도 모르는 선택을 해야 하는 천재 과학자의 핵개발 프로젝트.', 'https://image.tmdb.org/t/p/w500/jpD6z9fgNe7OqsHoDeAWQWoULde.jpg', 2023, 0, 0, '2026-06-06 13:25:03.341803', 'US');
INSERT INTO public.movies VALUES (4555, 1396965, '명탐정 코난: 척안의 잔상', '["Animation", "Action", "Mystery", "Crime"]', 'Katsuya Shigehara', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Rikiya Koyama", "Yuji Takada"]', '국립천문대 노베야마의 괴한 침입 사건을 조사하던 나가노현경 형사 야마토 칸스케. 사건을 수사하던 중, 천문대의 파라볼라 안테나가 움직이자 10개월 전 눈사태 속 총격 피습으로 인한 왼쪽 눈의 상처에 갑자기 통증이 이는데… 그날 밤, 모리 코고로에게 형사 시절의 옛 동료 와니 형사의 전화가 걸려 온다. 나가노현 눈사태 사고의 내막을 조사하고 있던 와니는 사건 파일에서 모리 탐정의 이름을 발견, 참고 차 모리 탐정과 만나기로 한다. 약속 당일, 코난과 란도 모리 탐정을 따라 약속 장소로 향하지만 그곳에서 의문의 총성이 울려 퍼진다.', 'https://image.tmdb.org/t/p/w500/40nUEiyj9j7y2rryZf1JE9qp8ut.jpg', 2025, 0, 0, '2026-06-08 06:33:12.429838', 'JP');
INSERT INTO public.movies VALUES (187, 1084577, '볼스 업', '["Comedy", "Action", "Adventure"]', 'Peter Farrelly', '["Mark Wahlberg", "Paul Walter Hauser", "Sacha Baron Cohen", "Benjamin Bratt", "Luciano Szafir"]', '마케팅 임원 브래드 와 일라이자 가 월드컵을 상대로 대담한 전신 커버 콘돔 스폰서십을 제안하며 모든 것을 걸고 도전하는 이야기를 다룬 야하고 과장된 코미디. 브라질에서의 만취한 축하 행사가 전 세계적 스캔들을 촉발하고, 그들은 분노한 팬들, 범죄자들, 권력에 눈이 먼 관계자들로부터 도망쳐야 하는 상황에 이른다. 그들의 커리어를 구하고 살아서 집으로 돌아가기 위해서 말이다.', 'https://image.tmdb.org/t/p/w500/jntqR2lt6rV1e8e5lXJXadkcsti.jpg', 2026, 0, 0, '2026-06-06 13:25:03.332221', 'US');
INSERT INTO public.movies VALUES (189, 575265, '미션 임파서블: 파이널 레코닝', '["Action", "Thriller", "Adventure"]', 'Christopher McQuarrie', '["Tom Cruise", "Hayley Atwell", "Ving Rhames", "Simon Pegg", "Esai Morales"]', '디지털상의 모든 정보를 통제할 수 있는 사상 초유의 무기로 인해 전 세계 국가와 조직의 기능이 마비되고, 인류 전체가 위협받는 절체절명의 위기가 찾아온다. 이를 막을 수 있는 건 오직 존재 자체가 기밀인 에단 헌트와 그가 소속된 IMF뿐이다. 무기를 무력화하는 데 반드시 필요한 키를 손에 쥔 에단 헌트. 오랜 동료 루터와 벤지, 그리고 새로운 팀원이 된 그레이스, 파리, 드가와 함께 지금껏 경험했던 그 어떤 상대보다도 강력한 적에 맞서 모두의 운명을 건 불가능한 미션에 뛰어든다.', 'https://image.tmdb.org/t/p/w500/c5pDU8SW0ZbmO5jHfw7fX6keyyR.jpg', 2025, 0, 0, '2026-06-06 13:25:03.337001', 'US');
INSERT INTO public.movies VALUES (188, 1235877, 'ஜன நாயகன்', '["Action", "Drama", "Sci-Fi"]', 'H. Vinoth', '["Vijay", "Mamitha Baiju", "Bobby Deol", "Pooja Hegde", "Priyamani"]', NULL, 'https://image.tmdb.org/t/p/w500/jt8pfSIdi47YpFMMWVRr8w5u2S0.jpg', NULL, 0, 0, '2026-06-06 13:25:03.334673', 'IN');
INSERT INTO public.movies VALUES (192, 829557, '365일: 오늘', '["Romance", "Drama"]', NULL, '[]', '재결합하여 그 어느 때보다도 열렬한 관계를 이어가는 라우라와 마시모. 하지만 마시모의 가족 관계, 그리고 라우라의 마음을 얻으려는 수수께끼의 남자로 인해 삶이 복잡해진다.', 'https://image.tmdb.org/t/p/w500/nzrh7HhednL8gp08zR1rY3OAImC.jpg', 2022, 0, 0, '2026-06-06 13:25:03.344205', 'US');
INSERT INTO public.movies VALUES (2136, 1274706, '신원 미상의 여자', '["Thriller", "Crime"]', NULL, '[]', '컨테이너 안에서 자신에 대한 기억을 잃은 여인이 발견되자, 두 형사는 그녀의 정체와 그녀를 죽이려 하는 자의 정체를 밝히려 한다.', 'https://image.tmdb.org/t/p/w500/diKhdwtx2Ij3Qx2bnYIcSLT0EKT.jpg', 2026, 0, 0, '2026-06-07 12:17:18.944034', 'US');
INSERT INTO public.movies VALUES (4070, 851644, '20세기 소녀', '["Romance", "Drama"]', 'Bang Woo-ri', '["Kim You-jung", "Byeon Woo-seok", "Park Jung-woo", "Roh Yoon-seo", "Kim Sung-kyung"]', '보라의 둘도 없는 친구 연두는 심장 수술을 위해 미국에 가면서 자신이 좋아하는 남자 백현진에 대한 모든 정보를 수집해 달라고 보라에게 부탁한다. 보라는 백현진의 가장 친한 친구 풍운호와 먼저 친해지기로 한다. 하지만 보라의 서투른 계획은 예상치 못한 방향으로 전개된다. 새로운 세기가 오기 1년 전인 1999년, 17세가 된 보라는 첫사랑의 열병에 빠진다.', 'https://image.tmdb.org/t/p/w500/rSNtRQpCsDckczokmynAcVAt4Fm.jpg', 2022, 0, 0, '2026-06-08 06:26:37.179003', 'KR');
INSERT INTO public.movies VALUES (324, 4232, '스크림', '["Crime", "Horror", "Mystery"]', 'Wes Craven', '["David Arquette", "Neve Campbell", "Courteney Cox", "Matthew Lillard", "Rose McGowan"]', '작은 소도시 우즈버러에 사는 케이시에게 이상한 남자로부터 전화가 걸려온다. 비디오를 보려는 케이시에게 그 남자는 케이시의 남자 친구인 스티브의 목숨을 걸고 게임을 하자고 한다. 케이시가 문제를 맞추면 살고, 틀리면 남자친구가 죽는다. 문제는 ''13일의 금요일''에 나오는 살인마의 이름을 맞추는 것. 케이시는 문제를 풀지 못하고, 스티브는 처참하게 죽임을 당한다. 이튿날, 혼자 집에 있는 시드니에게도 이상한 전화가 걸려온다. 시드니는 케이시와는 달리 힘들게 괴전화의 마수에서 빠져 나온다. 그러나 시드니의 남자 친구 빌리가 살인 용의자로 체포되는데, 조사 후 무혐의로 풀려난다.', 'https://image.tmdb.org/t/p/w500/fvprcRjlvrgok1rvOJN4NY8Uqba.jpg', 1996, 0, 0, '2026-06-06 13:25:08.686593', 'US');
INSERT INTO public.movies VALUES (198, 264980, 'Das Mädchen mit der heißen Masche', '["Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/g3Mqv7hHPcjjmlpJrNSvx1lkZHx.jpg', 1972, 0, 0, '2026-06-06 13:25:03.358273', 'US');
INSERT INTO public.movies VALUES (197, 829560, '또 다른 365일', '["Romance", "Drama"]', NULL, '[]', '신뢰 문제를 극복하려 애쓰는 라우라와 마시모의 관계가 흔들리는 가운데, 끈질긴 나초가 둘을 갈라놓으려 한다.', 'https://image.tmdb.org/t/p/w500/3O5apa9wZiQr6IOrkpGQmsVAFev.jpg', 2022, 0, 0, '2026-06-06 13:25:03.355867', 'US');
INSERT INTO public.movies VALUES (199, 1533735, 'Nawab Cafe', '["Drama"]', 'Pramod Harsha', '["Shiva Kandukuri", "Rajiv Kanakala", "Rajkumar Kasireddy", "Teju Ashwini", "Liam"]', NULL, 'https://image.tmdb.org/t/p/w500/318rq88OAqNFlDhlh1HwWnHBTK4.jpg', 2026, 0, 0, '2026-06-06 13:25:03.360929', 'IN');
INSERT INTO public.movies VALUES (205, 11, '스타워즈 에피소드 4: 새로운 희망', '["Adventure", "Action", "Sci-Fi"]', 'George Lucas', '["Mark Hamill", "Harrison Ford", "Carrie Fisher", "Peter Cushing", "Alec Guinness"]', '공화국이 붕괴하고 제국이 수립된 뒤 20년, 제다이 기사단은 전멸하고 강력한 제국군의 횡포에 은하계는 공포에 휩싸여 있다. 그러던 중 공화국 재건을 노리는 반란군이 제국군의 비밀병기 데스스타 설계도를 훔쳐 달아나고 제국군은 이를 쫓는다. 하지만 결국 제국의 손에 붙잡히게 된 그들은 드로이드 R2-D2에 설계도를 넣어서 R2의 친구 C-3PO와 탈출시키는 데 성공하고, 두 드로이드 콤비는 타투인의 시골 마을에서 숙부와 함께 살고 있던 청년 루크 스카이워커에게 오게 되는데...', 'https://image.tmdb.org/t/p/w500/7XFfURIFCJxN1mfBg0SAjk5yGzg.jpg', 1977, 0, 0, '2026-06-06 13:25:04.091658', 'US');
INSERT INTO public.movies VALUES (196, 1022789, '인사이드 아웃 2', '["Animation", "Adventure", "Comedy", "Family"]', 'Kelsey Mann', '["Amy Poehler", "Maya Hawke", "Kensington Tallman", "Liza Lapira", "Tony Hale"]', '13살이 된 라일리의 행복을 위해 매일 바쁘게 머릿속 감정 컨트롤 본부를 운영하는 ‘기쁨’, ‘슬픔’, ‘버럭’, ‘까칠’, ‘소심’. 그러던 어느 날, 낯선 감정인 ‘불안’, ‘당황’, ‘따분’, ‘부럽’이가 본부에 등장하고, 언제나 최악의 상황을 대비하며 제멋대로인 ‘불안’이와 기존 감정들은 계속 충돌한다. 결국 새로운 감정들에 의해 본부에서 쫓겨나게 된 기존 감정들은 다시 본부로 돌아가기 위해 위험천만한 모험을 시작하는데…', 'https://image.tmdb.org/t/p/w500/x2BHx02jMbvpKjMvbf8XxJkYwHJ.jpg', 2024, 0, 0, '2026-06-06 13:25:03.35349', 'US');
INSERT INTO public.movies VALUES (6040, 1262547, '원사', '["Action", "Crime", "Drama"]', 'Suresh Triveni', '["Anil Kapoor", "Radhikka Madan", "Aditya Rawal", "Saurabh Shukla", "Mona Singh"]', '사별의 슬픔과 점점 멀어지는 딸 때문에 괴로워하던 퇴역 원사 아르준 마우리아. 민간인으로서 그의 삶은 단 한 번의 무모한 행동으로 뒤흔들린다. 오래된 상처가 다시 벌어지자, 그는 내면의 전사 본능을 불러내어 자신에게 깊숙이 다가온 새 전쟁에 맞서야 한다.', 'https://image.tmdb.org/t/p/w500/aTyyLXJGz8g4Le1ab0A5weYzPAx.jpg', 2026, 0, 0, '2026-06-08 06:53:16.440162', 'IN');
INSERT INTO public.movies VALUES (292, 1236153, '노 머시: 90분', '["Sci-Fi", "Action", "Thriller"]', 'Timur Bekmambetov', '["Chris Pratt", "Rebecca Ferguson", "Kali Reis", "Kylie Rogers", "Chris Sullivan"]', '모든 진실을 데이터로만 판단하는 냉혹한 AI 재판 시스템 ‘MERCY’에 맞서 사형을 피하기 위해 90분 안에 자신의 무죄를 증명해야 하는 형사(크리스 프랫)의 숨 막히는 반격을 그린 타임리미트 스릴러', 'https://image.tmdb.org/t/p/w500/fQ8Q3VAybCt6fHFJQD0kwd5azNL.jpg', 2026, 0, 0, '2026-06-06 13:25:07.179486', 'US');
INSERT INTO public.movies VALUES (203, 1368314, '패신저', '["Horror", "Thriller"]', 'André Øvredal', '["Lou Llobell", "Jacob Scipio", "Melissa Leo", "Joseph Lopez", "Tony Doupe"]', '캠핑카를 타고 유랑 생활을 시작한 커플 ‘매디’와 ‘타일러’는 어느 늦은 밤 도로 위에서 운전자가 사망하는 끔찍한 사고를 목격한다. 그 후 차량에 알 수 없는 표식이 생겨 불안한 매디의 눈에만 정체불명의 남자가 보이기 시작하고, 곧 그들은 ‘패신저’라고 불리우는 고대 악마의 표적이 되었음을 알게 된다. 목숨을 노리는 ‘패신저’의 공격을 피해 두 사람은 계속 도망치려 애쓰지만 집요한 추격은 그들의 턱밑까지 다다르는데…', 'https://image.tmdb.org/t/p/w500/igMwSTVF3Hm5pjouUmmwO4fABOo.jpg', 2026, 0, 0, '2026-06-06 13:25:04.085944', 'US');
INSERT INTO public.movies VALUES (212, 933260, '서브스턴스', '["Horror", "Sci-Fi", "Thriller"]', 'Coralie Fargeat', '["Demi Moore", "Margaret Qualley", "Dennis Quaid", "Edward Hamilton-Clark", "Gore Abrams"]', '한때 아카데미상을 수상하고 명예의 거리까지 입성한 대스타였지만 지금은 TV 에어로빅 쇼 진행자로 전락한 엘리자베스. 50살이 되던 날, 프로듀서에게서 어리고 섹시하지 않다는 이유로 해고를 당한다. 돌아가던 길에 차 사고로 병원에 실려간 엘리자베스는 매력적인 남성 간호사로부터 서브스턴스라는 약물을 권유받는다. 한 번의 주사로 젊고 아름답고 완벽한 수가 탄생하는데...', 'https://image.tmdb.org/t/p/w500/oUkeyrXvGUEylOQtlYMv9esNRiu.jpg', 2024, 0, 0, '2026-06-06 13:25:04.108166', 'GB');
INSERT INTO public.movies VALUES (215, 1380316, 'Is God Is', '["Drama", "Thriller"]', 'Aleshea Harris', '["Kara Young", "Mallori Johnson", "Vivica A. Fox", "Sterling K. Brown", "Janelle Monáe"]', NULL, 'https://image.tmdb.org/t/p/w500/c3nN8XnbYfj2ZEBcNqqlTbtLiQy.jpg', 2026, 0, 0, '2026-06-06 13:25:04.115064', 'US');
INSERT INTO public.movies VALUES (211, 8587, '라이온 킹', '["Animation", "Family", "Drama"]', 'Roger Allers', '["Matthew Broderick", "Moira Kelly", "Jeremy Irons", "Nathan Lane", "Ernie Sabella"]', '아프리카의 평화로운 왕국 프라이드랜드. 이곳을 다스리는 사자 무파사의 아들 심바가 태어난다. 왕의 동생 스카는 자신이 왕위를 차지하기 위해 하이에나들과 결탁하여 무파사를 죽이고 심바에게 죄를 뒤집어 씌워 멀리 내쫓는다. 간신히 목숨을 건진 심바는 유쾌한 미어캣 티몬과 멧돼지 품바와 함께 생활하며 어른이 된다. 어느 날 심바는 옛 친구 날라를 만나 프라이드랜드가 파괴되고 있다는 소식을 듣게 된다. 하지만 자신이 저지른 실수 때문에 고향으로 돌아가기를 거부하는 심바. 결국 아버지의 가르침과 자신의 운명을 깨달은 심바는 스카와 하이에나들을 물리치고 평화를 되찾기 위해 왕국으로 돌아가는데...', 'https://image.tmdb.org/t/p/w500/9Y048zYw66TWvpUtsiNK0uReiVX.jpg', 1994, 0, 0, '2026-06-06 13:25:04.105896', 'US');
INSERT INTO public.movies VALUES (293, 662707, '스타브라이트', '["Adventure", "Action"]', 'Francesco Lucente', '["John Rhys-Davies", "Ted Levine", "Elisabeth Röhm", "Diego Boneta", "Alexandra Dowling"]', '어려운 현실을 살아가는 한 여성이 마법 같은 세계로 도피하면서 소원을 이루는 비밀을 발견하게 되는 판타지 어드벤처.', 'https://image.tmdb.org/t/p/w500/m1Zl07DNYeSyNcz9hf8hDsS2oB5.jpg', 2026, 0, 0, '2026-06-06 13:25:07.18178', 'US');
INSERT INTO public.movies VALUES (213, 557, '스파이더맨', '["Action", "Sci-Fi"]', 'Sam Raimi', '["Tobey Maguire", "Willem Dafoe", "Kirsten Dunst", "James Franco", "Cliff Robertson"]', '평범하고 내성적인 고등학생 피터 파커는 우연히 방사능에 감염된 거미에 물린다.그 후, 피터는 손에서 거미줄이 튀어 나오고 벽을 기어 오를 수 있는 거미와 같은 능력을 갖게 된다. 다가오는 위험을 본능적으로 감지하는 초감각과 엄청난 파워를 소유하게 된 것이다. 피터는 짝사랑하던 메리 제인의 관심을 끌기 위해 멋진 스포츠카를 구입하는데 초능력을 처음 사용한다. 그러다 사랑하는 벤 아저씨의 죽음을 계기로 그 힘을 악의 세력에 대항하는데 쓰기로 결심한다. 한편 피터의 절친 해리 오스본의 아버지인 노만은 실험 도중 가스에 중독되어 악의 화신 그린 고블린으로 변하는데...', 'https://image.tmdb.org/t/p/w500/4xOhtzXGt0if74dTmS4qtizFelX.jpg', 2002, 0, 0, '2026-06-06 13:25:04.110443', 'US');
INSERT INTO public.movies VALUES (6060, 1444973, 'జటాధర', '["Action", "Horror", "Thriller"]', 'Venkat Kalyan', '["Sudheer Babu", "Sonakshi Sinha", "Shilpa Shirodkar", "Divya Khossla", "Indira Krishnan"]', NULL, 'https://image.tmdb.org/t/p/w500/91aJa79gHiTUWh86XFRMaD2MGjj.jpg', 2025, 0, 0, '2026-06-08 06:53:32.704725', 'IN');
INSERT INTO public.movies VALUES (6059, 611359, '거짓말하는 너, 속이는 나', '["Comedy", "Romance", "Family"]', 'Luv Ranjan', '["Ranbir Kapoor", "Shraddha Kapoor", "Anubhav Singh Bassi", "Dimple Kapadia", "Boney Kapoor"]', '꿈에 그리던 여자와 사랑에 빠져버린 이별 전문가 미키. 관계를 끝내는 법만 아는 남자가 관계를 유지하는 방법을 터득할 수 있을까?', 'https://image.tmdb.org/t/p/w500/zHLtNP4KP0GMi6p1ACf2QvVnBvI.jpg', 2023, 0, 0, '2026-06-08 06:53:31.947802', 'IN');
