INSERT INTO public.movies VALUES (2157, 1038918, '美女奉行 おんな牢秘抄II', '["Drama", "History"]', 'Toru Harada', '["Shin''ya Ohwada", "Ayako Takaishi", "Kyōko Aizome"]', NULL, 'https://image.tmdb.org/t/p/w500/i3Ouy0rMUHyKeHZV3PYl106OSwe.jpg', 1995, 0, 0, '2026-06-07 12:17:19.84836', 'JP');
INSERT INTO public.movies VALUES (226, 389, '12명의 성난 사람들', '["Drama"]', 'Sidney Lumet', '["Martin Balsam", "John Fiedler", "Lee J. Cobb", "E.G. Marshall", "Jack Klugman"]', '뉴욕시의 법정에 아버지를 칼로 찌른 한 소년의 살인혐의를 두고, 12인의 배심원들은 만장일치 합의를 통해 소년의 유무죄 여부를 가려줄 것을 요구받는다. 판사는 유죄일 경우 이 소년은 사형이 불가피하다는 것을 이들에게 미리 일러둔다.  배심원 방에 모인 이들은 투표를 통해 유무죄 여부를 가리기로 한다. 사람들이 전부 소년이 유죄로 판단하는 가운데, 오직 한 배심원만이 소년이 무죄라고 주장하는데...', 'https://image.tmdb.org/t/p/w500/yg2XzSxH10DVGNY73e7yZgLnDF5.jpg', 1957, 0, 0, '2026-06-06 13:25:04.852772', 'US');
INSERT INTO public.movies VALUES (227, 1673393, 'कृष्णावतरम भाग 1: हृदय (हृदयम्)', '["Adventure", "Romance", "Drama"]', 'Hardik Gajjar', '["Siddharth Gupta", "Sushmitha Bhat", "Sanskruti Jayana", "Nivaashiyni Krishnan", "J. Karthik"]', NULL, 'https://image.tmdb.org/t/p/w500/3dQwU1FaH2VsYFA9U9Shamkr1a8.jpg', 2026, 0, 0, '2026-06-06 13:25:04.855117', 'IN');
INSERT INTO public.movies VALUES (223, 1316092, '"폭풍의 언덕"', '["Romance", "Drama"]', 'Emerald Fennell', '["Margot Robbie", "Jacob Elordi", "Hong Chau", "Alison Oliver", "Shazad Latif"]', '자유를 꿈꾸는 캐서린과 상처 입은 영혼 히스클리프, 서로에게 완전히 빠져든 두 사람의 치명적인 사랑을 담은 이야기', 'https://image.tmdb.org/t/p/w500/oDXVQRHTomnm9N569Pu2d38IubP.jpg', 2026, 0, 0, '2026-06-06 13:25:04.844743', 'GB');
INSERT INTO public.movies VALUES (154, 1234821, '쥬라기 월드: 새로운 시작', '["Sci-Fi", "Adventure", "Action"]', 'Gareth Edwards', '["Scarlett Johansson", "Mahershala Ali", "Jonathan Bailey", "Rupert Friend", "Manuel Garcia-Rulfo"]', '지구 최상위 포식자가 된 공룡들이 인간 세상으로 나온 5년 후, 인간과 공룡의 위태로운 공존이 이어지는 가운데 인류를 구할 신약 개발을 위해 육지, 하늘, 바다를 지배하는 가장 거대한 공룡들의 DNA가 필요하게 된다. 불가능한 미션 수행을 위해 조라와 헨리 박사 그리고 던컨은 공룡들을 추적하며 지구상에서 가장 위험한 섬에 도착하고 폐쇄된 쥬라기 공원의 연구소가 감추어 온 충격적인 진실을 마주하게 되는데...', 'https://image.tmdb.org/t/p/w500/ygr4hE8Qpagv8sxZbMw1mtYkcQE.jpg', 2025, 0, 0, '2026-06-06 13:25:01.80783', 'US');
INSERT INTO public.movies VALUES (225, 1218925, '극장판 체인소 맨:  레제편', '["Animation", "Action", "Romance", "Fantasy"]', 'Tatsuya Yoshihara', '["Kikunosuke Toya", "Tomori Kusunoki", "Reina Ueda", "Shogo Sakata", "Karin Takahashi"]', '데블 헌터로 일하는 소년 ‘덴지’는 조직의 배신으로 죽음에 내몰린 순간 전기톱 악마견 ‘포치타’와의 계약으로 하나로 합쳐져 누구도 막을 수 없는 존재 ‘체인소 맨’으로 다시 태어난다. 악마와 사냥꾼, 그리고 정체불명의 적들이 얽힌 잔혹한 전쟁 속에서 ‘레제’라는 이름의 미스터리한 소녀가 ‘덴지’ 앞에 나타나는데… ‘덴지’는 사랑이라는 감정에 이끌려 지금껏 가장 위험한 배틀에 몸을 던진다!', 'https://image.tmdb.org/t/p/w500/oTn0PoR8gSMpMqJaT2pUtkkN0Ia.jpg', 2025, 0, 0, '2026-06-06 13:25:04.850395', 'JP');
INSERT INTO public.movies VALUES (220, 1235192, 'Wormtown', '["Sci-Fi", "Horror", "Adventure"]', 'Sergio Pinheiro', '["Caitlin McWethy", "Rachel Ryu", "Emily Soppe", "Maggie Lou Rader", "A.J. Baldwin"]', NULL, 'https://image.tmdb.org/t/p/w500/lE10ww38b7XA5LIagIsVQj9a8Hn.jpg', 2025, 0, 0, '2026-06-06 13:25:04.127244', 'US');
INSERT INTO public.movies VALUES (222, 1241982, '모아나 2', '["Adventure", "Animation", "Comedy", "Family", "Fantasy"]', 'David G. Derrick Jr.', '["Auliʻi Cravalho", "Dwayne Johnson", "Hualālai Chung", "Rose Matafeo", "David Fane"]', '바다를 누볐던 선조들에게서 예기치 못한 부름을 받은 모아나가 마우이와 다시 만나 새로운 선원들과 함께 오랫동안 잊혀진 멀고 위험한 바다 너머로 떠나는 특별한 모험을 담은 이야기', 'https://image.tmdb.org/t/p/w500/hwmwTFtMbzxAWbIOp1RyyiOCyx0.jpg', 2024, 0, 0, '2026-06-06 13:25:04.841805', 'US');
INSERT INTO public.movies VALUES (224, 43947, '네 무덤에 침을 뱉어라', '["Thriller", "Crime", "Horror"]', 'Steven R. Monroe', '["Sarah Butler", "Jeff Branson", "Tracey Walter", "Andrew Howard", "Chad Lindberg"]', '시골 마을로 글을 쓰러 온 미모의 여성작가 제니퍼(사라 버틀러 분)는 도시를 벗어나 여유롭게 전원의 분위기를 만끽한다. 하지만 혼자 한적한 산장에서 지내는 그녀의 존재를 알게 된 동네 청년들과 보안관은 그녀의 집에 몰래 들어가 잔혹하게 그녀를 강간하고 폭행한다. 죽은 줄 알았던 그녀는 자신에게 끔찍한 상처를 준 가해자들에게 잔인한 복수를 하기 시작 하는데…', 'https://image.tmdb.org/t/p/w500/vssZGmkZjmwZI9gMdVykycQgwlA.jpg', 2010, 0, 0, '2026-06-06 13:25:04.847961', 'US');
INSERT INTO public.movies VALUES (6063, 1166133, '브라마유감', '["Horror", "Thriller", "Drama"]', 'Rahul Sadasivan', '["Arjun Ashokan", "Mammootty", "Sidharth Bharathan", "Manikandan Achari", "Amalda Liz"]', '"광기의 시대" 17세기 케랄라의 한 민속 가수가 한 저택을 발견한다. 그 안에서 그는 수수께끼 같은 요리사와 강력한 주인을 만나게 되며, 이는 그의 삶을 바꾸는 일련의 사건들을 촉발시킨다.', 'https://image.tmdb.org/t/p/w500/x4geWE7mQwGyzNGLw1MKoDf8Fs7.jpg', 2024, 0, 0, '2026-06-08 06:53:34.950378', 'IN');
INSERT INTO public.movies VALUES (231, 458293, 'Michael Jackson: Searching for Neverland', '["Drama"]', 'Dianne Houston', '["Navi", "Chad L. Coleman", "Sam Adegoke", "Aidan Hanlon Smith", "Taegen Burns"]', NULL, 'https://image.tmdb.org/t/p/w500/mRZIiG4vJiCgJh4v2EPUVVTznC8.jpg', 2017, 0, 0, '2026-06-06 13:25:04.864316', 'US');
INSERT INTO public.movies VALUES (2840, 11970, '헤라클레스', '["Animation", "Family", "Fantasy", "Adventure", "Comedy", "Romance"]', NULL, '[]', '신들의 신전인 올림포스 산의 제왕인 제우스와 그의 아내 헤라가 아들 헤라클레스를 얻는다. 초인적인 신력을 타고난 헤라클레스에게 제우스는 페가소스라는 이름의 날개 달린 조랑말을 선물한다. 헤라클레스가 선물을 받는 순간 모든 신들의 갈채와 축복이 쏟아진다. 하지만 이때 질투와 시기에 불타는 눈으로 나타나는 악마가 있었으니. 죽은 사람의 영토를 지배하는 하이데스다. 축복 대신 저주를 퍼붓는 하이데스는 언젠가 올림포스 산을 차지하려는 속셈을 갖고 있다.  하지만 운명의 세 여신은 하이데스가 헤라클레스와 싸우면 지게 된다고 예언을 하고 분노한 하이데스는 우스꽝스럽고 작은 악마들, 페인과 패닉에게 헤라클레스를 처치할 것을 명한다. 페인과 패닉은 어린 헤라클레스를 유괴하여 땅으로 데려간 뒤, 신의 능력을 없애는 약물을 먹인다. 하지만 갑자기 나타난 인간들 때문에 마지막 한방울을 먹이지 못한 채 달아나고, 헤라클레스는 반은 신의 능력이 남겨진 인간이 되어 양부모의 손에 길러진다. 하지만 스스로도 컨트롤할 수 없는 초인적인 힘과 능력으로 사사건건 말썽을 일으켜 마침내 사람들로부터 쫓겨나고 만다. 그는 그의 양부모로 부터 그가 지니고 있던 제우스의 표식인 팬던트를 받아들고 제우스 신전에 찾아가 출생의 비밀을 알게되고 아버지와 재회를 한다.', 'https://image.tmdb.org/t/p/w500/b1qxxjws8UPcZ12B6Heg1CEWpnR.jpg', 1997, 0, 0, '2026-06-07 12:17:50.159524', 'US');
INSERT INTO public.movies VALUES (239, 285213, '해적: 바다로 간 산적', '["Action", "Adventure", "Comedy", "Fantasy"]', 'Lee Suk-hoon', '["Son Ye-jin", "Kim Nam-gil", "Oh Dal-su", "Park Cheol-min", "Yoo Hai-jin"]', '전대미문 국새 강탈 사건으로 조정은 혼란에 빠지고, 이를 찾기 위해 조선의 난다긴다 하는 무리들이 바다로 모여든다. 바다를 호령하다 졸지에 국새 도둑으로 몰린 위기의 해적, 고래는커녕 바다도 처음이지만 의기양양 고래사냥에 나선 산적, 건국을 코앞에 두고 발등에 불이 떨어진 개국세력까지! 국새를 차지하는 자, 천하를 얻을 것이다!', 'https://image.tmdb.org/t/p/w500/yMydhXOFTKPxxFBJiBMKv2JM7sl.jpg', 2014, 0, 0, '2026-06-06 13:25:04.882523', 'KR');
