INSERT INTO public.movies VALUES (230, 960505, 'ザ・本番　アイドル歌手篇', '["Drama"]', 'Akira Takatsuki', '["Yôko Nagai", "Mika Tanaka", "Juri Aoyama", "Yutaka Morita", "Shirô Machida"]', NULL, 'https://image.tmdb.org/t/p/w500/o5ST5VIhOlt3pbhvBlwoA0y5fK8.jpg', 1987, 0, 0, '2026-06-06 13:25:04.862087', 'JP');
INSERT INTO public.movies VALUES (243, 1340206, '튜너', '["Crime", "Thriller"]', 'Daniel Roher', '["Leo Woodall", "Havana Rose Liu", "Lior Raz", "Tovah Feldshuh", "Jean Reno"]', NULL, 'https://image.tmdb.org/t/p/w500/kyM60vcgf7lfofmZB4F5Rj7OrHW.jpg', 2026, 0, 0, '2026-06-06 13:25:05.604975', 'US');
INSERT INTO public.movies VALUES (237, 1336770, 'വാഴ II', '["Comedy", "Drama"]', 'Savin Sa', '["Hashir", "Alan Bin Siraj", "Ajin Joy", "Vinayak V", "Alphonse Puthren"]', NULL, 'https://image.tmdb.org/t/p/w500/1yLZ7kExd0UGGbaZW4LxmYD4OIf.jpg', 2026, 0, 0, '2026-06-06 13:25:04.878027', 'IN');
INSERT INTO public.movies VALUES (171, 1184918, '와일드 로봇', '["Family", "Animation", "Sci-Fi", "Adventure"]', 'Chris Sanders', '["Lupita Nyong''o", "Pedro Pascal", "Kit Connor", "Bill Nighy", "Stephanie Hsu"]', '우연한 사고로 거대한 야생에 불시착한 로봇 로즈는 주변 동물들의 행동을 배우며 낯선 환경 속에 적응해 가던 중, 사고로 세상에 홀로 남겨진 아기 기러기 브라이트빌의 보호자가 된다. 로즈는 입력되어 있지 않은 새로운 역할과 관계에 낯선 감정을 마주하고 겨울이 오기 전에 남쪽으로 떠나야 하는 브라이트빌을 위해 동물들의 도움을 받아 이주를 위한 생존 기술을 가르쳐준다. 그러나 선천적으로 몸집이 작은 브라이트빌은 짧은 비행도 힘겨워 하는데...', 'https://image.tmdb.org/t/p/w500/iA9NiygwSOBy8FjZjvdYOMxRUG0.jpg', 2024, 0, 0, '2026-06-06 13:25:02.571601', 'US');
INSERT INTO public.movies VALUES (235, 570595, 'Русская нимфетка: искушение', '["Drama", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/dYrocmJO2bCFI5aYkuaYogkrgmu.jpg', 2004, 0, 0, '2026-06-06 13:25:04.873464', 'US');
INSERT INTO public.movies VALUES (238, 1084187, '치명적이고 아름다운', '["Thriller", "Action", "Horror"]', 'Vicky Jewson', '["Maddie Ziegler", "Lana Condor", "Iris Apatow", "Millicent Simmonds", "Avantika"]', '액션으로 가득한 스릴러. 댄스 대회로 향하던 다섯 발레리나가 외딴 숲에서 길을 잃어 음산한 모텔에 머문다. 모텔 주인 데보라 카시메르와 맞서기 위해 그들은 발레를 무기로 삼아야 한다.', 'https://image.tmdb.org/t/p/w500/wlV000ToWdP5jtBBswT98DUibIS.jpg', 2026, 0, 0, '2026-06-06 13:25:04.880274', 'US');
INSERT INTO public.movies VALUES (397, 402431, '위키드', '["Drama", "Romance", "Fantasy"]', 'Jon M. Chu', '["Cynthia Erivo", "Ariana Grande", "Michelle Yeoh", "Jonathan Bailey", "Ethan Slater"]', '자신의 진정한 힘을 미처 발견하지 못한 엘파바, 자신의 진정한 본성을 아직 발견하지 못한 글린다. 전혀 다른 두 사람은 마법 같은 우정을 쌓아간다. 그러던 어느 날, 마법사의 초대를 받아 에메랄드 시티로 가게 되고 운명은 예상치 못한 위기와 모험으로 두 사람을 이끄는데...', 'https://image.tmdb.org/t/p/w500/mCB6biaBEafLGbs1eTImqlOgZj9.jpg', 2024, 0, 0, '2026-06-06 13:25:11.046031', 'US');
INSERT INTO public.movies VALUES (242, 1497348, 'Alas Roban', '["Drama", "Horror", "Mystery"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/dtJmnGZYuA2Ngnj3iv0T9EqCHBH.jpg', 2026, 0, 0, '2026-06-06 13:25:05.602285', 'US');
INSERT INTO public.movies VALUES (250, 875828, '피키 블라인더스: 불멸의 남자', '["Crime", "Drama"]', 'Tom Harper', '["Cillian Murphy", "Barry Keoghan", "Rebecca Ferguson", "Tim Roth", "Stephen Graham"]', '멀어진 아들이 나치 음모에 휘말리자, 스스로 은둔을 택했던 갱스터 토마스 셸비는 가족과 조국을 구하기 위해 버밍엄으로 돌아온다.', 'https://image.tmdb.org/t/p/w500/q1GPxUb7dfzfw4toS5TnRoSPVbn.jpg', 2026, 0, 0, '2026-06-06 13:25:05.623852', 'GB');
INSERT INTO public.movies VALUES (253, 4258, '무서운 영화 5', '["Comedy"]', 'Malcolm D. Lee', '["Ashley French", "Simon Rex", "Gracie Whitton", "Ava Kolker", "Erica Ash"]', '죽은 형의 아이들을 맡게 된 댄과 아내 조디는 한 연구기관에서 제공한 새집으로 이사를 한다. 방마다 설치된 수많은 카메라가 24시간 그들의 생활을 관찰하는데, 수상한 새집에서 조디는 섬뜩한 기운을 느낀다. 어느 순간 집안에서 정체 모를 소리와 사람의 기척이 들리고 심지어 물건까지 움직이기 시작한 것. 게다가 아이들이 ‘마마’라 부르는 존재가 점차 모습을 드러내기 시작하는데…  악마의 책에 의해 저주를 받은 ‘마마’, 좁혀오는 그녀의 손아귀에서 벗어나라!', 'https://image.tmdb.org/t/p/w500/f8Ms3vhJ1ANVtUmQUW4uZlLqKWH.jpg', 2013, 0, 0, '2026-06-06 13:25:05.632733', 'US');
INSERT INTO public.movies VALUES (193, 10138, '아이언맨 2', '["Adventure", "Action", "Sci-Fi"]', 'Jon Favreau', '["Robert Downey Jr.", "Gwyneth Paltrow", "Don Cheadle", "Scarlett Johansson", "Sam Rockwell"]', '세계 최강의 무기업체를 이끄는 CEO이자, 타고난 매력으로 화려한 삶을 살아가던 토니 스타크. 기자회견을 통해 자신이 아이언맨이라고 정체를 밝힌 이후, 정부로부터 아이언맨 수트를 국가에 귀속시키라는 압박을 받지만 이를 거부한다. 스타크 인더스트리의 운영권까지 수석 비서였던 페퍼 포츠에게 일임하고 히어로로서의 인기를 만끽하며 지내던 토니 스타크. 하지만 그 시각, 아이언맨의 수트 기술을 스타크 가문에 빼앗긴 후 쓸쓸히 돌아가신 아버지의 복수를 다짐해 온 위플래시는 수트의 원천 기술 개발에 성공, 치명적인 무기를 들고 직접 토니 스타크를 찾아 나선다.', 'https://image.tmdb.org/t/p/w500/ebJbC9OYAZJxy7bRUGryR72hfa2.jpg', 2010, 0, 0, '2026-06-06 13:25:03.346576', 'US');
INSERT INTO public.movies VALUES (245, 1078605, '웨폰', '["Horror", "Mystery"]', 'Zach Cregger', '["Julia Garner", "Josh Brolin", "Alden Ehrenreich", "Austin Abrams", "Benedict Wong"]', '평범한 수요일, 어느 마을 학교의 같은 반 학생 17명이 등교하지 않는다. 그날 새벽 2시 17분, 잠에서 깬 아이들이 어둠 속으로 달려가 돌아오지 않았기 때문이다. 유일하게 남은 아이는 입을 다물고, 사라진 아이들을 찾으려는 이들은 악몽 같은 현실을 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/lcu0aRFg7lzmzxGzpkYCeN4XRjh.jpg', 2025, 0, 0, '2026-06-06 13:25:05.610384', 'US');
INSERT INTO public.movies VALUES (921, 273481, '시카리오:  암살자의 도시', '["Action", "Crime", "Thriller"]', NULL, '[]', '미국과 멕시코의 국경지역 후아레즈는 멕시코 최대 마약조직의 본거지이자 온갖 범죄의 온상지. FBI 요원 케이트는 어린이 납치사건을 수사하다가 멕시코 마약 조직의 정체를 알게 되고 CIA가 계획하는 마약 조직 소탕 작전에 자원한다. 그녀는 그곳에서 작전을 이끄는 책임자 맷과 멕시코 검사 출신의 알레한드로를 만난다. 작전이 전개되면서 수사는 법의 테두리를 넘지 말아야 한다는 케이트의 정의와 원칙은 수단과 방법을 가리지 않고 임무를 완수하려는 맷과 개인적인 복수를 위해 작전에 개입한 알레한드로 때문에 흔들리는데...', 'https://image.tmdb.org/t/p/w500/oVA4Rx01OUAYdLOiBNBPjaG7I7v.jpg', 2015, 0, 0, '2026-06-06 13:25:31.913716', 'US');
INSERT INTO public.movies VALUES (934, 335787, '언차티드', '["Action", "Adventure", "Mystery"]', NULL, '[]', '평범한 삶을 살던 네이선은 인생을 바꿀 뜻밖의 제안을 받는다. 그의 미션은 크루와 함께 사라진 형과 500년 전 잃어버린 천문학적인 가치를 지닌 트레져를 찾아내는 것. 그러나 몬카다의 위협 속, 누구보다 빠르게 미지의 세계에 닿기 위해 결단을 내려야만 하는데…', 'https://image.tmdb.org/t/p/w500/mEHmuzE0vam89FGLiZ0HkZ8CMVn.jpg', 2022, 0, 0, '2026-06-06 13:25:31.954752', 'US');
INSERT INTO public.movies VALUES (912, 512200, '쥬만지: 넥스트 레벨', '["Adventure", "Comedy", "Fantasy"]', NULL, '[]', '쥬만지 게임으로부터 가까스로 탈출해 평화로운 일상을 보내고 있었던 스펜서와 친구들. 어느 날, 스펜서는 망가져버린 쥬만지 게임 속으로 사라지고 그를 찾기 위해 친구들은 다시 위험천만한 게임 속으로 들어간다. 우연히 함께 빨려 들어간 스펜서의 할아버지 에디&마일로와 랜덤으로 선택된 새로운 아바타가 된 이들은 정글부터 설산, 사막까지 한층 진화된 예측 불가능한 게임 속에서 목숨을 건 미션을 수행하게 되는데...', 'https://image.tmdb.org/t/p/w500/n7KDDIWOY5IZrGlkeizuFMZfJFl.jpg', 2019, 0, 0, '2026-06-06 13:25:31.178841', 'US');
INSERT INTO public.movies VALUES (258, 603692, '존 윅 4', '["Action", "Thriller", "Crime"]', 'Chad Stahelski', '["Keanu Reeves", "Donnie Yen", "Bill Skarsgård", "Ian McShane", "Laurence Fishburne"]', '죽을 위기에서 살아난 존 윅은 최고 회의를 쓰러트릴 방법을 찾아낸다. 비로소 완전한 자유의 희망을 보지만, 빌런 그라몽 후작과 전 세계의 최강 연합은 존 윅의 오랜 친구까지 적으로 만들어 버리고, 새로운 위기에 놓인 존 윅은 최후의 반격을 준비하는데...', 'https://image.tmdb.org/t/p/w500/h3LsdSBzhRnBebz4BTpAhh63PD3.jpg', 2023, 0, 0, '2026-06-06 13:25:05.647309', 'US');
INSERT INTO public.movies VALUES (259, 519182, '슈퍼배드 4', '["Action", "Animation", "Comedy", "Family", "Sci-Fi"]', 'Chris Renaud', '["Steve Carell", "Kristen Wiig", "Will Ferrell", "Sofía Vergara", "Miranda Cosgrove"]', '슈트-업 하고 악당 전담 처리반 AVL이 된 에이전트 미니언즈와 미니언즈 만큼 귀여운 그루 주니어가 태어나면서 더욱 완벽해진 그루 패밀리. 이들 앞에 과거 그루의 고등학교 동창이자 그에게 체포당했던 빌런 맥심이 등장하고, 오직 그루를 향한 복수심에 불타올라 탈옥까지 감행한 맥심은 그루 패밀리의 뒤를 바짝 추격하며 위협을 가하기 시작하는데... 과연 에이전트 미니언즈와 그루 패밀리는 맥심을 막아낼 수 있을까?', 'https://image.tmdb.org/t/p/w500/vZmCFVff9JySHTUp9zbYUIAcxzc.jpg', 2024, 0, 0, '2026-06-06 13:25:05.651131', 'US');
INSERT INTO public.movies VALUES (827, 10198, '공주와 개구리', '["Animation", "Romance", "Fantasy", "Family"]', NULL, '[]', '1930년대 미국 뉴올리언스. 티아나(애니카 노니 로즈)는 밤낮없이 아르바이트를 뛰며 돈을 모은다. 일찍 돌아가신 아빠(테렌스 하워드)의 꿈이었으며 이제는 그녀 본인의 목표가 된 뉴올리언스 최고의 레스토랑을 열기 전까지, 그녀에겐 연애할 시간도 없다. 그러다가 우연히 사악한 부두마법사 파실리에(키스 데이비드)에게 휘말려 개구리로 변해버린 나빈 왕자(브루노 캠포스)를 마주친다. 키스 한번이면 개구리가 왕자로 변한다는 공식을 믿고 티아나는 나빈에게 키스하지만 오히려 티아나까지 개구리로 변해버리는데...', 'https://image.tmdb.org/t/p/w500/rlDgcM2cLbnNCmUJRGByuyCl0yt.jpg', 2009, 0, 0, '2026-06-06 13:25:28.094573', 'US');
INSERT INTO public.movies VALUES (260, 1487604, 'La casaca de Dios', '["Comedy", "Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/v56hSpcEnS0joV9lUn9bKpPdktl.jpg', 2026, 0, 0, '2026-06-06 13:25:05.654599', 'US');
INSERT INTO public.movies VALUES (257, 687259, '镜花风月三之螺女挑情', '["Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/m4ALMhsuqOOUkkABvgQWfrgoL8y.jpg', 1982, 0, 0, '2026-06-06 13:25:05.644337', 'US');
INSERT INTO public.movies VALUES (264, 798645, '더 러닝 맨', '["Action", "Thriller", "Sci-Fi"]', 'Edgar Wright', '["Glen Powell", "William H. Macy", "Lee Pace", "Michael Cera", "Emilia Jones"]', '실직한 가장 ‘벤 리처즈’가 거액의 상금을 위해 30일간 잔인한 추격자들로부터 살아남아야 하는 글로벌 서바이벌 프로그램에 참가하며 펼쳐지는 추격 액션 블록버스터', 'https://image.tmdb.org/t/p/w500/klfSEbFOquMFjBQJ5uKAfp0rrsK.jpg', 2025, 0, 0, '2026-06-06 13:25:06.387695', 'US');
INSERT INTO public.movies VALUES (216, 920728, '우리 지금 할래', '["Romance"]', 'Park Bum-soo', '["수지", "Han Seok-bong"]', '무인도나 다름없는 외딴 섬에 섬을 지키는 남자와 그 남자의 여자 수희가 살고 있다. 그리고 사랑하던 남자에게 버림을 받고 정신을 놓아버린 복순. 이렇게 오직 세 명만이 사는 섬 ''죽어도''. 그러던 어느 날 이 섬에 무언가 비밀을 간직한 것처럼 보이는 사진작가가 찾아온다. 하지만 이 섬을 지키는 남자는 그 방문객을 오해하게 되고 그로 인해 그를 죽이고 만다. 죽은 사진작가를 사랑했던 복순은 사진작가의 죽음을 보고 자살을 한다. 사람을 죽이고 정신이 나간 남자는 같이 사는 수희에게서 이야기를 들으며 나중에서야 모든 비밀을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/mQ95TSIl1QqNWCMQs1lTRgZUWT8.jpg', 2016, 0, 0, '2026-06-06 13:25:04.117414', 'KR');
INSERT INTO public.movies VALUES (4080, 982843, '대홍수', '["Sci-Fi", "Adventure", "Drama"]', 'Kim Byung-woo', '["Kim Da-mi", "Park Hae-soo", "Kwon Eun-seong", "Jeon Hye-jin", "Park Byung-eun"]', '대홍수가 덮친 지구 종말의 날. 물에 잠겨가는 아파트에 갇힌 연구원과 어린 아들이 탈출을 시도한다. 그 순간 도착한 중대 임무. 그녀는 인류의 운명이 걸린 과제를 끝까지 완수할 수 있을까.', 'https://image.tmdb.org/t/p/w500/8SQWFPE6UhNGIMDimAOOg4T5Hem.jpg', 2025, 0, 0, '2026-06-08 06:26:44.628434', 'KR');
INSERT INTO public.movies VALUES (910, 115290, '블루 라군: 어웨이크닝', '["Drama", "Adventure", "Romance"]', NULL, '[]', '수학여행에서 일어난 작은 사고 때문에 무인도로 휩쓸려간 에마와 딘. 공통점이라고는 찾기 힘든 둘 사이에 불꽃이 튀기 시작한다.', 'https://image.tmdb.org/t/p/w500/ptsBY9Aqo4Mn0V1krI5s8WfFxzW.jpg', 2012, 0, 0, '2026-06-06 13:25:31.172971', 'US');
INSERT INTO public.movies VALUES (269, 1228246, '프레디의 피자가게 2', '["Horror", "Thriller"]', 'Emma Tammi', '["Josh Hutcherson", "Piper Rubio", "Elizabeth Lail", "Matthew Lillard", "Freddy Carter"]', '소문과 괴담에 휘말려 폐업한 ‘프레디의 피자가게’ 본점이 수십년 만에 다시 열리고, 그곳에 오랫동안 잠들어 있던 신형 프레디와 친구들이 눈을 뜨게 된다. 안면 인식 시스템을 가진 한층 더 기괴하고 오싹해진 신형 애니메트로닉스들은 이제 피자가게 밖으로 나와 세상을 공포에 몰아넣기 시작하는데…', 'https://image.tmdb.org/t/p/w500/kEmPnUUXaF9hPgDMlc0eJht5JYO.jpg', 2025, 0, 0, '2026-06-06 13:25:06.399298', 'US');
INSERT INTO public.movies VALUES (270, 58, '캐리비안의 해적: 망자의 함', '["Adventure", "Fantasy", "Action"]', 'Gore Verbinski', '["Johnny Depp", "Orlando Bloom", "Keira Knightley", "Jack Davenport", "Bill Nighy"]', '잭 스패로우는 블랙펄을 되찾아 포트 로열을 떠났지만 그를 기다리는 것은 수평선만이 아니었다. 유령선 플라잉 더치맨의 선장 데이비 존스는 잭이 자신에게 피로 진 빚이 있다면서 빚을 갚거나 영혼을 내놓으라고 요구한다. 불행 중 다행한 것은 잭에게 피의 빚 외에도 중매의 은총이 있었다는 것. 결혼을 앞둔 윌 터너와 엘리자베스 스완은 만사를 제쳐두고 옛 친구를 도우러 온다. 잭을 구할 수 있는 단 한 가지 방법은 세상 끝에 있다는 망자의 함을 찾는 것 뿐인데...', 'https://image.tmdb.org/t/p/w500/6tD4oT7C01aZLVfoZDz5VFVbJCi.jpg', 2006, 0, 0, '2026-06-06 13:25:06.401705', 'US');
INSERT INTO public.movies VALUES (2853, 297090, '고문 클럽', '["Drama", "Comedy"]', 'Kōta Yoshida', '["Noriko Kohara", "Haruna Yoshizumi", "Yuki Mamiya", "Mika Yano", "Nami Motoyama"]', '꿈에도 생각 못한 고급 사립여고에 입학하게 된 유즈키. 어느 화창한 봄날, 그녀는 학교에서 정식으로 승인 받은 고문클럽에 강제로 끌려간다. 꾸준한 연습과 습득으로 고문을 예술로 승화시키는 고문클럽. 입학시험 때 첫눈에 반한 선배, 아오이가 클럽에 있는 것을 알게 된 유즈키는 클럽에 가입하여 하드트레이닝을 시작한다. 섹슈얼한 고문의 세계로 여러분을 초대합니다! (2014년 제18회 부천국제판타스틱영화제)', 'https://image.tmdb.org/t/p/w500/oGbY4oF5vTM57Ggp7cxQxC7jJCg.jpg', 2014, 0, 0, '2026-06-07 12:17:51.018897', 'JP');
INSERT INTO public.movies VALUES (267, 76600, '아바타: 물의 길', '["Action", "Adventure", "Sci-Fi"]', 'James Cameron', '["Sam Worthington", "Zoe Saldaña", "Sigourney Weaver", "Stephen Lang", "Kate Winslet"]', '판도라 행성에서 제이크 설리와 네이티리가 이룬 가족이 겪게 되는 무자비한 위협과 살아남기 위해 떠나야 하는 긴 여정과 전투, 그리고 견뎌내야 할 상처에 대한 이야기를 그렸다. 살아남기 위해 설리 가족이 숲에서 바다로 터전을 옮기면서 겪게 되는 화합의 과정, 그리고 곳곳에서 도사리는 새로운 위협까지 역경 속에서 더 아름답게 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/u2aVXft5GLBQnjzWVNda7sdDpdu.jpg', 2022, 0, 0, '2026-06-06 13:25:06.394725', 'US');
INSERT INTO public.movies VALUES (271, 1115544, '마이크 & 닉 & 닉 & 앨리스', '["Comedy", "Sci-Fi", "Crime"]', 'BenDavid Grabinski', '["James Marsden", "Vince Vaughn", "Eiza González", "Keith David", "Jimmy Tatro"]', '갱스터 둘과 그들이 사랑하는 여자가 위험천만한 하룻밤을 무사히 보내기 위해 고군분투하는 유쾌하고 개성 넘치는 청불 액션 코미디. 죽을 위기에 처한 것도 모자라 그들 앞에 타임머신이란 엄청난 변수가 등장한다.', 'https://image.tmdb.org/t/p/w500/7F0jc75HrSkLVcvOXR2FXAIwuEv.jpg', 2026, 0, 0, '2026-06-06 13:25:06.40398', 'US');
INSERT INTO public.movies VALUES (273, 4588, '색, 계', '["Action", "Drama", "Romance", "Thriller"]', NULL, '[]', '1938년 홍콩, 친일파의 핵심 인물이자 정보부 대장인 이(양조위)와 그를 암살하기 위해 막 부인으로 신분을 위장하고 접근하는 왕치아즈(탕웨이). 그녀의 임무는 자신의 신분을 위장하고 이의 아내(조안첸)에게 접근하여 신뢰를 쌓은 후 이에게 가까워 지는 것. 둘은 처음 본 순간부터 운명 같은 강렬한 이끌림을 느끼게 되지만 이의 상하이 발령으로 헤어지게 되고 암살 계획 또한 무산된다. 1941년 상하이, 다시 시작 된 암살계획으로 둘은 상하이에서 재회하게 된다. 경계를 푼 이, 그에게 다른 감정을 느끼는 왕치아즈. 이들은 서로에게 빠져들게 되는데...', 'https://image.tmdb.org/t/p/w500/xd7dT3mh7cUk1rqDs7AaqJ5NZES.jpg', 2007, 0, 0, '2026-06-06 13:25:06.40858', 'US');
INSERT INTO public.movies VALUES (294, 1252309, '나의 S 파트너', '["Romance", "Drama"]', NULL, '[]', '주디는 어느 날, 회사의 인수합병을 위해 방문한 억만장자 CEO 에릭과 엘리베이터에 갇히게 된다. 우연히 시작된 치명적인 끌림. 주디는 에릭의 유혹 앞에 흔들리고 만다. 그의 따뜻한 진심에 마음을 연 주디는 결국, 위험하고 달콤한 제안을 받아들인다. 에릭이 이끄는 금기의 세계에 발을 들인 주디. 비밀스러운 만남이 이어질수록, 그녀는 에릭의 숨겨진 진짜 얼굴을 알고 싶어지고, 동시에 자신 안에 잠든 본능까지 깨워가는데…', 'https://image.tmdb.org/t/p/w500/5rtaLwyKAjbceww4J1ro8aA8BNB.jpg', 2024, 0, 0, '2026-06-06 13:25:07.184094', 'US');
INSERT INTO public.movies VALUES (266, 429, '석양의 무법자', '[]', NULL, '[]', '미국의 남북전쟁이 한창인 때, 블론디는 멕시코인 총잡이 투코와 함께 동업 중이다. 블론디는 현상범 투코를 잡아 현상금을 받고, 투코가 교수형을 당하는 순간 구해주는 역할. 한편 세텐자라 불리우는 범죄자는 엄청나 돈이 묻힌 비밀장소를 추적 중이다. 그런데, 투코와 실랑이를 벌이던 블론디는 돈이 묻힌 장소를 죽어가는 사람에게 듣게 되고, 결국 둘은 돈을 찾아 나서는데...', 'https://image.tmdb.org/t/p/w500/s7qPuoj4liolAtmx9vcL6AyaZzR.jpg', 1966, 0, 0, '2026-06-06 13:25:06.392427', 'US');
INSERT INTO public.movies VALUES (275, 541671, '발레리나', '["Action", "Thriller", "Crime"]', 'Len Wiseman', '["Ana de Armas", "Keanu Reeves", "Ian McShane", "Anjelica Huston", "Gabriel Byrne"]', '살해당한 아버지의 복수를 원하는 이브는 전설적인 킬러 존 윅을 배출한 암살자 양성 조직 루스카 로마에서 혹독한 훈련을 거쳐 발레리나이자 킬러로 성장한다. 아버지의 죽음에 얽힌 자들을 쫓던 이브는 루스카 로마를 뛰어넘는 거대한 조직의 정체를 알아차리게 되고, 킬러들의 표적이 된 이브의 눈앞에 존 윅이 나타나는데…', 'https://image.tmdb.org/t/p/w500/rGe64vmd9cpvwiTD5OGWJezBnNg.jpg', 2025, 0, 0, '2026-06-06 13:25:06.413375', 'US');
INSERT INTO public.movies VALUES (280, 769, '좋은 친구들', '["Drama", "Crime"]', 'Martin Scorsese', '["Robert De Niro", "Ray Liotta", "Joe Pesci", "Lorraine Bracco", "Paul Sorvino"]', '아일랜드계 이탈리아인 헨리 힐와 토미는 13살에 마피아에 입문해 지미와 함께 트럭이나 공항 화물을 훔치는 일을 한다. 결혼 후에도 마피아 생활을 계속하는 헨리는 이제 조직에서도 안정된 위치와 경제적 여유를 갖는다.  어느 날 헨리와 지미는 공항터미널 사건을 모의해 현금 6백만 달러라는 엄청한 돈을 훔친다. 이 사건을 은폐하기 위해 혈안이 된 지미는 모의에 참여했던 사람들을 죽이고, 토미는 마피아 조직에 가담했다가 살해당한다. 엎친데 덮친격으로 헨리마저 마약거래로 경찰서에 잡혀 들어가는데...', 'https://image.tmdb.org/t/p/w500/zF9hSBS1t7PVFLo01GrJ3OjGi67.jpg', 1990, 0, 0, '2026-06-06 13:25:06.424804', 'US');
INSERT INTO public.movies VALUES (276, 106646, '더 울프 오브 월 스트리트', '["Crime", "Drama", "Comedy"]', 'Martin Scorsese', '["Leonardo DiCaprio", "Jonah Hill", "Margot Robbie", "Matthew McConaughey", "Kyle Chandler"]', '부자가 되는 게 꿈인 22살의 조던 벨포트는 꿈을 실현코자 월스트리트에 발을 들인다. 고객의 돈을 내 주머니로 끌어들이는 비법은 코카인과 마스터베이션에 있다고 말하는 괴짜들이 하루 종일 전화기를 붙들고 사기치는 곳, 조던에게 월스트리트의 첫인상은 그랬다. 첫 직장에 몸담은 지 1년 만에 블랙 먼데이를 경험하고 실직자가 된 조던은 현란한 언변을 무기로 위기를 기회로 만들어버린다. 친구들을 불러모아 스트래튼 오크몬트사를 세운 그는 수수료가 비싼 투기적 저가주을 팔아 돈을 긁어모으고, 주가 조작으로 억만장자가 된 후 술과 마약, 여자를 탐닉한다. 그사이 FBI는 그의 뒤를 캐기 시작하는데...', 'https://image.tmdb.org/t/p/w500/rdBYtoxLvd8J9PsVYVGd7FGzQux.jpg', 2013, 0, 0, '2026-06-06 13:25:06.415679', 'US');
INSERT INTO public.movies VALUES (277, 329505, 'Il peccato di Lola', '["Drama", "Comedy", "Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/iQt9Kydd8yn9xfBvYeKec56glyv.jpg', 1984, 0, 0, '2026-06-06 13:25:06.41794', 'US');
INSERT INTO public.movies VALUES (953, 550988, '프리 가이', '["Comedy", "Adventure", "Sci-Fi"]', NULL, '[]', '평범한 직장, 절친 그리고 한 잔의 커피.  평화로운 일상 속 때론 총격전과 날강도가 나타나는 버라이어티한 ‘프리시티’에 살고 있는 ‘가이’. 그에겐 뭐 하나 부족한 것이 없었다. 우연히 마주친 그녀에게 한눈에 반하기 전까지는…  갖은 노력 끝에 다시 만난 그녀는 ‘가이’가 비디오 게임 ‘프리시티’에 사는 배경 캐릭터이고, 이 세상은 곧 파괴될 거라 경고한다. 혼란에 빠진 ‘가이’ 그러나 그는 ‘프리시티’의 파괴를 막기 위해 더 이상 배경 캐릭터가 아닌, 히어로가 되기로 결심한다.', 'https://image.tmdb.org/t/p/w500/sEYyQ4lW43jg77yTiTSRUNVdtMc.jpg', 2021, 0, 0, '2026-06-06 13:25:32.716304', 'US');
INSERT INTO public.movies VALUES (2180, 1646787, 'Sundutan', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/2neZgVuY7prWIak5hhNKT53Hk0N.jpg', 2026, 0, 0, '2026-06-07 12:17:20.70969', 'US');
INSERT INTO public.movies VALUES (295, 385687, '분노의 질주: 라이드 오어 다이', '["Action", "Crime", "Thriller"]', 'Louis Leterrier', '["Vin Diesel", "Michelle Rodriguez", "Tyrese Gibson", "Ludacris", "John Cena"]', '돔과 그의 패밀리 앞에 나타난 운명의 적 단테. 과거의 그림자는 돔의 모든 것을 파괴하기 위해 달려온다. 단테에 의해 산산히 흩어진 패밀리들은 모두 목숨을 걸고 맞서야 하는 함정에 빠지고 마는데...', 'https://image.tmdb.org/t/p/w500/cltj9nKLzl0HXtz2qdu55BoIgOn.jpg', 2023, 0, 0, '2026-06-06 13:25:07.186349', 'US');
INSERT INTO public.movies VALUES (950, 772, '나 홀로 집에 2: 뉴욕을 헤매다', '["Comedy", "Family", "Adventure"]', NULL, '[]', '시카고에 살고 있는 케빈의 가족은 크리스마스에 플로리다에 가기로 되어있다. 그러나 공항의 소란 속에, 홀로 뉴욕행 비행기에 오르게 되어 거대한 도시에 혼자 남게 된 케빈은 기지를 발휘하여 아버지 카드로 플로리자 호텔에 묶게되고, 의심스러워 하는 종업원들을 멋지게 따돌린다. 한편, 감옥을 탈출한 2인조 강도 마브와 해리는 뉴욕의 장난감 가게를 털어 한 몫 잡을 꿈에 부풀어 있는데...', 'https://image.tmdb.org/t/p/w500/eUYFbtuSBuvihNmFgLJtl1Y54fE.jpg', 1992, 0, 0, '2026-06-06 13:25:32.709268', 'US');
INSERT INTO public.movies VALUES (290, 429617, '스파이더맨: 파 프롬 홈', '["Action", "Adventure", "Sci-Fi"]', 'Jon Watts', '["Tom Holland", "Jake Gyllenhaal", "Samuel L. Jackson", "Marisa Tomei", "Jon Favreau"]', '어벤져스 멤버들과 타노스와의 대접전을 마친 뒤, 지난 5년 동안 사라졌던 사람들이 동시에 돌아왔다. 아이언맨이 떠난 채 한동안 지구를 구할 히어로가 공석인 상황을 수습할 히어로는 현재 스파이더맨 피터 파커뿐이다. 친구들과의 유럽 현장학습 도중 닉 퓨리의 부름을 받게 된 피터는 미스테리오라는 정체 모를 히어로와 힘을 합쳐 엘리멘탈이라는 괴생명체를 무찔러야 하는 상황에 처한다. 그런데 피터는 지구를 구하는 일보다 MJ에게 멋지게 고백할 계획이 우선인데...', 'https://image.tmdb.org/t/p/w500/3YewJtji80oIroeXUavNRZkeXfQ.jpg', 2019, 0, 0, '2026-06-06 13:25:07.174988', 'US');
INSERT INTO public.movies VALUES (287, 693134, '듄: 파트 2', '["Sci-Fi", "Adventure"]', 'Denis Villeneuve', '["Timothée Chalamet", "Zendaya", "Rebecca Ferguson", "Javier Bardem", "Josh Brolin"]', '황제의 모략으로 멸문한 가문의 유일한 후계자 폴. 어머니 레이디 제시카와 간신히 목숨만 부지한 채 사막으로 도망친다. 그곳에서 만난 반란군들과 숨어 지내다 그들과 함께 황제의 모든 것을 파괴할 전투를 준비한다. 한편 반란군들의 기세가 높아질수록 불안해진 황제와 귀족 가문은 잔혹한 암살자 페이드 로타를 보내 반란군을 몰살하려 하는데…', 'https://image.tmdb.org/t/p/w500/8AsDR2o5AC3V8Jmj6JH6cpta7dz.jpg', 2024, 0, 0, '2026-06-06 13:25:07.167927', 'US');
INSERT INTO public.movies VALUES (289, 1352874, 'The Crucifix: Blood of the Exorcist', '["Horror"]', 'Stephen Roach', '["Hannaj Bang Bendz", "Dean Kilbey", "Nicholas Anscombe", "Tom Carter", "Darren Le Fevre"]', NULL, 'https://image.tmdb.org/t/p/w500/u3qOxvlykoTpurg1G8VOcawoePI.jpg', 2025, 0, 0, '2026-06-06 13:25:07.172684', 'US');
INSERT INTO public.movies VALUES (284, 1387382, '헌팅시즌', '["Action", "Drama", "Thriller"]', 'Raja Collins', '["Mel Gibson", "Shelley Hennig", "Jordi Mollà", "Sofia Hublitz", "A.J. Buckley"]', '은둔하며 살아가던 생존 전문가와 그의 딸은 강가에서 상처 입은 정체불명의 여자를 구조하게 된다. 그러나 이로 인해 그들은 폭력과 복수의 잔혹한 소용돌이에 휘말리게 되고 살아남기 위해 잔혹한 범죄자와 맞서야만 한다.', 'https://image.tmdb.org/t/p/w500/7OPedgbyapZ8LjIQIMIh72ZEfW6.jpg', 2025, 0, 0, '2026-06-06 13:25:07.160476', 'US');
INSERT INTO public.movies VALUES (291, 967998, 'Conspiração Fatal', '["Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/zpj3nNoc5xaUZTIdnuhwXwUcRag.jpg', 2022, 0, 0, '2026-06-06 13:25:07.177241', 'US');
INSERT INTO public.movies VALUES (4084, 1131759, '전지적 독자 시점', '["Action", "Adventure", "Fantasy"]', 'Kim Byung-woo', '["Ahn Hyo-seop", "Lee Min-ho", "Chae Soo-bin", "Shin Seung-ho", "Nana"]', '10년 이상 연재된 소설이 완결된 날 소설 속 세계가 현실이 되어 버리고, 유일한 독자였던 ‘김독자’가 소설의 주인공 ‘유중혁’ 그리고 동료들과 함께 멸망한 세계에서 살아남기 위한 이야기.', 'https://image.tmdb.org/t/p/w500/lWQRM7IOCyJT9E5kOnoUvZNELHQ.jpg', 2025, 0, 0, '2026-06-08 06:26:47.928013', 'KR');
INSERT INTO public.movies VALUES (283, 258216, '님포매니악: 볼륨 1', '["Drama"]', NULL, '[]', '한 허름한 뒷골목 길에 폭행을 당한 채 쓰려져 있던 조(샬롯 갱스부르)를 중년의 남자 셀리그먼(스텔란 스카스가드)이 그녀를 구해 집으로 데리고 온다. 샐리그먼은 평범한 사람들이 상상할 수 없는 성적 경험을 한 여성 조의 이야기를 듣는다. 샐리그먼은 조의 남성 편력과 성적 체험을 편견 없이 경청한다. 그리고 자신의 문학적, 수학적, 음악적 지식을 동원하여 조의 이야기를 해석한다. 일찍 성에 눈을 뜨고 여성의 성을 실험한 조에게 샐리그먼은 날개가 있는데 날면 좀 어떠냐고 이야기한다. 셀리그먼은 그녀와의 대화 중에 자신의 내부 어딘가에서 뭔가 불이 켜지는 것이 느껴진다.', 'https://image.tmdb.org/t/p/w500/iLU2meXFN8BxNcM0Lq2gPtpoO8L.jpg', 2013, 0, 0, '2026-06-06 13:25:07.15766', 'US');
INSERT INTO public.movies VALUES (299, 1220522, 'డెకాయిట్', '["Action", "Romance", "Thriller"]', 'Shaneil Deo', '["Adivi Sesh", "Mrunal Thakur", "Anurag Kashyap", "Prakash Raj", "Sunil Varma"]', NULL, 'https://image.tmdb.org/t/p/w500/yUn0et9QaiHXME4awdwxeEsuslc.jpg', 2026, 0, 0, '2026-06-06 13:25:07.195625', 'IN');
INSERT INTO public.movies VALUES (4087, 687209, '여자 전쟁: 이사 온 남자', '["Drama"]', 'Kim Pil-jin', '["Lee Hae-in", "Ahn Suk-hwan", "Kim Jeong-wook"]', '소박하지만 행복한 삶을 누리고 있던 ''민정''의 일상이 이사 온 옆집 남자로 인해 엉망이 된다. 그 남자는 바로 오래 전 악연으로 인해 기억 속에서 지우고만 싶었던 ''덕만''이었기 때문. 그리고 덕만의 또 다른 목적을 눈치 챈 그녀. 이제 덕만을 향한 적극적 복수가 시작된다.', 'https://image.tmdb.org/t/p/w500/6j4aU2E2utHNBec1EtnxYDediIS.jpg', 2016, 0, 0, '2026-06-08 06:26:50.128335', 'KR');
INSERT INTO public.movies VALUES (298, 1101383, '오크 스트리트의 마지막 날', '["Sci-Fi", "Mystery", "Thriller"]', 'David Robert Mitchell', '["Anne Hathaway", "Ewan McGregor", "Christian Convery", "Maisy Stella", "Jordan Alexa Davis"]', NULL, 'https://image.tmdb.org/t/p/w500/60bRdW7JTXTaSMFgLHjcoS1fXHh.jpg', 2026, 0, 0, '2026-06-06 13:25:07.193226', 'US');
INSERT INTO public.movies VALUES (308, 1601797, '¿Quieres ser mi novia?', '["Comedy", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/oscW8xV8EhRYj7iAhyVlBohKqxo.jpg', 2026, 0, 0, '2026-06-06 13:25:07.948529', 'US');
INSERT INTO public.movies VALUES (892, 854, '마스크', '["Comedy", "Fantasy", "Crime", "Romance"]', NULL, '[]', '에지 시(Edge City). 은행에서 단조로운 일상을 보내고 있던 평범한 은행원 스탠리. 어느날 그는 우연한 기회로 고대 시대의 유물인 마스크를 발견한다. 그런데 이 마스크는 아주 신비로운 힘을 가지고 있다.  스탠리가 마스크를 쓰면 초인적인 힘을 가진 불사신이 된다. 스탠리는 나이트클럽 가수인 티나를 사랑하지만 그녀는 악당 조직 보스의 정부다. 스탠리의 마스크 때문에 여러가지 소동이 일어나고 경찰은 스탠리를 뒤쫓는다. 티나가 보스를 사랑하지도 않으며 빠져나올 기회만을 노리고 있다는 것을 알고 그녀를 돕는다.  스탠리의 마스크 때문에 일어난 여러가지 소동으로 경찰은 그를 추적하고 엎친데 덮친격으로 조직까지 가세, 쫓고 쫓기는 사건이 벌어진다. 조직의 사주를 받은 어느 여기자에 의해 정체가 탄로난 스탠리는 조직에게 마스크를 빼앗기고 조직의 보스는 마스크를 이용하여 도시의 세력을 장악하려하는데…', 'https://image.tmdb.org/t/p/w500/jPC2eYub74zwf2tPGVtzSlBW6Oy.jpg', 1994, 0, 0, '2026-06-06 13:25:30.414927', 'US');
INSERT INTO public.movies VALUES (4079, 581392, '반도', '["Horror", "Action", "Thriller", "Adventure"]', 'Yeon Sang-ho', '["Gang Dong-won", "Lee Jung-hyun", "Lee Re", "Kwon Hae-hyo", "Kim Min-jae"]', '전대미문의 재난 이후 4년이 흐른 대한민국은 버려진 땅이 되어버렸다. 사람들은 고립된 섬이 된 반도에 갇혔고 누구의 생사도 확인할 수 없는 상황에서 정석은 피할 수 없는 미션을 받고 한국 땅에 다시 발을 들인다. 정석은 미지의 세계인 그곳에서 예상치 못한 습격을 받고 일촉즉발의 순간 ‘반도’의 생존자들을 만나게 된다.', 'https://image.tmdb.org/t/p/w500/ew1lAU8yV66JbivBU1Zh4Wj4pOB.jpg', 2020, 0, 0, '2026-06-08 06:26:43.963042', 'KR');
INSERT INTO public.movies VALUES (307, 244786, '위플래쉬', '["Drama", "Thriller"]', 'Damien Chazelle', '["Miles Teller", "J.K. Simmons", "Paul Reiser", "Melissa Benoist", "Austin Stowell"]', '최고의 드러머가 되기 위해서라면 무엇이든 할 각오가 되어있는 음악대학 신입생 앤드류는 아무도 없는 지하실에서 혼자 드럼을 연습하던 중 우연한 기회로 누구든지 성공으로 이끄는 최고의 실력자이지만, 또한 동시에 최악의 폭군인 플렛처 교수에게 발탁되어 그의 밴드에 들어가게 된다. 설레는 마음으로 참가한 첫 연습에서, 그는 플렛처 교수의 진짜 얼굴을 마주치게 된다. 폭언과 학대 속에 좌절과 성취를 동시에 안겨주는 플렛처의 지독한 교육방식은 천재가 되길 갈망하는 앤드류의 집착을 끌어내며 그를 점점 광기로 몰아넣는데...', 'https://image.tmdb.org/t/p/w500/oKNkhmyIBiDENivK6ELZxfBWa3q.jpg', 2014, 0, 0, '2026-06-06 13:25:07.94622', 'US');
INSERT INTO public.movies VALUES (305, 138843, '컨저링', '["Horror", "Thriller"]', 'James Wan', '["Vera Farmiga", "Patrick Wilson", "Lili Taylor", "Ron Livingston", "Hayley McFarland"]', '1971년 로드 아일랜드, 해리스빌. 페론 가족은 꿈에 그리던 새 집으로 이사를 간다. 물론 1863년에 그 집에서 일어난 끔찍한 살인 사건을 전혀 몰랐다. 또한 그 이후에 일어난 많은 무서운 사건에 대해서도 알지 못했다. 이 가족은 그 집에서 겪은 일이 너무 무서워서 한 마디라도 외부에 언급하는 것을 거절했었다. 지금까지는…', 'https://image.tmdb.org/t/p/w500/pWpTToZ32bG09PaZ1rvYG5mpOyV.jpg', 2013, 0, 0, '2026-06-06 13:25:07.941398', 'US');
INSERT INTO public.movies VALUES (4282, 1706018, 'Absolute Value Of romance', '["Romance", "Comedy", "Drama"]', NULL, '["Kim Hyang-gi", "Kim Jae-hyun", "Kim Dong-gyu"]', NULL, NULL, NULL, 0, 0, '2026-06-08 06:29:46.131009', 'KR');
INSERT INTO public.movies VALUES (313, 13576, '마이클 잭슨의 디스 이즈 잇', '["Documentary"]', 'Kenny Ortega', '["Michael Jackson", "Orianthi", "Kenny Ortega", "Dorian Holley", "Patrick Woodroffe"]', '팝 황제 마이클 잭슨의 마지막 리허설 모습을 담은 다큐멘터리.  7월 런던을 시작으로 50일간 예정되어 있던 투어의 정식 명칭으로 사망 몇일전인 지난 6월 LA스테이플스 센터에서 진행된 리허설을 중심으로, 지인들의 인터뷰와 그의 음악인생을 조명하는 미공개 영상들로 구성될 예정.', 'https://image.tmdb.org/t/p/w500/4exwxdn3HxHYQ2Nls2yhM3pW1Mw.jpg', 2009, 0, 0, '2026-06-06 13:25:07.960727', 'US');
INSERT INTO public.movies VALUES (311, 1159831, '브라이드!', '["Sci-Fi", "Horror", "Fantasy"]', 'Maggie Gyllenhaal', '["Jessie Buckley", "Christian Bale", "Peter Sarsgaard", "John Magaro", "Jeannie Berlin"]', '1930년대 미국, 죽음에서 깨어난 브라이드와 그녀를 사랑하게 된 프랑켄슈타인. 어느 날, 끔찍한 사건을 저지르고 위험천만한 도주를 시작한다. 세상의 모든 규범을 깨부순 브라이드와 프랑켄슈타인의 파격적인 행보는 미국 전역을 뒤흔들고 그들의 운명은 걷잡을 수 없는 방향으로 치닫는데…', 'https://image.tmdb.org/t/p/w500/ftIYdV8IEE4n8odMv7FLam9VDVy.jpg', 2026, 0, 0, '2026-06-06 13:25:07.955429', 'US');
INSERT INTO public.movies VALUES (6066, 758923, 'बाघी ४', '["Action", "Romance", "Thriller"]', 'A. Harsha', '["Tiger Shroff", "Sanjay Dutt", "Harnaaz Kaur Sandhu", "Sonam Bajwa", "Shreyas Talpade"]', NULL, 'https://image.tmdb.org/t/p/w500/u2YEFW5o2Y7RAw2K4hSA4TEXF3Q.jpg', 2025, 0, 0, '2026-06-08 06:53:38.068151', 'IN');
INSERT INTO public.movies VALUES (310, 1297446, '금발이 되고 싶어', '["Comedy", "Horror", "Sci-Fi"]', 'Amy Wang', '["Shirley Chen", "Mckenna Grace", "Amelie Zilber", "Vivian Wu", "Maitreyi Ramakrishnan"]', '또래들의 시선과 자신의 정체성 사이에서 흔들리는 중국계 미국인 소녀가, 프롬 퀸의 자리를 꿈꾸며 백인처럼 보이기 위한 위험한 실험적 수술을 선택한다.', 'https://image.tmdb.org/t/p/w500/gYiWShxkNTAtedD4xR4uvw8XYvE.jpg', 2026, 0, 0, '2026-06-06 13:25:07.953098', 'US');
INSERT INTO public.movies VALUES (314, 2062, '라따뚜이', '["Animation", "Comedy", "Family", "Fantasy"]', 'Brad Bird', '["Patton Oswalt", "Ian Holm", "Lou Romano", "Brian Dennehy", "Peter Sohn"]', '절대미각, 빠른 손놀림, 끓어 넘치는 열정의 소유자 레미. 프랑스 최고의 요리사를 꿈꾸는 그에게 단 한가지 약점이 있었으니, 바로 주방 퇴치대상 1호인 생쥐라는 것. 어느 날 하수구에서 길을 잃은 레미는 파리의 별 다섯개짜리 최고급 레스토랑에 떨어진다. 보글거리는 수프, 둑닥둑닥 도마소리, 향긋한 허브 내음에 식욕이 아닌 요리욕이 북받친 레미의 작은 심장은 콩닥콩닥 뛰기 시작한다. 끝내 주방으로 들어가는 레미는 요리에 열중하다 견습생 링귀니에게 딱 걸리고 만다. 해고위기에 처해있던 링귀니는 레미의 재능을 한눈에 알아보고 의기투합을 제안하는데...', 'https://image.tmdb.org/t/p/w500/zFah4LNeWw68y7RRGi20CQlGByY.jpg', 2007, 0, 0, '2026-06-06 13:25:07.963056', 'US');
INSERT INTO public.movies VALUES (312, 115724, '두 유 노우 미', '["Crime", "Mystery", "Thriller"]', 'Penelope Buitenhuis', '["Rachelle Lefevre", "Jeremy London", "Ted Whittall", "Lynda Boyd", "Victoria Duffield"]', NULL, 'https://image.tmdb.org/t/p/w500/nsQPjGTUxSqupDaODIIQF9e1Fsy.jpg', 2009, 0, 0, '2026-06-06 13:25:07.958341', 'US');
INSERT INTO public.movies VALUES (6064, 1136736, '러스트 스토리 2', '["Drama", "Romance"]', 'Konkona Sen Sharma', '["Neena Gupta", "Mrunal Thakur", "Tamannaah Bhatia", "Kajol", "Angad Bedi"]', '인도 대표 감독 4인이 사랑과 섹스, 인간의 욕망에 관해 이야기하는 단편 영화들을 모아놓은 옴니버스 형식의 극영화', 'https://image.tmdb.org/t/p/w500/p5x729JI6wZs9hCqX7tc7oH87ih.jpg', 2023, 0, 0, '2026-06-08 06:53:36.530147', 'IN');
INSERT INTO public.movies VALUES (6065, 1227128, '레이드 2', '["Crime", "Drama", "Thriller"]', 'Raj Kumar Gupta', '["Ajay Devgn", "Riteish Deshmukh", "Vaani Kapoor", "Saurabh Shukla", "Rajat Kapoor"]', '1편의 사건으로부터 7년 후를 배경으로, 겉보기에는 선량해 보이는 정치인을 무너뜨리려는 국세청 요원 아메이 팻나익의 귀환을 다룹니다.', 'https://image.tmdb.org/t/p/w500/562SAxZP1sLuYqDDTuODu3hdGyx.jpg', 2025, 0, 0, '2026-06-08 06:53:37.313153', 'IN');
INSERT INTO public.movies VALUES (6067, 965979, 'டாடா', '["Drama", "Comedy", "Romance"]', 'Ganesh K. Babu', '["Kavin Raj", "Aparna Das", "Harish Kumar", "Pradeep Anthony", "Arvind Ezhilarasan"]', NULL, 'https://image.tmdb.org/t/p/w500/x7C2u4oXoMFQBaSJqqcyU3qpwKy.jpg', 2023, 0, 0, '2026-06-08 06:53:38.839951', 'IN');
INSERT INTO public.movies VALUES (6068, 1427822, 'വലത് വശത്തെ കള്ളൻ', '["Crime", "Thriller", "Drama"]', 'Jeethu Joseph', '["Biju Menon", "Joju George", "Lenaa", "Shaju Sreedhar", "K R  Gokul"]', NULL, 'https://image.tmdb.org/t/p/w500/ko4cEKcBHcCNbGok2YxnlD4u16N.jpg', 2026, 0, 0, '2026-06-08 06:53:39.600882', 'IN');
INSERT INTO public.movies VALUES (318, 12444, '해리 포터와 죽음의 성물 1', '["Adventure", "Fantasy"]', 'David Yates', '["Daniel Radcliffe", "Emma Watson", "Rupert Grint", "Toby Jones", "Helena Bonham Carter"]', '덤블도어 교장의 죽음 이후, 마법부는 죽음을 먹는 자들에게 점령당하고 호그와트는 위기에 빠진다. 성년이 되며 해리를 지켜주던 수호 마법은 사라지고 해리와 론, 헤르미온느는 볼드모트 영혼의 조각이 보관된 호크룩스를 찾아 파괴하기 위한 모험을 떠난다. 그러나 이미 볼드모트에 의해 장악된 마법세계에서 죽음을 먹는 자들을 피해 숨어다니는 것만으로도 쉽지 않다. 세 사람에게 남겨진 덤블도어의 유품은 수수께끼처럼 그저 막막하고, 아무런 단서도 없이 떠난 그들의 모험은 불안과 초조함으로 가득하다. 계속되는 시련의 나날 속에 세 친구는 끊임없이 서로에 대한 믿음과 숙명에 대한 의지를 시험받는다.', 'https://image.tmdb.org/t/p/w500/lOXvz8HrgOkp7AXGQp1APKeZqag.jpg', 2010, 0, 0, '2026-06-06 13:25:07.972205', 'GB');
INSERT INTO public.movies VALUES (326, 1446616, 'तू या मैं', '["Thriller", "Romance"]', 'Bejoy Nambiar', '["Adarsh Gourav", "Shanaya Kapoor", "Kshitee Jog", "Parul Gulati", "Ansh Chopra"]', NULL, 'https://image.tmdb.org/t/p/w500/nUPnA0I1MTaZRVCsUQc5DS5JA8W.jpg', 2026, 0, 0, '2026-06-06 13:25:08.6912', 'IN');
INSERT INTO public.movies VALUES (320, 1635279, 'SNOS-056り広げられる、お酒の勢いで一線を超えてしまった男女のふしだらな土日。生々しくて普通だけど一番エロいSEX', '["Drama"]', 'Sapporo Taro', '["Saika Kawakita"]', NULL, 'https://image.tmdb.org/t/p/w500/eAuSdg6aYf9nole1RhY4qTfZvRX.jpg', 2026, 0, 0, '2026-06-06 13:25:07.976984', 'JP');
INSERT INTO public.movies VALUES (325, 10867, '말레나', '["Drama"]', NULL, '[]', '무솔리니 정권의 이탈리아, 한 시골마을에 사는 주인공 소년 레나토(주세페 술파로)는 마을에서 가장 아름다운 여인 말레나(모니카 벨루치)에 한눈에 반한다. 레나토의 라틴어 선생(피에트로 노타리안니)의 딸인 말레나는 전쟁으로 남편을 잃고 혼자 살고 있었다. 레나토는 빼어난 미모 때문에 온 마을 사내들의 정욕에 찬 시선과 아낙네들의 따돌림을 감내해야 하는 말레나를 늘 안타깝게 지켜본다.  어느 날 말레나의 남편 스코르디아(가에타노 아로니카)의 전사소식이 전해지고, 독일군이 점령한 마을에서 생계를 잃은 말레나는 창녀가 된다.', 'https://image.tmdb.org/t/p/w500/d5JdpKKyG8bLCBQsAfFskPhuj19.jpg', 2000, 0, 0, '2026-06-06 13:25:08.688858', 'US');
INSERT INTO public.movies VALUES (4081, 682827, '여친 언니 2', '[]', NULL, '["Jo Wan-jin", "Kang Min-woo", "Hong Sae-hee"]', '매일매일 뜨거운 민철-나희 커플. 나희는 민철을 언니 은영에게 소개해주려고 집으로 같이 간다. 간단한 인사 후, 그들은 곧 바로 방으로 들어가 뜨거운 섹스를 나눈다. 그 모습을 우연히 보게된 은영. 그날 밤부터 민철이 자꾸 생각나 자위를 한다. 어느 날, 나희는 친구를 만나러 집을 비우고, 마침 민철이 집에 찾아온다. 같이 술을 마시게 되고, 민철은 애인 없이 외로워하는 모습에 그녀를 달래주고자 하는데…', 'https://image.tmdb.org/t/p/w500/gN92tUc58ZGCwRsjF64OprHDmQB.jpg', 2020, 0, 0, '2026-06-08 06:26:45.300596', 'KR');
INSERT INTO public.movies VALUES (828, 615457, '노바디', '["Action", "Thriller"]', NULL, '[]', '비범한 과거를 숨긴 채 남들과 다를 바 없는 평범한 일상을 사는 한 가정의 가장 ‘허치’ 매일 출근을 하고, 분리수거를 하고 일과 가정 모두 나름 최선을 다하지만 아들한테는 무시당하고 아내와의 관계도 소원하다. 그러던 어느 날, 집안에 강도가 들고 허치는 한 번의 반항도 하지 못하고 당한다. 더 큰 위험으로부터 가족을 지키기 위한 선택이었는데 모두 무능력하다고 ‘허치’를 비난하고, 결국 그동안 참고 억눌렀던 분노가 폭발하고 만다.', 'https://image.tmdb.org/t/p/w500/oXQtH8O7pCvXaDKGB8OAjiPVDi5.jpg', 2021, 0, 0, '2026-06-06 13:25:28.097172', 'US');
INSERT INTO public.movies VALUES (6069, 1227241, 'మా ఇంటి బంగారం', '["Action", "Thriller", "Drama"]', 'B. V. Nandini Reddy', '["Samantha Ruth Prabhu", "Gulshan Devaiah", "Diganth Manchale", "Gautami Tadimalla", "Anand"]', NULL, 'https://image.tmdb.org/t/p/w500/n7X5JZLzqzUxwdn9Mwx9cegEnBv.jpg', 2026, 0, 0, '2026-06-08 06:53:40.365982', 'IN');
INSERT INTO public.movies VALUES (329, 574475, '파이널 데스티네이션: 블러드라인', '["Horror", "Mystery"]', 'Zach Lipovsky', '["Kaitlyn Santa Juana", "Teo Briones", "Rya Kihlstedt", "Richard Harmon", "Owen Patrick Joyner"]', '끝없는 악몽에 시달리던 스테파니는 그 원인을 찾던 중 집안 대대로 내려오는 죽음의 저주와 그 실체를 알게 된다. 놀랍게도, 죽음의 순서가 자신의 가족에게 이어졌음을 알게 되는데...  이제, 다음 차례는 누구?', 'https://image.tmdb.org/t/p/w500/agaIglFrRGuUQOzkhzlrvcjJgt2.jpg', 2025, 0, 0, '2026-06-06 13:25:08.697979', 'US');
INSERT INTO public.movies VALUES (6070, 612402, '나니의 갱 두목', '["Comedy", "Crime", "Thriller"]', 'Vikram Kumar', '["Nani", "Kartikeya Gummakonda", "Lakshmi", "Saranya Ponvannan", "Priyanka Arul Mohan"]', '‘펜슬’이라는 필명으로 활동하는 범죄 소설 작가인 나니가 이끄는 여자 갱단에 관한 이야기', 'https://image.tmdb.org/t/p/w500/ejXpzRk1jyZenFhYANehhk4vGcD.jpg', 2019, 0, 0, '2026-06-08 06:53:41.115607', 'IN');
INSERT INTO public.movies VALUES (323, 1440050, 'The Breadwinner', '["Comedy", "Family"]', 'Eric Appel', '["Nate Bargatze", "Mandy Moore", "Stella Grace Fitzgerald", "Birdie Borria", "Charlotte Ann Tucker"]', NULL, 'https://image.tmdb.org/t/p/w500/4apG9Xk6HQvV48JKEjSUeiebju7.jpg', 2026, 0, 0, '2026-06-06 13:25:08.684259', 'US');
INSERT INTO public.movies VALUES (327, 107257, 'A Perfect Ending', '["Drama", "Romance"]', 'Nicole Conn', '["Barbara Niven", "Jessica Clark", "John Heard", "Morgan Fairchild", "Kerry Knuppe"]', NULL, 'https://image.tmdb.org/t/p/w500/mjwWEwE1xdbtFGCOgeXi5jvQnOU.jpg', 2012, 0, 0, '2026-06-06 13:25:08.693452', 'US');
INSERT INTO public.movies VALUES (6071, 1059007, '아그라', '["Drama"]', 'Kanu Behl', '["Mohit Agarwal", "Priyanka Bose", "Rahul Roy", "Vibha Chibber", "Aanchal Goswami"]', '젊은 콜센터 직원 구루는 낡은 저택 1층에 어머니와 함께 살고, 아버지는 두 번째 부인과 함께 테라스가 있는 2층에 산다. 무엇 하나 이룬 것 없이 외로움과 좌절감에 휩싸인 그는 데이트 앱, 성적 환상, 히스테리적 자해 사이에서 광기에 가까운 열병에 빠진다.', 'https://image.tmdb.org/t/p/w500/biX8D3kSh4HuZzf1r0ynRgaEJte.jpg', 2025, 0, 0, '2026-06-08 06:53:41.869833', 'IN');
INSERT INTO public.movies VALUES (339, 1317672, '사랑해 줘 사랑해 줘', '["Romance", "Drama"]', 'Roger Kumble', '["Pepe Barroso", "Mia Jenkins", "Luca Melucci", "Andrea Guo", "Michelangelo Vizzini"]', '오빠의 죽음으로 모든 것을 잃은 준은 상처를 안고 밀라노로 떠나 국제학교로 전학한다. 그곳에서 만난 모범생이자 완벽한 연인인 윌에게서 안정을 찾지만, 비밀스럽고 위험한 불법 격투 경기에 몸담은 절친 제임스와의 갈등은 서서히 금지된 설렘으로 바뀌어 가고, 준은 안전한 삶과 모든 것을 뒤흔드는 사랑 사이에서 흔들린다.', 'https://image.tmdb.org/t/p/w500/o6SeivdAJ4ri8EbgJlIiffVN9Q.jpg', 2026, 0, 0, '2026-06-06 13:25:08.721042', 'US');
INSERT INTO public.movies VALUES (421, 64084, 'Scorned', '["Drama", "Thriller"]', 'Andrew Stevens', '["Shannon Tweed", "Andrew Stevens", "Kim Morgan Greene", "Daniel McVicar", "Michael D. Arenz"]', NULL, 'https://image.tmdb.org/t/p/w500/latrrZjz5kwVz3Am3ajLaCrJ1LW.jpg', 1993, 0, 0, '2026-06-06 13:25:12.523241', 'US');
INSERT INTO public.movies VALUES (342, 1054867, '원 배틀 애프터 어나더', '["Thriller", "Crime", "Comedy"]', 'Paul Thomas Anderson', '["Leonardo DiCaprio", "Sean Penn", "Chase Infiniti", "Benicio del Toro", "Regina Hall"]', '자유를 외치는 혁명가 밥 퍼거슨. 16년이 흐른 뒤, 후유증으로 모든 걸 내려놓고 무너진 삶을 살고 있다. 그에게 남은 유일한 희망은 세상 누구보다 소중한 딸 윌라뿐. 자신의 몸도, 딸과의 관계도 엉망진창인 삶을 살아가던 중 과거의 숙적이었던 스티븐 J. 록조가 딸을 납치한다. 딸을 찾기 위해서 옛 동료들의 도움이 절실하지만, 오래된 동료들은 만나기조차 쉽지 않은데…', 'https://image.tmdb.org/t/p/w500/bCg9iDSXPjVTUs1RyYH8AhmJ11d.jpg', 2025, 0, 0, '2026-06-06 13:25:09.44531', 'US');
INSERT INTO public.movies VALUES (4093, 713607, '엄마친구 2020', '["Romance"]', 'Kim Hwan', '["Kim Ji-ah", "Lee Eun-mi", "Han Seok-bong", "Min Do-yoon"]', '죽은 남편을 못 있어, 재혼 안 하고 혼자 사는 태희.  이웃에 사는 친구 영주- 철민 부부는 아직 젊은 그녀가 안타깝기만 하다. 그런데, 영주의 아들 민호는 남몰래 엄마 친구 태희의 다리를 몰래 찍으며, 그녀를 흠모하고 있다.  어느 날, 같이 마트에 간 태희와 영주, 영주의 집에 휴대폰을 두고 온 태희는 다시 집으로 향한다. 그런데, 샤워를 마치고 나온 민호가 태희를 보자 확 끌어안는데...', 'https://image.tmdb.org/t/p/w500/ajBTNjytyQdSRywpIrd78ivppyS.jpg', 2020, 0, 0, '2026-06-08 06:26:55.706376', 'KR');
INSERT INTO public.movies VALUES (333, 801335, '걸 인 더 베이스먼트', '["Thriller", "Crime"]', 'Elisabeth Röhm', '["Judd Nelson", "Stefanie Scott", "Joely Fisher", "Braxton Bjerken", "Kim Rosen"]', '2008년 사건 발생 국가인 오스트리아는 물론 전세계를 경악시킨 근친 납치, 감금 및 강간 사건으로,  24년의 감금 요제프 프리츨 사건을 모티브로 한  스토리', 'https://image.tmdb.org/t/p/w500/tPP9n6r5QrIKPnshnJqE7klptj2.jpg', 2021, 0, 0, '2026-06-06 13:25:08.707117', 'US');
INSERT INTO public.movies VALUES (337, 18785, '행오버', '["Comedy"]', 'Todd Phillips', '["Bradley Cooper", "Ed Helms", "Zach Galifianakis", "Justin Bartha", "Heather Graham"]', '더그의 결혼식을 앞두고 친구 세 명은 함께 라스베가스로 총각 파티를 떠난다. 멋진 호텔에서 한껏 즐거운 밤을 보낸 이들은 아침에 친구인 더그가 사라진 사실을 알게 된다. 아무 생각도 해낼 수 없던 이들은 지난 밤 만났던 사람들에게 친구를 수소문하고 우여곡절끝에 그를 결혼식장에 데려간다.', 'https://image.tmdb.org/t/p/w500/A0uS9rHR56FeBtpjVki16M5xxSW.jpg', 2009, 0, 0, '2026-06-06 13:25:08.71635', 'US');
