INSERT INTO public.movies VALUES (336, 1669057, 'Check-In', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/r7tXZoO3rfkOpYQPCXftwugwny9.jpg', 2026, 0, 0, '2026-06-06 13:25:08.714049', 'US');
INSERT INTO public.movies VALUES (350, 19404, '용감한 자가 신부를 데려가리', '["Comedy", "Drama", "Romance"]', 'Aditya Chopra', '["Kajol", "Shah Rukh Khan", "Amrish Puri", "Farida Jalal", "Anupam Kher"]', '영국에서 유학중인 라즈(샤룩 칸)와 인도 처녀 심란(까졸).  심란은 부모님이 정해주신 약혼자가 있는데 약혼을 앞두고 친구들과 유럽 여행을 떠나게 된다.  여행 중 우연히 만남 샤룩과 까졸. 두 남녀의 연속된 우연과 좌충우돌 사랑 만들기.  그렇게 사랑하게 된 그들이지만 까졸은 약혼자가 있는 몸. 인도로 돌아가게 된다.  샤룩 또한 그녀를 못 잊어 인도로 뒤 따라 들어가지만 엄격한 까졸의 부모를 설득하기가 힘이 든다. 도망가자는 까졸의 제안을 거부하고 샤룩은 끝내 그녀의 부모님의 허락을 얻어 내기 위해 고군분투한다.', 'https://image.tmdb.org/t/p/w500/2CAL2433ZeIihfX1Hb2139CX0pW.jpg', 1995, 0, 0, '2026-06-06 13:25:09.466149', 'IN');
INSERT INTO public.movies VALUES (468, 1317288, '마티 슈프림', '["Drama", "Thriller"]', NULL, '[]', '어떤 대가를 치르더라도 반드시 가장 높은 곳으로! 탁구로 인생 역전을 꿈꾸는 마티 마우저는 굴욕적인 패배 후 누구도 무시할 수 없는 성공을 손에 넣기로 결심한다. 최고가 되기 위해 모든 것을 걸고 지옥까지 질주하는 마티 마우저의 꿈은 이루어질 수 있을까?', 'https://image.tmdb.org/t/p/w500/hqzCMHTuymM7FOZwpHfW5meiX1m.jpg', 2025, 0, 0, '2026-06-06 13:25:14.08641', 'US');
INSERT INTO public.movies VALUES (4095, 1267319, '사마귀', '["Action", "Crime", "Thriller"]', 'Lee Tae-sung', '["Yim Si-wan", "Park Gyu-young", "Choi Hyun-wook", "Bae Gang-hee", "Hwang Sung-bin"]', '하룻밤 사이 몰락한 청부살인 업계의 거물들. 그들이 세운 질서가 무너지고, 어둠의 세계가 흔들린다. 혼돈 속에서 기회를 노리는 실력자 ''사마귀''. 그의 손끝에서 새로운 킬러들의 시대가 열린다.', 'https://image.tmdb.org/t/p/w500/gRPSu4sG5iVnWyLv9um7t3L0yhH.jpg', 2025, 0, 0, '2026-06-08 06:26:57.189416', 'KR');
INSERT INTO public.movies VALUES (4096, 1412113, '오징어 게임: 시즌2 제작 이야기', '["Documentary"]', NULL, '["Hwang Dong-hyuk", "Lee Jung-jae", "Lee Byung-hun", "Chae Kyoung-sun", "Kim Ji-yong"]', '《오징어 게임》 시즌 2의 치열했던 제작 현장 속으로. 웅장한 세트장부터 캐릭터들의 이야기가 완성되는 순간까지, 전 세계를 매료한 드라마의 주역들이 들려주는 특별한 제작 비화.', 'https://image.tmdb.org/t/p/w500/yQGaui0bQ5Ai3KIFBB45nTeIqad.jpg', 2025, 0, 0, '2026-06-08 06:26:57.848205', 'KR');
INSERT INTO public.movies VALUES (553, 62, '2001 스페이스 오디세이', '["Sci-Fi", "Mystery", "Adventure"]', NULL, '[]', '인류에게 문명의 지혜를 가르쳐 준 검은 돌기둥의 정체를 밝히기 위해서 디스커버리호의 선장 보우만과 승무원 풀은 목성을 향해서 날아간다. 하지만 평온하던 디스커버리호에 갑자기 재난이 찾아온다. 우주선 내부에서 일어난 재난은 컴퓨터 HAL이 반란을 일으킨 것. HAL은 풀을 우주선 밖으로 던져버리고, 보우만까지도 모선 밖으로 끌어내지만 그는 필사의 노력으로 HAL을 제압한다. 보우만은 마침내 목성 궤도에서 문제의 검은 돌기둥을 발견하지만, 그 순간 우주의 급류에 휘말리게 된다. 보우만은 지구로의 귀환을 위해 노력하고, 신비한 시간의 흐름을 경험하는데...', 'https://image.tmdb.org/t/p/w500/2qJjH5mYNlGPdVrPqfEq1J6Mgb4.jpg', 1968, 0, 0, '2026-06-06 13:25:17.222066', 'US');
INSERT INTO public.movies VALUES (640, 43949, '플립', '["Romance", "Drama"]', NULL, '[]', '건너편에 이사 온 브라이스를 보고 첫 눈에 사랑을 직감한 7살 줄리. 그 후로 줄리는 브라이스에게 끊임없이 마음을 표현하지만, 나무가 잘리는 걸 막기 위해 시위를 하는 등 남다른 행동을 하는 줄리의 모습이 이상할 뿐이다. 그런 줄리를 요리조리 피해 다니기를 6년. 어느 날, 줄리가 정성들여 키운 닭의 계란을 선물 받고 바로 쓰레기통에 버리던 브라이스의 모습을 줄리에게 들키고 만다. 브라이스는 화가 난 줄리에게 미안함을 느끼며 자꾸 신경이 쓰인다. 철없는 브라이스에 비해, 가난하지만 화목한 가정 속에서 현명하게 살아가는 마음이 예쁜 줄리. 그런 그녀를 보며 사랑임을 확신하는데...', 'https://image.tmdb.org/t/p/w500/cTrDvMeKGagEk07x9lwewGNofgh.jpg', 2010, 0, 0, '2026-06-06 13:25:20.363165', 'US');
INSERT INTO public.movies VALUES (4611, 14003, '강철의 연금술사: 샴발라를 정복하는 자', '["Action", "Adventure", "Animation", "Drama"]', 'Seiji Mizushima', '["Romi Park", "Rie Kugimiya", "Toru Okawa", "Megumi Toyoguchi", "Miyuu Sawai"]', '1920년 독일로 떨어진 에드워드는 연금술을 사용할 수 없게 되어, 로켓등의 기계문맹에 관심을 가지된다. 그런데 이곳(현실세계)에서 전설에 등장하는 샴발라라고 불리는 에드의 세계로 가기 위한 음모가 꾸며진다. 여러가지 우여곡절끝에 결국 에드는 아보지 호엔 함임을 연성하고 알은 살아남은 호문크루스인 롸스와 그라토니를 연성하여 문을 열게되는데...', 'https://image.tmdb.org/t/p/w500/pBTMwJQp5h5si0fUsPqRLbCEm4W.jpg', 2005, 0, 0, '2026-06-08 06:34:01.822591', 'JP');
INSERT INTO public.movies VALUES (344, 855435, '사형참극', '["Horror"]', 'Daniel Goldhaber', '["Barbie Ferreira", "Dacre Montgomery", "Josie Totah", "Aaron Holliday", "Jermaine Fowler"]', '웹사이트 콘텐츠 관리자로 일하는 한 여성이 영화 속 죽음 장면을 재현한 일련의 폭력적인 영상들을 발견하게 된다.', 'https://image.tmdb.org/t/p/w500/vPVY3S57lEooBLJCg6KGdMHkUxm.jpg', 2026, 0, 0, '2026-06-06 13:25:09.450608', 'US');
INSERT INTO public.movies VALUES (348, 912649, '베놈: 라스트 댄스', '["Sci-Fi", "Action", "Adventure"]', 'Kelly Marcel', '["Tom Hardy", "Chiwetel Ejiofor", "Juno Temple", "Rhys Ifans", "Stephen Graham"]', '환상의 케미스트리의 에디 브록과 그의 심비오트 베놈은 그들을 노리는 정체불명 존재의 추격을 피해 같이 도망을 다니게 된다. 한편 베놈의 창조자 널은 고향 행성에서부터 그들을 찾아내기 위해 지구를 침략하고 에디와 베놈은 그동안 겪어보지 못한 최악의 위기를 맞이하게 되는데…', 'https://image.tmdb.org/t/p/w500/ptfoRD0MmL8Ry0iBVccYbqoN9Xc.jpg', 2024, 0, 0, '2026-06-06 13:25:09.461481', 'US');
INSERT INTO public.movies VALUES (4097, 601796, '외계+인 1부', '["Sci-Fi", "Action", "Fantasy", "Adventure"]', 'Choi Dong-hoon', '["Ryu Jun-yeol", "Kim Woo-bin", "Kim Tae-ri", "So Ji-sub", "Yum Jung-ah"]', '2022년 현재, 가드와 썬더는 인간의 몸에 가두어진 외계인 죄수를 관리하며 지구에 살고 있다. 어느 날, 서울 상공에 우주선이 나타나고 형사 문도석은 기이한 광경을 목격하게 되는데.. 한편, 630년 전 고려시대 얼치기 도사 무륵과 천둥 쏘는 처자 이안이 엄청난 현상금이 걸린 신검을 차지하기 위해 서로를 속고 속이는 가운데 신검의 비밀을 찾는 두 신선 흑설과 청운, 가면 속의 자장도 신검 쟁탈전에 나선다. 그리고 우주선이 깊은 계곡에서 빛을 내며 떠오르는데…', 'https://image.tmdb.org/t/p/w500/ynyN9hdxL5vq7GnSX8Fdz3TfoTE.jpg', 2022, 0, 0, '2026-06-08 06:26:59.776137', 'KR');
INSERT INTO public.movies VALUES (4099, 397469, '새폴더 2', '["Drama"]', 'Hwang Sang-won', '["Yoon Sul-hee", "Lee Doo-yeon", "Kim Soo-ji", "Amy", "Shin Hwa-chul"]', NULL, 'https://image.tmdb.org/t/p/w500/tAp9J9WhZSY0zGhq0D9ufk1zj9p.jpg', 2015, 0, 0, '2026-06-08 06:27:01.833962', 'KR');
INSERT INTO public.movies VALUES (363, 1643729, 'Ishqa''n De Lekhe', '["Drama", "Romance"]', 'Manvir Brar', '["Gurnam Bhullar", "Isha Malviya", "Rana Ranbir", "Mintu Kapa", "Balwinder Bullet"]', NULL, 'https://image.tmdb.org/t/p/w500/eky8n1Xu5oMDe4iu4pKFCdStHkt.jpg', 2026, 0, 0, '2026-06-06 13:25:10.207517', 'IN');
INSERT INTO public.movies VALUES (355, 8966, '트와일라잇', '["Fantasy", "Drama", "Romance"]', 'Catherine Hardwicke', '["Kristen Stewart", "Robert Pattinson", "Billy Burke", "Peter Facinelli", "Ashley Greene"]', '17세의 평범한 고등학생 소녀 ‘벨라’는 집안 사정으로 워싱턴 주 포크스에 있는 아빠의 집으로 이사를 온다. 전학 첫날, ‘벨라’는 냉담하지만 자신을 무장 해제시킬 정도로 잘생긴 ‘에드워드’와 마주치고, 전율과 두려움 넘치는 인생의 전환을 맞이한다. ‘에드워드’와 돌이킬 수 없는 사랑에 빠져든 ‘벨라’. 하지만 ‘에드워드’와 그의 가족이 뱀파이어 일족이라는 사실을 알게 되고, 예기치 못한 운명에 빠져든다.', 'https://image.tmdb.org/t/p/w500/ryvt6cLTjHHH7Nnce3Xi5S3I533.jpg', 2008, 0, 0, '2026-06-06 13:25:09.478839', 'US');
INSERT INTO public.movies VALUES (4092, 614696, '#살아있다', '["Action", "Horror", "Sci-Fi"]', 'Cho Il', '["Yoo Ah-in", "Park Shin-hye", "Lee Hyun-wook", "Jin So-yeon", "Kim Hak-seon"]', '원인불명 증세의 사람들의 공격에 통제불능에 빠진 도시. 영문도 모른 채 잠에서 깬 준우는 아무도 없는 집에 혼자 고립된 것을 알게 된다. 데이터, 와이파이, 문자, 전화 모든 것이 끊긴 채 고립된 상황. 연락이 두절된 가족에 이어 최소한의 식량마저 바닥이 나자 더 이상 버티기 힘들어진 준우. 하지만 그 순간 건너편 아파트에서 누군가 시그널을 보내온다. 또 다른 생존자 유빈이 아직 살아있음을 알게 된 준우는 함께 살아남기 위한 방법을 찾아 나서는데...', 'https://image.tmdb.org/t/p/w500/zb06eXz3Pg5JzytPnMFb3cIDV7B.jpg', 2020, 0, 0, '2026-06-08 06:26:54.839504', 'KR');
INSERT INTO public.movies VALUES (4098, 792723, '처제가 왜 거기서 나와?', '["Romance"]', 'Kim Jong-seok', '["Ye Seul", "Sae Bom", "Kang Min-woo"]', '언니와 같이 살고 있는 여대생 미나는 명품을 사기 위해 언니 몰래 술집에서 아르바이트를 한다. 평소와 같이 술집에 출근 한 미나는 룸에서 형부를 손님으로 맞이하고 도망치듯 나온다. 미나는 언니에게 비밀로 해달라고 부탁하며 형부를 유혹하는데...', 'https://image.tmdb.org/t/p/w500/8yTFfOplPMQs6HG3pGex6tXZO7x.jpg', 2020, 0, 0, '2026-06-08 06:27:00.442538', 'KR');
INSERT INTO public.movies VALUES (356, 101, '레옹', '["Crime", "Drama", "Action"]', 'Luc Besson', '["Jean Reno", "Natalie Portman", "Gary Oldman", "Danny Aiello", "Peter Appel"]', '한 손엔 우유 2팩이 든 가방, 다른 한 손엔 화분을 들고 뿌리 없이 떠도는 킬러 레옹은 어느 날 옆 집 소녀 마틸다의 일가족이 몰살 당하는 것을 목격한다. 그 사이 심부름을 갔다 돌아 온 마틸다는 가족들이 처참히 몰살 당하자 레옹에게 도움을 청한다. 가족의 원수를 갚기 위해 킬러가 되기로 결심한 12세 소녀 마틸다는 레옹에게 글을 알려주는 대신 복수하는 법을 배우고, 그 사이 레옹에 대한 사랑을 키워나간다. 드디어 그녀는 가족을 죽인 사람이 부패한 마약 경찰 스탠스임을 알게 되고, 홀로 그의 사무실로 향하게 되는데...', 'https://image.tmdb.org/t/p/w500/cVNasmF1Egd3v3mpq747Hizxx4x.jpg', 1994, 0, 0, '2026-06-06 13:25:09.481436', 'FR');
INSERT INTO public.movies VALUES (358, 218, '터미네이터', '["Action", "Thriller", "Sci-Fi"]', 'James Cameron', '["Arnold Schwarzenegger", "Michael Biehn", "Linda Hamilton", "Paul Winfield", "Lance Henriksen"]', '1997년, 인간이 만든 인공지능 컴퓨터 전략 방어 네트워크가 스스로의 지능을 갖추고는 인류를 핵전쟁의 참화을 일으켜 30억이라는 인류를 잿더미 속에 묻어버린다. 그리고 남은 인간들은 기계의 지배를 받아 시체를 처리하는 일 등에 동원된다. 이때 비상한 지휘력과 작전으로 인간들을 이끌던 사령관 존 코너는 반기계 연합을 구성, 기계와의 전쟁을 시작하면서 상황은 반전된다. 이에 기계는 존 코너의 탄생 자체를 막기 위해 2029년의 어느 날 타임머신에 터미네이터를 태워서 1984년의 L.A로 보내게 된다.', 'https://image.tmdb.org/t/p/w500/sez4xWeylbYQqiI8HIgnciTP7MY.jpg', 1984, 0, 0, '2026-06-06 13:25:09.48641', 'US');
INSERT INTO public.movies VALUES (354, 1549519, 'Sex Trip', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/oVyD6sX6Vr5Ej8X1DLrs12zG40Y.jpg', 2026, 0, 0, '2026-06-06 13:25:09.476269', 'US');
INSERT INTO public.movies VALUES (469, 2105, '아메리칸 파이', '["Comedy", "Romance"]', 'Paul Weitz', '["Jason Biggs", "Chris Klein", "Thomas Ian Nicholas", "Alyson Hannigan", "Shannon Elizabeth"]', '이스트그레이트 폴츠 고등학교(East Great Falls High School) 졸업반이 된 네 녀석들은 지상 최대의 고민에 빠져있다! 도대체 어떻게 하면 ''총각 딱지''을 떼어버릴 수 있을까? 결국 졸업하기 전까지는 하늘이 두쪽나도 그걸 떼버리고야 말리라 다짐한 이들은 ''성공적인 첫 경험''을 위한 다각적 전술을 세우기 시작한다.  지미(Jim: 제이슨 비그스 분)는 성인 채널, 포르노 사이트, 풍선도 아닌데 불어보는 콘돔. 혼자서 어떻게든 그걸 해결해 보려고 한다. 그러던 중 엄마가 먹으라고 구워놓은 애플파이에 구멍을 뚫어 그걸(?) 하던 중 아빠에게 들키고 만다. 도대체 왜 그랬을가? 하지만 그에게도 나디아(Nadia: 샤논 엘리자베스 분)라는 여학생이 숙제를 도와달라며 기회가 찾아온다.  케빈(Kevin: 토마스 이안 니콜라스 분)은 사랑보다는 섹스라는 구체적인 말을 더 믿는다. 오랜 여자 친구 비키(Victoria ''Vicky'': 타라 레이드 분)와 항상 가다가 마는, 결국은 아직까지 한번도 제대로 해보지 못한 미완의 커플. 어떻게든 성공적으로 해보고 싶은 케빈은 섹스의 백과사전이랄 수 있는 섹스 바이블을 입수하는데.  미식축구 선수 오즈(Chris "Oz" Ostreicher: 크리스 클레인 분)는 노바, 일명 카사노바로 자칭하지만 실제로는 근처에도 가보지 못했다. 우연히 아카펠라 합창단원인 헤더(Heather: 메나 수바리 분)에게 첫눈에 반해 덩달아 합창단에 들어가게 된다. 그러나 요조 숙녀 헤더는 오즈와 친구들의 외설스런 대화를 듣고 실망하는데.  결벽증이 있는 핀치(Finch: 에디 케이 토마스 분)는 늘 그것(?) 보다는 커피와 카푸치노의 차이에 대해 열변을 토하는 술취한 철학자. 평소 섹스엔 전혀 관심없는 척 하던 그는 작전돌입 후 여학생들에게 자기의 그것(?)이 가장 크다는 소문을 내어 호기심을 유발시키려하는데...', 'https://image.tmdb.org/t/p/w500/5P68by2Thn8wHAziyWGEw2O7hco.jpg', 1999, 0, 0, '2026-06-06 13:25:14.088699', 'US');
INSERT INTO public.movies VALUES (527, 762509, '무파사: 라이온 킹', '["Adventure", "Family", "Animation"]', NULL, '[]', '길을 잃고 혼자가 된 새끼 사자 무파사는 광활한 야생을 떠돌던 중 왕의 혈통이자 예정된 후계자 타카와 우연히 만나게 된다. 마치 친형제처럼 끈끈한 우애를 나누며 함께 자란 무파사와 타카는 운명을 개척하기 위해 거대한 여정을 함께 떠난다. 한 치 앞을 알 수 없는 적들의 위협 속에서 두 형제의 끈끈했던 유대에 금이 가기 시작하고 예상치 못한 위기까지 맞닥뜨리게 되는데…', 'https://image.tmdb.org/t/p/w500/1VUExee8iFohFTwYVi4IOArYyaM.jpg', 2024, 0, 0, '2026-06-06 13:25:16.448172', 'US');
INSERT INTO public.movies VALUES (374, 963261, '아들의 여친 아빠의 여친 2', '["Romance"]', 'Ri Yoon', '["Yoo Jung", "Kim Soo-ji", "Lee Chae-dam", "Cha Myung-Hoon", "Park Do-jin"]', '아들의 여친 아빠의 여친 2', 'https://image.tmdb.org/t/p/w500/6xu9crDySkzj16gfH89Elc2Yyqc.jpg', 2022, 0, 0, '2026-06-06 13:25:10.233945', 'KR');
INSERT INTO public.movies VALUES (4101, 952079, '초대받은 배달부 2', '["Romance"]', 'Lee Sang-soo', '["Yeon Joo", "Yoo Ji-hyun", "Im Tae-mok"]', '발기부전으로 성생활에 문제가 있는 부부가 근육질의 배달부, 비뇨기과 여의사와 벌이는 성행각을 그린 성애영화', 'https://image.tmdb.org/t/p/w500/41Q9zWeeZXJguvrSmZGDgci1cbB.jpg', 2022, 0, 0, '2026-06-08 06:27:03.170872', 'KR');
INSERT INTO public.movies VALUES (370, 38365, '다 큰 녀석들', '["Comedy"]', 'Dennis Dugan', '["Adam Sandler", "Kevin James", "Chris Rock", "David Spade", "Rob Schneider"]', '초등학교 농구팀 팀원으로 지냈던 다섯 친구. 당시 코치 선생님의 부고 소식에 30년만에 재회한다. 그리고 가족동반으로 호숫가 별정에 간 이들. 어째 데리고 간 아이들보다 어른들이 더 말썽이다. 나이만 먹었지 정작 성장은 하지 못한 어른들이 이야기를 코믹하게 그린다.', 'https://image.tmdb.org/t/p/w500/2vgdOjlrpuGTwnMNzFWPSuaKuVA.jpg', 2010, 0, 0, '2026-06-06 13:25:10.224625', 'US');
INSERT INTO public.movies VALUES (4102, 1355666, '고백의 역사', '["Romance", "Drama", "Comedy"]', 'Namkoong Sun', '["Shin Eun-soo", "Gong Myoung", "Cha Woo-min", "Youn Sang-hyun", "Kang Mi-na"]', '사랑에 빠진 10대 소녀, 학교 최고 인기남의 마음을 얻기 위해 곱슬머리를 생머리로 바꾸기로 결심한다.', 'https://image.tmdb.org/t/p/w500/hOi5K1tx8aAZN239VU1qzvyao87.jpg', 2025, 0, 0, '2026-06-08 06:27:03.843152', 'KR');
INSERT INTO public.movies VALUES (526, 1318413, 'Pressure', '["Thriller", "History"]', 'Anthony Maras', '["Andrew Scott", "Brendan Fraser", "Kerry Condon", "Chris Messina", "Damian Lewis"]', NULL, 'https://image.tmdb.org/t/p/w500/9RkDrI8V8QJBjhtyRX7y6Qow3aq.jpg', 2026, 0, 0, '2026-06-06 13:25:16.445773', 'GB');
INSERT INTO public.movies VALUES (369, 559, '스파이더맨 3', '["Action", "Adventure", "Sci-Fi"]', 'Sam Raimi', '["Tobey Maguire", "Kirsten Dunst", "James Franco", "Thomas Haden Church", "Topher Grace"]', '대중의 사랑을 듬뿍 받으며 진정한 영웅으로 거듭난 스파이더맨, 피터 파커는 어느 날, 외계에서 온 수수께끼의 유기체인 심비오트에 감염되고 스파이더맨은 오리지날 스파이더맨에서 블랙 슈트 스파이더맨으로 변화한다. 한층 업그레이드 되고 강력해진 파워를 얻게 된 스파이더맨은 자신의 힘에 도취되어 마음껏 세상을 즐긴다. 그러나 아버지의 복수를 위해 뉴 고블린이 된 해리와 물리 실험에 노출되어 능력을 얻게 된 피터의 삼촌을 죽인 진범 샌드맨은 호시탐탐 스파이더맨을 노리는데...', 'https://image.tmdb.org/t/p/w500/9atb6Nn8TRGxfwROJGuzOD24GNl.jpg', 2007, 0, 0, '2026-06-06 13:25:10.222338', 'US');
INSERT INTO public.movies VALUES (373, 1119449, '굿 럭, 해브 펀, 돈 다이', '["Sci-Fi", "Action", "Comedy"]', 'Gore Verbinski', '["Sam Rockwell", "Juno Temple", "Haley Lu Richardson", "Michael Peña", "Zazie Beetz"]', '미래에서 온 한 남자가 로스앤젤레스의 한 식당에 도착한다. 그는 그곳에 모인 불만 가득한 손님들 가운데 정확한 조합을 골라, 그들과 함께 하룻밤 동안 지구를 구해내야 한다. 목표는 통제를 벗어난 인공지능이 초래할 최후의 위협을 막는 것이다.', 'https://image.tmdb.org/t/p/w500/rWcfOdY7TU6lTdazWj0ebDZnAfO.jpg', 2026, 0, 0, '2026-06-06 13:25:10.231669', 'US');
INSERT INTO public.movies VALUES (368, 1010755, '스트레인저스: 챕터3', '["Horror", "Thriller"]', 'Renny Harlin', '["Madelaine Petsch", "Richard Brake", "Ema Horvath", "Gabriel Basso", "Pedro Leandro"]', '핀업걸이 죽은 후, 남은 두 살인마들의 끝없는 추격으로 다시 한번 그들의 손아귀에 붙잡힌 마야. 스케어크로우와 돌페이스는 마야에게 핀업걸의 가면을 씌우고 그들의 살인 게임에 강제로 동참시킨다. 한편, 마야를 찾는 가족과 친구들이 비너스 마을까지 다다르고 마스크 살인마들과 마을을 둘러싼 어두운 비밀이 차츰 밝혀진다. 수십 년을 이어 온 살육과 비극의 숨바꼭질을 끝내기 위해, 마야는 이제 스스로 총을 들고 마지막 게임을 준비하는데...', 'https://image.tmdb.org/t/p/w500/nxoxD8FdbhRWd2Ra0W6qsZA0frn.jpg', 2026, 0, 0, '2026-06-06 13:25:10.220027', 'US');
INSERT INTO public.movies VALUES (365, 1088434, 'Hellfire', '["Action", "Thriller"]', 'Isaac Florentine', '["Stephen Lang", "Harvey Keitel", "Scottie Thompson", "Dolph Lundgren", "Chris Mullinax"]', NULL, 'https://image.tmdb.org/t/p/w500/tQti9QTf13MfzNpXguijgNh7ojE.jpg', 2026, 0, 0, '2026-06-06 13:25:10.212833', 'US');
INSERT INTO public.movies VALUES (2870, 1477712, '아이스크림맨', '["Horror", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/c987gxFjXqYOxZEZKcTkS1ONTWH.jpg', 2026, 0, 0, '2026-06-07 12:17:51.948959', 'US');
INSERT INTO public.movies VALUES (375, 1062722, '프랑켄슈타인', '["Drama", "Fantasy", "Horror"]', 'Guillermo del Toro', '["Oscar Isaac", "Jacob Elordi", "Christoph Waltz", "Mia Goth", "Felix Kammerer"]', '과학자 빅터 프랑켄슈타인과 그의 손에서 탄생한 괴물이 펼치는 이야기. 고전이 된 메리 셸리의 소설을 오스카 수상 감독 기예르모 델토로가 영화화했다.', 'https://image.tmdb.org/t/p/w500/vSMWJkBTEfa7kFxHizSz4uJNVlf.jpg', 2025, 0, 0, '2026-06-06 13:25:10.236292', 'US');
INSERT INTO public.movies VALUES (367, 1241634, '떠돌이별', '["Romance", "Drama"]', 'Mohit Suri', '["Ahaan Panday", "Aneet Padda", "Alam Khan", "Rajesh Kumar", "Geeta Agrawal Sharma"]', '재능 있는 음악가와 열정적인 작가가 사랑에 빠진다. 그러나 점차 성공이 찾아오면서 재앙 같은 병이 두 사람을 갈라놓으려 하는데.', 'https://image.tmdb.org/t/p/w500/hQBIsi3ZfBYEayMc3GhcEmJVkss.jpg', 2025, 0, 0, '2026-06-06 13:25:10.217767', 'IN');
INSERT INTO public.movies VALUES (366, 426889, 'Le Clitoris', '["Animation", "Documentary"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/osBGGlyIwsnSDIJ3vy83JpH1OUY.jpg', 2017, 0, 0, '2026-06-06 13:25:10.215279', 'US');
INSERT INTO public.movies VALUES (4104, 122126, '후궁: 제왕의 첩', '["Drama"]', 'Kim Dae-seung', '["Cho Yeo-jeong", "Kim Dong-wook", "Kim Min-jun", "Park Ji-young", "Cho Eun-ji"]', '부모의 강요로 후궁이 되어야 하는 화연(조여정)은 오랜 연인인 권유(김민준)와 헤어져 궁으로 들어간다. 왕의 이복동생인 성원대군(김동욱)은 화연을 사랑하지만, 형수가 된 그녀를 어쩔 수는 없다. 5년 뒤, 선왕의 승하와 함께 성원대군은 왕위에 오른다. 섭정의 명목으로 왕의 머리 위에 오른 대비(박지영)와 그녀의 간신들이 선왕의 세력들을 처단하는 가운데, 화연 또한 위기에 놓인다. 하지만 여전히 그녀를 사랑하는 성원대군은 무능한 왕이고, 내시가 되어 궁에 들어온 옛 연인 권유는 화연과 화연의 부모를 향해 이를 갈고 있는데...', 'https://image.tmdb.org/t/p/w500/tkkUBkGMnoaxwzClDMFZ0HKlXG8.jpg', 2012, 0, 0, '2026-06-08 06:27:05.364906', 'KR');
INSERT INTO public.movies VALUES (378, 10193, '토이 스토리 3', '["Animation", "Family", "Comedy"]', 'Lee Unkrich', '["Tom Hanks", "Tim Allen", "Joan Cusack", "Don Rickles", "Wallace Shawn"]', '모든 장난감들이 겪는 가장 슬픈 일은 바로 주인이 성장해 더이상 자신들과 놀아주지 않는 것. 우디와 버즈에게도 그 위기가 찾아온다. 앤디가 대학에 진학, 집을 떠나게 된 것. 헤어짐의 불안에 떨던 토이들은 앤디 엄마의 실수로 집을 나오게 되고 우여곡절 끝에 탁아소에 기증된다. 앤디가 자신들을 버렸다고 생각하는 장난감들. 게다가 어린이집의 아이들은 난폭하고 험한 데다가, 상상도 못했던 거대한 음모까지 숨겨져 있는 어린이집 장난감의 세계. 앤디가 여전히 자신들을 사랑한다는 사실을 알게 된 장난감들은 앤디 곁으로 돌아가기 위해 생애 가장 큰 모험을 결심하는데...', 'https://image.tmdb.org/t/p/w500/hbUWahBLUon8RaIb9Tq7aWCBCtS.jpg', 2010, 0, 0, '2026-06-06 13:25:10.243458', 'US');
