INSERT INTO public.movies VALUES (381, 1557848, 'Uykucu', '["Action", "Thriller", "Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/xvycfI4PRusKfqvzmkb8xqO0g48.jpg', 2025, 0, 0, '2026-06-06 13:25:10.998906', 'US');
INSERT INTO public.movies VALUES (383, 1294203, '나의 잘못: 런던', '["Drama", "Romance"]', 'Dani Girdwood', '["Asha Banks", "Matthew Broome", "Eve Macklin", "Ray Fearon", "Enva Lewis"]', '영국의 부유한 사업가 윌리엄과 최근 사랑에 빠진 엄마를 따라 미국에서 영국으로 거처를 옮긴 18세 노아는 윌리엄의 불량한 아들 닉을 만나게 되고 둘은 서로에게 거부할 수 없는 매력을 느낀다. 여름 내내 노아는 새로운 생활에 적응하며 처음으로 사랑에 빠지지만 과거의 괴로운 기억이 노아의 발목을 잡는다.', 'https://image.tmdb.org/t/p/w500/h7H6Kd9kX1dvN8FZjUy6FcNdXxQ.jpg', 2025, 0, 0, '2026-06-06 13:25:11.005587', 'GB');
INSERT INTO public.movies VALUES (4652, 391345, '화신', '["Romance", "Drama"]', 'Yōichi Higashi', '["Tatsuya Fuji", "Hitomi Kuroki", "Yoko Aki", "Hiroko Aota", "Masato Hoshi"]', '일본의 유명 소설가 와타나베 준이치의 동명 소설을 원작으로 한 작품. 중년 남성의 탐미주의와 한 여성이 세련되게 변모해가는 과정을 그린 ''피그말리온''적 테마를 담고 있다.', 'https://image.tmdb.org/t/p/w500/6KEIO30IXRhez4OIYTyKaq31ItQ.jpg', 1986, 0, 0, '2026-06-08 06:34:35.381329', 'JP');
INSERT INTO public.movies VALUES (386, 1652947, 'Tuklas', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/pJiNDWSEguOY8m5x2vbgnl9DPme.jpg', 2026, 0, 0, '2026-06-06 13:25:11.014675', 'US');
INSERT INTO public.movies VALUES (382, 49051, '호빗: 뜻밖의 여정', '["Adventure", "Fantasy", "Action"]', 'Peter Jackson', '["Martin Freeman", "Ian McKellen", "Richard Armitage", "James Nesbitt", "Ken Stott"]', '호빗족 빌보 배긴스는 어느 날 찾아온 회색의 마법사 간달프로부터 뜻밖의 제안을 받는다. 오래 전 난쟁이족의 영토였지만 무시무시한 용 스마우그에게 빼앗겨 지금은 황무지로 변한 동쪽의 외로운 산 에레보르 왕국을 되찾기 위해 함께 떠나자는 것. 빌보는 전설의 용사 소린이 이끄는 13명의 난쟁이족과 함께 위험 가득한 여정에 오른다. 외로운 산에 가기 위해서 반드시 거쳐야 하는 고블린 동굴에서 일행과 떨어져 헤매던 빌보는 그의 일생을 뒤바꿔놓는 존재인 골룸과 마주치게 되고, 골룸과의 수수께끼 대결 중에 대단한 힘을 지닌 골룸의 보물 절대반지를 얻게 되는데...', 'https://image.tmdb.org/t/p/w500/vtsequVUU3W2NVfWObXkq31VIgN.jpg', 2012, 0, 0, '2026-06-06 13:25:11.002411', 'US');
INSERT INTO public.movies VALUES (8699, 197796, '미녀와 야수', '["Fantasy", "Romance"]', 'Christophe Gans', '["Vincent Cassel", "Léa Seydoux", "André Dussollier", "Eduardo Noriega", "Myriam Charleins"]', '벨 은 상인이었던 아버지의 배가 침몰된 후 두 언니와 오빠들, 아버지와 함께 시골로 내려간다. 다른 형제들은 시골 생활에 불만이 많지만 벨은 밭을 일구며 가족과 함께하는 일상에 오히려 만족한다. 어느 날 침몰되었던 배가 발견되어 재산을 되찾을 수 있다는 희망을 가지고 마을로 나갔던 아버지가 눈보라 속에 기이한 성에 도달하고, 그곳에서 많은 보석을 가져오게 된다. 마지막으로 벨의 부탁이었던 장미꽃 한 송이를 꺾자 야수 가 모습을 드러낸다. 예기치 않게 찾아온 운명의 밤, 장미 한 송이로 시작된 위험한 거래와 사랑. 순수한 사랑을 갈망하는 외로운 야수와 아름다운 벨의 로맨스가 시작되는데...', 'https://image.tmdb.org/t/p/w500/lM2K5eGz9kvrYRi366wEzVwC8Tb.jpg', 2014, 0, 0, '2026-06-08 07:28:22.016911', 'FR');
INSERT INTO public.movies VALUES (575, 530385, '미드소마', '["Horror", "Drama", "Mystery"]', NULL, '[]', '한여름, 낮이 가장 긴 날 열리는 미드소마에 참석하게 된 친구들. 꽃길인 줄 알고 들어간 지옥길, 축제가 끝나기 전까지 절대 빠져나올 수 없다. 큰 상실을 겪은 대니가 남자친구 크리스티안과 비밀스러운 스웨덴의 한 마을에서 한여름 낮이 가장 긴 날 열리는 하지 축제에 참석해 기이한 경험을 겪고 점점 공포에 빠져들게 되는데...', 'https://image.tmdb.org/t/p/w500/u2c6wgkam9JJ5V4ML3l8EqIXCdF.jpg', 2019, 0, 0, '2026-06-06 13:25:18.007923', 'US');
INSERT INTO public.movies VALUES (391, 12, '니모를 찾아서', '["Animation", "Family", "Adventure"]', 'Andrew Stanton', '["Albert Brooks", "Ellen DeGeneres", "Alexander Gould", "Willem Dafoe", "Geoffrey Rush"]', '광대어 말린은 아내 코랄과 2세들의 부화를 기다리던 중 상어의 습격을 받는다. 알을 보호하려던 아내는 행방불명되고, 유일하게 살아남은 아기에게 말린은 니모라는 이름을 붙인다. 사건 이후 큰 바다를 무조건 겁내게 된 말린은 니모를 과보호한다. 하지만 니모는 등교 첫날 잠수부에게 납치돼 시드니에 있는 치과의사의 수족관에 끌려가고, 슬픔으로 혼비백산한 아빠 말린은 평소의 심약함을 잊고니모를 찾아나선다. 단기기억상실증을 지닌 명랑한 물고기 도리의 도움으로 상어, 심해어, 해파리의 위협을 뚫고 동호주 해류로 향하는 동안, 니모는 수족관의 새 친구들과 탈출을 모의한다.', 'https://image.tmdb.org/t/p/w500/9ViCYfZ0whpwtKbM2WJP5PfsG2x.jpg', 2003, 0, 0, '2026-06-06 13:25:11.028875', 'US');
INSERT INTO public.movies VALUES (396, 986056, '썬더볼츠*', '["Action", "Sci-Fi", "Adventure"]', 'Jake Schreier', '["Florence Pugh", "Sebastian Stan", "Julia Louis-Dreyfus", "Lewis Pullman", "David Harbour"]', '어벤져스가 사라진 후, 세계 최대의 위협과 마주한 세상을 구하기 위해 전직 스파이, 암살자, 살인 청부 업자 등 마블의 별난 놈들이 펼치는 예측불허 팀플레이를 담은 액션 블록버스터', 'https://image.tmdb.org/t/p/w500/iTX4O9gb8Jn0F5N5WgYnbIopdnP.jpg', 2025, 0, 0, '2026-06-06 13:25:11.04328', 'US');
INSERT INTO public.movies VALUES (594, 370172, '007 노 타임 투 다이', '["Action", "Thriller", "Adventure"]', 'Cary Joji Fukunaga', '["Daniel Craig", "Léa Seydoux", "Rami Malek", "Lashana Lynch", "Ralph Fiennes"]', 'MI6를 떠난 이후 매들린과 이탈리아의 오랜 도시 마테라에서 평화로운 일상을 즐기던 제임스 본드. 어느 날 CIA 요원 펠릭스가 찾아와 선별적 DNA 공격이 가능한 새로운 형태의 생화학 무기 유출을 알린다. 위험에 처한 전 세계를 구하기 위해 복귀하게 된 제임스 본드는 임무를 수행하는 과정에서 새로운 MI6 요원 노미를 만나고, 모든 사건의 배후에 운명으로 얽혀 있는 최악의 적 사핀이 존재한다는 것을 알아낸다. 위험천만한 위기 속, 감춰져 있던 비밀이 밝혀지면서 작전은 점점 더 예측할 수 없는 상황으로 치닫게 되는데...', 'https://image.tmdb.org/t/p/w500/68ZwnPALUeweaFdT1z75oXJ4Xie.jpg', 2021, 0, 0, '2026-06-06 13:25:18.778917', 'GB');
INSERT INTO public.movies VALUES (392, 675, '해리 포터와 불사조 기사단', '["Adventure", "Fantasy"]', 'David Yates', '["Daniel Radcliffe", "Rupert Grint", "Emma Watson", "Imelda Staunton", "Helena Bonham Carter"]', '길고도 지루한 여름 날 호그와트 마법학교 다섯 번째 해를 기다리고 있는 해리포터. 이모부 더즐리 식구들과 참고 사는 것도 지겨운데다 친구 론과 헤르미온느에게서는 편지 한 통 오지 않는다. 그러던 중 예상치 못했던 편지 한 장이 도착한다. 그것은 해리가 학교 밖인 리틀 위닝에서 얄미운 사촌 두들리, 즉 머글 앞에서 디멘터들의 공격을 막는 마법을 사용했기 때문에 호그와트 마법학교에서 퇴학 당하게 되었다는 소식이었다. 앞이 캄캄한 해리. 갑자기 어둠의 마법사 오러들이 나타나 해리를 불사조 기사단의 비밀 장소로 데리고 가는데...', 'https://image.tmdb.org/t/p/w500/1ItejykqHTbFWbZXdzqlvqriv7K.jpg', 2007, 0, 0, '2026-06-06 13:25:11.031566', 'GB');
INSERT INTO public.movies VALUES (395, 1384758, '아이스 에이지 6: 화산 대폭발', '["Adventure", "Animation", "Comedy", "Family"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/pwOLMfHdCPHcpftM93igKNkPWsS.jpg', 2027, 0, 0, '2026-06-06 13:25:11.040559', 'US');
INSERT INTO public.movies VALUES (4106, 955555, '범죄도시 3', '["Action", "Crime", "Comedy", "Thriller"]', 'Lee Sang-yong', '["Don Lee", "Lee Jun-hyuk", "Munetaka Aoki", "Lee Beom-soo", "Kim Min-jae"]', '베트남 납치 살해범 검거 후 7년 뒤, 마석도는 새로운 팀원들과 함께 살인사건을 조사한다. 사건 조사 중 마석도는 신종 마약 사건이 연루되었음을 알게 되고 수사를 확대한다. 한편 마약 사건의 배후인 주성철은 계속해서 판을 키워가고, 약을 유통하던 일본 조직과 리키까지 한국에 들어오며 사건의 규모는 점점 더 커져가는데...', 'https://image.tmdb.org/t/p/w500/kPtNokhBtgwSp3MHaR3X4O0SPbF.jpg', 2023, 0, 0, '2026-06-08 06:27:06.926215', 'KR');
INSERT INTO public.movies VALUES (2883, 954, '미션 임파서블', '["Adventure", "Action", "Thriller"]', NULL, '[]', '동유럽 첩보원들의 비밀 명단을 훔쳐 무기상에 팔아 넘기려는 음모를 막기 위해 짐 펠프스가 이끄는 CIA 최고의 팀 미션 임파서블이 투입된다. 그러나 대사관 파티에 잠입하여 동료들과 함께 작전을 수행하던 중 팀의 리더였던 이단 헌트만이 구사일생으로 혼자 살아 남는다. 곧 이어 본부에 연락을 취한 헌트는 이번 작전이 CIA 내에 침투한 이중간첩의 체포작전이라는 것과 자신이 범인으로 지목된 것을 알고 재빨리 피신한다. 그는 자신을 함정에 빠뜨리고 동료들을 살해한 진짜 범인을 찾기 위해 나선다. 마침내 그는 컴퓨터의 접속암호를 풀어 무기 밀매상인 맥스와 연락을 취하는데...', 'https://image.tmdb.org/t/p/w500/6vDaYhZypJzd8r0NnSY2JPIX6Y5.jpg', 1996, 0, 0, '2026-06-07 12:17:52.769582', 'US');
INSERT INTO public.movies VALUES (4107, 560210, '내 학생의 엄마 3', '["Romance"]', 'Yoo Hae-jong', '["Ga Bin", "Park Joo-bin", "Sang Woo", "Yoon Taek-seung", "Yoo Sul-young"]', NULL, 'https://image.tmdb.org/t/p/w500/jPYWpxZXEF35qkY9OTGU2z8l9Uh.jpg', 2018, 0, 0, '2026-06-08 06:27:07.589595', 'KR');
INSERT INTO public.movies VALUES (401, 1321179, '왕과 사는 남자', '["History", "Drama"]', 'Chang Hang-jun', '["Yoo Hai-jin", "Park Ji-hoon", "Yoo Ji-tae", "Jeon Mi-do", "Kim Min"]', '계유정난이 조선을 뒤흔들고 어린 왕 이홍위는 왕위에서 쫓겨나 유배길에 오른다. 한편, 강원도 영월 산골 마을 광천골의 촌장 엄흥도는 먹고 살기 힘든 마을 사람들을 위해 청령포를 유배지로 만들기 위해 노력한다. 그러나 촌장이 부푼 꿈으로 맞이한 이는 왕위에서 쫓겨난 이홍위였다. 유배지를 지키는 보수주인으로서 그의 모든 일상을 감시해야만 하는 촌장은 삶의 의지를 잃어버린 이홍위가 점점 신경 쓰이는데…', 'https://image.tmdb.org/t/p/w500/kkJB3SeUJp7Y0IXXLkv5QZHJGkH.jpg', 2026, 0, 0, '2026-06-06 13:25:11.762368', 'KR');
INSERT INTO public.movies VALUES (404, 524047, '그린랜드', '["Thriller", "Adventure", "Action", "Sci-Fi"]', 'Ric Roman Waugh', '["Gerard Butler", "Morena Baccarin", "David Denman", "Hope Davis", "Roger Dale Floyd"]', '혜성의 지구 충돌 속보를 지켜보던 존과 가족들. 미 항공우주국(NASA)의 예측과 달리 해상으로 떨어졌어야 할 파편은 캘리포니아를 비롯해 세계 대도시로 추락해 세계는 순식간에 혼돈에 빠진다. 지구의 3/4을 날려버릴 초대형 혜성 추락까지 남은 시간은 단 48시간. 존과 가족은 지구의 유일한 안전 대피소인 ‘그린란드’의 벙커로 향하는데... 인류의 마지막 카운트다운이 시작된다!', 'https://image.tmdb.org/t/p/w500/wLgHczwajb3QV2JBgsqNVjuHoJC.jpg', 2020, 0, 0, '2026-06-06 13:25:11.770446', 'US');
INSERT INTO public.movies VALUES (403, 181808, '스타워즈 에피소드 8: 라스트 제다이', '["Adventure", "Action", "Sci-Fi"]', 'Rian Johnson', '["Mark Hamill", "Carrie Fisher", "Adam Driver", "Daisy Ridley", "John Boyega"]', '악의 세력인 무자비한 퍼스트 오더가 은하계를 장악한 시대. 레아 장군의 저항군은 힘겨운 싸움을 이어가고 있다. 그들의 유일한 희망은 마지막 제다이 루크 스카이워커. 저항군은 승리의 불씨를 지필 마지막 희망을 찾아 레이를 과거의 영웅 루크에게 보낸다. 레이는 우여곡절 끝에 루크를 찾아내지만, 자신의 잘못으로 레아의 아들 벤 솔로가 퍼스트 오더의 실세 카일로 렌이 되었다고 생각하는 루크는 함께 떠나자는 레이의 제안을 거절한다. 한편 레이는 알 수 없는 이유로 카일로 렌과 교감할 수 있게 된다.', 'https://image.tmdb.org/t/p/w500/zRvMTCzUVnkdW9lno9HQwrigWSr.jpg', 2017, 0, 0, '2026-06-06 13:25:11.768025', 'US');
INSERT INTO public.movies VALUES (933, 37799, '소셜 네트워크', '["Drama"]', NULL, '[]', '2003년 가을, 하버드대의 컴퓨터 천재 마크는 비밀 엘리트 클럽의 윈클보스 형제에게 하버드 선남선녀들만 교류할 수 있는 하버드 커넥션 사이트 제작을 의뢰 받는다. 하지만 여기서 획기적인 아이디어를 생각해낸 마크는 인맥 교류 사이트 페이스북을 개발, 절친 왈도의 도움으로 사이트를 오픈한다. 페이스북은 순식간에 모두의 마음을 사로잡고, 유명한 냅스터의 창시자 숀의 참여로 전세계로 번지면서 마크는 기업가치 58조원, 전세계 최연소 억만장자가 된다. 하지만 그 순간 윈클보스 형제는 물론 왈도마저 전대미문의 소송을 제기하는데...', 'https://image.tmdb.org/t/p/w500/4WAq2IZuVvWl0Wd1YIgBXdYgXna.jpg', 2010, 0, 0, '2026-06-06 13:25:31.952481', 'US');
INSERT INTO public.movies VALUES (402, 214756, '19곰 테드 2', '["Comedy", "Fantasy"]', 'Seth MacFarlane', '["Mark Wahlberg", "Seth MacFarlane", "Amanda Seyfried", "Jessica Barth", "Giovanni Ribisi"]', '왕따에게도 왕따 당하던 8살 존(마크 월버그)의 크리스마스 소원으로 살아 움직이게 된 테드(세스 맥팔레인)! 무적의 썬더 버디로 30년 동안 철없고 끈끈한 우정을 이어가던 둘은 테드가 인간이 아니라 물건(?)이라는 법원의 판결로 멘붕에 빠진다. 빡친 테드는 존과 함께 자신의 인권(?)을 입증하기 위해 승률 99.8% 변호사 사만다(아만다 사이프리드)를 찾아가는데……', 'https://image.tmdb.org/t/p/w500/9ljV8sG9HQs6bBc19Vw0754aujG.jpg', 2015, 0, 0, '2026-06-06 13:25:11.765615', 'US');
INSERT INTO public.movies VALUES (406, 866398, '비키퍼', '["Action", "Crime", "Thriller"]', 'David Ayer', '["Jason Statham", "Emmy Raver-Lampman", "Josh Hutcherson", "Jeremy Irons", "Bobby Naderi"]', '법 위에 있는 비밀 기관 ''비키퍼'' 그곳의 전설로 남은 탑티어 에이전트 ''애덤 클레이''는 기관의 눈을 피해 자취를 감추고 양봉가로 살아간다. 그러던 어느 날, 거대 보이스 피싱 조직으로부터 유일한 친구 ''엘로이즈''를 잃게 된 그는 피의 복수를 위해 잠재웠던 진짜 모습을 드러내기 시작하는데....', 'https://image.tmdb.org/t/p/w500/ekHemOB84SoKi6fqG0ciwvKWM2i.jpg', 2024, 0, 0, '2026-06-06 13:25:11.775055', 'US');
INSERT INTO public.movies VALUES (407, 1381027, '굿 보이', '["Thriller", "Drama", "Mystery"]', NULL, '[]', '성격이 급한 19세 청년 토미는 마약, 파티, 폭력에 빠져 산다. 술에 취해 친구들과 헤어진 그는 정체불명의 인물에게 납치된다. 깨어난 토미는 외딴 요크셔의 한 집 지하실에 갇혀 있고, 그곳에는 아주 이상한 가족이 살고 있다. 하지만 그에게 닥쳐오는 일들은 상상조차 할 수 없는 일들이다.', 'https://image.tmdb.org/t/p/w500/nXWewAZxRAr9jYNe2uypLlyPehl.jpg', 2026, 0, 0, '2026-06-06 13:25:11.777956', 'US');
INSERT INTO public.movies VALUES (405, 1542995, 'বনলতা এক্সপ্রেস', '["Drama", "Comedy", "Family"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/h6nITbbSobZ0EwU6Dcw6LGZOZYA.jpg', 2026, 0, 0, '2026-06-06 13:25:11.772713', 'US');
INSERT INTO public.movies VALUES (2890, 1206167, 'Return of the Jungle', '["Animation", "Comedy"]', 'Vaibhav Kumaresh', '[]', NULL, 'https://image.tmdb.org/t/p/w500/kXxSc3cG5wAB2wolqX8j0QKNwjD.jpg', 2026, 0, 0, '2026-06-07 12:17:52.786832', 'IN');
INSERT INTO public.movies VALUES (2897, 972445, '젬 2024', '["Comedy"]', NULL, '[]', '터키의 유명 코미디언 젬 일마즈가 스탠드업 코미디 무대에 올라 50대 이혼남으로서의 삶과 코미디 경력을 되돌아보고, 캔슬 컬처부터 후회하는 문신까지 ​​다양한 주제에 대해 이야기합니다.', 'https://image.tmdb.org/t/p/w500/zN25h6zhlYLEnrCv1Zv3MWjtLoy.jpg', 2025, 0, 0, '2026-06-07 12:17:52.804217', 'US');
INSERT INTO public.movies VALUES (417, 458376, 'ネオ チンピラ 続 鉄砲玉ぴゅ～', '[]', 'Banmei Takahashi', '["Show Aikawa", "Shiori Sakura", "Chikako Aoyama", "Rikiya Yasuoka", "Tatsuo Yamada"]', NULL, 'https://image.tmdb.org/t/p/w500/rNxItOXexbqwpXBSOGbrH6VHsS0.jpg', 1991, 0, 0, '2026-06-06 13:25:11.801273', 'JP');
INSERT INTO public.movies VALUES (412, 637649, '캐시트럭', '["Thriller", "Crime", "Drama"]', NULL, '[]', '캐시트럭을 노리는 무장 강도에 의해 아들을 잃은 H(제이슨 스타뎀). 분노에 휩싸인 그는 아들을 죽인 범인의 단서를 찾기 위해 현금 호송 회사에 위장 취업한다. 첫 임무부터 백발백중 사격 실력을 자랑하며, 단숨에 에이스로 급부상한 H. 캐시트럭을 노리는 자들을 하나 둘 처리하며, 아들을 죽인 범인들과 점점 가까워지는데… 자비는 없다, 분노에 가득 찬 응징만이 남았다.', 'https://image.tmdb.org/t/p/w500/qEkQy6H83Sz7vPWN9ZQXWl9RiBF.jpg', 2021, 0, 0, '2026-06-06 13:25:11.789503', 'US');
INSERT INTO public.movies VALUES (4108, 397567, '신과함께-죄와 벌', '["Action", "Adventure", "Drama", "Fantasy", "Thriller"]', 'Kim Yong-hwa', '["Ha Jung-woo", "Cha Tae-hyun", "Ju Ji-hoon", "Kim Hyang-gi", "Lee Jung-jae"]', '살인, 나태, 거짓, 불의, 배신, 폭력, 천륜 7개의 지옥에서 7번의 재판을 무사히 통과한 망자만이 환생하여 새로운 삶을 시작할 수 있다. 화재 사고 현장에서 여자아이를 구하고 죽음을 맞이한 소방관 자홍, 그의 앞에 저승차사 해원맥과 덕춘이 나타난다. 자신의 죽음이 아직 믿기지도 않는데 덕춘은 정의로운 망자이자 귀인이라며 그를 치켜세운다. 저승으로 가는 입구, 초군문에서 그를 기다리는 또 한 명의 차사 강림, 그는 차사들의 리더이자 앞으로 자홍이 겪어야 할 7개의 재판에서 변호를 맡아줄 변호사이기도 하다. 염라대왕에게 천년 동안 49명의 망자를 환생시키면 자신들 역시 인간으로 환생시켜 주겠다는 약속을 받은 삼차사들, 그들은 자신들이 변호하고 호위해야 하는 48번째 망자이자 19년 만에 나타난 의로운 귀인 자홍의 환생을 확신하지만, 각 지옥에서 자홍의 과거가 하나 둘씩 드러나면서 예상치 못한 고난과 맞닥뜨리는데…', 'https://image.tmdb.org/t/p/w500/z54zrEXAKd5u1SCPNOIAKgvGXte.jpg', 2017, 0, 0, '2026-06-08 06:27:08.26342', 'KR');
INSERT INTO public.movies VALUES (2274, 1556616, 'Yaz Evi', '["Romance", "Family", "Drama", "Mystery"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/kA6e4wmyulZn76xBd5Bq29PZwnb.jpg', 2026, 0, 0, '2026-06-07 12:17:25.166024', 'US');
INSERT INTO public.movies VALUES (410, 1214931, '뉘른베르크', '["History", "Drama"]', 'James Vanderbilt', '["Rami Malek", "Russell Crowe", "Michael Shannon", "Leo Woodall", "John Slattery"]', '전후 독일에서, 한 미국인 정신과 의사는 나치 수감자들이 전쟁 범죄 재판을 받을 수 있는 정신 상태인지 판단해야 하는 임무를 맡게 되고, 히틀러의 오른팔이었던 헤르만 괴링과 지성과 윤리를 둘러싼 복잡한 대결을 벌이게 된다.', 'https://image.tmdb.org/t/p/w500/xthXNYltOOm80vW5Kxjzxx5gvQ6.jpg', 2025, 0, 0, '2026-06-06 13:25:11.784845', 'US');
INSERT INTO public.movies VALUES (2287, 1300501, 'Patriot', '["Action", "Drama", "Thriller"]', 'Mahesh Narayanan', '["Mammootty", "Mohanlal", "Fahadh Faasil", "Kunchacko Boban", "Nayanthara"]', NULL, 'https://image.tmdb.org/t/p/w500/4cK4Js7yg8wL2YeZh7DWuoz1bgZ.jpg', 2026, 0, 0, '2026-06-07 12:17:26.010724', 'IN');
INSERT INTO public.movies VALUES (413, 19173, 'S 중독자의 고백', '["Drama", "Romance"]', NULL, '[]', '사랑... 무엇일까 ? 그녀의 이름 발레리. 아름다운 그녀에게 아직 사랑이라는 것은 서툴고 잡기 힘든 존재이다. 사랑한다고 느꼈지만 만족할 수 없었던 첫 경험, 그리고 다시 찾아간 그의 방에서 찾아낸 특별한 시간. 사랑 보다 몸으로 먼저 느껴지는 감정에 충실해진 발레리는 자신에게 솔직하게 상대를 만나지만 그들은 사랑 없는 섹스에 질려 그녀를 떠나가고 만다. 그리고 우연히 면접에서 그녀에게 찾아 온 사랑. 남들처럼 장미 꽃과 와인, 고백과 근..', 'https://image.tmdb.org/t/p/w500/cRoXNkjFA8f4cP2hTH7H7GcZcTI.jpg', 2008, 0, 0, '2026-06-06 13:25:11.791945', 'US');
INSERT INTO public.movies VALUES (416, 1584215, '인턴십', '["Action"]', 'James Bamford', '["Lizzy Greene", "Megan Boone", "Sky Katz", "Philip Winchester", "Alix Villaret"]', '“배신당한 킬러들의 반란, CIA 내부를 격돌하다”  어린 시절부터 비밀 CIA ‘인턴십’으로 혹독한 훈련을 받아온 여성이 이제 그 프로그램이 자신의 삶을 빼앗아간 진짜 이유를 밝히기 위해 나선다. 그녀는 자신처럼 길러진 동료 인턴들을 모아 조직을 무너뜨리려 하고, 점점 더 치명적인 임무 속에서 배신과 살아남기 위한 본능이 충돌하게 된다. CIA는 이를 막기 위해 더욱 강력한 대응에 나서고, 인턴들과 기관 모두가 최후의 결전을 벌이게 되는데…', 'https://image.tmdb.org/t/p/w500/fYqSOkix4rbDiZW0ACNnvZCpT6X.jpg', 2026, 0, 0, '2026-06-06 13:25:11.798772', 'US');
INSERT INTO public.movies VALUES (414, 1511417, 'Bāhubali: The Epic', '["Action", "Drama"]', 'S. S. Rajamouli', '["Prabhas", "Rana Daggubati", "Anushka Shetty", "Ramya Krishnan", "Sathyaraj"]', NULL, 'https://image.tmdb.org/t/p/w500/4sLSorDKKDN944kWngxgQlpdDeg.jpg', 2025, 0, 0, '2026-06-06 13:25:11.79424', 'IN');
INSERT INTO public.movies VALUES (415, 664413, '365일', '["Romance", "Drama"]', NULL, '[]', '직장에서 성공 가도를 달리지만 연인과의 관계는 열정을 잃은 지 오래인 여자. 생일을 맞아 떠난 여행에서 마피아 보스에게 납치당하며 아찔한 나날이 시작된다. 마음을 얻기 위해 365일 동안 뭐든 하겠다는 이 남자를 믿어도 될까.', 'https://image.tmdb.org/t/p/w500/ibaDBJBAvWd4J5lzfbpq1PJ6ZU1.jpg', 2020, 0, 0, '2026-06-06 13:25:11.796496', 'US');
INSERT INTO public.movies VALUES (316, 150540, '인사이드 아웃', '["Animation", "Family", "Adventure", "Drama", "Comedy"]', 'Pete Docter', '["Amy Poehler", "Phyllis Smith", "Richard Kind", "Bill Hader", "Lewis Black"]', '모든 사람의 머릿속에 존재하는 감정 컨트롤 본부. 그곳에서 불철주야 열심히 일하는 기쁨, 슬픔, 버럭, 까칠, 소심 다섯 감정들. 정든 옛 동네를 떠나 도시로 이사하는 라일리 가족. 이사 후 새로운 환경에 적응해야 하는 라일리를 위해 그 어느 때 보다 바쁘게 감정의 신호를 보내지만 우연한 실수로 기쁨과 슬픔이 본부를 이탈하게 되자 라일리의 마음 속에 큰 변화가 찾아온다. 라일리가 예전의 모습을 되찾기 위해서는 기쁨과 슬픔이 본부로 돌아가야만 한다. 그러나 엄청난 기억들이 저장되어 있는 머릿속 세계에서 본부까지 가는 길은 험난하기만 한데...', 'https://image.tmdb.org/t/p/w500/rMXHvHzpuYZXrJUhRVJ3TvDSwe5.jpg', 2015, 0, 0, '2026-06-06 13:25:07.967608', 'US');
INSERT INTO public.movies VALUES (423, 822119, '캡틴 아메리카: 브레이브 뉴 월드', '["Action", "Thriller", "Sci-Fi"]', 'Julius Onah', '["Anthony Mackie", "Harrison Ford", "Danny Ramirez", "Shira Haas", "Tim Blake Nelson"]', '대통령이 된 새디우스 로스와 재회 후, 국제적인 사건의 중심에 서게 된 샘이 전 세계를 붉게 장악하려는 사악한 음모 뒤에 숨겨진 존재와 이유를 파헤쳐 나가는 액션 블록버스터', 'https://image.tmdb.org/t/p/w500/qj1uEI7zrCWbMppjFZmCXVlWlb1.jpg', 2025, 0, 0, '2026-06-06 13:25:12.528152', 'US');
INSERT INTO public.movies VALUES (430, 857, '라이언 일병 구하기', '["Drama", "History"]', 'Steven Spielberg', '["Tom Hanks", "Tom Sizemore", "Edward Burns", "Barry Pepper", "Adam Goldberg"]', '노르망디 상륙 작전에서 살아남은 존 밀러 미군 대위가 대원들을 이끌고 적진에 침투한다. 그들의 임무는 이 전쟁으로 형제 셋을 모두 잃은 공수부대원을 구출하는 것.', 'https://image.tmdb.org/t/p/w500/9W0XUvNtoJMG6kI4F4Y2mbsS2kt.jpg', 1998, 0, 0, '2026-06-06 13:25:12.544424', 'US');
INSERT INTO public.movies VALUES (424, 1223601, '시수: 복수의 길', '["Action", "Thriller"]', NULL, '[]', '제2차 세계대전이 끝난 직후, 전설적인 핀란드 저격수였던 Aatami Korpi는 고향 집으로 돌아오지만, 가족이 전쟁 중 적군에게 잔인하게 살해된 후다. 그는 집을 해체해 트럭에 싣고 가족을 기리기 위한 새로운 장소에 재건하기로 결심한다. 그런데 가족을 처참히 죽인 소련 붉은 군대 지휘관 Igor Draganov이 그의 뒤를 추적하며, 두 사람 사이에 정면대결과 전국을 가로지르는 추격전이 벌어진다.', 'https://image.tmdb.org/t/p/w500/dONN7cHf2MF1nEZX2THgi89otcj.jpg', 2025, 0, 0, '2026-06-06 13:25:12.530414', 'US');
INSERT INTO public.movies VALUES (426, 1003596, '어벤져스: 둠스데이', '["Sci-Fi", "Action", "Adventure"]', 'Joe Russo', '["Robert Downey Jr.", "Chris Evans", "Chris Hemsworth", "Pedro Pascal", "Paul Rudd"]', NULL, 'https://image.tmdb.org/t/p/w500/qbguX4ENXLoQ0K5cSYLhEItwHib.jpg', 2026, 0, 0, '2026-06-06 13:25:12.534936', 'US');
INSERT INTO public.movies VALUES (428, 1145899, 'Marsupilami', '["Adventure", "Comedy"]', 'Philippe Lacheau', '["Philippe Lacheau", "Jamel Debbouze", "Tarek Boudali", "Élodie Fontan", "Julien Arruti"]', NULL, 'https://image.tmdb.org/t/p/w500/rJNHFa07Id2ylQgw0ttzGwpeczE.jpg', 2026, 0, 0, '2026-06-06 13:25:12.539513', 'FR');
INSERT INTO public.movies VALUES (2908, 630, '오즈의 마법사', '["Adventure", "Fantasy", "Family"]', NULL, '[]', '회오리 바람에 휩쓸려 오즈의 나라로 내던져진 도로시는 집으로 되돌아갈 수 있는 유일한 길이 위대한 오즈의 마법사를 만나는 것임을 알고 그를 찾아 긴 여정이 시작된다. 도로시는 애견 토토와 함께 노란 길을 따라 오즈의 마법사가 사는 에메랄드 시티로 향한다. 도중에 만난 세 명의 친구들, 지능을 얻고자 하는 허수아비와 심장을 원하는 양철 나뭇꾼, 용기를 가지고 싶어하는 겁장이 사자와 함께 오즈의 마법사에게 자신의 소원이 이루어지도록 부탁하기 위해 도로시와 함께 경쾌한 발걸음을 옮긴다. 그러나 도로시 일행을 방해하기 위해 뒤쫓아오는 서쪽 나라 마녀의 검은 그림자.', 'https://image.tmdb.org/t/p/w500/9FzHxca1OybjwOdTmWLfhdD4u0g.jpg', 1939, 0, 0, '2026-06-07 12:17:53.618094', 'US');
INSERT INTO public.movies VALUES (433, 475557, '조커', '["Crime", "Thriller", "Drama"]', NULL, '[]', '홀어머니와 사는 아서 플렉은 코미디언을 꿈꾸지만 그의 삶은 좌절과 절망으로 가득 차 있다. 광대 아르바이트는 그에게 모욕을 가져다주기 일쑤고, 긴장하면 웃음을 통제할 수 없는 신경병 증세는 그를 더욱 고립시킨다. 정부 예산 긴축으로 인해 정신과 약물을 지원하던 공공의료 서비스마저 없어져 버린 어느 날, 아서는 지하철에서 시비를 걸어온 증권사 직원들에게 얻어맞던 와중에 동료가 건네준 권총으로 그들을 쏴 버리고 만다. 군중들은 지배계급에 대한 저항의 아이콘이 된 그를 추종하기 시작하며 광대 마스크로 얼굴을 가리고 거리로 쏟아져 나오기 시작하는데...', 'https://image.tmdb.org/t/p/w500/6OnFzi7nU6t4j1rmX9QI8EYDWb4.jpg', 2019, 0, 0, '2026-06-06 13:25:12.551764', 'US');
INSERT INTO public.movies VALUES (429, 1191876, '잿더미 속에서', '["Drama", "Crime", "Mystery"]', 'Jeremy Wiles', '["Jeanne Neilson", "Paul du Toit", "Syreeta Banks", "Jeremy John Wells", "Lucy Capri"]', '어느 여학교를 휩쓸고 간 처참한 화재. 그 잿더미 속에서 반항과 비난, 충격적인 결말의 이야기가 그 모습을 드러낸다. 실제 사건을 모티브로 한 작품.', 'https://image.tmdb.org/t/p/w500/aEUH2ECoZHvSmoMzJpca0STF2CZ.jpg', 2027, 0, 0, '2026-06-06 13:25:12.542033', 'US');
INSERT INTO public.movies VALUES (434, 843527, '너란 개념', '["Comedy", "Romance", "Drama"]', NULL, '[]', '세상에서 가장 섹시한 보이밴드 어거스트 문의 리드 싱어인 24세 헤이스 캠벨(니컬러스 갈리친)과 40세 싱글 맘 솔렌(앤 해서웨이)이 펼치는 뜻밖의 로맨스에 관한 이야기', 'https://image.tmdb.org/t/p/w500/6x9gZWCqEGYObUCJPjTKFT2LNqA.jpg', 2024, 0, 0, '2026-06-06 13:25:12.55429', 'US');
INSERT INTO public.movies VALUES (432, 1137129, 'O Cavalo de Pedro', '[]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/shwAnEF5cUHFhu2uM4x0SkWmK1T.jpg', 2023, 0, 0, '2026-06-06 13:25:12.549304', 'US');
INSERT INTO public.movies VALUES (425, 145341, 'Pułkownik Kwiatkowski', '["Comedy", "History"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/q6Jb1IdOJ8k7QO9vk3tJkaMGyIF.jpg', 1996, 0, 0, '2026-06-06 13:25:12.532684', 'US');
INSERT INTO public.movies VALUES (2910, 1233506, 'L''Homme qui rétrécit', '["Adventure", "Sci-Fi"]', 'Jan Kounen', '["Jean Dujardin", "Marie-Josée Croze", "Daphné Richard", "Serge Swysen", "Salim Talbi"]', NULL, 'https://image.tmdb.org/t/p/w500/xfkQnNFPFP5ITUQ1rCt6rYtnzLH.jpg', 2025, 0, 0, '2026-06-07 12:17:53.623332', 'FR');
INSERT INTO public.movies VALUES (447, 38757, '라푼젤', '["Animation", "Family", "Adventure"]', 'Nathan Greno', '["Mandy Moore", "Zachary Levi", "Donna Murphy", "Ron Perlman", "M.C. Gainey"]', '장장 18년을 탑 안에서만 지낸 끈기 만점의 소녀 라푼젤. 어느 날 자신의 탑에 침입한 왕국 최고의 대도를 한 방에 때려잡고, 그를 협박해 꿈에도 그리던 집 밖으로의 모험을 단행한다. 과잉보호 모친의 영향으로 세상을 험난한 곳으로만 상상하던 라푼젤 앞에 왕실 경비마 맥시머스의 추격, 라이더에게 복수의 칼날을 가는 스태빙턴 형제의 위협, 라푼젤의 가짜 엄마 고델의 무서운 음모 등이 얽혀 점점 흥미진진한 사건들이 터지기 시작한다. 그러나 세상물정 모르는 라푼젤은 자신 앞에 펼쳐진 스릴 넘치는 세상을 맘껏 즐기는데...', 'https://image.tmdb.org/t/p/w500/sT1vLH38iaezVgoFqmaiihbnTUy.jpg', 2010, 0, 0, '2026-06-06 13:25:13.305171', 'US');
INSERT INTO public.movies VALUES (438, 1125257, '프리키 프라이데이 2', '["Comedy", "Fantasy", "Family"]', NULL, '[]', '엄마 테스와 딸 애나가 서로 몸이 바뀌는 대환장 바디 체인지를 겪은 지도 어느덧 22년이 흐른 지금. 성공한 심리학자로서 첫 책 출간을 앞두고 책 사인회를 준비 중인 테스. 팝스타 매니저이자 싱글맘인 애나는 스타 셰프 에릭과 결혼을 앞두고 있지만, 애나의 딸 하퍼와 에릭의 딸 릴리는 이들의 결혼을 극구 반대한다. 한편, 진정한 하나의 가족이 되기 위해 한 지붕 아래 낯선 동거가 시작되고, 크고 작은 갈등이 이어지는 와중 설상가상 네 명의 몸이 모두 뒤바뀌며 혼란스러운 시간을 보내게 되는데… 과연 이들은 이번에도 무사히 돌아올 수 있을까?', 'https://image.tmdb.org/t/p/w500/dQtLQIv1GK92uPLx8HzhdleX9XI.jpg', 2025, 0, 0, '2026-06-06 13:25:12.564271', 'US');
INSERT INTO public.movies VALUES (437, 1083637, 'ಕಾಂತಾರ: ಅಧ್ಯಾಯ - ೧', '["Action", "Drama", "Fantasy"]', 'Rishab Shetty', '["Rishab Shetty", "Rukmini Vasanth", "Jayaram", "Gulshan Devaiah", "Ramitha Shailendra"]', NULL, 'https://image.tmdb.org/t/p/w500/ehQPboTPaIMkMUOoNOh8e7pZ5Rp.jpg', 2025, 0, 0, '2026-06-06 13:25:12.561781', 'IN');
INSERT INTO public.movies VALUES (2909, 1472638, '산티아고의 철부지 아빠', '["Comedy", "Family", "Adventure"]', NULL, '[]', '아버지라는 역할이 어색했던 남자. 실종된 딸을 찾아 산티아고 순례길에 오른 그는 앞으로 한 걸음씩 내디디며 진짜 아버지가 되어 간다.', 'https://image.tmdb.org/t/p/w500/jUiGMecwhYLOwJJqVl1YovRMAFa.jpg', 2025, 0, 0, '2026-06-07 12:17:53.62092', 'US');
INSERT INTO public.movies VALUES (2911, 423108, '컨저링 3: 악마가 시켰다', '["Horror", "Mystery", "Thriller"]', NULL, '[]', '1981년, 미국 역사상 최초로 잔혹한 살인사건의 용의자가 악마가 살해하도록 시켰다고 주장하는 초유의 사태가 일어난다. 그리고 사건의 배후에는 악마에게 빙의된 소년이 있다. 살인사건의 범인은 인간인가 악마인가…', 'https://image.tmdb.org/t/p/w500/yxPlLa5p54Wk1o2koiW4hqn4wfG.jpg', 2021, 0, 0, '2026-06-07 12:17:53.625796', 'US');
INSERT INTO public.movies VALUES (4113, 1354959, '내 남편을 세워줘!', '["Drama"]', '모니카', '["Ha Yool", "Gil Dong", "Shine", "Min Do-yoon"]', NULL, 'https://image.tmdb.org/t/p/w500/6GzBmkYRMirSjXyBv3tmB5WcTrh.jpg', 2024, 0, 0, '2026-06-08 06:27:12.385362', 'KR');
INSERT INTO public.movies VALUES (2305, 77338, '언터처블: 1%의 우정', '["Drama", "Comedy"]', 'Éric Toledano', '["François Cluzet", "Omar Sy", "Anne Le Ny", "Audrey Fleurot", "Joséphine de Meaux"]', '상위 1% 귀족남과 하위 1% 무일푼이 만났다.  2주간의 내기로 시작된 상상초월 특별한 동거 스토리  하루 24시간 내내 돌봐주는 손길이 없으면 아무 것도 할 수 없는 전신불구의 상위 1% 백만장자 필립(프랑수아 클루제). 어느 날 우연히, 가진 것이라곤 건강한 신체가 전부인 하위 1% 무일푼 백수 드리스(오마 사이)를 만나게 된 그는 거침없이 자유로운 성격의 드리스에게 호기심을 느껴 특별한 내기를 제안한다. 바로 2주 동안 필립의 손발이 되어 한시도 떨어지지 않고 자신을 간호하며 버틸 수 있는지 시험해보겠다는 것. 참을성이라곤 눈꼽 만큼도 찾아 볼 수 없던 드리스는 오기가 발동해 엉겁결에 내기를 수락한다. 이렇게, 전혀 어울릴 것 같지 않던 극과 극, 두 남자의 예측불허 기막힌 동거가 시작 되는데…', 'https://image.tmdb.org/t/p/w500/4oOf3pmDD5rMNQGgsf7zMbFKtKC.jpg', 2011, 0, 0, '2026-06-07 12:17:26.85874', 'FR');
INSERT INTO public.movies VALUES (398, 767, '해리 포터와 혼혈왕자', '["Adventure", "Fantasy"]', 'David Yates', '["Daniel Radcliffe", "Rupert Grint", "Emma Watson", "Jim Broadbent", "Michael Gambon"]', '어둠의 세력이 더욱 강력해져 머글 세계와 호그와트까지 위협해온다. 위험한 기운을 감지한 덤블도어 교수는 다가올 전투에 대비하기 위해 해리 포터와 함께 대장정의 길을 나선다. 볼드모트를 물리칠 수 있는 유일한 단서이자 그의 영혼을 나누어 놓은 7개의 호크룩스를 파괴하는 미션을 수행해야만 하는 것! 또한 덤블도어 교수는 호크룩스를 찾는 기억여행에 결정적 도움을 줄 슬러그혼 교수를 호그와트로 초청한다. 한편 학교에서는 계속된 수업과 함께 로맨스의 기운도 무르익는다. 해리는 자신도 모르게 지니에게 점점 끌리게 되고, 새로운 여자 친구가 생긴 론에게 헤르미온느는 묘한 질투심을 느끼는데...', 'https://image.tmdb.org/t/p/w500/yrGlb3HLtjGp39mv4MJ5UuIHcj4.jpg', 2009, 0, 0, '2026-06-06 13:25:11.048744', 'GB');
INSERT INTO public.movies VALUES (446, 20453, '세 얼간이', '["Drama", "Comedy"]', 'Rajkumar Hirani', '["Aamir Khan", "R. Madhavan", "Sharman Joshi", "Kareena Kapoor Khan", "Boman Irani"]', '천재들만 간다는 일류 명문대 ICE, 성적과 취업만을 강요하는 학교를 발칵 뒤집어 놓은 대단한 녀석 란초! 아버지가 정해준 꿈, ‘공학자’가 되기 위해 정작 본인이 좋아하는 일은 포기하고 공부만 하는 파파보이 파르한! 찢어지게 가난한 집, 병든 아버지와 식구들을 책임지기 위해 무조건 대기업에 취직해야만 하는 라주! 친구의 이름으로 뭉친 ‘세 얼간이’! 삐딱한 천재들의 진정한 꿈을 찾기 위한 세상 뒤집기 한판이 시작된다!', 'https://image.tmdb.org/t/p/w500/9zQdFVyDoXqFmGYXp4obna6FEMh.jpg', 2009, 0, 0, '2026-06-06 13:25:13.302693', 'IN');
INSERT INTO public.movies VALUES (439, 11036, '노트북', '["Romance", "Drama"]', 'Nick Cassavetes', '["Ryan Gosling", "Rachel McAdams", "Gena Rowlands", "James Garner", "Joan Allen"]', '17살, 노아는 밝고 순수한 앨리를 보고 첫눈에 반한다. 빠른 속도로 서로에게 빠져드는 둘. 그러나 이들 앞에 놓인 장벽에 막혀 이별하게 된다. 24살, 앨리는 우연히 신문에서 노아의 소식을 접하고 잊을 수 없는 첫사랑 앞에서 다시 한 번 선택의 기로에 서게 되는데…', 'https://image.tmdb.org/t/p/w500/ntdgcdsmMuHd9s4oEKTvWDiUyU7.jpg', 2004, 0, 0, '2026-06-06 13:25:12.56679', 'US');
INSERT INTO public.movies VALUES (451, 567609, '레디 오어 낫', '["Horror", "Comedy"]', 'Matt Bettinelli-Olpin', '["Samara Weaving", "Adam Brody", "Mark O''Brien", "Henry Czerny", "Andie MacDowell"]', '한 젊은 신부(사마라 위빙 역)가 부자이며 기이한 가족을 가진 남편(마크 오브라이언 역)과 결혼을 하는데 이 가족의 일원이 되려면 결혼식 날 밤에 끔찍한 게임을 해야 하는 전통이 있다. 어쩔 수 없이 게임을 하게 된 신부의 첫날밤은 생존을 위해 싸워야 하는 불길한 죽음의 게임으로 변하는데...', 'https://image.tmdb.org/t/p/w500/fIpXKQecVTp7veBSm6IXZSe0wzb.jpg', 2019, 0, 0, '2026-06-06 13:25:13.314954', 'US');
INSERT INTO public.movies VALUES (453, 271110, '캡틴 아메리카: 시빌 워', '["Adventure", "Action", "Sci-Fi"]', 'Joe Russo', '["Chris Evans", "Robert Downey Jr.", "Scarlett Johansson", "Sebastian Stan", "Anthony Mackie"]', '어벤져스가 벌인 전투로 많은 사람들이 불의의 사고를 당하는 등 부수적인 피해가 일어나자 정부는 슈퍼히어로 등록제를 추진하려 한다. 어벤져스의 독자적인 판단에 맡기기보다 직접 관리, 감독하겠다는 게 정부의 속내. 아이언맨은 정부의 방침을 따라야 한다는 입장인 반면, 캡틴 아메리카는 정부의 감시 없이 자유롭게 지구를 지켜야 한다고 주장한다. 어벤져스 내부는 캡틴 아메리카(윈터 솔져, 팔콘, 호크아이, 스칼렛 위치, 앤트맨)와 아이언맨(블랙위도우, 워머신, 블랙 팬서, 비전, 스파이더맨) 두 입장으로 나뉘어 대립하게 되는데...', 'https://image.tmdb.org/t/p/w500/vaMRzME3Dt73robEjOtDw4SPJGA.jpg', 2016, 0, 0, '2026-06-06 13:25:13.319478', 'US');
INSERT INTO public.movies VALUES (456, 109445, '겨울왕국', '["Animation", "Family", "Adventure", "Fantasy"]', 'Jennifer Lee', '["Idina Menzel", "Kristen Bell", "Jonathan Groff", "Josh Gad", "Livvy Stubenrauch"]', '서로가 최고의 친구였던 자매 엘사와 안나. 하지만 언니 엘사에게는 하나뿐인 동생에게조차 말 못할 비밀이 있다. 모든 것을 얼려버리는 신비로운 힘이 바로 그 것. 엘사는 통제할 수 없는 자신의 힘이 두려워 왕국을 떠나 북쪽 산으로 도망치고, 홀로 그곳에서 얼음 궁전을 지어 지내게 된다. 한편 얼어버린 왕국의 저주를 풀기 위해 안나는 언니를 찾아 나서고, 그 과정에서 안나는 까칠한 매력의 얼음장수 크리스토프와 만나 영원히 얼어붙은 왕국을 구해내기 위해 함께 고군분투한다.', 'https://image.tmdb.org/t/p/w500/lYceQKe3EsYn7VdDXGTy7dSwBLp.jpg', 2013, 0, 0, '2026-06-06 13:25:13.327325', 'US');
INSERT INTO public.movies VALUES (454, 1173559, 'Insidious Inferno', '["Horror"]', 'Calvin Morie McCarthy', '["Stephanie Leet", "Neil Green", "Chynna Rae Shurts", "Steve Larkin", "Erik Skybak"]', NULL, 'https://image.tmdb.org/t/p/w500/8kljUAovBatZRYp2ye2RZr239hU.jpg', 2024, 0, 0, '2026-06-06 13:25:13.321992', 'US');
INSERT INTO public.movies VALUES (449, 1688163, 'Hayok', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/i4FFY9mskUpJLnLXQwZSTn3f1Ek.jpg', 2026, 0, 0, '2026-06-06 13:25:13.310079', 'US');
INSERT INTO public.movies VALUES (452, 519465, '퀸 오브 하츠', '["Drama"]', NULL, '[]', '청소년 전문 변호사로 쌍둥이 딸들과 의사 남편과 함께 행복한 삶을 살고 있었던 안느. 남편과 전부인 사이에서 낳은 아들 구스타브가 사고를 치고 집에 들어오면서 다섯 식구는 함께 살아가게 된다. 남들이 보기에 완벽한 삶을 살고 있었지만 안느는 중년의 위기를 겪고 있었고 구스타브는 계속 사고를 쳐 안느를 힘들게 한다. 그러던 중 구스타브가 여자 친구를 집으로 데려와 관계를 맺게 되고 안느는 알 수 없는 감정을 느끼게 된다. 안느의 외로움을 눈치 챈 구스타브가 안느에게 다가오고 그렇게 안느와 구스타브는 가까워진다. 약속이나 한 듯 안느와 구스타브는 하룻밤을 보내게 되고 그렇게 위험한 관계가 시작되는데...', 'https://image.tmdb.org/t/p/w500/rjLi95uydrVInjWD0bJIqsgvb3A.jpg', 2019, 0, 0, '2026-06-06 13:25:13.317204', 'US');
INSERT INTO public.movies VALUES (563, 940551, '인투 더 월드', '["Family", "Comedy", "Adventure", "Animation"]', NULL, '[]', '가족을 과잉보호하는 아빠 ‘맥’ 때문에 평생을 작은 연못에서 안전하게 살아온 말러드 가족. 하지만 호기심 가득한 남매 ‘댁스’와 ‘그웬’을 위해 새로운 세상을 모험하고 싶은 엄마 ‘팸’의 설득으로 가족들은 항상 꿈꿔온 자메이카로 생애 첫 가족 모험을 떠나기로 한다! 설렘 넘치는 시작과 달리 태풍을 만나 길을 잃고, 낯선 친구들을 만나고, 위험 가득한 뉴욕에 불시착하게 된다. 인생 처음으로 모든 계획이 틀어지고 위기에 빠진 말러드 가족은 서툴지만 서로를 의지하며 모험을 계속한다. 새로운 세상, 함께라면 두려울 것 없어!', 'https://image.tmdb.org/t/p/w500/2xE3NI6zElWhwN9WJ92fqbZKmzZ.jpg', 2023, 0, 0, '2026-06-06 13:25:17.977116', 'US');
INSERT INTO public.movies VALUES (3576, 273248, '헤이트풀8', '["Drama", "Mystery"]', NULL, '[]', '레드 락 타운으로 죄수를 이송해가던 교수형 집행인은 설원 속에서 우연히 현상금 사냥꾼, 보안관과 합류하게 된다. 거센 눈보라를 피해 산장으로 들어선 4명은 그곳에 먼저 와있던 또 다른 4명, 연합군 장교, 이방인, 리틀맨, 카우보이를 만나게 된다. 큰 현상금이 걸린 죄수를 호시탐탐 노리는 이들에게 교수형 집행인은 경고를 하지만, 이를 비웃기라도 하듯 참혹한 독살 사건이 일어난다. 각자 숨겨둔 비밀이 하나씩 밝혀지면서 서로를 향한 불신은 커져만 가고, 팽팽한 긴장감 속에 증오의 밤은 점점 깊어지는데...', 'https://image.tmdb.org/t/p/w500/CJ1Swrno8D9ykFYtqL7bNkS73d.jpg', 2015, 0, 0, '2026-06-08 06:24:24.276036', 'US');
INSERT INTO public.movies VALUES (4116, 698779, '룸싸롱 여대생들 3', '["Romance", "Action"]', 'Lee Min-woo', '["Kim Ji-ah", "Jin Yi", "Hae Il", "Min Do-yoon", "Kang Min-woo"]', NULL, 'https://image.tmdb.org/t/p/w500/efzmOJME5zbmXsgLCjCINm1e7X2.jpg', 2020, 0, 0, '2026-06-08 06:27:15.289388', 'KR');
INSERT INTO public.movies VALUES (345, 177572, '빅 히어로', '["Adventure", "Family", "Animation", "Action", "Comedy"]', 'Chris Williams', '["Scott Adsit", "Ryan Potter", "Daniel Henney", "T.J. Miller", "Jamie Chung"]', '천재 공학도 ‘테디’가 개발한 힐링로봇 ‘베이맥스’! ‘테디’의 동생이자 로봇 전문가인 ‘히로’는 도시가 파괴될 위기에 처하자 ‘베이맥스’를 슈퍼히어로로 업그레이드 하는데... 과연 이들은 도시의 위험을 막아낼 수 있을까?', 'https://image.tmdb.org/t/p/w500/gLabmTVZpNOGa8LEiMvTi9hJPDe.jpg', 2014, 0, 0, '2026-06-06 13:25:09.454409', 'US');
INSERT INTO public.movies VALUES (464, 696393, '콜드 스토리지', '["Horror", "Sci-Fi", "Comedy"]', NULL, '[]', '"최악의 야간 근무, 봉인된 재앙이 깨어난다"  옛 미군 기지 위에 세워진 개인 창고 시설에서 야간 근무를 하던 트래비스와 나오미는 정체를 알 수 없는 이상 징후와 마주한다. 오래전 비밀리에 봉인된 지하 시설에서 변이와 확산을 거듭하는 치명적인 균류가 깨어나고, 평범한 두 직원은 과거 그 위협을 상대했던 노련한 생물테러 요원과 함께 단 하룻밤 안에 재앙의 확산을 막아야 하는 상황에 내몰린다. 보이지 않는 공포가 폐쇄된 공간을 잠식해 갈수록, 그들은 인류의 운명을 건 사투에 휘말리게 되는데…', 'https://image.tmdb.org/t/p/w500/3HA2iiq982e01EKXJvPFyfMADVM.jpg', 2026, 0, 0, '2026-06-06 13:25:14.07652', 'US');
INSERT INTO public.movies VALUES (461, 572802, '아쿠아맨과 로스트 킹덤', '["Action", "Adventure", "Fantasy"]', NULL, '[]', '아틀란티스 왕국을 이끌 왕의 자리에 오른 아쿠아맨. 그 앞에 블랙 만타가 세상을 뒤흔들 강력한 지배 아이템 블랙 트라이던트를 손에 넣게 된다. 그동안 겪지 못 했던 최악의 위협 속 아쿠아맨은 블랙 만타와 손을 잡았던 이복 동생 옴 없이는 절대적 힘이 부족한 상황. 바다를 지배할 슈퍼 히어로가 세상의 판도를 바꾼다!', 'https://image.tmdb.org/t/p/w500/eDps1ZhI8IOlbEC7nFg6eTk4jnb.jpg', 2023, 0, 0, '2026-06-06 13:25:14.068219', 'US');
INSERT INTO public.movies VALUES (466, 11013, '세크리터리', '["Romance", "Drama", "Comedy"]', NULL, '[]', '사랑에도 액션(?)이 필요한 법, 그녀는 온몸으로 타이핑을 한다!그녀의 취미가 수상하다…리 할로웨이는 겉으론 봐선 그냥 평범한 이십대 여성. 하지만 이 조용한 아가씨에겐 비밀이 하나 있다. 자신의 몸에 생채기를 내야만 위로를 받는 오랜 습관이 있는 것. 잠시 요양원에서 지낸 리는 다시 가족의 품으로 돌아온다. 하지만 그녀의 일상은 여전히 무료하고 우울하다. 이웃에 사는 고등학교 동창인 피터와의 데이트도 시큰둥할 뿐…엉덩이에 찰싹~', 'https://image.tmdb.org/t/p/w500/sHoSvGWwbdFcF29vskvv2XvYgEk.jpg', 2002, 0, 0, '2026-06-06 13:25:14.081313', 'US');
INSERT INTO public.movies VALUES (467, 1072790, '페이크 러브', '["Romance", "Comedy"]', NULL, '[]', '누가 봐도 완벽해 보이는 커플인 비와 벤. 하지만 황홀했던 첫 데이트는 예상치 못한 오해로 꼬일 대로 꼬여버리고, 우연히 같은 결혼식에 초대받은 둘은 자신들을 엮어주려는 주위 사람들의 성화에 못 이겨 서로에게 빠진 척 진짜 같은 가짜 연애를 하기 시작한다.', 'https://image.tmdb.org/t/p/w500/5qHoazZiaLe7oFBok7XlUhg96f2.jpg', 2023, 0, 0, '2026-06-06 13:25:14.084054', 'US');
INSERT INTO public.movies VALUES (465, 1891, '스타워즈 에피소드 5: 제국의 역습', '["Adventure", "Action", "Sci-Fi"]', NULL, '[]', '제국군은 데스스타를 잃은 뒤에도 여전히 강력한 화력으로 반란군을 수세로 몰아넣었고, 반란군은 게릴라전을 위해 얼음으로 뒤덮인 행성 호스에 은신한다. 하지만 결국 제국군에 의해 호스의 반란군 기지마저 탄로나게 되고, 일행은 필사적으로 호스를 탈출해 다시 정처없는 피난길에 오른다. 반란군의 피난길에 함께 오르던 루크는 포스의 영이 된 오비완으로부터 제다이 마스터 요다를 찾아가라는 메시지를 받고 요다가 있는 정글 행성 대고바로 향한다. 루크는 요다를 만나 제다이가 되기 위한 훈련을 시작하고 솔로 일행은 제국군을 따돌리기 위해 옛 친구 랜도를 찾아가는데...', 'https://image.tmdb.org/t/p/w500/icaO5w8uLVm4JxMew71JJrQE2YX.jpg', 1980, 0, 0, '2026-06-06 13:25:14.078819', 'US');
INSERT INTO public.movies VALUES (460, 447365, '가디언즈 오브 갤럭시 Vol. 3', '["Sci-Fi", "Adventure", "Action"]', 'James Gunn', '["Chris Pratt", "Zoe Saldaña", "Dave Bautista", "Karen Gillan", "Pom Klementieff"]', '가모라를 잃고 슬픔에 빠져 있던 피터 퀼이 위기에 처한 은하계와 동료를 지키기 위해 다시 한 번 가디언즈 팀과 힘을 모으고, 성공하지 못할 경우 그들의 마지막이 될지도 모르는 미션에 나서는 이야기.', 'https://image.tmdb.org/t/p/w500/zK0FTsXvkWVS3yubZkbenbAFcnY.jpg', 2023, 0, 0, '2026-06-06 13:25:13.342048', 'US');
INSERT INTO public.movies VALUES (463, 1692948, 'ਚੜਦੀਕਲਾ', '["Drama", "History"]', 'Amarjit Singh Saron', '["Ammy Virk", "Roopi Gill", "Jarnail Singh", "Naiqra Dhillon", "Amiek Virk"]', NULL, 'https://image.tmdb.org/t/p/w500/haTgVHRQ1pfCwIiU8MDI2qt30HV.jpg', 2026, 0, 0, '2026-06-06 13:25:14.074209', 'IN');
INSERT INTO public.movies VALUES (4336, 719825, '외도2', '["Drama", "Romance"]', 'Choi Woo-seong', '["Lee Eun-mi", "Yoo Sul-young", "Jung In", "Lee Kang-woo", "Ah Ri"]', NULL, 'https://image.tmdb.org/t/p/w500/zaUtuEaCmgWjJkCOP8Ne7Lsq7Ru.jpg', 2020, 0, 0, '2026-06-08 06:30:25.467806', 'KR');
INSERT INTO public.movies VALUES (479, 812583, '나이브스 아웃: 웨이크 업 데드 맨', '["Thriller", "Mystery", "Comedy"]', 'Rian Johnson', '["Daniel Craig", "Josh O''Connor", "Glenn Close", "Josh Brolin", "Mila Kunis"]', '브누아 블랑이 탐정 인생을 통틀어 가장 위험한 사건으로 돌아온다.어두운 과거를 지닌 작은 마을의 성당. 그곳에서 불가사의한 범죄가 발생한다. 그러자 브누아 블랑 탐정이 신실한 젊은 신부와 함께 수사에 나선다.', 'https://image.tmdb.org/t/p/w500/qFXkslzkBIihZnwyYal9WnQ9OTe.jpg', 2025, 0, 0, '2026-06-06 13:25:14.111628', 'US');
INSERT INTO public.movies VALUES (2917, 524434, '이터널스', '["Sci-Fi", "Action", "Adventure"]', NULL, '[]', '이터널스는 7천년 전 우주선 도모를 타고 지구에 온 순간부터 지구를 사랑한 히어로들이다. 이들의 임무는 기괴한 크리처 데비안츠에게서 인간을 지키는 것. 임무를 부여한 이는 그들을 탄생시킨 천상의 존재 셀레스티얼이다. 이터널스는 시간의 흐름을 느낄 수 없기에, 공간을 기준 삼아 연대기를 구성하는 뱀파이어처럼 세계 곳곳에 흩어져 자신만의 삶을 살아가고 있다. 물질을 변화시키는 세르시는 런던에서 박물관 학자가 됐고, 우주의 기운을 총처럼 쏘는 킹고는 발리우드 배우로 살며, 타인을 조종하는 드루이그는 아마존에 소국을 만들었다. 괴력의 소유자 길가메시는 호주 사막에서 정신 건강이 위험해진 테나를 돌보며 살고 있다. 세르시는 데비안츠의 공세가 심해지자 오랜 연인 이카리스, 소녀처럼 보이는 불멸의 존재 스프라이트와 함께 이터널스를 불러모으기 시작한다.', 'https://image.tmdb.org/t/p/w500/aNtAP8ZzUMdnCPoqYgVOcgI0Eh4.jpg', 2021, 0, 0, '2026-06-07 12:17:53.641076', 'US');
INSERT INTO public.movies VALUES (4185, 1137179, '야당', '["Crime", "Action", "Comedy", "Drama", "Thriller"]', 'Hwang Byeong-gug', '["Kang Ha-neul", "Yoo Hai-jin", "Park Hae-joon", "Ryu Kyung-soo", "Chae Won-been"]', '누명을 쓰고 교도소에 수감된 이강수는 검사 구관희로부터 감형을 조건으로 야당을 제안받는다. 강수는 관희의 야당이 돼 마약 수사를 뒤흔들기 시작하고, 출세에 대한 야심이 가득한 관희는 굵직한 실적을 올려 탄탄대로의 승진을 거듭한다.  한편, 마약수사대 형사 오상재는 수사 과정에서 강수의 야당질로 번번이 허탕을 치고, 끈질긴 집념으로 강수와 관희의 관계를 파고든다.  마약판을 설계하는 브로커 강수, 더 높은 곳에 오르려는 관희, 마약 범죄 소탕에 모든 것을 건 상재. 세 사람은 각자 다른 이해관계로 얽히기 시작하는데…', 'https://image.tmdb.org/t/p/w500/k4yTwFqvQDApqaoFdgubsbYcuno.jpg', 2025, 0, 0, '2026-06-08 06:28:09.7859', 'KR');
INSERT INTO public.movies VALUES (476, 1290417, '스래시: 상어의 습격', '["Horror", "Thriller"]', NULL, '[]', '치명적인 허리케인으로 폐허가 된 해안가 마을. 모두가 혼돈과 절망에 빠진 지금, 홍수로 인해 물에 잠긴 마을에 굶주린 상어떼의 습격이 시작된다.', 'https://image.tmdb.org/t/p/w500/8HjP0vqOk1FIxoN96ciRnOcmGu4.jpg', 2026, 0, 0, '2026-06-06 13:25:14.10495', 'US');
INSERT INTO public.movies VALUES (473, 539972, '크레이븐 더 헌터', '["Action", "Adventure", "Thriller"]', NULL, '[]', '죽음의 문턱에서 맹수의 초인적인 힘을 얻고 살아 돌아온 크레이븐이 무자비한 복수의 길을 택하며 거침없는 사냥을 펼치는 액션 블록버스터', 'https://image.tmdb.org/t/p/w500/gYOhHBHSqb3J0QaZWlKYDbpxY7Y.jpg', 2024, 0, 0, '2026-06-06 13:25:14.098266', 'US');
INSERT INTO public.movies VALUES (359, 198663, '메이즈 러너', '["Action", "Mystery", "Sci-Fi", "Thriller"]', 'Wes Ball', '["Dylan O''Brien", "Kaya Scodelario", "Thomas Brodie-Sangster", "Ki Hong Lee", "Will Poulter"]', '삭제된 기억, 거대한 미로로 둘러싸인 낯선 공간  모든 기억이 삭제된 채 의문의 장소로 보내진 토마스. 토마스는 미로에 갇힌 그곳에서 자신과 같은 상황의 사람들을 만난다. 그들은 매일 밤 살아 움직이는 미로에서 정체를 알 수 없는 죽음의 존재와 대립하며, 지옥으로부터 빠져나갈 탈출구인 지도를 완성해 나간다. 그러던 어느 날, 미로의 문이 열리고 그들은 마지막 선택의 기로에 놓이게 되는데…', 'https://image.tmdb.org/t/p/w500/bL0bBepUCLFcCj2ATFD40FbyDEl.jpg', 2014, 0, 0, '2026-06-06 13:25:09.488823', 'US');
INSERT INTO public.movies VALUES (472, 73861, '세르비안 필름', '["Crime", "Horror", "Thriller"]', NULL, '[]', '한물간 포르노 스타 밀로스는 큰 돈을 벌기 위해 ‘예술적’포르노 영화 출연제의를 받아들인다. 하지만 영화촬영장 분위기와 내용이 심상치 않음을 느끼고 촬영장에서 자리를 박차고 나오지만, 차를 타고 집으로 가던 중 기억을 잃게 되고 잃어버린 사흘간의 충격적인 행적을 찾아가는데...', 'https://image.tmdb.org/t/p/w500/qT312t40YmlOSsOXOoOLDCvRbPx.jpg', 2010, 0, 0, '2026-06-06 13:25:14.096057', 'US');
INSERT INTO public.movies VALUES (478, 791373, '잭 스나이더의 저스티스 리그', '["Action", "Adventure", "Fantasy"]', NULL, '[]', '슈퍼맨이 죽고 지구에 어둠의 그림자가 드리운다. 마더박스를 차지하기 위해 빌런 스테픈울프가 파라데몬 군단을 이끌고 지구에 온 것이다. 지구를 지키기 위해 목숨을 바친 슈퍼맨의 희생이 헛되지 않도록 하기 위해 브루스 웨인은 다이애나 프린스와 적에 맞서기로 한다. 배트맨과 원더 우먼은 새로이 등장한 위협에 맞서 싸우기 위해 특별한 능력을 가진 메타휴먼, 아쿠아맨과 사이보그, 플래시를 찾아가 설득하여 힘을 합친다. 드디어 한 팀이 된 저스티스 리그. 혹시 스테픈울프와 데사드 그리고 다크사이드를 물리치기에 너무 늦어버린 것이 아닐까?', 'https://image.tmdb.org/t/p/w500/qd7iPB26bwMPZqRcnflzAeDkMn.jpg', 2021, 0, 0, '2026-06-06 13:25:14.109372', 'US');
INSERT INTO public.movies VALUES (491, 1175942, '배드 가이즈 2', '["Family", "Comedy", "Crime", "Adventure", "Animation"]', 'Pierre Perifel', '["Sam Rockwell", "Marc Maron", "Awkwafina", "Craig Robinson", "Anthony Ramos"]', '착하게 살기 위해 무지하게 애쓰는 자타공인 최고의 나쁜 녀석들이 새롭게 등장한 ''배드 걸즈''로 인해 일생일대의 글로벌 범죄 작전에 휘말리며 벌어지는 범죄오락액션 블록버스터', 'https://image.tmdb.org/t/p/w500/1oG69MtmZGovhho0pPgRY9d1qrU.jpg', 2025, 0, 0, '2026-06-06 13:25:14.881361', 'US');
INSERT INTO public.movies VALUES (2923, 508642, '곤지암', '["Horror", "Mystery"]', 'Jung Bum-shik', '["Wi Ha-jun", "Park Ji-hyun", "Oh Ah-yeon", "Moon Ye-won", "Park Sung-hoon"]', '1979년 환자 42명의 집단 자살과 병원장의 실종 이후, 섬뜩한 괴담으로 둘러싸인 곤지암 정신병원으로 공포체험을 떠난 7명의 멤버들. 원장실, 집단 치료실, 실험실, 열리지 않는 402호. 괴담의 실체를 담아내기 위해 병원 내부를 촬영하기 시작하던 멤버들에게 상상도 못한 기이하고 공포스러운 일들이 실제로 벌어지기 시작 하는데…', 'https://image.tmdb.org/t/p/w500/llj8dIkLSHOG1X7aFXims2IaCU5.jpg', 2018, 0, 0, '2026-06-07 12:17:54.45783', 'KR');
INSERT INTO public.movies VALUES (4118, 447759, '청불학원', '["Comedy", "Drama", "Romance"]', 'Choi Moo-yeon', '["Kim Min-soo", "Yoo Ji-won", "Oh Joo-ha", "Jo Wan-jin", "Jeong Ho-yoon"]', '소심한 재수생, 하지만 전설적인 물건(?)을 가진 남자!  치수는 동년배 친구들에게 괴롭힘을 당하는 등 소심함으로 똘똘 뭉친 재수생이다. 하지만 그에게는 소문만 무성한 신체적 비밀이 있었으니… 바로 말로만 전해져 왔던 상상을 초월한 대물(?)을 소유자라는 사실. 치수에 대한 소문이 퍼지면서 모든 여자들은 그를 갈망하게 되고, 자신의 장점을 깨닫게 된 치수는 자신을 괴롭힌 친구들의 주변 여자들을 정복하며 복수를 시작하는데…', 'https://image.tmdb.org/t/p/w500/5XR1lyewXl4U4VoVTi4Mgn0bmiF.jpg', 2017, 0, 0, '2026-06-08 06:27:17.655832', 'KR');
INSERT INTO public.movies VALUES (486, 1339876, '마르다니 3', '["Action", "Crime", "Thriller"]', 'Abhiraj Minawala', '["Rani Mukerji", "Mallika Prasad", "Janki Bodiwala", "Jisshu Sengupta", "Mikhail Yawalkar"]', NULL, 'https://image.tmdb.org/t/p/w500/dHxLBtHw4InwsVumnthupZYz6NM.jpg', 2026, 0, 0, '2026-06-06 13:25:14.86681', 'IN');
INSERT INTO public.movies VALUES (489, 1196470, '서바이브', '["Sci-Fi", "Thriller", "Adventure", "Action"]', 'Frédéric Jardin', '["Émilie Dequenne", "Andreas Pietschmann", "Lisa Delamar", "Lucas Ebel", "Arben Bajraktaraj"]', '카리브해에서 요트 여행중인 한 가족. 유성이 바다에 떨어지고 폭풍이 몰아친다. 그 순간 지구의 자기장이 뒤집히고 바다와 육지가 뒤바뀐다. 심해의 괴생명체가 공격해오고 바다는 다시 되돌아올 예정인데…', 'https://image.tmdb.org/t/p/w500/3FO4B9WRrtzXHzGzqvVdYlSqs5k.jpg', 2024, 0, 0, '2026-06-06 13:25:14.876219', 'FR');
INSERT INTO public.movies VALUES (483, 823219, '플로우', '["Adventure", "Animation", "Family", "Fantasy"]', NULL, '[]', '인간이 살았던 흔적만이 남아있는 세상, 홀로 집을 지키던 ''고양이''는 갑작스러운 대홍수로 평화롭던 일상과 아늑했던 터전을 잃고 만다. 때마침 다가온 낡은 배에 올라탄 ''고양이''는 그 안에서 ''골든 리트리버'', ''카피바라'', ''여우원숭이'', ''뱀잡이수리''를 만나고 서로의 차이점을 극복하고 팀을 이뤄 험난한 파도를 헤쳐나간다.', 'https://image.tmdb.org/t/p/w500/iEDrRE5TWjKrWO2MtkCBR5aH7pT.jpg', 2024, 0, 0, '2026-06-06 13:25:14.859207', 'US');
INSERT INTO public.movies VALUES (485, 1306293, 'Aimons-nous vivants', '["Comedy", "Romance"]', 'Jean-Pierre Améris', '["Valérie Lemercier", "Gérard Darmon", "Patrick Timsit", "Alice de Lencquesaing", "Aurélien Cavagna"]', NULL, 'https://image.tmdb.org/t/p/w500/gBT1mJ2E7K8QqOM0HVtStlBElvV.jpg', 2025, 0, 0, '2026-06-06 13:25:14.864409', 'FR');
INSERT INTO public.movies VALUES (492, 10591, '내겐 너무 아찔한 그녀', '["Comedy", "Romance"]', NULL, '[]', '고등학교 졸업반인 매튜는 이웃집에 이사온 19세의 다니엘에게 첫 눈에 반한다. 아름다운 그녀에게 홀딱 빠진 매튜는 결국 다니엘과 사귀게 된다. 그러나 다니엘이 전직 포르노 스타라는 것을 알게 되고 갈등을 겪기 시작하는데...', 'https://image.tmdb.org/t/p/w500/xwZJo5B48TdkbHS1V0GLWGbtEX6.jpg', 2004, 0, 0, '2026-06-06 13:25:14.883935', 'US');
INSERT INTO public.movies VALUES (490, 1064213, '아노라', '["Drama", "Comedy", "Romance"]', NULL, '[]', '뉴욕의 스트리퍼 아노라는 자신의 바를 찾은 철부지 러시아 재벌2세 이반을 만나게 되고 충동적인 사랑을 믿고 허황된 신분 상승을 꿈꾸며 결혼식을 올리게 된다. 그러나 신데렐라 스토리를 꿈꿨던 것도 잠시, 한 번도 본 적 없는 이반의 부모님이 아들의 결혼 사실을 알게 되자 길길이 날뛰며 미국에 있는 하수인 3인방에게 둘을 잡아 혼인무효소송을 진행할 것을 지시한다. 하수인 3인이 들이닥치자 부모님이 무서워 겁에 질린 남편 이반은 아노라를 버린채 홀로 도망친다. 이반을 찾아 결혼 생활을 유지하고 싶은 아노라와 어떻게든 이반을 찾아 혼인무효소송을 시켜야만 하는 하수인 3인방의 대환장 발악이 시작된다.', 'https://image.tmdb.org/t/p/w500/sk2JbDCTMHk14owQPm2lryV1fca.jpg', 2024, 0, 0, '2026-06-06 13:25:14.878873', 'US');
INSERT INTO public.movies VALUES (8773, 28178, '하치 이야기', '["Drama", "Family"]', 'Lasse Hallström', '["Richard Gere", "Joan Allen", "Sarah Roemer", "Cary-Hiroyuki Tagawa", "Erick Avari"]', '대학교수인 파커 는 퇴근길 기차역 플랫폼에서 길 잃은 강아지를 발견하고 아내 의 반대에도 불구하고 녀석을 극진히 보살피고 키운다. 품종이 일본의 아키타견인데 착안해 ‘하치’라는 이름을 얻게 되고, 하치는 주인을 따라 아침이면 출근길을 배웅하고 저녁이면 그 기차역에서 주인을 마중하기를 하루도 거르지 않는다. 그런 녀석이 너무도 사랑스러운 파커 교수, 그러나 어느날 파커가 강단에서 강연 중 쓰러지고 하치는 오지 않는 주인을 매일같이 기다리는데...', 'https://image.tmdb.org/t/p/w500/swhEROMJrSQ2qQ7N9jBRksNWIx3.jpg', 2009, 0, 0, '2026-06-08 07:29:13.707552', 'GB');
INSERT INTO public.movies VALUES (8774, 1173476, 'Michael Jackson: Faking It', '["Documentary", "Crime"]', NULL, '["Michael Jackson", "Kerry Daynes", "Martin Bashir", "Macaulay Culkin", "Paris Jackson"]', NULL, 'https://image.tmdb.org/t/p/w500/aZbRJYyj9bSJpFI5SvnrE5565qJ.jpg', 2023, 0, 0, '2026-06-08 07:29:14.381757', 'GB');
INSERT INTO public.movies VALUES (346, 301528, '토이 스토리 4', '["Family", "Comedy", "Animation", "Adventure"]', 'Josh Cooley', '["Tom Hanks", "Tim Allen", "Annie Potts", "Tony Hale", "Keegan-Michael Key"]', '앤디와 작별한 우디는 새로운 주인 보니와의 생활에 적응 중이다. 보니는 처음 간 유치원에서 불안한 마음을 달래고자 포크를 가지고 새 장난감 포키를 만든다. 쓰레기에서 장난감으로 거듭난 포키는 자꾸 쓰레기통으로 도망치려 하지만 우디는 보니를 위해 포키를 돌봐주기로 한다. 어느 날 가족여행으로 함께 떠난 놀이공원에서 포키가 납치되고, 포키를 구하기 위한 모험을 하던 중 우디는 우연히 오래 전 헤어진 친구 보핍을 만난다. 우디는 주인 없이 자유로운 삶을 살고 있는 보핍을 보며 마음이 흔들리기 시작하는데...', 'https://image.tmdb.org/t/p/w500/9P8IX4UyH3QFLL4MV6GZyuOB7Ue.jpg', 2019, 0, 0, '2026-06-06 13:25:09.456794', 'US');
INSERT INTO public.movies VALUES (2338, 484503, '黑珍珠', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/yRlYkjecV3lJf51jIJI9ECzofVQ.jpg', 1982, 0, 0, '2026-06-07 12:17:27.76215', 'US');
INSERT INTO public.movies VALUES (8775, 11619, '플러쉬', '["Adventure", "Animation", "Comedy", "Family"]', 'David Bowers', '["Hugh Jackman", "Kate Winslet", "Ian McKellen", "Jean Reno", "Bill Nighy"]', '고품격 라이프 스타일을 즐기던 럭셔리 쥐 ’로디’가 조폭 개구리들의 거친 암흑 세계에 빠져 벌이는 익사이팅한 모험을 그리고 있다. 런던 켄싱턴의 최고급 아파트에서 여유로운 시간을 보내던 ‘로디’는 느닷없이 싱크대에서 역류되어 올라온 시궁창 쥐로 인해 변기에 빠지게 되고, 거칠고 위험한 쥐들의 세상 ‘래프로폴리스’에 떨어진다. 로디는 집으로 돌아가기 위한 방법을 찾던 중 터프 걸 ‘리타’를 만나 도움을 요청하지만 일을 꼬여만 가고, ‘로디’와 ‘리타’는 조폭 개구리 일당의 사건에 휘말리면서 이들의 짜릿하고 익사이팅한 모험이 시작된다.', 'https://image.tmdb.org/t/p/w500/dbawNwFkEjUIlPPBD7ROJXh58U3.jpg', 2006, 0, 0, '2026-06-08 07:29:15.042269', 'GB');
INSERT INTO public.movies VALUES (499, 324552, '존 윅: 리로드', '["Action", "Thriller", "Crime"]', NULL, '[]', '업계 최고의 레전드 킬러 존 윅은 과거를 뒤로 한 채 평화로운 삶을 꿈꾸며 은퇴를 선언하지만, 과거 자신의 목숨을 구해 줬던 옛 동료 산티노와의 피로 맺은 암살자들의 룰에 발목을 잡히고 만다. 피의 맹세에 대한 선택권 없이 산티노의 청을 들어줘야만 하는 존 윅은 산티노의 지시대로 로마로 향한다. 국제 암살자 연합의 최고 자리를 탈취하기 위해 자신의 친누나를 대신 암살하라는 산티노의 계획으로 인해 존 윅은 위험에 빠지게 되고, 무려 700만 달러의 현상금에 눈이 먼 전 세계의 암살자들의 총구는 그를 향하는데...', 'https://image.tmdb.org/t/p/w500/7IEjgGVcOT3kTIb42yFLPVjSvot.jpg', 2017, 0, 0, '2026-06-06 13:25:14.909016', 'US');
INSERT INTO public.movies VALUES (497, 245891, '존 윅', '["Action", "Thriller"]', NULL, '[]', '전설이라 불리던 킬러 존 윅은 사랑하는 여인을 만나 결혼을 하면서 범죄의 세계에서 은퇴한다. 행복도 잠시, 투병 끝에 부인이 세상을 떠나고 그의 앞으로 부인이 죽기 전에 보낸 강아지 한 마리가 선물로 배달된다. 어느 날 그의 차를 탐낸 러시아 마피아의 일원 요세프가 존 윅을 폭행하고 애완견 데이지마저 죽여버리는 일이 벌어진다. 그런데 요세프는 과거 존 윅을 고용한 적 있는 러시아 마피아 보스 비고의 아들이다. 마지막 남은 애완견마저 잃은 존 윅은 이제 그만의 방식으로 복수를 시작하는데...', 'https://image.tmdb.org/t/p/w500/mjKe6CmoxRcdiwbDeghyQKY09J.jpg', 2014, 0, 0, '2026-06-06 13:25:14.902133', 'US');
INSERT INTO public.movies VALUES (498, 10674, '뮬란', '["Animation", "Family", "Adventure"]', NULL, '[]', '파씨 가문의 말썽꾸러기 외동딸 뮬란은 선머슴 같은 성격에 강한 자아를 가지고 있어, 가문의 명예를 걸고 중매쟁이를 만나러 가서도 거듭되는 실수로 퇴짜를 맞게 된다. 뮬란은 나름대로는 부모님과 가문의 자랑이 되려고 노력하지만 그것이 그녀에게는 쉬운 일은 아니다. 한편, 훈족이 국경을 침략하자 황제는 가문에 한 사람씩 전쟁터로 나가라는 징집 명령을 내린다. 파씨 가문 역시 징집 명령을 받게 되고, 충성심이 강한 아버지는 전쟁에 나갈 준비를 한다. 그러나 뮬란은 지병이 있는 아버지가 전쟁에 나가도록 할 순 없다고 결심하고, 마침내 아버지 대신 갑옷을 입고 전쟁터로 향하게 된다.', 'https://image.tmdb.org/t/p/w500/zlh3FTTu0Q6aEhUKrTByfBuS7iW.jpg', 1998, 0, 0, '2026-06-06 13:25:14.90598', 'US');
INSERT INTO public.movies VALUES (500, 1102883, '마더 메리', '["Drama", "Thriller"]', NULL, '[]', '전설적인 팝스타 마더 메리가 컴백 공연을 하루 앞두고 소원해진 절친이자 전 의상 디자이너인 샘 앤셀름과 재회하면서 오랫동안 묻어두었던 상처가 다시 ​​떠오른다.', 'https://image.tmdb.org/t/p/w500/qMgUI6pxkPtIuoXX4DcJ6X7bdt2.jpg', 2026, 0, 0, '2026-06-06 13:25:14.912191', 'US');
INSERT INTO public.movies VALUES (494, 1600771, 'आखरी सवाल', '["Drama", "Thriller"]', 'Abhijeet Mohan Warang', '["Sanjay Dutt", "Namashi Chakraborty", "Amit Sadh", "Tridha Choudhury", "Sameera Reddy"]', NULL, 'https://image.tmdb.org/t/p/w500/9CXBZH6sRJpFTMSaY3wj1jx98F4.jpg', 2026, 0, 0, '2026-06-06 13:25:14.890312', 'IN');
INSERT INTO public.movies VALUES (502, 337404, '크루엘라', '["Comedy", "Crime", "Drama"]', NULL, '[]', '재능은 있지만 밑바닥 인생을 살던 에스텔라는 우여곡절 끝에 런던에 오게 된다. 그곳에서 운명처럼 재스퍼와 호레이스를 만난 에스텔라는 뛰어난 패션 감각을 이용해 완벽한 변장과 빠른 손놀림으로 런던 거리를 싹쓸이한다. 도둑질이 지겹게 느껴질 때 쯤, 꿈에 그리던 리버티 백화점에 들어가게 된 에스텔라. 그곳에서 런던 패션계를 꽉 쥐고 있는 남작 부인을 만나 충격적 사건을 겪게 되며, 에스텔라는 런던 패션계를 발칵 뒤집을 파격 아이콘 크루엘라로 새롭게 태어나게 되는데...', 'https://image.tmdb.org/t/p/w500/89y66LHU3T3txFALo2nwyBfYpWA.jpg', 2021, 0, 0, '2026-06-06 13:25:15.659942', 'US');
INSERT INTO public.movies VALUES (496, 539745, '동물농장', '["Animation", "Comedy", "Drama", "Family", "Sci-Fi"]', 'Andy Serkis', '["Seth Rogen", "Gaten Matarazzo", "Steve Buscemi", "Glenn Close", "Laverne Cox"]', NULL, 'https://image.tmdb.org/t/p/w500/6pzI1DIlxwAFffw9OZcG6cr031U.jpg', 2026, 0, 0, '2026-06-06 13:25:14.897869', 'GB');
INSERT INTO public.movies VALUES (503, 286217, '마션', '["Sci-Fi", "Drama", "Adventure"]', NULL, '[]', 'NASA 소속의 아레스 3 탐사대는 화성에 도착한 지 6일째 되는 날 거대한 모래 폭풍을 만난다. 팀원 마크 와트니가 실종되고 회오리바람에 우주선이 기울어지자, 팀원들은 마크를 찾는 일을 포기하고 화성을 떠난다.  극적으로 생존한 마크 와트니는 남은 식량과 기발한 재치로 화성에서 살아남을 방법을 찾으며 자신이 살아있음을 알리려 노력한다. 마침내 자신이 살아있다는 사실을 지구에 알리게 된 마크 와트니. NASA는 총력을 기울여 마크 와트니를 구출하기 위해 노력하고, 아레스 3 탐사대 또한 그를 구출하기 위해 그들만의 방법을 찾게 되는데...', 'https://image.tmdb.org/t/p/w500/uH8q40cjMAjrRHyPJMbQwAIJATb.jpg', 2015, 0, 0, '2026-06-06 13:25:15.672582', 'US');
INSERT INTO public.movies VALUES (2344, 1197137, '블랙폰 2', '["Horror", "Thriller"]', 'Scott Derrickson', '["Ethan Hawke", "Mason Thames", "Madeleine McGraw", "Demián Bichir", "Miguel Mora"]', '다시 울리기 시작한 공포의 전화. 충격적인 사건의 유일한 생존자 ‘피니’, 죽은 자의 환영을 보는‘그웬’. 그들을 향한 사이코패스 살인마 ‘그래버’의 복수가 시작된다. 받을 수도, 끊을 수도 없는 공포의 전화벨. 당신은 이 전화를 받을 수 있습니까?', 'https://image.tmdb.org/t/p/w500/1sx2U13D7zBOCGYE9GBxVKYvmtg.jpg', 2025, 0, 0, '2026-06-07 12:17:28.578687', 'US');
INSERT INTO public.movies VALUES (507, 1510745, 'Bodycam', '["Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/xFpBNcG3Dlr8mYF5Kz9Tizs3Pxn.jpg', 2026, 0, 0, '2026-06-06 13:25:15.683233', 'US');
INSERT INTO public.movies VALUES (508, 1209511, 'லவ் இன்சூரன்ஸ் கம்பெனி', '["Romance", "Sci-Fi", "Comedy"]', 'Vignesh Shivan', '["Pradeep Ranganathan", "Krithi Shetty", "S. J. Suryah", "Yogi Babu", "Gouri G Kishan"]', NULL, 'https://image.tmdb.org/t/p/w500/1IIUWMKzNVvI6YJX8BKE6EJ9bVd.jpg', 2026, 0, 0, '2026-06-06 13:25:15.685706', 'IN');
INSERT INTO public.movies VALUES (513, 76341, '매드맥스: 분노의 도로', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '핵전쟁으로 멸망한 22세기. 얼마 남지 않은 물과 기름을 차지한 독재자 임모탄 조가 살아남은 인류를 지배한다. 한편 아내와 딸을 잃고 살아남기 위해 사막을 떠돌던 맥스는 임모탄의 부하들에게 납치되어 노예로 끌려가고, 폭정에 반발한 외팔의 사령관 퓨리오사는 인류 생존의 열쇠를 쥔 임모탄의 여인들을 탈취해 분노의 도로로 폭주한다. 이에 임모탄의 전사인 워보이들과 신인류 눅스는 피주머니 신세로 전락한 맥스를 이끌고 퓨리오사의 뒤를 쫓는데...', 'https://image.tmdb.org/t/p/w500/cadVm6gKYYukmPysHGCwrawUHHa.jpg', 2015, 0, 0, '2026-06-06 13:25:15.699098', 'US');
INSERT INTO public.movies VALUES (515, 414419, '킬 빌: 더 홀 블러디 어페어', '["Action", "Crime"]', NULL, '[]', '23년 만에 공개되는 완전판, 275분 동안 펼쳐지는 완벽한 복수의 향연! 최고의 암살자였던 키도는 빌과 그의 조직인 데들리 바이퍼스로 인해, 끔찍한 피의 결혼식을 겪게 된다. 그리고 4년 후, 이제 그녀에게 남은 것은 자비 없는 복수뿐. 빌을 죽여라!', 'https://image.tmdb.org/t/p/w500/je5CQCCvXoAhWAwi6MoCai8IFwC.jpg', 2011, 0, 0, '2026-06-06 13:25:15.704393', 'US');
INSERT INTO public.movies VALUES (506, 11324, '셔터 아일랜드', '["Drama", "Thriller", "Mystery"]', NULL, '[]', '보스턴 셔터아일랜드의 정신병원은 중범죄를 저지른 정신병자를 격리하는 병동으로 탈출 자체가 불가능하다. 하지만 자식 셋을 죽인 혐의를 받고 있는 여인이 이상한 쪽지만을 남긴 채 감쪽같이 사라지는 사건이 발생한다. 연방보안관 테디 다니엘스(레오나르도 디카프리오)는 수사를 위해 동료 척(마크 러팔로)과 함께 셔터아일랜드로 향한다. 테디는 수사를 위해 의사, 간호사, 병원관계자 등을 심문하지만 수사는 전혀 진척되지 않는다. 설상가상 폭풍이 불어 닥쳐 테디와 척은 섬에 고립되게 되고, 그들에게 점점 괴이한 일들이 일어나기 시작하는데...', 'https://image.tmdb.org/t/p/w500/aywZdSOXtwcqqLTl271EUJemi2.jpg', 2010, 0, 0, '2026-06-06 13:25:15.680847', 'US');
INSERT INTO public.movies VALUES (593, 1022256, '''셀레나 고메즈: 마이 마인드 앤드 미'' - Selena Gomez: My Mind & Me', '["Documentary"]', NULL, '[]', '수년간 세상의 주목을 받으며 셀레나 고메즈는 상상을 초월한 인기를 얻는다. 하지만 인기가 절정에 도달했을 때, 예상하지 못했던 사건으로 셀레나는 어둠 속에 빠진다. 이 유례없이 생생하고 은밀한 다큐멘터리는 셀레나가 새로운 빛을 찾아 떠나는 6년간의 여정을 다룬다.', 'https://image.tmdb.org/t/p/w500/aBmP7Cxx8AaOuAEab7vbw89Phus.jpg', 2022, 0, 0, '2026-06-06 13:25:18.776697', 'US');
INSERT INTO public.movies VALUES (408, 694, '샤이닝', '["Horror", "Thriller"]', NULL, '[]', '소설가인 잭 토랜스는 콜로라도 산맥에 있는 오버룩 호텔의 관리인으로 취직한다. 다음 시즌 준비를 하는 이곳은 겨울 동안 폐쇄되기 때문에 토랜스의 가족들만 호텔에 머물게 된다. 갑자기 몰아친 폭설로 잭과 아내 웬디와 아들과 함께 호텔에 고립되고, 투시와 텔레파시 능력이 있는 잭의 아들 대니는 호텔에 유령이 있으며 유령들이 천천히 아버지를 미치게 하고 있음을 알게 된다. 잭은 과거에 스스로 자신의 아내와 두 딸을 죽인 이곳의 예전 관리인 그레이디의 유령을 만난다. 과거에 있었던 살인사건의 악령에 휘말린 잭은 호텔을 공포의 도가니로 몰아가는데...', 'https://image.tmdb.org/t/p/w500/aaItbIXZlC2C7Arg3PI0IglKi0.jpg', 1980, 0, 0, '2026-06-06 13:25:11.780263', 'US');
INSERT INTO public.movies VALUES (512, 44896, '랭고', '["Animation", "Comedy", "Family", "Adventure"]', NULL, '[]', '당신들이 아무렇게나 생각하는 그런 영웅이 아냐!! 예측을 불허하는 대단한 놈이 왔다! 광대한 모하비 사막에 툭 떨어진 정체 모를 카멜레온 랭고, 적응하려면 수백만 년이 걸린다는 모하비 사막에서 살아남기 위해 고군분투하던 랭고는 아주 우연한 계기로 사막의 무법자 매를 죽이게 된다. 얼떨결에 마을의 영웅이 되어버린 랭고는 황무지 빌리지의 보안관을 맡게 되는데... 위험이 도사리는 거대한 사막, 쫓고 쫓기는 추격, 예측 불허한 사건들 속에서 랭고의 운명은 과연 어떻게 펼쳐질까?', 'https://image.tmdb.org/t/p/w500/r03cVlmlKRPVAQxEqmhhPyYwfcr.jpg', 2011, 0, 0, '2026-06-06 13:25:15.696552', 'US');
INSERT INTO public.movies VALUES (514, 228150, '퓨리', '["Drama", "Action"]', NULL, '[]', '2차 세계대전, 전차부대를 이끄는 대장 워대디에게 적으로 둘러싸인 최전선에서의 마지막 전투 명령이 떨어진다. 하지만 수 차례의 전투로 대부분의 동료를 잃은 그에겐 단 한 대의 탱크 퓨리와 지칠 대로 지쳐버린 부대원들만이 남아있을 뿐. 게다가 지원군으로 경력이 전무한 신병 노먼이 배치되고, 워대디는 신참을 포함한 단 4명의 부대원만으로 적진에 나서야 하는 상황에 처한다. 수백 명의 적들과 맞서야 하는 단 5인의 병사. 최소의 인원과 최악의 조건 속, 사상 최대 위기에 처한 워대디와 그의 부대는 생존 가능성 제로인 최후의 전쟁터로 향하는데...', 'https://image.tmdb.org/t/p/w500/dYwwlFLd8WNrfa3s6HBzAbH3QXG.jpg', 2014, 0, 0, '2026-06-06 13:25:15.701695', 'US');
INSERT INTO public.movies VALUES (525, 1231914, '여직원들 : 직장 연애사 3', '["Romance"]', 'Choi Jong-gyoo', '["Soo Hee", "Lee Chae-dam", "Hae Il", "Woo Yeol", "Yoon Taek-seung"]', NULL, 'https://image.tmdb.org/t/p/w500/c4HACOcvKsWAaNTsyYs1JzfwXWi.jpg', 2023, 0, 0, '2026-06-06 13:25:16.44353', 'KR');
INSERT INTO public.movies VALUES (522, 1643, '파리에서의 마지막 탱고', '["Drama", "Romance"]', NULL, '[]', '폴(말론 브랜도)은 아파트를 둘러보러 왔다가 아름다운 젊은 여성인 쟌느(마리아 슈나이더)를 만난다. 둘은 미친듯이 서로를 탐닉하고 적나라한 정사를 즐기지만 서로에 대해서 알기를 원하지 않는다. 그런 관계를 맺고도 폴과 쟌느는 자신의 생활로 돌아가 폴은 자신의 아내가 자살한 허름한 한 여관으로, 쟌느는 그녀에 관한 영화를 만들고 있는 그녀의 약혼자 톰에게 돌아간다.  그러나 그들은 다시 아파트에서 만나 다시 서로를 원하는 깊은 관계가 되는데...', 'https://image.tmdb.org/t/p/w500/qX0Chw8rJP1RwcXEVAvMCPanGR2.jpg', 1972, 0, 0, '2026-06-06 13:25:16.436306', 'US');
INSERT INTO public.movies VALUES (518, 741929, 'Cold Feet', '[]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/7ABURsWnzHQpf9QcP67968q9R3S.jpg', 2019, 0, 0, '2026-06-06 13:25:15.71172', 'US');
INSERT INTO public.movies VALUES (4123, 1290182, '그 시절, 우리가 좋아했던 소녀', '["Romance", "Drama", "Comedy"]', 'Cho Young-myoung', '["Jung Jinyoung", "DAHYUN", "Demian", "Lee Min-goo", "Kim Yo-han"]', '선아에게 고백하기까지 수많은 날을 보낸 철없던 진우의 열여덟 첫사랑 스토리. 각양각색 사춘기 소년들의 유일한 공통점은 같은 반 반장 선아를 좋아한다는 것! 어느 날, 고등학생 진우는 학교에서 작은 사고를 치게 되고, 이를 계기로 선아에게 특별 감시를 받게 된다. 문제아 진우를 비롯한 친구들은 모범생 선아의 사랑을 얻기 위해 고군분투하며 즐거운 학창 시절을 보내는데, 15년 뒤, 진우는 선아로부터 뜻밖의 고백을 듣게 된다.', 'https://image.tmdb.org/t/p/w500/1aSRSDDHQX2egc1az05qQ5tz6zS.jpg', 2025, 0, 0, '2026-06-08 06:27:21.393042', 'KR');
INSERT INTO public.movies VALUES (8784, 710, '007 골든 아이', '["Adventure", "Action", "Thriller"]', 'Martin Campbell', '["Pierce Brosnan", "Sean Bean", "Izabella Scorupco", "Famke Janssen", "Joe Don Baker"]', '골든 아이라는 비밀 신무기가 냉전시대 때 미국과 소련에 의해 개발된다. 이 신병기의 목적은 대기권 밖에서 핵무기를 폭발시켜 전자 회로를 가진 적의 모든 장비를 마비시키는 것. 그런데 이 골든 아이가 도난당하는 사고가 발생하자 영국 최고의 첩보원 007은 러시아로 향한다. 골든 아이를 훔쳐간 무리의 두목은 007의 과거 파트너였던 006. 그는  공산주의와 싸우기 한 집단, 코자크에 소속되어 있던 자신의 부모가 죽은 이유가 1945년 2차대전 후 영국의 배신 때문이라고 생각한다. 006은 부모의 복수를 위해 러시아 군부 장성과 함께 음모를 꾸미는데...', 'https://image.tmdb.org/t/p/w500/b0tjkc1p5dWW9KQFgnCt2zgequ6.jpg', 1995, 0, 0, '2026-06-08 07:29:22.603544', 'GB');
INSERT INTO public.movies VALUES (519, 207947, '白衣物語 淫す！', '["Comedy", "Drama"]', 'Hidehiro Ito', '["Mina Asami", "Kazuyo Ezaki", "Nami Misaki", "Hiroshi Fukami", "Yūji Nogami"]', NULL, 'https://image.tmdb.org/t/p/w500/vfWbS6u3EtOw9zMbJJJQ8hVq701.jpg', 1984, 0, 0, '2026-06-06 13:25:15.714166', 'JP');
INSERT INTO public.movies VALUES (521, 868668, '영웅 바가트 싱', '["Action", "Comedy", "Drama"]', 'Harish Shankar', '["Pawan Kalyan", "Sreeleela", "Raashii Khanna", "R. Parthiban", "Nawab Shah"]', '한 부족 소년은 스승의 가르침을 통해 성장하며, 스승으로부터 ‘바가트 싱’이라는 이름을 얻는다. 그는 확고한 도덕적 신념을 깊이 간직하며 자라나고, 이 신념은 평생 그의 행동을 이끌어 간다. 그는 불의에 맞서 굳건히 버티며, 아무리 불리한 상황이라도 강력한 악의 세력에 맞서 싸운다.', 'https://image.tmdb.org/t/p/w500/8n4ypYQWztEXlR8JxD0fctdKwfC.jpg', 2026, 0, 0, '2026-06-06 13:25:16.432452', 'IN');
INSERT INTO public.movies VALUES (524, 953, '마다가스카', '["Adventure", "Animation", "Comedy", "Family"]', NULL, '[]', '센트럴파크 동물원의 인기절정 뉴요커 4인방  사자 알렉스(벤 스틸러)는 스포트라이트를 한 몸에 받는 뉴욕 센트럴파크 동물원 최고의 인기 스타. 타고난 품종은 정글의 왕이지만 사실 알렉스는 동물원 인기 스타인 자신을 자랑스러워하고 정글 구경은 한 번도 해 본 적 없는 정통 뉴욕 토박이다.  알렉스의 친구들인 얼룩말 마티(크리스 록)와 기린 멜먼(데이비드 쉬머), 하마 글로리아(제이다 핀켓 스미스)도 온실 속 화초처럼 동물원의 안락한 생활이 익숙하기만 한데...  탈출은 꿈꾼 적도 없는 데 미지의 정글 마다가스카로?!  그러던 어느 날, 호기심 많은 마티가 그들의 고향 남극으로 탈출기회만을 노리는 정체불명 펭귄 특공대의 꾐에 빠져 야생에 대한 동경을 안고 외출을 시도한다. 알렉스와 친구들은 사라진 마티를 찾기 위해 동물원 밖으로 나가게 되고, 사람들에게 발견된 동물 4인방(사실은 뉴요커 4인방)은 갑갑한 동물원 탈출을 모의했다는 오해 아닌 오해를 받은 채 아프리카로 향하는 배에 오르게 되고...  정글보다 도시가 더 좋은 뉴요커 4인방의 정글 탈출기!  뉴요커 4인방이 포획된 배를 남극을 향한 배로 오인한 펭귄 특공대는 재빠르게 선박을 접수하고 항로를 바꾸는 사이, 4인방이 갇혀 있던 상자가 바다로 떨어지면서 알렉스와 친구들은 미지의 정글 마다가스카에 표류하게 된다.  지금까지 안락한 뉴요커의 삶을 살아온 이들이 과연 거친 야생의 정글 마다가스카에서 살아갈 수 있을 것인가? 아니면 다시 센트럴파크의 동물원으로 돌아갈 것인가?  정글보다 도시가 더 좋은 뉴요커 4인방의 험난한 정글 탈출기는 이제부터 시작된다!!', 'https://image.tmdb.org/t/p/w500/7BeMHBgS6nUaxj6w0hGhsiK827c.jpg', 2005, 0, 0, '2026-06-06 13:25:16.441241', 'US');
INSERT INTO public.movies VALUES (4122, 386874, '나쁜 수업', '["Drama"]', 'Han Dong-Ho', '["Yoon Sul-hee", "Lee Chae-dam", "Lee Han-bit", "Jung Neom-chyeo", "Kim Jun-hee"]', '아빠와의 안좋은 기억으로 남자의 존재를 거부하는 지은은 엄마(현아)의 권유로 미대생에게 과외를 받게되고, 미대생(정우)는 쌀쌀맞은 지은의 태도에 당황해하며 둘 사이에는 미묘한 기류가 흐르게 된다. 한편 지은과 정우에게 혹시 무슨일이 생길까 불안해 하는 현아는 정우를 집으로 불러 한가지 제안을 하지만 정우는 현아에게 뜻밖의 고백을 하게 된다. 부적절한 관계가 된 현아와 정우, 엄마를 못마땅해 하는 지은은 자신의 방법대로 엄마에게 충격을 주게 된다.', 'https://image.tmdb.org/t/p/w500/r1zxUdK5VPPurWi0gFWFJJArOfk.jpg', 2015, 0, 0, '2026-06-08 06:27:20.718544', 'KR');
INSERT INTO public.movies VALUES (523, 10020, '미녀와 야수', '["Romance", "Family", "Animation", "Fantasy"]', NULL, '[]', '18세기 프랑스의 작은 마을, 밝고 아름다운 소녀 벨은 아버지와 함께 단 둘이 살고 있다. 마을 청년 개스톤은 벨의 미모에 반해 끈질기게 구애를 하지만, 벨은 책 읽기만 즐기며 평범한 시골생활에서 벗어나기를 꿈꾼다. 그러던 어느 날, 아버지가 흉측한 야수의 성에 갇히게 되는 일이 벌어지고 벨은 아버지를 구하기 위해 아버지 대신 자신이 성에 남기로 한다. 그녀를 경계하던 야수는 순수하고 아름다운 벨에게 조금씩 마음을 열게 되고, 벨 또한 흉측한 외모에 가려진 야수의 따뜻한 영혼을 발견하게 된다. 한편 질투심에 눈이 먼 개스톤은 야수를 없애기 위해 마을 사람들을 이끌고 야수의 성으로 향하는데...', 'https://image.tmdb.org/t/p/w500/xN8yuKcIIQEJo1Cuk6RuZpV64Uh.jpg', 1991, 0, 0, '2026-06-06 13:25:16.438699', 'US');
INSERT INTO public.movies VALUES (534, 1665724, 'Shera', '["Action", "Drama"]', 'Savio Sandhhu', '["Parmish Verma", "Sonal Chauhan", "Yograj Singh", "Manav Vij", "Hashneen Chauhan"]', NULL, 'https://image.tmdb.org/t/p/w500/7qgjO10RA9Jd7ffXbYeqQAwf1WF.jpg', 2026, 0, 0, '2026-06-06 13:25:16.465584', 'IN');
INSERT INTO public.movies VALUES (533, 14324, '버진 테리토리', '["Adventure", "Action", "Comedy", "Romance"]', 'David Leland', '["Hayden Christensen", "Mischa Barton", "Kate Groombridge", "Rosalind Halstead", "Tim Roth"]', '흑사병이 창궐해 이탈리아를 암울하게 만들었던 시기. 몰락한 집안의 딸 팜피네아는 정혼자인 제르진스키 백작이 러시아로부터 도착하기를 기다리던 중, 악당 제르비노의 계략으로 그와 강제 결혼을 하게 될 위기에 처하자 급히 수녀원으로 도망친다. 그곳에서 역시 제르비노에게 쫓기다 수녀원으로 도망쳐 와 정원사로 일하는 피렌체 젊은이 로렌조를 만나게 되고, 둘은 감정의 줄다리기를 하며 점점 서로에게 사랑을 느끼게 되는데...', 'https://image.tmdb.org/t/p/w500/zofWP7ZKhoVTh2VUltaDo4LRQXc.jpg', 2007, 0, 0, '2026-06-06 13:25:16.463174', 'GB');
INSERT INTO public.movies VALUES (4126, 934246, '사모님 골프 개인교습', '["Drama", "Romance"]', 'Kim Ho-cheol', '["Yoon Yool", "Seo Bo-ra", "Ji Min-iI", "Im Tae-mok"]', NULL, 'https://image.tmdb.org/t/p/w500/vaNB68cS06sOour5wfIu9YhiJvY.jpg', 2021, 0, 0, '2026-06-08 06:27:23.440675', 'KR');
INSERT INTO public.movies VALUES (880, 378236, '이모티: 더 무비', '["Animation", "Family", "Comedy"]', NULL, '[]', '스마트폰 속 이모티들의 비밀 세계 ‘텍스토폴리스’의 제1원칙은 1인 1표정! 각자 맡은 표정을 완벽히 해내야 하지만 다양한 감정의 소유자 ‘진’은 출동한 첫날 당황한 나머지 실수를 저지른다. ‘진’의 실수는 스마트폰 초기화라는 ‘텍스토폴리스’의 파멸을 불러오고 ‘텍스토폴리스’의 시장인 ‘스마일’은 도시를 위기에 빠뜨린 ‘진’을 파괴하기 위해 백신봇을 출동시키는데…  ‘진’은 친구 ‘하이파이브’, 해커 ‘핵키 브레이크’와 함께 ‘텍스토폴리스’와 자신의 운명을 구하기 위해 ‘소스 코드’를 찾기 위한 험난한 여정을 떠난다! 깨알만한 귀요미 이모티들의 가장 스마트한 어드벤처가 시작된다!', 'https://image.tmdb.org/t/p/w500/8fbkDJ9uYCGwCySN0RbFRYk6OCl.jpg', 2017, 0, 0, '2026-06-06 13:25:29.670476', 'US');
INSERT INTO public.movies VALUES (2935, 104866, 'Play Motel', '["Crime", "Thriller", "Romance", "Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/enThPsPnWpzJpJm4Lbddowe2LkY.jpg', 1979, 0, 0, '2026-06-07 12:17:54.487477', 'US');
INSERT INTO public.movies VALUES (530, 466272, '원스 어폰 어 타임 인… 할리우드', '["Comedy", "Drama", "Thriller"]', NULL, '[]', '자유의 바람이 불던 1969년 할리우드, 잊혀져 가는 액션스타 릭 달튼과 그의 스턴트 배우 겸 매니저인 클리프 부스는 과거의 영광을 되찾기 위해 고군분투하지만 새로운 스타들에 밀려 큰 성과를 거두진 못한다. 어느 날 릭의 옆집에 할리우드에서 가장 핫한 로만 폴란스키 감독과 배우 샤론 테이트 부부가 이사 오자 릭은 새로운 기회가 생길 수도 있다고 기뻐하지만 인사조차 나누지 못한다. 형편상 더 이상 함께 일할 수 없게 된 릭과 클리프는 각자의 길을 가기로 하고 릭의 집에서 술을 거나하게 마시던 중 뜻하지 않은 낯선 방문객을 맞이하게 되는데…', 'https://image.tmdb.org/t/p/w500/AgulxT0MIna1ZxPQmtw3j6prfxA.jpg', 2019, 0, 0, '2026-06-06 13:25:16.455978', 'US');
INSERT INTO public.movies VALUES (4127, 1317512, '세계의 주인', '["Drama"]', 'Yoon Ga-eun', '["Seo Su-bin", "Jang Hye-jin", "Kim Jeong-sik", "Kang Chae-yun", "Lee Jae-hee"]', '반장, 모범생, 학교 인싸인 동시에 연애가 가장 큰 관심사인 열여덟 이주인. 어느 날, 반 친구 수호가 제안한 서명운동에 전교생이 동참하던 중 오직 주인만이 내용에 동의할 수 없다며 나 홀로 서명을 거부한다. 어떻게든 설득하려는 수호와 단호한 주인의 실랑이가 결국 말싸움으로 번지고, 화가 난 주인이 아무렇게나 질러버린 한마디가 주변을 혼란에 빠뜨린다. 설상가상, 주인을 추궁하는 익명의 쪽지가 배달되기 시작하는데…….', 'https://image.tmdb.org/t/p/w500/1UrMMAChGXORYrbCef7GNId98Vk.jpg', 2025, 0, 0, '2026-06-08 06:27:24.138493', 'KR');
INSERT INTO public.movies VALUES (531, 1248226, '언더커버 대디', '["Action", "Comedy", "Family"]', NULL, '[]', '하루 아침에 직장해서 해고된 브라이언과 그의 착한 아들 루카스. 공원에서 우연히 만난 제프, 아들 CJ는 쿨해 보이지만 하는 행동마다 의심스럽다. 아니나 다를까, 그들과 친해지자 목숨을 위협하는 수상한 인물들이 접근하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/nzEjHWzNstCy4JeXq6bHkSSnFUB.jpg', 2025, 0, 0, '2026-06-06 13:25:16.458388', 'US');
INSERT INTO public.movies VALUES (532, 18334, '기니어피그 EP1 : 악마의 실험', '["Horror"]', 'Satoru Ogura', '["Shigeru Saiki", "Mari Somei"]', NULL, 'https://image.tmdb.org/t/p/w500/yskvkbz3NihL2xswJ2GomCXuQH6.jpg', 1985, 0, 0, '2026-06-06 13:25:16.460785', 'JP');
INSERT INTO public.movies VALUES (4125, 482036, '착한 형수', '["Romance", "Drama"]', 'Gi Dae-ho', '["Baek Se-ri", "Park Do-jin", "Sang Woo", "Han Seol-hwa", "Sang Hoon-I"]', '"형수님, 오늘 밤은 저만 믿으세요!" 취업 준비생 민호는 면접을 위해 부모님 집에 신세를 지게 된다. 그러나 오랜만에 찾아간 집엔 정작 부모님은 안 계시고 젊은 형수만 있다. 알고 보니 부모님은 아는 분 장례식장에 참석하러 지방에 가셨고, 사이가 나쁜 형 현수는 형수와 싸우고 가출했던 것. 홀로 남은 젊은 형수의 싱그러운 몸매는 자꾸만 민호의 욕망을 자극하는데...', 'https://image.tmdb.org/t/p/w500/e0BF6bJYWnEqaGucuNilOEHqRwf.jpg', 2016, 0, 0, '2026-06-08 06:27:22.767181', 'KR');
INSERT INTO public.movies VALUES (377, 315162, '장화신은 고양이: 끝내주는 모험', '["Animation", "Adventure", "Fantasy", "Comedy", "Family"]', 'Joel Crawford', '["Antonio Banderas", "Salma Hayek Pinault", "Harvey Guillén", "Wagner Moura", "Florence Pugh"]', '아홉 개의 목숨 중 단 하나의 목숨만 남은 장화신은 고양이.  마지막 남은 목숨을 지키기 위해 히어로의 삶 대신 반려묘의 삶을 선택한 그에게 찾아온 마지막 기회, 바로 소원을 들어주는 소원별이 있는 곳을 알려주는 지도!  잃어버린 목숨을 되찾고 다시 히어로가 되기를 꿈꾸는 장화신은 고양이는 뜻밖에 동료가 된 앙숙 파트너 ''키티 말랑손'', 그저 친구들과 함께라면 모든 게 행복한 강아지 ''페로''와 함께 소원별을 찾기 위해 길을 떠난다.  그리고 소원별을 노리는 또 다른 빌런들과 마주치게 되는데…', 'https://image.tmdb.org/t/p/w500/rKgvctIuPXyuqOzCQ16VGdnHxKx.jpg', 2022, 0, 0, '2026-06-06 13:25:10.241146', 'US');
INSERT INTO public.movies VALUES (544, 1202285, 'Porn', '["Documentary"]', 'Amélie Menu', '["Céline Tran", "Liza Del Sierra", "Lou Charmelle", "Sofia Ferrazzini", "Manon in the sun"]', NULL, 'https://image.tmdb.org/t/p/w500/rbzySQcXmTvWOaaJAsFDlCjW8eG.jpg', 2023, 0, 0, '2026-06-06 13:25:17.199895', 'FR');
INSERT INTO public.movies VALUES (552, 1100988, '28년 후', '["Horror", "Thriller", "Sci-Fi"]', 'Danny Boyle', '["Jodie Comer", "Aaron Taylor-Johnson", "Alfie Williams", "Ralph Fiennes", "Jack O''Connell"]', '28년 전 생물학 무기 연구소에서 세상을 재앙으로 몰아넣은 바이러스가 유출된 후, 일부 생존자들이 모여 철저히 격리된 채 살아가는 섬 홀리 아일랜드. 이곳에서 태어나 한 번도 섬 밖을 나가 본 적 없는 소년 스파이크는 어느 날 섬을 떠나 본토에 발을 들이게 되고 난생처음 바이러스에 잠식된 세상을 마주하게 된다. 변이된 바이러스는 10,228일의 시간 동안 감염자들을 더욱 충격적으로 진화시켰고 스파이크는 그 실체를 목격하며 극강의 공포에 휩싸이게 되는데...', 'https://image.tmdb.org/t/p/w500/zRo90O0bTKJem1aDgVa6Sm0gthE.jpg', 2025, 0, 0, '2026-06-06 13:25:17.219632', 'GB');
INSERT INTO public.movies VALUES (545, 786892, '퓨리오사: 매드맥스 사가', '["Action", "Sci-Fi", "Adventure"]', NULL, '[]', '문명 붕괴 45년 후, 황폐해진 세상 속 누구에게도 알려지지 않은 풍요가 가득한 녹색의 땅에서 자란 퓨리오사는 바이커 군단의 폭군 디멘투스의 손에 모든 것을 잃고 만다. 가족도 행복도 모두 빼앗기고 세상에 홀로 내던져진 퓨리오사는 반드시 고향으로 돌아가겠다는 어머니와의 약속을 지키기 위해 인생 전부를 건 복수를 시작하는데...', 'https://image.tmdb.org/t/p/w500/zaUFDdJidS4Nyyd6jb2Ok3Kq4Vo.jpg', 2024, 0, 0, '2026-06-06 13:25:17.202723', 'US');
INSERT INTO public.movies VALUES (539, 1448560, '와일드캣', '["Action", "Thriller"]', 'James Nunn', '["Kate Beckinsale", "Lewis Tan", "Alice Krige", "Charles Dance", "Rasmus Hardiker"]', '전직 특수요원의 딸이 납치된다 옛 팀원들이 소환되고 몸값을 위해 런던 갱단을 강탈하는 작전에 돌입한다. 급기야 런던 3대 조직이 참전하고 단 12시간, 딸을 구하기 위한 전면전이 시작되는데…', 'https://image.tmdb.org/t/p/w500/mCoARYlSAIJGTSFgk0wJ3YCtpiW.jpg', 2025, 0, 0, '2026-06-06 13:25:16.477446', 'GB');
INSERT INTO public.movies VALUES (595, 49013, '카 2', '["Animation", "Family", "Adventure", "Comedy"]', NULL, '[]', '오붓한 휴식을 취하려던 맥퀸의 소망과 달리, 단짝인 견인차 메이터의 오지랖으로 또다시 세계 그랑프리 대회에 참가하게 된다. 석유가 아닌 대체연료 알리놀을 사용해야 하는 이 대회에서 맥퀸이 강력한 경쟁 상대인 프란체스코와 대립의 각을 세우는 사이, 메이터는 뜻하지 않게 국제적인 첩보전에 휘말린다. 영국 최고의 스파이 핀 맥미사일과 아름다운 초보 스파이 홀리 쉬프트웰이 메이터를 미국 스파이로 오해하면서 사건은 걷잡을 수 없이 커지는데...', 'https://image.tmdb.org/t/p/w500/azNYfwYnrdCVB3uzZaRl0JIx4N0.jpg', 2011, 0, 0, '2026-06-06 13:25:18.781135', 'US');
INSERT INTO public.movies VALUES (547, 858024, '햄넷', '["Drama", "Romance", "History"]', NULL, '[]', '자연 속에서 자유롭게 살아온 아녜스는 마을에 새로 온 교사 윌리엄 셰익스피어와 사랑에 빠져 가정을 이룬다. 어느 날, 두 사람에게 예기치 못한 비극이 찾아오고 삶의 가장 소중한 것을 잃은 참혹한 상실의 고통 속에서 두 사람은 각자의 방식으로 상처와 비극을 극복하게 되는데…', 'https://image.tmdb.org/t/p/w500/96ikpEmn7Uxct77x6kTIUgnldh2.jpg', 2025, 0, 0, '2026-06-06 13:25:17.207999', 'US');
INSERT INTO public.movies VALUES (548, 68718, '장고: 분노의 추적자', '["Drama"]', NULL, '[]', '흑인 노예 장고는 착한 사마리아인 같은 독일인 현금사냥꾼 닥터 킹의 도움을 받아 멋진 말을 타고 미국 평원을 달리며 헤어진 아내 브룸힐다를 찾아다니는 총잡이 낭만주의자로 변신한다. 그는 브룸힐다가 미시시피에서 가장 악독한 농장 캔디랜드의 노예로 일하고 있다는 소식을 듣고 농장주 캔디를 찾아간다. 아내를 구해야 하는 분노의 로맨티스트 장고, 그를 돕는 정의의 바운티 헌터 닥터 킹, 그리고 그들의 표적이 된 욕망의 마스터 캔디. 복수의 사슬이 풀리면, 세 남자의 피도 눈물도 없는 대결이 시작된다.', 'https://image.tmdb.org/t/p/w500/AoH4YLDdxAHraeT336sc9nOIaX0.jpg', 2012, 0, 0, '2026-06-06 13:25:17.210275', 'US');
INSERT INTO public.movies VALUES (549, 1370123, 'Aída y vuelta', '["Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/k3Bk1v28P0ZVQKFL90WtttpQhEP.jpg', 2026, 0, 0, '2026-06-06 13:25:17.212574', 'US');
INSERT INTO public.movies VALUES (561, 1627824, 'Rocky''s Cat-astrophe', '["Animation", "Family"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/pqfkJh0CyF00GvR4NIdvJYkJb2F.jpg', 2026, 0, 0, '2026-06-06 13:25:17.969854', 'US');
INSERT INTO public.movies VALUES (384, 285, '캐리비안의 해적: 세상의 끝에서', '["Adventure", "Fantasy", "Action"]', 'Gore Verbinski', '["Johnny Depp", "Geoffrey Rush", "Orlando Bloom", "Keira Knightley", "Jack Davenport"]', '윌 터너와 엘리자베스 스완, 바르보사 선장은 바다괴물 크라켄에 잡아먹힌 잭 스패로우를 구하는 데 도움을 얻기 위해 싱가포르의 해적 사오펭을 찾아간다. 이들은 잭 스패로우가 있어야만 해적연맹의 아홉 영주를 모아 연합함대를 구성할 수 있고, 해적 소탕에 쌍심지를 켠 동인도회사에 맞설 수 있다. 동인도회사의 커틀러 베켓 경은 유령선 플라잉 더치맨과 그 선장 데비 존스를 수하에 거느리게 된 터. 이 힘이 막강해서, 해적 연합함대는 다시 바다의 여신 칼립소에게 도움을 요청하기로 한다.', 'https://image.tmdb.org/t/p/w500/bTotG6tZERQqfKr2TDjwdjW8It4.jpg', 2007, 0, 0, '2026-06-06 13:25:11.009001', 'US');
INSERT INTO public.movies VALUES (555, 270473, 'ฟัด จัง โตะ', '["Comedy", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/4x32HOq15WeTxNcda6oJaWmbNxp.jpg', 2013, 0, 0, '2026-06-06 13:25:17.226921', 'US');
INSERT INTO public.movies VALUES (557, 588228, '내일의 전쟁', '["Action", "Sci-Fi", "Adventure"]', NULL, '[]', '현재로 긴급 메시지를 전하기 위해 2051년에서 온 한 무리의 시간 여행자들이 도착한다. 메세지의 내용은 30년 동안 미래 인류가 치명적인 외계 종족과 세계 전쟁에서 지고 있다는 것. 인류가 생존할 수 있는 유일한 희망은 현재 세계의 군인과 민간인들이 미래로 보내서 전쟁에 참여하는 것이다. 어린 딸을 위해 세상을 구하기로 결심한 댄 포레스터는 지구의 운명을 다시 쓰기 위해 뛰어난 과학자와 사이가 멀어진 아버지와 함께 팀을 이룬다.', 'https://image.tmdb.org/t/p/w500/jN7yirvhOTNLUsHHvjKXwoTRe9B.jpg', 2021, 0, 0, '2026-06-06 13:25:17.231753', 'US');
INSERT INTO public.movies VALUES (556, 1514125, '사이공 선셋', '["Romance", "Drama"]', 'Son Hyeon-woo', '["Danny Lee", "Seo Rina", "손동제", "라라", "Shin Sae-rom"]', NULL, 'https://image.tmdb.org/t/p/w500/A7yQj3vKBU98PQoZPghCFUDqDnZ.jpg', 2025, 0, 0, '2026-06-06 13:25:17.229318', 'KR');
INSERT INTO public.movies VALUES (559, 7131, '반 헬싱', '["Horror", "Adventure", "Action"]', NULL, '[]', '세상 모든 악이 두려워하는 이름, 반헬싱  악의 기운이 느껴지는 곳이면 어디든 나타나 신의 이름으로 처단을 내리는 신의 사제 ''반헬싱''. 지상의 모든 악을 소탕하는 것이 그의 소명. 늘 살인자라 비난받으며 숨어지내야 하는 것은 그에게 내린 저주이다. 그러나 왜 그런 운명을 타고났는지, 자신이 누구인지 그에게 7년 이전의 기억은 없다. 그저 로마 교황청의 부름을 받아 움직일 뿐.', 'https://image.tmdb.org/t/p/w500/5p2rU70TTEd1bFXRIXZGSlgUhbe.jpg', 2004, 0, 0, '2026-06-06 13:25:17.236947', 'US');
INSERT INTO public.movies VALUES (558, 330457, '겨울왕국 2', '["Family", "Animation", "Adventure", "Comedy", "Fantasy"]', 'Jennifer Lee', '["Idina Menzel", "Kristen Bell", "Josh Gad", "Jonathan Groff", "Evan Rachel Wood"]', '평화를 되찾은 아렌델 왕국에 새로운 위기가 찾아온다. 어느 날부턴가 의문의 목소리가 엘사를 부르고, 평화로운 아렌델 왕국을 위협한다. 트롤은 모든 것은 과거에서 시작되었음을 알려주며 엘사의 힘의 비밀과 진실을 찾아 떠나야한다고 조언한다. 위험에 빠진 아렌델 왕국을 구해야만 하는 엘사와 안나는 숨겨진 과거의 진실을 찾아 크리스토프, 올라프, 그리고 스벤과 함께 위험천만한 놀라운 모험을 떠나게 된다. 자신의 힘을 두려워했던 엘사는 이제 이 모험을 헤쳐나가기에 자신의 힘이 충분하다고 믿어야만 하는데...', 'https://image.tmdb.org/t/p/w500/lVcwSnzhSMWYXUQzyMilCztSE6I.jpg', 2019, 0, 0, '2026-06-06 13:25:17.234202', 'US');
INSERT INTO public.movies VALUES (554, 1278, '몽상가들', '["Drama", "Romance"]', NULL, '[]', '자유를 외치는 젊은이들의 뜨거운 열기로 가득한 1968년 파리, 영화광인 미국인 유학생 매튜는 시네마테크에서 쌍둥이 남매 이사벨과 테오를 만나 가까워진다. 부모가 휴가를 떠난 이사벨과 테오의 집에서 한 달 간 지내게 된 매튜는 영화와 음악, 책, 혁명 등의 이야기를 자유롭게 나누며 특별한 추억을 쌓는다. 자연스레 이사벨에게 사랑을 느끼게 되는 매튜, 하지만 이사벨은 테오와 떨어지려 하지 않고 세 사람의 은밀하고 특별한 관계는 계속되는데...', 'https://image.tmdb.org/t/p/w500/gb0vVzJlxumQrsN8Mnud647Zh0V.jpg', 2003, 0, 0, '2026-06-06 13:25:17.224546', 'US');
INSERT INTO public.movies VALUES (4130, 793602, '애첩', '["Drama"]', 'Richard Kim', '["Rika", "Min Do-yoon", "James"]', NULL, 'https://image.tmdb.org/t/p/w500/gGyQhfdqw9saOAlYHz4sxJO9Ot.jpg', 2020, 0, 0, '2026-06-08 06:27:26.179123', 'KR');
INSERT INTO public.movies VALUES (4132, 938091, '미용실 : 특별한 서비스 5', '["Romance"]', 'Cho Tae Ho', '["Seung Ha", "Kang Min-woo", "Min Do-yoon", "Hae Il", "So Jeong"]', '불황에 홀로 미용실을 운영하는 지민은 어느날 손님으로 찿아온 민우의 얘기를 듣고 영업 전략을 바꿔서 새로운 직원을 뽑는다 이때부터 미용실로 밀려오는 손님들로 즐거운 비명을 지른다 과연 갑자기 손님이 늘어나게 된 이 수상한 미용실의 영업비밀은 무엇일까?', 'https://image.tmdb.org/t/p/w500/75AcuuTJ6T0qM7SmrCIMl2w30O9.jpg', 2021, 0, 0, '2026-06-08 06:27:28.315587', 'KR');
INSERT INTO public.movies VALUES (568, 1317149, '아이 스웨어', '["Drama"]', 'Kirk Jones', '["Robert Aramayo", "Maxine Peake", "Peter Mullan", "Shirley Henderson", "Scott Ellis Watson"]', NULL, 'https://image.tmdb.org/t/p/w500/vUwyhNWBKkSwK8ELvEeBRwV724h.jpg', 2025, 0, 0, '2026-06-06 13:25:17.990057', 'GB');
INSERT INTO public.movies VALUES (574, 127585, '엑스맨: 데이즈 오브 퓨처 패스트', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '돌연변이들을 멸종시키기 위해 제작된 로봇 센티넬이 인간들까지 모조리 말살하는 2023년. 인류의 종말이 코앞에 닥친 상황에서 프로페서X와 매그니토는 과거를 통해 미래의 운명을 바꾸고자 한다. 울버린은 트라스크가 센티넬을 개발하는 것을 막기 위해 1973년으로 보내진다. 1973년의 찰스는 절망에 빠진 채 행크 맥코이와 함께 은둔 생활을 하고 있고, 에릭은 케네디 대통령 암살 용의자로 붙잡혀 펜타곤 지하 깊숙한 곳에 위치한 수용소에 갇혀 있다.', 'https://image.tmdb.org/t/p/w500/zm5zanw86TX2T7qJNTKilL3x3S8.jpg', 2014, 0, 0, '2026-06-06 13:25:18.005585', 'US');
INSERT INTO public.movies VALUES (303, 617126, '판타스틱 4: 새로운 출발', '["Sci-Fi", "Adventure", "Action"]', 'Matt Shakman', '["Pedro Pascal", "Vanessa Kirby", "Ebon Moss-Bachrach", "Joseph Quinn", "Ralph Ineson"]', '1960년대, 전 세계적인 관심 속 우주로 떠난 4명의 엘리트 우주비행사 ‘리드 리처드’, ‘수잔 스톰’, ‘조니 스톰’, ‘벤 그림’은 예기치 못한 사고로 우주 방사능에 노출되면서 초인적인 능력을 갖게 된다. 신체를 자유자재로 변형할 수 있게 된 ‘리드 리처드’(미스터 판타스틱)부터 온몸이 투명해지고, 강력한 방어막을 형성하는 ‘수잔 스톰’(인비저블 우먼), 온몸으로 뜨거운 화염을 내뿜으며 비행 능력까지 지닌 ‘조니 스톰’(휴먼 토치), 그리고 바위 같은 엄청난 피지컬과 압도적 파워를 갖춘 ‘벤 그림’(씽)까지 ‘판타스틱4’라는 새로운 슈퍼 히어로 팀이 된 4명의 멤버들. 인생에 완전히 새로운 국면을 맞이하게 되면서 혼란과 갈등에 휩싸인 이들 앞에 행성 파괴자 ‘갤럭투스’의 위협을 전달하는 미스터리한 전령 ‘실버서퍼’가 등장해 지구 파괴를 예고하고 ‘판타스틱 4’는 세상을 구하기 위해 다 함께 힘을 모으게 되는데…', 'https://image.tmdb.org/t/p/w500/vXvcMeUL6dGr9iBhNOMG3SPRHGA.jpg', 2025, 0, 0, '2026-06-06 13:25:07.936077', 'US');
INSERT INTO public.movies VALUES (546, 1654429, '扫恶', '["Action", "Crime"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/xDFlWTgY60FiBW1QiGbm1KwwBd7.jpg', 2026, 0, 0, '2026-06-06 13:25:17.205364', 'US');
INSERT INTO public.movies VALUES (4133, 611291, '브링 더 소울: 더 무비', '["Documentary"]', 'Park Jun-soo', '["RM", "Jin", "Suga", "j-hope", "Jimin"]', '2018년 방탄소년단 월드 투어 ‘러브 유어셀프’(BTS WORLD TOUR ‘LOVE YOURSELF’) 당시, 서울을 시작으로 수많은 도시를 지나 파리에서 유럽 투어의 기나긴 대장정을 마친 방탄소년단이 투어를 마친 다음 날, 파리의 작은 루프탑 테이블에서 그들만의 작은 뒷풀이를 담아낸 영화', 'https://image.tmdb.org/t/p/w500/uQI0fm8uPild3U5spX0I6MapSHB.jpg', 2019, 0, 0, '2026-06-08 06:27:29.36193', 'KR');
INSERT INTO public.movies VALUES (565, 587412, '케이.지.에프 : 챕터 2', '["Action", "Thriller", "Adventure", "Crime"]', 'Prashanth Neel', '["Yash", "Sanjay Dutt", "Raveena Tandon", "Srinidhi Shetty", "Archana Jois"]', NULL, 'https://image.tmdb.org/t/p/w500/aN30pwRBhRo1NS6ILAz3ejxXb0g.jpg', 2022, 0, 0, '2026-06-06 13:25:17.982212', 'IN');
INSERT INTO public.movies VALUES (573, 9806, '인크레더블', '["Action", "Adventure", "Animation", "Family"]', NULL, '[]', '밥 파는 한때 미스터 인크레더블이라는 이름으로 불리며 보이지 않는 곳에서 악의 무리들을 일망타진하던 슈퍼히어로 가정의 든든한 버팀목이자 정신적 지주인 그는 슈퍼히어로였다가 외압에 의하여 평범한 아버지이자 남편으로 바뀐 자신의 변신을 받아들이기 힘들어한다. 그러던 어느 날 집으로 돌아온 그에게 출처를 알 수 없는 지령이 떨어진다.  출동할 곳은 본토와 아득히 떨어진 섬, 특명을 내린 사람을 알 수 없는 1급 비밀작전. 은퇴한지 15년, 이미 몸은 초강력 허리띠조차 튕겨버릴 정도로 망가져버린 그가 다시 빛나는 영웅으로 복귀할 수 있을지...', 'https://image.tmdb.org/t/p/w500/11Byg6rHkKIvSehlW3R4pcUj8J.jpg', 2004, 0, 0, '2026-06-06 13:25:18.002961', 'US');
INSERT INTO public.movies VALUES (572, 781732, '애니멀', '["Action", "Crime", "Drama"]', 'Sandeep Reddy Vanga', '["Ranbir Kapoor", "Rashmika Mandanna", "Anil Kapoor", "Bobby Deol", "Triptii Dimri"]', '힘있는 기업가의  아들이 해외에서 더 강해져서 돌아와 아버지의 목숨을 위협하는 자들에게 피비린내 나는 복수를 하겠다고 다짐한다.', 'https://image.tmdb.org/t/p/w500/hr9rjR3J0xBBKmlJ4n3gHId9ccx.jpg', 2023, 0, 0, '2026-06-06 13:25:18.000457', 'IN');
INSERT INTO public.movies VALUES (569, 633604, '냠냠', '["Horror", "Comedy"]', NULL, '[]', 'F컵 소녀 알리슨은 유달리 큰 가슴이 무겁기만 하고 쳐다보는 남자들의 시선도 끔찍할 뿐이다. 결국 알리슨은 만류하는 모친과 딱히 내키지 않아하는 듯한 남자친구 미카엘과 함께 전문 성형외과를 찾는다. 꿈에 그리던 B컵 가슴을 얻기 바로 직전, 병원의 은밀한 실험으로 인해 탄생한 좀비의 습격으로 알리슨과 미카엘은 생존을 위한 병원 탈출을 시도한다.', 'https://image.tmdb.org/t/p/w500/nychvxBaGEijaMmgRzkeMNSfPpT.jpg', 2019, 0, 0, '2026-06-06 13:25:17.992612', 'US');
INSERT INTO public.movies VALUES (620, 698508, '리디밍 러브', '["Romance", "Drama"]', NULL, '[]', '올 봄, 이 사랑이 당신을 꿈꾸게 한다!  누구나 품을 수 있지만, 누구도 소유할 수 없는 ‘엔젤’  단 한 번도 원하는 삶을 살아본 적 없던 그녀에게 운명처럼 오직 그녀를 사랑하는 남자가 나타난다. 무조건적인 그의 사랑에 ‘엔젤’은 매번 도망치지만 조금씩, 그리고 천천히 진정한 세상을 알아가는데…', 'https://image.tmdb.org/t/p/w500/fiwiBgJNkRoDA1snWnPNxXVv4R.jpg', 2022, 0, 0, '2026-06-06 13:25:19.583863', 'US');
INSERT INTO public.movies VALUES (190, 796, '사랑보다 아름다운 유혹', '["Drama", "Romance"]', 'Roger Kumble', '["Sarah Michelle Gellar", "Ryan Phillippe", "Reese Witherspoon", "Selma Blair", "Louise Fletcher"]', '맨하탄의 최상류층 자제인 캐더린(사라 미셸 겔러)과 세바스찬(라이언 필립)은 의붓 남매 사이이다. 캐더린의 남자 친구가 순진한 세실에게 마음을 빼앗기자 질투가 생긴 캐더린은 세바스찬에게 세실을 유혹해 잠자리를 같이 해 달라고 부탁한다.  세바스찬은 많은 여성을 농락한 경험이 있는 남자로 캐더린의 부탁을 들어주는데 세실은 엉뚱하게도 자신의 첼로 교습을 맡고 있는 로날드와 사랑에 빠진다.  그러던 어느 날 세바스찬에게 새로운 유혹 목표가 생기는데, 학장의 딸 아네트(리즈 위더스푼)가 바로 그 상대이다. 세바스찬은 캐더린과 가을 학기가 되기 전까지 아네트를 침대로 끌어들일 수 있다는 것에 내기를 건다. 만일 세바스찬이 실패하면 세바스찬이 아끼는 재규어를 주고 이기면 그들의 부모가 결혼하기 전부터 세바스찬이 원하던, 캐더린과의 잠자리를 허락한다는 것이다.  그러나 세바스찬은 아네트로 인해 진정한 사랑과 기쁨을 느끼게 되고, 아네트 역시 세바스찬에게 조금씩 마음을 여는데...', 'https://image.tmdb.org/t/p/w500/7XczYr1AY4e1z3xUOpJoZYuR7B0.jpg', 1999, 0, 0, '2026-06-06 13:25:03.339346', 'US');
INSERT INTO public.movies VALUES (2410, 985939, '폴: 600미터', '["Thriller"]', 'Scott Mann', '["Grace Caroline Currey", "Virginia Gardner", "Jeffrey Dean Morgan", "Mason Gooding", "Jasper Cole"]', '내려갈 길이 끊겨버린 600미터 TV 타워 위에서  두 명의 친구가 살아남기 위해 펼치는 사상 최초의 고공 서바이벌 여기에서', 'https://image.tmdb.org/t/p/w500/uyiALGPVtVsrTY4YHSq2osSYls5.jpg', 2022, 0, 0, '2026-06-07 12:17:31.214184', 'US');
INSERT INTO public.movies VALUES (364, 2251, '언페이스풀', '["Thriller", "Drama", "Romance"]', 'Adrian Lyne', '["Diane Lane", "Richard Gere", "Olivier Martinez", "Erik Per Sullivan", "Željko Ivanek"]', '결혼 10년차 부부 에드워드 섬너와 코니 섬너. 8살 아들과 함께 뉴욕 교외에 살고 있는 이 부부는 무엇하나 부러울 것 없는 이상적이고 행복한 삶을 영위하고 있다. 그러던 어느날, 뉴욕 시내로 쇼핑을 나갔던 코니가 우연히 사고를 당하게 되고, 폴 마텔이라는 젊은 프랑스 남자가 치료를 자처한다. 처음에는 견제의 눈길을 감추지 못하던 코니도 어딘지 모를 폴의 신비스런 매력에 긴장을 풀게 된다. 다시 일상으로 돌아온 코니. 사랑하는 남편과 아들이 곁에 있지만 문득문득 떠오르는 폴의 웃음과 말투에 다시 한번 폴을 만나겠다는 결심을 하게 되고, 이렇게 폴과 코니는 위험스럽게 서로에게 탐닉하게 되는데.', 'https://image.tmdb.org/t/p/w500/vXl4cigeyWPOYOjaHcnXcb6Dfb3.jpg', 2002, 0, 0, '2026-06-06 13:25:10.210433', 'US');
INSERT INTO public.movies VALUES (578, 1522079, 'సతీ లీలావతి', '["Comedy", "Drama", "Romance"]', 'Tatineni Satya', '["Lavanya Tripathi", "Dev Mohan", "Madonna Sebastian", "Naresh", "VTV Ganesh"]', NULL, 'https://image.tmdb.org/t/p/w500/7lRCDsm8vTA8VIdfkDXEe4UK70C.jpg', 2026, 0, 0, '2026-06-06 13:25:18.014947', 'IN');
