INSERT INTO public.movies VALUES (581, 1031774, '스릴러 40', '["Documentary"]', NULL, '[]', '마이클 잭슨의 앨범 스릴러의 제작 과정과 그의 삶을 담은 다큐멘터리', 'https://image.tmdb.org/t/p/w500/5LOKk1Ca1YaCb3EjTEMDJdPbQxN.jpg', 2023, 0, 0, '2026-06-06 13:25:18.747725', 'US');
