INSERT INTO public.movies VALUES (584, 1181678, '¿Quieres ser mi hijo?', '["Comedy", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/6PQJsmuvSMZQMmlJfTpjIkrizUh.jpg', 2023, 0, 0, '2026-06-06 13:25:18.755487', 'US');
INSERT INTO public.movies VALUES (588, 508947, '메이의 새빨간 비밀', '["Animation", "Family", "Comedy", "Fantasy"]', NULL, '[]', '엄마의 착한 딸, 아니면 미운 13살? 성적도 우수하고 친구들과 사이도 좋은 데다 부모와도 친밀한 관계를 유지하고 있는, 똑 부러지면서도 엉뚱한 매력의 소유자 메이는 요즘 질풍노도의 시기를 겪느라 고민이 많다. 이 나이에 엄마의 과잉보호를 받자니 스트레스가 이만저만이 아닌 데다, 관심사, 인간관계, 신체 등 그녀의 모든 것이 변하고 있기 때문. 그런데 이 와중에 흥분하면 거대한 레서판다로 변신하는 비밀까지 떠안게 되다니! 아침도 먹어야 하고 학교도 가야 하는데, 이 엄청난 비밀을 어떻게 숨겨야 할까?', 'https://image.tmdb.org/t/p/w500/94C3iked9vCmCxmXdQkV2oBubqt.jpg', 2022, 0, 0, '2026-06-06 13:25:18.765', 'US');
INSERT INTO public.movies VALUES (587, 920, '카', '["Animation", "Adventure", "Comedy", "Family"]', NULL, '[]', '화려한 성공과 갈채를 꿈꾸는 주인공 라이트닝 맥퀸은 경주에서 성공하는 것만이 인생의 모든 것이라 생각하는 타오르는 청춘. 하지만 피스톤 컵 챔피온쉽에 참가하기 위해 달리던 중 경쟁과 함성과는 동떨어진 래디에이터 스프링스란 한적한 시골로 들어서게 된다. 이제는 지도에 조차 표시되지 않는 한적한 66번 국도. 조용하지만 다양한 캐릭터들이 큰 열정을 간직하고 있는 이곳에서 맥퀸은 미스터리한 과거를 지닌 닥 허드슨과 샐리, 그리고 메이터를 만나게 된다. 그들을 통해 인생이란 목적지가 아닌, 여행하는 과정 그 자체이며 명성과 스폰서, 트로피 뒤에 가려진 소중한 가치를 깨닫게 되는데...', 'https://image.tmdb.org/t/p/w500/uwQMfpTRXQUHvGKtnHGdQE7nZWv.jpg', 2006, 0, 0, '2026-06-06 13:25:18.762749', 'US');
INSERT INTO public.movies VALUES (591, 370663, '빌로우 허', '["Drama", "Romance"]', NULL, '[]', '누구나 한번 보면 빠져들 수밖에 없는 매력을 지녔지만 사랑을 믿지 않기에 늘 상처받는 그녀, 달라스. 패션 에디터로 성공한 커리어우먼의 삶을 살고 있지만 단조로운 일상에 지친 그녀, 재스민. 어느 날 우연히 한 파티에서 달라스를 만난 재스민은  그녀만을 바라보는 달라스의 강렬한 눈빛에 흔들리기 시작한다. 자신도 모르게 서로에게 운명처럼 이끌린 두 사람은  남들 시선은 신경 쓰지 않고 뜨겁게 사랑하지만 피할 수 없는 현실의 장벽에 가로막히고 마는데…', 'https://image.tmdb.org/t/p/w500/5twlT43Kt18MoUCqYgfMqppVXfa.jpg', 2017, 0, 0, '2026-06-06 13:25:18.772218', 'US');
INSERT INTO public.movies VALUES (680, 713704, '이블 데드 라이즈', '["Horror", "Thriller"]', NULL, '[]', '오랜만에 집에 온 이모와 함께 먹을 피자를 사러갔다 돌아오는 길에 지진을 경험한 삼남매가 아파트 주차장 바닥에 난 틈 사이로 숨은 금고에서 책을 발견하고, 그 책에서 악령이 깨어나 악령과 맞서 필사적으로 싸우는 이야기를 다룬 영화', 'https://image.tmdb.org/t/p/w500/h67qcBzl7tnjd7zy3xQRRrQsG8H.jpg', 2023, 0, 0, '2026-06-06 13:25:21.889955', 'US');
INSERT INTO public.movies VALUES (592, 640, '캐치 미 이프 유 캔', '["Drama", "Crime"]', NULL, '[]', '1965년, FBI를 발칵 뒤집는 사건이 발생한다. 파일럿을 가장해 모든 비행기에 무임승차는 기본, 50개 주 은행을 순회하며 무려 140만 달러를 횡령한 희대의 사기꾼이 나타난 것. 21년 경력의 FBI 최고의 요원 칼 핸러티가 프랭크의 뒤를 쫓고, 드디어 프랭크의 호텔방을 덮친다. 하지만 칼과 마주친 프랭크는 정부 비밀요원으로 둔갑, 증거물을 챙긴다며 위조수표를 챙겨 들고 여유롭게 빠져나온다. 뒤늦게 자신이 속았음을 깨달은 칼은 자존심 회복을 결심한다. 그리고 마침내 찾은 프랭크의 가족. 하지만 자신을 속인 프랭크가 겨우 17살의 고등학생이라는 사실을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/1q4rV06m6PginBB4nAgYcG48Oik.jpg', 2002, 0, 0, '2026-06-06 13:25:18.774478', 'US');
INSERT INTO public.movies VALUES (4137, 398222, '용주골', '["Drama", "Romance"]', 'Choi Woo-seong', '["Lee Chae-dam", "Min Do-yoon", "Jin Seo-hyeon", "Joo Hyang-woon", "Park Jong-hwan"]', '은밀하고 가장 뜨거운 바로 그 곳! 사상 최대의 방송사고(!?)가 시작된다! 용주골의 생계형 건달 용화(민도윤)는 발길이 끊긴 손님들과 악덕 돈줄 강회장(박종환)에게 빚 독촉을 받다가 온라인에 유행하는 성인방송국을 시작하기로 결심한다. 용주골의 선수 끝판왕 섹시 BJ 마샬(이채담)을 내세워 순식간에 엄청난 반응을 끌어 모으는 용화. 성깔 있는 질투화신 BJ 방울(진서현)까지 가세해 순식간에 둘은 뜨거운 BJ 인기경쟁을 시작하는데... 과연, 이들의 화끈한 온라인 섹시스캔들은 성공할 수 있을까!??', 'https://image.tmdb.org/t/p/w500/z71W04S43PfM4Vdvz3NgGLEF7He.jpg', 2015, 0, 0, '2026-06-08 06:27:32.297175', 'KR');
INSERT INTO public.movies VALUES (2946, 53064, '지하환등극화소녀춘 미도리', '["Animation", "Drama", "Horror"]', 'Hiroshi Harada', '["Minako Naka", "Norihiko Morishita", "Keinosuke Okamoto", "Kazuyoshi Hayashi", "Yoshihiko Matsui"]', '다리밑에서 꽃을 팔던 가난한 소녀 미도리는 홀어머니가 돌아가시자 어느 서커스단에게 팔려가게 된다. 하지만 이 서커스단은 프릭쇼라는 기형적인 사람들을 구경거리로 삼는 곳이였다. 이곳에서 미도리는 매일 단원들에게 학대를 당하게 되는데...', 'https://image.tmdb.org/t/p/w500/jf504pce65Bc6CcCR2btQDN3cA2.jpg', 1992, 0, 0, '2026-06-07 12:17:55.324246', 'JP');
INSERT INTO public.movies VALUES (681, 1658214, 'Scorpio Nights 4', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/lhgGvrHkwu9mtNeAhzaG828boH4.jpg', 2026, 0, 0, '2026-06-06 13:25:22.611559', 'US');
INSERT INTO public.movies VALUES (610, 255709, '소원', '["Drama"]', 'Lee Joon-ik', '["Sul Kyung-gu", "Uhm Ji-won", "Lee Re", "Kim Sang-ho", "Kim Hae-sook"]', '어느 비 오는 아침, 학교를 가던 9살 소녀 소원은 술에 취한 아저씨에게 끌려가 믿고 싶지 않은 사고를 당한다. 이 일로 몸과 마음에 지울 수 없는 상처를 받은 소원이네 가족. 하지만 절망 끝에서 희망을 찾아 나서는데...', 'https://image.tmdb.org/t/p/w500/PZlNvDwKwHeHUsXnd6SEDXWZNn.jpg', 2013, 0, 0, '2026-06-06 13:25:19.559269', 'KR');
INSERT INTO public.movies VALUES (606, 300496, 'Nefeli', '["Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/4EgkcisexFjGfQmGI0IrVxZUBIv.jpg', 1980, 0, 0, '2026-06-06 13:25:19.54896', 'US');
INSERT INTO public.movies VALUES (607, 185664, '단 오니로쿠: 밧줄 지옥의 수녀', '["Drama", "Horror"]', 'Katsuhiko Fujii', '["Miki Takakura", "Maya Ito", "Asami Ogawa", "Hiroshi Unayama", "Hiromi Yamaguchi"]', '단 오니로쿠의 원작 - 타카코는 연인의 아내가 그들을 현장에서 붙잡은 후 수녀원에 들어간다. 그녀는 수녀들과 성공한 작가가 퇴폐적인 S&M에 관여하기 위해 공모했다는 것을 곧 알게 된다.', 'https://image.tmdb.org/t/p/w500/wne8L5rLN4ZBOSsIt8uh6t8eyqY.jpg', 1984, 0, 0, '2026-06-06 13:25:19.551239', 'JP');
INSERT INTO public.movies VALUES (609, 47971, '트리플 엑스 리턴즈', '["Action", "Adventure", "Crime"]', 'D.J. Caruso', '["Vin Diesel", "Donnie Yen", "Ruby Rose", "Deepika Padukone", "Toni Collette"]', '전설의 스파이 샌더 케이지는 자취를 감춘 채 살아가던 중, 기븐스 요원의 뒤를 이어 ‘트리플 엑스’ 프로젝트 시작하라는 임무를 받게 된다. 흩어져 있던 남다른 개성을 지닌 최정예 스파이 요원들은 샌더 케이지를 중심으로 모이게 되고, 마침내 재결성된 최강의 스파이 군단 ‘트리플 엑스’는 전세계를 위협하는 판도라 박스를 되찾기 위한 사상 최악의 미션에 돌입하는데…', 'https://image.tmdb.org/t/p/w500/eTJVHRrWnK5Cv7vCxmwqFksbYm1.jpg', 2017, 0, 0, '2026-06-06 13:25:19.555912', 'US');
INSERT INTO public.movies VALUES (2940, 500, '저수지의 개들', '["Crime", "Thriller"]', NULL, '[]', '동부 LA 폐허의 텅빈 창고 안. 대규모 보석 강도를 위해 서로를 전혀 모르는 6명의 프로갱들이 한곳에 모인다. 이들을 한 곳에 불러 모은 장본인은 프로 도둑인 죠 캐봇과 그의 아들 나이스 가이 에디. 다이아몬드 도매상을 강탈하는 보석강도의 전 과정을 지휘하는 이 두 사람은 6명의 갱들에게 각각의 가명을 지정하고, 서로의 신분을 노출시킬 어떠한 정보 교환도 하지 말 것을 지시한다. 거사에 성공한 갱들은 그들 앞으로 돌아올 거액을 꿈구며 환호성을 지른다. 그러나 환호성도 잠시, 그들의 강도짓이 끝나기를 기다리며 문밖에 대기하고 있던 경찰을 발견한 그들은 경악하는데...', 'https://image.tmdb.org/t/p/w500/3RmF67rohiTKfNOixinNveLsX2T.jpg', 1992, 0, 0, '2026-06-07 12:17:54.499304', 'US');
INSERT INTO public.movies VALUES (597, 1042834, '에덴', '["Thriller", "Drama"]', NULL, '[]', '환멸에 빠진 아웃사이더들이 현대 사회를 버리고 새로운 시작을 찾아 나선다. 외딴 무인도에 정착한 그들의 유토피아적 꿈은 순식간에 무너진다. 가장 큰 위협은 혹독한 기후나 치명적인 야생 동물이 아니라 바로 서로라는 사실을 깨닫기 때문이다.', 'https://image.tmdb.org/t/p/w500/yMpVNYbdYwaMy3SWkaZYOkurKOe.jpg', 2025, 0, 0, '2026-06-06 13:25:18.785616', 'US');
INSERT INTO public.movies VALUES (608, 744, '탑건', '["Action", "Drama", "Romance"]', NULL, '[]', '해군 최신예 전투기인 F-14기를 모는 젊은 조종사 매버릭 대위는 훌륭한 전투기 조종사였던 아버지를 둔 패기만만한 파일럿 청년. 솜씨가 거칠기로 소문난 그는 탑 건 훈련학교에 입학하면서 인생의 전환을 맞게 된다. 가장 큰 변화는 항공물리학을 강의하는 여교관 찰리와 사랑에 빠진 것. 하지만 매버릭이 조종하던 F-14 전투기가 비행 훈련 도중 그만 제트 기류에 빠지면서 엔진 고장을 일으키고, 이때 함께 탈출을 시도하던 구즈가 사망하는 사고가 발생하고 마는데...', 'https://image.tmdb.org/t/p/w500/oqn0k8FbQ5mKXk5WbtKrvHwV5yV.jpg', 1986, 0, 0, '2026-06-06 13:25:19.553517', 'US');
INSERT INTO public.movies VALUES (598, 270946, '마다가스카의 펭귄', '["Family", "Animation", "Adventure", "Comedy"]', NULL, '[]', '넘치는 유머, 감쪽 같은 위장술, 똑소리 나는 브레인! 날 때부터 남달랐던 악동 펭귄 스키퍼, 코왈스키, 리코, 프라이빗! 어느 날 그들 앞에 복수심에 불타는 문어박사 옥토브레인이 나타나고, 그의 거대한 음모를 알게 된 펭귄 4총사는 비밀 조직 ‘노스윈드’와 함께 세상을 구할 사상 최대의 작전을 펼치는데…!', 'https://image.tmdb.org/t/p/w500/ft5SBKI0MFZpdW1tlG75XD9JeHO.jpg', 2014, 0, 0, '2026-06-06 13:25:18.787802', 'US');
INSERT INTO public.movies VALUES (605, 1029575, '''패밀리 플랜'' - The Family Plan', '["Action", "Comedy", "Adventure"]', NULL, '[]', '헌신적인 남편이자 사랑이 넘치는 아버지, 그리고 자동차 영업왕인 댄 모건. 전직 킬러라는 과거가 그의 발목을 붙잡으려 하자, 댄은 아무것도 모르는 가족들을 데리고 기상천외한 로드 트립을 떠난다.', 'https://image.tmdb.org/t/p/w500/oMTuRG8koeKqH2tVonaWhyp7OBw.jpg', 2023, 0, 0, '2026-06-06 13:25:19.546091', 'US');
INSERT INTO public.movies VALUES (4138, 475812, '올래 - 천사들의 도시편', '["Romance"]', 'NS. Tak', '["Jo Wan-jin", "Papichaya Prapatanan", "Watcharaporn Wongchai", "Yoon Dong-gyoo", "Walaipech Link Khunthira"]', '"본격 아시아 섹플레이스 투어 프로젝트, 첫 번째 이야기!  직장에서 막 쫒겨난 일봉에게 친구와 선배의 진심어린 조언.  “넌 처자식도 없으면서 인생 졸라 재미없게 산다!”  “해외여행? 한 달에 술 두어 번 안 먹고 안마 한 번 안가면 갈 수 있어, 인마!” 만취로 성사된 일봉이의 첫 해외여행!  천사들의 도시, 필리핀 클락에 가다! 일봉의 첫눈에 반해버린 씨야와의 우연 아닌 인연!  언젠가 한국에 데리고 가서 살겠다는 준식의 애인 미나의 속사정!?  한 번도 안 가본 사람은 있어도, 한번 만 가본 사람은 없다는,  천사들의 도시 속 섹스러운 여정이 펼쳐진다!  필리핀으로 올래?!"', 'https://image.tmdb.org/t/p/w500/n5qyICO54IiZRY3NmUC2ThCSilT.jpg', 2017, 0, 0, '2026-06-08 06:27:32.984489', 'KR');
INSERT INTO public.movies VALUES (2947, 337339, '분노의 질주: 더 익스트림', '["Action", "Crime", "Thriller"]', NULL, '[]', '마침내 평화로운 일상으로 돌아온 리더 도미닉(빈 디젤)과 멤버들. 하지만 레티(미셸 로드리게스)와 쿠바에서 신혼을 만끽 중인 도미닉(빈 디젤)에게 불청객이 찾아온다. 전설적인 해커이자 테러 조직의 리더 사이퍼(샤를리즈 테론)는 도미닉을 협박해 자신의 명령을 따르게 한다. 멤버들은 도미닉이 사이퍼와 함께  사상 최악의 테러를 계획하고 있음을 알게 된다.  리더의 배신으로 위기에 놓인 멤버들은 한때 팀을 모두 전멸시키려 했던 데카드 쇼(제이슨 스타뎀)까지 영입해  최악의 적이 되어버린 도미닉과의 피할 수 없는 대결을 앞두게 되는데...', 'https://image.tmdb.org/t/p/w500/h7tvYU9kN4pKjCIzUhf6PLNhQHT.jpg', 2017, 0, 0, '2026-06-07 12:17:55.326533', 'US');
INSERT INTO public.movies VALUES (616, 1315303, '프라이메이트', '["Horror", "Thriller"]', NULL, '[]', '광견병에 걸린 침팬지 ''벤''에게서 벗어나 생존하려는 주인공 ''루시''와 친구들의 이야기를 그린 공포 영화', 'https://image.tmdb.org/t/p/w500/4Q5IClJJyKUHKNLywQaqwcK00OF.jpg', 2026, 0, 0, '2026-06-06 13:25:19.573097', 'US');
INSERT INTO public.movies VALUES (612, 637, '인생은 아름다워', '["Comedy", "Drama"]', NULL, '[]', '로마에 갓 상경한 시골 총각 귀도는 운명처럼 만난 여인 도라에게 첫눈에 반한다. 넘치는 재치와 유머로 약혼자가 있던 그녀를 사로잡은 귀도는 가정을 꾸리며 분신과도 같은 아들 조수아를 얻는다. 조수아의 다섯 살 생일, 갑작스레 들이닥친 군인들은 귀도와 조수아를 수용소 행 기차에 실어버리고, 소식을 들은 도라 역시 기차에 따라 오른다. 귀도는 아들을 달래기 위해 무자비한 수용소 생활을 단체게임이라 속이고 1,000점을 따는 우승자에게는 진짜 탱크가 주어진다고 말한다. 하루하루가 지나 어느덧 전쟁이 끝났다는 말을 들은 귀도는 조수아를 창고에 숨겨둔 채 아내를 찾아 나서는데...', 'https://image.tmdb.org/t/p/w500/iyQ8pmCpmnPrGtaHMfmSvQLv8Fy.jpg', 1997, 0, 0, '2026-06-06 13:25:19.56397', 'US');
INSERT INTO public.movies VALUES (343, 98, '글래디에이터', '["Action", "Drama", "Adventure"]', 'Ridley Scott', '["Russell Crowe", "Joaquin Phoenix", "Connie Nielsen", "Oliver Reed", "Richard Harris"]', '죽을 날이 머지않은 황제 마르쿠스 아우렐리우스는 막시무스를 총애하여 아들이 아닌 그에게 권력을 넘겨주기로 한다. 황제의 아들 코모두스는 이에 질투와 분노를 느껴 황제를 살해한다. 왕좌를 이어받은 코모두스는 막시무스와 그의 가족을 죽이라고 명령한다. 가족을 모두 잃고 겨우 살아남은 막시무스는 노예로 전락하고, 투기장의 검투사가 된다. 그에게 남은 건 오직 황제 코모두스에 대한 복수 뿐. 검투사로서 매 경기마다 승리로 이끌면서 살아남자 그의 명성은 날로 높아 간다. 그러던 어느 날 오래 전 사랑했던 황제의 누이 루실라를 다시 만나게 되는데...', 'https://image.tmdb.org/t/p/w500/4mMwki6S1MfdBfsKTvP8xqaRnWh.jpg', 2000, 0, 0, '2026-06-06 13:25:09.447968', 'US');
INSERT INTO public.movies VALUES (617, 976573, '엘리멘탈', '["Animation", "Comedy", "Family", "Fantasy", "Romance"]', NULL, '[]', '불, 물, 공기, 흙 4개의 원소들이 살고 있는 엘리멘트 시티. 재치 있고 불처럼 열정 넘치는 앰버는 어느 날 우연히 유쾌하고 감성적이며 물 흐르듯 사는 웨이드를 만나 특별한 우정을 쌓으며, 지금껏 믿어온 모든 것들이 흔들리는 새로운 경험을 하게 되는데...', 'https://image.tmdb.org/t/p/w500/w7eApyAshbepBnDyYRjSeGyRHi2.jpg', 2023, 0, 0, '2026-06-06 13:25:19.575661', 'US');
INSERT INTO public.movies VALUES (2949, 1627792, 'Sagaran', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/x44TC1EEYDR7Qo6ZGECabsnzkdQ.jpg', 2026, 0, 0, '2026-06-07 12:17:55.331129', 'US');
INSERT INTO public.movies VALUES (619, 420817, '알라딘', '["Adventure", "Fantasy", "Romance", "Family"]', NULL, '[]', '알라딘은 전광석화 같은 손놀림과 타고난 삼십육계 줄행랑을 고루 갖춘 아그라바 왕국의 좀도둑이다. 원숭이 친구 아부를 대동한 채 굶주림에 고통받는 아이들을 못 본 척하지 않는 게 그의 인간적인 매력. 어느 날 아그라바 왕국을 다스리는 술탄이 애지중지하는 딸 자스민 공주가 백성들을 살피기 위해 성 밖으로 나왔다가 빵을 훔쳤다는 누명을 쓰게 된다. 마침 그 광경을 목격한 알라딘은 자스민 공주를 위기에서 구해준다. 자스민 공주가 왕궁에서 일하는 시녀인 줄 알고 그녀를 보러 성 안에 들어간 알라딘은 재상 자파에게 붙잡히고 마는데...', 'https://image.tmdb.org/t/p/w500/hvoi0h5hX7cKjatXvbc3gYqT1Xw.jpg', 2019, 0, 0, '2026-06-06 13:25:19.581484', 'US');
INSERT INTO public.movies VALUES (615, 383498, '데드풀 2', '["Action", "Comedy", "Adventure"]', NULL, '[]', '암 치료를 위한 비밀 실험에 참여한 후, 강력한 힐링팩터 능력을 지닌 슈퍼히어로 데드풀로 거듭난 웨이드 윌슨은 여자친구 바네사와 더없이 행복한 시간을 보낸다. 그러나 행복도 잠시, 눈 앞에서 소중한 연인을 잃어버리고 삶의 의미를 상실하지만 자기 치유 능력 때문에 죽고 싶어도 죽지를 못한다. 밑바닥까지 내려간 데드풀은 더 나은 사람이 되기로 결심한다. 한편 미래에서 온 케이블은 러셀을 집요하게 쫓는다. 데드풀은 팀 엑스포스를 결성하고, 뭘 해도 운이 따르는 도미노가 엑스포스에 합류하는데...', 'https://image.tmdb.org/t/p/w500/u4FChoDddutqEBP4L0AHhPbrCAk.jpg', 2018, 0, 0, '2026-06-06 13:25:19.570641', 'US');
INSERT INTO public.movies VALUES (618, 1893, '스타워즈 에피소드 1: 보이지 않는 위험', '["Adventure", "Action", "Sci-Fi"]', NULL, '[]', '공화국력 BBY 32년, 공화국이 큰 분쟁에 휩싸인다. 상인 조직인 무역 연합이 암흑에 가린 세력의 조종을 받고 나부 행성을 봉쇄해버린 것. 분쟁을 해결하기 위해 은하계 원로 회의는 콰이곤 진과 오비완 케노비 두 제다이를 파견한다. 타투인 행성에서 그는 노예 구역에서 어머니와 살고 있는 아나킨 스카이워커라는 소년을 만나 그가 미래의 은하계를 구할 수 있는 강한 힘을 가진 인물임을 믿고 그를 데려간다. 한편 나부 행성이 침입을 받자 아미달라 여왕은 은하계 원로 회의에 도움을 청하나, 원로 회의는 힘을 상실한 상태로 나부 행성은 위험에 처하게 되는데...', 'https://image.tmdb.org/t/p/w500/pt7oxFkvQFzXD0ByCe1uJumL6vD.jpg', 1999, 0, 0, '2026-06-06 13:25:19.578002', 'US');
INSERT INTO public.movies VALUES (4140, 911835, '숙모', '["Romance"]', 'Lee Sang-soo', '["Yoo Ji-hyun", "Lee Soo", "Woo Yeol"]', '첫 휴가를 나온 영철은 자대 복귀 전, 숙모 집에 며칠 간 신세를 지게 된다.  미망인으로 살아가는 숙모는 성적인 외로움을 달래기 위해, 조카지만 훌쩍 커서 남성미를 물씬 뿜기는 군인으로 나타난 영철에게 점점 성적인 매력을 느끼게 된다.  스물한 살이 되도록 동정을 떼지 못한 영철도 숙모의 성숙한 여성미에 매력을 느끼게 되고, 숙모의 유혹에 빠져 영철은', 'https://image.tmdb.org/t/p/w500/zTZqwdxVPs0Qmx4gVejnWWdmudD.jpg', 2021, 0, 0, '2026-06-08 06:27:34.410669', 'KR');
INSERT INTO public.movies VALUES (923, 2493, '프린세스 브라이드', '["Adventure", "Family", "Fantasy", "Romance"]', NULL, '[]', '바람이 몹시 부는 추운 겨울밤, 감기에 걸려 누워있는 어린 소년에게 한 할아버지가 ''프린세스 브라이드''라는 책을 읽어주면서 이야기는 시작된다. 환상의 플로린 나라엔 아름다운 소녀 버터컵(Buttercup: 로빈 라이트 분)이 살고 있다. 소녀는 마음 속으론 ''분부시라면''이란 대답으로 무슨 일이든 들어주는 촌뜨기 일꾼 소년 웨스틀리(Westley: 캐리 엘위스 분)를 사랑하지만 곧 이웃 나라의 왕자 훔퍼딩크(Prince Humperdinck: 크리스 새런든 분)와 결혼하기로 돼 있다. 그러나 결혼식 직전에 전쟁 도발의 음모에 휩쓸려 세 악당에게 사로잡히게 된다. 이때 검은 복면의 남자가 나타나 세 악당과 차례로 결투해 버터컵을 구출한다. 그는 웨스틀리였다. 버터컵은 웨스틀리의 생명을 위해 어쩔 수 없이 왕자에게 돌아간다. 하지만 왕자는 약속을 어기고 웨스틀리를 죽이려하는데 웨스틀리와의 결투에 진 악당 이니고와 페직이 그를 위한 구출작전이 펼친다.', 'https://image.tmdb.org/t/p/w500/a0N2wr3rmnoeeDjErvqcxPvTs1L.jpg', 1987, 0, 0, '2026-06-06 13:25:31.928064', 'US');
INSERT INTO public.movies VALUES (2958, 44833, '배틀쉽', '["Thriller", "Action", "Adventure", "Sci-Fi"]', NULL, '[]', '전 세계 해군들이 한데 모여 훈련하는 림팩 다국적 해상 훈련. 해상 합동 훈련 첫날, 태평양 한 가운데에서 정체불명의 물체가 발견되고 쉐인 함장(리암 니슨)은 수색팀을 파견한다.  괴물체에 접근한 하퍼 대위(테일러 키취)가 몸체에 손을 가져다 댄 순간, 엄청난 충격과 함께 괴물체는 자신들을 보호하기 위한 거대한 장벽을 구축한다. 레이더도 통하지 않고, 부딪히는 순간 모든 걸 파괴시키는 엄청난 위력의 장벽을 시작으로 지구를 향한 대규모 선재 공격을 감행하는 외계의 존재들!  목적 조차 알 수 없는 그들의 엄청난 공격에 평화롭던 지구는 순식간에 초토화 되기 시작하고, 이들로부터 지구를 구하기 위해 육해공을 넘나드는 전 세계 연합군의 합동 작전이 펼쳐지는데…  정체를 알 수 없는 외계 존재와 전 세계 다국적 연합 군함의 전면전이 드넓은 바다 한가운데에서 시작된다!', 'https://image.tmdb.org/t/p/w500/w8cAiKre5Qk9Bc33Dj3YmhEmNvW.jpg', 2012, 0, 0, '2026-06-07 12:17:55.353415', 'US');
INSERT INTO public.movies VALUES (627, 411088, '인비저블 게스트', '["Drama", "Mystery", "Thriller"]', NULL, '[]', '의문의 습격으로 살해 당한 ‘로라’ ‘아드리안’은 연인의 죽음에 절망하고, 범인은 흔적도 없이 사라졌다.  유력한 용의자로 누명을 쓴 ‘아드리안’은 승률 100%의 변호사 ‘버지니아’를 선임한다.  그리고 자신의 무죄를 입증하기 위해 고군분투하던 중  과거 그와 ‘로라’가 은폐한 교통사고와 숨겨진 연관성을 찾게 되는데…  남은 시간은 단 3시간, 사건을 재구성해 무죄를 입증해야 한다!', 'https://image.tmdb.org/t/p/w500/1bS5Do7dmOzda4nSIUU4PAgDCgV.jpg', 2017, 0, 0, '2026-06-06 13:25:20.328261', 'US');
INSERT INTO public.movies VALUES (8794, 11631, '맘마미아!', '["Comedy", "Romance"]', 'Phyllida Lloyd', '["Amanda Seyfried", "Meryl Streep", "Pierce Brosnan", "Colin Firth", "Stellan Skarsgård"]', '그리스의 작은 섬에서 모텔을 운영하는 도나(메릴 스트립)의 딸 소피(아만다 사이프리드)는 연인 스카이와 행복한 결혼을 앞두고 있다. 그러나 완벽한 결혼을 꿈꾸는 그녀의 계획에 한가지 걸리는 것이 있으니, 바로 결혼식장에 자신의 손을 잡고 입장해 줄 아빠가 없다는 것. 결혼식을 앞두고 우연히 낡은 트렁크에서 엄마의 일기장을 발견한 소피는 아빠로 추정되는 세 남자의 이름을 발견하고 도나의 이름으로 이들을 결혼식에 초대한다. 마침내 결혼식이 다가오고 소피가 초대한 세 남자 샘(피어스 브로스넌), 해리(콜린 퍼스), 빌(스텔란 스카스가드)이 그리스 섬에 도착하면서 도나는 당황하게 되는데...', 'https://image.tmdb.org/t/p/w500/9fnWov6Mb7LJKA2dJLV9h1mcSnF.jpg', 2008, 0, 0, '2026-06-08 07:29:30.880785', 'GB');
INSERT INTO public.movies VALUES (624, 508442, '소울', '["Animation", "Family", "Drama", "Fantasy"]', NULL, '[]', '뉴욕에서 음악 선생님으로 일하던 조는 꿈에 그리던 최고의 밴드와 재즈 클럽에서 연주하게 된 그 날, 예기치 못한 사고로 영혼이 되어 태어나기 전 세상에 떨어진다. 탄생 전 영혼들이 멘토와 함께 자신의 관심사를 발견하면 지구 통행증을 발급하는 태어나기 전 세상. 조는 그 곳에서 유일하게 지구에 가고 싶어하지 않는 시니컬한 영혼 22의 멘토가 된다. 링컨, 간디, 테레사 수녀도 멘토되길 포기한 영혼 22, 꿈의 무대에 서려면 22의 지구 통행증이 필요한 조. 그는 다시 지구로 돌아가 꿈의 무대에 설 수 있을까?', 'https://image.tmdb.org/t/p/w500/qJiaB4RJMM5Oh6A4rqrEOHQUJbu.jpg', 2020, 0, 0, '2026-06-06 13:25:20.319031', 'US');
INSERT INTO public.movies VALUES (2951, 629, '유주얼 서스펙트', '["Drama", "Crime", "Thriller"]', NULL, '[]', '산 페드로 부두에서 27명이 사망하고 9,100만달러가 증발하는 유혈극이 벌어진다. 수사관 데이브 쿠얀은 끔찍한 사건 현장의 유일한 생존자인 버벌로부터 폭발 사고의 유력한 용의자로 지목되었던 5인에 대한 진술을 듣는다. 유치장에서의 만남으로 시작한  그들의 6주 간의 화려한 범죄 행각들이 버벌의 진술과 함께 속속 드러나기 시작한다. 하지만 정작 용의자들도 모르게 그들의 머리 위에 존재했던 전설 속의 악마와도 같은 지하 범죄 조직의 두목 카이저 소제의 존재가 부각되며, 쿠얀은 점점 혼란에 빠지기 시작한다.', 'https://image.tmdb.org/t/p/w500/cbgicjq4Q2OVvXlfd3PqRlLvqmf.jpg', 1995, 0, 0, '2026-06-07 12:17:55.335837', 'US');
INSERT INTO public.movies VALUES (625, 36557, '007 카지노 로얄', '["Adventure", "Action", "Thriller"]', 'Martin Campbell', '["Daniel Craig", "Eva Green", "Mads Mikkelsen", "Judi Dench", "Jeffrey Wright"]', 'MI6의 평범한 요원이던 제임스 본드. 체코에서의 암살 임무를 마치고 007로 승격된 그에게 첫번째 임무가 주어진다. 국제 테러조직의 자금줄로 알려진 수수께끼의 인물 르쉬프의 배후를 밝혀내는 것. 마다가스카에서 작전을 수행하던 007은 르쉬프가 몬테카를로의 카지노 로얄에서 무제한 배팅이 가능한 홀뎀 포커를 통해 테러자금을 모으려는 음모를 알아낸다. MI6의 상관 M은 제임스 본드의 위장 잠입과 자금 관리를 위해 베스퍼 린드를 파견하고, 서로의 능력을 의심하던 두 사람 사이에는 팽팽한 긴장감이 감돌지만 테러조직의 위협을 함께 겪으며 차츰 애틋한 연인관계로 발전한다.', 'https://image.tmdb.org/t/p/w500/2e9maVDTkHXjEB3Bk1oBvZ5Xs0M.jpg', 2006, 0, 0, '2026-06-06 13:25:20.321957', 'GB');
INSERT INTO public.movies VALUES (4142, 491584, '버닝', '["Mystery", "Drama", "Thriller"]', 'Lee Chang-dong', '["Yoo Ah-in", "Steven Yeun", "Jeon Jong-seo", "Kim Soo-kyung", "Choe Seung-ho"]', '유통회사 알바생 종수는 배달을 갔다가 어릴 적 같은 동네에서 살았던 친구 해미를 만난다. 종수는 해미에게서 아프리카 여행을 간 동안 자기가 키우는 고양이를 돌봐 달라는 부탁을 받는다. 여행에서 돌아온 해미는 아프리카에서 만난 벤이라는 정체불명의 남자를 종수에게 소개한다. 어느 날 벤은 해미와 함께 종수의 집으로 찾아와 자신의 비밀스러운 취미에 대해 고백한다. 그때부터 종수는 무서운 예감에 사로잡히게 되는데...', 'https://image.tmdb.org/t/p/w500/AlKlezuaJkP2lDEWbJxYv47GeDf.jpg', 2018, 0, 0, '2026-06-08 06:27:36.060778', 'KR');
INSERT INTO public.movies VALUES (8795, 4347, '어톤먼트', '["Drama", "Romance"]', 'Joe Wright', '["James McAvoy", "Keira Knightley", "Saoirse Ronan", "Romola Garai", "Vanessa Redgrave"]', '1935년 영국, 부유한 집안의 아름다운 딸 세실리아는 시골 저택에서 여름을 보내던 중 가정부의 아들이자 세실리아 집안의 도움으로 캠브리지 의대를 졸업한 로비와 마주친다. 어릴 때부터 서로에게 애틋한 마음이 있었지만 서로의 신분 차이 때문에 애써 자신의 마음을 부정하며 고백하지 못하던 이들은 그날 밤 서로의 사랑을 확인한다. 하지만 이들을 지켜본 세실리아의 동생 브라이오니의 오해로 로비는 억울한 누명을 쓰고 전쟁터로 끌려가게 된다. 이후 세실리아는 로비가 전쟁터에서 돌아오기만을 기다리며 간호사로 일하게 되고, 로비 또한 세실리아를 다시 만난다는 단 하나의 일념으로 전쟁터에서 살아남기 위해 애쓰는데…', 'https://image.tmdb.org/t/p/w500/xOwDTYsUUNriE7e9LauxB7k581J.jpg', 2007, 0, 0, '2026-06-08 07:29:31.617835', 'GB');
INSERT INTO public.movies VALUES (633, 957119, 'Sidelined: The QB and Me', '["Comedy", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/mSL6truNrWP1Bn9ng1rN0SkMI4f.jpg', 2025, 0, 0, '2026-06-06 13:25:20.344759', 'US');
INSERT INTO public.movies VALUES (353, 1495, '킹덤 오브 헤븐', '["Drama", "Action", "Adventure", "History"]', 'Ridley Scott', '["Orlando Bloom", "Eva Green", "Jeremy Irons", "David Thewlis", "Ghassan Massoud"]', '전쟁으로 가족을 잃고 깊은 슬픔에 잠겨있는 프랑스의 젊은 대장장이 발리안에게 부상당한 십자군 기사 고프리가 찾아온다. 무언가 비밀을 품고 있는 듯한 그의 정체는 바로 발리안의 아버지. 발리안에게 숨겨진 전사의 자질을 꿰뚫어본 고프리는 자신과 함께 떠날 것을 제안하고, 발리안은 성스러운 도시를 지키기 위한 영예로운 여정을 시작한다. 발리안은 고프리로부터 여러 가지 검술과 전술 등을 배우며 용맹한 전사로 거듭난다. 그리고 고프리가 죽기 직전 수여한 작위를 받아 정식기사가 되어 성스러운 도시 예루살렘의 국왕 볼드윈 4세에 대한 충성을 서약하는데...', 'https://image.tmdb.org/t/p/w500/bwQ4a50Jp0aU1jpoM4m1PbEzo36.jpg', 2005, 0, 0, '2026-06-06 13:25:09.473455', 'GB');
INSERT INTO public.movies VALUES (632, 604079, '롱 워크', '["Sci-Fi", "Thriller", "Horror"]', NULL, '[]', '"살아남고 싶다면, 멈추지 마라"INSERT INTO public.movies VALUES (540, 6977, '노인을 위한 나라는 없다', '["Crime", "Thriller"]', NULL, '[]', '사막 한 가운데서 사냥을 즐기던 모스는 총격전이 벌어진 듯 출혈이 낭자한 사건 현장을 발견한다. 모스는 물 한 모금을 갈구하는 단 한명의 생존자를 외면한 채 떠나다가 우연히 200만 달러가 들어있는 가방을 발견한다. 횡재를 했지만 물을 달라는 요구를 거절한 게 내심 꺼림칙했던 모스는 새벽녘에 현장을 다시 방문하게 되고, 때마침 마주친 경찰에게 쫓기는 신세가 되고 만다. 여기에 200만 달러가 든 가방을 찾는 살인마 안톤 시거와 보안관 벨이 끼어들면서 이야기는 혼돈과 폭력의 결말로 치달아 간다.', 'https://image.tmdb.org/t/p/w500/2SU078qZf8ZTNfl6XlqgYiQohhG.jpg', 2007, 0, 0, '2026-06-06 13:25:16.480073', 'US');
INSERT INTO public.movies VALUES (635, 85, '인디아나 존스: 레이더스', '["Adventure", "Action"]', NULL, '[]', '1936년 남아메리카. 인디아나 존스 박사는 험난한 밀림 지대를 헤치고 독거미와 온갖 부비트랩을 뚫고서 고대 문명의 동굴에 보관된 보물을 손에 넣는데 성공하지만, 마지막 순간 악덕 고고학자 벨로크에게 빼앗기고 만다.  대학으로 돌아온 인디에게 정보국 사람들이 찾아온다. 정부로부터 성서에 나오는 성궤를 찾으라는 명령을 받는은 인디는 단서를 하나하나 찾아가며 성궤의 행방을 추적해 나간다. 그런데 나치군들도 역시 전쟁에 가지고 나가기만 하면 모든 전쟁에서 승리를 거둘 수 있는 무서운 힘을 지닌 성궤를 찾아나서는데...', 'https://image.tmdb.org/t/p/w500/xB8nOHHz8bmuM3GoW3gFttUvEks.jpg', 1981, 0, 0, '2026-06-06 13:25:20.349899', 'US');
INSERT INTO public.movies VALUES (630, 284054, '블랙 팬서', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '유엔 폭탄 테러로 아버지를 잃은 와칸다의 왕자 티찰라는 시빌 워 이후 고국 와칸다로 돌아가 왕좌에 오른다. 와칸다의 새로운 지도자 블랙팬서가 된 그는 옛 연인이자 와칸다의 스파이 나키아, 호위 무사 오코예와 함께 최강 희귀 금속 비브라늄 폭탄 거래가 이뤄지는 부산을 찾는다. 폭탄 거래의 배후에 있는 인물은 와칸다와 묘종의 연이 있는 정체불명의 남자, 에릭 킬몽거. 그는 놀라운 위력으로 티찰라를 제압하고 와칸다의 새로운 왕이 되려 하고, 이에 블랙 팬서는 피할 수 없는 전쟁에 나서는데...', 'https://image.tmdb.org/t/p/w500/iRkknrX0rRxZHSL79W2Rax0EFsL.jpg', 2018, 0, 0, '2026-06-06 13:25:20.336542', 'US');
INSERT INTO public.movies VALUES (2959, 102899, '앤트맨', '["Sci-Fi", "Adventure", "Action"]', NULL, '[]', '하나뿐인 딸에게 멋진 아빠이고 싶지만 현실은 생계형 도둑인 스콧 랭. 하지만 전과자인 스콧의 새 출발은 번번이 좌절된다. 어느 날 그에게 몸을 자유자재로 늘리거나 줄일 수 있는 핌 입자를 개발한 과학자 행크 핌이 찾아와 수트와 헬멧을 건네며 앤트맨이 되어 줄 것을 요청한다. 행크는 앤트맨의 기술이 악용되는 것을 막기 위해 스콧에게 접근했고, 스콧을 앤트맨으로 훈련시켜 그 비밀기술을 훔쳐내려는 계획을 짠다. 어리둥절하지만 일단 한번 해보기로 결심한 스콧은 행크 핌의 딸인 호프의 도움을 받아 점차 히어로의 면모를 갖추어가게 되는데...', 'https://image.tmdb.org/t/p/w500/ewbQqebFMXqs2n1DEOS2CoDtGm.jpg', 2015, 0, 0, '2026-06-07 12:17:55.355971', 'US');
INSERT INTO public.movies VALUES (8687, 2334, '택시 3', '["Action", "Comedy", "Crime"]', 'Gérard Krawczyk', '["Samy Naceri", "Frédéric Diefenthal", "Bernard Farcy", "Emma Wiklund", "Marion Cotillard"]', '계획만 세우고 대책은 전혀 없는 어리버리한 형사 에밀리앙. 그리고 짭새를 세상에서 제일 싫어하고 정치, 사회, 문화, 경제에 아무런 관심이 없는 마르세이유 최고의 총알택시 운전기사 다니엘! 본인들은 원치 않았지만 독일 갱들과 일본 야쿠자 소탕 작전 성공으로 인해 마르세이유의 영웅이 되어 버린 에밀리앙과 다니엘의 울고 웃는 협공 작전이 다시 시작된다!  에밀리앙과 다니엘의 이번 상대는 정체모를 인라인 스케이트 라이더들! 바람같이 빠르게 도시의 하늘과 도로를 가르는 인라인 스케이트 라이더들이 평화로운 마르세이유에 비상을 걸었다! 화려한 익스트림 스포츠 개인기로 도시를 질주하며 약탈에 일삼는 인라인 스케이트 라이더 족들을 수배하기 위해 다시 한번 마르세이유 경찰청, 그리고 에밀리앙과 다니엘은 아주 특별한 작전을 펼친다!', 'https://image.tmdb.org/t/p/w500/qKqp7DeVNcpDchhBUEfDkca7JUo.jpg', 2003, 0, 0, '2026-06-08 07:27:03.591809', 'FR');
INSERT INTO public.movies VALUES (4145, 16318, '색즉시공', '["Comedy", "Romance"]', 'JK Youn', '["Im Chang-jung", "Ha Ji-won", "Choi Sung-kook", "Yoo Chae-young", "Jung Min"]', '군대 제대 후 늦깎이 대학생이 된 은식. 남보다 늦은 출발 때문에 고시 합격에 인생 목표를 건다. 하지만 대학에 들어가자마자 해병대 고참 성국을 만나게 되고 그의 꾐에 빠져 차력 동아리에 가입하고 만다. 불철주야 공부를 해도 모자랄 판에 웬 차력? 그런데 거기에 또 하나, 그의 꿈을 가로막는 장애가 있었으니.', 'https://image.tmdb.org/t/p/w500/eRCd4nqD3i4tAzIVeyd1zTNiRPD.jpg', 2002, 0, 0, '2026-06-08 06:27:38.168535', 'KR');
INSERT INTO public.movies VALUES (745, 454626, '수퍼 소닉', '["Action", "Sci-Fi", "Comedy", "Family"]', NULL, '[]', '소리보다 빠른 초고속 고슴도치 히어로 ''소닉''은 지구에 불시착한다. 그의 특별한 능력을 감지한 과학자 ‘닥터 로보트닉’은 세계 정복의 야욕을 채우려 하고, 경찰관 ‘톰’은 위험에 빠진 ‘소닉’을 돕기 위해 나서는데…! 과연, ‘소닉''은 천재 악당에 맞서 지구를 지킬 수 있을까?', 'https://image.tmdb.org/t/p/w500/bhGOIk6lVNVDx082NDB2OlrjjWO.jpg', 2020, 0, 0, '2026-06-06 13:25:24.94284', 'US');
INSERT INTO public.movies VALUES (642, 615453, '너자', '["Animation", "Fantasy", "Adventure"]', NULL, '[]', '태을진인의 실수로 영주(선) 대신 마환(악)은 이정의 아들 나타로 환생한다. 3년 후, 천겁을 맞고 사라져야 할 운명을 타고난 나타는 마을을 혼란에 빠트려 사람들의 미움을 사게 된다. 세상에 파멸을 가져올 운명을 짊어진 나타의 마지막은 과연…', 'https://image.tmdb.org/t/p/w500/zb8xejiaNR0snSJgDepwFQUIi2e.jpg', 2019, 0, 0, '2026-06-06 13:25:21.090347', 'US');
INSERT INTO public.movies VALUES (641, 945961, '에이리언: 로물루스', '["Horror", "Sci-Fi"]', NULL, '[]', '2142년, 부모 세대가 맞닥뜨렸던 암울한 미래를 피하려는 청년들이 더 나은 삶을 찾기 위해 식민지를 떠날 계획을 세운다. 하지만 버려진 우주 기지 로물루스에 도착한 이들은 악몽과도 같은 에이리언의 무자비한 공격에 쫓기기 시작한다. 그 누구도 그들의 절규를 들을 수 없는 우주 한가운데, 생존을 위한 치열한 사투를 벌여야 하는데...', 'https://image.tmdb.org/t/p/w500/AmWTYg3RCMv7fbQxwCqrxiaUhkc.jpg', 2024, 0, 0, '2026-06-06 13:25:21.078047', 'US');
INSERT INTO public.movies VALUES (644, 941109, '더티 플레이', '["Crime", "Action", "Thriller", "Drama"]', NULL, '[]', '셰인 블랙 감독의 액션 가득한 스릴러 영화 <더티 플레이>에서 전문 도둑이 인생 최대의 강도 사건을 벌인다. 파커는 그로필드, 젠, 그의 숙련된 일당과 함께 뉴욕 마피아가 벌인 판에 휘말리게 되고, 그들과 맞서며 거친 머리싸움을 펼친다.', 'https://image.tmdb.org/t/p/w500/AnyBri87eZZ3FpvTVkJft6I7FEw.jpg', 2025, 0, 0, '2026-06-06 13:25:21.095988', 'US');
INSERT INTO public.movies VALUES (643, 14161, '2012', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '고대 마야 문명에서부터 끊임없이 회자되어 온 인류 멸망. 2012년, 저명한 과학자들은 오랜 연구 끝에 실제로 멸망의 시기가 다가오고 있음을 감지하고 각국 정부에 이 사실을 알린다. 그리고 곧 고대인들의 예언대로 전세계 곳곳에서는 지진, 화산 폭발, 거대한 해일 등 각종 자연 재해들이 발생해 그 누구도 막을 수 없는 최후의 순간이 도래한다. 한편, 이혼 후 가족과 떨어져 살던 소설가 잭슨 커티스(존 쿠삭)는 인류 멸망에 대비해 진행되어 왔던 정부의 비밀 계획을 알아차리고 가족과 함께 살아남기 위한 필사의 사투를 벌이는데…', 'https://image.tmdb.org/t/p/w500/kdyhLTaforuBk0CjnACiMXuj7zd.jpg', 2009, 0, 0, '2026-06-06 13:25:21.093356', 'US');
INSERT INTO public.movies VALUES (645, 701387, '부고니아', '["Sci-Fi", "Thriller", "Comedy"]', NULL, '[]', '벌들은 사라지고, 지구는 병들고 있고, 인류는 고통받고 있다. 거대 바이오 기업의 물류센터 직원인 테디는 이 모든 것이 은밀하게 진행되고 있는 외계인의 지구침공 계획 때문이고, 사장 미셸이 안드로메다에서 온 외계인이라고 굳게 믿는다. 오랜 준비 끝, 함께 사는 사촌 동생 돈과 함께 결국 미셸을 납치하는데 성공한 테디. 그는 지하실에 미셸을 감금한 채 지구를 찾아온 이유와 앞으로의 음모를 캐묻지만 자신은 외계인이 아니라는 말만 반복하는 미셸. 과연 테디는 미셸에게서 원하는 답을 얻고 지구를 지킬 수 있을까?', 'https://image.tmdb.org/t/p/w500/ko6Wxr4sB9RM3pJb5JlWPqiSOIp.jpg', 2025, 0, 0, '2026-06-06 13:25:21.098621', 'US');
INSERT INTO public.movies VALUES (638, 205596, '이미테이션 게임', '["History", "Drama", "Thriller"]', NULL, '[]', '매 순간 3명이 죽는 사상 최악의 위기에 처한 제 2차 세계대전. 절대 해독이 불가능한 암호 에니그마로 인해 연합군은 속수무책으로 당하게 된다. 결국 각 분야의 수재들을 모아 기밀 프로젝트 암호 해독팀을 가동한다. 천재 수학자 앨런 튜링은 암호 해독을 위한 특별한 기계를 발명하지만  24시간 마다 바뀌는 완벽한 암호 체계 때문에 번번히 좌절하고 마는데... 과연, 앨런 튜링과 암호 해독팀은 암호를 풀고 전쟁의 승리를 끌어낼 수 있을까…?', 'https://image.tmdb.org/t/p/w500/wT4cHJMqWqWxY4GXDXgD10lMQWy.jpg', 2014, 0, 0, '2026-06-06 13:25:20.357537', 'US');
INSERT INTO public.movies VALUES (4146, 554776, '정사 : 처제의 사랑', '["Drama", "Romance"]', 'Choi Min', '["Lee Chae-dam", "Do Mo-se", "Kim Ji-yeon"]', NULL, 'https://image.tmdb.org/t/p/w500/4roDAaF9Kpvd9ob6XLkoCRoDLkn.jpg', 2018, 0, 0, '2026-06-08 06:27:38.861534', 'KR');
INSERT INTO public.movies VALUES (4147, 21647, '색즉시공 시즌 2', '["Romance", "Comedy"]', 'Yoon Tae-yoon', '["Im Chang-jung", "Song Ji-hyo", "Choi Sung-kook", "Shin Yi", "Lee Sang-yun"]', '''색''에 굶주린 법대생. 남들 다 부러워하는 여친이 있음 뭘 해. 주야장천 키스만 입술 부르트게 하는데! 고시 준비도 막막, 색의 실천도 막막하던 차에 엄청난 라이벌까지 맞이하다니. 이제 여친이랑 진도 빼기는커녕 여친을 잃을 위기? 캠퍼스는 불철주야 끓어오르는 열기와 함께 오늘도 ‘색’을 실천하며 나날이 건강(?)해 지고 있다. 밤마다 모텔행의 실랑이가 벌어지고, 잠 못 이루는 기숙사에선 예측 불가능한 실험들이 난무하는데...', 'https://image.tmdb.org/t/p/w500/7CXkBFZvQ6kKeiDJeUQOZRyLHMl.jpg', 2007, 0, 0, '2026-06-08 06:27:39.568477', 'KR');
INSERT INTO public.movies VALUES (4148, 743814, '인민을 위해 복무하라', '["Drama"]', 'Jang Cheol-soo', '["Yeon Woo-jin", "Ji an", "Cho Seong-ha", "Jeong Gyu-su", "Kim Ji-chul"]', '모범사병으로 사단장 사택의 취사병이 된 ‘무광’. 그의 목표는 오직 아내와 아이를 위해 출세의 길에 오르는 것이다. 그러나, 사단장이 출장을 간 사이 시작된 그의 젊은 아내 ‘수련’의 위험한 유혹에 ‘무광’은 자신의 목표와 신념 그리고 빠져보고 싶은 금기된 사랑 사이에서 갈등을 겪는데…', 'https://image.tmdb.org/t/p/w500/rfKduNqGNmmAc6rw0GvK9K9vHFh.jpg', 2022, 0, 0, '2026-06-08 06:27:40.268376', 'KR');
INSERT INTO public.movies VALUES (8688, 1254808, '누벨바그', '["Comedy", "Drama", "History"]', 'Richard Linklater', '["Guillaume Marbeck", "Zoey Deutch", "Aubry Dullin", "Adrien Rouyard", "Antoine Besson"]', '1959년 파리, 젊은 비평가 ‘고다르’가 올해 최악의 영화이자 세기의 데뷔작이 될 <네 멋대로 해라>를 찍는 미친 모험의 시간으로 점프하는 리처드 링클레이터의 시네마 매직', 'https://image.tmdb.org/t/p/w500/y5UUa7KSStUar4rdCxvclOj3qvB.jpg', 2025, 0, 0, '2026-06-08 07:27:04.251115', 'FR');
INSERT INTO public.movies VALUES (654, 510657, 'Wellwood', '["Sci-Fi", "Horror", "Drama", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/vRwzVKNHeeQ9srX6u2qsuflBozb.jpg', 2025, 0, 0, '2026-06-06 13:25:21.120906', 'US');
INSERT INTO public.movies VALUES (648, 374720, '덩케르크', '["Action", "Drama"]', NULL, '[]', '제2차 세계대전 당시인 1940년, 프랑스 덩케르크 지역에서 진행된 연합군 구출 작전. 영화는 세개의 시공간을 동시에 진행시킨다. 도버 해협을 건너려는 영국군을 중심으로 한 잔교에서의 일주일, 민간 선박들의 자발적 참전과 차출이 이어지는 바다에서의 하루, 적기를 겨냥한 스피트파이어기 전투사가 있는 하늘에서의 한 시간. 전쟁의 전방위성, 공포의 상시성과 그 압도, 개별 공간을 떠난 공포의 유사성, 그 속의 다급함이 혼재되어 있는 가운데 전쟁과 죽음에의 공포와 생존을 향한 인간적 열망을 그린다.', 'https://image.tmdb.org/t/p/w500/nLQpUxLulXpIvN7FwREWjRNRBRI.jpg', 2017, 0, 0, '2026-06-06 13:25:21.107257', 'US');
INSERT INTO public.movies VALUES (8689, 1144430, '사라진 탄환 3', '["Action", "Crime", "Thriller", "Drama"]', 'Guillaume Pierret', '["Alban Lenoir", "Stéfi Celma", "Nicolas Duvauchelle", "Gérard Lanvin", "Pascale Arbillot"]', '복수의 여정을 끝내기 위해 돌아온 자동차 천재 리노. 자신의 인생을 망가뜨린 아레스키와 부패한 경정을 붙잡기 위한 추적에 나선다. 터보 엔진을 장착한 액션 삼부작의 완결편.', 'https://image.tmdb.org/t/p/w500/cd8ThAWer67IvETRmRm3NZFdhU2.jpg', 2025, 0, 0, '2026-06-08 07:27:04.91343', 'FR');
INSERT INTO public.movies VALUES (8796, 454983, '키싱 부스', '["Romance", "Comedy"]', 'Vince Marcello', '["Joey King", "Joel Courtney", "Jacob Elordi", "Molly Ringwald", "Stephen Jennings"]', '첫 키스를 해버린 엘, 그것도 학교의 인기 넘버원하고! 하지만 그는 넘봐선 안 될 사람. 그와 사랑에 빠지면 평생의 단짝을 잃게 된다. 새가슴 엘의 선택은?', 'https://image.tmdb.org/t/p/w500/cOeFUn1r2RNVYwVhelxwqfdxYL1.jpg', 2018, 0, 0, '2026-06-08 07:29:32.363452', 'GB');
INSERT INTO public.movies VALUES (651, 615173, '마녀 2', '["Action", "Mystery", "Thriller", "Sci-Fi"]', 'Park Hoon-jung', '["Shin Sia", "Park Eun-bin", "Seo Eun-soo", "Jin Goo", "Sung Yoo-bin"]', '자윤이 사라진 뒤, 정체불명의 집단의 무차별 습격으로 마녀 프로젝트가 진행되고 있는 아크가 초토화된다. 그곳에서 홀로 살아남은 소녀는 생애 처음 세상 밖으로 발을 내딛고 우연히 만난 경희의 도움으로 농장에서 지내며 따뜻한 일상에 적응해간다. 한편, 소녀가 망실되자 행방을 쫓는 책임자 장과 마녀 프로젝트의 창시자 백총괄의 지령을 받고 제거에 나선 본사 요원 조현, 경희의 농장 소유권을 노리는 조직의 보스 용두와 상해에서 온 의문의 4인방까지 각기 다른 목적을 지닌 세력이 하나 둘 모여들기 시작하면서 소녀 안에 숨겨진 본성이 깨어나는데…', 'https://image.tmdb.org/t/p/w500/cah6iIYQBctvCmBjsKGb1NCiygr.jpg', 2022, 0, 0, '2026-06-06 13:25:21.114292', 'KR');
INSERT INTO public.movies VALUES (639, 1724, '인크레더블 헐크', '["Sci-Fi", "Action", "Adventure"]', NULL, '[]', '실험 중 감마선에 노출된 이후 분노를 통제할 수 없는 상태가 되면 괴력을 지닌 녹색 괴물 헐크로 변하게 되는 브루스 배너. 필사적으로 치료제 개발에 매달리지만, 그의 능력을 이용하려는 정부와 군대의 끈질긴 추격을 받고 쫓기게 된다. 한편 헐크의 거대한 힘의 비밀을 파헤치던 이들은 헐크보다 더 파괴적인 어보미네이션을 만드는데 성공, 도시 전체를 집어삼키려 한다. 이에 브루스 배너는 정상적인 인생을 되찾으려던 계획을 버리고, 어보미네이션과 군대, 그리고 자기 자신과의 마지막 대결을 준비하는데...', 'https://image.tmdb.org/t/p/w500/hKoPe6G1piR73G1Lj9dHd5AG1b.jpg', 2008, 0, 0, '2026-06-06 13:25:20.360383', 'US');
INSERT INTO public.movies VALUES (652, 935505, '女教師仕置人　復讐の女神', '["Action"]', 'Yasuo Uchida', '["Reiko Kato", "Naoko Aizawa", "Mieko Arai", "Mayo Kawasaki"]', NULL, 'https://image.tmdb.org/t/p/w500/z6T7ZsZ9hEx4ssmeTuQhizdhJ2t.jpg', 1990, 0, 0, '2026-06-06 13:25:21.116519', 'JP');
INSERT INTO public.movies VALUES (649, 1659826, '彼女のプラウダ 河北彩伽', '["Romance"]', 'Paul Dodds', '["Saika Kawakita"]', NULL, 'https://image.tmdb.org/t/p/w500/g2MwVlxvEjawC6n1QYM5mejHnBU.jpg', 2025, 0, 0, '2026-06-06 13:25:21.109682', 'JP');
INSERT INTO public.movies VALUES (845, 2057, '오리지날 씬', '["Thriller", "Drama", "Mystery", "Romance", "History"]', NULL, '[]', '쿠바에 나타난 섹시함과 신비함을 지닌 여인 줄리아(안젤리나 졸리 역). 남자들은 그녀의 사랑을 얻기 위해 그 어떤 행동도 불사하지만, 그녀가 택한 사람은 커피 부호이자 모든 여자들의 이상형인 루이스(안토니오 반데라스 역). 서로에게 격렬하게 끌려 결혼한 두 사람은 꿈 같은 하루 하루를 보내게 되고, 루이스는 자기 인생이 완성된 듯한 착각에 취한다. 거액의 돈과 함께 자취를 감춰버린 줄리아, 루이스는 이해할 수 없는 그녀의 행동에 당황하고 한순간에 어이없이 사랑하는 아내를 잃어버린 슬픔에 잠겨 그녀를 찾고자 한다. 그러나, 그녀를 행방을 찾는 과정에서 용서할 수 없는 과거가 밝혀지게 된다. 아름답기만 한 그의 아내는 잔인한 살인 혐의를 받고 도피 중인 범죄자였던 것. 그가 알고 있던 그녀의 모습은 모두 거짓이었다는 사실 또한 그를 경악케 한다. 진심으로 줄리아를 사랑했던 루이스는 분노하게 되고 복수를 결심하는데.', 'https://image.tmdb.org/t/p/w500/5FEn7YoYzyn0v6E4kAowUVFWwQR.jpg', 2001, 0, 0, '2026-06-06 13:25:28.847002', 'US');
INSERT INTO public.movies VALUES (657, 210203, 'The Favourite Game', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/417bYgeqOWmj53zau5LL7cdVNvA.jpg', 2003, 0, 0, '2026-06-06 13:25:21.127677', 'US');
INSERT INTO public.movies VALUES (655, 1142921, 'तेरे इश्क़ में', '["Romance", "Drama"]', 'Aanand L. Rai', '["Dhanush", "Kriti Sanon", "Prakash Raj", "Tota Roy Chowdhury", "Priyanshu Painyuli"]', NULL, 'https://image.tmdb.org/t/p/w500/7FsHlW9z7gDhDE4EXAE2WcXUVQj.jpg', 2025, 0, 0, '2026-06-06 13:25:21.123176', 'IN');
INSERT INTO public.movies VALUES (5959, 376812, '술탄', '["Drama", "Action", "Romance"]', 'Ali Abbas Zafar', '["Salman Khan", "Anushka Sharma", "Randeep Hooda", "Amit Sadh", "Kumud Mishra"]', '살만칸 주연으로 중년의 전 레슬링 챔피언이 격투기 선수로 재기하기 위해 분투한다는 내용의 영화다. 이야기의 배경은 8년 전으로 거슬러 올라간다. 술탄(살만 칸)은 아르파(아누쉬카 샤르마)를 본 순간 그녀에게 첫눈에 반한다. 하지만 올림픽을 꿈꾸는 여자 레슬링 유망주인 아르파는 뛰어난 레슬링 선수에게만 마음을 허락하겠다며 술탄의 관심을 일체 거부한다. 술탄은 그런 그녀의 마음을 얻기 위해 레슬링에 뛰어들고, 각고의 노력 끝에 성공 가도를 달리며 그녀의 마음을 얻는 데 성공한다. 그런데 올림픽을 앞두고 아르파는 임신한 사실을 알게 되고 올림픽을 향한 자신의 꿈을 포기한다. 한편 술탄은 성공을 거듭하며 점차 오만해지는데, 술탄 없이 홀로 출산을 하게 된 아르파는 그의 부재로 수혈을 받지 못한 채 아이를 잃는 비극을 겪는다. 결국 아르파는 술탄에게 등을 돌리고, 자책감에 빠진 술탄도 선수 생활을 그만둔 채 은둔의 세월을 보내게 된다. 그렇게 8년의 세월이 지나고, 중년이 된 술탄은 잃어버린 인생과 사랑을 되찾기 위해 격투기 선수로서 새로운 도전을 시작한다.', 'https://image.tmdb.org/t/p/w500/nZmxqub8t0ziqxcaGhj6Rg1h9Dm.jpg', 2016, 0, 0, '2026-06-08 06:52:11.929373', 'IN');
INSERT INTO public.movies VALUES (2965, 1701, '콘 에어', '["Action", "Thriller", "Crime"]', NULL, '[]', '최정예 특공대원 카메론 포우(니콜라스 케이지 분)는 제대하던 날 아내와 귀가하다가, 자신의 아내를 노리는 폭력배로부터 위협을 받는다. 불행하게도 카메론은 그들 중 한 명을 죽이게 된다. 사랑하는 아내와 아내의 뱃속에서 자라고 있는 딸을 지키기 위해서였다. 그로부터 8년 뒤, 모범수로 가석방된 카메론은 결코 타지 말았어야 할 죄수 수송기에 몸을 싣는다. 이 수송기는, 미국 전역의 형무소에 격리수용된 악명높은 죄수들만 따로 통합 수용하기 위하여 세워진 새 형무소로 흉악범들을 이송하는 임무를 띤 ‘콘 에어’ 수송기였다.    모범수인 카메론은 그 형무소까지 가지 않고 중간 기착지에서 내리도록 되어 있다. 콘 에어가 이륙하는 순간 카메론은 예상하지 못한 위기를 직감한다. 8명의 죄수들이 콘 에어를 공중납치해버린 것이다. 죄수들의 행동 대장은 ‘바이러스’란 별명을 가진 사이러스 그리섬(존 말코비치 분)이다. 카메론은 사태의 심각성과 신변의 위험을 깨닫지만 기내에 동승한 연방 보안 요원과 간수들이 속속 당하는 것을 보고만 있어야 할 만큼 속수무책이다. 연방 보안관이자 진압 대장인 빈스 라킨(존 쿠삭 분)과 FBI요원 그리고 특전반은 콘 에어가 착륙할 사막의 중간 기착지에 매복한 뒤 기습소탕작전을 준비하고 있다. 수송기에 탑승할 중간 기착지의 죄수들이 대기하고 있는 가운데 콘 에어가 서서히 착륙한다. 그러나 내리기로 되어 있던 카메론은 보이지 않고, 라킨의 상관은 기내의 보안요원이 전부 살해된 것으로 판단하고 콘 에어 수송기를 공중 폭파시키라는 명령을 내리는데..', 'https://image.tmdb.org/t/p/w500/1WGzV906MDSr4IFOtWxJC8wrhRu.jpg', 1997, 0, 0, '2026-06-07 12:17:56.170434', 'US');
INSERT INTO public.movies VALUES (2969, 842675, '유랑지구 2', '["Sci-Fi", "Action", "Adventure"]', NULL, '[]', '태양계 소멸의 위기를 맞은 인류는 지구 표면에 거대한 엔진을 달아 궤도를 옮기는 ‘유랑지구 프로젝트’에 돌입한다. 하지만, 데이터베이스로 영생을 가지려는 ‘디지털 라이프’와 대립하게 되며 프로젝트는 난관에 부딪히게 되고, 그 과정 속 달과의 충돌이라는 예상치 못한 대재앙에 놓이게 되는데… 살아남기 위한 선택은 단 하나, 달을 파괴하라!', 'https://image.tmdb.org/t/p/w500/pajq0n6FZivirCg1ifpe4zYKvsA.jpg', 2023, 0, 0, '2026-06-07 12:17:56.18323', 'US');
INSERT INTO public.movies VALUES (653, 11836, '보글보글 스폰지밥', '["Adventure", "Animation", "Comedy", "Family", "Fantasy"]', NULL, '[]', '세상에서 가장 안전하고 평화로운 세상인 ‘비키니 보톰’은 스폰지 밥의 삶의 터전이다. 그러나 그의 아늑한 보금자릴 떠나 새로운 모험을 하여야 할 운명이 그를 기다리고 있었다. 그것은 바로 도단 당한 넵튠 왕의 왕관을 다시 찾아내야 하는 거국적인 임무를 수행하여야 하는 것이었다.  하지만, 우연치 않게 ‘스폰지 밥’이 근무하는 회사의 사장이 도둑으로 몰리게 되고 ‘스폰지 밥’은 왕관도 구하면서 동시에 그의 사장도 위기에서 구하여 하는 엄청난 도전이 기다리고 있었다.  우리의 영웅 ‘스폰지 밥’과 그의 영원한 친구 ‘스타피시 패트릭’ 그리고 사장은 거사를 이루기 위하여 한번도 가본 적이 없는 미지의 바다를 향하여 용감하게 돌진하게 되는데…….', 'https://image.tmdb.org/t/p/w500/A2G5gYXMwg10sKpRUTq371TooVu.jpg', 2004, 0, 0, '2026-06-06 13:25:21.118692', 'US');
INSERT INTO public.movies VALUES (659, 447273, '백설공주', '["Family", "Fantasy"]', NULL, '[]', '눈보라가 몰아치던 겨울 밤 태어난 백설공주. 온정이 넘치던 왕국에서 모두의 사랑을 받았지만, 강력한 어둠의 힘으로 왕국을 빼앗은 여왕의 위협에 숲으로 도망친다. 마법의 숲에서 간신히 살아남은 백설공주는 신비로운 일곱 광부들과 만나게 되며 새로운 세상을 마주하고, 마음속 깊이 숨겨진 용기와 선한 힘을 깨닫게 된다. 그리고 마침내, 빼앗긴 왕국을 되찾기 위해 여왕과 맞서 싸우기로 결심하는데…', 'https://image.tmdb.org/t/p/w500/7EruTgYzDFM8kWhr2ysuuwoXFqk.jpg', 2025, 0, 0, '2026-06-06 13:25:21.132361', 'US');
INSERT INTO public.movies VALUES (2971, 73723, '로렉스', '["Animation", "Family"]', NULL, '[]', '공기도, 풀도, 바람도 모두 인공적으로 만들어낸 최첨단의 도시 스니드빌에 살고 있는 테드는 옆 집에 사는 소녀 오드리를 좋아합니다. 그녀의 마음을 얻을 궁리를 하던 테드는 오드리가 간절히 원하는 것이 지금은 그 어디에서도 볼 수 없는 살아있는 나무라는 것을 알게 됩니다. 그녀를 위해 테드는 나무에 얽힌 비밀을 알고 있는 단 한 사람, 원슬러를 만나러 스니드빌 밖으로의 위험천만한 모험을 떠나기로 결심합니다! 한편 공기와 인공 나무 등을 만들어 파는 최고의 부자이자 스니드빌의 지배자 미스터 오헤어는 테드가 살아있는 나무의 존재를 알게 되는 것을 막기 위해, 덩치 큰 부하들과 첨단 감시 기기 등의 온갖 방법을 동원해 음모를 꾸밉니다. 갖은 고생과 모험 끝에 마침내 황량한 언덕 꼭대기에 있는 원슬러의 오두막에 도착한 테드! 그 곳에서 원슬러가 들려준 이야기는 바로 환상적인 트러풀라 숲과 나무 요정 로렉스에 대한 놀라운 비밀이었는데……', 'https://image.tmdb.org/t/p/w500/zRZVssgf4L4tdPFsYwJlyJknybe.jpg', 2012, 0, 0, '2026-06-07 12:17:56.189505', 'US');
INSERT INTO public.movies VALUES (667, 244998, 'Senario XX', '["Comedy", "Adventure", "Action"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/scoQLzyPEsL7pSzN22Af2xKzl35.jpg', 2005, 0, 0, '2026-06-06 13:25:21.860014', 'US');
INSERT INTO public.movies VALUES (666, 109418, '다 큰 녀석들 2', '["Comedy"]', NULL, '[]', '어렸을 때부터 친했던 친구들인 레니, 라몬소프, 맥켄지, 히긴스. 여름을 맞아 이들은 옛 추억을 떠올리며 한때 자신들이 겁 없이 무모한 짓을 했던 곳을 찾아간다. 하지만 접근 금지 구역인 그곳에는 과거의 자신들처럼 젊은 대학생들이 한창 파티를 즐기고 있다. 대학생들은 이들을 불청객 취급을 하고 쫓아낸다. 수치스러운 모습으로 쫓겨난 이들은 대학생들에게 복수를 하고 옛 추억을 떠올리며 레니의 집에서 80년대를 주제로 한 파티를 여는데...', 'https://image.tmdb.org/t/p/w500/hT6ijOtjtYrnyDhN7VA2QWyGFAm.jpg', 2013, 0, 0, '2026-06-06 13:25:21.857619', 'US');
INSERT INTO public.movies VALUES (560, 489, '굿 윌 헌팅', '["Drama"]', NULL, '[]', '수학, 법학, 역사학 등 모든 분야에 재능이 있는 윌은 천재적인 두뇌를 가지고 있지만 어린 시절 받은 상처로 인해 세상에 마음을 열지 못하고 절친인 처키와어울려 다니는 불우한 반항아이다. 대학을 청소하면서 벽에서 우연히 접한 수학 문제를 간단히 풀어버린 일을 그 대학 교수 램보가 발견하고 윌에게 관심을 갖지만 윌은 냉대한다. 어느 날 보호관찰 대상인 윌은 폭행죄로 수감되고, 램보 교수는 자신이 감독하겠다는 조건으로 윌을 석방시킨 다음 대학 동기인 심리학 교수 숀에게 그를 부탁한다. 거칠기만 하던 윌은 숀과 함께 시간을 보낼수록 상처를 위로 받으며 조금씩 변화하기 시작하는데...', 'https://image.tmdb.org/t/p/w500/67dZYyIKnwjCe2C22mn8jreObah.jpg', 1997, 0, 0, '2026-06-06 13:25:17.239495', 'US');
INSERT INTO public.movies VALUES (670, 1213906, 'द साबरमती रिपोर्ट', '["Drama", "Thriller", "Crime"]', 'Ranjan Chandel', '["Vikrant Massey", "Raashii Khanna", "Ridhi Dogra", "Nazneen Patni", "Barkha Singh"]', NULL, 'https://image.tmdb.org/t/p/w500/zd3CBwv04BRyH4WJuM5xFsZkgjX.jpg', 2024, 0, 0, '2026-06-06 13:25:21.866988', 'IN');
INSERT INTO public.movies VALUES (676, 1305781, '표인: 풍기대막', '["Action", "Drama", "History"]', NULL, '[]', '광활한 사막에서 표국, 관군, 상인 세력 등 수많은 집단이 권력을 차지하기 위해 치열하게 다툰다. 전설적인 현상금 사냥꾼 도마는 한 남자를 장안까지 호송하는 임무를 맡는다. 그러나 자신이 호송하는 인물이 사실은 제국에서 가장 위험한 수배자 지시랑임을 알게 되고, 거액의 현상금을 둘러싼 목숨 건 사투가 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/AsWzPlQK2xJTIrzw6McT8Yvy6H2.jpg', 2026, 0, 0, '2026-06-06 13:25:21.880828', 'US');
INSERT INTO public.movies VALUES (672, 746036, '스턴트맨', '["Action", "Comedy", "Romance"]', NULL, '[]', '잠수 이별을 택하고 후회뿐인 날을 보내던 스턴트맨 콜트. 영화감독이 된 전 여친 조디의 촬영장에 복귀하며 아련한 재회를 기대했지만… 갑자기 주연배우가 사라지고 콜트는 우선 그부터 찾아야만 한다.', 'https://image.tmdb.org/t/p/w500/aUZ176q7ldMaPLYVnmaFWK4CApE.jpg', 2024, 0, 0, '2026-06-06 13:25:21.871585', 'US');
INSERT INTO public.movies VALUES (674, 1659087, '180', '["Thriller", "Crime", "Drama"]', NULL, '[]', '다른 운전자와 예상치 못한 시비가 붙으면서 아들이 중태에 빠지자, 격분한 아버지가 감정의 소용돌이에 휘말리며 복수의 어두운 길로 치닫는다.', 'https://image.tmdb.org/t/p/w500/9ISjrhA38HpSSGtfiCk8lpziC3K.jpg', 2026, 0, 0, '2026-06-06 13:25:21.876276', 'US');
INSERT INTO public.movies VALUES (675, 1108211, '사라진 그녀', '["Mystery", "Crime", "Thriller"]', NULL, '[]', '결혼기념일 여행 중에 아내가 사라졌다. 보름이 지난후, 남편 허페이 앞에 정체 모를 낯선 여자가 나타나 자신이 그의 사라진 아내라고 말한다.', 'https://image.tmdb.org/t/p/w500/cXUFTBsPif5UqHRc7j569mH7KJ1.jpg', 2023, 0, 0, '2026-06-06 13:25:21.878554', 'US');
INSERT INTO public.movies VALUES (455, 30112, '로스트 인 베이징', '["Romance", "Drama"]', NULL, '[]', '리얼하고 섹시한 도시 남녀들의 일상!INSERT INTO public.movies VALUES (671, 1198984, '죽은 자를 묻는 사람들', '["Horror", "Thriller"]', NULL, '[]', '대규모 군사 재난 이후, 죽은 자들이 다시 움직이기 시작하며 세상은 봉쇄된다. 사라진 남편의 흔적을 찾기 위해 격리 구역으로 향한 에이바는 시신을 찾아 묻는 임무를 맡은 수습 부대에 자원한다. 하지만 폐허가 된 도시를 지나며 그녀가 마주한 존재들은 당국의 발표와 달리 점점 더 공격적이고 위협적으로 변해가고, 에이바는 생존을 위한 처절한 사투와 함께 상상 이상의 끔찍한 진실을 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/eydncvvbukvdr1DrpxIGy3N3bgy.jpg', 2026, 0, 0, '2026-06-06 13:25:21.869219', 'US');
INSERT INTO public.movies VALUES (511, 324786, '핵소 고지', '["Drama", "History"]', 'Mel Gibson', '["Andrew Garfield", "Sam Worthington", "Vince Vaughn", "Teresa Palmer", "Luke Bracey"]', '비폭력주의자인 도스는 전쟁으로부터 조국과 소중한 사람들을 지키기 위해 총을 들지 않아도 되는 의무병으로 육군에 자진 입대한다. 총을 들 수 없다는 이유로 필수 훈련 중 하나인 총기 훈련 마저 거부한 도스는 동료 병사들과 군 전체의 비난과 조롱을 받게 된다. 결국 군사재판까지 받게 되지만 끝까지 자신의 신념을 굽히지 않은 도스에게 군 상부는 오키나와 전투에 총기 없이 의무병으로 참전할 것을 허락하는데…', 'https://image.tmdb.org/t/p/w500/nlvcNogJK9R9iIj0YINApQE36FF.jpg', 2016, 0, 0, '2026-06-06 13:25:15.694022', 'GB');
INSERT INTO public.movies VALUES (677, 114168, 'Perras', '["Thriller", "Drama", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/jrJrgwFjAyzkZLiaU5dA8o1hcUA.jpg', 2011, 0, 0, '2026-06-06 13:25:21.883037', 'US');
INSERT INTO public.movies VALUES (2475, 1287571, 'Agak Laen: Menyala Pantiku!', '["Comedy", "Crime", "Drama", "Mystery"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/2Jzfr9XdJ7o3TWecHUMOWoFGUXg.jpg', 2025, 0, 0, '2026-06-07 12:17:33.886139', 'US');
INSERT INTO public.movies VALUES (679, 6479, '나는 전설이다', '["Drama", "Sci-Fi", "Thriller"]', NULL, '[]', '바이러스 감염으로 전 인류가 사망하고 홀로 뉴욕에 살아 남은 과학자 로버트 네빌(윌 스미스). 혹시라도 있을 다른 생존자를 찾아 절박한 심정으로 네빌은 3년 동안 방송을 송신해 왔다. 마침내 그는 혼자가 아니라는 것을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/yvaDfiS0DzsHDWBjlqxo6CPgDVJ.jpg', 2007, 0, 0, '2026-06-06 13:25:21.887537', 'US');
INSERT INTO public.movies VALUES (673, 359410, '로드 하우스', '["Action", "Thriller", "Drama"]', NULL, '[]', '전직 UFC 파이터 돌턴은 플로리다키스 제도의 로드 하우스에서 경비원으로 일하게 되지만, 이곳이 보이는 것 같은 낙원이 결코 아니라는 걸 알게 된다.', 'https://image.tmdb.org/t/p/w500/8D2eWclxjKJff0bDSNFVRySnPuT.jpg', 2024, 0, 0, '2026-06-06 13:25:21.873918', 'US');
INSERT INTO public.movies VALUES (4151, 81481, '도가니', '["Drama"]', 'Hwang Dong-hyuk', '["Gong Yoo", "Jung Yu-mi", "Kim Hyeon-soo", "Jung In-seo", "Baek Su-ho"]', '믿을 수 없지만, 한 청각장애인학교에서 실제 일어난 사건입니다. 2000년부터 5년간 청각장애아를 상대로 교장과 교사들이 비인간적인 성폭력과 학대를 저질렀습니다. 인정하고 싶지 않지만 이 이야기는 진실입니다. 이제 이 끔찍한 진실을 마주해야 할 시간입니다.', 'https://image.tmdb.org/t/p/w500/bBNkmna3iDVpNJmIc8QlECTmiUH.jpg', 2011, 0, 0, '2026-06-08 06:27:42.371707', 'KR');
INSERT INTO public.movies VALUES (787, 198184, '채피', '["Crime", "Action", "Sci-Fi"]', NULL, '[]', '2016년, 매일 300건의 범죄가 폭주하는 요하네스버그. 도시의 치안을 책임지는 세계 최초의 로봇 경찰 ‘스카우트’ 군단을 설계한 로봇 개발자 ‘디온(데브 파텔)’은 폐기된 스카우트 22호에 고도의 인공지능을 탑재하여 스스로 생각하고 느낄 수 있는 성장하는 로봇 ‘채피’를 탄생시킨다.  한편, 진화하는 로봇에 맞서 인간의 힘으로 로봇을 통제하고 싶은 무기 개발자 ‘빈센트 (휴 잭맨)’는 눈엣가시 ‘채피’를 제거하기 위한 음모를 꾸미게 되고, 예상을 뛰어넘는 속도로 성장하던 ‘채피’는 어느새 인류를 위협하는 대상으로 몰리게 되는데… 생존을 꿈꾸는 로봇 ‘채피’와 로봇을 통제하려는 ‘인간’의 대결이 시작된다!', 'https://image.tmdb.org/t/p/w500/hcGym66raZDzDIGjdkVDoQZvLks.jpg', 2015, 0, 0, '2026-06-06 13:25:26.523012', 'US');
INSERT INTO public.movies VALUES (5981, 33142, '비바', '["Romance", "Drama"]', 'Sooraj Barjatya', '["Shahid Kapoor", "Amrita Rao", "Anupam Kher", "Seema Biswas", "Alok Nath"]', '제목 가 의미하는 결혼은 두 개인을 신성하고 순수하며 영원한 결합으로 묶어주는 화합이자 서약이다. 중산층 가정에서 태어난 푸남은 어린 시절 부모를 여의게 된다. 그녀의 삼촌은 아버지의 빈 자리를 채우며 큰 사랑으로 그녀를 보살펴 주지만, 숙모는 자신의 딸보다 예쁜 푸남을 순수하게 친자식으로 받아들이지 못한다. 아름다운 처녀로 자라난 푸남을 높이 평가한 삼촌의 친구는 그녀를 위해 중매를 자청하고, 뉴델리의 존경 받는 사업가의 아들인 프렘을 그녀의 짝으로 연결시켜 준다. 어색한 첫 만남을 거쳐 푸남과 프렘은 여섯 달 동안의 꿈 같은 시간을 함께 하며 사랑을 키워나가게 되지만, 예기치 못한 운명의 장난이 결혼을 눈 앞에 둔 그들의 사랑에 시련을 던져 주게 된다.', 'https://image.tmdb.org/t/p/w500/e5zFYX3hW1TNeFCzRw7ET2DxRPm.jpg', 2006, 0, 0, '2026-06-08 06:52:29.250543', 'IN');
INSERT INTO public.movies VALUES (686, 718930, '불릿 트레인', '["Action", "Comedy", "Thriller"]', NULL, '[]', '운이 없기로 유명한 킬러 레이디버그는 초고속 열차에 탑승해 의문의 서류 가방을 가져오라는 미션을 받는다. 생각보다 쉽게 미션을 클리어한 후 열차에서 내리려는 그를 가로막는 것이 있었으니,  그것은 바로 전세계에서 몰려든 초특급 킬러들. 열차에서 내릴 수 없다면 목숨을 걸고 가방을 지켜야만 한다. 과연 레이디버그는 무사히 열차에서 내려 미션을 완수할 수 있을까?', 'https://image.tmdb.org/t/p/w500/msh4N8dxHk4FeEPZ8VBqHQFQYjI.jpg', 2022, 0, 0, '2026-06-06 13:25:22.623967', 'US');
INSERT INTO public.movies VALUES (6116, 26389, '프롬 파리 위드 러브', '["Action", "Crime", "Thriller"]', 'Pierre Morel', '["John Travolta", "Jonathan Rhys Meyers", "Kasia Smutniak", "Richard Durden", "Bing Yin"]', '비밀 특수요원 ‘왁스’(존 트라볼타)는 자폭 테러조직으로부터 미국의 1급 정부인사를 보호하라는 중요한 임무를 부여 받고 파리에 도착한다. 하지만 파리 공항의 입국 심사부터 문제를 일으킨 단순무식의 트러블 메이커 ‘왁스’. 현지에서 그런 그를 돕기 위해 주 프랑스 미대사관 직원인 ‘제임스’(조나단 리스 마이어스)가 파트너로 배치된다. 섹시한 외모와 달리 융통성 제로에 성실하게만 살아온 ‘제임스’는 뜻하지 않게 ‘왁스’의 파란만장한 행보에 합류하게 되고, 사사건건 으르릉거리며 혹독한 미션을 해결해 나가는데… 과연 이들은 테러리스트의 공격을 막아낼 수 있을까?', 'https://image.tmdb.org/t/p/w500/8L47xarzaPmFAt5Wii4GLRxeSio.jpg', 2010, 0, 0, '2026-06-08 06:54:18.609803', 'FR');
INSERT INTO public.movies VALUES (683, 664767, '모탈 컴뱃 레전드: 스콜피온의 복수', '["Animation", "Action", "Fantasy"]', NULL, '[]', '한 세대에 한 번 꼴로 개최되는 외계와 지구의 챔피언들 간의 토너먼트를 통해 세계의 운명을 결정짓게 되는 이야기. 지구의 수호자인 라이덴 경은 지구에서 가장 강력한 파이터들을 모아 최후의 대결인, 모탈 컴뱃에서 사악한 빌런 상췡으로부터 지구를 지켜야 하는데...', 'https://image.tmdb.org/t/p/w500/iBvo3qOPcmhlqAaJcXcQHtx2qLk.jpg', 2020, 0, 0, '2026-06-06 13:25:22.617143', 'US');
INSERT INTO public.movies VALUES (2705, 1469164, 'Casa Grande', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/mE9E4nsGM91Cf4b1s6nOOdUAE9P.jpg', 2026, 0, 0, '2026-06-07 12:17:44.649714', 'US');
INSERT INTO public.movies VALUES (684, 297762, '원더 우먼', '["Action", "Adventure", "Fantasy"]', NULL, '[]', '수천년 간 존재를 숨긴 채 지구를 수호하던 데미스키라의 공주 다이애나는 어느 날 하늘에서 이상한 움직임을 포착한다. 1차 세계대전에 참전해 스파이 활동을 벌이다가 격추된 미국인 조종사 스티브가 해변에 불시착한 것. 태어나 처음으로 남성을 보게 된 다이애나는 호기심을 감추지 못하고, 데미스키라의 일원들은 그가 파멸을 가져올 수도 있음을 경고한다. 다이애나는 엄마이자 여왕인 히폴리타의 반대에도 불구하고 나치군의 추격을 따돌리면서 그들의 생화학무기 공격을 비밀리에 막아야 하는 스티브를 따라나선다.', 'https://image.tmdb.org/t/p/w500/oZGYR75RaSLQ8XdJIVerYnOdhFx.jpg', 2017, 0, 0, '2026-06-06 13:25:22.619487', 'US');
INSERT INTO public.movies VALUES (2485, 898704, '데저트 워리어', '["History", "Action", "Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/waxnw1NpzTPY5JkqWvu0muSopRJ.jpg', 2026, 0, 0, '2026-06-07 12:17:34.859804', 'US');
INSERT INTO public.movies VALUES (687, 1007734, '노바디 2', '["Action", "Thriller", "Comedy"]', NULL, '[]', '가족과 소홀해지는 걸 느낀 허치. 오랜만에 가족들과 떠나는 여름 휴가지는 유년 시절의 추억이 깃든 플러머빌. 꿀 같은 휴식을 꿈꿨지만 평온은 온데간데없고… 사건만 터지는데. 일도 가족도 고단한 아저씨의 휴가를 쟁탈하기 위한 싸움이 시작된다.', 'https://image.tmdb.org/t/p/w500/vBKQuGX0nrx9p8H3j3GGojDYoKH.jpg', 2025, 0, 0, '2026-06-06 13:25:22.626231', 'US');
INSERT INTO public.movies VALUES (688, 950, '아이스 에이지 2', '["Animation", "Family", "Comedy", "Adventure"]', NULL, '[]', '전세계가 기다려온 2006년 최고의 애니메이션 대작!  더욱 강력해진 웃음과 스케일로 돌아왔다!  평화롭던 빙하기에 닥친 절대절명 위기! “웁쓰~ 이번엔 해빙기다!”  평화롭던 빙하기가 지구 온난화 현상으로 해빙기에 접어든다. 동물들의 유아 캠프를 운영하는 맘모스 매니와 나무늘보 시드, 호랑이 디에고 일행은 왕뻥토니로부터 곧 대홍수가 올 것이라는 경고를 듣지만 모두들 “뻥치시네~”를 외치며 토니의 말을 믿지 않는다. 그러던 중 진짜 빙하가 녹는 현장을 직접 눈으로 목격한 매니, 시드, 디에고는 다급하게 동료들을 모아 안전한 고지대를 찾아 대규모 이주를 시작한다.  하지만 매니에겐 대홍수의 위기보다 더 큰 위기가 닥친다. 바로 자신을 제외한 모든 맘모스가 멸종되어 버렸다는 기절초풍할 소식을 듣게 되는 것이다.  위기 속에서 피어나는 작업 로맨스! “종족보존을 위해 우리…연애나 할까?”  더 이상 가족을 만들 수 없다는 절망에 빠진 매니. 그러나 그의 눈앞에 맘모스 엘리가 나타난다. 나는 남자~ 너는 여자~! 이제 종족의 번영은 우리 하기 나름~~!!! 이라는 기쁨도 잠시, 매니와 시드, 디에고는 곧 혼란에 빠져버린다. 섹시하고 풍성한 엉덩이를 가진 맘모스 엘리는 자신이 주머니쥐라고 믿고 있는 것이다. 그것도 진짜 주머니쥐 악동 형제 크래쉬와 에디의 여동생으로서. 어이~ 아가씨, 농담이 지나쳐!  그러나 매니는 멸종위기의 맘모스를 구해야 한다는 사명감(그 외의 이유는 묻지 말아주세요)과 이를 부추기는 시드, 디에고의 응원에 힘입어 엘리에게 작업을 걸어보지만 오히려 엘리의 반감만 사게 되는데…', 'https://image.tmdb.org/t/p/w500/1Dy4HsXBdMc5kcsmjKyU1ufI10J.jpg', 2006, 0, 0, '2026-06-06 13:25:22.628477', 'US');
INSERT INTO public.movies VALUES (935, 9792, '힐즈 아이즈', '["Horror", "Thriller"]', NULL, '[]', '힐즈 아이즈라는 원작 제목으로도 알려져있는 영화. 결혼기념일을 맞이해서 여행을 떠난 한 가족. 그 가족이 여행 중 길을 잘못 들어 정부가 원자폭탄 실험을 해서 모든 주민이 이주한 지역으로 가게 된다. 그곳에서 그들을 희생양으로 삼으려는 피에 굶주린 돌연변이 가족을 만나는데..', 'https://image.tmdb.org/t/p/w500/2eJL1Ccr1FN3dm9OSDwyd8uaX1b.jpg', 2006, 0, 0, '2026-06-06 13:25:31.956972', 'US');
INSERT INTO public.movies VALUES (3375, 1217931, 'Vampires of the Velvet Lounge', '["Comedy", "Horror"]', 'Adam Sherman', '["Mena Suvari", "Dichen Lachman", "Stephen Dorff", "Sarah Dumont", "Will Redmond"]', NULL, 'https://image.tmdb.org/t/p/w500/4uJcIW0PL4vNZvk0z6kwWdOqLv6.jpg', 2026, 0, 0, '2026-06-08 06:24:15.242497', 'US');
INSERT INTO public.movies VALUES (693, 91314, '트랜스포머: 사라진 시대', '["Sci-Fi", "Action", "Adventure"]', NULL, '[]', '시카고에서 벌어진 오토봇과 디셉티콘의 전투로 인해 수많은 사상자가 발생하고 도시가 처참하게 파괴되자  정부는 일부 오토봇을 제외한 트랜스포머에 대해 체포령을 내린다. 시카고 사태, 5년 후 대부분의 디셉티콘이 처벌되고 오토봇 역시 모습을 감춘 상황, 엔지니어 케이드 예거는 우연히 폐기 직전 고물차로 변해있던 옵티머스 프라임을 깨우게 된다. 그리고 그의 생존이 알려지자 옵티머스 프라임을 노리고 있던 어둠의 세력 역시 모습을 드러내기 시작한다. 전세계를 새로운 위협에 몰아넣을 거대한 음모, 사상 최대 가장 강력한 적에 맞서 옵티머스 프라임과 오토봇 군단은 목숨을 건 대결에 나서는데...', 'https://image.tmdb.org/t/p/w500/zPbiUwVSToxgQHMAbuzint09fHf.jpg', 2014, 0, 0, '2026-06-06 13:25:22.639528', 'US');
INSERT INTO public.movies VALUES (696, 493922, '유전', '["Horror", "Mystery", "Thriller"]', NULL, '[]', '애니는 일주일 전 돌아가신 엄마의 유령이 집에 나타나는 것을 느낀다. 애니가 엄마와 닮았다며 접근한 수상한 이웃 조안을 통해 엄마의 비밀을 발견하고, 자신이 엄마와 똑같은 일을 저질렀음을 알게 된다. 그리고 마침내 애니의 엄마로부터 시작돼 아들 피터와 딸 찰리에게까지 이어진 저주의 실체가 정체를 드러내는데…', 'https://image.tmdb.org/t/p/w500/h2Fw8XXqDSyRA5Dn9ntCRJESYYY.jpg', 2018, 0, 0, '2026-06-06 13:25:22.646218', 'US');
INSERT INTO public.movies VALUES (4333, 505292, '어린 누나', '["Romance"]', 'Kim Tae-soo', '["Seo Won", "Min Do-yoon", "Shin Joon-hyun", "Ha Jin"]', '어린 시절 친남매처럼 자란 사촌 사이던 은정과 태수. 20년이 흘러서 은정은 시나리오 작가로 활동하고 있다. 태수는 마음속에 담고 있던 사촌 누나 은정을 짝사랑 하던 것을 생각해 내고 사업구상을 핑계로 사촌누나 은정의 집으로 찾아온다. 하지만, 은정의 집에는 은정의 친구이자 보조 작가인 미란이 함께 있었고\r세 사람의 미묘한 동거가 시작되는데...', 'https://image.tmdb.org/t/p/w500/e2uKsBgakda3XyHKCLPcUfKsmFw.jpg', 2018, 0, 0, '2026-06-08 06:30:23.422118', 'KR');
INSERT INTO public.movies VALUES (698, 744276, '애프터: 에버 해피', '["Romance", "Drama"]', NULL, '[]', '뉴욕으로 떠난 테사와 소설가로 데뷔한 하딘,  런던에서 삶을 송두리째 뒤흔들 엄청난 과거를 알게 된 하딘은 자신의 불행 속에 테사를 끌어들이기 싫어서 애써 밀어낸다.  계속 제자리만 맴도는 관계에 지친 테사는 새로운 삶을 꿈꾸며 뉴욕으로 향하고, 떨어진 동안 그의 소중함을 깨달은 하딘은 뉴욕에서 테사와 재회하여 서로의 숨결과 살결을 탐한다.  다시 미래를 꿈꾸던 테사는 하딘이 집필한 소설 ‘애프터’에 자신의 첫 키스부터 첫 경험뿐만 아니라 감추고 싶던 아픈 기억까지 모두 담겨 있다는 것을 알고 충격을 받는데…', 'https://image.tmdb.org/t/p/w500/fZqvzsekRXxRrtEKIWoAWP5eqe7.jpg', 2022, 0, 0, '2026-06-06 13:25:22.650675', 'US');
INSERT INTO public.movies VALUES (504, 1315772, '미니언즈 & 몬스터즈', '["Adventure", "Animation", "Comedy", "Family", "Fantasy"]', NULL, '[]', '우연히 영화 촬영장에 난입한 미니언들이 세계적인 무비스타로 거듭나며 벌어지는 이야기', 'https://image.tmdb.org/t/p/w500/8uvgppq5obV06X9X8SogQiU79Kd.jpg', 2026, 0, 0, '2026-06-06 13:25:15.675289', 'US');
INSERT INTO public.movies VALUES (699, 1625582, 'The Kerala Story 2', '["Crime", "Drama"]', 'Kamakhya Narayan Singh', '["Ulka Gupta", "Aishwarya Ojha", "Aditi Bhatia", "Arjan Aujla", "Abhishek Shankar"]', NULL, 'https://image.tmdb.org/t/p/w500/rUllL8MD78JfgkDPLV6Tx13IiID.jpg', 2026, 0, 0, '2026-06-06 13:25:22.652887', 'IN');
INSERT INTO public.movies VALUES (8806, 472269, '포썸: 죽음을 부르는 기억', '["Drama", "Horror", "Thriller"]', 'Matthew Holness', '["Sean Harris", "Alun Armstrong", "Andy Blithe", "Ryan Enever", "Charlie Eales"]', '인형술사 `필립`은 평생 자신을 따라다니며  고문하던 사악한 비밀에 맞서기 위해 고향을 찾는다. ​도착한 도시엔 사람들의 생기라곤 없었으며, 낡은 집 한가운데 힘없는 노인 `모리스`만이 자신을 반긴다. ​한편, 한켠에서 수상한 가방을 발견한 `필립`은 마을 이곳저곳을 떠돌기 시작하는데...​ 떨쳐내려 할수록 더 깊게 자리하는 공포!  눈을 뗄 수 없는 기묘한 이야기 속에서 두려움에 사로잡힌 당신을 마주하라!!', 'https://image.tmdb.org/t/p/w500/gqnv75UMpBn1lfWDPJ6RdVquseF.jpg', 2018, 0, 0, '2026-06-08 07:29:40.698817', 'GB');
INSERT INTO public.movies VALUES (495, 272, '배트맨 비긴즈', '["Drama", "Crime", "Action"]', NULL, '[]', '브루스 웨인은 어린 시절, 부모님이 길거리에서 피살되는 것을 눈 앞에서 지켜본 후 죄의식과 분노로 늘 고통 받는다. 복수의 욕망과 부모님의 가르침 사이에서 갈등하던 그는 악을 물리칠 방법을 터득하기 위해 고담시를 떠나 홀로 세상을 유랑하던 중 듀커드라는 수수께끼의 인물을 만나 가름침을 받고, 듀커드는 브루스에게 어둠의 사도들에 가입하라는 제안을 한다. 듀커드가 속해있는 어둠의 사도들은 라스 알 굴이 이끄는 범죄 소탕 조직. 그러나 브루스는 눈에는 눈, 이에는 이라는 강경책으로 응징하는 이들의 방법이 자신과는 맞지 않음을 깨닫고 고담시로 돌아온다.', 'https://image.tmdb.org/t/p/w500/e8MB1d69fmzyonT6mz9iQs3rhw7.jpg', 2005, 0, 0, '2026-06-06 13:25:14.89413', 'US');
INSERT INTO public.movies VALUES (700, 507086, '쥬라기 월드: 도미니언', '["Adventure", "Sci-Fi", "Thriller"]', NULL, '[]', '공룡들의 터전이었던 이슬라 누블라 섬이 파괴된 후,  마침내 공룡들은 섬을 벗어나 세상 밖으로 출몰한다. 지상에 함께 존재해선 안 될 위협적 생명체인 공룡의 등장으로 인류 역사상 겪어보지 못한 사상 최악의 위기를 맞이한 인간들. 지구의 최상위 포식자 자리를 걸고 인간과 공룡의 최후의 사투가 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/upGiyJeCbG61899TXiY01mxdjEF.jpg', 2022, 0, 0, '2026-06-06 13:25:22.655063', 'US');
INSERT INTO public.movies VALUES (694, 321612, '미녀와 야수', '["Family", "Fantasy", "Romance"]', NULL, '[]', '프랑스의 작은 마을에 아버지와 살고 있는 벨은 책을 통해 넓은 세계를 꿈꾼다. 전쟁 영웅 개스톤의 저돌적인 구애와 마을 사람들의 핀잔에도 결혼 따위엔 관심이 없다. 어느 날 행방불명된 아버지를 찾아 폐허가 된 성에 도착한 벨은 저주에 걸린 야수를 만나 아버지 대신 성에 갇히고, 야수 뿐 아니라 성 안의 모든 이들이 신비로운 장미의 마지막 꽃잎이 떨어지기 전에 저주를 풀지 못하면 영원히 인간으로 돌아올 수 없는 운명임을 알게 된다. 성에서 도망치려던 벨은 자신을 보호해 준 야수의 진심을 알게 되면서 차츰 마음을 열어가기 시작하는데...', 'https://image.tmdb.org/t/p/w500/tzYsKo6wGoBrP51eL9wDzfDP6Vx.jpg', 2017, 0, 0, '2026-06-06 13:25:22.641808', 'US');
INSERT INTO public.movies VALUES (697, 1022453, 'ది రాజాసాబ్', '["Comedy", "Horror", "Fantasy", "Action"]', 'Maruthi Dasari', '["Prabhas", "Sanjay Dutt", "Zarina Wahab", "Nidhhi Agerwal", "Malavika Mohanan"]', NULL, 'https://image.tmdb.org/t/p/w500/nvK6gYa4diCnQkDVN42uoYXPrdT.jpg', 2026, 0, 0, '2026-06-06 13:25:22.648414', 'IN');
INSERT INTO public.movies VALUES (708, 439079, '더 넌', '["Horror"]', NULL, '[]', '루마니아의 젊은 수녀가 자살하는 사건을 의뢰 받아 바티칸에서 파견된 버크 신부와 아이린 수녀가 수녀원을 조사하면서 충격적인 악령의 실체와 만나게 되는 이야기를 그린다.', 'https://image.tmdb.org/t/p/w500/mN226GIDSMhWBpqPJopGlLk3qXn.jpg', 2018, 0, 0, '2026-06-06 13:25:23.398439', 'US');
INSERT INTO public.movies VALUES (707, 87101, '터미네이터 제니시스', '["Sci-Fi", "Action", "Thriller"]', NULL, '[]', '인간 저항군의 리더 존 코너의 탄생을 막기 위해 스카이넷은 터미네이터를 과거로 보내고, 이를 저지하기 위해 부하 카일 리스가 뒤를 따른다. 젊은 사라 코너와 그녀를 보호하고 있던 T-800은 로봇과의 전쟁을 준비하며 이미 그들을 기다리고 있었다. 시간의 균열로 존 코너 역시 과거로 오지만 그는 나노 터미네이터 T-3000으로 변해있었던 것. 이제 인류는 인간도 기계도 아닌 그 이상의 초월적인 존재, 사상 최강의 적에 맞서 전쟁을 벌여야만 한다.', 'https://image.tmdb.org/t/p/w500/bzcw6IyAbX3DbXrzPXx7ZgLXalr.jpg', 2015, 0, 0, '2026-06-06 13:25:23.396145', 'US');
INSERT INTO public.movies VALUES (746, 150689, '신데렐라', '["Romance", "Fantasy", "Family", "Drama"]', NULL, '[]', '어린 시절 어머니를 여읜 엘라는 새엄마와 그녀의 두 딸과 함께 살게 된다. 무역상인 아버지마저 타지에서 돌아가시자 새엄마와 의붓 언니들은 엘라를 재투성이라는 뜻의 신데렐라라고 부르며 온갖 구박을 일삼는다. 항상 착한 마음씨와 용기를 가지라는 엄마의 유언을 지켜나가던 엘라는 숲 속에서 왕궁의 견습생이라는 키트를 만난다. 왕궁에서 무도회가 열리자 엘라는 키트를 만날 생각에 부풀지만, 새엄마는 엘라의 드레스를 찢어버린다. 상심에 빠져 울고 있던 엘라는 거지 여인으로 분장한 요정 대모를 만나는데...', 'https://image.tmdb.org/t/p/w500/3yNm2SdzdcXYXv8D7cS9RV5H6DG.jpg', 2015, 0, 0, '2026-06-06 13:25:24.945229', 'US');
INSERT INTO public.movies VALUES (712, 616037, '토르: 러브 앤 썬더', '["Fantasy", "Action", "Comedy"]', NULL, '[]', '이너피스를 위해 자아 찾기 여정을 떠난 천둥의 신 토르. 그러나 우주의 모든 신들을 몰살하려는 신 도살자 고르의 등장으로 토르의 안식년 계획은 산산조각 나 버린다. 토르는새로운 위협에 맞서기 위해 킹 발키리, 코르그, 그리고 전 여자친구 제인과 재회하게 되고, 그녀가 묠니르를 휘두르는 마이티 토르가 되어 나타나 모두를 놀라게 한다. 이제 팀 토르는 고르의 복수에 얽힌 미스터리를 밝히고 더 큰 전쟁을 막기 위한 전 우주적 스케일의 모험을 시작하는데...', 'https://image.tmdb.org/t/p/w500/un8ZDtx2SMwNwXRYy65aItnNjab.jpg', 2022, 0, 0, '2026-06-06 13:25:23.407618', 'US');
INSERT INTO public.movies VALUES (709, 1022787, '엘리오', '["Adventure", "Animation", "Comedy", "Family", "Sci-Fi"]', NULL, '[]', '세상 그 어디에서도 소속감을 느끼지 못한 채, 외계인의 납치를 꿈꾸는 외톨이 소년 엘리오. 그러던 어느 날 작은 오해로 인해 지구 대표로 우주에 소환되고, 그곳에서 자신과는 너무도 다른 특별한 존재 글로든을 만나 처음으로 마음을 나눌 친구를 갖게 된다.  낯설지만 따뜻한 우주에서 꿈같은 나날들을 보내던 엘리오 앞에 온 우주를 위험에 빠뜨릴 크나큰 위기가 닥쳐오는데...', 'https://image.tmdb.org/t/p/w500/ymd7E8ZRXOfOpJ418rgGtEdVmEN.jpg', 2025, 0, 0, '2026-06-06 13:25:23.400719', 'US');
INSERT INTO public.movies VALUES (711, 1560230, 'Ella solo come carne', '[]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/i3zEJNROaJHFnFk9isbLLsJYrVn.jpg', 2026, 0, 0, '2026-06-06 13:25:23.40527', 'US');
INSERT INTO public.movies VALUES (706, 296096, '미 비포 유', '["Drama", "Romance"]', NULL, '[]', '6년간 일하던 카페가 폐업하면서 하루아침에 일자리를 잃은 루이자(에밀리아 클라크). 그녀는 새 직장을 찾던 중 집에서 가깝고 보수도 좋은 간병인 일을 찾게 되고, 면접을 본 그날 바로 채용이 결정된다. 하지만 루이자가 간병해야 할 윌(샘 클라플린)은 2년 전 사고로 전신마비 환자가 된 자신을 받아들이지 못하고 남에게 쌀쌀맞기 일쑤다. 어느 날 윌이 루이자에게 유독 심한 독설을 퍼붓자 루이자는 참지 못해 그의 태도를 따끔하게 지적하고, 그때부터 윌은 그녀에게 호감을 느끼기 시작한다. 두 사람이 점점 가까워지던 사이, 루이자는 윌이 존엄사를 계획하고 있음을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/aCnkVi4QTuc7E0d0qp0SAnRA3M0.jpg', 2016, 0, 0, '2026-06-06 13:25:23.393805', 'US');
INSERT INTO public.movies VALUES (710, 640146, '앤트맨과 와스프: 퀀텀매니아', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '슈퍼히어로 파트너인 스캇 랭과 호프 반 다인, 호프의 부모 재닛 반 다인과 행크 핌, 그리고 스캇의 딸 캐시 랭까지 미지의 양자 영역 세계 속에 빠져버린 앤트맨 패밀리. 그 곳에서 새로운 존재들과 무한한 우주를 다스리는 정복자 캉을 만나며, 그 누구도 예상 못 한 모든 것의 한계를 뛰어넘는 모험을 시작하게 되는데…', 'https://image.tmdb.org/t/p/w500/sz6mTIDDQmR3DYgJudiTmoW2gR5.jpg', 2023, 0, 0, '2026-06-06 13:25:23.402991', 'US');
INSERT INTO public.movies VALUES (721, 1058424, '호프', '["Sci-Fi", "Mystery", "Action"]', 'Na Hong-jin', '["Hwang Jung-min", "Zo In-sung", "Hoyeon", "Alicia Vikander", "Michael Fassbender"]', '고립된 항구마을 호포항에서 시작된 의문의 존재 공격에 맞서는 주민들의 이야기', 'https://image.tmdb.org/t/p/w500/1n37BJchWHLiSYQkuFxe5KjB951.jpg', 2026, 0, 0, '2026-06-06 13:25:24.15178', 'KR');
INSERT INTO public.movies VALUES (717, 1469458, 'സംഭവം അദ്ധ്യായം ഒന്ന്', '["Fantasy", "Thriller", "Drama"]', 'Jithu Satheesan Mangalathu', '["Askar Ali", "Vineeth Kumar", "Sidharth Bharathan", "Assim Jamal", "Senthil Krishna Rajamani"]', NULL, 'https://image.tmdb.org/t/p/w500/4ASKGsPMbzChx0YX5Pqc9HFXQm3.jpg', 2026, 0, 0, '2026-06-06 13:25:23.419351', 'IN');
INSERT INTO public.movies VALUES (715, 579974, 'RRR: 라이즈 로어 리볼트', '["Action", "History", "Drama"]', 'S. S. Rajamouli', '["N.T. Rama Rao Jr.", "Ram Charan", "Olivia Morris", "Ray Stevenson", "Alison Doody"]', '위험한 임무에 나선 용맹한 전사. 영국을 위해 일하는 냉혹한 경찰과 맞대결을 펼친다. 독립 이전의 인도를 배경으로 한 대서사극.', 'https://image.tmdb.org/t/p/w500/sxI1qKDHZRAi2LPmJUPhQ2x1u07.jpg', 2022, 0, 0, '2026-06-06 13:25:23.414682', 'IN');
INSERT INTO public.movies VALUES (8815, 220289, '평행이론: 도플갱어 살인', '["Thriller", "Sci-Fi"]', 'James Ward Byrkit', '["Emily Baldoni", "Maury Sterling", "Nicholas Brendon", "Lorene Scafaria", "Elizabeth Gracen"]', '파티를 위해 오랜만에 모인 친구들  즐거운 시간을 보내던 중 혜성 충돌로 도시 전체가 정전 사태에 빠지고,  핸드폰 마저 먹통이 되자 모두 이상한 낌새를 느낀다.  설상가상 어둠에 갇힌 그들은 누군가로부터 위협을 받게 되고,  도움을 청하기 위해 몇 명의 친구들이 이웃집으로 향한다.  하지만 그곳에서 발견한 것은 다름 아닌 자기 자신!  보고도 믿지 못할 상황에 충격에 빠진 그들은  살아남기 위해 그 누구도 믿을 수 없게 되고,  살기 위해 또 다른 나와의 싸움을 벌여야 하는데…', 'https://image.tmdb.org/t/p/w500/4vx8kt8R4ac9LNuCqBjjJ9NHhaw.jpg', 2014, 0, 0, '2026-06-08 07:29:47.466356', 'GB');
INSERT INTO public.movies VALUES (714, 346364, '그것', '["Horror", "Thriller", "Drama"]', NULL, '[]', '살인과 실종사건이 이상하게 많이 생기는 데리라는 마을, 비 오는 어느 날 종이배를 들고 나간 동생이 사라졌다.  형 빌은 ‘루저 클럽’ 친구들과 함께 동생을 찾아 나서고, 27년마다 가장 무서워하는 것의 모습을 한 채 아이들을 잡아먹는다는 ‘그것’이 빨간 풍선을 든 삐에로의 모습으로 그들 앞에 나타나는데…  빌과 친구들은 공포를 이겨내고 ‘그것’에 맞서 동생과 사라진 아이들을 찾을 수 있을까?', 'https://image.tmdb.org/t/p/w500/nlZKIOeoSWwrRcrppoIbkfOGZ6J.jpg', 2017, 0, 0, '2026-06-06 13:25:23.412383', 'US');
INSERT INTO public.movies VALUES (724, 696506, '미키 17', '["Sci-Fi", "Comedy", "Adventure"]', 'Bong Joon Ho', '["Robert Pattinson", "Naomi Ackie", "Steven Yeun", "Mark Ruffalo", "Toni Collette"]', '친구 티모와 함께 차린 마카롱 가게가 쫄딱 망해 거액의 빚을 지고 못 갚으면 죽이겠다는 사채업자를 피해 지구를 떠나야 하는 미키. 기술이 없는 그는, 정치인 마셜의 얼음행성 개척단에서 위험한 일을 도맡고, 죽으면 다시 프린트되는 익스펜더블로 지원한다. 4년의 항해와 얼음행성 니플하임에 도착한 뒤에도 늘 미키를 지켜준 여자친구 나샤. 그와 함께, 미키는 반복되는 죽음과 출력의 사이클에도 익숙해진다. 그러나 미키 17이 얼음행성의 생명체인 크리퍼와 만난 후 죽을 위기에서 돌아와 보니 이미 미키 18이 프린트되어 있다. 행성 당 1명만 허용된 익스펜더블이 둘이 된 멀티플 상황. 둘 중 하나는 죽어야 하는 현실 속에 걷잡을 수 없는 사건이 기다리고 있었으니…', 'https://image.tmdb.org/t/p/w500/mH7QnJDxQibVZw0M66IBZbsw2O6.jpg', 2025, 0, 0, '2026-06-06 13:25:24.169731', 'GB');
INSERT INTO public.movies VALUES (723, 1124, '프레스티지', '["Drama", "Mystery", "Sci-Fi"]', 'Christopher Nolan', '["Hugh Jackman", "Christian Bale", "Michael Caine", "Piper Perabo", "Rebecca Hall"]', '로버트 앤지어는 상류층 집안에서 자란 쇼맨십이 강한 마술사다. 반면 고아로 사람들과 잘 어울리지 못하는 알프레드 보든은 아이디어를 남들에게 보여 줄 배짱은 없지만 누구보다도 뛰어난 재능을 가진 천재이다. 두 사람은 서로를 아끼는 친구이자 선의의 경쟁자였지만, 그들이 최고라 자부했던 수중 마술이 실패로 돌아가면서 두 사람은 철천지 원수로 돌변한다. 서로 상대방 마술의 비밀을 캐내려 경쟁을 벌이는 가운데, 로버트는 알프레드의 비밀을 알아내기 위해 자신의 조수이자 사랑하는 여인 올리비아를 알프레드에게 접근하게 만든다.', 'https://image.tmdb.org/t/p/w500/pN3H35IXZb9Aiew4BWLiloWQe7q.jpg', 2006, 0, 0, '2026-06-06 13:25:24.166944', 'GB');
INSERT INTO public.movies VALUES (718, 58008, 'L''infermiera di notte', '["Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/cjJuN9MUmYrSh3fzT7JHrN5fHOP.jpg', 1979, 0, 0, '2026-06-06 13:25:23.421617', 'US');
INSERT INTO public.movies VALUES (2510, 61823, '원숭이 여인', '["Drama", "Comedy"]', NULL, '[]', '한 사기꾼이 수녀들이 운영하는 시설에서 얼굴이 털로 뒤덮인 아름다운 여인을 발견한다. 그는 즉시 특별한 사업 아이템을 구상하는데, 바로 ‘원숭이 여인’이 출연하는 공연을 펼치는 것이다. 그렇게 여러 마을을 돌아다니기 시작한 두 사람은 기대보다 더 큰 인기를 누리며 갖가지 사건들과 마주한다.  (2017년 한국시네마테크협의회 - 2017 베니스 인 서울)', 'https://image.tmdb.org/t/p/w500/aSSGRLYNubTyE4BEophnEr9IUIg.jpg', 1964, 0, 0, '2026-06-07 12:17:35.794978', 'US');
INSERT INTO public.movies VALUES (8816, 578149, 'Better Gay Sex', '[]', 'Steve Bulfield', '["David Demeter", "Richard Hochuli", "Brian McElroy", "Paul Bales", "Yanni Van Stadan"]', NULL, 'https://image.tmdb.org/t/p/w500/prgC0s1VNjpfoi9siT4ZO0jHHS9.jpg', 1994, 0, 0, '2026-06-08 07:29:48.223626', 'GB');
INSERT INTO public.movies VALUES (947, 1424965, '더 드리프트', '["Drama", "Thriller"]', NULL, '[]', '북극해의 빙산에 고립된 피겨 스케이터를 중심으로 펼쳐지는 생존 드라마. 빙산이 남쪽으로 떠내려가 녹기 시작하자, 피겨 스케이터는 살아남기 위해 모든 수단을 동원해야 한다.', 'https://image.tmdb.org/t/p/w500/m93BKabB7Je8WQACed58BXeHNNR.jpg', 2026, 0, 0, '2026-06-06 13:25:32.701406', 'US');
INSERT INTO public.movies VALUES (716, 1173558, '뜨거운 배신', '["Drama", "Mystery", "Romance"]', NULL, '[]', '약혼자에게 배신당한 회계사. 배신감에 빠져 있기보다 성적인 자유에 눈뜰 기회로 삼기로 한다. 하지만 위험한 결과가 뒤따라온다. 수 헤케르의 소설을 각색한 작품.', 'https://image.tmdb.org/t/p/w500/8MqXNQbR6v9Opj7gOfoOKpFwm8O.jpg', 2023, 0, 0, '2026-06-06 13:25:23.417044', 'US');
INSERT INTO public.movies VALUES (4334, 465603, '스와핑: 친구의 아내', '["Romance", "Drama"]', 'Hong Seong-soo', '["Ahn So-hee", "Lee Chae-dam", "Kim Cheol-soo-II", "Kang Min-woo", "Je Dong-hwa"]', '일 욕심이 많은 아내 혜주를 위해 가정주부가 되기로 결심한 성식. 홀로 살림을 하느라 고군분투하는 성식의 바로 옆집에 친구 준석 부부가 이사 온다. 준석의 아내 은영에게 살림을 배우게 된 성식. 처음에는 말 잘 통하는 친구 같았던 성식과 은영은 곧 틈만 나면 자신의 아내와 남편 몰래 서로를 탐하게 되고, 이를 알아차린 준석과 혜주 또한 그동안 참아왔던 욕망에 눈을 뜨는데...', 'https://image.tmdb.org/t/p/w500/pPJSi1vcaN2YQjG4AzRM4b3mdIQ.jpg', 2016, 0, 0, '2026-06-08 06:30:24.122763', 'KR');
INSERT INTO public.movies VALUES (2523, 1293550, 'बंदर', '["Thriller"]', 'Anurag Kashyap', '["Bobby Deol", "Sanya Malhotra", "Saba Azad", "Sapna Pabbi", "Jitendra Joshi"]', NULL, 'https://image.tmdb.org/t/p/w500/3TrQUHmnEL2tOYf4KKkXb01BQt2.jpg', 2026, 0, 0, '2026-06-07 12:17:36.621797', 'IN');
