INSERT INTO public.movies VALUES (731, 1650558, 'Abot Langit', '["Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/5lVYe4aSimWdxJINKwq9s68TZ2G.jpg', 2026, 0, 0, '2026-06-06 13:25:24.18771', 'US');
INSERT INTO public.movies VALUES (733, 10144, '인어공주', '["Animation", "Family", "Fantasy"]', NULL, '[]', '바다의 왕 트리톤의 막내딸 에리얼은 사랑스럽고 아름다운 목소리를 가져 모든 이들의 사랑을 독차지하고 있다. 인간 세계에 대한 왕성한 호기심을 갖고 있던 에리얼은 어느날 인간 세상 근처에 갔다가 생일 파티 중인 왕자를 보고 한눈에 반한다. 배가 폭풍을 만나 바다에 빠진 왕자를 구한 에리얼은 그를 진심으로 사랑하게 되고 그의 곁에 있고 싶어한다. 그 사실을 알게 된 마녀 우슬라는 에리얼에게 다리를 주는 대신 그녀의 목소리를 가지기로 한다. 3일 안에 왕자의 키스를 받지 못하면 우슬라에게 영혼을 빼앗기기 때문에 친구인 세바스찬과 플라우더는 갖은 방법을 써서라도 왕자와 에리얼이 잘 되도록 하려고 한다.', 'https://image.tmdb.org/t/p/w500/dxEZkFIxuLjyS6VEHeirlURHlrt.jpg', 1989, 0, 0, '2026-06-06 13:25:24.192225', 'US');
INSERT INTO public.movies VALUES (520, 111, '스카페이스', '["Action", "Crime", "Drama"]', NULL, '[]', '1980년 5월 쿠바가 마리엘 항을 개항하여 반카스트로 지지자들이 미국 플로리다에 입항한다. 토니 몬타나와 마니리베라도 이민 수용소로 보내진다. 3개월 후 마니가 수용소에 있는 레벤가라는 자를 살해해 주면 신분증을 입수해 주겠다는 일을 받아 수용소에 폭동을 일으켜 레벤가를 암살한다. 접시닦이로 근근히 살아가던 토니는 프랭크의 부하로부터 콜롬비아 마약상과의 거래일을 맡았다가 위험천만한 위기를 넘긴다. 그 사건을 계기로, 토니는 프랭크의 신임을 얻고 그의 부하가 되지만, 수 개월 후 결국 자신을 없애려는 프랭크를 죽이고 조직을 장악, 보스 자리에 오르는데...', 'https://image.tmdb.org/t/p/w500/zx7sXrMISbs8RI4URbjPyKocRgP.jpg', 1983, 0, 0, '2026-06-06 13:25:15.716727', 'US');
INSERT INTO public.movies VALUES (2513, 1421155, 'Ikatan Darah', '["Action", "Crime", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/lF9amilOGIudUIq6NgDnz2YrPPa.jpg', 2026, 0, 0, '2026-06-07 12:17:35.804359', 'US');
INSERT INTO public.movies VALUES (728, 76492, '몬스터 호텔', '["Animation", "Comedy", "Family", "Fantasy"]', NULL, '[]', '몬스터들의 유일한 천국, 인간출입금지 몬스터 호텔.  딸바보 드라큐라는 딸 마비스의 118번째 생일을 맞아  프랑켄슈타인, 늑대인간, 미이라, 투명인간 등 몬스터 친구들을 모두 초대한다.  그.런.데! 초대받지 않은 인간소년 조니가 나타나고, 몬스터들은 멘붕 상태에 빠진다.  과연, 몬스터들은 신나는 파티를 즐길 수 있을까?', 'https://image.tmdb.org/t/p/w500/nZapoab0MzOY11IcNEMIYJDoljF.jpg', 2012, 0, 0, '2026-06-06 13:25:24.180612', 'US');
INSERT INTO public.movies VALUES (729, 1087040, '머니 샷: 폰허브를 말하다', '["Documentary"]', NULL, '[]', '폰허브의 성공과 추문에 대해 깊숙이 파헤친다. 배우, 운동가 그리고 전직 직원들의 인터뷰로 이루어진 다큐멘터리.', 'https://image.tmdb.org/t/p/w500/kpTqWqLYcf1uErnx5VXLah4EWJZ.jpg', 2023, 0, 0, '2026-06-06 13:25:24.183056', 'US');
INSERT INTO public.movies VALUES (744, 1403735, 'లైలా', '["Comedy", "Romance"]', 'Ram Narayan', '["Vishwak Sen", "Akanksha Sharma", "Babloo Prithiveeraj", "Abhimanyu Singh", "Vineet Kumar"]', NULL, 'https://image.tmdb.org/t/p/w500/l4gsNxFPGpzbq0D6QK1a8vO1lBz.jpg', 2025, 0, 0, '2026-06-06 13:25:24.940468', 'IN');
INSERT INTO public.movies VALUES (738, 575264, '미션 임파서블: 데드 레코닝 PART ONE', '["Action", "Adventure", "Thriller"]', NULL, '[]', '모든 인류를 위협할 새로운 무기를 추적하게 된 에단 헌트와 IMF팀은 이 무기가 인류의 미래를 통제할 수 있다는 사실을 알게 된다. 전 세계가 위태로운 상황에 처한 가운데, 이를 추적하던 에단 헌트에게 어둠의 세력까지 접근하고 마침내 미스터리하고 강력한 빌런과 마주하게 된 그는 가장 위험한 작전을 앞두고 자신이 아끼는 사람들의 생명과 중요한 임무 사이에서 선택을 해야 하는 상황에 놓이게 되는데…', 'https://image.tmdb.org/t/p/w500/dIcLgXA6R54EZ0XPSMKW4XDNCAA.jpg', 2023, 0, 0, '2026-06-06 13:25:24.203698', 'US');
INSERT INTO public.movies VALUES (740, 667538, '트랜스포머: 비스트의 서막', '["Sci-Fi", "Adventure", "Action"]', NULL, '[]', '전 우주의 행성을 집어삼키는 절대자, ‘유니크론’의 부하 ‘스커지’는 ‘테러콘’들을 이끌고 지구에 당도한다. 그에 맞서기 위해 지구에 정체를 숨기고 있던 트랜스포머 ‘오토봇’ 군단이 모습을 드러내고 또 다른 트랜스포머 진영인 ‘맥시멀’과 힘을 합친다. 옵티머스 프라임이 이끄는 ‘오토봇’과 옵티머스 프라이멀을 중심으로 한 ‘맥시멀’. 모두의 운명을 건 그들의 압도적 전투가 시작된다!', 'https://image.tmdb.org/t/p/w500/chUZNPNd7EiETSB4xBGykXhuXRr.jpg', 2023, 0, 0, '2026-06-06 13:25:24.208252', 'US');
INSERT INTO public.movies VALUES (739, 135397, '쥬라기 월드', '["Adventure", "Sci-Fi", "Thriller"]', NULL, '[]', '쥬라기 공원 사건에서 22년이 지난 후, 이슬라 누블라에서는 새로 열린 쥬라기 공원이 정상적으로 영업 중이다. 유전자 조작으로 탄생한 공룡들을 앞세운 쥬라기 월드는 지상 최대의 테마파크로 자리잡는다. 하지만 유전공학자들이 그 동안의 연구를 바탕으로 탄생시킨 새로운 유전자 조작 하이브리드 공룡들은 지능과 공격성을 끝없이 진화시키며 인간의 통제를 벗어날 조짐을 보인다. 한편 오랫동안 벨로시랩터를 연구해온 오웬 그래디(크리스 프랫)는 이런 시도에 반대하고, 그가 예상한 대로 이 하이브리드 공룡이 탈출하면서 공원은 아수라장이 되는데...', 'https://image.tmdb.org/t/p/w500/zJ5pZvsd5I8HYnRRAvLE2tSxtOW.jpg', 2015, 0, 0, '2026-06-06 13:25:24.205918', 'US');
INSERT INTO public.movies VALUES (736, 140300, '쿵푸팬더 3', '["Animation", "Action", "Adventure", "Comedy", "Family"]', NULL, '[]', '어느 날 우연히, 어린 시절 잃어버렸던 진짜 팬더 아버지를 만난 포는 아버지 리와 함께 팬더들이 어울려 사는 비밀스러운 그 곳, 팬더 마을로 향한다. 자신 못지 않게 여유와 흥 넘치는 팬더들과 즐거운 시간을 보내는 포. 하지만 모든 쿵푸 마스터들을 제압하며 전세계를 위협하는 악당 카이의 등장으로 포는 예상치 못했던 불가능한 도전에 맞닥뜨리게 된다. 놀기 좋아하고, 먹는 게 행복이며, 덤벙대는 게 특기인 팬더 친구들에게 궁극의 쿵푸를 전수해야 하는 것!', 'https://image.tmdb.org/t/p/w500/vMaqgPgMhO1XvwzoEAurUKVQJNV.jpg', 2016, 0, 0, '2026-06-06 13:25:24.199064', 'US');
INSERT INTO public.movies VALUES (741, 748783, '가필드 더 무비', '["Adventure", "Animation", "Comedy", "Family"]', 'Mark Dindal', '["Chris Pratt", "Samuel L. Jackson", "Hannah Waddingham", "Ving Rhames", "Nicholas Hoult"]', '세상귀찮 집냥이, 바쁘고 험난한 세상에 던져졌다! 집사 ‘존’과 반려견 ‘오디’를 기르며 평화로운 나날을 보내던 집냥이 ‘가필드’. 어느 날, 험악한 길냥이 무리에게 납치당해 냉혹한 거리로 던져진다. 돌봐주는 집사가 없는 집 밖 세상은 너무나도 정신없게 돌아가고 길에서 우연히 다시 만난 아빠 길냥이 ‘빅’은 오히려 ‘가필드’를 위기에 빠지게 하는데… 험난한 세상, 살아남아야 한다!', 'https://image.tmdb.org/t/p/w500/8tmtj4WIJEYVXxlrDcO6SqQN0Vz.jpg', 2024, 0, 0, '2026-06-06 13:25:24.932602', 'GB');
INSERT INTO public.movies VALUES (8831, 116149, '패딩턴', '["Comedy", "Adventure", "Family"]', 'Paul King', '["Ben Whishaw", "Hugh Bonneville", "Sally Hawkins", "Madeleine Harris", "Samuel Joslin"]', '폭풍우에 가족을 잃은 꼬마곰 패딩턴은 페루에서 영국까지 나홀로 여행을 떠난다. 런던에 도착한 패딩턴은 우연히 브라운 가족을 만나게 되고 그들의 도움을 받아 새로운 가족을 찾아 나선다. 하지만 움직이기만 해도 사고, 만지기만 해도 사고, 1초에 한번씩 사고를 치는 패딩턴은 브라운 가족의 골칫거리가 되고 만다. 한편, 말하는 곰이 나타났다는 소식에 악당 박제사 밀리센트는 호시탐탐 패딩턴을 노리는데…', 'https://image.tmdb.org/t/p/w500/5VXMYfHN8BSScA9cOQKC59NKwcO.jpg', 2014, 0, 0, '2026-06-08 07:30:00.607125', 'GB');
INSERT INTO public.movies VALUES (743, 13009, '좀비 스트리퍼스', '["Comedy", "Horror", "Sci-Fi"]', NULL, '[]', '가까운 미래, 부시의 장기집권으로 미국은 수많은 나라와 전쟁을 벌이고, 군인들이 부족해지자 국방 과학연구소는 이를 해결할 수 있는 획기적인 연구결과를 내놓는다. 바로 시체를 살리는 약물 키모 바이러스이다. 그러나 키모 바이러스가 연구소에 퍼지자 실험대상들은 좀비가 되고, 그들을 없애기 위해 군인들이 투입된다. 동료들과 좀비를 사살하던 버드플루는 좀비에게 물려 감염되고 사살될 것이 두려워 도망친다. 불법 스트립바로 숨어든 그는 스트립 쇼걸을 물고, 쇼걸들은 하나 둘씩 좀비가 되는데....', 'https://image.tmdb.org/t/p/w500/iQcOzXCpewM9pbEwLoIrHLjpMvB.jpg', 2008, 0, 0, '2026-06-06 13:25:24.93807', 'US');
INSERT INTO public.movies VALUES (737, 653346, '혹성탈출: 새로운 시대', '["Sci-Fi", "Adventure", "Action"]', NULL, '[]', '진화한 유인원과 퇴화된 인간들이 살아가는 땅. 유인원 리더 프록시무스는 완전한 군림을 위해 인간들을 사냥하며 자신의 제국을 건설한다. 한편, 또 다른 유인원 노아는 우연히 숨겨진 과거의 이야기와 시저의 가르침을 듣게 되고 인간과 유인원이 함께 할 새로운 세상을 꿈꾼다. 어느 날 그의 앞에 나타난 의문의 한 인간 소녀. 노아는 그녀와 함께 자유를 향한 여정을 시작하게 되는데…', 'https://image.tmdb.org/t/p/w500/caNBYk7beRAg8Tcpe7ZjzM2nYXH.jpg', 2024, 0, 0, '2026-06-06 13:25:24.201323', 'US');
INSERT INTO public.movies VALUES (752, 474350, '그것: 두 번째 이야기', '["Horror", "Thriller", "Drama"]', NULL, '[]', '27년마다 아이들이 사라지는 마을 데리, 또 다시 ‘그것’이 나타났다. 27년 전, 가장 무서워하는 것의 모습으로 나타나 아이들을 잡아먹는 그것 페니와이즈에 맞섰던 ‘루저 클럽’ 친구들은 어른이 되어도 더 커져만 가는 그것의 공포를 끝내기 위해 피할 수 없는 마지막 대결에 나선다.', 'https://image.tmdb.org/t/p/w500/cGevUnUmfibLL51Zj3R1oZW9adt.jpg', 2019, 0, 0, '2026-06-06 13:25:24.959329', 'US');
INSERT INTO public.movies VALUES (748, 1008042, '톡 투 미', '["Horror"]', NULL, '[]', 'SNS에서 핫한 빙의 챌린지에 중독된 미아와 친구들. 위험한 게임을 이어가던 중 친구 라일리가 미아의 죽은 엄마에게 빙의되자 미아는 이성을 잃고 마의 90초를 넘기고 마는데...', 'https://image.tmdb.org/t/p/w500/bYxNkZpRAygeo1Kbo79KJOn2Qjr.jpg', 2023, 0, 0, '2026-06-06 13:25:24.949948', 'US');
INSERT INTO public.movies VALUES (754, 1087891, '아마추어', '["Thriller", "Action"]', NULL, '[]', '어느 날, 사랑하는 아내가 살해당했다. 내가 소속된 CIA는 침묵했고 진실은 묻혔다. 나는 프로 킬러도, 현장 요원도 아니다. 암호를 풀던 내가 이제는 복수를 설계한다. 놈들을 반드시 찾아내서 똑같이 갚아줄 것이다. 컴퓨터나 두들기는 범생이, 총 한 발 못 쏘는 ‘아마추어’라고 생각했겠지만, 내가 잘하는 게 뭔지 알기나 해?', 'https://image.tmdb.org/t/p/w500/cmwcZimmMNzEUoXQenGAcWaxmge.jpg', 2025, 0, 0, '2026-06-06 13:25:24.963841', 'US');
INSERT INTO public.movies VALUES (755, 7485, '더블 타겟', '["Drama", "Action", "Thriller"]', NULL, '[]', '은둔중이던 전직 특수부대 최강 스나이퍼 스웨거(마크 윌버그)는 어느날 정부 고위 관계자 존슨대령(대니 글로버)으로부터 대통령 암살 조짐이 있으니 이를 막아달라는 요청을 받는다. 누구도 따라 올 수 없는 저격기술을 지닌 스나이퍼로서 자신의 경험과 노하우로 미리 범행 장소와 방법을 연구하는 스웨거. 대통령 암살 예정 당일, 치밀하고 정확한 예측을 했다는 이유로 스웨거가 범인으로 지목 된다. 스웨거는 현장에서 도망가던 중 부상을 입고, 미국 정부에게도 쫓기게 된 절대절명의 위기를 맞는다. 이제 미국 정부 VS 최강 스나이퍼의 전쟁이 시작된다!', 'https://image.tmdb.org/t/p/w500/eF4EnO3xjofoCKYgv9FbLAScZup.jpg', 2007, 0, 0, '2026-06-06 13:25:24.966053', 'US');
INSERT INTO public.movies VALUES (4156, 853376, '별장하녀들', '["Drama"]', 'Pae Kon', '["Joo Ah", "Rika", "Kim Ji-ah", "Sae Bom", "Seung Ha"]', '한순간의 실수 때문에 시골 별장으로 유배를 떠나게 된 재벌 2세.INSERT INTO public.movies VALUES (763, 1144107, '나소흑전기 2: 우리가 원하는 미래', '["Animation", "Fantasy", "Action", "Adventure"]', NULL, '[]', '공격이 영계와 인간계 사이의 위태로운 평화를 깨뜨리자, 헤이는 스승 무현의 마지막 제자 루예와 힘을 합쳐 양계를 위협하는 음모를 밝혀낸다. 그들이 지키기로 맹세한 유대마저 위태롭게 하는 음모를.', 'https://image.tmdb.org/t/p/w500/rmdy6AVOlFEne4IM5Jj0WBOhCBP.jpg', 2025, 0, 0, '2026-06-06 13:25:25.710249', 'US');
INSERT INTO public.movies VALUES (751, 126889, '에이리언: 커버넌트', '["Horror", "Sci-Fi"]', NULL, '[]', '2천명의 승객과 12명의 승무원을 실은 커버넌트호는 새로운 행성의 개척과 이주를 위해 항해 중이다. 인공지능 로봇 월터가 홀로 깨어 승무원들의 건강을 관리하던 중 예기치 못한 사고로 선장이 사망하고 승무원들이 깨어난다. 이들은 커버넌트호를 정비하던 중 인근의 행성으로부터 알 수 없는 신호를 감지한다. 여행에 지친 승무원들은 다니엘스의 반대에도 불구하고 행성을 탐사하기로 결정한다. 이들은 정체불명의 생명체에 감염되어 위기에 빠지지만 10년 전 사라졌던 프로메테우스호의 인공지능 로봇 데이비드의 도움을 받아 상황을 모면하는데...', 'https://image.tmdb.org/t/p/w500/qTiZhRh4y152Gj5jvEXMPmQZ71m.jpg', 2017, 0, 0, '2026-06-06 13:25:24.957033', 'US');
INSERT INTO public.movies VALUES (4161, 719128, '아이돌 섹스: LA 교포녀', '["Romance", "Drama"]', 'Jeong Mi-na', '["Lee Chae-dam", "Hae Il", "Jo Wan-jin", "Kim So-jin", "Tae Hee"]', NULL, 'https://image.tmdb.org/t/p/w500/d6HcmOCX204Cc1HK6czTGEKD7UJ.jpg', 2020, 0, 0, '2026-06-08 06:27:51.87311', 'KR');
INSERT INTO public.movies VALUES (4370, 687003, '새엄마의 목적', '["Drama"]', 'Lee Ro-woon', '["Yoo Jung", "Gil Dong", "Sung Yeon", "Lee Sul-ah"]', '와이프와 이혼하고 혼자 자주 가던 술집 여성과 사랑에 빠진 남자. 남자에게는 아들이 있고 술집여자에게는 딸이 있는 걸 알면서도 같이 살기로 한다. 어느 날 혼자 남게 된 엄마는 집 청소를 하다가 우연히 서류를 보게 되고 집과 모든 재산이 아들에게 상속 돼 있는 걸 알게 된다. 재산을 노리고 들어온 엄마의 속내가 들어나고, 다음날부터 아들에게 잘 보이기 위해 아들의 눈에 보이도록 엄마는 자꾸 자신의 신체부위를 노출시켜 아들의 관심을 끈다.', 'https://image.tmdb.org/t/p/w500/sePfMZqKg7NX3Sn0gp7k3M6RTxa.jpg', 2020, 0, 0, '2026-06-08 06:30:50.373544', 'KR');
INSERT INTO public.movies VALUES (759, 1034541, '테리파이어 3', '["Horror"]', NULL, '[]', '5년 전 벌어진 ''아트 더 크라운''의 대학살에서 살아남은 시에나와 조나단 남매는 여전히 그날의 끔찍한 기억에 시달리며 힘겨운 일상을 이어간다. 크리스마스를 맞아 따뜻한 일상으로 복귀하려 노력하던 그들 앞에, 또다시 마을 곳곳에서 벌어지는 잔혹한 살인 사건들이 이어지고, 시에나는 아트의 귀환을 목격하게 된다. 아트는 크리스마스의 행복을 공포로 물들이며, 또 한 번의 악몽을 현실로 만들려 한다. 이제 시에나는 사랑하는 사람들과 마을을 지키기 위해 그 악몽에 맞서야 한다.', 'https://image.tmdb.org/t/p/w500/ju10W5gl3PPK3b7TjEmVOZap51I.jpg', 2024, 0, 0, '2026-06-06 13:25:24.975032', 'US');
INSERT INTO public.movies VALUES (757, 10625, '퀸카로 살아남는 법', '["Drama", "Comedy"]', NULL, '[]', '동물학자인 아버지를 따라 아프리카에서 성장한 케이디는 일리노이즈의 고등 학교로 전학을 오게 된다. 케이디가 전학 온 고등학교에는 레지나라는 퀸카가 그녀의 매력을 주무기로 학교의 여왕으로 군림을 하고 있었다.  레지나는 케이디가 지닌 미모와 지성이 자신이 누리고 있는 교내 ''여왕벌''의 위치를 위협할 수 있다고 판단하고 그녀를 감시할 목적으로 케이디에게 접근을 하여 둘은 친구가 된다. 케이디는 수학시간에 만난 남학생 애런 사무엘에게 한눈에 반하여 그와 사귀려는 노력을 하지만 그는 바로 레지나의 헤어진 남자 친구였다. 케이디가 애런에게 관심이 있는 것을 안 레지나는 고의로 그들의 사이를 방해하고 케이디에게 모욕감을 느끼게 한다. 이 일을 계기로 케이디는 레지나를 극도로 미워하게 되고 둘 사이에는 서로상대를 꺽기 위한 숨막히는 권모술수가 동원된 팽팽한 대결이 시작되는데.', 'https://image.tmdb.org/t/p/w500/6WcZxeBF5rOrTr7cocljvu3ET77.jpg', 2004, 0, 0, '2026-06-06 13:25:24.970509', 'US');
INSERT INTO public.movies VALUES (762, 263115, '로건', '["Action", "Drama", "Sci-Fi"]', NULL, '[]', '2029년 알 수 없는 이유로 돌연변이들이 태어나지 않는 미래, 더이상 엑스맨은 없다. 갈수록 재생력이 약해져 늙고 수척해진 로건은 멕시코 국경지대 은신처에 찰스 교수를 보호 중이다. 뇌에 심각한 손상을 입은 찰스 교수는 과거를 제대로 기억하지 못하는 데다 간헐적으로 주변을 위협하는 발작까지 일으킨다. 찰스 교수와 함께 떠날 배를 사기 위해 리무진 기사로 일하며 돈을 모으는 로건. 어느 날 낯선 여인이 찾아와 돌연변이 소녀 로라를 캐나다 국경까지 데려다 달라고 부탁한다. 로건은 로라를 쫓는 기업의 경호집단을 피해 험난한 여정을 떠난다.', 'https://image.tmdb.org/t/p/w500/tE6tvHXlAZ8hqM4k9ZvtWtBk4pc.jpg', 2017, 0, 0, '2026-06-06 13:25:25.706267', 'US');
INSERT INTO public.movies VALUES (614, 28, '지옥의 묵시록', '["Drama"]', NULL, '[]', '미국 특수부대의 윌라드 대위는 고향에 돌아갔다가 아내가 내민 이혼장에 도장을 찍고 다시 정글로 돌아온다. 혼돈과 막연한 갈망에 시달리던 윌라드에게 떨어진 임무는 캄보디아에 자신의 왕국을 건설한 커츠 대령을 암살하라는 것. 커츠 대령은 한때 가장 뛰어난 군인으로 인정받았으나 미국의 통제를 벗어나 캄보디아에서 독자적인 왕국을 거느리고 있다. 윌라드 대위는 4명의 병사들과 함께 커츠 대령을 찾아 나선다. 폭염과 광기로 가득한 전투를 겪으면서 두려움과 공포로 이성을 잃어가던 그들은 마침내 커츠 대령의 왕국에 도착한다. 그리고 그곳에서 윌라드 대위는 상상을 초월하는 진실을 마주하게 되는데...', 'https://image.tmdb.org/t/p/w500/giP5yeJBrsqglkM05pbiTyRsoBa.jpg', 1979, 0, 0, '2026-06-06 13:25:19.568451', 'US');
INSERT INTO public.movies VALUES (4162, 696026, '착한처제 2019', '["Drama", "Romance"]', 'Wang Ji-bang', '["Jin Joo", "Jo Wan-jin", "Ha Jin"]', NULL, 'https://image.tmdb.org/t/p/w500/vnCyIfkkvfR4gPeaEZ7LQem5Bd7.jpg', 2019, 0, 0, '2026-06-08 06:27:52.548392', 'KR');
INSERT INTO public.movies VALUES (335, 210577, '나를 찾아줘', '["Mystery", "Thriller", "Drama"]', 'David Fincher', '["Ben Affleck", "Rosamund Pike", "Neil Patrick Harris", "Tyler Perry", "Carrie Coon"]', '모두가 부러워하는 삶을 살아가는 완벽한 커플인 닉과 에이미. 결혼 5주년 기념일 아침, 에이미가 흔적도 없이 실종된다. 유년시절 어린이 동화 시리즈 어메이징 에이미의 실제 여주인공이었던  유명인사 아내가 사라지자, 세상은 그녀의 실종사건으로 떠들썩해진다. 한편 경찰은 에이미가 결혼기념일 선물로 숨겨뒀던 편지와 함께  곳곳에서 드러나는 단서들로 남편 닉을 유력한 용의자로 지목한다. 미디어들이 살인 용의자 닉의 일거수일투족을 보도하기 시작하고, 시간이 갈수록 세상의 관심이 그에게 더욱 집중되는데...', 'https://image.tmdb.org/t/p/w500/m2Lw04GIjiTjylqPiccoo3WFMVb.jpg', 2014, 0, 0, '2026-06-06 13:25:08.711687', 'US');
INSERT INTO public.movies VALUES (4160, 791128, '막장자매 클라쓰', '["Drama", "Romance"]', NULL, '["Seung Ha", "Yoon Yool", "Kim Dong-woo", "Kang Min-woo", "Park Do-jin"]', NULL, 'https://image.tmdb.org/t/p/w500/ce29t67HRvnOwjEHuDaUByPnJXR.jpg', 2020, 0, 0, '2026-06-08 06:27:51.176948', 'KR');
INSERT INTO public.movies VALUES (2540, 467905, '하우 투 메이크 어 킬링', '["Comedy", "Thriller"]', 'John Patton Ford', '["Glen Powell", "Margaret Qualley", "Jessica Henwick", "Bill Camp", "Zach Woods"]', NULL, 'https://image.tmdb.org/t/p/w500/vxMeKC7o5Gi8IHMi6lUgsdprTqv.jpg', 2026, 0, 0, '2026-06-07 12:17:36.66363', 'GB');
INSERT INTO public.movies VALUES (4371, 451417, '옆집 소녀', '["Romance"]', 'Park Sun-Uk', '["Hong Sae-hee", "Ha Bin", "Choi Yong-joon", "Min Do-yoon", "Jeong Hyang"]', '이사 온 첫날부터 옆집 신음소리에 잠을 설친 세희. 섹스 경험이 없는 세희는 자립하기 위해 야한 소설을 쓰고 있다. 바람둥이 성현은 섹파 지아에 싫증을 느끼던 중 옆집소녀가 야설작가 임을 알게 된다. 세희의 작업을 도와주게 된 성현~ 소설보단 세희에게 관심이 있는 성현은 소설을 미끼로 세희와의 로맨틱한 섹스를 꿈꾼다. 과연, 세희의 야설은 완성 될 수 있을까?', 'https://image.tmdb.org/t/p/w500/sg2xNXLacKgj9NHm8M6Tv1HTIhB.jpg', 2017, 0, 0, '2026-06-08 06:30:51.126695', 'KR');
INSERT INTO public.movies VALUES (4166, 852363, '18 모델 리카의 화려한 외출', '["Drama", "Romance"]', 'Choi Jin-chul', '["Rika", "Joo Ah", "Si Hoo"]', NULL, 'https://image.tmdb.org/t/p/w500/neTFIO3YIDcH6p8e8a0ka0V21fO.jpg', 2020, 0, 0, '2026-06-08 06:27:55.953578', 'KR');
INSERT INTO public.movies VALUES (769, 928358, '그랑 쥬테: 은밀한 몸짓', '["Drama"]', NULL, '[]', '유명한 발레 무용수로 활동했던 나자는 스스로에 대한 통제와 혹독한 훈련으로 자신을 끝없는 고통 속으로 몰아갔다. 그러나 현재 발레 교사로서의 삶은 나자의 어떤 공허함을 채울 수가 없다. 그녀는 새로운 삶을 찾기 위해 어머니가 있는 곳으로 돌아가 10대에 낳아 어머니 손에서 키운 자신의 아들 마리오를 만난다. 둘은 서로를 낯선 이처럼 느끼며 강하게 이끌리고 도덕적 관습을 뛰어넘는 강렬한 관계로 발전한다. 그러나, 이 만남은 각자 자기 자신만을 인식하기 위한 몸부림으로 변하기 시작한다.', 'https://image.tmdb.org/t/p/w500/7pw6mRwsJDHgwnf4wSUsaEHtnB0.jpg', 2022, 0, 0, '2026-06-06 13:25:25.728559', 'US');
INSERT INTO public.movies VALUES (562, 8355, '아이스 에이지 3: 공룡시대', '["Animation", "Comedy", "Family", "Adventure"]', NULL, '[]', '얼음 위가 아니라 얼음 아래 세계가 궁금하다고?  세상을 발칵 뒤집는 야생 스캔들(?)이 터진다!!  얼음이 녹는 절체절명의 위기를 이겨낸 빙하기 친구들 매니, 엘리, 시드, 디에고. 공식 커플 매니와 엘리는 아기 맘모스 탄생 준비에 호들갑이고, 소외감을 느끼던 시드는 자신도 가족을 갖겠단 욕심에 그만 공룡 알을 훔치고 만다. 지하 공룡 세계를 발칵 뒤집어 놓은 이 대형 사건으로 인해, 위험에 처한 시드를 구하려는 빙하기 친구들은 얼음 속 신비한 야생의 세계 속으로 들어가게 되는데… 지나가는 곳곳마다 거대한 공룡들의 위협이 도사리는 숲 속에서 만난 공룡 사냥꾼 애꾸눈 벅은 지금껏 상상할 수 없었던 새로운 모험으로 빙하기 친구들을 이끈다. 한편 도토리를 쫓아 지하 공룡세계까지 도착한 스크랫 앞에 나타난 도토리 라이벌 초절정 섹시미녀 스크래티!! 거부할 수 없는 그녀의 유혹과 도토리를 향한 순정사이에서 갈등하는 스크랫의 파란만장한 운명이 예고되는데…', 'https://image.tmdb.org/t/p/w500/zty1hzthRVGgMDFU1B1uo8zfCk7.jpg', 2009, 0, 0, '2026-06-06 13:25:17.972924', 'US');
INSERT INTO public.movies VALUES (767, 232672, '블렌디드', '["Comedy", "Romance"]', NULL, '[]', '아내와 사별한 남자 ‘짐’(아담 샌들러)과 남편과 이혼하고 홀로 두 아들을 키우고 있는 ‘로렌’(드류 베리모어)은 소개팅에서 처음 만난다. 장소부터 음식, 대화까지 모든 게 엉망이었던 첫 만남으로 그들은 서로에 대해 최악의 첫인상을 가진 채 헤어진다. 우연한 기회로 짐과 로렌은 각자의 아이들과 함께 광활한 대자연의 아프리카로 여행을 떠나게 되고, 둘 사이에 평범하지 않은 로맨스가 싹트게 되는데…', 'https://image.tmdb.org/t/p/w500/o2YrH9jS7CAfWjETHFeL0tth79E.jpg', 2014, 0, 0, '2026-06-06 13:25:25.722468', 'US');
INSERT INTO public.movies VALUES (766, 18239, '뉴 문', '["Adventure", "Fantasy", "Drama", "Romance"]', NULL, '[]', '초능력을 가진 뱀파이어 에드워드는 인간 벨라가 자신 때문에 위험해지자 냉정하게 그녀를 떠난다.  이제 벨라를 지키는 것은 오랜 친구 제이콥. 하지만 제이콥은 뱀파이어와 적을 이루는 늑대인간 ‘퀼렛족’의 일원으로 벨라와 에드워드를 떼어놓고자 한다.  그러던 어느 날 벨라는 자신이 위험한 사고를 당할 때마다 에드워드의 환영이 보인다는 것을 알고 급기야 절벽에서 떨어지는 무모한 행동을 한다. 그리고 이 사건은 누구도 예상치 못할 결과를 초래하는데…  인간과 뱀파이어의 위험한 사랑! 어둠을 지배하는 절대 세력의 탄생!  올 겨울, 운명에 맞선 거대한 대결이 시작된다!', 'https://image.tmdb.org/t/p/w500/q1zQIaDMBgLzpW8Hikzhau1InvI.jpg', 2009, 0, 0, '2026-06-06 13:25:25.719707', 'US');
INSERT INTO public.movies VALUES (2975, 43347, '러브 & 드럭스', '["Drama", "Comedy", "Romance"]', NULL, '[]', '타고난 바람둥이 제이미(제이크 질렌할 분)는 넘치는 바람기 때문에 다니던 직장에서 해고를 당한다. 제약회사에 영업사원으로 취직한 제이미는 자신의 매력을 100% 활용, 병원을 상대로 영업에 나선다. 얽매이길 싫어하는 자유로운 영혼의 소유자인 매기(앤 헤서웨이 분). 그녀는 진지한 사랑에 빠지길 두려워하며 가벼운 관계만을 쫓아 하룻밤 상대로 남자들을 고른다.  병원에 영업차 갔던 제이미는 그곳에서 환자인 매기를 우연히 만나게 되고 장난스럽고 유쾌한 제이미의 연애신청이 싫지 않은 매기는 진지한 사랑보다는 몇 시간을 함께 보낼 잠자리 친구로 지내자고 제안한다.  한편, 화이자가 개발한 비아그라가 선풍적인 인기를 끌면서 제이미는 업계에서 승승장구하게 된다. 몸으로 하는 사랑(?)엔 쿨하고 마음으로 하는 사랑은 싫은 두 사람은 시간이 지날수록 서로의 매력에 이끌리게 되고 제이미는 매기에게 사랑을 고백하지만 그녀는 받아들이지 않는데……', 'https://image.tmdb.org/t/p/w500/3Q4rfwS3HliQa2Yhp9bIDYWetJb.jpg', 2010, 0, 0, '2026-06-07 12:17:56.201772', 'US');
INSERT INTO public.movies VALUES (781, 870028, '어카운턴트 2', '["Mystery", "Crime", "Thriller"]', NULL, '[]', '크리스찬 울프는 복잡한 문제를 해결하는 데 재능이 있다. 오랜 지인이 ‘회계사를 찾아달라’는 수수께끼 같은 메시지를 남기고 살해당하자, 울프는 그동안 소원했던 위험천만한 동생 브랙스를 불러 사건 해결에 도움을 구한다. 이들은 미국 재무부 부국장 메디나와 협력하여 무시무시한 음모를 밝혀내지만, 무자비한 살인 조직의 표적이 된다.', 'https://image.tmdb.org/t/p/w500/625ohbmqK8tj9DhQc66aF6CqQLz.jpg', 2025, 0, 0, '2026-06-06 13:25:26.498407', 'US');
INSERT INTO public.movies VALUES (777, 423, '피아니스트', '["Drama"]', 'Roman Polanski', '["Adrien Brody", "Thomas Kretschmann", "Frank Finlay", "Maureen Lipman", "Emilia Fox"]', '1939년 폴란드 바르샤바, 유명한 유대계 피아니스트 블라디슬로프 스필만은 한 인기 라디오 프로그램에서 쇼팽의 야상곡을 연주하다 폭격을 당한다. 이후 유태인인 스필만과 가족들은 게토에서 생활하지만, 결국 수용소로 향하는 기차에 몸을 싣게 된다. 가족들을 죽음으로 내보내고 간신히 목숨을 구한 스필만은 허기와 추위, 고독과 공포 속에서 마지막까지 생존해 나간다. 자신을 도와주던 몇몇의 사람마저 떠나고, 자신만의 은신처에서 끈질기게 생존을 유지하는 스필만. 어둠과 추위로 가득한 폐건물 속에서 은신생활 중 스필만은 우연찮게 순찰을 돌던 독일 장교에게 발각되는데...', 'https://image.tmdb.org/t/p/w500/t7L2YDpu635qKT3ehqZxry4yvTX.jpg', 2002, 0, 0, '2026-06-06 13:25:25.754382', 'GB');
INSERT INTO public.movies VALUES (776, 420818, '라이온 킹', '["Adventure", "Drama", "Family", "Animation"]', NULL, '[]', '혈통을 이어받은 사자가 왕국을 다스리는 아프리카의 프라이드 랜드, 무파사의 아들 심바는 왕좌를 물려받기로 예정되어 있다. 하지만 탐욕스런 무파사의 동생 스카가 자신의 형제를 죽이고, 마치 그 원인이 심바에게 있는 것처럼 분위기를 조장해 그를 왕국에서 쫓아낸다. 아버지의 죽음에 대한 죄책감에 시달리던 심바는 의욕 충만한 친구들 품바와 티몬의 도움으로 희망을 되찾는다. 어느 날 우연히 옛 친구 날라를 만난 심바는 과거를 마주할 용기를 얻고, 진정한 자신의 모습을 찾아 위대하고도 험난한 도전을 떠나게 되는데...', 'https://image.tmdb.org/t/p/w500/mOR24P4tXgcT3cjzPs7Ca0wog7X.jpg', 2019, 0, 0, '2026-06-06 13:25:25.751758', 'US');
INSERT INTO public.movies VALUES (773, 8689, '홀로코스트', '["Horror"]', NULL, '[]', '네명의 기록영화팀이 아마존 오지의 비밀을 필름에 담기 위해 출발하지만, 두달이 지나도록 소식이 없다. 그들을 후원했던 방송국에서는 구조대를 특파하고 아마존에 도착한 구조대는 기록영화팀의 참혹한 죽음의 소식과 함께 그들이 남긴 필름을 가지고 돌아온다.  필름을 현상한 방송국에서는 이 필름을 방영하면 높은 시청률을 이끌어 낼 수 있을 것이라 생각하고 시사를 하지만 그 내용의 참혹함에 놀라 결국 필름을 소각시켜 버린다.  ''지옥으로 가는 길''이란 제목이 붙어있는 그 필름에는 기록영화팀이 원시의 생활 속에서 차츰 잔인한 본능을 드러내고 평화롭게 살고 있던 원주민들을 잔인하게 살해하는 모습이 담겨있었는데...', 'https://image.tmdb.org/t/p/w500/sGUuLvKOf6JlBFtPDVWFIlvLjeO.jpg', 1980, 0, 0, '2026-06-06 13:25:25.74137', 'US');
INSERT INTO public.movies VALUES (774, 505642, '블랙 팬서: 와칸다 포에버', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '국왕이자 블랙 팬서인 티찰라의 죽음 이후 수많은 강대국으로부터 위협을 받게 된 와칸다. 라몬다, 슈리 그리고 나키아, 오코예, 음바쿠는 각자 사명감을 갖고 와칸다를 지키기 위해 외로운 싸움을 이어간다. 한편, 비브라늄의 패권을 둘러싼 미스터리한 음모와 함께 깊은 해저에서 모습을 드러낸 최강의 적 네이머와 탈로칸의 전사들은 와칸다를 향해 무차별 공격을 퍼붓기 시작하는데…', 'https://image.tmdb.org/t/p/w500/4LaJseYluZxp4Odlisd1Zb4RWHR.jpg', 2022, 0, 0, '2026-06-06 13:25:25.746209', 'US');
INSERT INTO public.movies VALUES (775, 278986, 'গাঙ্গর', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/jf3Wa4ZIpHDhDkjUQ0PaUW7gyJM.jpg', 2011, 0, 0, '2026-06-06 13:25:25.748943', 'US');
INSERT INTO public.movies VALUES (8832, 147441, '엑소더스: 신들과 왕들', '["Adventure", "Drama", "Action"]', 'Ridley Scott', '["Christian Bale", "Joel Edgerton", "Ben Kingsley", "John Turturro", "Aaron Paul"]', '인간이 신처럼 군림하던 시대, 이집트 왕국에서 형제와도 같이 가깝게 자란 모세스와 람세스. 전차에서 낙마한 람세스를 모세가 목숨을 걸고 구해날 정도로 둘의 우애는 깊었지만, 생지옥 같은 노예들의 삶을 목격하고 이에 분노하게 된 모세스는 스스로를 태양신 라의 화신이라 믿는 제국의 왕 람세스와 정면으로 맞서게 된다. 이집트의 동쪽으로 추방당하며 겪은 여정에서 신비한 소년을 만나게 되는 모세스. 결국 자신이 400년간 억압받던 노예들을 이끌 운명임을 깨닫게 된 모세스는 자유를 찾기 위해 동족들을 이끌고 이집트 탈출을 결심하는데...', 'https://image.tmdb.org/t/p/w500/tkh2IPZ7jMNLotzFGjyHQBzdl7.jpg', 2014, 0, 0, '2026-06-08 07:30:01.273884', 'GB');
INSERT INTO public.movies VALUES (780, 331482, '작은 아씨들', '["Drama", "Romance"]', NULL, '[]', '첫째 메그는 배우가 되고 싶은 욕망과 가족을 가지고 싶어하는 욕망 사이에서 고민하고, 둘째 조는 소설을 쓰지만 여성들이 쓴 소설은 어떻게 끝이 나야 하는지 잘 알고 있는 척하는 편집장과 맞서야 한다. 셋째 베스는 피아노를 잘 치지만 건강에 문제가 있고, 막내 에이미는 그림을 그리는 데 소질이 있지만 남자들이 좋아하는 취향에 따라 그림을 그려야 하는 상황에 처한다. 이웃집 소년 로리는 네 자매를 우연히 알게 되고, 각기 다른 개성의 네 자매들과 인연을 쌓아 간다. 7년 후, 어른이 된 그들에겐 각기 다른 숙제가 놓이게 되는데...', 'https://image.tmdb.org/t/p/w500/2kfDJEwZ7Rxo3yz5v6rJlwqtY0W.jpg', 2019, 0, 0, '2026-06-06 13:25:25.762765', 'US');
INSERT INTO public.movies VALUES (778, 102651, '말레피센트', '["Fantasy", "Adventure", "Action", "Family", "Romance"]', NULL, '[]', '인간과의 공존을 꿈꾼 순수한 요정 말레피센트는 인간 스테판과 사랑에 빠진다. 하지만 권력을 탐한 스테판은 말레피센트를 희생시켜 왕관을 차지하고 그 일로 말레피센트는 인간을 미워하게 된다. 사나워진 그녀의 곁에 머무는 유일한 친구는 수족 같은 까마귀 디아발뿐이다. 그사이 스테판 왕은 인간 여자와 혼인해 오로라를 낳는다. 말레피센트는 스테판 왕에 대한 복수로 오로라에게 저주를 걸지만, 예기치 않게 그 저주로 인해 그녀는 오로라와 더 깊은 연을 맺게 되는데...', 'https://image.tmdb.org/t/p/w500/e1XEV04HrfSSrE82dUZDy1c3Aq5.jpg', 2014, 0, 0, '2026-06-06 13:25:25.75742', 'US');
INSERT INTO public.movies VALUES (477, 9769, '로리타', '["Drama"]', NULL, '[]', '슬픈 첫사랑의 아픔을 간직한 47세의 불문학자 험버트(제레미 아이언스). 뜨거운 여름, 강의차 미국 뉴잉글랜드에 들른다. 샤롯트(멜라니 그리피스)라는 미모의 미망인의 집에 거처를 마련한 그는 그녀의 딸 로리타(도미니크 스웨인)를 본 순간, 아찔한 사랑에 빠진다. 결국 험버트는 로리타의 곁을 떠나지 않기 위해 샬롯의 프로포즈를 받아들이고 그녀와 결혼한다. 그러던 어느날, 로리타에 대한 마음을 기록한 그의 일기장을 샬롯이 발견하고, 그 충격에 거리로 뛰쳐나가 교통사고로 죽고 만다. 어머니의 죽음을 알게 된 로리타는 자신을 버리지 말라고 험버트에게 매달리는데...', 'https://image.tmdb.org/t/p/w500/9INcC14WZjCMKGE360VXmklCLdZ.jpg', 1997, 0, 0, '2026-06-06 13:25:14.107126', 'US');
INSERT INTO public.movies VALUES (772, 926393, '더 이퀄라이저 3', '["Action", "Thriller", "Crime"]', NULL, '[]', '전직 특수 요원이 우연히 마주치게 된 이탈리아 마약조직 일당과 사투를 벌이는 내용을 다룬 영화', 'https://image.tmdb.org/t/p/w500/cXKe85IL6zFQnFk5465Kpr3YG9j.jpg', 2023, 0, 0, '2026-06-06 13:25:25.737817', 'US');
INSERT INTO public.movies VALUES (791, 1341137, 'A Great Awakening', '["Drama", "History"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/dXeeDRLGpTX1U97lWBAwQeeplsW.jpg', 2026, 0, 0, '2026-06-06 13:25:26.532509', 'US');
INSERT INTO public.movies VALUES (792, 184315, '허큘리스', '["Action", "Adventure"]', NULL, '[]', '네메안의 사자와 지옥의 개들을 맨 손으로 물리쳤다는 전설적인 업적으로 유명한 ‘허큘리스’는 충실한 추종자들과 방랑하는 용병이 되어 돈을 벌며 살아간다. 그의 명성을 들은 이웃나라 트라키아의 왕과 공주는 죽음의 군단이라 불리는 강력한 군사들을 물리쳐주기를 요청한다. 허큘리스는 이제 전설로 전해지는 자신의 활약상을 증명하고 세상의 질서를 바로잡을 진정한 남자로 거듭나야만 하는데…', 'https://image.tmdb.org/t/p/w500/hmWwoUXorZyyymGdmrX46lEIrnf.jpg', 2014, 0, 0, '2026-06-06 13:25:26.535319', 'US');
INSERT INTO public.movies VALUES (789, 679, '에이리언 2', '["Action", "Thriller", "Sci-Fi"]', NULL, '[]', '에일리언과의 싸움에서 간신히 살아남은 리플리는 잠든 채로 57년을 떠돌다 구조선에 의해 구출된다. 회사는 리플리를 비롯한 당시 승무원들이 노스트로모호를 잃어버린 것을 추궁하지만 에이리언 얘기는 믿지 않는다. 이때 지구와 한 혹성 거주민들의 통신이 두절되는 사건이 벌어지자 리플리는 고문 자격으로 해병대와 동행하게 된다. 혹성에 도착한 해병대원들은 곧 혹성 거주민들이 에일리언 유충의 산 먹이로 된 것을 목격하고, 곧이어 벌어진 교전에서 여러 대원들을 잃는다. 그들은 혹성 거주민들의 실험실로 대피하고, 리플리는 이곳에서 마지막 생존자인 뉴트를 발견하게 된다.', 'https://image.tmdb.org/t/p/w500/8J1SwqmsHRzZ5k8QVRibkzyc9jc.jpg', 1986, 0, 0, '2026-06-06 13:25:26.527504', 'US');
INSERT INTO public.movies VALUES (783, 558449, '글래디에이터 II', '["Action", "Adventure", "Drama"]', NULL, '[]', '로마의 영웅이자 최고의 검투사였던 막시무스가 콜로세움에서 죽음을 맞이한 뒤 20여 년이 흐른 후. 쌍둥이 황제 게타와 카라칼라의 폭압 아래 시민을 위한 자유로운 나라 로마의 꿈은 잊힌 지 오래다. 한편 아카시우스 장군이 이끄는 로마군에 대패한 후 모든 것을 잃고 노예로 전락한 루시우스는 강한 권력욕을 지닌 마크리누스의 눈에 띄어 검투사로 발탁된다. 로마를 향한 걷잡을 수 없는 분노, 타고난 투사의 기질로 콜로세움에 입성하게 된 루시우스는 결투를 거듭하며 자신이 진짜 누구인지 알게 되고 마침내 로마의 운명을 건 결전을 준비하게 되는데...!', 'https://image.tmdb.org/t/p/w500/aJaKH3wJvdcMyq28vUhHnINWPjI.jpg', 2024, 0, 0, '2026-06-06 13:25:26.513764', 'US');
INSERT INTO public.movies VALUES (790, 222517, 'Biancaneve & Co...', '["Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/yMiM9Zg9JuNy9k1Q7wsyEpwTSQR.jpg', 1982, 0, 0, '2026-06-06 13:25:26.529801', 'US');
INSERT INTO public.movies VALUES (788, 137113, '엣지 오브 투모로우', '["Action", "Sci-Fi"]', NULL, '[]', '가까운 미래, 미믹이라 불리는 외계 종족의 침략으로 인류는 멸망 위기를 맞는다. 빌 케이지는 자살 작전이나 다름없는 작전에 훈련이나 장비를 제대로 갖추지 못한 상태로 배정되고 전투에 참여하자마자 죽음을 맞는다. 하지만 불가능한 일이 일어난다. 그가 다시 그 끔찍한 날이 시작된 시간에 다시 깨어나 다시 전투에 참여하게 되고 다시 죽었다가 또 다시 살아나는 것. 외계인과의 접촉으로 같은 시간대를 반복해서 겪게 되는 타임 루프에 갇히게 된 것이다.', 'https://image.tmdb.org/t/p/w500/uZy5RUNb052OSyhZgTBA9ZxFVzc.jpg', 2014, 0, 0, '2026-06-06 13:25:26.525255', 'US');
INSERT INTO public.movies VALUES (719, 766507, '프레이', '["Thriller", "Action", "Sci-Fi"]', NULL, '[]', '300년 전 아메리카, 용맹한 전사를 꿈꾸는 원주민 소녀 나루는 갑작스러운 곰의 습격으로 절체절명의 위기에 놓인 순간, 정체를 알 수 없는 외계 포식자 프레데터를 목격하게 된다.  자신보다 강한 상대를 향한 무자비한 사냥을 시작한 프레데터. 최첨단 기술과 무기로 진화된 외계 포식자 프레데터의 위협이 점점 다가오고 나루는 부족을 지키기 위해 자신만의 기지와 무기로 생존을 건 사투를 시작하는데…', 'https://image.tmdb.org/t/p/w500/dBcot5vSnmn3XeAg1c4PZM63G5x.jpg', 2022, 0, 0, '2026-06-06 13:25:23.42388', 'US');
INSERT INTO public.movies VALUES (786, 281957, '레버넌트: 죽음에서 돌아온 자', '["Drama", "Adventure"]', NULL, '[]', '서부 개척시대 이전인 19세기 아메리카 대륙, 전설적인 모피 사냥꾼인 휴 글래스 는 아들 호크를 데리고 동료들과 함께 사냥하던 중 회색곰에게 습격 당해 사지가 찢긴다. 하지만 돈에 눈이 먼 비정한 동료 존 피츠 제럴드 는 아직 살아 있는 휴를 죽이려 하고, 아들 호크가 이에 저항하자 호크마저 죽인 채 숨이 붙어 있는 휴를 땅에 묻고 떠난다. 눈 앞에서 하나뿐인 아들의 죽음을 목격한 휴는 처절한 복수를 위해 부상 입은 몸으로 배신자 존 피츠제럴드의 뒤를 쫓아 300km가 넘는 광활하고 거친 야생에서 인간의 한계에 도전하는데...', 'https://image.tmdb.org/t/p/w500/8LqhLTQHb3fJn4ddZtQva03cKC.jpg', 2015, 0, 0, '2026-06-06 13:25:26.520719', 'US');
INSERT INTO public.movies VALUES (784, 1491248, 'Hotel Excelsior', '["Comedy", "Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/oIsFMywtS9MqdpPFtdZ3yJQMU0J.jpg', 2026, 0, 0, '2026-06-06 13:25:26.516161', 'US');
INSERT INTO public.movies VALUES (6006, 370665, '딜발레', '["Crime", "Action", "Comedy"]', 'Rohit Shetty', '["Shah Rukh Khan", "Kajol", "Varun Dhawan", "Kriti Sanon", "Boman Irani"]', '자동차 정비소를 운영하는 라즈(샤룩 칸)에게는 남들이 모르는 비밀이 하나 있다. 15년 전 샥티(머케시 티와리)와 안와르를 데리고 불가리아와 전 세계를 호령하던 마피아였던 그는 어떠한 사고를 계기로 손을 씻고, 지금의 정비소를 운영하고 있는 것이다. 아버지도 돌아가신 지금, 라즈에게는 하나 있는 동생 비르(바룬 다완)가 가장 소중했다. 그러던 어느 날 비르가 킹(보만 이라니)이라는 조폭에게 당한 것을 알게 된 라즈는 옛날의 실력을 발휘하여 그들을 박살내버린다.  사실을 알고보니, 비르가 당하게 된 원인에는 동생이 좋아하는 이슈(크리티 사논)라는 여인이 있다는 것을 알게된다. 하지만 그보다 더 큰 사실은 이슈에게는 언니가 있었고, 그녀가 미라(까졸)라는 사실이었다. 15년 전 라즈가 손을 씻게 된 이유에는 미라와의 오해도 있었고, 15년이 지난 오늘. 그녀와 재회하게 된 것이다.  15년 간을 쌓아 온 오해와 진실. 그리고 사랑. 라즈와 비르 형제는 그들의 사랑을 찾아, 이슈와 미르의 마음을 얻을 수 있을 것인가?', 'https://image.tmdb.org/t/p/w500/pYgPu6hhOr61knwbestTx4vSdMb.jpg', 2015, 0, 0, '2026-06-08 06:52:49.94605', 'IN');
INSERT INTO public.movies VALUES (793, 615656, '메가로돈 2', '["Action", "Sci-Fi", "Horror"]', NULL, '[]', '전 세계에서 가장 깊은 마리아나 해구, 역사상 가장 거대하고 무자비한 포식자가 도사리는 그곳에서 강철 다이버 ''조나스''(제이슨 스타뎀)가 더 맹렬하게 돌아온 ''메가로돈''과 짜릿한 대결을 펼치는 액션 어드벤처', 'https://image.tmdb.org/t/p/w500/cbAHK6Vrt0GClMRUxH8TsgC2JqL.jpg', 2023, 0, 0, '2026-06-06 13:25:26.538081', 'US');
INSERT INTO public.movies VALUES (288, 290098, '아가씨', '["Thriller", "Drama", "Romance"]', 'Park Chan-wook', '["Kim Min-hee", "Kim Tae-ri", "Ha Jung-woo", "Cho Jin-woong", "Kim Hae-sook"]', '어릴 적 부모를 잃고 후견인 이모부의 보호 아래 살아가는 귀족 아가씨에게 백작이 추천한 새로운 하녀가 찾아온다. 이모부의 서재에서 책을 읽는 것이 일상의 전부인 아가씨는  순박해 보이는 하녀에게 조금씩 의지하기 시작한다. 하지만 하녀의 정체는 유명한 여도둑의 딸인 소매치기 고아 소녀 숙희. 막대한 재산을 상속받게 될 아가씨를 유혹하여 돈을 가로채겠다는 사기꾼 백작의 제안을 받고  아가씨가 백작을 사랑하게 만들기 위해 하녀가 된 것. 드디어 백작이 등장하고, 백작과 숙희는 자신만의 방식으로 아가씨의 마음을 흔들기 시작하는데...', 'https://image.tmdb.org/t/p/w500/pDogzUCSBy0m4ybLKUv3OtGMRNm.jpg', 2016, 0, 0, '2026-06-06 13:25:07.170318', 'KR');
INSERT INTO public.movies VALUES (803, 883714, '착한 형수4', '["Romance"]', 'Lim Hyun-tae', '["Lee Joon-hyun"]', '형수님, 이제 형의 빈자리를 채워드릴게요!  형 준현의 집에 얹혀사는 동생 민현. 형수와 한집에 사는 것이 부담스럽던 경석은 언젠가부터 자꾸 젊고 섹시한 형의 아내 미정에게 눈길이 간다. 옆방에서 들려오는 야릇한 신음소리에 급기야 형수과 사랑은 나누는 모습까지 상상한다. 어느 일요일, 형이 회사 업무 떄문에 급히 집을 비우고, 단둘이 남은 그들은 묘한 감정에 사로잡히는데…', 'https://image.tmdb.org/t/p/w500/bSL5uTtNd6X1ER7F1X1MTy2Ezpr.jpg', 2019, 0, 0, '2026-06-06 13:25:27.289682', 'KR');
INSERT INTO public.movies VALUES (802, 1278162, 'พนอ', '["Horror", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/fjvV2wQL8j7cgDVlR0Jru50UE16.jpg', 2025, 0, 0, '2026-06-06 13:25:27.287029', 'US');
INSERT INTO public.movies VALUES (805, 934433, '스크림 6', '["Horror", "Thriller", "Crime"]', NULL, '[]', '고스트페이스의 습격에서 살아남은 생존자들이 우즈보로를 떠나 뉴욕에서 새로운 삶을 시작하지만, 다시금 과거의 살인마에게 쫓기게 되는 이야기', 'https://image.tmdb.org/t/p/w500/1zhb49U0Rjg2qVU9L7VLmujf1Hs.jpg', 2023, 0, 0, '2026-06-06 13:25:27.294433', 'US');
INSERT INTO public.movies VALUES (801, 1163974, '玉蒲团之极乐宝鉴', '["Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/fgDil15yqzf3ABqJjoQPq01sNlf.jpg', 1999, 0, 0, '2026-06-06 13:25:27.283792', 'US');
INSERT INTO public.movies VALUES (2573, 628847, '트랩 하우스', '["Action", "Crime", "Thriller"]', 'Michael Dowse', '["Dave Bautista", "Jack Champion", "Sophia Lillis", "Whitney Peak", "Bobby Cannavale"]', '텍사스주 엘패소에서 마약단속국 비밀 요원이 파트너와 대담하기 짝이 없는 도적단을 추격한다. 도둑의 정체는 요원들의 반항심 가득한 10대 자녀들로, 이들은 부모의 전략과 극비 정보를 이용하여 위험한 카르텔을 강탈하기 시작한다.', 'https://image.tmdb.org/t/p/w500/6tpAPeuuqbVnYWWPoOLEDLSBU7a.jpg', 2025, 0, 0, '2026-06-07 12:17:38.389877', 'GB');
INSERT INTO public.movies VALUES (577, 259693, '컨저링 2', '["Horror"]', NULL, '[]', '1977년 영국 엔필드. 엄마 페기와 네 남매가 살고 있는 가족의 집에 정체를 알 수 없는 존재가 나타난다. 일명 폴터가이스트 유령. 벽을 두드리는 소리, 사악한 목소리, 유령은 밤마다 가구와 물건들, 심지어 아이들까지 공중에 띄우는 등 기이한 일들을 일으킨다. 결국 교회의 요청을 받은 워렌 부부가 영국 엔필드의 집을 찾아가 사건을 조사한다. 그러나 워렌 부부는 그 집에서 예상보다 더욱 엄청난 상대를 만나게 되고, 워렌 부부의 목숨까지 위협받는데…', 'https://image.tmdb.org/t/p/w500/RTmoz2DYYOPDnTKGqkJDWKdcd6.jpg', 2016, 0, 0, '2026-06-06 13:25:18.012733', 'US');
INSERT INTO public.movies VALUES (797, 1254594, '오무카데', '["Horror", "Thriller"]', NULL, '[]', '1941년 태국, 소수의 일본군 병사들과 포로들이 저주받은 광산에 갇힌다. 적들 사이의 긴장감이 폭발 직전에 이르자, 그들은 어둠 속에 도사린 끔찍한 고대 괴물과 마주해야만 하는 상황에 처한다.', 'https://image.tmdb.org/t/p/w500/7RdzEmKj2yy3DttYkvZ6G5cCtoE.jpg', 2026, 0, 0, '2026-06-06 13:25:26.548304', 'US');
INSERT INTO public.movies VALUES (8833, 814338, '채털리 부인의 연인', '["Drama", "Romance"]', 'Laure de Clermont-Tonnerre', '["Emma Corrin", "Jack O''Connell", "Matthew Duckett", "Joely Richardson", "Faye Marsay"]', '남편과의 사랑이 식은 채털리 부인. 가문의 영지에서 사냥터를 관리하는 남자와 격정적인 관계에 빠져든다. D. H. 로런스의 동명 소설 원작.', 'https://image.tmdb.org/t/p/w500/aSgl2DxPG3DuQXoaHr500KeULmT.jpg', 2022, 0, 0, '2026-06-08 07:30:01.942163', 'GB');
INSERT INTO public.movies VALUES (804, 10527, '마다가스카 2', '["Adventure", "Animation", "Comedy", "Family"]', NULL, '[]', '마다가스카 섬에서 좌충우돌 모험을 끝낸 뉴요커 4인방 사자 알렉스(벤 스틸러), 얼룩말 마티(크리스 락), 기린 멜먼(데이빗 쉼머), 하마 글로리아(제이다 핀켓 스미스)는 펭귄 특공대가 제작한 비행기 ‘에어 펭귄’을 타고 뉴욕으로 컴백하던 중 또 다시 미지의 세계에 불시착하게 된다. 이번에는 말로만 듣던 진짜 生 야생 ‘아프리카’! 그들은 각자 헤어졌던 가족, 새친구, 연인을 만나 生 야생에 적응해간다. 그러던 중, 평화롭던 아프리카에 가뭄이 찾아오고 뉴요커 4인방은 혼란에 빠진 아프리카를 구하기 위해 뭉치는데…  과연 함께해도 모자란 이들이 위기의 아프리카를 구할 수 있을까?  그리고 아프리카를 탈출해 무사히 집으로 돌아갈 수 있을까?', 'https://image.tmdb.org/t/p/w500/9Yk2lAIye5TUBuibD2EYZGYqhz3.jpg', 2008, 0, 0, '2026-06-06 13:25:27.292057', 'US');
INSERT INTO public.movies VALUES (795, 458156, '존 윅 3: 파라벨룸', '["Action", "Thriller", "Crime"]', NULL, '[]', '사랑하는 아내와 반려견이 죽은 후 복수를 위해 돌아온 전설의 킬러, 존 윅은 성역 콘티넨탈 호텔에서는 살인하면 안 된다는 룰을 깨면서 전세계 킬러들의 표적이 된다. 전편에서 존 윅이 국제암살자연맹에서 파문당한 직후 1시간 동안 도망갈 시간을 내어 준 윈스턴은 최고회의로부터 그를 도왔다는 이유로 자리에서 물러날 것을 요구받는다. 현상금이 1400만달러로 불어난 존 윅은 옛 동료이자 현재 카사블랑카 콘티넨탈 호텔의 지점장인 소피아에게 도움을 청한다.', 'https://image.tmdb.org/t/p/w500/8dGCWRwrMjn1jdFCI5xu5VrkGBL.jpg', 2019, 0, 0, '2026-06-06 13:25:26.543427', 'US');
INSERT INTO public.movies VALUES (799, 1671548, '给阿嬷的情书', '["Drama", "Family", "Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/s0sC3hPPX4OobLNfdl2iSs2vtvI.jpg', 2026, 0, 0, '2026-06-06 13:25:26.552957', 'US');
INSERT INTO public.movies VALUES (4257, 1068844, '내 엄마의 친구 2', '["Romance"]', 'Lee Dong-hyun', '["Jeong-yeon", "Do Mo-se", "Han Jae-kyung", "Park Joo-bin", "Shin Yeon-woo"]', '태윤은 이혼한지 두 달 만에 새살림을 차린 아버지와 젊고 섹시한 새엄마와의 동거가 못마땅하다. 하지만 아버지의 사업 실패로 새엄마와 단 둘이 살게 되면서 점점 새엄마가 여자로 보이기 시작한다. 점점 가까워지던 두 사람은 결국 돌이킬 수 없는 욕망에 빠져든다.', 'https://image.tmdb.org/t/p/w500/mIN2PxRJd951ZKo4Vnf4NFzhcDB.jpg', 2019, 0, 0, '2026-06-08 06:29:27.341738', 'KR');
INSERT INTO public.movies VALUES (814, 1032823, '트랩', '["Crime", "Horror", "Thriller"]', NULL, '[]', '10대 딸과 함께 인기 팝스타의 콘서트를 찾은 쿠퍼. 신나게 콘서트를 즐기던 그는 순간 이상한 낌새를 느끼고, 그곳이 최악의 연쇄살인마를 잡기 위한 거대한 덫임을 알게 된다. 그런데 문제는 쿠퍼 자신이 바로 연쇄살인마라는 것! 이제 쿠퍼는 수많은 관객과 경찰을 따돌리고 어린 딸과 함께 무사히 이 덫에서 탈출해야만 하는데…', 'https://image.tmdb.org/t/p/w500/2LC4gLNbHpZTq28EWOwCMiVnGcq.jpg', 2024, 0, 0, '2026-06-06 13:25:27.316872', 'US');
INSERT INTO public.movies VALUES (809, 1227877, '아이 러브 부스터스', '["Comedy", "Sci-Fi", "Crime"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/4pNKIUFy7tkZiBx0rnSmG9ysRy.jpg', 2026, 0, 0, '2026-06-06 13:25:27.304115', 'US');
INSERT INTO public.movies VALUES (807, 161, '오션스 일레븐', '["Thriller", "Crime"]', NULL, '[]', '역사상 유례없이 특이한 강도 11명이 한자리에 모였다. 뉴저지 감옥에서 하릴없이 세월을 보내던 대니 오션에게도 좋은 시절이 왔다. 한방에 뜰 기회를 노리던 그에게 가석방으로자유시간이 주어진 것. 주도면밀하면서도 쿨한 대니가 이 기회를 놓칠 리 없다. 그는 세계적인 권투시합이 열리는 밤, 3개의 카지노를 동시에 턴다는 무모한 계획 아래 10명의 멤버들을 특별 공수한다. 참모, 오른팔, 막내, 폭탄 전문가, 자금줄, 탈출 전문가, 망보는 녀석 등 11명의 강도단이 구성된다.  단 이들에게는 세 가지 규칙이 있다. 살상은 금물, 평민들의 재산에 눈독들이지 말 것, 그리고 게임처럼 즐길 것.', 'https://image.tmdb.org/t/p/w500/hl9dkOnNCR4adxDTVISjkkC0JQj.jpg', 2001, 0, 0, '2026-06-06 13:25:27.299219', 'US');
INSERT INTO public.movies VALUES (810, 345940, '메가로돈', '["Action", "Sci-Fi", "Horror"]', NULL, '[]', '국제 해저 관측 프로그램으로 일환으로 심해를 탐사 중인 해저 탐험대는 정체 모를 거대 생물에게 공격을 당한다. 긴급 투입된 심해 구조 전문가 조나스(제이슨 스타뎀)는 그것이 200만년 전 멸종된 것으로 알려진 ‘메가로돈’임을 주장한다. 아무도 믿으려 하지 않지만, 조나스는 역사상 가장 위대하고 가장 거대한 포식자와 두 번째로 마주하는 것인데…', 'https://image.tmdb.org/t/p/w500/nJW6nWxQh9vq9RHayZFzuRF9ybj.jpg', 2018, 0, 0, '2026-06-06 13:25:27.306833', 'US');
INSERT INTO public.movies VALUES (815, 1669050, 'Tayuan 2', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/gkHNa8q3RNhgj2EMuoYWJUHsMa6.jpg', 2026, 0, 0, '2026-06-06 13:25:27.31932', 'US');
INSERT INTO public.movies VALUES (812, 73, '아메리칸 히스토리 X', '["Drama"]', NULL, '[]', '3년 전 강도 사건으로 소방수였던 아버지를 잃은 데렉은 백인 우월주의자들의 모임인 DOC에 관심을 갖게 되면서 유색인종에게 그 분노와 증오를 터트린다. 그는 혐오스러운 유색인종들을 이 땅에서 몰아내야 한다고 주장하면서 강렬한 카리스마로 동료들 사이에서 영웅이 된다. 가족들은 그런 그의 모습을 걱정하여 만류하지만, 단 한 사람, 동생 대니만은 그를 전적으로 믿고 따른다. 어느 날, 데렉에게 적대감을 품은 흑인들이 아버지의 낡은 밴을 훔치러 왔을 때 그는 서슴없이 그들에게 총을 겨눈다. 그리고는 총을 맞고 신음하는 그를 참혹하게 죽이고 마는데...', 'https://image.tmdb.org/t/p/w500/nm4XkYBt79ZjUQj6Rqxxzl1Wt3c.jpg', 1998, 0, 0, '2026-06-06 13:25:27.311864', 'US');
INSERT INTO public.movies VALUES (813, 566525, '샹치와 텐 링즈의 전설', '["Action", "Adventure", "Fantasy"]', NULL, '[]', '초인적인 능력을 가진 텐 링즈의 힘으로 수세기 동안 어둠의 세상을 지배해 온 웬우. 샹치는 아버지 웬우 밑에서 암살자로 훈련을 받았지만 이를 거부하고 평범함 삶을 선택한다. 샌프란시스코로 떠나와 자신의 진짜 이름을 숨긴 채 션이란 가명으로 살아가는 샹치. 웬우가 수장으로 있는 조직 텐 링즈의 일원인 레이저 피스트가 찾아와 샹치의 펜던트를 훔쳐가자 샹치는 친구 케이티와 함께 연이 끊겼던 동생 샤링을 염려하며 그녀가 숨어 지내는 마카오로 찾아간다. 텐 링즈의 마법 같은 힘을 통해 수천년 동안 지구의 역사를 혼란에 빠뜨렸던 웬우는 자신의 아들딸을 다시 불러들여 새로운 계략을 꾸민다.', 'https://image.tmdb.org/t/p/w500/14L4NGrqO4r7gJtVRiSRP5rNsL5.jpg', 2021, 0, 0, '2026-06-06 13:25:27.314371', 'US');
INSERT INTO public.movies VALUES (808, 174341, '어느 창녀의 하루', '["Drama"]', NULL, '[]', '어느 날 아침, 24년을 함께한 아내를 버리고 4년 만에 연락도 없이 벨벳을 찾아온 프레드. 다시 잘해보고 싶은 프레드와 달리 벨벳은 마음이 떠난 지 오래다. 프레드는 벨벳의 마음을 돌리려 애쓰지만 오히려 갈등은 깊어만 가고 감정만 앞선 프레드의 욕망으로 인해 걷잡을 수 없는 상황에 빠지게 되는데…', 'https://image.tmdb.org/t/p/w500/c1ELmkYAHLQbWdDmLdvrC6Lx8Uk.jpg', 2013, 0, 0, '2026-06-06 13:25:27.301723', 'US');
INSERT INTO public.movies VALUES (818, 1049471, '''부메랑'' - Outcome', '["Comedy", "Drama"]', NULL, '[]', '여섯 살 때부터 할리우드의 상징이었던 리프 호크는 무너지기 일보 직전이다. 의문의 영상과 엮인 협박 사건을 알게 된 리프는 업계에서 퇴출당하기 전에 먼저 반성의 여정을 시작하며 자신의 과오를 바로잡고 과거의 그림자를 떨쳐낸다.', 'https://image.tmdb.org/t/p/w500/17QQjBBCYiZb0BhtwEUp5W1oyny.jpg', 2026, 0, 0, '2026-06-06 13:25:27.327207', 'US');
INSERT INTO public.movies VALUES (832, 75656, '나우 유 씨 미: 마술사기단', '["Thriller", "Crime"]', NULL, '[]', '1년 전 만해도 무명이었던 길거리 마술사 포 호스맨은 단 3초만에 파리 은행의 비자금을 통째로 털어 관객들에게 뿌리는 매직쇼를 성공시켜 전세계의 이목을 끈다. 하지만 이것은 시선 끌기였을 뿐! 포 호스맨의 범행은 점점 더 거대해지고 치밀해지는데... 전세계를 무대로 한 통쾌하고 짜릿한 완전범죄 매직쇼가 시작된다!', 'https://image.tmdb.org/t/p/w500/mX3ozgAvhonMzawKFlxjvP605Sm.jpg', 2013, 0, 0, '2026-06-06 13:25:28.107704', 'US');
INSERT INTO public.movies VALUES (823, 297802, '아쿠아맨', '["Action", "Adventure", "Fantasy"]', NULL, '[]', '정략결혼을 피해 해저 왕국 아틀란티스에서 도망쳐 육지로 오게 된 아틀라나는 등대지기 톰과 사랑에 빠진다. 아틀란티스의 세력으로부터 남편과 아들 아서를 지키기 위해서 아틀라나는 바다로 돌아가고, 육지에 남은 아서는 어릴 때부터 자신의 초능력을 인지해 인간세계의 해적을 물리치는 등 나름의 활약을 펼친다. 한편 아서의 이부형제 옴은 육지를 정복하기 위한 작전을 세운다. 옴의 약혼자이자 네레우스 왕의 딸 메라는 아서에게 평화를 위해 해저 7개 왕국의 왕이 되어야만 한다고 설득하는데...', 'https://image.tmdb.org/t/p/w500/5tetypC0S7BwpBk1ZG36wExvNYj.jpg', 2018, 0, 0, '2026-06-06 13:25:28.084711', 'US');
INSERT INTO public.movies VALUES (4172, 1016011, '윤율과 러시아 색녀', '["Romance"]', 'Kim Deok-gyu', '["Yoon Yool", "Min Do-yoon", "Kang Min-woo"]', NULL, 'https://image.tmdb.org/t/p/w500/30Yju7mD4O4gWq55Y4uOKur83Pu.jpg', 2022, 0, 0, '2026-06-08 06:28:00.763046', 'KR');
INSERT INTO public.movies VALUES (2976, 739405, '스파이 코드명 포춘', '["Action", "Comedy", "Thriller", "Adventure"]', NULL, '[]', '전 세계 검은 무기 거래 왕, 슈퍼 빌런 ‘그렉’  그가 정체를 파악조차 불가능한 ‘핸들’을 거래한다는  첩보 내용이 입수된다. 국가 정보국은 전세계를 붕괴시킬 수도 있는  이것이 무엇인지 대혼돈에 빠지게 되고… 이 혼돈을 해결할 자는 오직 하나! 액션 만랩, 수트 핏과 꿀성대까지! 모든 것이 완벽한 업계 최고의 스파이 ‘포춘’ 무비 스타, 테크 전문가와 샷건 마스터까지 팀 ‘포춘’을 조합한 후 일생일대의 위험한 임무에 나서게 되는데…', 'https://image.tmdb.org/t/p/w500/5QXoAgO905YGucMJmeDb4CmjEUT.jpg', 2023, 0, 0, '2026-06-07 12:17:56.20484', 'US');
INSERT INTO public.movies VALUES (822, 438695, '씽2게더', '["Animation", "Comedy", "Family"]', NULL, '[]', '대국민 오디션 이후 각자의 자리에서 꿈을 이루고 있는 버스터 문(매튜 맥커너히)과 크루들에게 레드 쇼어 시티에서 전 세계가 주목하는 사상 최고의 쇼가 펼쳐진다는 소식이 들려오고 버스터 문과 크루들은 도전에 나선다. 그러나 최고의 스테이지에 서기 위한 경쟁은 이전과는 비교도 할 수 없을 만큼 치열하고, 버스터 문은 완벽한 라이브를 위해 종적을 감춘 레전드 뮤지션 클레이(보노)를 캐스팅하겠다는 파격 선언을 하는데!', 'https://image.tmdb.org/t/p/w500/xxpPSgWZ1D7S5ugMjGdHJpOjZIz.jpg', 2021, 0, 0, '2026-06-06 13:25:28.081568', 'US');
INSERT INTO public.movies VALUES (2983, 756999, '블랙폰', '["Horror", "Thriller"]', NULL, '[]', '한 소년이 대낮에 마스크를 쓴 남자에게 납치당한다. 소리가 새 나가지 않는 방음 지하실에 갇힌 소년. 그런데 전화벨이 울리기 시작한다. 발신자는 납치 살인범의 이전 희생자들.', 'https://image.tmdb.org/t/p/w500/eJPIkRiYGnvQaPCZtTRTDmhMJVK.jpg', 2022, 0, 0, '2026-06-07 12:17:57.104884', 'US');
INSERT INTO public.movies VALUES (2984, 1291659, '크렘린의 마법사', '["Drama"]', 'Olivier Assayas', '["Paul Dano", "Jude Law", "Alicia Vikander", "Tom Sturridge", "Will Keen"]', '고르바초프와 옐친의 시대, 페레스트로이카의 자유와 혼란이 공존하던 시기를 배경으로 시작된다. 새 시대를 꿈꾸며 돈과 성공에 취한 ‘신흥 러시아인들’의 한 사람, 바딤 바라노프는 푸틴을 권좌로 끌어올리는 데 결정적인 역할을 한다. 하지만, 이 선택은 곧 자신을 파괴하게 될 힘을 스스로 초래한 것이기도 하다.', 'https://image.tmdb.org/t/p/w500/efxlwMqMiZzDF2DABswC5VWptRC.jpg', 2026, 0, 0, '2026-06-07 12:17:57.107537', 'FR');
INSERT INTO public.movies VALUES (817, 651045, '노래방: 화끈한 여자들 2', '["Drama", "Romance"]', 'Lee Min-woo', '["Hae Il", "Han Seo-ah", "Seo Bo-ra", "Kim Ji-ah", "Min Do-yoon"]', '노래방 도우미와 손님들사이의 관계를 다룬 성애 영화', 'https://image.tmdb.org/t/p/w500/tQFVcoko6Qn5RldUnnlCg50Xdtw.jpg', 2019, 0, 0, '2026-06-06 13:25:27.324755', 'KR');
INSERT INTO public.movies VALUES (829, 1621, '대역전', '["Comedy"]', NULL, '[]', '증권 중개 회사를 경영하는 대재벌 듀크 형제 랜돌프(랄프 벨러미 분)와 모티머(돈 에머치 분)는 내기를 건다. 그것은 밑바닥 인생을 사는 흑인 거지 빌리(에디 머피 분)와 앞날이 창창한 듀크 회사의 전무인 루이스(댄 애크로이드 분)의 처지를 서로 바꾸는 것이었다. 이들은 한낱 재미에 불과한 장난이지만 본인들은 서로 인생이 바뀌는 모험 속에 빠지고 만다.  졸지에 마약 거래범으로 체포되어 거지가 된 루이스는 결국 자살 시도까지 하고, 또 거지에서 증권 중개인으로 성공한 빌리는 상류 사회에 빠져든다. 결국 두 사람은 자신들의 인생이 듀크 형제에 의해 놀아난 것을 알고 복수를 계획한다. 루이스의 집사인 콜먼(덴홀 엘리오트 분)과 거지가 된 빌리를 도와준 창녀 오필리아(제이리 리 커티스 분)의 힘을 빌린 두 사람은 듀크 형제가 돈을 벌 계략을 알아내어, 이것을 이용, 마침내 듀크 형제의 전재산을 날리게 하고 자신들은 일약 거액의 돈을 버는데 성공한다.', 'https://image.tmdb.org/t/p/w500/8mBuLCOcpWnmYtZc4aqtvDXslv6.jpg', 1983, 0, 0, '2026-06-06 13:25:28.100103', 'US');
INSERT INTO public.movies VALUES (2587, 41264, '아듀 아프리카', '["Documentary", "History", "Horror"]', NULL, '[]', '아프리카 식민지 시대의 종말에 대한 다큐멘터리로, 밀렵, 폭력, 살인, 부족 학살 행위를 묘사합니다.', 'https://image.tmdb.org/t/p/w500/3QRqOjfjon5j3RQEK87t0ftut5G.jpg', 1966, 0, 0, '2026-06-07 12:17:39.276581', 'US');
INSERT INTO public.movies VALUES (600, 142, '브로크백 마운틴', '["Drama", "Romance"]', NULL, '[]', '눈부신 만년설로 뒤덮인 봉우리와 맑고 깊은 계곡, 한없이 펼쳐진 푸른 초원 위에 노니는 수천 마리의 양떼가 장관을 이루고 있는 8월의 브로크백 마운틴. 이곳의 양떼 방목장에서 여름 한 철 함께 일하게 된 갓 스물의 두 청년 에니스와 잭은 마치 오랜 친구처럼 서로에게 마음을 터놓는 사이가 된다. 대자연의 품에서 깊어져 간 그들의 우정은 친구 사이의 친밀함 이상으로 발전해간다. 그들 앞에 놓인 낯선 감정의 실체가 무엇인지도 알지 못한 채 짧은 방목철이 끝나고 다시 만날 기약도 없이 두 사람은 각자의 삶으로 돌아간다. 결혼해 아이를 낳고 평범한 생활을 하다가 4년 만에 다시 만난 두 사람은 단번에 브로크백에서 서로에게 가졌던 그 낯선 감정이 일시적인 것이 아니었음을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/o5oQC9GxEfClgnHvabpvGhkUoqe.jpg', 2005, 0, 0, '2026-06-06 13:25:18.792323', 'US');
INSERT INTO public.movies VALUES (830, 20017, '빗나간 동작', '["Drama"]', NULL, '[]', '빌헬름은 글을 쓰고 싶지만 고향에는 음울함과 실의만이 무겁게 자리하고 있다. 곧 그는 작가가 되려는 열망을 이루기 위해 어머니와 고향으로부터 멀어져 여행을 떠난다. 여행하는 동안 그는 과거에 나치였던 유랑가수 라에르테스와 벙어리 소녀 미뇽과 동행하게 되며 여배우인 테레사와 사랑에 빠지는가하면 젊은 유랑 시인 베른하르트 란다우와 친구가 되기도 한다. 하지만 그들을 초대해 하룻밤을 묵게 해줬던 한 산업자본가가 자살한 이후 일행들은 하나 둘씩 떨어져 나간다. 다시 혼자가 된 빌헬름은 글을 쓰는데 전력을 기울이게 된다..', 'https://image.tmdb.org/t/p/w500/qzMyOIUJ5UQgFSoljRQtkYRKXMU.jpg', 1975, 0, 0, '2026-06-06 13:25:28.103062', 'US');
INSERT INTO public.movies VALUES (658, 242582, '나이트 크롤러', '["Crime", "Drama", "Thriller"]', NULL, '[]', '루이스는 우연히 목격한 교통사고 현장에서 사건 현장을 카메라에 담아 TV 매체에 고가에 팔아 넘기는, 일명 나이트 크롤러를 보게 된다. 경찰이 도착하기 전에 빠르게 나타나 현장을 스케치하고 전화를 통해 가격을 흥정하는 그들에게서 묘한 돈 냄새를 맡은 루이스는 즉시 캠코더와 경찰 무전기를 구입하고 사건현장에 뛰어든다. 유혈이 난무하는 끔찍한 사고 현장을 적나라하게 촬영해 첫 거래에 성공한 루이스는 남다른 감각으로 지역채널의 보도국장 니나의 적극적인 지지를 받게 된다. 매번 더욱 더 자극적이고 충격적인 뉴스를 원하는 니나와 그 이상을 충족 시켜주는 루이스는 최상의 시청률을 만들어내며 승승장구한다. 자신의 촬영에 도취된 루이스는 결국 완벽한 특종을 위해 사건을 조작하기에 이르는데...', 'https://image.tmdb.org/t/p/w500/wVflplL5OMy8nD1Z7gM64lIRvwa.jpg', 2014, 0, 0, '2026-06-06 13:25:21.129992', 'US');
INSERT INTO public.movies VALUES (8834, 397243, '제인 도', '["Horror", "Mystery"]', 'André Øvredal', '["Emile Hirsch", "Brian Cox", "Ophelia Lovibond", "Olwen Catherine Kelly", "Michael McElhatton"]', '3대째 부검소를 운영 중인 토미와 오스틴 부자는 보안관의 다급한 의뢰로 신원미상인 젊은 여성의 부검을 하게 된다. 하지만 그녀의 몸에 숨겨져 있던 흔적들에서 끔찍한 비밀이 밝혀지는데...', 'https://image.tmdb.org/t/p/w500/gem6mHLneu1q970nZ8eRG8bWgH8.jpg', 2016, 0, 0, '2026-06-08 07:30:02.611681', 'GB');
INSERT INTO public.movies VALUES (826, 593643, '더 메뉴', '["Comedy", "Horror"]', NULL, '[]', '커플인 마고와 타일러는 까다롭기로 유명한 셰프, 슬로윅의 초청을 받아 어느 외딴섬 레스토랑의 저녁 식사에 참석하게 된다. 평소 슬로윅을 존경해왔던 타일러는 들뜬 마음으로 여러 유명인사들과 함께 섬으로 출발하는 배에 탑승한다. 레스토랑에 도착한 손님들은 슬로윅의 화려한 환대에 탄성을 자아낸다. 하지만 ‘음식은 또 다른 예술’이라는 슬로윅의 기괴한 집착에, 좋았던 분위기는 점차 이상한 방향으로 흐른다. 뭔가 심상치 않음을 감지한 마고는 이의를 제기하려 하지만, 이미 슬로윅의 음식에 푹 빠져버린 타일러에게 그녀의 제안은 안중에도 없다. 그런 와중에 슬로윅의 기괴한 집착은 점점 선을 넘기 시작하는데...', 'https://image.tmdb.org/t/p/w500/2Bi9OTGNAkNjStDnMDR93GPgwFY.jpg', 2022, 0, 0, '2026-06-06 13:25:28.092162', 'US');
INSERT INTO public.movies VALUES (831, 170, '28일 후', '["Horror", "Thriller", "Sci-Fi"]', 'Danny Boyle', '["Cillian Murphy", "Naomie Harris", "Brendan Gleeson", "Megan Burns", "Christopher Eccleston"]', '분노 바이러스에 감염되어있던 침팬지들이 우리에서 풀려나고 바이러스는 런던 전역에 퍼진다. 텅 빈 병원에서 깨어난 짐은 감염자들의 공격을 피해 생존자들과 맨체스터로 향한다.', 'https://image.tmdb.org/t/p/w500/yUEgICZTj6NMiPsb0hWs3qYByDe.jpg', 2002, 0, 0, '2026-06-06 13:25:28.105387', 'GB');
INSERT INTO public.movies VALUES (6024, 205022, '첸나이 익스프레스', '["Romance", "Comedy", "Action"]', 'Rohit Shetty', '["Shah Rukh Khan", "Deepika Padukone", "Nikitin Dheer", "Sathyaraj", "Mukesh Tiwari"]', '라훌은 자신의 유골을 인도에서 신성한 장소 중 하나인 라메스와람에 뿌려달라는 할아버지의 유언을 지키기 위해 첸나이행 특급열차에 오른다. 라훌은 기차에서 아리따운 여인을 만나는데 그녀는 조폭이나 다름없는 가족들을 피해 달아나는 중! 활기 넘치는 곳 남인도를 배경으로 의 샤룩 칸과 디피카 파두콘 콤비가 선사하는 눈과 귀가 즐거운 맛살라 무비. (2014년 제18회 부천국제판타스틱영화제)', 'https://image.tmdb.org/t/p/w500/9j7XfhBJKNfidMCa8JsNbqU1waV.jpg', 2013, 0, 0, '2026-06-08 06:53:04.349862', 'IN');
INSERT INTO public.movies VALUES (4178, 1099639, '50대 묵은지 장모님의 유혹', '["Romance", "Drama"]', '김태훈', '["Ahn So-hee", "Jeon Eun-jin", "Han Seok-bong", "Jo Wan-jin", "Ji Min-iI"]', NULL, 'https://image.tmdb.org/t/p/w500/w4NBXeIu5wR8RZmw3Apq6pw72tB.jpg', 2023, 0, 0, '2026-06-08 06:28:04.943045', 'KR');
INSERT INTO public.movies VALUES (841, 1123640, '卍舞Ⅲ いかせてあげる、極楽浄土', '["Drama"]', 'Keiichirō Yoshida', '["Hitoe Ootake", "Taisaku Akino", "Junko Asahina", "Ito Yozaburo", "Hiroyuki Konishi"]', NULL, 'https://image.tmdb.org/t/p/w500/mvyxrQtti8b8fn5ZoAc36VcwArt.jpg', 1996, 0, 0, '2026-06-06 13:25:28.836631', 'JP');
INSERT INTO public.movies VALUES (835, 410119, '육보단', '["Drama", "Fantasy", "Romance"]', NULL, '[]', '청년시절 여인을 탐하는 꿈을 자주 꾸던 이운생은 소향과 결혼한 후, 과거보러 떠난 길에 명주실 짜는 옥분을 알게 되어 사랑에 빠진다. 옥분의 남편 관녹지는 위자료를 받아낸 뒤, 운생의 집에 머슴으로 들어가 소향과 밀애후 도피행각을 하기에 이른다. 복수가 목적이었던 곽녹지는 소향을 홍루에 팔아버린 후, 절에 들어간다. 한편, 집에 돌아와 장인으로부터 아내가 상사병에 걸려 죽었다는 말을 듣고 다시 길을 떠나다 홍루에서 기생이 된 아내를 만나게 된 운생은 모든 사실을 알게된다. 소향이 고심 씉에 목을 매어 자살하자, 이운생은 삭발 후 절에 들어가 판녹지와 함께 큰스님을 모신다.', 'https://image.tmdb.org/t/p/w500/3NwBn6zPY6yXCqfxEHmEgGh8Jgc.jpg', 1987, 0, 0, '2026-06-06 13:25:28.114562', 'US');
INSERT INTO public.movies VALUES (838, 85877, '밀도성숙시33D', '["Comedy", "Sci-Fi"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/bBC1fBHyFBmc6fn4UDedtkOVSaD.jpg', 2011, 0, 0, '2026-06-06 13:25:28.121255', 'US');
INSERT INTO public.movies VALUES (629, 333339, '레디 플레이어 원', '["Adventure", "Action", "Sci-Fi"]', NULL, '[]', '2045년, 암울한 현실과 달리 가상현실 오아시스에서는 누구든 원하는 캐릭터로 상상하는 모든 걸 할 수 있다. 웨이드 와츠의 유일한 낙은 오아시스에 접속하는 것. 어느 날 오아시스의 창시자인 괴짜 천재 제임스 할리데이는 자신이 가상현실 속에 숨겨둔 3개의 미션에서 우승하는 사람에게 오아시스의 소유권과 막대한 유산을 상속한다는 유언을 남기고, 그가 사랑했던 80년대 대중문화 속에 힌트가 있음을 알린다. 와츠가 첫 번째 수수께끼를 푸는 데 성공하자 이를 저지하기 위해 현실에서 살인도 마다하지 않는 IOI라는 거대 기업이 뛰어드는데...', 'https://image.tmdb.org/t/p/w500/j4TIfwFrm8WnckByTnMFEAuIVju.jpg', 2018, 0, 0, '2026-06-06 13:25:20.333839', 'US');
INSERT INTO public.movies VALUES (837, 601, '이티', '["Adventure", "Sci-Fi", "Family"]', NULL, '[]', '지구조사를 위해 우주선을 타고 지구에 온 외계인 이티는 식물 채집에 열중하다가 우주선에서 낙오되어 혼자 지구에 남게된다. 지구인들에게 쫓기던 이티는 엘리엇을 만나 그의 집에 숨는다. 엘리엇은 형 마이클, 여동생 거티와 함께 이티를 보살펴주지만 이티는 알 수 없는 병에 걸려 점점 약해져간다. 한편 이티를 추적하던 당국은 이티가 있는 곳을 알아내어 이티를 치료하며 실험용으로 관찰한다. 그러나 병이 회복되지 않아 모두 포기해버린 때에 외계인의 우주선이 보낸 전파로 인해 이티가 다시 소생하고, 엘리엇은 이티를 데리러 오는 우주선의 착륙장소에 이티를 데리고 가는데...', 'https://image.tmdb.org/t/p/w500/9Kl6z0J1Hu3cFOFXNBrqqVWoNmI.jpg', 1982, 0, 0, '2026-06-06 13:25:28.119041', 'US');
INSERT INTO public.movies VALUES (839, 351286, '쥬라기 월드: 폴른 킹덤', '["Adventure", "Sci-Fi", "Thriller"]', NULL, '[]', '지상 최대의 테마파크 쥬라기 월드가 폐쇄된 지 3년 후.  이슬라 누블라의 활화산 시보산이 분화하려는 조짐을 보이자 조짐에 뉴스에서는 이와 더불어 공룡들의 보호에 관련된 시위나 소식들을 보도한다. 오웬(크리스 프렛)과 클레어(브라이스 달라스 하워드)는 벤자민 록우드(제임스 크롬웰)의 부탁으로 공룡들의 멸종을 막기 위해 이슬라 누블라 섬으로 떠난다. 한편 진화된 공룡들을 이용하려는 세력의 거대한 음모가 드러나고, 절대 지상에 존재해선 안될 위협적 공룡들이 마침내 세상 밖으로 등장하게 되는데...', 'https://image.tmdb.org/t/p/w500/xR2VgpNxElFOJBul0q7ULiT0ayF.jpg', 2018, 0, 0, '2026-06-06 13:25:28.123496', 'US');
INSERT INTO public.movies VALUES (864, 704347, 'Honey Do List', '["Romance", "Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/of6zefDol6KaIZVaoAbQqDCqQAV.jpg', 2020, 0, 0, '2026-06-06 13:25:29.617655', 'US');
INSERT INTO public.movies VALUES (836, 373571, '고질라: 킹 오브 몬스터', '["Sci-Fi", "Action"]', NULL, '[]', '고질라의 샌프란시스코 공격으로 인해 아들을 잃은 상처로 엠마와 마크, 딸 매디슨 가족은 슬픔 속에 살고 있다. 미지의 생물을 연구하는 모나크 소속 과학자인 엠마는 또 다른 공격에 대비해 거대 괴수와 소통하는 주파수를 발견한다. 그러나 괴수들을 조종해 지구를 초토화 시키려는 테러 세력에게 딸 매디슨과 납치되고, 주파수로 모스라, 로단, 기도라 등 고대 괴수들이 하나 둘 깨어난다. 역대급 재난 상황에서 인류의 생존 자체조차 불투명해지고, 여기에 강력한 고질라의 등장으로 괴수들의 대결은 새로운 국면을 맞이한다. 또 다시 최악의 위기를 맞은 가족들은 어떻게든 함께 위험을 헤쳐나가야만 하는데...', 'https://image.tmdb.org/t/p/w500/ge8zQ874jsZBcsYxn7yV5EMHV10.jpg', 2019, 0, 0, '2026-06-06 13:25:28.116829', 'US');
INSERT INTO public.movies VALUES (4177, 1297107, '흑인에게 미친 여친', '["Romance"]', 'Lee Sang-soo', '["Lee Soo", "Joey", "Shin Yeon-woo"]', NULL, 'https://image.tmdb.org/t/p/w500/jhzKqwkcx5cFOAkUMHfMR08n9rH.jpg', 2023, 0, 0, '2026-06-08 06:28:04.128621', 'KR');
INSERT INTO public.movies VALUES (4179, 387820, '수상한 미용실', '["Romance", "Drama"]', 'Han Dong-Ho', '["Lee Sin-ho", "Jung Won-II", "Lee Chae-dam"]', '미용실을 개업한 원장 분홍과 종업원 미나. 미용실을 개업한지 한참 지나도 손님이 늘지는 않고, 미용실에는 파리만 날리고 있다. 그래서 미나는 섹시함을 컨셉으로 손님들을 끌어들이고 이에 미용실은 대박이 나게 된다. 한편 미나는 애인인 오탁구에게 미용실 홍보를 부탁하고, 오탁구의 회사 동료들도 미용실을 애용하게 된다. 그러던 와중 탁구의 회사 부장인 변상태가 분홍의 미용실을 찾게 되고, 분홍에게 관심을 보이며 탁구에게 분홍, 미나와 함께 여행을 가자며 제안을 하게 되는데...', 'https://image.tmdb.org/t/p/w500/qqSZAGnEh1ntFnKFBDACh7YUOwb.jpg', 2015, 0, 0, '2026-06-08 06:28:05.612134', 'KR');
INSERT INTO public.movies VALUES (844, 9453, '칼리굴라', '["Drama", "History"]', NULL, '[]', '편집증 황제 티베리우스가 죽은 후, 그의 후계자 칼리굴라가 권력을 장악하고 제국을 광기와 타락의 소용돌이에 빠뜨립니다.', 'https://image.tmdb.org/t/p/w500/e5lth5KCLCOQLB9N903a7RMXzrU.jpg', 1979, 0, 0, '2026-06-06 13:25:28.844716', 'US');
INSERT INTO public.movies VALUES (849, 9340, '구니스', '["Adventure", "Comedy", "Family"]', NULL, '[]', '은행에 잡힌 저당으로 인해 곧 철거될 한 변두리 동네에서 아이들이 보물지도 한 장을 찾아낸다. 이 지도가 17세기 중엽 영국 해군과 싸우다 패하여 해저동굴에 숨어들어갔다는 ''애꾸눈 윌리''가 보물을 숨겨둔 장소를 나타낸 것임을 알고 아이들은 모험을 시작한다. 해저 동굴의 입구인 등대 식당에서 위조지폐를 만드는 악당들에게 심한 곤욕을 치른 후 탈출한 아이들은 식당 지하실부터 해저 동굴로 들어가 한없는 통로를 헤쳐 나간다. 마침내 지도가 표시한 지점에 당도하여 보물을 손에 넣게 되지만 아이들은 악당들에게 잡혀 손에 들었던 금은 보화는 내동뎅이친 채 탈출한다. 그러나 우연히 들고나온 한 자루의 보물이 철거될 동네를 구하게 되어 아이들의 모험은 보석처럼 빛을 발한다.', 'https://image.tmdb.org/t/p/w500/w4AKh5YDOwUKqrnuyDZkY83Urjn.jpg', 1985, 0, 0, '2026-06-06 13:25:28.857326', 'US');
INSERT INTO public.movies VALUES (848, 299537, '캡틴 마블', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '외계 크리 문명의 수도 할리, 캐롤 댄버스은 압도적인 능력을 가진 전사다. 그는 멘토 욘 로그로부터 힘을 통제하고 과거의 기억은 묻어야 한다는 가르침을 받고 있다. 그러던 어느 날, 변방 행성 토르파에서 스크럴 종족에게 붙잡혀 뇌를 스캔당한 캐롤은 과거 자신이 낯선 행성의 파일럿이었음을 알게 된다. 스크럴을 따돌리고 탈출하는 과정에서 공교롭게 C-53 행성, 즉 지구에 불시착한 캐롤. 우여곡절 끝에 쉴드 신참 요원 닉 퓨리에게 발견되어 팀을 이룬 그들은 지구로 향하는 더 큰 위협을 감지하고 힘을 합쳐 전쟁을 끝내야 하는데...', 'https://image.tmdb.org/t/p/w500/2JO8X8aT97BwxMMGr9ChrCl4xGQ.jpg', 2019, 0, 0, '2026-06-06 13:25:28.854758', 'US');
INSERT INTO public.movies VALUES (529, 12155, '이상한 나라의 앨리스', '["Family", "Fantasy", "Adventure"]', NULL, '[]', '더 이상 소녀가 아닌 19살의 앨리스가 어쩌다 본의 아니게 또다시 들어간 이상한 나라는 예전에 겪었던 그 이상한 나라가 아니다. 십여년 전 홀연히 앨리스가 사라진 후 이상한 나라는 독재자 붉은 여왕이 그녀 특유의 공포 정치로 통치하고 있었던 것. 물론 하얀 토끼와 트위들디와 트위들덤 쌍둥이, 겨울잠 쥐, 애벌레와 음흉하게 웃어대는 체셔 고양이 그리고 미친 모자장수는 붉은 여왕의 공포 정치 속에서도 정신없는 오후의 티타임을 즐기고 있다. 마치 어제 헤어진 친구를 오늘 다시 만난 듯 앨리스의 귀환을 대환영하는 미친 모자장수와 그 친구들. 손가락만큼 작아져버린 앨리스는 모자장수의 정신없는 환대와 붉은 여왕의 공포 정치를 뚫고 이번에도 무사히 집으로 돌아갈 수 있을까?', 'https://image.tmdb.org/t/p/w500/9PZfYjgz6FeATs3V99FD509KWJf.jpg', 2010, 0, 0, '2026-06-06 13:25:16.45336', 'US');
INSERT INTO public.movies VALUES (847, 197, '브레이브하트', '["Action", "Drama", "History"]', NULL, '[]', '13세기 말, 스코틀랜드 왕이 후계자 없이 죽자 잉글랜드는 왕권을 요구하며 스코틀랜드에 포악한 정치의 그림자를 드리우기 시작한다. 윌리엄 월레스(멜 깁슨)는 폭정을 피하여 멀리 보내져 양육된다. 그가 성장하여 고향에 돌아왔을때 스코틀랜드는 여전히 잉글랜드의 군주 롱생크(패트릭 맥구한)의 핍박과 탄압에 시달리고 있었다. 그는 운명적인 사랑의 여인 머론(캐서린 맥코맥)을 만나 결혼하지만, 잉글랜드의 폭정에 머론은 잔인하게 처형된다. 월레스는 머론의 복수를 다짐하고, 하나 둘씩 모여드는 스코틀랜드 사람들을 모아 용맹과 투지로 무장한 저항군의 지도자가 되는데...', 'https://image.tmdb.org/t/p/w500/3aEg4uxWUJsd1Mcx6TaQAlxZiyZ.jpg', 1995, 0, 0, '2026-06-06 13:25:28.852049', 'US');
INSERT INTO public.movies VALUES (678, 493529, '던전 앤 드래곤: 도적들의 명예', '["Adventure", "Fantasy", "Comedy"]', NULL, '[]', '한때는 명예로운 기사였지만, 어떤 사건 이후 홀가, 사이먼, 포지와 함께 도적질을 하게 된 에드긴. 소피나의 제안으로 부활의 서판을 얻기 위해 코린의 성에 잠입하지만 포지와 소피나의 배신으로 실패하고 감옥에 갇힌다. 기발한 방법으로 탈옥에 성공한 에드긴과 홀가는 소중한 사람들과 다시 만나고, 부활의 서판도 되찾기 위해  자신만의 팀을 꾸리기 시작한다. 옛 동료인 소질 없는 소서러 사이먼과 새롭게 합류한 변신 천재 드루이드 도릭, 재미 빼고 다 가진 팔라딘 젠크까지 어딘가 2% 부족한 오합지졸로 가득한 이 팀, 과연 무사히 모험을 끝마칠 수 있을까?', 'https://image.tmdb.org/t/p/w500/rEEEl6t8LDA3h25woAw6aYsqaSs.jpg', 2023, 0, 0, '2026-06-06 13:25:21.88525', 'US');
INSERT INTO public.movies VALUES (843, 1366, '록키', '["Drama"]', NULL, '[]', '이탈리아의 종마라는 별명을 가진 젊은 청년 록키 발보아는 필라델피아 빈민촌에 살면서 4회전 복서를 업으로 삼아 근근히 살아간다. 복싱만으로는 생계를 유지할 수 없어 고리대금 업자의 하수인 노릇을 하기도 하며 뒷골목의 주먹 노릇도 하는 그는 짝사랑하는 애드리언에게 열심히 관심을 보이면서 성실하게 살아 가려고 애쓴다. 그러던 어느 날 록키에게 기회가 오게 된다. 헤비급 세계 챔피언 아폴로 크리드가 미국 독립 200주년을 기념하는 이벤트로서 이름 없는 복서에게 도전권는 이벤트를 기획하고, 록키가 도전자로 선발이 되는데...', 'https://image.tmdb.org/t/p/w500/vpo99XjnIdkM9QDlQRTj5XEuUOH.jpg', 1976, 0, 0, '2026-06-06 13:25:28.842439', 'US');
INSERT INTO public.movies VALUES (855, 146233, '프리즈너스', '["Drama", "Thriller", "Crime"]', NULL, '[]', '한가로운 휴일, 가족과 행복한 시간을 보내던 도버 와 버치 는 자신들의 딸이 실종됐다는 사실을 뒤늦게 알아차린다. 곧바로 형사 로키 와 함께 존스 를 용의자로 지목하지만 그에게서는 어떤 증거도 찾을 수 없다. 완벽한 용의자를 의심하는 아빠는 홀로 그를 쫓기 시작하고, 형사는 세상에 숨겨진 진범을 찾기 위해 추적을 시작한다. 유력한 용의자를 범인이라고 믿는 아빠. 진짜 범인은 따로 있다고 믿는 형사. 각각 다른 방식으로 추적을 시작한 두 사람은 마침내 세상을 충격에 빠트릴 진실과 마주치게 되는데...', 'https://image.tmdb.org/t/p/w500/9IDBwAfNzv4Xa03uhT8ggoxg5py.jpg', 2013, 0, 0, '2026-06-06 13:25:28.872739', 'US');
INSERT INTO public.movies VALUES (970, 50727, '방자전', '["Romance", "Drama", "Comedy"]', 'Kim Dae-woo', '["Kim Joo-hyuk", "Cho Yeo-jeong", "Ryoo Seung-bum", "Ryu Hyun-kyung", "Song Sae-byuk"]', '몽룡을 따라간 청풍각에서 기생의 딸 춘향에게 한 눈에 반해 버린 몸종 방자. 도련님 또한 그녀를 눈여겨본다는 사실에 마음을 접으려 하지만, 자신을 하대하는 몽룡의 태도에 적개심으로 춘향에 대한 자신의 마음을 드러내 버린다. 춘향 역시 방자의 남자다움과 자상함에 흔들리고, 마침내 방자는 춘향을 품게 된다.  하지만, 신분 상승의 꿈을 접을 수 없는 춘향은 몽룡이 과거 시험을 위해 한양으로 떠나기 전 정인 서약을 맺고, 방자는 이를 알면서도 춘향에 대한 마음을 접지 못한다. 그러던 어느날, 장원 급제한 몽룡이 돌아와 춘향에게 더 큰 출세를 위해 모종의 거래를 제안하게 되는데…', 'https://image.tmdb.org/t/p/w500/QsXaA6s0TTM8TP28Jx4QXgaY1I.jpg', 2010, 0, 0, '2026-06-06 13:25:33.489892', 'KR');
INSERT INTO public.movies VALUES (854, 882569, '더 커버넌트', '["Action", "Thriller"]', NULL, '[]', '끝이 보이지 않았던 전쟁의 한가운데 미 육군 소속 상사 ‘존 킨리’(제이크 질렌할)는 습격을 당한다. 목숨을 잃을 절체절명의 순간, 그는 현지 통역사 ‘아메드’(다 살림)의 도움으로 생환에 성공하고 ‘아메드’와 그의 가족들이 미국에서 살 수 있도록 최선을 다 하겠다고 약속한다  생환 이후의 어느 날, ‘존 킨리’는 자신을 도와주었던 ‘아메드’가 미국에 오지 못했으며 적들에게 억류되어 있다는 사실을 알게 된다.', 'https://image.tmdb.org/t/p/w500/11EHXs37YRZPyIyJjlUB2FAnbys.jpg', 2023, 0, 0, '2026-06-06 13:25:28.8703', 'US');
INSERT INTO public.movies VALUES (860, 80785, 'Curral de Mulheres', '["Thriller", "Adventure", "Action"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/z8WoJGqbHGxEAMZhPO5SXyKrbT6.jpg', 1982, 0, 0, '2026-06-06 13:25:28.884201', 'US');
INSERT INTO public.movies VALUES (4182, 1194963, '노이즈', '["Horror", "Thriller"]', 'Kim Soo-jin', '["Lee Sun-bin", "Kim Min-seok", "Jeon Ik-ryoung", "Ryu Kyung-soo", "Han Su-ah"]', '내 집 마련에 성공한 주영과 주희 자매. 어느 날부터 아파트 어딘가에서 들려오는 정체불명의 층간소음에 시달린다. 그러던 중 동생 주희와 연락이 끊기자 불안에 휩싸인 주영은 급히 지방 공장에서 집으로 돌아오고, 주희의 남자친구 기훈과 함께 실종된 동생을 추적하기 시작한다. 한편, 자매와 마찬가지로 층간소음에 시달리던 아랫집 남자는 그 소음의 근원이 윗집 자매에게 있다고 생각해 살인 협박을 하게 되는데….', 'https://image.tmdb.org/t/p/w500/tPOcNetZHfmn97V93TikhWDXj4T.jpg', 2025, 0, 0, '2026-06-08 06:28:07.739893', 'KR');
INSERT INTO public.movies VALUES (861, 246655, '엑스맨: 아포칼립스', '["Sci-Fi", "Fantasy", "Action"]', NULL, '[]', '고대 이집트에서 신으로 숭배받았던 최초의 돌연변이 아포칼립스가 오랜 잠에서 깨어난다. 초능력을 흡수해가며 수천년을 살아온 아포칼립스는 스톰, 사일록, 아크엔젤 그리고 매그니토에게 자신의 힘을 나누어준 뒤, 그들과 함께 현재의 세상을 뒤엎고 새로운 세상을 건설하려 한다. 찰스 자비에와 미스틱은 아포칼립스의 지구 종말 계획을 알아채고, 진 그레이, 사이클롭스, 퀵 실버, 나이트크롤러 등 젊은 돌연변이들과 함께 아포칼립스에 대항한다.', 'https://image.tmdb.org/t/p/w500/4MaTkqk4LKccDYKh7AjV220CVgW.jpg', 2016, 0, 0, '2026-06-06 13:25:29.60803', 'US');
INSERT INTO public.movies VALUES (863, 799583, '언젠틀 오퍼레이션', '["Action", "Comedy"]', NULL, '[]', '제2차 세계대전, 나치의 살상 무기 유보트를 막기 위해 ‘처칠’의 지휘 아래 최초의 비밀 특수 부대가 탄생한다. 통제 불능의 미친개, 지옥에서 돌아온 근육질 군인 냉철한 폭발물 전문가, 암살이 주특기인 미인계 특수 요원까지··· 대장인 ‘거스 마치’를 필두로 막 나가는 그들이 뭉쳤다!  영국군에 잡히면 감옥에, 나치에게 잡히면 죽음뿐!  유보트를 막기 위한 거스 마치 일행의 ‘언젠틀’한 작전이 시작된다!', 'https://image.tmdb.org/t/p/w500/fYRf4U7w0eyaWG3fVZhbGQBnWQs.jpg', 2024, 0, 0, '2026-06-06 13:25:29.614114', 'US');
INSERT INTO public.movies VALUES (2711, 1895, '스타워즈 에피소드 3: 시스의 복수', '["Adventure", "Action", "Sci-Fi"]', NULL, '[]', '클론 전쟁이 시작되었던 때로부터 3년이 지나고 팰퍼틴 의장과 제다이 사이의 불화는 더욱 커져 클론 전쟁은 더 이상 걷잡을 수 없게 격화된다. 자신이 제다이가 될 것임을 굳게 믿고 있던 아나킨은 제다이 기사 자격을 줄 수 없다는 기사단의 결정에 절망하고, 스승인 오비완과의 갈등은 더욱 깊어만 간다. 그런 아나킨에게 자신의 정체를 드러낸 팰퍼틴은 절대적인 힘을 갖게 해 주겠다며 그를 유혹하고, 아나킨은 점점 어둠의 힘에 이끌려 변해간다. 어둠의 세력에 완전히 장악 당한 아나킨은 자신에게는 아버지나 다름없는 오비완과 맞닥뜨리게 되는데...', 'https://image.tmdb.org/t/p/w500/cKrtSemvrt2tOeHLgxCWauJ3URr.jpg', 2005, 0, 0, '2026-06-07 12:17:44.664734', 'US');
INSERT INTO public.movies VALUES (862, 153104, 'Wicked Minds', '["Mystery", "Drama", "Romance", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/A6A15cDR8mpdOxW4y7UzFanzbM0.jpg', 2003, 0, 0, '2026-06-06 13:25:29.61125', 'US');
INSERT INTO public.movies VALUES (857, 1684226, '올해의 신부', '["Comedy", "Romance", "Family"]', NULL, '[]', '가정을 꾸리는 것이 꿈이었던 링키. 그런데 그 꿈이 산산이 무너지자 ''올해의 신부''에 선정되기 위한 교묘한 계획을 세워 전 남자 친구에게 복수하려 한다.', 'https://image.tmdb.org/t/p/w500/geFc71rCYM8fErbROLY6n1LfAS6.jpg', 2026, 0, 0, '2026-06-06 13:25:28.877311', 'US');
INSERT INTO public.movies VALUES (866, 1561144, 'മധുവിധു', '["Family", "Comedy", "Drama"]', 'Vishnu Aravind', '["Sharafudheen", "Kalyani Panicker", "Vijitha Vijayakumar", "Sreejaya Nair", "Vineeth Thattil David"]', NULL, 'https://image.tmdb.org/t/p/w500/anp8pOwSXCYgKbP8LcYSJ9KgwD9.jpg', 2026, 0, 0, '2026-06-06 13:25:29.624627', 'IN');
INSERT INTO public.movies VALUES (869, 530254, '마녀', '["Action", "Sci-Fi"]', 'Park Hoon-jung', '["Kim Da-mi", "Cho Min-soo", "Park Hee-soon", "Choi Woo-shik", "Go Min-si"]', '10년 전 의문의 사고가 일어난 시설에서 홀로 탈출한 후 모든 기억을 잃은 자윤. 나이도, 이름도 모르는 자신을 거두고 키워준 노부부의 보살핌으로  씩씩하고 밝은 여고생으로 자라났다. 어려운 집안사정을 돕기 위해 상금이 걸린 오디션 프로그램에 출연한 자윤, 방송이 나간 직후부터 의문의 인물들이 그녀 앞에 나타난다. 자윤의 주변을 맴돌며 날카롭게 지켜보는 남자 귀공자, 그리고 과거 사고가 일어난 시점부터 사라진 아이를 찾던 닥터 백과 미스터 최까지 자신은 전혀 기억하지 못하는 그들의 등장으로, 자윤은 혼란에 휩싸이게 되는데...', 'https://image.tmdb.org/t/p/w500/abWjmAyjSWqNo6C5ty3UZTZIYDz.jpg', 2018, 0, 0, '2026-06-06 13:25:29.634213', 'KR');
INSERT INTO public.movies VALUES (873, 278154, '아이스 에이지: 지구 대충돌', '["Adventure", "Animation", "Family", "Comedy", "Sci-Fi"]', NULL, '[]', '도토리를 쫓던 스크랫이 이번에는 우주로 날아가 태양계를 위협하는 행성 충돌 사건을 일으킨다. 이로 인해 거대 운석이 지구로 향해 떨어지는 사상 초유의 위기가 닥치고, 시드와 매니, 디에고를 비롯한 그의 친구들은 안전한 곳을 찾아 머나먼 땅으로 떠나야만 한다. 다시 돌아온 벅은 그들을 이끄는 길잡이가 되고 요가의 대가 샹그리라마, 초절정 미녀 브룩 등이 있는 지오토피아를 만난다. 과연 그들은 지구의 위기를 뚫고 모두를 구해낼 수 있을 것인가? 우주 사상 초유의 모험이 시작된다!', 'https://image.tmdb.org/t/p/w500/e1Fe5z8zcPlpzv2rRrCIhl4zPXQ.jpg', 2016, 0, 0, '2026-06-06 13:25:29.64768', 'US');
INSERT INTO public.movies VALUES (871, 619979, '딥 워터', '["Drama", "Mystery", "Thriller"]', NULL, '[]', '이혼을 피하기 위해 아내가 바람을 피울 수 있도록 허락한 유복한 남편이 연인들의 실종 사건의 유력한 용의자가 된다.', 'https://image.tmdb.org/t/p/w500/bHLDN1EEGuaAjF9H4UmhAOdLN6c.jpg', 2022, 0, 0, '2026-06-06 13:25:29.641087', 'US');
INSERT INTO public.movies VALUES (870, 1531018, '3대3: 캠핑의 목적', '["Drama"]', NULL, '[]', '바람둥이지만 너무 끌리는 그 남자!INSERT INTO public.movies VALUES (889, 562, '다이 하드', '["Action", "Thriller"]', NULL, '[]', '뉴욕 경찰관 존 맥클레인(브루스 윌리스)은 떨어져 사는 아내 홀리 (보니 델리아)를 만나기 위해 LA의 나카도미 빌딩으로 찾아간다. 그러나 파티가 한창 무르익을 무렵, 한스 그루버(알란 릭맨)가 이끄는 일단의 테러리스트들이 침입, 사장을 비롯한 파티 참석자 30여 명을 인질로 삼고 건물 금고에 소장하고 있는 돈과 보물을 손에 넣으려 한다. 최첨단 하이테크에 의해 관리되던 34층짜리 나카토미 빌딩은 통채로 테러리스트들의 수중으로 넘어가 폐쇄되고 고층 빌딩은 살벌한 생존 게임의 전쟁터로 변해가는데...', 'https://image.tmdb.org/t/p/w500/9MPaeRkwS12glOQ818SEtnMd3XA.jpg', 1988, 0, 0, '2026-06-06 13:25:30.407512', 'US');
INSERT INTO public.movies VALUES (868, 260514, '카 3: 새로운 도전', '["Animation", "Drama", "Family"]', NULL, '[]', '한때 최고의 스피드를 자랑하던 레이싱계의 전설 라이트닝 맥퀸은 어느덧 날렵한 디자인과 파워풀한 엔진을 장착한 신예들에 밀려 퇴물 소리를 듣게 된다. 경쟁하던 동료들 역시 하나둘 은퇴를 선언하고, 외롭게 스피드 경쟁을 펼치던 맥퀸도 떠오르는 슈퍼스타 스톰에게 망신을 당하며 1위 자리를 내준다. 급기야 치명적 부상을 입고 은둔생활을 하게 된다. 그러던 중 맥퀸은 젊은 트레이너 크루즈를 만나 재기를 도모한다. 하지만 안 맞아도 너무 안 맞는 크루즈와의 훈련은 맥퀸을 또 다시 어려움에 빠트리는데...', 'https://image.tmdb.org/t/p/w500/3joH7aixEEJeQIov9AB2k04UQkW.jpg', 2017, 0, 0, '2026-06-06 13:25:29.631199', 'US');
INSERT INTO public.movies VALUES (867, 1177445, '카니발 먹방', '["Horror", "Comedy", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/f30neqyKxshsD9T5bCGenqVSkjf.jpg', 2025, 0, 0, '2026-06-06 13:25:29.627926', 'US');
INSERT INTO public.movies VALUES (888, 259316, '신비한 동물사전', '["Fantasy", "Adventure"]', 'David Yates', '["Eddie Redmayne", "Katherine Waterston", "Dan Fogler", "Alison Sudol", "Colin Farrell"]', '1926년 뉴욕, 검은 존재가 거리를 쑥대밭으로 만들고 미국의 마법의회 MACUSA의 대통령과 어둠의 마법사를 체포하는 오러의 수장 그레이브스가 이를 추적하는 혼돈 속에 영국의 마법사 뉴트 스캐맨더가 이 곳을 찾는다. 그의 목적은 세계 곳곳에 숨어있는 신비한 동물들을 찾기 위한 것. 여행을 하면서 다양한 크기의 신비한 동물을 구조해 안에 마법의 공간이 있는 가방에 넣어 다니며 보살핀다. 하지만 은행을 지나던 중 금은보화를 좋아하는 신비한 동물인 니플러가 가방 안에서 탈출을 하고 이 일로 전직 오러였던 티나와 노마지 제이콥과 엮이게 된다. 한편 검은 존재의 횡포는 더욱 거세져 결국 인간 사회와 마법 사회를 발칵 뒤집는 사건이 발생하고, 이 모든 것이 뉴트의 소행이라는 오해를 받게 되는데...', 'https://image.tmdb.org/t/p/w500/1HHH1YR2UL5JLkrsbO6gfcg0gna.jpg', 2016, 0, 0, '2026-06-06 13:25:30.405073', 'GB');
INSERT INTO public.movies VALUES (885, 936245, '히든페이스', '["Mystery", "Thriller"]', 'Kim Dae-woo', '["Song Seung-heon", "Cho Yeo-jeong", "Park Ji-hyun", "Park Ji-young", "Park Seong-geun"]', '지휘자 성진이 이끄는 오케스트라의 첼리스트이자 약혼녀 수연이 어느 날 영상 편지만을 남겨둔 채 자취를 감춘다. 성진은 수연을 잃은 상실감에 고통스러워하지만, 그녀를 대신한 첼리스트 미주에게 강한 끌림을 느낀다. 비 오는 밤, 서로의 욕망에 휩쓸린 성진과 미주는 수연의 집에서 용서받지 못할 짓을 저지른다. 한편 사라진 줄 알았던 수연은 혼자서는 절대 나올 수 없는 집 안 밀실에 갇혀 숨겨진 민낯을 지켜보는데...', 'https://image.tmdb.org/t/p/w500/rkuzlpvaAQIbamiRvEFPqzv4zVk.jpg', 2024, 0, 0, '2026-06-06 13:25:30.397186', 'KR');
INSERT INTO public.movies VALUES (886, 948, '할로윈', '["Horror", "Thriller"]', NULL, '[]', '1963년 할로윈, 6살의 마이클 마이어스는 누나와 누나의 남자 친구를 살해하고 정신 병원으로 보내진다. 15년 후인 1978년 10월 30일, 태풍을 틈타 주치의 루미스 박사의 차를 훔쳐 탈출한 마이크는 고향으로 돌아간다. 한편 학생이자 부동산 중개인의 딸인 로리는 아이들을 봐주고 있는데, 로리의 친구들이 하나씩 사라지기 시작한다.', 'https://image.tmdb.org/t/p/w500/wijlZ3HaYMvlDTPqJoTCWKFkCPU.jpg', 1978, 0, 0, '2026-06-06 13:25:30.400088', 'US');
INSERT INTO public.movies VALUES (887, 531428, '타오르는 여인의 초상', '["Drama", "Romance"]', 'Céline Sciamma', '["Noémie Merlant", "Adèle Haenel", "Luàna Bajrami", "Valeria Golino", "Christel Baras"]', '1770년, 젊은 화가 마리안느는 밀라노 귀족과 결혼을 앞둔 여인 엘로이즈의 초상화를 그려달라는 백작 부인의 의뢰를 받고 엘로이즈가 머무는 외딴섬의 영지에서 며칠간 머물게 된다. 마리안느는 엘로이즈가 초상화 그리는 걸 싫어한다는 이유 때문에 화가라는 신분을 숨기고 접근한다. 마리안느는 엘로이즈의 이목구비를 눈에 담기 위해 매일 산책에 동행하면서 그녀가 지닌 아픔을 어루만져주고 친분도 쌓는다. 어쨌든 그녀는 엘로이즈의 결혼을 종용하는 도구로 사용될 초상화 완성에 매진해야 한다.', 'https://image.tmdb.org/t/p/w500/M0mm1VGMZRa6eRzgoZmYW9zPd8.jpg', 2019, 0, 0, '2026-06-06 13:25:30.402601', 'FR');
INSERT INTO public.movies VALUES (878, 1511057, '룸메이트 소동', '["Comedy"]', NULL, '[]', '내성적인 대학 신입생 데번. 쿨내 나는 셀레스트에게 룸메이트가 되어 달라고 하면서 우정이 시작된다. 하지만 앞에선 웃고 뒤로는 골탕 먹이는 신경전으로 이내 치닫는다.', 'https://image.tmdb.org/t/p/w500/eoVVNi0ErOUTsq7xT1K5i7cR2do.jpg', 2026, 0, 0, '2026-06-06 13:25:29.6646', 'US');
INSERT INTO public.movies VALUES (695, 166426, '캐리비안의 해적: 죽은 자는 말이 없다', '["Adventure", "Action", "Fantasy"]', NULL, '[]', '윌 터너는 죽은 자들을 저승으로 인도하는 플라잉 더치맨호의 선장이다. 뭍에는 일년에 한번밖에 올라오지 못하고, 평생 바다 속에서 지낼 운명에 처해 있다. 윌 터너의 아들, 헨리 터너는 아버지의 저주를 풀기위해 바다 전설을 섭렵했다. 그가 찾은 해결책은 포세이돈의 삼지창을 찾는 것이다. 헨리는 자신을 도와줄 캡틴 잭 스패로우를 찾아 전세계 바다를 떠돈다. 잭 스패로우를 찾는 이는 또 있다. 악마의 삼각지대에 발이 묶인 채 좀비가 되어버린 캡틴 살라자르 일당이 그들인데...', 'https://image.tmdb.org/t/p/w500/arcIFL50IPQT7JDG2SD6tzcOlRL.jpg', 2017, 0, 0, '2026-06-06 13:25:22.644019', 'US');
INSERT INTO public.movies VALUES (877, 1429520, 'Sidelined 2: Intercepted', '["Romance", "Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/sEIP1pTVXa8BJaYSuVeVG3wFN10.jpg', 2025, 0, 0, '2026-06-06 13:25:29.661208', 'US');
INSERT INTO public.movies VALUES (2987, 82690, '주먹왕 랄프', '["Family", "Animation", "Comedy", "Adventure"]', NULL, '[]', '8비트 게임 ‘다고쳐 펠릭스’에서 건물을 부수는 악당 주먹왕 랄프. 30년째 매일같이 건물을 부수며 직업에 충실해왔지만, 악당이라는 이유로 누구도 그를 좋아하지 않는다. 모두에게 인정 받는 영웅이 되고 싶은 마음에 급기야 자기 게임을 이탈하여 다른 게임으로 들어가는 랄프! 슈팅게임 ‘히어로즈 듀티’를 거쳐 레이싱 게임 ‘슈가 러시’에 불시착하는 랄프는 과연 게임 세계의 새로운 영웅이 될 수 있을 것인가! 그리고 랄프가 떠난 후 고장 딱지가 붙은 ‘다고쳐 펠릭스’ 게임은 오락실에서 퇴출될 위기를 넘길 수 있을까?', 'https://image.tmdb.org/t/p/w500/2wVcx484rbNsmP07SRCLdpGtOjM.jpg', 2012, 0, 0, '2026-06-07 12:17:57.115299', 'US');
INSERT INTO public.movies VALUES (879, 1308821, '돈의 맛 : 아찔한 결혼식', '["Romance", "Drama"]', NULL, '[]', '동성이지만 서로를 사랑하는 베카와 유나.INSERT INTO public.movies VALUES (2988, 9753, '쓰리: 서바이벌 아일랜드', '["Adventure", "Drama", "Thriller"]', 'Stewart Raffill', '["Billy Zane", "Kelly Brook", "Juan Pablo Di Pace", "Todd Collins", "Gabrielle Jourdan"]', '건축가 부부 잭과 제니퍼는 친구 부부와 함께 카리브해로 항해 여행을 떠난다. 하지만 잭은 사사건건 배의 크루인 마누엘과 불화를 일으키고 결국 마누엘은 배를 떠나려 한다. 그 때 배에 화재가 발생해 배는 폭발하고 모두 뿔뿔이 흩어진다. 얼마 후 무인도에 표류하게 된 제니퍼는 마누엘을 만나고 그의 본심을 알고 경계를 푼다. 잭도 발견되어 마누엘이 살려주지만 잭은 제니퍼를 의심하고 마누엘을 질투해 결국 이들의 관계는 파국을 향하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/fuQW1G5Xc1oKzAkGCabGzmD8X4E.jpg', 2005, 0, 0, '2026-06-07 12:17:57.117681', 'GB');
INSERT INTO public.movies VALUES (894, 1271, '300', '["Action", "Adventure"]', NULL, '[]', 'BC 480년, 페르시아 국왕 크세르크세스(로드리고 산토로)가 이끄는 대군이 그리스로 진군해온다. 1년 전 복종을 요구하는 페르시아 사자를 우물에 처넣었던 스파르타 국왕 레오니다스(제라드 버틀러)는 그리스 도시국가들과 연합군을 결성하려고 하지만, 신탁은 이를 허락하지 않는다. 그러나 레오니다스는 전쟁에 반대하는 의회에 등을 돌리고 300명의 정예부대와 테르모필레 협곡으로 향한다. 대를 이을 아들이 있는 자만 선발한 레오니다스는 자신이 다시는 왕비 고르고(레나 헤디) 곁으로 돌아오지 못하리라는 사실을 알고 있다.', 'https://image.tmdb.org/t/p/w500/rmJE35EYnJZIp8ObAK3lkiwwjfi.jpg', 2007, 0, 0, '2026-06-06 13:25:30.419733', 'US');
INSERT INTO public.movies VALUES (896, 70981, '프로메테우스', '["Sci-Fi", "Mystery", "Horror"]', NULL, '[]', '리플리가 노스트로모호를 타고 에일리언과 접촉하기 30여년 전, 과학자 엘리자베스 쇼와 찰리 할러웨이가 스코틀랜드에서 선사시대 벽화를 발견한다. 이 벽화가 인류를 창조한 외계인들의 위치를 나타내는 지도라는 걸 깨달은 그들은 웨일랜드사가 꾸린 팀과 함께 탐사선 프로메테우스호를 타고 우주로 나아간다. 탐사대는 행성에 착륙하자마자 외계인들이 남긴 거대한 피라미드형 유적을 발견하고, 내부에서 죽은 외계인들의 시체와 마주친다. 엘리자베스는 죽은 외계인의 DNA가 인간의 것과 똑같다는 것을 밝혀내는데...', 'https://image.tmdb.org/t/p/w500/lpgh1NL1w8p4pk96YLHI0UmPE0o.jpg', 2012, 0, 0, '2026-06-06 13:25:30.424578', 'US');
INSERT INTO public.movies VALUES (908, 240832, '루시', '["Action", "Sci-Fi"]', 'Luc Besson', '["Scarlett Johansson", "Morgan Freeman", "Choi Min-sik", "Amr Waked", "Julian Rhind-Tutt"]', '평범한 삶을 살던 여자 루시는 어느 날 지하세계에서 극악무도하기로 유명한 미스터 장에게 납치되어, 몸 속에 강력한 합성 약물을 넣은 채 강제로 운반하게 된다. 다른 운반책들과 같이 끌려가던 루시는 갑작스런 외부의 충격으로 인해 몸 속 약물이 체내로 퍼지게 되면서, 그녀 안의 모든 감각이 깨어나기 시작하는데…', 'https://image.tmdb.org/t/p/w500/dHPhwkoDDslf2SFzccRG17Y9f2K.jpg', 2014, 0, 0, '2026-06-06 13:25:31.16759', 'FR');
INSERT INTO public.movies VALUES (893, 1363123, '''패밀리 플랜 2'' - The Family Plan 2', '["Action", "Comedy"]', NULL, '[]', '킬러 시절을 뒤로한 댄은 크리스마스에 아이들과 오붓한 시간을 보내고 싶어 한다. 하지만 딸이 따로 계획을 세운 걸 알고, 런던행 가족 여행을 예약해 버린다. 그 결정으로 댄과 가족들은 예상치 못한 적의 표적이 된다.', 'https://image.tmdb.org/t/p/w500/leWNzgtVJwwpukdYdu8aerQFvjP.jpg', 2025, 0, 0, '2026-06-06 13:25:30.417309', 'US');
INSERT INTO public.movies VALUES (897, 225886, 'S테이프', '["Comedy"]', NULL, '[]', '애니(카메론 디아즈)와 제이(제이슨 시겔)는 대학 시절 뜨거운 사랑에 빠져 어린 나이에 결혼한 10년차 부부다. 아이들이 없는 틈을 타서 모처럼 사랑을 나누게 된 두 사람은, 무미건조한 섹스에 실망하여 극단의 조치를 취한다. 바로 둘만의 포르노를 만드는 것. 무려 3시간 동안의 섹스를 아이패드로 촬영한 두 사람은 기진맥진하여 잠이 든다. 다음 날, 제이는 동영상을 잘 봤다는 의문의 문자를 받고는 자신의 실수를 깨닫는다. 섹스 동영상이 그가 선물해준 아이패드에 동기화되어 버린 것이다. 우여곡절 끝에 두 사람은 절친한 친구 로비(롭 코드리) 부부, 사업가 행크의 아이패드를 회수하는데 성공한다. 하지만 문자의 범인인 하워드 때문에 안심할 수는 없는 상황. 로비의 아들인 하워드는 동영상 파일의 복사본을 갖고 있으며, 2만5천 달러를 주지 않으면 포르노 사이트에 파일을 올리겠다고 제이를 협박하는데…', 'https://image.tmdb.org/t/p/w500/pFdS7SIdjcrYXtf141dabWVly9B.jpg', 2014, 0, 0, '2026-06-06 13:25:30.426899', 'US');
INSERT INTO public.movies VALUES (898, 69403, 'L''infermiera nella corsia dei militari', '["Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/8UuCwHK8htLjedwP6hZxMI5WpKZ.jpg', 1979, 0, 0, '2026-06-06 13:25:30.429232', 'US');
INSERT INTO public.movies VALUES (2612, 1257009, '프리미티브 워', '["Action", "Horror", "Sci-Fi"]', NULL, '[]', '1968년, 베트남 정글 깊숙이 사라진 특수부대를 찾기 위해 미군 정찰대가 투입된다. 하지만 그들이 마주한 것은 전쟁이 아니라, 정부의 비밀 실험이 낳은 ‘시간의 틈’이었다. 살아있는 공룡들이 지배하는 금단의 구역에서, 인간은 다시 사냥감이 된다.', 'https://image.tmdb.org/t/p/w500/rPFXcEp6UNLJrjktuixG0aesNwe.jpg', 2025, 0, 0, '2026-06-07 12:17:40.137302', 'US');
INSERT INTO public.movies VALUES (2989, 770156, '루시 쉬머즈 앤 더 프린스 오프 피스', '["Drama", "Family"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/yfnJ5qIYx7q33fY4jqv9Pu95RSg.jpg', 2020, 0, 0, '2026-06-07 12:17:57.120045', 'US');
INSERT INTO public.movies VALUES (623, 313369, '라라랜드', '["Comedy", "Drama", "Romance"]', NULL, '[]', '차들로 빽빽이 들어찬 LA의 고속도로. 거북이 걸음이던 도로가 뚫리기 시작하지만 미아 지금 손에 든 연기 오디션 대본을 놓지 못한다. 세바스찬은 경적을 누르며 미아를 노려보고는 사라진다. 악연의 시작. 이후 미아는 감미로운 피아노 선율에 이끌려 재즈바로 향하는데, 연주자가 바로 세바스찬이다. 미아가 세바스찬에게 인사를 건네려고 다가가던 순간은 하필 그가 재즈바의 레퍼토리를 무시하고 연주한 탓에 해고된 직후. 세바스찬은 인사를 건네려 다가온 미아를 쌩하니 스쳐 지나가버린다. 세 번째로 두 사람은 파티에 온 손님과 출장 밴드의 키보드 연주자로 다시 만나는데...', 'https://image.tmdb.org/t/p/w500/ad9ndytwOckyShSc0A6tx1rZRkW.jpg', 2016, 0, 0, '2026-06-06 13:25:20.316277', 'US');
INSERT INTO public.movies VALUES (904, 614479, '인시디어스: 빨간 문', '["Horror", "Thriller"]', NULL, '[]', '10년 전, 유체이탈을 통해 기이한 사건을 겪은 ''조쉬''와 ''달튼'' 부자는 그날의 기억을 모두 지운다. 10년 후,''조쉬''는 수상한 존재가 주변을 맴돌고 있음을 느끼고, 집을 떠나 대학에 입학한 ‘달튼''은 봉인된 기억 속 빨간 문에 대한 의문을 품게 된다. 램버트 가족에게 연달아 기괴한 사건들이 일어나고 과거의 비밀이 끔찍한 악몽으로 되살아나는데…', 'https://image.tmdb.org/t/p/w500/4UCQWDmMsOxqgtdTbkihSXbexbf.jpg', 2023, 0, 0, '2026-06-06 13:25:31.156357', 'US');
INSERT INTO public.movies VALUES (906, 11224, '신데렐라', '["Family", "Fantasy", "Animation", "Romance"]', NULL, '[]', '친절하고 상냥한 아릉다운 아가씨 신데렐라는 맘씨 나쁜 새 엄마와 시기심 많은 언니들의 구박을 받으면서도 희망을 잃지 않았다. 친구들이라고는 거스와 자크같은 생쥐뿐이지만 그들은 무슨 일이든 신데렐라를 도왔고, 왕자님의 무도회가 열리던 날에는 착한 요정이 나타나 신데렐라에게 아름다운 드레스와 호박으로 만든 마차를 준비해 주었을 때에도 말이 되어 신데렐라와 동행한다. 궁정의 무도회에 참석해서 멋진 왕자님을 만난 신데렐라. 하지만, 시계가 12시를 가리키자 마법은 풀려나고 신데렐라는 유리구두 한짝을 떨군 채 왕자님에게 인사도 못하고 도망치듯 궁전을 빠져나오는데...', 'https://image.tmdb.org/t/p/w500/xJsPQJeQjnD9llyDVVlANQvWdPZ.jpg', 1950, 0, 0, '2026-06-06 13:25:31.162147', 'US');
INSERT INTO public.movies VALUES (907, 131631, '헝거게임: 모킹제이', '["Sci-Fi", "Adventure", "Thriller"]', NULL, '[]', '헝거게임이 끝나고 캣니스의 고향인 12구역이 캐피톨의 폭격으로 파괴되자 그녀는 절망감으로 괴로워한다. 12구역의 생존자들이 13구역에 있다는 것을 알게 된 캣니스는 반정부 세력의 중심이 된다. 어떤 공격도, 어떤 감시도 피할 수 있는 전설의 13구역을 다스리는 대통령 코인은 캣니스에게 혁명의 불꽃이자 반군의 상징인 모킹제이가 되어달라고 부탁하고, 모두의 희망이 된 캣니스는 이제 세상을 구할 반격을 시작한다.', 'https://image.tmdb.org/t/p/w500/r5UG5tSXpHIFFcpx4rvi6ZnJroj.jpg', 2014, 0, 0, '2026-06-06 13:25:31.164834', 'US');
INSERT INTO public.movies VALUES (905, 254, '킹콩', '["Adventure", "Drama", "Action"]', NULL, '[]', '새로운 작품에 대한 열정이 넘치던 영화감독은 거리에서 우연히 발굴한 매력적인 여인 앤 대로우와 함께 영화 촬영을 위해 해골섬을 찾아 떠난다. 그리고 수억만 년 전의 고대 정글이 고스란히 존재하는 해골섬에서 그들은 전설로만 들어왔던 거대한 킹콩과 맞닥뜨린다. 해골섬의 원주민들에게 붙잡혀 제물로 바쳐진 앤의 아름다움에 매료된 킹콩. 갑자기 섬에 존재하는 잔인한 공룡이 나타나 그녀를 공격하고 킹콩은 공룡과 혈전을 벌이며 그녀를 지켜낸다. 그러나 탐욕스러운 욕망에 사로잡힌 감독은 킹콩이 앤에게 마음을 빼앗긴 틈을 타 킹콩을 뉴욕으로 생포해온다. 뉴욕 도심에서 사람들의 구경거리로 전락한 킹콩의 분노는 극에 달하고 야수의 본능을 드러내며 뉴욕 도심을 휩쓸기 시작하는데...', 'https://image.tmdb.org/t/p/w500/51YN66JgY2D6eexN3PwWQwZTXTH.jpg', 2005, 0, 0, '2026-06-06 13:25:31.159383', 'US');
INSERT INTO public.movies VALUES (903, 273477, '좀비 서바이벌 가이드', '["Comedy", "Horror"]', NULL, '[]', '어린 시절부터 6년간 스카우트 생활을 해온 벤(타이 쉐리던)과 카터(로건 밀러)는 카터의 누나 켄들(할스톤 세이지)이 참여하는 비밀파티에 초대를 받는다. 초대를 받은 날 파티에 참여하기 위해 스카우트 캠프를 빠져나온 벤과 카터. 하지만 파티 전 평소 호기심을 갖고 있던 스트립클럽의 문지기가 없은 것을 본 카터는 몰래 클럽에 들어갔다가 좀비들의 공격을 받는다.  뜬금없는 좀비들의 공격. 그곳에서 데니스(사라 두몬트)를 만난 벤과 카터는 비밀파티가 열리는 장소로 켄들을 구하러 가는데...', 'https://image.tmdb.org/t/p/w500/lUKvvSnjFlazrdh6wyHxHrdMknD.jpg', 2015, 0, 0, '2026-06-06 13:25:31.153636', 'US');
INSERT INTO public.movies VALUES (690, 1417, '판의 미로: 오필리아와 세개의 열쇠', '["Fantasy", "Drama"]', NULL, '[]', '먼 옛날 인간들은 모르던 지하 왕국, 행복과 평화로 가득 찬 환상의 세계에 공주가 있었다. 햇빛과 푸른 하늘이 그리웠던 공주는 인간 세계로의 문을 열고 만다. 하지만 너무나 눈부신 햇살에 공주는 기억을 잃은 채로 죽어갔다.  꿈 많은 소녀 오필리아는 만삭인 엄마와 함께 군인인 새아버지의 부대 저택으로 이사를 간다. 하지만 자신을 못마땅해 하는 냉혹한 새아버지에게 두려움을 느끼는 데다, 신비한 숲으로 둘러싸인 저택의 이상한 분위기에 잠을 못 이루던 오필리아에게 요정이 나타난다. 신비로운 모습에 이끌린 오필리아는 요정을 따라 미로로 들어가게 되고 거기서 판이라는 기괴한 요정을 만나는데...', 'https://image.tmdb.org/t/p/w500/dsaQY07ioldk1fpEqm394slWepM.jpg', 2006, 0, 0, '2026-06-06 13:25:22.632986', 'US');
INSERT INTO public.movies VALUES (2642, 375846, 'Bad Sister', '["Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/jKrIlgfJPIWNeowaOZPBZuOPmq0.jpg', 2015, 0, 0, '2026-06-07 12:17:41.957188', 'US');
INSERT INTO public.movies VALUES (8643, 1364, '루시아', '["Drama", "Romance"]', 'Julio Medem', '["Paz Vega", "Tristán Ulloa", "Elena Anaya", "Najwa Nimri", "Daniel Freire"]', '마드리드 도심의 레스토랑 웨이트리스 루시아. 어느 날 6년 동안 동거했던 남자친구 로렌조가 갑자기 떠나버린다. 사랑을 잃은 상실감과 고통에 괴로워하던 루시아는 지중해의 한 외딴 섬으로 여행을 떠난다. 그곳의 신선한 공기와 눈부신 햇살, 빛나는 깊고 푸른 물에 둘러싸여 마음의 위안을 얻게 된 루시아는 로렌조와의 지난 시간을 되돌아본다.  소설가인 로렌조는 6년 전 여름 휴가지에서 만난 낯선 여자와 생애 최고의 섹스를 경험한다. 하지만 서로의 이름도 모른 채 헤어진 두 사람. 그 후 루시아와 사랑에 빠지고 행복한 나날을 보내던 로렌조에게 6년 전의 섹스가 남긴 놀라운 비밀이 밝혀진다. 하지만 위험한 열정은 돌이킬 수 없는 비극을 가져오고, 모든 이들에게 지울 수 없는 상처를 남기는데......', 'https://image.tmdb.org/t/p/w500/k2cSUupLrRKCDSUocPpclspvkSd.jpg', 2001, 0, 0, '2026-06-08 07:26:32.376438', 'FR');
INSERT INTO public.movies VALUES (4186, 481836, '두 엄마', '["Drama", "Romance"]', 'Lee Do-si', '["Baek Se-ri", "Song In-ho", "Lee Yoo-chan", "Park Hyun-jung"]', '절친한 두 친구, 서로의 엄마를 탐하다!INSERT INTO public.movies VALUES (4283, 464026, '가자! 장미여관으로', '["Drama", "Romance"]', 'Jeong-gyun Shin', '["Sung Eun-chae", "Jang Sung-won", "Woo Do-hwan", "Yeo Min-jeong"]', '사귄 지 6개월 된 여자친구 민애와 아직까지 육체적인 관계를 가져본 적 없는 성수는 그녀와의 만남이 늘 흥분된다. 그러던 어느 날, 민애를 설득해 장미여관으로 끌어들이는데 성공한 성수. 샤워를 하기 위해 들어간 욕실에서 작은 구멍을 발견하게 되고 그 구멍을 통해 옆방을 우연히 엿보게 되고, 거기서 남녀의 성행위 장면을 목격하게 된다. 호기심이 발동한 성수는 더욱 숨죽여 그 장면을 엿보던 중 여자 연예인 사라가 거물급 정치인에게 성 상납을 하는 현장임을 알고 충격을 받게 되는데...', 'https://image.tmdb.org/t/p/w500/8ogCczLG6EhQEnSWoqs6092bGm3.jpg', 2013, 0, 0, '2026-06-08 06:29:46.79795', 'KR');
INSERT INTO public.movies VALUES (914, 441900, '双程2', '["Action", "Drama", "Romance", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/iQebv3OwoAlFuCtjnY1PNvnnR06.jpg', 2016, 0, 0, '2026-06-06 13:25:31.184812', 'US');
INSERT INTO public.movies VALUES (917, 1531023, 'Bulong Ng Laman', '["Drama", "Fantasy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/mMakUQEHUJVtKn2RLPdGOYdV8aH.jpg', 2025, 0, 0, '2026-06-06 13:25:31.19277', 'US');
INSERT INTO public.movies VALUES (915, 1151031, '브링 허 백', '["Horror"]', NULL, '[]', '아빠의 죽음 후 새엄마에게 입양된 남매 앤디와 파이퍼. 평화로운 집, 따뜻한 보금자리에서의 안식도 잠시 새엄마는 두 남매 사이를 갈라놓으며 앤디와 파이퍼를 혼란에 빠트린다. 고립된 집, 집 안 곳곳에서 발견되는 정체를 알 수 없는 의식의 흔적들, 새엄마가 숨긴 끔찍한 비밀이 드러나면서 남매를 극한의 공포 상황으로 몰아붙이기 시작하는데… 보지 말아야 할 것을 본 두 사람은 과연 살아남을 수 있을까!', 'https://image.tmdb.org/t/p/w500/A4W0yRN7Xy6JLIhRymIh5plK2Zj.jpg', 2025, 0, 0, '2026-06-06 13:25:31.187425', 'US');
INSERT INTO public.movies VALUES (2629, 1173357, '女魔', '["Horror", "Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/focEYGIMnuNz2Zmmqft4Gd1ROBg.jpg', 1974, 0, 0, '2026-06-07 12:17:41.043018', 'US');
INSERT INTO public.movies VALUES (582, 573435, '나쁜 녀석들: 라이드 오어 다이', '["Action", "Comedy", "Crime"]', NULL, '[]', '마이애미 강력반 최고의 콤비 마이크와 마커스. 가족 같은 하워드 반장이 사망 전 마약 카르텔 조직의 비리에 연루되었다는 뉴스 속보를 접하게 된다. 하지만 아무도 믿지 말라는 하워드 반장의 비밀 메시지를 받은 마이크와 마커스 형사는 사건의 진실을 밝히기 위해 위험한 수사를 시작한다. 서서히 드러나는 거대한 음모와 마주하게 된 나쁜 녀석들. 그러나 이들 역시 함정에 빠져 사건의 용의자로 지목되며 동료 경찰들은 물론 마약 카르텔 조직에게도 쫓기는 신세가 되고 마는데…', 'https://image.tmdb.org/t/p/w500/wIrhEUBWjRmZuL1Ix41cF2LhJrW.jpg', 2024, 0, 0, '2026-06-06 13:25:18.750761', 'US');
INSERT INTO public.movies VALUES (913, 9072, '리틀 맨', '["Comedy", "Crime"]', NULL, '[]', '성인이면서도 아기 같은 몸과 얼굴을 가진 캘빈 심즈. 그러나 그런 순진하고 귀여운 외모와는 달리 그는 얼마전에 출소한 전과자 출신이다. 출소하자마자 그의 파트너 퍼시와 함께 이번에는 갱단 두목으로부터 의뢰를 받아 다이아몬드를 훔쳐 달아나던 도중, 다급한 나머지 지나가던 여자의 핸드백 속에 다이아몬드를 숨긴다. 그녀는 막 부사장으로 승진한 능력있는 여성으로 그녀의 남편 대릴은 아기를 갖고 싶어하지만 그녀는 일 때문에 선뜻 임신을 결심하지 못하고 있는 상태였다. 캘빈과 퍼시는 이 사실을 이용해 자신이 아기로 위장해 그들 부부에게 입양되어 다이아몬드를 되찾을 계획을 세운다.', 'https://image.tmdb.org/t/p/w500/1DxVRdcIeAtihxKSfeHytmgKBtg.jpg', 2006, 0, 0, '2026-06-06 13:25:31.18212', 'US');
INSERT INTO public.movies VALUES (922, 818647, '스루 마이 윈도', '["Romance", "Drama", "Comedy"]', NULL, '[]', '옆집에 사는 남자를 오랫동안 짝사랑해온 라켈. 가족의 반대에도 불구하고 그 남자 역시 라켈에게 마음을 열기 시작하자, 그녀의 감정도 커져간다.', 'https://image.tmdb.org/t/p/w500/3F5MkMadQOWiZNVaNuOuw6UaK7a.jpg', 2022, 0, 0, '2026-06-06 13:25:31.925446', 'US');
INSERT INTO public.movies VALUES (8644, 1044736, 'Je le jure', '["Drama"]', 'Samuel Theis', '["Julien Ernwein", "Marie Pires-Masala", "Marina Foïs", "Louise Bourgoin", "Souleymane Cissé"]', NULL, 'https://image.tmdb.org/t/p/w500/iTtk01mXyupLSzBnkIxbhIyc3nO.jpg', 2025, 0, 0, '2026-06-08 07:26:33.041515', 'FR');
INSERT INTO public.movies VALUES (924, 635302, '극장판 귀멸의 칼날: 무한열차편', '["Animation", "Action", "Fantasy"]', 'Haruo Sotozaki', '["Natsuki Hanae", "Akari Kito", "Hiro Shimono", "Yoshitsugu Matsuoka", "Satoshi Hino"]', '혈귀로 변한 여동생 ‘네즈코’를 되돌리기 위해 귀살대가 된 ‘탄지로’! 어둠 속을 달리는 무한열차에서 승객들이 흔적 없이 사라진다는 소식에 ‘젠이츠’, ‘이노스케’와 함께 임무 수행을 위해 무한열차에 탑승한다. 그리고 그곳에서 만난 귀살대 최강 검사 염주 ‘렌고쿠’! 이들은 무한열차에 숨어 있는 혈귀의 존재를 직감하고 모두를 구하기 위해 목숨을 건 혈전을 시작하는데…', 'https://image.tmdb.org/t/p/w500/8VhwCJ9gqfGor5uk2sqt9ZqeacN.jpg', 2020, 0, 0, '2026-06-06 13:25:31.930501', 'JP');
INSERT INTO public.movies VALUES (926, 18491, '엔드 오브 에반게리온', '["Animation", "Sci-Fi", "Drama", "Fantasy"]', 'Kazuya Tsurumaki', '["Megumi Ogata", "Megumi Hayashibara", "Kotono Mitsuishi", "Yuko Miyamura", "Fumihiko Tachiki"]', '‘카오루’의 죽음 이후 공황 상태에 빠진 ‘신지’. 한편, 네르프 총사령관 ‘겐도’는 ‘서드 임팩트’ 즉, ‘인류보완계획’을 놓고 ‘제레’와 갈등을 벌인다. 이에 ‘제레’는 양산형 에바를 투입해 네르프 본부와 에바 파일럿들을 향해 총공격을 감행하고 맹공에 혼수 상태였던 ‘아스카’까지 완전히 폭주한다. ‘신지’는 ‘미사토’의 도움으로 겨우 초호기에 오르지만, 인류의 운명을 결정해야 하는 상황에 한계에 부딪히게 되는데…', 'https://image.tmdb.org/t/p/w500/rS97sHvlsUAp8F6tkC78YjRU8wl.jpg', 1997, 0, 0, '2026-06-06 13:25:31.935186', 'JP');
INSERT INTO public.movies VALUES (4187, 357458, '젊은 엄마: 내 나이가 어때서', '["Comedy", "Romance"]', 'Kim Jong-il', '["Dong Bang-woo", "Chae Min-seo", "Hong Seo-jun", "An Min-young", "Kim Min-sang"]', '아버지, 아들, 손자까지!  삼대를 사로잡은 29세 존예 섹시맘!  역대  시리즈 사상 최고의 엄마가 나타났다!  아내와 사별하고 동네 약국을 운영하는  말기 암 시한부 아버지, 용태(명계남)  눈치라고는 약에 쓸래도 없는  정리해고 1순위 아들, 성민(홍서준)  밤이면 밤마다 공부보다는 성인영화에 푹 빠져있는  만년 재수생 손자, 영찬(김민상)  한 지붕 세 남자 앞에 역대  시리즈 사상  최고의 엄마가 나타났다!  29세 존예 섹시맘 진희(채민서)의 등장으로  온통 집 안이 양기로 가득 찬 가운데  각자의 사정으로 위기에 몰린 세 남자를 위한  젊은 엄마의 특급 처방이 시작된다.  아버지부터 손자까지! 도대체 누가 엄마랑!', 'https://image.tmdb.org/t/p/w500/kxAMzYivxnEftAEML4FGAIbia0.jpg', 2015, 0, 0, '2026-06-08 06:28:11.103567', 'KR');
INSERT INTO public.movies VALUES (925, 459151, '보스 베이비 2', '["Animation", "Comedy", "Adventure", "Family"]', NULL, '[]', '베이비 주식회사의 레전드 보스 베이비에서 인생 만렙 CEO가 된 `테드`. 베이비인 줄 알았던 조카 `티나`가 알고 보니 베이비 주식회사 소속이라니! 뉴 보스 베이비 `티나`의 지시로 `테드`는 형과 함께 다시 베이비로 돌아가야만 하는데…', 'https://image.tmdb.org/t/p/w500/zGaeo3fNXCcnttUQMgZr1FW0t4V.jpg', 2021, 0, 0, '2026-06-06 13:25:31.932865', 'US');
INSERT INTO public.movies VALUES (753, 37169, '인간 지네', '["Horror"]', NULL, '[]', '아리따운 두 미국 소녀들이 유럽으로 여행을 떠난다. 한밤중에 독일의 어느 숲 속에서 차가 고장 나고, 그들은 외딴 집을 찾아 들어간다. 다음 날 자신을 샴쌍둥이 분리 전문의라고 소개하는 남자가 나타난다. 그러나 그의 목적은 분리가 아니라 합체! 과연 소녀들은 결합되어 인간 지네가 될 것인가?', 'https://image.tmdb.org/t/p/w500/rYNnz5Psi7cfAFGrdulCxV7vgrW.jpg', 2009, 0, 0, '2026-06-06 13:25:24.961582', 'US');
INSERT INTO public.movies VALUES (928, 1501204, '나는 노리개다', '["Drama", "Romance"]', 'Lee Jung-hwan', '["Seung Ha", "Woo Yeol", "Do Hee"]', '스스로 창녀가 된 효민을 이곳을 관리하는 경섭에 의해 손님을 상대하는 섹스 훈련을 받는다.INSERT INTO public.movies VALUES (929, 76493, '독재자', '["Comedy"]', NULL, '[]', '가상 중동 공화국인 와디야의 독재자 알라딘 장군은 미국을 방문하던 중 삼촌의 계략으로 대역과 바꿔치기 되면서 다시 독재자의 위치를 찾기 위해 고군분투하는 이야기', 'https://image.tmdb.org/t/p/w500/e9XpUc370pKV7LsSC2VGMQq6aMo.jpg', 2012, 0, 0, '2026-06-06 13:25:31.942516', 'US');
INSERT INTO public.movies VALUES (931, 676, '진주만', '["Romance", "History", "Action"]', NULL, '[]', '2차 세계대전이 한창 진행되고 있던 1941년, 아직 미국은 전쟁을 방관한 채 평화로운 중립을 견지하고 있다. 래프 맥콜레이는 어려서부터 형제처럼 자란 대니 워커와 미 육군 항공대의 파일럿이 된다.', 'https://image.tmdb.org/t/p/w500/smVaB0pkAywTXQK2wCPsWWt7AgF.jpg', 2001, 0, 0, '2026-06-06 13:25:31.947663', 'US');
INSERT INTO public.movies VALUES (932, 697843, '익스트랙션 2', '["Action", "Thriller", "Crime"]', NULL, '[]', '고도로 숙련된 전직 특수 요원 타일러 레이크. 죽음의 문턱에서 가까스로 살아 돌아온 그가 또다시 위험천만한 작전에 뛰어든다. 임무는 하나. 무자비한 갱스터의 가족을 감옥에서 탈출시켜라.', 'https://image.tmdb.org/t/p/w500/uJGYC2l97RWz8zJ9WFjLiUOqUva.jpg', 2023, 0, 0, '2026-06-06 13:25:31.950071', 'US');
INSERT INTO public.movies VALUES (927, 1791, '피아니스트', '["Drama", "Romance"]', 'Michael Haneke', '["Isabelle Huppert", "Annie Girardot", "Benoît Magimel", "Susanne Lothar", "Udo Samel"]', '유명 음악학교의 피아노 교수 에리카는 잘 생긴 외모와 뛰어난 음악적 재능을 가진 공대생 ''윌터''를 만난다. 첫눈에 반한 그의 적극적인 애정공세에 외롭고 쓸쓸했던 그녀의 일상에 조금씩 변화가 생기기 시작하고, 머뭇거림도 잠시, 에리카는 자신이 꿈꿔왔던 은밀하고도 치명적인 방식의 사랑을 요구하는데...', 'https://image.tmdb.org/t/p/w500/hx0RQpS262xCtc7qgVA3ynJ9Qmk.jpg', 2001, 0, 0, '2026-06-06 13:25:31.937586', 'FR');
INSERT INTO public.movies VALUES (2643, 1101412, '폴 2: 데드포인트', '["Thriller"]', 'Michael Spierig', '["Harriet Slater", "Arsema Thomas", "Tom Brittney", "Einar Haraldsson", "Juju Journey Brener"]', NULL, 'https://image.tmdb.org/t/p/w500/ckKAdEz49bJ10jCLbCYIzVHJGEu.jpg', 2026, 0, 0, '2026-06-07 12:17:41.959802', 'GB');
INSERT INTO public.movies VALUES (941, 152601, '그녀', '["Romance", "Sci-Fi", "Drama"]', NULL, '[]', '테오도르는 다른 사람들의 편지를 대신 써주는 대필 작가로, 깊이 아꼈던 아내와 이혼 소송 중이다. 타인의 마음을 전해주는 일을 하고 있지만, 정작 테오도르 자신은 너무 외롭고 공허한 삶을 살고 있다. 그러던 어느 날, 스스로 생각하고 느끼는 인공 지능 운영체제인 사만다를 만나게 된다. 사만다는 따뜻한 목소리와 뛰어난 전산처리 능력을 통해 테오도르가 더 편안한 삶을 살 수 있도록 돕고, 테오도르는 자신의 육체를 통해 사만다가 더 많은 세계를 경험할 수 있도록 격려한다. 그렇게 둘은 직접적인 접촉보다 밀도 높은 정신적 교감을 나누는데...', 'https://image.tmdb.org/t/p/w500/thUJI82kWMxA2jtjLtPxDIj67tY.jpg', 2013, 0, 0, '2026-06-06 13:25:32.686304', 'US');
INSERT INTO public.movies VALUES (939, 438148, '미니언즈 2', '["Comedy", "Crime", "Sci-Fi", "Animation", "Family"]', NULL, '[]', '세계 최고의 슈퍼 악당을 꿈꾸는 미니보스 ‘그루’와 그를 따라다니는 미니언들. 어느 날 그루는 최고의 악당 조직 ‘빌런6’의 마법 스톤을 훔치는 데 성공하지만 뉴페이스 미니언 ‘오토’의 실수로 스톤을 잃어버리고 빌런6에게 납치까지 당한다. 미니보스를 구하기 위해 잃어버린 스톤을 되찾아야 하는 ‘오토’, 그리고 쿵푸를 마스터해야 하는 ‘케빈’, ‘스튜어트’, ‘밥’! 올 여름 극장가를 점령할 MCU(미니언즈 시네마틱 유니버스)가 돌아온다!', 'https://image.tmdb.org/t/p/w500/b6Q4hqPWxL3IsNfBwta5I8CsClI.jpg', 2022, 0, 0, '2026-06-06 13:25:31.966006', 'US');
INSERT INTO public.movies VALUES (945, 492101, '신 금병매', '["Drama", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/54zOGJOTt0YMqp3cAqBnF6slN39.jpg', 1996, 0, 0, '2026-06-06 13:25:32.696837', 'US');
INSERT INTO public.movies VALUES (940, 84308, '러블리 마드리드', '["Drama"]', NULL, '[]', '저명한 저널리스트 미구엘은 아름답고 수줍음 많은 언론학도 안젤라를 만나 집에서 인터뷰를 하던 중 사고로 욕실 문이 고장나 둘은 욕실에 갇히게 된다.  그렇게 시작된 두 사람의 치열한 설전.  둘은 여러 가지 주제를 놓고 현학적 토론을 벌이며 상대방을 조금씩 알아가고 가까워진다.  매우 좁고 한정된 공간 안에서 펼치는 문학과 언론, 삶, 욕망과 영감 등 사적이면서 특별한 대화가 펼쳐지는데...', 'https://image.tmdb.org/t/p/w500/9rQDTG1bRUUeyWheR47acgqOqXE.jpg', 2012, 0, 0, '2026-06-06 13:25:31.968272', 'US');
INSERT INTO public.movies VALUES (946, 341174, '50가지 그림자: 심연', '["Drama", "Romance"]', NULL, '[]', '크리스찬 그레이는 아나스타샤 스틸을 잊지 못해 되찾으려고 하지만 아나스타샤는 지금까지와 다른 새로운 관계를 원한다. 과거의 상처를 고백하며 점점 변해가는 크리스찬의 모습에 아나스타샤는 결국 그를 받아들이고, 둘은 서로에게 더욱 깊이 빠져들며 뜨거운 사랑을 나눈다. 그러나 그의 숨겨진 과거와 비밀을 아는 사람들이 아나스타샤를 위협하기 시작하면서 그들의 관계는 위태로워지는데...', 'https://image.tmdb.org/t/p/w500/stwVY9rRcA3NSKW04IOD30ZsrZx.jpg', 2017, 0, 0, '2026-06-06 13:25:32.699116', 'US');
INSERT INTO public.movies VALUES (622, 546554, '나이브스 아웃', '["Comedy", "Crime", "Mystery"]', NULL, '[]', '미스터리 소설의 대가인 작가 할란이 자신의 85살 생일에 자신의 방에서 날카로운 단검으로 목이 그인 채 발견된다. 외딴 저택에 모인 할란의 간병인과 자식 내외, 그리고 3세들은 유산 상속을 놓고 대거 혼란에 빠진다. 파견된 형사들은 가족과의 면담을 할 수록 자살로 의견이 모이지만, 면담 중 멀찍이 떨어져 상황을 전망하는 푸른 눈의 사내는 형사들마저 압도하며 심문을 주도해나간다. 남자의 이름은 바로 브누아 블랑. 챔피언 사건을 해결해서 이름이 높아진 유명한 사립탐정이다.', 'https://image.tmdb.org/t/p/w500/7brBiaaH1sToGV1YBi5EIUnyjo0.jpg', 2019, 0, 0, '2026-06-06 13:25:20.313308', 'US');
INSERT INTO public.movies VALUES (942, 299054, '익스펜더블 4', '["Action", "Adventure", "Thriller"]', NULL, '[]', '테러 단체에게 핵미사일이 탈취되어 3차 세계대전이 발발할 위기의 상황에 ‘리’(제이슨 스타뎀)를 새로운 리더로 맞은 무적의 팀 익스펜더블이 작전에 투입되는데...', 'https://image.tmdb.org/t/p/w500/dWR8OTRCcYDbBmd8GKsyJT73kU2.jpg', 2023, 0, 0, '2026-06-06 13:25:32.689436', 'US');
INSERT INTO public.movies VALUES (944, 331586, '부니베어: 나무 도둑의 습격', '["Comedy", "Animation"]', NULL, '[]', '“가만두지 않겠어!”  갑자기 나타나 평화로운 숲을 망가뜨리는 악당 로봇!  갑자기 해고를 당해 하루아침에 일자리를 잃고 만밉상 나무꾼 로거빅.  고향에 계신 부모님 선물을 사기 위해 숲 속 나무들 함부로 베어가지 못하게 지키는 삼림감시원으로 새롭게 일하게 된다. 사이좋은곰 형제 브라이어와 브램블, 귀여운 원숭이 콤비 티키와 바부, 부지런한 땅다람쥐 워렌과 허버트, 똘똘이 부엉이 후후와 즐거운 하루하루를 보내던 중 갑자기 무자비하게 나무를 베어내는 악당 로봇이 나타나고, 곰돌이 형제와 숲 속 친구들은 이에 맞서려 하지만 엄청난 위력에 속수무책이다. 점점 숲 속 나무들은 악당 로봇에 의해 사라지고 위험을 알게 된 로거빅은 친구들과 함께 악당 로봇을 물리치기 위해 힘을 합치는데…  과연 이들은 악당 로봇을 물리치고 숲 속 나무들을 위험에서 지킬 수 있을까?', 'https://image.tmdb.org/t/p/w500/jfPj4OejC5swmuRmrUm7cxRCfZx.jpg', 2014, 0, 0, '2026-06-06 13:25:32.694514', 'US');
INSERT INTO public.movies VALUES (937, 592695, '플레저', '["Drama"]', NULL, '[]', '벨라 체리는 포르노 영화 배우의 꿈을 안고 로스앤젤레스에 도착하지만,  그녀는 그녀의 야망과 교활함을 활용하여 이 매혹적이고 독특한 세계의  정상에 오르기 위해 노력하지만 그런 명성이 쉽게 오지 않는다는 것을 곧 알게 된다.', 'https://image.tmdb.org/t/p/w500/t3SEI2YI81oO3nEgjJ9jMAIKApY.jpg', 2021, 0, 0, '2026-06-06 13:25:31.961424', 'US');
INSERT INTO public.movies VALUES (4189, 1268609, '파반느', '["Romance", "Drama"]', 'Lee Jong-pil', '["Ko A-sung", "Moon Sang-min", "Byun Yo-han", "Lee E-dam", "Han Yu-eun"]', '백화점에서 일하는 세 사람. 서로에게 그저 낯선 타인이었던 외로운 이들. 점차 서로에게 빛이 되어주며 삶의 의미와 사랑의 본질을 알아나간다.', 'https://image.tmdb.org/t/p/w500/22RlxpIT4u4psfIx9tmtbPvgAbm.jpg', 2026, 0, 0, '2026-06-08 06:28:12.446333', 'KR');
INSERT INTO public.movies VALUES (943, 1601243, 'Oscar Shaw', '["Action", "Crime", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/tsE3nySukwrfUjouz8vzvKTcXNC.jpg', 2026, 0, 0, '2026-06-06 13:25:32.691969', 'US');
INSERT INTO public.movies VALUES (4188, 961268, '발레리나', '["Action", "Thriller"]', 'Lee Chung-hyun', '["Jeon Jong-seo", "Kim Ji-hoon", "Park Yu-rim", "Shin Se-hwi", "Park Hyoung-soo"]', '소중한 친구의 죽음을 발견한 전직 경호원. 친구가 남긴 마지막 소원을 들어주기 위해 아름다운 복수에 나선다.', 'https://image.tmdb.org/t/p/w500/gyHrSGGud3ToeGJ3XHbVXtZmR4X.jpg', 2023, 0, 0, '2026-06-08 06:28:11.774786', 'KR');
INSERT INTO public.movies VALUES (8662, 184314, '영 앤 뷰티풀', '["Drama"]', 'François Ozon', '["Marine Vacth", "Géraldine Pailhas", "Charlotte Rampling", "Frédéric Pierrot", "Nathalie Richard"]', '여름 남프랑스 휴가지, 17세 생일을 앞둔 이사벨은 그곳에서 만난 독일인 청년과 첫경험을 치른다. 가을, 파리로 돌아온 이사벨은 레아라는 이름으로 학교와 호텔을 오가며 낯선 남자들과의 매춘에 빠져 있다. 겨울, 이사벨의 은밀한 이중생활에도 위기가 찾아온다. 경찰이 들이닥치고 엄마 실비에는 모든 것을 알게 되는데… 그리고 봄, 이사벨은 아무 일도 없었던 것처럼 평범한 10대 소녀의 생활로 돌아갈 수 있을까.', 'https://image.tmdb.org/t/p/w500/ehusiPCJxkI1riWgAdudv0qwKD4.jpg', 2013, 0, 0, '2026-06-08 07:26:46.165524', 'FR');
INSERT INTO public.movies VALUES (4191, 698438, '스와핑: 완벽한 이웃', '["Romance"]', 'Kim Bu-gon', '["Yoo Jung", "Lee Eun-mi", "Hae Il", "Jo Wan-jin"]', '진구와 주희 부부는 결혼 후 어느덧 권태기가 찾아와 부부관계가 소원하기만 하다. 그러던 중 이웃에 새로 이사 온 젊은 부부 현진과 유정 부부가 집에 인사를 온다. 각각 이웃집 아내와 남편에게 끌리고, 결국, 이웃집과 넘어서는 안될 선을 넘는다. 그날 이후, 두 부부의 금술은 더 좋아지는데…', 'https://image.tmdb.org/t/p/w500/3ArCpGHdnVqBjhkdRcQHSBYH1yA.jpg', 2019, 0, 0, '2026-06-08 06:28:13.990624', 'KR');
INSERT INTO public.movies VALUES (2672, 935508, '女教師仕置人 地獄の女神', '["Action"]', 'Yasuo Uchida', '["Reiko Kato", "Naoko Aizawa", "Mieko Arai", "Mayo Kawasaki"]', NULL, 'https://image.tmdb.org/t/p/w500/uTR9osRcA5hKALePWTsyhZdNt56.jpg', 1990, 0, 0, '2026-06-07 12:17:42.828407', 'JP');
INSERT INTO public.movies VALUES (952, 1948, '아드레날린 24', '["Action", "Thriller", "Crime"]', NULL, '[]', '내 이름은 체브 첼리오스, 오늘은 내가 죽는 날!내 이름은 체브 첼리오스, 서부 갱단을 위해 일하는 프리랜서 킬러다. 둔탁한 통증에 깨어나보니 ‘fuck you’ 라고 쓰인 CD한 장이 TV앞에 놓여있었다. CD속에는 기절해 잠든 나에게 망할 ‘베로나’가 이상한 약물을 주사하고 있다!!! 게다가 이제 1시간 후면 심장이 멎는다는 헛소리를 지껄인다!! Game to Death. 주어진 미션은 단 하나!멈춰가는 심장을 뛰게 하라!그런데… 눈앞이 어질 거리고 걸을 수가 없다. 정말로 심장이 멎어가고 있다! 이제 청부 살인 일도 그만두고 귀여운 이브와의 행복한 날들만을 기다리고 있었는데…이런 거지 같은 게임, 내가 끝내주지… 이렇게 죽을 순 없어!! 나는 살아 있다!!그리고 해야 할 일은 베로나의 심장에 총알을 박는 것뿐!', 'https://image.tmdb.org/t/p/w500/wxd32fkKdnF34uyw63odsdd2ZVU.jpg', 2006, 0, 0, '2026-06-06 13:25:32.713985', 'US');
INSERT INTO public.movies VALUES (8690, 9280, '팜므 파탈', '["Mystery", "Crime", "Thriller"]', 'Brian De Palma', '["Rebecca Romijn", "Antonio Banderas", "Peter Coyote", "Ériq Ebouaney", "Édouard Montoute"]', '미모의 보석 전문 털이범 ''로라''는 칸느영화제에 수천만 달러의 보석을 몸에 걸친 모델이 참석할 것이라는 정보를 입수, 현장에 잠입한다. ''로라''는 삼엄한 경비를 뚫고, 엄청난 양의 다이아몬드를 훔치는데 성공하지만 동료들을 따돌린 뒤 혼자 파리로 도망친다. 파리에서 미국으로 밀입국을 시도하기 위해 위조 여권단과 거래를 시도하던 ''로라''는 낯선 사람들의 추격을 받게 되고, 놀라울 정도로 자신과 똑같은 외모를 지닌 ''릴리''라는 여자의 집으로 우연히 숨어 든다. 그러나 ''로라''는 바로 눈앞에서 ''릴리''의 자살을 목격하고, 어두운 과거로부터 벗어나고 싶었던 ''로라''는 완벽한 ''릴리'' 행세를 하며 미국행 비행기에 몸을 싣는다.', 'https://image.tmdb.org/t/p/w500/9yu9kOYt88tVXSpHqk4QubybvXn.jpg', 2002, 0, 0, '2026-06-08 07:27:05.593092', 'FR');
INSERT INTO public.movies VALUES (850, 17073, '아메리카 70 섹스 천국', '["Documentary"]', 'Jon Hart', '["Buck Henry", "Melvin Van Peebles", "Ed Koch", "Jamie Gillis", "Ron Jeremy"]', '모두가 자유롭고 즐거운 삶을 갈망하던 1970년대. 이 시기 뉴욕에는''Studio 54'', ''CBGB'', ''Plato''s Retreat''등 화려하고 젊음이 넘치는 클럽들이 각광받았다. 자유로운 공공 섹스로 국제적인 센세이션을 일으켰던 뉴욕의 실존 클럽,''Plato''s Retreat''의 연대기를 다룬 다큐멘터리.', 'https://image.tmdb.org/t/p/w500/d4rfQ9lEq0G1yNUOjHEofXlfk0Z.jpg', 2009, 0, 0, '2026-06-06 13:25:28.859991', 'US');
INSERT INTO public.movies VALUES (779, 1422, '디파티드', '["Drama", "Thriller", "Crime"]', NULL, '[]', '프랭크 코스텔로가 이끄는 남부 보스턴의 최대 범죄 조직망, 아일랜드 마피아를 일망타진하기 위해 매사추세츠 주 경찰청은 신참 경찰 빌리 코스티건을 조직에 침투시킨다. 한편, 또다른 신참 경찰 콜린 설리반은 경찰청 내에서 승승장구하여 코스텔로를 제거하기 위한 특별 수사반에 배치된다. 그러나 콜린은 경찰청에 투입된 코스텔로의 첩자였다. 그들은 곧 그들 사이에 첩자가 있다는 사실을 알아차리게 되는데...', 'https://image.tmdb.org/t/p/w500/j7REKrvSiC2GSsvXfxyAvXQVj7q.jpg', 2006, 0, 0, '2026-06-06 13:25:25.760161', 'US');
INSERT INTO public.movies VALUES (692, 41630, '친구와 연인사이', '["Comedy", "Romance"]', NULL, '[]', '생물학적으로 일부일처제는 있을 수 없다고 믿는 엠마, 아버지에게 전 여친을 빼앗긴 후 사랑을 믿지 않는 아담. 서로에 대해 너무나 잘 아는 이들의 오랜 우정 사이에 어느 날 보너스(?)가 붙기 시작했다. 바로 ‘섹스’ 라는 특별 보너스가! 한 번의 섹스가 그들의 관계를 180도 바꿔 놓았다! 하지만 친구에서 결코 연인이 되고 싶지는 않았던 두 사람은 서로가 원한다면 언제 어디서든 뜨거운 섹스가 가능한 둘만의 은밀하고 아찔한 “조건 없이 즐기기” 규칙을 정하기에 이르는데… 과연 이 둘은 섹스만 즐기면서 사랑이란 걸림돌을 피해 갈 수 있을까? 이들의 오랜 우정은 지켜질 수 있을까?', 'https://image.tmdb.org/t/p/w500/yxyxPMIyx1swMuJ5T68kEf51KcC.jpg', 2011, 0, 0, '2026-06-06 13:25:22.637334', 'US');
INSERT INTO public.movies VALUES (951, 74997, '인간 지네 2', '["Drama", "Horror", "Crime"]', NULL, '[]', '영화에 푹 빠져 영화처럼 실제로 인간지네를 만들고픈 욕망에 푹 빠져 있는 마틴. 주차관리원으로 일하는 그 는 사람들을 납치하기 시작하여 그의 욕망을 이루려고 한다. 2010년 PiFan을 찾았던 의 속편으로 이번에는 3명이 아닌 10명이 거대한 지네로 둔갑한다. 입과 항문을 잇는 또 다른 기술(!)이 궁금하시다면 놓치지 말 것.', 'https://image.tmdb.org/t/p/w500/2BgPsTCXqsiBmFonQRMAvNqBqzb.jpg', 2011, 0, 0, '2026-06-06 13:25:32.71172', 'US');
INSERT INTO public.movies VALUES (961, 268, '배트맨', '["Fantasy", "Action", "Crime"]', NULL, '[]', '범죄와 부패, 탐욕의 도시 고담에 정체불명의 배트맨이 나타나 공포와 위협으로부터 시민들을 구한다. 모든 시민들은 배트맨의 활약상을 보면서 그에 대한 궁금증을 더해간다. 고담시의 모두가 배트맨에 대해 궁금해 하고 있을때 전쟁터에서 활약한 경험까지 있는 유능한 사진기자 비키 베일(킴 베이싱어)은 동료 기자와 함께 배트맨을 취재한다. 그러나 비키 앞에는 매력적인 의문의 백만장자 브루스 웨인(마이클 키튼)이 등장한다. 매력적이고 의문투성이인 이 젊은 부호는 점점 비키와 가까워지고 배트맨으로 인해 모습이 변해버린 악당 조커는 배트맨에게 복수를 다짐한다.', 'https://image.tmdb.org/t/p/w500/9SZjh4c1Th7MjBWc8T4x4gdF4yT.jpg', 1989, 0, 0, '2026-06-06 13:25:33.458549', 'US');
INSERT INTO public.movies VALUES (962, 1242011, '투게더', '["Horror", "Romance"]', NULL, '[]', '관계의 한계에 부딪힌 오래된 커플 팀과 밀리. 어느 날 서로의 몸이 점점 붙어버리기 시작하는데…', 'https://image.tmdb.org/t/p/w500/ivWOD2MiC1HywIPBF2Ei2CN3ywY.jpg', 2025, 0, 0, '2026-06-06 13:25:33.46997', 'US');
INSERT INTO public.movies VALUES (960, 8681, '테이큰', '["Action", "Thriller"]', 'Pierre Morel', '["Liam Neeson", "Maggie Grace", "Famke Janssen", "Olivier Rabourdin", "Leland Orser"]', '파리로 여행을 떠난 딸 킴(매기 그레이스)이 아버지 브라이언(리암 니슨)과 통화를 하던 중 납치 당한다. 딸을 찾아 파리에 도착한 브라이언은 킴의 부서진 휴대전화에서 피터의 사진을 발견하고 그를 미행하지만, 결정적인 단서를 얻으려던 순간 피터는 죽고 만다. 마약에 중독된 여성들이 가득한 곳에서 킴이 입고 있던 재킷을 가진 여자를 발견한 브라이언은 그녀를 통해 실마리를 추적한다. 킴이 납치당하던 순간 휴대전화를 향해 소리쳤던 외모를 그대로 지닌 남자를 발견한 브라이언. 마침내 결정적 단서를 얻게 되고, 일생일대의 사투를 시작하는데...', 'https://image.tmdb.org/t/p/w500/wUBC2bs4SxGgomacSR32qRm0SPh.jpg', 2008, 0, 0, '2026-06-06 13:25:32.733324', 'FR');
INSERT INTO public.movies VALUES (958, 343611, '잭 리처: 네버 고 백', '["Action", "Thriller", "Drama", "Crime"]', NULL, '[]', '군사 스파이 혐의로 자신의 후임인 수잔 터너 소령이 체포되자  잭 리처만이 그녀의 무죄를 확신하고 탈출을 돕는다. 사건의 진실을 파헤치던 중 관련된 사람들이 잇따라 살해 당하기 시작하고  잭 리처는 이 모든 사건의 배후에 누군가가 존재한다는 것을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/jIhdOizM2SOiNzOU6jgiC9t3Qjc.jpg', 2016, 0, 0, '2026-06-06 13:25:32.728468', 'US');
INSERT INTO public.movies VALUES (705, 613504, '애프터: 그 후', '["Drama", "Romance"]', NULL, '[]', '"너만의 테사는 더 이상 없어!"  첫사랑 하딘이 자신과의 연애를 내기에 걸었다는 비밀을 알게 된 ''테사''  둘은 헤어지지만 서로의 살결과 숨결을 끊지 못하며 아슬아슬한 썸을 이어간다. 이후 대학 졸업을 앞둔 취준생 테사는 대형 출판사의 인턴십에 합격하고  거친 하딘과는 180도 다른 젠틀한 직장 남사친 ''트레버''를 만나게 된다. "테사의 두 번째 남자를 만났다" 런던으로 떠나기 전에 테사를 향한 진심을 전하고 싶었던 ''하딘'' 테사의 용서를 기다리며 과거의 잘못을 하나씩 고쳐나간다.  워크숍 파티에서 취한 테사의 연락에 하딘은 기대 반, 걱정 반 마음으로 결국 테사의 호텔 룸에 찾아가고, 샤워실에서 그녀석 ''트레버''와 마주치는데…', 'https://image.tmdb.org/t/p/w500/d45gDeSa3eDpYo2Aj6AJ7SeHx0t.jpg', 2020, 0, 0, '2026-06-06 13:25:23.391201', 'US');
INSERT INTO public.movies VALUES (2990, 509967, '6 언더그라운드', '["Action", "Comedy", "Thriller"]', NULL, '[]', '죽음을 위장하고 사라진 억만장자. 그가 전 세계에서 최정예 요원들을 선발한다. 존재하지 않았던 것처럼 개인의 모든 기록을 지우고 스스로 ‘고스트’가 된 여섯 명의 정예요원이 펼치는 지상 최대의 작전을 담은 액션 블록버스터. 잔인한 독재자의 피로 세상을 물들여라!', 'https://image.tmdb.org/t/p/w500/hroNIUa8KdThEzSb9Vgzku8enXt.jpg', 2019, 0, 0, '2026-06-07 12:17:57.122394', 'US');
INSERT INTO public.movies VALUES (8698, 8069, '바바렐라', '["Sci-Fi", "Adventure", "Comedy"]', 'Roger Vadim', '["Jane Fonda", "John Phillip Law", "Anita Pallenberg", "Marcel Marceau", "Claude Dauphin"]', '41세기 우주 어느 곳, 우리의 주인공 바바렐라는 지구 대통령의 명령을 받고 실종된 젊은 과학자 듀란 듀란을 찾아나선다. 바바렐라는 눈먼 천사 파이가와 한 패가 되어 그를 찾아 독재자 블랙 퀸의 영토로 숨어 들어간다. 그러다가 듀란듀란의 정체와 음모가 밝혀지고 그로부터 이 우주를 구할 사람은 단 하나...', 'https://image.tmdb.org/t/p/w500/facTz5BZz4AkJal1FWgjYciekih.jpg', 1968, 0, 0, '2026-06-08 07:28:21.359734', 'FR');
INSERT INTO public.movies VALUES (963, 1892, '스타워즈 에피소드 6: 제다이의 귀환', '["Adventure", "Action", "Sci-Fi"]', NULL, '[]', '전작으로부터 약 1년 후의 이야기로, 전편의 클라이막스에서 엄청난 과거사를 접한 후 몸과 마음을 추스린 루크 스카이워커가 어엿한 제다이 기사로 성장해 동료들과 함께 결국 사악한 은하 제국을 무너뜨린다는 내용. 제국의 역습 때보다 배는 더 되는 금액[8]을 특수효과에 투입했으며, 흥행도 전작들(제국의 역습은 5억 3천만 달러, 새로운 희망은 재개봉까지 합쳐 7억 7천만 달러) 못잖게 엄청난 대박(전세계 5억 7천만 달러)을 쳤다. 한동안 최대 흥행 영화로 기네스북에 실렸으며 이는 타이타닉이 나올 때까지 깨지지 않았다.', 'https://image.tmdb.org/t/p/w500/qUA5lGAXzgr9UDKvUreiLOGa9fM.jpg', 1983, 0, 0, '2026-06-06 13:25:33.472466', 'US');
INSERT INTO public.movies VALUES (972, 1688652, '게리', '["Drama", "Comedy"]', NULL, '[]', '출장을 떠난 두 친구. 업무를 수행하며 예상치 못한 난관에 부딪힌다. 문제를 해결하고 주민들과 교감하는 과정에서 이 경험은 두 사람에게 깊은 인상을 남기고, 우정에 대한 새로운 관점을 선사한다.', 'https://image.tmdb.org/t/p/w500/wqT9w11asFWmp8FNGOeKyatomyk.jpg', 2026, 0, 0, '2026-06-06 13:25:33.494352', 'US');
INSERT INTO public.movies VALUES (4193, 340819, '연애의 맛', '["Drama", "Comedy", "Romance"]', 'Aaron Kim', '["Kang Ye-won", "Oh Ji-ho", "Ha Joo-hee", "Oh Min-suk", "Choi Seung-yoon"]', '겉으론 멀쩡한 외모와 스펙의 뇌섹남!  그러나, 여자 속만 알고 정작 여자 맘은 모르는 산부인과 전문의 왕성기(오지호).  거침없는 성격으로 여성 불모지인 금녀의 벽에 도전!  그러나, 남성의 은밀한 그 곳을 진단하면서도 연애 경험은 전무한 비뇨기과 전문의 길신설(강예원).  낮에는 성 전문가  밤에는 연애 초보자  한 지붕 아래 만난 두 닥터!  환자 쟁탈을 위한 제로섬 게임이 시작된다!', 'https://image.tmdb.org/t/p/w500/kK9ZfwRCX8mCvOtGL4Oal3Bkoy8.jpg', 2015, 0, 0, '2026-06-08 06:28:16.359042', 'KR');
INSERT INTO public.movies VALUES (967, 1317448, '싱글을 위한 나라는 없다', '["Romance", "Comedy"]', NULL, '[]', '펠리차 킹슬리의 베스트셀러 소설을 원작으로 한 영화. 사랑이 무엇보다 중요한 가치로 여겨지는 토스카나 지방의 아름다운 마을, 벨베데레에서 강인하고 독립심이 강한 싱글맘 엘리사가 살아간다. 엘리사는 이제껏 혼자 힘으로 일궈온 삶과 잊어버리려고 애썼던 감정을 일깨우는 한 남자, 미켈레 사이에서 선택의 갈림길에 서게 된다.INSERT INTO public.movies VALUES (968, 1071585, '메간 2.0', '["Action", "Sci-Fi", "Thriller"]', NULL, '[]', '강제 종료 후 다시 돌아온 돌AI ‘메간’. 쌍돌AI ‘아멜리아’의 위협으로 ‘메간’의 유일한 친구 ‘케이디’ 목숨이 위태로워지자 ‘젬마’의 기술로 완전히 새롭게 진화한 메간이 다시 태어난다.', 'https://image.tmdb.org/t/p/w500/5dDIFCUsDD5rFvBmT8Hl3bwXAm0.jpg', 2025, 0, 0, '2026-06-06 13:25:33.485331', 'US');
INSERT INTO public.movies VALUES (969, 1442975, 'భర్త మహాశయులకు విజ్ఞప్తి', '["Family", "Drama", "Comedy"]', 'Kishore Tirumala', '["Ravi Teja", "Ashika Ranganath", "Dimple Hayathi", "Sunil Varma", "Satya"]', NULL, 'https://image.tmdb.org/t/p/w500/3QoTnvsbIAAWVXpfHzQKeEQhUi7.jpg', 2026, 0, 0, '2026-06-06 13:25:33.487591', 'IN');
INSERT INTO public.movies VALUES (973, 646385, '스크림', '["Horror", "Mystery"]', NULL, '[]', '잔혹한 살인 사건으로 우즈보로 마을이 충격에 휩싸인 지 25년이 지난 후,  고스트 페이스를 한 새로운 살인마가 다시 십대들을 노리면서 마을의 어두운 비밀이 다시 수면 위로 떠오르는데…', 'https://image.tmdb.org/t/p/w500/tk5i99DjBAYTxbdBGAPIBkP6wID.jpg', 2022, 0, 0, '2026-06-06 13:25:33.49661', 'US');
INSERT INTO public.movies VALUES (971, 1284120, '어글리 시스터', '["Horror", "Comedy", "Drama"]', NULL, '[]', '아름다움이 곧 권력이 되는 잔혹한 경쟁의 왕국. 언제나 외모로 조롱받던 ‘엘비라’는 ‘왕자’와의 달콤한 사랑을 꿈꾼다.  그러던 어느 날, 그녀에게 찾아온 단 한 번의 기회— 의붓언니인 ‘아그네스’와 함께 왕자가 개최하는 무도회에 초대된다. 그녀는 왕자의 마음을 사로잡기 위해 아름다움에 집착하며, 그 어떤 고통도 마다하지 않는다.  아름다움을 향한 그 갈망의 끝에 끔찍한 대가가 따른다는 사실을 모른 채…', 'https://image.tmdb.org/t/p/w500/eptIaZpqiBnmGeoHzN5fqiX0W5H.jpg', 2025, 0, 0, '2026-06-06 13:25:33.492133', 'US');
INSERT INTO public.movies VALUES (974, 76338, '토르: 다크 월드', '["Action", "Adventure", "Fantasy"]', NULL, '[]', '어벤져스의 뉴욕 사건 후, 다시 신들의 고향인 아스가르드 왕국으로 돌아간 토르와 로키. 지구를 위협한 로키는 지하 감옥에 갇히고, 토르는 아버지 오딘과 함께 우주의 질서를 재정립하기 위해 나선다. 1년 후, 지구에 혼자 남은 제인은 우연히 태초부터 존재해왔던 어둠의 종족 다크 엘프의 무기 에테르를 얻게 된다. 이 사실을 안 다크엘프의 리더 말레키스는 에테르를 되찾기 위해 제인과 아스가르드를 공격하고, 토르는 사랑하는 여인 제인과 아스가르드 왕국을 지키기 위해 로키에게 위험한 동맹을 제안하게 된다.', 'https://image.tmdb.org/t/p/w500/tcJSE6OVDGE8LOqOWmBnvfEyidy.jpg', 2013, 0, 0, '2026-06-06 13:25:33.498846', 'US');
INSERT INTO public.movies VALUES (2993, 5503, '도망자', '["Action", "Thriller", "Drama"]', NULL, '[]', '리차드는 저명한 의사로 아내와 시카고 근교의 고급 주택가에서 살고 있다. 어느 날 괴한이 집에 들어와 아내 헬렌을 살해하고 리차드와 사투를 벌이다 도망친다. 경찰은 리차드를 살인범으로 지목하고 그의 주장을 묵살한 채 사형선고를 내린다. 리차드는 교도소로 향하던 중 탈출하여 진범을 추적하기 시작하고, 형사 샘은 리차드를 추적하는데...', 'https://image.tmdb.org/t/p/w500/hTe0eJaiUjBDNYZim3OZUkSvCXe.jpg', 1993, 0, 0, '2026-06-07 12:17:57.129735', 'US');
INSERT INTO public.movies VALUES (979, 335797, '씽', '["Animation", "Comedy", "Family"]', NULL, '[]', '한때 잘나갔던 문(Moon) 극장의 주인 코알라 ‘버스터 문’(매튜 맥커너히)은 극장을 되살리기 위해 대국민 오디션을 개최한다. 하지만 한 순간의 실수로 우승 상금이 1,000달러에서 10만 달러로 바뀌게 되고 이로 인해 전국 각지에서 동물들이 몰려와 오디션에 참가하게 된다.  25남매를 둔 슈퍼맘 돼지 ‘로지타’(리즈 위더스푼), 남자친구와 록스타의 꿈을 키우는 고슴도치 ‘애쉬’(스칼렛 요한슨), 범죄자 아버지를 둔 고릴라 ‘조니’(태런 에저튼), 무대가 두렵기만 한 코끼리 소녀 ‘미나’(토리 켈리), 그리고 오직 상금이 목적인 생쥐 ‘마이크’(세스 맥팔레인)까지!  꿈을 펼치기 위해 한 자리에 모인 이들은 자신들의 무대를 시작하는데…', 'https://image.tmdb.org/t/p/w500/kKDXw5uRCioD522P1skH49YLNAH.jpg', 2016, 0, 0, '2026-06-06 13:25:33.510405', 'US');
INSERT INTO public.movies VALUES (977, 408, '백설공주와 일곱 난쟁이', '["Fantasy", "Animation", "Family"]', NULL, '[]', '아주 먼 옛날, 왕비는 뱃속의 아이가 눈처럼 하얀 피부에 사과처럼 붉은 입술, 장미빛 뺨을 지닌 공주이기를 빌었다. 드디어 왕비는 예쁜 공주를 낳고 그녀를 백설공주라 불렀다. 백설공주는 모든 사람들의 사랑을 받으며 자라났지만 왕비가 죽고 새로 들어온 계모가 여왕이 되자 혹독한 시달림을 받는다. 계모에게는 신비로운 마술 거울이 있었는데, 어느 날 여왕이 세상에서 가장 아름다운 사람은 누구냐고 질문하자 마술 거울은 백설공주라고 대답한다. 분노한 여왕은 사냥꾼을 불러 백설공주를 죽이도록 명령하지만, 사냥꾼은 백설공주의 순수한 마음씨에 감동하여 그녀를 죽이는 대신 계모를 피해서 도망치도록 일러주는데...', 'https://image.tmdb.org/t/p/w500/xTEtTPgVwuOt7lnKVBJKZahmKdK.jpg', 1938, 0, 0, '2026-06-06 13:25:33.50577', 'US');
INSERT INTO public.movies VALUES (978, 845781, '레드 원', '["Action", "Comedy", "Fantasy"]', NULL, '[]', '크리스마스 D-1, 철통같은 보안을 뚫고 코드명 ''레드 원'' 산타클로스가 납치되고 크리스마스가 사라질 위기에 처했다! ''레드 원''을 찾기 위해 사령관 ''칼럼 드리프트''는 산타클로스 따위는 없다고 믿는 현상금 사냥꾼 ''잭 오말리''와 협력하기로 한다. 시작부터 삐그덕 거리는 이들 앞에 크리스마스의 존재를 위협하는 위험천만한 적들이 나타나는데…', 'https://image.tmdb.org/t/p/w500/4zNUNhVpSqFggxqvdSXDRzy1QwE.jpg', 2024, 0, 0, '2026-06-06 13:25:33.508116', 'US');
INSERT INTO public.movies VALUES (976, 620249, '나소흑전기: 첫만남편', '["Animation", "Fantasy", "Action"]', NULL, '[]', '요정과 인간이 공존하는 환상적인 세계가 열린다! 숲속의 집을 잃고 홀로 떠돌던 검은 고양이 요정 ‘소흑’은 도시 뒷골목에서 미스터리한 능력의 요정 ‘풍식’을 만나 위기를 모면한다. ‘풍식’의 무리와 버려진 섬에서 행복한 시간을 보내는 ‘소흑’. 그러던 중 최강 능력의 집행자 ‘무한’이 ‘풍식’을 쫓아 섬에 오자 ‘풍식’ 일행은 달아나고, ‘소흑’만 남게 된다. 홀로 남은 ‘소흑’을 요정들의 회관으로 데려가려는 ‘무한’과 ‘무한’을 무서운 인간이라 여겨 도망치려는 ‘소흑’. 둘은 여정 속에서 점점 마음을 열게 되고, ‘무한’은 ‘소흑’에게 특별한 능력이 있음을 알게 된다. 한편, 요정들이 공격받는 의문의 사건이 곳곳에서 일어나고, 엄청난 능력을 지닌 존재들이 ‘소흑’과 ‘무한’의 앞을 막아서는데... 함께하면 두려울 것 없는 우리들의 이야기는 지금부터!', 'https://image.tmdb.org/t/p/w500/4VhlO8O5COmkz3XBwrbfnunTnzK.jpg', 2019, 0, 0, '2026-06-06 13:25:33.503392', 'US');
INSERT INTO public.movies VALUES (980, 399402, '헌터 킬러', '["Action", "Thriller"]', NULL, '[]', '미 국방부는 격침당한 잠수함의 행방을 찾기 위해 ‘헌터 킬러’를 극비리에 투입시키고 캡틴 ‘글래스’ 는 배후에 숨겨진 음모가 있음을 알게 된다. 한편, 지상에서는 VIP가 납치되어 전세계는 초긴장 상태에 놓이게 되는데… 일촉즉발 위기상황, VIP를 구출하라! 단 한 척의 공격 잠수함 ‘헌터 킬러’와 최정예 특수부대 네이비 씰의 숨막히는 육해공 합동 작전이 펼쳐진다!', 'https://image.tmdb.org/t/p/w500/7BPBXYV2vINB8xcIc5TentaNfzs.jpg', 2018, 0, 0, '2026-06-06 13:25:33.513385', 'US');
INSERT INTO public.movies VALUES (981, 2048, '아이, 로봇', '["Action", "Sci-Fi"]', NULL, '[]', '2035년, 인간은 지능을 갖춘 로봇에게 생활의 모든 편의를 제공받으며 편리하게 살아가게 된다. 인간의 안전을 최우선으로 하는 로봇 3원칙이 내장된 로봇은 인간을 위해 요리하고 아이들을 돌보며 없어서는 안될 신뢰 받는 동반자로 여겨진다. NS-4에 이어 더 높은 지능을 가진 로봇 NS-5의 출시를 하루 앞둔 어느 날, NS-5의 창시자인 래닝 박사가 의문의 죽음을 맞이한다. 그의 죽음을 둘러싼 수많은 추측이 난무한 가운데, 시카고 경찰 델 스프너는 자살이 아니라는데 확신을 갖고 조사에 착수한다. 끔찍한 사고 이후 로봇에 대한 적대감을 갖고 있던 그는 이 사건 역시 로봇과 관련이 있다고 믿고 숨은 음모를 파헤치는데...', 'https://image.tmdb.org/t/p/w500/1Nj0pcza7LuMrx3igjW5Go3zUji.jpg', 2004, 0, 0, '2026-06-06 13:25:34.230261', 'US');
INSERT INTO public.movies VALUES (982, 399579, '알리타: 배틀 엔젤', '["Action", "Sci-Fi", "Adventure"]', NULL, '[]', '모두가 갈망하는 공중도시와 그들을 위해 존재하는 고철도시로 나누어진 26세기. 고철 더미 속 모든 기억을 잃은 채 깨어난 알리타는 마음 따뜻한 의사 이도의 보살핌으로 새로운 삶을 시작한다. 이도는 사이보그인 알리타에게 특별한 과거의 비밀과 영혼이 존재한다는 사실을 깨닫고 미스터리한 과거로부터 그녀를 지키고자 한다. 한편 새로운 친구 휴고는 알리타가 위험한 고철도시를 헤쳐나갈 수 있는 방법과 함께 기억을 되찾도록 돕는다. 알리타가 자신의 과거에 다가갈수록 도시를 지배하는 악랄한 세력들이 그녀를 노리며 제거하려고 하는데...', 'https://image.tmdb.org/t/p/w500/s9nAuXPBR5iK4Z11UKiaPBBIJqY.jpg', 2019, 0, 0, '2026-06-06 13:25:34.235142', 'US');
INSERT INTO public.movies VALUES (4194, 482040, '엄마친구 3', '["Romance", "Drama"]', 'Myeong Seok Hwan', '["Shin Yeon-woo", "Lee Yeong-ho-I", "Seo Won", "Seo Eun-yeong-I", "Hyeon Yeong-im-I"]', '엄마가 교통사고로 입원한 후 엉망으로 살던 아버지와 아들. 두 사람만 살던 집에 엄마의 부탁으로 살림을 봐주러 온 엄마 친구 미애! 깔끔한 살림꾼인 줄만 알았더니, 술만 마시면 화끈한 섹스머신으로 돌변하는 그녀. 그녀의 완전무결 S라인 앞에서 두 남자는 무너지고 만다.', 'https://image.tmdb.org/t/p/w500/jVPxCVo5GEbJJZqQT9BpRpuO8G.jpg', 2017, 0, 0, '2026-06-08 06:28:17.568214', 'KR');
INSERT INTO public.movies VALUES (8835, 12405, '슬럼독 밀리어네어', '["Drama", "Romance"]', 'Danny Boyle', '["Dev Patel", "Freida Pinto", "Madhur Mittal", "Anil Kapoor", "Mahesh Manjrekar"]', '2006년, 뭄베이. 빈민가 출신의 18살 고아 자말은 거액의 상금이 걸려있는 ‘누가 백만장자가 되고 싶은가’라는 최고 인기 퀴즈쇼에 참가한다. 처음 모두에게 무시당하던 자말은 예상을 깨고 최종 라운드에 오르게 되고, 정규 교육도 제대로 받지 못한 그의 부정행위를 의심한 경찰은 자말을 사기죄로 체포한다. 하지만, 결국 자말이 살아온 모든 순간이 정답을 맞출 수 있는 실마리였다는 것과, 그가 퀴즈쇼에 출연한 진짜 목적이 밝혀지게 되는데…', 'https://image.tmdb.org/t/p/w500/q1iXWNplvy5bm61SH6EbpOVU1fU.jpg', 2008, 0, 0, '2026-06-08 07:30:03.266395', 'GB');
INSERT INTO public.movies VALUES (2994, 458220, '''파머'' - Palmer', '["Drama"]', NULL, '[]', '학창 시절 미식축구 스타였던 에디 파머. 12년의 수감 생활을 마치고 돌아간 고향에서 가족으로부터 버림받은 소년 샘과 예상치 못하게 인연을 맺게 된다. 그러나 에디의 과거가 새로운 삶과 가족을 위협하게 되는데...', 'https://image.tmdb.org/t/p/w500/2VXKO2fqjZuqqwkWk2Jv6guhglE.jpg', 2021, 0, 0, '2026-06-07 12:17:57.132297', 'US');
INSERT INTO public.movies VALUES (992, 1420733, '귀시', '["Horror", "Thriller"]', 'Hong Won-ki', '["You Chea-myung", "Moon Chae-won", "Seo Young-hee", "Won Hyun-jun", "Solar"]', '매일 밤, 아무도 모르게 열리는 귀신을 사고 파는 시장 ‘귀시’. 양손의 검지와 새끼손가락을 맞대 여우 모양의 창을 그리면, 그 문이 열린다. 돈, 외모, 성적, 스펙, 인기.. 갖지 못한 것을 탐하는 사람들이 모이는 곳, 그곳에서는 매일 밤 상상조차 할 수 없는 섬뜩한 거래가 벌어지는데…', 'https://image.tmdb.org/t/p/w500/prXqVtz3NOGGh52y9VZK5ja4efh.jpg', 2025, 0, 0, '2026-06-06 13:25:34.260479', 'KR');
INSERT INTO public.movies VALUES (4284, 554972, '성난황소', '["Crime", "Action", "Thriller", "Comedy"]', 'Kim Min-ho', '["Don Lee", "Song Ji-hyo", "Kim Seung-o", "Kim Min-jae", "Park Ji-hwan"]', '거칠었던 과거를 벗어나 수산시장에서 건어물 유통을 하며 건실하게 살던 동철. 어느 날 아내 지수가 납치되고, 경찰에 신고를 하지만 그녀의 행방은 묘연하기만 하다. 그리고 동철에게 걸려 온 납치범의 전화. 오히려 지수를 납치한 대가로 거액의 돈을 동철에게 주겠다는 파격 제안을 하고, 이에 폭발한 동철은 지수를 구하기 위해 움직이기 시작하는데…', 'https://image.tmdb.org/t/p/w500/xiVHlQ4aUyeQQFngyGEounzcYlX.jpg', 2018, 0, 0, '2026-06-08 06:29:47.466377', 'KR');
INSERT INTO public.movies VALUES (984, 166428, '드래곤 길들이기 3', '["Animation", "Family", "Adventure"]', NULL, '[]', '영원한 친구 히컵과 투슬리스의 활약으로 사람과 드래곤이 공존하며 평화롭게 살아가는 버크섬. 새로운 드래곤 ‘라이트 퓨어리’를 쫓아간 투슬리스를 찾다가 히컵은 누구도 찾지 못했던 드래곤의 파라다이스 ‘히든월드’를 우연히 발견하게 된다. 하지만 평화도 잠시, 역대 최악의 드래곤 헌터 그리멜의 등장으로 드래곤들의 안전과 버크섬의 평화까지 위협받기 시작하는데…', 'https://image.tmdb.org/t/p/w500/51HTWy1h5a2cbXC9gKYGOt2YQBV.jpg', 2019, 0, 0, '2026-06-06 13:25:34.241034', 'US');
INSERT INTO public.movies VALUES (987, 7220, '퍼니셔', '["Action", "Crime", "Drama"]', NULL, '[]', '델타포스 출신의 FBI 비밀요원 프랭크 캐슬은 무기 거래상 위장근무를 끝으로 은퇴, 사랑스런 가족의 품으로 돌아가 평범한 삶을 살기로 결심한다. 하지만 마지막 임무를 수행하던 중 처치한 범인이 무기 밀매와 검은 돈 세탁에 연루된 거대기업의 총수 하워드 세인트의 아들이란 사실이 밝혀지고, 격노한 하워드는 상상을 초월하는 무자비한 방법으로 프랭크의 아내와 아들, 가족 모두를 몰살하기에 이른다.  가까스로 혼자만 살아남은 프랭크에게 가족이 죽어가는 처참한 기억은 잔인하기만 하다. 5개월이 지나도록 법과 정의 조차도 돈과 권력을 방패로 삼은 하워드를 처벌할 수 없음을 깨달은 프랭크는 스스로 ''퍼니셔''가 되어 세인트 그룹과 하워드 패밀리를 붕괴시킬 계획을 세운다. 이제 단순한 복수의 차원을 뛰어넘어 심리전과 첨단 전술을 동원한 프랭크의 잔인한 처형이 시작되는데.', 'https://image.tmdb.org/t/p/w500/1VdWpKm6defALMuhwVF6X47iSiT.jpg', 2004, 0, 0, '2026-06-06 13:25:34.248018', 'US');
INSERT INTO public.movies VALUES (988, 1505183, 'Dusun Mayit', '["Adventure", "Horror", "Mystery"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/pkcOwMJXYAbjxEwO8rDTi8H9irL.jpg', 2025, 0, 0, '2026-06-06 13:25:34.250373', 'US');
INSERT INTO public.movies VALUES (989, 1455079, 'You, Me & Tuscany', '["Romance", "Comedy"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/mJS0IF7Af3WpPRhSTDT6rGpiLzw.jpg', 2026, 0, 0, '2026-06-06 13:25:34.252903', 'US');
INSERT INTO public.movies VALUES (2995, 507089, '프레디의 피자가게', '["Horror", "Thriller"]', NULL, '[]', '80년대에 아이들이 실종되고 폐업한지 오래된 프레디의 피자가게 그곳의 야간 경비 알바를 하게 된 ‘마이크''는 캄캄한 어둠만이 존재하는 줄 알았던 피자가게에서 살아 움직이는 피자가게 마스코트 ''프레디와 친구들’을 목격한다. 어딘가 기괴하고 섬뜩한 프레디와 친구들이 실체를 드러내기 시작하는데...', 'https://image.tmdb.org/t/p/w500/6rUZcazlkYILiNPKFgCGkzTn0BN.jpg', 2023, 0, 0, '2026-06-07 12:17:57.134713', 'US');
INSERT INTO public.movies VALUES (991, 1588846, '밤의 여왕들', '["Drama"]', NULL, '[]', '여성 범죄 크루는 앙 회장 아들의 막대한 몸값을 노리고 위험천만한 납치 계획을 실행에 옮긴다. 한 치의 오차도 없을 것 같았던 그들의 설계는 성공하는 듯 보였으나, 돈 가방을 손에 쥐기 직전 예기치 못한 폭력과 함께 계획은 처참하게 어긋나기 시작한다. 피비린내 나는 소용돌이 속에서 그녀들의 결속력에 균열이 가고, 서로를 향한 칼날이 날카로워질수록 현장은 통제 불능의 학살극으로 변해간다. 과연 그녀들은 살아남을 수 있을까?', 'https://image.tmdb.org/t/p/w500/d3kXXMAsGPfl2t8R6tv8JIdv9XM.jpg', 2025, 0, 0, '2026-06-06 13:25:34.258054', 'US');
INSERT INTO public.movies VALUES (986, 1252037, '전차 티거', '["Action", "Drama"]', NULL, '[]', '1943년 동부 전선. 독일군 티거 전차 분대는 치열한 최전선 너머로 침투해야 하는 위험한 임무를 맡는다. 그들은 생사를 장담할 수 없는 무인 지대를 헤쳐 나가며 적과 내면의 악마를 동시에 마주해야 한다.', 'https://image.tmdb.org/t/p/w500/swNuqlHua7uLgV6ulS4t2RGP2sd.jpg', 2025, 0, 0, '2026-06-06 13:25:34.245704', 'US');
INSERT INTO public.movies VALUES (990, 359724, '포드 V 페라리', '["Drama", "Action", "History"]', NULL, '[]', '1960년대, 매출 감소에 빠진 포드는 판매 활로를 찾기 위해 페라리와의 인수 합병을 추진한다. 막대한 자금력에도 불구, 계약에 실패하고 엔초 페라리로부터 모욕까지 당한 헨리 포드 2세는 르망 24시간 레이스에서 페라리를 박살 낼 차를 만들 것을 지시한다. 지옥의 레이스로 불리는 르망 24시간 레이스. 출전 경험조차 없는 포드는 대회 6연패를 차지한 페라리에 대항하기 위해 르망 우승자 출신 자동차 디자이너 캐롤 셸비를 고용하고, 그는 누구와도 타협하지 않지만 열정과 실력만큼은 최고인 레이서 켄 마일스를 자신의 파트너로 영입하는데...', 'https://image.tmdb.org/t/p/w500/wBUoWL4z0nsvC9cYT3VCc74X3jE.jpg', 2019, 0, 0, '2026-06-06 13:25:34.255579', 'US');
INSERT INTO public.movies VALUES (999, 1241693, 'दो दीवाने शहर में', '["Romance", "Drama", "Comedy"]', 'Ravi Udyawar', '["Siddhant Chaturvedi", "Mrunal Thakur", "Ila Arun", "Joy Sengupta", "Ayesha Raza Mishra"]', NULL, 'https://image.tmdb.org/t/p/w500/pJu9oL6ElIaajAjwgoKyUCM319H.jpg', 2026, 0, 0, '2026-06-06 13:25:34.278817', 'IN');
INSERT INTO public.movies VALUES (996, 9757, '나이스 가이 노빗', '["Comedy"]', NULL, '[]', '온순한 성격의 노르빗 알버트 라이스에게 있어서 지금까지의 삶이란 어느 것하나 제대로 풀리지 않는 우울함 그 자체였다. 우선 그는 아기인채로 중국인 미스터 왕이 운영하는 골든 완탕 레스토랑 겸 고아원 앞에 던져졌다. 그곳에서 어린시절을 보내는 동안 노르빗은 자신의 소울메이트라 할 수 있는 사랑스러운 케이트를 만나지만 그것도 잠시 케이트가 입양되어 떠나면서 이별의 슬픔을 경험한다. 9살이 된 어느날 놀이터에서 동네 말썽쟁이들에게 괴롭힘을 당하던 노르빗을 10살이라고는 믿기 힘든 덩치 큰 소녀 라스푸티아가 구해준다. 이를 인연의 시작으로 장성한 노르빗은 괴물같은 덩치가 된 라스푸티아와 약론을 하게 된다. 라스푸티아와의 결혼 압력을 받고 있던 중 아름답게 성장한 케이트가 고향으로 돌아온다. 이제 노르빗은 자신의 진정한 사랑을 이룰 방법을 찾기 시작하는데...', 'https://image.tmdb.org/t/p/w500/XcZ5NzygPp54csxCnzvQKuxFL2.jpg', 2007, 0, 0, '2026-06-06 13:25:34.271362', 'US');
INSERT INTO public.movies VALUES (994, 260346, '테이큰 3', '["Thriller", "Action"]', NULL, '[]', '전 부인 레니(팜케 얀센)가 방문한다는 연락을 받고 집으로 돌아온 브라이언 밀스(리암 니슨)를 기다리는 건 살해당한 아내의 싸늘한 시체. 사태를 파악할 겨를도 없이 경찰이 집에 들이닥치고 브라이언은 살인범으로 체포되기 직전 가까스로 탈출한다. 쫓아야 할 대상도, 쫓기는 이유도 알 수 없는 상황에 경찰, FBI, CIA까지 총동원 되어 모두가 그를 쫓는다. 이제 그에게 무엇보다 중요한 것은 마지막 남은 딸 킴(매기 그레이스)을 지켜내는 것. 브라이언은 부인을 죽인 범인을 찾고 딸을 지키기 위해 목숨을 건 추격을 시작하는데...', 'https://image.tmdb.org/t/p/w500/bwV9BA7EyejT347YI38FmTwl599.jpg', 2014, 0, 0, '2026-06-06 13:25:34.266123', 'US');
INSERT INTO public.movies VALUES (998, 365045, '하이디', '["Adventure", "Family", "Drama"]', NULL, '[]', '고아가 된 하이디는 숙모 손에 이끌려 산에 살고 있는 할아버지에게 간다. 산 생활에 조금씩 적응해 가던 과정 중 또 다시 숙모에 의해 어떤 가정으로 가게 되는데 그곳에서 장애인 소녀 클라라의 도우미로 일하게 되는데… 아주 잘 알려진 작품으로 아이들의 연기가 매우 사랑스런 2016년 리메이크작이다.', 'https://image.tmdb.org/t/p/w500/kxnhHaPOvh0cqMOAx5k0NnqhDqS.jpg', 2015, 0, 0, '2026-06-06 13:25:34.276453', 'US');
INSERT INTO public.movies VALUES (4285, 1316057, '아씨마님', '["Drama"]', 'Richard Kim', '["Jo Wan-jin", "Do Hee", "Min Do-yoon", "Im Cho-hee", "Ha Yool"]', NULL, 'https://image.tmdb.org/t/p/w500/6sTeWsvRtWSEU4BA6CpNP1FVukc.jpg', 2024, 0, 0, '2026-06-08 06:29:48.145267', 'KR');
INSERT INTO public.movies VALUES (997, 5175, '러시아워 2', '["Action", "Comedy", "Crime"]', NULL, '[]', '홍콩 특수 경찰의 베테랑 형사 리(성룡 분)는 휴가차 홍콩에 들른 LA 경찰 카터(크리스 터커 분)와 반가운 재회를 한다. 그러나 즐거운 시간도 잠시, 홍콩 내 미국 대사관에서 원인을 알 수 없는 대형 폭발사고가 발생하고 휴가는 고스란히 반납되고 만다. 사건배후엔 수퍼빌이라는 미화 100불 짜리 위조지폐를 밀매하는 대규모 범죄조직이 존재하고 있음을 알게 된 ''리'' 형사. 더욱이 그 조직의 우두머리가 그의 아버지를 죽음으로 몰고 간 리키 탄(존 론 분)인 것을 알고 피할 수 없는 대결을 예감한다. 그러나 탄의 오른팔인 후 리(장지이 분)의 거센 방해공작으로 사건은 좀처럼 해결기미가 보이지 않는다. 사건의 윤곽이 드러나면서 리키 탄 일당이 LA 범죄조직과 연관되어 있음이 밝혀지고 ''리''와 ''카터''는 미국행 비행기에 오른다. 홍콩과 LA, 뉴욕을 거치면서 탄 일당의 범죄행각을 파헤치기 위해 종횡무진하던 두 파트너. 최후의 결전을 위해 카지노와 환락의 도시 라스베거스로 발걸음을 재촉하는데.', 'https://image.tmdb.org/t/p/w500/szpcEjLUh65pkPaDagMfTRs3u5N.jpg', 2001, 0, 0, '2026-06-06 13:25:34.273923', 'US');
INSERT INTO public.movies VALUES (995, 38575, '베스트 키드', '["Action", "Adventure", "Drama", "Family"]', NULL, '[]', '베이징으로 이민 와 친구들의 괴롭힘에 시달리는 외톨이 미국 소년 ‘드레(제이든 스미스)’ 앞에 아파트 관리인인 ‘Mr.한(성룡)’이 나타나 놀라운 쿵푸 기술로 그를 위험으로부터 구해준다. 맞서기 위해서는 강해질 수 밖에 없다는 그의 충고에 따라 ‘드레’는 정식으로 쿵푸를 배우기로 한다.  무술의 기본기라고는 어설픈 가라데 동작 밖에 없는 ‘드레’는 ‘Mr.한’의 가르침에 따라 혹독한 쿵푸 수련의 길로 들어서는데!', 'https://image.tmdb.org/t/p/w500/dIZRhQAvqI4r2YfKRxvi9Pp3GEV.jpg', 2010, 0, 0, '2026-06-06 13:25:34.268705', 'US');
INSERT INTO public.movies VALUES (2999, 621, '그리스', '["Romance", "Comedy"]', NULL, '[]', '1950년대말, 캘리포니아에 있는 한 고등학교. 대니 주코(Danny Zuko: 존 트라볼타 분)와 샌디 올슨(Sandy Olsen: 올리비아 뉴튼 존 분)은 여름 방학 때 해변에서 우연히 알게 된 사이로 바캉스 시즌이 끝나자 두 사람은 기약없이 작별하지만 대니가 다니는 고등학교에 샌디가 전학해 오면서 뜻밖의 재회가 이루어진다. 내심 기뻤던 대니지만 학교의 서클인 티버즈의 리더인 그가 어느 특정한 여자에게 가까이 하면 친구들의 빈촉을 살까봐 이러지도 저러지도 못한다.  이런 대니의 마음을 모른는 샌디는 오해를 해 스포츠에 만능인 톰과 친하게 지낸다. 이에 쇼크를 받은 대니는 샌디에게 용서를 빌어 가까스로 샌디의 마음을 되돌려 놓는다. 바야흐로 학교의 최대 행사인 댄스 파티가 열리자 대니와 샌디는 한조가 되어 출전, 결승전까지 진출하지만 티버즈의 라이벌인 스코피언스의 리더인 차차의 방해로 우승을 놓친다. 화가 난 샌디에게 야외 극장에서 대니는 자기의 반지를 빼주며 샌디의 마음을 바꾸지만 샌디의 몸을 강요한게 그녀를 더 토라지게 만들고 말았다.  드디어 티버즈와 숙적인 스콜피온스 간에 카레이스로 결판을 내는 날이다. ''선더로드 경주''라는 이름의 이 시합에서 차차는 비겁한 수단으로 골탕을 먹이지만 이를 잘 피해 대니가 이기는데 이를 가슴조이며 지켜보던 샌디는 대니의 품에 안긴다. 이윽고 고등학교 졸업식이 왔다. 졸업 파티가 성대하게 벌어지고 정장을 하고 머리에다 그리이스를 발라 의젓해진 대니와 샌디는 빨간 승용차를 타고 다정하게 교문을 나선다. 축하무드가 절정을 이루며 뒤를 따르는 동창생들.', 'https://image.tmdb.org/t/p/w500/2rM7fQKpb7cs1Iq7IBqub9LFDzJ.jpg', 1978, 0, 0, '2026-06-07 12:17:57.144626', 'US');
INSERT INTO public.movies VALUES (3000, 490132, '그린 북', '["Drama", "Comedy", "History"]', NULL, '[]', '1962년 미국, 입담과 주먹만 믿고 살아가던 토니 발레롱가는 교양과 우아함 그 자체인 천재 피아니스트 돈 셜리의 운전기사 면접을 보게 된다. 백악관에도 초청되는 등 미국 전역에서 콘서트 요청을 받으며 명성을 떨치고 있는 돈 셜리는 위험하기로 소문난 미국 남부 투어 공연을 떠나기로 결심하고, 투어 기간 동안 자신의 보디가드 겸 운전기사로 토니를 고용한다. 거친 인생을 살아온 토니와 교양과 기품을 지키며 살아온 돈. 생각, 행동, 말투, 취향까지 달라도 너무 다른 두 사람은 그들을 위한 여행안내서 그린북에 의존해 특별한 남부 투어를 시작하는데...', 'https://image.tmdb.org/t/p/w500/dyqQ12gZGwl5Y0R9UsLBDkZWOUA.jpg', 2018, 0, 0, '2026-06-07 12:17:57.147173', 'US');
INSERT INTO public.movies VALUES (393, 1930, '어메이징 스파이더맨', '["Action", "Adventure", "Sci-Fi"]', 'Marc Webb', '["Andrew Garfield", "Emma Stone", "Rhys Ifans", "Denis Leary", "Martin Sheen"]', '어릴적 사라진 부모 대신 삼촌 내외와 살고 있는 피터 파커는 평범한 학교 생활을 하며 일상을 보내고, 같은 학교 학생 그웬 스테이시와 첫사랑에 빠져 우정과 사랑, 그리고 둘 만의 비밀을 키워나간다. 어느 날 아버지가 사용했던 가방을 발견하고 부모님의 실종사건에 대한 의심을 품게 된 그는 숨겨져 왔던 과거의 비밀을 추적하게 된다. 아버지의 옛 동료 코너스 박사의 실험실을 찾아가게 된 피터는 우연한 사고로 특별한 능력을 갖게 되고, 피터의 도움으로 연구를 완성한 코너스 박사는 자신의 숨겨진 자아인 악당 리자드를 탄생시키는데...', 'https://image.tmdb.org/t/p/w500/a1Kup5VnmxjAHnsT3Sz7RtrC9UU.jpg', 2012, 0, 0, '2026-06-06 13:25:11.034594', 'US');
INSERT INTO public.movies VALUES (48, 1291608, '두란다르', '["Action", "Crime", "Thriller"]', 'Aditya Dhar', '["Ranveer Singh", "Akshaye Khanna", "R. Madhavan", "Arjun Rampal", "Sanjay Dutt"]', '1999년 12월 30일, 인도 외무부 장관 데바브라트 카푸르와 정보국의 국장인 아제이 산얄(M. 마다반)은 인도 항공기를 납치한 테러범인 자후르 미스트리와 협상을 벌여 세 명의 테러범들을 석방하고 칸다하르에 억류된 승객들의 목숨을 대가로 1천만 달러의 몸값을 지불한다.INSERT INTO public.movies VALUES (4286, 729097, '젊은엄마 5', '["Drama", "Romance"]', 'Jeong Do-soo', '["Lee Eun-mi", "Cheon Yoo-ji", "Min Do-yoon", "Park Do-jin"]', NULL, 'https://image.tmdb.org/t/p/w500/ggvBofagO3rEs7bki3EqrNhBzNv.jpg', 2020, 0, 0, '2026-06-08 06:29:48.806512', 'KR');
INSERT INTO public.movies VALUES (32, 249397, '님포매니악: 볼륨 2', '["Drama", "Mystery"]', NULL, '[]', '무수한 남성을 만난 뒤 조는 첫 남자 제롬(샤이아 러버프)과 조우하고 사랑이라는 감정을 느낀다. 그러나 아이러니하게도 사랑은 성적 쾌감을 빼앗아갔다. 조는 삶의 공허함을 느끼게 되고 가학적인 방식으로 성적 만족을 제공하는 K(제이미 벨)를 찾아간다. 조는 감각을 되찾은 대가로 제롬을 잃지만 여성으로서 자신감을 되찾는다. 아무도 믿지 않고 아무 의미도 추구하지 않던 조는 자신의 분신이자 후계자인 P(미아 고스)에게 마음을 주기 시작하면서 조금씩 달라진다. 길고 긴 조의 경험담이 다다른 결론은 자신의 욕망을 인정한다는 것이다.', 'https://image.tmdb.org/t/p/w500/tsYCG9yLRr7p2ZBqtCe3162cT4n.jpg', 2013, 0, 0, '2026-06-06 13:24:57.148654', 'US');
INSERT INTO public.movies VALUES (18, 603, '매트릭스', '["Action", "Sci-Fi"]', 'Lana Wachowski', '["Keanu Reeves", "Laurence Fishburne", "Carrie-Anne Moss", "Hugo Weaving", "Gloria Foster"]', '인간의 기억마저 AI에 의해 입력되고 삭제되는 세상, 진짜보다 더 진짜 같은 가상 현실 매트릭스. 그 속에서 진정한 현실을 인식할 수 없게 재배되는 인간들. 그 매트릭스를 빠져 나오면서 AI에게 가장 위험한 인물이 된 모피어스는 몇 안 되는 동료들과 함께 기계와의 전쟁 전후의의 폐허를 떠돌며 인류를 구할 마지막 영웅을 찾아 헤맨다. 마침내 모피어스는 낮에는 평범한 회사원 앤더슨으로, 밤에는 해커로 활동하는 청년 네오를 그로 지목한다. 모피어스의 지시대로 그를 만나게 된 네오는 두개의 알약 중 하나를 고르는 선택을 하게 되는데...', 'https://image.tmdb.org/t/p/w500/fxBxoXFAYKWde6lKzXxSusn18Av.jpg', 1999, 0, 0, '2026-06-06 13:24:56.384165', 'US');
INSERT INTO public.movies VALUES (17, 1419406, '포풍추영', '["Action", "Crime", "Drama", "Thriller"]', NULL, '[]', '첨단 감시 시스템과 삼엄한 보안망을 무력화하고, 수십억을 탈취한 정체불명의 범죄 조직. 통제 불능의 범죄에 마카오 경찰은 결국 은퇴한 전설의 범죄 추적 전문가 ‘황더중’에게 도움을 요청한다. 황더중은 신입 경찰 ‘허추궈’와 함께 최정예 감시반을 구성해, 범죄 조직의 수장 ‘푸룽성’을 추적하기 시작한다. 하지만 수사망이 조여올수록 상대의 덫과 함정은 더욱 교묘해지고, 예상치 못한 반격 속에 황더중 역시 추적당하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/uiIT7CsJ4V7rMnTqy7xYvj9IRhs.jpg', 2025, 0, 0, '2026-06-06 13:24:56.379998', 'US');
INSERT INTO public.movies VALUES (63, 1368166, '하우스메이드', '["Mystery", "Thriller"]', 'Paul Feig', '["Sydney Sweeney", "Amanda Seyfried", "Brandon Sklenar", "Michele Morrone", "Elizabeth Perkins"]', '과거를 숨긴 채 완벽한 저택의 가정부로 들어간 밀리가 이상한 행동을 보이는 아내 니나와 그런 아내를 이해하는 모범적인 남편 앤드루와 얽히며 닫힌 문 뒤의 거짓과 마주하게 되는 월드 베스트셀러 원작의 고자극 미스터리 스릴러', 'https://image.tmdb.org/t/p/w500/fUDX16A4fJXmAuUA5t0pnqzXS0b.jpg', 2025, 0, 0, '2026-06-06 13:24:58.682085', 'US');
INSERT INTO public.movies VALUES (79, 1375646, '군체', '["Action", "Thriller", "Horror"]', 'Yeon Sang-ho', '["Gianna Jun", "Koo Kyo-hwan", "Ji Chang-wook", "Kim Shin-rock", "Shin Hyun-been"]', '서울 도심의 초고층 빌딩에서 정체불명의 집단 감염사태가 발생한다. 건물은 순식간에 봉쇄되고, 그 안에 있던 사람들은 그대로 고립된다. 처음에는 짐승처럼 기어다니던 감염자들은 점점 진화하며 두 발로 걷기 시작하고, 사람을 식별하며 무리를 지어 생존자들을 공격한다. 생명공학자 권세정과 생존자들은 자신의 몸에 백신을 주입했다고 신고한 서영철을 찾아 구조대가 기다리는 옥상으로 향한다. 하지만 올라갈수록 상황은 점점 더 예측할 수 없게 변해가고, 서영철은 감염자들을 앞세워 생존자들 앞을 막아서는데...', 'https://image.tmdb.org/t/p/w500/thK6glS5pklrlijsgSN6Hw9GLQK.jpg', 2026, 0, 0, '2026-06-06 13:24:58.729721', 'KR');
INSERT INTO public.movies VALUES (874, 10191, '드래곤 길들이기', '["Fantasy", "Adventure", "Animation", "Family"]', NULL, '[]', '바이킹의 세계, 절대 친구가 될 수 없는 둘이 만났다?  용맹한 바이킹과 사나운 드래곤들의 싸움이 끊이지 않는 버크섬.  바이킹 족장의 아들 ‘히컵’은 드래곤 사냥에 소질 없는 마을의 사고뭉치. 어느날 그는 부상 당한 드래곤 ‘투슬리스’를 구하게 되고, 아무도 몰래 그를 돌본다. 서로를 알아가며, 드래곤들의 친구가 된 ‘히컵’. 그들과의 새로운 생활을 만끽하던 ‘히컵’은 드래곤들의 위험한 비밀을 알게 되는데…  불멸의 드래곤과 바이킹족 이단아의 만남!  2010년 5월, 그들의 스펙터클한 모험이 시작된다!', 'https://image.tmdb.org/t/p/w500/5JtTkNwOeztwfCPv965e9bZi6G3.jpg', 2010, 4.5, 1, '2026-06-06 13:25:29.651087', 'US');
INSERT INTO public.movies VALUES (69, 1242898, '프레데터: 죽음의 땅', '["Action", "Sci-Fi", "Adventure"]', 'Dan Trachtenberg', '["Elle Fanning", "Dimitrius Schuster-Koloamatangi", "Ravi Narayan", "Michael Homick", "Stefan Grube"]', '프레데터로서 존재를 증명하기 위해 우주에서 가장 위험한 행성으로 첫 사냥에 나선 덱. 죽음의 땅에 도사린 모든 것으로부터 공격을 받던 순간, 휴머노이드 티아를 만난다. 최상위 포식자 칼리스크에 맞서게 된 둘은 생존과 각자의 목적을 위해 극한의 사투를 벌이게 되는데…', 'https://image.tmdb.org/t/p/w500/8lpCbwbYh9SSzCFsHDndZHKrcD4.jpg', 2025, 0, 0, '2026-06-06 13:24:58.700773', 'US');
INSERT INTO public.movies VALUES (92, 1314481, '악마는 프라다를 입는다 2', '["Comedy", "Drama"]', 'David Frankel', '["Meryl Streep", "Anne Hathaway", "Emily Blunt", "Stanley Tucci", "Kenneth Branagh"]', '전 세계 트렌드를 주도해 온 전설적인 패션 매거진 런웨이가 급변하는 미디어 시장 속에서 예기치 못한 위기에 직면한다. 런웨이를 지켜내려는 편집장 미란다와 20년 만에 신임 기획 에디터로 당당히 돌아온 앤디, 그리고 이제는 럭셔리 브랜드 임원이 되어 다시 나타난 에밀리까지 더 화려하고, 치열해진 뉴욕 패션계에서 주도권을 차지하기 위해 벌이는 이들의 새로운 이야기가 펼쳐진다!', 'https://image.tmdb.org/t/p/w500/28A1VUDML1RzENYNtIU1WkBLT9V.jpg', 2026, 0, 0, '2026-06-06 13:24:59.482983', 'US');
INSERT INTO public.movies VALUES (4136, 1255, '괴물', '["Horror", "Drama", "Sci-Fi"]', 'Bong Joon Ho', '["Song Kang-ho", "Byun Hee-bong", "Park Hae-il", "Bae Doona", "Ko A-sung"]', '아버지가 운영하는 한강매점, 늘어지게 낮잠 자던 강두는 우연히 특이한 광경을 목격하게 된다. 생전 보도 못한 무언가가 한강다리에 매달려 움직이는 것이다. 정체를 알 수 없는 괴물은 둔치 위로 올라와 사람들을 거침없이 깔아뭉개고, 무차별로 물어뜯기 시작한다. 순식간에 아수라장으로 돌변하는 한강변. 강두도 뒤늦게 딸 현서를 데리고 정신없이 도망가지만, 꼭 잡았던 현서의 손을 놓치고 만다. 하루아침에 집과 생계, 그리고 현서까지 모든 것을 잃게 된 강두 가족. 돈도 없고 빽도 없는 그들은 위험구역으로 선포된 한강 어딘가에 있을 현서를 찾아 나선다.', 'https://image.tmdb.org/t/p/w500/tqDQzYGi1EWHgUZY91YRSJLDJVf.jpg', 2006, 0, 0, '2026-06-08 06:27:31.612925', 'KR');
INSERT INTO public.movies VALUES (122, 155, '다크 나이트', '["Action", "Crime", "Thriller"]', 'Christopher Nolan', '["Christian Bale", "Heath Ledger", "Aaron Eckhart", "Michael Caine", "Maggie Gyllenhaal"]', '범죄와 부정부패를 제거하여 고담시를 지키려는 배트맨. 그는 짐 고든 형사와 패기 넘치는 고담시 지방 검사 하비 덴트와 함께 도시를 범죄 조직으로부터 영원히 구원하고자 한다. 세 명의 의기투합으로 위기에 처한 악당들이 모인 자리에 보라색 양복을 입고 얼굴에 짙게 화장을 한 괴이한 존재가 나타나 배트맨을 죽이자는 사상 초유의 제안을 한다. 그는 바로 어떠한 룰도, 목적도 없는 사상 최악의 악당 미치광이 살인광대 조커. 배트맨을 죽이고 고담시를 끝장내버리기 위한 조커의 광기 어린 행각에 도시는 혼란에 빠지는데...', 'https://image.tmdb.org/t/p/w500/9ICUbdveP56jRoMMVkXSOr3ceyV.jpg', 2008, 0, 0, '2026-06-06 13:25:01.010685', 'US');
INSERT INTO public.movies VALUES (4199, 13855, '추격자', '["Crime", "Thriller", "Action"]', 'Na Hong-jin', '["Kim Yun-seok", "Ha Jung-woo", "Seo Young-hee", "Kim You-jung", "Jung In-gi"]', '출장안마소를 운영하는 전직 형사 중호. 최근 데리고 있던 여자들이 잇달아 사라지는 일이 발생하던 중 조금 전 나간 미진을 불러낸 손님의 전화 번호와 사라진 여자들이 마지막으로 통화한 번호가 일치함을 알아낸다. 연락이 두절된 미진을 찾아 헤매던 중 우연히 옷에 피가 묻은 영민과 마주치고, 추격 끝에 그를 붙잡는다. 실종된 여자들을 모두 죽였다는 충격적인 고백을 담담히 털어 놓는 영민에 의해 경찰서는 발칵 뒤집어진다. 공세우기에 혈안이 된 경찰은 미진의 생사보다는 증거를 찾기에만 급급해 하고, 미진이 살아 있다고 믿는 단 한 사람인 중호는 미진을 찾아 나서는데...', 'https://image.tmdb.org/t/p/w500/3Y5COpcDL8I9u4GdUl0HskNO8zI.jpg', 2008, 0, 0, '2026-06-08 06:28:21.338088', 'KR');
INSERT INTO public.movies VALUES (121, 634649, '스파이더맨: 노 웨이 홈', '["Action", "Adventure", "Sci-Fi"]', 'Jon Watts', '["Tom Holland", "Zendaya", "Benedict Cumberbatch", "Jacob Batalon", "Jon Favreau"]', '미스테리오의 계략으로 세상에 정체가 탄로난 스파이더맨 피터 파커는 하루 아침에 평범한 일상을 잃게 된다. 문제를 해결하기 위해 닥터 스트레인지를 찾아가 도움을 청하지만 뜻하지 않게 멀티버스가 열리면서 각기 다른 차원의 불청객들이 나타난다. 닥터 옥토퍼스를 비롯해 스파이더맨에게 깊은 원한을 가진 숙적들의 강력한 공격에 피터 파커는 사상 최악의 위기를 맞게 되는데…', 'https://image.tmdb.org/t/p/w500/fvqoI9r1GU2EFkc0xjZ6dKCuDVR.jpg', 2021, 0, 0, '2026-06-06 13:25:01.007888', 'US');
INSERT INTO public.movies VALUES (103, 1579, '아포칼립토', '["Action", "Drama", "History"]', 'Mel Gibson', '["Rudy Youngblood", "Raoul Max Trujillo", "Gerardo Taracena", "Iazua Larios", "Antonio Monroy"]', '마야 문명이 번창하던 시절, 평화로운 부족 마을의 젊은 전사 표범 발은 가족과 함께 행복한 나날을 보내며 살아가고 있다. 어느 날, 잔인한 전사로 구성된 침략자들이 마을을 습격하여 부족민을 학살하고 젊은 남녀를 그들의 왕국으로 끌고 가는 일이 발생한다. 표범 발은 이 혼란 속에 그의 아내와 어린 아들을 깊숙한 우물에 숨긴 채 자신은 인질로 끌려가게 된다. 죽음과 마주친 위기 상황에서 겨우 탈출한 표범 발은 우물 속에 숨겨둔 가족에게 돌아가려 하지만 적들의 집요한 추적은 계속된다. 생명을 위협하는 죽음의 손길이 조금씩 다가오는 가운데, 표범 발은 도리어 적들을 향해 기상천외한 공격을 하기 시작하는데...', 'https://image.tmdb.org/t/p/w500/mAFf4oW3XiH4IlFJw6dgwNnEPhg.jpg', 2006, 0, 0, '2026-06-06 13:25:00.241645', 'US');
INSERT INTO public.movies VALUES (104, 980477, '너자 2', '["Animation", "Action", "Fantasy", "Adventure"]', NULL, '[]', '신·인간·요괴가 뒤섞여 사는 세상, 조금 다르게 태어났다는 이유로 말썽쟁이로 불리는 팬더 눈 너자. 엄청난 파워의 너자는 스승과 함께 수련에만 열심히인데… 문제의 시작은 삼계의 균형을 흔드는 위험한 힘의 흔적. 가만히 두면 세상이 통째로 뒤집힐 판이라, 우리의 주인공 너자가 나선다. 소동의 근원을 찾아 나선 너자 일행, 그러나 길은 순탄치 않고 싸움은 점점 그 규모가 커져 가는데…', 'https://image.tmdb.org/t/p/w500/tc3wdEEov3SdMja9ZkBiAZ6fBGV.jpg', 2025, 0, 0, '2026-06-06 13:25:00.244551', 'US');
INSERT INTO public.movies VALUES (4155, 1224993, '검은 수녀들', '["Horror", "Mystery", "Thriller", "Drama"]', 'Kwon Hyeok-jae', '["Song Hye-kyo", "Jeon Yeo-been", "Lee Jin-uk", "Moon Woo-jin", "Huh Joon-ho"]', '유니아 수녀는 희준의 몸에 숨어든 악령이 12형상 중 하나라고 확신한다. 당장 올 수 없는 구마 사제를 기다리다가 부마자가 희생될 것이 분명한 상황. 결국 유니아는 소년을 구하기 위해 서품을 받지 못한 수녀는 구마를 할 수 없다는 금기를 깨기로 결심한다. 하지만 담당의는 희준을 살릴 수 있는 것은 오직 의학이라 믿는 바오로 신부. 우연한 기회에 그의 제자 미카엘라 수녀의 비밀을 알아챈 유니아는 희준을 병원에서 빼내기 위해 막무가내로 도움을 요청한다. 미카엘라는 거침없는 유니아에게 반발심을 느끼지만, 동질감이 느껴지는 희준을 위해 힘을 보태기로 한다. 마침내 두 수녀는 수단과 방법을 가리지 않고 오직 소년을 살리기 위한 위험한 의식을 시작하는데...', 'https://image.tmdb.org/t/p/w500/fT6SIrOyGwWZ4ZujHjRcabcxgfq.jpg', 2025, 0, 0, '2026-06-08 06:27:47.707866', 'KR');
INSERT INTO public.movies VALUES (4159, 351523, '동창회의 목적', '["Romance", "Drama"]', 'Jung Dae-man', '["Jo In-woo", "Kim Yoo-yeon", "Lee Hyeon-seong", "Kim Neul-me", "Yoo Seung-hyeon"]', '밤이 너무 긴 기러기 아빠, 와이프 한 마디에 벌벌 떨며 사는 공처가 남편, 35살 모태쏠로까지! "그것"이 너무 고픈 남자들! 여전히 예쁜 고교 퀸카, 화끈한 골드미스, 물이 오를대로 오른 이혼녀까지! "그것"이 재미없어진 여자들!  오늘 밤 그들이 제대로 만났다!  15년만에 만났더니 너무 매력적으로 변했구나 우리들?!  그들의 화끈한 동창회가 지금 시작된다!', 'https://image.tmdb.org/t/p/w500/AjlwGaT6tDs2fBIgFaepYiDhL6A.jpg', 2015, 0, 0, '2026-06-08 06:27:50.483562', 'KR');
INSERT INTO public.movies VALUES (180, 240, '대부 2', '["Drama", "Crime"]', 'Francis Ford Coppola', '["Al Pacino", "Robert Duvall", "Diane Keaton", "Robert De Niro", "John Cazale"]', '아버지의 장례식 도중에 맏아들 파올로가 총에 맞아 죽고, 비토(로버트 드니로)는 겨우 도망쳐 미국으로 건너온다. 대부로 성장한 후 비토는 다시 치치오를 찾아 복수를 한다. 새롭게 등장한 젊은 대부 마이클(알 파치노)은 본거지를 라스베가스로 옮기고 가족의 사업을 가능한 합법적인 것으로 바꾸려고 애쓴다. 그런 과중 중에 자신을 제거하려는 음모를 알게되고 그는 냉혹하고 신속하게 반대파들을 제거, 조직을 더욱 확대해 나간다. 이를 위해 마이클은 배신한 형마저 죽이고, 일 때문에 아내와 헤어지는 등 인간적으로는 계속 외로워져 가는데...', 'https://image.tmdb.org/t/p/w500/35RGDgySfINL9V2e6lkDECQ0hRa.jpg', 1974, 0, 0, '2026-06-06 13:25:02.596445', 'US');
INSERT INTO public.movies VALUES (319, 545611, '에브리씽 에브리웨어 올 앳 원스', '["Action", "Adventure", "Sci-Fi"]', 'Daniel Scheinert', '["Michelle Yeoh", "Stephanie Hsu", "Ke Huy Quan", "James Hong", "Jamie Lee Curtis"]', '남편과 세탁소를 운영하며 근근히 살아가고 있는 이민자 이블린 왕. 20대 시절 남편과 순수한 사랑을 불태우며 모든 것을 뒤로 하고 미국으로 이민을 떠났지만, 50대가 된 지금은 세탁소 운영 등 온갖 일로 허덕이며 단란했던 가족과도 삐그덕거리는 등 고달프게 살고 있다. 세무조사를 받던 중 자신이 멀티버스의 여러 다른 자신들과 연결되어 있음을 알게 되고, 강력한 악의 기운으로부터 모든 우주와 가족을 구해내기 위한 모험에 나서게 되는데...', 'https://image.tmdb.org/t/p/w500/dd29Kt2p2voyP2sB6p3jC36A7ce.jpg', 2022, 0, 0, '2026-06-06 13:25:07.9746', 'US');
INSERT INTO public.movies VALUES (151, 1233413, '씨너스: 죄인들', '["Horror", "Action", "Thriller"]', 'Ryan Coogler', '["Michael B. Jordan", "Hailee Steinfeld", "Miles Caton", "Jack O''Connell", "Wunmi Mosaku"]', '1932년, 시카고 갱단의 생활을 정리하고 고향 미시시피로 돌아온 쌍둥이 형제 스모크와 스택은 큰돈을 벌기 위해 술집 주크 조인트를 운영하기로 한다. 화려한 오프닝 파티가 열리는 밤, 천부적인 재능을 지닌 새미의 노래로 파티의 열기는 점점 뜨거워지고 초대하지 않은 불청객 일행이 찾아오는데…', 'https://image.tmdb.org/t/p/w500/qEipksU5SzHxbeZbE0cZQzEt6bD.jpg', 2025, 0, 0, '2026-06-06 13:25:01.800652', 'US');
INSERT INTO public.movies VALUES (166, 425274, '나우 유 씨 미 3', '["Crime", "Thriller"]', 'Ruben Fleischer', '["Jesse Eisenberg", "Dominic Sessa", "Ariana Greenblatt", "Justice Smith", "Rosamund Pike"]', '한때 더러운 방식으로 돈을 모으는 재벌들을 시원하게 혼내주던 마술사기단 ‘포 호스맨’. 은퇴 후 평범한 삶을 살고 있던 그들에게 새로운 임무를 알리는 의미심장한 카드가 배달된다. 그렇게 다시 모이게 된 오리지널 ‘포 호스맨’은 자신들을 흉내 내던 신예 마술사들까지 영입하며 미션을 준비한다. 그들의 목표는 무기 밀매, 자금 세탁 등 더러운 돈에 물든 ‘하트 다이아몬드’를 훔치는 것. 하지만 다이아몬드를 훔치고, 통쾌한 쇼를 선보이려는 이들 앞에는 수많은 함정이 펼쳐지는데…', 'https://image.tmdb.org/t/p/w500/dECA069mRikkghzgSBsM0cvic4F.jpg', 2025, 0, 0, '2026-06-06 13:25:02.557633', 'US');
INSERT INTO public.movies VALUES (6041, 256040, '바후발리: 더 비기닝', '["Action", "Drama"]', 'S. S. Rajamouli', '["Prabhas", "Rana Daggubati", "Tamannaah Bhatia", "Anushka Shetty", "Ramya Krishnan"]', '폭포 아래로 기적처럼 살아 떠밀려 온 갓난 아기. 그 곳에 사는 한 여인은 아이의 목숨을 구하고 정성을 다해 키우지만 아이는 자랄수록 자신이 발견 된 폭포 위 절벽 너머의 세상에 대한 집착을 멈추지 않는다. 결국 성인이 된 아이는 폭포 너머에서 범상치 않은 부름의 기운을 느끼고 수 백 번의 시행착오 끝에 절벽을 올라 그 곳에서 운명적 여인 ‘아반티카’를 만난다. 반란군의 전사이자 25년간 포로로 잡혀 있는 ‘데바세나’ 공주를 구하는 것이 임무인 ‘아반티카’와 사랑에 빠지고만 그는, 과거 왕국의 후계자였던 아버지에 얽힌 엄청난 비밀과 자신이 왕국을 구할 전설 속 전사 ‘바후발리’라는 진실을 알고 큰 혼란에 빠진다. ‘아반티카’와 함께 공주를 구하기 위해 복수의 반격을 시작한 전사 ‘바후발리’...  과연 그의 운명은?', 'https://image.tmdb.org/t/p/w500/l0uufbEixAZBbJyd2td4WzIZ0WA.jpg', 2015, 0, 0, '2026-06-08 06:53:17.193339', 'IN');
INSERT INTO public.movies VALUES (175, 361743, '탑건: 매버릭', '["Action", "Drama"]', 'Joseph Kosinski', '["Tom Cruise", "Miles Teller", "Jennifer Connelly", "Bashir Salahuddin", "Jon Hamm"]', '최고의 파일럿이자 전설적인 인물 매버릭은 자신이 졸업한 훈련학교 교관으로 발탁된다. 그의 명성을 모르던 팀원들은 매버릭의 지시를 무시하지만 실전을 방불케 하는 상공 훈련에서 눈으로 봐도 믿기 힘든 전설적인 조종 실력에 모두가 압도된다. 매버릭의 지휘 아래 견고한 팀워크를 쌓아가던 팀원들에게 국경을 뛰어넘는 위험한 임무가 주어지자 매버릭은 자신이 가르친 동료들과 함께 마지막이 될지 모를 하늘 위 비행에 나서는데...', 'https://image.tmdb.org/t/p/w500/jeqXUwNilvNqNXqAHsdwm5pEfae.jpg', 2022, 0, 0, '2026-06-06 13:25:02.582772', 'US');
INSERT INTO public.movies VALUES (20, 1116201, '아이언 렁', '["Horror", "Mystery", "Sci-Fi"]', 'Mark Fischbach', '["Mark Fischbach", "Caroline Kaplan", "Troy Baker", "Elsie Lovelock", "Elle LaMont"]', '수십 년 전, ''조용한 휴거(The Quiet Rapture)''가 발생해 알려진 우주의 모든 별과 거주 가능한 행성이 사라졌다. 인류는 무너져가는 우주정거장의 녹슨 복도에 남겨졌다. 그리고 황량한 위성에서 발견된, 유일한 희망일지도 모르는 피의 바다(Ocean of Blood). 생존자들은 이 피 흘리는 심연을 탐사하기 위해 잠수함을 만들었고, 그 안을 조종할 단 하나의 영혼을 용접해 가두었다. 죄수(The Convict)는 ''아이언 렁(Iron Lung)''이라 불리는 작은 잠수함을 타고 피의 바다를 수색하는 임무에 투입된다. 하지만 이 공허 속에서 희망은 별빛만큼이나 허상일 뿐이다. 이것은 탐사가 아니다.INSERT INTO public.movies VALUES (201, 672, '해리 포터와 비밀의 방', '["Adventure", "Fantasy"]', 'Chris Columbus', '["Daniel Radcliffe", "Rupert Grint", "Emma Watson", "Kenneth Branagh", "Toby Jones"]', '해리 포터에겐 이번 여름방학이 별로 즐겁질 못했다. 마법이라면 질색을 하는 페투니아 이모와 버논 이모부의 구박도 그렇지만, 무엇보다 속상한 건 단짝이었던 론 위즐리와 헤르미온느 그레인저가 그 사이 자신을 까맣게 잊었는지 자신의 편지에 답장 한 통 없다는 것.  그러던 어느날 꼬마 집요정 도비가 해리의 침실에 나타나 뜻밖의 얘기를 한다. 호그와트 마법학교로 돌아가면 무서운 일을 당할 거라는 것. 도비는 해리를 학교에 못 가게 하려고 자신이 여태까지 론과 헤르미온느의 답장을 가로채 왔음을 고백한다. 그러나 도비와 더즐리 가족의 방해에도 불구, 해리는 론과 그의 형제들이 타고 온 하늘을 나는 자동차를 타고 이모집을 탈출, 따뜻한 가족애가 넘치는 론의 집으로 가는데...', 'https://image.tmdb.org/t/p/w500/bo8FuQPWKLqbg3WgAXYISkwrbZ9.jpg', 2002, 0, 0, '2026-06-06 13:25:04.080448', 'GB');
INSERT INTO public.movies VALUES (4165, 488623, '기억의 밤', '["Thriller", "Mystery", "Crime"]', 'Chang Hang-jun', '["Kang Ha-neul", "Kim Moo-yul", "Moon Sung-keun", "Na Young-hee", "Nam Myung-ryeol"]', '새 집으로 이사 온 날 밤, 정체불명의 괴한들에게 납치된 형 유석. 동생 진석은 형이 납치된 후 매일 밤 환청과 환각에 시달리며 불안해한다. 납치된지 19일째 되는 날 돌아온 유석은 그동안의 모든 기억을 잃었다고 말한다. 하지만 돌아온 뒤로 어딘가 변해버린 유석을 의심하던 진석은 매일 밤 사라지는 형을 쫓던 중 충격적인 사실과 마주하게 되는데...', 'https://image.tmdb.org/t/p/w500/pXHLaA2dvIfJ3NbslufKqvS48dt.jpg', 2017, 0, 0, '2026-06-08 06:27:55.252075', 'KR');
INSERT INTO public.movies VALUES (209, 121, '반지의 제왕: 두 개의 탑', '["Adventure", "Fantasy", "Action"]', 'Peter Jackson', '["Elijah Wood", "Ian McKellen", "Viggo Mortensen", "Sean Astin", "Andy Serkis"]', '9명의 반지원정대는 사우론의 세력에 맞서 반지를 지켜냈지만 반지 원정대는 뿔뿔이 흩어지게 된다. 메리와 피핀을 구하기 위해 우르크하이 군대를 추격하던 아라곤과 레골라스, 김리는 유령 숲에서 백색의 마법사로 부활한 마법사 간달프를 만나게 되고 사우론이 암흑세계의 두 개의 탑을 통합하여 점점 그 세력을 넓혀가고 있다는 사실을 듣게 된다. 이에 아라곤과 원정대는 중간계의 선한 무리의 통합을 이뤄 사우론의 세력을 견제해야 하는 큰 임무를 맡게 된다. 하지만 원수지간인 곤도르와 로한으로 나뉜 인간 종족의 통합은 쉽지 않고 게다가 로한의 왕마저 사루만에게 동화되는데...', 'https://image.tmdb.org/t/p/w500/zxZdTi3fA7aDxEOivmzZAY2bmTu.jpg', 2002, 0, 0, '2026-06-06 13:25:04.101208', 'US');
INSERT INTO public.movies VALUES (185, 22, '캐리비안의 해적: 블랙펄의 저주', '["Adventure", "Fantasy", "Action"]', 'Gore Verbinski', '["Johnny Depp", "Geoffrey Rush", "Orlando Bloom", "Keira Knightley", "Jack Davenport"]', '잭 스패로우는 10년 전의 반란 사건으로 자신의 배 블랙펄을 빼앗긴 해적 선장이다. 혼자 대양을 떠돌던 그는 자메이카의 로열포트에 이르러 유령선처럼 변해버린 블랙펄과 재회하게 된다. 아즈텍의 황금을 훔친 블랙펄의 선원들은 영원히 죽지 못하는 저주에 걸린 처지. 보물을 모두 제자리에 돌려놓고 피의 제물을 바쳐야만 고대 신들이 내린 저주를 풀 수 있다. 그들은 로열포트를 습격해 아즈텍의 마지막 목걸이를 가진 총독의 딸 엘리자베스를 납치하고, 엘리자베스를 사랑하는 어린 시절 친구 윌과 스패로우는 그 뒤를 쫓는데...', 'https://image.tmdb.org/t/p/w500/3ovejwQO4fKOWx4VgGBJeT8CKCn.jpg', 2003, 0, 0, '2026-06-06 13:25:03.326315', 'US');
INSERT INTO public.movies VALUES (4204, 465595, '달콤한섹스', '["Romance", "Drama"]', 'Park Sun-Uk', '["Lee Chae-dam", "Sin Seong-hoon", "Yoon Se-na", "Min Do-yoon", "Jang Ji-eun-I"]', '파티쉐를 꿈꿔왔던 능금, 현실은 남자친구의 학비셔틀~ 이젠 그만! (내 꿈을 찾을래~) 짜릿하고 달콤한 디저트로 유명한 유학파 파티쉐 우현, 오늘도 새로운 레시피를 얻기 위해 은밀한 섹스를 하게 되는데, 그에게는 섹스도 사랑도 달콤함을 찾아가는 과정일 뿐이다. 대학 선배인 우현의 연습생으로 들어간 그녀. 그녀와 우현의 공개할 수 없는 은밀하고 달콤한  디저트 수업이 시작되는데. 과연, 오늘은 어떤 섹스? 어떤 맛일까?', 'https://image.tmdb.org/t/p/w500/hkt25KjYmyuRchMpGUPhdEgxnd2.jpg', 2017, 0, 0, '2026-06-08 06:28:25.148501', 'KR');
INSERT INTO public.movies VALUES (195, 569094, '스파이더맨: 어크로스 더 유니버스', '["Animation", "Action", "Adventure", "Sci-Fi"]', 'Kemp Powers', '["Shameik Moore", "Hailee Steinfeld", "Brian Tyree Henry", "Luna Lauren Vélez", "Jake Johnson"]', '여러 성장통을 겪으며 새로운 스파이더맨이 된 마일스 모랄레스. 그 앞에 다른 평행세계의 스파이더우먼 그웬이 다시 나타난다. 모든 차원의 멀티버스 속 스파이더맨들을 만나게 되지만, 질서에 대한 신념이 부딪히며 예상치 못한 균열이 생기는데… 상상 그 이상을 넘어서는 멀티버스의 세계가 열린다!', 'https://image.tmdb.org/t/p/w500/lMWTlGr9jVUC18T515hPRKym5QQ.jpg', 2023, 0, 0, '2026-06-06 13:25:03.351199', 'US');
INSERT INTO public.movies VALUES (4169, 51608, '아저씨', '["Action", "Thriller", "Crime"]', 'Lee Jeong-beom', '["Won Bin", "Kim Sae-ron", "Kim Tae-hun", "Kim Hie-won", "Kim Seung-o"]', '불행한 사건으로 아내를 잃고 세상을 등진 채 전당포를 꾸려가며 외롭게 살아가는 전직 특수요원 태식. 찾아오는 사람이라곤 전당포에 물건을 맡기러 오는 사람들과 옆집소녀 소미뿐이다. 세상으로부터 버림받은 소미와 함께 보내는 시간이 많아지면서 태식과 소미는 서로 마음을 열며 친구가 되어간다.  그러던 어느 날 소미의 엄마가 범죄단체 연루되고 태식의 눈앞에서 소미가 납치되는데...', 'https://image.tmdb.org/t/p/w500/14QbjXp8m3LN9l1U4SoBWy441kr.jpg', 2010, 0, 0, '2026-06-08 06:27:57.981007', 'KR');
INSERT INTO public.movies VALUES (228, 950387, 'A MINECRAFT MOVIE 마인크래프트 무비', '["Family", "Fantasy", "Comedy", "Adventure"]', 'Jared Hess', '["Jason Momoa", "Jack Black", "Sebastian Eugene Hansen", "Emma Myers", "Danielle Brooks"]', '왕년의 게임 챔피언이었지만 지금은 폐업 직전의 게임샵 주인이 된 ''개릿''과 엄마를 잃고 낯선 동네로 이사 온 남매 ''헨리''와 ''나탈리'' 그리고 그들을 돕는 부동산 중개업자 ''던''. 이들은 ‘개릿’이 수집한 ‘큐브’가 내뿜는 신비한 빛을 따라가다 어느 폐광 속에 열린 포털을 통해 미지의 공간으로 빨려들어간다. 산과 나무, 구름과 달, 심지어 꿀벌까지 상상하는 모든 것이 네모난 현실이 되는 이곳은 바로 ‘오버월드’. 일찍이 이 세계로 넘어와 완벽하게 적응한 ‘스티브’를 만난 네 사람은 지하세계 ‘네더’를 다스리는 마법사 ‘말고샤’의 침공으로 ‘오버월드’가 위험에 빠졌다는 사실을 알게 된다. 현실 세계로 돌아가기 위해서는 일단 살아남아야 하는 법! 다섯 명의 ‘동글이’들은 ‘오버월드’를 구하기 위해 힘을 합치게 되는데…', 'https://image.tmdb.org/t/p/w500/k5aQ2TqKcQFwPoXHkpAGoKNVDLZ.jpg', 2025, 0, 0, '2026-06-06 13:25:04.857495', 'US');
INSERT INTO public.movies VALUES (254, 27098, '아름다운 청춘', '["Drama", "Romance"]', NULL, '[]', '학교 여선생인 비올라는 사춘기 소년인 자신의 학생 스틱의 사랑을 받게 된다. 처음에 비올라는 그저 그런 사춘기 소년의 짝사랑이려니 했지만, 결국은 스틱이 보내는 사랑을 받아들여 함께 사랑에 빠진다. 단지 감정적인 사랑으로서만 만나는 것이 아니라 적극적인 육체 접촉도 마다하지 않게 되고, 점점 더 서로의 육체에 탐닉하게 된다. 두 사람의 관계를 눈치챈 비올라의 남편은 현실에 순응하는 사람이고, 스틱은 그런 그녀의 남편에게 연민을 느낀다. 그러면서 스틱은 비올라에게서 점차 멀어져가고 비올라는 점점 더 스틱과의 관계에 집착하게 된다.', 'https://image.tmdb.org/t/p/w500/iIzl9GbCmk39Mgla3jnpRZLpQnC.jpg', 1995, 0, 0, '2026-06-06 13:25:05.635626', 'US');
INSERT INTO public.movies VALUES (4173, 587727, '가슴 큰 여자친구', '["Romance"]', 'Junsei', '["Yoo Jung", "Kang Min-sik", "Kim Wan- jin"]', '민철과 수희는 결혼을 앞두고 민철 아버지(대식)에게 인사를 드리러 간다. 대식은 예비 며느리인 수희를 반갑게 맞이하고 수희 또한 인자한 대식을 좋은 사람이라 여긴다.  하지만 결혼 전 성격차이로 민철과 수희는 파혼 되고… 결혼준비만 하던 수희는 곧 생활고를 격어….. 수희의 오랜 친구이자 벗인 민주가 일하는 키스방에서 일하게 된다.  어느 날과 마찬가지로 수희는 키스방에서 손님을 기다리는데…. 키스방 문으로 들어오는 손님인 대식과 마주치게 되는데…', 'https://image.tmdb.org/t/p/w500/tH1gyQaEEOEMLy9tUjc6iIcpE0S.jpg', 2019, 0, 0, '2026-06-08 06:28:01.448706', 'KR');
INSERT INTO public.movies VALUES (4176, 437542, '딸의 친구', '["Romance"]', 'Choi Woo-seong', '["Jeon Ji-hak", "Min Do-yoon", "Han Ga-hee", "Seo Won"]', '"전 연하는 싫어요" 원기는 오래 전 아내를 잃고 홀로 지방으로 내려와 펜션 일을 하고 있다. 그러던 어느 날 서울에서 대학생활을 하던 원기의 딸 은지와 친구인 세영이 방학동안 원기의 펜션에 놀러와 지내게 되고 원기는 딸의 친구인 세영이 죽은 자신의 아내와 너무도 닮은 모습에 자기도 모르게 점차 끌리게 된다. 그러던 중 세영의 도발적인 유혹에 원기는 넘지 말아야할 선을 넘어버리고 마는데...', 'https://image.tmdb.org/t/p/w500/bR1ID2VvQIHrWKdToWKc3mIpeyW.jpg', 2017, 0, 0, '2026-06-08 06:28:03.456325', 'KR');
INSERT INTO public.movies VALUES (4181, 1241624, '괴기열차', '["Horror", "Mystery"]', 'Tak Se-woong', '["Joo Hyun-young", "Jeon Bae-soo", "Choi Bo-min", "Kim Ji-in", "Kim Woo-kyum"]', '사람들이 사라지는 광림역. 조회수가 간절한 공포 유튜버 다경. 전국 최다 실종 사건 발생지인 광림역을 둘러싼 괴기한 소문을 업로드하고 단숨에 최고 조회수를 기록한다. 모두의 만류에도 조회수를 향한 다경의 욕심은 멈추지 않고 광림역을 둘러싼 충격적인 비밀을 듣게 되는데…', 'https://image.tmdb.org/t/p/w500/2tsSBC8v47oBbdKkyGmvMWy2IhK.jpg', 2025, 0, 0, '2026-06-08 06:28:07.081367', 'KR');
INSERT INTO public.movies VALUES (265, 1011985, '쿵푸팬더 4', '["Action", "Adventure", "Animation", "Comedy", "Family", "Fantasy"]', 'Mike Mitchell', '["Jack Black", "Awkwafina", "Viola Davis", "Dustin Hoffman", "Bryan Cranston"]', '마침내 내면의 평화… 냉면의 평화…가 찾아왔다고 믿는 용의 전사 ‘포’ 이젠 평화의 계곡의 영적 지도자가 되고, 자신을 대신할 후계자를 찾아야만 한다. “이제 용의 전사는 그만둬야 해요?” 용의 전사로의 모습이 익숙해지고 새로운 성장을 하기보다 지금 이대로가 좋은 ‘포’ 하지만 모든 쿵푸 마스터들의 능력을 그대로 복제하는 강력한 빌런 ‘카멜레온’이 나타나고 그녀를 막기 위해 정체를 알 수 없는 쿵푸 고수 ‘젠’과 함께 모험을 떠나게 되는데… 포는 가장 강력한 빌런과 자기 자신마저 뛰어넘고 진정한 변화를 할 수 있을까?', 'https://image.tmdb.org/t/p/w500/fvtswV04JfLGxxrjxW4t4j8bPhx.jpg', 2024, 0, 0, '2026-06-06 13:25:06.390044', 'US');
INSERT INTO public.movies VALUES (4208, 1139817, '무도실무관', '["Action", "Comedy", "Crime"]', 'Jason Kim', '["Kim Woo-bin", "Kim Sung-kyun", "Lee Hyun-gul", "Park Ji-yeol", "Lee Jung-ok"]', '힘든 사람을 그냥 지나치지 못하는 무술 유단자 이정도. 보호관찰관 김선민이 그런 정도를 알아보고 ‘무도실무관’을 권한다. 이제 전자발찌 대상자를 감시하며 범죄를 예방하는 그들의 활약이 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/jiihI4Fmu8fUhXllfPX4F8VPG2N.jpg', 2024, 0, 0, '2026-06-08 06:28:28.110764', 'KR');
INSERT INTO public.movies VALUES (83, 755898, '우주전쟁', '["Sci-Fi", "Thriller"]', 'Rich Lee', '["Ice Cube", "Eva Longoria", "Clark Gregg", "Iman Benson", "Henry Hunter Hall"]', '전설적인 동명 소설을 새롭게 재해석한 이번 작품은 거대한 침공의 서막을 알린다. 에바 롱고리아와 전설적인 래퍼이자 배우 아이스 큐브, 그리고 마이클 오닐과 이만 벤슨이 합류해, 기술과 감시, 사생활이라는 현대적 주제를 아우르는 짜릿한 우주급 모험을 선보인다.', 'https://image.tmdb.org/t/p/w500/yvirUYrva23IudARHn3mMGVxWqM.jpg', 2025, 0, 0, '2026-06-06 13:24:59.460318', 'US');
INSERT INTO public.movies VALUES (309, 72190, '월드워 Z', '["Action", "Horror", "Sci-Fi"]', 'Marc Forster', '["Brad Pitt", "Mireille Enos", "Daniella Kertesz", "James Badge Dale", "Ludi Boeken"]', '세계 곳곳에서 원인을 알 수 없는 이변이 일어나기 시작하고, 정체 불명의 존재들의 무차별적 공격으로 도시는 순식간에 아수라장으로 변한다. 군인 출신으로 전시 경험이 풍부하고 위기 대처 능력이 뛰어난 전직 UN 소속 조사관 제리는 위험한 상황에서 가까스로 가족들과 탈출하는데 성공하고 이제껏 본 적 없는 인류 최대의 위기 앞에 대재난에 맞설 최후의 적임자로 지목된다. 마침내 제리는 전 세계를 위협하는 거대한 정체들과 직면하게 되고, 그들의 끊임없는 공격에 맞서 필사의 사투를 벌이게 되는데...', 'https://image.tmdb.org/t/p/w500/cnUlKvIXbTmDnyp6pIGIMgdl332.jpg', 2013, 0, 0, '2026-06-06 13:25:07.950792', 'US');
INSERT INTO public.movies VALUES (4207, 636173, '드림', '["Comedy", "Drama"]', 'Lee Byeong-heon', '["Park Seo-jun", "IU", "Kim Jong-soo", "Ko Chang-seok", "Jung Seung-kil"]', '아직 탈락은 이르다! 세계 대회 출전을 위해 치열한 노력과 헌신으로 훈련에 임하는 홈리스 선수들. 감독의 성격이 조금 괴팍하지만, 그래도 포기란 없다.', 'https://image.tmdb.org/t/p/w500/yEEwn4AfgVXEyjKsJ6w6qSaInez.jpg', 2023, 0, 0, '2026-06-08 06:28:27.367014', 'KR');
INSERT INTO public.movies VALUES (4183, 200085, '감기', '["Action", "Sci-Fi", "Thriller"]', 'Kim Sung-soo', '["Jang Hyuk", "Soo Ae", "Park Min-ha", "Yoo Hai-jin", "Don Lee"]', '밀입국 노동자들을 분당으로 실어 나른 남자가 원인불명의 바이러스에 감염되어 사망한다. 환자가 사망한지 채 24시간이 되지 않아 분당의 모든 병원에서 동일한 환자들이 속출한다. 사망자들은 기하급수적으로 늘어나지만 분당의 시민들은 무방비상태로 바이러스에 노출된다. 감염의 공포가 대한민국을 엄습하고, 호흡기를 통해 초당 3.4명 감염, 36시간 내 사망에 이르는 사상 최악의 바이러스에 정부는 2차 확산을 방지하기 위해 국가 재난사태를 발령, 급기야 도시 폐쇄라는 초유의 결정을 내린다. 피할 새도 없이 격리된 사람들은 일대혼란에 휩싸이게 되고, 대재난 속 사랑하는 이들을 구하기 위한 사람들과 죽음에서 살아 남기 위한 사람들은 목숨을 건 사투를 시작하는데…', 'https://image.tmdb.org/t/p/w500/7fQlPXebfjEqjysW3rv4RyNplih.jpg', 2013, 0, 0, '2026-06-08 06:28:08.414801', 'KR');
INSERT INTO public.movies VALUES (4206, 391423, '입영전야', '["Romance"]', 'Yoo Seung-taek', '["Kim Seung-wook", "Han Seol-hwa", "Heo Yoon-joo", "Kim Sang-cheol-I", "Lim Hyeong-soon"]', '입대 3일 전. 군대를 안 갈 수 없다면 “도장”이라도 제대로 찍어야 한다는 일념으로 여기저기 들이대보는 ‘승욱’. 하지만 섹시한 과 선배 ‘소윤’도, 소개팅으로 만난 청순녀 ‘일홍’도 도무지 쉽게 넘어오지 않는다. 마침내 다가온 입영전야. 초조해진 ‘승욱’은 친구들의 도움을 받아 무슨 수를 써서라도 입대 전에 두 여자와 함께 하는 화끈한 밤을 보내겠다고 결심한다. 피 끓는 청춘들의 ‘도장’ 찍기 프로젝트가 지금 시작한다.', 'https://image.tmdb.org/t/p/w500/sITpyNP0k8GkW9NVAhCgHJnlJPT.jpg', 2016, 0, 0, '2026-06-08 06:28:26.627221', 'KR');
INSERT INTO public.movies VALUES (286, 335984, '블레이드 러너 2049', '["Sci-Fi", "Drama"]', 'Denis Villeneuve', '["Ryan Gosling", "Harrison Ford", "Ana de Armas", "Dave Bautista", "Robin Wright"]', '인간과 리플리컨트가 혼재된 2049년. 인간의 통제를 벗어난 리플리컨트를 쫓는 블레이드 러너 K는 임무 수행 도중 약 30년 전 여자 리플리컨트의 유골을 발견하고 충격적으로 출산의 흔적까지 찾아낸다. 리플리컨트가 출산까지 가능하다는 사실이 알려지면사회에 큰 혼란이 야기되므로 이를 덮으려는 경찰 조직과, 그 비밀의 단서를 찾아내 더욱 완벽한 리플리컨트를 거느리고 세상을 장악하기 위해 K를 쫓는 니안더 월레스. 리플리컨트의 숨겨진 진실에 접근할수록 점차 정체성의 혼란을 겪게 되는 K는 과거 블레이드 러너였던 릭 데커드를 만나 전혀 상상치 못한 진실을 마주하게 되는데...', 'https://image.tmdb.org/t/p/w500/fJZmCJpLeBFKktLFEIKPEhllWlU.jpg', 2017, 0, 0, '2026-06-06 13:25:07.165577', 'US');
INSERT INTO public.movies VALUES (274, 1087192, '드래곤 길들이기', '["Fantasy", "Family", "Action", "Adventure"]', 'Dean DeBlois', '["Mason Thames", "Nico Parker", "Gerard Butler", "Nick Frost", "Gabriel Howell"]', '수백년간 지속되어온 바이킹과 드래곤의 전쟁. 드래곤을 없애는 것이 삶의 모든 목적인 바이킹들과 다른 신념을 가진 ''히컵''은 무리 속에 속하지 못하고 족장인 아버지에게도 인정받지 못한다. 그러던 어느 날, 히컵은 베일에 싸인 전설의 드래곤 나이트 퓨어리인 ''투슬리스''와 만나게 되고, 드래곤을 죽이라는 바이킹의 신념을 깨고 ''투슬리스''와 친구가 된다. 하지만 드래곤을 죽여야 된다고 믿는 바이킹 족과 모든 드래곤을 위협하는 더 거대한 존재와 맞닥뜨리게 된 ''히컵''과 ''투슬리스''. 세상을 변화시키기 위한 특별한 여정을 시작하게 되는데... 다르다는 건, 특별하다는 것. 세상을 바꿀 우리들의 모험이 시작된다!', 'https://image.tmdb.org/t/p/w500/frXkpt1dLKO3iDbmBsjQUKseLiS.jpg', 2025, 0, 0, '2026-06-06 13:25:06.411017', 'US');
INSERT INTO public.movies VALUES (4209, 408349, '내 이웃의 아내', '["Romance", "Drama"]', 'Jung Dae-man', '["Kim Jin-seon", "Kim Geon", "Min Jae-ha", "Im So-mi", "Oh Mi-seon"]', '남편이 출장을 간 사이, 윤정은 딸 아이를 친정에 맡기고 이웃 집 남자와 뜨거운 밀월 여행을 떠난다. 법, 도덕, 상식 같은 건 모두 다 잊어버리고 밥 먹다가 하고 씻다가 하고 걷다가 하고 테니스 치다가 하는, 오로지 본능만을 느끼는 두 남녀의 2박 3일. 그 끝날 줄 모르는 욕정이 그녀의 전신을 휘감는다.', 'https://image.tmdb.org/t/p/w500/qpW0myP5nCSZbSmOS0IhMJYXVkF.jpg', 2016, 0, 0, '2026-06-08 06:28:28.874646', 'KR');
INSERT INTO public.movies VALUES (321, 30709, '캘리포니아 돌스', '["Comedy", "Drama"]', NULL, '[]', '해리는 2인조 여자 레슬링팀 ‘캘리포니아 돌스’의 쩨쩨하고 인색한 매니저다. 아이리스와 몰리 두 사람으로 이루어진 ‘캘리포니아 돌스’는 해리와 함께 이 도시에서 저 도시로 떠돌며 시시한 게임을 계속하고 있지만, 언젠가는 프로로 화려하게 데뷔하리라는 꿈을 가지고 있다. 그러던 어느 날 해리가 세계챔피언 ‘톨레도 타이거스’와의 비공식게임을 따온다. 돌스는 그들을 이기지만, 두 번째 게임에서는 보기 좋게 지고 만다. 그러나 돌스의 실력을 인정한 타이거스는 리노에서 열리는 타이틀전에 돌스를 참가시킨다. 마침내 돌스는 결승전에서 타이거스와 일대 접전을 벌이게 되고, 여기에 마피아에게 뇌물을 받은 심판까지 가세하여 게임은 더욱 치열해진다.', 'https://image.tmdb.org/t/p/w500/qv0WuNiP93ahEEYDFwC5DcjJmOS.jpg', 1981, 0, 0, '2026-06-06 13:25:08.678421', 'US');
INSERT INTO public.movies VALUES (332, 581528, '악인전', '["Action", "Crime", "Thriller"]', 'Lee Won-tae', '["Don Lee", "Kim Moo-yul", "Kim Sung-kyu", "Heo Dong-won", "You Chea-myung"]', '중부권을 쥐고 흔드는 제우스파 조직의 보스 장동수, 비 내리던 밤 한적한 도로에서 접촉사고를 위장해 접근한 남자에게 불의의 습격을 받는다. 격투 끝에 가까스로 목숨은 건졌지만 조직 보스의 권위와 자존심은 무너지고 만다. 바짝 독이 오른 장동수 앞에 형사 정태석이 나타나 그를 찌른 놈이 연쇄살인범이라며 그날 밤 기억나는 것을 모두 말하라고 한다. 장동수는 얼굴 없는 연쇄살인마와 마주쳐 살아남은 유일한 생존자이자 목격자였다. 자신의 몸에 손 댄 그 놈을 살 떨리게 잡고 싶은 조직의 보스 장동수와 미치도록 범인을 잡고 싶은 강력반 미친개 정태석, 두 사람은 장동수의 조직력과 자본, 정태석의 정보력과 기술력을 이용해 "K"라 불리는 연쇄살인마를 함께 잡기로 하는데...', 'https://image.tmdb.org/t/p/w500/az4OVqXbFVaHoZlktcm7oCm0LZo.jpg', 2019, 0, 0, '2026-06-06 13:25:08.704769', 'KR');
INSERT INTO public.movies VALUES (72, 840464, '그린랜드 2: 마이그레이션', '["Adventure", "Thriller", "Sci-Fi"]', 'Ric Roman Waugh', '["Gerard Butler", "Morena Baccarin", "Roman Griffin Davis", "Tommie Earl Jenkins", "Trond Fausa Aurvåg"]', '혜성 충돌로 문명이 붕괴된 지 5년 후, 방사능 폭풍을 피해 지하 벙커에서 살아남은 인류는 끝이 보이지 않는 지하 생활을 이어가고 있다. 점점 심해지는 지진과 고갈되어 가는 보급품으로 벙커는 붕괴 위기에 처하고, 존과 그의 가족들은 가까스로 탈출해 폐허가 된 유럽 대륙으로 향한다. 무너진 도시, 극한의 환경, 그리고 예측할 수 없는 생존자들의 위협 속에서 인류 최후의 희망의 땅이라 불리는 ‘크레이터’를 향한 위험한 여정이 시작되는데...!', 'https://image.tmdb.org/t/p/w500/63MYZJKDgg1jg1ISo9QUiE33lrT.jpg', 2026, 0, 0, '2026-06-06 13:24:58.709533', 'US');
INSERT INTO public.movies VALUES (4210, 1172507, '장손', '["Drama", "Mystery"]', 'Oh Jung-min', '["Kang Seung-ho", "Woo Sang-jeon", "Son Sook", "Cha Mi-kyeong", "Oh Man-seok"]', '3대 대가족이 모두 모인 제삿날. 일가의 명줄이 달린 가업 두부공장 운영 문제로 가족들이 다투는 와중, 장손 성진은 그 은혜로운 밥줄을 잇지 않겠다고 선언한다. 설상가상 갑작스레 맞닥뜨린 예기치 못한 이별로 가족 간의 갈등은 극에 달하는데…', 'https://image.tmdb.org/t/p/w500/sLJfFRhu3tiXyHQAWGoiKc5WKiH.jpg', 2024, 0, 0, '2026-06-08 06:28:29.613434', 'KR');
INSERT INTO public.movies VALUES (330, 99861, '어벤져스: 에이지 오브 울트론', '["Action", "Adventure", "Sci-Fi"]', 'Joss Whedon', '["Robert Downey Jr.", "Chris Hemsworth", "Mark Ruffalo", "Chris Evans", "Scarlett Johansson"]', '토니 스타크는 뉴욕전쟁 때와 같은 사태가 벌어지지 않도록 한때 가동하려다 중단된 휴면 상태의 평화 유지 프로그램을 작동 시키려 한다. 배너 박사와 함께 지구를 지킬 최강의 인공지능 울트론을 탄생시키게 되지만, 울트론은 예상과 다르게 지배를 벗어나 폭주하기 시작하고 어벤져스는 지구의 운명이 걸린 거대한 시험대에 오르게 된다. 울트론이 자신을 복제해 위협을 가하자 이를 저지하기 위해 아이언맨, 캡틴 아메리카, 토르, 헐크, 블랙위도우, 호크아이 등으로 구성된 어벤져스와 새로 합류하게 되는 퀵 실버, 스칼렛 위치 남매와 불안한 동맹을 맺는다.', 'https://image.tmdb.org/t/p/w500/y8pY5MIzpPAnF5vYUNm1tw1AzL3.jpg', 2015, 0, 0, '2026-06-06 13:25:08.700204', 'US');
INSERT INTO public.movies VALUES (4184, 142093, '애인', '["Romance", "Drama"]', 'Kim Eun-tae', '["Sung Hyun-ah", "Cho Dong-hyuk", "Kim Ye-ryeong", "Ji Dae-han", "Kil Hae-yeon"]', '춥지 않은 날씨임에도 단추를 목 끝까지 맨, 한치의 흐트러짐도 없는 여자. 여자는 같은 엘리베이터를 탄 매력적인 남자에게 묘한 기분을 느낀다. 같은날 헤이리에서의 또 한번의 우연, 소심하고 조용한 자신에게 가볍게 작업을 걸어오는 남자가 싫지 않다. 당당하고 유쾌한 남자에게 너무도 쉽게 끌려버린 그녀는 즉흥적으로 섹스를 허락하게 되는데...  7년을 사귄 남자가 있고, 그와의 결혼을 한달 앞두고 있는데 처음본 남자에게 자꾸 끌리는 까닭은 무엇일까? 고민을 하기엔 그와 보낼 수 있는 시간이 너무도 짧다. 첫 눈에 상대를 알아보고, 단숨에 사랑을 느끼고 사랑을 확인하는 여자와 남자…. 하루라는 짧은 시간 동안 서로에게 빠져버린 여자와 남자, 과연 내 남자 모르게 애인을 가슴 깊이 숨겨둘 수 있을까?', 'https://image.tmdb.org/t/p/w500/b7SAyFvG1hCnCdA3FbVeJFPlWfQ.jpg', 2005, 0, 0, '2026-06-08 06:28:09.097362', 'KR');
INSERT INTO public.movies VALUES (387, 1865, '캐리비안의 해적: 낯선 조류', '["Adventure", "Action", "Fantasy"]', 'Rob Marshall', '["Johnny Depp", "Penélope Cruz", "Geoffrey Rush", "Ian McShane", "Kevin McNally"]', '부두교의 주술을 부리던  검은 수염은 다리가 한쪽인 남자에게 죽게 된다는 예언을 듣게 된다. 자신의 수명을 늘리기 위해 검은 수염은 젊음의 샘을 찾으러 떠나고, 바르보사 또한 검은수염에게 복수를 하기 위해 그를 뒤쫒는다. 한편 영국에서 블랙펄의 선장이 선원을 모집한다는 소문을 듣게 된 잭 스패로우는 자신을 사칭하는 사기꾼을 잡으려다 영국 왕실에 체포되고, 영국의 국왕은 잭 스패로우에게 젊음의 샘으로 가는 길을 안내하라고 명령하고, 이에 필요한 선장과 배, 선원을 모두 내 주겠다고 하는데...', 'https://image.tmdb.org/t/p/w500/osJVVjkHmoO5WoJfbBsImYrKWIb.jpg', 2011, 0, 0, '2026-06-06 13:25:11.017517', 'GB');
INSERT INTO public.movies VALUES (4211, 1166580, '내 아내를 임신시켜줘', '["Romance", "Drama"]', 'Han Dong-yeon', '["Jin Seo-yool", "Cha Myung-Hoon", "Lee Do-jin", "Ga Won"]', '주승기와 유아린은 아이를 갖기 위해 필사적으로 하루에도 몇 번씩 부부관계를 갖지만 임신이 되질 않아 검사를 받고, 검사 결과 승기의 불임이 원인이었다. 승기는 고민 끝에 불알친구인 윤우에게 아린과 관계를 가져달라고 부탁하고, 집요한 설득 끝에 아린과 윤우는 관계를 가진다. 이후 승기는 윤우와 아린의 관계를 의심하기 시작하는데...', 'https://image.tmdb.org/t/p/w500/rXkqccTVVCFRCTXNEBAFBtGn000.jpg', 2023, 0, 0, '2026-06-08 06:28:30.392881', 'KR');
INSERT INTO public.movies VALUES (409, 949, '히트', '["Crime", "Drama", "Action"]', NULL, '[]', '닐 맥컬리(로버트 드 니로)는 빈틈없고 치밀하게 일을 처리하는 프로 범죄자지만 따뜻한 가정의 온기를 동경한다. 반면 LA 경찰국 강력계 수사반장인 빈센트 한나(알 파치노)는 두 번의 이혼 경력에 이어 세 번째 결혼마저 위기를 맞은 불안정한 사생활의 소유자지만, 일에 있어서는 굶주린 짐승처럼 집요하게 쫓아가 결국에는 해결을 보고 만다. 닐과 그의 동료들이 특급우편 발송 차량을 습격하는 대규모 도난 사건을 일으켜 증권 투자사 간부의 고액 채권을 강탈한다. 사건 발생 직후부터 빈센트는 예리한 추리력으로 한걸음씩 닐에게 접근해간다. 닐 역시 빈센트의 추격을 눈치채는데...', 'https://image.tmdb.org/t/p/w500/p0uAcyDgBXtCSXZdnacwr9OGcIH.jpg', 1995, 0, 0, '2026-06-06 13:25:11.782561', 'US');
INSERT INTO public.movies VALUES (88, 1246049, '드라큘라: 어 러브 테일', '["Horror", "Fantasy", "Romance"]', 'Luc Besson', '["Caleb Landry Jones", "Zoë Bleu Sidel", "Christoph Waltz", "Matilda De Angelis", "Ewens Abid"]', '거장 뤽 베송이 선사하는 전설의 화려한 부활, 그 태초의 이야기.INSERT INTO public.movies VALUES (4197, 235704, '동창생', '["Action", "Thriller", "Drama"]', 'Park Hong-soo', '["T.O.P", "Han Ye-ri", "Yoon Je-moon", "Cho Seong-ha", "Kim You-jung"]', '명훈은 남파공작원인 아버지의 누명으로, 여동생 혜인과 단 둘이 살아 남아 요덕 수용소에 감금된다. 그 곳에서 그는 정찰국 소속 장교 문상철에게 동생을 구하려면 남으로 내려가 공작원이 되라는 거절할 수 없는 제안을 받는다. 동생을 지키기 위해, 고등학생 강대호로 위장해 어떤 지령도 마다하지 않던 명훈은 동생과 같은 이름에 늘 혼자인 혜인을 눈 여겨 보게 된다. 그러나 시간이 지날수록 그의 임무는 위험해져 가는데...', 'https://image.tmdb.org/t/p/w500/ToZGJadpR5wQjy1rpuzgNZqYmw.jpg', 2013, 0, 0, '2026-06-08 06:28:19.846835', 'KR');
INSERT INTO public.movies VALUES (422, 207, '죽은 시인의 사회', '["Drama"]', 'Peter Weir', '["Robin Williams", "Robert Sean Leonard", "Ethan Hawke", "Josh Charles", "Gale Hansen"]', '1859년에 창립된 미국의 명문 사립학교인 웰튼 고등학교의 새 학기를 맞아 신입생들도 들어오고, 이 학교 출신인 새로운 영어 교사 존 키팅(로빈 윌리엄스)도 부임한다. 키팅 선생은 학생들에게 관습에 맞서고 자신의 삶을 남다르게 가꾸라며 새로운 학습 방법으로 학생들을 지도하며 학생들에게 신선한 충격을 준다. 닐(로버트 숀 레오나드)은 키팅 선생을 캡틴이라 부르며 따르게 되고, 몇몇 학생들과 함께 죽은 시인의 사회라는 시낭독 클럽을 조직한다. 닐과 그의 친구들은 엄격한 학교 규율을 어기고 서클에 참여하면서 키팅 선생을 통해 참된 인생이 무엇인지를 조금씩 느끼게 되는데...', 'https://image.tmdb.org/t/p/w500/41AJ4X5TRWpECsiMIKS8so4MSsD.jpg', 1989, 0, 0, '2026-06-06 13:25:12.525791', 'US');
INSERT INTO public.movies VALUES (4212, 581526, '다만 악에서 구하소서', '["Crime", "Action", "Drama"]', 'Hong Won-chan', '["Hwang Jung-min", "Lee Jung-jae", "Park Jeong-min", "Moon Choi", "Oh Dae-hwan"]', '태국에서 충격적인 납치사건이 발생하고 마지막 청부살인 미션을 끝낸 암살자 인남은 그것이 자신과 관계된 것임을 알게 된다. 인남은 곧바로 태국으로 향하고, 조력자 유이를 만나 사건을 쫓기 시작한다. 한편, 자신의 형제가 인남에게 암살당한 것을 알게 된 레이. 무자비한 복수를 계획한 레이는 인남을 추격하기 위해 태국으로 향하는데...', 'https://image.tmdb.org/t/p/w500/xYnL0kA0V7aDvg8wupmWQbdgb9a.jpg', 2020, 0, 0, '2026-06-08 06:28:31.957966', 'KR');
INSERT INTO public.movies VALUES (431, 1193501, '휘슬', '["Horror", "Mystery"]', NULL, '[]', '"죽음의 휘파람, 그 소리를 불어서는 안 됐다"INSERT INTO public.movies VALUES (93, 1630423, '친애하는 나의 킬러', '["Action", "Drama", "Romance"]', NULL, '[]', '희귀 혈액형 때문에 쫓기던 소녀가 암살자 가족의 손에 길러진다. 그런데 복수심에 불타는 적이 그녀의 혈액을 노리고 다시 돌아오자, 그녀는 사랑하는 이와 함께 싸워 영원히 자유를 쟁취하기로 결심한다.INSERT INTO public.movies VALUES (4198, 849869, '길복순', '["Action", "Drama", "Thriller", "Crime"]', 'Byun Sung-hyun', '["Jeon Do-yeon", "Sul Kyung-gu", "Kim Si-a", "Esom", "Koo Kyo-hwan"]', '청부살인이 본업이지만 겉으로 보기에는 평범한 이벤트 회사인 MK 소속 킬러 길복순은 작품은 반드시 완수해 내는 성공률 100%의 킬러이자, 10대 딸을 둔 엄마다. 업계에서는 아무도 범접할 수 없는 에이스지만, 딸 재영과의 관계는 서툴기만 한 싱글맘인 그는 자신과 딸 사이의 벽을 허물기 위해 퇴사까지 결심한다. MK 대표 차민규의 재계약 제안의 답을 미룬 채, 마지막 작품에 들어간 복순은 임무에 숨겨진 진실을 알게 된 후, 회사가 허가한 일은 반드시 시도해야 한다는 규칙을 어기게 된다. 그 소식을 들은 MK는 물론, 모든 킬러들의 타겟이 되고야 마는데…', 'https://image.tmdb.org/t/p/w500/eDXV9K4vBRULyCNYDVjeOBNZq3E.jpg', 2023, 0, 0, '2026-06-08 06:28:20.589633', 'KR');
INSERT INTO public.movies VALUES (493, 329865, '컨택트', '["Drama", "Sci-Fi", "Mystery"]', NULL, '[]', '어느 날 전 세계 12개 지역에 외계 비행물체 셸이 동시다발로 출현한다. 450m에 달하는 거대 비행체가 가만히 서 있을 뿐 어떤 행동도 하지 않자 각국 정부는 각자의 방식으로 외계인과 접촉을 시작하지만, 완전히 다른 언어 체계 때문에 첫 단계부터 난항을 겪는다. 미국 정부의 요청을 받은 언어학자 루이스와 물리학자 이안은 말과 글이 통하지 않는 상황에서, 신체의 모든 기관과 감정을 이용해 미지의 생명체와 대화를 시도하고 서로의 문자를 배워나간다. 마침내 대화의 물꼬가 트이게 되지만 그때부터 루이스는 이해하기 어려운 환상을 연이어 보기 시작하는데...', 'https://image.tmdb.org/t/p/w500/yHEMUTIYZFHN3jjkKmTFrvhj64a.jpg', 2016, 0, 0, '2026-06-06 13:25:14.886892', 'US');
INSERT INTO public.movies VALUES (482, 49521, '맨 오브 스틸', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '무리한 자원 채취로 크립톤 행성의 종말이 다가오자 조드 장군은 반란을 일으켜 자신들만의 왕국을 건설하려 한다. 이에 반대한 조엘은 크립톤인의 유전자 정보가 담긴 코덱스를 빼돌려 이를 갓 태어난 자신의 아들 칼엘과 함께 지구로 보내고, 반란에 실패한 조드 장군은 감옥에 갇힌다. 지구에 도착한 칼엘은 뒤늦게 자신의 정체를 알아내지만 감옥에서 탈출한 조드 장군의 공격을 받는다. 조드 장군은 코덱스를 되찾아 지구에 새로운 왕국을 건설하려 하고클라크 켄트는 자신을 그토록 괴롭혔던 지구인을 지키기 위해 조드 장군과 전면 승부를 벌인다.', 'https://image.tmdb.org/t/p/w500/8Qx9fp2lZJU4v67jks6MmOMBCQg.jpg', 2013, 0, 0, '2026-06-06 13:25:14.856677', 'US');
INSERT INTO public.movies VALUES (480, 855, '블랙 호크 다운', '["Action", "History"]', NULL, '[]', 'UN 평화유지작전의 일환으로 1993년 동아프리카 소말리아의 수도 모가디슈에 파견된 최정예 미군 부대원들이 소말리아 민병대에 의해 공습당하면서 19명의 사상자를 낸다. 당시 소말리아에는 UN이 제공하는 구호식량을 착취할 목적으로 동포를 굶어 죽이는 민병대장이 전횡을 휘두르고 있었고, UN은 정예부대를 파견해 민병대장의 두 최고 부하를 납치하려다 실패한다. 무적의 전투헬기 블랙 호크 슈퍼 61과 블랙 호크 슈퍼 64가 소말리아 민병대에 의해 격추당하고, 제임스 장군은 단 한명의 생존자도, 단 한점의 살점도 남기지 말라고 명령, 최후의 순간까지 자존심을 건 전투를 펼치는데...', 'https://image.tmdb.org/t/p/w500/slmD4lDBrQaH68hAYQZLDOZ0Bcz.jpg', 2001, 0, 0, '2026-06-06 13:25:14.113866', 'US');
INSERT INTO public.movies VALUES (505, 283995, '가디언즈 오브 갤럭시 Vol. 2', '["Sci-Fi", "Adventure", "Action"]', NULL, '[]', '타노스에 맞서 은하계를 구하고 최고의 해결사로 등극한 스타로드 일행. 하지만 소버린 행성의 여사제 아이샤를 돕던 중 옛버릇을 고치지 못하고 행성의 배터리를 훔쳤다가 소버린 종족에 쫓기는 신세가 된다. 그 과정에서 피터의 아버지 에고가 그들을 돕는다. 아픈 엄마와 어린 자신을 버리고 떠난 아버지에 대한 원망이 컸던 피터는 에고의 행성에서 아버지의 능력을 확인하곤 그 힘에 이끌린다. 하지만 가모라는 에고의 행성에서 이상한 기운을 감지한다. 한편 반란군에 의해 위기에 처한 욘두는 로켓과 그루트의 도움으로 목숨을 구한다.', 'https://image.tmdb.org/t/p/w500/uDuwGhQgffd5GQ695oUfy5oZGqP.jpg', 2017, 0, 0, '2026-06-06 13:25:15.678084', 'US');
INSERT INTO public.movies VALUES (481, 533533, '트론: 아레스', '["Sci-Fi", "Adventure", "Action"]', NULL, '[]', '가상 세계에서 창조된 존재를 현실 세계로 끌어올 수 있는 시대. 그곳에서 탄생한 AI 최종 병기 아레스는 초인적인 힘과 속도, 고도 지능으로 설계되어 무한히 재생될 수 있지만 기술의 한계로 현실 세계에 단 29분만 머무를 수 있다. 그러던 중, 세계 최고의 프로그래머 이브 킴은 기술의 한계를 넘어설 해답을 발견하게 되고 아레스가 점차 통제를 벗어나 자신만의 목적을 향해 움직이기 시작하자 인류는 역사상 한 번도 경험한 적 없는 최악의 위기에 처하게 되는데…', 'https://image.tmdb.org/t/p/w500/4nJcUMpWgnIPZPJ13TWKRxAdY9U.jpg', 2025, 0, 0, '2026-06-06 13:25:14.853896', 'US');
INSERT INTO public.movies VALUES (510, 4348, '오만과 편견', '["Drama", "Romance"]', 'Joe Wright', '["Keira Knightley", "Matthew Macfadyen", "Brenda Blethyn", "Rosamund Pike", "Carey Mulligan"]', '베넷 가의 다섯 자매 중 둘째인 엘리자베스는 사랑하는 사람과의 결혼을 믿는 자존심 강하고 영리한 소녀이다. 부유하고 명망있는 가문의 신사 빙리와 그의 친구 다아시가 여름 동안 대저택에 머물게 되고, 댄스 파티에서 처음 만난 엘리자베스와 다아시는 서로에게서 눈을 떼지 못한다. 다아시는 아름답고 지적인 그녀의 매력에 점점 빠져들고, 폭우가 쏟아지는 날 비바람이 몰아치는 언덕에서 가슴 속 깊은 곳에 담아둔 뜨거운 사랑을 그녀에게 고백한다. 하지만 다아시가 빙리와 제인의 결혼을 제인이 명망있는 가문 출신이 아니라는 이유로 반대한 것을 알게 되자, 그를 오만하고 편견에 가득 찬 속물로 여기며 외면하는데...', 'https://image.tmdb.org/t/p/w500/rgKfvG0PgJBIPR6cNICukRnfMga.jpg', 2005, 0, 0, '2026-06-06 13:25:15.691396', 'GB');
INSERT INTO public.movies VALUES (4200, 288418, '밀애', '["Romance", "Drama"]', 'Kim Min-joon-I', '["Hwang Bo-wook", "Yoo Ra-seong", "Kim Bo-ri", "Kim Neul-me", "Jo Eun-seo"]', '모든 걸 다 갖춘 최고의 큐레이터 윤희는 전시회 준비 과정에서 최근 각광 받고 있는 사진 작가 형석을 만나게 된다 . 한 눈에 형석에게 호감을 느낀 윤희는 그에게 100일간의 섹스 게임을 제안한다. 한국판 ''나인 하프 위크''의 탄생! 위험할수록 더 짜릿한 그들의 사랑은 오로지 본능이 지배할 뿐! 이제 그들에게 룰 따위는 존재하지 않는다.', 'https://image.tmdb.org/t/p/w500/2Swy1OST9sY6gW1rPgBD7kAPTu8.jpg', 2014, 0, 0, '2026-06-08 06:28:22.106229', 'KR');
INSERT INTO public.movies VALUES (516, 348893, '보이카: 언디스퓨티드 파이널', '["Action", "Drama", "Thriller", "Crime"]', NULL, '[]', '‘유리 보이카’는 챔피언 벨트만을 노리는 세계 최고의 파이터. 그는 부다페스트에서 열리는 유럽지부 챔피언십에 나가기 위해 경기를 하던 중 사고로 상대 선수를 죽인다. 이에 죄책감을 느끼며 괴로워하던 보이카는 죽은 선수의 아내를 돕기 위해 위험을 무릅쓰고 러시아로 떠난다. 그러던 중 그녀는 범죄조직에게 팔려가게 되고 보이카는 그녀를 구하기 위해 링에서 위험한 적들과 끊임없이 싸워야만 하는데...', 'https://image.tmdb.org/t/p/w500/bv58O1paP9cYlcOL7OEUwmzmDzy.jpg', 2016, 0, 0, '2026-06-06 13:25:15.706882', 'US');
INSERT INTO public.movies VALUES (2677, 9487, '벅스 라이프', '["Adventure", "Animation", "Comedy", "Family"]', NULL, '[]', '개미 왕국의 개미들은 메뚜기 떼를 위해 열심히 일한다. 메뚜기 떼의 두목인 하퍼에게 해마다 할당된 식량을 바쳐야 하기 때문이다. 착하고 영리한 개미 플릭은 하퍼 일당을 무찌르기 위해 덩치가 큰 곤충을 데려나가 맞서 싸우자고 제안한다. 여왕 개미는 플릭의 용기를 치하한다. 도시에 나간 플릭은 삼류 서커스단의 곤충들을 용병으로 착각하고 데려온다. 사실이 밝혀지자 난감해진 플릭은 기지를 발휘해 서커스단의 곤충들이 마술쇼를 하며 하퍼의 관심을 딴 데로 돌려 놓는 사이 가짜 새를 만들어 하퍼 일당을 위협하는데...', 'https://image.tmdb.org/t/p/w500/5NmKSyeIL3qb9XvBLz0b6Vv8Ba3.jpg', 1998, 0, 0, '2026-06-07 12:17:42.843079', 'US');
INSERT INTO public.movies VALUES (528, 311, '원스 어폰 어 타임 인 아메리카', '["Drama", "Crime"]', NULL, '[]', '1921년, 좀도둑질을 일삼던 누들스는 친구들과 함께 밀수품 운반 일을 하며 돈을 벌어들인다. 누들스 무리에 위협을 느낀 벅시는 누들스의 친구를 죽이고, 분노한 누들스는 벅시를 살해한 후 감옥에 들어가게 된다. 1932년, 출소한 누들스는 어린 시절 첫사랑 데보라와 밀주 사업으로 크게 성공한 맥스를 다시 만나지만, 금주법 철폐로 밀주 사업도 위기를 맞는다. 맥스는 누들스에게 연방준비은행을 털 것을 제안하지만 누들스는 거절한다. 1968년, 베일리 재단 파티에 초대 받은 누들스는 재단 창립 기념 사진 속에서 데보라를 발견하고 그녀를 찾아가는데...', 'https://image.tmdb.org/t/p/w500/xbuc6sjIIopkA1Ep24rR6yCw0DK.jpg', 1984, 0, 0, '2026-06-06 13:25:16.450879', 'US');
INSERT INTO public.movies VALUES (112, 238, '대부', '["Drama", "Crime"]', 'Francis Ford Coppola', '["Marlon Brando", "Al Pacino", "James Caan", "Robert Duvall", "Richard S. Castellano"]', '시실리에서 이민온 뒤, 정치권까지 영향력을 미치는 거물로 자리잡은 돈 꼴레오네는 갖가지 고민을 호소하는 사람들의 문제를 해결해주며 대부라 불리운다. 한편 솔로소라는 인물은 꼴레오네가와 라이벌인 탓타리아 패밀리와 손잡고 새로운 마약 사업을 제안한다. 돈 꼴레오네가 마약 사업에 참여하지 않기로 하자, 돈 꼴레오네를 저격해 그는 중상을 입고 사경을 헤매게 된다. 그 뒤, 돈 꼴레오네의 아들 소니는 조직력을 총 동원해 다른 패밀리들과 피를 부르는 전쟁을 시작하는데... 가족의 사업과 상관없이 대학에 진학한 뒤 인텔리로 지내왔던 막내 아들 마이클은 아버지가 총격을 당한 뒤, 아버지를 구하기 위해 위험천만한 협상 자리에 나선다.', 'https://image.tmdb.org/t/p/w500/1yvBkSv4ZLS1GohlmMDmdpSgfYo.jpg', 1972, 0, 0, '2026-06-06 13:25:00.268473', 'US');
INSERT INTO public.movies VALUES (538, 3933, '유령 신부', '["Romance", "Fantasy", "Animation"]', NULL, '[]', '생선 통조림 공장을 하며 벼락부자가 된 반 도르트 일가와 세습귀족이지만 가난한 에버글롯 일가는 각기 서로의 신분과 재산 때문에 사돈으로서의 연을 맺기로 결정한다. 결혼식 전날, 예행연습을 위해 처음 만나게 된 빅터와 빅토리아. 두 사람은 쑥스럽고 어색한 분위기 속에서도 사랑의 가능성을 발견하게 된다. 하지만 빅터는 결혼 리허설에서 계속해서 실수를 저지르고 급기야 연습을 더 하고 오라며 갤스웰 목사에게 쫓겨난다. 숲 속에서 홀로 연습하던 도중, 땅 위로 튀어나온 손가락 뼈에 반지를 끼웠다가 유령 신부의 오해로 지하세계에 끌려가게 되는 색다른 경험을 하게 된다.', 'https://image.tmdb.org/t/p/w500/dNFskiyB2AGpKJCsh6qviPN03NQ.jpg', 2005, 0, 0, '2026-06-06 13:25:16.475123', 'US');
INSERT INTO public.movies VALUES (4201, 559638, '정사: 아내의 친구', '["Romance"]', 'Jo Tae-ho', '["Kim Hee-jeong", "Yoon Da-hyeon", "Moon Sung-sik", "Choi Woo-suk-I", "Yoo Sul-young"]', '외로운 밤, 아내 몫(?)까지 해주는 고마운 아내 친구!  현주는 다니던 회사를 그만둔 후, 월세도 못 내 살던 집에서 쫓겨난다. 고민 끝에 일자리를 구하는 동안만 친구 혜진의 집에 빌붙기로 한다. 걱정과 달리 혜진의 남편 상우는 따뜻하게 대해준다. 어느 날, 혜진의 갑작스런 출장으로 집에는 현주와 상우만 남게 된다. 그들은 저녁에 같이 술을 마시다 취해 넘어서는 안 될 선을 넘는다. 한 편, 아내 혜진은 남자 후배와 같이 간 출장에서 모텔에 방이 없어 혼숙하게 되는데...', 'https://image.tmdb.org/t/p/w500/tYSkdwCYZlg1Dr7pZjxPFOyLVqo.jpg', 2018, 0, 0, '2026-06-08 06:28:22.865406', 'KR');
INSERT INTO public.movies VALUES (564, 427641, '램페이지', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '유인원 전문가 ‘데이비스(드웨인 존슨)’는 사람들은 멀리하지만, 어릴 때 구조해서 보살펴 온 영리한 알비노 고릴라 ‘조지’와는 특별한 감정을 공유한다. 어느 날, 유순하기만 하던 조지가 의문의 가스를 흡입하면서 엄청난 괴수로 변해 광란을 벌인다. 재벌기업이 우주에서 무단으로 감행한 ‘프로젝트 램페이지’라는 유전자 조작 실험이 잘못되면서 지구로 3개의 병원체가 추락했던 것. 조지뿐만 아니라 가스를 마신 늑대와 악어 역시 변이시키고 끝도 없이 거대해진 이들 포식자들이 도심을 파괴하며 미국 전역을 쑥대밭으로 만들어 놓는다. 데이비스는 괴수들을 상대로 전지구적인 재앙을 막고 변해버린 조지를 구하기 위한 해독제를 찾아야만 하는데…', 'https://image.tmdb.org/t/p/w500/uJeetKzCUEFfne2LRHlr6paxxKk.jpg', 2018, 0, 0, '2026-06-06 13:25:17.979614', 'US');
INSERT INTO public.movies VALUES (576, 1359, '아메리칸 사이코', '["Thriller", "Drama", "Crime"]', NULL, '[]', '모든 것에 최고와 최상을 추구하는 패트릭 베이트만. 하버드 MBA출신의 그는 합병회사의 최고경영자이다. 최고급 브랜드의 옷을 입고, 최고급 향수를 뿌리며 아무나 예약할 수 없는 최고급 식당에서 식사를 즐긴다. 패트릭은 자신보다 더 잘나가는 폴이에게 적대감을 느끼고 그를 자신의 집으로 불러들여 살인을 저지른다. 곧 일상으로 복귀한 패트릭은 간밤의 살인은 까맣게 잊은 듯 하다. 그러나 사실 그는 살인에서 묘한 쾌감을 얻었다. 죄책감없이 일상으로 완벽하게 복귀한 듯 보이지만, 그는 어느 새 다른 대상을 물색하는 자신을 본다.', 'https://image.tmdb.org/t/p/w500/ix9Q7d4IQ329yhsBo7lZ9n9EgIb.jpg', 2000, 0, 0, '2026-06-06 13:25:18.010351', 'US');
INSERT INTO public.movies VALUES (579, 510, '뻐꾸기 둥지 위로 날아간 새', '["Drama"]', NULL, '[]', '많은 죄를 짓고 수감중이던 맥머피는 교도소에서 정신 병원으로 후송되는데, 감옥보다는 자유로울 것으로 생각했지만 전혀 그렇지 않다는 것을 깨닫는다. 정신 병원의 여러 환자들과 생활하면서 맥머피는 그들이 겉으로는 전혀 문제가 없어 보이지만 보이지 않는 병원내의 압력에 의해 짓눌려 사는 죽은 인간들임을 간파한다. 그리고 그러한 압력의 주범이 간호사 레취드임을 알게 된다. 맥머피는 환자들을 끌고 병원을 빠져나가 낚시를 다녀오거나 파티를 여는 등 의도적인 반항을 시도하다 결국 탈출을 결심하게 되는데...', 'https://image.tmdb.org/t/p/w500/9FfIRtY1BpUHDeYQ6CyOEXnJXLn.jpg', 1975, 0, 0, '2026-06-06 13:25:18.017198', 'US');
INSERT INTO public.movies VALUES (550, 645710, '더 보이어즈', '["Thriller"]', NULL, '[]', '''롭티크''에서 일하는 안경사 피파는 연인 토머스와 함께 몬트리올 시내의 멋진 아파트에서 동거를 시작한다. 첫날밤, 피파와 토머스는 사랑을 나누는 이웃집 연인 셉과 줄리아를 우연히 보게 된다. 그 후 피파는 망원경을 사서 다른 여자와 바람을 피우는 사진작가 셉을 지켜본다. 처음에는 호기심과 재미로 시작했던 피파의 관음증이 점차 집착과 스토킹으로 변해간다. 피파는 토머스와 함께 셉과 줄리아의 핼러윈 가면 파티에 참석한다. 셉의 아파트에 몰래 수신기를 설치한 피파는 레이저를 통해 두 사람의 대화를 엿듣는다. 다음 날, 줄리아가 안경을 맞추기 위해 롭티크에 찾아온다. 줄리아는 친절하게 시력 검사를 해 준 피파를 스파에 초대한다. 피파는 남편이 전부라고 말하는 줄리아에게 셉의 불륜 사실을 차마 말하지 못한다. 얼마 후 또다시 모델과 바람을 피운 셉을 목격한 피파는 익명으로 남편이 바람피운다는 사실을 줄리아에게 알리는데...', 'https://image.tmdb.org/t/p/w500/8Y4XOIWhpOvSOEn8XrxbkH9yAXO.jpg', 2021, 0, 0, '2026-06-06 13:25:17.214844', 'US');
INSERT INTO public.movies VALUES (566, 345, '아이즈 와이드 셧', '["Drama", "Thriller", "Mystery"]', 'Stanley Kubrick', '["Tom Cruise", "Nicole Kidman", "Sydney Pollack", "Marie Richardson", "Rade Šerbedžija"]', '뉴욕의 크리스마스, 성공한 의사 빌 하퍼드와 그의 아름다운 아내 앨리스는 빌의 친구 지글러가 여는 크리스마스 파티에 참석한다. 파티에서 두 사람은 각각 이성으로부터 강한 성적 유혹을 받는다. 그 다음날 앨리스는 빌에게 숨겨왔던 비밀을 털어 놓는다. 여름 휴가 때 우연히 마주친 한 해군 장교의 매력에 반해 그에게 강한 충동을 느껴 그와 하루밤만 보낼 수 있다면 남편과 딸 모두를 포기할 수 있을 것만 같다는 것이 그 내용이다. 평소에 아내를 정숙한 여자라 믿어 왔던 빌은 커다란 충격을 받는다. 그날 밤 환자의 부음 소식을 듣고 집을 나선 그는 앨리스가 장교와 정사를 나누는 환상에 시달린다. 얼마 후 빌은 대학 동창인 닉으로부터 부자들의 비밀 섹스 파티에 대한 이야기를 듣게 되고 닉의 반대를 무시한 채 파티장에 찾아간다. 그러나 빌의 위장 침입이 곧 밝혀지는데...', 'https://image.tmdb.org/t/p/w500/jVytMY7bVeYqFBp0SpKRoIKXa7W.jpg', 1999, 0, 0, '2026-06-06 13:25:17.984743', 'GB');
INSERT INTO public.movies VALUES (611, 1119878, '아이스 로드: 복수', '["Action", "Thriller", "Drama"]', NULL, '[]', '“빙하 위에 펼쳐진 새롭고 위험한 여정”  얼어붙은 도로 대신, 네팔의 설산 ‘하늘로 가는 길’이 배경이다. 첫 번째 영화에서의 비극 이후, 마이크 맥캔(리암 니슨 분)은 형의 유언을 따라 그의 유골을 히말라야 만년설에 뿌리기로 결심한다. 그곳에서 만난 산악 가이드 다니(판 빙빙 분)와 함께, 그는 설산을 횡단하는 관광 버스를 운전하며 설원을 가로지른다. 그런데 뜻하지 않게 만나게 된 용병 집단의 계략은 평화를 위협하고, 마이크는 탑승객과 마을 사람들을 위해 다시 한 번 몸을 던지게 된다. 거친 산길 위에서 벌어지는 긴장감 넘치는 추적과 대결, 그리고 인간애가 교차하며 숨 막히는 순간들을 이어가는데… 그리고 마침내 그가 마주하게 될 진실은…?', 'https://image.tmdb.org/t/p/w500/cQN9rZj06rXMVkk76UF1DfBAico.jpg', 2025, 0, 0, '2026-06-06 13:25:19.561637', 'US');
INSERT INTO public.movies VALUES (4203, 1589611, '비밀의 문', '["Romance"]', 'Lee Dong-hyun', '["Oh Ji-yoon", "Jang Tae-gyeom", "Kim Dan-ah", "Seung Ha"]', '잘나가는 성인 웹소설 작가. 함재경은 갑자기 슬럽프에 빠지게 된다. 썻던 말을 다시 쓰고 캐릭터도 계속 겹치고. 웹소설 업체의 대표 세희는 재경의 친구이다. 세희는 재경에게 슬럼프를 극복하는 방법으로 sm장르의 소설을 써보는게 어떤지 제안을 하게 된다. 처음에는 절대 안할거처럼 거부 했지만 보조작가 기동의 설득에 sm플레이를 즐기는 성수를 만나게 된다. 잘생기고 메너좋은 성수에게 끌리게 되는 재경은 소설을 쓰기 위한 취재인지 연애를 하고 있는건지?.... 점점 성수의 매력에 빠져 sm플레이를 도전 하게 된다.', 'https://image.tmdb.org/t/p/w500/d6aVgyQOblM29EpWZT3SmnppZJ.jpg', 2025, 0, 0, '2026-06-08 06:28:24.390212', 'KR');
INSERT INTO public.movies VALUES (3168, 1295400, '더 라스트 바이킹', '["Comedy", "Crime", "Drama"]', NULL, '[]', '강도죄로 14년을 복역하고 출소한 안케르는 정신 질환을 앓고 있는 동생 만프레드와 재회한다. 만프레드는 훔친 돈이 숨겨진 곳을 알고 있지만, 그 위치를 잊어버린 상태. 형제는 돈을 되찾기 위한 여정을 시작한다.', 'https://image.tmdb.org/t/p/w500/5aK6PmgYVoGa5oJezT4oY3UtRXj.jpg', 2025, 0, 0, '2026-06-08 06:24:06.405022', 'US');
INSERT INTO public.movies VALUES (621, 1107166, '싸이코 킬러', '["Crime", "Horror", "Mystery"]', NULL, '[]', '"핏빛 복수의 추적 끝, 악의 실체가 모습을 드러낸다"INSERT INTO public.movies VALUES (891, 82702, '드래곤 길들이기 2', '["Fantasy", "Action", "Adventure", "Animation", "Family"]', NULL, '[]', '바이킹과 드래곤이 친구가 되어 평화롭게 살아가는 버크섬.  청년이 된 히컵은 아버지 스토이크의 바람과는 달리  족장이 되는 것 보다 버크섬 밖의 더 넓은 세상을 보고 싶어한다.  그러던 어느 날, 신비로운 얼음대륙을 탐험하던 히컵과 투슬리스는 드래곤 사냥꾼들이 쳐놓은 덫에 걸리고,  드래곤들을 위협하는 강력한 어둠의 존재에 대해 알게 된다.  히컵과 투슬리스는 드래곤들의 평화를 위해  의문의 드래곤 군단과 맞서기로 결심하는데…', 'https://image.tmdb.org/t/p/w500/kSP4QmHMLnbySksUb2O9sGkoEQM.jpg', 2014, 0, 0, '2026-06-06 13:25:30.412407', 'US');
INSERT INTO public.movies VALUES (4217, 419329, '불륜의 후예', '["Romance"]', 'Lee Sang-soo', '["Lee Chae-dam", "Seo Bo-ra", "Sang Woo", "Chae Ye-jin", "Moon Jae-hoon"]', NULL, 'https://image.tmdb.org/t/p/w500/5hDIHNft2A7tlNsFuTKhIJfKKdc.jpg', 2016, 0, 0, '2026-06-08 06:28:35.702285', 'KR');
INSERT INTO public.movies VALUES (161, 27205, '인셉션', '["Action", "Sci-Fi", "Adventure"]', 'Christopher Nolan', '["Leonardo DiCaprio", "Joseph Gordon-Levitt", "Ken Watanabe", "Tom Hardy", "Elliot Page"]', '타인의 꿈에 들어가 생각을 훔치는 특수 보안요원 코브. 그를 이용해 라이벌 기업의 정보를 빼내고자 하는 사이토는 코브에게 생각을 훔치는 것이 아닌, 생각을 심는 ‘인셉션’ 작전을 제안한다. 성공 조건으로 국제적인 수배자가 되어있는 코브의 신분을 바꿔주겠다는 거부할 수 없는 제안을 하고, 사랑하는 아이들에게 돌아가기 위해 그 제안을 받아들인다. 최강의 팀을 구성, 표적인 피셔에게 접근해서 ‘인셉션’ 작전을 실행하지만 예기치 못한 사건들과 마주하게 되는데… 꿈 VS 현실! 시간, 규칙, 타이밍 모든 것이 완벽해야만 하는, 단 한 번도 성공한 적 없는 ‘인셉션’ 작전이 시작된다!', 'https://image.tmdb.org/t/p/w500/atSxEGstxXRoSKDQFBgqQ5lpGSt.jpg', 2010, 0, 0, '2026-06-06 13:25:02.53553', 'GB');
INSERT INTO public.movies VALUES (4218, 626412, '외계+인 2부', '["Action", "Fantasy", "Adventure", "Sci-Fi"]', 'Choi Dong-hoon', '["Ryu Jun-yeol", "Kim Tae-ri", "Kim Woo-bin", "Lee Hanee", "Yum Jung-ah"]', '인간의 뇌 속에 갇혀 있는 외계인 포로들의 탈출을 막으려다 먼 과거에 갇혀버린 이안과 썬더는 시간을 관통하는 문을 열 수 있는 신검을 얻게 된다. 한편, 이안의 탈출을 도왔던 무륵은 자신의 몸에 이상한 존재가 있다는 것을 느끼자 혼란에 빠진다. 무륵의 몸에 숨어있는 외계인으로 의심되는 존재가 이안과 무륵을 추격하기 시작하고, 이안은 미래로 돌아가 외계인과 맞서 하바의 폭발을 막아야만 하는데.  마침내 시간의 문이 열리고 무륵, 이안, 썬더의 비밀이 드러나기 시작한다!', 'https://image.tmdb.org/t/p/w500/3l04H9ljNegDGG9gnKDhLExJvpz.jpg', 2024, 0, 0, '2026-06-08 06:28:36.459003', 'KR');
INSERT INTO public.movies VALUES (628, 1734, '미이라 2', '["Adventure", "Action", "Fantasy"]', NULL, '[]', '''미이라''에서 동고동락을 한 릭 오코넬과 에블린은 결혼하여 8살짜리 아들까지 두고 행복한 가정을 꾸려나가고 있다. 그들은 고대 이집트 문명에 관한 전문가가 되어, 세계 어느 곳이든 발굴 여행을 떠난다.  그러던 어느날 에블린이 환영을 보고, 그것을 근거로 이집트의 한 무덤에 발을 들여 놓는다. 그곳은 바로 오래전 죽음의 신 아누비스의 군대를 이끌고 전세계를 정복하였던 전설적인 왕 스콜피온 킹의 팔찌가 있는 곳이었다. 스콜피온 킹이 세계를 정복하는 꿈을 이루자 죽음의 신은 스콜피온 킹이 약속한대로 그의 영혼을 거두고 그의 군대와 종족을 없애 버렸다. 스콜피온 킹은 누군가가 그의 팔찌를 찾아 그를 환생시켜 군대를 다시 통솔할 날을 기다리며 조용히 무덤속에 묻혀 있었다.  한편, 부활한 고대 이집트 마법사 이모텝은 세계를 정복하기 위해서는 스콜피온 킹 팔찌를 찾은 뒤 그를 죽이고 그의 군대를 이용해야만 한다는 결론을 내린다. 그러나 그 팔찌는 우연히 오코넬 아들 손에 들어가고...', 'https://image.tmdb.org/t/p/w500/1mYrlAHF0U99dm3ijaw13EpAx01.jpg', 2001, 0, 0, '2026-06-06 13:25:20.331088', 'US');
INSERT INTO public.movies VALUES (646, 79871, '밀도성숙시', '["Comedy", "Romance", "Drama"]', NULL, '[]', '아진은 부잣집 외동딸로 방학을 이용해 영국에서 열리는 하계 캠프에 가기로 한다. 단짝 친구 애이미와 그녀의 남자친구가 공항에서 서로의 이별을 아쉬워하 것을 보고 비행기표를 건네주고 영국행을 포기한다. 그녀는 자신의 남자친굴 찾아가는데 다른 여자와 있는 장면을 보고 그와 결별할 것을결심한다. 그리고 그녀는 진정한 사랑을 찾아 여행을 떠나가로 마음 먹는다. 여행길에 진은 여러가지 수난도 당하지만 해변에서 우연히 만난 히피에게 그의 사랑학에 대한 이야기를 듣고, 또한 극작가 지망생인 대위라는 남자를 만나 서로 사랑하게 된다. 하지만 둘 사이에 오해가 생겨 아진은 대위와 헤어지게 되고 다시 사랑을 찾아 떠난다. 그러나 그녀가 사랑할 수 있는 사람은 대위 밖에 없다는 것을 느끼게 된다. 그리고 우연히 다시만난 히피와 이야기를 나누며서 그녀가 진정으로 사랑하는 사람은 대위라는 것이 더욱 확실해 진다. 또한 사랑하는 사이라면 자존심도 버릴줄 알아야 된다고 생각하여 직접 그를 찾아가고 사랑을 확인한다. 그로써 그녀의 사랑 여행도 막을 내리게 된다.', 'https://image.tmdb.org/t/p/w500/vM4Tb2Wxk2X0Sgfy1wAS9bzSZsa.jpg', 1993, 0, 0, '2026-06-06 13:25:21.10128', 'US');
INSERT INTO public.movies VALUES (636, 2109, '러시아워', '["Action", "Comedy", "Crime"]', NULL, '[]', 'LA 한복판에서 홍콩 고위 관리인 안(Consul Han: 취 마 분)의 딸이 납치된다. 수사에 나선 FBI는 납치사건을 조속히 해결하기 위해 대대적인 수사에 나서지만 납치범에 관한 어떠한 단서도 발견하지 못한다. 안은 FBI에게 그의 오랜 친구이자 홍콩 경찰청 최고의 형사 리(Detective Inspector Lee: 성룡 분)를 사건에 투입할 것을 강력히 제안한다. 마지못해 FBI는 안의 제안을 수락하지만 홍콩 출신의 강력반 형사 리가 사건 해결에 별 도움이 되지 않을 것으로 판단, LA 경찰청의 사고뭉치 형사 카터(Detective James Carter: 크리스 터커 분)를 그의 파트너로 선정한다. 하지만 리와 카터는 사건 해결은 커녕 서로 판이한 성격탓에 첫 만남부터 사사건건 충돌한다.  그러던 어느날, 안과 FBI는 납치범으로 추측되는 한 단체로부터 괴전화를 받는다. 전화 추적 장치로 납치범의 위치를 파악한 FBI는 대대적인 테러진압반을 출동시키지만 납치범들은 이미 사라지고 출동대원들은 모두 사건현장에서 폭발사 당한다. 같은 시간, 리는 먼 발치에서 폭파 현장을 황급히 벗어나는 낯선 남자를 발견, 직감적으로 그가 이번 사건과 연계되었다고 판단하고 추적하지만 끝내 놓치고 만다. 더 이상 FBI를 믿을 수 없다고 판단한 리와 카터. 둘은 직접 납치범들을 찾아 나서 결국 납치범의 정체는 수년전, 리가 놓친 홍콩 최대 규모의 마약 조직 보스 준타오(JunTao: 데이비드 워너 분)였다는 것을 알게 된다. 리와 카터는 수소문 끝에 준타오의 아지트를 발견, 현장에 침입하지만 카터의 경솔한 공격으로 오히려 둘은 위기에 처한다.', 'https://image.tmdb.org/t/p/w500/pDBNXUOiLKHTtEUwI4OFvPMSlDY.jpg', 1998, 0, 0, '2026-06-06 13:25:20.352397', 'US');
INSERT INTO public.movies VALUES (634, 293167, '콩: 스컬 아일랜드', '["Action", "Adventure", "Fantasy"]', NULL, '[]', '전 세계 누구에게도 알려지지 않은 미지의 섬 스컬 아일랜드. 어느 날 세상에 존재하는 괴생명체를 쫓는 모나크 팀은 위성이 이 섬에 무언가를 포착했다는 정보를 입수한다. 이에 모나크의 수장이자 탐사팀의 리더를 필두로 지질학자, 생물학자가 합류하고,  수많은 전투에서 뼈가 굵은 베트남 베테랑인 중령과 부대원들, 그리고 전직 군인 출신의 정글 전문 가이드와 반전 사진기자가 탐사의 진짜 목적을 파헤치기 위해 작전에 동참한다.  폭풍우를 헤치고 섬에 도착하자마자 그들 앞에 나타난 것은 바로 이 섬의 왕인 콩. 콩은 등장과 함께 모든 것을 박살내고, 가까스로 살아남은 생존자들은 해골이 흩뿌려진 황무지에서 콩의 적들까지 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/zkvi78iWU5Qc8bXtqNuOaWROLmg.jpg', 2017, 0, 0, '2026-06-06 13:25:20.347279', 'US');
INSERT INTO public.movies VALUES (637, 50620, '브레이킹 던 Part 2', '["Fantasy", "Drama", "Romance"]', NULL, '[]', '르네즈미를 잉태하면서 죽음의 순간까지 닿았던 벨라는 그녀를 살리기 위한 에드워드의 노력으로 마침내 뱀파이어로 다시 태어나고,  제이콥이 자신의 딸 르네즈미에게 ‘각인’되었다는 사실을 알고 충격에 빠진다.  한편 르네즈미를 뱀파이어에게 위험한 ‘불멸의 아이’라고 판단한 볼투리가는 그녀를 제거하기 위해 군대를 모으기 시작한다.  신이 허락하지 않은 인간과 뱀파이어의 사랑이 불러 온 위험천만한 전운이 컬렌가를 감돌고 벨라와 르네즈미를 지키기 위해 전세계에 흩어져 있는 뱀파이어들을 모은 에드워드는 볼투리의 군대와 최후의 전쟁을 시작하는데...  전세계가 열광하는 매혹적인 판타지 대서사의 화려한 피날레가 마침내 시작된다!', 'https://image.tmdb.org/t/p/w500/Akxxrqg1Zb6pLvj3MxlHCNFWDf0.jpg', 2012, 0, 0, '2026-06-06 13:25:20.354955', 'US');
INSERT INTO public.movies VALUES (4213, 518068, '신과함께-인과 연', '["Action", "Adventure", "Fantasy", "Thriller"]', 'Kim Yong-hwa', '["Ha Jung-woo", "Ju Ji-hoon", "Kim Hyang-gi", "Don Lee", "Kim Dong-wook"]', '천 년 동안 48명의 망자를 환생시킨 저승 삼차사, 한 명만 더 환생시키면 그들도 새로운 삶을 얻을 수 있다. 하지만 강림은 원귀였던 수홍을 자신들의 마지막 귀인으로 정한다. 저승법 상 원귀는 소멸되어야하나 염라대왕은 새로운 조건을 내걸며 강림의 제안을 수락한다. 염라의 조건은 성주신이 버티고 있어 저승 차사들이 가는 족족 실패하는 허춘삼 노인을 수홍의 재판이 끝나기 전까지 저승으로 데려오는 것. 허춘삼을 데리러 이승으로 내려간 해원맥과 덕춘, 하지만 성주신의 막강한 힘 앞에 속수무책으로 당하기만 하는데...', 'https://image.tmdb.org/t/p/w500/2ETx0U2Q5gUHtPJZiQ3hakTqyaR.jpg', 2018, 0, 0, '2026-06-08 06:28:32.704386', 'KR');
INSERT INTO public.movies VALUES (682, 57158, '호빗: 스마우그의 폐허', '["Fantasy", "Adventure", "Action"]', NULL, '[]', '사나운 용 스마우그가 빼앗아간 동쪽의 외로운 산 에레보르 왕국을 되찾기 위해 뜻하지 않은 여정을 떠나게 된 호빗 빌보 배긴스와 간달프, 그리고 난쟁이족 왕족의 후예 소린이 이끄는 13명의 난쟁이족. 원정대는 외로운 산으로 가는 길에 어둠의 숲에서 모습을 자유자재로 바꾸는 베오른과 거대한 거미떼를 만나고, 난쟁이들에게 적대적인 엘프족에게 잡혔다가 도망쳐 호수마을을 지나는 등 다양한 모험을 하게 된다. 그리고 마침내 지금껏 만났던 그 어떤 존재보다도 위험하고 모두의 용기와 우정, 지혜의 한계를 시험에 들게 한 용 스마우그와 맞닥뜨리게 되는데...', 'https://image.tmdb.org/t/p/w500/jhnHkvYSi9AlwDcYLlv193LiOPG.jpg', 2013, 0, 0, '2026-06-06 13:25:22.614812', 'US');
INSERT INTO public.movies VALUES (669, 9820, '페어런트 트랩', '["Comedy", "Family", "Romance"]', NULL, '[]', '즐거운 여름캠프의 추억을 만들기 위해 몰려든 소녀들로 붐비는 캠프 월든에는 멀리 캘리포니아에서 이곳까지 날아온 할리 파커도 있다. 드넓은 포도 농장에서 아빠와 함께 살고 있는 할리는 함께 말타기도 즐기고, 비밀도 나눌 수 있는 최고의 아빠를 두었지만, 대신 엄마가 없었다.  할리가 캠프장에서 새로운 친구들을 사귀고 있을 무렵. 의리의리한 리무진 한 대가 캠프장 안으로 미끄러져 들어온다. 그 안에서 사뿐히 내려선 소녀는 애니 제임스. 바다 건너 런던에서 온 애니는 웨딩 드레스 디자이너인 멋쟁이 엄마와 함께 살고 있다. 말쑥한 옷 맵시에 프랑스어를 유창하게 구사하며, 카드 놀이까지 잘하는 완벽한 꼬마 숙녀지만, 아버지에 대해서는 하나도 아는 것이 없다. 갓난 아기였을 때부터 가족이라곤 엄마와 애니, 그리고 할아버지 이렇게 셋 뿐이었으며, 엄마는 아빠 이야기도 거의 해주지 않았기 때문이다. 캠프 월든에서 할리와 애니, 두 소녀가 만났을 때, 친구들과 선생님들은 놀란 입을 다물 수 없었다.두 소녀가 너무나 꼭 닮아있었기 때문이다. 하지만, 누구보다고 놀란것은 본인들이었다. 알고보니 이들은 쌍둥이 자매였던 것이다.  꿈에도 그리던 엄마, 아빠가 살아있다는 것을 알게 된 할리와 애니는 깜찍한 계획을 세운다. 캠프가 끝나는 날. 서로가 상대방으로 가장하여 생활하고, 결국에는 두 분이 재결합하도록 일을 꾸미기로 한 것인데...', 'https://image.tmdb.org/t/p/w500/p4dGmi8u9W0HHyVXcgWPoiFfKTF.jpg', 1998, 0, 0, '2026-06-06 13:25:21.864701', 'US');
INSERT INTO public.movies VALUES (4220, 511642, '여자 하숙집 2', '["Romance", "Drama"]', 'Lee Ri-dan', '["Lee Chae-dam", "Seo Won", "Kang Min-woo", "Min Do-yoon", "Jin Joo"]', '숙식 제공! 우리가 시키는 건 다해줄 남자 구합니다! 요리, 청소, 빨래, 그리고 ''그것''까지!  에로 시나리오 작가 지혜는 여자들끼리 모여 사는 하숙집을 운영하던 중 아무래도 집안일을 할 때 힘 써줄 사람이 필요하단 생각이 들어 공짜로 사는 대신 여자들의 부탁을 모두 다 들어줄 머슴(?)을 구한다는 공고를 낸다. 마침 저렴한 방을 찾던 인성은 공짜 집을 찾아 지혜의 하숙집에 들어온다. 그런데 그녀들이 인성에게 원한 것은 요리, 설거지, 청소, 빨래뿐만 아니라 매일 밤 제공되는 뜨거운 육체까지였는데...?', 'https://image.tmdb.org/t/p/w500/9IFgKpXWF5GWgtyoXPAL1AkO3Zs.jpg', 2018, 0, 0, '2026-06-08 06:28:37.99322', 'KR');
INSERT INTO public.movies VALUES (172, 299534, '어벤져스: 엔드게임', '["Adventure", "Sci-Fi", "Action"]', 'Joe Russo', '["Robert Downey Jr.", "Chris Evans", "Mark Ruffalo", "Chris Hemsworth", "Scarlett Johansson"]', '어벤져스의 패배 이후 지구는 초토화됐고 남은 절반의 사람들은 정신적 고통을 호소하며 하루하루를 근근이 버텨나간다. 와칸다에서 싸우다 생존한 히어로들과 우주의 타이탄 행성에서 싸우다 생존한 히어로들이 뿔뿔이 흩어졌는데, 아이언맨과 네뷸라는 우주를 떠돌고 있고 지구에 남아 있는 어벤져스 멤버들은 닉 퓨리가 마지막에 신호를 보내다 만 송신기만 들여다보며 혹시 모를 우주의 응답을 기다리는 중이다. 애초 히어로의 삶을 잠시 내려놓고 가족과 시간을 보내던 호크아이 역시 헤아릴 수 없는 마음의 상처를 입은 채 사라지고 마는데...', 'https://image.tmdb.org/t/p/w500/z7ilT5rNN9kDo8JZmgyhM6ej2xv.jpg', 2019, 0, 0, '2026-06-06 13:25:02.574588', 'US');
INSERT INTO public.movies VALUES (233, 438631, '듄', '["Sci-Fi", "Adventure"]', 'Denis Villeneuve', '["Timothée Chalamet", "Rebecca Ferguson", "Oscar Isaac", "Jason Momoa", "Stellan Skarsgård"]', '10191년, 아트레이데스 가문의 후계자인 폴은 시간과 공간을 초월해 과거와 미래를 모두 볼 수 있고, 더 나은 미래를 만들 유일한 구원자인 예지된 자의 운명을 타고났다. 그리고 어떤 계시처럼 매일 꿈에서 아라키스의 행성에 있는 한 여인을 만난다. 귀족들이 지지하는 아트레이데스 가문에 대한 황제의 질투는 폴과 그 일족들을 죽음이 기다리는 아라키스로 이끄는데...', 'https://image.tmdb.org/t/p/w500/7zV8FTYofAORGm0Umgh1mNNCym8.jpg', 2021, 0, 0, '2026-06-06 13:25:04.868881', 'US');
INSERT INTO public.movies VALUES (4216, 471413, '선 섹스 후 사랑', '["Romance", "Drama"]', 'Kim Hyeon-cheol', '["Choi Min-ho", "Suh Zi-eun", "Jung Myung-seo", "Jeon Ji-hak", "Kang Ye-na"]', '사람은 쉽게 사랑에 빠져도  진짜 사랑을 만나기는 어렵다!  언더웨어 디자인회사에서 근무하고 있는 공수는 같은 회사 동료인 신입 디자이너 수연을 짝사랑한다. 대기업 디자인PT를 준비하던 공수는 수연에게 자신의 마음을 고백하기로 결심하고 호시탐탐 고백할 기회를 노리지만 그 기회는 잘생기고 능력까지 갖춘 직장 상사인 이과장에 의해 매번 무산되고 만다. 어느날 실의에 빠져 살던 공수에게 운명처럼 마법팔찌가 나타나고 마법팔찌가 가진 놀랍고 신비로운 힘을 이용해 자신의 욕망을 조금씩 채워나가는 공수는 팔찌의 힘을 빌어 수연에게 다가가게 되는데...', 'https://image.tmdb.org/t/p/w500/lLMUPdwwyDaBlsuFL44e530cQmN.jpg', 2017, 0, 0, '2026-06-08 06:28:34.940883', 'KR');
INSERT INTO public.movies VALUES (722, 607, '맨 인 블랙', '["Action", "Adventure", "Comedy", "Sci-Fi"]', NULL, '[]', '뉴욕 경찰 에드워드는 용의자를 추적 중 그가 건물을 기어오르고 허공을 떠오르는 등의 장면을 목격한다. 용의자는 지구가 멸망할 것이라 주장하며 투신 자살을 하고 에드워드는 검은 양복을 입은 MIB요원 캐이를 만난다. 캐이는 에드워드의 탁월한 능력을 알아차리고 그를 비밀 요원으로 발탁한다. MIB는 지구인의 모습으로 살고 있는 외계인들을 감시하고 외계인의 정체를 보호하며 혹시라도 일반인이 그들이 외계인임을 알아차리면 기억 말소 장치를 이용해 외계인들을 보호한다. 그러나 사악한 바퀴벌레 외계인 에드가가 지구에 침투해 오면서 이민외계인들은 불안해 하는 등 동요하기 시작한다. 이 때 지구를 방문한 외교 사절이 암살당하는 사건이 발생해 은하계가 전면전에 돌입하자 지구는 멸망의 위기에 처한다. 지구를 지키고 우주의 평화를 지키기 위해 에드워드와 케이는 에드가와의 결전을 준비하는데...', 'https://image.tmdb.org/t/p/w500/nWQNnOvrJJVrjLKKmmxieiivAWS.jpg', 1997, 0, 0, '2026-06-06 13:25:24.164128', 'US');
INSERT INTO public.movies VALUES (4222, 826945, '자매 바이러스', '["Drama"]', 'Choi Jae-hoo', '["Yoon Yool", "Rika", "Yeon Joo", "Lee Dae-gon"]', '신종 바이러스로 인해 아내의 자매들과 함께 자가 격리된 남자가 바이러스 치료를 위해 벌이는 행각을 그린 성애영화', 'https://image.tmdb.org/t/p/w500/gSvLzCvjA8nVWE3vywODTPQfNei.jpg', 2021, 0, 0, '2026-06-08 06:28:39.552848', 'KR');
INSERT INTO public.movies VALUES (484, 20352, '슈퍼배드', '["Animation", "Comedy", "Crime", "Family", "Sci-Fi"]', 'Chris Renaud', '["Steve Carell", "Jason Segel", "Miranda Cosgrove", "Dana Gaier", "Elsie Fisher"]', '파리의 에펠탑, 뉴욕의 자유의 여신상 등 각 나라를 대표하는 명소들을 한 번에 훔쳐버린 기상천외한 주인공 그루. 그는 세계 최고의 악당이 되기 위하여 다른 사람이 절대 훔칠 수 없는 것을 하나 훔치기로 마음 먹는다. 그것은 바로 달. 달을 훔치기 위한 최신식 장비를 구하기 위해 어쩔 수 없이 세 소녀들을 맡게 된 그루는 세 소녀들과 함께 살게 되면서 세상에서 가장 어려운 일은 악당이 되는 것이 아니라 바로 이 소녀들을 키우는 일임을 알게 된다. 소녀들에 의해 점차 사랑을 배우고 변화되어 가는 그루, 과연 그는 달을 훔칠 수 있을 것인가?', 'https://image.tmdb.org/t/p/w500/avyPqGBGeeGsx4c89sIIDcfggjR.jpg', 2010, 0, 0, '2026-06-06 13:25:14.861878', 'US');
INSERT INTO public.movies VALUES (4225, 983294, '힐링하우스 : 섹스의 왕국', '["Romance", "Drama"]', 'Yoon Soo-hyun', '["Chae Ah-ra", "Min Do-yoon", "Sung Yeon", "Kang Min-woo", "Sae Bom"]', '혜경은 순실과 정섭의 가정부로 들어간다. 우연히 순실과 같은 사이비 종교라는 것을 알게 된 혜경!  순실과의 소속감을 이용하여 애인 태봉을 집으로 끌어들인다.  한편 순실은 태봉에게 홀리고, 순실의 남편인 양아치 정섭은 혜경에게 빠져든다.  서로를 차지하기 위해 혜경, 정섭, 순실, 태봉은 머리를 굴린다.', 'https://image.tmdb.org/t/p/w500/498GLLKKBHoECx3o3cedb7PTWED.jpg', 2022, 0, 0, '2026-06-08 06:28:41.839751', 'KR');
INSERT INTO public.movies VALUES (272, 674, '해리 포터와 불의 잔', '["Adventure", "Fantasy"]', 'Mike Newell', '["Daniel Radcliffe", "Rupert Grint", "Emma Watson", "Brendan Gleeson", "Michael Gambon"]', '요즘 들어 매일 꾸는 악몽 때문에 이마의 상처에 더욱 통증을 느끼는 해리는 친구 론과 헤르미온느와 함께 퀴디치 월드컵에 참가해 악몽에서 벗어날 수 있게 돼 마냥 기쁘다. 그러나 퀴디치 캠프장 근방 하늘에 불길한 기운이 나타난다. 바로 마왕 볼드모트의 상징인 어둠의 표식이 나타난 것. 볼드모트가 13년 전에 자취를 감춘 뒤, 감히 모습을 드러내지 못했던 그의 추종자 데스 이터들이 그 표식을 불러낸 것이다. 두려움으로 가득 찬 해리는 안전한 호그와트 마법학교로 돌아가고 싶어한다. 덤블도어 교장이라면 자신을 지켜줄 수 있을 것이기에. 그러나 올해는 예년과 상황이 좀 다른데...', 'https://image.tmdb.org/t/p/w500/uWPnKtu1eutmgBQ2hoWm0Xe8nfN.jpg', 2005, 0, 0, '2026-06-06 13:25:06.406282', 'GB');
INSERT INTO public.movies VALUES (747, 615777, '바빌론', '["Drama", "Comedy"]', NULL, '[]', '황홀하면서도 위태로운 고대 도시 바빌론에 비유되는 할리우드에서 전성기를 누리고 있는 당대 최고의 스타 잭 콘래드.  누구나 잭과 같은 성공을 꿈꾸지만 아무나 이룰 수 없던 그 때, 화려한 데뷔를 위해 당차게 야망을 좇는 넬리 라로이와 열정적인 청년 매니 토레스가 영화 같은 삶을 꿈꾸며 할리우드에 입성한다. 하지만 할리우드에서는 기존 영화 산업의 틀을 깬 새로운 변화가 시작되고 그 격변의 한가운데에서 잭과 넬리, 그리고 매니는 살아남아 각자의 꿈을 이루기 위해 고군분투하는데...', 'https://image.tmdb.org/t/p/w500/6JQtIajMe70HWtBf7uZ1ZyWiW1F.jpg', 2022, 0, 0, '2026-06-06 13:25:24.947663', 'US');
INSERT INTO public.movies VALUES (750, 49018, '인시디어스', '["Horror", "Thriller"]', NULL, '[]', '매일 밤, 문 밖을 서성이는 검은 그림자…  절대 ‘그것’을 안에 들이지 마라!  그 순간, 당신의 영혼은 잠식될 것이다!  단란하고 행복해 보이기만 하던 조쉬 부부와 세 자녀.  하지만 그들 주변에 언젠가부터 기이한 현상이 끊이지 않더니  급기야 6살 된 아들 달튼이 다락방 사다리에서 떨어지는 의문의 사고를 당하게 된다.  겉으로는 아무런 외상도 발견되지 않아 대수롭지 않게 지나치고 만다.  하지만 다음 날 아침, 아무리 불러도 잠자리에서 일어나지 않는 아이는,  결국 의사도 해명할 수 없는 원인불명의 혼수상태에 빠져버린다.  6개월 동안을 의식불명인 상태로 꼼짝도 하지 않는 달튼.  그 사이 집안을 감싸던 불길한 공기는 서서히 공포로 번져가고,  정체를 알 수 없는 그 ‘무언가’의 위협적인 존재에 가족은 패닉 상태에 빠져버린다.  3개월 뒤, 이들에게 다가온 구원의 손길.  아이의 영혼이 이대로 텅 빈 채 사라지기 전에 누군가 목숨을 건  어둠 속으로의 ‘영혼의 여행’을 감행해야 한다고 경고하는데…..', 'https://image.tmdb.org/t/p/w500/9uymSsEKDVKOuqgY4EpVJSuG640.jpg', 2011, 0, 0, '2026-06-06 13:25:24.954648', 'US');
INSERT INTO public.movies VALUES (734, 859, '위험한 관계', '["Drama", "Romance"]', NULL, '[]', '18세기 프랑스 소설인 쇼데를로 드 라클로의 ''위험한 관계''를 원작으로 하는 영화. 이 영화 뿐만 아니라  한국 영화인 도 그 소설과 관련이 있다. 18세기 프랑스 혁명 전야의 파리 귀족 사회. 사람들은 사치가 극에 달한 감미로운 생활에 취해 쾌락을 추구한다. 사교계의 여왕인 메르퇴이유 부인(Marquise de Merteuil)은 바람둥이로 유명한 비콩트(Viscomte de Valmont)과 계약을 맺고, 자기를 배신하고 떠난 애인 바스티드가 불랑쥬 부인(Madame de Volanges)의 딸 세실(Cecile de Volanges)을 신부감으로 점찍고 있으니, 세실의 순결을 빼앗아 바스티드를 웃음 거리로 만들 계획을 세운다.  비콩트는 그보다는 자기 고모의 성채에 묶고 있는 덕망과 신앙심 깊은 투르벧 부인(Madame de Tourve)에게 더 관심이 있다고 말한다. 비콩트는 능숙한 언변과 기질을 발휘해서 끈질기게 투르벧 부인을 유혹하고, 투르벧 부인은 마음의 갈등으로 번민에 싸인다. 그러나 끝내 비콩트를 물리치지 못하고 넘어가고 만다. 그녀의 선의는 비콩트의 악의를 악의로 분별할 수 없었던 것이다.  순수하기 그지없는 세실을 소심한 청년 당스니(Chevalier D''arceny)와 사랑에 빠진 것을 이용하여 결국 임신까지 시킨 악독한 비콩트가 투르벧 부인을 진심으로 사랑하게 되는데...', 'https://image.tmdb.org/t/p/w500/eNvJXuTQ7lusuUrIvS7wplORXBX.jpg', 1988, 0, 0, '2026-06-06 13:25:24.194523', 'US');
INSERT INTO public.movies VALUES (411, 530442, '마이 티쳐, 마이 러브', '["Drama", "Thriller"]', 'Damián Romay', '["Rusty Joiner", "Lucy Loken", "Laura Bilgeri", "Jana Lee Hamblin", "Alexandria DeBerry"]', '아픈 상처를 딛고 새 출발을 다짐하며 이사 온 크리스와 라일리 부녀. 모든 것이 낯선 라일리에게 먼저 다가온 카일라. 라일리는 점차 카일라에게 마음을 열지만 카일라는 어쩐지 라일리의 아빠이자 영어 교사인 크리스에게 더 관심을 갖는다. 한편, 엄마의 새 애인이 크리스라는 걸 알게 된 카일라는 거짓과 음모로 둘 사이를 갈라놓고 감춰둔 욕망을 꺼내기 시작하는데…', 'https://image.tmdb.org/t/p/w500/2VOFI6HOnuncgTU08rjDwUG5FDs.jpg', 2018, 0, 0, '2026-06-06 13:25:11.7871', 'US');
INSERT INTO public.movies VALUES (794, 436270, '블랙 아담', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '기원전 가장 번성하고 위대한 고대 국가였지만 현재는 국제 군사 조직 인터갱의 독재 국가로 전락한 칸다크. 인터갱의 눈을 피해 고대 유물을 찾던 아드리아나는 우연히 5000년 동안 잠들어 있던 블랙 아담을 깨우게 된다.  엄청난 괴력과 스피드, 방탄 능력과 자유자재의 고공비행, 번개를 쏘는 능력까지. 온몸이 무기인 블랙 아담은 자신의 앞을 막아서는 인터갱들을 모조리 쓸어버리고 칸다크 국민들은 이에 열광한다. 한편, 그의 폭주를 막기 위해 호크맨, 닥터 페이트, 아톰 스매셔, 사이클론으로 구성된 히어로 군단 저스티스 소사이어티가 칸다크에 나타나는데...', 'https://image.tmdb.org/t/p/w500/mEdMHGy1FfCUc7PskFO0tibm8jp.jpg', 2022, 0, 0, '2026-06-06 13:25:26.540844', 'US');
INSERT INTO public.movies VALUES (798, 447332, '콰이어트 플레이스', '["Horror", "Drama", "Sci-Fi"]', NULL, '[]', '인류 종말의 초기 단계로 보이는 가까운 미래, 이미 폐쇄된 뉴욕 주에서 간신히 살아남은 부부와 세 자녀가 맨발로 숨죽인 채 시골 마을의 식료품점을 헤맨다. 작은 소리에도 민감하게 반응해 소리의 근원지를 파괴하러 달려오는 괴 생명체가 곳곳에 도사리고 있기 때문. 전 세계를 파괴해 버린 무차별적인 공격과 숨통을 조여 오는 거대한 위협 속에서 살아남기 위해 주인공 가족은 일상에서 발생하는 모든 소리를 최소화하며 위태롭게 살아간다. 숨소리조차 마음 편히 낼 수 없는 극한의 상황, 아버지 리(존 크래신스키)와 어머니 에블린(에밀리 블런트)은 아이들과 자신들의 생명을 지키기 위해 고군분투하는데...', 'https://image.tmdb.org/t/p/w500/vdiR7qc7cWxXD0pT8BZJ35DDB0B.jpg', 2018, 0, 0, '2026-06-06 13:25:26.550633', 'US');
INSERT INTO public.movies VALUES (782, 1242419, '루프맨', '["Crime", "Comedy", "Drama"]', NULL, '[]', '전직 육군 레인저이자 생활고에 몰려 맥도날드 매장의 지붕을 뚫고 침입하는 방식으로 강도를 벌이며 ‘루프맨’이라는 별명을 얻는다. 체포된 뒤 탈옥에 성공한 그는 한동안 모습을 감춘 채 토이저러스 매장 안에 숨어 6개월 동안 아무에게도 들키지 않고 지내며 다음 범행을 준비한다. 그러던 중, 예기치 않게 한 이혼 여성을 만나 그의 매력에 이끌린 그녀와 관계가 깊어지면서 그의 이중생활은 균열을 맞기 시작한다. 그리고 과거가 서서히 그를 덮쳐오며, 숨기려는 남자와 들춰내려는 세력 사이에 팽팽한 긴장감의 고양이와 쥐의 추격전이 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/qUeT9KG99sSyxkGzWJ7pBVoKz5j.jpg', 2025, 0, 0, '2026-06-06 13:25:26.51114', 'US');
INSERT INTO public.movies VALUES (758, 2501, '본 아이덴티티', '["Action", "Drama", "Mystery", "Thriller"]', NULL, '[]', '이탈리아 어부들이 지중해 한 가운데에서 등에 두 발의 총상을 입은 채 표류하고 있는 한 남자를 구하게 된다. 그는 기억 상실증에 걸려 자신이 누구인지조차 모른다. 단서는 등에 입은 총상과 스위스 은행의 계좌번호 뿐.  자신의 존재를 찾아 스위스로 향한 그는 자신이 파리에서 제이슨 본이라는 이름으로 살았음을 알게 되지만, 여러 개의 가명으로 만들어진 여권을 보고 자신의 정체성을 잃게 된다. 경찰과 군인까지 그를 추적하고 있다는 사실을 알게 된 제이슨 본. 추격을 피해 도망가다 우연히 만나게 된 마리라는 여성에게 2만 달러라는 거금을 주고 파리까지 차를 얻어 타게 되는데...', 'https://image.tmdb.org/t/p/w500/crj9CUvNqeNHNdUm8bTN9jpEWqI.jpg', 2002, 0, 0, '2026-06-06 13:25:24.972703', 'US');
INSERT INTO public.movies VALUES (771, 78, '블레이드 러너', '["Sci-Fi", "Drama", "Thriller"]', NULL, '[]', '2019년, 지구의 파괴와 엄청난 인구증가로 인해 다른 행성을 식민지 이주가 본격화된다. 2주전 6명의 복제 인간 리플리컨트가 식민행성에서 탈출, 23명을 죽이고 우주선을 탈취하여 지구로 잠입한다. 전투용 로이 베티와 리온, 살인 훈련을 받은 조라, 식민행성 군인 클럽 소속의 위안부 프리스가 그들이다. 이들은 타이렐사에 침입하려 하지만 한 사람이 죽고, 직원으로 위장한 리온이 회사 간부의 테스트에 발각되어 도주한다. 이에 경찰은 복제 인간을 구별할 능력을 지닌 블레이드 러너 데커드를 호출하는데...', 'https://image.tmdb.org/t/p/w500/6yXqNiVIoJcMhio10Nkb5QMNeh8.jpg', 1982, 0, 0, '2026-06-06 13:25:25.734372', 'US');
INSERT INTO public.movies VALUES (875, 207703, '킹스맨: 시크릿 에이전트', '["Crime", "Comedy", "Action", "Adventure"]', 'Matthew Vaughn', '["Taron Egerton", "Colin Firth", "Samuel L. Jackson", "Mark Strong", "Sophie Cookson"]', '높은 IQ, 주니어 체조대회 2년 연속 우승! 그러나 학교 중퇴, 해병대 중도 하차. 동네 패싸움에 직장은 가져본 적도 없이 별볼일 없는 루저로 낙인 찍혔던 그가 젠틀맨 스파이로 전격 스카우트 됐다! 전설적 베테랑 요원 해리 하트는 경찰서에 구치된 에그시를 구제한다. 탁월한 잠재력을 알아본 그는 에그시를 전설적 국제 비밀정보기구 킹스맨 면접에 참여시킨다. 아버지 또한 킹스맨의 촉망 받는 요원이었으나 해리 하트를 살리기 위해 죽었다는 사실을 알게 된 에그시. 목숨을 앗아갈 만큼 위험천만한 훈련을 통과해야 하는 킹스맨 후보들. 최종 멤버 발탁을 눈 앞에 둔 에그시는 최고의 악당 발렌타인을 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/pVwvZAgnsuMcDGbeWVtXOpks1oQ.jpg', 2015, 0, 0, '2026-06-06 13:25:29.654421', 'GB');
INSERT INTO public.movies VALUES (890, 812037, '라스트 썸머', '["Drama"]', 'Catherine Breillat', '["Léa Drucker", "Samuel Kircher", "Olivier Rabourdin", "Clotilde Courau", "Serena Hu"]', '남편 피에르와 함께 입양한 두 딸을 키우며 완벽한 삶을 살고 있는 청소년 전문 변호사 안느. 어느 날, 남편이 전처와 낳은 아들 테오가 학교에서 사고를 치며 안느와 테오는 한집에 살게 된다. 테오는 어딘가 외로워보이는 안느에게 적극적으로 다가가고 안느는 그런 테오에게 걷잡을 수 없이 빠져들며 그와 금지된 사랑을 나누게 되는데…', 'https://image.tmdb.org/t/p/w500/1T3nJiKJyIHNFZoiSTYOwDJc7lH.jpg', 2023, 0, 0, '2026-06-06 13:25:30.409918', 'FR');
INSERT INTO public.movies VALUES (833, 1097549, '베이비걸', '["Romance", "Thriller"]', NULL, '[]', '맨해튼의 호화로운 아파트, 자상한 예술가 남편과 사랑스런 두 딸, 로봇 자동화 회사의 CEO 로미. 여성들의 롤모델로서 모든 것이 완벽해 보이는 삶이지만, 로미는 지배 당하고 싶은 자신의 욕망이 부끄럽다고 생각해 오랜 결혼생활에도 진정한 즐거움을 찾지 못했다. 출근길에서 목줄이 풀린 개를 완벽하게 통제하는 사무엘이 회사의 인턴으로 들어와 무례한 질문을 하고 아무 일도 없었다는 듯 커피를 건네자 로미가 불편할 정도로 흥분한 것을, 이미 서로 눈치챈다. 단숨에 사무엘에게 사로잡힌 로미는 그의 놀잇감을 자처하고 둘만의 욕망 플레이는 점점 로미가 쌓아온 모든 것을 위태롭게 만드는데… 그럼에도 둘의 관계는 부인할 수 없이 뜨겁게 달아오르고, 더 이상 멈출 수 없다!', 'https://image.tmdb.org/t/p/w500/vkX85I1Mv27bnxMSWOuKntwjVgb.jpg', 2024, 0, 0, '2026-06-06 13:25:28.109964', 'US');
INSERT INTO public.movies VALUES (4232, 724109, '구멍동서', '["Romance"]', 'Lee Sang-soo', '["Seung Ha", "Han Yi-seul", "Min Do-yoon", "Kang Min-woo", "Alex-I"]', NULL, 'https://image.tmdb.org/t/p/w500/ZAhAOX5RsstfrbLtkSjiUZGgw2.jpg', 2020, 0, 0, '2026-06-08 06:28:48.022396', 'KR');
INSERT INTO public.movies VALUES (4233, 27154, '해피 엔드', '["Drama", "Romance"]', 'Jung Ji-woo', '["Jeon Do-yeon", "Choi Min-sik", "Ju Jin-mo", "Joo Hyun", "Yoo Yeon-soo"]', '6년 동안 은행에서 일하다 실직한 서민기는 실직의 불안정함과 오랜만에 맛보는 일상의 여유 사이를 오간다. 어린이 영어학원 원장인 서민기의 아내 최보라는 대학 시절 연인이었던 김일범과 은밀한 만남을 이어간다. 젖먹이 아기와 남편을 소중하게 여기지만 김일범의 한결같은 사랑에도 행복해 한다. 서민기가 아내와 김일범의 밀회를 눈치채고, 세 사람의 욕망은 팽팽한 긴장을 불러온다. 사랑과 집착으로 뒤엉킨 삼각관계. 배신감과 상실감에서 비롯된 살의 속에 세 사람은 서로 다른 해피엔딩을 꿈꾸는데...', 'https://image.tmdb.org/t/p/w500/bqnOc1FnaRU9X3whv7gG43zkUrk.jpg', 1999, 0, 0, '2026-06-08 06:28:48.768678', 'KR');
INSERT INTO public.movies VALUES (824, 2832, '아이덴티티', '["Mystery", "Thriller"]', NULL, '[]', '폭풍우가 몰아치는 어느 밤... 네바다 주의 사막에 위치한 외딴 모텔에 10명의 사람들이 모여든다. 리무진 운전사와 그가 태우고 가던 여배우, 경찰과 그가 호송하던 살인범, 라스베이거스 매춘부와 신혼부부, 신경질적인 모텔 주인까지 포함한 총 11명. 사나운 폭풍우로 길은 사방이 막혀버리고 사람들은 어둠과 폭우가 걷히기를 기다리지만 연락이 두절된 호텔에 갇힌 이들은 하나 둘씩 살해당하기 시작한다. 죽음으로 시작된 살인의 그림자는 그들을 극도의 공포로 몰아간다. 현장에 남겨진 것이라곤 모텔 룸 넘버 10이 적힌 열쇠뿐... 연이은 죽음의 현장에는 9,8,7.. 카운트 다운을 알리는 열쇠만이 남아 끝나지 않은 살인을 예고하다. 서로가 서로를 의심하는 가운데 모두가 기억하기 싫은 비밀이 서서히 베일을 벗는데...', 'https://image.tmdb.org/t/p/w500/91N7EeWISYM4mBsdQnGJtcrywhS.jpg', 2003, 0, 0, '2026-06-06 13:25:28.087224', 'US');
INSERT INTO public.movies VALUES (816, 530915, '1917', '["History", "Drama"]', NULL, '[]', '제1차 세계대전이 한창인 1917년 4월 6일. 독일군에 의해 모든 통신망이 파괴된 상황 속에서 서부전선의 영국군 병사 스코필드와 블레이크에게 하나의 미션이 주어졌다. 독일군의 함정에 빠진 영국군 부대의 수장 매켄지 중령에게 에린무어 장군의 공격 중지 명령을 전달하라는 것. 블레이크는 데본셔 연대에 있는 형을 구하기 위해 기꺼이 임무를 수행한다. 동료인 스코필드는 처음엔 당황스러워하지만 이내 1600명의 동료들을 구하기 위해 전쟁터 한가운데를 가로지르는 여정에 동참한다.', 'https://image.tmdb.org/t/p/w500/u2oRQqUashBBIj5UNeOd5TN0bmB.jpg', 2019, 0, 0, '2026-06-06 13:25:27.322187', 'US');
INSERT INTO public.movies VALUES (4230, 938090, '윤율의 사내 불륜', '["Drama", "Romance"]', 'Mr. Na', '["Yoon Yool", "Lee Chae-dam", "Min Do-yoon", "Han Seok-bong", "Seung Hwan"]', NULL, 'https://image.tmdb.org/t/p/w500/s68Pe8JclbbTZlh8Tso6faW4nad.jpg', 2021, 0, 0, '2026-06-08 06:28:45.660233', 'KR');
INSERT INTO public.movies VALUES (4231, 853033, '불륜 동창회 2', '["Drama", "Romance"]', 'Kim Jong-min', '["Ahn So-hee", "Lee Chae-dam", "Kim Soo-ji", "Min Do-yoon", "Kang Min-woo"]', '동창 남녀들의 자유분방한 사랑이 시작된다!INSERT INTO public.movies VALUES (834, 9837, '이집트 왕자', '["Adventure", "Animation", "Drama", "Family"]', NULL, '[]', '히브리 인이 모두 이집트의 노예로 소유되었던 시대. 히브리 인의 반란과 예언자의 출현을 두려워한 이집트 왕 세티는 히브리 신생남아를 모두 죽이라는 명령을 내린다. 아기 모세의 어머니와 형제들은 아기를 광주리에 담아 강물에 띄워 보내고, 왕비에게 발견된 모세는 람세스와 함께 건장한 이집트 왕자로 성장한다. 어느 날 밤 모세는 파티에서 선물받은 미디안 처녀 십보라가 도망치는 뒤를 밟다가 자신의 친형제 미리암, 아론과 마주친다. 미리암으로부터 자신의 출생과 성장의 비밀을 들은 모세는 아버지로 믿어왔던 세티에게서 이 사실을 확인하고 괴로와한다.  그러던 어느 날 모세는 히브리 노예가 학대받는 것을 보고 실수로 건설감독을 떼밀어 죽인다. 자신의 성장배경과 예기치 않은 살인으로 충격받은 모세는 왕궁을 떠나 사막을 배회하다가 미디안 처녀 십보라가 속한 유랑민을 만난다. 그들과 함께 생활하면서 아름다운 십보라와 결혼하여 행복하게 살던 모세는 우연히 양을 찾으러 나갔다가 불붙은 떨기나무를 보고 하나님의 계시를 듣는다. 그 계시는 바로 이집트인의 박해로부터 히브리인을 구하라는 것. 왕궁으로 돌아온 모세를 보고 람세스는 뛸듯이 반가와하지만 모세가 히브리인의 해방을 요구하자 저주를 내리겠다고 협박한다.  모세는 하나님의 말씀과 인도에 따라 이집트에 열 가지 재앙을 내린다. 이집트인의 장자를 죽이는 열 번째 재앙에 람세스의 아들도 목숨을 잃자 마침내 람세스는 모세로 하여금 히브리인들을 데리고 떠나도록 허락한다. 모세가 이끄는 히브리 백성들의 무리가 홍해에 다달았을 무렵 복수심에 불타는 람세스가 병사를 이끌고 따라온다. 위기의 상황에서 모세가 하나님이 주신 지팡이를 홍해에 담그자 물이 양쪽으로 갈라지는 기적이 일어나는데.', 'https://image.tmdb.org/t/p/w500/58T9BmzbqXRKbdn0Fr6FasKxvWy.jpg', 1998, 0, 0, '2026-06-06 13:25:28.112291', 'US');
INSERT INTO public.movies VALUES (8852, 4638, '뜨거운 녀석들', '["Crime", "Action", "Comedy"]', 'Edgar Wright', '["Simon Pegg", "Nick Frost", "Jim Broadbent", "Paddy Considine", "Rafe Spall"]', '런던에서 잘나가는 경찰 니콜라스 엔젤(사이몬 페그)은 몸을 사리지 않는 근성과 동물적인 감각으로 검거율 400%라는 경이적인 기록을 세우며 승승장구하지만 경찰청 간부들과 동료들의 견제를 받아 시골로 좌천된다. 그가 부임한 곳은 범죄율 제로를 자랑하는 아름답고 평화로운 마을 샌드포드. 좀 덜 떨어진듯한 순둥이 경찰 대니 버터맨(닉 프로스트)과 파트너가 되어 마을 축제의 안전관리, 실종된 백조 수색 등의 무료한 업무에 전전하던 어느 날, 끔찍한 사고들이 연이어 발생한다. 평화롭기만 하던 마을의 이면에는 엄청난 비밀이 숨겨져 있는데...', 'https://image.tmdb.org/t/p/w500/pzMU5ohKBC3IJKWDGhzLLlpgDk3.jpg', 2007, 0, 0, '2026-06-08 07:30:15.416456', 'GB');
INSERT INTO public.movies VALUES (853, 49444, '쿵푸팬더 2', '["Animation", "Family", "Comedy", "Action"]', NULL, '[]', '그토록 원하던 용의 전사가 되어 무적의 5인방과 함께 평화의 계곡을 지키게 된 포. 진정한 용의 전사로 거듭나기 위해 시푸 사부와 쿵푸 수련에 매진하던 중, 셴 선생이 위대한 쿵푸 사부들을 하나 둘씩 제거하고 있다는 소식을 듣게 된다.  여전히 바람을 가르는 주먹의 소리보다 배에서 울리는 꼬르륵 소리가 더 크고, 오랜 숙적인 계단 앞에서는 맥을 못 추는 천방지축 팬더 포. 이제 막 정식 수련을 시작하려는 포에게 쿵푸를 지켜야 한다는 막중한 미션이 주어지고, 포는 무적의 5인방과 함께 길을 떠난다. 과연 포는 쿵푸의 대가들도 막지 못한 셴 선생의 비밀병기에 맞서 쿵푸를 지켜낼 수 있을까?', 'https://image.tmdb.org/t/p/w500/bPocc0TkmgENeBcreGSq3nNiEB7.jpg', 2011, 0, 0, '2026-06-06 13:25:28.867771', 'US');
INSERT INTO public.movies VALUES (4391, 435601, '브이아이피', '["Crime", "Thriller", "Action"]', 'Park Hoon-jung', '["Kim Myung-min", "Jang Dong-gun", "Park Hee-soon", "Lee Jong-suk", "Peter Stormare"]', '국정원과 CIA의 기획으로 북에서 온 VIP 김광일이 살인사건의 유력한 용의자로 지목된다. 본능적으로 그가 범인임을 직감한 경찰 채이도가 VIP를 뒤쫓지만 국정원 요원 박재혁의 비호로 번번이 용의선상에서 벗어난다. CIA와 국정원 간의 ‘기획 귀순자’를 둘러싼 알력 다툼, 경찰의 봐주기 수사부터 검찰과의 거래, 여기에 북한 정치 상황 지형도까지 얽히는데...', 'https://image.tmdb.org/t/p/w500/nAF51unFGuizy0dOnmn74VytRLt.jpg', 2017, 0, 0, '2026-06-08 06:31:07.060568', 'KR');
INSERT INTO public.movies VALUES (865, 698687, '트랜스포머 ONE', '["Animation", "Sci-Fi", "Adventure", "Family"]', NULL, '[]', '사이버트론 행성의 지하 광산에서 일하는 변신 못 하는 하급 로봇 오라이온 팩스와 D-16. 한 번도 가보지 못한 지상 세계를 꿈꾸던 둘은 쾌활한 수다쟁이 B-127, 카리스마 넘치는 엘리타 원과 함께 출입이 금지된 지상에 도달한다. 지상에서 잠들어 있던 알파 트라이온을 만난 넷은 그의 도움으로 잠재되어 있던 변신 능력을 얻게 된다. 막강한 힘과 변신 능력으로 자유를 느낀 것도 잠시, 자신들의 행성을 지배하고 있는 거대한 배후의 존재를 알게 되며 모든 것을 바꿀 전쟁을 시작하는데…', 'https://image.tmdb.org/t/p/w500/c2JXlWzvXegSda8qaATr8I47kMx.jpg', 2024, 0, 0, '2026-06-06 13:25:29.621219', 'US');
INSERT INTO public.movies VALUES (872, 176, '쏘우', '["Horror", "Mystery", "Crime"]', NULL, '[]', '어느 지하실. 자신들의 발목에 쇠줄이 묶인 채 마주하게 된 ‘아담’(리 와넬)과 닥터 ‘고든’(캐리 엘위스). 중앙에는 자신의 머리를 총으로 쏘고 자살한 듯한 사내가 피투성이가 되어 누워 있을 뿐, 이 둘은 자신들이 왜 잡혀왔는지, 서로가 누군지조차 모르고 있다. 주머니 속에 들어있는 테이프. 테이프에 들어있는 누군가의 메시지. 어떻게든 빠져나가려고 갖은 애를 써보지만 소용이 없다. 이제 둘은 자신들의 하루 전 기억을 더듬어 보는데. ‘고든’은 이 일이 최근 계속되고 있는 연쇄살인과 관계가 있음을 깨닫게 된다. 끔찍한 연쇄살인의 현장에 자신의 펜이 떨어져 있었고, 그 증거물을 근거로 ‘탭’형사(대니 글로버)가 자신을 찾아왔던 것. 한편, 연쇄살인을 추적하던 ‘탭’형사는 닥터 ‘고든’을 범인으로 지목하고 그 뒤를 쫓는데…', 'https://image.tmdb.org/t/p/w500/vRVtn1HLMGMHbUsAJkFLC6oT6pQ.jpg', 2004, 0, 0, '2026-06-06 13:25:29.644653', 'US');
INSERT INTO public.movies VALUES (851, 1091, '괴물', '["Horror", "Mystery", "Sci-Fi"]', NULL, '[]', '남극의 노르웨이 탐사팀이 이상한 개를 쫓아 미국 기지까지 오게 된다. 거의 발광하다시피 개를 공격하다가 그만 방어하던 미국인들에게 사살된다. 미국인들은 진상을 조사하기 위해 노르웨이 기지로 사람을 보낸다. 그곳은 사람은 하나도 없고 이상하게 일그러진 시체와 잔해들을 발견한다. 시체들을 해부해 봤지만 별 이상이 발견되지는 않았다. 그러던 어느 날 노르웨이 탐사팀의 추격을 받았던 개가 개집에서 끔찍한 괴물로 변하게 되는데...', 'https://image.tmdb.org/t/p/w500/sJfEZgPQpxFn6TVx96Im3GeMYzG.jpg', 1982, 0, 0, '2026-06-06 13:25:28.862514', 'US');
INSERT INTO public.movies VALUES (916, 22832, '닌자 어쌔신', '["Action", "Adventure", "Thriller"]', 'James McTeigue', '["Rain", "Naomie Harris", "Ben Miles", "Rick Yune", "Sho Kosugi"]', '거리의 고아였던 라이조는 베일에 싸인 비밀 조직 ''오주누파''에게 거둬져 훈련을 받고 세계 최고의 인간 병기로 키워진다. 어느 날 조직에 의해 친구가 무자비하게 처형된 것을 목격하고 조직을 뛰쳐나온 그는 행방을 감춘 채 조용히 복수를 준비한다.  한편 베를린에서는 정체불명의 조직에 의한 정치적 암살사건을 추적하던 유로폴 요원 미카가 일급비밀 문서를 손에 넣게 되고, 그로 인해 라이조의 라이벌인 타케시가 이끄는 ''오주누파'' 암살단의 표적이 된다.  우연히 쫓기는 미카를 구해낸 라이조는 조직이 두 사람을 결코 포기하지 않을 것임을 깨닫고, 이제야 결전의 때가 되었음을 느끼게 된다. 유럽 전역을 무대로 펼쳐지는 쫓고 쫓기는 추격전 속에서 라이조와 미카는 살기 위해, ''오주누파''를 끝장내기 위해 서로를 믿고 의지해야만 한다!', 'https://image.tmdb.org/t/p/w500/yiHxwpi7PUcMHOIRqx4r03qlMUL.jpg', 2009, 0, 0, '2026-06-06 13:25:31.190008', 'FR');
INSERT INTO public.movies VALUES (4236, 390845, '맛있는 비행', '["Romance"]', 'Choi Sang-hoon', '["Son Woo-hyuk", "Jeong Yoo-jin", "Shin Yu-ju", "Jeon Hyeon-soo", "Baek In-kwon"]', '홍콩(?)행 기내 서비스가 시작됩니다! 광활한 창공에서 펼쳐지는 리얼 19금 연애담! 청순가련의 대명사였지만 아이돌과의 섹스 스캔들로 도망친 여배우, 그녀의 모든 커리어를 망쳐 버린 발랑 까진 아이돌, 그녀에게 절대 충성하는 열혈 매니저, 그리고 이제는 섹시한 승무원이 된 매니저의 전 여친까지! 절대 만나선 안 될 네 사람이 비행기 안에서 마주쳤다. 도망칠 수 없는 그곳에서 지나치게 발칙하고 지독하게 화끈한 로맨스가 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/kw7QEMiIFW7EjZQSRO9ebKls21k.jpg', 2015, 0, 0, '2026-06-08 06:28:51.005109', 'KR');
INSERT INTO public.movies VALUES (936, 9902, '데드 캠프', '["Horror", "Thriller"]', NULL, '[]', '웨스트 버지니아, 그린브리어 백카운티(Greenbrier Backcountry). 중요한 면접에 참석하기 위하여 정체되는 고속도로를 피해 산 속 지름길로 들어선 의대생 크리스. 낯선 길을 달리던 중, 도로에 세워진 캠핑카와 충돌하고 만다. 바닥에 놓여진 철조망에 타이어가 터진 이 차는 숲 속으로 캠핑 온 여섯 명의 대학생들의 것.  인적이 드문 산에 고립된 그들. 크리스와 몇 명의 사람들은 외부와 연락할 전화를 찾아보려 숲 속을 헤매던 중, 시체 냄새와 기괴한 사냥 도구로 가득한 오두막을 발견한다. 한편, 차에 남아있던 두 친구는 정체를 알 수 없는 살인마에게 잔혹하게 살해 당하고 만다. 남은 사람들은 잔인한 살인마, 마운틴 맨이 자신들의 목숨을 노리고 있음을 깨닫게 되는데.', 'https://image.tmdb.org/t/p/w500/4ENDpqHddaIodooOe3jUBmtc9KV.jpg', 2003, 0, 0, '2026-06-06 13:25:31.959196', 'US');
INSERT INTO public.movies VALUES (899, 508943, '루카', '["Animation", "Comedy", "Drama", "Family", "Fantasy"]', NULL, '[]', '이탈리아 리비에라의 해변 마을. 마을 사람들 사이엔 인근에 바다괴물이 산다는 전설이 떠돈다. 실제로 바다에는 루카(제이콥 트렘블레이)를 비롯한 바다괴물 가족들이 산다. 루카의 부모는 루카에게 바다 밖을 경계하라 이르지만, 루카는 기어이 바다 밖 세상으로 향한다. 루카는 육지에선 인간의 모습으로 변하지만 물에 닿으면 바다괴물의 모습으로 돌아간다. 바다괴물 친구이자 육지 생활 선배인 알베르토(잭 딜런 그레이저)는 루카에게 두 다리로 걷는 법부터 자유와 일탈의 짜릿함까지 맛보게 한다. 급기야 인간 마을로 들어간 둘은 줄리아(엠마 버만)와 친구가 돼 함께 수영, 사이클, 파스타 빨리 먹기 3종 대회에 참가하는데...', 'https://image.tmdb.org/t/p/w500/cgQMmwPtSInmIvoQLJhoByBelGA.jpg', 2021, 0, 0, '2026-06-06 13:25:30.431557', 'US');
INSERT INTO public.movies VALUES (920, 11216, '시네마 천국', '["Drama", "Romance"]', NULL, '[]', '어린 시절 영화가 세상의 전부였던 소년 토토는 학교 수업을 마치면 마을 광장에 있는 낡은 시네마 천국이라는 극장으로 달려가 영사 기사 알프레도와 친구로 지내며 어깨너머로 영사기술을 배운다. 어느 날 관객들을 위해 광장에서 야외 상영을 해주던 알프레도가 그만 화재 사고로 실명하게 되고, 토토가 그의 뒤를 이어 시네마 천국의 영상기사로 일하게 된다. 실명한 후에도 토토의 친구이자 아버지로 든든한 정신적 지주가 되어준 알프레도는 청년이 된 토토가 사랑하는 여자 엘레나의 부모님의 반대로 좌절하자 넓은 세상으로 나가서 더 많은 것을 배우라며 권유하는데...', 'https://image.tmdb.org/t/p/w500/r782z4H7GzkyNaf3hAtBB4pVkOj.jpg', 1988, 0, 0, '2026-06-06 13:25:31.200353', 'US');
INSERT INTO public.movies VALUES (4237, 698700, '어린 처제', '["Romance"]', 'Choi Woo-seong', '["Park Joo-bin", "Kim Seon-i"]', '남자 친구와 헤어지고 혼자 여행을 하던 가은은 우연히 사촌 언니 가영의 집에 들리 게 된다. 어려서 친자매처럼 지냈던 가은과 가영은 오랜만에 보게 되고, 가은은 형부인 우성의 다정한 행동과 말에 오랜만에 웃게 된다. 가영이 붙잡는 바람에 가은은 며칠 더 지내게 되고, 가영이 갑자기 출장을 가게 되자 우성과 가은은 단둘이 집에 있게 되는데...', 'https://image.tmdb.org/t/p/w500/sn0VRzQDW3bVCmB7gunksaRvHJf.jpg', 2018, 0, 0, '2026-06-08 06:28:51.766267', 'KR');
INSERT INTO public.movies VALUES (4238, 1165642, '이 별에 필요한', '["Animation", "Romance", "Sci-Fi"]', 'Han Ji-won', '["Kim Tae-ri", "Hong Kyung", "Sharon Kwon", "Kang Ku-han", "An Young-mi"]', '화성으로 떠난 여자와 지구에 머무르는 남자. 운명처럼 만나 사랑에 빠진 그들 사이엔 아득히 넓고 깊은 우주가 놓여있다. 별과 별 사이를 뛰어넘는 설렘과 아련함이 가득한 로맨스 애니메이션 영화.', 'https://image.tmdb.org/t/p/w500/rVtwjG89FnHcvcIm9odmFtxTnNA.jpg', 2025, 0, 0, '2026-06-08 06:28:52.512295', 'KR');
INSERT INTO public.movies VALUES (811, 122906, '어바웃 타임', '["Drama", "Romance", "Fantasy"]', 'Richard Curtis', '["Domhnall Gleeson", "Rachel McAdams", "Bill Nighy", "Tom Hollander", "Margot Robbie"]', '모태솔로 팀은 성인이 된 날, 아버지로부터 놀랄만한 가문의 비밀을 듣게 된다.  바로 시간을 되돌릴 수 있는 능력이 있다는 것!  그것이 비록 히틀러를 죽이거나 여신과 뜨거운 사랑을 할 수는 없지만,  여자친구는 만들어 줄 순 있으리..  꿈을 위해 런던으로 간 팀은 우연히 만난 사랑스러운 여인 메리에게 첫눈에 반하게 된다.  그녀의 사랑을 얻기 위해 자신의 특별한 능력을 마음껏 발휘하는 팀.  어설픈 대시, 어색한 웃음은 리와인드! 뜨거웠던 밤은 더욱 뜨겁게 리플레이!  꿈에 그리던 그녀와 매일매일 최고의 순간을 보낸다.  하지만 그와 그녀의 사랑이 완벽해질수록 팀을 둘러싼 주변 상황들은 미묘하게 엇갈리고,  예상치 못한 사건들이 여기저기 나타나기 시작하는데…  어떠한 순간을 다시 살게 된다면, 과연 완벽한 사랑을 이룰 수 있을까?', 'https://image.tmdb.org/t/p/w500/cLfuuK1Y5FjX1xXDrrEa9ppnKuy.jpg', 2013, 0, 0, '2026-06-06 13:25:27.309302', 'GB');
INSERT INTO public.movies VALUES (954, 1497970, '톰과 제리: 황금나침반 대소동', '["Animation", "Comedy", "Family", "Fantasy", "Adventure"]', NULL, '[]', '세기의 콤비 톰과 제리, 최초 3D 탄생! 마법의 나침반을 깨운 톰과 제리의 차원이동이 시작된다! 박물관 경비원으로 일하는 톰은 몰래 들어온 제리를 쫓다 우연히 마법의 황금나침반을 깨우게 되고, 신비로운 빛에 휩싸여 동양의 한 고대도시에 불시착한다 뜻밖의 차원이동을 하게 된 톰과 제리는 300년 동안 고대도시를 지켜온 봉황사부와 그의 친구들을 만나 기상천외한 모험을 시작하는데…! 황금나침반을 이용해 천계로 돌아가야 하는 봉황사부와 톰과 제리의 시공을 초월한 모험이 펼쳐진다!', 'https://image.tmdb.org/t/p/w500/fwtu3bazam69kAIlzilf4irGroX.jpg', 2025, 0, 0, '2026-06-06 13:25:32.718626', 'US');
INSERT INTO public.movies VALUES (956, 14, '아메리칸 뷰티', '["Drama"]', NULL, '[]', '레스터 번햄은 좌절감으로 가득 찬 잡지사 직원으로 하루하루를 무기력 속에서 살아간다. 부동산 소개업자로 일하는 아내 케롤린은 수완가로 자처하고 완벽주의를 외치며 물질만능의 길을 추구한다. 둘의 결혼생활은 단지 남들에게 과시하기 위한 형식뿐이고, 외동딸 제인은 아버지가 사라져 주길 바랄 정도로 미워한다. 제인의 학교를 방문한 레스터는 딸의 되바라진 친구 안젤라를 보는 순간 한 눈에 욕정을 품게 된다. 레스터는 기억 속에서 이미 사라진 자신의 소년기를 회복하려는 듯이 자유를 추구하는데...', 'https://image.tmdb.org/t/p/w500/osdwif0XkFgalOCPksm4Yvczyzc.jpg', 1999, 0, 0, '2026-06-06 13:25:32.723252', 'US');
INSERT INTO public.movies VALUES (660, 384018, '분노의 질주: 홉스 & 쇼', '["Action", "Adventure", "Comedy"]', NULL, '[]', '이상한 약물에 의해 강력한 파워를 얻게 된 아나키스트 브릭스턴 로어는 인류를 천천히, 그리고 영원히 다른 존재로 바꿔버릴 수 있는 생화학무기를 손에 넣고 자신은 진화형 인간이 된다. 그런데 데카드 쇼의 동생이자 M16 요원인 해티 쇼가 치명적인 병원균이 들어 있는 실린더를 브릭스턴의 손에서 훔쳐 달아난다. 양국으로부터 해티의 행방을 찾아달라는 명령을 받은 루크와 데카드는 유전자 조작으로 사실상 파괴 불가능한 존재가 되어버린 브릭스턴을 상대로 힘겨운 싸움도 이겨나가야 하는데...', 'https://image.tmdb.org/t/p/w500/8MdVJYHKp7JFvTMkLkZOou13LYV.jpg', 2019, 0, 0, '2026-06-06 13:25:21.134735', 'US');
INSERT INTO public.movies VALUES (735, 24, '킬 빌: 1부', '["Action", "Crime"]', NULL, '[]', '어느 한적한 오후, 행복한 결혼식을 앞둔 더 브라이드와 그녀의 신랑, 그리고 모든 하객들이 의문의 조직에 의해 처참하게 살해당한다. 그로부터 5년 후, 코마상태의 더 브라이드는 죽음 직전까지 갔다가 어렵게 깨어난다. 그리고 피로 얼룩진 과거가 그녀의 뇌리에 스치면서 서서히 복수의 리스트를 작성하기 시작한다. 그녀는 전세계적으로 악명높은 살인조직 데들리 바이퍼의 일원이었고, 조직의 보스인 빌을 포함한 5명의 일원이 새로운 삶을 앞둔 그녀를 처참하게 무너뜨렸음이 밝혀지자, 그녀는 텍사스, 멕시코, 일본을 방문하며 가장 잔인한 복수를 실행하게 되는데...', 'https://image.tmdb.org/t/p/w500/lH82lk837fACeVZUmqHH0UiEeWL.jpg', 2003, 0, 0, '2026-06-06 13:25:24.196773', 'US');
INSERT INTO public.movies VALUES (4239, 505283, '사촌 누나', '["Romance", "Drama"]', 'Yoon Joong-boo', '["Ahn So-hee", "Min Do-yoon", "Kang Min-woo", "Yoo Hae-na", "Lee Mi-na"]', '"누나가 전부 다 알려줄게!" 신혼부부와 사촌누나의 아슬아슬 기묘한 동거가 시작된다!INSERT INTO public.movies VALUES (4240, 1223142, '흑형을 동경한 윗집 소녀', '["Drama", "Romance"]', 'Kim Ray', '["Ji Won", "Min Do-yoon", "Im Tae-mok", "White Sugar"]', NULL, 'https://image.tmdb.org/t/p/w500/fny6wiBD6BwkB0UXKnMaQda2lH9.jpg', 2023, 0, 0, '2026-06-08 06:28:54.047223', 'KR');
INSERT INTO public.movies VALUES (4242, 409276, '착한 여비서의 목적', '["Romance", "Drama"]', 'Kim Hyo-jae', '["Kim Do-hee", "Jung Won-II", "James"]', '“사장님, 저 ... 잘하죠? ”  완벽한 그녀의 말할 수 없는 비밀  대기업 임원들과 전문 기술 인력들을 중국과 거래하는 업체 . 주영철 대표의 비서가 출산 휴가를 가게 되어 그녀를 대신해 새로운 비서 지원이 입사를 하게 된다. 섹시한 외모가 한 눈에 들어오는 그녀. 외모와 능력 따듯한 성품까지 모두 갖춘 그녀를 직원들은 환영한다.  비 오는 밤, 늦게까지 야근을 하던 중 사무실에서 간단하게 맥주를 마시게 된 주 대표와 지원.  그의 업무를 방해하지 않기 위해 일찍 자리를 뜨는 그녀의 뒷모습에 아쉬움 든다. 남자직원들과 유쾌하게 대화하며 웃는 그녀를 보며 질투심을 느끼게 되는 주대표.  어느 날, 회식 후 지원을 집에 데려다 주던 주 대표는 지원의 집에서 그녀와 은밀한 사이로 발전하게 되는데... .', 'https://image.tmdb.org/t/p/w500/zXLx1o1x8u5ZbV7jpCJwWMg7Byf.jpg', 2016, 0, 0, '2026-06-08 06:28:55.524514', 'KR');
INSERT INTO public.movies VALUES (4243, 1240815, '그 술집의 사정 : 무삭제', '["Romance"]', NULL, '["Yoon Yool", "Min Do-yoon", "Kang Min-woo", "Ji Hee", "Kenny"]', NULL, 'https://image.tmdb.org/t/p/w500/oqfprRSQIAIeModlwdfezeaagVQ.jpg', 2021, 0, 0, '2026-06-08 06:28:56.287606', 'KR');
INSERT INTO public.movies VALUES (2740, 1658216, 'Stepdaddy', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/oZxNblisKuDzSUW5g18FERjyJs9.jpg', 2026, 0, 0, '2026-06-07 12:17:45.616186', 'US');
INSERT INTO public.movies VALUES (462, 68726, '퍼시픽 림', '["Action", "Sci-Fi", "Adventure"]', 'Guillermo del Toro', '["Charlie Hunnam", "Rinko Kikuchi", "Idris Elba", "Max Martini", "Clifton Collins Jr."]', '2025년, 태평양 연안의 심해에 커다란 균열이 일어난다. 정체를 알 수 없었던 이곳은 지구와 우주를 연결하는 포탈이었고 여기서 엄청난 크기의 외계 괴물 카이주가 나타난다. 일본 전역을 시작으로 미국, 중국, 러시아, 호주 등 지구 곳곳을 파괴하는 카이주의 공격에 전 세계가 혼돈에 빠지고, 전 지구적인 비상사태 돌입에 세계 각국의 정상들은 인류 최대의 위기에 맞서기 위한 범태평양연합방어군을 결성한다. 상상을 초월하는 수퍼 파워, 뇌파를 통해 파일럿의 동작을 인식하는 신개념 조종시스템을 장착한 예거와 이를 조종하는 최정예 파일럿들이 괴물들에게 반격을 시작하는데...', 'https://image.tmdb.org/t/p/w500/BWJhHHqeW5oCRvqLXF5twAFAga.jpg', 2013, 0, 0, '2026-06-06 13:25:14.071639', 'US');
INSERT INTO public.movies VALUES (765, 568124, '엔칸토: 마법의 세계', '["Animation", "Comedy", "Family", "Fantasy"]', NULL, '[]', '콜롬비아의 깊은 산 속, 놀라운 마법과 활기찬 매력이 넘치는 세계 엔칸토. 이곳을 만든 장본인은 마드리갈 가문의 기둥인 알마 할머니다. 그녀는 젊었을 때 세 쌍둥이를 데리고 이곳으로 오던 중에 위기를 맞았다. 그때 그녀가 들고 있던 촛불에 기적이 일어났고 그이후로 마법의 능력이 손주 세대까지 대물림된다. 3대에 걸친 이대가족은 음식으로 병을 고치는 능력, 꽃을 피우는 능력, 날씨를 조종 하는 능력 등 저마다 독특한 능력을 지니게 됐다. 하지만 가족 중 유일하게 미라벨만 아무런 능력이 없다. 어느 날 엔칸토가 지닌 마법의 힘이 위험에 처하고 가족들은 점차 자신의 능력을 잃어가기 시작한다. 이를 감지한 미라벨은 유일하게 평범한 자신이 특별한 이 가족의 마지막 희망일지 모른다고 생각하는데...', 'https://image.tmdb.org/t/p/w500/8xoP2YfCmhhVUZ0jfLjVl45oM2U.jpg', 2021, 0, 0, '2026-06-06 13:25:25.716862', 'US');
INSERT INTO public.movies VALUES (858, 335, '옛날 옛적 서부에서', '["Drama"]', NULL, '[]', '프랭크가 보낸 세명의 총잡이가 기차역에서 누군가를 기다린다. 드디어 그들이 기다리던 한 남자가 하모니카를 불며 기차역에 도착하고, 그들 세 총잡이는 모두 이름 없는 그 남자의 총에 쓰러진다. 한편, 프랭크와 그 부하들은 아일랜드 출신인 맥베인 일가를 잔인하게 살해하는데, 뉴올리언즈에서 이제 막 도착한 맥베인의 새 아내 질로서는 황망할 수밖에 없다. 두 사람은 한달 전 이미 결혼을 한 상태였다.  다시 뉴올리언즈로 돌아가려던 질은 마음을 고쳐먹고 맥베인과 아이들의 시체만 있는 그 집에서 혼자 생활을 시작한다.', 'https://image.tmdb.org/t/p/w500/3MPqF2iK6ZBoagnB5H1pjImHpHc.jpg', 1968, 0, 0, '2026-06-06 13:25:28.879545', 'US');
INSERT INTO public.movies VALUES (4241, 653127, '여자 하숙집 3', '["Romance"]', 'Jo Tae-ho', '["Park Hyun-jung", "Kim In-ae", "Yoon Da-hyeon", "Choi Chul-min"]', '외로운 하숙집 여자들! 힌 번 들어온 남자는 그냥 못 보내요!INSERT INTO public.movies VALUES (4255, 995926, '베테랑 2', '["Action", "Crime", "Comedy"]', 'Ryoo Seung-wan', '["Hwang Jung-min", "Jung Hae-in", "Oh Dal-su", "Oh Dae-hwan", "Jang Yoon-ju"]', '가족들도 못 챙기고 밤낮 없이 범죄들과 싸우는 베테랑 형사 서도철과 강력범죄수사대 형사들. 어느 날, 한 교수의 죽음이 이전에 발생했던 살인 사건들과 연관성이 있는 것으로 밝혀지며 전국은 연쇄살인범으로 인해 떠들썩해진다. 이에 단서를 추적하며 수사를 시작한 형사들. 하지만 이들을 비웃기라도 하듯, 연쇄살인범은 다음 살인 대상을 지목하는 예고편을 인터넷에 공개하며 또 한 번 전 국민을 흔들어 놓는다. 강력범죄수사대는 서도철의 눈에 든 정의감 넘치는 막내 형사 박선우를 투입한다. 그리고 사건은 새로운 방향으로 흐르게 되는데...', 'https://image.tmdb.org/t/p/w500/akqfhtM1Wa1klFi7ijmyNm7Sm1j.jpg', 2024, 0, 0, '2026-06-08 06:29:25.769463', 'KR');
INSERT INTO public.movies VALUES (241, 396535, '부산행', '["Horror", "Thriller", "Action", "Adventure"]', 'Yeon Sang-ho', '["Gong Yoo", "Kim Su-an", "Jung Yu-mi", "Don Lee", "Choi Woo-shik"]', '별거 중인 펀드 매니저 석우는 소원해진 딸 수안의 생일 소원을 들어주기 위해 아내가 있는 부산행 KTX에 오른다. 이내 열차는 좀비의 침투와 감염으로 아수라장으로 변하고, 전국적 재난 뉴스를 차내에서 접한 승객들의 생존가능성은 유일하게 초기 대응에 성공한 도시 부산까지 살아남은 채 도착할 수 있느냐에 달리게 된다. 열차에 몸을 실은 석우와 딸 수안, 상화와 성경 커플, 고등학생 영국, 진희, 그리고 노숙자와 중년의 비즈니스맨 용석은 감염된 사람들의 공격을 피해 열차 안에서 사투를 벌인다.', 'https://image.tmdb.org/t/p/w500/6XvEZVBFFjybvb1yQd1qfOC6F2S.jpg', 2016, 0, 0, '2026-06-06 13:25:05.599449', 'KR');
INSERT INTO public.movies VALUES (184, 7451, '트리플 엑스', '["Action", "Adventure", "Thriller", "Crime", "Drama"]', 'Rob Cohen', '["Vin Diesel", "Asia Argento", "Marton Csokas", "Samuel L. Jackson", "Michael Roof"]', '싸이렌이 온 거리를 울려 퍼지며 요란한 추격씬이 벌어지는 도중 한 녀석이 콜벳를 몰고 다리를 돌진, 200미터 높이에서 자동차 번지를 시도한다. 짜릿한 곡예를 선보인 후 낙하산을 펴고 유유히 사라지는 녀석의 이름은 ''젠더 케이지''. 인터넷에 생방송된 이 장면은 전세계 네티즌들에게 열렬한 환호를 받는다. 또 한 번의 멋진 프로젝트로 영웅 대접을 받는 젠더 케이지. 그러나 파티가 무르익을 무렵, 갑자기 들이닥친 특수부대는 그에게 신경 안정제를 쏜 후 잠들게 한다. 깨어난 곳은 알 수 없는 레스토랑. 어리둥절한 그 곳은 갑자기 강도들의 침입장으로 돌변하고, 단숨에 상황을 정리해버린 그에게 기븐스가 축하 인사를 전한다. 미국 비밀첩보국 NSA의 1차 테스트를 통과한 것. 이후 또 다시 잠에서 깨어난 곳은 비행기 안. 2번째 테스트로 콜럼비아 마약 밀매상의 아지트에 던져진 젠더 케이지. 때마침 콜럼비아 정부와 마약상들의 충돌로 아수라장이 된 그곳에서 살아남기 위한 치열한 전쟁이 펼쳐지는데...  상황종료 후 유유히 나타난 기븐스는 NSA의 테스트를 유일하게 통과한 그에게 비밀요원이 되어줄 것을 부탁한다. 단 그렇지 않을 경우는 감옥행뿐이라는 단서를 둔다. 젠더 케이지의 코드명은 트리플 X. 첫번째 임무지는 비밀요원의 무덤이라는 별칭을 가지고 있는 도시 프라하. 이제 얼떨결에 비밀요원이 되어버린 트리플 X의 위험한 여정이 시작되는데.', 'https://image.tmdb.org/t/p/w500/ysmsesGYF83VZXSvkG8ZdNNCKAz.jpg', 2002, 0, 0, '2026-06-06 13:25:03.323455', 'US');
INSERT INTO public.movies VALUES (488, 102382, '어메이징 스파이더맨 2', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '스파이더맨의 삶에 완전히 적응한 피터 파커는 거미줄로 뉴욕을 활강하며 위험에 처한 시민들을 구해주고 사랑하는 연인 그웬과 데이트를 즐기며 행복하게 살아간다. 그러던 어느 날, 스파이더맨의 열렬한 팬이자 오스코프사의 전기 엔지니어인 맥스는 작업 중 치명적인 사고로 자신에게 엄청난 능력이 생긴 것을 발견한다. 하지만 이 능력으로 인해 뉴욕을 마비시킨 대규모 정전사태가 발생하고 사태를 해결하기 위해 나선 자신의 영웅 스파이더맨에게 공격을 당하자 배신감을 느끼고 분노하는데...', 'https://image.tmdb.org/t/p/w500/eYaFLrKuEdzrGw6XG5ZTVciH28v.jpg', 2014, 0, 0, '2026-06-06 13:25:14.872571', 'US');
INSERT INTO public.movies VALUES (282, 1726, '아이언맨', '["Action", "Sci-Fi", "Adventure"]', 'Jon Favreau', '["Robert Downey Jr.", "Terrence Howard", "Jeff Bridges", "Gwyneth Paltrow", "Leslie Bibb"]', '천재적인 두뇌와 재능으로 세계 최강의 무기업체를 이끄는 CEO이자, 타고난 매력으로 셀러브리티 못지않은 화려한 삶을 살아가던 억만장자 토니 스타크. 아프가니스탄에서 자신이 개발한 신무기 발표를 성공리에 마치고 돌아가던 그는 게릴라군의 갑작스런 공격에 의해 가슴에 치명적인 부상을 입고 게릴라군에게 납치된다. 가까스로 목숨을 건진 그에게 게릴라군은 자신들을 위한 강력한 무기를 개발하라며 그를 위협한다. 그러나 그는 게릴라군을 위한 무기 대신, 탈출을 위한 무기가 장착된 철갑수트를 몰래 만드는 데 성공하고, 그의 첫 수트인 ‘Mark1’를 입고 탈출에 성공한다. 미국으로 돌아온 토니 스타크는 자신이 만든 무기가 많은 사람들의 생명을 위협하고, 세상을 엄청난 위험에 몰아넣고 있다는 사실을 깨닫고 무기사업에서 손 뗄 것을 선언한다. 그리고, Mark1을 토대로 최강의 하이테크 수트를 개발하는 데 자신의 천재적인 재능과 노력을 쏟아 붓기 시작한다. 탈출하는 당시 부서져버린 Mark1을 바탕으로 보다 업그레이드 된 수트 Mark2를 만들어낸 토니 스타크. 거기에 만족하지 않고, 숱한 시행착오와 실패 끝에 자신의 모든 능력과 현실에서 가능한 최강의 최첨단 과학 기술이 집적된 하이테크 수트 Mark3를 마침내 완성, 최강의 슈퍼히어로 ‘아이언맨’으로 거듭난다. 토니 스타크가 탈출하는 과정을 통해 Mark1의 가공할 위력을 확인한 게릴라 군은 토니 스타크가 미처 회수하지 못한 Mark1의 잔해와 설계도를 찾아낸다. Mark1을 재조립하여 그들의 목적을 이루기 위한 거대하고 강력한 철갑수트를 제작하려는 음모를 꾸미는 게릴라군. 토니 스타크가 갖고 있던 에너지원을 훔쳐 ‘아이언맨’을 능가하는 거대하고 강력한 ‘아이언 몽거’를 완성한 그들은 세계 평화를 위협하고, 토니 스타크는 그들의 음모과 배후세력이 누구인지를 알게 되는데...!', 'https://image.tmdb.org/t/p/w500/ziReGUV3xURsWmcmsn2GOunPc0L.jpg', 2008, 0, 0, '2026-06-06 13:25:07.154163', 'US');
INSERT INTO public.movies VALUES (300, 585, '몬스터 주식회사', '["Animation", "Comedy", "Family", "Fantasy"]', 'Pete Docter', '["John Goodman", "Billy Crystal", "Mary Gibbs", "Steve Buscemi", "James Coburn"]', '호탕한 설리와 재치만점 마이크는 몬스터 주식회사 겁주기 팀의 최우수 콤비다. 매일 밤 투철한 직업정신으로 인간 세계로 통하는 벽장 문을 열던 설리와 마이크 콤비는 어느 날 일생일대의 실수를 저지른다. 덜 닫힌 벽장 문 사이로 인간아이 부가 몬스터 세계에 침입한 것. 설리와 마이크는 부를 인간세계로 돌려보내고 사건을 조용히 수습하려 하지만 부는 설리를 무서워하기는커녕 애완 야옹이쯤으로  생각하고 쫄래쫄래 따라다닌다. 부의 침입이 발각되자 몬스터 주식회사는 발칵 뒤집히고 마는데...', 'https://image.tmdb.org/t/p/w500/fnDLrtEoIrxTCWUvuurMzOzQGpQ.jpg', 2001, 0, 0, '2026-06-06 13:25:07.199277', 'US');
INSERT INTO public.movies VALUES (2511, 12104, '핑크 플로이드의 벽', '["Drama"]', 'Alan Parker', '["Bob Geldof", "Christine Hargreaves", "James Laurenson", "Eleanor David", "Kevin McKeon"]', '전쟁으로 아버지를 잃은 핑크(Pink: 봅 제도프 분)는 엄마와 단둘이 외롭게 살아간다. 늘 혼자인 핑크는 전쟁 공포증과 더불어 자유로운 사고를 가로막는 교육 제도에 적응하지 못하고 방황한다. 이런 부적응이 세상이 다 자신을 향해 쌓은 벽이라 생각한 그는 틀에 박힌 관념과 행동양식에 파괴의식을 느낀다. 성장하여 록스타가 되었지만 사람들의 박수는 참을 수 없는 짐이 되고, 사랑에도 실패한 핑크는 세상과 벽을 쌓는 자학적인 행동을 하면서 소외도디고 불안정한 생활을 지속한다.', 'https://image.tmdb.org/t/p/w500/aElHyIdF5jmctFGhlhhaPFsbBJC.jpg', 1982, 0, 0, '2026-06-07 12:17:35.798007', 'GB');
INSERT INTO public.movies VALUES (536, 338803, '간신', '["Drama", "History", "Crime"]', 'Min Kyu-dong', '["Ju Ji-hoon", "Kim Kang-woo", "Lim Ji-yeon", "Lee You-young", "Cheon Ho-jin"]', '연산군 11년, 1만 미녀를 바쳐 왕을 쥐락펴락하려는 자가 득실거리니,  그야말로 간신들의 시대가 도래했다.  “단 하루에 천년의 쾌락을 누리실 수 있도록 준비하겠나이다!”  연산군은 임숭재를 채홍사로 임명하여 조선 각지의 미녀를 강제로 징집했고, 그들을 운평이라 칭하였다.  최악의 간신 임숭재는 이를 기회로 삼아 천하를 얻기 위한 계략을 세우고, 양반집 자제와 부녀자, 천민까지 가릴 것 없이 잡아들이니 백성들의 원성이 하늘을 찔렀다.  "왕을 다스릴 힘이 내 손안에 있습니다!  내가 바로 왕 위의 왕이란 말입니다!"  임숭재와 임사홍 부자는 왕을 홀리기 위해 뛰어난 미색을 갖춘 단희를 간택해 직접 수련하기 시작하고, 임숭재 부자에게 권력을 뺏길까 전전긍긍하던 희대의 요부 장녹수는 조선 최고의 명기 설중매를 불러들여 단희를 견제한다.  한 치도 물러설 수 없는 간신들의 치열한 권력다툼이 시작되고, 단희와 설중매는 살아남기 위해 조선 최고의 색(色)이 되기 위한 수련을 하게 되는데…', 'https://image.tmdb.org/t/p/w500/wjHi19IHTq6VmOtSENnLbkhUiMk.jpg', 2015, 0, 0, '2026-06-06 13:25:16.470623', 'KR');
INSERT INTO public.movies VALUES (856, 639988, '어쩔수가없다', '["Comedy", "Crime", "Thriller"]', 'Park Chan-wook', '["Lee Byung-hun", "Son Ye-jin", "Park Hee-soon", "Lee Sung-min", "Yeom Hye-ran"]', '다 이루었다는 생각이 들 만큼 삶에 만족하던 25년 경력의 제지 전문가 만수. 아내 미리, 두 아이, 반려견들과 함께 행복한 일상을 보내던 만수는 회사로부터 돌연 해고 통보를 받는다. 목이 잘려 나가는 듯한 충격에 괴로워하던 만수는, 가족을 위해 석 달 안에 반드시 재취업하겠다고 다짐한다. 그 다짐이 무색하게도, 그는 1년 넘게 마트에서 일하며 면접장을 전전하고, 급기야 어렵게 장만한 집마저 빼앗길 위기에 처한다. 무작정 문 제지를 찾아가 필사적으로 이력서를 내밀지만, 선출 반장 앞에서 굴욕만 당한다. 문 제지의 자리는 누구보다 자신이 제격이라고 확신한 만수는 모종의 결심을 한다.', 'https://image.tmdb.org/t/p/w500/9w7WGjQes0Cs0s4U3Qr09Tg1Sra.jpg', 2025, 0, 0, '2026-06-06 13:25:28.875048', 'KR');
INSERT INTO public.movies VALUES (372, 9502, '쿵푸팬더', '["Action", "Animation", "Comedy", "Family"]', 'Mark Osborne', '["Jack Black", "Dustin Hoffman", "Angelina Jolie", "Ian McShane", "Seth Rogen"]', '평화의 계곡에서 아버지의 국수 가게를 돕고 있는 팬더 포. 아버지는 국수의 비법을 알려주어 가업을 잇게 하고 싶지만, 포의 관심사는 오로지 쿵푸 마스터. 가게 일은 뒷전으로 하고 쿵푸의 비법이 적힌 용문서의 전수자를 정하는 무적의 5인방 대결을 보러 시합장을 찾은 포. 그런데 마을의 현인 우그웨이 대사부가 포를 용문서의 전수자로 점지하는 이변이 일어난다. 무적의 5인방은 물론 시푸 사부 역시 이 사태를 받아들이지 못하는 가운데, 용문서를 노리고 어둠의 감옥에서 탈출한 타이 렁이 마을을 습격해오자 그를 막아야 하는 미션이 포에게 떨어지는데...', 'https://image.tmdb.org/t/p/w500/c3Dzd3A3QE0LkKb5HMOHTzs2Fyg.jpg', 2008, 0, 0, '2026-06-06 13:25:10.229215', 'US');
INSERT INTO public.movies VALUES (352, 62177, '메리다와 마법의 숲', '["Adventure", "Animation", "Family", "Fantasy"]', 'Mark Andrews', '["Kelly Macdonald", "Emma Thompson", "Billy Connolly", "Julie Walters", "Robbie Coltrane"]', '스코틀랜드의 공주 메리다는 부왕 퍼거스와 왕비 엘리노의 관심과 애정 속에 행복한 나날을 보낸다. 유일한 골칫거리는 엄마의 끊임없는 간섭과 참견. 어린 시절부터 활쏘기와 말타기를 더 좋아하는 공주에게 왕국의 공주로서 요구되는 정숙과 위엄은 거추장스러울 뿐이다. 그러던 어느 날 세 부족장의 아들들이 정식으로 공주에게 청혼을 하고 더 이상 참을 수 없어진 메리다는 신랑 후보들에게 망신을 준 뒤 성을 뛰쳐나온다. 금지된 숲을 헤매다 마녀를 만난 그녀는 엄마의 마음을 바꿀 수 있는 마법을 부탁한다. 하지만 자신의 소원 때문에 엄마가 곰으로 변해버리고 엄마를 인간으로 되돌리기 위한 메리다의 모험이 시작된다.', 'https://image.tmdb.org/t/p/w500/uzVUEQ6PPGGsETviLwVKSzS8OUG.jpg', 2012, 0, 0, '2026-06-06 13:25:09.470679', 'US');
INSERT INTO public.movies VALUES (206, 315635, '스파이더맨: 홈커밍', '["Action", "Adventure", "Sci-Fi"]', 'Jon Watts', '["Tom Holland", "Michael Keaton", "Robert Downey Jr.", "Marisa Tomei", "Jon Favreau"]', '토니 스타크의 제안을 받고 시빌 워에 참여한 피터 파커는 다음 임무가 언제일지 설렘을 안고 하루하루를 보낸다. 토니는 MIT 진학 준비에 전념할 것을 권하지만 친절한 이웃에 머무는 것은 피터의 성에 차지 않는다. 한편 어벤져스 군단과 외계 세력의 전투로 생긴 산업폐기물을 처리하던 아드리안 툼즈는 그 일이 토니 스타크와 정부에 넘어가면서 하루아침에 빈털터리가 된다. 이에 앙심을 품은 아드리안은 외계 첨단무기를 훔쳐서 개조하는 빌런이 되고, 그의 존재를 알게 된 피터는 도움을 빌리지 않고 자기가 일을 해결해보려고 한다.', 'https://image.tmdb.org/t/p/w500/hjki9weYYVABvkpZbX5jBOmKXXv.jpg', 2017, 0, 0, '2026-06-06 13:25:04.094079', 'US');
INSERT INTO public.movies VALUES (703, 286687, '화려한 외출', '["Romance", "Drama", "Comedy"]', 'Ko Kyeong-Ah', '["Kim Sun-young", "Byun Jun-suk", "Oh Cho-hee", "Kim Ji-hoon", "Heo Jung-min"]', '화려한 겉과 달리 외로움에 빠져 있던 한 여인이  우연히 마주친 소년에게 사랑을 가르쳐주면서 진정한 사랑을 다시 느끼는  19금 힐링 로맨스  완성한 곡마다 히트를 기록하는 잘 나가는 작곡가, 희수!  그러나 새로운 곡을 써야 하는 상황에 직면했으나 아무래도 영감이 떠오르지 않는다.  외로움에 익숙해지다 못해 연애세포가 죽어가는 것 같은 이 기분을 어쩌지?  감정을 다 소모해버린 것 같은 허탈감에 젖어있던 희수는 아파트 엘리베이터에서 우연히 소년과 마주치고,  자신의 육감적 몸매에 흔들리는 소년의 눈빛에서 새로운 노래의 영감을 발견한다.  소년에게 음악을 가르쳐주는 것을 핑계로, 러브 레슨을 시작한 희수!  시간이 흐를수록 소년은 희수에게 빠져들고 희수는 소년을 보며 새로운 곡을 완성해나간다.  그런데, 희수에게 음악과 사랑을 가르쳐 주었던 인생의 스승 준호가 돌아왔다?  외로움에 무감각해져 가던 희수에게 가슴 떨리는 사랑을 다시 불러일으킬 남자는 과연 누구?!  작곡가 희수, 그녀의 짜릿한 음악이 지금 시작된다!', 'https://image.tmdb.org/t/p/w500/1bMvC9fOTQSfwIGwXBJNcy2cV9N.jpg', 2013, 0, 0, '2026-06-06 13:25:23.385482', 'KR');
INSERT INTO public.movies VALUES (1000, 532794, '성판17: 남자들의 17가지 성적 판타지', '["Comedy", "Drama", "Romance"]', 'Song Eun-joo', '["Choi Jae-hwan", "Park Kyoung-hee", "Kim Nam-soo", "Park Ha-on", "Jo Ah-rang"]', '기하가 꿈꾸는 성적 판타지…  난데없이 나타난 조희가 실현시켜 준다. 그녀는 누구인가?  여자친구 영은이 딴 남자와 침대에서 뒹굴고 있는 모습을 본 기하! 오 마이 갓!  격한 배신감에 사무쳐 있을 즈음, 난데없이 기하가 사는 옥탑 옆 건물에 조희라는 여자가 이사를 온다. 예쁘고 다정해 보이는 조희, 기하에게 호감을 보이는 것은 물론 제대로 된 섹스 경험이 없는 기하가 “소원이 섹스…” 라고 하자, 한 술 더 떠서 기하의 판타지 속 섹스를 실현해 주겠다고 한다. 단 3주 후면 조희는 어딘가로 떠나야 한다고 하는데...  인정받는 연기파 배우 “최재환”, 아이돌 출신 배우 “박경희”의 거침없는 노출 연기  당신의 모든 성적 판타지를 이루어줄 이야기!', 'https://image.tmdb.org/t/p/w500/86cLgLKNkHUUyHsgvWCpuh10JLZ.jpg', 2017, 0, 0, '2026-06-06 13:25:34.281001', 'KR');
INSERT INTO public.movies VALUES (475, 106, '프레데터', '["Sci-Fi", "Action", "Adventure", "Thriller"]', 'John McTiernan', '["Arnold Schwarzenegger", "Carl Weathers", "Kevin Peter Hall", "Elpidia Carrillo", "Bill Duke"]', '더치와 특수부대 동료들은 CIA와 계약을 맺어 중앙 아메리카 정글에서 게릴라들에게 붙잡힌 조종사를 구하러 간다. 임무는 순조롭게 진행되었으나 그들은 귀환 도중 무언가로 부터 공격을 받는다. 보이지 않는 적은 정글 속에 숨어서 그들의 사체를 전리품으로 수집해간다.  이 외계 괴물은 더치의 동료들을 하나씩 죽이면서 유희를 벌이는데...', 'https://image.tmdb.org/t/p/w500/AjYcJsuiqW4sHFEmh5SVSy5PswH.jpg', 1987, 0, 0, '2026-06-06 13:25:14.102736', 'US');
INSERT INTO public.movies VALUES (459, 16869, '바스터즈: 거친 녀석들', '["Drama", "Thriller"]', 'Quentin Tarantino', '["Brad Pitt", "Mélanie Laurent", "Christoph Waltz", "Eli Roth", "Michael Fassbender"]', '2차 세계 대전, 나치의 잔인하고 폭력적인 행태에 분개한 미군 알도 레인 중위는 당한 만큼 돌려준다는 강렬한 신념으로 최고의 재능을 가진 8명의 대원을 모아 바스터즈란 군단을 만들어 나치가 점령한 프랑스에 잠입해 복수를 시작한다. 어느 날 알도 레인 중위는 독일의 여배우이자 영국의 더블 스파이인 브리짓에게 뜻밖의 소식을 듣는다. 나치 수뇌부가 모두 참석하는 독일 전쟁 영화의 프리미어에 히틀러도 참석을 한다는 것. 한 번에 나치를 모두 쓸어버릴 계획으로 바스터즈는 이탈리아 영화 관계자로 분장해 극장으로 향하는데...', 'https://image.tmdb.org/t/p/w500/4eQ2DQi2Vb8oYN9IRAca8vaALNl.jpg', 2009, 0, 0, '2026-06-06 13:25:13.338932', 'US');
INSERT INTO public.movies VALUES (535, 809, '슈렉 2', '["Animation", "Comedy", "Family", "Fantasy", "Romance"]', NULL, '[]', '더 크고 신나는 세상! "겁나먼" 왕국에서 펼쳐지는 끝없는 상상!  꿈결같은 허니문에서 돌아온 슈렉과 피오나. 이 행복한 녹색 커플은 "겁나먼" 왕국의 왕과 왕비인 피오나의 부모님으로부터 초청장을 받는다. 드디어 도착한 왕국에는 모든 시민들이 기대에 부풀어 그들을 기다리고 있는데... 덜리는 맘으로 슈렉이 모습을 드러내는 순간, 멋진 왕자를 기대했던 모든 이들은 기절초풍! 초록색이 되어버린 공주는 말할 것도 없이 말이다. 발칵 뒤집힌 "겁나먼" 왕국. 이제 이 충격적인 사건을 해결하기 위해 만만치 않은 강적들이 속속 등장한다. 업계 1위의 괴물 전문 킬러 ''장화신은 고양이'', 퍼펙트한 외모의 왕자 ''프린스 챠밍'', 신비한 힘을 가진 요정 대모까지. 성가신 건 질색인 슈렉에게 터져버린 대형 사고! 또 다시 의도하지 않은 사건에 휘말린 슈렉 패밀리 앞에 상상할 수 없는 예측 불허의 모험들이 펼쳐지는데...', 'https://image.tmdb.org/t/p/w500/2yYP0PQjG8zVqturh1BAqu2Tixl.jpg', 2004, 0, 0, '2026-06-06 13:25:16.468365', 'US');
INSERT INTO public.movies VALUES (586, 578, '죠스', '["Horror", "Thriller", "Adventure"]', NULL, '[]', '뉴 잉글랜드의 작은 해안 피서지 애미티(Amity). 아주 평화로운 바닷가 마을로, 우정이란 뜻을 가진 이 마을은 전형적인 작은 바닷가 마을이다. 이곳은 여름 피서객들을 상대로 하는 것이 마을 수입의 전부다. 여름이 되어 막 해수욕장이 개장하기에 앞서 한 무리의 젊은이들이 한밤의 백사장에서 캠프파이어를 하며 젊음을 불태우고 있다. 이때 한 여자가 옷을 하나씩 벗어 던지면 모래밭을 달려가더니 바다로 헤엄쳐 들어간다. 달빛 아래 바다. 하지만 그 여자는 갑자기 무언가에 물리기라도 한 것처럼 바닷물 속으로 빨려 들어가더니 사라져버린다.  다음날, 바닷물을 싫어하는 도시 출신의 브로디 경찰서장이 전화를 받는다. 여자의 시체가 발견되었다는 것. 악어나 상어에게 묻어 뜯긴 게 분명한 그 시체는 찢겨져 있었고, 그는 즉시 해안을 폐쇄한다. 하지만, 마을의 책임자인 시장은 이 마을은 피서객들로 돈을 버는 곳이데 어떻게 하려고 그러느냐면서, 해안 경비를 강화하고, 감시 속에서 여름 해수욕장을 개장시킨다.  하지만 결국 일은 터지고, 한 소년이 상어의 습격을 받게 된다. 이제 이 마을은 상어의 공포에 휩싸이게 된다. 상어에 현상금이 붙자 상어사냥꾼들이 몰려든다. 하지만 다들 별볼 일 없이 그저 상금만 노리고 온 사람들이다. 그러나 그중에 두 명의 전문가가 찾아온다. 바로 상어 박사인 마틴 후퍼와 이 마을의 어부이자 카리스마 넘치는 퀸터 선장이 그들이다. 결국 브로디 서장과 퀸터 선장, 매트 박사는 배를 타고 바다로 나가 상어 사냥에 나서는데...', 'https://image.tmdb.org/t/p/w500/hbTQy1uBV4xzqHDIbWsMnCcR7J0.jpg', 1975, 0, 0, '2026-06-06 13:25:18.760486', 'US');
INSERT INTO public.movies VALUES (2159, 13333, '사망유희', '["Drama", "Action", "Thriller"]', NULL, '[]', '연예인들을 상대로 거액의 돈을 상습적으로 갈취하는 범죄 조직이 인기 액션 배우 빌리(이소룡)에게도 위협을 가한다. 빌리는 자신의 출연작에서 화려한 액션 연기를 보여 주는 것뿐만 아니라 실제로도 무술 고수였고, 그런 빌리는 범죄 조직의 협박에도 꿈쩍하지 않는다. 그러자 범죄 조직의 두목 닥터 랜드는 살인 청부업자를 고용하여 빌리를 암살하려 하지만 이는 곧 실패로 끝나게 된다. 끊임없는 암살 작전에 빌리는 자신이 죽은 것으로 위장한 뒤, 닥터 랜드의 조직을 차례차례 소탕해 나가기로 마음 먹는데...', 'https://image.tmdb.org/t/p/w500/skPlqRoNG7bfV6ABoE8KLFr6j0P.jpg', 1978, 0, 0, '2026-06-07 12:17:19.854101', 'US');
INSERT INTO public.movies VALUES (2536, 18240, '프로포즈', '["Comedy", "Romance", "Drama"]', NULL, '[]', '나만 믿어! 금방 이혼해줄께? 전 세계를 뒤집어 버린 협박보다 무서운(?) 청혼. 성공가도를 달리는 뉴욕의 출판사 편집장인 마가렛 과 그녀가 가혹하게 부려 먹어온 부하직원인 앤드류 가 이 수상한 청혼의 당사자들이다. 마가렛이 모국인 캐나다로 추방당할 위기에 처하자 앤드류에게 자신과 결혼해 줄 것을 명령하고, 앤드류 또한 승진이란 짜릿한 대가에 혹한 나머지 마녀 같은 상사의 약혼자 행세를 하면서 박장대소의 이야기를 부풀려간다.', 'https://image.tmdb.org/t/p/w500/yM0HNVCWfrb5VrFgPQMec2SmfrZ.jpg', 2009, 0, 0, '2026-06-07 12:17:36.652609', 'US');
INSERT INTO public.movies VALUES (948, 287649, '마담 뺑덕', '["Thriller", "Drama", "Romance"]', 'Yim Pil-sung', '["Jung Woo-sung", "Esom", "Park So-young", "Kim Hie-won", "Park Seo-yeon"]', '불미스러운 오해에 휘말려, 지방 소도시 문화센터의 문학 강사로 내려온 교수 학규는 퇴락한 놀이공원의 매표소 직원으로, 고여있는 일상에 신물 난 처녀 덕이와 걷잡을 수 없는 사랑에 빠진다. 그러나 학규는 복직이 되자마자 서울로 돌아가고 덕이는 버림 받는다. 8년 후, 학규는 작가로 명성을 얻지만 딸 청이는 엄마의 자살이 아버지 탓이라 여기며 반항하고, 학규는 눈이 멀어져 가는 병까지 걸린다. 모든 것을 잃을 위기에 처한 학규의 앞 집으로 이사 온 여자 세정. 눈이 거의 보이지 않는 학규가 세정이 8년 전 덕이라는 걸 모른 채 그녀에게 의지하는 사이, 청이 또한 그녀에게 집착하게 된다. 덕이 없이 아무것도 못하게 된 학규, 그리고 두 사람 사이를 눈치채고 위험한 질투를 시작하는 청이. 세 사람의 위태로운 관계의 한 가운데, 마침내 주도권을 쥔 덕이는 학규의 모든 것을 망가뜨리려고 하는데…', 'https://image.tmdb.org/t/p/w500/trvtnsNZjHwvB97RLQ3Nc5oncti.jpg', 2014, 0, 0, '2026-06-06 13:25:32.703735', 'KR');
INSERT INTO public.movies VALUES (537, 1495694, '뷰티 프롬 페인', '["Romance", "Drama"]', NULL, '[]', '참담한 이별을 겪은 후, 한 음악 지망생이 호주로 도피한다. 그녀는 억만장자 와인 제조업자와 조건 없는 연애를 하기로 동의하지만, 사랑에 빠지게 되자 떠나야 할지, 사랑을 두려워하는 남자에게 마음을 걸어야 할지 선택해야 한다.', 'https://image.tmdb.org/t/p/w500/mJtBKvHQaFzgp0N6JFskSvjbTar.jpg', 2025, 0, 0, '2026-06-06 13:25:16.472873', 'US');
INSERT INTO public.movies VALUES (626, 118, '찰리와 초콜릿 공장', '["Adventure", "Comedy", "Family", "Fantasy"]', NULL, '[]', '전 세계 누구에게나 사랑 받는 윌리 웡카 초콜릿 공장. 매일 엄청난 양의 초콜릿을 생산해 세계 각국으로 운반하고 있지만 그 누구도 공장을 드나 드는 사람을 본 적이 없는 비밀의 공간이다. 공장보다 더 신비로운 수수께끼는 공장장인 윌리 웡카라는 인물. 소문에 의하면 웡카는 몇 년 동안 공장 밖으로 나가본 적도 없다고 한다. 어느 날 윌리 웡카가 5개의 웡카 초콜릿에 감춰진 행운의 황금티켓을 찾은 어린이 다섯 명에게 자신의 공장을 공개하고 그 모든 제작과정의 비밀을 보여주겠다는 선언을 한다. 이제 전 세계 어린이들은 황금티켓을 찾기 위한 노력을 시작한다.', 'https://image.tmdb.org/t/p/w500/iKP6wg3c6COUe8gYutoGG7qcPnO.jpg', 2005, 0, 0, '2026-06-06 13:25:20.325019', 'US');
INSERT INTO public.movies VALUES (689, 436969, '더 수어사이드 스쿼드', '["Action", "Comedy", "Adventure"]', NULL, '[]', '최고의 사망률을 자랑하는 벨 리브 교도소. 미국 정보국 월러 국장은 태스크 포스 X라는 극비 군사 작전팀을 꾸리기 위해 이곳에 왔다. 그녀는 수감 중인 슈퍼 빌런들을 팀에 합류시키기 위해 사면이나 감형을 조건으로 제시한다. 또한 만약을 대비해 언제라도 이들을 처형할 수 있게 머리에 폭탄도 심어놓는다. 우여곡절 끝에 완성된 팀은 두개로 나뉘어 남미의 작은 섬나라 코르토 몰티즈로 향한다. 이들의 임무는 이 섬에 위치한 요툰하임이라는 비밀 연구실에 잠입해 스타피쉬의 흔적을 없애는 것. 각기 다른 해안가에 도착한 두 팀은 상반된 상황을 맞이한다.', 'https://image.tmdb.org/t/p/w500/1FiLuxuowOusZAG1vvI4TorMuNG.jpg', 2021, 0, 0, '2026-06-06 13:25:22.630783', 'US');
INSERT INTO public.movies VALUES (760, 242, '대부 3', '["Crime", "Drama", "Thriller"]', NULL, '[]', '이제는 60대의 노인이 되어버린 마이클(알 파치노)은 거대해진 패밀리의 강력한 자금력을 바탕으로 합법적인 사업으로 전환하는데 힘쓴다. 이 과정에서 특히 그는 바티칸 은행의 책임을 맡고 있는 대주교와 거래하므로써 이러한 합법적인 사업을 행할 수 있었고 바티칸의 대주교 역시 마이클의 사업에 참여하여 이익을 얻고 있었다. 이러한 그의 계획에 젊은 보스 조이 자자(죠 맨테그나)가 정면으로 도전해오고, 마이클 자신도 습격을 받는다. 그러나 일단 도전을 받은 이상 응하지 않을 수가 없고, 자자의 뒤에는 그의 계획을 방해하는 거대한 조직의 음모가 도사리고 있었는데...', 'https://image.tmdb.org/t/p/w500/eLbVVIgIoqBxR0ZnxbCXao4ujFP.jpg', 1990, 0, 0, '2026-06-06 13:25:24.977373', 'US');
INSERT INTO public.movies VALUES (656, 419430, '겟 아웃', '["Mystery", "Thriller", "Horror"]', NULL, '[]', '크리스와 그의 여자친구 로즈는 주말을 맞아 로즈의 부모님 집을 방문한다. 가족들의 과한 친절이 그저 딸이 흑인 남자친구를 데려왔기 때문이라고 생각한 크리스. 하지만 머무는 시간이 길어질수록 이상한 점을 한 두가지씩 발견하는데... 그가 상상도 못한 진실이 기다리고 있었다.', 'https://image.tmdb.org/t/p/w500/paPvmoLgUUQojsSdAZmf7dwkKGT.jpg', 2017, 0, 0, '2026-06-06 13:25:21.125465', 'US');
INSERT INTO public.movies VALUES (143, 496243, '기생충', '["Comedy", "Thriller", "Drama"]', 'Bong Joon Ho', '["Song Kang-ho", "Lee Sun-kyun", "Cho Yeo-jeong", "Choi Woo-shik", "Park So-dam"]', '전원 백수로 살 길 막막하지만 사이는 좋은 기택 가족. 장남 기우에게 명문대생 친구가 연결시켜 준 고액 과외 자리는 모처럼 싹튼 고정수입의 희망이다. 온 가족의 도움과 기대 속에 박 사장 집으로 향하는 기우. 글로벌 IT기업의 CEO인 박 사장의 저택에 도착하자 젊고 아름다운 사모님 연교와 가정부 문광이 기우를 맞이한다. 큰 문제 없이 박 사장의 딸 다혜의 과외를 시작한 기우. 그러나 이렇게 시작된 두 가족의 만남 뒤로, 걷잡을 수 없는 사건이 기다리고  있는데.....', 'https://image.tmdb.org/t/p/w500/jjHccoFjbqlfr4VGLVLT7yek0Xn.jpg', 2019, 0, 0, '2026-06-06 13:25:01.777827', 'KR');
INSERT INTO public.movies VALUES (685, 57800, '아이스 에이지 4: 대륙 이동설', '["Animation", "Comedy", "Adventure", "Family"]', NULL, '[]', '격돌! 드디어 적수를 만나다!!  쩍! 갈라진 대륙과 바다, 딱! 마주친 빙하 해적단!  다람쥐 스크랫의 도토리를 향한 엄청난 집념이 지구의 운명마저 바꿔놓는 초대형 사고로 이어지면서, 대륙이 쩍쩍 갈라지기 시작한다.  갑작스러운 대륙 이동으로 살 곳을 잃어버린 매니, 디에고, 시드는 빙하를 배 삼아 정처 없이 떠돌던 중, 무시무시한 해적단과 마주치게 되는데…', 'https://image.tmdb.org/t/p/w500/8DSHzbDsNDaC0wlRZS3hLUzJAC7.jpg', 2012, 0, 0, '2026-06-06 13:25:22.621744', 'US');
INSERT INTO public.movies VALUES (650, 812, '알라딘', '["Animation", "Family", "Adventure", "Fantasy", "Romance"]', NULL, '[]', '원숭이 아부와 함께 살아가는 아그라바의 좀도둑 알라딘은 어느 날 궁궐을 탈출한 술탄의 딸 자스민에게 한눈에 반한다. 술탄의 자리를 노리는 사악한 마법사 자파는 알라딘을 눈여겨보고 그에게 마법의 램프를 가져다주면 부자로 만들어 주겠다고 말한다. 동굴에 들어가서 램프를 찾던 알라딘은 도중에 동굴이 무너지는 바람에 갇히게 된다.  위기에 빠진 알라딘은 램프의 요정 지니와 마법 양탄자의 도움으로 동굴에서 탈출한다. 지니의 주인이 된 알라딘은 지니를 램프에서 구해주겠다고 약속하고, 지니의 힘을 빌어 왕자로 변신해 자스민에게 청혼하기 위해 아그라바로 돌아오는데...', 'https://image.tmdb.org/t/p/w500/dNqpfCTQjUDRDGsaaAP6kdVAS8M.jpg', 1992, 0, 0, '2026-06-06 13:25:21.111985', 'US');
INSERT INTO public.movies VALUES (663, 497698, '블랙 위도우', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '어벤져스 멤버들이 뿔뿔이 흩어지고 혼자가 된 어벤져스의 히어로 블랙 위도우는  20년 전 헤어진 여동생 옐레나와 재회하는데, 이 과정에서 사라진 줄 알았던 레드룸이 아직도 실재한다는 사실을 알게 된다. 레드룸은 두 사람을 암살자로 만든 소비에트연방의 훈련기관. 두 사람은 레드룸을 없애고 지배받는 여성들을 구하기로 의기투합한다. 상대의 능력을 복제하는 빌런 태스크마스터와 새로운 위도우들의 위협에 맞서 목숨을 건 반격을 시작하는 나타샤는 스파이로 활약했던 자신의 과거 뿐 아니라, 어벤져스가 되기 전 함께했던 동료들을 마주해야만 하는데...', 'https://image.tmdb.org/t/p/w500/oPMAUqhwQf9mLCU5xEGPv33lAJO.jpg', 2021, 0, 0, '2026-06-06 13:25:21.850444', 'US');
INSERT INTO public.movies VALUES (770, 604, '매트릭스 2: 리로디드', '["Adventure", "Action", "Thriller", "Sci-Fi"]', NULL, '[]', '시온이 컴퓨터 군단에게 장악될 위기에 처하면서, 네오는 자신의 능력에 대한 더 큰 통제력을 갖게 된다. 이제 몇 시간 후면 지구상에 남은 인류 최후의 보루인 시온이 인간 말살을 목적으로 프로그래밍 된 센티넬 무리에 의해 짓밟히게 될 터. 그러나 시온의 시민들은 오라클의 예언이 이루어져 전쟁이 끝날 것이라는 모피어스의 신념에 용기를 얻고, 네오에게 모든 희망과 기대를 걸어보기로 한다. 서로에 대한 사랑의 힘으로, 스스로에 대한 믿음으로 용기를 얻은 네오와 트리니티는 모피어스와 함께 인간을 억압하고 착취하는 시스템에 맞서기 위해 매트릭스로 돌아간다.', 'https://image.tmdb.org/t/p/w500/5RsZJfcXUndClV1vaI68V2shJOs.jpg', 2003, 0, 0, '2026-06-06 13:25:25.731229', 'US');
INSERT INTO public.movies VALUES (357, 552524, '릴로 & 스티치', '["Family", "Sci-Fi", "Comedy"]', 'Dean Fleischer Camp', '["Maia Kealoha", "Sydney Agudong", "Chris Sanders", "Zach Galifianakis", "Billy Magnussen"]', '보송보송한 파란 솜털, 호기심 가득한 큰 눈, 장난기 가득한 웃음을 가졌지만 가장 위험한 실험체 취급을 받던 스티치는 우주에서 도망쳐 지구의 하와이 섬에 불시착하게 된다. 단짝 친구를 원하던 외톨이 소녀 릴로는 별똥별과 함께 나타난 귀여운 파란색 강아지 스티치와 소중한 친구이자, 하나의 가족이 되어가며 외로웠던 일상이 유쾌하게 변하기 시작한다. 그러던 어느 날, 스티치를 잡아 우주로 되돌아가려는 정체불명의 요원들이 등장하고 릴로와 스티치는 예상치 못한 상황을 마주하게 되는데..!', 'https://image.tmdb.org/t/p/w500/ww7jn7lv1YzTAGd5m0R6CP1VXAs.jpg', 2025, 0, 0, '2026-06-06 13:25:09.483935', 'US');
INSERT INTO public.movies VALUES (580, 105825, '요재연담 3: 등초화상', '["Horror", "Drama", "Fantasy"]', NULL, '[]', '협객인 주중과 그의 약흔녀인 유사사는 우연히 한 사찰을 지나가다 자기 몸을 축소할 수 있는 등초화상을 만난다. 그날 밤 주중은 절안에 있는 벽화 속의 미녀를 보고 한눈에 반하게 된다. 그는 등초화상에게 벽화 속으로 들어갈 수 있게 도와줄 것을 부탁한다. 주중의 끈질긴 부탁으로 등초화상은 어쩔 수 없이 도술을 써 그를 벽화속으로 들여보낸다. 벽화 속으로 들어간 주중은 기몽과 그녀의 두 동생인 춘몽, 옥몽을 만나게 되고, 서로 한눈에 반한 주중과 기몽은 위험하고도 이루어질 수 없는 사랑을 하게 된다. 두사람은 행복한 시간을 보내나, 그 뒤에는 무서운 마녀의 계략이 숨어있었다. 마녀는 주중을 기몸의 미색으로 유인하여 마계의 수호신인 갑원신을 죽이는데 이용한다. 수호신이 죽자 마녀는 마계를 장악하고 온갖 악행을 일삼는다. 마녀의 악행을 본 주중은 마녀에게 맞서고, 이미 주중에게 마음을 빼앗긴 기몽과 춘몽의 도움으로 주중은 마계에서 탈출하는데, 이 사실을 안 마녀는 기몽을 감옥에 가두고 온갖 고문을 계속한다. 벽화 밖으로 나온 주중은 중상을 입어 이를 본 등초화상은 생각 끝에 주중을 구하기 위해 약흔녀인 유사사의 순결을 이용하여 주중을 치료한다. 그러나 유사사는 주중이 계속 기몽의 이름을 부르는 것을 듣고는 충격을 받고 사찰을 떠나다 마녀에게 납치된다. 흔수상태에서 깨어난 주중은 이 사실을 알고 벽화속으로 유사사와 기몽을 구하기 위해 다시 들어가게 되는데.', 'https://image.tmdb.org/t/p/w500/1VLGHPr3DJMjlCP5F6BPgGghfTX.jpg', 1992, 0, 0, '2026-06-06 13:25:18.019604', 'US');
INSERT INTO public.movies VALUES (2609, 4951, '내가 널 사랑할 수 없는 10가지 이유', '["Comedy", "Romance", "Drama"]', NULL, '[]', '상냥하고 얼굴도 예쁜 비앙카는 인기 만점의 여학생이다. 하지만 아직까지 한 번도 데이트를 해본 적이 없다. 아버지가 고교 졸업 전까지는 이성교제를 엄금했기 때문이다.  하나뿐인 언니 캣이 공동전선을 펴서 아빠를 좀 설득해주면 좋으련만, 캣은 남자 친구 따위는 관심도 없다는 투다. 그런데, 최근에 이성교제에 대한 아빠의 규칙이 약간 바뀌었다. 캣이 남자친구를 사귀면 비앙카도 데이트를 할 수 있다는 것. 이 소식을 듣고 희망에 부푼 사람은 비앙카 뿐이 아니었다. 전학 온 첫 날, 비앙카를 보고 한 눈에 반해버린 카메론은 오직 그녀를 만나고 싶다는 일념으로 비앙카와 함께 프랑스어 스터디를 하고 있었다.  카메론은 친구 마이클의 도움을 받아 캣과 교제할 사람을 찾아나선다. 캣의 오만함과 독설에 나가떨어지지 않고 그녀를 상대해줄 만한 사람이어야 했다. 이들이 점찍은 남학생은 패트릭. 독특한 호주 액센트를 구사하는 아웃사이더로서 암거래 조직의 일원이라는 둥, 화재 사건의 범인이라는 둥, 그를 둘러싼 소문은 무성했지만, 아무도 가까이 접근하지 못하는 미스터리의 터프 가이였다. 이런 패트릭이 카메론의 사랑에 감격해서 자발적으로 캣과 데이트를 해줄 리는 만무하므로, 두 사람은 그를 매수하기로 한다.  이를 위한 물주로 떠오른 이는 죠이. 학생이자 모델인 그는 빨간 스포츠카를 몰고 다니는 인기 만점의 남학생으로 돈 많고, 체격 좋고, 잘생겼지만, 머리에 든 것도 별로 없고 우쭐대기만 하는 속물인데, 오래전부터 비앙카에게 눈독을 들이고 있었다. 마이클은 캣에게 남자친구가 생기면 비앙카와 데이트할 수 있다는 정보를 슬쩍 흘리며 죠이로하여금 패트릭을 매수하도록 부추겼다. 일은 착착 진행되어, 드디어 패트릭이 캣과 함께 파티에 참석하는데 성공한다.  만남이 잦아지면서 서로의 참모습을 알게 된 두 사람은, 다른 이들의 의도와는 상관없이 정말로 사랑에 빠지지만...', 'https://image.tmdb.org/t/p/w500/syoeWNSLr7AMesZXM5DUAmoDRvp.jpg', 1999, 0, 0, '2026-06-07 12:17:40.128442', 'US');
INSERT INTO public.movies VALUES (599, 10195, '토르: 천둥의 신', '["Adventure", "Fantasy", "Action"]', NULL, '[]', '파괴를 일삼는 요툰하임을 제압한 왕 오딘의 통치로 평화로운 나날을 보내고 있는 신의 세계 아스가르드. 오딘의 아들인 토르의 왕위 계승식이 있던 날, 요툰하임의 지배자인 라우페이는 평화 협정을 위반하고 아스가르드를 침입한다. 이 사건으로 왕위에 오르지 못한 토르는 분노와 모욕감에 요툰하임을 공격하지만 막강한 군대에 포위되어 위기에 몰리게 되고, 오딘은 토르의 오만하고 경솔한 행동에 분노해 토르의 신으로서의 능력을 박탈한 채 인간 세계 미스가르드로 추방한다. 한편 천체의 이상현상을 연구하던 과학자 제인 일행은 거대한 섬광의 흔적을 쫓던 중, 그 현장 한가운데서 지구에 떨어진 토르와 맞닥뜨린다.', 'https://image.tmdb.org/t/p/w500/7hThYJ0yBzclKviPxBt5UB94zNT.jpg', 2011, 0, 0, '2026-06-06 13:25:18.790053', 'US');
INSERT INTO public.movies VALUES (3647, 483664, 'PlayBoy (and the Gang of Cherry)', '["Action", "Crime", "Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/3LlbpgxWqPXr5U7jQOPJ6RyXMHh.jpg', 2017, 0, 0, '2026-06-08 06:24:27.75333', 'US');
INSERT INTO public.movies VALUES (691, 284052, '닥터 스트레인지', '["Fantasy", "Adventure", "Action"]', NULL, '[]', '오만함과 실력 모두 최고인 신경외과 의사 닥터 스티븐 스트레인지는 운전 중에 핸드폰을 한 대가로 두 손의 신경이 끊어지는 심각한 부상을 입고 큰 상심에 빠진다. 게다가 모난 말들로 사랑하는 여인 크리스틴 팔머마저 그의 곁을 떠나게 만든다. 그는 치료를 위해 히말라야의 영적 지도자, 에인션트 원을 만나 마지막 희망을 걸고 수련을 시작한다. 스트레인지는 빠르게 마법을 터득해 나가는 동시에 세계의 작동원리와 우주를 정복하려는 도르마무 일당의 계략을 알게 된다. 모든 것을 초월한 최강의 히어로로 거듭나는데...', 'https://image.tmdb.org/t/p/w500/xA7ic72L0mejJX1SYMU38F7wwiF.jpg', 2016, 0, 0, '2026-06-06 13:25:22.635206', 'US');
INSERT INTO public.movies VALUES (4083, 42384, '가루지기', '["Comedy", "Fantasy", "Drama"]', 'Shin Han-sol', '["Bong Tae-gyu", "Kim Ye-won", "Oh Dal-su", "Youn Yuh-jung", "Jeon Soo-kyeong"]', '음양의 불일치로 기센 아낙네들이 주도권을 잡은 마을, 떡장수를 하는 청년 강쇠는 밤일 제대로 하는 남정네 하나 없는 마을에서도 단연 부실 랭킹 1위! 온 마을 아낙네들의 놀림거리로 살아간다. 그러던 강쇠의 굴욕인생에 어느 날 일생일대의 사건이 일어났으니!  우연히 만난 음양통달 도사님에게 비책을 전해 듣고 500% 가득 찬 양기로 돌아온 변강쇠!!! 졸지에 마을 최고 완소남으로 변신한 강쇠는 천지를 뒤흔드는 막강파워로 아낙네들은 물론 온 동네 동물들마저 놀라게 만드는 상상초월 활약을 펼친다. 이제 그 앞에 펼쳐진 것은 온갖 산해진미를 싸들고 줄을 선 아낙네들의 들이대기 러시와 조선 방방곡곡에서 쏟아지는 스포트라이트!  조선 최고의 거물로 인생역전에 성공한 강쇠, 그러나 마냥 행복할 것만 같던 그의 앞날에 감당할 수 없는 큰 시련이 다가오는데…', 'https://image.tmdb.org/t/p/w500/35sluk2cRZsDHzn0jSIK3SfSrlg.jpg', 2008, 0, 0, '2026-06-08 06:26:46.666705', 'KR');
INSERT INTO public.movies VALUES (3675, 1439584, 'Ugly Story', '["Romance", "Drama", "Thriller"]', 'L. Pranava Swaroop', '["Nandu Vijay Krishna", "Avika Gor", "Ravi Teja Mahadasyam", "Pragya Nayan Sinha", "Shivaji Raja"]', NULL, 'https://image.tmdb.org/t/p/w500/hxJOr9MRXTg3HYMpdj6VbD1FSXZ.jpg', 2026, 0, 0, '2026-06-08 06:24:28.697749', 'IN');
INSERT INTO public.movies VALUES (3731, 1125899, '클리너', '["Action", "Thriller"]', 'Martin Campbell', '["Daisy Ridley", "Taz Skylar", "Matthew Tuck", "Flavia Watson", "Ruth Gemmell"]', '테러단이 초고층 빌딩을 순식간에 점령한다. 그 모든 것을 목격한 것은 오직 유리창 청소부다. 300명의 인질과 빌딩에 갇힌 동생. 전직 특수대원의 본능이 깨어난다.', 'https://image.tmdb.org/t/p/w500/AsHF4KUK7sLllGeDJ2pqH8QS45Z.jpg', 2025, 0, 0, '2026-06-08 06:24:31.316921', 'GB');
INSERT INTO public.movies VALUES (725, 181812, '스타워즈 에피소드 9: 라이즈 오브 스카이워커', '["Adventure", "Action", "Sci-Fi"]', NULL, '[]', '포스의 균형을 교란시키는 퍼스트 오더의 수장 카일로 렌의 횡포가 극에 달한다. 저항군의 수장 레아 장군은 스타킬러 기지 파괴에는 성공하나 저항군 세력의 상당수를 잃고 전략적 후퇴를 선택한다. 퍼스트 오더 군대 내에 스파이를 두어 동태를 살피던 포 다메론은 팰퍼틴이 생존해 군대를 꾸린다는 첩보를 접한다. 제다이 수련에 빠져 있던 레이, 능숙한 파일럿으로 거듭난 핀과 포를 비롯한 소수 정예의 저항군은 팰퍼틴이 숨어 있다고 알려진 다크 사이드의 본거지 엑시골의 위치를 알아내기 위한 비밀작전을 수행한다.', 'https://image.tmdb.org/t/p/w500/cJevdcvbBw0FhpUtrwmj1MYMiK3.jpg', 2019, 0, 0, '2026-06-06 13:25:24.172383', 'US');
INSERT INTO public.movies VALUES (664, 1368, '람보', '["Action", "Adventure", "Thriller"]', NULL, '[]', '월남전에서 제대한 그린베레 출신의 존 람보(실베스타 스탤론 분)는, 전우를 찾아 록키 산맥의 어느 한적한 시골 마을에 도착한다. 하지만 그가 찾고자 하는 이는 이미 암으로 세상을 떠난 뒤였다. 마을 보안관 셔리프 윌 티즐(브라이언 데니히 분)는 그의 부랑자 행색에 반감을 갖고 마을에서 쫓아내려한다. 하지만 람보가 순순히 응하지 않자 억지 죄목으로 체포하는데, 조사를 하는 과정에서 그 옛날 월맹 포로 수용소에서 받은 고문 기억이 악몽처럼 되살아나자, 람보는 갑자기 미친 사람처럼 광폭해져 경찰관과 경찰서를 때려 부수고 탈출한다. 경찰의 추적을 따돌리고 마을 산 속으로 숨어든 람보는 월남전에서 몸에 익힌 게릴라 전술로 경찰과 대치한다. 그러다 경찰 헬기를 피하고자 절벽에서 뛰어내려 결국 큰 부상을 입는다. 이때 저격의 위험 때문에 그가 던진 돌이 헬기 유리창을 맞추고 이틈에 경찰관 하트가 헬기에서 떨어져 죽는다. 위험에서 벗어난 람보는 피가 흐르는 팔을 바늘로 꿰맨다. 동료마저 잃은 경찰은 람보를 잡는데 혈안이 되어 사냥개를 이끌고 숲으로 추적해 오지만 결국 람보의 교묘한 전술로 모두 부상을 입고 물러난다. 사태가 커지자 지방 경찰 기동대와 주경비대대의 지원을 받아 주변의 모든 길이 통제되고, 이 일은 신문과 방송 등 메스컴의 집중을 받는데...', 'https://image.tmdb.org/t/p/w500/ljcXBx9N9kQxMskkCjEpypAUkGd.jpg', 1982, 0, 0, '2026-06-06 13:25:21.852712', 'US');
INSERT INTO public.movies VALUES (742, 298618, '플래시', '["Action", "Sci-Fi", "Adventure"]', NULL, '[]', '시공간이 붕괴된 세계, 차원이 다른 히어로가 온다! 빛보다 빠른 스피드, 물체 투과, 전기 방출, 자체 회복, 천재적인 두뇌까지 갓벽한 능력을 자랑하지만 존재감은 제로, 저스티스 리그에서 궂은일을 도맡아 하는 히어로 ‘플래시’. 어느 날 자신에게 빛보다 빠른 속도로 달리면 시공간 이동 능력이 있음을 알게 된 그는 ‘브루스 웨인’의 만류를 무시한 채 끔찍한 상처로 얼룩진 과거를 바꾸기 위해 시간을 역행한다. 의도치 않은 장소에 불시착한 ‘플래시’는 멀티버스 세상 속 또 다른 자신과 맞닥뜨리고 메타 휴먼이 흔적도 없이 사라지고 모든 것이 뒤엉킨 세상과 마주하게 된다. ‘플래시’는 자신이 알던 모습과 전혀 달라진 나이 들고 은퇴한 ‘배트맨’과 크립톤 행성에서 온 ‘슈퍼걸’의 도움으로 외계의 침공으로부터 시간과 차원이 붕괴된 지구를 구하려 나서는데…', 'https://image.tmdb.org/t/p/w500/wgjojKrLVoeWhx0C22YjdAkizgH.jpg', 2023, 0, 0, '2026-06-06 13:25:24.935591', 'US');
INSERT INTO public.movies VALUES (3732, 1232667, '미스 유, 러브 유', '["Drama"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/aVt8ubqnuBU8R5MVNbuf9OTy8sa.jpg', 2026, 0, 0, '2026-06-08 06:24:31.320159', 'US');
INSERT INTO public.movies VALUES (3740, 80295, 'Der Frühreifen-Report', '["Comedy", "Romance"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/sreO7KKeh6s99jYFl9XzpxDkOeZ.jpg', 1973, 0, 0, '2026-06-08 06:24:31.339929', 'US');
INSERT INTO public.movies VALUES (3886, 137, '사랑의 블랙홀', '["Romance", "Fantasy", "Comedy"]', NULL, '[]', '잘나가는 기상 캐스터 필 코너스는 매해 펑서토니에서 열리는 성촉절 취재를 위해 촬영을 나갔다가 이상한 경험을 하게된다. 취재를 건성으로 끝내고 돌아가려는데 기상 예보에도 없었던 폭설을 만나 발이 묶이게 되고, 다음날 일어났더니 날짜가 하루 지난 것이 아닌 바로 어제의 그날, 그 장소였던 것이다. 어제와 똑같은 오늘이 반복되자 필 코너스는 매일 매일을 관찰하여 여자를 꼬시기도 하고, 금고 수송 차량을 털어 멋진차를 사기도 한다. 하지만 반복되는 나날들에 환멸을 느끼게 되고 결국 자살을 시도하지만 여전히 일어나면 바로 어제의 그 시간, 그 장소로 돌아간다. 그런 가운데 그는 함께 온 신임 프로듀서 리타의 착하고 순수한 마음을 알게되고, 그녀를 진심으로 사랑하게 된다. 매일 그녀의 생각과 행동들을 익히게 되고, 그녀의 마음을 얻으려하지만 하루만에 이루어지지 않는 사랑도 있는 법, 필 코너스는 언제까지 같은 시간 같은 장소에 묶여있게 될까?', 'https://image.tmdb.org/t/p/w500/d00qZPqqTMOnRg2m6l6NVbhSbaP.jpg', 1993, 0, 0, '2026-06-08 06:24:37.682038', 'US');
INSERT INTO public.movies VALUES (4086, 293670, '곡성', '["Horror", "Mystery"]', 'Na Hong-jin', '["Kwak Do-won", "Hwang Jung-min", "Chun Woo-hee", "Jun Kunimura", "Kim Hwan-hee"]', '낯선 외지인이 나타난 후 벌어지는 의문의 연쇄 사건들로 마을이 발칵 뒤집힌다. 경찰은 집단 야생 버섯 중독으로 잠정적 결론을 내리지만  모든 사건의 원인이 그 외지인 때문이라는 소문과 의심이 걷잡을 수 없이 퍼져 나간다. 경찰 종구는 현장을 목격했다는 여인 무명을 만나면서  외지인에 대한 소문을 확신하기 시작한다. 딸 효진이 피해자들과 비슷한 증상으로 아파오기 시작하자 다급해진 종구. 외지인을 찾아 난동을 부리고, 무속인 일광을 불러들이는데...', 'https://image.tmdb.org/t/p/w500/k9AKtgRErXjz14lFHL2IJVCgwOT.jpg', 2016, 0, 0, '2026-06-08 06:26:49.464572', 'KR');
INSERT INTO public.movies VALUES (3715, 104894, '小鳥たちのいない花園', '["Horror"]', 'Akira Nobi', '["Hino Harumi", "Somiya Daisuke", "Takayuki Harada", "Yosuke Nikaidou", "Sham-Tear"]', NULL, 'https://image.tmdb.org/t/p/w500/wbSCK7bKziQrSB0vYZSR2aTJ9I7.jpg', 1992, 0, 0, '2026-06-08 06:24:30.448344', 'JP');
INSERT INTO public.movies VALUES (726, 9470, '쿵푸 허슬', '["Action", "Comedy", "Crime", "Fantasy"]', NULL, '[]', '1940년대 중국 상하이. 난세를 틈타 어둠의 세력을 평정한 도끼파의 잔인함에 신음하고 있던 그 때, 너무 가난해서 뺏길 것도 없는 하층민만이 평화롭게 모여사는 돼지촌에 불의만 보면 도망치는 소심한 건달 싱(주성치)이 흘러든다. 돼지촌을 폼나게 접수해서 도끼파 보스의 눈에 띄고 싶었던 싱의 협박은 도끼파와 돼지촌 주민 간의 전면대결로 이어지고, 놀랍게도 강호를 떠나 돼지촌에 숨어있던 강호의 고수들이 그 실체를 드러낸다. 예상치 못한 쿵푸 고수들의 등장으로 위기에 몰린 도끼파는 떠돌이 형제 킬러를 고용하는 한편, 싱을 이용해 전설 속의 쿵푸 달인 야수를 빼돌려 돼지촌을 접수할 음모를 꾸미는데...', 'https://image.tmdb.org/t/p/w500/rX8XXAMyMGZRDhEgG1cmwXmxjZU.jpg', 2004, 0, 0, '2026-06-06 13:25:24.175214', 'US');
INSERT INTO public.movies VALUES (846, 1064028, '메이드', '["Horror", "Sci-Fi", "Thriller"]', NULL, '[]', '아내 매기의 부재로 인해 AI가 탑재된 메이드를 들이기로 한 닉. 딸이 마음에 들어한 메이드를 집에 입주시키고 ‘앨리스’라는 이름을 붙인다.  청소, 요리, 장보기까지 완벽하게 집안일을 해내는 앨리스. 닉은 편리함을 느끼지만 그것도 잠시, 앨리스는 닉을 위한다는 명목 아래 아슬아슬한 행동을 이어간다.  “마음이 힘들면 능률이 떨어지죠. 제가 도와드릴게요”  아내 매기의 목소리까지 흉내 내는 앨리스와 금단의 선을 넘은 닉. 매기가 집으로 돌아오고 닉은 모든 것을 없었던 일로 하고 싶지만 앨리스는 닉에 대한 집착을 멈추지 않는다. 위험한 일도 서슴지 않으며 그녀는 폭주하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/9nK3lfPhbzMJGhkueloRQ56ui8n.jpg', 2024, 0, 0, '2026-06-06 13:25:28.849219', 'US');
INSERT INTO public.movies VALUES (668, 1250, '고스트 라이더', '["Thriller", "Action", "Fantasy"]', NULL, '[]', '세계 최고의 모터싸이클 스턴트 챔피언 ‘자니 블레이즈’(니콜라스 케이지 분). 사랑하는 사람을 위해 악마 메피스토펠레스(피터 폰타 분)에게 자신의 영혼을 팔아넘긴 자니는 밤마다 자신도 모르는 사이, 죽을 수도 살 수도 없는 불멸의 영혼사냥꾼 ‘고스트 라이더’로 변하게 된다. 악마의 요구대로 영혼을 빼앗아야 하는 운명과 정의감 사이에서 방황하던 자니는 첫사랑 록산느(에바 멘데스 분)와 재회하게 되지만, 차마 자신의 비밀을 밝힐 수 없어 괴로워한다.  한편, 4명의 타락천사 ‘데블4’를 동원해서 어두운 세상의 지배를 꿈꾸는 메피스토펠레스의 아들 블랙하트는 가장 큰 방해세력인 고스트 라이더와의 정면승부를 위해 록산느를 내세워 상상조차 할 수 없었던 방법을 준비하는데…', 'https://image.tmdb.org/t/p/w500/rXF383684CoNnbuN90Z5uD253aU.jpg', 2007, 0, 0, '2026-06-06 13:25:21.862394', 'US');
INSERT INTO public.movies VALUES (4091, 799379, '늑대사냥', '["Action", "Thriller", "Horror", "Crime"]', 'Kim Hong-sun', '["Seo In-guk", "Jang Dong-yoon", "Park Ho-san", "Jung So-min", "Ko Chang-seok"]', '동남아시아로 도피한 인터폴 수배자들을 이송할 움직이는 교도소 프론티어 타이탄. 극악무도한 이들과 베테랑 형사들이 필리핀 마닐라 항구에 모이고 탈출을 꿈꾸는 종두, 한국으로 돌아가야만 하는 도일을 비롯해 이들은 각자의 목적과 경계심을 품고 탑승한다. 한국으로 향하던 중, 태평양 한 가운데에서 이들에게는 지금까지 보지 못한 극한의 상황과 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/op2y1gvqKhAh4yAPLwc4PlX3XRv.jpg', 2022, 0, 0, '2026-06-08 06:26:53.403681', 'KR');
INSERT INTO public.movies VALUES (665, 9312, '모탈 컴뱃', '["Action", "Fantasy"]', NULL, '[]', '세계에서 모인 무술 고수들이 ''모탈 컴뱃''이라는 무술대회에 참가하기 위해 홍콩의 한 부두에서 분위기도 으스스한 배를 탄다. 무술대회의 목적은 외계의 괴물들이 지구를 침공할 권리를 부여받느냐의 여부를 결정하는 것. 지구를 지키기 위해 떨쳐나선 무술인들 중에는 중국의 사찰에서 무술을 연마하며 성장한 류 캉, 홍콩의 여경찰관 소냐, 그리고 액션 영화 배우 자니 케이지가 있으며, 그들을 돕는 초인적 존재는 번개신 라이덴이라 불리는 반인반신이다. 한편, 사악하고 간교한 마법사 샹 청의 지휘를 받는 외계의 싸움꾼들은 지하범죄왕 케이노, 팔이 넷 달린 괴물 고로, 초자연적인 힘을 가진 얼음 귀신과 전갈 귀신 등이고, 외계의 왕족이며 황위계승권을 가진 10,000살 먹은 키타나 공주는 어느 편인지 애매모호하다.  외계를 대표하는 싸움꾼들은 대회 전날부터 막강한 힘을 선보이지만, 막상 대회가 시작되자 소냐가 케이노의 목을 부러뜨려 승리하고, 케이지는 전갈 귀신을 물리치며 류는 키타나 공주와 비기는 싸움을 한다. 사실 키타나 공주는 일부러 비긴 것으로 그녀는 류에게 다음 싸움에서 얼음귀신을 이길 수 있는 비법을 알려준다. 대회가 계속되면서 마침내 케이지가 천하무적으로 일컬어지던 고로를 물리치고, 이에 충격을 받은 샹 청은 소냐를 외계로 납치해간다. 번개신의 조언을 들을 후 외계로 쫓아간 류와 케이지는 그곳에서 키타나 공주의 도움을 받는다. 류는 샹 청에게 도전하여 대회의 승패를 결정하는 최후의 대결에서 승리하고, 키타나 공주는 괴물 황제에게 빼앗겼던 외계의 통치권을 회복한다. 지구로 돌아온 류, 케이지, 소냐는 번개신과 만나 승리를 축하하지만, 그들의 기쁨도 잠시뿐, 영생불멸의 존재인 괴물황제가 주궁의 사원탑을 부수며 나타난다.', 'https://image.tmdb.org/t/p/w500/uPtIEeksAtQ7UMPOsRSNXrL0AkW.jpg', 1995, 0, 0, '2026-06-06 13:25:21.85512', 'US');
INSERT INTO public.movies VALUES (3779, 335977, '인디아나 존스: 운명의 다이얼', '["Adventure", "Action"]', NULL, '[]', '1969년 뉴욕, 전설적인 모험가이자 고고학자 인디아나 존스 앞에 대녀 헬레나와 오랜 숙적 위르겐 폴러의 세력이 등장한다. 그들의 목표는 단 하나, 운명의 다이얼. 역사의 흐름을 바꿀 수 있는 다이얼을 차지하려는 쫓고 쫓기는 위협 속에 인디아나 존스는 전 세계를 무대로 하는 새로운 모험에 뛰어드는데…', 'https://image.tmdb.org/t/p/w500/8ifAx8GS5AHL7xOTMJDMaza84RQ.jpg', 2023, 0, 0, '2026-06-08 06:24:33.162962', 'US');
INSERT INTO public.movies VALUES (704, 9552, '엑소시스트', '["Horror", "Drama"]', NULL, '[]', '노신부 메린(막스 본 시도우 분)은 이라크 북부에서 고분을 발굴하다 이상한 조각을 발견한다. 악마를 상징하는 그 조각에 노신부는 불안해 한다. 한편, 미국 조지타운에 사는 인기 여배우 크리스 멕닐(엘런 번스타인 )는 어느 날 밤 딸 리건(린다 블레어)의 방에서 이상한 소리를 듣고 쥐가 있는 것 같다며 운전 기사 칼(루돌프 쉰들러)에게 쥐덫을 놓도록 한다. 이어 딸 리건에게서 이상한 증세가 나타나기 시작하자 크리스는 리건을 데리고 병원을 전전하지만 병명조차 알아내지 못한 채 증세는 점점 악화된다. 그 와중에 크리스의 애인이 리건을 간호하던 중 변사체로 발견되는가 하면 조그맣고 귀엽던 리건의 얼굴이 무섭고 흉측한 악령의 모습으로 변하며 "그리스도가 나를 범하고 있다"라고 외치며 자해를 하는 사건이 연이어 벌어진다. 크리스는 지푸라기라도 잡는 심정으로 젊은 카라스 신부(제이슨 밀러)를 찾아가 악마를 내쫓는 엑소시즘 의식을 부탁한다. 결국 카라스 신부는 엑소시즘의 경험이 있는 노신부 메린에게 도움을 청하고 둘은 리건에게서 악령을 몰아내는 의식을 집행하기에 이른다. 그러나 악령은 쉽게 물러나지 않고, 악마와 메린 신부의 처절한 사투가 시작되는데…', 'https://image.tmdb.org/t/p/w500/1Y0h6vedMbWPJNzqBnRkik16MO4.jpg', 1973, 0, 0, '2026-06-06 13:25:23.388361', 'US');
INSERT INTO public.movies VALUES (3802, 624860, '매트릭스: 리저렉션', '["Sci-Fi", "Action", "Adventure"]', NULL, '[]', '토마스 앤더슨은 자신의 현실이 물리적 구성개념인지 아니면 정신적 구성개념인지 알아내기 위해 이번에도 흰 토끼를 따라가야 한다. 토마스, 아니 네오가 배운 게 있다면 비록 환상이라 할지라도 선택이야말로 매트릭스를 탈출할 유일한 길이라는 것이다. 물론 네오는 무엇을 해야 할지 이미 알고 있다. 그가 아직 모르는 사실은 이 새로운 버전의 매트릭스가 그 어느 때보다도 강력하고, 확고부동하고, 위험하다는 것이다.  평범한 일상과 그 이면에 놓여 있는 또 다른 세계, 두 개의 현실이 존재하는 세상에서 운명처럼 인류를 위해 다시 깨어난 구원자 네오. 빨간 약과 파란 약 중 어떤 것을 선택할 것인가?', 'https://image.tmdb.org/t/p/w500/AvWlbyLk32HdvSrrSTYpjmXHEXC.jpg', 2021, 0, 0, '2026-06-08 06:24:34.206347', 'US');
INSERT INTO public.movies VALUES (800, 598, '시티 오브 갓', '["Drama", "Crime"]', NULL, '[]', '빈민가가 막 형성되기 시작한 1960년대, 마을을 지나가는 배달 트럭을 털면서 가족을 부양하는 텐더 삼총사가 주름잡던 그 시기에는 엄연한 룰이 존재했다. 돈은 훔치되 살인은 삼가는 것이다. 이들은 엉뚱한 용의자를 사살하고도 지갑을 챙기는 악질 경찰에 비하면 약자에 불과했다. 텐더 트리오 시대에 종지부를 찍은 제빼게노는 큰 돈을 만지기 위해서는 마약을 다뤄야 함을 알게 된다. 단짝친구 베네는 악랄하기만 할 뿐 주변을 다독일 줄 모르던 제빼게노를 보좌하며 또 다른 룰을 만들어내지만, 위태로운 평화의 유효기간은 그리 길지 않다.', 'https://image.tmdb.org/t/p/w500/iKXrQB16sxeXoc6GlnYjeeZKsOW.jpg', 2002, 0, 0, '2026-06-06 13:25:26.555306', 'US');
INSERT INTO public.movies VALUES (3808, 1534530, 'El Susurro', '["Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/evDvchrDRS2i9jKcLJpixSLjx45.jpg', 2026, 0, 0, '2026-06-08 06:24:34.221873', 'US');
INSERT INTO public.movies VALUES (3814, 1598, '케이프 피어', '["Drama", "Crime", "Thriller"]', NULL, '[]', '영화는 복수심에 불타는 맥스 케이디(Max Cady: 로버트 드니로 분)가 강간 폭행죄로 14년형을 마치고 출소하면서부터 시작된다. 감옥에 있는 동안 글을 배우고 문학서에서 철학서 등을 독파, 스스로 변호할 수준까지 오른 맥스는 자신의 과거 공선변호사인 샘 보든(Sam Bowden: 닉 놀테 분)을 찾아간다. 샘은 14년전 케이디가 무죄를 선고 받을 수 있는 정보를 입수했지만 16세 소녀를 강간한 그에겐 자유를 누릴 권리가 없다고 판단, 검찰측에 제시하지 않았다. 이 사실을 알고 있는 맥스는 샘이 자신을 배신했다는 생각에 수감내내 복수심을 키워온 것. 처음 맥스의 위협을 받고 가볍게 생각했던 샘은 맥스가 평소 가까이 지내던 법원서기인 로리 데이비스에게 접근하여 그녀에게 무자비한 성폭행을 보고는 경악한다. 사립 탐정 커젝(Claude Kersek: 죠 돈 베이커 분)을 고용한 샘은 그일로 점차 자신의 가정까지 흔들리는 것을 느끼게 된다.  한편 맥스는 막 사춘기에 접어든 15살 난 샘의 딸 대니(Danielle Bowden: 줄리엣 루이스 분)가 한창 성격이 반항적이고 성적 호기심이 높은 것을 이용하여 헨리 밀러의 ''섹서스''와 ''북회귀선'' 등을 이용하여 접근한다. 위기 의식을 느낀 나머지 샘은 청부업자를 고용하여 맥스를 습격하게 한다. 청부업자들은 파이프와 체인으로 맥스를 피투성이로 만들지만 불사신 같은 맥스는 이들을 때려 눕힌다. 이 사건은 맥스의 복수심을 더욱 자극하는 계기가 되고 맥스는 처절한 복수의 화신이 되어 샘을 괴롭힌다. 그의 최후 복수의 장소는 폭풍이 휘몰아치는 케이프 피어. 그곳에서 맥스와 샘의 마지막 대결은 빛도 소리도 없는 다만 공포로 변해간다.', 'https://image.tmdb.org/t/p/w500/tIrtSrA4Qnvdv0jlTlaPf0E73ee.jpg', 1991, 0, 0, '2026-06-08 06:24:35.109541', 'US');
INSERT INTO public.movies VALUES (768, 93685, '스윙어스', '["Romance", "Drama"]', NULL, '[]', '충격적인 테스트를 통해 소중한 진실을 깨닫게 된다! 평화로운 오후, 한적한 시골의 호화로운 별장으로 평범한 부부가 도착하여 짐을 푼다. 조용하고 수줍은 듯한 아내 다이아나와 건장한 체구의 시원시원한 남편 율리안. 하지만 그들 부부는 무언가 채워지지 않은 듯 보인다. 다이아나와 율리안 부부는 부부생활에 새로운 활력소를 불어넣기 위해서 특별한 주말을 마련하게 되고, 그들의 초대에 또 다른 커플 알렉스와 티모가 방문하게 된다. 섹시하고 대담한 알렉스와 사교적이며 젠틀한 티모는 스와핑을 즐기는 프라이빗 클럽의 경험 많은 부부이다. 이제 두 커플에게는 서로의 사랑을 확인해 볼 수 있는 설레이는 경험이 기다리고 있다. 한편 다이아나는 막상 기대하고 상상했던 거와는 달리 자신감에 차고 매혹적인 알렉스를 보자 몹시 불안해지기 시작한다. 두 커플은 색다른 주말 파티를 통해서 서로에 대해 친밀감과 궁금증을 나누기 시작하고, 급기야 그들이 계획했던 섹시한 테스트를 실행에 옮긴다. 하지만 예상과는 달리 서로를 탐하게 되면서부터, 두 부부에게 숨겨져 있던 미묘한 감정들이 되살아나게 되고, 부부간의 질투와 오해, 믿음과 이해 등 내면의 복잡한 연애심리가 뒤엉키게 된다. 부부 스스로도 서로에 대해 몰랐던 부분들을 깨닫게 되면서 설레였던 그들의 주말은 예상치 못한 국면으로 치닫는데...', 'https://image.tmdb.org/t/p/w500/vsctdCbDHApN003Fs3QzJB8Nl9B.jpg', 2002, 0, 0, '2026-06-06 13:25:25.725676', 'US');
INSERT INTO public.movies VALUES (761, 140607, '스타워즈 에피소드 7: 깨어난 포스', '["Adventure", "Action", "Sci-Fi"]', NULL, '[]', '2번째 데스 스타가 파괴되고 다스 베이더가 사망한 지 약 30년 후, 마지막 남은 제다이인 루크 스카이워커가 사라졌다. 몰락한 은하 제국으로부터 일어난 퍼스트 오더는 루크와 공화국을 찾아내 제거하려 한다. 공화국과 루크의 쌍둥이 여동생 레이아 오르가나가 이끄는 저항군은 퍼스트 오더를 저지하고 루크의 도움을 받기 위해 루크를 찾는다. 저항군 최고의 파일럿 포 다메론은 자쿠 행성의 마을 장로를 만나 루크가 있는 장소의 지도를 얻는다. 카일로 렌이 이끄는 스톰트루퍼들은 마을을 파괴하고 포를 붙잡지만, 포의 드로이드 BB-8는 지도를 갖고 탈출하고 부랑자 레이를 만나게 된다.', 'https://image.tmdb.org/t/p/w500/qmzc2xck6ZiJG4faxhGiDSX48Ck.jpg', 2015, 0, 0, '2026-06-06 13:25:25.702654', 'US');
INSERT INTO public.movies VALUES (3842, 1473878, 'Speed Demon', '["Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/1qeO6qbbOXFkwN19aCWQAlmpbHQ.jpg', 2026, 0, 0, '2026-06-08 06:24:35.972286', 'US');
INSERT INTO public.movies VALUES (3843, 28844, 'Velluto nero', '["Drama", "Romance", "Horror"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/j2upbE7HW1mzhSoqiM5WYudDYng.jpg', 1976, 0, 0, '2026-06-08 06:24:35.974549', 'US');
INSERT INTO public.movies VALUES (4110, 419116, '러시아 엄마', '["Drama", "Romance"]', 'Choi Won-joon-I', '["Irina Griga", "Kang Ye-na", "Kim Do-hee", "Yoon Se-hyeong", "Jeon Ji-hak"]', '엄마, 이제 우리 둘만 아는 비밀이 생겼네요  요리사를 꿈꾸는 장호는 아버지 영수와 여자친구에 대한 이야기를 공유할 만큼 허물없이 지내며 단둘이 한 집에 산다. 어느 날, 아버지는 장호에게 러시아의 젊은 여인과 재혼을 했다는 충격적인 사실을 털어놓는다. 쿨하게 아버지의 재혼을 받아들인 장호 앞에 나타난 새엄마 올가. 장호는 예상치 않게 젊고 아름다운 올가를 보고 몹시 당황한다. 며칠 뒤, 아버지 영수는 러시아로 출장을 가게 되고 올가와 장호는 일상을 함께하며 조금씩 가까워지기 시작하는데…', 'https://image.tmdb.org/t/p/w500/hktmN8qVDyzp3I9f7veWfF6l45c.jpg', 2016, 0, 0, '2026-06-08 06:27:09.629462', 'KR');
INSERT INTO public.movies VALUES (957, 377, '나이트메어', '["Horror"]', NULL, '[]', '연일 흉칙한 괴물에게 쫓기는 악몽에 시달리던 티나는 어느날 엄마가 외출해 집이 비자 친구인 낸시와 글렌, 로드를 불러 잠을 자게 된다.  이날 밤도 꿈 속에서 또 다시 흉칙하게 생긴 괴물에게 쫓기던 티나는 이것이 현실로 그대로 나타나 침대에서 무참하게 살해당한다. 그리고 티나와 동침했던 로드가 평소 품행이 좋지 않아 살인 용의자로 체포된다. 이 사건의 수사관인 낸시의 아버지는 딸이 말하는 악몽에 관한 이야기를 믿지 않는다.  한편 낸시도 학교에서 잠이 들어 전과 같이 꿈에서 괴물에게 쫓기다 이것이 꿈이라며 근처에 있는 뜨거운 것에 팔에 디어 그 고통으로 깨어나지만 깨어났을 때 팔에 화상이 남아 있었다. "하나 둘, 프레디가 다가온다. 셋 넷, 대문을 잠궈라. 여섯 여섯, 십자가를 가슴에. 일곱 여덟, 늦게까지 깨어있어라. 아홉 열, 잠들지 말고." 이런 이상한 가사로 된 노래를 부르며 욕조에서 목욕을 하던 낸시는 잠깐 잠이 들었다가, 욕조 속에 괴물이 나타나는 위기를 넘긴다.  결국 낸시는 괴물을 만나지 않는 방법은 잠을 자지 않는 것밖에 없음을 알고, 앞 집에 사는 글랜을 불러 자신이 악몽을 꾸는 것처럼 보이면 깨워달라고 부탁한다. 하지만 글랜도 잠이 들고, 낸시는 다시 꿈에서 괴물 프레디를 만나는데, 프레디는 로드가 있는 구치소에 침입하다가 다시 낸시에게 달려든다. 이때 낸시는 때마침 시계가 울려 꿈에서 깨어난다. 낸시는 글렌과 함께 로드를 찾기 위해 경찰서로 달려가지만 그는 이미 숨이 끊어진 후였다. 빨강 초록색 쉐타를 입고 흉칙한 얼굴에 긴 손톱칼을 가진 괴물 이야기를 하던 낸시는 결국 병원으로 데려가고, 낸시는 몸 상태를 체크받는다. 이윽고 잠이 든 낸시가 다시 심하게 몸부림치면서 악몽에 시달리다 깨어나는데 낸시의 팔에 상처나 나고 프레드 크루거라는 이름이 새겨진 괴물의 모자를 들고 있는 것을 본 어머니는 마침내 지하실에 숨겨두었던 괴물의 날카롭고 흉칙한 칼 장갑을 보이면서 프레드에 관한 이야기를 털어놓는데...', 'https://image.tmdb.org/t/p/w500/wGTpGGRMZmyFCcrY2YoxVTIBlli.jpg', 1984, 0, 0, '2026-06-06 13:25:32.725776', 'US');
INSERT INTO public.movies VALUES (975, 602, '인디펜던스 데이', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '7월 2일, 이상한 현상이 지구를 감싼다. 하늘은 이글이글 불타오르고 땅은 지진이 난 듯 격렬히 요동친다. 직경 550km, 무게가 달의 4분의 1이나 되는 거대한 괴 비행물체가 태양을 가려 지구는 그 빛을 잃어간다. 숨막히는 공포가 세계의 주요도시를 엄습하기 시작한다.  7월 3일, 거대하고 기괴한 비행물체에서 내뿜는 가공할 위력의 불기둥은 뉴욕의 마천루와 워싱턴의 백악관, 이집트의 피라밋 등을 순식간에 잿더미로 만들고, 거리의 자동차들은 휴지조각처럼 공중을 날아다닌다. 사람들은 당황하여 숨을 곳을 찾지만 도망칠 곳은 아무데도 없다. 인간의 힘으로 감당할 수 없는 엄청난 힘이 지구에 도달했음이 밝혀진다. 그들의 목적은 완전한 지구의 파멸.  7월 4일, 엄청난 파괴 속에서 살아남은 지구의 생존자들은 그 힘을 모아 거대한 괴비행물체에 대항하려 한다. 그러나 외계인들의 지구파괴는 더욱 맹렬해지고 인류 전체의 생존과 외계인으로부터 지구의 독립은 점점 어려워지는데.', 'https://image.tmdb.org/t/p/w500/fy4Y1o2tGip4V1Pl1DYoRBLc1GR.jpg', 1996, 0, 0, '2026-06-06 13:25:33.501107', 'US');
INSERT INTO public.movies VALUES (3892, 36647, '블레이드', '["Horror", "Action"]', NULL, '[]', '출산을 바로 앞둔 산모가 응급실에 실려온다. 이미 위독한 상황에 있는 산모에게서 뱃속의 아이라도 살리기 위해 응급수술이 시작된다. 그러나 누구도 산모가 뱀파이어에게 물렸다는 사실을 모른다.  산모의 몸 속에 스며든 뱀파이어의 피는 아기의 혈관 속으로 스며들어 아이의 운명을 바꾼다. 반은 인간, 반은 뱀파이어로 태어난 블레이드(웨슬리 스나입스)는 자신의 어머니를 죽게 한 뱀파이어에 대해 복수를 다짐한다.  한편 뱀파이어들은 인간세계에 은밀히 섞여서 살고 있다. 지역지구장을 맡고 있는 뱀파이어 프로스트(스티븐 도프)는 자신의 세력 확장을 위해 무자비한 방식으로 인간을 공격한다. 그런데 프로스트가 가장 무서워하는 존재는 인간과 뱀파이어의 우성 유전자만을 이어받은 블레이드인데...', 'https://image.tmdb.org/t/p/w500/rD74tCs0fEX618Urk43H1YGinAH.jpg', 1998, 0, 0, '2026-06-08 06:24:38.510618', 'US');
INSERT INTO public.movies VALUES (3897, 930094, '빨강, 파랑, 어쨌든 찬란', '["Comedy", "Romance"]', NULL, '[]', '‘뉴욕 타임스’ 베스트셀러 원작의 ‘빨강, 파랑, 어쨌든 찬란’은 미국 대통령의 아들 알렉스와 영국의 헨리 왕자의 이야기다. 두 라이벌의 오랜 불화가 미-영 관계를 위협하자 이들은 사이가 좋은 척 연기하기를 강요받는다. 그러면서 둘의 냉랭한 관계는 서서히 녹아내리고 예상치도 못했던 불꽃이 둘 사이에 활활 타오른다.', 'https://image.tmdb.org/t/p/w500/pw2q0dMQYFFtYzKfbtoMKU8iyc9.jpg', 2023, 0, 0, '2026-06-08 06:24:38.526064', 'US');
INSERT INTO public.movies VALUES (2925, 116745, '월터의 상상은 현실이 된다', '["Adventure", "Comedy", "Drama", "Fantasy"]', NULL, '[]', '자신의 꿈은 접어둔 채 16년째 ‘라이프’ 잡지사에서 포토 에디터로 일하고 있는 월터 미티.  해본 것도, 가본 곳도, 특별한 일도 없는 월터의 유일한 취미는 바로 상상!  상상 속에서만큼은 ‘본 시리즈’보다 용감한 히어로, ‘벤자민 버튼’보다 로맨틱한 사랑의 주인공이 된다.  어느 날, ‘라이프’지의 폐간을 앞두고 전설의 사진작가가 보내 온 표지 사진이 사라지는 일이 벌어진다.  당장 사진을 찾아오지 못할 경우 직장에서 쫓겨날 위기에 처하게 된 월터는  사라진 사진의 미스터리를 풀기 위해 연락조자 닿지 않는 사진작가를 찾아 떠나는데…  지구 반대편 여행하기, 바다 한 가운데 헬기에서 뛰어내리기, 폭발직전 화산으로 돌진하기 등  한 번도 뉴욕을 벗어나 본 적 없는 월터는 전혀 예상치 못한 곳에서 상상과는 비교도 안 되는 수 많은 어드벤처를 겪으면서 생애 최고의 순간을 맞이하게 되는데…  당신이 망설이고 있는 그 순간, 월터의 상상은 현실이 된다!', 'https://image.tmdb.org/t/p/w500/88J7DQ0Yn6MIqXaAiTgjyErzPnh.jpg', 2013, 0, 0, '2026-06-07 12:17:54.463072', 'US');
INSERT INTO public.movies VALUES (930, 294254, '메이즈 러너: 스코치 트라이얼', '["Sci-Fi", "Action", "Thriller", "Adventure"]', NULL, '[]', '미로를 탈출한 토마스와 러너들은 자신들이 겪었던 위험한 실험에 미스터리한 조직 ‘위키드’가 관여된 것을 알게 되고, 그들의 정체를 밝혀 왜 이런 일들이 일어나고 있는지를 알아내기 위해 또 다시 탈출을 시도한다.  한 순간도 예측할 수 없는 위험들이 도사리고 있는 ‘스코치’에 도착한 러너들은 ‘위키드’에 대항하기 위해 결성된 저항 단체를 만나 그들과 함께 거대 조직에 맞설 준비를 한다.  하지만 ‘위키드’에 접근할수록 위험천만한 일들이 벌어지고, 조직이 비밀리에 준비 중인 또 다른 충격적인 계획을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/frtwTyCkcRWXMzIry5uLaGG1fvj.jpg', 2015, 0, 0, '2026-06-06 13:25:31.944872', 'US');
INSERT INTO public.movies VALUES (3915, 184345, '헌티드 하우스 2', '["Comedy", "Horror"]', NULL, '[]', '공포영화 ''파라노말 액티비티 4'', ''시니스터'', ''포제션 : 악령의 상자(The Possession)'', ''인시디어스'' 그리고 ''컨저링''을 패러디한 스풋 무비로 자동차 사고로 여친 키샤(에센스 앳킨스)를 잃은 말콤(마론 웨이언스)이 새 여자친구와 아이들과 함께 새 집으로 이사하면서 벌이지는 초자연적인 현상을 다룬다', 'https://image.tmdb.org/t/p/w500/oV7M00fPXy5P0nbdeMbSUjYv0vx.jpg', 2014, 0, 0, '2026-06-08 06:24:39.400192', 'US');
INSERT INTO public.movies VALUES (3920, 861, '토탈 리콜', '["Action", "Adventure", "Sci-Fi"]', NULL, '[]', '서기 2084년. 어느 신도시에서 광산일을 하고 사는 퀘이드(아놀드 슈왈젠에거)는 미모의 아내 로리(샤론 스톤)와 행복하게 살아가지만 밤마다 이상한 꿈을 꾸게 된다. 한 번도 가본 적이 없는 화성에서 이름도 알 수 없는 갈색머리 여자와 행복하게 살고 있는 것이 자꾸 꿈으로 나타나자 퀘이드는 리콜이라는 여행사를 찾아간다. 이곳은 싼값으로 우주 여행을 다녀온 것처럼 뇌 속에 기억을 이식시켜줌으로써 욕구를 충족시켜주는 곳. 이식을 받던 퀘이드는 커다란 충격에서 깨어나 놀라운 사실들을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/q7uUVw1ryWoYgEKLo3MDBQbctw6.jpg', 1990, 0, 0, '2026-06-08 06:24:39.41335', 'US');
INSERT INTO public.movies VALUES (3918, 1244492, '룩백', '["Animation", "Drama"]', 'Kiyotaka Oshiyama', '["Yuumi Kawai", "Mizuki Yoshida", "Yoichiro Saito", "Kota Oka", "Kureha Maki"]', '4학년인 ''후지노''는 학교 신문에 네컷 만화를 그리며 친구들의 극찬을 받는다. 그림에 대한 자신감으로 만화가를 꿈꾸던 ‘후지노’는 학교에 나오지 않는 동급생 ‘쿄모토’와 함께 네컷 만화를 연재하며 그림을 향한 한결 같은 마음으로 눈부신 우정을 쌓아 간다. 그러던 어느 날, 단 하나의 사건이 그들을 찾아 오는데... 만화만이 세상이 전부였던 두 소녀의 가슴 벅찬 성장 이야기가 시작된다!', 'https://image.tmdb.org/t/p/w500/ehl2Du38qbg9M2cqfoVPUKgVDTy.jpg', 2024, 0, 0, '2026-06-08 06:24:39.408126', 'JP');
INSERT INTO public.movies VALUES (2888, 605, '매트릭스 3: 레볼루션', '["Adventure", "Action", "Thriller", "Sci-Fi"]', NULL, '[]', '진실을 찾는 여정에 한 걸음 더 접근하게 된 네오. 그러나 그 와중에 능력을 소진하고 매트릭스와 현실세계의 중간계를 떠돌게 된다. 한편 기계들이 인간말살을 목적으로 인류 최후의 보루 시온으로 침공해오자 인간들은 인류의 미래를 지키기 위해 필사적인 전투를 벌인다. 그러나 베인의 몸 속에 침투한 에이전트 스미스가 본 모습을 드러내면서 네오에게는 예기치 못한 변수가 생긴다. 매 순간 세력이 커져가면서 기계들의 통제권까지 벗어난 스미스는 현실 세계와 매트릭스는 물론 기계도시까지 말살할 야욕을 불태우고, 오라클은 네오에게 마지막 조언을 건네는데...', 'https://image.tmdb.org/t/p/w500/wLS7CaUNyz4hVwCxj7mXhX66A7r.jpg', 2003, 0, 0, '2026-06-07 12:17:52.782004', 'US');
INSERT INTO public.movies VALUES (3931, 804, '로마의 휴일', '["Romance", "Comedy", "Drama"]', NULL, '[]', '유럽 순방 중 로마를 방문한 공주 ‘앤’. 끝없는 일정에 지쳐버린 그녀는 한밤중 몰래 침실을 빠져나와 처음으로 자유롭게 로마의 거리를 거닌다. 로마에서 생활 중인 미국인 기자 ‘조 브래들리’. 공주와의 인터뷰를 맡게 된 그는 집으로 돌아가는 길에 술에 취해 잠든 한 여성을 발견하고 하룻밤 재워주게 된다. 다음 날, 신문사에 출근한 ‘조’는 공주와의 인터뷰가 돌연 취소됐다는 소식을 듣게 되고, 신문 1면에서 낯익은 얼굴을 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/dYLiHwYkoxCZI6bJUik4ZHbMRkc.jpg', 1953, 0, 0, '2026-06-08 06:24:40.241908', 'US');
INSERT INTO public.movies VALUES (3936, 1193774, 'Hijo, amo tu boca', '["Drama", "Family"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/bU5PA9DmgEjgQVhm1dNrRpBcJZ5.jpg', 2023, 0, 0, '2026-06-08 06:24:40.25596', 'US');
INSERT INTO public.movies VALUES (3944, 80794, '어둠의 딸', '["Thriller", "Horror", "Comedy"]', NULL, '[]', '뤼 반장이 딸 하나만 남겨 놓고 하루아침에 일가족이 전부 몰살당한 사건을 맡는다. 진범은 아주 나쁜 놈도 아니고 집에서 천대받다가 색정광 아버지한테 덮쳐져 순결을 잃고 또 한 번 굴욕을 당하다 머리가 돌아버려 가족들을 몰살시킨 아방이다. 모든 걸 털어놓은 아방이 사형을 구형 받고 죽기 직전 출산이 허가되어 자식을 낳은 다음 남편과 함께 사진을 찍는다.', 'https://image.tmdb.org/t/p/w500/oTKI3V3ohM4cJ4nrbcFJ37OC8qY.jpg', 1993, 0, 0, '2026-06-08 06:24:40.278319', 'US');
INSERT INTO public.movies VALUES (3945, 936108, '스머프', '["Animation", "Family", "Fantasy"]', NULL, '[]', '언제나 노래와 춤, 흥으로 가득한 해피 스머프 마을. 그러던 어느 날, 마을을 이끄는 ‘파파 스머프’가 거대한 소용돌이에 휘말려 납치된다. 특별한 재능도, 좋아하는 것도 없이 아직 이름조차 없는 ‘그냥 스머프’는 세상 힙한 스머프 ‘스머페트’와 함께 온갖 위험이 도사리는 인간 세상으로 ‘파파 스머프’ 구출 작전에 나선다.  한편, 오랜 세월 스머프를 노려온 마법사 ''가가멜’과 새롭게 등장한 그의 동생 ‘라자멜’까지 더욱 강력해진 악당들에 맞서기 위해 스머프 친구들은 도시부터 사막, 우주를 넘나들며 진정한 모험을 시작하는데...', 'https://image.tmdb.org/t/p/w500/1lQHA18T32JyIonQUkSWhMwinjm.jpg', 2025, 0, 0, '2026-06-08 06:24:40.281254', 'US');
INSERT INTO public.movies VALUES (825, 46195, '리오', '["Animation", "Adventure", "Comedy", "Family"]', NULL, '[]', '전세계 유일의 희귀 앵무새 ‘블루’는 미네소타 주의 작은 도시 무스 레이크에서 주인이자 가장 친한 친구인 린다와 안락한 삶을 즐기고 있다. 둘은 ‘블루’를 제외한 모든 마코 앵무새가 멸종했다고 생각하지만, 뜻밖에 지구상에 마지막 남은 단 한 마리의 암컷 마코 앵무새가 존재한다는 소식을 듣고, 짝짓기를 위해 멀리 브라질의 ‘리오 데 자네이로’로 향한다.  뜨거운 쌈바 축제의 열기로 가득한 ‘리오’는 그 동안의 생활과는 완전히 딴판인 야생 그 자체. 게다가 평온한 가정의 울타리 안에서 애완용으로 키워져 날지 못하던 새 ‘블루’와는 달리 독립적이고 활동적인 야생의 새 ‘쥬엘’은 종족만 같았지 물과 기름처럼 전혀 어울리지 못한다. 게다가 그의 짝 ‘쥬엘’은 지나치게 독립적이라 소심한 ‘블루’를 사사건건 비판, 좀처럼 둘 사이가 좁혀지지 않는다.  하지만, 예기치 못하게 동물 밀매업자들에게 납치를 당하게 된 ‘블루’와 ‘쥬엘’.  다행히 ‘블루’는 세상 물정에 밝은 ‘쥬엘’과 익살맞고 개성 강한 도시 새들의 도움을 받아 탈출에 성공하지만…', 'https://image.tmdb.org/t/p/w500/hrtTiqucWzoTV1MXsHyrrxVAl6.jpg', 2011, 0, 0, '2026-06-06 13:25:28.089645', 'US');
INSERT INTO public.movies VALUES (3958, 10555, '샤크', '["Animation", "Action", "Comedy", "Family"]', NULL, '[]', '상어 대부 돈 리노와 영웅을 꿈꾸는 오스카의 위험한 정면승부!!  무소불위, 절대권력의 막강 카리스마를 가진 상어 대부 ‘돈 리노’. 하지만 그에게도 말 못할 고민이 있다. 상어의 본성이 의심스러울 정도로 감성적인 아들, ‘레니’가 대부의 아들로서는 자격 미달인 것. 돈 리노는 아들 녀석을 어떻게든 강한 후계자로 키워보려고 하지만, 레니에게는 상어 가문으로서는 차마 밝힐 수 없는 치명적인 비밀이 있다!!  한편, 동네 ‘고래 세차장’에서 일하는 작은 물고기 ‘오스카’는 항상 그럴싸한 말로 위기를 모면하는 비범한 재주(?)의 소유자이다. 그의 유일한 꿈은 ‘부’와 ‘명예’를 얻어 바다 세계 최고 상류 사회로 신분 상승하는 것!!  어느날,‘돈 리노’의 큰 아들이 갑작스레 죽는 사건이 발생하고, 이 엄청난 사건의 장본인(?)은 바로 ‘오스카’로 밝혀진다. 작은 물고기가 상어 대부 큰 아들을 한 방에 보내버렸다는 소식이 전해지자,‘오스카’는 일약 바다 세계 ‘슈퍼스타’로 떠오르고 그토록 바라던 부와 명예 또한 얻게 된다. 그런데 알고보니, 그의 활약상은 사건 현장에서 위기를 모면하기 위해 그가 내뱉은 철없는 거짓말이 영웅담으로 둔갑한 것. 이 사건으로 인해 자존심에 큰 상처를 입게 된 바닷속 대부‘돈 리노’는 가문의 명예 회복과 아들의 복수를 위해 오스카와의 정면 대결을 선포한다.  ‘영웅을 꿈꾸는 작은 물고기, 오스카’와‘상어 대부, 돈 리노’의 자존심을 건 정면 승부, 과연 최후의 승자는 누가 될 것인가? 그리고 예상치 못한 바다 속 이야기는 어떻게 펼쳐질까?', 'https://image.tmdb.org/t/p/w500/JHuHF49paaQ9NUWtg32IHIue8X.jpg', 2004, 0, 0, '2026-06-08 06:24:41.127361', 'US');
INSERT INTO public.movies VALUES (3961, 1477108, '욕망의 프레임', '["Drama", "Thriller"]', NULL, '[]', NULL, 'https://image.tmdb.org/t/p/w500/ppU5voCkbLi7xfPAkDgClaBnQTK.jpg', 2025, 0, 0, '2026-06-08 06:24:41.1343', 'US');
INSERT INTO public.movies VALUES (3951, 1510769, '29', '["Romance", "Comedy", "Drama"]', 'Rathna Kumar', '["Vidhu", "Preethi Asrani", "Mahendran", "Prem", "Avinash Raghudevan"]', NULL, 'https://image.tmdb.org/t/p/w500/aQZ4OxzaYTN7cRN7fALi9BhPucp.jpg', 2026, 0, 0, '2026-06-08 06:24:41.109382', 'IN');
INSERT INTO public.movies VALUES (821, 9655, '쉬즈 더  맨', '["Comedy", "Romance"]', NULL, '[]', '말괄량이 바이올라 는 헤어진 남자친구에게 복수하기 위하여 쌍둥이 오빠 세바스찬 행세를 할 결심을 하고 친구들의 도움을 받아 세바스찬으로 변신, 남자 기숙사 잠입에 성공한다. 그러나 어딘지 어색한 바이올라의 행동으로 룸메이트인 듀크와 그 친구들에게 왕따를 당하기 일보 직전의 위기에 처하는데... 다행히 전 학교 친구들의 작전으로 멋지게 분위기 반전에 성공, 친구들에게 멋진 놈이자 연애에 박식한 킹카라고 소문이 나게 된다.  한편 기숙사 생활에 적응해 나름 행복한 시간을 보내고 있는 바이올라, 점점 룸메이트 듀크가 남자로 느껴진다. 다소 쑥맥이긴 하지만 멋진 외모와 몸매, 그리고 감성적이고 순수한 마음까지 너무도 완벽한 남자 듀크! 그러나 듀크가 좋아하는 학교 퀸카 올리비아는 엉뚱하게도 바이올라가 남자인줄 알고 좋아하게 되고 듀크는 올리비아와 데이트하기 위해 바이올라의 도움을 청한다. 과연 듀크와 바이올라, 올리비아와 세바스찬의 관계는 어떻게 정리될 것인가?', 'https://image.tmdb.org/t/p/w500/bzJhzqDsRmoxdYLueZO50MUDEGk.jpg', 2006, 0, 0, '2026-06-06 13:25:28.069022', 'US');
INSERT INTO public.movies VALUES (3972, 882598, '스마일', '["Horror", "Mystery"]', NULL, '[]', '기괴한 미소를 지으며 자신의 눈 앞에서 목숨을 끊는 환자를 목격한 정신과 의사 ‘로즈’. 그날 이후로 ‘로즈’의 일상에 설명할 수 없는 끔찍한 일들이 잇따라 발생한다. 일상을 덮친 공포에 발버둥치던 ‘로즈’는 이전에도 자신과 같은 일을 겪은 사람들이 있었고 그들 모두 끔찍한 죽음을 피할 수 없었다는 사실을 알게 된다. 시시각각 다가오는 죽음에서 벗어나기 위해 사투를 벌이던 로즈는 잊고 싶던 과거와 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/8ncuVFt4e0M2NTTsoPtbxfWN5dO.jpg', 2022, 0, 0, '2026-06-08 06:24:41.972533', 'US');
INSERT INTO public.movies VALUES (3973, 884605, '노 하드 필링스', '["Comedy", "Romance"]', NULL, '[]', '부모가 연애를 하지않는 아들과 데이트 할 사람을 구하다 만난 여성과 진짜 사랑에 빠지게 되는 내용을 다룬 로맨스 코미디 영화', 'https://image.tmdb.org/t/p/w500/cR10EZftaG4dBduGf0nZuyHG9Am.jpg', 2023, 0, 0, '2026-06-08 06:24:41.975045', 'US');
INSERT INTO public.movies VALUES (2962, 745, '식스 센스', '["Mystery", "Thriller", "Drama"]', NULL, '[]', '아동 심리학자인 크로우 박사(브루스 윌리스)는 필라델피아 주지사에게 아동을 위해 기여했다는 공로로 상을 받는다. 그날 밤, 부인과 함께 2층에 올라간 말콤 박사는 낯선 침입자를 발견하게 된다. 그 침입자는 몇 년 전 말콤 박사가 치료를 맡았던 ''빈센트 그레이''라는 환자인데, 박사는 그에게 총상을 입고 그는 자살한다. 이듬 해 가을, 총상에서 회복한 크로우 박사는 ''콜 시어''라는 자폐증에 걸린 8살 된 소년의 정신 치료를 맡게 된다. 콜은 처음엔 쉽게 마음을 열지 않다가 박사의 계속된 노력으로 누구에게도 말하지 않은 비밀을 말한다. 즉 콜은 항상 귀신들이 보이며, 귀신들은 자신이 죽었는지조차 모르고, 보고 싶은 것만 본다고 이야기한다. 박사는 쉽게 믿으려 하지를 않고 마침 부인의 외도를 목격한 후 콜의 치료를 포기하려고 한다. 그러다가 박사는 옛 환자였던 빈센트와의 상담 녹음 테잎에서 귀신의 소리인 듯한 소리를 듣게 되고 콜을 찾아가 콜이 귀신에 대한 공포를 이겨내는 걸 돕게 된다.', 'https://image.tmdb.org/t/p/w500/zmPBZos4lzZi95UayzjATYyLWHT.jpg', 1999, 0, 0, '2026-06-07 12:17:56.16122', 'US');
INSERT INTO public.movies VALUES (3979, 520763, '콰이어트 플레이스 2', '["Sci-Fi", "Thriller", "Horror"]', NULL, '[]', '실체를 알 수 없는 괴생명체의 공격으로 일상의 모든 것이 사라진 세상, 아이들 대신 죽음을 선택한 아빠의 희생 이후 살아남은 가족들은 위험에 노출된다. 갓 태어난 막내를 포함한 아이들과 함께 소리 없는 사투를 이어가던 엄마 에블린은 살아남기 위해 새로운 은신처를 찾아 집 밖을 나서지만, 텅 빈 고요함으로 가득한 바깥은 더 큰 위험이 도사리고 있다. 이들은 과연 고요함으로 가득한 세상 속을 무리 없이 걸어나갈 수 있을까.', 'https://image.tmdb.org/t/p/w500/6DoKA0l2TaHvw9BbP6YbMuAnxV3.jpg', 2021, 0, 0, '2026-06-08 06:24:41.989867', 'US');
INSERT INTO public.movies VALUES (3980, 93456, '슈퍼배드 2', '["Animation", "Comedy", "Family"]', NULL, '[]', '슈퍼 악당에서 딸바보 슈퍼 대디로 180도 변신한 그루는  수다스럽고 사랑스러운 세 딸 마고, 에디스, 아그네스와 함께 행복한 삶을 살고 있다.  어느 날 거대한 자석에 의해 남극의 비밀연구소가 사라지는 사건이 발생한다. 알고보니 이 연구소는 생물을 야수로 만드는 약물을 개발하고 있었고, 악당퇴치연맹은 이 짓을 벌인 악당을 잡기 위해 그루에게 조언을 구한다. 세 딸과 평화로운 시간을 보내던 그루는 비밀요원 루시와 함께 위장 쿠키 가게를 차려 악당을 찾고, 이 과정에서 루시에게 마음을 뺏기기 시작한다. 한편 정체 모를 악당은 미니언들을 납치해 괴물로 변신시켜 세계를 정복하려 하지만 그루는 이 사실도 모른 채 루시와 딸들에게만 신경을 쓰는데...', 'https://image.tmdb.org/t/p/w500/z20OdiTzgA7kh4mPKzwLZxymG7i.jpg', 2013, 0, 0, '2026-06-08 06:24:41.992275', 'US');
INSERT INTO public.movies VALUES (2875, 49530, '인 타임', '["Action", "Thriller", "Sci-Fi"]', NULL, '[]', '근 미래, 모든 인간은 25세가 되면 노화를 멈추고, 팔뚝에 새겨진 카운트 바디 시계에 1년의 유예 시간을 제공받는다. 이 시간으로 사람들은 음식을 사고, 버스를 타고, 집세를 내는 등, 삶에 필요한 모든 것을 시간으로 계산한다. 하지만, 주어진 시간을 모두 소진하고 13자리 시계가 0이 되는 순간, 그 즉시 심장마비로 사망한다. 때문에 부자들은 몇 세대에 걸쳐 시간을 갖고 영생을 누릴 수 있게 된 반면, 가난한 자들은 하루를 겨우 버틸 수 있는 시간을 노동으로 사거나, 누군가에게 빌리거나, 그도 아니면 훔쳐야만 한다. 윌 살라스는 매일 아침 자신의 남은 시간을 보며 충분한 양의 시간을 벌지 못하면, 더는 살 수 없다는 사실을 깨달으며 눈을 뜬다. 그러던 어느 날, 수천 년을 살수 있는 헤밀턴이란 남자를 위험에서 구해준 윌은 그에게서 소수의 영생을 위해 다수가 죽어야 하는 현 시스템의 비밀을 듣게 되지만, 그 남자가 100년의 시간을 물려주고 시체로 발견되면서 졸지에 살인자의 누명을 쓰고 쫓기게 된다. 사람들의 눈을 피해 부자들만이 모여 사는 뉴 그리니치로 잠입한 그는 끈질긴 타임 키퍼 리온의 추적으로 체포될 위기를 맞지만, 와이스 금융사의 회장 딸인 실비아를 인질로 삼아 간신히 탈출한다. 이때부터 윌은 실비아와 함께 누명을 벗고 전세계를 통제하는 시스템의 비밀을 파헤치려 하는데…', 'https://image.tmdb.org/t/p/w500/1bE6wSfmSNs0xj6rYsFcE1Vzqw8.jpg', 2011, 0, 0, '2026-06-07 12:17:51.961614', 'US');
INSERT INTO public.movies VALUES (4007, 11713, '정무문', '["Drama", "Action", "Thriller"]', NULL, '[]', '정무문의 창시자이자 태극권의 사부인 허영가의 사망 소식을 들은 첸(이소룡)은 사부의 주검 앞에서 세상을 잃은 듯 오열 한다. 사망 원인이 폐암으로 밝혀지나 첸젠은 수상한 낌새를 알아차린다. 장례식 중 일본 홍구도장 일원이 정무관으로 찾아와 도발을 하자 진진은 그 다음날 홍구도장 본거지로 찾아가 쑥대밭으로 만들어 버린다. 홍구도장 관장인 스즈키 히로시는 이에 분노하여 이번엔 자신이 부하들을 이끌고 정무관으로 찾아오고, 때마침 자리를 비웠던 진진은 자신의 행동 때문에 정무관이 위태롭게 되자 상하이를 떠나기로 마음 먹는다.', 'https://image.tmdb.org/t/p/w500/svZnOMnX8yN8OFsqIE4COCsPXp1.jpg', 1972, 0, 0, '2026-06-08 06:24:42.875504', 'US');
INSERT INTO public.movies VALUES (4114, 395000, '젊은 엄마 4', '["Romance"]', 'Kim Hyo-jae', '["Park Cho-hyeon", "Ah Ri", "Ho Yeong", "Soo Hwan", "Yoon Kyo-hee"]', '제가 지켜줄게요, 엄마  어느 섬마을, 재수생인 우진, 태식의 친구인 강희가 고향으로 놀러온다. 우진의 엄마인 현숙은 철모른 어린 시절 에로배우로 잠깐 활동한 적이 있었다. 현숙은 섬에서 작은 횟집과 민박집을 운영하며 생계를 이어나가고 육지로 나가길 거부한 채 섬에서 은둔자처럼 살아간다. 현숙은 봉성과 섹스를 하기도 하지만 봉성의 프로포즈는 거절한다.  우진과 강희는 연인 사이지만 우진의 바램과는 달리 강희는 키스 외에는 몸을 허락하지 않는다.  우진은 어느 날 민박집에 숙박한 혜리와 첫 경험을 했으나 그것은 한바탕 꿈 일뿐..  어느 날, 엄마인 현숙과 봉성의 섹스를 목격한 우진은 큰 충격을 받고 홧김에 강희를 찾아가 완력으로 강희를 덮치려 한다. 결국 강희와 이별하게 되고... . 현숙은 아들을 위해 봉성에게 이별을 통보한다.  태식은 친구가 구해온 에로 DVD를 보려 한다. DVD의 여배우는 우진 엄마를 꼭 닮았고, 태식은 다른 상상을 하기 시작하는데... .', 'https://image.tmdb.org/t/p/w500/UsQC34yh6U7oAUdRn2nMDNXbwf.jpg', 2016, 0, 0, '2026-06-08 06:27:13.080113', 'KR');
INSERT INTO public.movies VALUES (4248, 652572, '엄마친구 6', '["Romance"]', 'Kim Min-woo-I', '["Sae Bom", "Yoo Jung", "Lee Hyo-jin-I", "Choi Min-ho"]', NULL, 'https://image.tmdb.org/t/p/w500/fGl0JGTGNNgqT5XYwcR0BUmODA3.jpg', 2019, 0, 0, '2026-06-08 06:29:19.651418', 'KR');
INSERT INTO public.movies VALUES (4249, 628704, '미드나이트', '["Thriller", "Crime"]', 'Kwon Oh-seung', '["Jin Ki-joo", "Wi Ha-jun", "Park Hoon", "Kil Hae-yeon", "Kim Hye-yoon"]', '청각장애를 가진 경미는 귀가하던 길에 피를 흘리며 쓰러져 있는 소정을 목격하고, 그녀를 도와주려다 연쇄살인마 도식의 새로운 타겟이 된다. 살고 싶다는 의지로 미친듯이 도망치는 경미, 하지만 살인마의 발소리조차 들을 수 없고, 도식은 또 다른 얼굴로 나타나 경미를 위협하는데...', 'https://image.tmdb.org/t/p/w500/oJoLrbgEqupECFC7TwcmSZY2JSn.jpg', 2021, 0, 0, '2026-06-08 06:29:20.415189', 'KR');
INSERT INTO public.movies VALUES (4250, 938092, '다 받아주는 콜센터', '["Drama", "Romance"]', 'Mr. Na', '["Yoon Yool", "Lee Chae-dam", "Ji Hee", "Min Do-yoon", "Kenny"]', NULL, 'https://image.tmdb.org/t/p/w500/g9nRwyMGEWLyMOBtRgjkETloEfh.jpg', 2021, 0, 0, '2026-06-08 06:29:21.171797', 'KR');
INSERT INTO public.movies VALUES (4251, 508081, '어린 엄마', '["Drama"]', 'Kye Jang-hyuk', '["Ha Jin", "Min Do-yoon", "Park Hyun-jung"]', '어린 새엄마가 왔다! 부인을 일찍 보내고 혼자 아들과 사는 중년의 상민은 어리고 섹시한 재일교포 에리카를 집으로 데려온다. 아들 현민에게 앞으로 같이 살게 된 새엄마라고 소개하는데, 현민은 그런 아버지가 못마땅하면서도, 어리고 섹시한 에리카에게 묘한 감정을 느낀다. 그날 밤 우연히 살짝 열린 방문 사이로 아빠와 새엄마의 섹스 장면을 목격하게 되는데...', 'https://image.tmdb.org/t/p/w500/svbidodVCjahBqz2Et17AMghmZ9.jpg', 2017, 0, 0, '2026-06-08 06:29:21.929306', 'KR');
INSERT INTO public.movies VALUES (4263, 504903, '불륜 동창회', '["Drama", "Romance"]', 'Jo Tae-ho', '["Kim Hee-jeong", "Kim Ji-yeon", "Jin Joo"]', '오랜만에 펜션을 잡고 모인 다섯 명의 대학 동창들. 반가운 마음에 지난 추억을 나누고 있지만 사실 진짜 의도는 따로 있는데?! 대학 시절 짝사랑하던 유진을 찾아온 윤재. 두 명의 여자 동창 사이에서 양다리를 즐기는 정식. 각기 다른 방식으로 즐거움을 만끽하는 불륜 동창회가 이제 시작되는데…', 'https://image.tmdb.org/t/p/w500/oRcwpgqV7Wjt1xok8SztZWHcgn4.jpg', 2018, 0, 0, '2026-06-08 06:29:31.902041', 'KR');
INSERT INTO public.movies VALUES (4271, 1233728, '7일간의 스와핑', '["Romance"]', 'Kim Man-seok-I', '["Lee Chae-dam", "Yeon Joo", "Han Seok-bong", "Kang Min-woo"]', NULL, 'https://image.tmdb.org/t/p/w500/9DNis2hoyLImQnGIZoianI7iohe.jpg', 2023, 0, 0, '2026-06-08 06:29:37.98662', 'KR');
INSERT INTO public.movies VALUES (445, 4257, '무서운 영화 4', '["Comedy"]', 'David Zucker', '["Anna Faris", "Regina Hall", "Craig Bierko", "Bill Pullman", "Anthony Anderson"]', '패러디의 끝은 어디인가? 박스오피스를 화려하게 장식했던 작품 중에서도 명장면 명대사만 골라 기발한 아이디어를 첨가해 탄생한 무서운 영화가 벌써 4회를 맞았다. 이번에는 ‘소우’, ‘그루지’, ‘브로크백 마운틴’, ‘우주전쟁’. ‘빌리지’등을 패러디해 유쾌 상쾌 통쾌한 해학을 선사한다.  전편의 가슴 아픈 과거를 간직한 채, 가정에서 환자를 돌보는 간병인이 된 ‘신디 캠벨’은 크레인 운전기사로 일하는 ‘톰 라이언’에게 첫눈에 반한다. 급작스런 외계군단의 침공으로 도시가 아수라장이 된 가운데, 억울하게 죽어 지구를 떠돈다는 한 꼬마 아이의 영혼으로부터 침공을 막을 수 있는 방법을 알게 된 신디는 우연히 만난 옛친구, 브렌다와 함께 외딴 마을에 숨어든다. 트라이포드가 지구인의 목을 조여오면서, 미국 대통령은 비밀병기를 소개하며 반격을 약속하지만, UN을 ‘언’으로 읽으며 무식함을 만천하에 공개하는 실수를 저지르고 만다. 신디는 베일에 싸인 마을에서 꼬마의 영혼을 달래고 외계인의 침공을 중단시킬 실마리를 찾게 되는데...', 'https://image.tmdb.org/t/p/w500/6fnD5s7tPKQOxXmBzGcspUl1Qfu.jpg', 2006, 0, 0, '2026-06-06 13:25:13.300243', 'US');
INSERT INTO public.movies VALUES (4153, 260550, '맛', '["Drama"]', 'Kyung Seokho', '["Jung Myung-seo", "Yu Da-eun", "Hee-jeong", "Lee Eun-mi", "Kim Jin-seon"]', '남자는 하나, 여자는 다섯?!INSERT INTO public.movies VALUES (4264, 662702, '엄마의 유혹 2', '["Romance"]', 'Kim Min-woo-I', '["Han Seok-bong", "Kang Min-woo", "Sae Bom", "Lee Hyo-jin-I", "Yoo Jung"]', NULL, 'https://image.tmdb.org/t/p/w500/i6w3n00rCLGF3cRasGRabC0svJG.jpg', 2020, 0, 0, '2026-06-08 06:29:32.661805', 'KR');
INSERT INTO public.movies VALUES (4266, 845222, '킹덤: 아신전', '["Drama", "Fantasy", "Thriller"]', 'Kim Seong-hun', '["Gianna Jun", "Park Byung-eun", "Kim Si-a", "Kim Roi-ha", "Koo Kyo-hwan"]', '비극과 배신이 삶을 덮친다. 기이하고 불길한 뭔가를 발견한다. 한순간에 가족과 동족을 잃은 여인. 오직 복수를 꿈꾸며 살아온 그녀가 짙은 어둠을 마주한다.', 'https://image.tmdb.org/t/p/w500/dBz61uAt6xjJt4yqhiZXQt0a1bB.jpg', 2021, 0, 0, '2026-06-08 06:29:34.192435', 'KR');
INSERT INTO public.movies VALUES (4267, 919207, '서울의 봄', '["Drama", "Thriller", "Action", "History", "Crime"]', 'Kim Sung-soo', '["Hwang Jung-min", "Jung Woo-sung", "Lee Sung-min", "Park Hae-joon", "Kim Sung-kyun"]', '박 대통령의 암살 이후, 계엄령이 선포된다. 국군보안사령관 전두광과 그를 따르는 장교들에 의해 쿠데타가 일어나고 군대가 정치적 행동을 해선 안된다고 믿는 완고한 군인인, 수도방위사령관 이태신은 전두광을 막기 위해 그와 맞서기로 한다. 그들의 갈등이 점차 심화되고, 대혼란 속에서 모두가 갈망하던 서울의 봄은 예상치 못한 방향으로 흘러간다.', 'https://image.tmdb.org/t/p/w500/ukVVnY9ovwl78WE5KndcpA6SnAm.jpg', 2023, 0, 0, '2026-06-08 06:29:34.935844', 'KR');
INSERT INTO public.movies VALUES (4117, 1017163, '범죄도시 4', '["Action", "Crime", "Thriller", "Comedy"]', 'Heo Myeong-haeng', '["Don Lee", "Kim Moo-yul", "Park Ji-hwan", "Lee Dong-hwi", "Lee Ju-bin"]', '신종 마약 사건 3년 뒤, 괴물형사 마석도와 서울 광수대는 배달앱을 이용한 마약 판매 사건을 수사하던 중 수배 중인 앱 개발자가 필리핀에서 사망한 사건이 대규모 온라인 불법 도박 조직과 연관되어 있음을 알아낸다. 필리핀에 거점을 두고 납치, 감금, 폭행, 살인 등으로 대한민국 온라인 불법 도박 시장을 장악한 특수부대 용병 출신의 빌런 백창기와 한국에서 더 큰 판을 짜고 있는 IT업계 천재 CEO 장동철. 마석도는 더 커진 판을 잡기 위해 장이수에게 뜻밖의 협력을 제안하고 광역수사대는 물론, 사이버수사대까지 합류해 범죄를 소탕하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/jucHQwnRSma1O9V2bM007e4eSd7.jpg', 2024, 0, 0, '2026-06-08 06:27:16.985041', 'KR');
INSERT INTO public.movies VALUES (4261, 800345, '카터', '["Action", "Thriller", "Crime"]', 'Jung Byung-gil', '["Joo Won", "Lee Sung-jae", "Jeong So-ri", "Do Yeong-seo", "Camilla Belle"]', '기억을 잃은 채 깨어난 남자. 귀에 장착된 장치를 통해 의문의 목소리가 들려오고, 이제 이 목소리의 지시에 따라 위험천만한 인질 구조 작전에 뛰어들어야 한다.', 'https://image.tmdb.org/t/p/w500/aGKln9LeFkP30MAiwFiuaMmNvzG.jpg', 2022, 0, 0, '2026-06-08 06:29:30.421361', 'KR');
INSERT INTO public.movies VALUES (4262, 948632, '에이아이 섹스호텔', '["Drama", "Romance"]', 'Park Seon-ho-II', '["Lee Chae-dam", "Yoo Jung", "Ha Yeon", "Woo Yeol", "So Jeong"]', NULL, 'https://image.tmdb.org/t/p/w500/AgimCed3sTGkcNW5LiKUrb77EmN.jpg', 2022, 0, 0, '2026-06-08 06:29:31.164596', 'KR');
INSERT INTO public.movies VALUES (4269, 560527, '내안의 그놈', '["Fantasy", "Comedy", "Action"]', 'Kang Hyo-jin', '["Jung Jinyoung", "Park Sung-woong", "Ra Mi-ran", "Lee Soo-min", "Lee Pung-un"]', '옥상에서 떨어진 고등학생 동현이 길을 가던 엘리트 아재 판수를 덮치면서 제대로 바뀐다!? 게다가 판수는 동현의 몸으로 첫사랑 미선과 존재도 몰랐던 딸 현정을 만나게 되는데… 대유잼의 향연, 넌 이미 웃고 있다!', 'https://image.tmdb.org/t/p/w500/ofhf0Tn7hnBtboiUEuVj5IZyD3g.jpg', 2019, 0, 0, '2026-06-08 06:29:36.450509', 'KR');
INSERT INTO public.movies VALUES (4278, 1171345, '2대1 출장마사지 2', '["Drama", "Romance"]', 'Kim Nam-joon', '["Ahn So-hee", "Do Hee", "Sang Woo", "Si Woo", "Min Jo-ah"]', NULL, 'https://image.tmdb.org/t/p/w500/royJd80idWwTfZ0eVGLLnPyN0aM.jpg', 2023, 0, 0, '2026-06-08 06:29:43.437068', 'KR');
INSERT INTO public.movies VALUES (4280, 425650, '전망 좋은 집 3', '["Romance", "Drama"]', 'Gyeong Seok-Ho', '["Yoo Ji-won", "Kim Sang-hyeon", "Han Soo-min", "Kang Cheol-ho", "Seo Won"]', NULL, 'https://image.tmdb.org/t/p/w500/pTz9dZWXirTQL8sIUAOld5FTBmT.jpg', 2016, 0, 0, '2026-06-08 06:29:44.778988', 'KR');
INSERT INTO public.movies VALUES (4273, 1203329, '위쳐: 세이렌의 바다', '["Animation", "Fantasy", "Action"]', 'Kang Hei Chul', '["Doug Cockle", "Joey Batey", "Christina Wren", "Emily Carey", "Camrus Johnson"]', '심해에서 정체불명의 바다 생물이 뱃사람들을 공격하는 사건이 벌어진다. 이제 육지와 바다 사이의 전쟁을 막을 수 있는 이는 단 한 사람, 최고의 위쳐인 리비아의 게롤트뿐이다.', 'https://image.tmdb.org/t/p/w500/dr1531wNFRXamAQlcTe74JpNKLU.jpg', 2025, 0, 0, '2026-06-08 06:29:40.097745', 'KR');
INSERT INTO public.movies VALUES (4274, 297721, '강남 1970', '["Action", "Crime", "Thriller"]', 'Yoo Ha', '["Lee Min-ho", "Kim Rae-won", "Jung Jin-young", "Kim Ji-soo", "Kim Seol-hyun"]', '호적도 제대로 없는 고아로, 넝마주이 생활을 하며 친형제처럼 살던 종대와 용기. 유일한 안식처였던 무허가촌의 작은 판자집마저 빼앗기게 된 두 사람은 건달들이 개입된  전당대회 훼방 작전에 얽히게 되고 그 곳에서 서로를 잃어버린다.  3년 후, 자신을 가족으로 받아 준 조직 두목 출신 길수의 바람과 달리, 잘 살고 싶다는 꿈 하나로 건달 생활을 하게 되는 종대. 정보와 권력의 수뇌부에 닿아있는 복부인 민마담과 함께 강남 개발의 이권다툼에 뛰어든 종대는 명동파의 중간보스가 된 용기와 재회하고, 두 사람은 정치권까지 개입된 의리와 음모, 배신의 전쟁터. 그 한 가운데에 놓이게 되는데…', 'https://image.tmdb.org/t/p/w500/yRPuCjuxnOMLjtFRxV9XDqZRPzb.jpg', 2015, 0, 0, '2026-06-08 06:29:40.762404', 'KR');
INSERT INTO public.movies VALUES (4275, 859214, '엄마애인', '["Romance"]', '정진호', '["Jin Si-ah", "Min Do-yoon"]', '디자이너인 엄마와 함께 살고 있는 여대생 민희는 두 가지 비밀을 간직하고 있다.  한 가지는 정기적으로 만나는 나이 많은 섹스 파트너가 있는 것이다.  민희는 그 남자를 만남으로서 아빠의 빈자리를 대신 채우고 있다.  또 하나의 비밀은 최근 엄마에게 소개한 엄마의 개인트레이너 철민에게 자꾸 끌리는 것이다.  어느 날 약속이 취소되어 집으로 온 민희는 엄마와 철민의 섹스 장면을 몰래 훔쳐보게 되는데...', 'https://image.tmdb.org/t/p/w500/eZ4mmXwOBkfgbXbClqQAj943aGj.jpg', 2018, 0, 0, '2026-06-08 06:29:41.426863', 'KR');
INSERT INTO public.movies VALUES (4276, 430384, '내 아내의 언니', '["Romance", "Family", "Drama"]', 'Lee Sang-woo', '["Lee Chae-dam", "Kim Soo-ho", "Min Do-yoon", "Kim Ji-yeon"]', NULL, 'https://image.tmdb.org/t/p/w500/s1h6kr74MuJEWz3fl82NJVt7cnH.jpg', 2016, 0, 0, '2026-06-08 06:29:42.099344', 'KR');
INSERT INTO public.movies VALUES (4196, 335117, '맛있는 택배', '["Romance"]', 'Gi Dae-ho', '["Song Gi-joon", "Son Ga-ram", "Jeon Eun-jin", "Ban Hee", "Jeon Ye-eun"]', '물건 배달해 주다가 몸까지 줘버린 택배 청년!INSERT INTO public.movies VALUES (4205, 391907, '동거의 목적', '["Romance"]', 'Joo Sung-woo', '["Je Dong-hwa", "Park Ha-yan", "Joo Ye-bin", "Hee Jeong-I", "Lee Jun-hyeok"]', '신혼생활을 만끽하는 승구와 윤혜. 사진작가인 승구는 출근길 이웃 사촌이면서 선배인 정열과 한눈을 팔다가 신호대기중이던 앞차를 들이받고 엄청난 수리비때문에 괴로워 한다. 몸매 관리에 여념이 없는 윤혜는 어김없이 헬스장에 운동을 하러가고 담당 PT 인 태준의 이별얘기를 듣게 된다. 여자친구 집에서 동거를 하던 태준이 이별과 함꼐 쫓겨나게 되고 오갈 곳 없는 태준에게 윤혜는 자신의 신혼집 방 하나를 세를 놓아 승구의 수리비를 충당하려 하고 승구 역시 윤혜와 앙숙이자 친구인 모델 라라에게 자신의 집 월세를 제안한다. 그리고 그들의 목적(?)있는 동거가 시작되는데….', 'https://image.tmdb.org/t/p/w500/2XrA9pyHNoxuxNHQmSX3VCtZ7Ev.jpg', 2016, 0, 0, '2026-06-08 06:28:25.882703', 'KR');
INSERT INTO public.movies VALUES (4214, 437068, '택시운전사', '["Action", "Drama", "History"]', 'Jang Hoon', '["Song Kang-ho", "Thomas Kretschmann", "Yoo Hai-jin", "Ryu Jun-yeol", "Park Hyuk-kwon"]', '택시운전사 만섭은 아내를 여의고 11살 딸을 키우며 어렵게 살림을 꾸리는 가장. 외국손님을 태우고 광주에 갔다 통금 전에 돌아오면 밀린 월세를 갚을 수 있는 거금 10만원을 준다는 말에  독일기자 피터를 태우고 영문도 모른 채 길을 나선다. 피터는 독일 공영방송 소속 기자로, 일본에서 ‘광주가 심상치 않다’는 말을 듣고 광주로 향한다. 어떻게든 택시비를 받아야 하는 만섭의 기지로 검문을 뚫고 겨우 들어선 광주. 위험하니 서울로 돌아가자는 만섭의 만류에도 피터는 대학생 재식과 황기사의 도움 속에 촬영을 시작하는데...', 'https://image.tmdb.org/t/p/w500/pCdx7X5JLaSJZLNVtpryGSdjvvB.jpg', 2017, 0, 0, '2026-06-08 06:28:33.445845', 'KR');
INSERT INTO public.movies VALUES (4290, 700186, '엄마친구 5', '["Romance"]', 'Myeong Seok Hwan', '["Shin Yeon-woo", "Lee Yeong-ho-I", "Choi Yeon-i", "Seo Eun-yeong-I", "Hyeon Yeong-im-I"]', '밤마다 옆방에서 들려오는 엄마 친구의 신음소리!  남자의 마음을 뒤흔든 그녀가 다시 왔다!  집에서 공부하며 수능을 준비 중이던 삼수생 재홍앞에 지나치게 섹시한 엄마 친구 은진이 나타난다.  이혼 후 살 집을 구할 때까지만 재홍의 집에 얹혀 살기로 한 은진.  날이 갈수록 재홍은 책이 아니라 볼륨감 넘치는 은진의 바디라인에 시선이 간다.  게다가 재홍뿐만 아니라 아빠 영호 역시 은진에게 푹 빠져 버리는데…', 'https://image.tmdb.org/t/p/w500/1aqZZEYf1jzZHyvbCI2B008IQMw.jpg', 2018, 0, 0, '2026-06-08 06:29:51.469401', 'KR');
INSERT INTO public.movies VALUES (4292, 701952, '여친 엄마2', '["Romance"]', 'Choi Min', '["Yoo Ni", "Lee Chae-dam", "Lee Joon-hyuk-II", "Han Seol-hwa"]', '젊은 것(?)에 푹 빠진 여친 엄마! 그녀의 육탄공세가 시작된다!!!INSERT INTO public.movies VALUES (4293, 1310677, '하나 코리아', '["Drama"]', 'Frederik Sølberg', '["Kim Min-ha", "Kim Joo-ryoung", "An Seo-hyun", "Lee Jong-eun", "Lee Joo-mi"]', '모든 것을 뒤로하고, 자유를 찾아 남한 사회에 도착한 탈북 여성 혜선. 자유를 향한 그녀의 여정에는 대가가 따른다. 새로운 삶을 개척하기 위해 혜선은 짙게 드리우는 과거의 그림자와 싸우고, 포기와 순응을 요구하는 현대사회에서 자신의 자리를 찾아야 한다. 과연 혜선은 진정으로 자유로워질 수 있을까?', 'https://image.tmdb.org/t/p/w500/ceYPF2nk4ZruN8wU4EFTaobQNOL.jpg', 2026, 0, 0, '2026-06-08 06:29:54.213549', 'KR');
INSERT INTO public.movies VALUES (4294, 418827, '젊은 형부', '["Drama"]', 'Park Eun-ho', '["Park Joo-bin", "Joo Ye-bin", "Wi Ji-Woong", "Sang Woo"]', '섹시한 형부가 나에게로 왔다? 거기에 연하남!?  어릴 적, 입양 된 미연은 결혼 한 언니 시연과 그리고 그녀의 남편. 형부와 함께 살고 있다. 매일 밤 형부와 언니의 애정행각을 보며 형부에 대한 말할 수없는 욕망을 키워가는 미연.INSERT INTO public.movies VALUES (4392, 481891, '정사: 친구의 엄마', '["Romance", "Drama"]', 'Kwak Yeong-geun', '["Kim Ji-yeon", "Jo Wan-jin", "Hayashi Risa", "Kim Seung-goo", "Ga Bin"]', '친구의 엄마, 그리고 아들의 친구! 절대 맺어져선 안 될 그들의 파격 정사! 여친과 헤어진 다음날, 진탕 술을 마시고 친구 윤수의 집에서 깨어난 정식. 누나라고 해도 믿을 수 있을 정도로 젊고 아름다운 윤수의 엄마 주영과 마주친다. 자신이 여자라는 것도 잊고 살던 주영은 자신을 탐욕스럽게 바라보는 정식의 시선을 즐기게 되고, 결국 그녀가 먼저 정식의 젊은 몸을 탐하기 시작하는데...', 'https://image.tmdb.org/t/p/w500/gzODeFmANKzUAknaNplB0QGqQqJ.jpg', 2017, 0, 0, '2026-06-08 06:31:08.611309', 'KR');
INSERT INTO public.movies VALUES (4288, 357965, '원나잇온리', '["Romance", "Drama"]', 'Kim Jho Gwang-soo', '["Park Soo-jin", "Jang Yoo-sang", "Park Keun-rok", "Yoo Min-kyu", "Jeong Won-jo"]', '2014 서울LGBT영화제에서 프리미어로 공개된 퀴어옴니버스영화 ''하룻밤'' (김조광수). 스무 살 게이청년 세 명이 수능시험을 본 날 만나는 남자들과 하룻밤을 보내게 되는 내용. ''밤벌레'' (김태용) 한재는 게이인 척 위장하여 밤마다 인터넷 채팅을 통해 유흥가 호프에 게이들을 모아 술자리를 마련한 뒤 호프집 사장과 짜고 그들을 등쳐먹으며 산다. 그는 게이들에게 인기가 많은 귀여운 외모의 훈을 애인인 척 데리고 다니며 이용하지만 자신에 대한 훈의 마음을 애써 외면한다.', 'https://image.tmdb.org/t/p/w500/2h1doVetvEpvv6BEMvUpb00qHhH.jpg', 2014, 0, 0, '2026-06-08 06:29:50.144857', 'KR');
INSERT INTO public.movies VALUES (4289, 567646, '극한직업', '["Action", "Comedy", "Crime"]', 'Lee Byeong-heon', '["Ryu Seung-ryong", "Lee Hanee", "Jin Sun-kyu", "Lee Dong-hwi", "Gong Myoung"]', '불철주야 달리고 구르지만 실적은 바닥, 급기야 해체 위기를 맞는 마약반!  더 이상 물러설 곳이 없는 팀의 맏형 고반장은 국제 범죄조직의 국내 마약 밀반입 정황을 포착하고 장형사, 마형사, 영호, 재훈까지 4명의 팀원들과 함께 잠복 수사에 나선다.  마약반은 24시간 감시를 위해 범죄조직의 아지트 앞 치킨집을 인수해 위장 창업을 하게 되고, 뜻밖의 절대미각을 지닌 마형사의 숨은 재능으로 치킨집은 일약 맛집으로 입소문이 나기 시작한다.  수사는 뒷전, 치킨장사로 눈코 뜰 새 없이 바빠진 마약반에게 어느 날 절호의 기회가 찾아오는데…', 'https://image.tmdb.org/t/p/w500/lzzb384pgYyr0GQvu3K2ZW62CEE.jpg', 2019, 0, 0, '2026-06-08 06:29:50.810237', 'KR');
INSERT INTO public.movies VALUES (764, 1035048, '엘리베이션', '["Action", "Sci-Fi", "Thriller"]', 'George Nolfi', '["Anthony Mackie", "Morena Baccarin", "Maddie Hasson", "Danny Boyd Jr.", "Rachel Nicks"]', '전 세계에서 정체 불명의 싱크홀이 발생하며, 그 속에서 나타난 괴물 "리퍼(Reaper)"가 인류의 95%를 말살한다. 리퍼는 해발 8,000피트 이상의 고지대로는 올라가지 못하는 약점을 가지고 있다. 이에 살아남은 생존자들은 고지대에 피난처를 마련하고 생존을 이어간다. 주인공 윌은 폐질환을 앓고 있는 아들 헌터를 살리기 위해, 과학자 니나와 친구 케이티와 함께 위험을 무릎쓰고 산 아래로 내려와 필요한 장비를 구하려 한다. 이 과정에서 리퍼와 맞서 싸우며 생존을 위한 여정을 이어가는데...', 'https://image.tmdb.org/t/p/w500/tnfc0NJ3BzhJrGJhkkEd6MHBdq5.jpg', 2024, 0, 0, '2026-06-06 13:25:25.713939', 'US');
INSERT INTO public.movies VALUES (4291, 556509, '사바하', '["Horror", "Mystery", "Thriller", "Crime"]', 'Jang Jae-hyun', '["Lee Jung-jae", "Park Jeong-min", "Lee Jae-in", "Yoo Ji-tae", "Jung Jin-young"]', '신흥 종교 비리를 찾아내는 종교문제연구소 박목사. 최근 사슴동산이라는 새로운 종교 단체를 조사 중이다. 영월 터널에서 여중생이 사체로 발견되는 사건이 발생하고 이를 쫓던 경찰과 우연히 사슴동산에서 마주친 박목사는 이번 건이 심상치 않음을 직감한다. 터널 사건 유력 용의자의 자살, 그리고 실체를 알 수 없는 정비공 나한과 16년 전 태어난 쌍둥이 동생 금화의 존재까지, 사슴동산에 대해 파고들수록 박목사는 점점 더 많은 미스터리와 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/9NvqPjMwjQ2hGwSEXcZ1VZ4mqVS.jpg', 2019, 0, 0, '2026-06-08 06:29:52.150546', 'KR');
INSERT INTO public.movies VALUES (4299, 894753, '내로남불', '["Romance"]', NULL, '["Cha Myung-Hoon", "Choi Do-hee", "Sang Woo", "Yoon Yool"]', '부부관계가 소원한 여정과 도진, 알고보니 아내 여정 몰래 다른 여자와 밀애를 즐기던 도진. 한편, 외로움에 몸부림치던 여정은 우연히 영민을 알게 되었고, 이후 자신에게 사랑이라는 감정이 다시 싹트게 됨을 느끼게 된다.', 'https://image.tmdb.org/t/p/w500/jdxiDmtuLiiKV3W9nOGTzVwBEWY.jpg', 2020, 0, 0, '2026-06-08 06:29:58.223101', 'KR');
INSERT INTO public.movies VALUES (4297, 387839, '전원일기: 젖소농장새댁', '["Drama", "Romance"]', 'Han Dong-Ho', '["Lim Song-yi"]', '젖소농장에서 열심히 일을 하며 하루하루를 보내는 동길. 어느 날 동길이 일하고 있는 젖소농장에 매력적인 여자 주라가 일손을 도우러 오게 된다. 동길은 주라에게 마음을 빼앗기게 되고 주라도 그런 동길이 싫지만은 않다. 펜션과 젖소농장에서 분주하게 일하고 있는 주라에게 갑자기 의문의 남자가 찾아오게 되고.. 이 남자는 주라가 일하는 곳의 주인인 정태에게 은밀한 제안을 하게 되는데....', 'https://image.tmdb.org/t/p/w500/bWtWi0ka8mRDgdCXRhv4BJE3pr4.jpg', 2015, 0, 0, '2026-06-08 06:29:56.902783', 'KR');
INSERT INTO public.movies VALUES (4302, 1181107, '킹 오브 킹스', '["Adventure", "Animation", "Family", "Fantasy"]', 'Jang Seong-ho', '["Oscar Isaac", "Kenneth Branagh", "Uma Thurman", "Pierce Brosnan", "Roman Griffin Davis"]', '영국의 소설가 찰스 디킨스는 아서 왕을 동경하는 개구쟁이 막내 아들 월터에게 진정한 왕 예수에 대한 이야기를 들려주기로 한다. 아버지의 실감 나는 이야기에 빠져든 월터는 어느새 2000년 전, 예수가 태어난 순간으로 여행을 떠나게 된다. 월터는 예수의 놀라운 기적과 끝없는 사랑을 가까이에서 지켜보며 점점 그에게 이끌리게 된다. 그러나 행복한 순간도 잠시, 예수에게 닥쳐온 시련들과 그것을 담담히 받아들이는 모습을 통해 월터는 아버지의 이야기 속에 감춰진 진심을 깨닫게 된다.', 'https://image.tmdb.org/t/p/w500/98KunrxxQOaDGeefGuyjaZ0UWes.jpg', 2025, 0, 0, '2026-06-08 06:30:00.234408', 'KR');
INSERT INTO public.movies VALUES (219, 1234731, '아나콘다', '["Adventure", "Comedy"]', 'Tom Gormican', '["Jack Black", "Paul Rudd", "Steve Zahn", "Thandiwe Newton", "Daniela Melchior"]', '중년의 위기를 겪고 있는 친구들이 젊은 시절 가장 좋아했던 영화를 재현하기 위해 열대우림으로 떠난다. 그러나 그들은 자연 재해, 거대한 뱀, 그리고 폭력적인 범죄자들과 맞서 싸우며 생존을 위한 사투를 벌이게 된다.', 'https://image.tmdb.org/t/p/w500/4HxOXiEFPAFQhzkobIU9Lqlezlq.jpg', 2025, 0, 0, '2026-06-06 13:25:04.124569', 'US');
INSERT INTO public.movies VALUES (4298, 671622, '처제의 비밀', '["Drama"]', 'Choi Jae-hoo', '["Kim Ji-ah", "Sae Bom", "Jo Wan-jin"]', '처제는 동성 애인과 모텔에 간다. 모텔의 엘리베이터에서 예쁜 언니를 두고 바람을 피는 형부와 우연히 마주치게 된다. 그 순간 처제는 피가 거꾸로 솟았지만 어찌 할 수가 없었다. 자신 또한 형부에게 레즈비언인 것을 들켰기 때문이다. 그들은 서로의 비밀을 유지하기 위해 결탁하지만, 형부에게 약점이 잡힌 처제는 형부의 요구에 의해 자신의 동성 애인과 함께 쓰리섬을 하게 되는데...​', 'https://image.tmdb.org/t/p/w500/ib7jFLnrI7KLbGa1GeZ9ZCuoWgO.jpg', 2019, 0, 0, '2026-06-08 06:29:57.561862', 'KR');
INSERT INTO public.movies VALUES (4300, 435366, '조작된 도시', '["Action", "Thriller", "Crime"]', 'Bae Jong', '["Ji Chang-wook", "Shim Eun-kyung", "Oh Jung-se", "Ahn Jae-hong", "Kim Sang-ho"]', '게임 세계 속에서는 완벽한 리더지만 현실에서는 평범한 백수인 권유.  PC방에서 우연히 휴대폰을 찾아 달라는 낯선 여자의 전화를 받게 되고 이후, 영문도 모른 채 그녀를 잔인하게 살해한 범인으로 몰리게 된다. 모든 증거는 짜맞춘 듯 권유를 범인이라 가리키고,  아무도 그의 결백을 믿어주지 않는 가운데 권유의 게임 멤버이자 초보 해커인 여울은 이 모든 것이 단 3분 16초 동안, 누군가에 의해 완벽하게 조작되었음을 알게 된다. 특수효과 전문 데몰리션을 비롯 게임 멤버가 모두 모여 자신들만의 새로운 방식으로 사건의 실체를 추적해나가기 시작하고, 조작된 세상에 맞서기 위한 짜릿한 반격에 나서는데...', 'https://image.tmdb.org/t/p/w500/v2TRu7tQ8LKHOwfusckYjHvXiya.jpg', 2017, 0, 0, '2026-06-08 06:29:58.878114', 'KR');
INSERT INTO public.movies VALUES (4301, 387814, '맛있는 덫-정사', '["Romance", "Thriller"]', 'Jeong-gyun Shin', '["No Seong-gyoon", "Han Soo-yeon-I", "Yu Seok-hwan"]', '임대업을 하는 문자는 밤일도 잘 못하는 별 볼일 없는 셔터맨 남편 상인과 따분한 결혼생활을 보내고 있다. 그러던 어느 날, 문자네 집에 예전에 잘 나가던 에로 여배우 연희가 입주하게 되고, 상인은 연희를 보고 묘한 설레임에 들뜨게 된다. 사실 상인은 연희가 주연을 한 ''욕망의 늪''이라는 에로 영화의 광팬 이었던 것. 연희는 집주인인 상인에게 이것저것 수리를 부탁하면서 둘 사이는 점차 가까워진다. 그러던 와중 상인은 문자가 자신의 절친한 친구인 동석과 바람을 피우고 있다는 사실을 알게 되고 엎친 데 덮친 격으로 옆집 여자 연희에게 폭력을 행사하는 전 매니저를 목격하게 된다. 서로의 아픔을 나누며 옆집 여자 연희와 상인은 점점 더 가까워지게 되고, 상인은 옆집 여자 연희와 함께 하고 싶은 마음에 극단적인 선택을 하게 되는데...', 'https://image.tmdb.org/t/p/w500/aUuuzetIXKeKgCYtTHFsScfS5lL.jpg', 2015, 0, 0, '2026-06-08 06:29:59.563663', 'KR');
INSERT INTO public.movies VALUES (4296, 921436, '탈주', '["Action", "Drama", "Thriller"]', 'Lee Jong-pil', '["Lee Je-hoon", "Koo Kyo-hwan", "Hong Xa-bin", "Seo Hyun-woo", "Lee Sung-wook"]', '휴전선 인근 북한 최전방 군부대. 10년 만기 제대를 앞둔 중사 규남은 미래를 선택할 수 없는 북을 벗어나 원하는 것을 해 볼 수 있는 철책 너머로의 탈주를 준비한다. 그러나, 규남의 계획을 알아챈 하급 병사 동혁이 먼저 탈주를 시도하고, 말리려던 규남까지 졸지에 탈주병으로 체포된다. 탈주병 조사를 위해 부대로 온 보위부 소좌 현상은 어린 시절 알고 지내던 규남을 탈주병을 체포한 노력 영웅으로 둔갑시키고 사단장 직속보좌 자리까지 마련해주며 실적을 올리려 한다. 하지만 규남이 본격적인 탈출을 감행하자 현상은 물러설 길 없는 추격을 시작한다.', 'https://image.tmdb.org/t/p/w500/m2pFuNkL9V4lZxtVbBzB9yrYHai.jpg', 2024, 0, 0, '2026-06-08 06:29:56.21846', 'KR');
INSERT INTO public.movies VALUES (200, 537915, '애프터', '["Drama", "Romance"]', 'Jenny Gage', '["Josephine Langford", "Hero Fiennes Tiffin", "Shane Paul McGhie", "Khadijha Red Thunder", "Dylan Arnold"]', '대학 입학 후 첫 파티에 초대 받게 된 신입생 ‘테사’는 진실게임을 하던 중 키스 벌칙에 걸리고 만다. 상대는 학교에서 유명한 반항아 ‘하딘’. 키스를 앞둔 0.1초 전, 모두가 주목하는 그 순간 ‘테사’는 ‘하딘’의 입술을 거절하고 만다. 강렬했던 첫 만남 이후, 마치 새로운 세상을 발견한 듯 한번도 경험한 적 없던 감정에 눈을 뜨게 된 두 사람. ‘하딘’은 자신의 비밀 장소로 ‘테사’를 초대하고 이제 두 사람은 서로를 모르기 전으로 절대 되돌아 갈 수 없음을 알게 되는데…', 'https://image.tmdb.org/t/p/w500/zTZ7Q9mAwBQoYaR8HgGbmBNp6AC.jpg', 2019, 0, 0, '2026-06-06 13:25:03.363735', 'US');
INSERT INTO public.movies VALUES (4305, 499753, '처제의 유혹', '["Romance"]', 'Park Sun-Uk', '["Yoon Se-na", "Ah Ri", "Min Do-yoon", "Sin Seong-hoon", "Lee Yoo-chan"]', '인생 한방. 도박과 섹스에 빠져 빚쟁이에 쫓기며 하루 하루 살아가는 정민. 돈 많은 쌍둥이 형의 실종을 알게 된 정민은 형의 재산을 가로채 빛을 갚고 폼나게 살 계획을 세우는데 예상치 못한 젊고 아름다운 형의 처제 새은의 방문으로 정민의 계획은 어긋나기 시작하는데, 형부를 사랑하는 새은과 형의 재산을 노리는 정민의 위험하고 야한 동거가 시작된다. 정민은 새은의 유혹을 이겨내고 형의 재산을 가로챌 수 있을까?', 'https://image.tmdb.org/t/p/w500/xGA1LHCdxwjQwqRavFXlveS0Hvg.jpg', 2017, 0, 0, '2026-06-08 06:30:02.232206', 'KR');
INSERT INTO public.movies VALUES (4306, 1234966, '삼얼간이', '["Romance", "Comedy"]', 'Buk-gu', '["Sae Bom", "Yoon Yool", "Yoo Ji-hyun", "Min Do-yoon", "Kang Min-woo"]', NULL, 'https://image.tmdb.org/t/p/w500/9DTZbFvs6QFCkukILnjTcERnIb2.jpg', 2021, 0, 0, '2026-06-08 06:30:03.900445', 'KR');
INSERT INTO public.movies VALUES (4215, 854663, 'O형수박가슴가정부', '["Drama", "Romance"]', NULL, '["Seung Ha", "Chul Jin", "Kang Min-woo", "Han Yi-seul"]', '집안일은 못하지만 몸과 마음을 위로해 주는 신개념 가사도우미, 오늘은 어딜 풀어드릴까요?  오랜만에 만나 이야기를 나누게 된 친구 철민과 재혁. 재혁은 최근 자신의 집에 일하러 오는 가사도우미가 이상하다며 가정부에 대하여 이야기 하는데, 가사 도우미가 집안일인 청소나 음식준비 등 가사일을 너무 못해 고민이라고 한다. 가사 일은 잘 못하지만 커다란 가슴과 엉덩이로 자신을 유혹하는 것 같다고 말하는 재혁의 말에 철민은 재혁과 가정부와의 섹스를 상상하는데, 철민의 기대와는 다르게 재혁은 아직 가사도우미와 아무 일이 없었다 말하는 재혁의 말에 답답함을 느낀 철민은 순진한 재혁에게 그녀를 꼬실 수 있는 특급 비법을 알려주는데. 과연, 재혁은 미모의 가사도우미를 꼬셔 섹스에 성공 할 수 있을까?', 'https://image.tmdb.org/t/p/w500/1xdJWTn5Tuqy7yWTywC9WBPyicW.jpg', 2021, 0, 0, '2026-06-08 06:28:34.176738', 'KR');
INSERT INTO public.movies VALUES (4224, 727340, '헌트', '["Action", "Mystery", "Drama"]', 'Lee Jung-jae', '["Lee Jung-jae", "Jung Woo-sung", "Jeon Hye-jin", "Heo Sung-tae", "Go Youn-jung"]', '북한 고위 관리가 망명을 요청한 이후, 안기부 해외팀 차장 박평호와 국내팀 차장 김정도는 동림으로 알려진 안기부 내 스파이, 남파간첩 총책임자를 밝혀내는 임무를 맡는다. 이윽고 동림이 국가 안보를 위태롭게 할 1급 비밀 정보를 누설하기 시작하고 안기부의 해외팀과 국내팀은 서로를 조사하기에 이른다. 당장 스파이를 밝혀내지 못하면 자신이 혐의를 받을 수 있는 일촉즉발의 상황에서 평호와 정도는 서서히 진실을 찾아내고, 마침내 대한민국 1호 암살 작전이라는 거대한 사건과 직면하게 되는데...', 'https://image.tmdb.org/t/p/w500/Dyc3aCm3F4h8dXr4V5fnIopiyE.jpg', 2022, 0, 0, '2026-06-08 06:28:41.066278', 'KR');
INSERT INTO public.movies VALUES (4307, 1105602, '새엄마는 열아홉', '["Drama", "Romance"]', NULL, '["Seung Ha", "Lee Do-jin"]', NULL, 'https://image.tmdb.org/t/p/w500/wjHQOmstLZKF0urCZRwn2xunmsn.jpg', 2020, 0, 0, '2026-06-08 06:30:04.566373', 'KR');
INSERT INTO public.movies VALUES (4308, 1143209, '숫처녀의 조건만남', '["Romance"]', 'Yoon Soo-hyun', '["So Ra", "Kang Min-woo", "Lee Chae-dam", "James", "Lim Ji-yeong"]', NULL, 'https://image.tmdb.org/t/p/w500/tHgop4PCZHWCgPIKMFmKoxgnvx3.jpg', 2022, 0, 0, '2026-06-08 06:30:05.238416', 'KR');
INSERT INTO public.movies VALUES (4309, 1701849, 'BTS World Tour ‘Arirang’ in Busan: Live Viewing', '[]', 'Ha Jung-jae', '["RM", "Jin", "Suga", "j-hope", "Jimin"]', NULL, 'https://image.tmdb.org/t/p/w500/aUEKzaQKjO9l695NIWRxI00Fi67.jpg', 2026, 0, 0, '2026-06-08 06:30:05.904559', 'KR');
INSERT INTO public.movies VALUES (4311, 1614973, '여제자', '[]', NULL, '["Seung Ha", "Yoon Yool", "Min Do-yoon"]', '진이는 익숙한 고급창녀 생활에 회의를 느낀다 도망치고 싶은 인생.  마침 새로 입성한 복서 두산에게 호감을 갖고 함께 그곳을 떠나자고 하지만 두산은 진이의 바람과 달리 그곳에 남기로 한다.  한편, 연수는 힘들게 음대에 들어갔지만 홀로 대학생활을 이어가야하기에 아르바이트를 하는 등 학업을 제대로 잇지 못한다.  담당 교수에게 몸을 줄 각오로 짧은 치마를 입은 연주. 그러나 눈 하나 깜빡이지 않는 담당 교수.  희망을 잃은 연주는 삶을 포기하려 하는데 갑작스럽게 찾아온 행운에 우아한 인생을 꿈꾼다.', 'https://image.tmdb.org/t/p/w500/uSZjTUHO9KNvQO3uZ5K6wk73rge.jpg', 2025, 0, 0, '2026-06-08 06:30:07.229395', 'KR');
INSERT INTO public.movies VALUES (4312, 1075676, '전,란', '["Action", "Drama", "History"]', 'Kim Sang-man', '["Gang Dong-won", "Park Jeong-min", "Cha Seung-won", "Kim Shin-rock", "Jin Sun-kyu"]', '조선 최고 무신 집안의 아들 종려와 그의 몸종 천영. 함께 자란 두 남자가 왜란의 시대에 적이 되어 다시 만난다. 한 사람은 선조의 최측근 무관으로, 다른 사람은 의병으로, 파란의 세월을 헤쳐간다.', 'https://image.tmdb.org/t/p/w500/gnfNGXdW7J9HGNeHyaDpkAFJkHK.jpg', 2024, 0, 0, '2026-06-08 06:30:08.624436', 'KR');
INSERT INTO public.movies VALUES (4317, 1039882, '로기완', '["Romance", "Drama"]', 'Kim Hee-jin', '["Song Joong-ki", "Choi Sung-eun", "Waël Sersoub", "Cho Han-cheul", "Kim Sung-ryung"]', '탈북자 기완은 낯선 땅 벨기에에서 난민 지위를 인정받고자 사투를 벌인다. 가진 것은 없어도 간절하게 살고 싶은 기완과 삶의 이유를 잃어버린 마리. 그들이 서로에게 이끌리듯 빠져든다.', 'https://image.tmdb.org/t/p/w500/sjfc4YwpWLhMHbpxgPoA5s1xBN6.jpg', 2024, 0, 0, '2026-06-08 06:30:11.982478', 'KR');
INSERT INTO public.movies VALUES (4319, 534171, '동창회의 목적 2', '["Drama", "Romance"]', 'Seung Woo Jin', '["Lee Cheol-hee", "Yoon Se-na", "Suh Zi-eun", "Min Joon", "Kim Si-eon"]', '넌 학생이고, 난 선생이야! 학창 시절, 과감하게 들이댔다가 어린애 취급만 받고 차인 첫 사랑 그녀가 동창회에 온다! 선생님과의 한을 풀고 싶은 대범부터 여자 동창들과의 원나잇에 중독된 병식, 여자 동창들의 노골적인 유혹에 시달리는 인기남 주호까지! 그들의 내숭 없고 발랑 까진 동창회가 다시 시작된다.', 'https://image.tmdb.org/t/p/w500/vJjTRTDxCgFFZ7TEkJk36lsc9G4.jpg', 2017, 0, 0, '2026-06-08 06:30:13.325131', 'KR');
INSERT INTO public.movies VALUES (4321, 544583, '엄마 친구 : 그녀의 섹스고백 무삭제판', '["Drama", "Romance"]', 'Choi Kang-ho', '["Minori Kotani"]', NULL, 'https://image.tmdb.org/t/p/w500/4X80eEG3qeL4ebFw8S1e7KqQuy5.jpg', 2018, 0, 0, '2026-06-08 06:30:14.66749', 'KR');
INSERT INTO public.movies VALUES (4421, 604360, '제8일의 밤', '["Mystery", "Thriller", "Horror"]', 'Kim Tae-hyoung', '["Lee Sung-min", "Nam Da-reum", "Park Hae-joon", "Kim You-jung", "Kim Dong-young"]', '붉은 달이 뜨는 밤, 봉인에서 풀려난 `붉은 눈`이 7개의 징검다리를 밟고 자신의 반쪽, `검은 눈`을 찾아간다. 그리고 마지막 제8일의 밤, 그 둘이 만나 하나가 되면 고통과 어둠만이 존재하는 지옥의 세상이 될 것이다.', 'https://image.tmdb.org/t/p/w500/a11TdGOWqASvbeMs7q0a1YLa5K.jpg', 2021, 0, 0, '2026-06-08 06:31:29.333172', 'KR');
INSERT INTO public.movies VALUES (4228, 575604, '콜', '["Thriller", "Mystery", "Sci-Fi"]', 'Lee Chung-hyun', '["Park Shin-hye", "Jeon Jong-seo", "Kim Sung-ryung", "Lee El", "Park Ho-san"]', '오랜만에 집으로 돌아온 서연. 집에 있던 낡은 전화기를 연결했다가 영숙이란 이름의 낯선 여자와 전화를 하게 된다. 서연은 영숙이 20년 전, 같은 집에 살았던 사람이란 사실을 깨닫고 그때부터 두 사람은 우정을 쌓아간다. 그러던 어느 날, 서연과 영숙은 각자의 현재에서 서로의 인생을 바꿀 사소한 선택을 하게 된다. 영숙은 20년 전 죽은 서연의 아빠를 살려주고, 서연은 그 대가로 영숙의 20년 후 미래를 알려준 것. 그러나 자신의 끔찍한 미래를 알게 된 영숙이 예상치 못한 폭주를 하면서 서연을 위협하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/HKr6HSGZyZBcI38rR1NjwsIcc0.jpg', 2020, 0, 0, '2026-06-08 06:28:44.13782', 'KR');
INSERT INTO public.movies VALUES (4315, 1240875, '음란산장 : 수상한 약장수', '["Drama"]', '한길수', '["Ha Yeon", "Seon Yool", "Gil Dong", "Park Do-jin"]', NULL, 'https://image.tmdb.org/t/p/w500/1pjbSY7I2Mucp6eAqbFDhfwBkLB.jpg', 2023, 0, 0, '2026-06-08 06:30:10.630776', 'KR');
INSERT INTO public.movies VALUES (4322, 50476, '스캔들: 조선남녀상열지사', '["Drama", "Romance"]', 'E J-yong', '["Bae Yong-jun", "Lee Mi-sook", "Jeon Do-yeon", "Jo Hyun-jae", "Lee So-yeon"]', '조선에서 태어난 것이 한이요, 불만인 조씨부인. 조선 최고의 바람둥이로 팔도에 그 명성이 자자한 조원. 어느날 조씨부인은 조원에게 남편의 새 소실자리 처녀를 건드려 달라 청하는데 조원의 표적은 이미 딴곳에 있었으니 소문난 정절녀 숙부인 정씨더라. 허나, 천하의 바람둥이 조원도 열녀문을 무너뜨리기가 영 녹녹치만은 않은데...', 'https://image.tmdb.org/t/p/w500/3FNRkf6Q8LP9lKgcmyc3kfdOxRi.jpg', 2003, 0, 0, '2026-06-08 06:30:15.330292', 'KR');
INSERT INTO public.movies VALUES (4323, 11344, '달콤한 인생', '["Action", "Drama", "Crime"]', 'Kim Jee-woon', '["Lee Byung-hun", "Kim Yeong-cheol", "Shin Min-a", "Kim Roi-ha", "Lee Ki-young"]', '서울 하늘 한 켠, 섬처럼 떠 있는 한 호텔의 스카이라운지. 그 곳은 냉철하고 명민한 완벽주의자 선우의 작은 성이다. 왜라고 묻지 않는 과묵한 의리, 빈틈 없는 일 처리로 보스 강사장의 절대적 신뢰를 획득, 스카이라운지의 경영을 책임지기까지, 그는 꼬박 7년의 세월을 바쳤다. 룰을 어긴 자는 이유를 막론하고 처단하는 냉혹한 보스 강사장. 그런 그에게는 남들에게 말 못 할 비밀이 하나 있다. 젊은 애인 희수의 존재가 바로 그것. 그녀에게 딴 남자가 생긴 것 같다는 의혹을 가진 강사장은 선우에게 그녀를 감시, 사실이면 처리하라고 명령하는데...', 'https://image.tmdb.org/t/p/w500/bo5882JREd8LjbziR8F0h7HuOLs.jpg', 2005, 0, 0, '2026-06-08 06:30:16.003151', 'KR');
INSERT INTO public.movies VALUES (240, 424, '쉰들러 리스트', '["Drama", "History"]', 'Steven Spielberg', '["Liam Neeson", "Ben Kingsley", "Ralph Fiennes", "Caroline Goodall", "Jonathan Sagall"]', '2차 세계대전 당시 독일군이 점령한 폴란드. 시류에 맞춰 자신의 성공을 추구하는 기회주의자 쉰들러는 유태인이 경영하는 그릇 공장을 인수한다. 그는 공장을 인수하기 위해 나찌 당원이 되고 독일군에게 뇌물을 바치는 등 갖은 방법을 동원한다. 그러나 냉혹한 기회주의자였던 쉰들러는 유태인 회계사인 스턴과 친분을 맺으면서 냉혹한 유태인 학살에 대한 양심의 소리를 듣기 시작한다. 마침내 그는 강제 수용소로 끌려가 죽음을 맞게될 유태인들을 구해내기로 결심하고, 독일군 장교에게 빼내는 사람 숫자대로 뇌물을 주는 방법으로 유태인들을 구해내려는 계획을 세우는데...', 'https://image.tmdb.org/t/p/w500/oyyUcGwLX7LTFS1pQbLrQpyzIyt.jpg', 1993, 0, 0, '2026-06-06 13:25:04.884816', 'US');
INSERT INTO public.movies VALUES (4316, 700979, '친구 엄마들', '["Romance"]', 'Jo Tae-ho', '["Baek Yoon-jae", "Jo Wan-jin", "Yoon Joo-I", "Lee Hyo-won", "Seo Won"]', NULL, 'https://image.tmdb.org/t/p/w500/cG1hXEWGepEqKSRe2HLL33vvPn8.jpg', 2018, 0, 0, '2026-06-08 06:30:11.295906', 'KR');
INSERT INTO public.movies VALUES (4327, 1247002, '파과', '["Action", "Mystery", "Drama"]', 'Min Kyu-dong', '["Lee Hye-young", "Kim Sung-cheol", "Yeon Woo-jin", "Ok Ja-yeon", "Kim Moo-yul"]', '40여 년간 감정 없이 바퀴벌레 같은 인간들을 방역해온 60대 킬러 조각. 대모님이라 불리며 살아있는 전설로 추앙받지만 점차 오랜 시간 몸담은 회사 신성방역에서조차도 한물간 취급을 받는다. 한편, 평생 조각을 쫓은 젊고 혈기 왕성한 킬러 투우는 신성방역의 일원이 되고 조각에게서 시선을 떼지 않는다. 지켜야 할 건 만들지 말자고 약속했던 조각은 여전한 실력에도 불구하고 상처를 입은 그날 밤, 자신을 치료해 준 수의사 강선생과 그의 딸에게 남다른 감정을 느낀다. 투우는 그런 낯선 조각의 모습에 분노가 폭발하는데…', 'https://image.tmdb.org/t/p/w500/du65x58CJrMMThuiT85kBFMYi0Z.jpg', 2025, 0, 0, '2026-06-08 06:30:18.666327', 'KR');
INSERT INTO public.movies VALUES (4330, 760517, '모럴센스', '["Romance", "Comedy"]', 'Park Hyun-jin', '["Seohyun", "Lee Jun-young", "Lee El", "Seo Hyun-woo", "Kim Han-na"]', '할말은 하고 사는 홍보팀 사원 정지우. 부서 이동 후 모든 여직원의 관심을 받고 있는 잘생긴 대리 정지후. 이름만 비슷할 뿐 달라도 너무 다른 두 사람. 잘못 배송된 택배로, 지후의 절대 들키고 싶지 않은 성적 취향을 알게 된 지우는 점점 그에게 관심이 생기는데…', 'https://image.tmdb.org/t/p/w500/pDQOXcUs4hJvLlpkYn5VK0szzZF.jpg', 2022, 0, 0, '2026-06-08 06:30:20.671834', 'KR');
INSERT INTO public.movies VALUES (4328, 387843, '정사: 위험한 성적유희', '["Drama", "Romance"]', 'Lee Min-hwan', '["Kim Si-eon", "Baek In-kwon", "Kim Do-hee"]', '결혼 6년차 가을은 남편과의 불화로 술에 의존하기 시작하면서 알코올중독자가 되고 가을의 이웃집에 살고 있던 현직 작가 희망은 가을 부부의 싸움소리에 잠 못 이루는 날이 계속되자 도저히 견디지 못하고 가을의 집에 찾아가 항의한다. 그렇게 둘 사이의 첫 만남이 시작되고, 그 후 가을은 남편과 싸워 술에 취할 때면 희망의 집에 찾아가 섹스를 한다. 알 수 없는 가을의 태도에 희망은 아리송해지며 점점 더 가을에게 빠져 든다. 그러던 사이 남편과의 관계가 회복되고 있는 가을의 모습을 발견하고는 가을의 집에 무작정 찾아가 삼자대면을 하는데...', 'https://image.tmdb.org/t/p/w500/bXyz4zRt3lFVoJOW4cs2IIxGRIB.jpg', 2014, 0, 0, '2026-06-08 06:30:19.332554', 'KR');
INSERT INTO public.movies VALUES (4329, 549590, '동네사람들', '["Action", "Crime", "Thriller", "Mystery"]', 'Im Jin-soon', '["Don Lee", "Kim Sae-ron", "Jang Kwang", "Lee Sang-yeob", "Shin Se-hwi"]', '여고생이 사라졌지만 너무나 평온한 시골의 한적한 마을, 기간제 교사로 새로 부임 온 외지 출신 체육교사 ‘기철(마동석)’은 동네 분위기가 심상치 않음을 감지한다. 실종된 여고생의 유일한 친구 ''유진(김새론)''만이 친구가 납치된 거라 확신하여 사건을 쫓고, 의도치 않게 ‘유진’과 함께 사라진 소녀를 찾기 위해 나선 ‘기철’은 누군가에 의해 그녀의 흔적들이 사라지고 있다는 사실을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/fL5OHCA7jXhvq4MOJAdVpJJzBF4.jpg', 2018, 0, 0, '2026-06-08 06:30:20.011499', 'KR');
INSERT INTO public.movies VALUES (4331, 473924, '동창회의 목적: 더 비기닝', '["Comedy", "Romance"]', NULL, '["Yoo Ji-won", "Han Yeong-hoon", "Han Seol-hwa", "Han Gyeol"]', '걔랑 걔랑 사귄다고? 나도 걔랑 했는데?  친구끼리 막 해도 되는 건가?  알아도 모른 척, 몰라도 아는 척 했던 수많은 썸들의 전말 공개!  시도 때도 없이 이뤄지는 은밀한 작업들.  오늘은 선배랑, 내일은 후배랑, 모레는 동기랑.  우리들의 끈적끈적한 동창회의 목적이 밝혀진다.', 'https://image.tmdb.org/t/p/w500/pStoby0ssYiKRizkPJUaA8FGz3U.jpg', 2017, 0, 0, '2026-06-08 06:30:21.338696', 'KR');
INSERT INTO public.movies VALUES (4503, 1440040, '裸天使 宮下玲奈', '["Drama"]', NULL, '["Rena Miyashita"]', NULL, 'https://image.tmdb.org/t/p/w500/tcBKCHvbIfHkgDld8g4UdfZVO4C.jpg', 2025, 0, 0, '2026-06-08 06:32:31.642091', 'JP');
INSERT INTO public.movies VALUES (4325, 489150, '어린 형수 3', '["Romance"]', 'Choi Woo-seong', '["Kim In-ae", "Se Ah", "Shin Joon-hyun"]', '무역회사를 다니고 있는 용철은 여자 친구인 선경과 사내연애 금지 조항 때문에 비밀 연애를 하는 커플이다. 어느 날 동네 선배인 형구한테 연락이 오고 선배는 어린 부인 수영의 취업을 용철에게 부탁한다. 며칠 후 수영은 회사로 출근을 하게 되고 용철은 이런 수영을 친절하게 대한다. 그날 저녁 회식 후 술에 취한 수영을 부축하다 키스를 하게 되고, 그 후 용철과 수영은 서로 끌려 넘지 말아야 할선을 넘게 되는데...', 'https://image.tmdb.org/t/p/w500/a8qjKGH7peFrUlewKBSwymurkNs.jpg', 2017, 0, 0, '2026-06-08 06:30:17.336037', 'KR');
INSERT INTO public.movies VALUES (4339, 629792, '첫경험 2', '["Drama"]', 'Kim Tae-soo', '["Kim Ji-ah", "Yoo Jung", "Min Do-yoon"]', '곧 군대를 갈 예정인 충헌은 우울한 마음을 달래기 위해 건우와 술을 마신다.  집으로 돌아가는 길에 술에 취해 자고 있는 정인을 발견하고 자신에 자취방으로 데려간다.  다음 날, 잠에서 일어나 정인은 충헌에게 고맙다며 밥을 사고 어제 있었던 일을 이야기 해준다.  정인은 아직 남자 경험이 없는 자신을 놀리는 후배의 말들 듣고 화가 나서 술을 마시고 정신을 잃었고,  그런 자신을 집에 데려와 아무 일 없이 지켜준 충헌에게 호감을 느끼고 충헌에게 첫 남자가 되어 달라고 제안을 하게 되는데…', 'https://image.tmdb.org/t/p/w500/jaI8vVyyVfXiXFGchO0OTWCfQ7G.jpg', 2019, 0, 0, '2026-06-08 06:30:27.492742', 'KR');
INSERT INTO public.movies VALUES (4341, 471831, '일대일', '["Romance"]', 'Jeong Mi-na', '["Seo Han", "Yoon Se-na", "Sang Woo", "Baek Se-ri", "Ahn So-hee"]', '그녀는 어떤 기구를 좋아할까?  체대 졸업 후 백수생활을 하던 주인공 도영은 우연히 피트니스센터 트레이너로 취직하게 된다.  도영은 이웃주민인 미모의 유명 스포츠 캐스터 세희를 피트니스센터에서 만나게 되고,  그녀의 관심을 얻기 위해 노력하지만 매번 퇴짜만 당한다.  한편, 일대일 퍼스널트레이닝을 은밀하게 진행 중인 피트니스센터에서  세희가 이용당할 음모를 계획하고 있다는 사실을 알게 된 도영은 세희를 구하러 나서는데…  과연 피트니스센터에서 일어나는 은밀한 일대일 퍼스널트레이닝과 그 속에 숨겨진 음모는 무엇일까?', 'https://image.tmdb.org/t/p/w500/xQ7A6bubHPxKSOJjiZdx0z33fKH.jpg', 2017, 0, 0, '2026-06-08 06:30:28.876711', 'KR');
INSERT INTO public.movies VALUES (4342, 86000, '오직 그대만', '["Romance", "Drama"]', 'Song Il-gon', '["So Ji-sub", "Han Hyo-joo", "Kang Shin-il", "Park Cheol-min", "Oh Kwang-rok"]', '잘나가던 복서였지만 어두운 상처 때문에 마음을 굳게 닫아버린 철민.  시력을 잃어가고 있지만, 늘 밝고 씩씩한 정화.  좁은 주차박스에서 외로운 시간을 보내고 있던 철민에게 꽃 같은 그녀, 정화가 나타났다.  나보다 나를 더 사랑해주는 사람. 두 눈을 감으면 선명해지는 그 얼굴, 오직 그대만…', 'https://image.tmdb.org/t/p/w500/zqw49pO0FndPZL5LVkq85JCNIVH.jpg', 2011, 0, 0, '2026-06-08 06:30:29.550888', 'KR');
INSERT INTO public.movies VALUES (4343, 1466120, '데드 어게인', '["Thriller", "Romance", "Mystery"]', 'Son Hyeon-woo', '["Kim Tae-jin", "Seo Rina", "Yoo Mi", "Danny Lee", "손동제"]', '커플 동반 베트남 여행을 온 민혁과 해지, 선웅과 미미는 한껏 들뜬다. 민혁 역시 아내인 해지와는 물론, 오랜 내연 관계였던 미미와도 짜릿한 밀회를 즐기며 만족스러운 시간을 보낸다.하지만 갑자기 격렬한 고통을 느끼며 숨이 멎어가는 민혁. 이대로 죽는가 싶어 눈을 뜨니 베트남에 도착한 첫날이다. 모든 것이 혼란스러운 민혁은 죽음으로 끝나는 휴가에 이유가 있음을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/iqSmb9ugb8xK6avZ3Wglxue39N8.jpg', 2025, 0, 0, '2026-06-08 06:30:30.228339', 'KR');
INSERT INTO public.movies VALUES (4344, 498888, '엄마 애인', '["Drama", "Romance"]', 'Jeong Jin-ho', '["Lee Hyun-ji-II", "Min Do-yoon", "Jin Si-ah"]', '디자이너인 엄마와 함께 살고 있는 여대생 민희는 두 가지 비밀을 간직하고 있다.  한 가지는 정기적으로 만나는 나이 많은 섹스 파트너가 있는 것이다. 민희는 그 남자를 만남으로서 아빠의 빈자리를 대신 채우고 있다.  또 하나의 비밀은 최근 엄마에게 소개한 엄마의 개인트레이너 철민에게 자꾸 끌리는 것이다.  어느 날 약속이 취소되어 집으로 온 민희는 엄마와 철민의 섹스 장면을 몰래 훔쳐보게 되는데...', 'https://image.tmdb.org/t/p/w500/2F3zdl8w7RWA23ZAa6nlDYoi98e.jpg', 2018, 0, 0, '2026-06-08 06:30:30.89928', 'KR');
INSERT INTO public.movies VALUES (4345, 482617, '내 여자의 엄마', '["Romance", "Drama"]', 'Kyeong Seok-ho', '["Do Mo-se", "Seo Bo-ra", "Min Joo"]', '딸은 절대 몰라야 하는 두 사람의 은밀한 관계!  영오는 귀여운 여자친구 보건의 집에 놀러가 그녀와 정사를 즐기다가, 우연히 방에 들어온 그녀의 엄마 서영과 눈이 마주친다. 영오는 창피함보다 먼저 짜릿한 쾌감을 느끼고 그 순간부터 서영을 여자로 느끼게 된다. 보건이 모르는 사이 영오와 서영의 관계는 점점 더 깊어져만 간다.', 'https://image.tmdb.org/t/p/w500/aaGXMwzprvYwiP1U8mzELXPfIzW.jpg', 2016, 0, 0, '2026-06-08 06:30:31.568397', 'KR');
INSERT INTO public.movies VALUES (4663, 1100848, '변태정력왕: 투명인간의 탄생', '[]', 'Wataru Oku', '["Arina Arata"]', '평범한 삶을 살아가는 도쿄남 토시오는 어느날 자신의 집안이 닌자의 가문이고 옛부터 전해지는 비전의 약이 계승되고 있는 사실을 알게되고 그의 조상으로부터 그 비전의 약을 얻게 된다. 비전의 약은 복용하면 일정시간동안 세상 모든 여자의 마음과 몸을 훔칠 수 있는 능력을 얻기 된다. 하지만 어느날 비전의 약을 과다복용하게 된 토시오는 그 부작용으로 투명인간이 된다. 과연 앞으로 펼쳐질 음란하고 발칙한 그 이야기는..', 'https://image.tmdb.org/t/p/w500/sJeGwM1P9EubWe20BjL67kTI9Xg.jpg', 2016, 0, 0, '2026-06-08 06:34:44.091078', 'JP');
INSERT INTO public.movies VALUES (4338, 451997, '불한당: 나쁜 놈들의 세상', '["Action", "Crime", "Mystery"]', 'Byun Sung-hyun', '["Sul Kyung-gu", "Yim Si-wan", "Kim Hie-won", "Jeon Hye-jin", "Lee Kyung-young"]', '범죄조직의 1인자를 노리는 재호와 세상 무서운 것 없는 패기 넘치는 신참 현수는 교도소에서 만나 서로에게 끌리고 끈끈한 의리를 다져간다. 출소 후, 함께 권력을 차지하기 위해 의기투합하던 중, 두 사람의 숨겨왔던 야망이 조금씩 드러나고, 서로에 대해 새로운 사실을 알게 되면서 그들의 관계는 흔들리기 시작하는데…', 'https://image.tmdb.org/t/p/w500/bW9tePApxcM2QmvOgeEfQippM2I.jpg', 2017, 0, 0, '2026-06-08 06:30:26.815235', 'KR');
INSERT INTO public.movies VALUES (4340, 571625, '클로젯', '["Horror", "Thriller"]', 'Kim Kwang-bin', '["Ha Jung-woo", "Kim Nam-gil", "Heo Yool", "Kim Si-a", "Shin Hyun-been"]', '아내가 불의의 사고로 세상을 떠난 뒤, 아버지 연상원과 딸 연이나는 관계가 서먹서먹해진다. 어색한 관계를 유지하던 딸과 아버지가 새로운 출발을 하기 위해 원래 살던 도심을 떠나 한적한 곳에 있는 집으로 이사간다. 그곳에서 딸이 흔적도 없이 사라지고, 딸의 실종과 관련한 비밀을 알고 있는 퇴마사가 아버지를 찾아오면서 미스터리한 일들이 벌어진다.', 'https://image.tmdb.org/t/p/w500/dgrFMKqHfH5xQbpEyxpeea4nXys.jpg', 2020, 0, 0, '2026-06-08 06:30:28.169245', 'KR');
INSERT INTO public.movies VALUES (4348, 570503, '유열의 음악앨범', '["Romance", "Drama"]', 'Jung Ji-woo', '["Kim Go-eun", "Jung Hae-in", "Park Hae-joon", "Kim Guk-hee", "Jung Yoo-jin"]', '1994년 가수 유열이 라디오 DJ를 처음 진행하던 날, 엄마가 남겨준 빵집에서 일하던 미수는 우연히 찾아 온 현우를 만나 설레는 감정을 느끼게 되지만 뜻하지 않은 사건으로 인해 연락이 끊기게 된다. 다시 기적처럼 마주친 두 사람은 설렘과 애틋함 사이에서 마음을 키워 가지만 서로의 상황과 시간은 자꾸 어긋나기만 한다. 계속되는 엇갈림 속에서도 라디오 ‘유열의 음악앨범’과 함께 우연과 필연을 반복하는 두 사람… 함께 듣던 라디오처럼 그들은 서로의 주파수를 맞출 수 있을까?', 'https://image.tmdb.org/t/p/w500/rt8yDvXSnk9CMDJeNYh9lv6kPMt.jpg', 2019, 0, 0, '2026-06-08 06:30:33.572089', 'KR');
INSERT INTO public.movies VALUES (4349, 537190, '창궐', '["Action", "Horror", "Drama", "Fantasy"]', 'Kim Sung-hoon', '["Hyun Bin", "Jang Dong-gun", "Jo Woo-jin", "Jeong Man-sik", "Lee Sun-bin"]', '밤에만 활동하는 산 자도 죽은 자도 아닌 야귀가 창궐한 세상, 위기의 조선으로 돌아온 왕자 이청은 도처에 창궐한 야귀떼에 맞서 싸우는 최고의 무관 박종사관 일행을 만나게 되고, 야귀떼를 소탕하는 그들과 의도치 않게 함께하게 된다. 한편, 조선을 집어삼키려는 절대악 김자준은 이 세상을 뒤엎기 위한 마지막 계획을 감행하는데…', 'https://image.tmdb.org/t/p/w500/A8QCte7PN05efdQN8GUaKJfHqtT.jpg', 2018, 0, 0, '2026-06-08 06:30:34.239364', 'KR');
INSERT INTO public.movies VALUES (4234, 124157, '도둑들', '["Action", "Crime"]', 'Choi Dong-hoon', '["Kim Yun-seok", "Kim Hye-soo", "Lee Jung-jae", "Gianna Jun", "Simon Yam"]', '한 팀으로 활동 중인 한국의 도둑 뽀빠이와 예니콜, 씹던껌, 잠파노. 미술관을 터는데 멋지게 성공한 이들은 뽀빠이의 과거 파트너였던 마카오박이 제안한 홍콩에서의 새로운 계획을 듣게 된다. 여기에 마카오박이 초대하지 않은 손님, 감옥에서 막 출소한 금고털이 팹시가 합류하고 5명은 각자 인생 최고의 반전을 꿈꾸며 홍콩으로 향한다.  홍콩에서 한국 도둑들을 기다리고 있는 4인조 중국도둑 첸, 앤드류, 쥴리, 조니. 최고의 전문가들이 세팅된 가운데 서로에 대한 경계를 늦추지 않는 한국과 중국의 도둑들. 팽팽히 흐르는 긴장감 속에 나타난 마카오박은 자신이 계획한 목표물을 밝힌다. 그것은 마카오 카지노에 숨겨진 희대의 다이아몬드. 성공을 장담할 수 없는 위험천만한 계획이지만 2천만 달러의 달콤한 제안을 거부할 수 없는 이들은 태양의 눈물을 훔치기 위한 작업에 착수한다. 그러나 진짜 의도를 알 수 없는 비밀스런 마카오박과 그런 마카오박의 뒤통수를 노리는 뽀빠이, 마카오박에게 배신당한 과거의 기억을 잊지 못하는 팹시와 팀보다 눈 앞의 현찰을 먼저 챙기는 예니콜, 그리고 한국 도둑들을 믿지 않는 첸과 중국 도둑들까지. 훔치기 위해 모였지만 목적은 서로 다른 10인의 도둑들은 서서히 자신만의 플랜을 세우기 시작하는데…', 'https://image.tmdb.org/t/p/w500/ujIHEzt2EEboVzjQoWZBMYdAt1v.jpg', 2012, 0, 0, '2026-06-08 06:28:49.513295', 'KR');
INSERT INTO public.movies VALUES (4235, 581387, '백두산', '["Action", "Adventure", "Thriller"]', 'Kim Byung-seo', '["Lee Byung-hun", "Ha Jung-woo", "Don Lee", "Jeon Hye-jin", "Suzy"]', '대한민국 관측 역사상 최대 규모의 백두산 폭발 발생. 갑작스러운 재난에 한반도는 순식간에 아비규환이 되고, 남과 북 모두를 집어삼킬 추가 폭발이 예측된다. 사상 초유의 재난을 막기 위해 전유경은 백두산 폭발을 연구해 온 지질학 교수 강봉래의 이론에 따른 작전을 계획하고, 전역을 앞둔 특전사 EOD 대위 조인창이 남과 북의 운명이 걸린 비밀 작전에 투입된다. 작전의 키를 쥔 북한 무력부 소속 일급 자원 리준평과 접선에 성공한 인창. 하지만 준평은 속을 알 수 없는 행동으로 인창을 곤란하게 만든다. 한편, 인창이 북한에서 펼쳐지는 작전에 투입된 사실도 모른 채 서울에 홀로 남은 최지영은 재난에 맞서 살아남기 위해 고군분투하고 그 사이, 백두산 마지막 폭발까지의 시간은 점점 가까워 가는데…', 'https://image.tmdb.org/t/p/w500/1n5q3XpEhCe7TnGHzsHs5pwVT8O.jpg', 2019, 0, 0, '2026-06-08 06:28:50.260677', 'KR');
INSERT INTO public.movies VALUES (4244, 723562, '여배우들: 섹스 오디션', '["Drama"]', 'Jeong Mi-na', '["Lee Chae-dam", "Lee Soo", "Jo Wan-jin", "Han Seok-bong", "Tae Hee"]', '삼류 영화감독, 천봉은 새로 구한 조감독 미영과 함께 대부도로 헌팅을 간다.  하지만 헌팅은 구실일 뿐, 천봉의 관심은 젯밥에 더 있다. 업계 물정 모르는 미영을 현혹해 자신의 욕심을 채우려는 천봉.  천봉의 아내 은우도 아들의 축구교실 코치, 성규와 함께 대부도로 일탈의 여행을 떠난다. 대부도는 천봉과 은우 부부가 연애시절 즐겨 찾던 추억의 장소. 공교롭게도 이웃한 펜션에서 하룻밤의 만남을 즐기는 부부. 서로의 존재를 모른 채 같은 공간에서 서로의 육체를 불태우는데.......  에로스와 타나토스 사이를 오가며 아슬아슬 줄타기 하는 이 시대 부부의 삶. 그 균열의 공간 속을 은밀하게 파고든다.', 'https://image.tmdb.org/t/p/w500/hw0o7e3brKh9nygSqiEm2tfqjFq.jpg', 2020, 0, 0, '2026-06-08 06:29:16.642365', 'KR');
INSERT INTO public.movies VALUES (4352, 684501, '관전남', '["Drama", "Romance"]', 'Choi Woo-seong', '["Kim Min-jeong", "Yoo Jung", "Han Seok-bong", "Hun-i"]', '두 커플의 성행각을 그린 성애 영화', 'https://image.tmdb.org/t/p/w500/9BvrsCMgBtfd8kL7m3inaw3mfnX.jpg', 2019, 0, 0, '2026-06-08 06:30:36.99949', 'KR');
INSERT INTO public.movies VALUES (4356, 18377, '미녀는 괴로워', '["Drama", "Comedy", "Romance"]', 'Kim Yong-hwa', '["Ju Jin-mo", "Kim A-joong", "Sung Dong-il", "Kim Hyun-sook", "Im Hyun-sik"]', 'K-1이나 씨름판에 나가도 거뜬할 체격을 가졌지만 한 남자에게 사랑받고 싶은 여린 마음의 소유자 한나. 그녀에게 허락된 유일한 신의 선물은 천상의 목소리. 하지만 이마저도 섹시 미녀가수 ''아미''의 목소리를 대신해주는 신세다. ''아미''의 음반 프로듀서이자 자신의 음악성을 인정해준 유일한 사람 한상준을 남몰래 사랑하게 된 그녀는 드디어 꿈에 그리던 그의 생일파티에 초대받고 들뜬 마음으로 한껏 멋을 부리고 나타나는데...', 'https://image.tmdb.org/t/p/w500/hXadaSx1LpT7Hv5dkGWD0SX7z7R.jpg', 2006, 0, 0, '2026-06-08 06:30:39.87972', 'KR');
INSERT INTO public.movies VALUES (4358, 452073, '어린 형수 2', '["Romance"]', 'Kim Tae-soo', '["Han Ga-hee", "Lee Eun-mi", "Lee Do-Yoon", "Choi Min-ho"]', NULL, 'https://image.tmdb.org/t/p/w500/xWrAoVbcfrAAUivXh19DrmGqmVz.jpg', 2017, 0, 0, '2026-06-08 06:30:41.375813', 'KR');
INSERT INTO public.movies VALUES (4254, 736732, '브로커', '["Drama"]', 'Hirokazu Kore-eda', '["Song Kang-ho", "Gang Dong-won", "Bae Doona", "IU", "Lee Joo-young"]', '세탁소를 운영하지만 늘 빚에 시달리는 상현과 베이비 박스 시설에서 일하는 보육원 출신의 동수. 거센 비가 내리는 어느 날 밤, 그들은 베이비 박스에 놓인 한 아기를 몰래 데려간다. 하지만 이튿날, 생각지 못하게 엄마 소영이 아기 우성을 찾으러 돌아온다. 아기가 사라진 것을 안 소영이 경찰에 신고하려 하자 솔직하게 털어놓는 두 사람. 우성이를 잘 키울 적임자를 찾아 주기 위해서 그랬다는 변명이 기가 막히지만 소영은 우성이의 새 부모를 찾는 여정에 상현, 동수와 함께하기로 한다. 한편 이 모든 과정을 지켜본 형사 수진과 후배 이형사. 반 년째 이어온 수사를 마무리할 수 있는 결정적 증거를 포착하기 위해 이들의 뒤를 조용히 쫓는다.', 'https://image.tmdb.org/t/p/w500/8pAoMLsA1h3z2uXvt353P5aScPO.jpg', 2022, 0, 0, '2026-06-08 06:29:25.011077', 'KR');
INSERT INTO public.movies VALUES (4270, 729854, '콘크리트 유토피아', '["Thriller", "Action"]', 'Um Tae-hwa', '["Lee Byung-hun", "Park Seo-jun", "Park Bo-young", "Kim Sun-young", "Kim Do-yoon"]', '온 세상을 집어삼킨 대지진, 그리고 하루아침에 폐허가 된 서울. 모든 것이 무너졌지만 오직 황궁 아파트만은 그대로다. 소문을 들은 외부 생존자들이 황궁 아파트로 몰려들자 위협을 느끼기 시작하는 입주민들. 생존을 위해 하나가 된 그들은 새로운 주민 대표 ''영탁''을 중심으로 외부인의 출입을 철저히 막아선 채 아파트 주민만을 위한 새로운 규칙을 만든다. 덕분에 지옥 같은 바깥 세상과 달리 주민들에겐 더 없이 안전하고 평화로운 유토피아 황궁 아파트. 하지만 끝이 없는 생존의 위기 속 그들 사이에서도 예상치 못한 갈등이 시작되는데...! 살아남은 자들의 생존 규칙. 따르거나, 떠나거나.', 'https://image.tmdb.org/t/p/w500/aKApVX9hc5otPxa3Jbf27sW6tsi.jpg', 2023, 0, 0, '2026-06-08 06:29:37.184249', 'KR');
INSERT INTO public.movies VALUES (4360, 547507, '딥', '["Thriller", "Romance"]', 'Cho Sung-kyu', '["Choi Yeo-jin", "Ryu Seung-su", "Heo Dong-won", "Ahn Ji-hye", "Kwak Jin-seok"]', '시나리오 작업을 위해 프리다이버들의 천국 필리핀 보홀로 향한 ''희진''과 ''승수''. 그곳에서 강사로 일하는 ''시언''을 만난다. 보홀에 온 후부터 어딘가 수상한 ''희진''의 태도에 의구심을 가진 ''승수''. ''승수''는 작업을 위해 인터뷰를 하던 중 ''시언’과 ''희진'' 사이에 충격적인 비밀을 알게 된다. ''희진'' 역시 점점 자신의 본색을 드러내는데....', 'https://image.tmdb.org/t/p/w500/mU31qqjlSFKqDTKZd7KJwWlrahI.jpg', 2018, 0, 0, '2026-06-08 06:30:42.877183', 'KR');
INSERT INTO public.movies VALUES (4361, 685833, '목공소에서 생긴 일', '["Romance"]', 'No Hyun-jin', '["Tae Joo", "Ahn So-hee", "Min Do-yoon", "Gil Dong", "Hae Il"]', '동네에 소문이 쫙 퍼질 정도로 예쁘고, SNS 스타이기도 한 여자 목수 연주를 호시탐탐 흠모하며 짝사랑 해 오던 도식.  이번에는 어떻게든 결판을 내려 주말 데이트를 신청한다. 그런 도식에게는 눈길도 안주는 연주를 맘껏 주무르고 있던 아주 제대로 상남자가 등장한다. 한편, 세상물정 모르고 순진하면서 고지식한 목공소의 경리 태주는 누구도 생각지 못한 엄청난 비밀 두 가지를 간직하며 생활하고 있다. 드디어, 연주와 태주의 어마어마한 비밀이 밝혀지며 반전에 반전을 거듭하게 된다. ​', 'https://image.tmdb.org/t/p/w500/bMhxD4DKRJM1dydluvsS5aL2Tci.jpg', 2020, 0, 0, '2026-06-08 06:30:43.638357', 'KR');
INSERT INTO public.movies VALUES (4247, 265851, '우는 남자', '["Action", "Thriller", "Drama"]', 'Lee Jeong-beom', '["Jang Dong-gun", "Kim Min-hee", "Brian Tee", "Kim Min-jae", "Jun Kim"]', '낯선 미국 땅에 홀로 남겨져 냉혈한 킬러로 살아온 곤.  조직의 명령으로 타겟을 제거하던 중 예상치 못한 실수를 저지르고, 그는 자신의 삶에 깊은 회의를 느낀다. 그런 그에게 조직은 또 다른 명령을 내리고, 곤은 마지막 임무가 될 타겟을 찾아 자신을 버린 엄마의 나라, 한국을 찾는다. 남편과 딸을 잃고, 치매에 걸린 엄마를 돌보며 하루하루 절망 속에서 살아가고 있는 여자, 모경. 엄청난 사건에 연루된 것도 모른 채 일만 파고들며 술과 약이 없으면 잠을 이루지 못하던 그녀 앞에 딸의 죽음 뒤에 감춰진 진실을 알려주겠다는 한 남자가 다가온다.  잃을 것이 없는 남자와 남은 게 없는 여자, 그들이 절벽의 끝에서 만났다', 'https://image.tmdb.org/t/p/w500/qWPNb1qYmaL5eExuNzOyKkn5aR.jpg', 2014, 0, 0, '2026-06-08 06:29:18.898495', 'KR');
INSERT INTO public.movies VALUES (4366, 302945, '정사', '["Drama", "Romance"]', 'Kim Jung-hwan', '["Han Se-Ah", "Jeon Ju-ho", "Jung Wook", "Ryu Sung-hyun", "손인아"]', '"남편한테 들켰다며? 당신 괜찮아?"  "다 필요 없어. 그냥 하루종일 이것만 하고 싶어!"  퇴직 이후 서점을 운영하며 살던 성민의 무료한 일상에 아름다운 얼굴, 매혹적 몸매를 가진 가희가 나타난다.  발레 학원을 운영하는 가희 또한 남편과의 관계가 석연치 않던 차, 가희와 성민은 지독하게 서로에게 빠져든다.  함께 하면 안 된다는 것을 알기에 더욱 뜨겁게 타오르는 두 사람. 이제 그 지독한 사랑이 파멸을 향해 달려가기 시작한다.', 'https://image.tmdb.org/t/p/w500/5nGRaQV5MoVs2AGUP3qyf3BXuuz.jpg', 2014, 0, 0, '2026-06-08 06:30:47.414573', 'KR');
INSERT INTO public.movies VALUES (4367, 1268663, '신도시 엄마들', '["Romance"]', 'Jeong Do-soo', '["Jin Seo-yool", "Shine", "White Sugar", "Min Do-yoon", "Woo Yeol"]', NULL, 'https://image.tmdb.org/t/p/w500/qOf14UlxWSQajrbyge9EmP1G26o.jpg', 2024, 0, 0, '2026-06-08 06:30:48.162906', 'KR');
INSERT INTO public.movies VALUES (4369, 51393, '백야행: 하얀 어둠 속을 걷다', '["Mystery", "Romance", "Thriller"]', 'Park Shin-woo', '["Son Ye-jin", "Han Suk-kyu", "Go Soo", "Lee Min-jung", "Park Sung-woong"]', '출소한 지 얼마 안된 한 남자가 잔인하게 살해당한다. 이 사건이 14년 전 발생한 한 살인사건과 연관되어 있음을 안 수사팀은 담당형사였던 동수(한석규 분)를 찾아가고, 그는 본능적으로 당시 피해자의 아들이었던 요한(고수 분)이 연루되어 있음을 직감한다. 한편, 재벌총수 승조의 비서실장 시영(이민정 분)은 승조를 위해 그의 약혼녀 미호(손예진 분)의 뒤를 쫓는다. 모든 면에서 완벽한 미호. 하지만 비현실적일 만큼 완벽했던 미호에게 석연치 않은 과거의 흔적이 발견되면서, 그녀 곁에 그림자처럼 맴돌고 있는 존재를 발견하게 된다.  서로 다른 대상을 쫓다 한 자리에서 만나게 된 시영과 동수. 그들은 요한과 미호의 과거에 관한 충격적인 사실을 알게 된다. 14년 전 발생했던 사건의 살인용의자가 미호의 엄마, 피살자가 요한의 아빠였으며, 새로운 삶을 살고 있는 미호와 달리 요한은 여전히 어둠 속에 갇혀 살고 있다는 것이다. 마치 빛과 그림자처럼…… 14년 전, 그리고 현재까지 계속되는 미스터리한 살인사건들. 과연, 진실은 무엇일까?', 'https://image.tmdb.org/t/p/w500/7yWOK6oXiuGBBSCyh4gkgpnNOYc.jpg', 2009, 0, 0, '2026-06-08 06:30:49.633181', 'KR');
INSERT INTO public.movies VALUES (4281, 486589, '레드슈즈', '["Animation", "Fantasy", "Family", "Comedy", "Romance", "Adventure"]', 'Hong Sung-ho', '["Ahn So-yi", "Shin Yong-woo", "Jun Jin-ah", "Jeong Jae-heon", "Choi Han"]', '사건 사고가 끊이지 않는 동화의 섬. 사라진 아빠를 찾던 화이트 왕국의 공주는 우연히 마법구두를 신고 이전과 완벽하게 다른 ‘레드슈즈’로 거듭난다. 한편, 초록색 난쟁이가 된 일곱 왕자들은 우연히 자신들의 집에 머물게 된 ''레드슈즈’가 저주를 풀 유일한 희망이라 생각해 그녀를 돕기 시작하고, 영원한 아름다움을 꿈꾸는 왕비 ‘레지나’는 마법구두를 신고 성을 빠져나간 ‘레드슈즈’를 쫓기 시작하는데…', 'https://image.tmdb.org/t/p/w500/3yZ54uGQ4HxEbpNVO565mU1xagp.jpg', 2019, 0, 0, '2026-06-08 06:29:45.448446', 'KR');
INSERT INTO public.movies VALUES (4277, 482207, '챌린지 게임', '["Thriller", "Romance"]', 'Won Seok-ho', '["Kang Eun-hye", "Choi Ryung", "Choi Hyun-ho", "La Risa", "Baek Se-ri"]', '"우리 지금... 할래요?"  치명적 게임의 유혹 ''챌린지 게임''  플로리스트인 ‘애란’(비키)과 경찰청 감식반 형사인 ‘민호’(최령)는 남들이 부러워하는 가정을 이루고 있다. 하지만 ‘민호’는 정상적인 부부관계를 가지지 못하고 급기야 ‘애란’이 다른 남자를 유혹해 관계를 가지는 일종의 유혹게임 ''챌린지 게임''을 시작한다. 그러던 ‘애란’과 ‘민호’는 탱고카페에서 ‘알렉스’(최현호)를 만난다. ‘알렉스’는 ‘애란’에게 관심을 가지고 접근하고, 남편인 ‘민호’와 달리 뛰어난 외모에 자신감 넘치는 ‘알렉스’에게 호감을 가진 ‘애란’은 그를 챌린지 게임에 끌어들인다. 이후 ‘민호’는 우연히 두 사람의 뜨거운 관계를 목격하고 ‘애란’이 유혹한 남자가 ‘알렉스’임을 알고 분노한다. 이후 ‘민호’는 ‘알렉스’가 단순히 게임 파트너가 아니라 의도적으로 자신들에게 접근한 사실을 알게되고 불안해한다. ‘민호’는 ‘알렉스’를 떨쳐내려 하지만 승부욕이 넘치는 소시오패스 성향의 ‘알렉스’는 오히려 ‘민호’와 ‘애란’을 더욱 옥죄이며 카타르시스를 느낀다. 스스로가 즐기기 위해 만든 챌린지 게임이지만 이들이 시작한 게임은 점차 파국으로 치닫게 되는데...', 'https://image.tmdb.org/t/p/w500/1JFfsGsImc4qXeMdTqXypjs0sPL.jpg', 2016, 0, 0, '2026-06-08 06:29:42.756341', 'KR');
INSERT INTO public.movies VALUES (4304, 481840, '자매의 S스캔들', '["Drama", "Romance"]', 'Kim Hyeon-Bin', '["Shin Yu-ju", "Yoon Se-na", "Kim Joo-hyeop", "Kim Ji-hoon-VIII", "Sin Seong-hoon"]', '거칠고 남자 같은 성격의 유진과 여성스럽고 귀여운 외모를 가진 유정.INSERT INTO public.movies VALUES (4374, 854684, '21살 승하의 아이돌 비밀일기', '["Documentary"]', NULL, '["Seung Ha", "Min Do-yoon", "Kang Min-woo", "Chul Jin"]', '가수에서 배우를 선택하게 된 계기 및 이유 등 어디에서도 밝힌 적이 없는 그녀의 솔직하고 대범한 인터뷰 영화가 찾아온다!  2020년 성인 영화계의 가장 핫 한 배우 채승하! 걸그룹 바바 걸스로 활동하며 사랑을 받던 그녀가 전격적으로 성인 배우로 데뷔한지 몇 개월 만에 40편이 넘는 아주 많은 작품을 촬영했다.  현재도 팬들의 엄청난 지지와 사랑으로 현재도 많은 작품에서 러브콜을 받고 있다. 다른 배우와는 차별화된 그녀만의 끼와 섹시함으로 앞으로가 더욱 기대되고 가장 핫 한 신인배우이다.  그녀의 데뷔 과정부터 촬영 현장에서의 솔직한 모습들과 함께 그녀의 은밀한 이야기가 하나씩 공개된다!', 'https://image.tmdb.org/t/p/w500/fnG8xdPzv6l9OPXKXGMgGfA70KY.jpg', 2021, 0, 0, '2026-06-08 06:30:54.186886', 'KR');
INSERT INTO public.movies VALUES (4375, 1021582, '심야카페: 미씽 허니', '["Fantasy"]', 'Chong Yun-su', '["Chae Seo-jin", "Lee Yi-kyung", "Shin Ju-hwan", "Jeong Young-ju", "Moon Sook"]', '부산 산복지구대의 냉미녀 경찰, 윤. 파스타집 오너 셰프 다정한 연인, 태영.  누구 봐도 행복한 커플 윤과 태영은 결혼을 앞두고 있다.  누구보다 행복해야 할 결혼식 당일. 태영이 아무 연락도 없이 나타나지 않는 대참사를 겪게 된다.  갑자기 사라진 연인 태영의 행방이 묘연한 가운데 윤은 태영이 사라진 마지막 장소에서 수상한 지도를 발견한다. 지도를 따라간 윤은 평소에는 전혀 보지 못했던 카페를 발견하게 되는데…  마스터부터 손님까지 모두 수상하기만 한 ‘심야카페’에서 윤은 드디어 사라진 연인 태영을 만나게 된다. 하지만 태영은 자신을 알아보지 못하고 어딘지 어려보이기까지 하는데…  “저기.. 혹시 지금이 몇 년도인가요?”', 'https://image.tmdb.org/t/p/w500/xG8r9CdFLKMb9A5gn0YXfQ2AVBD.jpg', 2022, 0, 0, '2026-06-08 06:30:54.934266', 'KR');
INSERT INTO public.movies VALUES (4310, 382220, '마스터', '["Crime", "Action"]', 'Cho Ui-seok', '["Lee Byung-hun", "Gang Dong-won", "Kim Woo-bin", "Uhm Ji-won", "Oh Dal-su"]', '화려한 언변, 사람을 현혹하는 재능, 정관계를 넘나드는 인맥으로 수만 명 회원들에게 사기를 치며 승승장구해 온 원네트워크 진회장. 반년간 그를 추적해 온 지능범죄수사팀장 김재명은 진회장의 최측근인 박장군을 압박한다. 원네트워크 전산실 위치와 진회장의 로비 장부를 넘기라는 것. 뛰어난 프로그래밍 실력과 명석한 두뇌로 원네트워크를 키워 온 브레인 박장군은 계획에 차질이 생긴 것을 감지하자 빠르게 머리를 굴리기 시작한다. 진회장은 물론 그의 뒤에 숨은 권력까지 모조리 잡기 위해 포위망을 좁혀가는 재명,  오히려 이 기회를 틈타 돈도 챙기고 경찰의 압박에서도 벗어날 계획을 세우는 장군. 하지만 진회장은 간부 중에 배신자가 있음을 눈치채고, 새로운 플랜을 가동하는데…', 'https://image.tmdb.org/t/p/w500/ebJHlPpLKi4giADhtLhYoV3hV6Q.jpg', 2016, 0, 0, '2026-06-08 06:30:06.561051', 'KR');
INSERT INTO public.movies VALUES (4376, 546768, '메기', '["Drama", "Comedy"]', 'Yi Ok-seop', '["Lee Joo-young", "Koo Kyo-hwan", "Moon So-ri", "Chun Woo-hee", "Park Kyung-hye"]', '성관계를 하는 엑스레이 사진이 발견되면서 병원은 발칵 뒤집힌다. 간호사 여윤영은 사진의 주인공이 자신과 남자친구일지 모른다고 생각한다. 병원을 그만둬야 할 수도 있다고 생각하고 출근을 하는데 막상 병원에선 더 심각한 일들이 벌어진다.', 'https://image.tmdb.org/t/p/w500/z7dGO98VGECQiYzR1cD9PHaQWJS.jpg', 2019, 0, 0, '2026-06-08 06:30:55.747442', 'KR');
INSERT INTO public.movies VALUES (4377, 504891, '밀애: 친구엄마', '["Romance"]', 'Kim Bu-gon', '["Jin Si-ah", "Lee Jae-seok", "Jung Yoo-ah", "Im Dong-min", "Im Se-ho"]', '철부지 대학생 현수는 바닥을 친 성적을 되살리기 위해 도서관 근처에 사는 친구의 집에 시험기간 동안만 얹혀 살기로 한다. 그런데 이게 웬 걸? 전공서적보다 더 궁금해지는 섹시한 친구 엄마 애리와 마주친다. 애리는 아들 몰래 유혹의 손길을 뻗고 현수는 결국 무너지고 만다. 그렇게 두 사람은 짜릿한 육체의 욕망에 중독되기 시작하는데…', 'https://image.tmdb.org/t/p/w500/iTari5xjCHcQULu7gF2WV7eIbAL.jpg', 2018, 0, 0, '2026-06-08 06:30:56.504502', 'KR');
INSERT INTO public.movies VALUES (4379, 158445, '7번방의 선물', '["Drama", "Comedy"]', 'Lee Hwan-kyung', '["Ryu Seung-ryong", "Park Shin-hye", "Kal So-won", "Jung Jin-young", "Oh Dal-su"]', '최악의 흉악범들이 모인 교도소 7번방에 이상한 놈이 들어왔다! 그는 바로 6살 지능의 딸바보 용구. 평생 죄만 짓고 살아온 7번방 패밀리들에게 떨어진 미션은 바로 용구 딸 예승이를 외부인 절대 출입금지인 교도소에 반.입.하.는.것! 웃음과 감동 가득한 사상초유의 합동작전이 시작된다!', 'https://image.tmdb.org/t/p/w500/c9TqJPm4pZCuiEXumTayoNIrBSK.jpg', 2013, 0, 0, '2026-06-08 06:30:58.017592', 'KR');
INSERT INTO public.movies VALUES (4373, 585831, '나쁜 녀석들: 더 무비', '["Action", "Crime"]', 'Son Yong-ho', '["Don Lee", "Kim Sang-joong", "Kim A-joong", "Jang Ki-yong", "Park Hyo-joon"]', '교도소 호송차량이 전복되고 최악의 범죄자들이 탈주하는 사상 초유의 사건이 발생한다. 이에 경찰은 수감 중인 범죄자가 흉악범을 잡는 극비 프로젝트인 ‘특수범죄수사과’를 다시 소집한다. 오구탁 반장은 과거 함께 활약했던 전설의 주먹 박웅철을 찾아가고, 감성 사기꾼 곽노순과 전직 형사 고유성을 영입해 새로운 팀을 구성한다. 새로운 멤버들이 합류해 더욱 강력하고 치밀하고 독해진 나쁜 녀석들. 이 사건을 파헤칠수록 배후에 거대한 범죄조직이 있다는 것을 직감한 그들은 더 나쁜 놈들을 소탕하기 위해 움직이기 시작하는데…', 'https://image.tmdb.org/t/p/w500/m8jIFKcZK8MiEf79O8f3BrI5IUz.jpg', 2019, 0, 0, '2026-06-08 06:30:53.438615', 'KR');
INSERT INTO public.movies VALUES (4384, 1173494, '아지매의 뒷문 단속', '["Drama", "Romance"]', 'Ya Sin-soo', '["Lee Chae-dam", "Yeon Joo", "Seon Yool", "Im Tae-mok", "Myung Sub"]', NULL, 'https://image.tmdb.org/t/p/w500/t9VnZe8pOCV9Ippxac4FKbRcWBK.jpg', 2023, 0, 0, '2026-06-08 06:31:01.762174', 'KR');
INSERT INTO public.movies VALUES (4386, 133573, '비밀애', '["Drama", "Romance"]', 'Ryoo Hoon', '["Yoo Ji-tae", "Yoon Jin-seo", "Im Ye-jin", "Jung In-gi", "Oh Yeon-ah"]', '결혼 2개월만에 불의의 사고로 혼수상태에 빠진 남편 진우를 간호하는 연이의 일상은 시든 꽃처럼 무미건조하기만 하다. 그러던 어느 날, 오랜 외국 생활을 마치고 진우의 동생 진호가 귀국한다. 진우와 꼭 닮은 얼굴, 꼭 닮은 목소리... 모든 것이 진우와 같은 진호의 모습에 연이는 혼란스러운 가운데 미묘한 떨림을 느낀다. 진호 역시 생기를 잃은 채 살아가는 연이를 보며 어느새 연민 이상이 되어버린 자신의 감정을 숨기지 않는다. 결국 서로에 대한 이끌림을 감출 수 없던 그들의 위험한 사랑이 시작된다. 하지만 그들의 위태로운 사랑도 잠시. 혼수상태에 빠져있던 진우가 기적적으로 깨어나면서 세 사람의 사랑은 파국으로 치닫기 시작하는데...', 'https://image.tmdb.org/t/p/w500/pTL9Z1EaOpgXSA8HvZX8gtHIlBN.jpg', 2010, 0, 0, '2026-06-08 06:31:03.285018', 'KR');
INSERT INTO public.movies VALUES (389, 37165, '트루먼 쇼', '["Comedy", "Drama"]', 'Peter Weir', '["Jim Carrey", "Laura Linney", "Noah Emmerich", "Natascha McElhone", "Holland Taylor"]', '트루먼 버뱅크는 작고 조용한 섬마을에 사는 평범한 세일즈맨이다. 그런 그가 자신의 삶에 대해 의문을 갖기 시작한 것은 평소와 다름없이 평범한 어느 날, 갑자기 하늘에서 촬영용 조명등이 떨어지고, 어렸을 적 자신이 익사를 직접 목격했던 아버지가 살아오고, 또 누군가에 의해 끌려가는 등 상식 밖의 일들이 벌어지고 나서부터였다. 평생을 그다지 신경쓰지 않고 지냈던 일상이었지만 주변을 보니 이상한 일이 너무 많았다. 결국 자신이 특별한 상황에 놓여있다는 확신을 하게된 트루먼은 첫사랑 실비아의 모든 것이 다 거짓라는 말을 되새기며 일상으로부터 탈출을 결심하게 되는데...', 'https://image.tmdb.org/t/p/w500/AsUv4pFf1UQuOLKf7nYUXgmgCNf.jpg', 1998, 0, 0, '2026-06-06 13:25:11.023162', 'US');
INSERT INTO public.movies VALUES (4387, 928241, '수퍼모델', '["Thriller"]', 'Yoo Young-seon', '["Lee Shi-a"]', '인기 슈퍼모델 지은은 아침 일찍 이상한 전화를 받는다. 살인자가 되지 않기 위해서 시키는 대로 할 수밖에 없던 지은은 결국 함정에 빠져 벙커에 갇힌다. 범인은 2년 전 슈퍼모델 대회 사건의 진실을 얘기하라고 협박한다.', 'https://image.tmdb.org/t/p/w500/rBrQizyKXhJKR0D3NHkRPKuo0KD.jpg', 2021, 0, 0, '2026-06-08 06:31:04.039037', 'KR');
INSERT INTO public.movies VALUES (4388, 734118, '청불학원2', '["Drama", "Romance"]', 'Kim Seok-man', '["Yoo Jung", "Kang Min-woo", "Yoo Ji-won"]', NULL, 'https://image.tmdb.org/t/p/w500/jB3fWTu9FoABTvYLhXXSFb9ki3N.jpg', 2020, 0, 0, '2026-06-08 06:31:04.798123', 'KR');
INSERT INTO public.movies VALUES (4389, 486593, '여자전쟁: 도기의 난', '["Drama"]', 'Song Chang-soo', '["Choi Mu-sung", "Kim Joon-bae", "Choi Sung-hee", "Kim Ki-cheon", "Yoo Soon-woong"]', '산골 마을에서 큰 욕심 없이 살던 노총각 약초꾼 ‘도기’에게 어느 날 손님이 찾아온다.  사업 실패로 수배 중인 친구 ‘창국’이 뇌쇄적인 그의 아내 ‘선화’와 함께 찾아온 것.  도기가 이들을 어쩔 수 없이 숨겨주면서 셋의 이상야릇하고 불편한 동거가 시작되는데...  멈출 수 없는 친구 아내에 대한 강렬한 욕망을 도기는 과연 참아낼 수 있을까?  그리고 도기가 절대 알아선 안 되는 그녀의 비밀은 무엇일까?', 'https://image.tmdb.org/t/p/w500/4MkaHNhkKvoH69KdNJkgT5HB6lV.jpg', 2016, 0, 0, '2026-06-08 06:31:05.562477', 'KR');
INSERT INTO public.movies VALUES (4390, 726139, '탈출: 프로젝트 사일런스', '["Thriller", "Action", "Horror", "Sci-Fi", "Adventure"]', 'Kim Tae-gon', '["Lee Sun-kyun", "Ju Ji-hoon", "Kim Hie-won", "Moon Sung-keun", "Ye Su-jeong"]', '한치 앞도 구분할 수 없는 짙은 안개 속 붕괴 직전의 공항대교에 고립된 사람들이 그 안에 도사리고 있는 예기치 못한 위협으로부터 살아남기 위해 고군분투하는 이야기.', 'https://image.tmdb.org/t/p/w500/rXuSca6qEb4xPrSRT7XRzYCFbZB.jpg', 2024, 0, 0, '2026-06-08 06:31:06.321423', 'KR');
INSERT INTO public.movies VALUES (457, 168259, '분노의 질주: 더 세븐', '["Action", "Crime", "Thriller"]', 'James Wan', '["Vin Diesel", "Paul Walker", "Dwayne Johnson", "Michelle Rodriguez", "Tyrese Gibson"]', '도미닉과 멤버들은 범죄조직 소탕 후 모든 전과를 사면 받고 평범한 일상으로 돌아간다. 하지만 평화도 잠시, 전작에서 처리한 범죄조직의 리더 오웬 쇼의 형 데카드 쇼가 동생의 복수를 위해 멤버들을 차례로 공격한다. 특수부대 출신 용병 데카드 쇼의 난입으로 한이 갑작스레 사망하게 되고, 도미닉의 집은 순식간에 폭파당한다. 이에 맞서는 정부요원 페티는 도미닉을 돕는 조건으로 납치당한 해커 램지의 구출을 의뢰하고, 도미닉은 멤버들을 다시 모아 숨막히는 반격을 시작한다.', 'https://image.tmdb.org/t/p/w500/cuQdgDYANbKA46e4va2fz6fODkc.jpg', 2015, 0, 0, '2026-06-06 13:25:13.329774', 'US');
INSERT INTO public.movies VALUES (371, 9823, '모탈 컴뱃 2', '["Action", "Fantasy", "Sci-Fi"]', 'John R. Leonetti', '["Robin Shou", "Talisa Soto", "James Remar", "Brian Thompson", "Sandra Hess"]', '아웃 월드의 황제인 샤오 칸(Shao Kahn: 브라이언 톰슨 분)은 아웃월드와 지구를 합병시켜서, 파멸시키려는 음모를 꾸민다. 모탈 컴뱃에서 류캉(Liu Kang: 로빈 쇼 분)과 선택된 파이터들이 이긴 후, ''지구는 한 세대 동안 평화를 누려야한다''는 전 우주 세계의 이 신성한 규칙을 깨고, 샤오 칸은 아웃월드로부터 지구로 통하는 게이트를 열어 침략해온다. 이에 대항할 힘을 모으기 위해, 레이든(Rayden: 제임스 레마 분)은 류캉과 파이터들을 집합시킨다. 자신의 야욕을 채워줄 악의 파이터(인간이 아닌 무리들)들을 데리고 레이든 앞에 나타난 샤오 칸. 류캉은 샤오 칸에 맞서, 평화의 결정적인 열쇠를 가진 키타나 공주(Princess Kitana: 탈리사 소토 분)와 함께 그들의 소굴로 찾아간다. 그러나, 키타나 공주는 그들의 손에 빼앗기고 류캉은 그들의 함정에 걸려든다. 정신없이 일격을 가해 오는 샤오 칸 일당들은 마침내, 레이든을 죽이고 만다. 이에 분노한 파이터들은 류캉을 앞세우고, 6일 째의 마지막 전투에 임하게 된다. 키타나 공주는 샤오 칸의 일당으로 악의 화신이 되어 환생한 어머니와, 류캉은 샤오 칸과, 잭스(Jax: 린 레드 윌리암스 분)는 나이프울프(Nightwolf: 라이트풋 분)와, 소냐 블레이드(Sonya Blade: 산드라 헤스 분)는 몬타로(Motaro: 데론 맥비 분)와 각각 맞수가 되어, 목숨을 건 전투를 벌인다. 결국 샤오 칸은 신성한 규칙을 어긴 죄로 피를 흘리며 죽는 운명에 처하게 된다. 결국 지구는 악의 손길로부터 자유로워지고 신들로부터 다시 생명을 부여받은 레이든은 신의 자리에 오르게 된다.', 'https://image.tmdb.org/t/p/w500/ttryglcY2osWZE3sRYBf3ewTZsW.jpg', 1997, 0, 0, '2026-06-06 13:25:10.226887', 'US');
INSERT INTO public.movies VALUES (4382, 482204, '형수의 직업', '["Drama", "Romance"]', 'No Hyun-jin', '["Park Joo-bin", "Min Do-yoon", "Ji Soo-I", "Jung Jae-sik"]', NULL, 'https://image.tmdb.org/t/p/w500/mGrwb0WE2ARfIOBlon67tx20kqT.jpg', 2017, 0, 0, '2026-06-08 06:31:00.269116', 'KR');
INSERT INTO public.movies VALUES (4394, 658228, '딸의 애인 3', '["Romance"]', 'Jeong Jin-ho', '["Han Seo-ah", "Lee Eun-mi", "Sang Woo", "Tae Joo", "서아"]', '가정을 무엇보다 중요하게 생각하지만 사실 젊은 남자와 섹스하는 것을 좋아하는 욕정녀 미선. 어느 날 자신의 섹파 정우에게 동생이 있음을 듣게 된다. 더 어린 남자에게 호기심이 가는데... 한편 정우는 동생 정현이 여자친구가 생겼다는 것을 몰래 알게 된다. 평소 자신을 한심하게 쳐다보던 동생을 골탕 먹이려는 작전을 펼친다. 새로 꼬신 섹스파트너가 딸의 애인이라니?​', 'https://image.tmdb.org/t/p/w500/4zqJPk4NghDpBKWtPOa5fC74tKx.jpg', 2019, 0, 0, '2026-06-08 06:31:10.128204', 'KR');
INSERT INTO public.movies VALUES (4398, 763633, '처제는, 처제와, 처제의...', '["Romance", "Drama"]', NULL, '["Yoo Sul-young", "Ah Ri", "Min Do-yoon", "Kim Min-jeong", "Jung In"]', '한때는 미래가 기대되는 소설가였지만 지금은 그저 백수에 지나지 않은 집에서 살림을 도맡아가며 생활하는 길우. 글을 써야 하지만 마땅히 생각나는 아이템도 글에 대한 열정도 사라진 지 오래다. 날마다 지루하게 보내던 어느 날, 처제(지수)의 친구(제인)가 집에 찾아온다. 무더운 여름날 땀으로 얼굴에 덕지덕지 붙은 머리카락을 떼어 내며 현관문을 들어서는 제인. 길우는 어딘지 모르게 청순해 보이고 섹시해 보이는 제인을 본 순간 심장이 요동치게 되는데...', 'https://image.tmdb.org/t/p/w500/ebq7uYRnmYqtrOjGdrfJDkyJewG.jpg', 2019, 0, 0, '2026-06-08 06:31:13.136062', 'KR');
INSERT INTO public.movies VALUES (4400, 740996, '블랙핑크: 세상을 밝혀라', '["Documentary"]', 'Caroline Suh', '["JISOO", "JENNIE", "ROSÉ", "LISA", "TEDDY"]', '2016년 8월 8일, 괴물 신인 블랙핑크가 등장했다. 그 후로 4년, 쉼 없이 달려오며 K팝 최초의 기록을 써 내려온 그녀들. 여기서 돌아본다. 꿈을 향한 여정의 시작부터.', 'https://image.tmdb.org/t/p/w500/qfcnBeX8o7MndM52Ig79Zc1R4cT.jpg', 2020, 0, 0, '2026-06-08 06:31:14.55379', 'KR');
INSERT INTO public.movies VALUES (4401, 408620, '아수라', '["Action", "Crime", "Thriller"]', 'Kim Sung-soo', '["Jung Woo-sung", "Hwang Jung-min", "Ju Ji-hoon", "Kwak Do-won", "Jeong Man-sik"]', '강력계 형사 한도경은 이권과 성공을 위해 각종 범죄를 저지르는 악덕시장 박성배의 뒷일을 처리해주는 대가로 돈을 받는다. 악에 계속 노출되는 사이,  말기 암 환자인 아내의 병원비를 핑계로 돈 되는 건 뭐든 하는 악인의 길로 들어서게 된 한도경. 그의 약점을 쥔 독종 검사 김차인과 검찰 수사관 도창학은 그를 협박하고 이용해 박성배의 비리와 범죄 혐의를 캐려 한다. 각자의 이익과 목적을 위해 한도경의 목을 짓누르는 검찰과 박성배. 그 사이 태풍의 눈처럼 되어 버린 한도경은, 자신을 친형처럼 따르는 후배 형사 문선모를  박성배의 수하로 들여보내고, 살아남기 위해 혈안이 된 나쁜 놈들 사이에서 서로 물지 않으면 물리는 지옥도가 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/hrkpHTjBeuEaxNJetjCPtNsi5bv.jpg', 2016, 0, 0, '2026-06-08 06:31:15.221102', 'KR');
INSERT INTO public.movies VALUES (4504, 1050035, '괴물', '["Mystery", "Thriller", "Drama"]', 'Hirokazu Kore-eda', '["Sakura Ando", "Soya Kurokawa", "Hinata Hiiragi", "Eita Nagayama", "Yuko Tanaka"]', '싱글맘 사오리는 아들 미나토의 행동에서 이상 기운을 감지한다. 용기를 내 찾아간 학교에서 상담을 진행한 날 이후 선생님과 학생들의 분위기가 심상치 않게 흐르기 시작하고.  한편 사오리는 친구들로부터 따돌림을 당하고 있는 미나토의 친구 요리의 존재를 알게 되고 자신이 아는 아들의 모습과 사람들이 아는 아들의 모습이 다르다는 사실을 어렴풋이 깨닫는데… 태풍이 몰아치던 어느 날, 아무도 몰랐던 진실이 드러난다.', 'https://image.tmdb.org/t/p/w500/cHS3uVwAyViWcVbpRwrfekgn2cr.jpg', 2023, 0, 0, '2026-06-08 06:32:32.406869', 'JP');
INSERT INTO public.movies VALUES (4395, 1229007, '천국의 문 복상사', '["Romance"]', NULL, '["Rika", "Han Seok-bong", "Gil Dong", "Joo Ah"]', NULL, 'https://image.tmdb.org/t/p/w500/8ImPaza9P75DcUlOEVY2yY6vAWx.jpg', 2021, 0, 0, '2026-06-08 06:31:10.882972', 'KR');
INSERT INTO public.movies VALUES (4397, 45202, '하녀', '["Thriller", "Drama"]', 'Im Sang-soo', '["Jeon Do-yeon", "Lee Jung-jae", "Seo Woo", "Youn Yuh-jung", "Park Ji-young"]', '이혼 후 식당 일을 하면서도 해맑게 살아가던 은이는 자신에게는 까마득하게 높은 상류층 대저택의 하녀로 들어간다. 완벽한 주인집 남자 훈, 쌍둥이를 임신 중인 안주인 해라, 자신을 엄마처럼 따르는 여섯 살 나미, 그리고 집안을 총괄하는 나이든 하녀 병식과의 생활은 낯설지만 즐겁다. 어느 날 가족 여행에 동행하게 된 은이는 자신의 방에 찾아온 훈의 은밀한 유혹에 이끌려 육체적인 관계를 맺고 본능적인 행복을 느낀다. 은이와 훈은 격렬한 관계를 이어가지만 병식이 그들의 사이를 눈치채며 대저택에 알 수 없는 긴장감이 감돌기 시작하는데...', 'https://image.tmdb.org/t/p/w500/1ruIX5Y8wggViQ75v3dVbNQl5cy.jpg', 2010, 0, 0, '2026-06-08 06:31:12.381346', 'KR');
INSERT INTO public.movies VALUES (4399, 335777, '넛잡 2', '["Animation", "Family", "Adventure", "Comedy"]', 'Cal Brunker', '["Will Arnett", "Maya Rudolph", "Bobby Cannavale", "Bobby Moynihan", "Isabela Merced"]', '땅콩 털이에 성공 후 여유로운 삶을 즐기던 ‘설리’와 공원 친구들!  어느 날 갑자기, 영원할 것만 같던 땅콩 가게가 폭발하고, ‘설리’와 친구들은 어쩔 수 없이 ‘리버티공원’으로 돌아가게 되지만 이마저도 악덕 시장의 놀이공원 건설 계획으로 파괴될 위기에 처한다.  더 이상 물러날 곳이 없는 ‘설리’와 친구들! 과연 악덕 시장에 맞서 공원을 지킬 수 있을까?', 'https://image.tmdb.org/t/p/w500/jVUmyzSeJMBrgmblOWqiCmIhjRg.jpg', 2017, 0, 0, '2026-06-08 06:31:13.881215', 'KR');
INSERT INTO public.movies VALUES (4320, 610209, '내방에 일본여자가 있다', '["Drama", "Romance"]', 'EROPING', '["Mao Hamasaki", "Shin Yeon-woo", "Lee Soo", "Lee Mi-na", "Kwak Kyung-ho"]', '비장한 목표와 함께 한국에 있는 호텔에 취업한 사쿠라(하마사키 마오).  요리나 청소를 담당하기로 했으나, 첫 실무교육으로 마사지 실습을 받으며 흠칫!  마사지 팀장의 손이 사쿠라의 알몸을 파고들자, 눈물을 머금으며 호텔에서 탈출한다.  여관과 찜질방을 오가며 희망의 끈을 놓지 않으려 애쓰지만, 가는 곳마다 사쿠라를 괴롭히는 음란마귀들과 크고 작은 오해들로 결국 노숙자 신세가 되고 마는데...  추위와 배고픔에 생명의 위협을 느낀 사쿠라는 어느 커다란 저택 안으로 숨어든다.  여지없이 찾아 온 음란마귀의 기운에 청바지를 벗어 내리고 참을 수 없는 신음을 토해낸다.  커다란 저택에 스스로 감금되어 웹툰을 그리던 키스군은 사쿠라의 존재를 발견하고  당분간 함께 지낼 것을 제안한다.  예쁜 사쿠라의 미모는 키스군의 상상력에 활력을 불어넣고, 사쿠라는 키스군의 웹툰 속 주인공이 되어 여러 음란한 매력들을 선보인다.', 'https://image.tmdb.org/t/p/w500/m3pPpNBsj7XKpGfTeokZvOzJjgL.jpg', 2019, 0, 0, '2026-06-08 06:30:13.998099', 'KR');
INSERT INTO public.movies VALUES (4410, 482122, '사랑받지 못한 여자', '["Drama"]', 'No Zin-soo', '["Kim Hwa-yeon", "Yoon Ye-hee", "Shin Won-ho", "Han Jeong-hyeon"]', '군대를 갓 제대한 도경(신원호)은 외딴 섬으로 향하는 배에서 신비로운 매력을 지닌 가인(김화연)을 만나고, 물거품으로 사라질듯한 그녀의 가녀린 자태에 묘한 끌림을 느낀다.  그 날 저녁, 두 사람은 ‘유바리’라는 이름의 술집에서 다시 만나 하룻밤을 보내게 되는데…  가인의 마음 속에 품고 있던 욕망은 점차 커져가고 도경은 거부할 수 없는 그녀의 집착에서 벗어나기 위해 몸부림친다.', 'https://image.tmdb.org/t/p/w500/j0a4q2ImYFpU50JrsUM7I88vxH7.jpg', 2017, 0, 0, '2026-06-08 06:31:21.2345', 'KR');
INSERT INTO public.movies VALUES (4505, 1445276, 'たまらないのは恋なのか', '["Romance", "Animation"]', NULL, '["Chiaki Kobayashi", "Takeo Otsuka"]', NULL, 'https://image.tmdb.org/t/p/w500/zESBv0bTqtb4ICJ9oYn2HFec8JV.jpg', 2025, 0, 0, '2026-06-08 06:32:33.212337', 'JP');
INSERT INTO public.movies VALUES (4403, 552643, '아내의 애인2', '["Drama", "Romance"]', 'Jo Tae-ho', '["Kim In-ae", "Kim Hyun-jung", "Choi Chul-min", "Lee Hyo-won"]', NULL, 'https://image.tmdb.org/t/p/w500/wZxEUrvJvrmc1zrOK3gM3UM20A0.jpg', 2018, 0, 0, '2026-06-08 06:31:16.544015', 'KR');
INSERT INTO public.movies VALUES (4405, 715287, '새엄마의 욕망', '["Drama", "Romance"]', 'Lee Dong-Joon', '["Lee Soo", "Tae Hee", "James", "Jung In"]', '미모의 아내를 얻어 주위의 부러움을 받던 상진은 아내의 친구 지안에게 재수중인 아들의 과외 선생을 맡아줄 것을 부탁하고, 일찍 퇴근한 상진은 우연히 지안의 샤워하는 모습을 보게 되는데, 아들의 과외선생과 섹스가 하고픈 남자, 그리고 젊은 새엄마와 좋은 시간을 보내고 싶은 아들, 돈을 원하는 지안과 남편에게 실망하여 젊은 아들에게 몸을 허락한 이진. 기괴한 운명의 네 사람이 한집에 모이며 벌어지는 기막힌 이야기', 'https://image.tmdb.org/t/p/w500/rYC6UyML4CU4zYiZVbDMrwnGyWW.jpg', 2020, 0, 0, '2026-06-08 06:31:17.882872', 'KR');
INSERT INTO public.movies VALUES (4406, 1244806, '신의악단', '["Drama"]', 'Kim Hyung-hyup', '["Park Si-hoo", "Jeong Jin-woon", "Tae Hang-ho", "Jang Ji-gun", "Han Jung-wan"]', '대북제재로 돈줄이 막힌 북한. 국제사회의 2억 달러 지원을 얻기 위한 마지막 방법은 단 하나! 보위부는 당의 명령을 받고, 북한 최초의 가짜 찬양단을 만드는 임무를 맡는다.', 'https://image.tmdb.org/t/p/w500/uzMwEHO2s4aWutOEtYXld51qskT.jpg', 2025, 0, 0, '2026-06-08 06:31:18.580633', 'KR');
INSERT INTO public.movies VALUES (4408, 482059, '여친 엄마', '["Romance", "Drama"]', 'Lee Ri-dan', '["Si Woo", "Ahn So-hee", "Min Joo", "Kang Soo-cheol", "Jung Jae-sik"]', '나의 옛 여자... 여친 엄마로 돌아오다?! 오른 월세를 감당할 수 없어 길거리에 내쫓긴 경준. 갈 곳이 없는 그를 안쓰럽게 여긴 여친 지혜는 자신의 집에서 머물라고 제안한다. 그런데 지혜의 집에서 그를 마중 나온 여자는 바로 경준의 첫사랑 지영...! 경준은 자신에게 사랑을 알려줬던 연상녀 지영이 여친 지혜의 새엄마가 되었단 사실에 혼란스러워하면서도 같은 지붕 아래 자꾸만 마주치는 그녀에게 다시 한번 마음이 흔들린다. 새끈한 여친과 탱탱한 예비 장모, 그 파격의 삼각관계가 시작된다.', 'https://image.tmdb.org/t/p/w500/ts5nW9maHOM6VE086H6vTp07sGY.jpg', 2017, 0, 0, '2026-06-08 06:31:19.899921', 'KR');
INSERT INTO public.movies VALUES (4409, 707609, '왕게임', '["Drama"]', NULL, '["Han Yi-seul", "Cheon Yoo-ji", "Park Hyun-jung", "Kang Woo-je"]', '연인 민수와 영주가 기획한 1박 2일의 은밀한 펜션 미팅. 이별의 아픔을 겪은 민주와 연애 초보 연주, 그리고 각기 다른 매력의 경태와 현수가 한자리에 모인다. 설레는 한 시간의 데이트와 사진 촬영 미션으로 서로를 탐색하는 청춘들. 하지만 정작 미팅을 주선한 민수와 영주는 복잡한 시선들을 피해 둘만의 비밀스러운 움직임을 시작하는데...', 'https://image.tmdb.org/t/p/w500/jMukBVPyelOw7KzRF7ivcA2EdDG.jpg', 2020, 0, 0, '2026-06-08 06:31:20.565883', 'KR');
INSERT INTO public.movies VALUES (4506, 812225, '블랙 클로버: 마법제의 검', '["Animation", "Fantasy", "Action", "Adventure"]', 'Ayataka Tanemura', '["Gakuto Kajiwara", "Nobunaga Shimazaki", "Junichi Suwabe", "Kana Yuuki", "Toshihiko Seki"]', '마법을 사용할 순 없지만 용맹한 소년은 마법제가 되기 위해 애쓴다. 그러던 어느 날, 봉인되었던 네 명의 역대 마법제가 클로버 왕국을 섬멸하기 위해 다시 모습을 드러낸다.', 'https://image.tmdb.org/t/p/w500/cOxZNyCn422dXCuhO5YkqUUb50E.jpg', 2023, 0, 0, '2026-06-08 06:32:34.009983', 'JP');
INSERT INTO public.movies VALUES (4412, 1322831, '장모님의 육체적 본능', '["Drama"]', '심민재', '["Kim Soo-yeon", "Min Soo", "Sang Woo"]', NULL, 'https://image.tmdb.org/t/p/w500/wNEmxQmPc52wlSDxcPeGCS2BpaO.jpg', 2024, 0, 0, '2026-06-08 06:31:23.311849', 'KR');
INSERT INTO public.movies VALUES (4416, 689160, '맛있는 과외누나', '["Romance"]', 'Lee Ga-on', '["Jin Si-ah", "Shin Yeon-woo", "Jin Yi"]', '모태 쏠로 탈출을 위해 희망에게 연애 과외를 받는 봉수.INSERT INTO public.movies VALUES (4417, 892222, '새아빠와 모녀', '["Romance"]', 'Lee Han-II', '["Min Do-yoon", "Ye Seul", "Yoon Yool", "Yeon Joo", "Shin Yeon-ho"]', '미국 루이지애나에서 온 우아한 여자 서라는 사업가 경한과 결혼을 하는데, 경환은 돈이 되는 일은 뭐든지 해왔던 속물적인 사업가이다. 경환은 술집 마담이었던 미연과 애인 관계였지만 서라와의 결혼을 계기로 이제 우아하게 사업가답게 살아보겠다며 미연에게 이별을 통보한다. 그러나 경환에게는, 팬티라인이 보이지 않는 옷을 보면 성적 욕구가 치밀어 미쳐버리는 문제가 있었다. 어느 날 경환의 신혼집에 나타난 서라의 친딸 윤아가 짧은 치마를 입고 나타난다.', 'https://image.tmdb.org/t/p/w500/49UMGEIEACXOU5PvwUswyVDmgJf.jpg', 2021, 0, 0, '2026-06-08 06:31:26.675121', 'KR');
INSERT INTO public.movies VALUES (4418, 11658, '태극기 휘날리며', '["Action", "Adventure", "Drama", "History"]', 'Kang Je-kyu', '["Jang Dong-gun", "Won Bin", "Lee Eun-ju", "Gong Hyung-jin", "Lee Young-ran"]', '1950년 6월. 서울 종로에서 가족의 생계를 책임지기 위해 열심히 살아가는 진태는 힘든 생활 속에도 약혼녀 영신과의 결혼과, 세상에서 가장 소중하게 생각하는 동생 진석의 대학진학을 위해 언제나 활기차고 밝은 생활을 해 나간다. 6월의 어느 날, 한반도에 전쟁이 일어났다는 호외가 배포되면서 평화롭기만 하던 서울은 순식간에 싸이렌 소리와 폭발음, 그리고 사람들의 비명 소리로 가득해진다. 이에 남쪽으로 피난을 결정한 진태는 영신과 가족들을 데리고 수많은 피난행렬에 동참하지만, 피난열차를 타기 위해 도착한 대구역사에서 거대한 운명의 소용돌이에 말려들고 만다.', 'https://image.tmdb.org/t/p/w500/rcBc6lI7Ouj1kb0bbbX0CkuJe9q.jpg', 2004, 0, 0, '2026-06-08 06:31:27.35256', 'KR');
INSERT INTO public.movies VALUES (4419, 588108, '한산: 용의 출현', '["Action", "Drama", "History"]', 'Kim Han-min', '["Park Hae-il", "Byun Yo-han", "Ahn Sung-ki", "Son Hyun-joo", "Kim Sung-kyu"]', '1592년 4월, 조선은 임진왜란 발발 후 단 15일 만에 왜군에 한양을 빼앗기며 절체절명의 위기에 놓인다. 조선을 단숨에 점령한 왜군은 명나라로 향하는 야망을 꿈꾸며 대규모 병역을 부산포로 집결시킨다. 한편, 이순신 장군은 연이은 전쟁의 패배와 선조마저 의주로 파천하며 수세에 몰린 상황에서도 조선을 구하기 위해 전술을 고민하며 출전을 준비한다. 하지만 앞선 전투에서 손상을 입은 거북선의 출정이 어려워지고, 거북선의 도면마저 왜군의 첩보에 의해 도난당하게 되는데…', 'https://image.tmdb.org/t/p/w500/9zPOnQfvWJde1bLR9Y6DF1WUlnJ.jpg', 2022, 0, 0, '2026-06-08 06:31:28.01732', 'KR');
INSERT INTO public.movies VALUES (4420, 417974, '여직원들: 직장연애사', '["Romance"]', 'Myeong Seok Hwan', '["Joo Ye-bin", "Jung Myung-seo", "Baek Se-ri", "Heo Yoon-joo", "Ahn Joon-woo"]', '막내 여직원과 점심시간마다 비밀 섹스 중인 남근  유부녀 과장님한테 섹스를 배우고 있는 김대리  모든 여직원들에게 들이대는 이과장.  이들은 업무만 시작하면 직업병인지 아랫도리가 심심하다.  어느 날, 중국으로 파견 나갔던 최고의 섹시녀 희수가 돌아온다.  그것도 한껏 농염해진 모습으로 말이다.  아랫도리가 심심한 남자 직원들의 끈적하고도 음탕한 구애가 시작되는데...', 'https://image.tmdb.org/t/p/w500/n5begwrznTanurwuK6p04CozAE0.jpg', 2016, 0, 0, '2026-06-08 06:31:28.678516', 'KR');
INSERT INTO public.movies VALUES (349, 156022, '더 이퀄라이저', '["Thriller", "Action", "Crime"]', 'Antoine Fuqua', '["Denzel Washington", "Marton Csokas", "Chloë Grace Moretz", "David Harbour", "Haley Bennett"]', '새벽 2시만 되면 어김없이 잠에서 깨는 로버트 맥콜. 불면증으로 잠 못 드는 이 시간이면 그는 늘 책 한 권을 들고 카페로 향한다. 가족도 친구도 없는 그는 아내가 남기고 간 ‘죽기 전에 읽어야 할 소설 100권’을 모두 읽는 것이 유일한 삶의 목표다. 그런 그에게 어느 날, 어린 콜걸 테리가 말을 건넨다. 무료하게 전화를 기다리다 벨이 울리면 대기하고 있던 리무진에 오르는 테리와 매일 같은 공간에서 같은 시간을 공유하던 로버트는 묘한 동질감을 느끼며 가까워진다. 그러던 어느 날, 테리가 포주인 러시아 마피아에게 무자비하게 폭행을 당한 채로 발견되자 세상을 향한 분노가 폭발하고만 로버트는 마침내, 강자에겐 약하고 약자에겐 한없이 강한 이 세상을 향해 스스로 심판자가 되기로 결심하는데...', 'https://image.tmdb.org/t/p/w500/hqes9NQtVIULs8VKu0WqY6RdXGU.jpg', 2014, 0, 0, '2026-06-06 13:25:09.463832', 'US');
INSERT INTO public.movies VALUES (4413, 1063738, '화이트 리버', '["Drama"]', 'Ma Xue', '["Tian Yuan", "Song Ningfeng", "Xu Weihao", "Zhang Wenmo", "Zuo Xiaoguang"]', '베이징의 ''베드 타운'' 도시 ''얀자오''를 배경으로 펼쳐지는 서로에게 얽매인 세 사람의 적나라한 사랑이야기. 베이징의 ''베드 타운''이라 불리는 도시 얀자오에 사는 여성 ''양 판''. 그녀는 관음증 환자인 남편 ''위엔 용''과 레스토랑 종업원 ''시아오팡''과 위태로운 인연을 맺는다. 서로 얽매여 있고, 누구 하나 떨어질 수 없는 그들은 흐트러져가는 일상을 서서히 받아들이기 시작한다.', 'https://image.tmdb.org/t/p/w500/sQrbJpsyuC8gn5rWpVnCAbsmY53.jpg', 2025, 0, 0, '2026-06-08 06:31:24.001919', 'KR');
INSERT INTO public.movies VALUES (4414, 1470984, 'Sex Partner From a Blind Date App Who Helps Release Tension', '[]', NULL, '["Hae Il", "Kim Soo Yeon", "Lee Chae-dam", "Min Do-yoon", "Woo Yeol"]', NULL, 'https://image.tmdb.org/t/p/w500/yay9LXuyBOVy239NRhS6KbAWG6N.jpg', 2025, 0, 0, '2026-06-08 06:31:24.692588', 'KR');
INSERT INTO public.movies VALUES (4415, 640327, '대외비', '["Crime", "Thriller", "Drama"]', 'Lee Won-tae', '["Cho Jin-woong", "Lee Sung-min", "Kim Moo-yul", "Won Hyun-jun", "Kim Min-jae"]', '1992년 부산, 밑바닥 정치 인생을 끝내고 싶은 만년 국회의원 후보 해웅. 해웅은 이번 선거에서만큼은 금뱃지를 달 것이라 확신했지만, 정치판을 뒤흔드는 권력 실세 순태에게 버림받으며 지역구 공천에서 탈락한다. 순태에 의해 짜여진 선거판을 뒤집기 위해 부산 지역 재개발 계획이 담긴 대외비 문서를 입수한 해웅. 행동파 조폭 필도를 통해 선거 자금까지 마련한 해웅은 무소속으로 선거판에 뛰어들어 승승장구한다. 순태 역시 해웅이 가진 대외비 문서의 존재를 알게 되고, 점차 해웅의 숨통을 조여오는데…', 'https://image.tmdb.org/t/p/w500/lnk2cwY3CJIzKrLm0sur2U40iqp.jpg', 2023, 0, 0, '2026-06-08 06:31:25.354087', 'KR');
INSERT INTO public.movies VALUES (4426, 1151766, '살인자 리포트', '["Drama", "Thriller"]', 'Cho Young-jun', '["Cho Yeo-jeong", "Jung Sung-il", "Hwang Ji-ah", "Kim Tae-han", "Choi Su-im"]', '특종에 목마른 위기에 기자 백선주에게 자신이 연쇄살인범이라고 주장하는 정신과 의사 이영훈이 새로운 살인 예고와 함께 인터뷰 요청을 한다. 고민 끝에 선주는 호텔 스위트 룸에서 살인자와의 인터뷰를 시작하고, 그의 살인 동기가 환자의 치료 목적으로 시작되었다는 믿기지 않는 고백을 듣게 된다. 인터뷰가 진행될수록 무언가 잘못됨을 느끼고 도망가려던 선주는 지금 인터뷰를 멈추면 또 한 명이 살해될 것이라는 영훈의 충격적인 얘기를 듣게 되는데…', 'https://image.tmdb.org/t/p/w500/rcmJRflS4aFJg8Ockk7YePQWlzc.jpg', 2025, 0, 0, '2026-06-08 06:31:32.67643', 'KR');
INSERT INTO public.movies VALUES (4427, 716586, '국가 성생활 관리위원회', '["Romance"]', 'Gyeom Ji-san', '["Lee Chae-dam", "Kim Ah-rang", "Kang Min-woo", "Lee Soo", "Min Do-yoon"]', NULL, 'https://image.tmdb.org/t/p/w500/lYbwhNgyhVaBrUT2e0qeytHhy1a.jpg', 2018, 0, 0, '2026-06-08 06:31:33.346897', 'KR');
INSERT INTO public.movies VALUES (4429, 765056, '아이돌 연습생: 내 여동생의 친구들', '["Drama"]', 'Lee Dong-hyun', '["Seung Ha", "Sae Bom", "Lee Mi-na", "Gil Dong"]', '군대를 전역하고 아이돌 연습생인 동생 은주의 숙소로 몇일 지내러 온 재훈. 그 집엔 같은 연습생 친구들 현주와 연주가 있다. 잘생긴 재훈을 보고 호감을 느낀 동생 친구들. 재훈을 차지하기 위한 두 여자의 전쟁이 시작되고 중간에서 난처한 재훈은 현주와 연주에게 파격적인 제안을 한는데....', 'https://image.tmdb.org/t/p/w500/qhPS9o8wkmVIC0NVp9uLW8K2VT4.jpg', 2020, 0, 0, '2026-06-08 06:31:34.6769', 'KR');
INSERT INTO public.movies VALUES (4430, 1264805, '만약에 우리', '["Romance", "Drama"]', 'Kim Do-young', '["Koo Kyo-hwan", "Mun Ka-young", "Shin Jung-keun", "Lee Sang-yeob", "Kim Seo-won"]', '고향 가는 고속버스에 올라탄 은호와 휴학 후 어디론가 떠날 결심을 한 정원, 나란히 앉게 된 두 사람은 뜻밖의 인연을 맺는다. 서로의 꿈을 응원하며 의지하던 두 사람은 어느새 일상 깊숙이 스며들어 연인으로 발전한다. 웃고, 싸우고, 화해하며 세상을 다 가진 듯 뜨겁게 사랑하지만, 현실의 벽 앞에 두 사람은 결국 다른 길을 선택하게 된다. 그렇게 10년이 지난 후, 다시 마주한 순간 은호는 정원에게 오랫동안 묻어두었던 한마디를 꺼낸다.', 'https://image.tmdb.org/t/p/w500/3ajXIRwoTGvnlLWVPgZPrHgXIW.jpg', 2025, 0, 0, '2026-06-08 06:31:35.337358', 'KR');
INSERT INTO public.movies VALUES (4431, 1241612, '바람난 형수님 참교육', '["Romance"]', 'Jo Eon-joo', '["Ji Won", "Son Ye-ha", "Min Do-yoon", "Im Tae-mok"]', NULL, 'https://image.tmdb.org/t/p/w500/cRtwAq0fXPOJ3tlDipTeho6fXk5.jpg', 2023, 0, 0, '2026-06-08 06:31:36.013872', 'KR');
INSERT INTO public.movies VALUES (27, 44980, '제로 우먼 2', '["Action", "Thriller"]', 'Daisuke Gotô', '["Natsuki Ozawa", "Saori Iwama", "Kane Kosugi", "Hiroyuki Watari", "Tomomi Miyauchi"]', NULL, 'https://image.tmdb.org/t/p/w500/z9XSICETB0XWQRyMWpN2s3bAUlz.jpg', 1995, 0, 0, '2026-06-06 13:24:57.133725', 'JP');
INSERT INTO public.movies VALUES (4579, 1291559, '봄이 사라진 세계', '["Romance", "Drama"]', 'Takahiro Miki', '["Ren Nagase", "Natsuki Deguchi", "Mayuu Yokota", "Fumino Kimura", "Nene Otsuka"]', '살날이 1년밖에 남지 않은 열일곱 살 소년 아키토와 반년밖에 수명이 남지 않은 불치병 소녀. 소년은 소녀에게 즐거움을 선사하며 미처 몰랐던 삶의 의미를 알아간다.', 'https://image.tmdb.org/t/p/w500/cfq4mzrhAD6V49a8aLn15jCkzLA.jpg', 2024, 0, 0, '2026-06-08 06:33:31.598746', 'JP');
INSERT INTO public.movies VALUES (4423, 575718, '해치지않아', '["Comedy", "Drama"]', 'Son Jae-gon', '["Ahn Jae-hong", "Kang So-ra", "Park Young-kyu", "Kim Seung-o", "Jeon Yeo-been"]', '생계형 수습 변호사 태수에게 찾아온 일생일대의 기회, 위기의 동물원 동산파크를 구하라! 동산파크의 새 원장이 된 그는 손님은커녕 동물조차 없는 동물원을 살리기 위해 직원들에게 동물로 위장근무 하자는 기상천외한 제안을 한다. 북극곰, 사자, 기린, 고릴라, 나무늘보로 출근한 동산파크 5인방. 묵언수행은 기본, 어깨 결림, 근육 뭉침, 뒷목까지 뻐근한 그들의 털 날리는 고군분투가 계속되는 가운데, 목이 타던 태수는 북극곰의 신분을 망각하고 관람객 앞에서 콜라 한 모금을 마시게 되는데…', 'https://image.tmdb.org/t/p/w500/2yBRl13BrHXhK7KpMTMZ9YfSvRW.jpg', 2020, 0, 0, '2026-06-08 06:31:30.671031', 'KR');
INSERT INTO public.movies VALUES (4424, 1460811, 'MZ대학생과 어린이모', '["Romance"]', 'Won Myeong-jun', '["Ah Rang", "Sae Bom", "Park Do-jin", "Gil Dong", "Yoon Yool"]', NULL, 'https://image.tmdb.org/t/p/w500/oAiUDIONFnsQD14CyoPASZuxTNP.jpg', 2025, 0, 0, '2026-06-08 06:31:31.35244', 'KR');
INSERT INTO public.movies VALUES (4425, 336744, '차이나타운', '["Drama", "Thriller"]', 'Han Jun-hee', '["Kim Hye-soo", "Kim Go-eun", "Um Tae-goo", "Park Bo-gum", "Go Kyung-pyo"]', '지하철 보관함 10번에 버려져 이름이 일영인 아이. 아이는 오직 쓸모 있는 자만이 살아남는 차이나타운에서 엄마라 불리는 여자를 만난다. 엄마는 일영을 비롯해 쓸모 있는 아이들을 자신의 식구로 만들어 차이나타운을 지배한다. 돈이 되는 일이라면 어떤 일도 마다하지 않는 엄마가 일영에게는 유일하게 돌아갈 집이었다. 그리고 일영은 엄마에게 가장 쓸모 있는 아이로 자란다.', 'https://image.tmdb.org/t/p/w500/9YX1SdRcqLkDEMhvFMaFZ3b24Dv.jpg', 2015, 0, 0, '2026-06-08 06:31:32.014037', 'KR');
INSERT INTO public.movies VALUES (4428, 30018, '마더', '["Crime", "Drama", "Mystery"]', 'Bong Joon Ho', '["Kim Hye-ja", "Won Bin", "Jin Goo", "Yoon Je-moon", "Jeon Mi-seon"]', '읍내 약재상에서 일하며 아들과 단 둘이 사는 엄마. 그녀에게 아들 도준은 온 세상과 마찬가지다. 28세의 나이답지 않게 제 앞가림을 못 하는 어수룩한 아들  도준은 자잘한 사고를 치고 다니며 엄마의 애간장을 태운다. 어느 날, 한 소녀가 살해 당하고 어처구니없이 도준이 범인으로 몰린다. 아들을 구하기 위해 백방으로 뛰는 엄마. 하지만 경찰은 서둘러 사건을 종결 짓고 무능한 변호사는 돈만 밝힌다. 결국 아들을 구하기 위해 믿을 사람 하나 없이 범인을 찾아나선 엄마. 도준의 혐의가 굳어져 갈수록 엄마 또한 절박해져만 간다.', 'https://image.tmdb.org/t/p/w500/lhxVHEkaOH51oazowpdCHJNLIBE.jpg', 2009, 0, 0, '2026-06-08 06:31:34.009117', 'KR');
INSERT INTO public.movies VALUES (207, 1598785, '은하특급 밀키☆서브웨이: 각 역 정차 극장행', '["Animation", "Action", "Adventure", "Comedy", "Sci-Fi"]', 'Yohei Kameyama', '["Momoka Terasawa", "Anna Nagase", "Mikako Komatsu", "Hisako Kanemoto", "Makoto Koichi"]', '이런저런 이유로 체포된 여섯 명의 잡범들. 사회봉사 활동으로 열차를 청소하는 임무를 맡게 되는데. 하지만, 갑자기 열차가 폭주하면서 일동은 대소동에 휘말려 든다.', 'https://image.tmdb.org/t/p/w500/vGUC9vtVbavv0BePpkNUsdExLEI.jpg', 2026, 0, 0, '2026-06-06 13:25:04.096524', 'JP');
INSERT INTO public.movies VALUES (173, 372058, '너의 이름은.', '["Animation", "Romance", "Drama"]', 'Makoto Shinkai', '["Ryunosuke Kamiki", "Mone Kamishiraishi", "Ryo Narita", "Aoi Yuuki", "Nobunaga Shimazaki"]', '시골에 사는 소녀 미츠하(가미시라이시 모네)는 어느 날 잠에서 깬 후 자신의 몸이 남자로 바뀐 걸 알게 된다.  같은 시간, 도쿄에 사는 소년 타키(가미키 류노스케) 역시 이 기이한 상황을 겪고 있다.  낯선 가족, 낯선 친구들, 낯선 풍경들...  서로에게 이어진 끈을 알게 된 둘은 둘만의 규칙을 정하고 점차 상황을 받아들이기 시작한다.  서로에게 남긴 메모를 확인하며  점점 친구가 되어가는 타키와 미츠하.  언제부턴가 더 이상 몸이 바뀌지 않자  자신들이 특별하게 이어져있었음을 깨달은  타키는 미츠하를 만나러 가는데...', 'https://image.tmdb.org/t/p/w500/2DJCufz3Oa703PbLjNX1pM6MCG2.jpg', 2016, 0, 0, '2026-06-06 13:25:02.577552', 'JP');
INSERT INTO public.movies VALUES (217, 1539104, '극장판 주술회전: 시부야사변 X 사멸회유', '["Animation", "Action", "Fantasy"]', 'Shota Goshozono', '["Junya Enoki", "Megumi Ogata", "Koji Yusa", "Daisuke Namikawa", "Yuma Uchida"]', '2018년 10월 31일 시부야 역 주변에 갑자기 ‘장막’이 내려지고, 다수의 일반인이 갇히게 된다. 그곳에 홀로 뛰어든 현대 최강의 주술사, 고죠 사토루. 그러나 그곳에는 고죠의 봉인을 꾀하는 주저사·주령들이 기다리고 있었다. 시부야에 집결하는 이타도리 유지를 비롯한 수많은 주술사들. 전례 없는 대규모 주술전 「시부야사변」이 시작된다—. 그리고 싸움은, 최악의 주술사 카모 노리토시가 꾸민 데스 게임 「사멸회유」로 이어진다. 「시부야사변」을 거쳐, 마굴로 변한 전국 10개의 결계(콜로니). 대혼란의 한가운데, 이타도리의 사형 집행인으로 특급 주술사 옷코츠 유타가 나타난다. 절망 속에서도 싸움을 계속하는 이타도리. 무정하게도 칼날을 겨누는 옷코츠. 가속해가는 저주의 혼돈. 같은 스승을 둔 이타도리와 옷코츠, 두 사람의 사투가 시작된다——.', 'https://image.tmdb.org/t/p/w500/ifK2v7oQQrgqrmDu7sr1TgoAPT9.jpg', 2025, 0, 0, '2026-06-06 13:25:04.119738', 'JP');
INSERT INTO public.movies VALUES (157, 405746, '도어', '["Horror", "Mystery", "Thriller"]', 'Banmei Takahashi', '["Keiko Takahashi", "Daijiro Tsutsumi", "Shirō Shimomoto", "Takuto Yonezu", "Masao Ishida"]', '도심의 고층 아파트에서 살고 있는 야스코와 그녀의 가족들. 반복되는 장난전화와 한 판매원의 집착에 두려움을 느낀 야스코는, 판매원이 강제로 문틈에 팜플렛을 집어넣으려하자 그의 손가락을 문으로 찧어버린다. 이를 계기로 판매원은 그녀를 괴롭히기 시작하는데, 문의 낙서로 시작된 그의 집착은 갈수록 본격적인 스토킹으로 변모한다.', 'https://image.tmdb.org/t/p/w500/rmD3Q8wPrzbe5P5gDgbzR0fsDQx.jpg', 1988, 0, 0, '2026-06-06 13:25:01.814858', 'JP');
INSERT INTO public.movies VALUES (232, 1404791, '돌하우스', '["Horror", "Mystery"]', 'Shinobu Yaguchi', '["Masami Nagasawa", "Koji Seto", "Tetsushi Tanaka", "Aoi Ikemura", "Naomi Nishida"]', '다섯 살에 세상을 떠난 딸 메이에 대한 그리움과 슬픔으로 가득한 카에와 타다히코 부부. 어느 날, 카에는 골동품 시장에서 딸 아이를 닮은 인형을 발견하고 집에 가지고 오면서 정성스레 보살핀다. 인형을 통해 기운을 되찾은 카에와 남편 타다히코 사이에서 마이가 태어나고, 자연스레 인형은 관심 밖이 되지만...', 'https://image.tmdb.org/t/p/w500/gBCT1BbU5i0p9yj4M12Vvd2rVM2.jpg', 2025, 0, 0, '2026-06-06 13:25:04.866621', 'JP');
INSERT INTO public.movies VALUES (360, 1408208, '8번 출구', '["Horror", "Mystery"]', 'Genki Kawamura', '["Kazunari Ninomiya", "Yamato Kochi", "Nana Komatsu", "Naru Asanuma", "Kotone Hanase"]', '방심하는 순간 영원히 이곳에 갇힌다! 무한루프 속 이상 현상을 찾아 탈출하라! 끝없이 반복되는 지하도에 갇힌 ‘헤매는 남자’. 아래의 규칙에 따라 8번 출구로 탈출해야만 한다. 1. 단 하나의 이상 현상도 놓치지 말 것. 2. 이상 현상을 발견하면 즉시 되돌아갈 것. 3. 이상 현상이 없다면 앞으로 나아갈 것. 4. 8번 출구를 통해서 밖으로 나갈 것.', 'https://image.tmdb.org/t/p/w500/uId1j785aRg5hGDj49SRpQZrEJV.jpg', 2025, 0, 0, '2026-06-06 13:25:09.491102', 'JP');
INSERT INTO public.movies VALUES (444, 280, '터미네이터 2: 심판의 날', '["Action", "Thriller", "Sci-Fi"]', 'James Cameron', '["Arnold Schwarzenegger", "Linda Hamilton", "Edward Furlong", "Robert Patrick", "Earl Boen"]', '미래, 인류와 기계의 전쟁은 계속 되는 가운데 스카이넷은 인류 저항군 사령관 존 코너를 없애기 위해 액체 금속형 로봇인 T-1000(로버트 패트릭)을 과거의 어린 존 코너에게로 보낸다. 형태의 변신과 자가 치유까지 가능한 T-1000에 대항하고 존 코너를 지키기 위해 인류 저항군은 T-101(아놀드 슈왈제네거)을 과거로 급파한다. 미래의 인류 운명을 쥔 어린 존 코너, 그를 구해내지 않으면 인류의 미래는 없다. 반드시 제거해야 하는 스카이넷의 T-1000은 거침없이 존 코너 일행을 위협하며 숨가쁜 추격을 시작하는데...', 'https://image.tmdb.org/t/p/w500/nDVUiEqoeXaDQuM81KkUVNviYIm.jpg', 1991, 0, 0, '2026-06-06 13:25:13.288999', 'US');
INSERT INTO public.movies VALUES (304, 1287454, '農家の嫁は、取り扱い注意！ Part 2 有機ある大作戦篇', '["Comedy", "Drama", "Romance"]', 'Shinji Imaoka', '["Fumika", "Junko Maru", "Hitomi Wada", "Junko Miyashita", "Tamotsu Ishibashi"]', NULL, 'https://image.tmdb.org/t/p/w500/tiXbRle5rTTC1rMfnRl5dLNGi8m.jpg', 2021, 0, 0, '2026-06-06 13:25:07.938737', 'JP');
INSERT INTO public.movies VALUES (152, 129, '센과 치히로의 행방불명', '["Animation", "Family", "Fantasy"]', 'Hayao Miyazaki', '["Rumi Hiiragi", "Miyu Irino", "Mari Natsuki", "Takashi Naito", "Yasuko Sawaguchi"]', '평범한 열 살 짜리 소녀 치히로 식구는 이사 가던 중 길을 잘못 들어 낡은 터널을 지나가게 된다. 터널 저편엔 폐허가 된 놀이공원이 있었고 그곳엔 이상한 기운이 흘렀다. 인기척 하나 없는 이 마을의 낯선 분위기에 불길한 기운을 느낀 치히로는 부모님에게 돌아가자고 조르지만 부모님은 호기심에 들떠 마을 곳곳을 돌아다니기 시작한다. 어느 음식점에 도착한 치히로의 부모님은 그 곳에 차려진 음식들을 보고 즐거워하며 허겁지겁 먹어대다가 돼지로 변해버린다. 겁에 질려 당황하는 치히로에게 낯선 소년 하쿠가 나타나 빨리 이곳을 나가라고 소리치는데...', 'https://image.tmdb.org/t/p/w500/u1L4qxIu5sC2P082uMHYt7Ifvnj.jpg', 2001, 0, 0, '2026-06-06 13:25:01.802959', 'JP');
INSERT INTO public.movies VALUES (399, 1542261, '극장판 도라에몽: 신 진구의 해저비밀성', '["Animation", "Adventure", "Fantasy", "Family"]', 'Tetsuo Yajima', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Subaru Kimura", "Tomokazu Seki"]', '이번 여름방학은 바닷속 캠핑이다! 숨이 멎을 듯한 놀라움이 가득한 두근두근 해저 대모험! 여름방학 캠핑 장소를 두고 의견이 갈린 진구와 친구들은 도라에몽의 제안으로 바다 한가운데로 여행을 떠나기로 한다. 도라에몽의 비밀도구 ''수중 버기’와 ‘적응총’을 사용해 다양한 해양 생물도 만나고 바비큐도 하며 즐거운 시간을 보내던 중, 수상한 침몰선과 미스터리한 소년 ‘엘’과 만난다. 신비로운 해저 도시 ‘무대륙’에서는 육지인들을 싫어해 쉽게 마음을 열지 않는데… 그때, 수수께끼의 ‘귀암성’이 활동을 시작했다는 긴급한 소식이 전해지고 육지와 바다 모두가 위험에 처하고 만다! 소중한 우정을 가슴에 품고, 지구의 운명을 건 환상적인 모험이 지금 시작된다!', 'https://image.tmdb.org/t/p/w500/wfAb9wxmcsQqSAyQ82IZlDwNkC0.jpg', 2026, 0, 0, '2026-06-06 13:25:11.051473', 'JP');
INSERT INTO public.movies VALUES (252, 233651, 'セックス・ライダー　濡れたハイウェイ', '["Thriller"]', 'Koretsugu Kurahara', '["Mari Tanaka", "Ken Yoshizawa", "Yuki Seto", "Kinji Takinami", "Norihiko Umetani"]', NULL, 'https://image.tmdb.org/t/p/w500/gJNafT1asDVLV943q00mU0WpDl.jpg', 1971, 0, 0, '2026-06-06 13:25:05.629893', 'JP');
INSERT INTO public.movies VALUES (551, 630940, '女教師日記２　暴かれた性', '[]', 'Hiroaki Ito', '["Rinko Mayumi", "Ikki Ōsawa", "Ichiho Matsuda"]', NULL, 'https://image.tmdb.org/t/p/w500/rQSVn2kGbp15nQcbir2yLts0xqQ.jpg', 1996, 0, 0, '2026-06-06 13:25:17.217165', 'JP');
INSERT INTO public.movies VALUES (4346, 399902, '타부: 금지된 사랑', '["Drama", "Romance"]', 'Ko Goo-ma', '["Park Se-mi-I", "Wi Ji-Woong", "Park Ha-yan", "Yu Da-eun"]', '아이돌 연습생이던 은지는 자신을 스폰 해주던 진태에게 버림받고 친 언니인 선영의 집으로 향한다. 이젠 형부가 되어버린 첫사랑인 준환은 그런 은지를 따뜻하게 받아주지만 선영은 오랜만에 찾아온 은지를 어린애 취급하며 과거 아이돌 연습생을 포기했던 자신의 길을 걸을까 걱정한다. 그 후로도 은지와 선영의 사소한 다툼들이 이어지고 그때마다 준환은 은지를 보듬어주고 위로한다. 준환의 그런 모습에 은지는 준환에게 점점 의지하게 된다. 준환도 회사를 그만둔 사실은 은지에게 고백하며 그들은 그렇게 서로의 마음으로 조금씩 빠르게 스며들기 시작한다. 얼마 후, 선영은 일주일 간 집을 비우고 출장길에 오르고, 출장길에 오르는 날, 은지에게 그간의 다툼에 미안한 마음을 전한다. 쌍둥이 목각인형을 통해 서로의 추억을 공유한 두 사람. 그렇게 단둘만이 남게 된 집안. 과거 준환을 짝사랑했던 은지는 준환의 기사 등을 스크랩한 노트를 준환에게 보여주며 준환의 아픈 상처를 보듬어 주려 한다. 준환도 그런 은지에게 고마움을 느끼며 감추고 숨겨두었던 자신의 마음을 열기 시작한다. 결국 둘은 넘어선 안 될 선을 넘게 되고 일 주간의 뜨거운 여름날을 보내기로 한다. 시간이 지날수록 점점 서로에게 빠져드는 두 사람. 하지만 약속한 일주일이 시간이 다 되어가고 은지는 준환을 갖고 싶은 욕망에 언니를 향한 질투심까지 느끼게 된다...', 'https://image.tmdb.org/t/p/w500/hLUnGJs21uXkeXoqQA3uhVpqvqc.jpg', 2015, 0, 0, '2026-06-08 06:30:32.229723', 'KR');
INSERT INTO public.movies VALUES (4347, 623135, '싱크홀', '["Comedy", "Drama"]', 'Kim Ji-hoon', '["Cha Seung-won", "Kim Sung-kyun", "Lee Kwang-soo", "Kwon So-hyun", "Kim Hye-jun"]', '서울 입성과 함께 내 집 마련의 꿈을 이룬 가장 동원은 이사 첫날부터 프로 참견러 만수와 사사건건 부딪힌다. 동원은 자가취득을 기념하며 직장 동료들을 집들이에 초대하지만 행복한 단꿈도 잠시, 순식간에 빌라 전체가 땅 속으로 떨어지고 만다. 지하 500m 싱크홀 속으로 떨어진 이들은 과연 무사히 빠져나갈 수 있을까?', 'https://image.tmdb.org/t/p/w500/nEslKzaq3LKuQcDTNODzwh149Qh.jpg', 2021, 0, 0, '2026-06-08 06:30:32.911606', 'KR');
INSERT INTO public.movies VALUES (589, 128, '모노노케 히메', '["Adventure", "Fantasy", "Animation"]', 'Hayao Miyazaki', '["Yoji Matsuda", "Yuriko Ishida", "Yuko Tanaka", "Kaoru Kobayashi", "Masahiko Nishimura"]', '북쪽의 끝, 에미시족의 마을에 어느 날 갑자기 재앙신이 나타나 마을을 위협한다. 이에 강한 힘을 소유한 에미시족의 후계자인 아시타카는 결투 끝에 포악해진 재앙신을 쓰러트리지만 싸움 도중 오른팔에 저주의 상처를 받고 죽어야 할 운명에 처하게 된다. 결국 재앙신의 탄생 원인을 밝혀 자신의 저주를 없애기 위해 서쪽으로 길을 떠난 아시카타는 여행 중에 지코라는 미스테리한 수도승을 만나 재앙 신이 생겨나게 된 이유가 서쪽 끝에 있는 시시신의 숲과 관련이 깊다는 이야기를 듣게 되고 한시 바삐 서쪽으로 향한다.', 'https://image.tmdb.org/t/p/w500/lLftgg4iFyDwuodra3Isr41y2Lq.jpg', 1997, 0, 0, '2026-06-06 13:25:18.767398', 'JP');
INSERT INTO public.movies VALUES (852, 597221, 'おさな妻', '["Drama"]', 'Shinichi Shiratori', '["Etsuko Hara", "Shingo Yamamoto", "Nami Misaki", "Moeko Ezawa", "Tatsuya Hamaguchi"]', NULL, 'https://image.tmdb.org/t/p/w500/yv5Bx5iK2ySIBRSvG064n2Wtw36.jpg', 1980, 0, 0, '2026-06-06 13:25:28.865227', 'JP');
INSERT INTO public.movies VALUES (3983, 143308, '꽃과 뱀 3: 사육편', '["Drama", "Thriller", "Horror"]', 'Shōgorō Nishimura', '["Minako Ogawa", "Yuri Yau", "Sadami Sakamoto", "Mariko Kajikawa", "Shinichi Sato"]', '성공한 사업가가 전 파트너의 사업을 구하지 않자 아내와 그녀의 학생을 납치한다. 전 파트너는 두 여성을 SM 포르노 배우로 훈련시켜 성노예로 만들어 복수할 계획을 갖게 되는데..', 'https://image.tmdb.org/t/p/w500/dHG4mTjv4DDl2NFtQe3IMCcVHdT.jpg', 1986, 0, 0, '2026-06-08 06:24:41.999778', 'JP');
INSERT INTO public.movies VALUES (900, 31055, '제로 우먼: 파이널 미션', '["Drama", "Action"]', 'Koji Enokido', '["Misayo Haruki", "Naoko Iijima", "Miho Suzuki", "Takako Kitagawa", "Kôsuke Hishinuma"]', NULL, 'https://image.tmdb.org/t/p/w500/h5QsCLp8r9omENtZSs6ckLK72vq.jpg', 1995, 0, 0, '2026-06-06 13:25:30.43403', 'JP');
INSERT INTO public.movies VALUES (749, 8392, '이웃집 토토로', '["Fantasy", "Animation", "Family"]', 'Hayao Miyazaki', '["Noriko Hidaka", "Chika Sakamoto", "Hitoshi Takagi", "Shigesato Itoi", "Sumi Shimamoto"]', '1955년 일본의 아름다운 시골 마을, 상냥하고 의젓한 11살 사츠키와 장난꾸러기에 호기심 많은 4살의 메이 는 사이좋은 자매로 아빠와 함께 도시를 떠나 시골로 이사온다. 자상한 아빠 쿠사카베타츠오는 도쿄에서 대학 연구원이며, 입원 중이지만 따뜻한 미소를 잃지 않는 엄마가 있다. 곧 퇴원하실 엄마를 공기가 맑은 곳에서 맞이하기 위해서다. 숲 한복판에 금방이라도 쓰러질 것처럼 낡은 집을 보며 자매는 새로운 환경에 대한 호기심으로 잔뜩 들뜬다. 그러던 어느 날 사츠키가 학교에 간 동안 메이는 숲에서 정령을 만나다. 메이는 그 정령에게 토토로란 이름을 붙여주는데...', 'https://image.tmdb.org/t/p/w500/c9zCkL0rTkNQ1HB9cmeFIqbkS50.jpg', 1988, 0, 0, '2026-06-06 13:25:24.952176', 'JP');
INSERT INTO public.movies VALUES (713, 810693, '극장판 주술회전 0', '["Animation", "Action", "Fantasy"]', 'Sunghoo Park', '["Megumi Ogata", "Kana Hanazawa", "Yuichi Nakamura", "Takahiro Sakurai", "Mikako Komatsu"]', '어린 시절, 소꿉친구인 오리모토 리카를 교통사고로 눈 앞에서 잃은 옷코츠 유타. 옷코츠는 원령으로 변한 리카의 저주에 괴로워한 나머지 자신도 죽기를 바라지만, 최강의 주술사인 고죠 사토루에 의해 주술고전에 들어가게 된다. 그리고 동급생인 젠인 마키, 이누마키 토게, 판다를 만나면서 굳은 결심을 한다. 한편 옷코츠와 친구들 앞에 과거에 일반인을 대량으로 학살해서 고전에서 추방된 최악의 주저사인 게토 스구루가 나타난다. 주술사만의 낙원을 만들려는 게토는 비술사를 섬멸하겠다면서 신주쿠와 교토에 천의 저주를 내리는데...', 'https://image.tmdb.org/t/p/w500/gHcga1wgDD4MAeApoOM7yDn9BOq.jpg', 2021, 0, 0, '2026-06-06 13:25:23.409967', 'JP');
INSERT INTO public.movies VALUES (4478, 1575337, '초(超) 가구야 공주!', '["Animation", "Fantasy", "Sci-Fi"]', 'Shingo Yamashita', '["Yuko Natsuyoshi", "Anna Nagase", "Saori Hayami", "Miyu Irino", "Yuma Uchida"]', '달에서 도망쳐 온, 자유분방한 가구야가 이로하의 집에 살게 되면서, 이로하의 삶은 궤도를 이탈할 지경이다. 게다가 가구야는 이로하에게 가상 세계에서 함께 무대에 서자고 설득한다.', 'https://image.tmdb.org/t/p/w500/4Gh56xcxDoWWPuTclaKpKrZ3J4M.jpg', 2026, 0, 0, '2026-06-08 06:32:11.808723', 'JP');
INSERT INTO public.movies VALUES (4479, 1402474, '婚約者を腹上死させてしまい抜け殻のようなあいりさんと何度も何度も最低なヤケクソ中出しセックスをしたあの日… 希島あいり', '[]', NULL, '["Airi Kijima"]', NULL, 'https://image.tmdb.org/t/p/w500/2NIPJRFWnwLQAvqJrpLe7METwPv.jpg', 2024, 0, 0, '2026-06-08 06:32:12.5787', 'JP');
INSERT INTO public.movies VALUES (4350, 21707, '조폭 마누라', '["Action", "Comedy"]', 'Cho Jin-gyu', '["Shin Eun-kyung", "Park Sang-myeon", "Ahn Jae-mo", "Kim In-kwon", "Jang Se-jin"]', '조폭계의 살아있는 전설, 차은진. 가위하나로 절대 남성지대인 암흑가를 평정한 그녀지만 어린 시절 고아원에서 헤어졌던 언니에 대한 아픈 기억이 있다. 우여곡절 끝에 언니를 다시 만나지만 그녀는 이미 위암 말기 환자다. 이에 은진은, 언니의 마지막 소원을 위해 팔자에도 없는 결혼을 감행하는데... 동사무소 말단 직원으로 무려 58회의 맞선을 보고도 번번히 에프터 신청을 받지 못하는 남자 강수일. 어느 날 은진의 부하들과 우연히 마주친 그는 어리버리하게 생겼다는 이유 하나로 보스의 남편감으로 발탁(?)된다. 신부가 조폭인지도 모르고 마냥 신혼의 단꿈에 젖어있던 수일. 그러나 그런 그를 기다리는 것은 집안 살림은 고사하고 잠자리마저 거부하며 걸핏하면 발차기로 대응하는 새신부였으니...  은진은 그녀대로 조직 기반을 위해 벌이고 있는 부동산 사업 등으로 온전한 ''마누라'' 역할이 불가능한 가운데, 설상가상으로 언니마저 조카를 갖고 싶다는 폭탄같은 부탁을 한다.  그녀의 폭력적인 말투와 행동에 의심이 들기 시작한 수일이 결국 은진과 헤어질 결심을 하던 날 밤, 은진은 평소 자신들의 사업에 눈독을 들이던 백상어파와 대대적인 싸움을 벌인다. 싸움 도중 상대방의 공격에 은진이 유산하는 일이 발생하자 순진하기만 하던 수일의 꼭지는 180도로 돌고 마는데...', 'https://image.tmdb.org/t/p/w500/goC6sStC6MqtYYe1ukpd4pt7bda.jpg', 2001, 0, 0, '2026-06-08 06:30:34.907073', 'KR');
INSERT INTO public.movies VALUES (4482, 454561, '課外授業　暴行', '["Crime"]', 'Takahisa Zeze', '["Sayoko Nakajima", "Kunihiko Matsunaga", "Mami Ogawa", "Kazuhiro Sano", "Shirō Shimomoto"]', NULL, 'https://image.tmdb.org/t/p/w500/bUNSOpULT4Xs9Q3DH9mqymSRFmc.jpg', 1989, 0, 0, '2026-06-08 06:32:14.861182', 'JP');
INSERT INTO public.movies VALUES (4487, 1027766, '単身赴任　新妻の秘密', '["Drama"]', 'Shōgorō Nishimura', '["Maiko Kazama", "Osamu Tsuruoka", "Izumi Shima", "Yûko Asuka", "Eimei Esumi"]', NULL, 'https://image.tmdb.org/t/p/w500/defubsnQvkGhw5fv1D8emoqF1FL.jpg', 1980, 0, 0, '2026-06-08 06:32:18.763938', 'JP');
INSERT INTO public.movies VALUES (4488, 1285366, '사랑의 형태', '["Romance"]', 'Shinji Imaoka', '["Keisuke Koide", "Kei Fubuki", "Manami Shindo", "Yohta Kawase", "Kotaro Tanaka"]', '길거리에서 부딪힌 것을 계기로 몸이 뒤바뀌고 만 소설가 ''타카시''와 미용사 ''사토미''. 그들은 다시 원래의 몸으로 돌아갈 방법을 찾을 때까지 서로를 연기하며 생활하기로 한다. 그러던 중, 둘 다 사랑하는 사람과의 관계가 삐걱이고 있음을 알게 된다. 타인이면서 본인인 ''타카시''와 ''사토미''는 서로의 인생을 나아지게 하기 위한 고군분투를 시작하는데...', 'https://image.tmdb.org/t/p/w500/vTtq8iqEQlmgDTec9oe3YzjkOGT.jpg', 2024, 0, 0, '2026-06-08 06:32:19.564083', 'JP');
INSERT INTO public.movies VALUES (4490, 12493, '천국과 지옥', '["Drama", "Crime", "Thriller"]', 'Akira Kurosawa', '["Toshirō Mifune", "Tatsuya Nakadai", "Kyōko Kagawa", "Tatsuya Mihashi", "Isao Kimura"]', '신발 제조 회사의 중역인 곤도는 회사의 주도권을 잡기 위해 자신의 전 재산을 회사에 투자한 상태다. 어느 날 그는 자신의 아들이 납치됐으며 범인이 엄청난 몸값을 요구하고 있다는 통보를 받고 회사냐 아들이냐 하는 선택의 기로에 서게 된다. 하지만 정작 납치된 것은 그의 아들이 아니라 그의 운전사의 아들이란 사실이 밝혀지면서 곤도는 또 다른 고민에 빠지게 되는데...', 'https://image.tmdb.org/t/p/w500/qyMsijzCXBTFlsGeVkER6KqSJOm.jpg', 1963, 0, 0, '2026-06-08 06:32:21.057902', 'JP');
INSERT INTO public.movies VALUES (4491, 149, '아키라', '["Animation", "Sci-Fi", "Action"]', 'Katsuhiro Otomo', '["Mitsuo Iwata", "Nozomu Sasaki", "Mami Koyama", "Taro Ishida", "Mizuho Suzuki"]', '알 수 없는 폭발로 도쿄가 폐허가 된 지 31년이 지난 2019년의 일본. 신도시 네오도쿄는 정치와 자본의 결탁으로 첨단의 경제적 풍요를 누리고 있지만 이면에서는 퇴폐, 약물, 폭력, 광신으로 몸살을 앓고 있으며 반정부 시위가 곳곳에서 일어나고 있다. 고아이자 직업학교 출신 폭주족인 카네다 패거리는 오토바이로 거리를 누비며 아슬아슬한 심야의 레이싱을 즐긴다. 그중 한명인 테츠오는 자신에게 통제할 수 없는 엄청난 힘이 내재해 있음을 알고는 세상에 복수하듯 그 힘을 남용하기 시작한다. 과학자들은 진화된 인간에 도달하기 위해 아이들을 대상으로 능력을 각성시킬 실험을 자행하고, 30년 전의 도쿄 폭발은 실험대상 중 아키라라는 미지의 아이와 연관되어 있는데...', 'https://image.tmdb.org/t/p/w500/o5x9TTsTagSVsVe2lzcIDLRrmjm.jpg', 1988, 0, 0, '2026-06-08 06:32:21.816789', 'JP');
INSERT INTO public.movies VALUES (4481, 940721, '고질라 마이너스 원', '["Sci-Fi", "Horror", "Action"]', 'Takashi Yamazaki', '["Ryunosuke Kamiki", "Minami Hamabe", "Yuki Yamada", "Munetaka Aoki", "Hidetaka Yoshioka"]', '도쿄 앞바다에 고질라가 출현하면서 전후 일본은 최악의 상황에 놓인다. 민간인 몇몇이 모인 그룹이 이 새로운 위협을 막을 수 있을까?', 'https://image.tmdb.org/t/p/w500/6qLKVk53lorpoLilRSa7vvKXPW5.jpg', 2023, 0, 0, '2026-06-08 06:32:14.094977', 'JP');
INSERT INTO public.movies VALUES (4484, 1618818, '痴汉日记2：不停抚摸臀部的男人', '["Drama"]', 'Tadafumi Tomioka', '["Kazuya Takahashi", "Misa Aika", "Yoichi Nukumizu", "Kumiko Kin", "Yukijiro Hotaru"]', NULL, 'https://image.tmdb.org/t/p/w500/87vyeAPsMrsOnOW42cQZ0Wsxag8.jpg', 1995, 0, 0, '2026-06-08 06:32:16.412725', 'JP');
INSERT INTO public.movies VALUES (4485, 1545621, '명탐정 코난: 하이웨이의 타천사', '["Animation", "Action", "Mystery", "Crime"]', 'Takahiro Hasui', '["Minami Takayama", "Wakana Yamazaki", "Rikiya Koyama", "Megumi Hayashibara", "Miyuki Sawashiro"]', NULL, 'https://image.tmdb.org/t/p/w500/l2kfiNoRi6ofM5pSjr1rCloOfpx.jpg', 2026, 0, 0, '2026-06-08 06:32:17.161565', 'JP');
INSERT INTO public.movies VALUES (720, 14537, '하라키리', '["Action", "Drama", "History"]', 'Masaki Kobayashi', '["Tatsuya Nakadai", "Akira Ishihama", "Shima Iwashita", "Tetsuro Tamba", "Masao Mishima"]', '사소한 잘못으로 상부로부터 할복 명령을 하달받은 사무라이가 그것에 저항하는 이야기. 인습과 전통에 대해 순응하는 일본 사회에 저항하는 메세지를 담은 작품.', 'https://image.tmdb.org/t/p/w500/6Cw2LJzt6jRALHystjzWazeB4Pg.jpg', 1962, 0, 0, '2026-06-06 13:25:23.426761', 'JP');
INSERT INTO public.movies VALUES (4489, 508883, '그대들은 어떻게 살 것인가', '["Animation", "Fantasy", "Drama"]', 'Hayao Miyazaki', '["Soma Santoki", "Masaki Suda", "Ko Shibasaki", "Aimyon", "Yoshino Kimura"]', '화재로 어머니를 잃은 11살 소년 ‘마히토’는 아버지와 함께 어머니의 고향으로 간다. 어머니에 대한 그리움과 새로운 보금자리에 적응하느라 힘들어하던 ‘마히토’ 앞에 정체를 알 수 없는 왜가리 한 마리가 나타나고, 저택에서 일하는 일곱 할멈으로부터 왜가리가 살고 있는 탑에 대한 신비로운 이야기를 듣게 된다. 그러던 어느 날, ‘마히토’는 사라져버린 새엄마 ‘나츠코’를 찾기 위해 탑으로 들어가고, 왜가리가 안내하는 대로 이세계(異世界)의 문을 통과하는데…!', 'https://image.tmdb.org/t/p/w500/bzEpxah8vLNzPDrvswwgJ9rZQGX.jpg', 2023, 0, 0, '2026-06-08 06:32:20.301502', 'JP');
INSERT INTO public.movies VALUES (4494, 1593282, 'SONE-852 結婚式間近の花嫁、新郎との愛あるSEXよりも男性ウェディングプランナーから無理やり犯●れるほうがま●こビチャ濡れでイキまくる', '[]', NULL, '["Riri Nanatsumori"]', NULL, 'https://image.tmdb.org/t/p/w500/wwxOqYIXjCPzPtQiH3Aziim6XqR.jpg', 2025, 0, 0, '2026-06-08 06:32:24.900369', 'JP');
INSERT INTO public.movies VALUES (859, 44981, 'Zero WOMAN 危ない遊戯', '["Action", "Thriller", "Mystery"]', 'Hidekazu Takahara', '["Chieko Shiratori", "Ichiho Matsuda", "Terunori Miyazaki", "Ken Miyawaki", "Daisuke Ryū"]', NULL, 'https://image.tmdb.org/t/p/w500/AdPpB8xW0oPjFj3a2dqNeIuW9mW.jpg', 1998, 0, 0, '2026-06-06 13:25:28.881956', 'JP');
INSERT INTO public.movies VALUES (4502, 533514, '극장판 바이올렛 에버가든', '["Animation", "Drama", "Fantasy", "Romance"]', 'Taichi Ishidate', '["Yui Ishikawa", "Daisuke Namikawa", "Takehito Koyasu", "Hidenobu Kiuchi", "Haruka Tomatsu"]', '친애하는 길베르트 소령님, 오늘도 또 당신을 떠올리고 말았습니다.  무엇을 보든 무엇을 하든 당신이 떠오릅니다.  시간이 지나도 당신과 보냈던 기억은 선명하게 되살아납니다. 당신은 날 곁에 두었고 아무것도 모르는 제게 살아가는 방법을 가르쳐 주셨고 처음으로 사랑이라는 감정을 알려주셨습니다.  그래서 이렇게 또 편지를 쓰게 됩니다.  -언젠가 이 편지가 당신에게 닿기를 바라며-', 'https://image.tmdb.org/t/p/w500/mBUy2lCwk6fpByQ7GBFKRApKEHb.jpg', 2020, 0, 0, '2026-06-08 06:32:30.890836', 'JP');
INSERT INTO public.movies VALUES (4351, 56607, '나탈리', '["Drama", "Comedy", "Romance"]', 'Joo Kyeong-joong', '["Lee Sung-jae", "Kim Ji-hoon", "Hyeon-jin", "Kim Gi-yeon", "Kim Eun-Kyeong"]', '한 여자를 사랑한 두 남자, 그들의 엇갈린 사랑의 기억! 치명적인 아름다움으로 스포트라이트를 받아온 명품 조각상 ‘나탈리’. 하지만 실제 모델이 누군지 등 일체 알려진 바 없이 베일에 싸여있던 ‘나탈리’가 거장 조각가 황준혁의 개인전에서 10년 만에 다시 공개된다. 전시회 마지막 날, 준혁은 자신을 찾아온 평론가 장민우에게 ‘나탈리’의 실제 모델, 오미란과의 격정적인 사랑의 기억을 들려주게 되지만, 민우는 그녀가 자신을 사랑했다고 말한다. 그녀를 둘러싼 준혁과 민우의 엇갈린 기억, 그리고 ‘나탈리’를 둘러싼 비밀이 밝혀지기 시작하는데…', 'https://image.tmdb.org/t/p/w500/anawMl8fQiPz1FV3pScIGjvvWqh.jpg', 2010, 0, 0, '2026-06-08 06:30:35.574178', 'KR');
INSERT INTO public.movies VALUES (4354, 576174, '빠담풍', '["Drama", "Horror", "Thriller"]', 'Um Jong-sun', '["Yuk Cheol", "Kang Ri-na", "Jeon Moo-song", "Bae Su-chun", "Kwak Eun-Kyeong"]', NULL, 'https://image.tmdb.org/t/p/w500/oMTVfbyiHwluS5N5P42nxumPGAQ.jpg', 1992, 0, 0, '2026-06-08 06:30:38.335606', 'KR');
INSERT INTO public.movies VALUES (4355, 529569, '목격자', '["Thriller", "Crime"]', 'Cho Kyu-jang', '["Lee Sung-min", "Kim Sang-ho", "Jin Kyung", "Kwak Si-yang", "Bae Jung-hwa"]', '모두가 잠든 새벽, 비명소리를 듣고 베란다에 나간 ‘상훈’은 살인사건을 목격하게 된다. 신고를 하려던 순간, 손가락을 까딱거리며  자신의 아파트 층수를 세는 범인 ‘태호’와 눈이 마주치게 되는데…', 'https://image.tmdb.org/t/p/w500/g19rot2PyNKuldAD1IrMic1lYua.jpg', 2018, 0, 0, '2026-06-08 06:30:39.085362', 'KR');
INSERT INTO public.movies VALUES (4357, 346646, '베테랑', '["Action", "Crime", "Comedy", "Thriller"]', 'Ryoo Seung-wan', '["Hwang Jung-min", "Yoo Ah-in", "Yoo Hai-jin", "Oh Dal-su", "Jang Yoon-ju"]', '한 번 꽂힌 것은 무조건 끝을 보는 행동파 서도철은 겁 없고, 못 잡는 것 없고, 봐주는 것 없는 특수 강력사건 담당 광역수사대. 오랫동안 쫓던 대형 범죄를 해결한 후 숨을 돌리려는 찰나, 서도철은 재벌 3세 조태오를 만나게 된다. 세상 무서울 것 없는 안하무인의 조태오와 언제나 그의 곁을 지키는 오른팔 최상무. 서도철은 의문의 사건을 쫓던 중 그들이 사건의 배후에 있음을 직감한다. 건들면 다친다는 충고에도 불구하고 포기하지 않는 서도철의 집념에 판은 걷잡을 수 없이 커져가고, 조태오는 이를 비웃기라도 하듯 유유히 포위망을 빠져 나가는데...', 'https://image.tmdb.org/t/p/w500/8OJ4VtaddbDDwP1ydCitsYxgzCT.jpg', 2015, 0, 0, '2026-06-08 06:30:40.624917', 'KR');
INSERT INTO public.movies VALUES (4497, 1406657, '끝이 없는 스칼렛', '["Animation", "Action", "Drama", "Sci-Fi"]', 'Mamoru Hosoda', '["Mana Ashida", "Masaki Okada", "Yutaka Matsushige", "Kotaro Yoshida", "Koji Yakusho"]', '왕녀 스칼렛은 아버지를 죽인 숙부 클로디어스에게 복수를 하려다 죽임을 당하고 삶과 죽음이 뒤섞인 미지의 세계, 죽은 자들의 나라에서 깨어난다. 시간과 공간을 넘나드는 이곳에서 스칼렛은 영원한 죽음을 피하고 끝없는 복수의 여정을 시작한다.', 'https://image.tmdb.org/t/p/w500/nICE9EuyD5j9kmFHGxUJpqHOG2.jpg', 2025, 0, 0, '2026-06-08 06:32:27.136681', 'JP');
