INSERT INTO public.movies VALUES (4509, 143667, '縄地獄', '["Crime", "Drama"]', 'Kōyū Ohara', '["Naomi Tani", "Nami Aoki", "Hirokazu Inoue", "Hitoshi Takagi", "Kenji Fuji"]', NULL, 'https://image.tmdb.org/t/p/w500/bfxrYNWhnN6mKz7F28ELKUoVi5X.jpg', 1978, 0, 0, '2026-06-08 06:32:36.294286', 'JP');
INSERT INTO public.movies VALUES (4511, 444996, 'Neo Chinpira: Zoom Goes the Bullet', '["Crime", "Action"]', 'Banmei Takahashi', '["Show Aikawa", "Chikako Aoyama", "Joe Shishido", "Toru Minegishi", "Rikiya Yasuoka"]', NULL, 'https://image.tmdb.org/t/p/w500/1qN8VGqEJUw505ezFdbZKZokDI0.jpg', 1990, 0, 0, '2026-06-08 06:32:37.799092', 'JP');
INSERT INTO public.movies VALUES (4513, 2671, '링', '["Horror", "Thriller"]', 'Hideo Nakata', '["Nanako Matsushima", "Hiroyuki Sanada", "Rikiya Ôtaka", "Miki Nakatani", "Yuko Takeuchi"]', '아사가와 레이코는 조카 토모코의 죽음이 자신이 취재하고 있는 비디오와 연관이 있다고 생각하고 비디오를 찾아 나선다. 그러나 비디오를 본 그녀는 영상을 본 사람은 1주일 안에 죽는다는 것을 알아채고 전 남편인 류지에게 도움을 청한다. 비디오를 분석한 류지는 영상의 주인공인 시즈코라는 여인을 조사하고, 아들 요이치가 비디오를 본 사실을 알게 된 레이코는 그의 목숨을 살리기 위해 애쓴다.', 'https://image.tmdb.org/t/p/w500/gIgqm6K9PZXoN49AG9ZYNRtn86n.jpg', 1998, 0, 0, '2026-06-08 06:32:40.168009', 'JP');
INSERT INTO public.movies VALUES (4514, 934750, '尻を撫でまわしつづけた男 痴漢日記2', '[]', 'Tadafumi Tomioka', '["Kazuya Takahashi", "Yoichi Nukumizu", "Misa Aika", "Noboru Mitani", "Kumiko Kin"]', NULL, 'https://image.tmdb.org/t/p/w500/y2cG0Cj3PvdNSeMcKcsi9IhGe12.jpg', 1995, 0, 0, '2026-06-08 06:32:40.907757', 'JP');
INSERT INTO public.movies VALUES (4364, 1290183, '퍼스트 라이드', '["Comedy", "Drama", "Adventure"]', 'Nam Dae-joong', '["Kang Ha-neul", "Kim Young-kwang", "Cha Eun-woo", "Kang Young-suk", "Han Seon-hwa"]', '어린 시절부터 한 몸처럼 붙어 다닌 24년 지기 사총사, 태정, 도진, 연민, 금복의 꿈은 바로 함께 하는 여행! 학창 시절에 이루지 못했던 꿈을 위해 생애 첫 해외여행을 떠나는 날, 계획에 없던 옥심까지 합류하며 이들의 여행은 점점 환장의 세계로 흘러가는데…!', 'https://image.tmdb.org/t/p/w500/quzQxlecSoUeHs1W2D2g0FJnYCP.jpg', 2025, 0, 0, '2026-06-08 06:30:45.921472', 'KR');
INSERT INTO public.movies VALUES (4508, 715756, '성의 극약', '["Thriller", "Drama", "Horror"]', 'Hideo Jojo', '["Takashi Kitadai", "Sho Watanabe", "Kohei Nagano", "Ruri Shinato", "Seiki Chiba"]', '성공적인 젊은 샐러리맨 카츠나기는 한 순간의 부주의함으로 인해 부모와 모든 것을 잃고 나락으로 떨어져 급기야 자살을 시도한다. 미지의 남자 요덴이 그의 목숨을 구하지만, 카츠나기는 어딘지 알 수 없는 곳에 사슬에 묶여 감금된 자신을 발견한다. 그리고 요덴은 카츠나기의 몸 이곳 저곳을 탐색하며 끊임없는 성적 고문을 자행한다. 영문도 모른 채 묶인 채 카츠나기는 점차 고통에 익숙해져 가는 자신을 발견하고, 두 사람의 기이한 관계 뒤에는 또 다른 비밀이 숨어 있었다.', 'https://image.tmdb.org/t/p/w500/2D17INw4YmeRR0cLgMhlbzDI2m4.jpg', 2020, 0, 0, '2026-06-08 06:32:35.54851', 'JP');
INSERT INTO public.movies VALUES (4512, 916224, '스즈메의 문단속', '["Animation", "Drama", "Adventure", "Fantasy"]', 'Makoto Shinkai', '["Nanoka Hara", "Hokuto Matsumura", "Eri Fukatsu", "Shota Sometani", "Sairi Ito"]', '“이 근처에 폐허 없니? 문을 찾고 있어” 규슈의 한적한 마을에 살고 있는 소녀 ‘스즈메’는 문을 찾아 여행 중인 청년 ‘소타’를 만난다. 그의 뒤를 쫓아 산속 폐허에서 발견한 낡은 문. ‘스즈메’가 무언가에 이끌리듯 문을 열자 마을에 재난의 위기가 닥쳐오고 가문 대대로 문 너머의 재난을 봉인하는 ‘소타’를 도와 간신히 문을 닫는다. “닫아야만 하잖아요, 여기를!” 재난을 막았다는 안도감도 잠시, 수수께끼의 고양이 ‘다이진’이 나타나 ‘소타’를 의자로 바꿔 버리고 일본 각지의 폐허에 재난을 부르는 문이 열리기 시작하자 ‘스즈메’는 의자가 된 ‘소타’와 함께 재난을 막기 위한 여정에 나선다. “꿈이 아니었어” 규슈, 시코쿠, 고베, 도쿄 재난을 막기 위해 일본 전역을 돌며 필사적으로 문을 닫아가던 중 어릴 적 고향에 닿은 ‘스즈메’는 잊고 있던 진실과 마주하게 되는데…', 'https://image.tmdb.org/t/p/w500/95cnAy1nqjoEev1YkaXrSf0NDa1.jpg', 2022, 0, 0, '2026-06-08 06:32:39.429861', 'JP');
INSERT INTO public.movies VALUES (4518, 10515, '천공의 성 라퓨타', '["Adventure", "Fantasy", "Animation", "Action", "Family"]', 'Hayao Miyazaki', '["Keiko Yokozawa", "Mayumi Tanaka", "Minori Terada", "Kotoe Hatsui", "Fujio Tokita"]', '광산촌 슬랙 계곡의 기계 견습공인 고아 소년 파즈는 어느날 빛이 나는 목걸이를 한 채 하늘에서 떨어지던 소녀시타를 구해준다. 소녀는 대대로 전해져 오던 목걸이(비행석)로 인해 정부군과 해적 도라 일당들에게 쫓기고 있던 신세. 시타가 이들로부터 무사히 도망갈 수 있게 도와주던 중 파즈는 비행석과 하늘에 떠 있는 성 라퓨타가 실제로 존재한다는 사실을 알게 된다. 라퓨타의 존재를 믿고 있던 파즈는 시타와 함께 라퓨타를 찾기로 결심한다. 하지만 파즈와 시타는 그들을 쫓던 군대에게 잡히고, 시타는 정부 비밀 조사관인 무스카에게 파즈를 풀어주는 조건으로 협력을 약속하는데...', 'https://image.tmdb.org/t/p/w500/lObRXt53izxDbdlkGpNAHkDACmy.jpg', 1986, 0, 0, '2026-06-08 06:32:43.914074', 'JP');
INSERT INTO public.movies VALUES (4521, 1077347, '告白手記-私が濡れたあのSEX！', '[]', 'Ryōji Shinmura', '["Hitoe Ootake", "Hitomi Shiraishi", "Ijirî Okada", "Kyoko Tachibana"]', NULL, 'https://image.tmdb.org/t/p/w500/f3cDeWtL9jfkqyyzeU99BKXIWUW.jpg', 1997, 0, 0, '2026-06-08 06:32:46.171951', 'JP');
INSERT INTO public.movies VALUES (4522, 197998, '皆月', '["Drama"]', 'Rokurō Mochizuki', '["Eiji Okuda", "Kazuki Kitamura", "Takami Yoshimoto", "Keiko Oginome", "Takashi Saito"]', NULL, 'https://image.tmdb.org/t/p/w500/vPYecb60uKZPQjHluzULLrdaA5f.jpg', 1999, 0, 0, '2026-06-08 06:32:46.914619', 'JP');
INSERT INTO public.movies VALUES (4523, 372754, '동급생', '["Romance", "Animation"]', 'Shoko Nakamura', '["Kenji Nojima", "Hiroshi Kamiya", "Hideo Ishikawa", "Yurino"]', '밴드 활동을 하며 여자에게도 인기가 많은 쿠사카베 히카루.  고교 입시에서 만점을 받은 인재 사죠 리히토. 도무지 접점이 없어 보이는 두 남학생은 합창 대회 연습을 계기로 친해진다. 음을 느끼고 목소리에 귀를 기울이고 화음을 만들어가며 둘의 마음은 공명하기 시작하는데… 느긋하게 고조되다 뜻밖의 순간에 터져버리는 사랑의 감정. 순수하고 솔직한 쿠사카베 히카루와 그를 밀어내면서도 조금씩 마음을 열어가는 사죠 리히토.  청춘의 풋풋함 속에서 고민하고, 망설이며 앞으로 나아가고자 하는 그들이 깨달은 마음이란…', 'https://image.tmdb.org/t/p/w500/jNJ9shLhjRavjrCGRnoTmYB18d2.jpg', 2016, 0, 0, '2026-06-08 06:32:47.692945', 'JP');
INSERT INTO public.movies VALUES (4525, 504253, '너의 췌장을 먹고 싶어', '["Animation", "Drama", "Romance"]', 'Shinichiro Ushijima', '["Mahiro Takasugi", "Lynn", "Yukiyo Fujii", "Yuma Uchida", "Jun Fukushima"]', '어느 날, 우연히 주운 한 권의 「공병문고」를 통해 ‘나’는 학급 최고의 인기인 ‘사쿠라’의 비밀과 마주하게 된다. 비밀을 숨긴 채 살아가는 ‘사쿠라’와 그 비밀을 아는 유일한 클래스메이트 ‘나’', 'https://image.tmdb.org/t/p/w500/g1ucSvfDnV3HEVt8x7YeZ0fAIs2.jpg', 2018, 0, 0, '2026-06-08 06:32:49.192072', 'JP');
INSERT INTO public.movies VALUES (4526, 958430, '六本木令嬢　ふ・し・だ・ら', '["Drama"]', 'Hiroshi Shinomiya', '["Chizu Kirinami", "Asami Yûki", "Masahiko Sakata", "Koji Kawakami", "Daikei Shimizu"]', NULL, 'https://image.tmdb.org/t/p/w500/wv8OXFRuyhteeTTB4mwGB3pPRUi.jpg', 1987, 0, 0, '2026-06-08 06:32:49.950824', 'JP');
INSERT INTO public.movies VALUES (4519, 315011, '신 고질라', '["Action", "Sci-Fi", "Horror"]', 'Shinji Higuchi', '["Hiroki Hasegawa", "Yutaka Takenouchi", "Satomi Ishihara", "Kengo Kora", "Satoru Matsuo"]', '정체불명의 괴수 ‘고질라’의 출현으로 초토화된 일본  인류의 생존을 위협하는 대재앙을 상대로  불가능한 희망을 찾는 사람들의 최후 반격을 담은 블록버스터', 'https://image.tmdb.org/t/p/w500/8C0kCeMpCEmhiEytR1nNNK1eW5w.jpg', 2016, 0, 0, '2026-06-08 06:32:44.684669', 'JP');
INSERT INTO public.movies VALUES (4520, 591397, 'Doki Doki ヴァージン　もういちど I LOVE YOU', '["Romance", "Fantasy"]', 'Shun Nakahara', '["Shinobu Nakayama", "Yasufumi Hayashi", "Rika Furukawa", "Ichirō Ogura", "Masato Hagiwara"]', NULL, 'https://image.tmdb.org/t/p/w500/91GirQ8WcI54tHmwGMbuSKga960.jpg', 1990, 0, 0, '2026-06-08 06:32:45.427224', 'JP');
INSERT INTO public.movies VALUES (4529, 1470547, '酔わされて輪●されて 河北彩伽', '["Drama"]', 'Sabasuhori Naka', '["Saika Kawakita", "Daisuke Sadamatsu", "Toy Boy Aizawa", "Nick"]', NULL, 'https://image.tmdb.org/t/p/w500/a4LJqAHDS0trM9A0Zb3XRkb7e72.jpg', 2025, 0, 0, '2026-06-08 06:32:52.204618', 'JP');
INSERT INTO public.movies VALUES (4531, 1338799, '극장판 주술회전: 회옥·옥절', '["Animation", "Action", "Fantasy"]', 'Shota Goshozono', '["Yuichi Nakamura", "Takahiro Sakurai", "Anna Nagase", "Takehito Koyasu", "Aya Endo"]', '최강의 두 사람, 다시는 돌아갈 수 없는 푸른 봄. 2006년 봄, 주술고등전문학교 시절의 고죠 사토루와 게토 스구루. 불사의 술식을 가진 주술계 핵심, 텐겐으로부터 의뢰가 도착한다. 의뢰는 두 가지, 텐겐과 적합자인 성장체 아마나이 리코라는 소녀의 ‘호위’와 ‘말소’. 두 사람은 주술계 존속을 위한 호위 임무에 나서지만 후시구로라 불리는 ‘주술사 킬러’가 암살을 노리고 나타난다. 최강의 주술사와 최악의 주저사가 된 고죠와 게토, 두 사람의 엇갈린 운명의 과거가 밝혀진다.', 'https://image.tmdb.org/t/p/w500/3aKvAaZ4V9QKiqBFUVwyfXdATNU.jpg', 2025, 0, 0, '2026-06-08 06:32:53.72178', 'JP');
INSERT INTO public.movies VALUES (4534, 1104844, '극장판 블루 록 -에피소드 나기-', '["Animation", "Action", "Drama"]', 'Shunsuke Ishikawa', '["Nobunaga Shimazaki", "Yuma Uchida", "Kazuyuki Okitsu", "Kazuki Ura", "Tasuku Kaito"]', '“귀찮아”가 말버릇인 고등학교 2학년, ‘나기 세이시로’는 하루하루를 무기력하게 살고 있었다. 축구로 전 세계 제패를 꿈꾸는 동급생 ‘미카게 레오’가 그의 재능을 찾아내기 전까지는. ‘레오’의 권유로 축구를 시작하게 된 ‘나기’는 압도적인 축구 센스를 발휘하고 어느 날, 그들에게 ‘블루 록’ 프로젝트 초대장이 도착한다. 그곳에서 ‘이사기 요이치’, ‘바치라 메구루’, ‘이토시 린’ 등, 전국에서 선별된 스트라이커들이 기다리고 있는데…', 'https://image.tmdb.org/t/p/w500/yN773yRQjwG6KPjUGqBsmiLfKom.jpg', 2024, 0, 0, '2026-06-08 06:32:56.465941', 'JP');
INSERT INTO public.movies VALUES (4535, 1641014, 'SONE-053引っ越ししたマンションの隣人は絶倫元カレだった…過去をネタに揺すられ寝取られ夫のそばで他人棒イキしちゃう新婚妻', '["Drama"]', 'Kitorune Kawaguchi', '["Riri Nanatsumori"]', NULL, 'https://image.tmdb.org/t/p/w500/6930oFTiS87wj2S1q8uDj8GwJ9S.jpg', 2024, 0, 0, '2026-06-08 06:32:57.140196', 'JP');
INSERT INTO public.movies VALUES (4536, 143663, '黒薔薇夫人', '["Drama", "Horror"]', 'Shōgorō Nishimura', '["Naomi Tani", "Haruka Tajima", "Keijirō Shiga", "Mami Yuki", "Tesshō Furukawa"]', NULL, 'https://image.tmdb.org/t/p/w500/lP4fqX7aty3g9nObe9Xqlgqzt9d.jpg', 1978, 0, 0, '2026-06-08 06:32:57.816823', 'JP');
INSERT INTO public.movies VALUES (4368, 383045, '욕망의 독: 중독', '["Mystery", "Thriller"]', 'Yoon Yeo-chang', '["Kim Sun-young", "Hong Kyung-in", "Lee Jeong-woo", "Park Se-jin", "Lee Seol-gu"]', '‘마음 편한 정신과’를 운영하는 잘 나가는 정신과 의사 ‘준상’. 그 누구보다도 냉철하게 환자들을 치료하는 그에게는 지울 수 없는 상처가 있다. 과거에 부인이 강간을 당해 자살하는 장면을 눈 앞에서 목격한 것. 그 이후 씻을 수 없는 죄책감과 슬픔으로 불면증에 시달리던 그에게 치명적인 매력의 미녀 환자 ‘지수’가 찾아온다. 자신이 사랑하는 모든 남자들이 죽었다고 운을 뗀 그녀는 자신을 늘 지켜보는 존재가 있다며 ‘준상’을 유혹한다. 한편, 얼마 전 일어난 살인사건에 ‘지수’가 관계되어 있음을 직감한 형사는 ‘준상’에게 그녀의 진료 기록을 요청하는데… 그 끝을 알 수 없는 위험한 사랑에 빠져든다!', 'https://image.tmdb.org/t/p/w500/fExG9lgSbCRpW9E74LYFXta2Ruj.jpg', 2014, 0, 0, '2026-06-08 06:30:48.899524', 'KR');
INSERT INTO public.movies VALUES (4528, 466991, '迷宮', '["Adventure", "Sci-Fi", "Horror"]', 'Yonosuke Minamoto', '["Takeshi Maya", "Ryoka Yuzuki", "Ayako Takaishi", "Hitoe Ootake", "Hitomi Shiraishi"]', NULL, 'https://image.tmdb.org/t/p/w500/nIZSg8kVmOcm37JSVZWv9NhlpLH.jpg', 1996, 0, 0, '2026-06-08 06:32:51.449231', 'JP');
INSERT INTO public.movies VALUES (4530, 256522, '레이프 좀비: 러스트 오브 더 데드 2', '["Horror", "Comedy"]', 'Naoyuki Tomomatsu', '["Alice Ozawa", "Asami", "Saya Kobayashi", "Yui Aikawa", "Ayumi Kuroki"]', '알 수 없는 바이러스로 인해 전 세계 인구의 90%가 ''레이프 좀비''가 된다. 그러나 일본 아키하바라의 일부 남성들은 감염되지 않은 것으로 밝혀진다. 이 남자들은 좀비들과 함께 욕망을 채우기 위해 살아남은 젊은 여성들의 피와 살을 쫓는다. 여성 생존자들은 종말론적인 일본에서 살아남기 위해 싸워야 한다.', 'https://image.tmdb.org/t/p/w500/vMUSXLpKuHAaf5UFPSiLW18whQq.jpg', 2013, 0, 0, '2026-06-08 06:32:52.948988', 'JP');
INSERT INTO public.movies VALUES (4532, 223319, 'LSD -ラッキースカイダイアモンド-', '["Horror", "Sci-Fi"]', 'Izo Hashimoto', '["Naoko Amihama", "Reiko Nakamura", "Shiro Sano"]', NULL, 'https://image.tmdb.org/t/p/w500/kYTHzZpgnzhea5Trp3evcxSEdTG.jpg', 1989, 0, 0, '2026-06-08 06:32:55.14375', 'JP');
INSERT INTO public.movies VALUES (4533, 548, '라쇼몽', '["Crime", "Drama", "Mystery"]', 'Akira Kurosawa', '["Toshirō Mifune", "Machiko Kyō", "Takashi Shimura", "Masayuki Mori", "Minoru Chiaki"]', '전란이 난무하는 헤이안 시대, 폭우가 쏟아지는 라생문의 처마 밑에서 나뭇꾼과 스님이 심각한 표정으로 생각에 잠겨 있다. 잠시 비를 피하러 그곳에 들른 한 남자. 이들은 이 남자를 상대로 최근에 그 마을에 있었던 기묘한 사건을 들려준다. 사건의 배경은 녹음이 우거진 숲 속. 사무라이 타케히로가 자신의 아내 마사코와 함께 숲 속을 지나고 있었다. 산적 타조마루는 그들 앞에 나타나 속임수로 타케히로를 포박하고 마사코를 겁탈한다. 오후에 그 숲에 들어선 나뭇꾼은 타케히로의 가슴에 칼이 꽂혀있는 것을 발견하고 관청에 신고한다. 타조마루는 체포되고, 행방이 묘연했던 마사코도 불려와 관청에서 심문이 벌어지는데...', 'https://image.tmdb.org/t/p/w500/gpYADlpkoFTChBLjIrZU7hxDKz1.jpg', 1950, 0, 0, '2026-06-08 06:32:55.808689', 'JP');
INSERT INTO public.movies VALUES (4540, 26662, '명탐정 코난: 베이커가의 망령', '["Animation", "Mystery", "Sci-Fi"]', 'Kenji Kodama', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Akira Kamiya", "Hideyuki Tanaka"]', 'IT 회사 신드라 컴퍼니가 개발한 ‘코쿤’이라는 체험 시뮬레이션 게임 시연회에 참석한 코난. 게임이 시작되기 몇 분 전, 게임개발자인 카시무라가 ‘JTR’이라는 의문의 다잉 메시지를 남기고 살해 당한다. 메시지를 본 코난은 가상 게임 속에 살인 동기가 있을 것으로 직감하고 50명의 아이들과 함께 게임에 참여하게 된다. 하지만 인공 두뇌 ‘노아의 방주’의 서버 침입으로 게임은 통제불능의 상태에 빠지게 되고, ‘노아의 방주’는 19세기 전설적인 살인마 ‘잭 더 리퍼’를 이기지 못하면 게임에 참가한 50명의 아이들의 뇌를 전부 손상시키겠다고 협박하는데……', 'https://image.tmdb.org/t/p/w500/vpSDbgqaGblSvtVH5wSZAryTSfq.jpg', 2002, 0, 0, '2026-06-08 06:33:00.556473', 'JP');
INSERT INTO public.movies VALUES (4542, 1050390, '監禁逃亡　美しき獲物たち', '["Drama", "Thriller"]', 'Shinsuke Inoue', '["Reiko Hayama", "Koji Mizukami", "Mari Mizuki", "Junko Takazawa", "Fuyukaze Matsumura"]', NULL, 'https://image.tmdb.org/t/p/w500/cHlmO3svm2WKwIOHU1Mq9gCMj8n.jpg', 1993, 0, 0, '2026-06-08 06:33:02.949028', 'JP');
INSERT INTO public.movies VALUES (4543, 1333100, '극장판 진격의 거인 완결편 더 라스트 어택', '["Animation", "Action", "Adventure", "Drama"]', 'Yuichiro Hayashi', '["Yuki Kaji", "Yui Ishikawa", "Marina Inoue", "Hiroshi Kamiya", "Yu Shimamura"]', '거인의 위협으로부터 몸을 지키기 위해 거대한 벽을 쌓고 그 안에서 숨을 죽이고 살고 있는 인류. 백 년의 평화는 초대형 거인의 습격으로 파괴됐고, 어머니를 잃은 소년 엘런 예거는 모든 거인을 없앨 것을 맹세하고 거인과 싸우는 조사병단의 일원이 되었다. 글자 그대로 목숨을 건 싸움 속에서 엘런 예거는 자신도 거인이 되는 능력을 손에 넣었고 인류의 승리에 공헌하면서 조금씩 세계의 진실에 가까워지고 있었다. 이윽고 시간이 흘러 벽 밖으로 나간 엘런은 조사병단의 동료들과 갈라섰고 어떤 무시무시한 계획을 실행한다. 수많은 거인을 이끌고, 이 세계의 살아있는 모든 것들을 짓밟는 「땅울림」. 미카사와 아르민을 시작으로 남겨진 자들은 세계를 멸망시키려 하는 엘런을 막기 위해 최후의 싸움에 나선다.', 'https://image.tmdb.org/t/p/w500/nNjXyrutNl6fAAEFUvOsnC7tjgC.jpg', 2024, 0, 0, '2026-06-08 06:33:03.609466', 'JP');
INSERT INTO public.movies VALUES (4541, 292047, '도쿄 느와르', '["Drama"]', 'Masato Ishioka', '["Takami Yoshimoto", "Aimi Nakamura", "Kimika Yoshino", "Aya Seki", "Go Riju"]', 'Part 1 BIRTHDAY  인터넷 회사에서 12년 동안 일해 온 기타지마 (요시모토 다카미 분).  회사를 마치고 귀가하던 어느 날 그녀는 베일에 싸인 헤어 디자이너를 우연히 만나게 되고 그는 초라한 행색의 기타지마를 아름다운 여인으로 변신시킨다.  그리고 그녀에게 고급 호텔에서 남자를 만나는 일을 해보라고 권유한다.  Part2 GIRL''S LIFE  남자친구 토모야한테 버림받은 대학생 마유키(나카무라 아이미 분)는 안마 시술소에서 3개월째 아르바이트를 하고 있다.  이러한 생활을 통해 마음의 안정을 찾고 있던 미유키 앞에 토모야가 찾아와 용서를 구하고 그의 말과 태도로 인해 그녀의 감정은 다시 요동치기 시작한다.  Part 3 NIGHT LOVERS  나오(요시노 키미카 분)는 자신 앞에서 갑작스레 사라진 남자친구 유지를 찾기 위해 안간힘을 쓴다.  애타게 남자친구를 찾던 나오는 우연히 인터넷에서 자신과 이름이 같은 여성을 발견하게 되고 그 여자의 글을 읽으며 자신과 유지의 관계에 대해 깊은 고민에 빠지게 된다.', 'https://image.tmdb.org/t/p/w500/jevS92LciqEkkdfFg68HsPXeNH7.jpg', 2004, 0, 0, '2026-06-08 06:33:01.235495', 'JP');
INSERT INTO public.movies VALUES (4544, 610150, '드래곤볼 슈퍼: 슈퍼 히어로', '["Animation", "Sci-Fi", "Action"]', 'Tetsuro Kodama', '["Masako Nozawa", "Toshio Furukawa", "Yuko Minaguchi", "Hiroshi Kamiya", "Mamoru Miyano"]', '레드리본군은 손오공의 손에 절멸했다. 그러나 레드리본군의 정신을 계속해서 이어받고 있던 몇몇 사람들이 궁극의 인조인간 감마1과 감마2를 만들었다. 이들 두 인조인간은 자신을 ‘슈퍼 히어로즈’라 부른다. 이들이 피콜로와 손오반을 공격하기 시작하는데… 레드리본군의 새로운 목표는 무엇인가?', 'https://image.tmdb.org/t/p/w500/iJIqr4ucD4zLDlxVoGs0iRJkOZw.jpg', 2022, 0, 0, '2026-06-08 06:33:04.283787', 'JP');
INSERT INTO public.movies VALUES (4548, 10228, '극장판 포켓몬스터: 뮤츠의 역습', '["Animation", "Family", "Adventure", "Fantasy", "Action"]', 'Kunihiko Yuyama', '["Rica Matsumoto", "Ikue Otani", "Mayumi Izuka", "Satomi Korogi", "Yuji Ueda"]', '세계 최강의 포켓몬을 만들겠다는 생각을 한 과학자들은 뮤의 머리카락으로 뮤츠라는 복제를 만들어낸다. 그러나 뮤츠는 뮤와는 달리 흉폭한 성격으로 인간들을 증오하는 마음을 가지고 있다. 또한 자신을 이용하여 세계를 정복하려는 로켓단의 두목을 뒤로 하고 뉴아일랜드 성으로 향한다. 스스로 가장 강한 포켓몬 트레이너라고 칭하던 뮤츠는 다른 트레이너들의 포켓몬들을 납치하여 원래의 포켓몬보다 뛰어난 실력을 가진 복제 포켓몬을 만들어내는데...', 'https://image.tmdb.org/t/p/w500/w1SlfdoU144Sl4c8rXG9kw5jiuq.jpg', 1998, 0, 0, '2026-06-08 06:33:06.950769', 'JP');
INSERT INTO public.movies VALUES (4550, 1047041, '명탐정 코난: 흑철의 어영', '["Animation", "Action", "Crime", "Mystery"]', 'Yuzuru Tachikawa', '["Minami Takayama", "Wakana Yamazaki", "Rikiya Koyama", "Megumi Hayashibara", "Shuichi Ikeda"]', '인터폴의 최첨단 정보 해양 시설인 퍼시픽 부이. 일본과 유럽의 CCTV 정보를 확인할 수 있을 뿐 아니라, 장기 수배범이나 유괴당한 피해자를 전 세계에서 찾아낼 수 있는 전연령 인식이라는 획기적인 AI 기술을 개발 중이다. 그러던 중 독일에서 검은 조직에 의해 유로폴 직원이 살해되는 사건이 발생하고 뒤를 이어 전연령 인식의 핵심 기술자가 납치된다. 나이와 상관없이 안면 인식이 가능한 기술이 검은 조직의 손에 들어가면 독약 APTX4869 개발 후 사망한 것으로 알려진 코드명 셰리이자 하이바라 아이도 위험하게 되는데...', 'https://image.tmdb.org/t/p/w500/wBdLreR2YI2ZAYGk7c4Zy2qJU2d.jpg', 2023, 0, 0, '2026-06-08 06:33:08.303063', 'JP');
INSERT INTO public.movies VALUES (4552, 1673077, 'SONE-311 肉体はびくびく身闷え、体液だらだら垂れ流す、河北彩伽がケダモノ覚醒した强媚薬入りオイルマッサージ', '[]', NULL, '["Saika Kawakita"]', NULL, 'https://image.tmdb.org/t/p/w500/xUtzlU5OZMRb5sSswBdQAuglUJt.jpg', 2024, 0, 0, '2026-06-08 06:33:10.385321', 'JP');
INSERT INTO public.movies VALUES (4378, 622668, '오피스텔: 잘하는애들로', '["Romance"]', 'Chun Sung-joon', '["Yoo Sul-young", "Kim Min-jeong", "Jo Wan-jin", "Min Do-yoon", "Hae Il"]', '잘 나가는 오피스텔 걸 주희는 오늘도 자신의 몸과 돈을 교환한다. 오피스텔 에이스였던 주희는 갑자기 예약 전화가 없어지는데.. 그녀의 친구 지영은 몸이 두 개라도 모자랄 정도로 예약이 차고 넘친다. 그런 지영이 마냥 부럽던 주희는 오랜만에 찾은 손님으로부터 지영이 몰래 손님들에게 파격적인 서비스를 제공한다는 이야기를 듣게되고 자신의 손님들을 빼 간 것에 분노한 주희는 지영과 서비스 경쟁이 붙는다. 지영과 주희의 서비스 경쟁에 손님들은 황홀할 지경이지만 주희와 지영은 너무 힘들어 똑 같은 서비스만 하기로 합의를 하는데…그러던 중 갑자기 예약이 안들어와 무료하던 중 청천벽력 같은 소식을 듣는데 같은 오피스텔에서 일하던 영주가 옆 오피스텔로 넘어가 파격적인 서비스로 예약이 폭주하고 있다는 것이다. 고민하던 주희와 지영은 영주에게서 손님들을 되찾아 오기 위해 힘을 합치기로 한다. 2:1 황제 서비스라는 자극적이고 파격적인 서비스로 다시 손님들의 예약 전화가 끊이질 않게 되는데…', 'https://image.tmdb.org/t/p/w500/AhA0jM9bcEgQg7Y6wwZSMWKztgI.jpg', 2019, 0, 0, '2026-06-08 06:30:57.265769', 'KR');
INSERT INTO public.movies VALUES (4549, 47002, '러브레터', '["Drama", "Romance"]', 'Shunji Iwai', '["Miho Nakayama", "Etsushi Toyokawa", "Miki Sakai", "Takashi Kashiwabara", "Bunjaku Han"]', '사랑했던 연인 후지이 이츠키가 죽은 지 2년. 그의 약혼녀 와타나베 히로코는 여전히 그를 잊지 못하고 있다. 추모식 날, 히로코는 그의 중학교 졸업 앨범에서 지금은 이미 국도가 되어 버린 그의 중학교 시절 주소를 발견한다. 그리운 마음에 안부를 묻는 편지를 띄우는 히로코. 하지만 며칠 후, 후지이 이츠키로부터 거짓말처럼 답장이 날아오고, 히로코는 편지를 보낸 그 사람이 그와 같은 이름을 지닌 여자이며 그의 중학교 동창이라는 것을 알게 된다. 후지이는 히로코의 부탁으로 중학교 시절을 추억하고, 아름다웠던 중학교 시절의 이야기가 히로코에게 편지를 통해 들려진다.', 'https://image.tmdb.org/t/p/w500/ou96ZpfHuVPM8ur8EuJdmOX3WA5.jpg', 1995, 0, 0, '2026-06-08 06:33:07.622404', 'JP');
INSERT INTO public.movies VALUES (4556, 1173908, 'シン・交わる体液、濃密セックス完全ノーカット5本番 河北彩花', '["Documentary"]', 'Mon ℃', '["Saika Kawakita", "Hiromu Sawano", "Samejima", "Taku Yoshimura", "Yuto Kuroda"]', NULL, 'https://image.tmdb.org/t/p/w500/cz749esLPUONi5zlY4XqTFXAEvs.jpg', 2022, 0, 0, '2026-06-08 06:33:13.101844', 'JP');
INSERT INTO public.movies VALUES (4558, 625976, '분화구의 두 사람', '["Drama", "Romance"]', 'Haruhiko Arai', '["Tasuku Emoto", "Kumi Takiuchi", "Akira Emoto"]', '결혼을 앞둔 ‘나오코’는 전 연인이었던 ‘켄지’와 재회하고, 과거 함께 촬영했던 누드 사진을 발견한 이들은 단 하룻밤만 예전의 관계로 돌아가 보기로 한다. ‘나오코’의 약혼자가 출장에서 돌아오기까지 남은 시간은 단 5일, 욕망과 죄책감에 휩싸인 일탈의 종착지는 어디일까?', 'https://image.tmdb.org/t/p/w500/2Xi8RdqWfSAbaKCuDg7u2tvRVnf.jpg', 2019, 0, 0, '2026-06-08 06:33:14.601583', 'JP');
INSERT INTO public.movies VALUES (4411, 1543993, '순례자들은 왜 돌아오지 않는가', '["Animation", "Sci-Fi", "Adventure", "Drama", "Fantasy"]', 'Heo Pyoung-kang', '["Kim Hyang-gi", "Park Ji-hu", "Lee Joo-young"]', '혐오와 차별이 존재하지 않는 ''마을''의 아이들은 고통과 슬픔은 조금도 모른 채로 자란다. 아이들은 18세가 되면 마을 밖으로 순례를 다녀오는데 일부는 영영 귀환하지 않는다. 마을이 이토록 완벽한데, 왜 돌아오지 않는 것일까. 호기심을 억누르지 못한 데이지는 순례자들을 따라서 ''시초지''를 떠돈다. 여전히 마을에서 안온한 일상을 보내던 소피는 잊고 있던 데이지와의 기억을 되찾고, 데이지가 왜 시초지로 향했는지 고심한다. 인간성의 회복은 인식으로부터 시작한다. 첨단의 과학이 개성을 거세하고 인간을 물화한 시대, 인류는 아이러니하게도 결함과 다름을 인지해야만 공감과 사랑을 체화할 수 있다. 주어진 평화를 떨치고 능동적인 삶을 선택해 떠나온 아이들은 종종 괴로울 것이다. 다만 더 자주 행복하다고 느낄 것이다.', 'https://image.tmdb.org/t/p/w500/57SlsLysyEY2gJnR1vhCqXmGN9G.jpg', 2026, 0, 0, '2026-06-08 06:31:21.900434', 'KR');
INSERT INTO public.movies VALUES (4557, 39323, '드래곤볼 Z: 단 한 명의 최종 결전! 프리저에게 도전한 Z전사', '["Animation", "Action", "Sci-Fi", "Drama", "Fantasy"]', 'Mitsuo Hashimoto', '["Masako Nozawa", "Kazuyuki Sogabe", "Yuko Mita", "Takeshi Watabe", "Kozo Shioya"]', '버독은 프리저의 명령에 따라 동료 넷과 함께 행성 카낫사를 침공하여 멸망시킨 후 쉬고 있다가 최후로 살아남은 카낫사인 토오로에게 기습당한 후 일종의 예지 능력을 얻게 된다. 토오로는 버독에게 ''네게 미래를 볼 수 있는 환상의 주먹을 날렸다'', ''너희들은 우리들처럼 멸망할 운명이다''라는 말을 남기며 버독 일행의 공격을 받고 쓰러졌다. 그 직후 갑자기 버독은 머리에 통증을 느끼며 쓰러진다. 그 후 회복장치 속에서 치료를 받으며 계속 행성 베지터가 멸망하는 미래와 아직 갓난아기인 자기 아들 카카로트의 미래를 보게 된다. 본인은 그 의미도 잘 이해하지 못하고 그냥 이상한 꿈 정도로 여기고 있다가 앞서 동료들이 정벌하러 간 미트 별로 따라갔다가 동료들의 죽음을 목도하고 거기서 아직 살아남은 토마로부터 프리저가 사이어인을 말살시키려고 한다는 것을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/9Z5a7VKZiXkPE9i04qizjHKPiAf.jpg', 1990, 0, 0, '2026-06-08 06:33:13.906456', 'JP');
INSERT INTO public.movies VALUES (4559, 1311034, '劇場版「鬼滅の刃」無限城編 2', '["Animation", "Action", "Fantasy"]', 'Haruo Sotozaki', '["Natsuki Hanae", "Yoshitsugu Matsuoka", "Hiro Shimono", "Akari Kito"]', NULL, 'https://image.tmdb.org/t/p/w500/8uYxx23KyDnbDkA3eQSNECVeOiS.jpg', NULL, 0, 0, '2026-06-08 06:33:15.279435', 'JP');
INSERT INTO public.movies VALUES (4560, 4977, '파프리카', '["Animation", "Sci-Fi", "Thriller"]', 'Satoshi Kon', '["Megumi Hayashibara", "Tohru Emori", "Katsunosuke Hori", "Toru Furuya", "Akio Otsuka"]', '29살의 정신과 치료사 치바 아츠코에게는 또 하나의 자아가 있다. 바로 18살의 대담무쌍한 꿈 탐정 파프리카이다. 파프리카는 사람들의 꿈속에 들어가 그들의 무의식에 동조함으로써 환자의 불안과 신경증의 원인을 밝혀내고 치료한다. 어느 날, 치바의 연구소에서 개발 중이던 혁명적인 정신치료장치 DC-MINI의 프로토타입이 도난 당하고 조수마저 실종된다. 장치를 찾아나선 치바는 무서운 음모가 진행되고 있음을 알게 된다.', 'https://image.tmdb.org/t/p/w500/apQqEF7xXjPWfjQgRWmxNtyIaMd.jpg', 2006, 0, 0, '2026-06-08 06:33:16.078492', 'JP');
INSERT INTO public.movies VALUES (4383, 1306816, '좀비딸', '["Comedy", "Drama"]', 'Pil Gam-seong', '["Cho Jung-seok", "Lee Jung-eun", "Cho Yeo-jeong", "Yoon Kyung-ho", "Choi Yu-ri"]', '댄스 열정을 불태우는 사춘기 딸 수아와 함께 티격태격 일상을 보내는 맹수 전문 사육사 정환. 어느 날 전 세계를 강타한 좀비 바이러스에 감염된 딸 수아를 지키기 위해 정환은 어머니 밤순이 사는 바닷가 마을 은봉리로 수아와 함께 향한다. 감염자를 색출해 내려는 사회 분위기 속에서 수아가 어렴풋이 사람 말을 알아듣고, 평소 좋아하던 춤과 할머니 밤순의 따끔한 효자손 맛에 반응하는 모습을 발견한다. 절대 수아를 포기할 수 없는 정환은 호랑이 사육사의 오랜 경험을 살려 좀비딸 트레이닝에 돌입하는데...', 'https://image.tmdb.org/t/p/w500/aASLRiO8p9xLIvG9EHXSyZ71sPl.jpg', 2025, 0, 0, '2026-06-08 06:31:01.006616', 'KR');
INSERT INTO public.movies VALUES (4563, 37797, '귀를 기울이면', '["Animation", "Drama", "Family"]', 'Yoshifumi Kondo', '["Yoko Honna", "Issey Takahashi", "Takashi Tachibana", "Shigeru Muroi", "Minami Takayama"]', '중학교 3학년 시즈쿠는 평소 책을 많이 읽는 소녀. 여름방학, 매번 도서카드에서 먼저 책을 빌려간 세이지란 이름을 발견하고 호기심을 갖는다. 어느 날 지하철 안에서 혼자 탄 고양이를 보게 된다. 신기하게 여긴 시즈쿠는 고양이를 따라가다 골동품 가게에 들어가게 되고, 그곳에서 주인 할아버지와 손자를 보게 된다. 그 손자는 다름 아닌 아마사와 세이지, 사춘기의 두 사람은 점차 서로의 사랑에 대해 알게 된다. 시즈쿠는 바이올린 장인을 자신의 장래로 확실히 정한 세이지를 보면서 자신의 꿈과 미래를 진지하게 고민하게 된다. 그 후 이탈리아 연수를 간 세이지가 돌아올 때 까지 작가가 되고자 도전해 보기로 하는데...', 'https://image.tmdb.org/t/p/w500/kssrs4tPYXmfciITAQGLfh9lyJX.jpg', 1995, 0, 0, '2026-06-08 06:33:19.415542', 'JP');
INSERT INTO public.movies VALUES (4565, 169999, '蜜月', '["Drama"]', 'Hōjin Hashiura', '["Koichi Sato", "Kumi Nakamura", "Toru Masuoka", "Hirotaro Honda", "Ikko Suzuki"]', NULL, 'https://image.tmdb.org/t/p/w500/d6wa6VrTqmcDcDbZrVWI0H9QdJr.jpg', 1984, 0, 0, '2026-06-08 06:33:20.809668', 'JP');
INSERT INTO public.movies VALUES (4567, 126963, '드래곤볼 Z 극장판 14: 신들의 전쟁', '["Animation", "Action", "Sci-Fi"]', 'Masahiro Hosoda', '["Masako Nozawa", "Koichi Yamadera", "Masakazu Morita", "Ryo Horikawa", "Hiromi Tsuru"]', '프리더, 셀, 그리고 마인부우와의 대결에서 모두 승리한 손오공 일행덕분에 지구엔 평화가 찾아왔다. 하지만 몇 년 후, 머나먼 우주 저편에서 ''파괴''를 관장하는 전 우주 최강의 존재 파괴신 비루스가 39년 만에 잠에서 깨어나게 되고, 또 다시 심상치 않은 기운이 감돈다.  비루스는 부르마의 생일을 맞아 모처럼 한자리에 모인 손오공 일행을 찾아가 전설의 전사 초사이야인 갓을 내놓지 않으면 지구를 파괴시켜 버린다고 위협한다. 손오반, 베지터를 비롯해 모두 비루스의 압도적인 파워에 속수무책으로 패배하는 가운데, 초사이야인 갓으로 변신에 성공한 오공은 지구의 운명을 건 최후의 대결을 펼치게 되는데...', 'https://image.tmdb.org/t/p/w500/7AuK9jwCSpt9bgwPjskGRMA5qhP.jpg', 2013, 0, 0, '2026-06-08 06:33:22.16649', 'JP');
INSERT INTO public.movies VALUES (268, 4935, '하울의 움직이는 성', '["Fantasy", "Animation", "Adventure"]', 'Hayao Miyazaki', '["Chieko Baisho", "Takuya Kimura", "Akihiro Miwa", "Tatsuya Gashûin", "Ryunosuke Kamiki"]', '19세기 말 마법과 과학이 공존하고 있는 세계 앵거리. 소피는 돌아가신 아버지의 모자상점에서 쉴틈없이 일하는 18살 소녀이다. 어느 날 오랫만에 마을로 나간 소피는 우연히 하울을 만나게 된다. 하울은 왕실 마법사로서 핸섬하지만 조금 겁이 많은 청년이다. 황무지 마녀는 두 사람의 사이를 오해, 주문을 걸어 소피를 90살의 늙은 할머니로 만들어 버린다. 가족을 걱정한 소피는 집을 나오게 되고 황무지를 헤매다가 하울이 사는 성에서 가정부로 낯선 생활을 시작한다. 4개의 다리로 걷는 기괴한 움직이는 성 안에서 하울과 소피의 기묘한 사랑과 모험이 시작되는데...', 'https://image.tmdb.org/t/p/w500/xiz6TiSduvR1U3VLfWVlBEdT9fO.jpg', 2004, 0, 0, '2026-06-06 13:25:06.39704', 'JP');
INSERT INTO public.movies VALUES (4562, 1012201, '극장판 하이큐!! 쓰레기장의 결전', '["Animation", "Comedy"]', 'Susumu Mitsunaka', '["Ayumu Murase", "Kaito Ishikawa", "Yuki Kaji", "Yuichi Nakamura", "Satoshi Hino"]', '봄철 고교 배구대회 미야기현 대표 결정전. 1회전과 2회전에서 우승 후보를 차례로 꺾은 카라스노 고등학교는 마침내 3회전에서 인연의 라이벌 네코마 고등학교와 맞붙게 된다. 공식 경기에서 처음으로 대결하는 두 고등학교, 통칭 까마귀 VS 고양이 ‘쓰레기장의 결전’. 약속의 땅에서 ‘한 번 더’가 없는 싸움이 드디어 시작된다!', 'https://image.tmdb.org/t/p/w500/d0jCRbTdJPEvGaboeZ3fvCUVrNT.jpg', 2024, 0, 0, '2026-06-08 06:33:18.74398', 'JP');
INSERT INTO public.movies VALUES (4564, 1363974, '극장판 전생했더니 슬라임이었던 건에 대하여 창해의 눈물편', '["Animation", "Fantasy", "Adventure", "Comedy"]', 'Yasuhito Kikuchi', '["Miho Okasaki", "Mao Ichimichi", "Tomoaki Maeno", "Makoto Furukawa", "Sayaka Senbongi"]', '마물의 나라 【템페스트】의 개국제를 마친 리무루 일행은 엘프의 대국 【마도 왕조 살리온】의 천제 에르메시아의 초대를 받아 그녀가 소유하고 있는 리조트 섬을 방문한다. 리무루 일행이 잠깐 바캉스를 만끽하는 사이 유라라는 의문의 여성이 나타나는데──. 끝없이 펼쳐진 창해를 무대로 새로운 사건이 일어난다!', 'https://image.tmdb.org/t/p/w500/y6EdV6tnfX0jd3I0rtw5U9jpnpi.jpg', 2026, 0, 0, '2026-06-08 06:33:20.122413', 'JP');
INSERT INTO public.movies VALUES (4568, 1675042, '영화 러브 라이브! 하스노소라 여학원 스쿨 아이돌 클럽 Bloom Garden Party', '["Animation"]', 'Go Kurosaki', '["Nozomi Nirei", "Kokona Nonaka", "Kanna Kan", "Nina Hanamiya", "Sasaki Kotoko"]', NULL, 'https://image.tmdb.org/t/p/w500/eV9i7GRcLbCzraWN4PdvRKKqtZv.jpg', 2026, 0, 0, '2026-06-08 06:33:22.835833', 'JP');
INSERT INTO public.movies VALUES (4572, 1083862, '레지던트 이블: 데스 아일랜드', '["Action", "Animation", "Sci-Fi", "Horror"]', 'Eiichiro Hasumi', '["Matthew Mercer", "Nicole Tompkins", "Kevin Dorman", "Stephanie Panisello", "Erin Cahill"]', '샌프란시스코의 집단 좀비 사건을 파헤치고자 앨커트래즈 섬으로 향하는 크리스와 중요한 납치 사건을 추적하는 레온의 사투를 그린 애니메이션', 'https://image.tmdb.org/t/p/w500/6YjwroiDhUODrgSp87u0rylpLTd.jpg', 2023, 0, 0, '2026-06-08 06:33:26.692202', 'JP');
INSERT INTO public.movies VALUES (4574, 283566, '신 에반게리온 극장판 :ll', '["Animation", "Action", "Sci-Fi", "Drama"]', 'Katsuichi Nakayama', '["Megumi Ogata", "Yuko Miyamura", "Maaya Sakamoto", "Megumi Hayashibara", "Kotono Mitsuishi"]', '‘에반게리온’ 신극장판 시리즈의 제4부이자 완결편  미사토가 이끄는 반네르프 조직 ‘빌레’는 코어화로 붉게 물든 파리 구시가에 있다.  기함 AAA 분더에서 선발대가 강하하여, 남겨져 있던 봉인주에 안착한다.  복원 작전의 작업 가능 시간은 고작 720초.  결사의 작전 수행 중 ‘네르프’의 EVA가 대량으로 무리를 이루고 접근하여,  마리의 개(改) 8호기가 요격을 개시한다.  한편 신지, 아스카, 아야나미 레이 (가칭) 세 사람은 일본의 대지를 떠돌고 있다…….', 'https://image.tmdb.org/t/p/w500/vpfX1mGVobWlrUGqEzbA2RNPdZF.jpg', 2021, 0, 0, '2026-06-08 06:33:28.0496', 'JP');
INSERT INTO public.movies VALUES (4576, 111934, '콘크리트', '["Horror", "Crime"]', 'Hiromu Nakumura', '["Miki Komori", "Katsuya Kobayashi", "Masanori Machida", "Kensuke Mano", "Mika Mifune"]', '여고생 콘크리트 살인사건을 다룬 영화', 'https://image.tmdb.org/t/p/w500/lSJKjUfVCeTlJ1TSKAh2FgYkoDG.jpg', 2004, 0, 0, '2026-06-08 06:33:29.402944', 'JP');
INSERT INTO public.movies VALUES (4577, 34433, '드래곤볼 Z 극장판 8: 불타올라라!! 열전! 열전! 초격전!', '["Animation", "Sci-Fi", "Action"]', 'Shigeyasu Yamauchi', '["Bin Shimada", "Masako Nozawa", "Ryo Horikawa", "Iemasa Kayumi", "Takeshi Kusao"]', '셀게임이 시작되기 며칠 전, 계왕은 대계왕에게서 전설의 초사이어인이 남쪽 은하를 습격하고 북쪽 은하를 노리고 있다는 말을 듣고 두려움에 빠진다.  한편, 한가롭게 벚꽃놀이 중이던 베지터 일행 앞에 파라가스라는 사이어인이 나타나 신 혹성 베지터를 건설해서 베지터를 왕으로 추대하고 싶다며 초대를 하는데...', 'https://image.tmdb.org/t/p/w500/pYfYIdlGN5ni1zhh0Xc7Y1sf0x6.jpg', 1993, 0, 0, '2026-06-08 06:33:30.222365', 'JP');
INSERT INTO public.movies VALUES (419, 539, '싸이코', '["Horror", "Thriller", "Mystery"]', 'Alfred Hitchcock', '["Anthony Perkins", "Janet Leigh", "Vera Miles", "John Gavin", "Martin Balsam"]', '마리온 크레인은 그녀의 애인 샘과 결혼하길 원하지만 샘은 빚을 갚을 때까지 기다리라고 말한다. 그래서 그녀는 자신이 다니고 있는 회사 사장이 은행에 입금하라고 맡긴 돈을 들고 도망친다. 도주 첫날 밤 묵게 된 도로변의 낡은 모텔 주인인 노만 베이츠는 그녀에게 친절하게 대해주며 자신은 모텔 바로 뒤쪽 저택에서 몸이 불편한 어머니와 함께 살고 있다고 말한다. 잠자리에 들기 전 마리온이 샤워를 하는 도중, 난데없이 검은 형상이 욕실에 나타나고 마리온은 실종된다. 마리온을 찾기 위해 그녀의 언니 릴라와 샘, 그리고 보험회사 측에서 고용한 탐정 등 세 사람이 추적에 나서는데...', 'https://image.tmdb.org/t/p/w500/vC3P8hH4r3I3fHiRFa1kj6yzeaN.jpg', 1960, 0, 0, '2026-06-06 13:25:11.805922', 'US');
INSERT INTO public.movies VALUES (420, 823464, '고질라 X 콩: 뉴 엠파이어', '["Action", "Adventure", "Sci-Fi"]', 'Adam Wingard', '["Rebecca Hall", "Brian Tyree Henry", "Dan Stevens", "Kaylee Hottle", "Alex Ferns"]', '두 타이탄의 전설적인 대결 이후 할로우 어스에 남은 콩은 드디어 애타게 찾던 동족을 발견하지만 그 뒤에 도사리고 있는 예상치 못한 위협에 맞닥뜨린다. 한편, 깊은 동면에 빠진 고질라는 알 수 없는 신호로 인해 깨어나고 푸른 눈의 폭군 스카 킹의 지배 아래 위기에 처한 할로우 어스를 마주하게 된다. 할로우 어스는 물론, 지구상에도 출몰해 전세계를 초토화시키는 타이탄들의 도발 속에서 고질라와 콩은 사상 처음으로 한 팀을 이뤄 반격에 나서기로 하는데…', 'https://image.tmdb.org/t/p/w500/4z1VMmlxHrziG45901esjB4dpIa.jpg', 2024, 0, 0, '2026-06-06 13:25:11.808425', 'US');
INSERT INTO public.movies VALUES (436, 1357633, '나 혼자만 레벨업 -리어웨이크닝-', '["Action", "Adventure", "Fantasy", "Animation"]', 'Shunsuke Nakashige', '["Taito Ban", "Genta Nakamura", "Haruna Mikawa", "Reina Ueda", "Daisuke Hirakawa"]', '다른 차원과 이쪽 세계를 이어 주는 통로인 ''게이트가'' 갑자기 발생한 지 10여 년. 세계에는 ''헌터''라고 불리는 초인적인 힘에 각성한 사람들이 출현했다. 헌터는 그 힘을 사용해 게이트 안의 던전을 공략하고 대가를 받는 것을 생업으로 하고 있는데 강자들만 모인 헌터들 중 ''성진우''는 인류 최약병기라 불리는 저랭크 헌터로서 생활하고 있었다. 어느 날, 저랭크 던전에 숨겨진 고랭크 이중 던전에서 빈사의 중상을 입은 성진우의 눈앞에 수수께끼의 퀘스트창이 나타났다. 죽음의 순간, 퀘스트를 수락하기로 결심한 성진우는 자신만 ''레벨업''할 수 있게 되는데── 전직 퀘스트를 클리어하고 그림자 병사를 부릴 수 있는 ''그림자 군주''가 된 성진우의 앞에 다음 시련으로서 나타난 것은 상급 던전으로 이어지는 레드 게이트였다──', 'https://image.tmdb.org/t/p/w500/vOONcAbFSVCOgct9k4JJPLbPvOi.jpg', 2024, 0, 0, '2026-06-06 13:25:12.559191', 'JP');
INSERT INTO public.movies VALUES (4573, 602063, '바람의 검심 최종장: 더 파이널', '["Action", "Adventure", "History", "Drama"]', 'Keishi Otomo', '["Takeru Satoh", "Emi Takei", "Mackenyu", "Munetaka Aoki", "Yu Aoi"]', '그놈의 빰에 아직 십자 흉터가 있는가? 켄신의 과거를 알고 있는 남자, 에니시. 한때는 가족이었던 그가 사상 최강의 적이 되어 켄신 앞에 서고, 드디어 마지막 전투의 서막이 오른다.', 'https://image.tmdb.org/t/p/w500/dUcxuc0Tlmk3LfxJeKF2AYe2R3h.jpg', 2021, 0, 0, '2026-06-08 06:33:27.366982', 'JP');
INSERT INTO public.movies VALUES (4578, 52795, '극장판 도라에몽: 진구의 마계 대모험 7인의 마법사', '["Family", "Adventure", "Animation", "Sci-Fi", "Fantasy"]', 'Yukiyo Teramoto', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Subaru Kimura", "Tomokazu Seki"]', '집에서는 엄마에게, 학교에선 선생님에게 매일 야단 맞기 일쑤인 불량 초딩 진구.  꾸지람을 참다 못한 진구는 도라에몽의 4차원 마법 주머니에서 ‘만약에 박스’를 꺼내, 현실세계를 상상대로 모든 일이 이뤄지는‘마법의 세계’로 바꿔놓는다.  새로운 세상에서 마법을 즐기던 도라에몽과 진구는 마계의 대마왕이 지구를 손아귀에 넣기 위해 다가오고 있다는 날벼락 같은 소식을 듣게 되는데…  과연 그들은 대마왕의 위협으로부터 지구를 구해낼 수 있을 것인가....!!', 'https://image.tmdb.org/t/p/w500/nCSJG7Rl0ViasVz0ESTA9aLJCSW.jpg', 2007, 0, 0, '2026-06-08 06:33:30.910573', 'JP');
INSERT INTO public.movies VALUES (4583, 39202, '명탐정 코난: 미궁의 십자로', '["Animation", "Mystery", "Adventure"]', 'Kenji Kodama', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Akira Kamiya", "Ryo Horikawa"]', '오사카와 도쿄, 그리고 교토에서 유명한 문화재 도굴단인 ''겐지보타루''의 일원들이 연이어 살해되는 사건이 일어난다. 교토를 방문하고 있던 코난 일행은 그 곳에서 겐지보타루의 소행으로 추측되는 불상 도난 사건을 전해듣고 살인 사건과 연관지어 수사를 시작한다.수사를 위해 고조 다리를 찾은 코난은 그 곳에서 고교생 탐정 헤이지를 만나고, 그와 함께 사건을 조사하기로 하는데...', 'https://image.tmdb.org/t/p/w500/pJSA3b29qK8BTA654w4ibPCSvch.jpg', 2003, 0, 0, '2026-06-08 06:33:35.171056', 'JP');
INSERT INTO public.movies VALUES (806, 10494, '퍼펙트 블루', '["Animation", "Thriller"]', 'Satoshi Kon', '["Junko Iwao", "Rica Matsumoto", "Shiho Niiyama", "Masaaki Okura", "Shinpachi Tsuji"]', '아이돌 소녀 그룹인 Charm의 리더인 미마는 본격적인 연기를 시작하기 위해 아이돌의 그늘을 벗어나려고 하지만,첫 출연작부터 난관에 부딪힌다. 누드 등을 통한 과격적인 홍보로 그녀를 더욱 알리려는 소속사 대표와 미마를 지켜주려고 노력하는 그녀의 담당 매니저의 갈등. 그리고 아직까지도 아이돌로서의 그녀를 그리워하는 팬들. 그 모든 것의 중심에 선 미마는 비록 대사는 한마디에 불과한 단역이지만 그래도 주어진 역할에 충실히 하기 위해 노력한다. 드라마에서 광기어린 살인을 저지르고 다니는 소녀 역할을 맡은 미마는 현실과 허구의 경계선에서 자신을 쫓아다니던 스토커를 해친다. 그러나 그 일 역시 사실인지 허구인지는 불분명하다. 이제 미마의 눈에는 또 다른 미마가 보이기 시작한다. 아이돌 시절 그대로의 모습으로 미마의 눈 앞에 나타난 또 다른 미마는 그녀에게 과거 인기 스타로의 회귀를 강요한다. 니가 나고, 내가 너야. 라고 말하는 또 다른 자아 앞에서 미마는 혼란에 빠진다. 그러던 중, 미마의 주변을 둘러싼 사람들이 하나 둘 살해당하고 범인을 알 수 없는 상황에서 극도의 불안감을 느끼는 미마는 누군가 끊임없이 자신을 지켜보고 있다는 것을 느끼는데...', 'https://image.tmdb.org/t/p/w500/cpsxJP7lUNEozPtDLIM5gPC9gJH.jpg', 1998, 0, 0, '2026-06-06 13:25:27.296842', 'JP');
INSERT INTO public.movies VALUES (4582, 1395724, '치인의 사랑 : 나오미', '["Drama", "Romance"]', 'Kishū Izuchi', '["Shima Onishi", "Sena Natsuki", "Shiori Doi", "Shunsuke Sato", "柴山庸平"]', '각본가가 되고자 고군분투하던 조지는 허름한 바에서 배우 지망생 나오미와 조우한다. 어느 날 조지는 영화 각본을 써보지 않겠냐는 권유를 받고, 각본 집필에 골몰하던 중 나오미와 재회한다.', 'https://image.tmdb.org/t/p/w500/74FAwSOaX5VpZHqfuwROPM3aAUl.jpg', 2024, 0, 0, '2026-06-08 06:33:34.504945', 'JP');
INSERT INTO public.movies VALUES (4584, 1360829, '버진 펑크', '["Animation", "Action", "Sci-Fi"]', 'Yasuomi Umetsu', '["Saki Miyashita", "Katsuyuki Konishi", "Taku Yashiro", "Rui Tanabe", "Norio Wakamoto"]', '2099년, 의료용 인공인체 기술 ‘소마디아’로 인류는 부상과 질병을 극복했으나, 그 부작용은 범죄와 혼돈으로 번져간다. 정부는 불법 수배범을 처단하기 위해 바운티 헌터 제도를 도입하고, 소녀 우부는 어린 시절 악연으로 얽힌 Mr. 엘레강스의 강압 속에 헌터가 된다.', 'https://image.tmdb.org/t/p/w500/oARmiq6Lar4RNAlPzsuRf8cqL8j.jpg', 2025, 0, 0, '2026-06-08 06:33:35.863787', 'JP');
INSERT INTO public.movies VALUES (4585, 585534, 'モーニング・ムーンは粗雑に', '["Drama"]', 'Masanori Watanabe', '["Mio Takaki", "Junnosuke Saitô", "Tsunehiko Watase", "Bunjaku Han", "Ikko Furuya"]', NULL, 'https://image.tmdb.org/t/p/w500/ogRSqsyiiQOxPXQR6y2WUMwcMb8.jpg', 1981, 0, 0, '2026-06-08 06:33:36.54512', 'JP');
INSERT INTO public.movies VALUES (4586, 989730, '극장판 모노노케: 우중망령', '["Animation", "Fantasy", "Mystery"]', 'Kenji Nakamura', '["Hiroshi Kamiya", "Tomoyo Kurosawa", "Aoi Yuuki", "Kana Hanazawa", "Mami Koyama"]', '에도 시대 왕을 위한 여성들의 궁 오오쿠에 들어온 두 신입 시녀. 정치적 음모와 대립 그리고 원한을 품은 망령을 목격하는데. 이 망령을 퇴치할 수 있는 건 떠돌이 약장수뿐이다.', 'https://image.tmdb.org/t/p/w500/ooqs01AyaEOYNWBu1pMyiAnuXP6.jpg', 2024, 0, 0, '2026-06-08 06:33:37.259794', 'JP');
INSERT INTO public.movies VALUES (4588, 916192, '여름을 향한 터널, 이별의 출구', '["Animation", "Drama", "Romance", "Fantasy", "Sci-Fi"]', 'Tomohisa Taguchi', '["Ouji Suzuka", "Marie Iitoyo", "Tasuku Hatanaka", "Arisa Komiya", "Haruka Terui"]', '소원을 이루어 주지만 안팎의 시간이 다르게 흐르는 ''우라시마 터널''을 발견한 고등학생 ''카오루''와 전학생 ''안즈'' 터널의 비밀을 알아내기 위해 뜨거웠던 여름을 함께 보낸 두 사람은 어느새 서로에게 가장 소중한 존재가 되는데...', 'https://image.tmdb.org/t/p/w500/oQy8ak5yBg5pSJ5P0Esr4Etn56U.jpg', 2022, 0, 0, '2026-06-08 06:33:38.643185', 'JP');
INSERT INTO public.movies VALUES (4492, 499191, '콜보이', '["Drama"]', 'Daisuke Miura', '["Tori Matsuzaka", "Sei Matobu", "Ami Tomite", "Yuki Sakurai", "Kenta Izuka"]', '일상에서도, 여성과의 관계에서도 따분함을 느끼며 무기력하게 생활하던 명문대생 료(마츠자카 토리). 어느 날 시즈카(마토부 세이)라는 아름다운 여성이 료가 아르바이트 하는 바에 찾아온다. 여성과의 관계가 시시하다는 료에게 시즈카는 ‘정열의 시험’을 치르게 한다. 그것은 바로 시즈카가 운영하는 회원제 클럽의 입사 시험. 시험에 통과한 료는 다음 날부터 ‘콜보이’로서 일하게 된다. 당황스러운 일을 겪기도 하지만 콜보이로 일해 나가면서 료는 점차 여성 한 명 한 명의 마음 속에 숨겨진  욕망의 신비로움을 깨닫고 진정한 보람을 느끼기 시작한다.', 'https://image.tmdb.org/t/p/w500/2btaZjkRWJN0Fb323iIL4oNZW5y.jpg', 2018, 0, 0, '2026-06-08 06:32:23.361462', 'JP');
INSERT INTO public.movies VALUES (4493, 372962, '마이쨩의 일상', '["Horror"]', 'Sade Satô', '["An Koshi", "Miyako Akane", "Shôgo Maruyama", "Soaco Roman"]', '외딴 지역에 위치한 곳에서 젊은 소녀들을 유인하기 위해 메이드를 구한다는 구인 광고를 낸다. 하지만 이는 소녀들을 끌어들여 성적 학대, 고문, 살인, 그리고 식인 행위를 저지르기 위한 덫으로 밝혀진다.', 'https://image.tmdb.org/t/p/w500/jibA50cQkfJvqX8E9NZsafzXGNJ.jpg', 2014, 0, 0, '2026-06-08 06:32:24.145265', 'JP');
INSERT INTO public.movies VALUES (4591, 888009, '地下鉄連続レイプ ＯＬ狩り', '["Drama", "Crime"]', 'Shūji Kataoka', '["Chiemi Akimoto", "Saya Hôjô", "Kazumi Natsuki", "Hiromi Saotome"]', NULL, 'https://image.tmdb.org/t/p/w500/aMg4eM8dXZF7a5bNUSIMh8nV2z4.jpg', 1986, 0, 0, '2026-06-08 06:33:41.622467', 'JP');
INSERT INTO public.movies VALUES (4592, 505192, '어느 가족', '["Drama", "Crime", "Thriller"]', 'Hirokazu Kore-eda', '["Lily Franky", "Sakura Ando", "Mayu Matsuoka", "Kairi Jo", "Miyu Sasaki"]', '할머니의 연금과 물건을 훔쳐 생활하며 가난하지만 웃음이 끊이지 않는 어느 가족. 우연히 길 위에서 떨고 있는 한 소녀를 발견하고 집으로 데려와 가족처럼 함께 살게 된다. 그런데 뜻밖의 사건으로 가족이 뿔뿔이 흩어지게 되고 각자 품고 있던 비밀과 간절한 바람이 드러나게 되는데…', 'https://image.tmdb.org/t/p/w500/vjBjqZ4AWO0l6mMfPpd3z1Z2Oo9.jpg', 2018, 0, 0, '2026-06-08 06:33:43.116498', 'JP');
INSERT INTO public.movies VALUES (4593, 1534381, '8月26日 花火大会の夜 ずっと両片想いだった僕らは結ばれ 十数年分の’好き’をぶつけ合うように身体を貪り合った 河北彩伽', '["Drama"]', 'Shiro Shoten', '["Saika Kawakita"]', NULL, 'https://image.tmdb.org/t/p/w500/yGWt7PKnc7cRKIXNbgrpxQUeyl9.jpg', 2025, 0, 0, '2026-06-08 06:33:43.804187', 'JP');
