INSERT INTO public.movies VALUES (4595, 1220552, '劇場版 陰の実力者になりたくて！ 残響編', '["Animation", "Comedy", "Adventure", "Fantasy"]', 'Kazuya Nakanishi', '["Seiichiro Yamashita"]', NULL, 'https://image.tmdb.org/t/p/w500/jxrLc5uCK3s7qlb4aJU4aNTOJZR.jpg', NULL, 0, 0, '2026-06-08 06:33:45.208781', 'JP');
INSERT INTO public.movies VALUES (4596, 1600672, 'エヴァンゲリオン放送30周年記念特別興行', '["Animation", "Sci-Fi", "Comedy"]', 'Naoyuki Asano', '["Yuko Miyamura", "Megumi Ogata", "Akira Ishida", "Kotono Mitsuishi", "Miki Nagasawa"]', NULL, 'https://image.tmdb.org/t/p/w500/25csgA1l0jpvvSRwdFgjrI7PDnk.jpg', 2026, 0, 0, '2026-06-08 06:33:45.886458', 'JP');
INSERT INTO public.movies VALUES (4598, 802464, '新任教師 野本美穂 恥肉の裏授業', '["Romance"]', 'Hideo Hashizume', '["Miho Nomoto", "Rin Sakiyama", "Kuronosuke Kagawa", "Yôko Momochi", "Shiba Hanai"]', NULL, NULL, 2003, 0, 0, '2026-06-08 06:33:47.385794', 'JP');
INSERT INTO public.movies VALUES (4599, 927589, '尻を撫でまわしつづけた男　痴漢日記', '[]', 'Tadafumi Tomioka', '["Yoshiyuki Omori", "Hitoe Ootake", "Michihiro Yamanishi", "Yukijiro Hotaru", "Minako Ogawa"]', NULL, 'https://image.tmdb.org/t/p/w500/iJL6OF6aEE0aBxj1kPgZFIk7370.jpg', 1995, 0, 0, '2026-06-08 06:33:48.081014', 'JP');
INSERT INTO public.movies VALUES (4602, 18148, '동경 이야기', '["Drama"]', 'Yasujirō Ozu', '["Chishū Ryū", "Chieko Higashiyama", "Setsuko Hara", "Haruko Sugimura", "So Yamamura"]', '2차 세계대전 후. 결혼하여 도쿄에 살고 있는 자식들을 만나기 위해 노부부가 상경한다. 의사 장남과 미용실을 운영하는 둘째 딸은 곧 부모님의 방문을 부담스러워하고 바쁜 일상을 핑계로 소홀히 대한다. 전쟁 중 남편을 잃은 며느리 노리코만이 노부부를 극진히 모시는데…', 'https://image.tmdb.org/t/p/w500/qcq69w02VC93Kc16CV5e4YY2Xgm.jpg', 1953, 0, 0, '2026-06-08 06:33:51.16941', 'JP');
INSERT INTO public.movies VALUES (4495, 976893, '퍼펙트 데이즈', '["Drama"]', 'Wim Wenders', '["Koji Yakusho", "Tokio Emoto", "Arisa Nakano", "Aoi Yamada", "Yumi Aso"]', '도쿄 시부야의 공공시설 청소부 ‘히라야마’는 매일 반복되지만 충만한 일상을 살아간다. 오늘도 그는 카세트 테이프로 올드 팝을 듣고, 필름 카메라로 나무 사이에 비치는 햇살을 찍고, 자전거를 타고 단골 식당에 가서 술 한잔을 마시고, 헌책방에서 산 소설을 읽으며 하루를 마무리한다. 그러던 어느 날, 사이가 소원한 조카가 찾아오면서 그의 반복되는 일상에 작은 변화가 생긴다.', 'https://image.tmdb.org/t/p/w500/tD5njVBxiDBEPmBiPOSnmP6AmNt.jpg', 2023, 0, 0, '2026-06-08 06:32:25.641918', 'JP');
INSERT INTO public.movies VALUES (4600, 39863, '다윗의 별: 미소녀 사냥', '["Horror", "Thriller"]', 'Norifumi Suzuki', '["Yuka Asagiri", "Yûko Asuka", "Shun Domon", "Hiromi Namino", "Hiroshi Nawa"]', '경찰에게 쫓기던 강간 살인범이 부유한 교수의 집에 침입해서 교수의 눈앞에서 부인을 강간한다. 그 결과 똑똑하고 잘생긴 사내아이가 태어나지만, 교수에게 학대 당하던 어머니가 결국 자살하고 출생의 비밀까지 알게 되서 비뚤어진 아이는 성년이 되자 친아버지 같은 살인자의 길을 걷기로 결심하는데.....', 'https://image.tmdb.org/t/p/w500/AnNj1YA4PS68LneEcTVTN1r1G9z.jpg', 1979, 0, 0, '2026-06-08 06:33:48.778189', 'JP');
INSERT INTO public.movies VALUES (4601, 36073, '기니어피그 EP2 : 혈육의 꽃', '["Horror"]', 'Hideshi Hino', '["Hiroshi Tamura", "Kirara Yugao"]', NULL, 'https://image.tmdb.org/t/p/w500/bSU1eNOC4KbkLYLMsjavGqVc7Ae.jpg', 1985, 0, 0, '2026-06-08 06:33:49.469691', 'JP');
INSERT INTO public.movies VALUES (4604, 1678, '고지라', '["Thriller", "Horror", "Sci-Fi"]', 'Ishirō Honda', '["Akira Takarada", "Momoko Kôchi", "Akihiko Hirata", "Takashi Shimura", "Fuyuki Murakami"]', '수만년동안 태평양에 잠들어있던 고질라가 핵폭탄 실험으로 인해 깨어나 선박들을 납치한다. 이어 고질라는 도쿄까지 상륙하지만, 핵실험의 영향으로 괴력을 갖게 된 고질라에게는 어떤 최첨단 무기도 통하지 않는다. 도시는 고질라가 내뿜는 방사능와 불길에 휩싸여 초토화되지만, 손쓸 방법이 없어 많은 희생자들이 발생한다. 이 고질라를 쓰러뜨릴 에너지인 오키시젠 디스트로이어를 개발한 과학자 세이자와 다이스케는 그 방법을 알리길 거부하고, 희생자는 점점 늘어만 가는데...', 'https://image.tmdb.org/t/p/w500/2MmLWzSo1DV8nwOE6OVcysId46M.jpg', 1954, 0, 0, '2026-06-08 06:33:53.092887', 'JP');
INSERT INTO public.movies VALUES (4605, 1263421, '한마 바키 VS 켄간 아슈라', '["Animation", "Action", "Fantasy"]', 'Toshiki Hirano', '["Nobunaga Shimazaki", "Tatsuhisa Suzuki", "Akio Otsuka", "Takuya Eguchi", "Kenta Miyake"]', '이것이 궁극의 대결이다. 《한마 바키》와 《켄간 아슈라》의 최강 투사들이 격돌하는 전대미문의 과격 격투 크로스오버.', 'https://image.tmdb.org/t/p/w500/d4r1Y2RDDLWzwVgKoaXSjyUD61B.jpg', 2024, 0, 0, '2026-06-08 06:33:53.773075', 'JP');
INSERT INTO public.movies VALUES (4607, 396263, '간츠: 오', '["Animation", "Sci-Fi", "Action", "Drama"]', 'Yasushi Kawamura', '["Yuki Kaji", "Daisuke Ono", "Saori Hayami", "Mao Ichimichi", "Masaya Onosaka"]', '지하철에서 위험에 빠진 시민을 구하려다 죽음을 당한 고등학생 ‘카토’는 어느 방 안에서 눈을 뜬다. 죽은 사람들이 모여 있는 방 안에 나타난 정체 모를 검은 구체 ‘간츠’. 그리고 ‘간츠’가 남긴 미션. ‘제한 시간 내에 괴생명체들과의 전투에서 살아 남아 100점이 걸린 최종보스를 제거하라!’ 홀로 남은 동생에게 돌아가기 위해 카토는 오사카 도심을 공격한 괴물에 맞서 싸우지만, 그와 ‘레이카’ 가 속한 도쿄팀은 열세에 몰리고, 때마침 ‘안즈’를 비롯해 ‘조지’, ‘무로야, ‘오카’까지 막강한 에이스가 모인 오사카팀과 조우한다. 그러나 최종보스 ‘누라리횬’의 등장으로 간츠팀은 역대 최악의 상황에 놓이는데..', 'https://image.tmdb.org/t/p/w500/8WMfdLAt19s1DArAcNHRd7A8JQd.jpg', 2016, 0, 0, '2026-06-08 06:33:55.32211', 'JP');
INSERT INTO public.movies VALUES (4608, 360776, 'くノ一忍法帖III 秘戯伝説の怪', '["Action"]', 'Masaru Tsushima', '["Shiho Wakabayashi", "Masuhiko Ida", "Marino Hase", "Mika Okamoto", "Yuki Ôhashi"]', NULL, 'https://image.tmdb.org/t/p/w500/uJDtI8RZPbV4gn5cEyxPyXF7QJo.jpg', 1993, 0, 0, '2026-06-08 06:33:57.107119', 'JP');
INSERT INTO public.movies VALUES (4609, 21452, '명탐정 코난: 14번째 표적', '["Animation", "Crime", "Mystery", "Adventure"]', 'Kenji Kodama', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Akira Kamiya", "Gara Takashima"]', '메구레 경부, 란의 엄마인 키사키 에리 변호사, 아가사 박사가 동일인으로 추정되는 범인에게 습격을 당한다. 피해자들이 모두 모리 코고로 탐정과 관련이 있다는 것과 범인이 현장에 남긴 트럼프 카드가 유일한 단서. 모리 코고로 탐정이 과거 형사 시절에 체포했던 전직 카드 딜러 출신의 살인범 무라카미 죠가 용의선상에 오른다. 코난은 범인이 남긴 트럼프 카드에서 습격당한 3명의 이름 속 공통점을 찾아내고, 끝나지 않은 연쇄 살인 게임을 막기 위해 범인의 다음 표적들의 행선지인 수중 레스토랑 ‘아쿠아 크리스탈’로 항한다. 코난 일행과 모리 코고로 탐정, 그리고 범인의 타깃들이 모두 완벽한 수중 밀실 시설 ‘아쿠아 크리스탈’에 모이게 되는데…', 'https://image.tmdb.org/t/p/w500/wX4Erw7OfQqx7cMkCWwcnzhTuhj.jpg', 1998, 0, 0, '2026-06-08 06:33:57.926599', 'JP');
INSERT INTO public.movies VALUES (4610, 348084, '団鬼六 白獣の槛', '["Drama"]', 'Hiroyuki Kawasaki', '["Aoi Mizumori", "Kazu Itsuki", "Kenji Nakazawa"]', NULL, 'https://image.tmdb.org/t/p/w500/apuIoAFqgwc0ZZmpgjtIGcCMtKJ.jpg', 2008, 0, 0, '2026-06-08 06:33:58.683649', 'JP');
INSERT INTO public.movies VALUES (450, 561, '콘스탄틴', '["Fantasy", "Action", "Horror"]', 'Francis Lawrence', '["Keanu Reeves", "Rachel Weisz", "Shia LaBeouf", "Djimon Hounsou", "Max Baker"]', '인간의 형상을 한 혼혈 천사와 혼혈 악마가 존재하는 세상. 태어날 때부터 그들을 구분하는 능력을 타고난 존 콘스탄틴은 자신의 능력을 저주하며 운명에서 벗어나기 위해 자살을 시도하지만 실패하고 만다. 그 후 다시 살아난 그는 천국과 지옥의 경계를 넘나들며 세상에 존재하는 악을 지옥으로 돌려보내기에 나선다. 그래야만 지옥으로 가게 되어 있는 자신의 운명이 뒤바뀌어 천국으로 들어갈 수 있음을 깨달았기 때문이다. 술, 담배에 쩔어 살면서 계속되는 전투에 지쳐만 가던 콘스탄틴. 그런 그에게 어느 날, LA 강력계 소속의 형사 안젤라가 찾아와 쌍둥이 동생의 죽음에 대한 의문을 풀기 위해 도움을 요청한다. 그러나 사건을 파헤칠수록 거대한 어둠의 힘 속으로 빨려 들게 되는데...', 'https://image.tmdb.org/t/p/w500/zHqg19nxvHKu8OS7RZWMBLGWxrz.jpg', 2005, 0, 0, '2026-06-06 13:25:13.312525', 'US');
INSERT INTO public.movies VALUES (4603, 54493, 'X 게임', '["Horror"]', 'Yôhei Fukuda', '["Kazuyuki Aijima", "Hirofumi Araki", "Shota Chiyo", "Meguru Katô", "Ayaka Kikuchi"]', '소꿉친구가 자살한 후, 히데아키와 그의 옛 동급생들은 조의를 표하기 위해 다시 만납니다. 얼마 지나지 않아 한 남자가 고문당하는 장면이 담긴 DVD가 도착하고, 히데아키는 동급생이 굴욕적인 바츠(벌칙) 게임을 당하는 것을 목격했던 기억을 떠올리며 플래시백을 시작합니다. 어느 날 저녁, 히데아키는 납치되고 다음 날 눈을 떴을 때 동료 친구들과 함께 옛날 학교 교실을 재현한 공간에 있다는 것을 알게 됩니다. 의문의 두건을 쓴 인물들에게 갇혀 포로가 된 이들은 이제 살아남기 위해 잔인하고 폭력적인 버전의 벌칙 게임을 해야 합니다.', 'https://image.tmdb.org/t/p/w500/eyAhiO44EOB5mKP6GEmlGtXNAmU.jpg', 2010, 0, 0, '2026-06-08 06:33:51.858423', 'JP');
INSERT INTO public.movies VALUES (4606, 11621, '붉은 돼지', '["Animation", "Adventure", "Fantasy"]', 'Hayao Miyazaki', '["Shūichirō Moriyama", "Tokiko Kato", "Bunshi Katsura VI", "Tsunehiko Kamijô", "Akemi Okamura"]', '제1차 세계대전이 끝난 후, 전쟁의 기억을 지우기 위해 스스로 돼지로 변한 이탈리아 공군의 에이스 비행사 포르코 롯소. 그는 이탈리아 근해의 무인도에서 혼자 지내며 그의 의지대로 자유롭게 날고 하늘의 해적을 소탕한다. 젊은 시절 인간의 모습을 한 얼굴은 지나의 레스토랑의 벽에 걸려 있는 사진 속에 유일하게 남아 있다. 사람들로부터 붉은 돼지로 불리는 포르코 롯소는 미국인 조종사 도널드 커티스의 공격으로 비행기가 파손되자, 비행기 제작자인 피콜로에게 수리를 요청한다. 피콜로의 손녀인 피오는 포르코 롯소와 함께 지내며 온갖 모험을 겪으면서 조금씩 그를 좋아하게 되는데...', 'https://image.tmdb.org/t/p/w500/4YLdlFM3XXzy1xfT6brHDcF5Upf.jpg', 1992, 0, 0, '2026-06-08 06:33:54.551222', 'JP');
INSERT INTO public.movies VALUES (4613, 242828, '추억의 마니', '["Animation", "Drama", "Family"]', 'Hiromasa Yonebayashi', '["Sara Takatsuki", "Kasumi Arimura", "Nanako Matsushima", "Susumu Terajima", "Toshie Negishi"]', '12살 소녀 안나는 요양차 방문한 바닷가 마을에서 어디서 본 듯한 낡은 저택을 발견한다. 아무도 살지 않는 듯 보이는 그 곳에서 안나는 금발의 아름다운 소녀 마니를 만나게 된다. 안나는 마니의 초대로 저택의 파티에 참가하지만 신기하게도 다음날 낮에 찾아간 저택은 아무도 살지 않은 폐가가 되어 있다. 그 이후로도 안나와 마니는 함께 시간을 보내지만 알 수 없는 일들이 자꾸 일어난다. 갑자기 마니는 사라져 버리고 낡은 저택에 새롭게 이사온 소녀 사야카는 자신의 방에서 우연히 마니의 일기장을 찾게 된다. 안나와 사야카는 상상조차 할 수 없었던 놀라운 이야기를 발견하게 되는데...', 'https://image.tmdb.org/t/p/w500/wwGfpFhMqFSiQAWdPX80X1uOf3s.jpg', 2014, 0, 0, '2026-06-08 06:34:05.472237', 'JP');
INSERT INTO public.movies VALUES (4614, 161715, '극장판 도라에몽: 진구와 꿈의 삼총사', '["Animation", "Family", "Adventure", "Comedy", "Fantasy", "Sci-Fi"]', 'Tsutomu Shibayama', '["Nobuyo Oyama", "Noriko Ohara", "Michiko Nomura", "Kaneta Kimotsuki", "Kazuya Tatekabe"]', '좋은 꿈을 꾸다가 깨어난 진구는 현실에서 된통 깨진다. 그 뒤 도라에몽의 꿈 보는 기계로 원하는 꿈을 꾸게 된다. 그 뒤 이상한 행인의 꾐으로 꿈의 삼총사 테이프를 사게 되고 모험을 시작하게 된다.', 'https://image.tmdb.org/t/p/w500/oCQtdezF7Ap5wm8ICiB3Pzx6wM4.jpg', 1994, 0, 0, '2026-06-08 06:34:06.25269', 'JP');
INSERT INTO public.movies VALUES (4615, 1405338, '데몬 시티: 악귀 죽이기', '["Action", "Crime", "Fantasy", "Thriller"]', 'Seiji Tanaka', '["Toma Ikuta", "Masahiro Higashide", "Miou Tanaka", "Ami Touma", "Taro Suruga"]', '가족을 살해했다는 누명을 쓴 채 식물인간으로 방치되었던 전직 킬러. 도시를 점령한 가면 쓴 ‘악귀들’을 향한 그의 거침없는 복수가 시작된다.', 'https://image.tmdb.org/t/p/w500/45us5s9vvXwah7rxF6lzYpKpzPi.jpg', 2025, 0, 0, '2026-06-08 06:34:07.024041', 'JP');
INSERT INTO public.movies VALUES (4616, 39207, '명탐정 코난: 전율의 악보', '["Animation", "Action", "Crime", "Mystery"]', 'Yasuichiro Yamamoto', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Akira Kamiya", "Naoko Matsui"]', '음악가만을 노리는 연속살인사건이 발생한다. 살해당한 사람은 모두, 고명한 전 피아니스트가 인솔한 음악 아카데미의 출신자였다. 그가 만든 음악 홀의 개장을 축하하는 첫 콘서트에 초청된 코난 일행들. 콘서트의 중심은 바하가 쳤다고 전해지는 파이프 오르간과 세계적으로 유명한 바이올린 ''스트라디바리우스''의 음색, 그리고 절대음감을 가진 천재가수의 노랫소리였다. 하지만 콘서트 본방을 향해 여러가지 수상한 사건이 일어나기 시작하고... 그리고 본 공연 당일이 되어 코난 일행이 방문한 콘서트 회장이 갑자기 대폭발, 온통 화염의 바다에 휩싸이는데...', 'https://image.tmdb.org/t/p/w500/4xu9wxgjMvaAS4EGz4j4tqJ5eDT.jpg', 2008, 0, 0, '2026-06-08 06:34:07.792095', 'JP');
INSERT INTO public.movies VALUES (4617, 32292, '기니어피그 EP6 : 맨홀 속의 인어', '["Horror", "Romance"]', 'Hideshi Hino', '["Shigeru Saiki", "Mari Somei", "Go Riju", "Masami Hisamoto", "Tsuyoshi Toshishige"]', NULL, 'https://image.tmdb.org/t/p/w500/dWDGZmy04PL36VszTyePSPdetYf.jpg', 1988, 0, 0, '2026-06-08 06:34:08.545906', 'JP');
INSERT INTO public.movies VALUES (4619, 127533, '바람의 검심', '["Adventure", "Action", "Fantasy", "History"]', 'Keishi Otomo', '["Takeru Satoh", "Emi Takei", "Koji Kikkawa", "Yu Aoi", "Munetaka Aoki"]', '그 흉터, 그 칼놀림.. 전설의 발도재가 돌아왔다!  10년 전 세상에 모습을 감추었지만 전설의 칼잡이로 불리는 이름 발도재. 그는 지난 날을 회개하며 불살의 맹세를 다짐하고 사람을 벨 수 없는 역날검을 들고 세상을 방랑하는 히무라 켄신으로 살고 있다. 그러던 어느 날 누군가 자신을 사칭해 세상을 위협한다는 것을 알게 되고 소중한 사람들을 지키기 위해 결투에 나서게 되는데... 불살의 맹세와 그의 손에 쥐어진 역날검. 그는 자신의 맹세와 함께 소중한 사람들을 지킬 수 있을 것인가!', 'https://image.tmdb.org/t/p/w500/pm6AhVq4rbg6PoisCXBWu3elc63.jpg', 2012, 0, 0, '2026-06-08 06:34:10.043125', 'JP');
INSERT INTO public.movies VALUES (4620, 1235431, '[최애의 아이] - 더 파이널 액트 -', '["Drama", "Fantasy"]', 'Smith', '["Nagisa Saito", "Kaito Sakurai", "Asuka Saito", "Nanoka Hara", "Mizuki Kayashima"]', '산부인과 의사 아마미야 고로가 근무하는 병원에 그가 열광하는 최애 아이돌 호시노 아이가 임신을 해서 방문하게 되고, 쌍둥이를 임신한 아이는 아이돌 활동 때문에 출산을 고민 중이었는데 고로와의 상담으로 아이를 출산하기로 결정합니다. 이후 아마미야 고로는 스토커에 의해 절벽에서 낙사하고, 아마미야 고로는 전생의 기억을 간직한 채 호시노 아이가 낳은 쌍둥이 아이 중 하나인 아쿠아로 인생 2회차를 살게 된다.', 'https://image.tmdb.org/t/p/w500/5V24N6J7zqJ1IaahM97Asg72jJX.jpg', 2024, 0, 0, '2026-06-08 06:34:10.695399', 'JP');
INSERT INTO public.movies VALUES (4621, 110420, '늑대아이', '["Animation", "Family", "Drama", "Fantasy"]', 'Mamoru Hosoda', '["Aoi Miyazaki", "Takao Osawa", "Haru Kuroki", "Yukito Nishii", "Momoka Ohno"]', '평범한 여대생 하나는 강의실에서 우연히 만나게 된 그에게 반하게 되고, 곧 사랑에 빠지게 된다. 하지만 그는 평범한 사람이 아닌 늑대인간이었다. 늑대인간과의 동화 같은 사랑 후에 남은 것은 두 아이뿐. 눈 내리는 날에 태어난 누이 유키, 비 내리는 날 태어난 동생 아메. 두 아이에게는 커다란 비밀이 있는데, 바로 흥분하면 귀가 쫑긋, 꼬리가 쏘옥 나오는 늑대아이라는 것. 남들과 조금 다른 육아, 남들과 살짝 다른 고민을 하며 신비로운 운명을 살아가는 남매와 특별한 두 아이를 키우는 엄마의 이야기가 시작된다.', 'https://image.tmdb.org/t/p/w500/2mF1IKMeB9JGstJqismy5AoamrV.jpg', 2012, 0, 0, '2026-06-08 06:34:11.380907', 'JP');
INSERT INTO public.movies VALUES (567, 38, '이터널 선샤인', '["Sci-Fi", "Drama", "Romance"]', 'Michel Gondry', '["Jim Carrey", "Kate Winslet", "Kirsten Dunst", "Mark Ruffalo", "Elijah Wood"]', '조엘은 아픈 기억만을 지워준다는 라쿠나사를 찾아가 헤어진 연인 클레멘타인의 기억을 지우기로 결심한다. 기억이 사라져 갈수록 조엘은 사랑이 시작되던 순간, 행복한 기억들, 가슴 속에 각인된 추억들을 지우기 싫어지기만 하는데... 당신을 지우면 이 아픔도 사라질까요? 사랑은 그렇게 다시 기억된다.', 'https://image.tmdb.org/t/p/w500/jULvvUymAqM18gIDHbMRfKHbCSB.jpg', 2004, 0, 0, '2026-06-06 13:25:17.987442', 'US');
INSERT INTO public.movies VALUES (4618, 257762, '여자 사냥꾼', '["Drama", "Horror"]', 'Toshiharu Ikeda', '["Erina Miyai", "Ayako Ota", "Teruo Matsuyama", "Seru Rando", "Nobuyuki Kawakami"]', '순수하고 재능넘치는 발레리나가 한때 자신의 우상이였던 여인에 의해서 성에 눈을 뜨게 되고 쾌락에 빠져들게 된다.', 'https://image.tmdb.org/t/p/w500/bKA9uWmorwLjLwtNMCHhs5OYhxD.jpg', 1980, 0, 0, '2026-06-08 06:34:09.320198', 'JP');
INSERT INTO public.movies VALUES (4500, 3782, '이키루', '["Drama"]', 'Akira Kurosawa', '["Takashi Shimura", "Haruo Tanaka", "Nobuo Kaneko", "Bokuzen Hidari", "Miki Odagiri"]', '주인공은 어떤 도시의 시청에서 근무하는 노년의 남자. 시민 과장이란 직위는 있지만 매일 출근해서 서류에 도장을 찍는 기계다. 말수도 적고 인간관계도 서투른 그는 부인을 잃은 후 외아들에게만 희망을 걸고 독신생활을 해왔다. 약간의 저축도 하면서 아들 부부와 함께 살고 있다. 어느날 갑자기 앞으로 3개월뿐이라는 위암선고를 받는 게 사건의 발단이 된다. 핏줄에게서 위안을 받으려 하지만, 부인과 함께 따로 살림을 차리는 데만 혈안이 된 아들의 모습에서 실망을 느끼고 자포자기 상태에 빠진다. 술과 도박장 등 쾌락에 의존해 죽음에 대한 공포를 떨쳐버리려 하지만 쉽지 않다. 그러다 옛날 여직원을 우연히 길에서 만나고, 지금은 인형 제조공장에서 여직공 일을 하고 있는 그녀에게서 건강함과 생명력을 느끼게 된다. 아무리 사소한 것이라도 뭔가를 창조하는 데서 즐거움을 얻을 수 있다는 사실을 배우게 되고, 먼지가 뿌옇게 쌓여 있던 서류더미 속에서 일거리를 찾아낸다. 가난한 사람들이 살고 있는 지역에 아이들을 위한 놀이터를 만들어달라는 건의였는데 계속 무시되고 있었던 터이다. 타성에 젖은 관료들에게 고개를 숙여 마침내 놀이터를 건립하지만, 준공식 후 주인공은 눈을 맞으며 죽고, 아무런 상관도 없는 관리들에게 공로가 돌아간다는 허무주의로 끝을 맺는다.', 'https://image.tmdb.org/t/p/w500/8aja0bziXOA0ZgspOLyt4PVZ9kF.jpg', 1952, 0, 0, '2026-06-08 06:32:29.393483', 'JP');
INSERT INTO public.movies VALUES (4501, 1326106, '괴수 8호: 미션 리컨', '["Animation", "Action", "Sci-Fi"]', 'Shigeyuki Miya', '["Masaya Fukunishi", "Wataru Katoh", "Fairouz Ai", "Tessyo Genda", "Kengo Kawanishi"]', '괴수로 가득한 일본에서 괴물 사체 처리 작업을 하고 있는 ‘히비노 카프카’는 소꿉친구이자 방위대의 떠오르는 스타 ‘아시로 미나’의 모습을 보고 다시 한번 꿈에 도전하기로 결심한다. 어느 날 갑작스럽게 강력한 “괴수 8호”로 변신하게 된 ‘카프카’. 후배 ‘이치카와 레노’의 도움을 받아 정체를 숨긴 채, 그는 오랜 꿈이었던 방위대 시험에 합격하였고 ‘미나’의 곁에 서는 것을 목표로 나아간다. 그러나 의문의 괴수가 방위대 기지를 공격하자, ‘카프카’는 절박한 상황 속에서 중요한 결정에 직면하게 되는데…', 'https://image.tmdb.org/t/p/w500/ziPpGchWdwiJaAXIbt4Tu0uNeBA.jpg', 2025, 0, 0, '2026-06-08 06:32:30.132573', 'JP');
INSERT INTO public.movies VALUES (4624, 505262, '나의 히어로 아카데미아 더 무비: 두 명의 히어로', '["Animation", "Action", "Adventure", "Fantasy"]', 'Kenji Nagasaki', '["Daiki Yamashita", "Kenta Miyake", "Mirai Shida", "Katsuhisa Namase", "Nobuhiko Okamoto"]', '모두가 ‘개성’이라는 초능력을 가진 세계, 여기에 ‘무개성’의 소년이 있었다! 하지만 소년은 ‘개성’ 대신 히어로가 될 조건을 가지고 있었는데… NO.1 히어로 ‘올마이트’의 뒤를 잇는 새로운 영웅 탄생! 개성이 없어도, 넌 세상을 빛낼 히어로가 될 수 있다! 5월 모두 다같이 입학~!', 'https://image.tmdb.org/t/p/w500/3coOIbsmeYwhLshMXHUrwtdhzDa.jpg', 2018, 0, 0, '2026-06-08 06:34:13.399985', 'JP');
INSERT INTO public.movies VALUES (4625, 295830, '진격의 거인 파트1', '["Horror", "Action", "Sci-Fi"]', 'Shinji Higuchi', '["Haruma Miura", "Kiko Mizuhara", "Kanata Hongo", "Hitomi Miyauchi", "Takahiro Miura"]', '100년 전, 정체를 알 수 없는 거인들의 등장에 의해 파괴된 문명,  거인의 습격을 막기 위해 인간들은 세 개의 거대한 벽을 쌓고 그 안에서 살아간다.  그러던 어느 날, 지금껏 본 적 없는 초대형 거인의 등장으로  인류를 지키고 있던 벽이 무너지고 거인들의 습격이 시작된다.  평화로웠던 세상은 지옥이 되고, 인류멸망의 위기가 찾아오는데...', 'https://image.tmdb.org/t/p/w500/6NsUAl5D0T9Dm8ynt2uSIPPCDBN.jpg', 2015, 0, 0, '2026-06-08 06:34:14.066112', 'JP');
INSERT INTO public.movies VALUES (4626, 662638, '명탐정 코난: 비색의 탄환', '["Animation", "Action", "Crime", "Mystery", "Romance", "Thriller"]', 'Chika Nagaoka', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Rikiya Koyama", "Shuichi Ikeda"]', '전 세계인의 축제 WSG(World Sports Games)의 개최를 앞둔 일본. 이를 기념해 시속 1,000km를 자랑하는 진공 초전도 리니어의 개통이 발표된다. 모두가 이를 주목하는 가운데, WSG의 공식 후원사 대표들이 연쇄 납치를 당하고, 코난은 이 사건이 15년 전 미국 보스턴에서 발생한 WSG 연쇄 납치 사건과 관련이 있다는 것을 밝혀내는데… 이를 지켜보는 아카이 슈이치와 FBI,  그리고 절대로 만나서는 안 될 위험천만한 가족이 모인다.', 'https://image.tmdb.org/t/p/w500/4i5ncqHRIJTjzOtDk7GU3SMQZgs.jpg', 2021, 0, 0, '2026-06-08 06:34:14.741624', 'JP');
INSERT INTO public.movies VALUES (4629, 238675, '恋は緑の風の中', '["Drama"]', 'Miyoji Ieki', '["Yûsuke Satô", "Mieko Harada", "Toyoto Fukuda", "Yoshio Inaba", "Ippei Souda"]', NULL, 'https://image.tmdb.org/t/p/w500/4AOJPwmtgXubEkM7JmTsUfB1C8N.jpg', 1974, 0, 0, '2026-06-08 06:34:16.76382', 'JP');
INSERT INTO public.movies VALUES (4630, 1192213, '女教師5', '[]', 'Masaharu Ito', '["Rei Natsume", "Yoshiki Yamamoto", "Takeshi Matsuura", "Yoshika Kurokawa", "Hirozumi Sato"]', NULL, 'https://image.tmdb.org/t/p/w500/hEkgIOPnYtg8WiyT88jhXh9QLJ0.jpg', 1998, 0, 0, '2026-06-08 06:34:17.50398', 'JP');
INSERT INTO public.movies VALUES (4510, 12429, '벼랑 위의 포뇨', '["Animation", "Fantasy", "Family"]', 'Hayao Miyazaki', '["Yuria Kozuki", "Hiroki Doi", "George Tokoro", "Tomoko Yamaguchi", "Yuki Amami"]', '호기심 많은 물고기 소녀 포뇨는 따분한 바다 생활에 싫증을 느끼고, 급기야 아빠 몰래 늘 동경하던 육지로 가출을 감행한다. 해파리를 타고 육지로 올라온 포뇨는 그물에 휩쓸려 유리병 속에 갇히는 위기에 처하게 된다. 때마침 해변가에 놀러 나온 소년 소스케의 도움으로 구출되는 포뇨. 이후 소스케가 마련해 준 초록 양동이에서 소스케와의 즐거운 육지 생활을 시작한다. 하지만 곧 바다의 주인이자 포뇨의 아빠인 후지모토에 의해 포뇨는 다시 바다로 끌려가게 된다. 우여곡절 끝에 여동생들의 도움으로 탈출에 성공한 포뇨는 거대한 파도와 함께 소스케에게로 향하는데...', 'https://image.tmdb.org/t/p/w500/tGSuFBsqdXxIz3fTSBfsZU9FBMN.jpg', 2008, 0, 0, '2026-06-08 06:32:37.050448', 'JP');
INSERT INTO public.movies VALUES (4633, 1295026, '100미터.', '["Animation", "Drama"]', 'Kenji Iwaisawa', '["Tori Matsuzaka", "Shota Sometani", "Yuma Uchida", "Koki Uchiyama", "Kenjiro Tsuda"]', '선천적으로 발이 빨라 달리기에서 지는 법이 없던 토가시는 현실을 잊기 위해 무작정 달렸던 전학생 코미야를 만나 제대로 달리는 법을 가르쳐 준다. 누구보다 빠르게 달릴 때의 환희를 알게 된 코미야는 토가시에게 100M 경주를 신청하고 그날의 경기 이후 코미야는 토가시의 앞에서 사라진다. 그리고 몇 년 후, 계속 이겨야 한다는 압박감에 시달리고 있던 토가시 앞에 일본 기록 경신을 꿈꾸는 코미야가 나타나는데…', 'https://image.tmdb.org/t/p/w500/itooVuz3gka7ykr3TpOvwXYqESM.jpg', 2025, 0, 0, '2026-06-08 06:34:20.323231', 'JP');
INSERT INTO public.movies VALUES (4634, 1431489, '「これが’犯●れる’ってことだよ？」田中レモンの圧倒的な美とSカワ痴女テクでひたすらに堕とされたい パンティと写真付き', '["Drama"]', NULL, '["Karen Kaede"]', NULL, 'https://image.tmdb.org/t/p/w500/yuIIuYi9IcN2TBHFsd6AyjomA8z.jpg', 2023, 0, 0, '2026-06-08 06:34:20.999085', 'JP');
INSERT INTO public.movies VALUES (4636, 297021, '최근, 여동생의 상태가 조금 이상한 것 같다만', '["Comedy", "Fantasy", "Romance"]', 'Iggy Coen', '["Tenka Hashimoto", "Yūkichi Kobayashi", "Mayu Mitsui", "Mika Yano", "Kazue Akita"]', '서로의 부모님의 결혼으로 미츠키와 유야는 의남매가 된다. 미츠키는 그녀의 새 가족을 어려워하고, 유야는 그런 미츠키에게 어떻게 다가가야 할지 몰라 곤란해 한다. 어느 날 미츠키는 유야를 좋아하고 유야만이 자신을 천국으로 보내줄 수 있다고 믿는 히요리의 유령에 사로잡힌다.', 'https://image.tmdb.org/t/p/w500/vG56lYDARmQ8uDpvNLqOSxJiBrc.jpg', 2014, 0, 0, '2026-06-08 06:34:22.367492', 'JP');
INSERT INTO public.movies VALUES (4637, 672322, '바람의 검심 최종장: 더 비기닝', '["Action", "Adventure", "Drama", "Romance"]', 'Keishi Otomo', '["Takeru Satoh", "Kasumi Arimura", "Issey Takahashi", "Nijiro Murakami", "Masanobu Ando"]', '마침내 십자 흉터의 비밀이 밝혀진다. 혼돈의 시대, 세상에 피의 비를 뿌리던 검객 켄신과 그의 인생을 바꾼 토모에. 켄신의 모든 이야기는 여기에서 시작되고 여기에서 끝난다.', 'https://image.tmdb.org/t/p/w500/99HMvRRLZthITldpxBoMzO0Py3m.jpg', 2021, 0, 0, '2026-06-08 06:34:23.073873', 'JP');
INSERT INTO public.movies VALUES (4639, 37280, '극장판 짱구는 못말려: 어른 제국의 역습', '["Animation", "Comedy", "Adventure"]', 'Keiichi Hara', '["Akiko Yajima", "Miki Narahashi", "Keiji Fujiwara", "Yuko Mita", "Satomi Korogi"]', '떡잎마을에 20세기 박물관이 생기자 어른들은 그곳에 푹 빠져 헤어 나오지 못한다. 그러던 어느 날, 20세기 박물관은 TV를 통해 중요한 안내 방송을 한다. 그때부터 어른들은 어린아이처럼 행동하기 시작하고, 다음 날 아침에는 박물관에서 보낸 트럭을 타고 단체로 사라진다. 그 이후 남겨진 아이들도 20세기 박물관에서 보낸 트럭에 실려 어딘가로 끌려가고, 짱구와 친구들은 이리저리 도망친다.  어른들을 찾으러 간 20세기 박물관에서 이 모든 일을 꾸민 켄을 만난다. 켄은 어른들이 20세기의 냄새에 취해 어린 시절로 돌아갔다고 하면서, 자신의 목표는 20세기를 되살리는 것이라고 한다. 한편, 짱구는 20세기 박물관에서 아버지와 어머니를 구하고, 한자리에 모인 짱구 가족들은 켄의 음모를 막기 위해 마지막 결전을 준비하는데...', 'https://image.tmdb.org/t/p/w500/6N3OawAyXsJg0Ir6EQ6LHApUyzr.jpg', 2001, 0, 0, '2026-06-08 06:34:24.485364', 'JP');
INSERT INTO public.movies VALUES (4635, 3777, '거미집의 성', '["Drama", "History"]', 'Akira Kurosawa', '["Toshirō Mifune", "Isuzu Yamada", "Takashi Shimura", "Akira Kubo", "Hiroshi Tachikawa"]', '전쟁에서 이기고 성으로 돌아가던 와시즈는 산속에서 길을 잃고 헤매다가 마녀를 만난다. 마녀로부터 새 영주가 될 것이라는 예언을 들은 와시즈는 갈등에 휩싸이다 결국 영주를 죽이고 권력을 차지하는데...', 'https://image.tmdb.org/t/p/w500/6ReixPFNYsPDFJmovfMF5DvrP59.jpg', 1957, 0, 0, '2026-06-08 06:34:21.686019', 'JP');
INSERT INTO public.movies VALUES (4641, 12599, '극장판 포켓몬스터: 루기아의 탄생', '["Adventure", "Fantasy", "Animation", "Sci-Fi", "Family"]', 'Kunihiko Yuyama', '["Rica Matsumoto", "Ikue Otani", "Mayumi Izuka", "Satomi Korogi", "Tomokazu Seki"]', '오렌지제도를 여행하던 지우 일행.  그들 앞에 의문의 수집가 「라단」이 나타나 불의 신이라고 불리는 「특별한 파이어」를 붙잡아 버린다.  그것이 원인이 되어 자연계의 균형은 망가지고, 세계에는 천재지변이 일어나기 시작한다.  지우 일행은 세계를 구할 수 있을 것인가...  그리고 이 순간에 나타난 환상의 포켓몬 「루기아」는 과연 적인가 아군인가?!', 'https://image.tmdb.org/t/p/w500/a4sHmafOKKOTo2TZYtvy9CufVTz.jpg', 1999, 0, 0, '2026-06-08 06:34:25.836048', 'JP');
INSERT INTO public.movies VALUES (4642, 36728, '나루토 질풍전 극장판 3기: 불의 의지를 잇는 자', '["Action", "Adventure", "Comedy", "Drama", "Fantasy", "Animation"]', 'Masahiko Murata', '["Junko Takeuchi", "Chie Nakamura", "Kazuhiko Inoue", "Romi Park", "Satoshi Hino"]', '제4차 닌자대전을 저지하라!  제 4차 닌자대전이 일어날 위기에 놓인 닌자세계의 모습 그리고 우정과 의리로 똘똘 뭉쳐 위기를 극복해 나가는 나루토의 고군분투와 동료들의 훈훈한 이야기를 그리고 있다.', 'https://image.tmdb.org/t/p/w500/lydplyUnKCc73T54bV87sAtVXhD.jpg', 2009, 0, 0, '2026-06-08 06:34:27.604398', 'JP');
INSERT INTO public.movies VALUES (4643, 1062807, '극장판 스파이 패밀리 코드 : 화이트', '["Animation", "Comedy", "Adventure", "Action"]', 'Takashi Katagiri', '["Takuya Eguchi", "Atsumi Tanezaki", "Saori Hayami", "Kenichirou Matsuda", "Tomoya Nakamura"]', '세계 각국이 물밑에서 치열하게 정보전을 펼치고 있는 시대. 서로의 정체를 숨긴 채 결성된 위장 가족의 아버지 ''로이드(스파이)''와 어머니 ''요르(암살자)’, 딸 ''아냐(초능력자)''는 각자의 목표를 위해 비밀스러운 임무를 수행한다. 오퍼레이션 올빼미 작전을 위해 첫 가족 여행을 떠나던 중, ‘아냐’는 열차 안에서 수상한 캐리어를 발견하고 그 안의 초콜릿을 실수로 그만 삼켜버리고 마는데… 엄청난 비밀이 숨겨진 초콜릿과 여행지에서 생기는 해프닝의 연속!! 세계의 명운은, 다시 이 위장 가족에게 맡겨졌다!', 'https://image.tmdb.org/t/p/w500/rlMJfgo8xXHkqgICy9kh4CWyQTu.jpg', 2023, 0, 0, '2026-06-08 06:34:28.283704', 'JP');
INSERT INTO public.movies VALUES (4644, 12140, '이노센스', '["Animation", "Drama", "Sci-Fi"]', 'Mamoru Oshii', '["Atsuko Tanaka", "Akio Otsuka", "Koichi Yamadera", "Tamio Ohki", "Yutaka Nakano"]', '네트워크를 통해 커뮤니케이션이 가능해진 정보화 시대의 미래. 그곳에서는 인간과 사이보그, 인간형 로봇이 공존하여 살아간다. 대테러기관인 공안 9과의 버트 역시 몸의 대부분이 기계로 모토코라는 여성의 기억을 가지고 있다. 그러던 어느 날, 애완용 로봇이 주인을 죽이는 사건이 벌어지자 버트와 토구사는 해커의 방해를 극복하고 수사를 시작한다.', 'https://image.tmdb.org/t/p/w500/ver96zqifBL2jWpCyQlkCbuowpw.jpg', 2004, 0, 0, '2026-06-08 06:34:28.974915', 'JP');
INSERT INTO public.movies VALUES (4645, 1303162, '일하는 세포', '["Adventure", "Action", "Comedy", "Fantasy"]', 'Hideki Takeuchi', '["Mei Nagano", "Takeru Satoh", "Mana Ashida", "Sadao Abe", "Koji Yamamoto"]', '모든 신체는 세포의 군단이며, 각 세포는 주인이 기능을 유지할 수 있도록 제 기능을 수행한다.INSERT INTO public.movies VALUES (4646, 1033051, 'リベンジポルノ PAIN OF LOVE', '["Romance", "Drama"]', 'Daisuke Yamanouchi', '["Sakura Kirishima", "Masamitsu Kani", "Shijimi", "Hotaru Hazuki", "Manzo Shinra"]', NULL, 'https://image.tmdb.org/t/p/w500/ceFW0MQUDqu1vTDs4DFWrfbyaPx.jpg', 2019, 0, 0, '2026-06-08 06:34:30.520659', 'JP');
INSERT INTO public.movies VALUES (4647, 1400032, '텐댄스', '["Romance", "Drama"]', 'Keishi Otomo', '["Ryoma Takeuchi", "Keita Machida", "Shiori Doi", "Anna Ishii", "Shinya Hamada"]', '모든 면에서 정반대인 두 명의 댄서가 궁극의 댄스 대회에 도전하기 위해 함께 연습하기로 한다. 처음부터 격렬하게 충돌하는 두 사람. 하지만 곧 서로를 향해 마음이 움직이기 시작한다.', 'https://image.tmdb.org/t/p/w500/zLZQJS0lSTGnBBo8Eq5im4qeSXr.jpg', 2025, 0, 0, '2026-06-08 06:34:31.203372', 'JP');
INSERT INTO public.movies VALUES (4648, 1379266, '국보', '["Drama"]', 'Sang-il Lee', '["Ryo Yoshizawa", "Ryusei Yokohama", "Mitsuki Takahata", "Shinobu Terajima", "Soya Kurokawa"]', '눈앞에서 아버지를 잃고 가부키 명문가 하나이 한지로에게 맡겨진 소년 키쿠오. 운명이 결정짓는 세계에 이방인으로 뛰어든 키쿠오는 명문가의 아들 슌스케와 부딪히며 라이벌로 성장하게 된다. 서로의 길을 시험하는 치열한 경쟁에 놓인 두 사람. 세상에 단 하나뿐인 이름 국보를 향해 달리기 시작하는데…', 'https://image.tmdb.org/t/p/w500/gwQcvBdoMWolyBcKn6VbdqJdUZx.jpg', 2025, 0, 0, '2026-06-08 06:34:31.892416', 'JP');
INSERT INTO public.movies VALUES (4649, 776305, '용과 주근깨 공주', '["Animation", "Sci-Fi", "Fantasy"]', 'Mamoru Hosoda', '["Kaho Nakamura", "Ryo Narita", "Shota Sometani", "Tina Tamashiro", "Lilas Ikuta"]', '고치현의 자연이 풍요로운 마을에 사는 17세의 여고생 스즈는, 어릴 적에 어머니를 사고로 여의고 아버지와 단둘이 살고 있다. 엄마와 함께 노래하는 것을 무엇보다도 좋아했던 스즈는 그 죽음을 계기로 노래할 수 없게 되었고, 어느새 아버지와의 관계에도 틈이 생겨 현실 세계에 마음을 닫게 된다. 곡을 만드는 일만이 삶의 양식이 되던 어느 날 공교롭게도 전세계에서 50억명 이상이 모여드는 초거대 인터넷 공간의 가상세계에 벨이라는 캐릭터로 참여하게 된다.', 'https://image.tmdb.org/t/p/w500/lN9cobJaHHLy3jojZf4YKEMTZWy.jpg', 2021, 0, 0, '2026-06-08 06:34:32.578104', 'JP');
INSERT INTO public.movies VALUES (4650, 150262, '秘書 黒蠍の誘惑', '["Drama"]', 'Yutaka Ogi', '["Tsugumi Nagasawa", "Mayu Asada", "Daisuke Iijima", "Akira Yamamoto", "Mutsuo Yoshioka"]', NULL, 'https://image.tmdb.org/t/p/w500/oDf1SISqS7lxEzlfoqWx02EtSBo.jpg', 2008, 0, 0, '2026-06-08 06:34:33.253158', 'JP');
INSERT INTO public.movies VALUES (4651, 272108, '淫獣エイリアン', '["Animation", "Horror", "Sci-Fi"]', 'Norio Takanami', '["Kumiko Nishihara", "Yumi Takada", "Yoko Soumi", "Hiroko Konishi", "Sumie Baba"]', NULL, 'https://image.tmdb.org/t/p/w500/iRel9pEZjbGafxFV9lz2b0lmtxD.jpg', 1997, 0, 0, '2026-06-08 06:34:33.935502', 'JP');
INSERT INTO public.movies VALUES (4515, 820067, '극장판 5등분의 신부', '["Animation", "Comedy", "Romance"]', 'Masato Jimbo', '["Yoshitsugu Matsuoka", "Kana Hanazawa", "Ayana Taketatsu", "Miku Ito", "Ayane Sakura"]', '「낙제 직전」「공부가 싫은」미소녀 다섯 쌍둥이를  아르바이트 가정 교사로서 「졸업」까지 이끈 후타로.  배우에 전념하기 위해 휴학하기로 한 이치카의 공부를 봐주면서  「학교 축제」 준비에 힘쓰는 후타로와,  후회 없는 「학교 축제」를 만들기 위해 평소 이상으로 노력하는 요츠바.  어지러운 날들이 지나고 정신을 차려보니 「학교 축제」 전날.  후타로는 포기하지 않고 힘쓰는 이츠키의 모습에 힘입어,  니노의 각오와 미쿠의 결의, 그리고 이치카·요츠바·이츠키에 대한 마음의 답을 찾는다.  저마다의 생각을 안고 있는 와중,  드디어 시작된 고교 생활 최후의(마지막) 이벤트인 「학교 축제」 첫날.  『학교 축제 첫날 15시에 교실에 와줘』  교실에 모인 다섯 쌍둥이는, 후타로에게 어떠한 마음을 고백 받게 될까?', 'https://image.tmdb.org/t/p/w500/shtqSAsB8snS3iww99iksu2QaoZ.jpg', 2022, 0, 0, '2026-06-08 06:32:41.670488', 'JP');
INSERT INTO public.movies VALUES (4654, 44251, '드래곤볼 Z 극장판 10: 위험한 두 사람!! 슈퍼 전사는 잠들지 않는다!', '["Animation", "Action", "Sci-Fi"]', 'Shigeyasu Yamauchi', '["Masako Nozawa", "Mayumi Tanaka", "Takeshi Kusao", "Yuko Minaguchi", "Junko Shimakata"]', '예전에 손오공에게 죽은 줄 알았던 브로리는 실은 어택볼에 타고 지구로 왔다가 부상 때문에 기절한 이후 고지대의 얼음층 속에 동면하고 있었다. 그리고 몇년 후 손오천과 트랭크스는 드래곤볼을 모아서 소원을 이루려다가 갑자기 브로리가 손오천을 카카로트로 착각해 깨어나는데....', 'https://image.tmdb.org/t/p/w500/vjkFcmZNTjxKXaMHtqLFedBXTIT.jpg', 1994, 0, 0, '2026-06-08 06:34:37.765445', 'JP');
INSERT INTO public.movies VALUES (4655, 825228, '尻を撫でまわしつづけた男 痴漢日記6', '[]', 'Tadafumi Tomioka', '["Hanako Kikuchi", "Hitoe Ootake", "Mao Misaki", "Yukijiro Hotaru", "Miyako Yamaguchi"]', NULL, 'https://image.tmdb.org/t/p/w500/mCSJ6j4cseQkACtUvIPI0M0N9au.jpg', 1998, 0, 0, '2026-06-08 06:34:38.46834', 'JP');
INSERT INTO public.movies VALUES (4656, 315846, '바닷마을 다이어리', '["Drama"]', 'Hirokazu Kore-eda', '["Haruka Ayase", "Masami Nagasawa", "Kaho", "Suzu Hirose", "Ryo Kase"]', '15년 전 가족을 버린 아버지의 장례식, 어릴 적 나와 꼭 닮은 아이를 만났다. 조그마한 바닷가 마을 카마쿠라에 살고 있는 사치, 요시노, 치카는 15년 전 집을 떠난 아버지의 부고를 듣고 장례식장으로 향한다. 아버지에 대한 미움도, 추억도 어느덧 희미해졌지만 홀로 남겨진 이복 여동생 스즈에게만은 왠지 마음이 쓰이는데..', 'https://image.tmdb.org/t/p/w500/6aV7pcVSrRd41GCKkt9eLVgEPAX.jpg', 2015, 0, 0, '2026-06-08 06:34:39.15448', 'JP');
INSERT INTO public.movies VALUES (4657, 1056444, '너의 색', '["Animation", "Drama"]', 'Naoko Yamada', '["Sayu Suzukawa", "Akari Takaishi", "Taisei Kido", "Yui Aragaki", "Aoi Yuuki"]', '사람을 색으로 느끼는 엉뚱한 여고생 ‘토츠코’. ‘토츠코’는 어느 날 학교에서 한번도 느껴보지 못한 찬란하고 아름다운 색을 가진 소녀 ‘키미’를 만난다.  그리고 우연히 작은 책방에서 조우한 음악을 좋아하는 소년 ‘루이’까지 합세하여 오랫동안 꿈꾸던 밴드를 결성하게 되고 서로에게 서서히 스며들기 시작하는데..!  올가을, 무지갯빛 청춘을 위한 노래가 시작된다!', 'https://image.tmdb.org/t/p/w500/jPlUGDUR5LbN3AB9eMwC2ixyC4R.jpg', 2024, 0, 0, '2026-06-08 06:34:39.838044', 'JP');
INSERT INTO public.movies VALUES (4658, 175168, '레이프 좀비: 러스트 오브 더 데드', '["Comedy", "Horror"]', 'Naoyuki Tomomatsu', '["Alice Ozawa", "Asami", "Yui Aikawa", "Saya Kobayashi", "Takeshi Nakazawa"]', '섹스를 경험한 모든 남자가 ‘레이프 좀비’가 된 세계에서, 좀비들로부터 자신을 지키기 위해 무장한 여자들과 오타쿠 남자들의 싸움을 그린 영화', 'https://image.tmdb.org/t/p/w500/qf52YWxGEGFCnd1s3iSNixBjyyk.jpg', 2012, 0, 0, '2026-06-08 06:34:40.547766', 'JP');
INSERT INTO public.movies VALUES (4659, 473197, '삼국지 제1장 영웅들의 새벽', '["Animation", "History", "Action", "Drama"]', 'Tomoharu Katsumata', '["Tetsuya Watari", "Teruhiko Aoi", "Taro Ishida", "Takeshi Aono", "Masane Tsukayama"]', NULL, 'https://image.tmdb.org/t/p/w500/bz4aPckUUUsrLVTnEIztrYW3yZT.jpg', 1992, 0, 0, '2026-06-08 06:34:41.227054', 'JP');
INSERT INTO public.movies VALUES (4662, 1148677, '극장판 도라에몽: 진구의 지구 교향곡', '["Animation", "Family", "Fantasy", "Adventure", "Comedy", "Sci-Fi"]', 'Kazuaki Imai', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Subaru Kimura", "Tomokazu Seki"]', '학교 음악회를 위해 서투른 리코더 연습을 하는 진구. 그 앞에 나타난 미스터리한 소녀 미카는 진구의 느릿하고 느긋한 리코더 소리가 마음에 들어  음악이 에너지가 되는 행성의 ‘파레의 전당’에 도라에몽과 친구들을 초대한다. 미카는 전당을 구하기 위해 음악의 달인 ‘비르투오소’를 찾고 있었던 것!  하지만 세계에서 음악을 지워버리는 섬뜩한 생명체가 다가오면서 지구에 위기가 오는데…! 과연 ‘음악의 미래’, 그리고 지구를 구할 수 있을까?', 'https://image.tmdb.org/t/p/w500/hDoluzOTRZKR2fNmoWn87j9Z5Gt.jpg', 2024, 0, 0, '2026-06-08 06:34:43.403692', 'JP');
INSERT INTO public.movies VALUES (4517, 81, '바람계곡의 나우시카', '["Adventure", "Animation", "Fantasy"]', 'Hayao Miyazaki', '["Sumi Shimamoto", "Ichiro Nagai", "Gorō Naya", "Yoji Matsuda", "Yoshiko Sakakibara"]', '천 년 전, 불의 7일간으로 불리는 전쟁이 끝난 후 지구는 죽음의 행성으로 변했다. 점점 커지는 곰팡이의 숲인 부해가 유독가스를 내뿜어 사람이 살 수 있는 땅도 얼마 남지 않았다. 자연과 대화를 나눌 수 있는 특별한 소녀 나우시카는 그 중 깨끗한 바람계곡에서 살고 있지만 부해는 이곳마저 먹어치울 듯 가깝게 다가온다. 그러나 위기는 인간들의 다툼에서 시작된다. 군사제국 토르메키아가 불의 7일간을 초래했던 병기 거신병을 부활시키려는 계획을 시작했기 때문. 바람계곡은 분쟁에 휘말리고 나우시카는 토르메키아와 맞서는 도시 국가 페지테의 인질이 된다. 그 와중에 나우시카는 부해가 지구를 정화하고 있었다는 사실을 깨닫는데...', 'https://image.tmdb.org/t/p/w500/gW5Djz91cgchPqrQElDfSXM3fn1.jpg', 1984, 0, 0, '2026-06-08 06:32:43.157193', 'JP');
INSERT INTO public.movies VALUES (4524, 51739, '마루 밑 아리에티', '["Fantasy", "Animation", "Family"]', 'Hiromasa Yonebayashi', '["Mirai Shida", "Ryunosuke Kamiki", "Tomokazu Miura", "Keiko Takeshita", "Kirin Kiki"]', '교외에 위치한 오래된 저택의 마루 밑에는 인간들의 물건을 몰래 빌려 쓰며 살아가는 소인들이 살고 있다. 그들의 철칙은 인간에게 정체를 들키면 그 집을 당장 떠나야 한다는 것. 14살이 된 아리에티는 부모님의 도움 없이 홀로 인간 세상으로 뛰어든다. 첫 목표는 각설탕. 생쥐와 바퀴벌레의 방해 공작에도 무사히 각설탕을 손에 넣은 아리에티는 두 번째 목표인 티슈를 얻으러 간 방에서 요양을 온 소년 쇼우의 눈에 띄게 된다. 인간은 무서운 존재라고 생각했던 것과 달리 쇼우의 다정한 모습에 조금씩 마음을 열기 시작한 아리에티. 마루 밑 세계의 규칙을 어기고 쇼우에게 다가가던 어느 날, 아리에티 가족에게 예기치 않은 위험이 찾아오는데...', 'https://image.tmdb.org/t/p/w500/1Xz0WSXeXzyTCbHADGBpmEaDpZl.jpg', 2010, 0, 0, '2026-06-08 06:32:48.437241', 'JP');
INSERT INTO public.movies VALUES (4666, 667520, '울고 싶은 나는 고양이 가면을 쓴다', '["Animation", "Drama", "Romance", "Fantasy"]', 'Tomotaka Shibayama', '["Mirai Shida", "Natsuki Hanae", "Koichi Yamadera", "Hiroaki Ogi", "Minako Kotobuki"]', '난 네가 맘에 드는데, 넌 내게 관심이 없나 봐. 그래서 고양이로 변신했어, 너랑 친해지고 싶어서. 하지만 너무 오랫동안 고양이로 있었던 탓일까, 어느새 경계가 흐려진 소녀. 인간과 고양이의 갈림길에서 선택의 순간을 맞는다.', 'https://image.tmdb.org/t/p/w500/g9ArpDiGMz9OCCCdI1JKmS5JteH.jpg', 2020, 0, 0, '2026-06-08 06:34:46.158908', 'JP');
INSERT INTO public.movies VALUES (4668, 431819, '쏘아올린 불꽃, 밑에서 볼까? 옆에서 볼까?', '["Animation", "Romance", "Fantasy", "Drama"]', 'Nobuyuki Takeuchi', '["Suzu Hirose", "Masaki Suda", "Mamoru Miyano", "Shintaro Asanuma", "Toshiyuki Toyonaga"]', '불꽃축제를 앞둔 어느 바닷가 마을  아이들은 ‘불꽃은 옆에서 보면 둥글까? 납작할까?’라는 것에 대한 이야기로 떠들썩하지만  갑작스런 전학을 앞둔 나즈나는 마음이 복잡하다.  우리 사랑의 도피를 떠나자.  노리미치에게 둘이서 마을을 떠날 것을 제안하는 나즈나.  하지만 어머니에게 발각된 나즈나는 집으로 끌려 들어가고  남겨진 노리미치는 나즈나가 간직하고 있던 구슬을 던져본다.  만약, 그때 내가…  나즈나와의 즐거웠던 순간으로 되돌아간 노리미치.  처음으로 나즈나와 단둘이 함께하기 위해, 마지막으로 나즈나에게 진심을 고백하기 위해  반복되는 하루를 몇 번이고 다시 겪게 되는데…  다시 불꽃이 터지면, 첫사랑도 이루어질까?', 'https://image.tmdb.org/t/p/w500/ca4O5RyS9aYuJq7Vrtd9YDWSlQP.jpg', 2017, 0, 0, '2026-06-08 06:34:47.534943', 'JP');
INSERT INTO public.movies VALUES (4671, 1542877, '劇場版「暗殺教室」みんなの時間', '["Animation", "Comedy", "Action", "Sci-Fi"]', 'Masaki Kitamura', '["Jun Fukuyama", "Tomokazu Sugita", "Shizuka Itoh", "Mai Fuchigami", "Nobuhiko Okamoto"]', NULL, 'https://image.tmdb.org/t/p/w500/dfrZ7VHcurFhLm2Hk6xyjRILc5d.jpg', 2026, 0, 0, '2026-06-08 06:34:49.609699', 'JP');
INSERT INTO public.movies VALUES (4665, 185095, '우노 코이치로의 젖은 스윙', '["Comedy"]', 'Shusuke Kaneko', '["Natsuko Yamamoto", "Arisa Hayashi", "Yūgo Sawada", "Satoru Harada", "Rika Ishii"]', '한 여고생이 여자 테니스부 리더를 짝사랑한다. 하지만 코트 밖에서는 항상 남자 선수들과 함께 득점을 올린다.', 'https://image.tmdb.org/t/p/w500/qWkiMyrLXHiThjP9cGpO86vPABf.jpg', 1984, 0, 0, '2026-06-08 06:34:45.475577', 'JP');
INSERT INTO public.movies VALUES (4539, 1159311, '나의 히어로 아카데미아 더 무비: 유어 넥스트', '["Animation", "Action", "Adventure", "Sci-Fi"]', 'Tensai Okamura', '["Daiki Yamashita", "Meru Nukumi", "Mamoru Miyano", "Kenta Miyake", "Nobuhiko Okamoto"]', '“다음은 너다” 초자연능력 ‘개성’을 가진 인간이 당연해진 세계에서 옛 ‘평화의 상징’ NO.1 히어로 ‘올마이트’가 악의 제왕 ‘올 포 원’과의 사투 직후 한 말. ‘올마이트’의 의지는 데쿠와 유에이 고등학교 히어로과로 이어져 왔다. 유에이 2년 차 봄, 히어로 VS 빌런의 전면전이 발발하고 황폐해진 사회에 수수께끼의 남자가 나타난다. 스스로를 ‘올마이트를 대신하는 새로운 상징’이라고 말하는 ‘다크마이트’는 자신의 야망을 위해 ‘개성’으로 거대한 요새를 만들어 마을과 사람들을 차례로 삼켜간다! ‘다크마이트’의 등장과 동시에 특별한 ‘개성’을 지닌 ‘안나’라는 소녀, 그리고 그녀를 ‘아가씨’라고 부르는 ‘줄리오’라는 남자가 나타나는데… 데쿠와 바쿠고, 토도로키, 그리고 유에이 고교 1학년 A반은 ‘다크마이트’에 맞서 세계를 지킬 수 있을까? “다음은 우리다!”', 'https://image.tmdb.org/t/p/w500/rSJnz7FqxEIe5uzAZbWSzc8bk5f.jpg', 2024, 0, 0, '2026-06-08 06:32:59.857682', 'JP');
INSERT INTO public.movies VALUES (4547, 292777, '꽃과 뱀: 더 제로', '["Mystery", "Thriller", "Drama", "Horror"]', 'Hajime Hashimoto', '["Maiko Amano", "Noriko Hamada", "Rina Sakuragi", "Kanji Tsuda", "Naoki Kawano"]', '일반 여성을 납치하여 성적 노예로 삼아 실시간 스트리밍으로 생중계하는 불법웹사이트 ‘바빌론’. 그들을 처단하기 위해 스스로 성적 노예가 되어 추적하는 여형사 미사키와 남편의 빚을 갚기 위해 바빌론에 들어오게 된 그곳에 감금 된 시즈코. 주체할 수 없는 성욕에 괴로워하는 전업주부 루리. 이 세 여자는 각기 다른 이유로 ‘바빌론’에 모이게 된다. 어릴 적부터 ‘바빌론’에 교육받아 온 냉혈 안 ‘에디’. 여자를 가지고 무슨 짓을 하던 아무런 가책도 성욕도 느끼지 못한다. 하지만 착한 시즈코에게 어느 샌가 태어나 처음 느끼는 감정을 가지게 되고 그들은 만인들 앞에서 성 학대가 아닌 진정한 둘만의 교감을 가지게 된다. 그리고 밝혀지는 ‘바빌론’의 계획된 무시무시한 충격적 진실이 그들에게 덮쳐오는데……', 'https://image.tmdb.org/t/p/w500/vF4cmgk1EDcsPUcz3xg0TPGK2Cz.jpg', 2014, 0, 0, '2026-06-08 06:33:06.28402', 'JP');
INSERT INTO public.movies VALUES (4676, 11948, '전장의 크리스마스', '["Drama", "History"]', 'Nagisa Ōshima', '["David Bowie", "Tom Conti", "Ryuichi Sakamoto", "Takeshi Kitano", "Jack Thompson"]', '제2차 세계대전, 인도네시아 자바섬. 무사도 정신을 맹신하는 일본군 대위 요노이는 포로수용소에서 영국군 소령 잭 셀리어스와 마주하게 된다. 사형 직전의 잭을 자신의 수용소로 데려온 요노이는 알 수 없는 매력에 끌리면서도 그의 자유분방한 태도에 끊임없이 갈등한다. 한편, 유일하게 일본어를 구사하는 영국군 중령 존 로렌스는 영국군과 일본군, 양측 사이에서 중재를 시도하지만, 수용소의 분위기는 점점 격화된다. 전쟁의 포로이자 인간으로서의 모습 사이에서 고뇌하는 이들. 과연 전쟁터 한가운데에서 크리스마스의 기적은 일어날 수 있을까?', 'https://image.tmdb.org/t/p/w500/qJzGgjUrFMUvdLi9iTexbH0x6mK.jpg', 1983, 0, 0, '2026-06-08 06:34:53.954428', 'JP');
INSERT INTO public.movies VALUES (4677, 39107, '드래곤볼 Z 극장판 12: 퓨전의 부활!! 손오공과 베지터', '["Animation", "Action", "Sci-Fi"]', 'Shigeyasu Yamauchi', '["Masako Nozawa", "Ryo Horikawa", "Takeshi Kusao", "Daisuke Gori", "Hiromi Tsuru"]', '지옥의 악한 영혼 정화통을 관리하는 붉은 오니가 음악에 심취해서 딴청피우다가 정화통이 폭주해서 그 안에 있던 악한영 혼의 엑기스를 뒤집어쓰고 쟈넨바라는 괴물이 되었다. 그리고 예전에 죽은 악당들이 전부 되살아나서 지구를 공격하는데...', 'https://image.tmdb.org/t/p/w500/xsMnNpTrBTctrKf7bKS5cSCTZso.jpg', 1995, 0, 0, '2026-06-08 06:34:54.633593', 'JP');
INSERT INTO public.movies VALUES (4678, 287590, '세인트 세이야: 레전드 오브 생츄어리', '["Action", "Animation", "Fantasy"]', 'Keiichi Sato', '["Kaito Ishikawa", "Ayaka Sasaki", "Kenji Akabane", "Kensho Ono", "Nobuhiko Okamoto"]', '`성역 십이궁 편`을 바탕으로 스스로의 운명과 사명에 농락당하는 소녀 사오리와 그녀를 지키기 성시들의 젊은 청동 세인트 (청동 세인트)들의 사투를 그린다.', 'https://image.tmdb.org/t/p/w500/5qCWYD1E5x1KkscSosvgRU2NBet.jpg', 2014, 0, 0, '2026-06-08 06:34:55.318662', 'JP');
INSERT INTO public.movies VALUES (4679, 105929, '망팔무사도, 사부라이', '["Action"]', 'Takashi Harada', '["Gorō Ibuki", "Emi Jo", "Keiko Aikawa", "Harumi Kuri", "Aki Takagi"]', '보하치 일족은 막부 깊숙이 뿌리내린, 가장 타락하고 악랄한 조직으로, 대대로 일본의 성매매 시장을 지배해왔다.INSERT INTO public.movies VALUES (4551, 303857, '드래곤볼 Z 극장판 15: 부활의 F', '["Action", "Animation", "Sci-Fi"]', 'Tadayoshi Yamamuro', '["Masako Nozawa", "Ryo Horikawa", "Ryusei Nakao", "Koichi Yamadera", "Masakazu Morita"]', '파괴의 신 비루스와의 대결이 끝나고, 평화를 찾은 지구에 프리저군의 생존자들이 프리저를 부활시키기 위해 몰래 잠입, 드래곤볼 7개를 모두 모으는데 성공한다. 이를 이용해 부활한 프리저는 손오공을 비롯한 사이어인에 대한 복수를 위해 수 많은 병사를 이끌고 지구를 침략하고, 손오반과 피콜로, 크리링 등은 이에 맞서 싸우지만 더욱 강해진 프리저의 파워 앞에 속수무책으로 당하고 만다. 한편, 비루스의 별에서 수련중이던 손오공과 베지터는 뒤늦게 프리저의 부활 소식을 듣게되는데…  끝없이 강해지고 싶은 손오공과 지옥에서 부활한 프리저!  다시 한번 최악의 위기에 직면한 지구의 운명은 과연?!', 'https://image.tmdb.org/t/p/w500/e6kmwINMGyPNxuoZyjIlhiXyYGH.jpg', 2015, 0, 0, '2026-06-08 06:33:08.982426', 'JP');
INSERT INTO public.movies VALUES (4683, 231164, '달콤한 채찍', '["Drama", "Crime"]', 'Takashi Ishii', '["Mitsu Dan", "Yuki Mamiya", "Naoto Takenaka", "Hiroko Nakajima", "Tsuyoshi Nakano"]', '오이시 케이의 동명 소설을 원작으로 하여, ''꽃과 뱀''의 이시이 다카시 감독이 메가폰을 잡았다.', 'https://image.tmdb.org/t/p/w500/4mXbvGaQuWteEyCAgszKMmQEcqS.jpg', 2013, 0, 0, '2026-06-08 06:34:58.759315', 'JP');
INSERT INTO public.movies VALUES (4685, 16804, '굿바이', '["Drama"]', 'Yojiro Takita', '["Masahiro Motoki", "Hirosue Ryoko", "Tsutomu Yamazaki", "Kimiko Yo", "Tetta Sugimoto"]', '첼로 연주자인 다이고(모토키 마사히로)는 어렵게 오케스트라에 자리를 얻지만 입단하자마자 재정난으로 오케스트라가 해체된다. 거액의 대출까지 받아 첼로를 구입한 그는 생계가 막막해지자 고향 야마가타로 돌아갈 계획을 세운다. 아내(히로스에 료코)와 함께 돌아가신 어머니가 물려준 집으로 이사를 한 다이고는 고수익 보장에 초보 환영이라는 구인 광고를 발견하고 지원한다. 여행 도우미라는 문구를 보고 찾아갔으나 그곳은 납관 전문회사. 기겁하는 다이고에게 사장(야마자키 쓰토무)은 고액의 월급을 제안한다. 임시방편으로 일을 시작한 다이고는 첫날부터 호된 신고식을 치르고 회의와 갈등에 빠지지만, 사장의 프로다운 직업 정신과 사자를 보내는 경건한 태도에 감화되어 조금씩 생각이 바뀐다.', 'https://image.tmdb.org/t/p/w500/zoc6mZepgC27aVD0X31eiNaJb5X.jpg', 2008, 0, 0, '2026-06-08 06:35:00.27637', 'JP');
INSERT INTO public.movies VALUES (4687, 36201, '디지몬 어드벤처 02: 디아블로몬의 역습', '["Adventure", "Animation", "Family", "Sci-Fi"]', 'Hiroyuki Kakudou', '["Reiko Kiuchi", "Junko Noda", "Rio Natsuki", "Koichi Tochika", "Megumi Urawa"]', '인터넷 세상에 해파리처럼 생긴 디지몬 쿠라몬이 증식하기 시작한다. 아이들이 3년 전 쓰러뜨린 디아블로몬의 소행으로 보이는 쿠라몬 무리는 급기야 현실 세계까지 뒤덮으며 대혼란을 야기하는데...', 'https://image.tmdb.org/t/p/w500/8ISAE7Dn4ERpn7M0sH1HYt8VTH1.jpg', 2001, 0, 0, '2026-06-08 06:35:01.653236', 'JP');
INSERT INTO public.movies VALUES (4688, 1661143, '重役秘書3', '["Drama"]', 'Koichi Kobayashi', '["Mizuki Kanno", "Harumi Ogawa", "Takashi Matsuyama"]', NULL, 'https://image.tmdb.org/t/p/w500/qX2CNh8NCjpTANDGHx9V9j4RzYJ.jpg', 1998, 0, 0, '2026-06-08 06:35:02.357986', 'JP');
INSERT INTO public.movies VALUES (4689, 40355, '淫獣学園3 くノ一狩り', '["Action", "Horror"]', 'Kaoru Kuramoto', '["Saya Hidaka", "Junko Asamiya", "Momoko Nishida"]', NULL, 'https://image.tmdb.org/t/p/w500/e0N7ZACXC4oTB7NKeXES1dC2ZVP.jpg', 1996, 0, 0, '2026-06-08 06:35:03.033993', 'JP');
INSERT INTO public.movies VALUES (4553, 317442, '나루토 질풍전 극장판 7기: 더 라스트', '["Action", "Romance", "Animation"]', 'Tsuneo Kobayashi', '["Junko Takeuchi", "Nana Mizuki", "Jun Fukuyama", "Chie Nakamura", "Showtaro Morikubo"]', '나루토와 사스케가 인연의 대결을 결판 지었던 2년 후  아직 전하지 못한 마음, 그 숨겨온 마음의 행방은…?  전쟁이 끝나고 평화로운 나뭇잎 마을. 나루토는 이제 전쟁 영웅이 되어 마을의 인기를 한 몸에 받는 인기남이 되어 있다. 그런 나루토를 바라보는 히나타는 자신의 마음을 전하기 위해 남몰래 짠 목도리를 나루토에게 전하고 싶지만 아직 전하지 못하고 있다. 그때 갑자기 의문의 남자가 나타나고, 그는 “너희는 곧 멸망할 운명이다. 그 전에 히나타, 널 꼭 맞이하러 오지.”라는 기묘한 말을 남긴 채 사라진다.   육도선인의 동생은 달에 쫓겨가 살고 있는데 그의 후손인 오오츠키 토네루는 권력 암투와 대결에 집중하는 지구를 보고 육도선인의 지구는 이미 실패했다고 생각한다. 이제 토네루는 달과 지구를 충돌시켜 지구를 폭파하려고 하는데…  의문의 남자 정체는 차크라의 시초이자 과거에 나루토, 사스케와 사투를 벌였던 오츠츠키 카구야의 후손. 괴뢰군을 거느린 토네리가 나타나 압도적인 힘으로 나루토 일행을 물리치고, 히나타는 결국 그의 손에 넘어간다. 그 무렵 지상에서는 쏟아지는 운석을 막는 장렬한 방어전이 한계에 다다르고 있다. 마침내 드러난 ‘진정한 최종 계획’이란?! 다가오는 지구 최후의 날, 저마다 굽힐 수 없는 마음이 시간을 초월하여 격돌한다!', 'https://image.tmdb.org/t/p/w500/zAxdiiyYbwmCUqzRJAsF3My9bsI.jpg', 2014, 0, 0, '2026-06-08 06:33:11.069385', 'JP');
INSERT INTO public.movies VALUES (4554, 77617, '명탐정 코난: 침묵의 15분', '["Animation", "Action", "Crime", "Mystery"]', 'Yasuichiro Yamamoto', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Rikiya Koyama", "Megumi Hayashibara"]', '지난 4년 동안 오만불손한 행동으로 도의 행정을 망쳤으니 천벌을 받아 마땅하다!  도지사 앞으로 익명의 협박 편지가 도착하고 그 후 대도심 한 복판에서의 폭탄 테러가 발생한다! 코난의 기지로 폭파 15초를 남겨두고 대참사를 막게 된다. 이 사건으로 인해 코난은 더 큰 참사가 발생할 것이라는 것을 예견하고 도지사 참석 예정인, 이전 5주년 기념식이 준비 되고 있는 북촌 마을을 찾아간다. 그 곳에서 만난 8년 만에 모인 북촌 마을 동창생 5명, 그들이 서로 얽혀있는 8년 전 뺑소니 교통 사고 등 수상한 과거의 사건들을 되짚어 가는 도중에 수수께끼 같은 설원 속 살인 사건이 발생한다. 범인을 밝혀내기도 전에 북촌댐 폭파 테러라는 또 다른 위기가 찾아오고, 코난은 다시 한 번 대 참사의 위기에 맞서게 되는데…', 'https://image.tmdb.org/t/p/w500/7KuZPC7tn9hVh30ye4WYlWyl2gc.jpg', 2011, 0, 0, '2026-06-08 06:33:11.742329', 'JP');
INSERT INTO public.movies VALUES (4692, 1330415, '制服暴行魔　放課後狩り', '[]', 'Sakae Nitta', '["Mami Ichinose", "Masato Kudo", "Rei Takagi", "Nao Saeki", "Yoshimi Shirato"]', NULL, 'https://image.tmdb.org/t/p/w500/YFHbmV0lMVgzjaZiDmCGbm21sm.jpg', 1991, 0, 0, '2026-06-08 06:35:06.191353', 'JP');
INSERT INTO public.movies VALUES (4695, 37933, '게드전기: 어스시의 전설', '["Animation", "Fantasy", "Adventure"]', 'Goro Miyazaki', '["Junichi Okada", "Aoi Teshima", "Bunta Sugawara", "Yuko Tanaka", "Teruyuki Kagawa"]', '서쪽 바다 끝에 살고 있던 용이 갑자기 인간 세계에 모습을 드러낸 이후 곳곳에서 작물이 죽어가고 가옥이 쓰러져 가고, 마법사들이 마법을 잃어버리는 기이한 일이 연이어 발생하기 시작한다. 한편 왕자의 신분과 나라를 버리고 여행을 하던 아렌은 악의 근원을 찾아 여행 중이던 대현자 하이타카(게드)와 우연히 만나게 되고, 이들은 함께 모험을 떠나게 된다. 그들은 사건의 실마리가 될 마을인 호트타운에 이르게 된다. 그곳은 인신매매가 행해지고, 모조품만이 거래되며, 마약을 일삼는 어둠의 마을. 거리를 돌아다니던 아렌은 위험에 처한 묘령의 소녀 테루를 도와주게 되는데...', 'https://image.tmdb.org/t/p/w500/9rZfpqUx8Q4uijHPte0C17QWERI.jpg', 2006, 0, 0, '2026-06-08 06:35:08.247662', 'JP');
INSERT INTO public.movies VALUES (4696, 20982, '나루토 질풍전 극장판 1기: 나루토의 죽음', '["Animation", "Action", "Fantasy"]', 'Hajime Kamegaki', '["Junko Takeuchi", "Chie Nakamura", "Yōichi Masukawa", "Koichi Tochika", "Ayumi Fujimura"]', '미래 예언과 마귀 봉인 능력을 지닌 원령나라의 무녀가 부활한 마귀의 표적으로 지목되자 나루토와 친구들은 무녀를 지키기 위해 길을 떠난다. 그러나 원령나라에 도착한 일행에게 무녀는 나루토의 죽음을 예언하고 이에 모두들 충격에 휩싸이는데...', 'https://image.tmdb.org/t/p/w500/nqk3BmndXLk3viksmBs9QYAXGXn.jpg', 2007, 0, 0, '2026-06-08 06:35:09.051525', 'JP');
INSERT INTO public.movies VALUES (4697, 685819, '人妻スチュワーデス 制服昇天', '[]', 'Hiroyoshi Takishima', '["Chisato Kawamura", "Yumi Yoshiyuki", "Sayuri Shinohara", "Manzo Shinra", "Yoshihisa Nemoto"]', NULL, 'https://image.tmdb.org/t/p/w500/dft9t7lNBaFnQluwR7Y2iLKzdqv.jpg', 1998, 0, 0, '2026-06-08 06:35:10.733737', 'JP');
INSERT INTO public.movies VALUES (4694, 149871, '가구야공주 이야기', '["Animation", "Drama", "Fantasy"]', 'Isao Takahata', '["Aki Asakura", "Takeo Chii", "Nobuko Miyamoto", "Kengo Kora", "Atsuko Takahata"]', '깊은 산속 마을의 할아버지는 우연히 빛나는 대나무 속에서 여자 아이를 발견하고 집으로 데려온다. 손바닥 위에 올라갈 정도의 크기에서 금세 아기로, 그리고 또 반나절 만에 아름다운 소녀로 성장하는 신비로운 아이. 가구야라고 이름 지어진 그녀의 미모는 널리 소문이 퍼져, 장안의 내로라 하는 귀공자 5명이 청혼을 해 오는가 하면, 급기야 황제까지 가구야에게 관심을 보이기 시작한다. 하지만 가구야는 산속 마을에서의 첫사랑 스테마루를 잊지 못하고 그를 찾아가 누구에게도 말하지 않았던 비밀을 털어놓는데... 과연 가구야는 그토록 원했던 꿈과 사랑을 이룰 수 있을까?', 'https://image.tmdb.org/t/p/w500/zcm38w01bnAdRVptcOCuEuRoc3B.jpg', 2013, 0, 0, '2026-06-08 06:35:07.556103', 'JP');
INSERT INTO public.movies VALUES (4570, 455476, '세인트 세이야: 더 비기닝', '["Fantasy", "Action", "Sci-Fi"]', 'Tomek Bagiński', '["Mackenyu", "Madison Iseman", "Diego Tinoco", "Mark Dacascos", "Nick Stahl"]', '강력한 힘을 가진 전쟁과 지혜의 신 ‘아테나’의 환생! 세상을 구할 수호 기사가 깨어난다!  어린 시절 누나 ‘패트리샤’가 납치된 후 홀로 자란 ‘세이야’  슬럼가 지하 격투장에서 벌어지는 결투로 근근이 살아가던 중, 위기의 상황에서 자신도 알지 못했던 미스터리한 힘이 발현되면서 ‘아테나’를 찾고 있던 ‘구라드’의 무장 조직에게 쫓기게 된다.  수수께끼의 남자 ‘알먼 키도’에 의해 가까스로 목숨을 구한 ‘세이야’는 그를 따라 도착한 은신처에서 ‘아테나’의 환생인 ‘시에나’와 마주한다.  오래전, 다른 신들에 맞서 인간을 지키던 전쟁과 지혜의 신 ‘아테나’ ‘알먼 키도’는 ‘시에나’에게 잠재된 ‘아테나’의 힘이 곧 깨어날 것이며, ‘세이야’는 ‘아테나’를 수호하고 세상을 지킬 성투사의 운명을 가졌다는 사실을 알려주는데...', 'https://image.tmdb.org/t/p/w500/fBNl8kpFMz5ugi3RGYfenKctzjq.jpg', 2023, 0, 0, '2026-06-08 06:33:24.217947', 'JP');
INSERT INTO public.movies VALUES (4700, 476292, '이별의 아침에 약속의 꽃을 장식하자', '["Animation", "Drama", "Fantasy"]', 'Mari Okada', '["Manaka Iwami", "Miyu Irino", "Yuuki Sakurai", "Ai Kayano", "Yuki Kaji"]', '10대 중반에 외모의 성장이 멈추고 수백년을 사는 장수 민족 이올프는 인간이 사는 마을에서 멀리 떨어져 조용히 살고 있었다.  하지만 그들의 온화한 일상은 장수의 피를 요구하는 메자테 군에 의해 파괴된다. 모든 것을 잃고 외톨이가 된 이올프의 소녀 마키아는 숲을 방황하던 중 부모를 잃은 아기를 운명적으로 만나 그를 키워 나가기로 결심한다.', 'https://image.tmdb.org/t/p/w500/x4lFC7knq631uFzGsOiu4xZ9ZYQ.jpg', 2018, 0, 0, '2026-06-08 06:35:13.262592', 'JP');
INSERT INTO public.movies VALUES (4701, 728754, '도라에몽: 스탠바이미 2', '["Animation", "Adventure", "Comedy", "Sci-Fi", "Drama", "Family", "Fantasy"]', 'Takashi Yamazaki', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Subaru Kimura", "Tomokazu Seki"]', '어느 날 진구는 돌아가신 할머니와의 추억이 담긴 낡은 곰 인형을 발견하고 할머니가 보고 싶은 마음에 도라에몽의 4차원 비밀도구 타임머신을 타고 과거로 향한다. 느닷없이 찾아온 소년을 금세 진구라고 믿어주시는 할머니는 한 가지 소원을 말씀하시는데…', 'https://image.tmdb.org/t/p/w500/3YST9Tnkt69FY2sinyJquVxVHcB.jpg', 2020, 0, 0, '2026-06-08 06:35:14.069269', 'JP');
INSERT INTO public.movies VALUES (4703, 1069497, 'あやしい人妻　テレクラ・リポート', '["Romance", "Drama"]', 'Hiroaki Ito', '["Hitoe Ootake", "Yōsuke Nakajima", "Misa Jono", "Hiromi Tokunaga", "Tetsu Watanabe"]', NULL, 'https://image.tmdb.org/t/p/w500/iZRJqnsItYZ8fYX3wLchqkBfCor.jpg', 1996, 0, 0, '2026-06-08 06:35:15.791438', 'JP');
INSERT INTO public.movies VALUES (4705, 334376, '공각기동대 신극장판', '["Sci-Fi", "Animation"]', 'Kazuya Nomura', '["Maaya Sakamoto", "Ikkyu Juku", "Kenichirou Matsuda", "Tarusuke Shingaki", "Shunsuke Sakuya"]', '2029년 3월, 전후 최대의 사건으로 불리는 일본 총리 암살사건이 벌어지자, 쿠사나기 소령은 사이보그 대원들로 구성된 정예 부대를 이끌고 수색에 나선다.  대테러의 배후를 파헤치던 쿠사나기 소령은 자신과 똑같은 모습을 한 사이보그를 뒤쫓던 중, 그녀의 출생에 얽힌 충격적인 진실을 마주하게 되는데…  드디어 ‘공각기동대’의 전설적인 서막이 열린다!  “자신의 고스트를 따르라!”', 'https://image.tmdb.org/t/p/w500/w0l9AgKlMxjVPeK7GSTjvwPIf6T.jpg', 2015, 0, 0, '2026-06-08 06:35:17.445989', 'JP');
INSERT INTO public.movies VALUES (4706, 384345, '극장판 도라에몽:신 진구의 버스 오브 재팬', '["Animation", "Adventure", "Fantasy", "Sci-Fi", "Family"]', 'Shinnosuke Yakuwa', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Tomokazu Seki", "Subaru Kimura"]', '가출을 결심한 도라에몽과 친구들은 타임머신을 타고 아무도 없는 7만년 전 원시시대로 떠난다. 자연 속에서 신나게 자유를 즐기던 도라에몽과 친구들은 다시 집으로 돌아오지만, 그곳에서 시간의 틈에 빠져 현대로 오게 된 원시인 ‘쿠쿠루’를 만나게 된다. 그러던 중 쿠쿠루의 부족인 태양족이 정령왕 ‘기가좀비’와 어둠족에게 습격 당했다는 소식을 듣게 되고, 마침내 도라에몽과 친구들은 쿠쿠루와 함께 원시시대로 돌아가 태양족을 구하기 위해 맞서는데...', 'https://image.tmdb.org/t/p/w500/z72rGzQ3PFyzXNPSpFpXLotfoBY.jpg', 2016, 0, 0, '2026-06-08 06:35:18.348859', 'JP');
INSERT INTO public.movies VALUES (4702, 1317276, '극장판 기븐 바다로', '["Animation", "Romance"]', 'Noriko Hashimoto', '["Shogo Yano", "Yuma Uchida", "Masatomo Nakazawa", "Takuya Eguchi", "Fumiya Imai"]', NULL, 'https://image.tmdb.org/t/p/w500/qUentZw7lvaRVbf2MRHVW8y1la8.jpg', 2024, 0, 0, '2026-06-08 06:35:15.035556', 'JP');
INSERT INTO public.movies VALUES (4571, 99099, '도쿠가와 여자의 형벌', '["Horror", "Drama"]', 'Teruo Ishii', '["Reiko Mikasa", "Miki Obana", "Masumi Tachibana", "Fumio Watanabe", "Teruo Yoshida"]', '근친상간, 강간, 고문 등 터부의 “이상 성애 노선“ 작품. 에도시대를 배경으로 죄를 고백해 형에 처해진 주인공. 그런 그녀가 오빠를 죽이기에 이른 경위, 여승방에서 승려와 비구니가 금지된 사랑에 질투, 참살한 비구니의 사건, 문신을 조각하기 위해 가세를 기울게 해 고문을 교사 한 문신사의 사건이 끔직한 영상으로 그려지고 있다.', 'https://image.tmdb.org/t/p/w500/nCKEACiT6Se3VH1yuj9LPIBctU6.jpg', 1968, 0, 0, '2026-06-08 06:33:24.901791', 'JP');
INSERT INTO public.movies VALUES (4575, 118406, '나루토 질풍전 극장판 6기: 로드 투 닌자', '["Animation", "Fantasy", "Action"]', 'Hayato Date', '["Junko Takeuchi", "Chie Nakamura", "Toshiyuki Morikawa", "Emi Shinohara", "Kazuhiko Inoue"]', '십 수년 전. 수수께끼의 닌자 가면 남자에 의해 거대한 마수 구미가 풀려나고 만다. 구미에 쫓겨 괴멸 위기에 처한 나뭇잎 마을. 마을을 지킬 수 있는 방법은 단 한가지. 리더인 4대 호카게 미나토와 아내 쿠시나가 함께 막 태어난 아들 나루토의 몸에 구미를 봉인하는 것 뿐. 자신의 생명을 희생한 두 사람에 의해 가까스로 마을은 구해지고, 그 미래는 나루토에게 맡겨지게 되는데.  시간은 흘러, 죽은 줄로 알고 있던 멤버까지 합세해 아카츠키가 나뭇잎 마을을 습격한다. 그런데 이상하게도 아카츠키는 별다른 반격도 없이 물러난다. 사투를 끝낸 나루토는 갑자기 나뭇잎 마을에 모습을 드러낸 가면 남자로부터 습격을 받는다. 사쿠라와 나루토는 가면 남자의 동술에 당해 정신을 잃게 된다. 그런데 눈을 뜬 두 사람 앞에 펼쳐진 나뭇잎 마을이 평소와 다르다는 것을 깨닫는다. 카카시나, 츠나데, 제7반의 멤버, 언제나 함께한 동료들이 마치 다른 사람인 것처럼 변해 있는 것이 아닌가. 게다가 사스케까지 마을에 돌아와 있다. 더 놀라운 것은 죽은 나루토의 부모 미나토와 쿠시나가 살아 있는 것!! 도대체 무슨 일이 일어 난 걸까?  갑자기 눈앞의 현실이 변해버리고 만 것에 대해 당혹해 하는 나루토와 사쿠라. 하지만 나루토는 부모와 만날 수 있게 되었다는 기쁨을 감출 수가 없다. 한편, 이 세계는 또 한번 가면 남자에 의해 존망의 위기를 맞게 된다. 구미의 힘을 노리는 가면 남자. 또 한번 나뭇잎 마을에 멸망의 위기가 찾아오게 되는데…과연, 나루토는 가면 남자로부터 세계를 지켜낼 수 있을까?', 'https://image.tmdb.org/t/p/w500/lFK2QMv9BWDxVDpWt47SUzJAvur.jpg', 2012, 0, 0, '2026-06-08 06:33:28.732704', 'JP');
INSERT INTO public.movies VALUES (4709, 580116, '더 레이프', '["Drama"]', 'Yōichi Higashi', '["Yuko Tanaka", "Morio Kazama", "Masahiko Tsugawa", "Takanori Goto", "Hiroshi Kashiwagi"]', '야하기 미치코는 어느 날 저녁 집으로 걸어가던 중 습격을 당해 성폭행을 당한다. 그 후 그녀는 경찰, 병원, 형사 사법 제도를 헤쳐나가면서 가정생활, 특히 연인 관계를 유지하기 위해 고군분투한다.', 'https://image.tmdb.org/t/p/w500/n2FsdkuY9xJWYWkLiFetgTb7LCu.jpg', 1982, 0, 0, '2026-06-08 06:35:22.518382', 'JP');
INSERT INTO public.movies VALUES (4710, 36095, '큐어', '["Crime", "Thriller", "Horror", "Mystery"]', 'Kiyoshi Kurosawa', '["Koji Yakusho", "Masato Hagiwara", "Tsuyoshi Ujiki", "Anna Nakagawa", "Yukijiro Hotaru"]', '도쿄 지역에서 동일한 방식의 엽기적인 연쇄 살인사건이 발생한다. 놀라운 것은 체포된 범인들이 하나같이 회사원, 교사, 경찰, 의사 등 평범한 사람들이라는 것. 평소 아무 문제가 없던 사람들이 똑같은 방식으로 살인을 저지른 것에 의문을 품은 다카베 형사(야쿠쇼 고지)는 이들이 모두 한 남자를 만난 후 범행을 저질렀다는 사실을 알게 된다.', 'https://image.tmdb.org/t/p/w500/7vOxMTYZwdNgPRPk0wBgGvitHvw.jpg', 1997, 0, 0, '2026-06-08 06:35:23.280825', 'JP');
INSERT INTO public.movies VALUES (4712, 1394621, '人妻セカンドバージン 私を襲って下さい', '["Drama"]', 'Hideo Jojo', '["Nana Nanaumi", "Nishina Momoka", "Mai Henmi", "Mutsuo Yoshioka", "Eiji Nakamura"]', NULL, 'https://image.tmdb.org/t/p/w500/t0chE8tHVIPHfuTaAbvX066BkPh.jpg', 2013, 0, 0, '2026-06-08 06:35:25.93099', 'JP');
INSERT INTO public.movies VALUES (4713, 1276073, '신칸센 대폭파', '["Action", "Thriller", "Crime", "Drama"]', 'Shinji Higuchi', '["Tsuyoshi Kusanagi", "Machiko Ono", "Jun Kaname", "Non", "Kanata Hosoda"]', '시속 100km 이하로 속도가 떨어지면 폭탄이 터지는 도쿄행 초고속 열차. 당국은 촌각을 다투며 탑승자 모두를 구하려 한다.', 'https://image.tmdb.org/t/p/w500/pqzza53yKNX65Z2dgrTbR1KoUnY.jpg', 2025, 0, 0, '2026-06-08 06:35:26.687658', 'JP');
INSERT INTO public.movies VALUES (4714, 1422404, '도쿄 택시', '["Drama"]', 'Yoji Yamada', '["Chieko Baisho", "Takuya Kimura", "Yu Aoi", "Takaya Sakoda", "Yûka"]', '어느 날, 택시 운전사 우사미 코지는 도쿄 시바마타에 사는 85세 할머니 타카노 스미레를 가나가와현 하야마에 있는 노인 요양원으로 모셔다 드리게 됩니다. 스미레는 코지에게 몇 군데를 우회해 달라고 부탁합니다. 점차 마음을 열어가는 스미레는 자신의 파란만장했던 과거 이야기를 들려주기 시작합니다…', 'https://image.tmdb.org/t/p/w500/iJHARu7sCkQy419txqTwKCgQQWQ.jpg', 2025, 0, 0, '2026-06-08 06:35:27.464749', 'JP');
INSERT INTO public.movies VALUES (4715, 573730, '메이드 인 어비스: 깊은 영혼의 여명', '["Animation", "Adventure", "Fantasy", "Mystery"]', 'Masayuki Kojima', '["Miyu Tomita", "Mariya Ise", "Shiori Izawa", "Toshiyuki Morikawa", "Inori Minase"]', '2017년 7월에 1쿨로 방송된 TVA 메이드 인 어비스의 완전신작 극장판. 2019년 1월 4일 티저 포스터와 함께 정보가 짤막하게 공개되었다.#  부제에 이름에서 유추할 수 있듯 여명경인 본도르드와의 결전을 다루는 내용이다.  심의 결과 아동에 대한 신체 손괴 등 학대 묘사가 심하여 R15+ 등급으로 결정되어, 15세 미만 관객에게는 환불이 이뤄지는 소동이 있었다.  2020년 9월 일본에서 블루레이가 발매된다.', 'https://image.tmdb.org/t/p/w500/tdLQI40RZC8aQ9cbRhBdprcsHYx.jpg', 2020, 0, 0, '2026-06-08 06:35:28.244635', 'JP');
INSERT INTO public.movies VALUES (4716, 553168, '横須賀男狩り 少女・悦楽', '["Drama", "Thriller"]', 'Toshiya Fujita', '["Kaori Ono", "Jun Nakagawa", "Shigeru Yazaki", "Moeko Ezawa", "Aya Origuchi"]', NULL, 'https://image.tmdb.org/t/p/w500/6mxVYlKY7B102lqwtTawwWlGOd9.jpg', 1977, 0, 0, '2026-06-08 06:35:29.222344', 'JP');
INSERT INTO public.movies VALUES (4717, 11299, '카우보이 비밥: 천국의 문', '["Action", "Animation", "Sci-Fi"]', 'Shinichiro Watanabe', '["Koichi Yamadera", "Unsho Ishizuka", "Aoi Tada", "Ai Kobayashi", "Megumi Hayashibara"]', '2071년의 화성. 도심에서 화물차가 폭발한 후 원인 불명의 죽음이 이어지자, 테러로 판단한 정부가 거액의 현상금을 내건다. 잔챙이 사냥에 지친 카우보이들, 오랜만에 몸 좀 풀어볼까?', 'https://image.tmdb.org/t/p/w500/x85cxMmo2VMqMFOzQ5iZSzxFB4O.jpg', 2001, 0, 0, '2026-06-08 06:35:29.995804', 'JP');
INSERT INTO public.movies VALUES (4718, 672515, '女銀行員暴行オフィス', '["Drama"]', 'Shōgorō Nishimura', '["Kaori Asô", "Kayo Kiyomoto", "Saeko Kizuki", "Nobuyuki Kawakami", "Hideaki Tezuka"]', NULL, 'https://image.tmdb.org/t/p/w500/zJ44tPUySDaQq4CStfaNp4b1uhc.jpg', 1985, 0, 0, '2026-06-08 06:35:30.754604', 'JP');
INSERT INTO public.movies VALUES (4720, 1153576, '스트리트 파이터', '["Action", "Comedy", "Fantasy"]', 'Kitao Sakurai', '["Noah Centineo", "Andrew Koji", "Callina Liang", "Joe Anoa''i", "David Dastmalchian"]', NULL, 'https://image.tmdb.org/t/p/w500/rOH0hMRFJZCMzf6zTUldrbjAmSO.jpg', 2026, 0, 0, '2026-06-08 06:35:32.74979', 'JP');
INSERT INTO public.movies VALUES (4722, 348950, '세라복 백합족', '["Drama", "Romance"]', 'Hiroyuki Nasu', '["Natsuko Yamamoto", "Kaoru Oda", "Koji Mizukami", "Hideaki Yada", "Nobutaka Masutomi"]', '세일러복을 입은 두 여고생이 사랑에 빠졌다. 하지만 한 소녀가 다시 남자와 관계를 가지기 시작하고 질투의 드라마가 이어진다.', 'https://image.tmdb.org/t/p/w500/6EArWCq6VYqPDybFjqbg3q17wfO.jpg', 1983, 0, 0, '2026-06-08 06:35:34.13074', 'JP');
INSERT INTO public.movies VALUES (4723, 15999, '뱀파이어 헌터 D', '["Animation", "Fantasy", "Horror"]', 'Yoshiaki Kawajiri', '["Andrew Philpot", "John Rafter Lee", "Pamela Adlon", "Wendee Lee", "Michael McShane"]', '아득히 먼 미래, 뱀파이어들이 밤을 지배하는 시대. 그러나 그들의 세력은 점차 쇠퇴하고, 그들을 사냥하는 헌터들이 어둠 속에서 활약하기 시작한다. 그중 인간과 뱀파이어의 피를 함께 지닌 전설의 사냥꾼 ‘D’. 탁월한 사냥 실력과 압도적인 존재감으로 공포와 전설의 대상이 된 그는 어느 날 지주의 딸 ‘샤를로트’를 구해달라는 의뢰를 받는다. 그녀를 납치한 귀족 뱀파이어 ‘마이어 링크’, 그리고 그들을 둘러싼 괴수와 현상금 사냥꾼들. 사랑과 피, 운명이 뒤얽힌 추적 끝에서 인간과 뱀파이어의 숙명이 충돌한다.', 'https://image.tmdb.org/t/p/w500/qJ12sSoy4VXeNBCzprsC8lrZF1k.jpg', 2001, 0, 0, '2026-06-08 06:35:34.817783', 'JP');
INSERT INTO public.movies VALUES (4724, 350499, '포켓몬 더 무비 XY 후파: 광륜의 초마신', '["Family", "Adventure", "Animation", "Action", "Fantasy"]', 'Kunihiko Yuyama', '["Rica Matsumoto", "Ikue Otani", "Mayuki Makiguchi", "Yuki Kaji", "Mariya Ise"]', '지우와 피카츄 일행은 ''무엇이든지 소환할 수 있는 링''을 가진 환상의 포켓몬 후파를 만난다. 그때, 데세르시티에서는 엄청난 포켓몬을 봉인한 ''굴레의 항아리''에 사악한 기운이 흐르고...! ''굴레의 항아리''를 열고 분노의 힘으로 되살아난 ''검은 그림자''! 그 그림자의 정체는 바로 ''후파''의 본래 모습, 초후파였다! 초후파는 힘을 되찾기 위해 포켓몬계의 최강 파워를 자랑하는 전설의 포켓몬들을 소환하기 시작하고! 지우와 후파 일행은 위기에 빠진 마을을 지키키 위해 이를 대적할 가공할만한 파워의 다른 전설의 포켓몬을 소환해내는데...!', 'https://image.tmdb.org/t/p/w500/mB98vcshgU7bGPGb5oJqf0Gz5Xz.jpg', 2015, 0, 0, '2026-06-08 06:35:35.50755', 'JP');
INSERT INTO public.movies VALUES (4725, 152042, '마법소녀 마도카☆마기카 [전편] 시작의 이야기', '["Thriller", "Animation", "Fantasy"]', 'Yukihiro Miyamoto', '["Aoi Yuuki", "Chiwa Saito", "Eri Kitamura", "Kaori Mizuhashi", "Ai Nonaka"]', '밝고 착한 15살 소녀 ‘마도카’는 미래의 꿈을 고민하는 평범한 소녀. 어느 날, 차가운 눈빛의 신비한 전학생 ‘호무라’를 만난다. 그녀는 ‘소중한 것들을 지키고 싶다면 변치 말고 그대로 있으라’며 ‘마도카’를 협박하는데. 같은 날, ‘큐베’라는 정체불명의 생명체가 나타나 마녀로부터 사람들을 구하는 마법소녀가 될 것을 권유한다. 다만 소녀의 영혼과 어떤 기적이든 가능한 한 가지 소원을 맞바꾸는 조건으로.  망설이는 ‘마도카’보다 먼저 계약을 한 단짝 ‘사야카’. 그러나 자신의 소원에 오히려 배신당한 ‘사야카’는 자포자기의 심정으로 폭주하고. ‘큐베’는 ‘마도카’가 우주의 법칙까지 바꿀만한 잠재력을 지녔다며 ‘사야카’도 다시 되돌릴 수 있다고 설득하지만 ‘호무라’는 끝까지 그녀의 계약을 막는다.  그리고 드러나는 마법소녀의 충.격.적 진실!', 'https://image.tmdb.org/t/p/w500/mNJYToUvHy1qHALWKTzQuDDbGcC.jpg', 2012, 0, 0, '2026-06-08 06:35:36.203769', 'JP');
INSERT INTO public.movies VALUES (4726, 390635, '페이트 스테이 나이트 헤븐즈필 제3장 스프링 송', '["Animation", "Romance", "Fantasy", "Action", "Drama"]', 'Tomonori Sudo', '["Noriaki Sugiyama", "Noriko Shitaya", "Ayako Kawasumi", "Kana Ueda", "Mai Kadowaki"]', '마술사 ''마스터''와 영령 ''서번트''가 모든 소원을 이뤄주는 ''성배''를 둘러싸고 싸우는 ''성배전쟁''. 하지만 그 싸움은 일그러져 있었다. 마토 사쿠라는 자신이 저지른 죄와 함께 마키리의 잔으로서 각성하여 깊은 어둠 속에 빠지고 말았다. 그런 사쿠라를 지키겠다고 맹세한 소년, 에미야 시로는 토오사카 린과 함께 사쿠라를 어둠 속에서 구하고 일그러진 ''성배전쟁''을 끝내기 위해 자신의 몸을 돌보지 않고 가혹한 싸움에 몸을 던진다. 소년의 소망은 소녀에게 닿을 것인가. 끝을 향해 달려가는 ''성배전쟁'' 최후의 싸움이 드디어 시작된다.', 'https://image.tmdb.org/t/p/w500/eKPSnszx2OvEVlJSwk2Zsjc6Ir0.jpg', 2020, 0, 0, '2026-06-08 06:35:37.138209', 'JP');
INSERT INTO public.movies VALUES (596, 50619, '브레이킹 던 Part 1', '["Adventure", "Fantasy", "Romance"]', 'Bill Condon', '["Kristen Stewart", "Robert Pattinson", "Taylor Lautner", "Billy Burke", "Peter Facinelli"]', '우여곡절 끝에 많은 이들의 축복 속에 뱀파이어 에드워드와 결혼식을 올린 벨라!  아직 마음을 정리하지 못한 제이콥을 뒤로하고 허니문을 떠난 벨라와 에드워드는  세상에서 가장 아름답고 특별한 첫날 밤을 보내게 된다.  행복한 시간도 잠시, 벨라는 예상치 못한 임신을 하게 된다.  새로운 생명의 탄생이 불러올 종족 간 최대의 위기!  시리즈 사상 가장 거대한 전쟁이 펼쳐진다!  한편 늑대인간 ‘퀼렛’족은 인간과 뱀파이어의 결합으로 생긴 아기가  후에 위험한 존재가 될 것이라고 판단, 임신한 벨라를 없애려 한다.  제이콥은 자신의 종족을 이탈해 뱀파이어 ‘컬렌’가와 함께 벨라를 지킨다.  그러나 벨라는 배 속에서 강력한 힘으로 빠르게 자라는 아기 때문에  목숨이 위태로운 상황에 놓이는데...!  전세계를 열광시킨 최고의 신드롬!  ‘트와일라잇’ 시리즈의 신화가 다시 시작된다!', 'https://image.tmdb.org/t/p/w500/osAoEqaiNO61IEkbKllJ7KlzrfW.jpg', 2011, 0, 0, '2026-06-06 13:25:18.783393', 'US');
INSERT INTO public.movies VALUES (4721, 16007, '데스노트', '["Fantasy", "Mystery", "Thriller"]', 'Shusuke Kaneko', '["Tatsuya Fujiwara", "Kenichi Matsuyama", "Asaka Seto", "Shigeki Hosokawa", "Erika Toda"]', '법관을 꿈꾸는 천재 대학생 야가미 라이토(후지와라 타츠야). 법의 한계를 느끼던 그는 어느 날 우연히 데스노트를 줍게 된다. 이 노트에 이름이 적힌 사람은 죽는다라는 한 문장을 반신반의하며 TV뉴스에 방영된 유괴범의 이름을 적자 실제로 죽음이 이루어진 것. 노트의 힘을 알게 된 라이토는 자기 손으로 범죄자를 처단하고 이상적인 세계를 만들어 가기로 결심한다. 세계 각지의 범죄자들이 의문의 심장마비로 죽어나가자 인터폴에서는 이 사건을 수사하기 위해 한 명의 천재에게 도움을 청한다. 그는 전세계 미궁에 빠진 사건을 해결해 온 수수께끼의 명탐정 L(마츠야마 켄이치). 이제 두 천재의 치열한 두뇌싸움이 시작되는데...', 'https://image.tmdb.org/t/p/w500/e7779G46To8KGIQyARGp49MBDU6.jpg', 2006, 0, 0, '2026-06-08 06:35:33.442851', 'JP');
INSERT INTO public.movies VALUES (4581, 347201, '보루토 - 나루토 더 무비', '["Adventure", "Action", "Animation", "Comedy", "Fantasy"]', 'Hiroyuki Yamashita', '["Yuko Sanpei", "Cocoro Kikuchi", "Junko Takeuchi", "Noriaki Sugiyama", "Daisuke Namikawa"]', '거대한 전설을 넘어설 새로운 시대가 시작된다!  지켜야 하는 소중한 가치를 위해 닌자는 강해진다!  그리고 지금, 역대 최강! 사상 최대! 대격돌이 펼쳐진다!  오랜 세월에 걸친 전쟁이 끝나고 고도성장을 이룬 새 시대, 평화의 시대를 이끌고 있는 것은 전설이 된 7대 호카게 우즈마키 나루토다. 분신술로도 감당하지 못할 만큼 바쁜 나날을 보내는 중에 나뭇잎 마을에서는 다섯 마을 통합으로 개최되는 중급닌자 선발시험이 한창이다.  각 마을을 대표하는 3인 1조의 하급 닌자들! 사스케의 딸이자 나루토를 동경하는 사라다와 수수께끼를 지닌 우수한 닌자 미츠키, 그리고 재능을 갖췄으면서도 나루토를 망할 아빠 취급하는 보루토도 참가 중이다. 마을의 영웅이지만 너무나 바쁜 아버지가 늘 미웠던 보루토는 ‘나루토의 유일한 라이벌’인 사스케의 제자가 되어 아버지를 놀라게 하는데…  마지막 개인전이 치뤄지던 그 순간! 차크라콜렉터 모모시키와 킨시키가 나타나 나루토의 차크라를 노리며 공격해온다! 나루토는 필사의 각오로 사람들을 구하지만 모모시키의 술법에 이공간으로 사라지고 만다. 그제서야 아버지의 걸어온 길과 그 무게를 느낀 보루토는 스승인 사스케, 다섯 카게들과 아버지를 구하기 위한 길을 나선다!', 'https://image.tmdb.org/t/p/w500/pvYHOrNCdlJR9uiVvxyqAfIeA3a.jpg', 2015, 0, 0, '2026-06-08 06:33:33.81729', 'JP');
INSERT INTO public.movies VALUES (4587, 70841, '극장판 도라에몽: 진구의 공룡대탐험', '["Animation", "Adventure", "Family", "Fantasy", "Sci-Fi"]', 'Ayumu Watanabe', '["Wasabi Mizuta", "Megumi Oohara", "Tomokazu Seki", "Ryunosuke Kamiki", "Subaru Kimura"]', '친구들과의 약속을 지키기 위해 우여곡절 끝에 공룡알 화석을 찾아낸 진구. 타임보자기를 이용해 부화를 성공시킨 진구는 공룡에게 `피스케`라는 이름을 지어주고 몰래 키우지만 거대하게 커져버린 `피스케`를 공룡의 시대로 다시 돌려보내기로 결심한다. 타임머신을 타고 1억년 전 백악기로 돌아간 도라에몽과 친구들.  하지만 피스케를 노리는 검은 마스크맨의 방해로 다시 돌아오지 못할 위기 상황에 처하는데...', 'https://image.tmdb.org/t/p/w500/i8NRnFEIlTwcnUNGoOdSDeROVQR.jpg', 2006, 0, 0, '2026-06-08 06:33:37.956132', 'JP');
INSERT INTO public.movies VALUES (4729, 4241, '비지터 Q', '["Comedy", "Drama", "Horror"]', 'Takashi Miike', '["Kenichi Endo", "Shungicu Uchida", "Kazushi Watanabe", "Jun Mutô", "Fujiko"]', '어느 러브호텔의 방, 말로는 “그만해”라고 하고 있지만 단단하게 발기되어 있는 자신이 슬프다. 도발적인 모습으로 눈 앞에 있는 여고생에게 미친듯 달려들며 무아지경에서 환희의 소리를 내고 있는 것은 전직 뉴스캐스터 야마자키 키요시(엔도 켄이치 분), 원조교제를 하는 지금 이 여고생을 다큐멘터리로 찍을 작정이었는데…', 'https://image.tmdb.org/t/p/w500/wqW1EFQBQ3OBEL0IgXS8kUsNlr3.jpg', 2001, 0, 0, '2026-06-08 06:35:40.223144', 'JP');
INSERT INTO public.movies VALUES (1, 1339713, '옵세션', '["Horror", "Thriller"]', 'Curry Barker', '["Michael Johnston", "Inde Navarrette", "Cooper Tomlinson", "Megan Lawless", "Andy Richter"]', '음반점 직원 베어(마이클 존스턴)는 어린 시절부터 짝사랑해 온 동료이자 소꿉친구 니키(인디 네버레티)에게 마음을 고백하지 못하고 있다. 용기를 내지 못한 베어는 우연히 발견한 신비로운 장난감 ''원 위시 윌로(One Wish Willow)''를 통해 니키가 자신을 세상에서 가장 사랑하게 해달라고 소원을 빈다. 소원은 즉시 이루어지고, 니키는 베어에게 모든 것을 건 사랑을 쏟아붓는다. 하지만 이 사랑은 점점 집착으로 변질되고, 니키의 행동은 기이하고 공포스러운 방향으로 치닫는다. 때로는 본래의 니키가 잠시 깨어나 공포에 질려 비명을 지르기도 한다. 베어는 자신이 원했던 것이 정말 니키인지, 그리고 그 구분이 얼마나 중요한지라는 끔찍한 질문에 직면하게 된다. 소원의 대가가 그들 모두를 위협하는 가운데, 베어는 자신의 욕망이 초래한 비극적 결과와 마주해야 한다.', 'https://image.tmdb.org/t/p/w500/6X4qFYBsG3bpWDG2XIKqr04kFJa.jpg', 2026, 0, 0, '2026-06-06 13:24:56.310651', 'US');
INSERT INTO public.movies VALUES (4590, 1359607, '영화 코바야시네 메이드래곤 외로움쟁이 용', '["Animation", "Comedy", "Fantasy"]', 'Tatsuya Ishihara', '["Maria Naganawa", "Mutsumi Tamura", "Yuuki Kuwahara", "Yuuki Takada", "Minami Takahashi"]', '평범한 회사원 코바야시 씨. 코바야시 씨에게 이끌려 모인 드래곤들. 그중 하나 어린 드래곤 칸나에게 누군가가 찾아온다. 그 정체는 놀랍게도 칸나의 아버지였는데.', 'https://image.tmdb.org/t/p/w500/qbkDlUJuFzjozUvIFOWA1xz74oO.jpg', 2025, 0, 0, '2026-06-08 06:33:40.594431', 'JP');
INSERT INTO public.movies VALUES (4597, 876792, '극장판 전생했더니 슬라임이었던 건에 대하여: 홍련의 인연편', '["Animation", "Fantasy", "Adventure"]', 'Yasuhito Kikuchi', '["Miho Okasaki", "Makoto Furukawa", "Megumi Toyoguchi", "Tomoaki Maeno", "Sayaka Senbongi"]', '[템페스트]의 서쪽에 위치한 [라자 소아국]. 한때는 금 채굴로 번영했지만 지금은 번영의 그림자는 찾아볼 수조차 없고, 호수는 광산의 독에 오염되어 나라는 위기 상황에 처했다. 여왕 ''토와''는 왕가에 대대로 전해 오는 왕관의 마력을 사용해 독을 제거하며 백성을 지키고 있었지만, 그 대가로 왕관에 걸려 있던 저주가 온몸에 퍼져 수명이 단축되고 있었다. 그러던 중, 템페스트에 갑자기 나타난 오거의 생존자 ''히이로''. 베니마루 일행의 형님뻘이었다는 히이로는, 토와의 도움으로 살아남았던 것이었다. 자신을 구해 준 토와와 [라자 소아국]을 지키기 위해, 템페스트의 리무루에게 도움을 청하기 위해 온 히이로는 베니마루와 운명의 재회를 한다. 라자를 위기에서 구하기 위해, 그리고 토와에게 걸린 저주의 수수께끼를 풀기 위해, 리무루는 라자로 향하는데...... 그곳에는 놀라운 음모가 기다리고 있었다!', 'https://image.tmdb.org/t/p/w500/kHeX34lOrTM793hCiCS72cIYY6i.jpg', 2022, 0, 0, '2026-06-08 06:33:46.700151', 'JP');
INSERT INTO public.movies VALUES (2014, 454639, '마스터즈 오브 유니버스', '["Action", "Fantasy", "Sci-Fi"]', 'Travis Knight', '["Nicholas Galitzine", "Camila Mendes", "Idris Elba", "Jared Leto", "Alison Brie"]', '아담이 전설의 검과 함께 자신의 운명을 받아들여 우주 최강의 전사 ‘히맨’으로 각성하게 되고, 파괴된 세계를 구하기 위해 스켈레토에 맞서 싸우는 SF히어로액션', 'https://image.tmdb.org/t/p/w500/u3g020QxrnsMdHDw0vvv1NjeFJA.jpg', 2026, 0, 0, '2026-06-07 12:17:13.713097', 'US');
INSERT INTO public.movies VALUES (2044, 931285, '모탈 컴뱃 2', '["Action", "Fantasy", "Adventure"]', 'Simon McQuoid', '["Karl Urban", "Adeline Rudolph", "Jessica McNamee", "Josh Lawson", "Martyn Ford"]', '왕년의 할리우드 액션 스타 ‘쟈니 케이지’. 무기는 ‘잘생긴 얼굴’ 하나뿐인 그가 지구의 운명을 짊어진 어스렐름의 전사로 낙점되어, 자비 없는 선혈의 전장 ‘모탈 컴뱃’ 토너먼트 리그에 강제 투입된다. 죽을 때까지 결코 끝나지 않는 토너먼트 속 ‘쟈니 케이지’는 궁극의 악 ‘샤오 칸’에 맞서, 복수를 위해 칼날을 간 에데니아의 공주 ‘키타나’와 어스렐름의 정예 전사들과 함께 위험천만한 리얼 액션에 뛰어드는데…', 'https://image.tmdb.org/t/p/w500/1NgBKiPrJzv1VHdEN8brdy59Rxo.jpg', 2026, 0, 0, '2026-06-07 12:17:15.392823', 'US');
INSERT INTO public.movies VALUES (58, 278, '쇼생크 탈출', '["Drama", "Crime"]', 'Frank Darabont', '["Tim Robbins", "Morgan Freeman", "Bob Gunton", "William Sadler", "Clancy Brown"]', '촉망받는 은행 간부 앤디 듀프레인은 아내와 그녀의 정부를 살해했다는 누명을 쓴다. 주변의 증언과 살해 현장의 그럴듯한 증거들로 그는 종신형을 선고받고 악질범들만 수용한다는 지옥같은 교도소 쇼생크로 향한다. 인간 말종 쓰레기들만 모인 그곳에서 그는 이루 말할 수 없는 억압과 짐승보다 못한 취급을 당한다. 그러던 어느 날, 간수의 세금을 면제받게 해 준 덕분에 그는 일약 교도소의 비공식 회계사로 일하게 된다. 그 와중에 교도소 소장은 죄수들을 이리저리 부리면서 검은 돈을 긁어 모으고 앤디는 이 돈을 세탁하여 불려주면서 그의 돈을 관리하는데...', 'https://image.tmdb.org/t/p/w500/qV9BQZdiM8foEzDz0Ag5hGWE5qM.jpg', 1994, 0, 0, '2026-06-06 13:24:57.938662', 'US');
INSERT INTO public.movies VALUES (54, 744275, '애프터: 관계의 함정', '["Drama", "Romance"]', 'Castille Landon', '["Josephine Langford", "Hero Fiennes Tiffin", "Carter Jenkins", "Louise Lombard", "Chance Perdomo"]', '영국 런던에서 미국 시애틀까지, 핫스팟에서 시작된 사랑의 클라이맥스! 첫사랑, 첫키스, 첫경험, 설렘 가득했던 처음을 뒤로 하고 꿈을 위해 잠시 서로를 떠나게 된 하딘과 테사. 각자 영국 런던과 미국 시애틀에서 롱디 연애를 앞둔 두 사람은 시간과 장소를 가리지 않고 달콤한 사랑을 속삭인다. 하지만 연애와 꿈의 갈림길에 선 둘은 서로에게 감춘 ''누군가''의 존재와 예상치 못한 비밀까지 알게 되면서 사랑의 클라이맥스에 치닫게 되는데…', 'https://image.tmdb.org/t/p/w500/o0PgoBD6jLYId3LYpu9yUY06SLT.jpg', 2021, 0, 0, '2026-06-06 13:24:57.927324', 'US');
INSERT INTO public.movies VALUES (6, 1439930, '퍼니셔 원 라스트 킬', '["Action", "Drama", "Crime"]', 'Reinaldo Marcus Green', '["Jon Bernthal", "Deborah Ann Woll", "Jason R. Moore", "Judith Light", "Kelli Barrett"]', '복수 이상의 의미를 찾아 헤매던 프랭크 캐슬은 뜻밖의 싸움을 다시 시작하게 된다.', 'https://image.tmdb.org/t/p/w500/dfKKipbQswChklXaaVTh6FP3oaJ.jpg', 2026, 5, 2, '2026-06-06 13:24:56.334615', 'US');
INSERT INTO public.movies VALUES (33, 11012, '데미지', '["Drama", "Romance"]', 'Louis Malle', '["Jeremy Irons", "Juliette Binoche", "Miranda Richardson", "Rupert Graves", "Peter Stormare"]', '모든 것을 다 가진 완벽한 남자 스티븐 플레밍(제러미 아이언스)은 어느 날 파티에서 아들 마틴(루퍼트 그레이브스)의 연인인 안나 바튼(줄리엣 비노쉬)을 만나게 된다. 스치는 찰나의 만남에서 서로를 향한 묘한 감정을 느낀 두 사람은 후에 재회하게 되고 되돌릴 수 없는 열정적 사랑에 빠지게 된다. 스티븐은 안나를 만나면 만날수록 마틴에 대한 죄책감을 느끼지만, 안나는 스티븐 그리고 마틴과의 관계를 자신만의 방법으로 각각 지속시켜 나간다. 그러던 중 마틴과 안나가 결혼 발표를 하게 되면서 스티븐과 안나의 금기된 사랑은 결국 파국을 향해 치닫게 되는데...', 'https://image.tmdb.org/t/p/w500/bc6ADs3tcdyQFrGrSsmujKSEPYo.jpg', 1992, 0, 0, '2026-06-06 13:24:57.151419', 'GB');
INSERT INTO public.movies VALUES (4612, 15370, '고양이의 보은', '["Adventure", "Fantasy", "Animation", "Drama", "Family"]', 'Hiroyuki Morita', '["Chizuru Ikewaki", "Yoshihiko Hakamada", "Aki Maeda", "Tetsu Watanabe", "Yousuke Saito"]', '17살의 평범한 여고생 하루는 매일 따분하기만 하고 즐거운 일이 하나도 없다. 어느 날 우연히 트럭에 치일 뻔한 고양이를 구해주면서부터 그녀의 일상은 변화를 맞는다. 하루가 구해준 고양이가 고양이 왕국의 룬 왕자라는 것. 그날 밤 하루의 집에 찾아온 고양이 떼는 자신들의 왕자를 구해준 보답으로 룬 왕자와 결혼해달라는 요청과 함께 앞으로는 행복한 일들만 일어날 것이라는 이상한 말을 남긴 채 사라진다. 얼마 후 고양이 왕국으로 초대된 하루는 고민 바쁜 일도 없이 즐거운 일만 고양이 왕국에 점차 매료되지만, 고양이 왕국의 대왕이 하루를 며느리 감으로 생각하고 룬 왕자와 결혼시키겠다고 하자 고민에 빠지는데...', 'https://image.tmdb.org/t/p/w500/mSJsmmFdihkn1UB8ahMzZ0aIYfb.jpg', 2002, 0, 0, '2026-06-08 06:34:04.688543', 'JP');
INSERT INTO public.movies VALUES (4623, 20677, '명탐정 코난: 눈동자 속의 암살자', '["Animation", "Crime", "Drama", "Mystery", "Adventure"]', 'Kenji Kodama', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Akira Kamiya", "Kenichi Ogata"]', '란은 신이치와 트로피컬 랜드에서 함께 보냈던 즐거운 한 때를 회상하고 있던 중 코난의 전화를 받는다. 코난에게 다시 한 번 그곳에 놀러가자고 말하지만 코난은 하필 그날 작아진 탓에 그 부탁을 들어줄 수가 없어 마음이 무겁다. 친구들과 함께 시간을 보내고 있던 코난은 근처에서 발생한 형사 저격사건을 목격하게 된다. 코난이 형사에게 범인에 관해 묻지만 형사는 오른손으로 가슴을 움켜쥐고서 숨을 거두고 마는데...', 'https://image.tmdb.org/t/p/w500/1hwNhgQrJ5FEYNJAiA3L8BZ7Yf9.jpg', 2000, 0, 0, '2026-06-08 06:34:12.719278', 'JP');
INSERT INTO public.movies VALUES (95, 24428, '어벤져스', '["Sci-Fi", "Action", "Adventure"]', 'Joss Whedon', '["Robert Downey Jr.", "Chris Evans", "Mark Ruffalo", "Chris Hemsworth", "Scarlett Johansson"]', '에너지원 큐브를 이용한 적의 등장으로 인류가 위험에 처하자 국제평화유지기구인 쉴드의 국장 닉 퓨리는 어벤져스 작전을 위해 전 세계에 흩어져 있던 슈퍼히어로들을 찾아나선다. 아이언맨부터 토르, 헐크, 캡틴 아메리카는 물론, 쉴드의 요원인 블랙 위도우, 호크 아이까지, 최고의 슈퍼히어로들이 어벤져스의 멤버로 모이게 되지만, 각기 개성이 강한 이들의 만남은 예상치 못한 방향으로 흘러가는데...', 'https://image.tmdb.org/t/p/w500/krgjV3rJtBcEpQehODKXNCt6uFL.jpg', 2012, 0, 0, '2026-06-06 13:24:59.492307', 'US');
INSERT INTO public.movies VALUES (124, 1159559, '스크림 7', '["Horror", "Mystery", "Crime"]', 'Kevin Williamson', '["Neve Campbell", "Courteney Cox", "Isabel May", "Jasmin Savoy Brown", "Mason Gooding"]', '시드니 프레스콧이 새롭게 정착한 조용한 마을에 새로운 고스트페이스가 등장한다. 그녀의 딸, 테이텀이 다음 표적이 되면서 우려했던 공포가 현실이 되고, 가족을 지키기 위해 시드니는 과거의 공포와 맞서 피의 학살을 영원히 끝내기로 결심하는데…', 'https://image.tmdb.org/t/p/w500/gqgBqxyr8tGQGJCFrRWAzfA7Cml.jpg', 2026, 0, 0, '2026-06-06 13:25:01.015737', 'US');
INSERT INTO public.movies VALUES (4627, 526894, '레이디 닌자', '["Action", "Sci-Fi"]', 'Ken''ichi Fujiwara', '["Mai Hakase", "Yuji Abe", "Saki Akai", "Asami", "Shin Ishikawa"]', '일본의 미래에는 경제가 붕괴되고, 나라가 빈민가로 변했다. 거대 국제기업 “쿠로다 그룹”는 대부분의 사람들을 빈곤으로 몰아 넣고 세계 지배를 획책하고 있다. 쿠로의 막강한 힘에 대응하는 비밀 기관인 ''고쿠라쿠''는 내부에 암살에 능한 조직된 “레이디 닌자”를 앞세워 쿠로다 그룹과 생사를 건 싸움을 하고 있다. 비밀 요원들은 “레이디 닌자"라고 불리워 지며 세계를 지배하려는 거대 기업 쿠로가 만들어낸 용병들과 싸우며 그들의 정보를 취합하고 있다.  하지만 어느 날, 생체병기를 만드는 유전자 공학의 부작용으로 나타난 강력한 살인마 야챠가 레이디 닌자들을 사냥하기 시작한다. 누가 살아남을 것인가? 지구의 미래를 위해 레이디 닌자들의 처절한 싸움이 시작된다.', 'https://image.tmdb.org/t/p/w500/sZLJJqtlfnGEdI7h1JnMmpeCq7Q.jpg', 2018, 0, 0, '2026-06-08 06:34:15.420758', 'JP');
INSERT INTO public.movies VALUES (4632, 16664, '릴리 슈슈의 모든 것', '["Drama", "Crime"]', 'Shunji Iwai', '["Hayato Ichihara", "Shugo Oshinari", "Yu Aoi", "Ayumi Ito", "Issey Takahashi"]', '가상의 가수 릴리 슈슈의 노래를 너무나 사랑하는 열네 살 소년 유이치. 그러나 그의 중학교 생활은 끔찍하기만 하다. 단짝 친구였던 반 아이들의 리더가 된 후 자신을 이지메시킨다. 한밤중에 불려나가 그들 앞에서 자위를 하거나 원조교제를 하고 있는 여학생의 일거수일투족도 감시해야 하며, 심지어 첫사랑 쿠노 역시 이지메를 당하지만 그녀를 도와주기에는 자신의 슬픔을 감당하기에도 벅차다. 그의 유일한 안식처는 오로지 영혼을 뒤흔드는 듯한 릴리 슈슈의 노래 뿐. 그러나 현실은 노래로 감출 만큼 만만하지 않다.', 'https://image.tmdb.org/t/p/w500/9DAISUBQi2aCgijRqxddmuLeNkU.jpg', 2001, 0, 0, '2026-06-08 06:34:19.632748', 'JP');
INSERT INTO public.movies VALUES (4638, 283984, '페이트 스테이 나이트 헤븐즈필 제1장 프레시지 플라워', '["Action", "Animation", "Drama", "Fantasy", "Romance"]', 'Tomonori Sudo', '["Noriaki Sugiyama", "Noriko Shitaya", "Hiroshi Kamiya", "Ayako Kawasumi", "Kana Ueda"]', '마술사 "마스터"와 영령 "서번트"가 모든 소원을 이뤄주는 「성배」를 둘러싸고 싸우는 「성배전쟁」이 벌어진 지 10년.  지난 「성배전쟁」의 참가자인 에미야 키리츠구의 양자, 에미야 시로는 그를 연모하는 소녀, 마토 사쿠라와 함께 평온한 나날을 보내고 있었다. 그러나 「성배전쟁」은 다시 시작되고 곳곳에서 벌어지는 살인사건으로 후유키 시는 불온한 기운에 휩싸인다. 시로는 사쿠라를 자기 집에 머물게 하기로 결정하고, 자신이 소환한 서번트인 세이버와 함께 마술사인 토오사카 린과 동맹을 맺고 「성배전쟁」에 나서기로 결심하는데... 하지만 이 싸움은 암약하는 자들에 의해 크게 일그러지기 시작한다.', 'https://image.tmdb.org/t/p/w500/sBDTqj4elwOK3za9X4toE4OJWDX.jpg', 2017, 0, 0, '2026-06-08 06:34:23.766763', 'JP');
INSERT INTO public.movies VALUES (919, 1694978, 'Chum', '["Horror", "Thriller"]', 'Jonathan Zuck', '["Alice Eve", "Eric Michael Cole", "Elle Haymond", "Sarah Siadat", "Johnny Gaffney"]', NULL, 'https://image.tmdb.org/t/p/w500/uJOW6pWxJ0i5sji9VXRR6Y1wXyE.jpg', 2026, 0, 0, '2026-06-06 13:25:31.197842', 'US');
INSERT INTO public.movies VALUES (133, 1383731, '프로텍터', '["Action", "Thriller"]', 'Adrian Grünberg', '["Milla Jovovich", "Matthew Modine", "Isabel Myers", "D. B. Sweeney", "Don Harvey"]', '미 특수부대에서 뛰어난 활약상을 보이며 국가를 위해 헌신했던 니키는 딸의 어린 시절을 함께 보내지 못했다. 남편이 사망한 후, 그녀는 딸 클로이 곁으로 돌아온다. 그러나 떨어져 지냈던 시간의 공백만큼 두 모녀 사이의 틈은 좁혀질 기미가 보이지 않는다. 클로이는 16번째 생일날 외출을 했다가 납치를 당하고, 니키는 거대 조직에 맞서 72시간 안에 딸을 되찾아야 하는 위험천만한 상황에 처한다. 경찰과 군대는 니키를 표적으로 삼고, 시간은 잔인하게 흐른다.', 'https://image.tmdb.org/t/p/w500/kJvFZt7x3VWOtMQwANwXGD59ArJ.jpg', 2026, 0, 0, '2026-06-06 13:25:01.036417', 'US');
INSERT INTO public.movies VALUES (164, 13078, '베이비시터', '["Drama"]', 'David Ross', '["John Leguizamo", "Katherine Waterston", "Cynthia Nixon", "Andy Comeau", "Denis O''Hare"]', '열일곱 살의 셜리는 대학 학비를 벌기 위해 베이비시터로 일하는 훌륭한 학생이다. 어느 날 밤 셜리가 돌보는 아이의 아버지 마이클은 자신의 결혼 생활이 불행하다고 고백한다. 마이클을 짝사랑한 셜리는 이 순간을 포착하여 그에게 키스한다. 너무 기뻤던 마이클은 셜리에게 준 큰 팁을 준다. 이를 계기로 셜리로 새로운 사업 아이디어를 떠올리게 된다. 셜리는 10대 친구들을 다른 불행한 아버지들과 사귀는 사업으로 더 큰 돈을 벌 계획이다.', 'https://image.tmdb.org/t/p/w500/nsrNUqGXI95unRKZEu8BJ584xWn.jpg', 2008, 0, 0, '2026-06-06 13:25:02.552302', 'US');
INSERT INTO public.movies VALUES (297, 4248, '무서운 영화 2', '["Comedy"]', 'Keenen Ivory Wayans', '["Anna Faris", "Regina Hall", "Marlon Wayans", "Shawn Wayans", "Christopher Masterson"]', '유령이 나올 것처럼 스산한 기운이 감도는 밤. 어느 대저택에서 한 무리의 사람들이 피아노 반주에 맞춰 엉덩이를 흔들며 신나게 노래를 부르고 있다. 이때 하얀 잠옷을 입은 소녀가 이들 앞에서 엄청난 양의 오줌을 질질 싸댄다.  이 소녀가 바로 악령이 깃들였다는 이 집 딸 나타샤.  괴상한 짓을 일삼지만 유능한(?) 사제인 맥필리 신부가 그녀에게 깃들인 악령을 쫓아내기 위해 찾아온다. 잠시 후 악령을 쫓아내려는 신부와 나타샤의 몸에서 쫓겨나지 않으려는 악령은 서로의 얼굴에 구토를 해대는 등 온갖 더럽고 추악한 짓으로 힘겨루기를 한다.  그로부터 1년 뒤 악령의 존재를 밝혀내 명예를 얻으려는 심리학 교수 올드먼이 실험대상인 제자들을 데리고 악령의 집을 찾는다.', 'https://image.tmdb.org/t/p/w500/iRS4R009OJM4KmhikmzGvkbeEaT.jpg', 2001, 0, 0, '2026-06-06 13:25:07.190965', 'US');
INSERT INTO public.movies VALUES (137, 680, '펄프 픽션', '["Thriller", "Crime", "Comedy"]', 'Quentin Tarantino', '["John Travolta", "Samuel L. Jackson", "Uma Thurman", "Bruce Willis", "Ving Rhames"]', '펌프킨와 허니 버니가 레스토랑에서 강도 행각을 벌이기 시작한다. 빈센트와 그 동료 쥴스는 두목의 금가방을 찾기 위해 다른 건달이 사는 아파트를 찾아간다. 마르셀러스는 부치에게 돈을 주며 상대 선수에게 져 주라고 하지만 부치는 상대 선수를 때려 눕히고 도망치다, 어릴 때 아버지에게 물려받은 시계를 찾기 위해 아파트로 향한다. 아무런 상관 없이 보이는 이 사건들이 서로 얽히고 섥히면서 예상치 못한 인과관계가 만들어지는데...', 'https://image.tmdb.org/t/p/w500/lnRkeQstaCvfMahZq7p9eAWzK1a.jpg', 1994, 0, 0, '2026-06-06 13:25:01.045544', 'US');
INSERT INTO public.movies VALUES (4640, 71883, '레드라인', '["Animation", "Action", "Sci-Fi"]', 'Takeshi Koike', '["Takuya Kimura", "Yu Aoi", "Tadanobu Asano", "Takeshi Aono", "Tatsuya Gashûin"]', '극한의 스피드를 추구하는 내성적인 순정남 JP(기무라 타쿠야). JP의 첫사랑이자 어려서부터 레이싱만을 꿈꿔온 소노시(아오이 유우), 그리고 JP의 친구이자 천재 정비사였지만 마피아와 결탁해 승부조작을 주도하는 프리스비(아사노 타다노부). 그들을 중심으로 5년마다 열리는 우주 최고의 레이싱 경기 ''레드라인''의 막이 오른다. 사실상의 둘도 없이 목숨을 걸어야 하는 경기에서 우승하기 위해서는 중화기로 무장한 다른 경쟁자들을 물리치는 한편, 레드라인의 개최를 막으려는 독재 국가 로보월드(RoboWorld)의 방해 공작도 이겨내야 하는데...', 'https://image.tmdb.org/t/p/w500/pHO7jBLVU3cMIX8Y4xFOELCbKOq.jpg', 2009, 0, 0, '2026-06-08 06:34:25.166561', 'JP');
INSERT INTO public.movies VALUES (155, 77, '메멘토', '["Mystery", "Thriller"]', 'Christopher Nolan', '["Guy Pearce", "Carrie-Anne Moss", "Joe Pantoliano", "Mark Boone Junior", "Russ Fega"]', '전직 보험 수사관이었던 레너드에게 기억이란 없다. 자신의 아내가 강간당하고 살해되던 날의 충격으로 기억을 10분 이상 지속시키지 못하는 단기 기억상실증 환자가 되었던 것이다. 그가 마지막으로 기억하고 있는 것은 자신의 이름이 레너드 셸비 라는 것과 아내가 강간당하고 살해당했다는 것, 그리고 범인은 존 G 라는 것이 전부. 레너드는 자신의 가정을 파탄 낸 범인을 찾기 위한 방법으로 메모와 문신을 사용하게 된다. 하지만 진실에 다가갈수록 자신의 기억, 주위 사람들에 대한 의심이 갈수록 커져만 가는데...', 'https://image.tmdb.org/t/p/w500/x5FPVwJHyf1SnDW04fwr9rsyWm4.jpg', 2000, 0, 0, '2026-06-06 13:25:01.810083', 'US');
INSERT INTO public.movies VALUES (182, 808, '슈렉', '["Animation", "Comedy", "Fantasy", "Adventure", "Family"]', 'Andrew Adamson', '["Mike Myers", "Eddie Murphy", "Cameron Diaz", "John Lithgow", "Vincent Cassel"]', '성 밖 늪지대에 사는 엄청나게 못생기고 무지무지 큰 괴물 슈렉. 지저분한 진흙으로 샤워를 즐기고 동화책은 화장실 휴지 삼아 쓰는 그는 혼자만의 시간을 즐긴다.  그러던 어느 날, 자신만의 고요한 안식처에 백설공주, 신데렐라, 빗자루를 타고 다니는 마녀, 피리부는 아저씨, 피터팬, 피노키오 등등.. 동화속의 주인공들이 모두 쳐들어온다. 그 중에서도 가장 귀찮은 건 쉴새없이 떠들어대는 당나귀 덩키. 알고보니 얼굴이 몸의 반을 차지하는 1m도 안되는 숏다리 파콰드영주가 동화속의 주인공들을 다 쫓아낸것. 결국 슈렉은 파콰드영주와 담판을 지으러 떠난다.  하지만 일은 이상하게 꼬여 결국 파콰드영주 대신 불뿜는 용의 성에 갇힌 피오나 공주를 구하러 떠나게 되는데..', 'https://image.tmdb.org/t/p/w500/hABnmgdAU3u6Nu61b9GUGaOseVl.jpg', 2001, 0, 0, '2026-06-06 13:25:03.318211', 'US');
INSERT INTO public.movies VALUES (183, 14836, '코렐라인: 비밀의 문', '["Animation", "Family", "Fantasy"]', 'Henry Selick', '["Dakota Fanning", "Teri Hatcher", "Jennifer Saunders", "Dawn French", "Keith David"]', '새로운 집으로 이사 온 열한 살 소녀 코렐라인은 모든 것이 낯설기만 하고, 늘 바쁜 부모님 때문에 외로운 날들을 보낸다. 호기심 많은 코렐라인은 홀로 집과 동네를 탐험하다 동네 소년 와이비와 개성 넘치는 이웃들을 만나게 된다. 그러던 어느 날, 집 안에 숨겨진 작은 비밀 문을 발견한 코렐라인은 문을 열고 어두운 통로를 지나 들어간다. 그곳은 현실과 꼭 닮았지만, 훨씬 더 완벽해 보이는 또 다른 세계였다. ‘다른 엄마’와 ‘다른 아빠’는 언제나 그녀를 따뜻하게 맞이하고, 신비로운 검은 고양이는 그림자처럼 곁을 맴돌며 호기심을 자극한다. 처음엔 꿈만 같은 낯선 세계였지만, 점점 그곳의 숨겨진 진실이 드러나기 시작하는데...', 'https://image.tmdb.org/t/p/w500/iGp4wBc0ZBVFd2HPicyDgl6Pn1r.jpg', 2009, 0, 0, '2026-06-06 13:25:03.320836', 'US');
INSERT INTO public.movies VALUES (194, 502356, '슈퍼 마리오 브라더스', '["Family", "Comedy", "Adventure", "Fantasy", "Animation"]', 'Aaron Horvath', '["Chris Pratt", "Anya Taylor-Joy", "Charlie Day", "Jack Black", "Keegan-Michael Key"]', '따단-딴-따단-딴 ♫ 전 세계를 열광시킬 올 타임 슈퍼 어드벤처의 등장! 뉴욕의 평범한 배관공 형제 ''마리오''와 ‘루이지’는 배수관 고장으로 위기에 빠진 도시를 구하려다 미스터리한 초록색 파이프 안으로 빨려 들어가게 된다. 파이프를 통해 새로운 세상으로 차원 이동하게 된 형제. 형 ''마리오''는 뛰어난 리더십을 지닌 ''피치''가 통치하는 버섯왕국에 도착하지만 동생 ''루이지''는 빌런 ''쿠파''가 있는 다크랜드로 떨어지며 납치를 당하고 ‘마리오’는 동생을 구하기 위해 ‘피치’와 ‘키노피오’의 도움을 받아 ''쿠파''에 맞서기로 결심한다. 그러나 슈퍼스타로 세상을 지배하려는 그의 강력한 힘 앞에 이들은 예기치 못한 위험에 빠지게 되는데...!', 'https://image.tmdb.org/t/p/w500/jt1GlLLvkWL2m83VX8I1qsDR187.jpg', 2023, 0, 0, '2026-06-06 13:25:03.348868', 'US');
INSERT INTO public.movies VALUES (214, 1242332, '노멀', '["Action", "Crime", "Thriller"]', 'Ben Wheatley', '["Bob Odenkirk", "Henry Winkler", "Lena Headey", "Billy MacLellan", "Ryan Allen"]', '눈 덮인, 조용하고 평범한 마을 노멀. 보안관 건더슨의 갑작스러운 죽음으로 공석이 된 자리에, 율리시스가 임시 보안관으로 부임한다. 조용한 마을, 친절한 이웃, 평화로운 하루. 율리시스의 목표는 단 하나, 이 마을을 처음 왔을 때 모습 그대로 두고 돌아가는 것. 그러던 어느 날, 단조로운 마을에 느닷없이 벌어진 은행 강도 사건. 현장을 제압하기 위해 출동한 율리시스는 뜻밖에도 동료들에게 포위당하게 되고, 그 순간, 평범해 보이던 노멀 마을에 숨겨진 거대한 비밀이 서서히 모습을 드러내기 시작한다.', 'https://image.tmdb.org/t/p/w500/A7TN0R78eenIf7hED3k96POTJMX.jpg', 2026, 0, 0, '2026-06-06 13:25:04.112761', 'US');
INSERT INTO public.movies VALUES (4653, 149870, '바람이 분다', '["Animation", "Drama", "History", "Romance"]', 'Hayao Miyazaki', '["Hideaki Anno", "Hidetoshi Nishijima", "Miori Takimoto", "Masahiko Nishimura", "Stephen Alpert"]', '전투기 설계사 호리코시 지로의 삶을 뼈대로, 소설가 호리 다쓰오의 자전적 소설 속 로맨스를 끌어와 극화한 작품이다. 하늘을 동경한 소년 지로는 그는 파일럿이 되고 싶었으나 눈이 좋지 않아 망설이던 찰나, 꿈속에서 카프로니 백작을 만나면서 비행기 설계가를 꿈꾼다. 청년이 된 지로는 열차 안에서 바람에 날아가는 모자를 잡아준 한 소녀를 만나지만 지진으로 긴박한 상황이 벌어지고, 서로 이름도 모른 채 헤어지게 된다. 소년의 꿈까지도 사랑한 소녀 나호코는 10년 뒤 바람과 함께 지로를 운명적으로 다시 만난다. 그러나 행복한 시간도 잠시, 두 사람에게 시간이 얼마 남지 않았음을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/a4n8fxLubMAKcYfzT8k3MPg9ZbE.jpg', 2013, 0, 0, '2026-06-08 06:34:36.072901', 'JP');
INSERT INTO public.movies VALUES (4661, 18881, '카이트', '["Animation", "Action", "Thriller"]', 'Yasuomi Umetsu', '["Konami Yoshida", "Kousuke Okano", "Kinryu Arimoto", "Rokuro Naya", "Dai Matsumoto"]', '어린 시절, 부모가 무참하게 살해당한 사와는 이후 사건 담당형사 케인의 양녀로 입양된다. 그러나 그 형사는 경찰의 탈을 쓴 잔혹한 살인청부조직의 보스로 법의 이름으로 처단할 수 없는 연예인이나 정치, 경제인들을 제거하는 일을 하고 있다. 실상 그는 죽어 가는 사람들의 고통스러운 모습에서 희열을 느끼는 악마적 기질을 가지고 있었던 것. 그는 자신의 양녀인 사와를 어렸을 때부터 자신의 노리개로 삼으면서 그녀를 철저한 살인 기계로 양육한다. 사와는 돌아가신 부모님의 피가 담겨있는 귀걸이를 하고 다니며 부모의 복수를 다짐하지만 그녀는 돌아가신 부모님을 죽인 사람이 바로 케인이라는 것을 알고 있었지만, 그를 제거할 정도의 실력이 될 때까지 원한을 가슴에 묻어두기로 한다. 그러던 중 자신과 비슷한 처지의 오클리에를 만나게 되어 그와 사랑에 빠진다. 둘의 관계가 깊어지자 케인은 오클리에를 제거하려 하고, 이 사실을 알게 된 사와는 복수의 시기가 다가왔음을 깨닫는데...', 'https://image.tmdb.org/t/p/w500/3EKHThnl6ziDHlqcmxwdjKescG1.jpg', 1998, 0, 0, '2026-06-08 06:34:42.713502', 'JP');
INSERT INTO public.movies VALUES (202, 1156593, '네 잘못이야', '["Drama", "Romance"]', 'Domingo González', '["Nicole Wallace", "Gabriel Guevara", "Marta Hazas", "Iván Sánchez", "Eva Ruiz"]', '전 세계적인 히트작 ''나의 잘못''의 속편. 노아와 닉의 사랑은 둘을 떼어놓으려는 부모님의 노력에도 불구하고 흔들림이 없어 보인다. 하지만 닉의 직업과 노아의 대학 진학은 두 사람의 관계와 레이스테르 가족의 근간을 흔들 새로운 관계로 그들의 삶을 안내한다. 많은 사람이 두 사람 사이를 파괴하려는 가운데 이 둘은 결국 행복을 맞이할 수 있을까?', 'https://image.tmdb.org/t/p/w500/zuctS3p8Bs9IeYv5ScKeOKp5Na5.jpg', 2024, 0, 0, '2026-06-06 13:25:04.083389', 'US');
INSERT INTO public.movies VALUES (244, 939243, '수퍼 소닉 3', '["Action", "Sci-Fi", "Comedy", "Family"]', 'Jeff Fowler', '["Jim Carrey", "Ben Schwartz", "Keanu Reeves", "Idris Elba", "Colleen O''Shaughnessey"]', '너클즈, 테일즈와 함께 평화로운 일상을 보내던 초특급 히어로 소닉. 연구 시설에 50년간 잠들어 있던 사상 최강의 비밀 병기 "섀도우"가 탈주하자, 세계 수호 통합 부대(약칭 세.수.통)에 의해 극비 소집된다. 소중한 것을 잃은 분노와 복수심에 불타는 섀도우는 소닉의 초고속 스피드와 너클즈의 최강 펀치를 단 단숨에 제압해버린다. 세상을 지배하려는 닥터 로보트닉과 그의 할아버지 제럴드 박사는 섀도우의 엄청난 힘 카오스 에너지를 이용해 인류를 정복하려고 하는데…', 'https://image.tmdb.org/t/p/w500/4784u4fHwcvc4owOGylVpP7JaKQ.jpg', 2024, 0, 0, '2026-06-06 13:25:05.607664', 'US');
INSERT INTO public.movies VALUES (236, 950396, '''더 캐니언'' - The Gorge', '["Romance", "Sci-Fi", "Thriller"]', 'Scott Derrickson', '["Miles Teller", "Anya Taylor-Joy", "Sigourney Weaver", "Ṣọpẹ́ Dìrísù", "William Houston"]', '고도의 훈련을 받은 두 요원는 비밀스러운 협곡의 양쪽을 지키는 임무를 받은 후 멀리서 서로와 서서히 친해진다. 도사리고 있던 악이 드러나자, 둘은 협곡 안의 위험으로부터 살아남기 위해 협력해야만 한다.', 'https://image.tmdb.org/t/p/w500/dBKMc0Bim0Z8amB7VihuCfhto2v.jpg', 2025, 0, 0, '2026-06-06 13:25:04.875779', 'US');
INSERT INTO public.movies VALUES (487, 209112, '배트맨 대 슈퍼맨: 저스티스의 시작', '["Action", "Adventure", "Fantasy"]', 'Zack Snyder', '["Ben Affleck", "Henry Cavill", "Jesse Eisenberg", "Gal Gadot", "Amy Adams"]', '슈퍼맨과 조드 장군의 격렬한 전투 이후 메트로폴리스는 파괴되었고 슈퍼맨은 세계 최고 논쟁의 인물이 되어 버린다. 검증되지 않은 신과 같은 능력을 지닌 슈퍼맨의 등장에 사람들은 두려움에 빠지게 된다. 한편 배트맨은 그 동안 타락했던 많은 자들처럼 슈퍼맨 역시 언젠가 타락을 할 것이라 생각하며 사회에서 가장 위험한 존재로 여긴다. 세계의 미래를 위해 무모하고 제어할 수 없는 힘을 가진 슈퍼맨으로 인해 벌어졌던 일들을 바로 잡으려 한다. 배트맨과 슈퍼맨이 격돌하는 사이 인류를 위협할 새로운 위기가 빠르게 부상하기 시작하는데...', 'https://image.tmdb.org/t/p/w500/nfdgwCossZkIEEaQ4iR80mX2iR3.jpg', 2016, 0, 0, '2026-06-06 13:25:14.869249', 'US');
INSERT INTO public.movies VALUES (8, 1582770, '두란다르: 더 리벤지', '["Action", "Crime", "Thriller"]', 'Aditya Dhar', '["Ranveer Singh", "Arjun Rampal", "R. Madhavan", "Sanjay Dutt", "Sara Arjun"]', '카라치의 암흑가를 상대로 한 함자의 싸움이 계속된다. 인도 역대 최고 흥행을 기록한 힌디어 영화 《Dhurandhar》의 속편', 'https://image.tmdb.org/t/p/w500/hsJG5r6etrMNwW00BVp4NC7zi67.jpg', 2026, 0, 0, '2026-06-06 13:24:56.3427', 'IN');
INSERT INTO public.movies VALUES (571, 670, '올드보이', '["Drama", "Thriller", "Mystery", "Action"]', 'Park Chan-wook', '["Choi Min-sik", "Yoo Ji-tae", "Kang Hye-jung", "Kim Byeong-ok", "Ji Dae-han"]', '오대수는 어느 날 술이 거나하게 취해 집에 돌아가는 길에 누군가에게 납치, 사설 감금방에 갇히게 된다. 중국집 군만두만을 먹으며 8평이라는 제한된 공간에서 그가 할 수 있는 일이라곤 텔레비전 보는 게 전부. 1년이 지났을 무렵, 뉴스를 통해 나오는 아내의 살해소식. 게다가 아내의 살인범으로 자신이 지목되고 있음을 알게 된 오대수는 복수와 탈출을 위해 감금방 한쪽 구석을 쇠젓가락으로 파기 시작한다. 감금 15년을 맞이하는 해, 마침내 사람 몸 하나 빠져나갈 만큼의 탈출구가 생겼을 때, 어이없게도 15년 전 납치됐던 바로 그 장소로 풀려나 있는 자신을 발견하게 된다.', 'https://image.tmdb.org/t/p/w500/xpa9ybm6tYGna5LseqSXvKpSSJn.jpg', 2003, 0, 0, '2026-06-06 13:25:17.997875', 'KR');
INSERT INTO public.movies VALUES (263, 269149, '주토피아', '["Animation", "Adventure", "Family", "Comedy"]', 'Byron Howard', '["Ginnifer Goodwin", "Jason Bateman", "Idris Elba", "Jenny Slate", "Nate Torrence"]', '어릴 적부터 경찰이 꿈이었던 토끼 주디 홉스는 주변의 만류에도 불구하고 경찰학교에 들어가 당당히 수석으로 졸업한다. 온갖 동물들이 모여 살며 교양 있고 세련된 라이프 스타일을 주도하는 대도시 주토피아에 자원한 주디는 의욕을 안고 출근하지만, 상사는 작은 토끼라는 이유로 주차관리 같은 소일거리만 시킨다. 따분하게 업무를 보던 주디는 아이스크림 불법 판매를 일삼는 사기꾼 여우 닉 와일드를 알게 되고, 그와 함께  48시간 안에 주토피아에서 벌어지고 있는 연쇄 실종사건을 추적해야만 하는데...', 'https://image.tmdb.org/t/p/w500/uitqZVbhvlQV5iLOdbk3itGoNNd.jpg', 2016, 0, 0, '2026-06-06 13:25:06.385381', 'US');
INSERT INTO public.movies VALUES (279, 991494, '스폰지밥 무비: 네모바지를 찾아서', '["Adventure", "Animation", "Comedy", "Family", "Fantasy"]', 'Derek Drymon', '["Tom Kenny", "Clancy Brown", "Rodger Bumpass", "Bill Fagerbakke", "Carolyn Lawrence"]', '비키니시티에 사는 스폰지밥은 무시무시한 롤러코스터를 탈 수 있는 용감한 ‘빅 가이’가 꿈이다. 그러던 어느 날, 미지의 세계 ‘언더월드’에 사는 유령선장을 만나 ‘용감무쌍짱 증명서’를 받으면 진정한 ‘빅 가이’가 될 수 있다는 말을 들은 스폰지밥은 절친 뚱이와 함께 해적선을 찾아 위험천만한 모험을 떠난다. 그 사실을 안 집게사장과 징징이, 핑핑이는 스폰지밥을 구하기 위해 따라나서는데…', 'https://image.tmdb.org/t/p/w500/2QCGC4toQXYuIsWKj5vJQRAdPjd.jpg', 2025, 0, 0, '2026-06-06 13:25:06.422519', 'US');
INSERT INTO public.movies VALUES (100, 1628448, '우린 망했다', '["Comedy", "Thriller", "Drama"]', 'Suresh Triveni', '["Madhuri Dixit", "Triptii Dimri", "Ravi Kishan", "Dharna Durga", "Jatin Sarna"]', '소원했던 딸들과 어머니 앞에 해결해야 할 문제가 닥친다. 이제 그들은 뭐 하나 비밀로 할 수 없는 참견 많은 동네에서 범죄를 은폐해야 한다.', 'https://image.tmdb.org/t/p/w500/rfooTavEjaWh6krAcPpHp1CPj7E.jpg', 2026, 0, 0, '2026-06-06 13:24:59.506309', 'IN');
INSERT INTO public.movies VALUES (4077, 927611, '위험한 관계: 교수와 여대생', '["Drama", "Romance"]', 'EROPING', '["Yoon Yool", "Seung Ha", "Min Do-yoon", "Yeon Joo"]', '진이는 익숙한 고급창녀 생활에 회의를 느낀다. 도망치고 싶은 인생. 마침 새로 입성한 복서 두산에게 호감을 갖고 함께 그곳을 떠나자고 하지만 두산은 진이의 바람과 달리 그곳에 남기로 한다.  한편, 연수는 힘들게 음대에 들어갔지만 홀로 대학 생활을 이어가야 하기에 아르바이트를 하는 등 학업을 제대로 잇지 못한다. 담당 교수에게 몸을 줄 각오로 짧은 치마를 입은 연주. 그러나 눈 하나 깜빡이지 않는 담당 교수. 희망을 잃은 연주는 삶을 포기하려 하는데, 갑작스럽게 찾아온 행운에 우아한 인생을 꿈꾼다.', 'https://image.tmdb.org/t/p/w500/3nkTc0zJlzB6oZoOGC89UFm2yW0.jpg', 2021, 0, 0, '2026-06-08 06:26:42.611918', 'KR');
INSERT INTO public.movies VALUES (247, 324857, '스파이더맨: 뉴 유니버스', '["Animation", "Action", "Adventure", "Sci-Fi"]', 'Bob Persichetti', '["Shameik Moore", "Jake Johnson", "Hailee Steinfeld", "Mahershala Ali", "Brian Tyree Henry"]', '평범한 10대 마일스 모랄레스는 우연히 방사능 거미에 물려 스파이더맨 능력을 가지게 된다. 혼란스러워하던 마일스는 악당과 싸우고 있는 피터 파커를 마주치게 되고 피터 파커는 마일스가 자신과 같은 능력을 가지고 있음을 직감한다. 여러 개의 평행세계가 존재한다는 것을 알게 된 마일스와 피터 파커는 이후 스파이더우먼 스파이더 그웬, 스파이더맨 누아르, 스파이더햄 등 평행세계 속 공존하는 모든 스파이더맨들을 만나게 되는데... 하나의 유니버스에서 만나 팀을 결성한 스파이더맨들은 과연 세계를 구할 수 있을까?', 'https://image.tmdb.org/t/p/w500/d9V6Q9vpVpmaca7vwSUbCajtDb3.jpg', 2018, 0, 0, '2026-06-06 13:25:05.615636', 'US');
INSERT INTO public.movies VALUES (306, 585032, '사방지', '["Drama", "Romance", "History"]', 'Song Gyeong-sik', '["Lee Hye-young", "Bang Hee", "Kwak Jeong-Hee", "Park Am", "Lee Kyeong-hui"]', '흉악범과 미친 여자의 몸에서 양성을 지니고 태어난 사방지는 시주승의 구원을 받아 미륵사에서 성장한다. 남편의 탈상제를 지내러 왔던 청상과부 이소사와 사방지는 운명적인 만남에 의해 속가로 내려와 육욕의 차원을 넘어선 정신적인 사랑을 나누기에 이른다.그러나, 그들의 사랑은 집안 어른들에게 발각당하게 되고, 소사는 사방지를 배신한다. 분노 속에 구사일생 탈출하여 떠돌던 사방지는, 무녀 모화를 만나 사대부가 마님들을 상대로 복수를 시작한다. 그러나 묘화는 결국 가문의 남자들에 의해 죽게되고, 쫓기던 사방지는 소사와 재상봉하지만 문중어른들의 추궁으로 소사는 자결을 택하고, 사방지도 그녀를 따라 자결한다.', 'https://image.tmdb.org/t/p/w500/uFsTrW5qzU2l3YE0ataLoUgfsjJ.jpg', 1988, 0, 0, '2026-06-06 13:25:07.943852', 'KR');
INSERT INTO public.movies VALUES (509, 1236814, '중년부부 스와핑 워크샵', '["Romance"]', 'Kim Tae-hoon', '["Dal Rae", "Do Hee", "Jang Mi", "Han Seok-bong", "Hun-i"]', NULL, 'https://image.tmdb.org/t/p/w500/1iVFVLcw9VN1P9kSrit8uw0iBUH.jpg', 2023, 0, 0, '2026-06-06 13:25:15.688159', 'KR');
INSERT INTO public.movies VALUES (3633, 1481041, 'गिन्नी वेड्स सन्नी 2', '["Romance", "Comedy", "Drama"]', 'Prashant Jha', '["Avinash Tiwary", "Medha Shankr", "Govind Namdeo", "Lillete Dubey", "Vishwanath Chatterjee"]', NULL, 'https://image.tmdb.org/t/p/w500/8lovlbsow4B5KbznLYDNky8usgc.jpg', 2026, 0, 0, '2026-06-08 06:24:26.909574', 'IN');
INSERT INTO public.movies VALUES (400, 1268127, '휴민트', '["Thriller", "Action", "Drama"]', 'Ryoo Seung-wan', '["Zo In-sung", "Park Jeong-min", "Park Hae-joon", "Shin Sae-kyeong", "Robert Maaser"]', '러시아에서 마약 조직을 추적하던 남한 요원. 북한 요원과 정면충돌하면서, 두 사람은 거대한 위험과 거미줄처럼 얽힌 음모에 휘말린다.', 'https://image.tmdb.org/t/p/w500/f7sCSLEPRfV2fWQ0RYOtHhnHXuG.jpg', 2026, 0, 0, '2026-06-06 13:25:11.054514', 'KR');
INSERT INTO public.movies VALUES (4667, 682153, '극장판 도라에몽: 진구의 신공룡', '["Animation", "Adventure", "Family", "Fantasy", "Sci-Fi", "Comedy"]', 'Kazuaki Imai', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Tomokazu Seki", "Subaru Kimura"]', '노비타는 공룡 박람회의 화석 발굴 체험에서 발견한 화석을 공룡알이라고 굳게 믿는다.  도라에몽의 비밀도구 ''타임보자기''로 화석을 원래 상태로 되돌리자 지금껏 알려지지 않은 새로운 종의 쌍둥이 공룡이 태어난다.  노비타를 닮아서 조금 믿음직스럽지 못한 큐와 말괄량이 뮤. 노비타는 개성의 차이로 고생하지만 부모처럼 사랑과 애정을 듬뿍 주며 키운다. 하지만 결국 큐와 뮤가 현재 시대에서 살아가기에는 한계가 오고 만다.  큐와 뮤를 원래의 시대로 데려다주기로 결심한 노비타는 도라에몽, 친구들과 6600만년 전으로 출발하고 큐와 뮤의 친구 공룡들을 찾는 여정을 시작한다.  도라에몽의 비밀도구와 공룡들의 힘을 빌려 공룡의 발자국을 따라간 노비타 일행이 도착한 곳은 신비의 섬. 공룡이 멸종했다고 알려진 백악기에서 큐와 뮤 그리고 노비타 일행에게 기다리고 있는 운명은!?', 'https://image.tmdb.org/t/p/w500/4e6UbuHWqJsTMzKIyTZ53IfiZmR.jpg', 2020, 0, 0, '2026-06-08 06:34:46.853436', 'JP');
INSERT INTO public.movies VALUES (4669, 16907, '나루토 극장판 1: 대활극! 눈의 공주 인법첩', '["Comedy", "Action", "Animation", "Adventure"]', 'Tensai Okamura', '["Junko Takeuchi", "Chie Nakamura", "Noriaki Sugiyama", "Kazuhiko Inoue", "Hidehiko Ishizuka"]', '풋내기 닌자인 우즈마키 나루토는 하다케 카카시 선생의 밑에서 수많은 임무를 수행한다. 명문가의 아들 사스케와 반의 유일한 홍일점 사쿠라와 함께 새로운 임무를 맡은 나루토는 유키노쿠니로 향하여 영화배우 후지카제 유키에를 경호하는 임무를 맡게 된다. 그러나 유키에는 촬영장을 맘에 들어하지 않고, 나루토 일행은 그런 유키에를 달래어 다시 유키노쿠니로 데려간다. 하지만 그곳에는 유키에를 공격하기 위해 닌자들이 숨어 있었는데...', 'https://image.tmdb.org/t/p/w500/kACy5S4EwO4lcV4dAVy4yx6o6aL.jpg', 2004, 0, 0, '2026-06-08 06:34:48.220291', 'JP');
INSERT INTO public.movies VALUES (4670, 75624, '나루토 질풍전 극장판 5기: 블러드 프리즌', '["Thriller", "Animation", "Action", "Comedy", "Horror", "Mystery"]', 'Masahiko Murata', '["Junko Takeuchi", "Mie Sonozaki", "Masaki Terasoma", "Chie Nakamura", "Rikiya Koyama"]', '자존심을 건 격투!  탈옥인가! 죽음인가!  나루토 최대의 위기, 최강의 격투!  모함을 당해 알 수 없는 죄명으로 붙잡힌 ‘나루토’는 한 번 수감되면 평생 탈옥할 수 없는 귀등성(호오즈키성)으로 보내진다. ‘블러드 프리즌’이라고 불리는 닌자들의 감옥, 귀등성의 성주인 ‘무이’는 나루토의 몸에 ‘천뢰’라는 금고술을 새기며 닌자의 힘을 봉인한다. 무이를 해치우면 천뢰가 사라질 것이라는 누군가의 말에 나루토는 탈출을 감행하며 무이를 없애려 하지만 번번히 실패하고, 목숨의 위협까지 받게 된다. 결국 무고함을 알리기 위해 목숨을 건 극단적인 탈출을 하려던 나루토를 의문의 닌자 류제츠가 구해주게 되고, 나루토는 류제츠에 의해 귀등성의 비밀을 알게 된다. 어떤 소원이든 이루어주는 ‘극락의 상자’ 비밀을 가지고 있는 귀등성.  귀등성의 호오즈키는 ‘꽈리’… 그 꽃말은 ‘거짓말’!  진실과 거짓이 엇갈리고 블러드 프리즌에 감춰진 비밀이 밝혀지는 순간, 자존심을 건 닌자들의 최후의 격투가 시작된다!', 'https://image.tmdb.org/t/p/w500/61vFsfB8u2uOHrx1N8sxxFhZzYO.jpg', 2011, 0, 0, '2026-06-08 06:34:48.913688', 'JP');
INSERT INTO public.movies VALUES (4673, 617337, '略奪愛', '["Thriller"]', 'Shunichi Kajima', '["Hitomi Kuroki", "Masato Furuoya", "Hisako Manda", "Toshinori Omi", "Tatsuo Umemiya"]', NULL, 'https://image.tmdb.org/t/p/w500/4E50zR0dFlVK2KwckBiOPagcNkJ.jpg', 1991, 0, 0, '2026-06-08 06:34:51.902821', 'JP');
INSERT INTO public.movies VALUES (4674, 9696, '이치, 더 킬러', '["Action", "Crime", "Horror"]', 'Takashi Miike', '["Tadanobu Asano", "Nao Omori", "Shinya Tsukamoto", "SABU", "Paulyn Sun"]', '보스가 거액의 돈을 가지고 사라지자 중간보스인 카키하라는 그의 뒤를 쫓고, 그런 카키하라를 죽이기 위해 이치라는 킬러가 나선다. 키카하라는 새디즘과 메저키즘을 모두 가지고 있는 인물로 어린 시절의 기억 때문에 자폐적인 성향을 나타내며 불안정한 정서 상태를 가지고 있다. 그는 보스가 사라진 것과 관련이 있다고 생각되는 사람들은 모두 잡아들여 고문을 하는데...', 'https://image.tmdb.org/t/p/w500/gtqkEgS7fhvgKmSCt9EqTdQt6t9.jpg', 2001, 0, 0, '2026-06-08 06:34:52.592487', 'JP');
INSERT INTO public.movies VALUES (471, 1461254, '살목지', '["Horror", "Thriller"]', 'Lee Sang-min', '["Kim Hye-yoon", "Lee Jong-won", "Kim Jun-han", "Kim Young-sung", "Oh Dong-min"]', '기이한 소문이 끊이지 않는 저수지 살목지의 로드뷰 화면에 촬영한 적 없는 정체불명의 형체가 포착된다. 오늘 안에 반드시 재촬영을 끝내야 하는 상황 속에 살목지로 향한 PD 수인과 촬영팀. 촬영이 시작되자 행방이 묘연했던 선배 교식이 등장하고, 설명되지 않는 일들이 연달아 벌어지며 촬영팀은 점점 아비규환에 빠진다. 휘몰아치는 공포 속 기태는 수인을 향해 내달리지만 빠져나오려 할수록 이들은 점점 더 깊은 곳으로 끌려 들어가게 되는데…', 'https://image.tmdb.org/t/p/w500/uVJyWlSPCWftRUXRM6lxTqOzPY6.jpg', 2026, 0, 0, '2026-06-06 13:25:14.093867', 'KR');
INSERT INTO public.movies VALUES (4680, 1209217, '명탐정 코난: 100만 달러의 펜타그램', '["Animation", "Crime", "Mystery", "Action"]', 'Chika Nagaoka', '["Minami Takayama", "Wakana Yamazaki", "Rikiya Koyama", "Ryo Horikawa", "Yuko Miyamura"]', '홋카이도 하코다테에 있는 ‘오노에’ 재벌 가의 창고에 ‘괴도 키드’의 예고장이 도착한다. ‘빅 주얼’만을 노리는 키드가 이번에 노리는 것은 과거 신선조 귀신 부장 ‘히지카타 토시조’와 얽힌 전설적인 검. 검술 대회에 참가하기 위해 하코다테에 방문한 ‘핫토리 헤이지’와 그를 응원하기 위해 온 ‘코난’ 일행도 괴도 키드를 막기 위해 사건에 뛰어들게 된다. 한편, 가슴에 열 십 자(十) 모양의 자상을 입은 시신이 발견되고 ‘죽음의 상인’이라고 불리는 무기상이 용의자로 지목된다. 그 역시 괴도 키드가 찾는 검을 노리고 있었고, 그 검이 오노에 가문이 세대에 걸쳐 지킨 보물을 찾을 열쇠임이 밝혀진다. 검을 쫓는 키드에게 수수께끼의 검사가 습격해 오고, 절체절명의 위기가 닥쳐오는데…!', 'https://image.tmdb.org/t/p/w500/n5tubyY6HoGzhd3RpTAmfKgrt9Y.jpg', 2024, 0, 0, '2026-06-08 06:34:56.692606', 'JP');
INSERT INTO public.movies VALUES (796, 49797, '악마를 보았다', '["Thriller", "Horror"]', 'Kim Jee-woon', '["Lee Byung-hun", "Choi Min-sik", "Jeon Kuk-hwan", "Cheon Ho-jin", "Oh San-ha"]', '국정원 경호요원 수현은 약혼녀 주연이 잔인하게 살해당하자 자신에게 가장 소중한 사람을 지켜내지 못했다는 자괴감과 분노로 가장 고통스러운 복수를 다짐한다. 수현은 연쇄살인마 장경철이 범인임을 알아내고 죽을 만큼의 고통만 가하고 놓아주기를 반복하며 처절한 응징을 시작한다. 그러나, 악마보다 더 악랄한 살인마 장경철은 난생 처음 만난 대등한 적수의 출현을 즐기며 반격에 나서기 시작하는데…', 'https://image.tmdb.org/t/p/w500/dFGrIdZGJtxm1GG4X1liYbxyjgd.jpg', 2010, 0, 0, '2026-06-06 13:25:26.54579', 'KR');
INSERT INTO public.movies VALUES (4094, 418579, '어린 형수', '["Romance"]', 'Choi Woo-seong', '["Kang Ye-na", "Si Hyeon", "Do Mo-se", "Jo Yong-bok", "Ah Ri"]', '“동갑내기 세 남녀의 위험천만한 동거가 시작된다!”  학교를 다니다 운 좋게 시나리오 공모전에 당선되어 영화화할 시나리오를 써야만 하는 휴학생, 병수(도모세)는 시끄러운 도시를 벗어나 조용히 창작에 몰두할 곳을 찾다가 결혼한 학교 선배의 집으로 들어가게 된다.  유학간 젊은 남편 대신 후배 병수와 함께 한 집에서 지내게 된 섹시한 동갑내기 어린 형수, 지은(시현)과 청순 글래머, 보영(예나).  세 남녀의 한 달간의 동거는 수습불가, 위기일발로 치닫고 마는데...!!', 'https://image.tmdb.org/t/p/w500/jAGlDPyNfLvGMXI3Gt9E4SrRtHg.jpg', 2016, 0, 0, '2026-06-08 06:26:56.398585', 'KR');
INSERT INTO public.movies VALUES (4100, 218746, '젊은 엄마', '["Comedy", "Romance"]', 'Kong Ja-kwan', '["Joo In-cheol", "Lee Eun-mi", "Yeon Hee", "Kim Min-jeong", "Jae Hoon Jeong"]', '열아홉 불타오르는 질풍욕정의 시절, 재수생 진구는 미모의 영어 과외 선생님을 떠올리며 혼자만의 에로틱한 상상을 즐긴다. 그러던 어느 날, 그녀에게 적나라한 순간을 들키며 어색한 분위기가 되는 두 사람. 하지만 위기는 곧 기회라고 했던가. 그녀는 진구에게 영어가 아닌 섹스를 가르치기 시작하고 두 청춘의 통제 불능 로맨스가 시작된다. 하지만 결혼을 핑계로 그녀가 과외를 그만두게 되고 이 사랑도 끝이 난다.  어느덧 시간이 흘러 성인이 된 진구. 이젠 애정 없는 섹스에 익숙하다. 하지만 육체적 사랑뿐이던 애인이 임신을 하며 일대 파란이 인다. 달갑지 않은 결혼과 장모와의 첫 만남. 그런데…너무나 아름답고 섹시하다. 진구는 데릴사위가 되어 장모와 한 집에 살게 되지만 철 없는 아내의 불륜과 도망으로 결혼 생활은 결국 파탄 나고 만다. 자신의 딸이 저지른 배신으로 미안해 어쩔 줄 모르는 장모. 진구는 장모의 제안으로 아이, 장모와 함께 기묘하고도 위험한 동거를 시작한다.', 'https://image.tmdb.org/t/p/w500/hvLj5bJ008LCMpNupXyUKFexWrP.jpg', 2013, 0, 0, '2026-06-08 06:27:02.496723', 'KR');
INSERT INTO public.movies VALUES (4103, 479787, '버려진 청춘', '["Romance"]', 'Jeong So-yeong', '["Nam Koong Won", "Lee Ki-seon"]', '약착같이 돈을 벌어 잘살아 보려고 가출한 명자는 공장의 남자에게 몸을 뺏기고 버림받은 뒤로부터 자포자기하며 범죄의 소굴로 빠진다. 소매치기가 된 명자는 우식에게 접근하여 결합한 며칠 뒤 재벌그룹의 양회장댁 파티장에 나타난다. 양회장을 만난 명자는 아들에게 폭행 강간을 당했다는 협박으로 거액의 돈을 받아낸다. 그후 명자는 또 남자를 유혹하러 호텔에 나타났다는 우식을 만나 도망치다 일본에 사업체를 둔 한사장의 자가용의 보호를 받는다. 한사장을 만난 명자는 평소의 꿈을 이루려고 하고 한사장 역시 명자의 열정에 남성을 찾는 기쁨을 누린다. 그래서 둘이 결혼하려는 순간 명자가 뇌종양으로 쓰러져 한달의 시한부 생명이 된다. 거리를 방황하던 명자는 뒤늦게 알고 가슴 아파하는 한사장의 눈물겨운 노력과 살고 싶다는 절규의 보람도 없이 세상을 떠난다.', 'https://image.tmdb.org/t/p/w500/2ty3Bx6ENkZlorh6NP6jzNcEUtL.jpg', 1982, 0, 0, '2026-06-08 06:27:04.525867', 'KR');
INSERT INTO public.movies VALUES (4105, 705996, '헤어질 결심', '["Thriller", "Mystery", "Romance"]', 'Park Chan-wook', '["Tang Wei", "Park Hae-il", "Lee Jung-hyun", "Go Kyung-pyo", "Park Yong-woo"]', '산 정상에서 추락한 한 남자의 변사 사건. 담당 형사 해준은 사망자의 아내 서래와 마주하게 된다. 남편의 죽음 앞에서 특별한 동요를 보이지 않는 서래. 경찰은 보통의 유가족과는 다른 서래를 용의선상에 올린다. 해준은 사건 당일의 알리바이 탐문과 신문, 잠복수사를 통해 서래를 알아가면서 그녀에 대한 관심이 점점 커져가는 것을 느낀다. 한편 좀처럼 속을 짐작하기 어려운 서래는 상대가 자신을 의심한다는 것을 알면서도 조금의 망설임도 없이 해준을 대하는데...', 'https://image.tmdb.org/t/p/w500/rXEJ28XDQsogIGqwVEgwM2oDdpl.jpg', 2022, 0, 0, '2026-06-08 06:27:06.066078', 'KR');
INSERT INTO public.movies VALUES (4681, 221731, '바람의 검심: 교토 대화재편', '["Action", "Adventure", "Drama", "Fantasy"]', 'Keishi Otomo', '["Takeru Satoh", "Emi Takei", "Munetaka Aoki", "Kaito Oyagi", "Yu Aoi"]', '세상을 뒤흔들 반란을 계획하고 있는 절대악 시시오와 그의 부하 십본도를 저지하기 위해 교토까지 온 히무라 켄신 (사토 타케루). 한때 켄신의 자리를 이어받아 유신지사로 활동했던 시시오가 정부에 배신당하고 반란을 일으킨 것이다. 시시오 일당에 맞서던 켄신은 십본도의 세타 소지로 (카미키 류노스케)에 의해 역날검이 반토막이 나게 되고, 나라와 자신의 곁을 지키는 사람들이 절체절명의 위험에 빠지고 심지어 유일한 무기였던 역날검마저 쓸 수 없게 되면서 최대의 궁지에 몰리게 된다. 불살을 맹세했던 켄신은 부러진 역날검을 들고 최강의 절대악인 시시오와 맞서 일생일대의 마지막 결전을 앞두게 되는데..', 'https://image.tmdb.org/t/p/w500/lYhKFVGinM9On5qRsayh7nA9g12.jpg', 2014, 0, 0, '2026-06-08 06:34:57.392222', 'JP');
INSERT INTO public.movies VALUES (4082, 308624, '옹녀뎐', '["Romance", "Drama"]', 'Gyeong Seok-Ho', '["Han Chae-you", "Kang Kyung-woo", "Shin Yu-ju", "Kim Tae-hoon", "Gil Son"]', '변강쇠를 능가하는 음녀 ‘옹녀’의 귀환!  조선 최고의 색남색녀의 이야기가 지금 시작된다!  한 손으론 감당할 수 없는 풍만한 가슴과 한 줌에 잡힐 듯한 잘록한 허리, 그리고 완벽한 곡선을 그리는 엉덩이까지! 그야말로 신이 내린 섹시한 몸매를 타고난 원조 ''베이글녀''가 있었으니 이름하야 바로 옹녀! 평범하게 살기엔 심하게 새끈하고 과하게 섹시한 옹녀와 그녀의 절친 을령은 온 동네 남자들의 음흉한 시선을 즐기며 화려한 밤생활을 즐기고 있다. 그러나 모든 남자를 자신의 치마폭으로 끌어들일 수 있는 무적의 옹녀에게도 단 한 가지 말 못할 비밀이 있었으니, 바로 그녀의 진정한 욕구를 감당할 남자가 이 세상에 없다는 것이다.', 'https://image.tmdb.org/t/p/w500/rtl4hW2KJHInieeCiGgrDJmMG7s.jpg', 2014, 0, 0, '2026-06-08 06:26:45.981694', 'KR');
INSERT INTO public.movies VALUES (4089, 793387, '거룩한 밤: 데몬 헌터스', '["Action", "Fantasy", "Horror", "Thriller"]', 'Lim Dae-hee', '["Don Lee", "Seohyun", "David Lee", "Kyung Soo-jin", "Jung Zi-so"]', '악마와 그를 쫓는 어둠의 숭배자들로 인해 혼란에 빠지게 된 도시. 공권력조차 이들 앞에서 무력해지자 특별한 능력을 가진 어둠의 해결사 거룩한 밤 팀 바우, 샤론, 김군이 직접 악의 무리를 처단하고자 한다. 그러던 중 갑자기 동생 은서가 이상증세를 보인다는 의뢰인 정원이 찾아오고 그 안에서 지금껏 본 적 없던 강력한 존재의 기운을 느끼는데… 과연 거룩한 밤 팀은 악의 무리에 맞서 세상을 구원해 낼 수 있을까?', 'https://image.tmdb.org/t/p/w500/7MGnHpfhF8savUsrUJoI8Q7dTk9.jpg', 2025, 0, 0, '2026-06-08 06:26:51.508314', 'KR');
INSERT INTO public.movies VALUES (4121, 707610, '가슴 큰 울 엄마', '["Drama", "Romance"]', 'Lee Dong-Joon', '["Yoo Jung", "Han Yi-seul", "James", "Shin Yeon-woo"]', '자신보다 나이가 꽤 많은 민수와 결혼하게 된 다희.  덕분에 나이차이가 얼마 나지 않은 아들을 얻게 된다. 어색한 재혁과 친해지기 위해 노력하는데..INSERT INTO public.movies VALUES (4109, 553512, '번 더 스테이지: 더 무비', '["Documentary"]', 'Park Jun-soo', '["RM", "Jin", "Suga", "j-hope", "Jimin"]', '19개 도시, 40회의 공연, 55만석 날개를 펼친 소년들의 역사. 성공적인 월드 투어로 마무리된 ‘2017 방탄소년단 라이브 트릴로지 에피소드3 윙스 투어(2017 BTS LIVE TRILOGY EPOSODE III THE WINGS TOUR)’를 가장 가까이에서 담아낸 방탄소년단의 첫 번째 영화! 지금, 우리  함께 빛나는 청춘의 순간이 스크린에 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/pJKy1yvnKh8UjcuYeG3Rt35xHFA.jpg', 2018, 0, 0, '2026-06-08 06:27:08.94599', 'KR');
INSERT INTO public.movies VALUES (4112, 1210938, '계시록', '["Thriller", "Crime", "Mystery"]', 'Yeon Sang-ho', '["Ryu Jun-yeol", "Shin Hyun-been", "Shin Min-jae", "Han Ji-hyeon", "Do Yeong-seo"]', '신의 계시를 받았다 믿고 실종 사건의 범인을 단죄하려는 목사와 죽은 동생의 환영에 시달리면서도 끈질기게 범인을 쫓는 형사. 어두운 현실 속 각자의 믿음을 따르는 자들의 추악한 민낯이 드러난다.', 'https://image.tmdb.org/t/p/w500/nLVJ5MtxmJQDdFrsoXo2MAeX7kQ.jpg', 2025, 0, 0, '2026-06-08 06:27:11.70703', 'KR');
INSERT INTO public.movies VALUES (4115, 1082010, '고급창녀 2', '["Drama"]', 'EROPING', '["Seung Ha", "Min Do-yoon", "Min Jung", "Shin Yeon-woo", "Yeon Joo"]', NULL, 'https://image.tmdb.org/t/p/w500/zZ3Nbb5Owchk5rrngaoQKAgUipH.jpg', 2022, 0, 0, '2026-06-08 06:27:14.590828', 'KR');
INSERT INTO public.movies VALUES (4119, 1147710, '하이재킹', '["Action", "Thriller", "Crime"]', 'Kim Sung-han', '["Ha Jung-woo", "Yeo Jin-goo", "Sung Dong-il", "Chae Soo-bin", "Moon You-kang"]', '1971년 겨울 속초공항 여객기 조종사 태인과 규식은 김포행 비행에 나선다. 승무원 옥순의 안내에 따라 탑승 중인 승객들의 분주함도 잠시, 이륙한지 얼마 되지 않아 사제폭탄이 터지며 기내는 아수라장이 된다. 여객기를 통째로 납치하려는 용대는 조종실을 장악하고 무작정 북으로 기수를 돌리라 협박한다. 폭발 충격으로 규식은 한 쪽 시력을 잃고 이제 여객기를 조종할 수 있는 사람은 태인 뿐. 이들은 여객기를 무사히 착륙시키기 위한 사투를 시작하는데...', 'https://image.tmdb.org/t/p/w500/pLEenJ0I1XqySVezRdETf2n2w7H.jpg', 2024, 0, 0, '2026-06-08 06:27:18.327214', 'KR');
INSERT INTO public.movies VALUES (4682, 192904, '극장판 도라에몽: 진구의 시공여행', '["Animation", "Adventure", "Family", "Sci-Fi", "Fantasy"]', 'Tsutomu Shibayama', '["Nobuyo Oyama", "Noriko Ohara", "Michiko Nomura", "Kaneta Kimotsuki", "Kazuya Tatekabe"]', '진구는 아이들과 야구를 하다 공을 잃어버린다. 공을 찾는 도중에 우연히 강아지를 발견하게 되고 자신을 쫓아오는 강아지를 내치지 못 해 엄마 몰래 집에 데리고 온다. 강아지에게 바둑이란 이름을 붙여주며 정을 붙이지만 결국 엄마에게 들킨다. 할 수 없이 사람들이 없는 3억 년 전으로 돌아가 그곳에서 살라고 한다.', 'https://image.tmdb.org/t/p/w500/fuMWdzJkGQs1kUvuxUEdugY3lXh.jpg', 2004, 0, 0, '2026-06-08 06:34:58.075156', 'JP');
INSERT INTO public.movies VALUES (4684, 137227, '극장판 도라에몽: 진구와 철인군단 날아라 천사들', '["Animation", "Adventure", "Family", "Sci-Fi", "Fantasy", "Comedy"]', 'Yukiyo Teramoto', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Tomokazu Seki", "Subaru Kimura"]', '어느 날 갑자기 진구네 집 마당으로 로봇의 부품들이 쏟아져 내리고, 도라에몽과 진구는 비밀 도구를 통해 들어간 ‘거울의 세상''에서 이 부품들을 조립해 거대한 로봇 ''잔다크로스''를 완성하는데 성공한다. 그런데 ‘리루루’라는 소녀가 나타나 자신이 바로 잔다크로스의 주인이라고 밝히는데…  잔다크로스와 리루루는 다름아닌 로봇의 별'' 메카토피아''에서 지구를 침략하기 위해 보내어진 로봇이었던 것!  지구 정복이라는 엄청난 계획과 비밀을 알게 된 도라에몽과 진구, 그리고 친구들은 지구를 지키기 위해 철인 군단의 대규모 공격에 맞설 준비를 하고, 마침내 최후의 대결이 시작되는데…', 'https://image.tmdb.org/t/p/w500/xqhuC5wGoOljnrU1RLpdFnj2CF.jpg', 2011, 0, 0, '2026-06-08 06:34:59.571249', 'JP');
INSERT INTO public.movies VALUES (4120, 700199, '엄마친구 4', '["Romance"]', 'Chae Joon-woo', '["Yoo Ri", "Sang Woo", "Si Hoo", "朴智妍", "成宥利"]', '외로운 밤 나를 위로해주는 친구의 아들! "난 오늘부터 엄마 친구가 아니고 네 여자야." 1년 365일 중 300일을 출장 다니는 남편 때문에 독수공방 신세였던 민정. 마침 친구 정희가 옆집으로 이사를 오자 민정은 외로운 마음에 그녀의 집을 자주 방문한다. 그때 우연처럼 계속 마주치게 되는 정희의 아들 재호. 충동적으로 재호와 정사를 나눈 뒤, 민정은 실수였다며 잊으려 하지만 자꾸만 탄탄한 젊은 몸이 떠오른다. 결국, 민정은 잔뜩 달아오른 몸을 식히기 위해 또 다시 재호를 찾는데...', 'https://image.tmdb.org/t/p/w500/szssOJ10ZixWA5gZrfYhdKOI0SZ.jpg', 2018, 0, 0, '2026-06-08 06:27:19.35083', 'KR');
INSERT INTO public.movies VALUES (4135, 543753, '상류사회', '["Drama"]', 'Byun Hyuk', '["Park Hae-il", "Soo Ae", "Yoon Je-moon", "Ra Mi-ran", "Lee Jin-uk"]', '학생들에게 인기와 존경을 동시에 받는 경제학 교수 태준은 우연한 기회를 통해 촉망받는 정치 신인으로 국회의원 선거에 출마하게 된다. 한편 그의 아내이자 미래미술관의 부관장 수연은 재개관전을 통해 관장 자리에 오르려 한다. 그러나 수연의 미술품 거래와 태준의 선거 출마 뒤에 미래그룹과 민국당의 어두운 거래가 있었다는 것이 밝혀지고 두 사람은 완벽한 상류사회 입성을 눈앞에 두고 위기에 처한다. 이 기회를 절대 놓칠 수 없는 태준과 수연 부부는 민국당과 미래그룹에게 새로운 거래를 제안하게 되는데...', 'https://image.tmdb.org/t/p/w500/6feljyK0fBrDDN6R2g61sSBJy2o.jpg', 2018, 0, 0, '2026-06-08 06:27:30.913156', 'KR');
INSERT INTO public.movies VALUES (4139, 474412, '사촌여동생', '["Drama", "Romance"]', 'Yang Ho-yeol', '["Yoo Ji-won", "Ahn So-hee", "Kim Jong-sin"]', '거칠게 애인 속옷을 벗길 때를 빼곤 무료한 나날을 보내는 미대생 광호.할아버지가 위독하다는 소식에 오랫동안 간 적 없는 서울 친척 집을 찾는데어색하고 지루한 친척들과의 만남 속에 떨리는 기억이 떠오른다.잊었다 생각했던 순수한 추억과 함께 어른이 되어 마주한 사촌 여동생 지윤.  훌쩍 커버린 그녀는 광호의 시선을 사로잡고... 어느새 광호는 지윤을 원한다.  이는 지윤도 마찬가지인데... “우리, 딱 한 잔만 더 할까?”서로 표현하진 않지만 걷잡을 수 없는 사랑을 느끼게 되는 둘. “오빠 천천히 해...”누구도 허락지 않는 금기의 사랑, 그리고 반전10년 만에 다시 만난 떨리는 사랑, 이뤄질 수 있을까?', 'https://image.tmdb.org/t/p/w500/1CHTQ06CDJTyvmx6HAyCs9uBY2n.jpg', 2017, 0, 0, '2026-06-08 06:27:33.716457', 'KR');
INSERT INTO public.movies VALUES (4141, 657654, '선배부부와 교환섹스', '["Romance"]', 'Choi Sung-gil', '["Min Do-yoon", "Kang Min-woo", "Kim Choi He", "Tae Joo"]', '지방의 대학 커플 원영과 준석은 졸업까지 시간이 많이 남았지만, 준석이 이미 직장을 구해서 졸업때 까지 딱히 할 게 없던 두 사람은 방학을 맞아 동경에 사는 친한 선배부부 애리와 성호의 집에 놀러가기로 한다.  그들이 오기 하루 전, 크게 싸운 애리와 성호. 반갑게 맞이해주지만 왠지 모를 냉랭한 분위기를 느낀다. 성호는 준석에게 따로 전날 부부싸움 한 사실을 이야기하는데, 그날밤 섹스하자 조르는 원영에게 성호부부의 상황을 설명하며 다음에 하자고 미루는 준석. 원영은 결국 성욕을 참지 못하고 성호를 찾아가 유혹하는데, 애리는 그 모습을 보고 준석에게 찾아가 상황을 설명하며 둘도 바람을 피울것을 제안하는데…과연, 두 커플의 사랑은 어떻게 될것인지?', 'https://image.tmdb.org/t/p/w500/7Dxc4qV8p2whHmlyCSWtIsLYerA.jpg', 2019, 0, 0, '2026-06-08 06:27:35.262969', 'KR');
INSERT INTO public.movies VALUES (4143, 458083, '탐하다: 욕망의 섬', '["Romance"]', 'Kim Jin-sung', '["Han Jae Bum", "Kim Hwa-yeon", "Park Cho-hyeon", "Bae Geon-sik", "Lee Min-Sik"]', '한적한 시골 어귀에서 낚싯배에 오른 사람들은 마음 속 깊은 욕망에 눈을 뜬다. 돈, 섹스, 권력... 끝없는 욕망이 얽힌 무인도에서 일행 중 누군가가 시체로 발견되고, 섬에는 또 다른 누군가가 있다는 사실이 밝혀진다. 과연 이들은 욕망의 섬에서 무사히 탈출할 수 있을까?', 'https://image.tmdb.org/t/p/w500/zNebLQ3O2BNNI1qCDqTRCzxJTrS.jpg', 2017, 0, 0, '2026-06-08 06:27:36.77473', 'KR');
INSERT INTO public.movies VALUES (4144, 897160, '용감한 시민', '["Action", "Drama", "Comedy"]', 'Park Jin-pyo', '["Shin Hae-sun", "Lee Jun-young", "Park Jung-woo", "Park Hyuk-kwon", "Cha Chung-hwa"]', '불의는 못 본 척, 성질은 없는 척, 주먹은 약한 척 먹고 살기 위해 조용히 살아 온 기간제 교사 소시민. 법도 경찰도 무서울 것 하나 없는 안하무인 절대권력 한수강의 선을 넘는 행동을 목격하게 된다. 그의 계속되는 악행을 도저히 참을 수 없었던 그녀, 정체를 숨긴 채 통쾌한 한 방을 날리기로 마음 먹는데…', 'https://image.tmdb.org/t/p/w500/oVJDtwC41sGx5zmWiEkhqwBlopD.jpg', 2023, 0, 0, '2026-06-08 06:27:37.452687', 'KR');
INSERT INTO public.movies VALUES (6072, 463821, '벽 속에 숨은 마법시계', '["Comedy", "Family", "Fantasy", "Horror", "Mystery"]', 'Eli Roth', '["Jack Black", "Cate Blanchett", "Owen Vaccaro", "Kyle MacLachlan", "Renée Elise Goldsberry"]', '부모님을 잃고 혼자가 된 ‘루이스’는 유일한 혈육인 삼촌 ‘조나단’(잭 블랙)을 찾아가고 그와 함께 살게 된다. ‘조나단’의 오랜 친구이자 이웃사촌인 ‘플로렌스’(케이트 블란쳇) 또한 ‘루이스’를 반갑게 맞아주지만 ‘루이스’는 어딘가 미스터리한 이 집에서의 생활이 두렵다. 한편, 매일 밤 무언가를 찾아 집을 돌아다니는 ‘조나단’은 자신을 수상하게 여기는 ‘루이스’에게 결국 자신과 ‘플로렌스’가 마법사임을 고백하고, 모든 것이 살아 움직이는 미스터리한 이 집에 숨겨진 비밀스러운 시계의 존재를 알려준다. 집 안을 채우는 종소리가 사라지기 전, 시계를 찾아 세상을 집어 삼키려는 저주를 풀어야만 하는 ‘조나단’과 ‘플로렌스’! 하지만 이들을 도우려던 ‘루이스’로 인해 깨어나선 안될 존재까지 눈을 뜨고 마는데...  과연 세 사람은 비밀의 시계를 찾아 위기에 빠진 세상을 구할 수 있을까?', 'https://image.tmdb.org/t/p/w500/mVmg4fYyU4fZLAGdWp3VSOoCQ7G.jpg', 2018, 0, 0, '2026-06-08 06:53:42.612291', 'IN');
INSERT INTO public.movies VALUES (4129, 165213, '신세계', '["Thriller", "Crime", "Drama"]', 'Park Hoon-jung', '["Lee Jung-jae", "Choi Min-sik", "Hwang Jung-min", "Park Sung-woong", "Song Ji-hyo"]', '경찰청 수사기획과 강과장은 국내 최대 범죄 조직 골드문이 기업형 조직으로 세력이 확장되자 신입경찰 이자성에게 잠입수사를 명한다. 그리고 8년, 자성은 골드문의 2인자 정청의 오른팔이 되기에 이른다. 골드문 회장이 갑자기 사망하자, 강과장은 후계자 결정에 직접 개입하는 신세계 작전을 설계한다. 후계자 전쟁의 한 가운데, 정청은 지금까지 친형제처럼 함께 해 온 자성에게 강한 신뢰를 보는 반면 작전의 성공만 생각하는 강과장은 자성의 목을 조여만 간다. 신분이 노출될 위기에 처한 자성은 언제 자신을 배신할지 모르는 경찰과, 형제의 의리로 대하는 정청 사이에서 갈등하게 되는데...', 'https://image.tmdb.org/t/p/w500/6odwPYkgvIlKpIYkvQYlWOfspAn.jpg', 2013, 0, 0, '2026-06-08 06:27:25.515814', 'KR');
INSERT INTO public.movies VALUES (4131, 1466115, '오늘 밤, 세계에서 이 사랑이 사라진다 해도', '["Romance", "Drama"]', 'Kim Hye-young', '["Choo Young-woo", "Shin Sia", "Cho Yu-jung", "Jin Ho-eun", "Cho Han-cheul"]', '하루가 지나면 모든 기억이 사라지는 특별한 여고생. 그녀 앞에 조용하고 다정한 같은 반 남학생이 나타난다. 매일이 첫날처럼 새로운 그들의 사랑은 과연 피어날 수 있을까?', 'https://image.tmdb.org/t/p/w500/bMA6E5cu1QUMehjBZOjWjqQjhey.jpg', 2025, 0, 0, '2026-06-08 06:27:26.868997', 'KR');
INSERT INTO public.movies VALUES (4134, 933131, '황야', '["Action", "Adventure", "Thriller", "Horror"]', 'Heo Myeong-haeng', '["Don Lee", "Lee Jun-young", "Lee Hee-jun", "Roh Jeong-eui", "Ahn Ji-hye"]', '세상은 폐허로 변했다. 오직 힘이 지배하는 무법천지가 되었다. 그 황량한 땅에서 살아가는 자들이 생존을 위해 최후의 사투를 벌이는 액션 블록버스터.', 'https://image.tmdb.org/t/p/w500/tgrtRcuyNvDIDUUwkg6HrHV6Q2P.jpg', 2024, 0, 0, '2026-06-08 06:27:30.057948', 'KR');
INSERT INTO public.movies VALUES (4154, 482706, '올리고당 더 무비', '["Drama"]', 'No Zin-soo', '["Kim Nam-woo", "Lee Chae-dam", "Suh Zi-eun", "Kim Hwa-yeon", "Ra Hee-jeong"]', '‘우리에겐 좀 더 달콤하고 끈적한 올리고당이 필요해!’  프리미엄 웹툰 플랫폼 ‘투믹스’의 화제작, 악어인간 작가의 히트 웹툰 ‘올리고당’ 전격 실사화!INSERT INTO public.movies VALUES (4158, 799710, '더 와일드: 야수들의 전쟁', '["Action", "Crime"]', 'Kim Bong-han', '["Park Sung-woong", "Oh Dae-hwan", "Oh Dal-su", "Ju Seok-tae", "Seo Ji-hye"]', '불법 사설 도박장에서 경기 중 상대를 죽인 죄로 징역 8년을 선고받은 전직 복싱 선수 우철. 모범수로 사면된 우철은 조직으로 돌아오라는 도식의 제안을 거절하고, 과거를 잊은 채 평범하게 살기로 결심한다. 하지만 우철은 도식을 비롯해 비리 경찰 정곤과 마약 브로커 각수까지 인간 이하의 짐승들과 필연적으로 얽히며 야수들의 전쟁 속에 뛰어들게 되는데…', 'https://image.tmdb.org/t/p/w500/sm9ETmNPR25kBhRAL1vB6IxvTf8.jpg', 2023, 0, 0, '2026-06-08 06:27:49.790095', 'KR');
INSERT INTO public.movies VALUES (167, 979, '돌이킬 수 없는', '["Drama", "Thriller", "Crime"]', 'Gaspar Noé', '["Monica Bellucci", "Vincent Cassel", "Albert Dupontel", "Jo Prestia", "Philippe Nahon"]', '애스홀클럽 ''렉텀'' 앞. 화면을 어지럽히며 싸이렌이 울린다. 한 남자는 들것에 실려나오고, 한 남자는 손목에 수갑이 채인 채 경찰을 따라나선다. 그들은 ''알렉스''의 연인 ''마르쿠스''와 옛 연인 ''피에르''. 이어 장면이 바뀌면 알렉스의 강간범 ''테니아''를 찾아 파리 밤거리를 미친 듯 돌아다니는 두 사람이 보인다. 그리고 강간당한 알렉스의 아픔보다 몇 배 더 잔인한 복수가 시작된다. 영화는 다시 시간을 거슬러 올라가 지하보도에서 강간당하는 알렉스를 비춘다. 파티장에서 자신을 돌보지 않는 마르쿠스와 다툰 후 혼자서 지하보도를 건너다 일을 당한 것. 그 후 카메라는 마르쿠스와 알렉스의 침실로 들어가 가장 행복했던 한 때를 비추며 그들을 가능한 한 현재의 불행에서 가장 멀리 있는 곳으로 데려간다.', 'https://image.tmdb.org/t/p/w500/AdrItykbv1evqcbIPrItVWnkaKj.jpg', 2002, 0, 0, '2026-06-06 13:25:02.560292', 'FR');
INSERT INTO public.movies VALUES (4157, 716273, '한입만', '["Romance"]', 'Choi Sung-eun', '["Sae Bom", "Bo Ra"]', '아랑은 남편 찬준과 속궁합이 안 맞아 자위행위로 욕구를 만족시키며 살고 있다. 한편 찬준은 성생활에 만족 못하는 아랑에게 질려하며 아랑의 친구 보라와 몰래 외도를 즐기게 되는데...', 'https://image.tmdb.org/t/p/w500/fBfbWJiG5CUGr1gjiaVPA6l94RW.jpg', 2020, 0, 0, '2026-06-08 06:27:49.088957', 'KR');
INSERT INTO public.movies VALUES (4163, 737057, '수상한 진료실: 엄마친구의 특별한 치료', '["Drama", "Romance"]', 'Kang Jeong-Hoon', '["Yurina Aizawa", "Makiko Ichinose", "Shin Fuji", "Take Makimura"]', NULL, 'https://image.tmdb.org/t/p/w500/sP1s76Er7RlV9FyfMkrEowE1wk6.jpg', 2018, 0, 0, '2026-06-08 06:27:53.216175', 'KR');
INSERT INTO public.movies VALUES (4686, 400136, '레지던트 이블: 벤데타', '["Action", "Animation", "Adventure", "Sci-Fi", "Horror"]', 'Takanori Tsujimoto', '["Kevin Dorman", "Matthew Mercer", "Erin Cahill", "John DeMita", "Fred Tatasciore"]', '대 바이오 테러 조직 ''BSAA''의 크리스 레드 필드는 정보를 바탕으로 불법무기 밀매 조직의 거점 인 수수께끼의 양옥에 잠입한다.탐색 하던 중 크리스는 국제 수배자인 "글렌 아리아스"와 대치하는 도중 믿기힘든 광경을 보게되는 한편, 라쿤 시경의 특수 부대 ''STARS''의 일원이었던 레베카 챔버스는 현재 대학 교수로 "사망자가 되살아 난다" 라는 이상한 사건의 조사, 연구을 하고 있었다.사건의 조사를 통해 "신형 바이러스"가 관계하고있는 것을 밝혀내고 그녀는 치료제의 개발에 성공. 그 직후, 연구소가 누군가에게 습격을 받고 레베카는 죽음의 위험에 노출되어 버리지만, 다행히 달려온 크리스들에 의해 구출된다. 이 습격 후 크리스와 레베카는 미국 대통령 직할 에이전트 조직 "DSO"에 소속 된 레온 S 케네디에게로 ... 그는이 신형 바이러스가 관련된 사건을 가장 잘 아는 인물이었다  다시만나게 된 "크리스와 레온" 은 국제 테러수배자인 "글렌 아리아스"의 진정한 목적이 "바이오 테러"라고 생각한  두사람은 레베카와 함께 그의 목적을 저지하고 사람들을 구하기 위해 그를 쫓아 뉴욕으로 향한다.', 'https://image.tmdb.org/t/p/w500/23ZH3MM53TfjG2vsT4h7uDK9A8l.jpg', 2017, 0, 0, '2026-06-08 06:35:00.966446', 'JP');
INSERT INTO public.movies VALUES (4150, 4552, '장화, 홍련', '["Drama", "Horror", "Mystery"]', 'Kim Jee-woon', '["Lim Soo-jung", "Moon Geun-young", "Yum Jung-ah", "Kim Kap-soo", "Park Mi-hyeon"]', '인적이 드문 시골, 이름 모를 들꽃들이 소담하게 피어 있는 신작로 끝에 일본식 목재 가옥이 홀로 서 있다. 낮이면 피아노 소리가 들려 올 듯 아름다운 그 집은 그러나,어둠이 내리면 귀기 서린 음산함을 뿜기 시작한다. 예사롭지 않은 기운이 서려 있는 이 집에서 어른도 아이도 아닌 아름다운 두자매. 수미.수연이, 아름답지만 신경이 예민한 새엄마와 함께 살게 된 그날. 그 가족의 괴담이 시작된다.', 'https://image.tmdb.org/t/p/w500/xsbh58JyVh7jTuSgFRiHMjVfiVy.jpg', 2003, 0, 0, '2026-06-08 06:27:41.66672', 'KR');
INSERT INTO public.movies VALUES (4152, 528549, '룸싸롱 여대생들', '["Romance"]', 'Jo Tae-ho', '["Kim Hee-jeong", "Yoon Da-hyeon", "Choi Chul-min"]', '매혹적이고 섹시한 여대생들이 룸싸롱에 떴다! 야간업소에서 일하고 있는 민주. 그녀는 섹시한 몸매로 많은 남자 손님들을 끌어모은다. 그런데 연말을 앞두고 일손이 부족해지자 마침 아르바이트를 구하고 있는 친구 주희에게 같이 일해보자고 제안하고. 주희는 가벼운 도우미 정도로 생각하고 일을 시작한다. 그런데 생각과 달리 손님들의 야릇한 요구가 끊이지 않자, 어느 순간부터는 적극적으로 손님의 요구를 들어주게 된다. 차츰 돈맛을 알아가는 그녀들의 서비스는 점점 화끈해지는데......', 'https://image.tmdb.org/t/p/w500/xIGPD1QQzxIwRJc55ThQjZpD3tT.jpg', 2018, 0, 0, '2026-06-08 06:27:43.82803', 'KR');
INSERT INTO public.movies VALUES (4168, 65881, '평양성', '["Comedy", "History"]', 'Lee Joon-ik', '["Jung Jin-young", "Lee Moon-sik", "Ryu Seung-ryong", "Hwang Jung-min", "Yoon Je-moon"]', '황산벌 전투를 기억하시는가? 그 후 8년, 백제를 손안에 넣은 신라가 이번엔 고구려 평양성을 타겟으로 점 찍었다. 삼국을 한꺼번에 삼키기위해서는 절대 양보할 수 없는 마지막 보루- 그곳이 고구려 평양성 되시겠다. 삼국통일의 노른자, 고구려의 평양성을 호시탐탐 노리는 능구렁이 야심가가 있었으니, 그가 바로 신라 김유신이다. 한반도 전체를 삼키려는 당나라의 야욕을 알아차리고 조심스럽게 고구려와 연합 작전을 계획, 삼국통일을 준비하는 김유신. 하지만난데없이 당나라로 망명한 고구려의 정통 후계자 남생 때문에 다 된 밥에 코를 빠뜨리게 된다. 이리저리 민폐만 끼치고 다니는 남생 때문에 속이 뒤집히는 이가 한 명 더 있으니, 남생의 동생 남건이다. 아버지 연개소문의 뜻을 받들어, 형 남생의 방해공작을 꿋꿋하게 버텨내는 남건. 신라의 멀티연합군에 맞서 고구려를 지키기 위해 기상천외한 신무기를 앞세워 평양성을 사수하는데...', 'https://image.tmdb.org/t/p/w500/1yeN6ubYUczSy8pEtKtBccW8Amj.jpg', 2011, 0, 0, '2026-06-08 06:27:57.306', 'KR');
INSERT INTO public.movies VALUES (4171, 938008, '더 킬러: 죽어도 되는 아이', '["Action", "Crime", "Thriller"]', 'Choi Jae-hoon', '["Jang Hyuk", "Lee Seo-young", "Bang Eun-jeong", "Bruce Khan", "Lee Seung-joon"]', '은퇴 후 성공적인 재테크로 호화롭게 생활하는 전설의 킬러 ‘의강’이  제멋대로 행동하는 여고생 ‘윤지’를 떠맡게 된다.  단기간 보호자 역할만 하면 될 거라고 가볍게 여긴 순간  ‘윤지’가 납치되는 사건이 일어나는데…  “걔는 다치면 안 되는 아이야”  애써 잠재운 ‘의강’의 본능이 깨어난다!', 'https://image.tmdb.org/t/p/w500/qPXGKOEQ1NSrmH6s7qFFF3qC9O6.jpg', 2022, 0, 0, '2026-06-08 06:27:59.330071', 'KR');
INSERT INTO public.movies VALUES (4174, 22536, '박쥐', '["Drama", "Horror", "Thriller"]', 'Park Chan-wook', '["Song Kang-ho", "Kim Ok-vin", "Kim Hae-sook", "Shin Ha-kyun", "Park In-hwan"]', '정체불명의 피를 수혈 받고 뱀파이어가 된 신부 상현. 피를 원하는 욕구와 신앙심 사이에서 갈등하던 그는 우연히 어린 시절 친구 강우와 그의 아내 태주를 만나면서 인간적 욕망에까지 눈뜨게 된다. 상현은 태주의 묘한 매력에 빠져 쾌락을 갈구하고 태주는 히스테리컬한 시어머니와 무능력한 남편에게 억눌렸던 욕망을 깨워준 상현에게 집착한다. 점점 더 대담해져만 가던 둘의 사랑은 급기야 상현이 뱀파이어라는 사실을 알게 된 태주가 자신의 남편을 죽이자고 제안하고, 상현이 제안을 받아들이면서 새로운 국면에 접어드는데...', 'https://image.tmdb.org/t/p/w500/2CoIYuNwGmdhsV5CM8jRJ2sAZKe.jpg', 2009, 0, 0, '2026-06-08 06:28:02.1105', 'KR');
INSERT INTO public.movies VALUES (4175, 1074218, '여교수와 남제자', '["Romance", "Comedy"]', 'Kim Jung-woo', '["Lee Ji-hyeon", "Lee Yong-joo"]', '심리학 여교수 고정우는 발렌타인데이에 남자친구가 바람 피우는 현장을 목격하고 만취한다. 그를 쫓아온 대학생 김대한은 그녀가 호수 근처에서 비틀거리는 모습을 보고 구하려다 그만 모두 호수에 빠져버리고 두 사람은 하룻밤을 보내게 된다. 이후 대학 강의실에서 교수와 제자로 다시 마주친 두 사람의 로맨스는 어떻게 될까? (출처 : 네이버영화)  여교수를 짝사랑하는 남제자의 설레임이 성숙한 사랑으로 완성되어가는 과정을 그린 로맨스 영화 (출처 : 영등위심의)', 'https://image.tmdb.org/t/p/w500/cUNIrxXniCOOaZIqDzDm6VcLzp4.jpg', 2022, 0, 0, '2026-06-08 06:28:02.786538', 'KR');
INSERT INTO public.movies VALUES (4690, 647, '파이널 판타지 7: 어드벤트 칠드런', '["Animation", "Action", "Adventure", "Fantasy", "Sci-Fi"]', 'Tetsuya Nomura', '["Takahiro Sakurai", "Ayumi Ito", "Showtaro Morikubo", "Maaya Sakamoto", "Keiji Fujiwara"]', '라이프스트림의 무한한 생명 에너지를 바탕으로 세상을 지배하게 된 신라컴퍼니와 그에 맞선 솔져 세피로스 간의 전쟁으로 세상은 폐허가 되어버렸고, 사람들은 혼란을 극복하지 못하고 있었다. 그로부터 2년이 지난 지금에도 세상의 혼란은 더욱 심해져 가기만 하는데, 이 때 세피로스의 피를 이어받아 새로운 세상을 세우려는 무리가 나타나기 시작한다. 한때 신라컴퍼니에서 함께 몸을 담았던 솔져 카다쥬와 아쥬. 이들은 세피로스의 세포를 통해 새로운 몸으로 막강한 힘을 가짐으로써 신라와 맞서고, 세상의 모든 것을 없애고자 한다. 한편 이들과 같은 세포를 이어받았고 또 함께 솔져에 몸담았던 클라우드는 2년 전의 전쟁에서 자신이 지키지 못한 사람들에 대한 죄책감으로 자신의 우리 안에 자신을 가둔 채 주변의 친구들을 받아들이려 하지 않는다. 그러던 어느 날 카다쥬 무리가 세상의 재편을 위해 아이들을 끌어모으던 중 클라우드가 돌보던 덴젤에게까지 손을 내밀고...', 'https://image.tmdb.org/t/p/w500/h2UTjtK46Ax04YhDt2oWK6Q4YpB.jpg', 2005, 0, 0, '2026-06-08 06:35:03.731045', 'JP');
INSERT INTO public.movies VALUES (4691, 1241320, '킹덤 4: 대장군의 귀환', '["Action", "Adventure"]', 'Shinsuke Sato', '["Kento Yamazaki", "Takao Osawa", "Ryo Yoshizawa", "Kanna Hashimoto", "Nana Seino"]', '때는 춘추전국시대, 천하대장군을 꿈꾸는 소년 ‘신’과 그가 이끄는 비신대는 조나라와의 전투에서 열세 끝에 승리하지만 그 기쁨도 잠시 자신을 무신이라 칭하는 조나라의 총대장 ‘방난’의 등장으로 치명상을 입고 위기에 처한다. 한편, 이 전황을 지켜보던 진나라의 총대장이자 전설의 대장군 ‘왕기’는 조나라의 계책을 눈치채고 9년 전부터 이어져온 악연 ‘방난’과의 숙명의 대결을 준비하는데…', 'https://image.tmdb.org/t/p/w500/cCSkNWNtKxERBSH3cmt2pMk3nUP.jpg', 2024, 0, 0, '2026-06-08 06:35:04.412255', 'JP');
INSERT INTO public.movies VALUES (4699, 408866, '리:본', '["Action", "Crime"]', 'Yuji Shimomura', '["Tak Sakaguchi", "Yura Kondo", "Takumi Saitoh", "Mariko Shinoda", "Hitomi Hasebe"]', '일찍이 최강의 특수 용병 부대에 있던 구로다 토시로는 지금은 이시카와 현 가가시의 편의점에서 평범하게 일하면서 사치라는 소녀와 함께 살고 있다. 어느 날 그들이 사는 마을에서 일본국방군이 전술연습 도중 사망한 채로 발견된다. 그리하여 최고의 능력을 인정받았던 위장첩보원은 그의 어두운 과거를 뒤로하고, 목숨을 걸만큼 중요한 것을 위해 그 안에 내재되어 있던 괴물을 깨우기로 결심한다. 한 편 팬텀이라는 정체불명의 남자(오오츠카 아키오)에게서 전달된 섬뜩한 메시지가 전달되면서… 눈 뜨고는 볼 수 없는 서로를 죽이기 위한 잔인한 혈투가 시작되는데..', 'https://image.tmdb.org/t/p/w500/oBKdYpGu2QQiIMdyOJetPOqpJYX.jpg', 2016, 0, 0, '2026-06-08 06:35:12.491639', 'JP');
INSERT INTO public.movies VALUES (4219, 4550, '친절한 금자씨', '["Drama", "Thriller"]', 'Park Chan-wook', '["Lee Young-ae", "Choi Min-sik", "Kwon Yea-young", "Kim Si-hoo", "Nam Il-woo"]', '사람들의 시선을 단번에 사로잡을 만큼 뛰어난 미모의 소유자인 금자는 20살에 죄를 짓고 감옥에 가게 된다. 어린 나이, 너무나 아름다운 외모로 인해 검거되는 순간에도 언론에 유명세를 치른다. 누구보다 성실하고 모범적인 수감생활을 보내는 금자. 친절한 금자씨라는 말도 교도소에서마저 유명세를 떨치던 그녀에게 사람들이 붙여준 별명이다. 13년간의 복역을 무사히 마치고 출소하는 순간, 금자는 그 동안 치밀하게 준비해온 복수를 시작한다. 그녀가 복수하려는 인물은 자신을 죄인으로 만든 백선생. 그녀가 친절을 베풀며 도왔던 동료들은 이제 다양한 방법으로 금자의 복수를 돕는다.', 'https://image.tmdb.org/t/p/w500/iInNT2yeNA8joH1RSSebUEfLC1x.jpg', 2005, 0, 0, '2026-06-08 06:28:37.229826', 'KR');
INSERT INTO public.movies VALUES (4223, 698963, '몽정: 파는 여자', '["Romance"]', 'Wang Ji-bang', '["Ahn So-hee", "Jo Wan-jin", "Shin Yeon-woo", "Sae Bom", "Min Do-yoon"]', '늘 술에 취해 들어오는 남편을 보면서  외로운 생활을 이어가는 상희...  남편이 늦는 날이면 동영상 속 주인공  민기를 보면서 위로를 받으며 살아간다.INSERT INTO public.movies VALUES (4190, 663121, '마이 퍼스널 트레이너', '["Comedy", "Romance"]', 'Byun Chun', '["Lee Na Gil", "Jang Seok Hun", "Kim Henry"]', '유튜버 진호는 구독자를 모으기 위해 헬스를 시작한다. 하지만 운동보다는 몸 좋은 트레이너 석훈에게 더 관심이 간다. 진호는 유난히 다정한 석훈을 보며 그도 자신에게 빠졌다고 확신한다. 그러던 중 샤워실에서 마주친 석훈. “회원님 오늘 시간 있으세요?”', 'https://image.tmdb.org/t/p/w500/tPyUbCCLXyeXgWulhpxvbZAC9b5.jpg', 2019, 0, 0, '2026-06-08 06:28:13.225529', 'KR');
INSERT INTO public.movies VALUES (4221, 591120, '해적: 도깨비 깃발', '["Action", "Adventure", "Comedy", "Fantasy"]', 'Kim Joung-hoon', '["Kang Ha-neul", "Han Hyo-joo", "Lee Kwang-soo", "Kwon Sang-woo", "Chae Soo-bin"]', '자칭 고려 제일검인 의적단 두목 무치와 바다를 평정한 해적선의 주인 해랑. 한 배에서 운명을 함께하게 된 이들이지만 산과 바다, 태생부터 상극으로 사사건건 부딪히며 바람 잘 날 없는 항해를 이어간다. 그러던 어느 날, 왜구선을 소탕하던 이들은 흔적도 없이 사라진 왕실의 보물이 어딘가 숨겨져 있다는 사실을 알게 되고 해적 인생에 다시없을 최대 규모의 보물을 찾아 위험천만한 모험에 나서기 시작한다. 하지만 사라진 보물을 노리는 건 이들뿐만이 아니었으니! 원하는 것을 얻기 위해 수단과 방법을 가리지 않는 역적 부흥수 또한 보물을 차지하기 위해 바다에 뛰어드는데...', 'https://image.tmdb.org/t/p/w500/kGCLsiqw2AbPHFPraOsyGTUOUAk.jpg', 2022, 0, 0, '2026-06-08 06:28:38.775439', 'KR');
INSERT INTO public.movies VALUES (4226, 1459745, '그룹섹스 중독자들', '["Drama", "Romance"]', 'EROPING', '["So Ra", "Im Tae-mok", "Yoon Yool", "Woo Yeol"]', NULL, 'https://image.tmdb.org/t/p/w500/d3K9KgqXjVDBndznRTUfPaLLfTT.jpg', 2025, 0, 0, '2026-06-08 06:28:42.621706', 'KR');
INSERT INTO public.movies VALUES (4195, 4689, '복수는 나의 것', '["Action", "Drama", "Thriller"]', 'Park Chan-wook', '["Song Kang-ho", "Shin Ha-kyun", "Bae Doona", "Im Ji-eun", "Han Bo-bae"]', '선천성 청각 장애인 류에게 누나는 유일한 가족이다. 신부전증을 앓고 있는 누나는 병이 악화되어 신장을 이식하지 않으면 얼마 살 수 없다는 진단을 받는다. 누나와 혈액형이 달라 이식 수술이 좌절된 류는 장기밀매단과 접촉해 자신의 신장과 전재산 천 만원을 넘겨주고 누나를 위한 신장을 받기로 하지만 모든 것이 사기로 드러난다. 누나에게 맞는 신장을 찾기 위해 돈이 필요한 류는 애인이자 운동권 학생인 영미의 말에 아이를 유괴한다. 착한 유괴라고 류를 설득해 동진의 딸을 유괴하지만 이 사실을 알게 된 류의 누이는 스스로 목숨을 끊고 우연한 사건으로 아이마저 죽게 되는데...', 'https://image.tmdb.org/t/p/w500/zrz5mJuXIhYGHBQndduUoT2JHvm.jpg', 2002, 0, 0, '2026-06-08 06:28:18.326956', 'KR');
INSERT INTO public.movies VALUES (427, 292431, '러브', '["Drama", "Romance"]', 'Gaspar Noé', '["Karl Glusman", "Aomi Muyock", "Klara Kristin", "Ugo Fox", "Juan Saavedra"]', '이른 아침부터 울리는 전화벨 소리에 어린 아내, 두 살배기 아이와 함께 잠에서 깬 ‘머피’. 남겨진 음성 메시지에선 ‘일렉트라’의 어머니가 그녀의 행방을 묻고 있다.  그녀와 이별한 후 2년이 흘렀다. 끝없이 비가 내리던 그날 머피는 아파트에 혼자 남아 자신이 가장 사랑했던 여인 일렉트라와 함께한 시간을 떠올린다. 뜨거운 열정으로 가득했던, 설렘과 환희, 질투, 후회의 나날을…', 'https://image.tmdb.org/t/p/w500/aF0D4MVp8ve9MT2EfEwxXlCyZQs.jpg', 2015, 0, 0, '2026-06-06 13:25:12.53719', 'FR');
INSERT INTO public.movies VALUES (4246, 79224, '최종병기 활', '["Drama", "Action", "History"]', 'Kim Han-min', '["Park Hae-il", "Moon Chae-won", "Kim Moo-yul", "Ryu Seung-ryong", "Park Ki-woong"]', '50만 포로가 끌려간 병자호란, 치열했던 전쟁의 한 복판에 역사가 기록하지 못한 위대한 신궁이 있었다.  역적의 자손이자 조선 최고의 신궁 남이. 유일한 피붙이인 누이 자인의 행복만을 바라며 살아간다.어렵사리 맞이한 자인의 혼인날, 가장 행복한 순간에 청나라 정예부대(니루)의 습격으로 자인과 신랑 서군이 포로로 잡혀가고 만다. 남이는 아버지가 남겨준 활에 의지해 청군의 심장부로 거침없이 전진한다.귀신과도 같은 솜씨로 청나라 정예부대(니루)를 하나 둘씩 처치하는 남이, 한 발 한 발 청군의 본거지로 접근해간다. 남이의 신묘한 활솜씨를 알아챈 청의 명장 쥬신타는 왕자 도르곤과 부하들을 지키기 위해 남이를 추격하기 시작한다. 날아오는 방향을 예측할 수 없는 곡사를 사용하는 남이와 무시무시한 파괴력을 가진 육량시를 사용하는 쥬신타, 가장 소중한 것을 지키기 위한 사상 최대 활의 전쟁을 시작한다.', 'https://image.tmdb.org/t/p/w500/gaXSEQ2XzkFnKxYIvkqj4Tidltk.jpg', 2011, 0, 0, '2026-06-08 06:29:18.147364', 'KR');
INSERT INTO public.movies VALUES (8663, 1631, '진실한 소녀', '["Romance", "Drama"]', 'Catherine Breillat', '["Charlotte Alexandra", "Hiram Keller", "Rita Maiden", "Bruno Balp", "Georges Guéret"]', '때는 1963년 8월,14세 소녀 알리스는 여름방학을 랑드지방에 있는 부모님 집에서 보내게 된다. 침울한 엄마와 뚱뚱한 아빠 사이에서 외로운 소녀는 일기 속에다가 속마음과 섹스에 대한 호기심을 솔직하게 풀어놓는다.그녀는 또한 깨진 달걀, 밀초, 귀지, 토사물, 소변, 혈액 심지어 정액을 만지며 촉각을 즐긴다.그녀는 속바지도 없이 걸어 다니며, 자전거도 타고, 바닷가에 앉아 있기도 한다.어느날 ''짐''이라는 건장한 체격과 조각 같은 얼굴의 20대 청년이 아버지의 목재소에 고용된다. 그녀는 그를 첫번째 애인으로 만들리라 결심하고 유혹을 하기 시작한다. 그러나 이미 약혼자가 있는 짐은 그녀의 유혹을 거절하고 그러면 그럴수록 알리스는 둘사이의 에로틱한 정사,나아가 사도매저키즘(가학적이며 피학적)인 환상에 빠져든다.드디어 짐과 밤에 만나기로 약속을 한 날, 눈치를 챈 부모는 그녀를 나가지 못하게 한다.', 'https://image.tmdb.org/t/p/w500/ku4Dz80IjiiQ7ODeAp1XsxRxqMK.jpg', 1976, 0, 0, '2026-06-08 07:26:46.827452', 'FR');
INSERT INTO public.movies VALUES (4704, 21422, '명탐정 코난: 시한장치의 마천루', '["Animation", "Crime", "Mystery", "Adventure"]', 'Kenji Kodama', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Akira Kamiya", "Kenichi Ogata"]', '검은 조직에 의해 초등학생 코난의 몸으로 작아진 고등학생 명탐정 쿠도 신이치. 천재 건축가 모리야 테이지 교수에게 가든 파티의 초대를 받았지만, 코난인 상태로는 참석할 수 없어 대리인을 부탁하려 소꿉친구 모리 란에게 목소리 변조기를 사용해 신이치로서 전화를 건다. 하지만 란이 신이치의 생일 전날인 5월 3일 밤 10시, 심야 영화를 보자고 조건을 걸어 난처해지고 만다. 약속 당일, 뉴스에서 화약 도난 사건을 보던 코난이자 신이치에게 수상한 협박 전화가 걸려 오고 의문의 남자가 도심 전체를 표적으로 한 연쇄 폭탄 테러를 예고한다. 자신에게 도전장을 내민 연쇄 폭탄 테러임을 알아챈 신이치는 범인과의 숨 막히는 대결 중, 베이카 시티 빌딩에 있는 란이 타깃이 되어 위험에 처했음을 깨닫는데…', 'https://image.tmdb.org/t/p/w500/ND2vNSrxd3BiiaxYDyqQ9IiZxO.jpg', 1997, 0, 0, '2026-06-08 06:35:16.634705', 'JP');
INSERT INTO public.movies VALUES (4708, 845387, '마보로시', '["Animation", "Drama", "Romance", "Fantasy"]', 'Mari Okada', '["Junya Enoki", "Reina Ueda", "Misaki Kuno", "Koji Seto", "Kento Hayashi"]', '공장 폭발 사고로 시간의 흐름이 멈춰 버린 작은 마을. 그곳에 남겨진 열네 살 마사무네와 친구들은 빠르게 붕괴해 가는 세계 속에서 발버둥 친다.', 'https://image.tmdb.org/t/p/w500/24N5QrUtp5LoPuMldudTJICIcYM.jpg', 2023, 0, 0, '2026-06-08 06:35:20.743198', 'JP');
INSERT INTO public.movies VALUES (4229, 694943, '배달노출: 알몸으로 유혹하기', '["Romance"]', 'Kong Ja-kwan', '["Yoo Jung", "Yoon So-jung", "Jin Si-ah", "Baek Yoon-jae", "Kang Min-woo"]', '치킨집을 운영하는 석과 현진 부부.INSERT INTO public.movies VALUES (4245, 103750, '돈의 맛', '["Drama"]', 'Im Sang-soo', '["Kim Kang-woo", "Baek Yoon-sik", "Youn Yuh-jung", "Maui Taylor", "Kim Hyo-jin"]', '대한민국을 돈으로 지배하는 재벌 백씨 집안의 탐욕스러운 안주인 금옥. 돈에 중독되어 살아온 자신의 삶을 모욕적으로 느끼는 그녀의 남편 윤회장. 백씨 집안의 은밀한 뒷일을 도맡아 하며 돈 맛을 알아가는 비서 영작. 그런 영작에게 묘한 감정을 느끼며 다가가는 장녀 나미. 돈을 지배한, 돈에 지배된 그들의 얽히고 설킨 권력, 욕정, 집착의 관계들. 이 시대 최고의 맛! 돈의 맛에 중독된 대한민국 최상류층의 숨겨진 이야기가 공개된다.', 'https://image.tmdb.org/t/p/w500/5wBYDAOVgPHGZzREG2mbVRzA3xv.jpg', 2012, 0, 0, '2026-06-08 06:29:17.407214', 'KR');
INSERT INTO public.movies VALUES (901, 360814, '당갈', '["Drama", "Family", "Comedy"]', 'Nitesh Tiwari', '["Aamir Khan", "Fatima Sana Shaikh", "Sanya Malhotra", "Zaira Wasim", "Suhani Bhatnagar"]', '전직 레슬링 선수였던 ‘마하비르 싱 포갓(아미르 칸)’은 아버지의 반대로 금메달의 꿈을 이루지 못한 채 레슬링을 포기한다. 아들을 통해 꿈을 이루겠다는 생각은 내리 딸만 넷이 태어나면서 좌절된다. 그러던 어느 날, 두 딸이 또래 남자아이들을 신나게 때린 모습에서 잠재력을 발견하고 레슬링 특훈에 돌입한다. 사람들의 따가운 시선과 조롱에도 불구하고 첫째 기타(파티마 사나이 샤크)와 둘째 바비타(삼아 말호 트라)는 아버지의 훈련 속에 재능을 발휘, 승승장구 승리를 거두며 국가대표 레슬러로까지 성장해 마침내 국제대회에 출전한다.하지만 세계의 벽은 높기만 하고 끝없이 이어지는 슬럼프로 연이은 패배만 이어지는데…INSERT INTO public.movies VALUES (8664, 52683, '진심으로', '["Drama", "Romance"]', 'Pierre Jolivet', '["Gérard Lanvin", "Carole Bouquet", "Virginie Ledoyen", "Guillaume Canet", "Aurélie Vérillon"]', NULL, 'https://image.tmdb.org/t/p/w500/m1KA1gxO8yNh1Z7PC3MMPSe13lE.jpg', 1998, 0, 0, '2026-06-08 07:26:47.505837', 'FR');
INSERT INTO public.movies VALUES (4265, 376858, '하숙집 2', '["Romance"]', 'Jeong Tae-ryeong', '["Jeong Neom-chyeo", "Eun Ha", "Ryoo Hyeon-ah", "Kim Do-hee", "Yu Da-eun"]', '“너, 나 만지고 싶지? 원하면 한 번 해 봐!”INSERT INTO public.movies VALUES (4268, 626872, '비상선언', '["Action", "Drama", "Thriller"]', 'Han Jae-rim', '["Song Kang-ho", "Lee Byung-hun", "Jeon Do-yeon", "Kim Nam-gil", "Yim Si-wan"]', '베테랑 형사 팀장 인호는 비행기 테러 예고 영상 제보를 받고 사건을 수사하던 중 용의자가 실제로 KI501 항공편에 타고 있음을 파악한다.딸의 치료를 위해 비행 공포증임에도 불구하고 하와이로 떠나기로 한 재혁은 주변을 맴돌며 위협적인 말을 하는 낯선 이가 신경 쓰인다.인천에서 하와이로 이륙한 KI501 항공편에서 원인불명의 사망자가 나오고, 비행기 안은 물론 지상까지 혼란과 두려움의 현장으로 뒤바뀐다.이 소식을 들은 국토부 장관 숙희는 대테러센터를 구성하고 비행기를 착륙시킬 방법을 찾기 위해 긴급회의를 소집하는데…', 'https://image.tmdb.org/t/p/w500/h8gyJKvIHzXo5HrGOe2WOJEe0IV.jpg', 2022, 0, 0, '2026-06-08 06:29:35.689357', 'KR');
INSERT INTO public.movies VALUES (4272, 387847, '친구 누나', '["Romance"]', 'Chae Gil-byeong', '["Park Cho-hyeon", "Min Joon", "Ahn So-yoon", "Joo In-cheol", "Seo Joon-yeol"]', '"누나, 그냥 우리집에서 살래요?"  섹시한 친구 누나와의 위험한 동거가 시작된다!  준수는 절친 희규의 누나 희진이 사기를 당해 오갈 곳이 없어진 사실을 알고 동거를 제안한다. 그날부터 시작된 두 사람의 위험한 동거. 친남매처럼 친하지만 절대로 친남매는 될 수 없는 두 성인 남녀는 자꾸만 야릇한 분위기를 풍기기 시작하고, 준수는 벽 너머에 잠들어 있을 희진의 생각에 잠 못드는 밤이 많아진다. 준수가 뭔가 변하고 있단 사실을 눈치 챈 여자친구 미나는 일부러 희진이 있는 집 안에서 준수를 유혹한다. 여자친구냐, 친구누나냐. 결코 답을 찾을 수 없는 난제가 준수 앞에 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/5J0SWa3BEYdWfvMgtOJIBAMSPQf.jpg', 2016, 0, 0, '2026-06-08 06:29:39.430396', 'KR');
INSERT INTO public.movies VALUES (4516, 429245, '좋아하지도 않으면서', '["Romance", "Drama", "Fantasy"]', 'Kōta Yoshida', '["Rico Tamaki", "Takuya Negishi", "Ryosuke Kawamura", "Hiroshi Kanbe", "Tomoko Fujita"]', '무명 모델 코토코는 밤에는 ‘성녀’란 애칭으로 불리는 에이스이다. 파티에서 만난 리쿠에게 첫눈에 반하지만 말도 못 붙이고 술김에 동료 고다와 하룻밤을 보낸다. 리쿠를 다시 만나서 불 같은 열정이 타오르지만 사랑을 느끼는 사람과 관계를 할 수 없다. 밀당보다 쉬운 사랑이 편한 4차원의 성녀는 고다와 리쿠 사이에서 아슬아슬한 줄다리기를 하는데… 그녀의 발칙하고 도발적인 사랑에 빠져든다!', 'https://image.tmdb.org/t/p/w500/rsPossEiIbglf3zJ05fZwQpDxoe.jpg', 2016, 0, 0, '2026-06-08 06:32:42.407214', 'JP');
INSERT INTO public.movies VALUES (4256, 440617, '가족의 재구성', '["Romance", "Drama"]', NULL, '["Yoon Se-na", "Baek Se-ri", "Sin Seong-hoon", "Kim Yo-seob"]', '각자 아이들을 데리고 재혼을 한 광식과 해라. 본의 아니게 남매가 된 광식의 아들 명호와 해라의 딸 달래는 아슬아슬한 관계를 이어가고 있다. 명호는 수시로 달래에게 수작을 걸고 달래 역시 싫지 않은 내색으로 이복 오빠의 장난을 받아 치던 중 가족은 강원도로 여행을 떠나게 되는데…  알고 보면 유명한 VJ로 야한 동영상을 올려오던 달래의 광 팬이었던 새 아버지 광식과 원숙한 새엄마에게 묘하게 끌리는 아들 명호. 가족은 제한된 공간에서 머물면서 휴가를 보내다 보니 자신들의 감정을 제어하기 점차 어려워지고, 우연히 달래와 광식 단 둘이 낚시를 떠나게 되며 가족 관계는 복잡하게 얽혀가기 시작한다.', 'https://image.tmdb.org/t/p/w500/sfl7CBslXn67PucISrVmJREx4tz.jpg', 2017, 0, 0, '2026-06-08 06:29:26.50486', 'KR');
INSERT INTO public.movies VALUES (4259, 1437256, '죽기 전에 한 번만', '["Drama"]', 'Min Chae-yeon', '["Hong Jin-gi", "Oh Ji-Yoon", "Yang Seung-soo", "Kim Dong-yeon", "Seo Jin-won"]', '29살에 시한부 인생을 선고받은 ‘민정’. 죽기 전 마지막으로 특별한 목표를 세운다. 바로 그녀와 함께했던 남자들을 모두 만나는 것! ‘민정’의 첫사랑, 연하남, 교수님, 심지어는 결혼까지 생각했던 전 남자친구까지! 각기 다른 이유로 헤어진 남자들과의 재회는 예기치 못한 아찔한 사건에 마주하게 하는데…  내가 사랑했던 남자들에게 남기는 마지막 메시지  “잊지 못할 최고의 밤을 선사할게!”', 'https://image.tmdb.org/t/p/w500/56qycU6OMyyZps1gIxWJ1VtPJSG.jpg', 2025, 0, 0, '2026-06-08 06:29:28.866227', 'KR');
INSERT INTO public.movies VALUES (4260, 280019, '황제를 위하여', '["Action", "Crime", "Thriller"]', 'Park Sang-joon', '["Lee Min-ki", "Park Sung-woong", "Lee Tae-im", "Kim Jong-goo", "Jung Heung-Chae"]', '촉망 받는 야구선수였지만 승부조작에 연루된 후 모든 것을 잃게 된 ‘이환’(이민기).  빠져 나갈 곳 없는 인생의 밑바닥에서 이환은  사채업과 도박판을 주름 잡는 부산 최대 규모의 조직,  황제 캐피탈의 대표 ‘상하’(박성웅)를 만나게 된다.  돈 앞에선 냉정하지만  자신의 식구들은 의리와 신뢰로 이끄는 상하.  이환의 잠재력을 본능적으로 알아 본 상하는  다른 조직원들의 우려와 반대에도 불구하고, 그를 자신의 세계로 끌어들인다.  이긴 놈만 살아남는 도박판 같은 세상.  상하의 절대적인 신임 속에서 이환은  타고난 승부근성과 거침없는 행보로 점점 자신의 영역을 넓히고,  감춰두었던 야망을 키워가는데…!', 'https://image.tmdb.org/t/p/w500/xNELPRzugre05vFC36ilVfkerCF.jpg', 2014, 0, 0, '2026-06-08 06:29:29.665175', 'KR');
INSERT INTO public.movies VALUES (8665, 1672, '프로페셔널', '["Action", "Adventure", "Thriller"]', 'Georges Lautner', '["Jean-Paul Belmondo", "Robert Hossein", "Elisabeth Margoni", "Jean-Louis Richard", "Jean Desailly"]', '프랑스 비밀 정보국 요원 조슬랭 보몽은 아프리카의 독재자 은잘라를 제거하라는 임무를 받고 파견된다. 하지만 임무가 갑작스럽게 취소되자, 그는 자국 정부가 자신을 현지 당국에 넘겨버렸다는 사실에 큰 충격을 받는다. 형식적인 재판 끝에 그는 20년의 강제 노동형을 선고받는다. 그러나 교도소를 탈출한 보몽은 자신을 배신한 자들에게 복수하고, 원래 맡았던 임무를 완수하겠다고 다짐한다.', 'https://image.tmdb.org/t/p/w500/mvX0FmhVY2jhPRhXUkf1VWiRXYC.jpg', 1981, 0, 0, '2026-06-08 07:26:48.166149', 'FR');
INSERT INTO public.movies VALUES (4287, 745323, '가슴 큰 엄마친구', '["Drama", "Romance"]', 'Lee Jeong-seok', '["Jin Joo", "Ye Seul", "Min Do-yoon", "Jo Yong-bok"]', '남편과 이혼 후 아들 동진과 둘이 살던 나연은 남편 형철의 사업 실패로 갈 곳이 없어진 후배 민주의 부탁으로 잠시 네 사람이 함께 살게 되는데. 형철은 민주를 섹 스를 하려 하지만 거절당한다.INSERT INTO public.movies VALUES (4295, 1354700, '강령: 귀신놀이', '["Horror", "Mystery", "Thriller"]', 'Son Dong-wan', '["YERI", "Lee Chan-hyeong", "Suh Dong-hyun", "Oh So-hyun", "Kim Eun-bi"]', '문을 열었습니다. 열었습니다. 열었습니다. 공모전에 제출할 독특한 영상을 위해 ‘무엇이든 알려주는 강령술’을 촬영하기로 한 ‘자영’과 친구들. 언니 ‘자영’을 잘 따르는 동생 ‘서우’까지 합류하고, 어두운 밤 6명의 아이들은 폐쇄된 지하 저수조로 향한다. 촬영 도중, 호기심이 발동한 ‘자영’과 친구들은 진짜 강령술을 시도한다. 걱정과 달리 잠잠한 분위기에 안도감과 아쉬움이 교차하던 순간, 빙의자 역할을 하던 ‘서우’가 검은 물을 토하며 쓰러지고, 질문이 적힌 부적에 답이 나타난다. 들어오세요. 들어오세요. 들어오세요. 가벼운 마음으로 시작한 강령술은 곧 끔찍한 저주가 되어, 아이들의 목숨을 위협하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/szBqzH2qcUthCm1uDVsBAYZbExW.jpg', 2025, 0, 0, '2026-06-08 06:29:55.550765', 'KR');
INSERT INTO public.movies VALUES (4314, 1396749, '와일드 씽', '["Comedy"]', 'Son Jae-gon', '["Gang Dong-won", "Um Tae-goo", "Park Ji-hyun", "Oh Jung-se", "Shin Ha-kyun"]', '한때 가요계를 휩쓸었지만 예기치 못한 사건에 휘말려 하루아침에 해체된 3인조 혼성 댄스 그룹 트라이앵글. 20년 만에 리더 현우에게 재기의 발판이 될 트라이앵글 공연 제안이 들어오고, 인생의 마지막 기회를 잡기 위해 멤버들을 찾아 나선다. 생계형 방송인이 된 현우, 재벌가 며느리가 된 도미, 솔로 앨범으로 빚더미에 앉은 상구까지 세 사람은 다시 모여 공연장으로 향하지만, 과거 트라이앵글의 라이벌 발라드 왕자 성곤과 악연으로 얽힌 전소속사 박대표까지 나타나며 상황은 점점 걷잡을 수 없이 꼬여가는데…', 'https://image.tmdb.org/t/p/w500/s4IUDzLZJb4CosgEXcmouY32Jfg.jpg', 2026, 0, 0, '2026-06-08 06:30:09.950551', 'KR');
INSERT INTO public.movies VALUES (4727, 188403, '극장판 도라에몽: 진구의 도라비안 나이트', '["Animation", "Adventure", "Fantasy", "Family", "Sci-Fi"]', 'Tsutomu Shibayama', '["Nobuyo Oyama", "Noriko Ohara", "Michiko Nomura", "Kazuya Tatekabe", "Kaneta Kimotsuki"]', '하룬 알라시드 왕의 통치 시대인 794년의 바그다드를 무대로 도라에몽 일행 5명의 활약을 그린 장편 작품이다. 《천일야화》(아라비안 나이트)를 모티브로 하고 있다.  도라에몽, 노비타, 자이언, 스네오 4명이 포로로 잡혀간 시즈카를 구하는 전개인데 이러한 전개를 담고 있는 대장편 도라에몽 작품은 본작이 유일하다(《노비타의 해저귀암성》에서도 시즈카가 잡혀갔지만 이것은 본인의 의사에 의한 것이기 때문에 사정이 다르다). 영화의 경우 《극장판 도라에몽: 진구의 인어대해전》에서 이 패턴이 사용되었다.  또한 본작에서는 도라에몽이 악역에게 자신의 4차원 주머니를 도둑맞고 주머니에서 〈비밀도구〉 없는 모험이라는 핸디캡을 강요받는다. 도라에몽이 가지고 있는 편리한 도구들을 “거의 통째로” 봉인하는 설정을 이용한 최초의 작품이기도 하다.[2] 따라서 본작에서는 비밀도구 이외에 신밧드가 가진 〈왕의 컬렉션〉이 작중에서 중요한 역할을 맡는 도구가 된다.', 'https://image.tmdb.org/t/p/w500/7M5av7hMjWhtYckOhplt5jX6D9e.jpg', 1991, 0, 0, '2026-06-08 06:35:37.827705', 'JP');
INSERT INTO public.movies VALUES (4303, 313980, '캠퍼스 S 커플', '["Romance"]', 'Song Chang-yong', '["Moon Bo-ryoung", "Seo Hyo-myeong", "Phillip Choi", "Hwang Bo-Mi", "Park Ran"]', '만물이 소생하는 새 학기 봄. 군 제대를 한 찬승(최필립)은 복학신청을 하다가 선배의 전화를 받고 나이트 클럽으로 향한다. 클럽 룸에서 부킹을 하던 찬승 일행은 웨이터에게 끌려온 아영 (문보령)과 마주치고 서로에게 반한 찬승과 아영은 원나잇 스탠드를 감행한다.  그렇게 황홀한 밤을 보낸 찬승은 다음날 학교에서 자신을 좋아하는 후배 유진(서효명)과 재회하며 서로 반가워 한다. 방과 후 기분 좋게 집에 가는 버스에 오른 찬승은 자신의 이상형 민조(박란)를 발견하게 되고 한눈에 반한다.  그러던 어느 날 학교 카페에서 아영과 다시 만나게 된 찬승은 아영이 같은 과 학생임을 알게 되면서 세 명의 여학생과 아슬 아슬한 데이트를 즐기게 되는데…', 'https://image.tmdb.org/t/p/w500/7wnwDBJvQr552rHCHYmAsiojSSj.jpg', 2014, 0, 0, '2026-06-08 06:30:00.89604', 'KR');
INSERT INTO public.movies VALUES (8666, 359364, '휴먼', '["Documentary"]', 'Yann Arthus-Bertrand', '[]', '헬리콥터 고장으로 종일 농부와 나눈 대화에 영감을 얻은 감독은 가장 높은 상공에서, 동시에 가장 친근한 거리에서 인간을 담았다. 3년간 110회차 촬영을 통해 완성된 장대한 다큐멘터리.', 'https://image.tmdb.org/t/p/w500/wLTAsQeJh8jfBAjMDyJc7MNIziI.jpg', 2015, 0, 0, '2026-06-08 07:26:48.843581', 'FR');
INSERT INTO public.movies VALUES (4326, 204553, '감시자들', '["Crime", "Action", "Thriller"]', 'Kim Byung-seo', '["Sul Kyung-gu", "Jung Woo-sung", "Han Hyo-joo", "Kim Byeong-ok", "Jin Kyung"]', '범죄 대상에 대한 감시만을 전문적으로 담당하는 경찰 내 특수조직 감시반. 동물적인 직감과 본능으로 범죄를 쫓는 감시 전문가 황반장이 이끄는 감시반에 탁월한 기억력과 관찰력을 지닌 신참 하윤주가 합류한다. 그리고 얼마 후 감시반의 철저한 포위망마저 무용지물로 만든 범죄가 벌어진다. 단 3분만에 한 치의 실수도 없이 벌어진 무장강도사건. 얼굴도, 단서도 남기지 않은 그들의 존재에 모든 시선이 꽂힌다. 철저하게 짜여진 계획 하에 움직이며 1초의 오차도 용납하지 않는 범죄 조직의 리더 제임스. 자신의 존재를 절대 드러내지 않는 그는 감시반의 추적이 조여올수록 더욱 치밀하게 범죄를 이어간다. 더 이상의 범죄를 막기 위해 반드시 놈의 실체를 알아내야만 하는 감시반. 황반장과 하윤주는 모든 기억과 단서를 동원해 놈을 쫓기 시작하는데…', 'https://image.tmdb.org/t/p/w500/2iZbCv0XJGaPwZTTF7atEosAxRR.jpg', 2013, 0, 0, '2026-06-08 06:30:18.001037', 'KR');
INSERT INTO public.movies VALUES (4332, 978726, '내 여친은 에로배우', '["Romance"]', 'Lee Sang-soo', '["Yoo Ji-hyun", "Ji Hee", "Woo Yeol", "Im Tae-mok", "Yoo Jong-hae"]', '은밀한 에로영화의 촬영 현장을 보여드립니다!INSERT INTO public.movies VALUES (4335, 409282, '타부: 새누나', '["Romance", "Drama", "Thriller"]', 'Kook Man-joong', '["Jeong Yoon-I", "Lee Yoo-rin", "Min Joon", "Kim Yeong-sik", "Do Mo-se"]', '2년전 지방 펜션 사업가 대길(정민준)의 재력을 보고 재혼한 보험왕 송여사(이유린). 하지만, 서서히 망해가는 대길의 펜션 사업과 자신을 인정하지 않는 대길의 아들 성호(김영식)로 인해 결혼생활은 평탄 치 않다. 더욱이 매달 조여오는 보험 실적에 짓눌린 송여사는 지긋지긋한 생활을 벗어나 멋지고 새로운 인생의 한방을 위해 그녀의 젊은 내연남과 음모를 꾸민다. 이윽고 재혼한 남편 대길과 그의 아들 성호를 대상으로 위험한 미끼를 던지는데...', 'https://image.tmdb.org/t/p/w500/wfEuhpvmA4QjY4CP0rHr4sysaoo.jpg', 2016, 0, 0, '2026-06-08 06:30:24.785811', 'KR');
INSERT INTO public.movies VALUES (4337, 736820, '공조 2: 인터내셔날', '["Action", "Comedy"]', 'Lee Suk-hoon', '["Hyun Bin", "Yoo Hai-jin", "Yoona", "Daniel Henney", "Jin Sun-kyu"]', '남한으로 숨어든 글로벌 범죄 조직을 잡기 위해 새로운 공조 수사에 투입된 북한 형사 림철령. 수사 중의 실수로 사이버수사대로 전출됐던 남한 형사 강진태는 광수대 복귀를 위해 모두가 기피하는 철령의 파트너를 자청한다. 이렇게 다시 공조하게 된 철령과 진태! 철령과 재회한 민영의 마음도 불타오르는 가운데, 철령과 진태는 여전히 서로의 속내를 의심하면서도 나름 그럴싸한 공조 수사를 펼친다. 드디어 범죄 조직 리더인 장명준의 은신처를 찾아내려는 찰나, 미국에서 날아온 FBI 소속 잭이 그들 앞에 나타나는데…', 'https://image.tmdb.org/t/p/w500/poEYP8BZswiVu0xCFVbq8uPxR6l.jpg', 2022, 0, 0, '2026-06-08 06:30:26.135003', 'KR');
INSERT INTO public.movies VALUES (4372, 884063, '섹귀 : 섹스에 미친 귀신들', '["Drama"]', 'Han Dong-Ho', '["Seung Ha", "Yoon Yool", "Kang Min-woo", "Park Do-jin"]', '고립된 외진 곳에 위치한 펜션에 일하며 살고 있는 임선균. 여자친구 오유민이 놀러 오는 것 빼고는 손님 하나 찾지 않는 쓸쓸한 이 집에 뭔가 수상하고 괴이한 일이 벌어진다. 이 집에 살았던 섹스 한 번 못하고 죽었던 쌍둥이 처녀귀신과 총각귀신이 선균, 유민 커플과의 전쟁을 선포한 것. 귀신들의 목적은 살아생전에 섹스 한 번 경험하지 못하고 억울하게 죽은 한을 선균과 유민에게 몸으로 풀어내는 것이다.  차고 넘치는 섹스로 그녀들의 몸을 달래주면 그때서야 비로소 선균의 집을 미련없이 떠난다는 귀신들의 소원을 이루어 주기 위해 선균은 불철주야 뼈와 살이 타는 극한의 밤을 보내게 되고....선균의 여자 친구인 유민 또한 총각귀신과 육체체험을 하자 미쳐 가기 시작한다.  그 집을 떠나자고 선균에게 말하지만 이미 선균은 귀신들의 육체의 포로가 된 상태. 급기야, 총각귀신이 임선균의 몸에 빙의하여 유민의 몸을 탐닉하게 되는데..', 'https://image.tmdb.org/t/p/w500/m4AeCsLqF0TGbpjaObYY4dfTppq.jpg', 2021, 0, 0, '2026-06-08 06:30:52.685642', 'KR');
INSERT INTO public.movies VALUES (4728, 27324, '회로', '["Horror", "Thriller", "Mystery"]', 'Kiyoshi Kurosawa', '["Kumiko Aso", "Haruhiko Kato", "Koyuki", "Kurume Arisaka", "Masatoshi Matsuo"]', '대학생활로 바쁜 카와시마 료스케(川島亮介, 가토 하루히코 분)와 평범한 직장여성으로 살아가는 쿠도 미치(工藤ミチ, 아소 구미코 분). 하지만 언젠가부터 그들 주변에서는 이상한 일들이 벌어지기 시작했다. 미치의 동료는 자살하고, 회사의 사장은 실종된다. 애인도 가족도 친구도 차례로 사라져버리는데. 한편 료스케가 시작한 인터넷의 화면에는, 접속도 안했는데 "유령을 만나고 싶습니까"라는 메세지가 뜨면서, 검은 자루를 뒤집어쓴 이상한 남자가 류스케를 덮친다. 뭔가를 느낀 료스케는 같은 대학에서 이 이상한 사이트를 연구하고 있는 카라사와 하루에(唐澤春江, 코유키 분)를 찾아가는데, 이미 학생들도, 연구생들도 모두 사라져버린 후이다. 혼란에 빠진 사회. 인터넷을 매개체로 뭐라고 설명할 수 없는 공포가 사람들을 덮친다. 점점 더 폐허가 되고 있는 거리에서, 마침내 료스케와 미치가 만나고, 그들을 엄습해 오는 공포와 맞서는데.', 'https://image.tmdb.org/t/p/w500/uykt2VRVtMRd6Jqwm7oyRnDIT74.jpg', 2001, 0, 0, '2026-06-08 06:35:39.532833', 'JP');
INSERT INTO public.movies VALUES (4324, 409387, '정사: 결혼 말고 연애', '["Drama"]', 'Jo Kyeong-hoon', '["Yoo So-hyeon", "Joo In-cheol", "Kim Yoo-yeon", "Ahn So-hee"]', '"결혼 따윈 미친 짓이야! 나는 연애만 즐기고 싶어!" 한 남자에게 정착하고 싶지 않은 발칙한 그녀의 연애 일대기! 결혼하라고 잔소리하는 엄마, 성과 좀 내라고 닥달하는 상사, 유부남인 걸 속였던 내 남자까지! 미칠 것 같은 심정을 입안이 얼얼할 정도로 매운 음식으로 다스리던 수경. 외로운 생일 날, 또 다시 매운 요리를 찾아간 레스토랑에서 쉐프와 요리보다 더 맵고 자극적인 정사를 나누고 만다. 마음도, 몸도 잘 맞는다는 것을 확인한 두 사람의 관계는 점점 더 끈끈해지지만 결혼 말고 연애만 좋은 수경은 쉐프의 청혼을 거절한다. 그러자 유부남이 된 쉐프가 돌아와 수경에게 묻는다. "결혼은 네 말대로 딴 여자랑 했어. 그럼 연애는 네가 해줄래?"', 'https://image.tmdb.org/t/p/w500/j3gFifMCgyIF63AI69HzDW6Cj9X.jpg', 2016, 0, 0, '2026-06-08 06:30:16.666184', 'KR');
INSERT INTO public.movies VALUES (4730, 768744, '나의 히어로 아카데미아 더 무비: 월드 히어로즈 미션', '["Animation", "Action", "Adventure", "Sci-Fi"]', 'Kenji Nagasaki', '["Daiki Yamashita", "Nobuhiko Okamoto", "Yuki Kaji", "Ryo Yoshizawa", "Kazuya Nakai"]', '전 세계 개성 보유자 섬멸을 목표로 하는 수수께끼 조직 휴머라이즈. 그들이 각국에 설치한 ''이디오 트리거 밤''으로부터 사람들을 구하기 위해 세계 선발 히어로 팀이 결성된다! 세계 각국의 프로 히어로와 유에이 고교 히어로과 학생들이 소집되어 각 지역에서 폭탄 회수 임무를 맡게 되는데... 엔데버 사무소에서 인턴 중인 미도리야, 바쿠고, 토도로키는 오세온에서 작전 수행 중, 어떠한 사건에 휘말리게 되고 미도리야는 이를 계기로 만난 운반책 소년 로디와 함께 경찰, 빌런의 공격을 받으며 전국에 지명수배된다. 한편, 휴머라이즈의 지도자 플렉트 턴이 범행을 예고하며 세계는 패닉에 빠지고, 히어로 팀은 절체절명의 상황에 위험을 무릅쓰고 폭탄 회수에 나서는데... 제한시간은 단 2시간! 전 세계와 히어로들의 미래가 ''그들'' 손에 달렸다!', 'https://image.tmdb.org/t/p/w500/rqyVJKWCZCWwYK5eDVYyo0jauN6.jpg', 2021, 0, 0, '2026-06-08 06:35:41.741951', 'JP');
INSERT INTO public.movies VALUES (26, 83533, '아바타: 불과 재', '["Sci-Fi", "Adventure", "Fantasy"]', 'James Cameron', '["Sam Worthington", "Zoe Saldaña", "Sigourney Weaver", "Stephen Lang", "Oona Chaplin"]', '인간들과의 전쟁으로 첫째 아들 ‘네테이얌’을 잃은 후, ‘제이크’와 ‘네이티리’는 깊은 슬픔에 빠진다. 상실에 빠진 이들 앞에 ''바랑''이 이끄는 재의 부족이 등장하면서, 판도라는 더욱 큰 위험에 빠지게 되고, ‘설리’ 가족은 선택의 기로에 서게 되는데…', 'https://image.tmdb.org/t/p/w500/l18o0AK18KS118tWeROOKYkF0ng.jpg', 2025, 0, 0, '2026-06-06 13:24:57.13123', 'US');
INSERT INTO public.movies VALUES (4353, 571627, '사자', '["Action", "Horror", "Thriller"]', 'Jason Kim', '["Park Seo-jun", "Ahn Sung-ki", "Woo Do-hwan", "Choi Woo-shik", "Park Ji-hyun"]', '어린 시절 아버지의 갑작스런 죽음으로 신의 존재를 부정하고 자기 자신만 믿기로 한 용후. 세월이 흘러 세계 격투기 챔피언이 된 용후는 어느 날 자신의 손바닥에 생긴 성흔을 발견한다. 고통스런 성흔을 없애기 위해 안 신부를 찾아간 용후는 구마 의식 중인 안 신부를 만나고, 위기에 처한 안신부를 자신의 성흔과 격투기 실력으로 구하게 된다. 용후는 자신의 능력을 부인하면서도, 점차 성흔의 힘을 알게 되고, 안신부와의 유대감도 조금씩 깊어지며, 구마동행을 하게 된다. 사악한 절대 악 ‘지신’은 안 신부와 용후가 구마했던 민주를 결국 죽이고, 앞으로도 더 많은 사람들을 이용하며 사람들을 죽일 계획을 세운다. 안신부와 용후는 지신을 처단하려 하지만, 안신부는 지신의 공격을 받고 죽을 위기에 처하고, 용후는 거부하던 신의 힘을 받아들이고 지신과 맞서는데…', 'https://image.tmdb.org/t/p/w500/mIYX1mfBqX9SsDB6k10AFAiRp2Z.jpg', 2019, 0, 0, '2026-06-08 06:30:37.665247', 'KR');
INSERT INTO public.movies VALUES (4362, 33196, '해운대', '["Action", "Drama", "Thriller"]', 'JK Youn', '["Sul Kyung-gu", "Ha Ji-won", "Park Joong-hoon", "Uhm Jung-hwa", "Lee Min-ki"]', '해운대 토박이 만식은 연희를 좋아하면서도 자신의 마음을 숨길 수 밖에 없다. 그러던 어느 날, 만식은 오랫동안 가슴 속에 담아두었던 자신의 마음을 전하기로 결심하고 연희를 위해 멋진 프로포즈를 준비한다. 한편 국제해양연구소의 지질학자 김휘 박사는 대마도와 해운대를 둘러싼 동해의 상황이 5년전 발생했던 인도네시아 쓰나미와 흡사하다는 엄청난 사실을 발견하게 된다. 그는 안전하지 않다고 수차례 강조하지만 그의 경고에도 불구하고 재난 방재청은 지질학적 통계적으로 쓰나미가 한반도를 덮칠 확률은 없다고 단언한다. 그 순간에도 바다의 상황은 시시각각 변해가고, 일본 대마도가 내려 앉으면서 초대형 쓰나미가 생성된다. 한여름 더위를 식히고 있는 수백만의 휴가철 인파와 평화로운 일상을 보내고 있는 부산 시민들, 그리고 이제 막 서로의 마음을 확인한 만식과 연희를 향해 초대형 쓰나미가 시속 800km의 빠른 속도로 밀려오는데...', 'https://image.tmdb.org/t/p/w500/AgWRG68qAT63wDybxNAebnbstts.jpg', 2009, 0, 0, '2026-06-08 06:30:44.392353', 'KR');
INSERT INTO public.movies VALUES (4365, 518963, '독전', '["Crime", "Action", "Thriller"]', 'Lee Hae-young', '["Cho Jin-woong", "Ryu Jun-yeol", "Kim Joo-hyuk", "Cha Seung-won", "Kim Sung-ryung"]', '아시아 최대 마약 조직 산하에 있는 마약 제조 공장에서 의문의 폭발 사고가 발생한다. 목숨을 잃을 뻔했던 조직의 후견인 연옥은 배신감을 느끼고, 조직의 수장 이 선생을 오랫동안 쫓아왔던 형사 원호를 직접 찾아가 중요한 정보를 흘린다. 유일한 생존자였던 락은 조직으로부터 버림받은 후 원호의 수사에 적극적으로 협조하기로 한다. 두 사람은 이 선생과 거래를 할 예정이었던 진하림과 헌신적인 조직원 선창 사이를 오가며 이 선생의 실체에 조금씩 다가간다. 그리고 원호와 락 앞에 거물급 조직 인사 브라이언이 모습을 드러낸다.', 'https://image.tmdb.org/t/p/w500/uKrVg8dQUiXCR6Wf1yx573ElFT1.jpg', 2018, 0, 0, '2026-06-08 06:30:46.659585', 'KR');
INSERT INTO public.movies VALUES (517, 11649, '마스터 돌프', '["Action", "Fantasy", "Sci-Fi", "Adventure", "Thriller"]', 'Gary Goddard', '["Dolph Lundgren", "Frank Langella", "Billy Barty", "Jon Cypher", "Courteney Cox"]', '무녀의 마법에 의하여 평화를 유지해 온 우주에 악마의 화신인 스켈리터가 나타난다. 권력에 눈이 먼 그는 우연히 마법을 일으키는 우주 열쇠를 차지하게 된다. 그 덕분에 에테르니아의 그레이스컬 성을 함락시키나 그의 라이벌인 히맨을 생포하질 못한다. 또다른 열쇠를 만들까 두려워 스켈리터는 난쟁이 열쇠 제조자, 그윌터를 없애려 하지만 히맨과 근위대장 덩칸과 그의 딸 틸라가 구해준다. 그러자 그윌더는 숨겨놓았던 다른 열쇠를 히맨에게 보여주게 되고 이를 알아차린 스켈리터는 히맨과 그 열쇠를 찾아 심혈을 기울인다. 무녀를 구하려던 히맨과 그의 동료들은 교전끝에 실패하고 급한 나머지 다른 유성으로 피신하게 되는데 그 와중에 열쇠를 떨어뜨린다. 그 유성은 지구임이 드러나고 고등학교 여학생 줄리와 그의 애인 케빈이 그 열쇠를 발견하게 된다. 이상한 불빛과 소리를 발산하는 우주의 열쇠를 케빈은 음향기로 오인하고 지구까지 추적해 온 스켈리터 무리들이 거리에서 총격까지 불사하자 경찰관 루빅은 이들 모두를 체포하려 한다. 이들의 싸움이 지구에서 벌어지고 스켈리터는 마침내 히맨의 지구인 친구들을 위협하여 히맨과 열쇠를 모두 차지하여 아테르니아로 돌아간다. 이에 덩칸, 틸라, 줄리, 케빈, 루빅 등 모든 히맨의 친구들은 아테르니아로 가 히맨을 구하고 지구인들은 무사귀환하는데...', 'https://image.tmdb.org/t/p/w500/gaUecXFd31V68yOTJPJYaB9YhAf.jpg', 1987, 0, 0, '2026-06-06 13:25:15.709296', 'US');
INSERT INTO public.movies VALUES (4385, 62569, '외출', '["Drama", "Romance"]', 'Hur Jin-ho', '["Bae Yong-jun", "Son Ye-jin", "Lim Sang-hyo", "Kim Kwang-il", "Yoo Seung-mok"]', '라이브 콘서트장. 조명 감독 인수는 후배에게 공연을 맡기고, 공연장을 급하게 떠난다. 강원도 삼척의 한 병원 수술실 복도에서 인수는 서영을 만난다. 그가 삼척으로 간 것은 아내, 수진의 자동차 사고 때문이다. 그 차에는 함께 사고를 당한 동승자, 서영의 남편, 경호도 함께 타고 있었다.  중상을 입은 수진과 경호가 좀처럼 의식을 회복하지 못하는 사이, 사고 처리 과정에서 인수와 서영은 수진과 경호가 ‘특별한 관계’ 임을 알게 된다. 인수와 서영에게 이 사실은, 참혹한 사고보다 더 받아들이기 힘들다.', 'https://image.tmdb.org/t/p/w500/l8OcqtnWUF3bbZJZLiX7sJ38PWF.jpg', 2005, 0, 0, '2026-06-08 06:31:02.519392', 'KR');
INSERT INTO public.movies VALUES (4402, 517991, '공작', '["Drama", "History", "Thriller"]', 'Yoon Jong-bin', '["Hwang Jung-min", "Lee Sung-min", "Cho Jin-woong", "Ju Ji-hoon", "Jeong So-ri"]', '1993년, 북한 핵 개발을 둘러싸고 한반도의 위기가 고조된다. 정보사 소령 출신으로 안기부에 스카우트된 박석영은 ‘흑금성’이라는 암호명으로 북핵의 실체를 캐기 위해 북의 고위층 내부로 잠입하라는 지령을 받는다. 안기부 해외실장 최학성과 대통령 외에는 가족조차도 그의 실체를 모르는 가운데 대북사업가로 위장해 베이징 주재 북 고위간부 리명운에게 접근한 흑금성. 그는 수 년에 걸친 공작 끝에, 리명운과 두터운 신의를 쌓고 그를 통해서, 북한 권력층의 신뢰를 얻는데 성공한다. 그러나, 1997년. 남의 대선 직전에 흑금성은 남과 북의 수뇌부 사이 은밀한 거래를 감지한다. 조국을 위해 굳은 신념으로 모든 것을 걸고 공작을 수행했던 그는 걷잡을 수 없는 갈등에 휩싸이는데…', 'https://image.tmdb.org/t/p/w500/uTiYfP9ESTHl1tHw2VJzqdxEtvF.jpg', 2018, 0, 0, '2026-06-08 06:31:15.883862', 'KR');
INSERT INTO public.movies VALUES (4393, 226327, '전망 좋은 집', '["Romance"]', 'Lee Soo-sung', '["Ha Na-kyeong", "Kwak Hyun-hwa", "Oh Seong-tae", "Lee Gun-II", "Son Jin-ho"]', '성(性)격이 다른 두 여자가 만났다!  피플 공인중개소에서 실장으로 근무하는 ‘아라(하나경)’는 순전히 즐기기 위해 남자고객들과 은밀한 만남을 갖는 적극적인 여성이다. 반면 이곳에 새로 입사한 ‘미연(곽현화)’은 자신의 몸매만 대놓고 바라보는 남자들의 시선이 너무나 싫다. 어느 날, 앞집에서 누군가 자신을 은밀하게 바라보고 있음을 알게 된 ‘미연’은 묘한 흥분을 느끼게 되고 그 은밀한 시선 앞에 점점 더 과감한 노출을 하기 시작하게 되는데...', 'https://image.tmdb.org/t/p/w500/k14XVRWmzIutb3GyNimWFWqcgX2.jpg', 2012, 0, 0, '2026-06-08 06:31:09.374007', 'KR');
INSERT INTO public.movies VALUES (4396, 538335, '엄마의 유혹', '["Romance"]', 'Yoo Hae-jong', '["Lee Eun-mi", "Yoo Sul-young", "Lee Kang-woo", "Park Joo-bin"]', '믿음직한 친구의 아들! 내 남자가 되다!INSERT INTO public.movies VALUES (34, 350, '악마는 프라다를 입는다', '["Drama", "Comedy"]', 'David Frankel', '["Meryl Streep", "Anne Hathaway", "Emily Blunt", "Stanley Tucci", "Simon Baker"]', '명문대를 졸업한 소도시 출신의 앤드리아 삭스. 최고의 저널리스트 꿈을 안고 뉴욕에 상경하지만 그녀의 이력서를 보고 연락이 온 곳은 딱 한곳. 세계 최고의 패션지 런웨이 뿐이다. 그것도 기자가 아닌 편집장 미란다의 말단 비서로서. 미란다 프리슬리는 세계 패션쇼의 스케쥴을 바꿀 수 있을 만큼의 거물이지만 까다로운 완벽주의자로 악명이 높다. 직장생활의 꿈에 부푼 앤드리아. 그러나 현실은 지옥 그 자체. 악마 같은 미란다 밑에서 그녀는 과연 살아남을 수 있을까?', 'https://image.tmdb.org/t/p/w500/lxjGbkRnY9d2j8cxIHxX57NNvRH.jpg', 2006, 0, 0, '2026-06-06 13:24:57.154063', 'US');
INSERT INTO public.movies VALUES (56, 157336, '인터스텔라', '["Adventure", "Drama", "Sci-Fi"]', 'Christopher Nolan', '["Matthew McConaughey", "Anne Hathaway", "Michael Caine", "Jessica Chastain", "Casey Affleck"]', '세계 각국의 정부와 경제가 완전히 붕괴된 미래가 다가온다. 지난 20세기에 범한 잘못이 전 세계적인 식량 부족을 불러왔고, NASA도 해체되었다. 나사 소속 우주비행사였던 쿠퍼는 지구에 몰아친 식량난으로 옥수수나 키우며 살고 있다. 거센 황사가 몰아친 어느 날 알 수 없는 힘에 이끌려 딸과 함께 도착한 곳은 인류가 이주할 행성을 찾는 나사의 비밀본부. 이 때 시공간에 불가사의한 틈이 열리고, 이 곳을 탐험해 인류를 구해야 하는 임무를 위해 쿠퍼는 만류하는 딸을 뒤로한 채 우주선에 탑승하는데...', 'https://image.tmdb.org/t/p/w500/evoEi8SBSvIIEveM3V6nCJ6vKj8.jpg', 2014, 0, 0, '2026-06-06 13:24:57.933725', 'US');
INSERT INTO public.movies VALUES (4380, 1160981, '청설', '["Romance", "Drama"]', 'Cho Sun-ho', '["Hong Kyung", "Roh Yoon-seo", "Kim Min-ju", "Jung Yong-ju", "Jeong Hye-young"]', '대학생활은 끝났지만 하고 싶은 것도, 되고 싶은 것도 없어 고민하던 용준. 엄마의 등쌀에 떠밀려 억지로 도시락 배달 알바를 간 용준은 완벽한 이상형 여름과 마주친다. 부끄러움은 뒷전, 첫눈에 반한 여름에게 용준은 서툴지만 솔직하게 다가가고 여름의 동생 가을은 용준의 용기를 응원한다. 손으로 말하는 여름과 더 가까워지기 위해 더 잘 듣기보단 더 잘 보고 느끼려 노력하지만, 마침내 가까워졌다 생각하던 찰나 여름은 왜인지 자꾸 용준과 멀어지려 하는데…', 'https://image.tmdb.org/t/p/w500/tKV0etz5OIsAjSNG1hJktsjbNJk.jpg', 2024, 0, 0, '2026-06-08 06:30:58.782499', 'KR');
INSERT INTO public.movies VALUES (4422, 15067, '좋은 놈, 나쁜 놈, 이상한 놈', '["Action", "Adventure", "Comedy"]', 'Kim Jee-woon', '["Song Kang-ho", "Lee Byung-hun", "Jung Woo-sung", "Yoon Je-moon", "Ryu Seung-su"]', '1930년대, 다양한 인종이 뒤엉키고 총칼이 난무하는 무법천지 만주에서 각자 다른 방식으로 격동기를 살아가는 조선의 풍운아, 세 명의 남자가 운명처럼 맞닥뜨린다. 돈 되는 건 뭐든 사냥하는 현상금 사냥꾼 박도원, 최고가 아니면 참을 수 없는 마적단 두목 박창이, 잡초 같은 생명력의 독고다이 열차털이범 윤태구. 이들은 서로의 정체를 모르는 채 태구가 열차를 털다 발견한 지도를 차지하기 위해 대륙을 누비는 추격전을 펼친다. 정체 불명의 지도 한 장을 둘러 싼 엇갈리는 추측 속에 일본군, 마적단까지 이들의 레이스에 가담하게 되는데...', 'https://image.tmdb.org/t/p/w500/inPPsMpQBKfDORKqemLZn8kQDTp.jpg', 2008, 0, 0, '2026-06-08 06:31:29.990196', 'KR');
INSERT INTO public.movies VALUES (631, 378064, '목소리의 형태', '["Animation", "Drama", "Romance"]', 'Naoko Yamada', '["Miyu Irino", "Saori Hayami", "Aoi Yuuki", "Kensho Ono", "Yuki Kaneko"]', '따분한 게 질색인 아이, 이시다 쇼야.  간디가 어떤 사람인지, 인류의 진화과정이라든지, 알게뭐람.  어느 날 쇼야의 따분함을 앗아갈 전학생이 나타났다. 니시미야 쇼코. 그 아이는 귀가 들리지 않는다고 한다.  쇼야의 짓궂은 장난에도 늘, 생글생글 웃고만 있다. 짜증난다.  그의 괴롭힘에 쇼코는 결국 전학을 갔고, 이시다 쇼야는 외톨이가 되었다.  6년 후, 더 이상 이렇게 살아봐야 의미가 없음을 느낀 쇼야는 마지막으로 쇼코를 찾아간다.  처음으로 전해진 두 사람의 목소리. 두 사람의 만남이 교실을, 학교를,  그리고 쇼야의 인생, 쇼코의 인생을 바꾸기 시작한다.', 'https://image.tmdb.org/t/p/w500/aUF10sSW5OVfpK6Ma3vJYd3Tp3A.jpg', 2016, 0, 0, '2026-06-06 13:25:20.33916', 'JP');
INSERT INTO public.movies VALUES (613, 346, '7인의 사무라이', '["Action", "Drama"]', 'Akira Kurosawa', '["Toshirō Mifune", "Takashi Shimura", "Yoshio Inaba", "Seiji Miyaguchi", "Minoru Chiaki"]', '일본의 전국시대. 주민들은 황폐한 땅에서 어렵게 수확한 식량으로 한해 한해를 넘기는 빈촌에 살고 있다. 이 빈촌엔 보리 수확이 끝날 무렵이면 어김없이 산적들이 찾아와 모든 식량을 모조리 약탈해 간다. 싸워도 애원해도 소용이 없었다. 가만히 있을 수만은 없던 촌장의 결단으로 사무라이들을 모집하는데, 이들은 풍부한 전쟁 경험을 가진 시마다 칸베에를 포함한 7명이었다. 시마다의 지휘하에 마을은 방위태세를 갖추고 전투훈련도 시작한다. 이윽고 산적들의 공격이 시작되어 치열한 사투가 벌어진다.', 'https://image.tmdb.org/t/p/w500/6Y8Q5t79ybiDA7XubUTneqZhjA3.jpg', 1954, 0, 0, '2026-06-06 13:25:19.566196', 'JP');
INSERT INTO public.movies VALUES (127, 4247, '무서운 영화', '["Comedy"]', 'Keenen Ivory Wayans', '["Anna Faris", "Regina Hall", "Marlon Wayans", "Shawn Wayans", "Jon Abrahams"]', '{"나는 네가 지난 할로윈 데이에 소리치는 걸보고 육감적으로 뭔가 특별한 일이 일어날 것이라는 것을 알았다!!"}  팝콘을 튀기던 드류에게 음산한 목소리의 남자에게서 이상한 전화가 걸려온다. "공포영화를 좋아하냐?"는 괴기한 질문을 던지고, 갑자기 등장해 그녀를 해치려 든다. 달아나는 드류는 속옷바람으로 슈퍼모델인양 멋진 포즈로 취하기도 하지만 결국 집으로 오던 그녀의 아버지의 차에 치어 죽고 만다. 드류가 죽었다는 소식을 전해들은 친구 신디는 드류의 죽음에 어떤 의문이 숨어있을까를 고민하다 문득 지난 할로윈 데이에 있었던 일을 떠올리는데..  흥겨운 할로윈 데이 파티를 마치고 집으로 돌아가던 고등학교 친구들 신디, 바비와 버피, 브렌다, 그렉, 레이 등은 차안에서 정신없이 즐기다 타고 있던 차에 한 사내를 치고 만다. 쓰러진 사내는 죽지 않고 일어나지만, 어이없게도 그 사내는 날아온 콜라병을 맞고 그자리에서 즉사하고 만다. 그 끔직한 사건과 드류의 죽음에 뭔가 연관이 있다고 느낀 신디는 친구들과 자신에게도 곧 위협이 닥칠 것이라고 예감하는데...', 'https://image.tmdb.org/t/p/w500/7WgS8qO4KYZxjUQMs0JSFxqcYgn.jpg', 2000, 0, 0, '2026-06-06 13:25:01.022658', 'US');
INSERT INTO public.movies VALUES (77, 1084244, '토이 스토리 5', '["Animation", "Family", "Comedy", "Adventure"]', 'Andrew Stanton', '["Tom Hanks", "Tim Allen", "Joan Cusack", "Greta Lee", "Conan O''Brien"]', '“시대는 변해도, 친구들은 영원하다" 스마트 태블릿 ’릴리패드''의 등장으로 온라인 세계에 모여들게 된 아이들. 친구들과 어울리기 위해 ‘보니’에게도 ‘릴리패드’가 생기게 되고, 장난감들은 점점 일상에서 밀려나게 된다. ''제시''는 이 위기를 해결하기 위해 자신만의 길을 떠났던 ''우디''에게 도움을 요청하게 되는데… 다시 뭉친 ''제시'', ''우디'', ''버즈''는 ''보니''의 마음을 되돌리고 ‘보니’의 진정한 친구를 찾아줄 수 있을까? "장난감 VS 전자기기! 새로운 세상 속, 멈춰있던 장난감들이 다시 움직이기 시작한다!"', 'https://image.tmdb.org/t/p/w500/AqrJx3nVVMlKWXGaPIH32GzjEJA.jpg', 2026, 0, 0, '2026-06-06 13:24:58.723905', 'US');
INSERT INTO public.movies VALUES (4507, 38142, '초속 5센티미터', '["Animation", "Romance", "Drama"]', 'Makoto Shinkai', '["Kenji Mizuhashi", "Yoshimi Kondou", "Satomi Hanamura", "Risa Mizuno", "Ayaka Onoue"]', '도쿄의 초등학교에 다니는 타카키와 아카리는 부모의 전근으로 막 이사왔다. 가정환경도, 적극성이 없다는 것도, 작은 체구에 병약한 부분도 같은 닮은 꼴이이었던 두 사람. 하지만 초등학교 졸업과 동시에 아카리의 이사가 결정된다. 뜻대로 되지 않는 사정을 이해하면서도 어린 아이이기에 쌓아올 수 있던 시간은 어린 아이이기에 무너지게 된다. 시간이 흘러 벚꽃의 계절을 눈앞에 둔 중학교 1학년 3학기, 이번에는 타카키가 카고시마로 전학을 가게 된다. 어린 시절의 후회와 아카리에게 줄 편지를 가슴에 품고 타카키는 그녀가 살고 있는 마을로 향하는데...', 'https://image.tmdb.org/t/p/w500/7qOhFQhvuCZ1hEJHJTWkFo75Vsm.jpg', 2007, 0, 0, '2026-06-08 06:32:34.775848', 'JP');
INSERT INTO public.movies VALUES (4480, 568160, '날씨의 아이', '["Animation", "Drama", "Fantasy", "Romance"]', 'Makoto Shinkai', '["Kotaro Daigo", "Nana Mori", "Tsubasa Honda", "Sakura Kiryu", "Sei Hiraizumi"]', '고등학교 1학년 여름. 외딴 섬에서 가출해, 도쿄에 온 호타카. 그러나 생활은 곧 곤란해졌고, 고독한 나날의 끝에 겨우 찾아낸 일은, 수상한 오컬트 잡지의 작가 일이었다. 그의 앞날을 시사하는 듯, 연일 쏟아지는 비. 그런 가운데, 잡담으로 북적거리는 도시 한 편에서, 호타카는 한 소녀를 만난다. 어떤 사연을 안고, 남동생과 둘이서 밝고 씩씩하게 사는 소녀, 하루나. 그녀에게는, 이상한 능력이 있었다.  "저기, 지금부터 맑아질 거야." 조금씩 비가 그치고, 아름답게 빛나는 거리. 그것은 기도하는 것만으로, 하늘을 맑게 하는 힘이었다.', 'https://image.tmdb.org/t/p/w500/t6r33klGbbZZjbEkHqsfZ9yahRy.jpg', 2019, 0, 0, '2026-06-08 06:32:13.347106', 'JP');
INSERT INTO public.movies VALUES (4483, 9323, '공각기동대', '["Action", "Animation", "Sci-Fi"]', 'Mamoru Oshii', '["Atsuko Tanaka", "Akio Otsuka", "Iemasa Kayumi", "Koichi Yamadera", "Yutaka Nakano"]', '때는 서기 2029년, 아시아의 뉴포트라는 도시. 인간의 뇌도 통신 네트워크의 일부가 된 사회에서 가장 극악한 범죄는 고스트 해킹이다. 인간의 정체성을 규명하는 광의의 영혼을 뜻하는 고스트를 해킹해 타인의 기억 등을 조작하고 변경시키는 것. 인형사라 불리는 정체불명의 악명 높은 고스트 해커가 유럽에서 뉴포트로 주활동 무대를 옮겼다는 소식이 들린다. 이를 막기 위해 외교상 일어나는 국제범죄, 테러 등에 대해 정보수집과 감사를 행하는 정보기관 공안 6과와 쿠사나기 모토코 소령을 중심으로 한 공안 9과는 조사에 나선다', 'https://image.tmdb.org/t/p/w500/piOTBFKd67p3ASodBjq5eOT8c4I.jpg', 1995, 0, 0, '2026-06-08 06:32:15.656535', 'JP');
INSERT INTO public.movies VALUES (4546, 1404404, '극장판 짱구는 못말려: 초화려! 작열하는 떡잎마을 댄서즈', '["Animation", "Adventure", "Comedy"]', 'Masakazu Hashimoto', '["Yumiko Kobayashi", "Miki Narahashi", "Toshiyuki Morikawa", "Satomi Korogi", "Mari Mashiba"]', '떡잎마을 어린이 엔터 페스티벌에서 우승한 떡잎마을 방범대 짱구, 맹구, 철수, 유리, 훈이는 우승 상품으로 인도 엔터 페스티벌 무대에 초청받아, 여행을 만끽한다. 짱구와 맹구는 수상한 잡화점에서 코 모양처럼 생긴 배낭을 발견하고, 맹구는 배낭의 콧구멍에 꽂혀 있는 휴지(?)를 홀린 듯이 자신의 코에 꽂아버린다. 그 순간, 알 수 없는 힘이 맹구에게서 뿜어져 나오는데…! 겉보기에는 평범한 휴지 같은 이 종이의 비밀은 바로, 종이를 코에 꽂는 사람에게 욕망을 불러일으켜 무자비하고 제멋대로인 폭군으로 만들어 버리는 것. “나에 대해 다 아는 척하지 마” 순둥이 맹구, 흑화해서 폭군으로 대변신! 폭주를 시작한다!', 'https://image.tmdb.org/t/p/w500/hh2eWvm91RMIVQb0esjQab8sWgh.jpg', 2025, 0, 0, '2026-06-08 06:33:05.620953', 'JP');
INSERT INTO public.movies VALUES (4537, 1014505, '극장판 오버로드 성왕국편', '["Action", "Adventure", "Animation", "Fantasy"]', 'Naoyuki Ito', '["Satoshi Hino", "Yoshino Aoyama", "Hitomi Nabatame", "Saori Hayami", "Haruka Tomatsu"]', '성왕녀 ''칼카''가 통치하는 로블 성왕국은 길고 거대한 성벽을 쌓고 그 안에서 평화로운 시대를 구가해 왔다. 하지만, 갑자기 나타난 마황 ''얄다바오트''와 ''아인'' 연합군의 침공으로 평화는 너무나도 쉽게 붕괴되고 말았다. 성기사 단장 ''레메디오스'', 신관 단장 ''케랄트''를 시작으로 성왕국은 전력을 모아 맞섰지만 얄다바오트와의 압도적인 힘의 차이에 손쓸 도리 없이 국가는 붕괴 위기에 직면하게 됐다. 레메디오스는 얄다바오트에게 대항할 힘을 얻기 위해 직접 성기사단과 종자 네이아를 이끌고 어떤 나라에 도움을 요청하러 갔다. 그 나라의 이름은 아인즈 울 고운 마도국. 성왕국의 사람들이 꺼림칙하게 여기는 ''언데드''가 통치하는 이형의 국가였는데...', 'https://image.tmdb.org/t/p/w500/15r8PgmVneYGxigbvu2bNEHIuuv.jpg', 2024, 0, 0, '2026-06-08 06:32:58.491654', 'JP');
INSERT INTO public.movies VALUES (4538, 3176, '배틀 로얄', '["Drama", "Thriller", "Action"]', 'Kinji Fukasaku', '["Tatsuya Fujiwara", "Aki Maeda", "Takeshi Kitano", "Taro Yamamoto", "Masanobu Ando"]', '극심한 사회혼란을 겪고 있는 일본. 학급붕괴와 범죄에 노출된 청소년들을 강력한 생존 능력의 소유자로 만들기 신세기교육개혁법(BR법)이 공표된다. BR 법은 전국의 중학교 3학년 중에서 매년 한 학급을 행동범위가 제한된 일반인이 없는 장소에 이송하여 지도와 일정의 음식, 그리고 여러 가지 무기를 나눠 주고, 마지막 한 사람이 남을 때까지 서로 죽이게 한다는 법률. 제한 시간 3일 동안 위법 행위에 구애받지 않고 서로를 죽여야 한다. 수학여행을 위장하여 무인도에 도착한 학생들은 마치 게임처럼 진행되는 상황에 경악하지만, 생존을 위해 결국 서로의 목숨을 빼앗기 시작한다.', 'https://image.tmdb.org/t/p/w500/vBK3XCY8WMAOCXrQewY6VFPbeTF.jpg', 2000, 0, 0, '2026-06-08 06:32:59.167451', 'JP');
INSERT INTO public.movies VALUES (4545, 15137, '에반게리온: 서', '["Animation", "Sci-Fi", "Action", "Drama"]', 'Kazuya Tsurumaki', '["Megumi Ogata", "Megumi Hayashibara", "Kotono Mitsuishi", "Yuriko Yamaguchi", "Akira Ishida"]', '세컨드 임팩트의 충격으로 인류의 절반이 사망한 지구. 어린 시절부터 떨어져서 지낸 아버지 겐도의 갑작스런 호출을 받은 14살 소년 신지는 도쿄 제 3지구로 올라오게 된다. 그 곳에서 자신이 정체불명의 적 사도의 공격에 대항하기 위해 개발한 생체 전투병기 에반게리온 초호기의 파일럿으로 선택되었다는 사실을 듣게 된 신지. 운명을 피해보려 하지만 결국 명령을 거역하지 못하고 탑승하게 된다. 본인의 의지에 상관없이 주변의 기대에 부응하기 위해 파일럿이 된 그는 전투에 에바 0호기의 파일럿이자 제1의 소녀 레이를 만나게 되는데...', 'https://image.tmdb.org/t/p/w500/43K0281D16eM0DOhfaDnE5hnlCD.jpg', 2007, 0, 0, '2026-06-08 06:33:04.949945', 'JP');
INSERT INTO public.movies VALUES (4566, 685274, '기동전사 건담: 섬광의 하사웨이', '["Animation", "Action", "Drama", "Sci-Fi"]', 'Shukou Murase', '["Kensho Ono", "Reina Ueda", "Junichi Suwabe", "Soma Saito", "Atsumi Tanezaki"]', '제2차 네오디온 전쟁(샤아의 반란) 이후 12년. U.C.0105 —— .  지구연방정부의 부패는 지구오염을 가속화시켜 강제로 민간인을 우주로 끌고 가는 비인도적 정책인 「사람 사냥」도 행해지고 있다.  그런 연방정부 고관을 암살하겠다는 가혹한 행위로 저항을 시작한 것이, 반지구연방정부운동 「마프티」. 리더의 이름은 마프티 나비유 에린. 그 정체는 일년전쟁을 싸운 연방군 대좌 브라이트 노아의 아들 「하사웨이」였다.  아무로 레이와 샤아 아즈나블의 이념과 이상, 의지를 담은 전사로서 길을 개척하려는 하사웨이지만 연방군 대좌 케네스 슬렉과 수수께끼의 미소녀 기기 안달루시아와의 만남이 그 운명을 크게 바꿔간다.', 'https://image.tmdb.org/t/p/w500/lSLXim5D2jTS7zJ2Ez1aR9qDDul.jpg', 2021, 0, 0, '2026-06-08 06:33:21.490998', 'JP');
INSERT INTO public.movies VALUES (4580, 1322752, '극장판 프로젝트 세카이 부서진 세카이와 전해지지 않는 미쿠의 노래', '["Animation", "Drama", "Sci-Fi"]', 'Hiroyuki Hata', '["Saki Fujita", "Asami Shimoda", "Yuu Asakawa", "Meiko Haigou", "Naoto Fuuga"]', '「너에 대해서, 알려 줘. 그러면 노래를 알 수 있을지도 몰라」 음반 가게에서 처음 듣는 미쿠의 노래를 듣게 된 호시노 이치카. 그녀는 모니터에서 처음 보는 모습의 "하츠네 미쿠"를 보고 「미쿠?!」라고 소리를 낸다. 그 목소리에 놀란 미쿠는 이치카와 눈이 마주쳤지만 금방 사라지고 말았다.  며칠 뒤, 거리 공연을 마친 이치카의 스마트폰에 저번에 봤던 미쿠의 모습이 나타난다. 쓸쓸한 듯 고개를 떨구고 있는 미쿠에게 이치카가 조심스레 물어보니, 노래를 전하고 싶은 사람들이 있는데 아무리 노래해도 그 노래가 전해지지 않는다고 말한다. 미쿠는 공연으로 많은 사람들의 마음에 노래를 전하는 이치카의 모습을 보고 이치카에 대해서 알면 자신도 이치카처럼 할 수 있을 거라고 생각해서 이치카를 찾아온 것이었다.  미쿠의 부탁에 이치카는 「나라도 괜찮다면」이라고 미소 지으며 대답하고, 하츠네 미쿠와 소년소녀들의 새로운 이야기가 시작된다.', 'https://image.tmdb.org/t/p/w500/ssWJFcux3TIf9LMsUBXccplvRnp.jpg', 2025, 0, 0, '2026-06-08 06:33:33.12433', 'JP');
INSERT INTO public.movies VALUES (4561, 405871, '젊은 아가씨: 고기 노예', '["Drama"]', 'Junichi Suzuki', '["Rei Akasaka", "Aki Hayasaka", "Hideaki Tezuka", "Sadami Sakamoto", "Ranko Mizuki"]', '여름의 쇼난 마을.INSERT INTO public.movies VALUES (4569, 900667, '원피스 필름 레드', '["Animation", "Adventure", "Action", "Fantasy"]', 'Goro Taniguchi', '["Mayumi Tanaka", "Kazuya Nakai", "Shuichi Ikeda", "Kaori Nazuka", "Akemi Okamura"]', '오직 목소리 하나로 전 세계를 사로잡은 디바 ‘우타’.  그녀가 모습을 드러내는 첫 라이브 콘서트가 음악의 섬 ‘엘레지아’에서 열리고  ‘루피’가 이끄는 밀짚모자 해적단과 함께 수많은 ‘우타’ 팬들로 공연장은 가득 찬다.  그리고 이 콘서트를 둘러싼 해적들과 해군들의 수상한 움직임이 시작되는데…  드디어 전세계가 애타게 기다리던 ‘우타’의 등장과 함께 노래가 울려 퍼지고,  그녀가 ‘샹크스의 딸’이라는 충격적인 사실이 드러난다.  ‘루피’, ‘우타’, ‘샹크스’, 세 사람의 과거가 그녀의 노랫소리와 함께 밝혀진다! 여기에서', 'https://image.tmdb.org/t/p/w500/q9Ul66mQDGpAvqUrTZdSMSzym5w.jpg', 2022, 0, 0, '2026-06-08 06:33:23.529906', 'JP');
INSERT INTO public.movies VALUES (4589, 11838, '주온', '["Horror"]', 'Takashi Shimizu', '["Megumi Okina", "Misa Uehara", "Yoji Tanaka", "Misaki Itō", "Kanji Tsuda"]', '자원봉사자 리카는 병든 노파 사치에를 간호하러 집으로 찾아갔다가 그 집에 감도는 불길한 기운을 감지한다. 어수선하고 폐허같은 집, 노파는 아프다기보다는 뭔가에 홀린 듯 보이고 2층 다락에선 의문의 남자아이가 나타났다 사라진다. 곧 이어 노파는 무언가에 홀린 듯 중얼거리다 갑자기 검은 그림자에 휩싸여 죽고 리카는 정신을 잃고 만다.  원한으로 죽어 저주로 살아난 집, 이제 그 집에 한 번이라도 방문한 사람은 모두 끔찍한 죽음을 맞을 수 밖에 없게 되는데...', 'https://image.tmdb.org/t/p/w500/c1CfeRa1PkeKWWMUi8xqMTgqYfx.jpg', 2002, 0, 0, '2026-06-08 06:33:39.3443', 'JP');
INSERT INTO public.movies VALUES (4622, 133121, '레지던트 이블: 댐네이션', '["Action", "Animation", "Sci-Fi", "Horror"]', 'Makoto Kamiya', '["Matthew Mercer", "Courtenay Taylor", "Robin Sachs", "Dave Wittenberg", "Wendee Lee"]', '지옥보다 더한 하루가 시작된다! 미 대통령 직속 비밀 요원 레온 S. 케네디는 내전이 계속되는 동유럽의 소국, 동 슬라브 공화국에서 생물 병기 B.O.W.가 실전 투입되고 있다는 정보를 입수하고, 단독 잠입한다. 그러나 이후 미국 정부는 동 슬라브 공화국으로부터의 철퇴를 결정하고, 레온에게도 급히 귀국하라는 명령이 떨어진다. 그러나 레온은 자신의 임무를 떠나 B.O.W.가 불러올 인류의 비극적인 미래를 생각하며, 상부의 명령을 무시하고 전장에 단독으로 뛰어든다. 지옥같이 처참하고 위험한 전쟁이 시작된다.', 'https://image.tmdb.org/t/p/w500/r5i5R1rMO8jPjyH8Md23rbNg4rU.jpg', 2012, 0, 0, '2026-06-08 06:34:12.061631', 'JP');
INSERT INTO public.movies VALUES (4628, 592350, '나의 히어로 아카데미아 더 무비: 히어로즈 라이징', '["Animation", "Action", "Fantasy", "Adventure"]', 'Kenji Nagasaki', '["Daiki Yamashita", "Nobuhiko Okamoto", "Yoshio Inoue", "Mio Imada", "Yuka Terasaki"]', '눈이 계속 내리는 겨울 어느 밤, 히어로 사회를 파괴하려고 계획하는 시가라키 토무라가 인솔하는 빌런 연합과 그 움직임을 사전에 포착한 히어로들의 전투가 전개되는 가운데, 남모르게 조용히 꿈틀거리는 "뭔가"가 일어나고, 그 자리를 떠났다. 마침 이즈쿠 일행의 유에이 고교 히어로과 1학년 A반이 은퇴한 No.1 히어로 올마이트의 뒤를 이어 "차세대 영웅 육성 프로젝트"의 일환으로 학급 전원에서 기간 한정의 교외 히어로 활동을 위해 일본의 훨씬 남쪽에 위치한 외딴 섬 "나부 섬"을 찾았다. 얼마 전 큰 사건이 일어나지 않았던 평화로운 섬에서 이들은 주재 영웅으로서 섬사람들의 생활을 도우며 분주했고, 그러면서도 한가한 시간을 보내고 있었다. 그러나 그 정적을 부수듯이, 갑자기 빌런들이 나부 섬을 덮쳐, 차례차례로 섬의 시설을 파괴해 간다. 그들을 지휘하는 것은, "나인". 그날 밤, 눈을 뜬 "뭔가"그 자체였다. 이즈쿠와 바쿠고 등의 1학년 A반의 멤버는 힘을 모아 빌런에 맞선다! 과연 섬을 덮치는 나인의 목적이란!? 그리고 이즈쿠 일행의 1학년 A반의 "뉴 히어로"들은 이 가장 흉악한 빌런으로부터 섬의 사람들을 지킬 수 있을까!?', 'https://image.tmdb.org/t/p/w500/x3BYGVio05n4Atdzc5WTmJpV7CY.jpg', 2019, 0, 0, '2026-06-08 06:34:16.100052', 'JP');
INSERT INTO public.movies VALUES (4631, 382190, '포켓몬 더 무비 XY&Z  「볼케니온: 기계왕국의 비밀」', '["Family", "Adventure", "Animation", "Fantasy", "Sci-Fi"]', 'Kunihiko Yuyama', '["Rica Matsumoto", "Ikue Otani", "Mayuki Makiguchi", "Yuki Kaji", "Mariya Ise"]', '포켓몬 사상 최초 [불꽃], [물] 쌍방 타입을 가진 환상의 포켓몬 볼케니온의 등장!  인간을 싫어하는 포켓몬 볼케니온은 우연히 여행하는 지우와 친구들과 만나게 되고  갑자기 나타난 이상한 고리로 지우와 묶여 떨어질 수 없는 사이가 되어버린다!  결국 볼케니온 그리고 지우와 친구들은 함께 모든 것이 기계로 이루어진 기계장치의 왕국인  아조트왕국으로 향하게 된다.  한편, 아조트왕국의 대신 자비스는 500년 전 왕국에서 태어난 환상의 포켓몬 마기아나를 납치하고  마기아나가 가진 ‘소울하트’라는 미지의 힘으로 왕국을 지배하려고 하는데...  지우와 친구들은 볼케니온과 힘을 합쳐 소울하트를 지켜낼 수 있을까?  지금, 포켓몬 역사상 가장 뜨거운 배틀이 시작된다!', 'https://image.tmdb.org/t/p/w500/eCWIz2WaVFyOiSJSKIU9GtjRxGR.jpg', 2016, 0, 0, '2026-06-08 06:34:18.167008', 'JP');
INSERT INTO public.movies VALUES (4660, 634429, '신 울트라맨', '["Action", "Sci-Fi"]', 'Shinji Higuchi', '["Takumi Saitoh", "Masami Nagasawa", "Hidetoshi Nishijima", "Daiki Arioka", "Akari Hayami"]', '일본 전역에서 정체불명의 괴수가 잇따라 출현하자 정부는 이들을 ‘화위수’라 명명하고 대응팀 ‘화특대’를 신설한다. ‘화위수’에 의한 국가적 위기가 임박해진 와중, 돌연 은빛의 거인이 나타나 ‘화위수’를 퇴치한다. 거인의 정체를 알아내기 위해 투입된 분석관 ‘아사미’는 그것에 ‘울트라맨’이라는 이름을 붙인다. 며칠 후, 이번에는 외성인에 의해 다시 위기에 빠진 ‘화특대’. 그 때, 어디선가 ‘울트라맨’이 나타나 ‘화특대’ 기지를 파괴하고 그를 아군이라 생각했던 인간들은 혼란에 빠지는데…', 'https://image.tmdb.org/t/p/w500/kyIFa7jROnKEGY6R6XXWTNOzu5E.jpg', 2022, 0, 0, '2026-06-08 06:34:41.91055', 'JP');
INSERT INTO public.movies VALUES (4664, 575222, '극장판 도라에몽: 진구의 달 탐사기', '["Animation", "Adventure", "Comedy", "Sci-Fi", "Fantasy", "Family"]', 'Shinnosuke Yakuwa', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Tomokazu Seki", "Subaru Kimura"]', '달 탐사기에서 의문의 흰 그림자가 발견됐다는 뉴스 속보로 진구는 그것이 ‘달 토끼’라고 주장하지만 아무도 믿지 않는다. 진구는 도라에몽과 함께 ‘같은 것을 믿게 하는 배지’를 이용해 달의 뒷면에 토끼 왕국을 만들기로 하고 우연히 신기한 힘을 가진 ‘에스펄’이라는 종족의 아이들과 만나게 되는데…!  과연 도라에몽과 친구들은 우주를 위협하는 악당 ‘디아블로’에 맞서 에스펄 친구들을 구할 수 있을까?', 'https://image.tmdb.org/t/p/w500/aN4BWWlhTsfqzjUOQ6V3HwdxLRL.jpg', 2019, 0, 0, '2026-06-08 06:34:44.790336', 'JP');
INSERT INTO public.movies VALUES (4672, 28808, '명탐정 코난: 세기말의 마술사', '["Adventure", "Animation", "Crime", "Drama", "Mystery"]', 'Kenji Kodama', '["Minami Takayama", "Kappei Yamaguchi", "Wakana Yamazaki", "Akira Kamiya", "Chafurin"]', '러시아 로마노프 왕조의 유산인 파베르제의 달걀 중 세기말 최후의 보물 ‘메모리즈 에그’가 발견되고, 이를 노리는 괴도 키드의 예고장이 도착한다. 그를 막기 위해 괴도 키드 특별 수사팀과 코난 일행, 서쪽의 고등학생 탐정 핫토리까지 합류한다. 신출귀몰한 괴도 키드는 모두를 따돌리며 ‘메모리즈 에그’를 훔치는 데 성공하지만, 정체불명의 누군가에게 저격당해 행방불명된다. 무사히 달걀을 되찾은 코난은 ‘메모리즈 에그’에 담긴 수수께끼를 발견한다. 달걀의 비밀을 풀기 위해 크루즈를 타고 도쿄로 향하는 코난 일행, 그러나 배 안에서 의문의 살인 사건이 발생하고 진실은 미궁에 빠지는데…', 'https://image.tmdb.org/t/p/w500/mGBjQkACdChVakczn92CfaqWQJH.jpg', 1999, 0, 0, '2026-06-08 06:34:51.205203', 'JP');
INSERT INTO public.movies VALUES (4675, 14282, '무사 쥬베이', '["Fantasy", "Animation", "Action"]', 'Yoshiaki Kawajiri', '["Koichi Yamadera", "Emi Shinohara", "Takeshi Aono", "Daisuke Gori", "Ryuuzaburou Ootomo"]', '불사의 술법을 익힌 괴력의 닌자, 히무로 겐마는 금광에서 발견된 금을 가로채려고 하고, 그 증거를 잡기 위해 막부는 밀사를 파견한다. 그러나 겐마는 귀문 8인조로 하여금 밀사를 제거하도록 하고, 여검객 카게고만이 살아남는다. 벳사이에게 겁탈을 당하려는 카게고를 위기에서 구해준 무사 쥬베는 곧 정체를 알 수 없는 노인이 던진, 독이 묻은 수리검에 맞는다. 해독약을 구하기 위해 쥬베는 귀문 8인조와 맞서기로 하는데...', 'https://image.tmdb.org/t/p/w500/8kmUvcdIvz0tx7JH3rgoYSE2aIm.jpg', 1993, 0, 0, '2026-06-08 06:34:53.274492', 'JP');
INSERT INTO public.movies VALUES (4693, 11645, '란', '["Action", "Drama", "History"]', 'Akira Kurosawa', '["Tatsuya Nakadai", "Akira Terao", "Jinpachi Nezu", "Daisuke Ryū", "Mieko Harada"]', '16세기 일본 전국시대, 손님들과 함께 멧돼지 사냥을 끝낸 성주 이치몬지 히데토라는 일흔의 나이로 자신의 권력을 아들들에게 넘겨주겠다는 결심을 굳힌다. 그리고 사냥을 함께 한 다른 영주는 자신의 딸을 그의 아들과 혼인시키려 한다. 아들들을 따로 불러 모은 그는 오랫동안 곰곰이 생각해서 내린 결정이라며 장남인 타로가 자신의 뒤를 이어 가문을 이끌 것이라 선언한다. 그리고 둘째, 셋째 아들인 지로와 사부로에게는 두 번째와 세 번째 성과 그에 딸린 영토를 주겠다고 한다. 그는 난세에 외곽에서 호위대를 거느리고 자식들에게 기대어 안락하게 여생을 보낼 생각이였다. 하지만 막내인 사부로는 그 자리에서 아버지가 망령이 들었다고 비난하게 되고 이에 분개한 히데토라는 사부로와 절연한다. 충직한 탄고가 사부로를 감싸지만 그는 들은 체 만 체다. 그 과정을 지켜본 후지마키는 사부로를 자신의 영지로 받아들인다. 한편 처음에는 권력에 별로 욕심이 없었던 장남 타로는 ‘모든 권력과 호칭을 넘겨받지 못하면 그림자에 불과하다’는 아내 카에데의 부추김에 차츰 히데토라의 권력을 완전히 차지하려고 한다. 그리고 그 사이 히데토라가 타로의 부하를 화살로 쏴 죽이는 일까지 발생하면서 갈등이 점점 고조되는데...', 'https://image.tmdb.org/t/p/w500/i6Y66eFjGE2HBS0509rum76xNwd.jpg', 1985, 0, 0, '2026-06-08 06:35:06.877268', 'JP');
INSERT INTO public.movies VALUES (4698, 198375, '언어의 정원', '["Animation", "Drama", "Romance"]', 'Makoto Shinkai', '["Miyu Irino", "Kana Hanazawa", "Fumi Hirano", "Takeshi Maeda", "Yuka Terasaki"]', '구두 디자이너를 꿈꾸는 고등학생 다카오는 비오는 날 오전에는 학교 수업을 빼먹고 도심의 정원으로 구두 스케치를 하러 간다. 어느 날 그는 우연히 유키노라는 여인과 정원에서 만나게 된다. 그녀는 그보다 연상으로 보이지만 세상과 동떨어진 듯한 삶을 살고 있는 여인. 나이 차이가 나는 그들의 예상치 못한 우연한 만남은 비가 오는 날이면 그 정원에서 계속 이어진다. 이름도 나이도 알지 못하지만 걷는 법을 잊어버린 그녀를 위해 다카오는 구두를 만들어 주기로 결심한다. 하지만 장마가 끝나갈 무렵 그들 사이에는 뭔가 말하지 못한 것들이 남아 있는데...  과연 다카오는 그의 감정을 행동이나 말로 옮길 수 있을까?', 'https://image.tmdb.org/t/p/w500/5KhyIJiLMJ7M2IuKhzaj1cce4Rd.jpg', 2013, 0, 0, '2026-06-08 06:35:11.512891', 'JP');
INSERT INTO public.movies VALUES (4707, 782054, '극장판 도라에몽: 진구의 우주소전쟁 리틀스타워즈 2021', '["Animation", "Sci-Fi", "Adventure", "Family", "Fantasy", "Comedy"]', 'Susumu Yamaguchi', '["Wasabi Mizuta", "Megumi Oohara", "Yumi Kakazu", "Subaru Kimura", "Tomokazu Seki"]', '여름방학 어느 날, 진구가 주운 작은 로켓 안에서 손바닥만 한 우주인 ‘파피’가 나타난다!  우주의 머나먼 곳에 있는 작은 별 ‘피리카’의 대통령인 그는  반란군에게서 도망쳐 지구에 왔다고 한다.  처음에는 너무 작은 ‘파피’의 사이즈에 당황하던 도라에몽과 진구는  비밀도구 ‘스몰 라이트’로 작아져서 함께 놀며 친구가 된다.  그러나 고래 형태의 우주전함이 ‘파피’를 붙잡기 위해 지구에 나타나 이들을 공격하고,  모두를 끌어들인 것에 책임감을 느낀 ‘파피’는 홀로 반란군에 맞서고자 하는데…  소중한 친구 ‘파피’와 그의 별을 지키기 위한  도라에몽과 친구들의 우주 모험이 시작된다!', 'https://image.tmdb.org/t/p/w500/1SJZmO5NbBEOLHYeou1OyfgcG9k.jpg', 2022, 0, 0, '2026-06-08 06:35:19.117972', 'JP');
INSERT INTO public.movies VALUES (4711, 227679, '극장판 포켓몬스터 베스트위시: 신의 속도 게노세크트, 뮤츠의 각성', '["Action", "Adventure", "Animation", "Family"]', 'Kunihiko Yuyama', '["Rica Matsumoto", "Ikue Otani", "Aoi Yuuki", "Minami Tsuda", "Mamoru Miyano"]', '대도시 뉴톡시티에서 ''포켓몬힐스''를 구경하던 지우와 친구들 앞에 갑자기 나타난 ''3억 년 전 화석에서 부활한 포켓몬 게노세크트'' 게노세크트를 만난 지우와 친구들은 그들을 도와주려 하지만 리더 ''붉은 게노세크트''의 갑작스런 공격으로 위험에 빠진다..!  그 순간 나타나 지우와 친구들을 위기에서 구한 ''전설의 포켓몬 뮤츠''. ''게노세크트''와 같이 인간에 의해 태어난 뮤츠는 어떻게든 힘이 되어주려 하지만 그 마음은 전해지지 못한 채 결국 두 포켓몬은 서로 격돌하게 되는데!!  가공할만한 위력의 각성한 뮤츠, 사상 최고의 스피드를 자랑하는 게노세크트.  운명적으로 맞붙게 된 이 둘의 대결의 결과는 과연?!', 'https://image.tmdb.org/t/p/w500/khNCYGklrIxhReawmOsL2fHsu7z.jpg', 2013, 0, 0, '2026-06-08 06:35:24.124092', 'JP');
INSERT INTO public.movies VALUES (4719, 572154, '청춘 돼지는 꿈꾸는 소녀의 꿈을 꾸지 않는다', '["Animation", "Romance", "Drama", "Fantasy"]', 'Soichi Masui', '["Kaito Ishikawa", "Asami Seto", "Inori Minase", "Nao Toyama", "Atsumi Tanezaki"]', '하늘과 바다가 반짝이는 마을 "후지사와"에 사는 고등학생 아즈사가와 사쿠타는 같은 학교 선배이자 연인인 사쿠라지마 마이와 설레는 일상을 보내고 있다. 하지만 어느 날 첫사랑인 마키노하라 쇼코가 등장하면서 그 일상은 완전히 뒤바뀌어 버린다. 알 수 없는 이유로 ''중학생''과 ''어른'', 두 명이 존재하는 쇼코와 부득이한 동거를 하면서 사쿠타와 마이의 관계가 삐걱거리기 시작한다. 그러던 중 ''중학생 쇼코''가 위중한 병을 앓고 있다는 것을 알고 사쿠타의 가슴 흉터는 다시 벌어지는데...', 'https://image.tmdb.org/t/p/w500/hqNkm15rQI6049Pg3XPSE8PMW98.jpg', 2019, 0, 0, '2026-06-08 06:35:31.974287', 'JP');
INSERT INTO public.movies VALUES (4731, 39324, '드래곤볼 Z: 절망에 대한 반격! 남겨진 슈퍼 전사', '["Animation", "Action", "Sci-Fi"]', 'Yoshihiro Ueda', '["Masako Nozawa", "Mayumi Tanaka", "Hiromi Tsuru", "Ryo Horikawa", "Takeshi Kusao"]', '미래에서 온 트랭크스와 스승인 손오반의 인조인간과의 혈투를 그리고 있는 작품.INSERT INTO public.movies VALUES (10, 1226863, '슈퍼 마리오 갤럭시', '["Family", "Comedy", "Adventure", "Fantasy", "Animation"]', 'Aaron Horvath', '["Chris Pratt", "Anya Taylor-Joy", "Charlie Day", "Jack Black", "Donald Glover"]', '브루클린의 배관공에서 세계를 구한 히어로로 레벨업한 형제 ‘마리오’와 ‘루이지’는 모래 왕국에서 임무를 수행하던 중, 길을 잃은 ‘요시’를 구출하며 특별한 우정을 쌓게 된다. 한편, 무너진 ‘쿠파’ 가문의 명예를 되찾기 위해 악의 왕자 ‘쿠파주니어’는 은하계의 수호자이자 치코들의 엄마 ‘로젤리나’를 납치하고, 버섯 왕국에 잡힌 아빠 ‘쿠파’를 되찾기 위해 왕국을 습격한다. 다시 찾아온 위기 속에서 마리오와 루이지, 피치, 키노피오 그리고 새로 합류한 요시까지 로젤리나도 구하고, 쿠파주니어의 비범한 계획을 막기 위해 넓은 갤럭시로 뛰어들게 되는데…', 'https://image.tmdb.org/t/p/w500/knaXOBDBecVBWZVup3zXaOoy23v.jpg', 2026, 4, 1, '2026-06-06 13:24:56.351089', 'US');
INSERT INTO public.movies VALUES (7, 687163, '프로젝트 헤일메리', '["Sci-Fi", "Adventure"]', 'Phil Lord', '["Ryan Gosling", "Sandra Hüller", "James Ortiz", "Lionel Boyce", "Milana Vayntrub"]', '눈을 떠보니 아득한 우주의 한가운데에서 깨어난 중학교 과학교사 그레이스는 희미한 기억 속에서 자신이 죽어가는 태양으로부터 지구와 인류를 살릴 마지막 희망으로 이곳에 왔다는 사실을 알게 된다. 잃어버린 기억으로 인해 모든 것이 혼란스러운 상황에서 그레이스는 우연히 우주 한복판에서 같은 목적으로 온 뜻밖의 존재 로키를 만나게 되고 그레이스와 로키는 각 두 행성의 운명을 건 마지막 미션을 수행하러 떠나게 되는데…', 'https://image.tmdb.org/t/p/w500/qqGpVVZk2KD1lAvccgTU4Z6nh1H.jpg', 2026, 0, 0, '2026-06-06 13:24:56.338283', 'US');
INSERT INTO public.movies VALUES (29, 1327819, '호퍼스', '["Adventure", "Animation", "Comedy", "Family", "Sci-Fi"]', 'Daniel Chong', '["Piper Curda", "Bobby Moynihan", "Jon Hamm", "Kathy Najimy", "Dave Franco"]', '오랜 연구 끝에 개발한 ‘호핑’ 기술로 동물 세계에 가까이 갈 수 있음을 알게 된 주인공 ‘메이블’은 마치 ‘아바타’ 같다며 신기해하고, 직접 로봇 비버가 되어 동물들의 세계에 잠입한다. 그들의 말을 알아듣게 된 ‘메이블’은 진짜 동물이 된 것처럼 동물 세상을 경험하는 가운데, 연못에 있던 다른 비버에게 달려드는 곰을 막아서지만 그들에겐 그들만의 질서와 법칙이 있다는 사실을 알게 된다. ‘호핑‘ 기술을 개발한 박사는 이 기술을 자연계 질서를 어지럽히는 데 쓰면 안 된다고 경고하지만, ‘메이블’은 통신을 끊어버려 이후 예측불가의 모험이 펼쳐질 것을 예고한다.', 'https://image.tmdb.org/t/p/w500/vJu9THzQ26Q5sWOVnhOkuRH5M1P.jpg', 2026, 0, 0, '2026-06-06 13:24:57.139015', 'US');
INSERT INTO public.movies VALUES (52, 39254, '리얼 스틸', '["Action", "Sci-Fi", "Drama"]', 'Shawn Levy', '["Hugh Jackman", "Dakota Goyo", "Evangeline Lilly", "Kevin Durand", "Anthony Mackie"]', '치열한 로봇 파이터들의 세계를 그려낸 블록버스터  로봇 파이터의 불가능한 도전이 시작된다!  2020년, 관중들의 뜨거운 열기로 가득 찬 복싱 경기장. 링 위에서 숨 막히는 승부를 펼치는 이들은 무려 900kg에 2m 50cm가 넘는 거대한 로봇 파이터들이다.  인간이 아닌 로봇 파이터들이 사각의 링을 지배하는 시대! 챔피언 타이틀 도전에 실패한 전직 복서 출신 찰리 켄튼(휴 잭맨)은 지하의 복싱 세계를 전전하며 삼류 프로모터로 살아가고 있다. 겨우 번 돈으로 구입한 고철 덩어리를 로봇 파이터로 만들어 지하의 복싱 세계를 벗어나 재기하려는 찰리는 어느 날 존재도 모르고 지낸 아들 맥스(다코다 고요)의 소식을 접하고 임시 보호를 맡게 된다. 어쩔 수 없이 한 팀이 된 그들은 맥스가 우연히 발견한 고철 로봇 ‘아톰’을 최고의 파이터로 키워내기 위한 훈련을 시작한다.  오직 승자와 패자만이 존재하는 무자비한 사각의 링 위, 이제 더 이상 물러날 곳이 없는 찰리와 맥스, 그리고 ‘아톰’의 불가능한 도전이 시작된다!', 'https://image.tmdb.org/t/p/w500/lbN080kn6nzq978jqsdgxci9llR.jpg', 2011, 0, 0, '2026-06-06 13:24:57.921237', 'US');
INSERT INTO public.movies VALUES (170, 862, '토이 스토리', '["Family", "Comedy", "Animation", "Adventure"]', 'John Lasseter', '["Tom Hanks", "Tim Allen", "Don Rickles", "Jim Varney", "Wallace Shawn"]', '카우보이 인형 우디는 꼬마 주인인 앤디의 가장 사랑받는 장난감이다. 그러나 어느날 버즈라는 새로운 장난감이 등장한다.  버즈는 최신형 장난감으로 레이저 빔 등의 첨단장비를 갖추고 있으나, 버즈는 자신이 장난감임을 인식하지 못하고 자신이 우주에서 온 전사이며 자신이 갖춘 장비로 하늘을 날 수 있다고 믿고 있다. 버즈의 허상을 상처받지 않고 인식시켜 주려는 우디와 친구들. 그러나 뜻밖의 사고가 일어난다. 옆집 개에게 버즈가 납치당하고 이런 버즈를 구하기 위해 우디와 친구들은 구조대를 조직해 버즈를 구하러 가는데...', 'https://image.tmdb.org/t/p/w500/iJbm78MxPjLutWUYixbeege8EVe.jpg', 1995, 0, 0, '2026-06-06 13:25:02.568995', 'US');
INSERT INTO public.movies VALUES (98, 19995, '아바타', '["Sci-Fi", "Action", "Adventure"]', 'James Cameron', '["Sam Worthington", "Zoe Saldaña", "Sigourney Weaver", "Stephen Lang", "Michelle Rodriguez"]', '가까운 미래, 지구는 에너지 고갈 문제를 해결하기 위해 머나먼 행성 판도라에서 대체 자원을 채굴하기 시작한다. 하지만 판도라의 독성을 지닌 대기로 인해 자원 획득에 어려움을 겪게 된 인류는 판도라의 토착민 나비의 외형에 인간의 의식을 주입, 원격 조종이 가능한 새로운 생명체를 탄생시키는 프로그램을 개발한다. 한편 하반신이 마비된 전직 해병대원 제이크 설리는 아바타 프로그램에 참가할 것을 제안받는다. 그 곳에서 자신의 아바타를 통해 자유롭게 걸을 수 있게 된 제이크는 자원 채굴을 막으려는 나비의 무리에 침투하라는 임무를 부여받는데...', 'https://image.tmdb.org/t/p/w500/m5lCha2XcbDowDoYHPc0DTNaCPU.jpg', 2009, 0, 0, '2026-06-06 13:24:59.501575', 'US');
INSERT INTO public.movies VALUES (70, 1368881, '레이디스 퍼스트: 거꾸로 가는 남자', '["Comedy", "Fantasy"]', 'Thea Sharrock', '["Sacha Baron Cohen", "Rosamund Pike", "Tom Davis", "Emily Mortimer", "Weruche Opia"]', '오만하지만 카리스마가 매력인 바람둥이 남자. 돈과 권력, 가벼운 연애로 가득한 삶을 누린다. 어느 날 갑자기 여자들이 지배하는 평행 세계에서 눈을 뜨게 되면서 그의 세계가 완전히 뒤집힌다.INSERT INTO public.movies VALUES (246, 1340110, '리덕스 리덕스', '["Sci-Fi", "Thriller", "Horror", "Crime"]', 'Kevin McManus', '["Michaela McManus", "Stella Marcus", "Jeremy Holm", "Jim Cummings", "Taylor Misiak"]', '연쇄살인범 네빌에게 사랑하는 딸 안나를 잃은 아이린. 상실의 고통 속에서 그녀는 시간여행 장치를 손에 넣고, 다중 우주를 넘나들며 네빌을 반복적으로 죽이는 방식으로 복수를 감행한다. 그러나 끝없는 살인은 아이린 안에 점점 더 커다란 공허함을 남기고, 어느 날 살해 위기에 처한 가출 소녀 미아를 구하게 되면서 그녀의 여정은 전환점을 맞는다. 아이린은 안나가 돌아오길 바랐던 것처럼, 미아만큼은 반드시 집으로 돌려보내겠다고 결심한다.', 'https://image.tmdb.org/t/p/w500/9u7sUTYPPTxGCXbkcw8FTq50PnO.jpg', 2025, 0, 0, '2026-06-06 13:25:05.612978', 'US');
INSERT INTO public.movies VALUES (113, 122, '반지의 제왕: 왕의 귀환', '["Adventure", "Fantasy", "Action"]', 'Peter Jackson', '["Elijah Wood", "Ian McKellen", "Viggo Mortensen", "Sean Astin", "Andy Serkis"]', '사우론이 인간들의 마지막 요새인 곤도르를 향해 야욕을 드러내고 있는 한편, 아라곤은 쇠락해가고 있는 곤도르의 재건을 위해 왕위 계승을 신중하게 결정지어야만 하는 상황. 이제 중간대륙의 미래는 그의 어깨에 달려있는 것. 사우론이 이끄는 어둠의 군대와의 마지막 전투를 위해 간달프는 곤도르에 흩어져 있던 병사들을 모으고, 로한의 왕 세오덴에게 도움을 받기도 하지만 사우론의 군대에 비하면 열세를 면치 못한다. 그러나 그들은 중간대륙을 사우론의 야욕으로부터 지키려는 사명감과, 마지막 반지 운반자에게 임무를 끝낼 기회를 주기 위해 어둠의 군대를 향해 돌진하게 되는데...', 'https://image.tmdb.org/t/p/w500/n8BPIRqvj1SdTRND828ANXhmSng.jpg', 2003, 0, 0, '2026-06-06 13:25:00.271336', 'US');
INSERT INTO public.movies VALUES (118, 911430, 'F1 더 무비', '["Action", "Drama"]', 'Joseph Kosinski', '["Brad Pitt", "Damson Idris", "Javier Bardem", "Kerry Condon", "Tobias Menzies"]', '한때 주목받는 유망주였지만 끔찍한 사고로 F1®에서 우승하지 못하고 한순간에 추락한 드라이버 소니 헤이스. 그의 오랜 동료인 루벤 세르반테스에게 레이싱 복귀를 제안받으며 최하위 팀인 APXGP에 합류한다.  그러나 팀 내 떠오르는 천재 드라이버 조슈아 피어스와 소니 헤이스의 갈등은 날이 갈수록 심해지고. 설상가상 우승을 향한 APXGP 팀의 전략 또한 번번이 실패하며 최하위권을 벗어나지 못하고 고전하는데···', 'https://image.tmdb.org/t/p/w500/bvVoP1t2gNvmE9ccSrqR1zcGHGM.jpg', 2025, 0, 0, '2026-06-06 13:25:00.287885', 'US');
INSERT INTO public.movies VALUES (204, 13, '포레스트 검프', '["Comedy", "Drama", "Romance"]', 'Robert Zemeckis', '["Tom Hanks", "Robin Wright", "Gary Sinise", "Sally Field", "Mykelti Williamson"]', '불편한 다리, 남들보다 조금 떨어지는 지능을 가진 포레스트 검프는 헌신적인 어머니의 보살핌과 첫사랑 제니와의 만남으로 편견과 괴롭힘 속에서도 따뜻한 마음을 지니고 성장한다. 또래들의 괴롭힘을 피해 도망치던 포레스트는 누구보다 빠르게 달릴 수 있는 자신의 재능을 깨닫는다. 그의 재능을 알아 본 대학에서 그를 미식축구 선수로 발탁하고, 졸업 후에도 뛰어난 신체능력으로 군에 들어가 무공훈장을 수여받는 등 탄탄한 인생 가도에 오르게 된 포레스트. 하지만 어머니가 병에 걸려 죽음을 맞이하고, 첫사랑 제니 역시 그의 곁을 떠나가며 다시 한 번 인생의 전환점을 맞이하게 되는데...', 'https://image.tmdb.org/t/p/w500/l8wvbQQIBV8LBHmx3Wx9xbE2kzt.jpg', 1994, 0, 0, '2026-06-06 13:25:04.088642', 'US');
INSERT INTO public.movies VALUES (210, 497, '그린 마일', '["Fantasy", "Drama", "Crime"]', 'Frank Darabont', '["Tom Hanks", "David Morse", "Bonnie Hunt", "Michael Clarke Duncan", "James Cromwell"]', '미국 루이지애나의 콜드 마운틴 교도소. 폴은 사형수 감방의 간수장으로 일하고 있다. 그의 일은 사형수들을 감독하고, 그린 마일이라 불리는 초록색 복도를 거쳐 그들을 사형 집행장까지 안내하는 것. 폴은 그들이 죽음을 맞이하는 순간까지 평화롭게 지낼 수 있도록 최선을 다한다. 어느 날 존 커피라는 사형수가 이송되어 온다. 그는 쌍둥이 여자아이를 살해한 흉악범. 하지만 순진한 눈망울에 겁을 잔뜩 집어먹은 그의 모습에 폴은 당혹감을 느낀다. 게다가 그는 초자연적 능력으로 폴의 지병을 깨끗하게 치료해주기까지 한다. 존을 전기 의자로 데려가야 할 날이 다가오면서 폴은 그가 무죄라는 확신을 갖게 되는데...', 'https://image.tmdb.org/t/p/w500/pk1TPODQVnI8GdLf0DhlJQYxWjd.jpg', 1999, 0, 0, '2026-06-06 13:25:04.103566', 'US');
INSERT INTO public.movies VALUES (251, 13192, '문워커', '["Fantasy"]', 'Colin Chilvers', '["Michael Jackson", "Joe Pesci", "Sean Ono Lennon", "Kelley Parker", "Brandon Quintin Adams"]', '마이클 잭슨의 실황 공연 장면과 잭슨이 주인공으로 등장하는 환상적인 이야기들로 구성된 작품이다. 이 영화에는 마이클의 삶과 어린아이들이 ''배드''를 부르는 패러디비디오의 몽타주 장면, 환상 장면에서 팬들에게 쫓기는 마이클의 모습과 함께 ''맨 인 더 미러'', ''스무드 크리미널''과 ''컴 투게더'' 뮤직비디오가 포함되어 있다. 이 영화속의 영화에서 마이클은 미스터 빅이 연기하는 마약 밀매상에게 쫓기는 한편 세 어린이들을 구하는 역을 연기한다. 특히 중간중간 삽입되는 특수 효과와 C.G는 이 영화의 비주얼적인 측면을 한층 돋보이게 한다.', 'https://image.tmdb.org/t/p/w500/3GwTPQkAcgDeAirRpEuJG8HDdRz.jpg', 1988, 0, 0, '2026-06-06 13:25:05.626879', 'US');
INSERT INTO public.movies VALUES (435, 4256, '무서운 영화 3', '["Comedy"]', 'David Zucker', '["Anna Faris", "Regina Hall", "Simon Rex", "Anthony Anderson", "Charlie Sheen"]', '여기저기 기사감을 찾아 떠도는 리포터 신디 켐벨는 오늘도 충격적인 뉴스에 목말라 있다. 그녀는 전세계를 공포에 떨게 할 만한 다양한 사실들을 접하게 되는데, 우주인의 습격, 킬러 비디오테이프, 옥수수 밭의 이상한 원형 싸인, ''더 원''에 대한 예언, 야심찬 백인 랩퍼, 마이클 잭슨과의 논쟁 등이 그것이다. 그녀는 다양한 음모이론 및 그녀 주위를 따르는 이상한 사람들에 맞서, 지구 정복을 꿈꾸는 세력을 저지해야 하는데.', 'https://image.tmdb.org/t/p/w500/lpNG1nx67rvYze1b1R9q0YoSzrC.jpg', 2003, 0, 0, '2026-06-06 13:25:12.556771', 'US');
INSERT INTO public.movies VALUES (261, 652, '트로이', '["Action", "History"]', 'Wolfgang Petersen', '["Brad Pitt", "Orlando Bloom", "Eric Bana", "Brian Cox", "Sean Bean"]', '고대 그리스 시대, 가장 잔인하고 불운한 사랑에 빠지고 만 비련의 두 주인공 트로이의 왕자 파리스와 스파르타의 왕비 헬레네. 사랑에 눈 먼 두 남녀는 트로이로 도주하고, 파리스에게 아내를 빼앗긴 스파르타의 왕 메넬라오스는 미케네의 왕이자 자신의 형인 아가멤논에게 복수를 부탁한다. 아가멤논은 그리스 도시 국가들을 규합해 트로이로부터 헬레네를 되찾기 위한 전쟁을 일으킨다. 그러나 전쟁의 명분은 동생의 복수였지만, 진짜 이유는 모든 도시 국가들을 통합하여 거대한 그리스 제국을 건설하려는 야심이었다.', 'https://image.tmdb.org/t/p/w500/1TsdNMKodmOKyo4xPacxq7opo3p.jpg', 2004, 0, 0, '2026-06-06 13:25:06.379843', 'US');
INSERT INTO public.movies VALUES (229, 414906, '더 배트맨', '["Crime", "Mystery", "Thriller"]', 'Matt Reeves', '["Robert Pattinson", "Zoë Kravitz", "Jeffrey Wright", "Colin Farrell", "Paul Dano"]', '지난 2년 간 고담시의 어둠 속에서 범법자들을 응징하며 배트맨으로 살아온 브루스 웨인. 알프레드와 제임스 고든 경위의 도움 아래 그는 도시의 부패한 공직자들과 고위 관료들 사이에서 복수의 화신으로 활약한다. 고담의 시장 선거를 앞두고 고담의 엘리트 집단을 목표로 잔악한 연쇄살인을 저지르는 수수께끼 킬러 리들러가 나타나자, 최고의 탐정 브루스 웨인이 수사에 나서고 남겨진 단서를 풀어가며 캣우먼, 펭귄, 카마인 팔코네, 리들러를 차례대로 만난다. 사이코 범인의 미스터리를 수사하면서 그 모든 증거가 자신을 향한 의도적인 메시지였음을 깨닫고,  리들러에게 농락 당한 배트맨은 광기에 사로잡힌다. 범인의 무자비한 계획을 막고 오랫동안 고담시를 썩게 만든 권력 부패의 고리를 끊어야 하지만, 부모님의 죽음에 얽힌 진실이 밝혀지자 복수와 정의 사이에서 갈등하는데...', 'https://image.tmdb.org/t/p/w500/jicHGaOX5pHs7RKjfexMxvLkwjf.jpg', 2022, 0, 0, '2026-06-06 13:25:04.859791', 'US');
INSERT INTO public.movies VALUES (255, 10681, '월•E', '["Animation", "Family", "Sci-Fi"]', 'Andrew Stanton', '["Ben Burtt", "Elissa Knight", "Jeff Garlin", "Fred Willard", "John Ratzenberger"]', '텅 빈 지구에 홀로 남아 수백 년이란 시간을 외롭게 일만 하며 보내던 월-E (WALL-E: Waste Allocation Load Lifter Earth-Class, 지구 폐기물 수거-처리용 로봇). 그런 그가 매력적인 탐사 로봇 ‘이브’와 마주친 순간, 잡동사니 수집만이 낙이던 인생에도 소중한 목표가 생긴다. 이브는 지구의 미래를 결정할 열쇠가 우연히 월-E의 손에 들어간 사실을 알게 되고, 고향별로 돌아갈 날만 애타게 기다리는 인간들에게 이를 보고하기 위해 서둘러 우주로 향한다. 한편 월-E는 이브를 뒤쫓아 은하를 가로지르며, 스크린 사상 가장 짜릿한 상상이 넘치는 어드벤처를 선사한다. 이제껏 꿈에서도 볼 수 없었던 미래 세계를 배경으로 우주에서 펼쳐지는 월-E의 환상적인 모험! 애완용 바퀴벌레, 용맹스럽지만 어딘가 나사가 빠진 듯한 사회 부적응 로봇 군단 등 일련의 유쾌한 캐릭터들이 여기에 동참한다.', 'https://image.tmdb.org/t/p/w500/skTzymk67FfQSfGvwp4JSAqje4Z.jpg', 2008, 0, 0, '2026-06-06 13:25:05.638554', 'US');
INSERT INTO public.movies VALUES (285, 863, '토이 스토리 2', '["Animation", "Comedy", "Family"]', 'John Lasseter', '["Tom Hanks", "Tim Allen", "Joan Cusack", "Kelsey Grammer", "Don Rickles"]', '앤디가 카우보이 캠프에 간 동안 앤디의 어머니는 벼룩 시장을 열고 앤디의 장난감 중 위지가 팔려가게 될 운명이 되자 우디가 위지를 구하러 간다. 그러나 우디는 토이 수집가 알에게 유괴당한다. 우디는 원래 제시와 스팅키와 한 세트로 셋이 모이면 일본의 토이 박물관에 갈 수 있다. 알은 우디를 새 것처럼 고쳐주고 제시와 스팅키는 우디와 함께 박물관으로 갈 것을 우디에게 요청한다. 앤디와 친구들을 생각하며 처음엔 거절했으나 우디는 그들과 함께 박물관으로 가기로 한다. 그러나 이 사실을 모르는 버즈와 토이 친구들은 구조대를 결성해 우디를 구하러 가는데...', 'https://image.tmdb.org/t/p/w500/gXUNsdIIn6NiEBvh8Mq6gjgVPm0.jpg', 1999, 0, 0, '2026-06-06 13:25:07.163131', 'US');
INSERT INTO public.movies VALUES (390, 12153, '화이트 칙스', '["Comedy", "Crime"]', 'Keenen Ivory Wayans', '["Shawn Wayans", "Marlon Wayans", "Frankie Faison", "Terry Crews", "Faune Chambers Watkins"]', '위장술 하나는 끝내주지만 정작 사건 해결은 못해본 FBI 명물 콤비 마커스(말론 웨이언스)와 케빈(숀 웨이언스)은 순간의 착각으로 거물급 마약상을 놓치는 일대 실수를 저지르고 만다. FBI에서 퇴출 위기에 몰린 둘은 얼떨결에 자선파티 참석을 위해 LA에 오는 호텔재벌 윌슨가 자매의 모두가 꺼려하는 경호를 떠맡게 된다. 하지만 첫날부터 호틀갑 자매의 귀하신 얼굴에 상처를 내는 대형사고(?)를 치고 마는데…  FBI고 뭐고 발각되면 인생 끝장이다! 힙 올리고 가슴 더 키워!!!  길길이 날뛰는 자매 앞에 이들이 살아남는 방법은 딱 하나! ‘뽕 넣고 찍어 발라서라도’ 그녀들로 변신, 그녀들 대신 사교계를 휘어잡는 것! 이제 풍만한 가슴에 쭉빠진 바디라인의 금발미녀가 된 그들, 아니 그녀들은 알고보면 첩보전을 능가하는 칵테일 파티와 총격전보다 살벌한 패션쇼 등 재벌계의 엄청난 사생활에 말려들기 시작하는데…?!', 'https://image.tmdb.org/t/p/w500/4caC5bNljJiakF2r18Bb3j4URAe.jpg', 2004, 0, 0, '2026-06-06 13:25:11.026115', 'US');
INSERT INTO public.movies VALUES (302, 348, '에이리언', '["Horror", "Sci-Fi"]', 'Ridley Scott', '["Tom Skerritt", "Sigourney Weaver", "Veronica Cartwright", "Harry Dean Stanton", "John Hurt"]', '2122년, 2천만톤의 광물과 7명의 승무원을 태우고 지구로 귀환중인 화물선 노스트로모호의 메인 컴퓨터 마더는 어떤 위성에서 나오는 알 수 없는 신호를 포착하게 된다. 마더에 의해 동면중 깨어난 승무원들은 이 신호를 조사하기 위해 혹성 LA-426에 착륙한다. 이들 중엔 2등 항해사인 엘렌 리플리도 있다. 혹성에서 정체 불명의 우주선을 발견한 그들은 탐사에 나서지만, 우주선은 이미 오래전에 파괴되어 썩고 있었으며 승무원들은 모두 미이라로 변해 있다. 사고 원인을 찾기 위해 좀 더 안으로 들어간 조사반은 여기저기 계란 모양의 물체가 있는 산란실을 발견하는데...', 'https://image.tmdb.org/t/p/w500/k3m1RdlYUlCx51PxxNMlmbm7QSk.jpg', 1979, 0, 0, '2026-06-06 13:25:07.924136', 'US');
INSERT INTO public.movies VALUES (470, 402, '원초적 본능', '["Thriller", "Mystery"]', 'Paul Verhoeven', '["Michael Douglas", "Sharon Stone", "George Dzundza", "Jeanne Tripplehorn", "Denis Arndt"]', '한 남자가 정사 도중 얼음 송곳으로 잔인하게 살해당하는 사건이 발생한다. 형사 닉(마이클 더글러스)은 살인 용의자로 여류추리소설가 캐서린 트러멜(샤론 스톤)을 지목하고, 그녀가 거주하는 바닷가의 별장을 찾는다. 닉은 캐서린이 자신에 관한 자료를 모으고 있다는 사실에 놀라고 그녀의 관능미와 자만심은 그에게 충동적인 욕망을 불러일으킨다. 그러던 중 캐서린의 작품 중에서 이번 살인과 동일한 책을 발견, 캐서린을 연행 심문한다. 취조실에 들어온 캐서린은 변호를 받을 권리를 거부하고 심리전과 증거 불충분으로 혐의를 벗지만, 닉크는 그녀가 범인임을 확신하고 계속 수사를 펼쳐나가는데...', 'https://image.tmdb.org/t/p/w500/h71UDoc8KublzLcJgDRyYRaOmqq.jpg', 1992, 0, 0, '2026-06-06 13:25:14.091359', 'US');
INSERT INTO public.movies VALUES (322, 105, '빽 투 더 퓨쳐', '["Adventure", "Comedy", "Sci-Fi"]', 'Robert Zemeckis', '["Michael J. Fox", "Christopher Lloyd", "Crispin Glover", "Lea Thompson", "Claudia Wells"]', '마티 맥플라이(마이클 J. 폭스)는 평범한 고등학생이다. 그런데 평소 친하게 지내던 괴상한 발명가 에메트 브라운 박사(크리스토퍼 로이드)가 스포츠카 드로리안을 개조해 타임머신을 만들고, 뜻밖의 사고로 브라운 박사가 테러범들에게 총을 맞고 위험해진 상황에서 마티는 30년 전으로 가게 된다. 극장 간판에는 2류 배우인 로널드 레이건이 보이고 청년인 아버지와 어머니를 보게 된다. 젊은 아버진 멍청하고, 어머니는 미래의 아들인 마티를 좋아해 야단이다. 마티가 미래로 가는 것을 도와 줄 사람은 30년 전인 젊은 브라운 박사뿐인데...', 'https://image.tmdb.org/t/p/w500/zzxvtXJ9pahjWVX3Q2ko29J0Zf6.jpg', 1985, 0, 0, '2026-06-06 13:25:08.681624', 'US');
INSERT INTO public.movies VALUES (334, 72105, '19곰 테드', '["Comedy", "Fantasy"]', 'Seth MacFarlane', '["Mark Wahlberg", "Mila Kunis", "Seth MacFarlane", "Joel McHale", "Giovanni Ribisi"]', '전세계를 홀린 진정한 짐승남이 온다!  애 같은 남자와 남자 같은 곰의 발칙한 우정!  어린 시절, 왕따에게도 왕따를 당하던 존(마크 월버그)의 소원을 통해 생명을 얻은 곰인형 테드(세스 맥팔레인)! 말하고 걷는 곰인형 테드는 전세계적인 스타가 된다. 그러나 세월에는 장사가 없는 법. 대중에게 잊혀진 스타 테드는 취미 음주가무, 특기 여자 꼬시기인 백수 한량으로 전락한다. 곰인형 외모에 어울리지 않는 음담패설과 욕설을 일삼는 발칙한 곰 테드와 27년째 그와 죽고 못사는 절친 존! 참다 못한 존의 여자친구 로리(밀라 쿠니스)는 남친의 미래를 위해 극약처방을 선택하는데…  “테드, 내 남친 옆에서 좀 꺼져 줄래?”', 'https://image.tmdb.org/t/p/w500/v6klSXH4e0HL4iCIj9FJYreqUdV.jpg', 2012, 0, 0, '2026-06-06 13:25:08.709348', 'US');
INSERT INTO public.movies VALUES (351, 68721, '아이언맨 3', '["Action", "Adventure", "Sci-Fi"]', 'Shane Black', '["Robert Downey Jr.", "Gwyneth Paltrow", "Don Cheadle", "Guy Pearce", "Rebecca Hall"]', '어벤저스의 일원으로 활약한 뉴욕 사건 이후, 트라우마로 인해 영웅으로서의 삶에 회의를 느끼는 토니 스타크. 그가 혼란을 겪는 사이 최악의 테러리스트 만다린을 내세운 익스트리미스 집단 AIM이 스타크 저택에 공격을 퍼붓는다. 이 공격으로 그에게 남은 건 망가진 수트 한 벌 뿐. 모든 것을 잃어버린 그는 다시 테러의 위험으로부터 세계와 사랑하는 여인을 지켜내야 하는 동시에 머릿속을 떠나지 않던 한가지 물음의 해답도 찾아야만 한다. 과연 그가 아이언맨인가? 수트가 아이언맨인가?', 'https://image.tmdb.org/t/p/w500/5aHoACZhLJR95uQN4Hd2k6swUZq.jpg', 2013, 0, 0, '2026-06-06 13:25:09.468402', 'US');
INSERT INTO public.movies VALUES (2361, 425, '아이스 에이지', '["Animation", "Comedy", "Family", "Adventure"]', 'Chris Wedge', '["Ray Romano", "John Leguizamo", "Denis Leary", "Goran Višnjić", "Jack Black"]', '거대한 빙하가 온 지구의 표면을 뒤덮기 시작하던 때, 모든 동물들은 따뜻한 남쪽나라로 이동을 시작하지만, 염세적인 털북숭이 맘모스 만프레드만은 유별나게 북쪽으로 향한다. 만프레드는 우연히 떠버리 나무늘보 시드를 만나고, 인간의 아이 로샨을 발견한 뒤 가족을 찾아주기로 한다. 이들은 여행길에 검치 호랑이 디에고와 동행하게 되지만, 디에고는 비밀스런 임무를 맡고 있는 처지다. 바로 호랑이 무리의 두목으로부터 끼니를 때울 만한 인간의 아이를 납치해오라는 명령을 받은 것이다. 과연 로샨은 무사히 가족의 품으로 돌아갈 수 있을까?', 'https://image.tmdb.org/t/p/w500/biwqSbuyxjrZMvVcb8Lsv3GyQbw.jpg', 2002, 0, 0, '2026-06-07 12:17:29.475584', 'US');
INSERT INTO public.movies VALUES (458, 453395, '닥터 스트레인지: 대혼돈의 멀티버스', '["Fantasy", "Action", "Adventure"]', 'Sam Raimi', '["Benedict Cumberbatch", "Xochitl Gomez", "Elizabeth Olsen", "Chiwetel Ejiofor", "Benedict Wong"]', '아메리카는 어느 날 멀티버스 사이를 오갈 수 있는 힘에 눈을 뜨지만 완전히 제어하지 못한다. 정체불명의 악마가 아메리카를 죽이려 하자 다른 우주의 스트레인지가 이를 막아보지만 결국 살해당한다. 우여곡절 끝에 우리가 알고 있는 우주로 넘어온 아메리카는 어벤져스 멤버인 닥터 스트레인지의 도움과 보호를 받는다. 닥터 스트레인지는 웨스트뷰 사건 이후 잠적한 완다에게 도움을 청하지만 곧바로 그녀가 사건의 진정한 흑막, 스칼렛 위치임이 드러난다. 스칼렛 위치는 자신의 원하는 멀티버스로 가기 위해 아메리카의 힘을 흡수하려 한다. 닥터 스트레인지와 아메리카는 압도적인 힘을 지닌 스칼렛 위치를 피해 또 한번 다른 멀티버스로 도망치지만 그의 끈질긴 추격을 받는다.', 'https://image.tmdb.org/t/p/w500/vL5ktZauR0fZMDOHKjakb1idhuU.jpg', 2022, 0, 0, '2026-06-06 13:25:13.332158', 'US');
INSERT INTO public.movies VALUES (440, 14160, '업', '["Animation", "Comedy", "Family", "Adventure"]', 'Pete Docter', '["Ed Asner", "Christopher Plummer", "Jordan Nagai", "Bob Peterson", "Delroy Lindo"]', '평생 모험을 꿈꿔 왔던 칼 할아버지는 재개발 공사 현장의 인부를 실수로 다치게 하고 집을 빼앗길 위기에 처한다. 그 동안 미뤄 왔던, 먼저 세상을 떠난 아내와의 약속을 지키기 위해 그는 수천 개의 풍선을 매달아 집을 통째로 남아메리카로 날려 버린다. 하지만 이 위대한 모험에 초대 받지 않은 불청객이 있었으니, 바로 황야의 어린이 탐험가 러셀. 우여곡절 끝에 도착한 남미에서 칼은 어린 시절의 우상이었던 위대한 모험가 찰스 먼츠를 만나게 되는데... 그들은 과연 남미의 잃어버린 세계에서 사라져 버린 꿈과 희망, 행복을 다시 찾을 수 있을까?', 'https://image.tmdb.org/t/p/w500/lL2WzkjLZP0RkPgUhybBjb9x9SL.jpg', 2009, 0, 0, '2026-06-06 13:25:12.569555', 'US');
INSERT INTO public.movies VALUES (3453, 4564, '섹스 앤 더 시티', '["Comedy", "Drama", "Romance"]', 'Michael Patrick King', '["Sarah Jessica Parker", "Kim Cattrall", "Kristin Davis", "Cynthia Nixon", "Chris Noth"]', '여자들은 원하고, 남자들은 궁금해 하는 그녀들의 짜릿한 연애, 솔직한 섹스, 완벽한 스타일의 모든 것! 당신을 황홀하게 할 그녀들이 온다!  뉴욕을 대표하는 잘나가는 그녀들 캐리, 사만다, 샬롯, 미란다! 남부러울 것 없는 완벽한 직업, 가던 사람도 뒤돌아보게 만드는 화려한 스타일로 뉴욕을 사로잡은 그녀들에게도 고민은 있다! 그건 바로 ‘사랑’. 뉴욕을 대표하는 싱글녀이자 유명 칼럼니스트인 ‘캐리’는 오랜 연인인 ‘미스터 빅’과의 완벽한 사랑을 꿈꾸고, 10살 연하의 배우와 불꽃 같은 사랑에 빠진 ‘사만다’는 그를 따라 할리우드로 떠나지만 자유로운 섹스와 뉴욕, 그리고 우정에 목말라한다.  쿨하고 이지적인 변호사 ‘미란다’는 평화롭기만 했던 결혼 생활에 뜻밖의 위기를 맞이하고, 남부러울 것 없는 결혼생활을 하고 있지만 아이를 가질 수 없어 고민하던 ‘샬롯’에게는 반가운 소식이 찾아오는데! 화려한 도시 뉴욕에서 영원한 해피엔딩을 꿈꾸는 그녀들. 하지만 인생에는 항상 반전이 있기 마련! 해피엔딩을 꿈꾸는 그녀들의 섹스보다 솔직하고 연애보다 짜릿한 사랑이 시작된다!', 'https://image.tmdb.org/t/p/w500/fqv2E2mDbiGrqAdHYMUoeOrYhlj.jpg', 2008, 0, 0, '2026-06-08 06:24:18.81339', 'US');
INSERT INTO public.movies VALUES (474, 406997, '원더', '["Family", "Drama"]', 'Stephen Chbosky', '["Jacob Tremblay", "Julia Roberts", "Owen Wilson", "Izabela Vidovic", "Noah Jupe"]', '누구보다 위트 있고 호기심 많은 매력 부자 어기. 하지만 남들과 다른 외모로 태어난 어기는 모두가 좋아하는 크리스마스 대신 얼굴을 감출 수 있는 할로윈을 더 좋아한다. 10살이 된 아들에게 더 큰 세상을 보여주고 싶었던 엄마와 아빠는 어기를 학교에 보낼 준비를 하고, 동생에게 모든 것을 양보해왔지만 누구보다 그를 사랑하는 누나도 첫걸음을 응원해준다. 그렇게 가족이 세상의 전부였던 어기는 처음으로 헬멧을 벗고 낯선 세상에 용감하게 첫발을 내딛는데...', 'https://image.tmdb.org/t/p/w500/1EX3A8mYkQk7czWj7l1tLVlCV2c.jpg', 2017, 0, 0, '2026-06-06 13:25:14.100517', 'US');
INSERT INTO public.movies VALUES (448, 284053, '토르: 라그나로크', '["Action", "Sci-Fi", "Comedy"]', 'Taika Waititi', '["Chris Hemsworth", "Mark Ruffalo", "Tom Hiddleston", "Cate Blanchett", "Idris Elba"]', '은하계를 탐험하던 토르는 오딘의 오랜 숙적 수르트와의 대결에서 승리하는데, 수르트는 라그나로크가 이미 시작됐고, 막을 수 없을 것이라는 의미심장한 말을 남긴다. 한편 오딘의 힘이 약해지며 그가 봉인했던 죽음의 여신 헬라가 나타난다. 오딘의 첫째딸인 그녀는 두 동생, 토르와 로키를 가볍게 제압하고 아스가르드를 정복한다. 헬라와의 전쟁에서 묠니르를 잃고 사카아르라는 미지의 행성에 불시착한 토르는 아스가르드 행성으로 돌아가기 위해 고군분투한다. 행성의 통치자 그랜드 마스터는 행성 최고의 투사 챔피언과 싸워 이기면 행성을 떠나게 해주겠다고 토르에게 제안한다.', 'https://image.tmdb.org/t/p/w500/98pS5T4Xe362fxJBWTuq1m46dOJ.jpg', 2017, 0, 0, '2026-06-06 13:25:13.307655', 'US');
INSERT INTO public.movies VALUES (5955, 872906, '자완', '["Action", "Thriller"]', 'Atlee', '["Shah Rukh Khan", "Nayanthara", "Vijay Sethupathi", "Deepika Padukone", "Sanjay Dutt"]', '수년 전 약속을 지키면서 개인적인 복수심에 사로잡힌 교도관의 감정적 여정은 과거를 청산하기 위해 수감자들을 모집하여 부패와 불의를 밝히는 터무니없는 범죄를 저지르고, 그에게 예상치 못한 재회가 찾아온다', 'https://image.tmdb.org/t/p/w500/jFt1gS4BGHlK8xt76Y81Alp4dbt.jpg', 2023, 0, 0, '2026-06-08 06:52:08.902587', 'IN');
INSERT INTO public.movies VALUES (328, 63964, '하늘이 보내준 딸', '["Drama", "Family"]', 'A. L. Vijay', '["Vikram", "Sara Arjun", "Anushka Shetty", "Nassar", "Amala Paul"]', '초콜릿 공장에서 일하는 ‘크리쉬나’는 지적 장애로 지능이 여섯 살에 머물러 있지만 마음만큼은 한 없이 넓고 따뜻하다. 아이만 남긴 채 아내가 세상을 떠나자 혼자 남은 ‘크리쉬나’는 이웃사람들의 도움을 받아 하늘이 보내준 선물 같은 딸 ‘닐라’를 애지중지 키운다. ‘크리쉬나’의 무한한 애정과 정성으로 ‘닐라’는 하루가 다르게 사랑스럽고 총명한 아이로 자라나고 부녀는 세상에서 가장 행복한 나날을 보낸다.  ‘닐라’가 다섯 살이 되던 해, 갑자기 아내의 가족들이 나타나 ‘크리쉬나’의 장애를 문제 삼아 ‘닐라’를 강제로 데려가고 양육권마저 빼앗으려 한다. 하루 아침에 ‘닐라’를 빼앗긴 ‘크리쉬나’는 딸을 되찾기 위해 신출내기 변호사의 도움을 받아 법정에 서게 되는데…', 'https://image.tmdb.org/t/p/w500/mRtr9nlquhzLXWwryTxtGZWISie.jpg', 2011, 0, 0, '2026-06-06 13:25:08.695715', 'IN');
INSERT INTO public.movies VALUES (5943, 857598, '푸시파 2 절대 권력', '["Action", "Drama", "Thriller", "Crime"]', 'Sukumar', '["Allu Arjun", "Rashmika Mandanna", "Fahadh Faasil", "Jagadeesh Bandari", "Rao Ramesh"]', '그의 밀수 제국이 확장됨에 따라, 대담한 푸슈파는 복수의 여정에서 권력과 존경을 갈망하며, 옛 라이벌들과 새로운 적들을 마주하게 된다.', 'https://image.tmdb.org/t/p/w500/759mIIerY4Njb8uPoj7AIXGSNh3.jpg', 2024, 0, 0, '2026-06-08 06:51:58.905919', 'IN');
INSERT INTO public.movies VALUES (5946, 1186350, '마르코', '["Action", "Crime", "Thriller"]', 'Haneef Adeni', '["Unni Mukundan", "Siddique", "Ishan Shoukath", "Jagadish", "Abhimanyu Thilakan"]', '격투기 경기 관람 후 귀가하던 ‘와심’과 절친 ‘빅터’. 시각 장애인이던 ‘빅터’의 옆에서 ‘와심’은 괴한들에게 무참히 살해당하고 마는데… ‘빅터’는 현장에 있던 범인의 독특한 향수 냄새를 ‘와심’의 장례식장에서 맡게 된다. 이를 알아차린 범이은 빅터를 납치, 불화수소산 통에 던져 사망케한다. 저명한 범죄 조직 중 하나인 ‘아다투 가문’의 보스인 ‘조지 피터’는 동생 ‘빅터’의 죽음에 큰 충격을 받게 되고 이를 알게 된 형제, 사냥개 ''마르코''가 본가로 돌아와 피의 복수를 시작하게 되는데…', 'https://image.tmdb.org/t/p/w500/bbDEsfI9HkK9cHIwXgaLUKsHNU3.jpg', 2024, 0, 0, '2026-06-08 06:52:02.042122', 'IN');
INSERT INTO public.movies VALUES (5947, 1542352, 'யூத்', '["Comedy", "Romance", "Drama"]', 'Ken Karunaas', '["Ken Karunaas", "Anishma Anilkumar", "Suraj Venjaramoodu", "Devadarshini", "Meenakshi Dinesh"]', NULL, 'https://image.tmdb.org/t/p/w500/rNzk0jlGRPnvZ26On5xhTmLaQhO.jpg', 2026, 0, 0, '2026-06-08 06:52:02.781834', 'IN');
