INSERT INTO public.movies VALUES (5949, 1416391, '토스터', '["Comedy", "Crime", "Action"]', 'Vivek Daschaudary', '["Rajkummar Rao", "Sanya Malhotra", "Archana Puran Singh", "Upendra Limaye", "Abhishek Banerjee"]', '결혼하는 커플에게 토스터를 선물한 구두쇠 남자. 결혼식이 취소되자 선물을 되찾으려 애쓰고, 그 과정에서 예기치 않게 살인을 저지르고 만다.', 'https://image.tmdb.org/t/p/w500/hmk01zHdqYggxhutHlaE6tnbpo3.jpg', 2026, 0, 0, '2026-06-08 06:52:04.289883', 'IN');
INSERT INTO public.movies VALUES (5950, 947036, 'സുഖമാണോ? സുഖമാണ്!', '["Drama", "Fantasy", "Comedy"]', 'Arunlal Ramachandran', '["Mathew Thomas", "Devika Sanjay", "Jagadish", "Manikuttan", "Spadikam George"]', NULL, 'https://image.tmdb.org/t/p/w500/7kPUvSFAz95BDs2Wdsz4JLafaIN.jpg', 2026, 0, 0, '2026-06-08 06:52:05.029231', 'IN');
INSERT INTO public.movies VALUES (5951, 1141320, 'ద ఫ్యామిలీ స్తార్', '["Family", "Romance", "Comedy", "Drama", "Action"]', 'Parasuram Petla', '["Vijay Deverakonda", "Mrunal Thakur", "Rohini Hattangadi", "Vasuki Anand", "Abhinaya"]', NULL, 'https://image.tmdb.org/t/p/w500/2mLyHeWwU0Ocv9Jvk72IDqZqT7G.jpg', 2024, 0, 0, '2026-06-08 06:52:05.818798', 'IN');
