INSERT INTO public.movies VALUES (5962, 1211237, 'ਰੱਬ ਦਾ ਰੇਡੀਓ 3', '["Drama", "Romance"]', 'Harry Bhatti', '["Tarsem Jassar", "Nimrat Khaira", "Ronak Joshi", "Nirmal Rishi", "Satwant Kaur"]', NULL, 'https://image.tmdb.org/t/p/w500/uXgnaogJMjzNs2pnZkcGM1EulOa.jpg', 2026, 0, 0, '2026-06-08 06:52:14.198138', 'IN');
INSERT INTO public.movies VALUES (5963, 801688, '칼키 AD 2898년', '["Drama", "Action", "Fantasy", "Sci-Fi"]', 'Nag Ashwin', '["Amitabh Bachchan", "Prabhas", "Deepika Padukone", "Kamal Haasan", "Saswata Chatterjee"]', '인류가 시작되기 이전, 태고의 어느 시기, 전쟁에서 패배한 아쉬와타마는 다음 인류에서 구원을 얻게 되기 전까지 죽지 못하는 저주를 받는다. 그로부터 6,000년이 지나 전쟁과 살육으로 점철된 현생 인류가 도달하게 된 디스토피아. 하나의 정부가 모든 군대와 자원을 통제하며, 돈이 있는 사람들만이 콤플렉스라 불리는 대규모 단지에서 상대적으로 평안한 삶을 영위할 수 있다. 콤플렉스에서는 프로젝트 K라는, 가임기 여성들을 대상으로 하는 비밀 실험이 진행되고 있다.', 'https://image.tmdb.org/t/p/w500/rstcAnBeCkxNQjNp3YXrF6IP1tW.jpg', 2024, 0, 0, '2026-06-08 06:52:14.944526', 'IN');
INSERT INTO public.movies VALUES (5964, 1190511, 'सितारे ज़मीन पर', '["Comedy", "Drama"]', 'R. S. Prasanna', '["Aamir Khan", "Genelia D''Souza", "Dolly Ahluwalia", "Brijendra Kala", "Happy Ranajit"]', NULL, 'https://image.tmdb.org/t/p/w500/adYjCJGSNiL7CIaDW3g0Bcg7r2Z.jpg', 2025, 0, 0, '2026-06-08 06:52:16.511292', 'IN');
