INSERT INTO public.movies VALUES (5967, 707974, 'ঘ্যাচাং ফু', '["Fantasy", "Drama"]', 'Joyraj Bhattacharjee', '["Anirban Bhattacharya", "Aritry Das", "Daminee Benny Basu", "Ben Zachariah", "Debarati Sarkar"]', NULL, 'https://image.tmdb.org/t/p/w500/eSw8WCM0RcC81HORSiQWNCoiD7q.jpg', 2017, 0, 0, '2026-06-08 06:52:18.74895', 'IN');
INSERT INTO public.movies VALUES (5968, 7508, '지상의 별처럼', '["Drama"]', 'Aamir Khan', '["Darsheel Safary", "Aamir Khan", "Tisca Chopra", "Vipin Sharma", "Tanay Chheda"]', '하늘의 별보다 더 빛나는  세상의 아이들은 모두 특별한 존재이다!  인도의 작은 마을, 아직은 세상의 모든 것이 신기한 8살 꼬마 아이 이샨이 있다.  물 속의 물고기는 이샨의 눈 속에서 친구가 되고, 숫자들은 눈 앞에서 날아 다닌다.  하지만 이샨의 상상력은 주위 사람들에게는 이상하게만 보인다.  친구들에게는 엉뚱한 소리만 하는 이상한 왕따가 되어가고,  선생님한테는 글 하나 제대로 읽지 못하는 문제아로 보이기 시작한다.  부모는 이샨에게 문제가 있다고만 생각해 엄격한 기숙학교로 이샨을 보내 버린다.  이샨은 자신의 뭘 잘못했는지도 모른채 낯선 환경에 홀로 남겨진다.  8살 나이에는 감당하기 힘든 외로움과 자괴감에  마음을 닫고 힘들어하는 이샨의 앞에  인생의 멘토,  미술 선생님 니쿰브가 나타난다.  학교의 선생들도, 심지어 부모조차 알지 못했던 이샨에게는 난독증이 있었고  니쿰브 선생님은 장애를 가능성으로 바꾸어 이샨의 속에서 별처럼 빛나는 능력을 발견한다.  조금씩 마음을 열어가는 이샨.  그리고 이샨을 넘버원이 아닌 세상에서 가장 특별한 온리원으로 만들고 싶은  니쿰브 선생님의 반짝이는 동행이 시작된다.', 'https://image.tmdb.org/t/p/w500/cBXvxEt9Q29uwKHcPH3KDrLOxil.jpg', 2007, 0, 0, '2026-06-08 06:52:19.48612', 'IN');
INSERT INTO public.movies VALUES (5969, 1163258, '12학년 낙제', '["Drama"]', 'Vidhu Vinod Chopra', '["Vikrant Massey", "Medha Shankr", "Anant Joshi", "Anshumaan Pushkar", "Priyanshu Chatterjee"]', '인도 공무원의 진실된 이야기인 마노즈 쿠마르 샤르마의 실화를 바탕으로 한 <12번째 실패>는 좌절과 도전에도 불구하고 학업의 길을 다시 시작하겠다는 생각을 두려움 없이 받아들이고, 수백만 명의 학생들이 세계에서 가장 어려운 경쟁 시험인 UPSC에 도전하는 그곳에서 자신의 운명을 되찾는 과정을 조명한다.', 'https://image.tmdb.org/t/p/w500/u7BeOSx3bkXkFNlMg8Ik5h5Jpl8.jpg', 2023, 0, 0, '2026-06-08 06:52:20.233367', 'IN');
