INSERT INTO public.movies VALUES (5984, 770906, '살라르: 1부 – 휴전', '["Action", "Crime", "Drama"]', 'Prashanth Neel', '["Prabhas", "Prithviraj Sukumaran", "Shruti Haasan", "Easwari Rao", "Jagapati Babu"]', '치열한 권력 다툼이 벌어지고 있는 왕국. 한때 친구였지만 이제는 적이 된 두 사람의 아슬아슬한 동맹에 그 운명이 달려있다. 권력과 살육, 배신에 관한 대서사극.', 'https://image.tmdb.org/t/p/w500/nlu9WbcetNFRGXXPWITr30ob7W6.jpg', 2023, 0, 0, '2026-06-08 06:52:32.350763', 'IN');
INSERT INTO public.movies VALUES (5985, 1195430, 'देवा', '["Action", "Thriller", "Mystery", "Crime"]', 'Rosshan Andrrews', '["Shahid Kapoor", "Pooja Hegde", "Pavail Gulati", "Pravessh Rana", "Girish Kulkarni"]', '무자비한 경찰인 데브 암브레는 살인 사건 해결을 마친 직후 사고로 기억을 잃고 이제 기억 상실을 DCP 파르한 칸을 제외한 모든 사람에게 비밀로 유지한 채 다시 조사해야 합니다.', 'https://image.tmdb.org/t/p/w500/4wKpglgZYMYpISMdThgdqS1TSQc.jpg', 2025, 0, 0, '2026-06-08 06:52:33.101641', 'IN');
INSERT INTO public.movies VALUES (5986, 297222, '피케이: 별에서 온 얼간이', '["Comedy", "Drama", "Sci-Fi"]', 'Rajkumar Hirani', '["Aamir Khan", "Anushka Sharma", "Saurabh Shukla", "Boman Irani", "Sushant Singh Rajput"]', '집(우주)으로 돌아갈 리모콘을 도둑 맞은 외계인 피케이(아미르 칸).  되찾을 수 있는 방법은 오직 신만이 알고 있다?  각종 종교 의식을 행하며 신을 찾아 헤매는데..  우리를 만든 신! 우리가 만든 신! 당신이 믿는 신은 누굽니까?  9월 3일, 신에 대한 발칙한 도발이 시작된다!', 'https://image.tmdb.org/t/p/w500/dxIKAPmykcoe7mRg87gzEEZqnhu.jpg', 2014, 0, 0, '2026-06-08 06:52:33.840722', 'IN');
INSERT INTO public.movies VALUES (5987, 784651, '파이터', '["Action", "Drama"]', 'Siddharth Anand', '["Hrithik Roshan", "Deepika Padukone", "Anil Kapoor", "Karan Singh Grover", "Sanjeeda Sheikh"]', '무모하지만 뛰어난 전투 비행대의 대장과 최고의 파일럿 대원들. 치명적인 위험, 내면의 고뇌와 맞서며, 목숨을 건 임무에서 하나가 된다.', 'https://image.tmdb.org/t/p/w500/zqFuriKJ6pYDvf72kXNLONnuE8k.jpg', 2024, 0, 0, '2026-06-08 06:52:34.652681', 'IN');
