INSERT INTO public.movies VALUES (5998, 868660, '군투르 카람', '["Action", "Drama"]', 'Trivikram Srinivas', '["Mahesh Babu", "Sreeleela", "Ramya Krishnan", "Prakash Raj", "Jayaram"]', '오래전 어머니의 재혼과 함께 버려진 한 남자. 선거에 출마하는 어머니에게서 아들임을 부인하는 문서에 서명하라는 요구를 받자, 진실의 답을 찾아 나선다.', 'https://image.tmdb.org/t/p/w500/qvBt4YLy274ZmoMAfVlwmHkjVkq.jpg', 2024, 0, 0, '2026-06-08 06:52:42.998667', 'IN');
INSERT INTO public.movies VALUES (6007, 4251, '비르 자라', '["Drama", "Romance"]', 'Yash Chopra', '["Shah Rukh Khan", "Preity Zinta", "Rani Mukerji", "Kirron Kher", "Divya Dutta"]', '파키스탄의 감옥에 수감 중인 비르, 20년 넘게 말을 하지 않은 그에게 어느날 미모의 여변호사가 면회를 온다. 그녀는 한 마디의 말로 굳게 다문 그의 입을 열고, 과거 비행 대대의 대장이던 비르는 파키스탄 여인 자라와의 운명적인 만남과 사랑에 대해 이야기하기 시작한다.', 'https://image.tmdb.org/t/p/w500/j267YqLvKAHeyykTflxzpgVgviQ.jpg', 2004, 0, 0, '2026-06-08 06:52:50.699606', 'IN');
