INSERT INTO public.movies VALUES (6013, 690957, '푸시파 1: 각성', '["Action", "Drama", "Thriller"]', 'Sukumar', '["Allu Arjun", "Rashmika Mandanna", "Jagadeesh Bandari", "Sunil Varma", "Anasuya Bharadwaj"]', '푸쉬파 라지는 붉은 샌달우드 밀수 세계에서 성공한자. 그 과정에서 그는 적 한두 명을 만드는 것을 두려워하지 않는다.', 'https://image.tmdb.org/t/p/w500/ry22efULBJNUS0IQDVCd6qJ2ECo.jpg', 2021, 0, 0, '2026-06-08 06:52:55.184289', 'IN');
