INSERT INTO public.movies VALUES (6015, 563987, 'Pihu', '["Thriller", "Drama"]', 'Vinod Kapri', '["Pihu Myra Vishwakarma", "Prerna Sharma"]', NULL, 'https://image.tmdb.org/t/p/w500/zRsqo4iSRvUK8eFsmT4y16BbmnX.jpg', 2018, 0, 0, '2026-06-08 06:52:56.746361', 'IN');
INSERT INTO public.movies VALUES (6016, 1389149, '피의자', '["Thriller", "Mystery", "Drama"]', 'Anubhuti Kashyap', '["Konkona Sen Sharma", "Pratibha Ranta", "Aditya Nanda", "Mashhoor Amrohi", "Monica Mahendru"]', '런던의 저명한 퀴어 의사가 성추행 혐의로 고발당하자 그녀의 삶은 무너져 내린다. 의혹과 감시의 폭풍 속에 휩싸인 그녀는 결혼 생활이 균열을 보이고 진실은 흐려진다. 그녀의 아내는 세상을 등지고 떠나야 할지, 세상이 등을 돌린 여성을 위해 싸워야 할지 선택해야 한다.', 'https://image.tmdb.org/t/p/w500/ipQcQFvmlF7FEm1aJKl1Ua7AJEj.jpg', 2026, 0, 0, '2026-06-08 06:52:57.489315', 'IN');
