INSERT INTO public.movies VALUES (6023, 362045, '바지라오 마스타니', '["History", "Romance", "Drama"]', 'Sanjay Leela Bhansali', '["Ranveer Singh", "Deepika Padukone", "Priyanka Chopra Jonas", "Tanvi Azmi", "Vaibhav Tatwawadi"]', '전사 바지라오는 자신의 곁을 스쳐가던 마스타니와 사랑을 나누지만, 그에게는 사실 결혼서약을 맺은 아내가 있다. 마스타니 역시 이 사실을 곧 깨닫지만 그에 대한 마음을 차마 놓지 못하는데. 마라타 왕국의 역사를 관통하는 사랑의 대 서사시.', 'https://image.tmdb.org/t/p/w500/qMOYKLt9XtGp4d4vTTHGJ8viR0H.jpg', 2015, 0, 0, '2026-06-08 06:53:02.762876', 'IN');
