INSERT INTO public.movies VALUES (6028, 1257960, '시칸다르', '["Action", "Drama"]', 'A. R. Murugadoss', '["Salman Khan", "Rashmika Mandanna", "Sathyaraj", "Sharman Joshi", "Prateik Smita Patil"]', '명망 높은 지주 시칸다르. 돌이킬 수 없는 비극적인 사고를 겪은 뒤, 부정부패와 탐욕에 맞서 싸우기 시작한다. 힘없고 소외된 이들을 지키기 위해, 때론 단호한 방법도 마다하지 않는다.', 'https://image.tmdb.org/t/p/w500/41s42CRXafa3OuRGvCtfYPEBmse.jpg', 2025, 0, 0, '2026-06-08 06:53:07.35813', 'IN');
