INSERT INTO public.movies VALUES (6031, 679018, 'जर्सी', '["Drama"]', 'Gowtam Tinnanuri', '["Shahid Kapoor", "Mrunal Thakur", "Pankaj Kapur", "Ronit Kamra", "Rituraj Singh"]', NULL, 'https://image.tmdb.org/t/p/w500/oH5AWyhNlx6kEzIhYPYltnLgnoG.jpg', 2022, 0, 0, '2026-06-08 06:53:09.739589', 'IN');
INSERT INTO public.movies VALUES (6032, 1372588, '아칸다 2: 탄다바', '["Action", "Drama"]', 'Boyapati Srinu', '["Nandamuri Balakrishna", "Pragya Jaiswal", "Samyuktha", "Aadhi Pinisetty", "Akshara Nunna Sujana"]', '모든 희망이 사라졌을 때, 아칸다가 나타났다. 그는 가족을 구하고, 백성을 보호하며, 악당들을 처단한 뒤 고립된 삶을 살았다. 그러나 수년이 지나 새로운 위협이 등장해 세상을 위험에 빠뜨린다. 그리고 세상이 불타오르자, 아칸다가 돌아온다.', 'https://image.tmdb.org/t/p/w500/jo9efbQSGDZNQ6xMocyD1prFjdF.jpg', 2025, 0, 0, '2026-06-08 06:53:10.483996', 'IN');
INSERT INTO public.movies VALUES (6033, 1531858, 'The Taj Story', '["Drama"]', 'Tushar Amrish Goel', '["Paresh Rawal", "Zakir Hussain", "Namit Das", "Amruta Khanvilkar", "Akhilendra Mishra"]', NULL, 'https://image.tmdb.org/t/p/w500/6oMIAvdPWFbwowAq7Zn8unbREAY.jpg', 2025, 0, 0, '2026-06-08 06:53:11.228775', 'IN');
INSERT INTO public.movies VALUES (6034, 585268, '워', '["Action", "Thriller", "Adventure"]', 'Siddharth Anand', '["Hrithik Roshan", "Tiger Shroff", "Vaani Kapoor", "Ashutosh Rana", "Anupriya Goenka"]', '여기 두명의 남자가 서로에게 총을 겨눈다. 카비르(리틱 로샨)와 카리드(타이거 슈로프). 끈끈한 우정을 쌓아온 이들은 정보국 요원으로, 한때 둘도 없는 동료였다. 하지만 둘의 운명은 묘하게 엇갈리며 희비가 교차한다. 카비르는 과거 변절자였던 카리드의 아버지를 살해한 장본인이고, 가문의 오명을 씻고자 요원이 된 카리드는 이제 반대의 입장이 되어 정부 고위 관료를 살해하려는 카비르를 저지하라는 명령을 받는다.', 'https://image.tmdb.org/t/p/w500/7JeHrXR1FU57Y6b90YDpFJMhmVO.jpg', 2019, 0, 0, '2026-06-08 06:53:11.985931', 'IN');
INSERT INTO public.movies VALUES (6035, 257088, '포인트 브레이크', '["Action", "Adventure", "Crime", "Thriller"]', 'Ericson Core', '["Edgar Ramírez", "Luke Bracey", "Teresa Palmer", "Ray Winstone", "Max Thieriot"]', '인도 초고층 빌딩 천만 캐럿 다이아몬드 도난 사건. 멕시코 상공 미국 현찰수송기 납치 사건. 기상천외한 방법으로 세계금융시장을 파괴하는 특수 범죄조직의 등장으로 FBI는 혼란에 빠진다. 신입 FBI요원 ‘유타’ 는 놈들을 잡기 위해 조직의 리더 ‘보디’ 에게 접근하게 되고, 그들의 위험천만한 세계에 점차 빠져들게 되는데…', 'https://image.tmdb.org/t/p/w500/DDCJP7vZT37bCX31zyLpcg1WBn.jpg', 2015, 0, 0, '2026-06-08 06:53:12.743598', 'IN');
INSERT INTO public.movies VALUES (6036, 44977, '더 그레이트 서커스', '["Action", "Crime"]', 'Vijay Krishna Acharya', '["Aamir Khan", "Abhishek Bachchan", "Katrina Kaif", "Uday Chopra", "Jackie Shroff"]', '어린 시절, 서커스단을 운영하는 아버지로부터 많은 재주와 위대한 서커스 정신을 배운 사히르는 비열한 은행가들의 압박 때문에 서커스단 운영에 어려움을 겪게 되는 아빠를 돕기 위해 애쓰지만 아빠는 은행가들을 저주하며 자살로 생을 마감한다.  그 이후, 오랜 시간이 흐른 후 사히르는 위대한 서커스단의 화려한 부활을 위해 노력을 하는 것과 더불어 획기적인 마술을 통해 철통보안 은행들을 털기 시작하는데...  뜨거운 복수심과 눈을 뗄 수 없는 획기적인 마술이 빚어내는 환상적인 마술사기단의 화려한 액션 스릴러!', 'https://image.tmdb.org/t/p/w500/uZ3NG27WGo0tfnvDlQaXRZnNUdG.jpg', 2013, 0, 0, '2026-06-08 06:53:13.490101', 'IN');
