INSERT INTO public.movies VALUES (6048, 538858, '툼바드', '["Fantasy", "Horror"]', 'Rahi Anil Barve', '["Sohum Shah", "Mohammad Samad", "Harsh K.", "Jyoti Malshe", "Dhundiraj Prabhakar Jogalekar"]', '탐욕스런 비나야크는 보물이라면 사족을 못쓴다. 19세기 인도의 시골 마을을 배경으로, 수십년 동안 무모하게 보물 사냥을 벌이는 비나야크는 보물보다 더 큰 비밀을 직면하게 된다.', 'https://image.tmdb.org/t/p/w500/z1xOCxw780WFJC5uCTMfCkQ4Agi.jpg', 2018, 0, 0, '2026-06-08 06:53:23.45515', 'IN');
INSERT INTO public.movies VALUES (6049, 1169516, 'Welcome to the Jungle', '["Comedy"]', 'Ahmed Khan', '["Akshay Kumar", "Suniel Shetty", "Disha Patani", "Jacqueline Fernandez", "Arshad Warsi"]', NULL, 'https://image.tmdb.org/t/p/w500/zibb9EBBCsCeXOUbEw0J6yA0vhZ.jpg', 2026, 0, 0, '2026-06-08 06:53:24.211971', 'IN');
INSERT INTO public.movies VALUES (6050, 634120, '찰리', '["Drama", "Adventure", "Comedy"]', 'Kiranraj K.', '["Rakshit Shetty", "Raj B Shetty", "Bobby Simha", "Sangeetha Sringeri", "Bhargavi Narayan"]', '다르마는 부정적이고 고독한 생활 방식에 갇혀 매일 고독의 안락함 속에서 지낸다. 장난꾸러기이면서 활기 넘치는 강아지 찰리가 그의 삶에 들어오는데, 이는 다르마의 성격과는 완전히 대조적이다. 찰리는 그에게 삶에 대한 새로운 시각을 선사한다.', 'https://image.tmdb.org/t/p/w500/hQh7xrfudzFNpyi3O9LETWIRj15.jpg', 2022, 0, 0, '2026-06-08 06:53:24.965721', 'IN');
INSERT INTO public.movies VALUES (6051, 1407437, 'ఆంధ్ర కింగ్ తాలూకా', '["Action", "Drama", "Romance", "Family"]', 'Mahesh Babu P', '["Ram Pothineni", "Upendra", "Bhagyashri Borse", "Rao Ramesh", "Murali Sharma"]', NULL, 'https://image.tmdb.org/t/p/w500/e1lNI9dZKar0JN9iNuDeUhCZcwL.jpg', 2025, 0, 0, '2026-06-08 06:53:25.70957', 'IN');
INSERT INTO public.movies VALUES (6052, 350312, '바후발리 2: 더 컨클루전', '["Action", "Adventure", "Fantasy"]', 'S. S. Rajamouli', '["Prabhas", "Rana Daggubati", "Anushka Shetty", "Sathyaraj", "Nassar"]', '선왕 바후발리와 데바세나와의 사랑 그리고 그의 죽음과 마히쉬마티 제국의 몰락에 대한 이야기가 스크린으로 펼쳐진다. 그리고 자신의 출생의 비밀을 알게 된 시부두는 과연 발랄라데바의 폭정으로부터 백성을 구할 수 있을 것인가.', 'https://image.tmdb.org/t/p/w500/8oc2LJH104hg6VwnexsO8dULK03.jpg', 2017, 0, 0, '2026-06-08 06:53:26.466036', 'IN');
