INSERT INTO public.movies VALUES (6054, 1118224, '마하라지', '["Action", "Thriller", "Mystery"]', 'Nithilan Saminathan', '["Vijay Sethupathi", "Anurag Kashyap", "Sachana Namidass", "Natarajan Subramaniam", "Abhirami"]', NULL, 'https://image.tmdb.org/t/p/w500/s0m4TM1XRAftQStgKpw024RvkJo.jpg', 2024, 0, 0, '2026-06-08 06:53:28.04968', 'IN');
