INSERT INTO public.movies VALUES (6056, 743563, '비크람', '["Action", "Crime", "Thriller"]', 'Lokesh Kanagaraj', '["Kamal Haasan", "Suriya", "Fahadh Faasil", "Vijay Sethupathi", "Narain"]', NULL, 'https://image.tmdb.org/t/p/w500/xN03FW6jPbRu5Bq9c63w8ILbw4J.jpg', 2022, 0, 0, '2026-06-08 06:53:29.689946', 'IN');
INSERT INTO public.movies VALUES (6057, 592508, '수리아반시', '["Action", "Crime", "Thriller"]', 'Rohit Shetty', '["Akshay Kumar", "Katrina Kaif", "Javed Jaffrey", "Kumud Mishra", "Abhimanyu Singh"]', '약간의 건망증만 빼면 나무랄 데 없이 대담하고 충실한 경찰 수리아반시. 뭄바이를 공격하려는 음모를 저지하기 위해 모든 노력을 기울인다. 온갖 수단을 동원해서라도 반드시 막고 말리라.', 'https://image.tmdb.org/t/p/w500/zgEc1Tn4iKvttPUzkMOUB4BNoXK.jpg', 2021, 0, 0, '2026-06-08 06:53:30.466408', 'IN');
INSERT INTO public.movies VALUES (6058, 352173, '의혹의 맹점', '["Mystery", "Thriller", "Drama"]', 'Nishikant Kamat', '["Ajay Devgn", "Tabu", "Shriya Saran", "Ishita Dutta", "Mrunal Jadhav"]', '평범한 일상을 살아가던 남자. 자신의 딸을 추행한 고위급 경찰 간부의 아들이 실종되면서 졸지에 살인 용의자가 된다.', 'https://image.tmdb.org/t/p/w500/gIClWRv5OSe8rl5Koi0AeUcCZ9Z.jpg', 2015, 0, 0, '2026-06-08 06:53:31.205118', 'IN');
INSERT INTO public.movies VALUES (6073, 454292, '사호', '["Action", "Adventure", "Thriller"]', 'Sujeeth', '["Prabhas", "Shraddha Kapoor", "Neil Nitin Mukesh", "Chunky Panday", "Mandira Bedi"]', '수수께끼의 강도 사건으로 수많은 무고한 시민이 희생양이 되고, 한 위장 경찰이 이 도시로 파견된다. 수사가 진행되면서, 세계 최대의 마피아에 관한 어두운 비밀들이 여러 미스테리와 함께 수면 위로 떠오른다.INSERT INTO public.movies VALUES (6074, 1383072, '전설의 화신 나라심하', '["Animation", "Action", "Fantasy", "Drama"]', 'Ashwin Kumar', '["Harjeet Walia", "Aditya Raj Sharma", "Haripriya Matta", "Sanket Jaiswal", "Priyanka Bhandari"]', '스스로를 무적이라 여기는 악마. 형이 죽자 비슈누 신에게 복수를 다짐하는데, 오직 비슈누만을 따르는 그의 아들이 걸림돌이 된다.', 'https://image.tmdb.org/t/p/w500/uGTF87VyfjtwwqRlT2apQg5YnEp.jpg', 2025, 0, 0, '2026-06-08 06:53:44.100524', 'IN');
INSERT INTO public.movies VALUES (6075, 783, '간디', '["Drama", "History"]', 'Richard Attenborough', '["Ben Kingsley", "Candice Bergen", "Edward Fox", "John Gielgud", "Trevor Howard"]', '영국에 유학해 변호사 자격을 딴 간디(벤 킹슬리)는 1893년 남아프리카에 가 소송사건을 맡는다. 간디는 그 곳에서 유색인종에 대한 차별대우를 받게 된다. 이를 계기로 그는 남아프리카의 인도 거류민을 돕기 위한 다양한 활동을 시작한다. 이후 1915년, 간디는 인도로 돌아와 인도독립을 위한 노력을 하게 된다. 그는 비폭력운동을 주도하면서 수차례 투옥되기도 한다. 인도는 마침내 1947년 8월 영국으로부터 독립을 이룬다. 그러나 힌두교와 이슬람교의 종교적 대립으로 인해 인도와 파키스탄으로 나뉘어 독립을 하게 된다. 이후에도 종교분쟁을 해결하기 위해 노력했던 간디는 1948년 1월 과격파 힌두교도가 쏜 총탄에 암살당한다.', 'https://image.tmdb.org/t/p/w500/jvcUKwxf7bbncPv6V6lchZnlkKT.jpg', 1982, 0, 0, '2026-06-08 06:53:44.858586', 'IN');
INSERT INTO public.movies VALUES (6076, 26022, '내 이름은 칸', '["Drama", "Romance"]', 'Karan Johar', '["Shah Rukh Khan", "Kajol", "Arjan Aujla", "Jimmy Shergill", "Sonya Jehan"]', '자폐증을 가지고 있지만 천재적인 지적 능력과 어머니로부터 얻게 된, 세상을 바라보는 순수한 눈을 가진 칸. 그는 어머니의 죽음 이후 동생이 있는 미국으로 향한다. 칸은 우연히 만난 아름다운 싱글맘 만디라와 운명적인 사랑에 빠져 결혼을 하게 된다. 하지만, 9.11테러 이후 한 순간 행복은 깨지게 된다. 오해가 낳은 끔찍한 사건으로 모든 것을 잃은 만디라는 모든 원망을 칸에게 돌리게 되고 칸은 그녀와의 약속을 지키기 위해 대통령을 만나기 위한 여정을 시작한다. 과연 그는 대통령을 만날 수 있을까? 그리고 그가 전하려는 말은 무엇일까?', 'https://image.tmdb.org/t/p/w500/4ZI5xSdyDfuBSY4GeEJJLYfGDpQ.jpg', 2010, 0, 0, '2026-06-08 06:53:45.629284', 'IN');
INSERT INTO public.movies VALUES (6077, 118051, '칵테일', '["Romance", "Drama", "Comedy"]', 'Homi Adajania', '["Saif Ali Khan", "Deepika Padukone", "Diana Penty", "Randeep Hooda", "Boman Irani"]', NULL, 'https://image.tmdb.org/t/p/w500/v7jnxqLjarV8LXUXKPU6WKE78CK.jpg', 2012, 0, 0, '2026-06-08 06:53:46.374633', 'IN');
INSERT INTO public.movies VALUES (6078, 503838, '레이드', '["Crime", "Drama", "Thriller"]', 'Raj Kumar Gupta', '["Ajay Devgn", "Saurabh Shukla", "Ileana D''Cruz", "Gayathri Iyer", "Sheeba Chaddha"]', '익명의 제보를 받은 세무 공무원이 수년간 소득세를 탈루해온 럭나우의 최고 권력자, 국회의원의 저택을 급습합니다.', 'https://image.tmdb.org/t/p/w500/qx3m9mRUmDZUVQeAe7CAzFX7xCB.jpg', 2018, 0, 0, '2026-06-08 06:53:47.139106', 'IN');
