INSERT INTO public.movies VALUES (6081, 946040, 'தீயவர் குலைகள் நடுங்க', '["Crime", "Thriller"]', 'Dinesh Lakshmanan', '["Arjun Sarja", "Aishwarya Rajesh", "Ramkumar Ganesan", "Abhirami Venkatachalam", "Prankster Rahul"]', NULL, 'https://image.tmdb.org/t/p/w500/aAQ0I4EZUmg7dEyTwxYZi1dYB8Y.jpg', 2025, 0, 0, '2026-06-08 06:53:49.450281', 'IN');
