INSERT INTO public.movies VALUES (6083, 62883, 'हम साथ - साथ हैं', '["Romance", "Family", "Drama"]', 'Sooraj Barjatya', '["Mohnish Behl", "Salman Khan", "Saif Ali Khan", "Tabu", "Sonali Bendre"]', NULL, 'https://image.tmdb.org/t/p/w500/lEAEzpAfSyBZc5sw1NBnWr5TeZU.jpg', 1999, 0, 0, '2026-06-08 06:53:51.012703', 'IN');
INSERT INTO public.movies VALUES (84, 78192, '마이클 잭슨: 더 라이프 오브 언 아이콘', '["Documentary"]', 'Andrew Eastel', '["Michael Jackson", "David Gest", "Tito Jackson", "Rebbie Jackson", "Katherine Jackson"]', '은 최초 공개되는 마이클 잭슨의 생전, 그를 가장 가까이에서 지켜보았던 이들의 인터뷰로 구성된 다큐멘터리로 그가 잭슨 파이브로 활동했을 때부터 세계적인 솔로 스타로 성장하기까지, 그리고 2009년 6월 그의 갑작스러운 사망에 이르기까지의 스토리를 공개한다.  앤드류 이스텔이 감독을 맡고 마이클 잭슨의 어릴 적부터 가까운 친구였던 데이비드 게스트가 제작을 맡은 에서는 마이클 잭슨의 어머니인 캐서린 잭슨이 고인의 죽음 이후 처음 허락한 인터뷰를 수록, 그녀의 입장에서 본 마이클 잭슨의 출생과 성장 이야기, 아버지 조와의 관계에 대한 이야기를 들려주고, 아들이 재판소에서 문제가 있었을 때 그를 지지했던 내용, 그리고 그 후의 인생에 대한 그녀의 생각과 이야기들을 들려준다. 마이클의 큰 누나 레비 잭슨과 형 티토의 인터뷰를 통해 잭슨가의 역사를 상세히 들어보고 그의 어린 시절과 어머니 캐서린과의 친밀한 관계, 2005년에 세상이 놀랐던 아동 성추행사건 재판기간에는 무슨 일이 있었는지 들려준다. 이 밖에도 데비 로우, 리사 마리 프레슬리와의 결혼 생활, 펩시 광고 촬영 중 발생한 화상사고, 성형수술, 진통제에 의존했던 마이클의 상황 등 그간 다루기 힘들었던 그의 루머와 불운했던 삶에 대한 이야기를 가감 없이 공개한다.', 'https://image.tmdb.org/t/p/w500/tOCYV9JCXXFtb7YehKXJBMKI4aD.jpg', 2011, 0, 0, '2026-06-06 13:24:59.463211', 'US');
INSERT INTO public.movies VALUES (262, 807, '세븐', '["Crime", "Mystery", "Thriller"]', 'David Fincher', '["Morgan Freeman", "Brad Pitt", "Gwyneth Paltrow", "John Cassini", "Peter Crombie"]', '은퇴를 7일 앞둔 관록의 형사 윌리엄 소머셋(모건 프리먼)과 새로 전근 온 신참내기 형사 밀스(브래드 피트)가 팀이 된 바로 다음날, 강압에 의해 위가 찢어질 때까지 먹다가 죽은 초고도 비만 남자와 역시 강압에 의해 식칼로 자기 살을 베어내 죽은 악덕 변호사의 사건과 마주한다. 식탐, 탐욕, 그리고 나태, 분노, 교만, 욕정, 시기. 소머셋은 현장에 남은 흔적들로 단테의 신곡과 쵸서의 캔터베리 서사시를 근거로 한 기나긴 연쇄 살인이 시작되었음을 직감하고 성서의 7가지 죄악을 따라 발생하는 사건들을 추적하기 시작하는데...', 'https://image.tmdb.org/t/p/w500/izzk8dbmrLowcoGbFaebqJvzyXg.jpg', 1995, 0, 0, '2026-06-06 13:25:06.382955', 'US');
INSERT INTO public.movies VALUES (281, 354912, '코코', '["Family", "Animation", "Adventure"]', 'Lee Unkrich', '["Anthony Gonzalez", "Gael García Bernal", "Benjamin Bratt", "Alanna Ubach", "Renée Victor"]', '미구엘은 멕시코의 자랑인 에르네스토 델라 크루즈 같은 뮤지션이 되길 꿈꾸지만 미구엘 집안 사람들에게 음악은 금기다. 먼 옛날 조상 중에 음악 때문에 가족을 버린 인물이 있었기 때문. 미구엘은 죽은 자의 날이 되자 실력으로 인정받겠다는 결심을 하고 경연 무대에 오르려 하는데, 우연히 에르네스토의 기타에 손을 댔다가 죽은 자들의 세상에 들어서게 된다. 이승과 저승을 이어주는 마리골드 꽃길을 건너 죽은 자들의 세상에 도착한 미구엘은 거짓말과 위변조가 장기인 헥터를 만난다. 그리고 꿈에 그리던 우상 에르네스토를 만나러 가는 여정에서 가족의 비밀을 알게 된다.', 'https://image.tmdb.org/t/p/w500/pQu93NuwR90AaCULzglVD5Ge4Ml.jpg', 2017, 0, 0, '2026-06-06 13:25:07.149428', 'US');
INSERT INTO public.movies VALUES (248, 680493, '리턴 투 사일런트 힐', '["Mystery", "Drama", "Horror"]', 'Christophe Gans', '["Jeremy Irvine", "Hannah Emily Anderson", "Evie Templeton", "Pearse Egan", "Nicola Alexis"]', '침묵이 지배하는 안개 속 도시, 잃어버린 사랑을 찾기 위한 잔혹한 여정이 다시 시작된다.INSERT INTO public.movies VALUES (949, 86331, 'Q - 섹스힐링', '["Drama", "Romance"]', 'Laurent Bouhnik', '["Déborah Révy", "Hélène Zimmer", "Gowan Didi", "Johnny Amaro", "Johan Libéreau"]', '자유분방하게 살아온 세실(데보라 레비)은 아버지를 떠나 보낸 상실감에 스스로를 학대하듯 처음 보는 남자 매트(고완 디디)를 유혹하며 도발적인 성적 유희에 빠져든다. 마치 활화산 같은 욕망의 분출이 자신의 해방구인 것처럼.  치명적인 유혹을 즐기듯 거침없이 몸을 던지는 세실은 연인 찬스(조니 아마로)와도 온몸을 사르는 불 같은 사랑에 빠져보지만 굶주린 욕망은 좀처럼 채워지지 않는다. 마찬가지로 출구 없는 삶에서 뜨거운 열정을 숨기듯 안고 사는 앨리스(헬렌 짐머)는 자신의 욕망을 대리 분출시키려는 세실로 인해 아슬아슬해서 더욱 위험한 욕망에 사로잡힌다. 결국 세실과 앨리스는 대담하게도 섹스리스 커플을 치료하는 ‘섹스힐링’에 나서고, 급기야는 친구들과 함께 집단 매춘에 뛰어들어 끝간 데를 모를 욕망의 화신들로 변해가는데…', 'https://image.tmdb.org/t/p/w500/flhv2fsi2b3tpjJzTtfz6GTIVTi.jpg', 2011, 0, 0, '2026-06-06 13:25:32.70626', 'FR');
INSERT INTO public.movies VALUES (6109, 39688, '라이크 어 브라더', '["Drama", "Romance"]', 'Cyril Legann', '["Benoit Deliere", "Johnny Amaro", "Thibault Boucaux", "Adeline Ishiomin", "Amandine Maugy"]', '세바스찬은 파리로 이사하여 적응하며 살고 있다. 클럽에서 한 남자를 만나게 되고.. 그에게 과거 자신이 겪은 일들을 들려준다. 그의 절친했던 로만과는 형제와 다름 없는관계로 이성애자 였으나 세바스찬과 묘한 관계성을 느꼈다. 하지만.. 그 이상의 진전은 있을 수 없었던 세바스찬과 로만은 결국 거리를 두게되고, 세바스찬은 파리로 이사를 하게 됐다. 시간이 지난 후 그를 보러온 로만은 전과는 달라진 세바스찬의 모습에 당황스럽기만 한데...', 'https://image.tmdb.org/t/p/w500/jzz9JYlDHnYB5atdjNM140aoH1J.jpg', 2005, 0, 0, '2026-06-08 06:54:13.092554', 'FR');
INSERT INTO public.movies VALUES (6112, 339964, '발레리안: 천 개 행성의 도시', '["Adventure", "Sci-Fi", "Action"]', 'Luc Besson', '["Dane DeHaan", "Cara Delevingne", "Clive Owen", "Rihanna", "Ethan Hawke"]', '수천 종의 외계종족이 평화롭게 살고 있는 28세기의 우주. 에이전트 발레리안과 로렐린에게 30년 전 사라진 행성 뮐의 마지막 남은 컨버터를 되찾아 오라는 미션이 내려진다. 그들은 키리안 행성에서 컨버터가 거래되고 있다는 정보를 입수하지만, 뜻하지 않게 외계종족의 표적이 되어버린다. 가까스로 컨버터를 구출해 낸 그들은 우주수호부의 본거지 알파로 향하고, 제한된 시간 안에 평화를 위협하는  레드존에 진입해 위협 요소를 제거해야 하는 새로운 임무를 받게 된다. 하지만 이 모든 사건이 자신들이 구출한 컨버터와 연계되어 있다는 사실을 알게 되는데...', 'https://image.tmdb.org/t/p/w500/2evxLMkx7oDnwxjoz3zF0Vd1Cea.jpg', 2017, 0, 0, '2026-06-08 06:54:15.362769', 'FR');
INSERT INTO public.movies VALUES (6113, 741110, 'L''Enfant rêvé', '["Drama", "Romance"]', 'Raphaël Jacoulot', '["Jalil Lespert", "Louise Bourgoin", "Mélanie Doutey", "Jean-Marie Winling", "Nathan Willcocks"]', NULL, 'https://image.tmdb.org/t/p/w500/mdLNmqIehGximKCHZre65hCcYxb.jpg', 2020, 0, 0, '2026-06-08 06:54:16.110595', 'FR');
INSERT INTO public.movies VALUES (6115, 3134, '베즈 무아', '["Crime", "Drama", "Thriller"]', 'Coralie Trinh Thi', '["Karen Lancaume", "Raffaëla Anderson", "Ouassini Embarek", "Adama Niane", "Marc Barrow"]', '비르지니 데팡트(Virginie Despentes) 감독 본인의 동명의 베스트셀러 소설을 직접 영화화한 작품으로 두 여성의 섹스, 마약 그리고 살인행각에 관한 이야기를 하고있다. 두 주연 배우는 실제 포르노 배우 출신이며, 프랑스에서 X 등급을 받는 등 논란이 되었다. 르몽드지는 "섹스와 죽음의 절망을 적절히 배합했다"라는 평과 함께 실제 포르로 배우 출신인 두 주인공 라파엘라 안드르송과 카렌 바하의 "믿을 수 없을 정도로 자연스러움"을 호평했다.  감독 카트린 브레이아와의 대담에서 감독 비리지니 데스팽은 "그림으로 표현하면 인정되는 장면을 영화로는 표현할 수 없다는 것은 억지이다"라고 분노를 감추지 않았다.', 'https://image.tmdb.org/t/p/w500/r07olKMs2bMksjDIhq6LLbKkE8Y.jpg', 2000, 0, 0, '2026-06-08 06:54:17.592724', 'FR');
INSERT INTO public.movies VALUES (6118, 1084736, '몬테크리스토 백작', '["Adventure", "Action", "Drama"]', 'Alexandre de La Patellière', '["Pierre Niney", "Bastien Bouillon", "Anaïs Demoustier", "Laurent Lafitte", "Pierfrancesco Favino"]', '에드먼드 단테스는  음모에 빠져 결혼식 날 자신이 저지르지도 않은 범죄로 체포된다. 샤토 디프에서 14년 동안의 수감 생활을 끝으로 탈옥에 성공하고  꿈에 그리던 부자가 된다. 단테스는 몬테크리스토 백작으로 신분을 위장하고 세 남자에게 복수를 실행에 옮긴다.', 'https://image.tmdb.org/t/p/w500/yBfLhsN2xk0Xy85fNNEDxwjcsiu.jpg', 2024, 0, 0, '2026-06-08 06:54:20.124884', 'FR');
INSERT INTO public.movies VALUES (6119, 1147411, '미라큘러스 월드 : 도쿄, 스텔라 포스', '["Animation", "Family", "Action", "Adventure", "Fantasy"]', 'Thomas Astruc', '["Anouck Hautbois", "Clara Soares", "Claire Baradat", "Grégory Laisné", "Benjamin Bollen"]', '카가미는 마리네트를 도쿄로 끌고 가서 스텔라스가 새로운 슈퍼빌런을 물리치는 것을 돕게 하지만, 곧 마리네트는 친구가 이 일본 여행에 또 다른 미지의 이유가 있음을 깨닫는다.', 'https://image.tmdb.org/t/p/w500/vFaopnGXRXxRf4z2Z3IgA1QtOyV.jpg', 2025, 0, 0, '2026-06-08 06:54:20.906897', 'FR');
INSERT INTO public.movies VALUES (6120, 112160, '밝히는 가족의 섹스 스토리', '["Comedy", "Drama", "Romance"]', 'Jean-Marc Barr', '["Mathias Melloul", "Valérie Maës", "Stephan Hersoen", "Pierre Perrier", "Yan Brian"]', '프랑스 교외 도시의 평범한 가족. 하지만 모든 가족에게 비밀은 있다. 자위에 집착하고 수업시간에 핸드폰으로 몰래 자신을 촬영하는 데 재미를 붙인 로맹으로 인해 가족의 평온한 일상은 흔들리기 시작하고, 가족 내에서 금기시되었던 섹스는 중요한 관심사로 변한다. 10대 청소년에서 70대 노인까지, 섹스는 누구에게나 풀리지 않는 숙제인 법.', 'https://image.tmdb.org/t/p/w500/vQDwzFYs1T3CQ26kzJVTWSeAocQ.jpg', 2012, 0, 0, '2026-06-08 06:54:21.65858', 'FR');
INSERT INTO public.movies VALUES (6121, 1390382, '쿠튀르', '["Drama"]', 'Alice Winocour', '["Angelina Jolie", "Anyier Anei", "Ella Rumpf", "Louis Garrel", "Vincent Lindon"]', NULL, 'https://image.tmdb.org/t/p/w500/zN2hnZzj3DjJH2CzB76kDo1zYFu.jpg', 2026, 0, 0, '2026-06-08 06:54:22.42011', 'FR');
INSERT INTO public.movies VALUES (6122, 21484, '포제션', '["Horror"]', 'Andrzej Żuławski', '["Isabelle Adjani", "Sam Neill", "Margit Carstensen", "Heinz Bennent", "Johanna Hofer"]', '전쟁에서 돌아온 첩보원 마크는 아내 안나에게 돌연 이혼 통보를 받는다. 안나의 외도를 의심한 마크는 사립탐정을 고용해 뒤를 밟지만, 이어지는 그녀의 기이하고 광기 어린 행동은 상황을 더욱 깊은 혼돈으로 몰아넣는다. 어느 날, 탐정이 정체불명의 존재에게 처참히 살해되자 마크는 마침내 안나를 집어삼킨 기이한 존재와 맞닥뜨리게 된다.', 'https://image.tmdb.org/t/p/w500/gtseOQqh2nPIdTNsZB3iWTfafct.jpg', 1981, 0, 0, '2026-06-08 06:54:23.18119', 'FR');
INSERT INTO public.movies VALUES (6123, 1124566, '센티멘탈 밸류', '["Drama"]', 'Joachim Trier', '["Renate Reinsve", "Stellan Skarsgård", "Inga Ibsdotter Lilleaas", "Elle Fanning", "Anders Danielsen Lie"]', '가족을 버리고 떠난 영화감독 구스타프는 재회한 딸에게 영화 출연을 제안한다. 하지만 노라는 아버지에 대한 불신과 원망으로 단칼에 거절한다.', 'https://image.tmdb.org/t/p/w500/bqWwoC6MjVXhFZgTMHD6m2w8MZq.jpg', 2025, 0, 0, '2026-06-08 06:54:23.947012', 'FR');
INSERT INTO public.movies VALUES (6124, 496450, '미라큘러스: 레이디버그와 블랙캣, 더 무비', '["Animation", "Fantasy", "Action", "Romance", "Family"]', 'Jeremy Zag', '["Anouck Hautbois", "Benjamin Bollen", "Fanny Bloc", "Alexandre Nguyen", "Antoine Tomé"]', '마법 보석의 수호자로 인해 슈퍼히어로가 된 수줍음 많은 소녀와 인기 많은 소년. 정반대에 끌리는 두 사람은 서로에게조차 정체를 밝힐 수 없는데.INSERT INTO public.movies VALUES (6125, 10995, '연인', '["Drama", "Romance"]', 'Jean-Jacques Annaud', '["Jane March", "Tony Leung Ka-fai", "Frédérique Meininger", "Arnaud Giovaninetti", "Melvil Poupaud"]', '가난한 10대 프랑스 소녀, 부유한 남자를 허락하고 처음으로 육체적 쾌락을 경험하게 된다.  불우한 가정 환경과 자신에 대한 혐오가 더해 갈수록 소녀는 욕망에 빠져들고 격정적인 관능에 몰입한다.  욕정일 뿐 사랑이 아니라고 부정하지만 평생 잊을 수 없는 운명으로 남게 되는데….', 'https://image.tmdb.org/t/p/w500/9YgWVUCb8SEFhFxniBHbJGSx7Gf.jpg', 1992, 0, 0, '2026-06-08 06:54:26.311988', 'FR');
INSERT INTO public.movies VALUES (6128, 4108, '트랜스포터', '["Action", "Crime", "Thriller"]', 'Corey Yuen', '["Jason Statham", "Shu Qi", "François Berléand", "Matt Schulze", "Ric Young"]', '룰(rule)이 깨지기 시작하면서…  예상치 못한 사건, 밝혀지는 음모!  과거 특수부대 출신인 프랭크(제이슨 스태덤 분). 현재 그는 범죄조직이 의뢰한 물건을 비밀리에 운반해주는 ‘트랜스포터’ 일을 하고 있다. 비밀스럽고도 위험한 이 일을 하는 그에겐 확고한 룰(rule)이 있는데, ‘첫째, 계약조건을 변경하지 말 것’, ‘둘째, 거래는 익명으로 할 것’, ‘셋째, 절대 포장을 열지 말 것’이다.  그러던 어느 날, 프랭크는 가칭 ‘월 스트리트’(맷 슐츠 분)라는 사람에게서 새로운 거래를 의뢰받는다. 그러나 운반 도중 가방이 움직인다는 사실을 알게 되고, 가방을 열자 그 속에서 물건이 아닌 사람이 발견된다. 프랭크가 자신의 ‘룰’을 깨고 ‘라이’(서기 분)라는 여인을 구해주면서부터 일은 꼬이기 시작하고, 프랭크는 범죄조직으로부터 생명의 위협을 받게 된다.  한편, 평소 프랭크를 그의 주위를 살피던 형사 타르코니(프랑수아 베를레앙 분). 그는 프랭크의 자동차가 폭발사고의 현장에서 발견되고, 얼마 지나지 않아 프랭크의 집 전체가 정체 모를 일당에 의해 폭파되면서 프랭크를 더욱 의심하게 된다.  라이를 구해준 프랭크는 그녀에게서 놀라운 사실을 듣게 된다. 월 스트리트 일당이 그녀의 가족이 포함된 수백명의 중국인 밀입국자들을 암거래하려 한다는 것. 프랭크는 혼자서 이들을 구출하려는 그녀를 돕기로 한다. 거대 범죄조직이 그들을 뒤쫓고, 프랭크를 의심하는 경찰의 포위망까지 좁혀지면서 상황은 더욱 예상치 못한 곳으로 치닫는다. 그리고 계속되는 위험 속에서 프랭크는 그녀에게 뭔가 다른 비밀이 숨겨졌음을 감지하는데…', 'https://image.tmdb.org/t/p/w500/jeyqPXokegkeOjsvk4kSTeMRz78.jpg', 2002, 0, 0, '2026-06-08 06:54:28.559052', 'FR');
INSERT INTO public.movies VALUES (6129, 1165366, '드골 - 파트 1: 자유 프랑스', '["History", "Drama"]', 'Antonin Baudry', '["Simon Abkarian", "Simon Russell Beale", "Florian Lesieur", "Benoît Magimel", "Mathieu Kassovitz"]', NULL, 'https://image.tmdb.org/t/p/w500/tFdosLwBWPwaslsyQP4yUSezxOg.jpg', 2026, 0, 0, '2026-06-08 06:54:29.324026', 'FR');
INSERT INTO public.movies VALUES (6130, 1383247, '에이전트 제로', '["Action", "Thriller"]', 'Guillaume de Fontenay', '["Marine Vacth", "Emmanuelle Bercot", "Grégoire Colin", "Stanislas Merhar", "Niels Schneider"]', '프랑스 정보기관 DGSE 출신 요원 바드는 라카 작전 이후 조직을 떠나 모로코에서 조용히 살아간다. 그러나 범죄 조직이 그의 연인 일리아스를 노리면서 평온한 삶은 무너진다. 바드는 일리아스를 지키기 위해 다시 싸움에 뛰어들고, 한편 옛 동료 조안나는 범죄 조직 보스 만수르와 위험한 거래를 이어간다. 두 사람의 서로 다른 선택이 하나의 사건으로 얽히며, 그 과정에서 바드의 목숨을 빼앗아갈 뻔했던 라카 작전에 숨겨진 진실이 서서히 드러난다.', 'https://image.tmdb.org/t/p/w500/sLjHm8eKrC27wykgmih6vVCxjbi.jpg', 2025, 0, 0, '2026-06-08 06:54:30.072113', 'FR');
INSERT INTO public.movies VALUES (6131, 641284, 'Excitation au soleil', '[]', 'Michel Lemoine', '["Danièle Troeger", "Morgane", "Thierry de Brem", "Olivier Mathot"]', NULL, 'https://image.tmdb.org/t/p/w500/ysKUDDAwHGZLbvAYAkAJABSwmFB.jpg', 1978, 0, 0, '2026-06-08 06:54:30.810461', 'FR');
INSERT INTO public.movies VALUES (6132, 1259983, 'Gourou', '["Drama", "Thriller"]', 'Yann Gozlan', '["Pierre Niney", "Marion Barbeau", "Anthony Bajon", "Christophe Montenez", "Jonathan Turnbull"]', NULL, 'https://image.tmdb.org/t/p/w500/ufdcPu8CdcsC0c73pATNjYXEmMR.jpg', 2026, 0, 0, '2026-06-08 06:54:31.58051', 'FR');
INSERT INTO public.movies VALUES (6133, 2011, '페르세폴리스', '["Animation", "Drama"]', 'Marjane Satrapi', '["Chiara Mastroianni", "Danielle Darrieux", "Catherine Deneuve", "Simon Abkarian", "Gabrielle Lopes Benites"]', '테헤란, 펑크록에 심취한 차도르 소녀 ''마르잔''. 마이클 잭슨과 아바를 좋아하는 마르잔은 정의감에 불타는 용감한 소녀다. 하지만 보수적인 이란 사회에서 마르잔의 대담함은 종종 그녀를 곤경에 처하게 하고 고민 끝에 마르잔의 부모는 그녀의 안전을 위해 오스트리아로 보내기로 결심한다.  비엔나, 청춘을 즐기는 자유 소녀 ''마르잔''. 고국을 떠나 낯선 땅에서 살게 된 마르잔은 술, 담배, 쇼핑과 함께 자유를 만끽한다. 새로운 친구들을 만나고 첫사랑도 경험하며 꿈같은 하루 하루를 보내는 마르잔. 하지만 달콤한 행복도 잠시, 가족의 사랑이 그리운 마르잔은 지독한 향수병을 앓게 되는데... 과연, 비범한 소녀 마르잔의 평범한 어른되기 프로젝트는 성공할 수 있을까?', 'https://image.tmdb.org/t/p/w500/lfmEJgTGE3jlLgUbxhMKEKOBTsr.jpg', 2007, 0, 0, '2026-06-08 06:54:32.338036', 'FR');
INSERT INTO public.movies VALUES (6134, 960292, '디자이어: 욕망의 밤', '["Romance", "Drama"]', 'Lucie Borleteau', '["Zita Hanrot", "Louise Chevillotte", "Laure Giappiconi", "Pedro Casablanc", "Sième Miladi"]', '지금껏 만나본 적 없는 세계. 평범한 삶을 살아온 그녀가 관능적인 스트립 클럽의 댄서가 되고 자신도 몰랐던 에로틱 본능이 깨어나면서 원초적 스트립 쇼와 매춘까지 하게 되는데… 즐길 준비가 되셨나요?', 'https://image.tmdb.org/t/p/w500/vzlYTOpiTZ1g4luRxFSZ84EXxEo.jpg', 2023, 0, 0, '2026-06-08 06:54:33.065178', 'FR');
INSERT INTO public.movies VALUES (6135, 74871, 'Un moment d''égarement', '["Comedy", "Drama", "Romance"]', 'Claude Berri', '["Jean-Pierre Marielle", "Victor Lanoux", "Agnès Soral", "Christine Dejoux", "Martine Sarcey"]', NULL, 'https://image.tmdb.org/t/p/w500/4B9xo3ewGbBN3gGxqiTqQlbqBYY.jpg', 1977, 0, 0, '2026-06-08 06:54:33.819063', 'FR');
INSERT INTO public.movies VALUES (6127, 339308, 'The Unscarred', '["Thriller"]', 'Buddy Giovinazzo', '["James Russo", "Heino Ferch", "Ornella Muti", "Steven Waddington", "Ulrike Haase"]', NULL, 'https://image.tmdb.org/t/p/w500/tgBRIucjHxtLUXO7HJiK54SteUb.jpg', 2000, 0, 0, '2026-06-08 06:54:27.815909', 'GB');
INSERT INTO public.movies VALUES (6137, 81774, '돈 쥬앙', '["Comedy", "Drama"]', 'Gianfranco Mingozzi', '["Serena Grandi", "Claudine Auger", "Marina Vlady", "Fabrice Josso", "François Perrot"]', '청년이 된 로져는 여름휴가를 보내기 위해서 아버지가 마련해준 시골별장에 내려간다. 건장한 일꾼들과 하녀들 간에 은밀히 행해지는 유희를 호기심에 차 관찰하던 로져는 서서히 이성에 대한 안목이 뜨여간다. 그 무렵 2차세계대전에 휘말려 젊은 일꾼들이 모두 전장으로 나가게 되어 별장에는 늙은 신부와 로져, 이렇게 두 남자만 남게 된다. 이를 기회로 로져는 젊은 하녀와 애틋한 연정의 싹을 틔우게 되고, 휴가가 끝날 무렵, 로져는 어엿한 성인이 되어 별장을 떠난다.', 'https://image.tmdb.org/t/p/w500/bKPNjbpDlLFZunI8l1SM5EAbAtH.jpg', 1986, 0, 0, '2026-06-08 06:54:35.359751', 'FR');
INSERT INTO public.movies VALUES (6139, 9335, '트랜스포터: 엑스트림', '["Action", "Thriller", "Crime"]', 'Louis Leterrier', '["Jason Statham", "Amber Valletta", "Alessandro Gassmann", "Kate Nauta", "Matthew Modine"]', '‘트랜스포터’ 제이슨 스태덤의 강력한 액션 전면전!  자동차 추격씬, 제트스키 추격씬이 긴장감 넘치고 스피디하게 펼쳐진다!  과거 특수부대 출신이자 범죄조직이 의뢰한 물건을 비밀리에 운반해주는 ‘트랜스포터’ 일을 하고 있던 프랭크. 위험하고 스릴 넘치는 생활을 하던 그는 모든 일에서 은퇴를 하고 마이애미에서 조용한 생활을 하고 있다.  그러던 그는 우연한 인연으로 잠시 경호를 맡았던 아이가 납치를 당하게 되면서 일생일대의 사건에 휘말리게 된다. 배후는 마약 근절을 꾀하는 세계 각국 대표단을 신종 바이러스를 이용해 암살하려는 콜롬비아 거대 마약상의 하수인들.  분노로 불타오른 프랭크는 아이와의 약속을 지키기 위해 그들과의 전쟁을 선포하고 납치의 전모를 밝혀가는데...', 'https://image.tmdb.org/t/p/w500/5jGQurjRp221eM1RvivGPUQQMmq.jpg', 2005, 0, 0, '2026-06-08 06:54:36.888375', 'FR');
INSERT INTO public.movies VALUES (6140, 152584, '가장 따뜻한 색, 블루', '["Romance", "Drama"]', 'Abdellatif Kechiche', '["Léa Seydoux", "Adèle Exarchopoulos", "Salim Kéchiouche", "Aurélien Recoing", "Catherine Salée"]', '여느 소녀들과 다를 바 없는 평범한 고등학생 아델은 빈칸들로 점철된 미래의 답을 찾고 있는 문학소녀이다. 피에르 드 마리보의 소설 을 이해하고자 노력하고 있는 아델 앞에 어느 날 파란 머리의 대학생 엠마가 나타난다. 단지 횡단보도에서 우연히 스치며 지나친 인연이지만 그날 이후 아델과 엠마는 서로를 기억하게 된다. 누가 먼저랄 것도 없이 아델과 엠마는 서로에게 이끌리고, 미술을 전공한 엠마는 본능적으로 자신의 캔버스 안으로 아델을 초대한다. 아델은 자신과 전혀 다른 삶을 살아온 엠마로 인해 이전에는 몰랐던 뜨거운 감정을 느끼게 되는데...', 'https://image.tmdb.org/t/p/w500/bRqQEPje0ALDUw1AhUT7FP99aap.jpg', 2013, 0, 0, '2026-06-08 06:54:37.635896', 'FR');
INSERT INTO public.movies VALUES (6141, 1266798, '도그 51', '["Thriller", "Sci-Fi", "Crime", "Action"]', 'Cédric Jimenez', '["Gilles Lellouche", "Adèle Exarchopoulos", "Louis Garrel", "Romain Duris", "Valeria Bruni Tedeschi"]', NULL, 'https://image.tmdb.org/t/p/w500/6pSkQRQxxC5AJ82aKbp1lFXQnXo.jpg', 2025, 0, 0, '2026-06-08 06:54:38.380037', 'FR');
INSERT INTO public.movies VALUES (6142, 1147416, '미라클 월드 런던: 시간의 끝에서', '["Animation", "Family", "Action", "Adventure", "Fantasy"]', 'Thomas Astruc', '["Anouck Hautbois", "Marie Nonnenmacher", "Benjamin Bollen", "Clara Soares", "Marie Chevalot"]', '끔찍한 운명을 맞이할 미래를 구하고자, 마리네뜨는 크로노버그가 되어 버닉스와 함께 시간을 여행하는 의문의 적을 물리치려 한다. 이 새로운 슈퍼 악당은 누구이며, 왜 이들은 마리네뜨의 은밀한 슈퍼히어로 정체성을 폭로하는 데 집착하는 걸까? 새로운 상대를 물리치고 레이디버그와 시간이 끝나는 걸 막는 것만이 마리네뜨의 유일한 희망이다!', 'https://image.tmdb.org/t/p/w500/vKLi7Q2Rw4Q4ppZGWWhMEwcyDdA.jpg', 2024, 0, 0, '2026-06-08 06:54:39.139124', 'FR');
INSERT INTO public.movies VALUES (6143, 342473, '발레리나', '["Animation", "Adventure", "Comedy", "Family"]', 'Eric Summer', '["Elle Fanning", "Dane DeHaan", "Nat Wolff", "Carly Rae Jepsen", "Maddie Ziegler"]', '작은 시골 마을에 살고 있는 고아 소녀 펠리시 와 그녀의 소꿉친구 빅터. 그들의 꿈은 최고의 발레리나와 발명가가 되는 것이다. 두 사람은 자신의 꿈을 이루기 위해 다소 황당무계해 보이는 계획을 실천한다. 바로 빛의 도시 파리를 향해 여행을 떠나는 것. 센느강, 에펠탑, 자유의 여신상, 최고의 무대인 오페라 하우스까지.. 화려하고 아름다운 파리의 모습은 그들의 꿈을 향한 열망을 더욱 뜨겁게 하는데.', 'https://image.tmdb.org/t/p/w500/soUeiEdtRAbRfhmo2nFBxQzLmYw.jpg', 2016, 0, 0, '2026-06-08 06:54:39.882008', 'FR');
INSERT INTO public.movies VALUES (6146, 406, '증오', '["Drama"]', 'Mathieu Kassovitz', '["Vincent Cassel", "Hubert Koundé", "Saïd Taghmaoui", "Abdel Ahmed Ghili", "Solo"]', '경찰의 심문을 받던 16세 아랍소년, 압델 이샤하는 혼수상태다. 시가전이 벌어진 지역에는 경찰의 계엄령이 선포되고, 성난 젊은이들은 위험한 긴장 속에서 경찰과 대치 중이다. 더 이상 살아 숨쉴 여지도 가지지 못한 젊은이들과 총과 헬멧으로 무장한 경찰 사이의 ''증오''는 더욱 커져만 간다. 유태계 프랑스인 빈츠, 아랍계 소년 사이드, 흑인 위베르. 그들은 2000년이 될 때까지 살아남는 것이 절대과제인 거리의 단짝 친구들이다. 이들은 경찰과의 격렬한 전투가 있던 다음날, 여느때처럼 모여 할 일없이 거리를 쏘다닌다.', 'https://image.tmdb.org/t/p/w500/gfdhSzPyAWtAizqs4ytc0MwOlQg.jpg', 1995, 0, 0, '2026-06-08 06:54:43.007354', 'FR');
INSERT INTO public.movies VALUES (6147, 82675, '테이큰 2', '["Action", "Crime", "Thriller"]', 'Olivier Megaton', '["Liam Neeson", "Maggie Grace", "Famke Janssen", "Leland Orser", "D. B. Sweeney"]', '킴(메기 그레이스)의 납치 사건으로 조직에 치명타를 입고, 가족의 목숨까지 빼앗긴 인신매매범 일당은 브라이언(리암 니슨)에게 똑같이 갚아주기 위해 조직력을 총동원, 그의 뒤를 쫓는다.  한편 이스탄불을 여행 중이던 브라이언과 전처 레노어(팜케 얀슨)는 알 수 없는 일당의 기습을 받고 납치되지만, 킴만은 극적으로 놈들의 손아귀에서 벗어난다. 어디론가 끌려가는 브라이언은 오직 소리에만 의존해 자신의 위치를 파악해간다. 감시를 피해 가까스로 탈출에 성공한 브라이언은 이제 킴과 레노아를 지키기 위해 다시 한번 전직 특수 요원의 실력을 발휘해 놈들을 역추적하기 시작하는데...', 'https://image.tmdb.org/t/p/w500/13wqoIbNQIE9Ak8QsFXabQsfiDc.jpg', 2012, 0, 0, '2026-06-08 06:54:43.74876', 'FR');
INSERT INTO public.movies VALUES (6149, 1215532, 'Chickenhare and the Secret of the Groundhog', '["Animation", "Adventure", "Comedy", "Family"]', 'Benjamin Mousquet', '["Jordan Tartakow", "Laila Berzins", "Joe Ochman", "Xanthe Huynh", "Odessa Lurlean"]', NULL, 'https://image.tmdb.org/t/p/w500/cUCwWxHF1bRfqeY7beZfsvT7WBR.jpg', 2025, 0, 0, '2026-06-08 06:54:45.235415', 'FR');
INSERT INTO public.movies VALUES (6150, 487616, '큐리오사', '["Drama", "History"]', 'Lou Jeunet', '["Noémie Merlant", "Niels Schneider", "Benjamin Lavernhe", "Camélia Jordana", "Amira Casar"]', '19세기 파리. 자유로운 영혼의 시인 피에르(니엘스 슈나이더)와 마리(노에미 메를랑)는 서로 사랑하지만, 마리는 부모님의 뜻을 따라 피에르의 친구와 결혼을 한다. 상처받은 피에르는 알제리로 떠나고, 그곳에서 예술적인 영감을 주는 매혹적인 뮤즈 조흐라(카멜리아 조르다나)를 만나 그녀의 누드사진을 찍기 시작한다. 1년 후. 애정 없는 결혼생활을 이어가던 마리는 피에르가 조흐라와 함께 파리에 돌아왔다는 소식을 듣고 그를 찾아간다. 여전히 서로를 잊지 못하고 있던 마리와 피에르는 은밀한 관계를 이어가고, 마리는 피에르의 사진작품들을 보며 자신의 누드사진을 찍어달라고 하는데… “사진 모델이 되고 싶어요. 도덕 따윈 아랑곳하지 않는 자세로”', 'https://image.tmdb.org/t/p/w500/gUfcOyUB1iqwI1RNNdK6ZDlwY6X.jpg', 2019, 0, 0, '2026-06-08 06:54:45.974977', 'FR');
INSERT INTO public.movies VALUES (6151, 1450599, 'KO', '["Action", "Drama", "Adventure"]', 'Antoine Blossier', '["Ciryl Gane", "Alice Belaïdi", "Foued Nabba", "Maleaume Paquin", "Anne Azoulay"]', '수년 전 링에서 실수로 상대 선수를 죽게 만든 전직 파이터. 죽은 선수의 아들이 실종되자, 소년을 찾기 위해 마르세유의 잔혹한 범죄 조직과 맞선다.', 'https://image.tmdb.org/t/p/w500/jK7IKdwJLfZZTh2TdbTmOrxhbTl.jpg', 2025, 0, 0, '2026-06-08 06:54:46.792038', 'FR');
INSERT INTO public.movies VALUES (6152, 231108, 'Washington, le président McKinley adressant son message au peuple', '["Documentary"]', 'Félix Mesguich', '["William McKinley"]', NULL, NULL, 1897, 0, 0, '2026-06-08 06:54:47.554063', 'FR');
INSERT INTO public.movies VALUES (6154, 102752, 'Cleveland Versus Wall Street', '["Documentary", "Crime", "Drama"]', 'Jean-Stéphane Bron', '["Barbara Anderson", "Keith Taylor", "Michael Osinski", "Tony Brancatelli", "Frederick Kushen"]', NULL, 'https://image.tmdb.org/t/p/w500/3kjLzbIpAHMjWmRmz56hZ15LSam.jpg', 2010, 0, 0, '2026-06-08 06:54:49.045837', 'FR');
INSERT INTO public.movies VALUES (6155, 111190, '투 마더스', '["Drama"]', 'Anne Fontaine', '["Naomi Watts", "Robin Wright", "Xavier Samuel", "James Frecheville", "Ben Mendelsohn"]', '어린 시절부터 자매처럼 늘 함께였던 릴과 로즈.  갑작스런 교통사고로 남편을 떠나 보낸 릴과 이안 모자를 가족처럼 보살피는 로즈와 그녀의 아들 톰. 네 사람은 서로에게 없어서는 안 될 존재가 된다. 어느 날, 이안은 로즈에게 숨겨왔던 진심을 고백하고,  그녀는 매력적인 남자로 성장한 이안의 유혹을 뿌리치지 못하고 키스를 받아들인다. 한편, 톰은 자신의 친구와 엄마의 관계를 목격한 뒤 감정을 억누르지 못하고 릴을 찾아간다. 릴과 톰, 로즈와 이안, 이제 네 사람은 서로의 비밀을 공유한 채 멈출 수 없는 사랑에 빠져 드는데…', 'https://image.tmdb.org/t/p/w500/s1mSUviCXABZhCix3PCdXkwCxTq.jpg', 2013, 0, 0, '2026-06-08 06:54:49.797333', 'FR');
INSERT INTO public.movies VALUES (6156, 5528, '코러스', '["Drama", "Comedy"]', 'Christophe Barratier', '["Gérard Jugnot", "François Berléand", "Kad Merad", "Jean-Paul Bonnaire", "Marie Bunel"]', '2차 세계대전 직후 프랑스 작은 기숙사 학교. 토요일마다 하염없이 아빠를 기다리는 전쟁고아 페피노, 엄마의 관심을 끌기 위해 말썽을 일으키는 모항주. 돌아갈 곳 없이 쓸쓸한 여름방학을 보내는 아이들의 학교에 미완성의 악보를 든 마티유가 임시직 교사로 부임해온다. 마티유는 강한 체벌로 다스리는 교장에 맞서 아이들의 닫힌 마음을 열기 위해 포기했던 음악을 작곡하고, 노래를 가르친다. 점차 아이들의 하모니가 교내에 울려 퍼지면서, 모항주는 놀라운 음악적 재능을 드러내고, 페피노는 마음의 보금자리를 교문 밖에서 마티유 옆 교탁으로 옮기게 된다. 하지만,문제소년 몽당의 전학으로 기숙학교는 예기치 못한 사건의 소용돌이에 휘말리게 되는데......', 'https://image.tmdb.org/t/p/w500/383H2OAb7P7PanpKDfNLszvDFtv.jpg', 2004, 0, 0, '2026-06-08 06:54:50.550338', 'FR');
INSERT INTO public.movies VALUES (6157, 499726, '해변의 밀프', '["Comedy", "Romance"]', 'Axelle Laffont', '["Virginie Ledoyen", "Marie-Josée Croze", "Axelle Laffont", "Matthias Dandois", "Victor Meutelet"]', '집을 처분하려고 해변으로 향하는 세 친구. 차는 쌩쌩 달리지만 마음은 인생에 대한 피로와 상실감쯤에 머물러 있다. 그런데 뜨거운 태양과 바다 탓일까. 점점 들떠가는 마음에 연하남들까지 불을 지핀다. 친구들아, 나 좀 설레도 되겠니?', 'https://image.tmdb.org/t/p/w500/bJGK2006L36f0Ybi7A4LfJpgiBb.jpg', 2018, 0, 0, '2026-06-08 06:54:51.337325', 'FR');
INSERT INTO public.movies VALUES (6158, 10497, '비터 문', '["Thriller", "Drama", "Romance"]', 'Roman Polanski', '["Peter Coyote", "Emmanuelle Seigner", "Hugh Grant", "Kristin Scott Thomas", "Victor Banerjee"]', '나이젤(Nigel : 휴 그랜트 분)과 휘요나(Fiona : 크리스틴 스콧 토마스 분)는 영국인 부부로 서로의 사랑을 확인하면서 지중해를 여행중이다. 그러던 어느날, 나이젤에게 휠체어에 탄 중년 남자가 접근한다. 그는 오스카(Oscar : 피터 코요테 분)라는 미국인 작가로, 빠리에 살면서 집필을 하고 있었다. 오스카도 아내인 미미(Mimi : 엠마뉴엘 세이너 분)와 여행을 하고 있었다. 오스카는 나이젤을 초대해, 자신의 이야기를 들려주는데...INSERT INTO public.movies VALUES (6159, 960135, 'Madame de Sévigné', '["Drama", "History"]', 'Isabelle Brocard', '["Karin Viard", "Ana Girardot", "Cédric Kahn", "Noémie Lvovsky", "Robin Renucci"]', NULL, 'https://image.tmdb.org/t/p/w500/v4satMrWuYPdTTB4nP0LKxQmZRP.jpg', 2024, 0, 0, '2026-06-08 06:54:52.853911', 'FR');
INSERT INTO public.movies VALUES (6160, 90104, 'Cecilia', '["Drama", "Romance"]', 'Olivier Mathot', '["Muriel Montossé", "Antonio Mayans", "Antonio de Cabo", "Olivier Mathot", "Lina Romay"]', NULL, 'https://image.tmdb.org/t/p/w500/8tLTCUHJW74tx1WFryOF8sk4DsX.jpg', 1983, 0, 0, '2026-06-08 06:54:53.774306', 'FR');
INSERT INTO public.movies VALUES (6163, 375588, '후드', '["Adventure", "Action", "Thriller", "Fantasy"]', 'Otto Bathurst', '["Taron Egerton", "Jamie Foxx", "Ben Mendelsohn", "Eve Hewson", "Jamie Dornan"]', '돈과 권력을 앞세운 권력층으로 인해 모두가 힘들어진 시기.  전쟁에서 죽은 줄 알았던 귀족 가문의 스무살 청년 ‘로빈’이 나타난 뒤 부자들의 돈만 훔친다는 후드를 쓴 남자에 대한 소문이 들려온다. 정체를 알 수 없는 그에게 막대한 현상금이 걸리지만 번번이 잡는데 실패하고 신출귀몰한 후드의 활약에 사람들도 점차 동요하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/6dM7btEP14R9pPgp80e8AGfsl5N.jpg', 2018, 0, 0, '2026-06-08 06:54:56.105751', 'FR');
INSERT INTO public.movies VALUES (6164, 1107216, '펫 트레인', '["Animation", "Comedy", "Adventure", "Thriller"]', 'Benoît Daffis', '["Damien Ferrette", "Hervé Jolly", "Kaycie Chase", "Frantz Confiac", "Emmanuel Garijo"]', '도심 속 동물 평화를 수호하는 정의의 너구리 ‘팔콘’! 배고픈 동물 친구들을 위해 열차에 오르는 순간, 복수심에 불타는 오소리 ‘한스’에 의해 반려동물들만 탑승한 열차가 브레이크 없이 폭주하기 시작한다. 정면 충돌까지 남은 시간은 단 몇 분! 일촉즉발의 위기 속에서 ‘팔콘’은 새로 만난 친구들과 힘을 합쳐 생존을 위한 스릴 만점의 탈출 작전에 나서는데…', 'https://image.tmdb.org/t/p/w500/8GIxRi789MUuF77rV98OK48qnJQ.jpg', 2025, 0, 0, '2026-06-08 06:54:57.730825', 'FR');
INSERT INTO public.movies VALUES (6165, 915935, '추락의 해부', '["Thriller", "Mystery", "Crime"]', 'Justine Triet', '["Sandra Hüller", "Swann Arlaud", "Milo Machado-Graner", "Antoine Reinartz", "Samuel Theis"]', '산드라와 사뮈엘은 시각 장애가 있는 아들 다니엘과 함께 프랑스 알프스의 외딴 산장에서 살고 있다. 갑작스러운 사뮈엘의 죽음 이후, 그의 죽음이 자살인지 혹은 범죄에 연루된 것인지를 밝히는 조사는 점차 미궁으로 빠지게 되는데...', 'https://image.tmdb.org/t/p/w500/zIxTPoS6zd3txeLP5FUdo3CSfbo.jpg', 2023, 0, 0, '2026-06-08 06:54:58.659873', 'FR');
INSERT INTO public.movies VALUES (6166, 1680516, 'WHO', '["Thriller"]', 'Wil Aime', '["Wil Aime", "Hassan Koné", "Solène Hegbe", "Eden Elijah", "John Dadie"]', NULL, 'https://image.tmdb.org/t/p/w500/rO9L4pXE0ykAKGHOTPNGXcvh450.jpg', 2026, 0, 0, '2026-06-08 06:54:59.345411', 'FR');
INSERT INTO public.movies VALUES (6167, 454527, '베네데타', '["History", "Drama", "Romance"]', 'Paul Verhoeven', '["Virginie Efira", "Charlotte Rampling", "Daphné Patakia", "Lambert Wilson", "Olivier Rabourdin"]', '성흔과 그리스도와의 심장 교환, 신과의 결혼 등 종교적이고 에로틱한 무아경으로 신비주의로 추앙 받으며 수녀원장에 오른 베네데타. 수녀원에 들어온 바톨로매아라는 처녀와의 사랑이 교회에 적발되면서 한순간에 부정한 여인으로 몰락하는데…', 'https://image.tmdb.org/t/p/w500/5pzVIYH4VHkFPxGcM5H823dIPIq.jpg', 2021, 0, 0, '2026-06-08 06:55:00.026583', 'FR');
INSERT INTO public.movies VALUES (6168, 974950, '에밀리아 페레즈', '["Drama", "Thriller"]', 'Jacques Audiard', '["Zoe Saldaña", "Karla Sofía Gascón", "Selena Gomez", "Adriana Paz", "Edgar Ramírez"]', '능력 있는 변호사 ''리타''는 ''큰돈을 벌게 해주겠다''는 비밀 의뢰를 받고 멕시코 카르텔의 수장 ''델 몬테''를 만나러 간다. 그의 요청은 놀랍게도 "자신을 여자로 다시 태어나게 해달라는 것. 아내도 모르게 새로운 삶을 살 수 있게 세팅하라는 것." 얼마 뒤, 새로운 그녀 ‘에밀리아 페레즈’가 나타나면서 모두의 인생에 2막이 오른다.', 'https://image.tmdb.org/t/p/w500/gLWjwltZIMIaYLiB6FHVVUXAlxz.jpg', 2024, 0, 0, '2026-06-08 06:55:00.712989', 'FR');
INSERT INTO public.movies VALUES (6169, 238636, '더 퍼지: 거리의 반란', '["Horror", "Thriller"]', 'James DeMonaco', '["Frank Grillo", "Carmen Ejogo", "Zach Gilford", "Michael Kenneth Williams", "Kiele Sanchez"]', '1년 전, 단 하나뿐인 아들을 잃은 뒤 복수를 위해 나선 한 남자  갑작스런 차 고장으로 거리 한복판에 갇힌 위기의 커플  가장 안전하다고 믿었던 집에서 무장 집단들에게 끌려 나온 모녀  오직 재미를 위해 도시를 접수한 가면을 쓴 무리들  법의 통제는 사라지고, 살인이 허락된 단 12시간  지금, 당신도 ‘퍼지데이’에 동참하라!', 'https://image.tmdb.org/t/p/w500/rHIkhTrClh2MQyFkfnu68ArMLjx.jpg', 2014, 0, 0, '2026-06-08 06:55:01.386195', 'FR');
INSERT INTO public.movies VALUES (6170, 804370, '아르코', '["Adventure", "Animation", "Family", "Sci-Fi"]', 'Ugo Bienvenu', '["Margot Ringard Oldra", "Oscar Tresanini", "Nathanaël Perrot", "Alma Jodorowsky", "Swann Arlaud"]', '2075년, 자연이 너무 위험해져 아이들은 돔 안에서 생활하고, 부모 없이 로봇에 의해 양육된다. 열 살 소녀 아이리스는 어느 날, 자신이 2932년 미래에서 왔으며 무지개를 타고 하늘을 날 수 있다고 말하는 동갑내기 소년 아르코를 만나며 희망의 빛을 발견하게 된다.', 'https://image.tmdb.org/t/p/w500/452fi4x08vqfaFpIEI9fsK7Zs4D.jpg', 2025, 0, 0, '2026-06-08 06:55:02.057731', 'FR');
INSERT INTO public.movies VALUES (6171, 219811, 'Éducation anglaise', '["Comedy", "Drama"]', 'Jean-Claude Roy', '["Brigitte Lahaie", "André Dupon", "Obaya Roberts", "Bernard Musson", "Jean-Claude Dreyfus"]', NULL, 'https://image.tmdb.org/t/p/w500/uWjPAGqgs5iAx9TqlV5WVO2NcSk.jpg', 1983, 0, 0, '2026-06-08 06:55:02.736753', 'FR');
INSERT INTO public.movies VALUES (6172, 467220, 'Guillaume à la dérive', '["Comedy", "Family"]', 'Sylvain Dieuaide', '["Anne Alvaro", "Marc Arnaud", "Bastien Bouillon", "Judith Chemla"]', NULL, 'https://image.tmdb.org/t/p/w500/d8DFgq7XU9E1MRjO7Shh6SDLxAq.jpg', 2016, 0, 0, '2026-06-08 06:55:03.532342', 'FR');
INSERT INTO public.movies VALUES (3881, 1393326, '고스트 인 더 셀', '["Horror", "Comedy"]', 'Joko Anwar', '["Abimana Aryasatya", "Bront Palarae", "Dimas Danang", "Endy Arfian", "Lukman Sardi"]', '폭력이 난무하는 인도네시아의 한 교도소에 침묵을 지키는 의문의 수감자가 도착한다. 그와 함께 등장한 기이한 존재는 가장 어두운 아우라를 가진 자를 찾아내 목숨을 앗아가기 시작한다. 살아남기 위해 선행을 베풀기 시작한 수감자들은 모두가 하나로 뭉치는 것만이 이 지옥을 벗어날 유일한 열쇠라는 것을 깨닫는다. 그렇지 않으면, 한 명씩 죽어갈 뿐이다.', 'https://image.tmdb.org/t/p/w500/jfV9yrEHuVCelig83wyCAcHl5ul.jpg', 2026, 0, 0, '2026-06-08 06:24:37.667244', 'KR');
INSERT INTO public.movies VALUES (756, 387848, '친구엄마', '["Drama", "Romance"]', 'Kong Ja-kwan', '["Kim Young-sam", "Ah Ri", "Kim Hae-jin", "Park Cho-hyeon", "Kim Jae-rok"]', '이론만 강한 남자, 스무살 경수!  섹스를 인터넷 야동으로만 보고 배운 경수. 그는 이론에만 강할뿐 실전은 전무하다. 짝사랑만 했을 뿐 키스한번 못 해 봤다. 짝사랑하던 선배 지연에게 고백했다가 개쪽만 당하고 방구석에서 일본 언니들을 벗삼아 오른손 긴긴 밤을 보내던 어느 날. 홀아버지와 대판 싸운 경수는 방학이 되면 자신의 집에 놀러오라는 친구 백현의 얘기를 떠 올리고 무작정 강원도 삼척으로 향하는 버스에 오른다.  뱀파이어인가! 늙지않는 친구 엄마, 현옥!  20대 뺨을 후려치는 완벽한 바디 라인과 이승환과 친구 먹는 동안의 전복 아가씨 출신 현옥. 긴긴밤 외로이 바닷가를 바라보며 소주잔을 기울이던 그녀에게 무려 20살이나 어린 아들 친구가 작업을 걸어온다. 이 어린 놈의 새끼를 받아줘도 문제. 안 받아줘도 문제?  사랑일까? 엔조이일까?  하루 수십번도 가능한 경수. 집에서도 하고, 해변에서도 하고, 물에서도 하고, 하고 하고 또 해도 경수는 끊임없이 일어선다. 그런 경수가 싫지 않은 현옥. 자신을 시도때도 없이 덮치는 경수가 귀엽고 사랑스럽다. 하지만 경수의 짝사랑 지연이 삼척에 내려오자 지랄 맞은 날씨처럼 경수의 마음이 오락가락 하기 시작한다. 지연에게 한번. 현옥에게 한번. 경수는 현옥을 사랑하는 것일까? 아니면 그냥 엔조이일까?', 'https://image.tmdb.org/t/p/w500/5JDVEZN0v3e9xMzZbZ92fC7HaQi.jpg', 2015, 0, 0, '2026-06-06 13:25:24.968257', 'KR');
INSERT INTO public.movies VALUES (730, 646315, '전설의 라이타', '["Action"]', 'Chae Ki-jun', '["Kim Hae-joon", "Park Sharon", "Lee Dong-ju", "Hong Dal-pyo"]', '맨주먹계의 전설적인 인물 채성빈(라이타). 아버지 같은 남자 마석준의 충고를 받아들여 이제는 평범한 삶을 살기로 결심한다. 그러던 중 우연히 골목에서 일진들에게 괴롭힘을 당하는 박주민을 구해주게 되고, 그를 계기로 박주민의 누나 박진아와 가까운 사이가 된다. 한편 박진아는 지역개발 이권 다툼에 휘말려 고통 받고 있었고 그 강도가 심해져 목숨까지 위협받는 처지가 된다. 끊임없는 조폭들의 위협으로 하루하루가 지옥 같던 박진아의 곁에 전설의 주먹 채성빈이 등장하게 되고, 채성빈은 사랑하는 박진아를 위해 마지막으로 다시 한번 라이타를 손에 쥐게 된다.', 'https://image.tmdb.org/t/p/w500/h5fCwKCnKAKxdX6onTnrU6MeYe8.jpg', 2019, 0, 0, '2026-06-06 13:25:24.185432', 'KR');
INSERT INTO public.movies VALUES (4090, 1174128, '동화지만 청불입니다', '["Comedy", "Romance"]', 'Lee Jong-suk', '["Park Ji-hyun", "Choi Si-won", "Sung Dong-il", "Park Geon-il", "Hwang Se-on"]', '동화 작가가 꿈이지만 현실은 불법 음란물 단속팀 새내기인 단비는 스타 작가를 찾던 성인 웹소설계 대부 황대표와 우연한 사고로 노예 계약을 맺게 되면서 하루아침에 19금 소설을 쓰게 된다. 생전 접한 적 없는 장르를 집필하는 데 난항을 겪던 단비는 음란물 단속을 하다 권태기에 빠진 선배 정석의 응원과, 친구들의 생생한 경험담에 힘입어 어느새 자신도 알지 못했던 성스러운 재능을 발견하게 되는데…', 'https://image.tmdb.org/t/p/w500/mkQE7ZOhBMoVhDFbwLiJ43T5GzX.jpg', 2025, 0, 0, '2026-06-08 06:26:52.179067', 'KR');
INSERT INTO public.movies VALUES (145, 269955, '인간중독', '["Drama"]', 'Kim Dae-woo', '["Song Seung-heon", "Lim Ji-yeon", "Cho Yeo-jeong", "On Ju-wan", "Yoo Hai-jin"]', '베트남전이 막바지로 치달아가던 1969년, 엄격한 위계질서와 상하관계로 지배되는 군관사. 모두의 신임을 받으며 승승장구 중인 교육대장 김진평과 남편을 장군으로 만들려는 야망을 가진 진평의 아내 이숙진. 어느 날, 김진평의 부하로 충성을 맹세하는 경우진과 그의 아내 종가흔이 이사를 온다. 진평은 우진의 아내 가흔에게 첫 만남부터 강렬한 떨림을 느끼는데…', 'https://image.tmdb.org/t/p/w500/zMCeJiRbV7Z5TFA8JpALExAQra.jpg', 2014, 0, 0, '2026-06-06 13:25:01.783266', 'KR');
INSERT INTO public.movies VALUES (4085, 17903, '쌍화점', '["Drama"]', 'Yoo Ha', '["Zo In-sung", "Ju Jin-mo", "Song Ji-hyo", "Shim Ji-ho", "Seo Young-joo"]', '격정의 고려말, 왕과 왕의 호위무사 ''홍림''. 원의 억압을 받던 고려 말, 친위부대 건룡위의 수장 ''홍림''은 대내외적 위기에 놓인 왕을 보필하며 경계를 늦추지 않는다. 그러나 후사문제를 빌미로 원의 무리한 요구는 계속되고, 정체불명의 자객들이 왕의 목숨을 위협하자, 왕은 중대한 결정을 내리게 된다.  거부할 수 없는 선택, 엇갈린 운명. 왕의 명령이라면 목숨처럼 따르는 홍림, 왕은 고려의 왕위를 이을 원자를 얻기 위해 홍림에게 왕후와의 대리합궁을 명한다. 충격과 욕망이 엇갈린 그날 밤, 세 사람의 운명은 소용돌이 치기 시작하는데...', 'https://image.tmdb.org/t/p/w500/fkugEylA1A8JZAdBmCWP6n1h4Rr.jpg', 2008, 0, 0, '2026-06-08 06:26:48.618213', 'KR');
INSERT INTO public.movies VALUES (4088, 870270, '내 아내의 언니3', '["Drama", "Romance"]', 'Jo Tae-ho', '["Yoon Da-hyeon", "Sang Woo", "Choi Woo-suk-I", "Kim Hee-jeong"]', '결혼전 남자친구와 동거를 하는 여동생과 이를 반대하고 감시하는 언니의 이야기를 다룬 성애 영화', 'https://image.tmdb.org/t/p/w500/u0xVE715SrPsJThL4xhUJnQQOfC.jpg', 2019, 0, 0, '2026-06-08 06:26:50.820219', 'KR');
INSERT INTO public.movies VALUES (4075, 852370, '아이돌 승하의 19금 AV를 찍자', '["Drama"]', 'Kim Ho', '["Seung Ha", "Yoo Jung", "Si Woo", "Kang Seo"]', 'AV도 연습이 필요해!  성인영화 제작비를 배상할 위기에 처한 촬영감독 나은과 연출자 영태. 엉망이 된 촬영을 서로에게 탓하기 바쁘다. 재촬영을 하기에 앞서 나은은 영태에게 직접 배우가 돼서 촬영 연습을 하자 제안한다. 부끄러워하는 영태를 능숙하게 리드해나가는 나은. 연습의 끝은 어디까지일까...?', 'https://image.tmdb.org/t/p/w500/4CVYNzGwTMgOKxycg2LQO9slwfH.jpg', 2021, 0, 0, '2026-06-08 06:26:41.265217', 'KR');
INSERT INTO public.movies VALUES (4078, 110415, '설국열차', '["Action", "Sci-Fi", "Drama"]', 'Bong Joon Ho', '["Chris Evans", "Song Kang-ho", "Ed Harris", "John Hurt", "Tilda Swinton"]', '기상 이변으로 모든 것이 꽁꽁 얼어붙은 지구, 살아남은 사람들을 태운 기차 한 대가 끝없이 궤도를 달리고 있다. 춥고 배고픈 사람들이 바글대는 빈민굴 같은 꼬리칸, 그리고 선택된 사람들이 술과 마약까지 즐기며 호화로운 객실을 뒹굴고 있는 앞쪽칸. 열차 안의 세상은 결코 평등하지 않다. 기차가 달리기 시작한 17년째, 꼬리칸의 젊은 지도자 커티스는 긴 세월 준비해 온 폭동을 일으킨다. 기차의 심장인 엔진을 장악하고 기차 전체를 해방시키기 위해 절대권력자 윌포드가 도사리고 있는 엔진 칸을 향해 질주하는 커티스와 꼬리칸 사람들. 그들 앞에 예기치 못한 상황들이 기다리고 있는데...', 'https://image.tmdb.org/t/p/w500/jw66dQvYyXkZNA0bJ7nKvua9jDr.jpg', 2013, 0, 0, '2026-06-08 06:26:43.299303', 'KR');
INSERT INTO public.movies VALUES (4073, 572164, '엑시트', '["Action", "Comedy"]', 'Lee Sang-geun', '["Cho Jung-seok", "Yoona", "Goh Doo-shim", "Park In-hwan", "Kim Ji-young"]', '대학교 산악 동아리 에이스 출신이지만 졸업 후 몇 년째 취업 실패로 눈칫밥만 먹는 용남은 온 가족이 참석한 어머니의 칠순 잔치에서 연회장 직원으로 취업한 동아리 후배 의주를 만난다. 어색한 재회도 잠시, 칠순 잔치가 무르익던 중 의문의 연기가 빌딩에서 피어 오르며 피할 새도 없이 순식간에 서울 도심은 유독가스로 뒤덮여 일대혼란에 휩싸이게 된다. 용남과 의주는 산악 동아리 시절 쌓아 뒀던 모든 체력과 스킬을 동원해 탈출을 향한 기지를 발휘하기 시작하는데…', 'https://image.tmdb.org/t/p/w500/7GTwjMaEVLbDBkg6McEizHTH1PF.jpg', 2019, 0, 0, '2026-06-08 06:26:39.937943', 'KR');
INSERT INTO public.movies VALUES (4149, 386716, '젊은 엄마 3', '["Romance"]', 'Chae Gil-byeong', '["Kim Jeong-ah", "Kim Ha-rae", "Yeong Ah", "Song Yo-sep"]', '잠든 새 엄마의 옷 속으로 그의 손이 들어갔다.INSERT INTO public.movies VALUES (4167, 2440, '공동경비구역 JSA', '["Drama", "Thriller", "Action"]', 'Park Chan-wook', '["Lee Young-ae", "Lee Byung-hun", "Song Kang-ho", "Kim Tae-woo", "Shin Ha-kyun"]', '비무장지대 수색 중 지뢰를 밟아 대열에서 낙오된 이수혁 병장은 북한군 중사 오경필과 전사 정우진의 도움으로 다행히 목숨을 건진다. 이를 계기로 그들은 친해졌고 이수혁 병장은 군사분계선을 넘어 그들을 만나러 간다. 그러던 어느날 그들이 만나는 장면을 북한군에게 들키고 친형제처럼 친하게 지내던 그들은 서로 총부리를 겨눈다. 그리고 판문점 공동경비구역 내 북한 초소에서 총성이 울린다. 사건의 진상을 밝히기 위해 중립국 감독위원회 소속의 한국계 스위스인 소피 장 소령이 파견된다. 그녀는 진실을 밝히기 위해 그들을 만나는데...', 'https://image.tmdb.org/t/p/w500/6pZw6KFwrADsS4HYfJe8AHMwpQh.jpg', 2000, 0, 0, '2026-06-08 06:27:56.6138', 'KR');
INSERT INTO public.movies VALUES (4170, 118451, '은교', '["Drama", "Romance"]', 'Jung Ji-woo', '["Park Hae-il", "Kim Moo-yul", "Kim Go-eun", "Jeong Man-sik", "Park Chul Hyeon"]', '한적한 산 속, 제자이자 이적요를 아버지처럼 모시는 소설가 서지우만이 드나드는 노시인 이적요의 집에 어느 날 우연히 여고생 은교가 나타난다. 집안일을 돕게 된 은교가 맑은 웃음소리를 내고, 이적요는 그녀의 젊고 순수하면서도 관능미를 갖고 있는 싱그러운 육체에 매료된다. 한편 스승을 존경하는 한편 손에 잡히지 않는 스승의 재능과 소녀 은교를 향한 질투심으로 갈등하는 제자의 열패감도 소리없이 늘어가며, 질투와 매혹으로 뒤얽힌 세 사람의 숨겨진 이야기가 펼쳐지는데...', 'https://image.tmdb.org/t/p/w500/tyT8i7zOfMvge8cOoYin0wLSHeL.jpg', 2012, 0, 0, '2026-06-08 06:27:58.647495', 'KR');
INSERT INTO public.movies VALUES (4180, 94047, '마이웨이', '["Drama", "Action", "History"]', 'Kang Je-kyu', '["Jang Dong-gun", "Joe Odagiri", "Fan Bingbing", "Kim In-kwon", "Lee Yeon-hee"]', '1938년 경성. 제 2의 손기정을 꿈꾸는 조선청년 준식과 일본 최고의 마라톤 대표선수 타츠오. 어린 시절부터 서로에게 강한 경쟁의식을 가진 두 청년은 각각 조선과 일본을 대표하는 세기의 라이벌로 성장한다. 그러던 어느 날, 준식은 예기치 못한 사건에 휘말려 일본군에 강제 징집되고 그로부터 1년 후, 일본군 대위가 된 타츠오와 운명적인 재회를 하게 된다. 2차 세계대전의 거대한 소용돌이에 던져진 두 청년은 중국과 소련, 독일을 거쳐 노르망디에 이르는 12,000Km의 끝나지 않는 전쟁을 겪으며 점차 서로의 희망이 되어가는데… 적으로 만나 서로의 희망이 된 조선과 일본의 두 청년 국적을 초월한 인간애의 드라마가 시작된다!', 'https://image.tmdb.org/t/p/w500/iMtEu7346RUV26OMwoqOPHrKERe.jpg', 2011, 0, 0, '2026-06-08 06:28:06.413247', 'KR');
INSERT INTO public.movies VALUES (4111, 479718, '범죄도시', '["Action", "Crime", "Thriller"]', 'Kang Yun-sung', '["Don Lee", "Yoon Kye-sang", "Jo Jae-yun", "Choi Gwi-hwa", "Lim Hyung-jun"]', '2004년 서울. 중국 하얼빈에서 활동하다 피신한 신흥 범죄조직의 악랄한 보스 장첸. 가리봉동 일대로 넘어온 장첸과 그의 일당들은 단숨에 기존 조직들을 장악하고 가장 강력한 세력인 춘식이파 보스 황사장까지 위협하며 도시 일대의 최강자로 급부상한다. 한편 대한민국을 뒤흔든 장첸 일당을 잡기 위해 오직 주먹 한방으로 도시의 평화를 유지해 온 괴물형사 마석도와  인간미 넘치는 든든한 리더 전일만 반장이 이끄는 강력반은 눈에는 눈 방식의  소탕 작전을 기획하는데...', 'https://image.tmdb.org/t/p/w500/sVwbHA4nhw389PwpDzkJam4WMoB.jpg', 2017, 0, 0, '2026-06-08 06:27:10.292727', 'KR');
INSERT INTO public.movies VALUES (4128, 471564, '부부의 스폰서', '["Drama", "Romance"]', 'Hwang Seong-wook', '["Jeong Neom-chyeo", "Kim Jin-seon", "Lee Hae-jin", "Lee Sin-woo"]', '기업체 기획실 과장인 ‘지현우’와 만년 과장인 ‘장명수’는 승진에서 탈락하면 둘 중 한 명은 명퇴를 해야 한다는 ‘한상무’의 지시를 받는다. 장과장이 여성 편력이 강한 한상무에게 성 로비를 제공하여 부장으로 승진 할 거라는 소문이 사내에 퍼지자 현우는 긴장한다. 현우는 승진 대상자를 추천하는 한상무에게 잘 보이려고 노력해 보지만 별 성과가 없자 자신의 옛 연인 ‘지현’과 모종의 거래를 맺고 한상무를 자신의 집으로 유인하여 지현을 아내라고 소개한다. 지현의 농염한 연기와 관능적인 몸매에 푹 빠진 한상무. 한편, 내조를 잘하지 못한다는 남편 현우의 핀잔에 마음이 상한 아내 ‘하나’는 승진문제로 의기소침해 하는 현우를 위해 한상무를 찾아가는데...', 'https://image.tmdb.org/t/p/w500/7zZr0lD26VxcnadkcmZ4UbHglB0.jpg', 2016, 0, 0, '2026-06-08 06:27:24.826427', 'KR');
INSERT INTO public.movies VALUES (4192, 392144, '캘린더걸', '["Romance", "Drama"]', NULL, '["Han Ga-yeong", "Lee So-hee-II", "Min Hyeok", "Kwon Yeong-ho", "Joo Yeon-seo"]', '만날 수는 없지만 자신을 바라보며 미소 짓는 캘린더 모델, 나영(한가영) 이 있어 종무(민혁)는 행복하다. 그러던 어느 날, 꿈에만 그리던 그녀가 옆집으로 이사를 오게 되고 종무의 무미건조한 삶은 활력으로 가득 찬다. 화려함 속에 감춰져 있던 그녀의 힘든 삶을 알게 된 종무는 목숨을 걸고 그녀를 위하려 하고 그의 순수하고 진실한 마음에 나영은 일과 사랑 사이에서 갈등한다. 한편, 종무의 친구 용진(권영호)은 애교 덩어리 여자친구 지희(이소희)와의 화끈한 하룻밤을 꿈꾸지만 사랑을 시도할 때마다 죽음의 기로에 서게 되고, 지희는 결국 그 동안 숨겨왔던 비밀을 고백하게 되는데..  두 커플의 목숨 건 사랑이 시작된다!', 'https://image.tmdb.org/t/p/w500/nh0p19vCPiuueRCgOaiMFIjNdSw.jpg', 2016, 0, 0, '2026-06-08 06:28:15.571927', 'KR');
INSERT INTO public.movies VALUES (4202, 740441, '스마트폰을 떨어뜨렸을 뿐인데', '["Thriller", "Crime", "Mystery"]', 'Kim Tae-joon', '["Chun Woo-hee", "Yim Si-wan", "Kim Hie-won", "Park Ho-san", "Kim Ye-won"]', '회사원 나미는 퇴근길, 자신의 분신과도 같은 스마트폰을 잃어버린다. 스마트폰을 주운 준영은 나미의 폰에 스파이웨어를 설치한 뒤 돌려준다. 나미의 스마트폰으로 취미, 취향, 직업, 동선, 경제력, 인간관계 등 나미의 모든 것을 알아낸 준영은 정체를 숨긴 채, 나미에게 접근한다. 한편, 살인 사건을 쫓는 형사 지만은 사건 현장에서 아들 준영의 흔적을 발견하고, 그가 범인일지도 모른다는 불길한 직감으로 준영을 몰래 조사하기 시작한다. 스마트폰을 찾았다는 기쁨도 잠시, 그날 이후 나미의 평범했던 일상은 점점 파국으로 치닫는데…', 'https://image.tmdb.org/t/p/w500/nAK839maBC4QdWSymeUXYXIGZ49.jpg', 2023, 0, 0, '2026-06-08 06:28:23.63039', 'KR');
INSERT INTO public.movies VALUES (4227, 290865, '타짜: 신의 손', '["Crime", "Drama"]', 'Kang Hyoung-chul', '["T.O.P", "Shin Sae-kyeong", "Kwak Do-won", "Lee Hanee", "Yoo Hai-jin"]', '삼촌 고니의 승부욕과 손재주를 닮은 대길은 노름판에서 미나를 보고 첫눈에 사랑에 빠지지만 바로 그 다음날 불미스러운 일에 연루되어 동네를 떠나게 된다. 강남의 하우스에 입성하게 된 대길은 타고난 기술과 매력을 활용해 선수로 급성장한다. 배신과 음모가 판을 치는 노름판에서 우 사장을 만나 사랑에 빠지지만 순진했던 그의 마음은 이용만 당한 채 버려진다. 황당한 액수의 채무와 장기 탈취 등으로 노름판 밑바닥까지 내려가게 된 대길은 우연히 고광렬을 만나고 노름판의 패가 아닌 노름꾼의 눈을 읽는 기술을 터득하게 되면서 재기의 발판을 다지게 된다.', 'https://image.tmdb.org/t/p/w500/pqvIcZWo1syeTXBMVGNqerJ32Co.jpg', 2014, 0, 0, '2026-06-08 06:28:43.390495', 'KR');
INSERT INTO public.movies VALUES (4252, 958263, '독전 2', '["Thriller", "Action", "Crime"]', 'Baik', '["Cho Jin-woong", "Cha Seung-won", "Han Hyo-joo", "Oh Seung-hoon", "Lee Zoo-young"]', '아직 추적은 끝나지 않았다. 집념에 불타는 형사가 아시아 최대 마약 조직의 진실과 그 실체를 찾기 위해 수사를 이어간다.', 'https://image.tmdb.org/t/p/w500/h3G2rjJoOOMOKweAY3YTK0Tnaa0.jpg', 2023, 0, 0, '2026-06-08 06:29:23.507602', 'KR');
INSERT INTO public.movies VALUES (4318, 436391, '군함도', '["Drama"]', 'Ryoo Seung-wan', '["Hwang Jung-min", "So Ji-sub", "Song Joong-ki", "Lee Jung-hyun", "Kim Su-an"]', '1945년 일제강점기, 경성 반도호텔 악단장 강옥과 그의 하나뿐인 딸 소희. 그리고 종로 일대를 주름잡던 주먹 칠성, 일제 치하에서 온갖 고초를 겪어온 말년 등 각기 다른 사연을 품은 조선인들이 일본에서 돈을 벌 수 있다는 말에 속아 군함도로 향한다. 하지만 그들이 함께 탄 배가 도착한 곳은 조선인들을 강제 징용해 노동자로 착취하고 있던 지옥섬 군함도였다. 영문도 모른 채 끌려온 조선인들이 해저 1,000 미터 깊이의 막장 속에서 매일 가스 폭발의 위험을 감수하며 노역해야 하는 군함도. 강옥은 어떻게 하든 일본인 관리의 비위를 맞춰 딸 소희만이라도 지키기 위해 온갖 수를 다하고, 칠성과 말년은 각자의 방식으로 고통스런 하루하루를 견뎌낸다. 한편 전쟁이 막바지로 치닫자 광복군 소속 OSS 요원 무영은 독립운동의 주요인사 구출 작전을 지시 받고 군함도에 잠입하는데...', 'https://image.tmdb.org/t/p/w500/t0rdNh51Rdnxr56vdeHuN8eK9Ig.jpg', 2017, 0, 0, '2026-06-08 06:30:12.651605', 'KR');
INSERT INTO public.movies VALUES (4279, 944496, '동서의 손맛', '["Drama"]', 'Choi Jung-ja', '["Kim Ji-ah", "Kim Min-jeong", "James", "Gil Dong"]', '신혼부부인 아영과 광수는 절벽 끝에 몰려있었다.  동생인 광춘의 산장에 작은 식당을 개업한 지 벌써 5개월째, 손님 하나 들지 않는 불경기에 고민하던 형 광수는 밀린 가게세를 내기 위해 주차 알바까지 나서게 되고, 이 사실을 전해 들은 광춘은 장사가 안정될 때까지 가게세를 면제해 주겠노라며 호의를 배푸는데... 그런 광춘의 친절에는 다른 목적이 있었으니, 이미 오래전부터 어리고 예쁜 형수 아영에게 눈독을 들이고 있었던 것!  광춘은 생활고에 시달리던 아영의 약점을 집요하게 파고들며 육체관계를 요구해오고, 아영은 남편과의 결혼생활을 지키기 위해 광춘과의 추악한 섹스를 허락한다. 낮에는 시동생의 성적 노리개로, 밤에는 식당의 정숙한 안주인으로... 아영이 위험한 외줄타기를 하며 남편과 시동생의 침실을 오가는 사이, 남편의 외도를 의심하던 효성은 그 상대가 어린 손윗동서라는 사실에 경악하며 잔혹한 복수를 결심하는데, 과연 동서로 만난 두 여자는 거미줄처럼 얽혀버린 가족의 굴레에서 벗어나 진정한 행복을 찾을 수 있을까?', 'https://image.tmdb.org/t/p/w500/ssUdVy15wdX8TgsDmwNH5mleUJE.jpg', 2021, 0, 0, '2026-06-08 06:29:44.109814', 'KR');
INSERT INTO public.movies VALUES (4313, 453133, '형님아내 3: 아랫집 부인', '["Drama"]', 'Lee Dol', '["Ahn So-hee", "Sang Woo", "Wi Ji-Woong", "Lee Eun-mi", "Hayashi Risa"]', '새집으로 누나와 이사했다. 별로 뛰지도 않았는데 밑에 집 여자가 올라와, 예민해서INSERT INTO public.movies VALUES (4258, 18438, '김씨 표류기', '["Drama", "Comedy", "Romance"]', 'Lee Hae-jun', '["Jung Jae-young", "Jung Ryeo-won", "Yang Mi-kyung", "Lee Sang-hun", "Jang So-yeon"]', '자살시도가 실패로 끝나 한강의 밤섬에 불시착한 남자. 죽는 것도 쉽지 않자 일단 섬에서 살아보기로 한다. 모래사장에 쓴 HELP가 HELLO로 바뀌고 무인도 야생의 삶도 살아볼 만하다고 느낄 무렵, 익명의 쪽지가 담긴 와인병을 발견하고 그의 삶은 알 수 없는 희망으로 설레기 시작한다. 한편 자신의 좁고 어두운 방이 온 지구이자 세상인 여자. 홈페이지 관리, 하루 만보 달리기 등 그녀만의 생활리듬도 있다. 유일한 취미인 달사진 찍기에 열중하던 어느 날, 저 멀리 한강의 섬에서 낯선 모습을 발견하고 그에게 리플을 달아주기로 하는 그녀는 3년 만에 자신의 방을 벗어나 그를 향해 달려가는데...', 'https://image.tmdb.org/t/p/w500/jRrdzFcJUTz9yb6A5quSQrvhJDB.jpg', 2009, 0, 0, '2026-06-08 06:29:28.095304', 'KR');
INSERT INTO public.movies VALUES (4359, 131926, '몽정기 2', '["Comedy"]', 'Zeong Cho-sin', '["Song Eun-Chae", "Lee Ji-hoon", "Jeon Hye-bin", "Shin Joo-ah", "Kim Ji-young"]', '성(性)에 대해 생기초도 모르는 오성은, 그래도 셋 중에 가장 많이 아는 방수연, 아는 듯 모르는 듯 속을 알 수 없는 김미숙. 이들 3인방은 누구도 확실하게 이야기해 주지 않고, 어디서도 화끈하게 보여주지 않는 것들(?)에 대한 야릇한 호기심에 목말라 있다. 모락모락 피어오르는 이 성적 호기심이 여고 3인방의 머리 속에서 떠나지 않고 있을 때, 그녀들 눈앞에 최상의 작업모드와 왕뽀대를 자랑하는 교생 강봉구가 나타난다.  소녀들의 이 야릇한 호기심을 해결해 줄 ‘운명의 남자’로 점 찍힌 교생 봉구씨는 순식간에 그녀들의 직접 관찰(?), 실험(?) 대상이 된다. 봉구씨를 사로잡기 위해 호기심 3인방은 ‘뽕브라 하고 냅다 달려들기’, ‘귀에 신음소리 내기’, ‘교복 치마 7단 접기’, ‘봉구씨 거시기 훔쳐보기’ 등 나름 고난이도 섹시 테크닉을 총동원해 도발을 펼쳐보지만 어찌된 일인지 봉구씨는 꿈쩍도 안한다.  게다가 얼짱몸짱(=왕재수) 여고생 탤런트 백세미까지 봉구씨를 찜하면서 상황은 더 꼬여만 간다. 그녀들이 아무리 도발해도 먹히지 않았던 그이지만, 백세미의 ‘수업시간에 교복 단추 풀어헤치기’, ‘팔짱 끼는 척 가슴 문지르기’, ‘아이스크림 핥아먹기’ 등의 섹시 도발에는 꺼뻑 꺼뻑 넘아가다니!!. 더군다나 불여우 백세미는 대놓고 성은에게 아직 초경도 못한 어린애라고 놀리기까지. 질 수 없다! 마지막 수단, 이젠 봉구씨 덮치기다!', 'https://image.tmdb.org/t/p/w500/w10M0egcmloikhqdIGyHAQmtnO0.jpg', 2005, 0, 0, '2026-06-08 06:30:42.124373', 'KR');
INSERT INTO public.movies VALUES (4363, 793058, '하이파이브', '["Action", "Adventure", "Comedy", "Fantasy"]', 'Kang Hyoung-chul', '["Lee Jae-in", "Ahn Jae-hong", "Yoo Ah-in", "Ra Mi-ran", "Kim Hie-won"]', '태권소녀 완서, 작가 지망생 지성, 후레쉬 매니저 선녀,  FM 작업반장 약선 그리고 힙스터 백수 기동. 의문의 장기 기증자로부터 각각 심장과 폐, 신장, 간, 각막을 이식받은 다섯 사람. 그런데 건강해진 몸과 함께 생각지도 못한 초능력이 덤으로 딸려왔다! 자신만의 표식을 통해 서로의 존재를 확인하고 한 팀을 결성하기로 의기투합하지만 능력도 성격도 취향도 제각각, 모이기만 하면 다툼과 사고가 끊이지 않는다. 한편, 췌장을 이식받고 마찬가지로 특별한 능력을 얻게 된 새신교 교주 영춘은 평생 꿈꿔온 절대자가 되기 위해 나머지 이식자들을 찾아 나서는데…', 'https://image.tmdb.org/t/p/w500/xpqa2ShXecFxMUGKv82Zx56ZoUD.jpg', 2025, 0, 0, '2026-06-08 06:30:45.153279', 'KR');
INSERT INTO public.movies VALUES (4404, 361539, '함정', '["Thriller", "Drama", "Crime", "Horror"]', 'Kwon Hyung-jin', '["Don Lee", "Kim Min-kyung", "Jo Han-sun", "Ji an", "Lim Jeong-woon"]', '5년째 아이가 없는 부부, 준식과 소연. 소연은 기분 전환을 위해 준식과 휴대폰도 터지지 않는 외딴 섬으로 여행을 떠나고, 그 곳에서 인터넷을 통해 우연히 알게 된 한 맛집에 가게 된다.  그곳의 허름하고 험악한 분위기의 불안한 기운이 감돌지만 이들이 온 것을 눈치챈 주인 성철은 보자마자 너무나도 친절하게 대하고 준식과 소연은 점점 경계를 풀게 된다.  화기애애한 분위기 속에 해가 지고 성철의 환대에 준식과 소연은 하룻밤만 묵고 가기로 하는데, 이때부터 의문의 묘한 분위기가 이들을 덮쳐오기 시작한다.  그 때 성철은 소연을 알아보는 듯 하며 알 수 없는 말을 건네는데...  함정에 빠뜨리려는 자와 빠져 나가려는 자의 목숨을 건 대결이 시작된다!', 'https://image.tmdb.org/t/p/w500/vI6dRKxESSnXJWsP7F7XYkZTnXS.jpg', 2015, 0, 0, '2026-06-08 06:31:17.220673', 'KR');
INSERT INTO public.movies VALUES (4381, 333167, '순수의 시대', '["Romance", "Drama", "History"]', 'Ahn Sang-hoon', '["Jang Hyuk", "Kang Hanna", "Shin Ha-kyun", "Kang Ha-neul", "Son Byung-ho"]', '1398년, 태조 이성계는 제 손에 피를 묻혀 개국을 일군 왕자 이방원이 아닌 어린 막내 아들을 정도전의 비호 하에 세자로 책봉하고, 왕좌와 권력을 둘러 싼 핏빛 싸움이 예고된다. 한편, 정도전의 사위이자 태조의 사위 진을 아들로 둔 장군 김민재는 북의 여진족과 남의 왜구로부터 끊임없이 위태로운 조선의 국경선을 지켜낸 공로로 군 총사령관이 된다. 왕이 될 수 없었던 왕자 이방원, 여진족 어미 소생으로 정도전의 개로 불린 민재와 그의 친자가 아니라는 비밀 속에 쾌락만을 쫓는 부마 진. 민재는 어미를 닮은 모습의 기녀 가희에게서 난생 처음 지키고 싶은 제 것을 발견한다. 하지만 그의 최초의 반역, 야망의 시대를 거스르는 그의 순수는 난세의 한 가운데 선 세 남자와 막 태어난 왕국 조선의 운명을 바꿀 피 바람을 불러온다.', 'https://image.tmdb.org/t/p/w500/rtNhTmR2sfl9PUqCHxAyzFNinG0.jpg', 2015, 0, 0, '2026-06-08 06:30:59.534174', 'KR');
INSERT INTO public.movies VALUES (4407, 701561, '이채담의 지스팟', '[]', 'Park Joo-yeong', '["Lee Chae-dam", "Jo Yong-bok"]', '여배우 이채담의 솔직하고 야한 섹스 라이프 전격 공개!  인기 성인 여배우 이채담이 그동안 숨겨왔던 그녀의 솔직하고 야한 섹스 라이프를 공개한다.  그녀의 첫 사랑, 첫 경험, 첫 작품 그리고 연기가 아닌 실제 그녀의 은밀하고 야한 성생활과 그녀의 지스팟을 공략한 최고의 섹스 파트너는 누구일지 궁금증을 자아낸다.  그녀만의 남자를 사로잡는 매력과 비법도 솔직하게 공개된다. 그녀의 은밀한 성생활과 그녀의 성감대와 오르가즘에 대하여 낱낱이 공개하는데...', 'https://image.tmdb.org/t/p/w500/tnxbYOlkXbuSXZWfHYOy4l4V51h.jpg', 2017, 0, 0, '2026-06-08 06:31:19.236335', 'KR');
INSERT INTO public.movies VALUES (39, 1311031, '극장판 귀멸의 칼날: 무한성편', '["Animation", "Action", "Fantasy"]', 'Haruo Sotozaki', '["Natsuki Hanae", "Takahiro Sakurai", "Akira Ishida", "Hiro Shimono", "Yoshimasa Hosoya"]', '혈귀로 변해버린 여동생 네즈코를 인간으로 되돌리기 위해 혈귀를 사냥하는 조직인 《귀살대》에 입대한 카마도 탄지로. 입대 후 동료인 아가츠마 젠이츠, 하시비라 이노스케와 함께 많은 혈귀와 싸우고, 성장하면서 세 사람의 우정과 유대는 깊어진다. 탄지로는 《귀살대》 최고위 검사인 《주》와도 함께 싸웠다. 「무한열차」에서는 염주・렌고쿠 쿄쥬로, 「유곽」에서는 음주・우즈이 텐겐, 「도공 마을」에서는 하주・토키토 무이치로, 연주・칸로지 미츠리와 함께 혈귀를 상대로 격렬한 전투를 벌였다. 그 후 다가올 혈귀와의 결전에 대비해 귀살대원들과 함께 《주》가 주도하는 합동 강화 훈련에 참가해 훈련을 받던 도중 《귀살대》의 본부인 우부야시키 저택에 나타난 키부츠지 무잔. 어르신의 위기에 달려온 《주》들과 탄지로였지만, 무잔의 술수로 의문의 공간으로 떨어지고 말았는데. 탄지로 일행이 떨어진 곳, 그곳은 혈귀의 본거지 《무한성》─ “귀살대”와 “혈귀”의 최종 결전의 포문이 열린다.', 'https://image.tmdb.org/t/p/w500/m6Dho6hDCcL5KI8mOQNemZAedFI.jpg', 2025, 0, 0, '2026-06-06 13:24:57.166327', 'JP');
INSERT INTO public.movies VALUES (158, 578883, 'スチュワーデス・スキャンダル　獣のように抱きしめて', '["Comedy", "Drama"]', 'Masaru Konuma', '["Tomoko Ai", "Kate Asabuki", "Shigeru Muroi", "Makoto Yoshino", "Ryosei Tayama"]', NULL, 'https://image.tmdb.org/t/p/w500/rXP4QwEZFwlBawT6V2QHkshLOnI.jpg', 1984, 0, 0, '2026-06-06 13:25:01.817147', 'JP');
INSERT INTO public.movies VALUES (278, 564, '미이라', '["Adventure", "Action", "Fantasy"]', 'Stephen Sommers', '["Brendan Fraser", "Rachel Weisz", "John Hannah", "Arnold Vosloo", "Patricia Velásquez"]', '고대 이집트의 파라오 중 가장 영화를 누렸던 세티 1세의 시대. 세티 1세의 정부인 앙크수나문과 세티 1세의 총애을 한몸에 받던 승정원 이모탭은 금지된 사랑에 빠진다. 그러나 그들의 운명적인 사랑은 얼마되지 않아 파라오에게 발각되고 이에 앙크수나문은 자결하게 된다. 이모텝은 흑마서의 주문으로 그녀를 부활시키려 하지만, 파라오의 근위대에 붙잡히게 되고, ''홈다이''라는 형벌에 처해진다. 홈다이란 산 채로 석관에 갇혀 영원히 생시체가 되는 끔찍한 극형. 결국 금지된 사랑은 파라오의 저주로 비극적인 끝을 맺고 왕족들이 잠든 하무납트라는 죽음의 도시가 되어 역사 속에 묻힌다.  황금의 유물을 찾아 여러 탐험가들이 하무납트라를 찾아오지만 하나 같이 의문의 죽음을 당하고, 전투 중에 피신했던 외인부대 장교 오커넬만이 유일하게 살아남는다. 그 소식을 들은 이집트 박물관 사서 이비와 그녀의 오빠 조나단이 오커넬을 찾아오고 죽음의 도시 하무납트라에 관한 단서를 듣게 된다. 용기와 모험심으로 뭉친 세 사람은 의기 투합하여 하무납트라의 황금유물을 찾아 떠나기로 한다.  한편 파라오의 저주를 푸는 열쇠를 손에 넣은 조나단은 실수로 이모텝을 부활시키고, 마침내 3천년을 기다려온 엄청난 분노가 온 이집트를 뒤덮는데. 아무것도 모르는 세 사람은 죽음과 저주의 왕국 한 가운데에서 살아난 미이라와의 사투를 벌인다.', 'https://image.tmdb.org/t/p/w500/31lxBgDl51HYnAnIV41aPyK4em7.jpg', 1999, 0, 0, '2026-06-06 13:25:06.420237', 'US');
INSERT INTO public.movies VALUES (317, 122917, '호빗: 다섯 군대 전투', '["Action", "Adventure", "Fantasy"]', 'Peter Jackson', '["Ian McKellen", "Martin Freeman", "Richard Armitage", "Orlando Bloom", "Evangeline Lilly"]', '빌보 배긴스와 참나무 방패 소린, 난쟁이 족이 떠난 거대한 여정의 끝에 난쟁이 족은 원래 자신들의 터전이던 에레보르에 있는 엄청난 보물을 되찾지만 이는 무시무시한 용 스마우그가 호수마을의 무기력한 주민들을 공격하게 되는 결과를 낳는다. 소린은 탐욕에 서서히 눈이 멀어 우정과 명예를 저버린 채 왕의 보물 아르켄스톤을 찾는다. 암흑의 군주 사우론은 오크 군대를 보내 외로운 산에 기습 공격을 감행한다. 마침내 다섯 군대의 전투가 시작되고 빌보는 본인과 친구들의 목숨을 걸고 싸워야만 하는데...', 'https://image.tmdb.org/t/p/w500/tLNTaP5kcH2FDQNxGu4EkOCpMjr.jpg', 2014, 0, 0, '2026-06-06 13:25:07.969866', 'US');
INSERT INTO public.movies VALUES (338, 263472, '노크 노크', '["Horror", "Thriller", "Crime"]', 'Eli Roth', '["Keanu Reeves", "Lorenza Izzo", "Ana de Armas", "Aaron Burns", "Colleen Camp"]', '가족에게 헌신적이고 누구보다 아내와 아이들을 사랑하는 성공한 건축가 에반(키아누 리브스)은 휴일을 맞아 여행을 떠난 가족들을 뒤로 하고 홀로 집에 남아 오랜만의 한적함에 젖어 든다. 작업에 열중하고 있던 에반은 폭우 속에 똑똑 문을 두들기는 소리를 듣고 낯선 두 여자와 처음 마주하게 된다. 비에 온몸이 젖은 육감적인 모습의 두 여자, 제네시스(로렌자 이조)와 벨(아나 드 아르마스)은 에반의 호의에 집으로 들어와 젖은 몸을 녹이게 되고 에반의 계속되는 호의 속에 서서히 끈적한 눈빛을 건네기 시작하는데...', 'https://image.tmdb.org/t/p/w500/8hjIz6BkZiBSeuHYs1e8eO0w489.jpg', 2015, 0, 0, '2026-06-06 13:25:08.718673', 'US');
INSERT INTO public.movies VALUES (315, 1367642, '리마인더스 오브 힘', '["Romance", "Drama"]', 'Vanessa Caswill', '["Maika Monroe", "Tyriq Withers", "Rudy Pankow", "Bradley Whitford", "Lauren Graham"]', '한순간의 비극적인 사고로 남자친구 ‘스코티’와 모든 것을 잃은 ‘케나 로완’. 수년 간의 수감 생활을 마치고 출소한 그녀는, 수감 도중 출산했지만 한 번도 품에 안아보지 못한 딸 ‘디엠’을 만나기 위해 고향으로 돌아온다. 하지만 사고로 아들을 잃은 ‘스코티’의 부모는 ‘케나’를 여전히 모든 비극의 원인으로 여기며 냉정하게 외면한다. 그런 그녀 앞에 ‘스코티’의 오랜 친구이자 ‘디엠’을 돌보고 있는 ‘레저’가 나타나고, 두 사람은 함께 시간을 보내며 점차 가까워진다. ‘레저’를 향한 감정이 깊어지면서 혼란에 빠진 ‘케나’는 이제 자신이 내린 선택과 과거의 실수를 진정으로 용서받을 방법을 찾아야만 하는데…', 'https://image.tmdb.org/t/p/w500/dnuiFWiogHw1fmIDdwkVkLkzzFM.jpg', 2026, 0, 0, '2026-06-06 13:25:07.965313', 'US');
INSERT INTO public.movies VALUES (418, 1402, '행복을 찾아서', '["Drama"]', 'Gabriele Muccino', '["Will Smith", "Jaden Smith", "Thandiwe Newton", "Brian Howe", "James Karen"]', '미국 샌프란시스코. 의료기 세일즈맨 크리스 가드너(윌 스미스)는 여기저기 열심히 뛰어다니지만 한물간 의료기기는 좀처럼 팔리지 않는다. 아들 크리스토퍼(제이든 스미스)는 엉터리 유치원에서 하루종일 엄마를 기다리다 잠들기 일쑤. 세금도 못내는 형편에 자동차까지 압류당하자 참다 지친 아내마저 두사람을 떠나버린다. 살던 집에서도 쫓겨난 크리스와 크리스토퍼. 이제 지갑에 남은 전재산이라곤 달랑 21달러 33센트 뿐.  전재산 21달러…  돌아갈 집도 없지만 꿈이 있다면 지켜내야 한다!  극한 상황에서도 크리스토퍼를 보살피던 크리스는 빨간색 페라리를 모는 성공한 주식중개인을 만나 ‘남이 할 수 있다면, 나도 할 수 있다’는 희망과 함께 주식중개인 인턴에 지원한다. 덜컥 붙긴 했지만 땡전 한푼 못받는 무보수에 60대 1이라는 엄청난 경쟁을 이겨내야 하는 혹독한 과정. 학력도 경력도 내세울 것 없지만 크리스는 아들과 함께 노숙자 시설과 지하철 화장실을 전전하는 어려움 속에서도 행복을 찾기 위한 위한 마지막 기회에 도전하게 되는데…', 'https://image.tmdb.org/t/p/w500/uRMMtYZkWyqsc4AO4aCoHBbZSwL.jpg', 2006, 0, 0, '2026-06-06 13:25:11.803497', 'US');
INSERT INTO public.movies VALUES (394, 293660, '데드풀', '["Action", "Adventure", "Comedy"]', 'Tim Miller', '["Ryan Reynolds", "Morena Baccarin", "Ed Skrein", "T.J. Miller", "Gina Carano"]', '특수부대 요원 출신의 용병 웨이드 윌슨은 취향과 장난기마저 똑 닮은 바네사를 만나 행복한 나날을 보낸다. 하지만 행복은 광고처럼 짧은 법. 말기 암 선고를 받은 웨이드는 비밀 임상실험에 참여하며 재기를 노린다. 극한의 고문으로 이뤄진 실험 후 웨이드는 암을 치료할뿐더러 무한한 재생 능력을 얻으며 불사의 존재가 된다. 하지만 동시에 부작용으로 호러영화에 어울릴 법한 외양을 갖는다. 스스로 슈트까지 지어 입고 데드풀이 된 웨이드는 자신을 고문한 자를 찾아 제대로 복수한 뒤 당당히 바네사 앞에 나서려 한다.', 'https://image.tmdb.org/t/p/w500/k1e0TlvDM4KsiSRyJENVrHxMqtK.jpg', 2016, 0, 0, '2026-06-06 13:25:11.037558', 'US');
INSERT INTO public.movies VALUES (3188, 6312, '늑대의 후예들', '["Adventure", "Horror", "Action", "History"]', 'Christophe Gans', '["Samuel Le Bihan", "Vincent Cassel", "Émilie Dequenne", "Monica Bellucci", "Jérémie Renier"]', '1765년 프랑스 남부 산악지대 제보당에 야수가 출현하여 마을의 여자와 어린아이들을 무참히 살해한다. 1년이 지나자 100여명의 사상자를 낸 야수의 소문은 프랑스 전역으로 번지고 루이 15세는 긴급히 프롱삭 기사와 모호크족 전사 마니를 밀사로 파견한다. 주민들은 늑대의 소행이라고 단언하지만, 프롱삭은 시체의 몸에 박힌 금속성의 물질과 구사 일생으로 살아남은 자들의 증언으로 미루어볼 때 늑대보다 거대한 몸집을 지닌 정체를 알 수 없는 야수라고 추측하게 된다. 흔적도 없이 사라지는 야수를 잡기위해 마침내 6000프랑의 상금을 내건 프랑스 최대 규모의 야수 사냥 대회가 열리지만 늑대가 떼죽음 당하고 무고한 주민 12명이 희생되었지만 야수는 잡지 못한 채 끝이 난다. 프롱삭 주변에는 묘한 분위기의 사람들이 하나 둘씩 나타나는데.  제보당에 도착한 첫날 프롱삭은 연회에서 백작의 딸 마리안을 만나 첫눈에 반한다. 프롱삭을 못마땅하게 여긴 음침한 분위기의 그녀의 오빠 장(뱅상 카셀 분)은 사사건건 프롱삭과 부딪히게 된다. 고급 요정에서 만난 신비로운 분위기의 창녀 실비아(모니카 벨루치 역)는 프롱삭에게 알 수 없는 단서들을 던져주고. 사건의 실마리는 점점 더 안개처럼 희미해져가고 프롱삭에게 접근하는 실비아와 장 그리고 악마적인 분위기의 집시들의 행동은 거세어져 간다. 어느날 야수를 쫓던 모호크족의 전사 마니가 집시들과의 격렬한 전투 도중 비참한 최후를 맞자 프롱삭은 심한 갈등과 혼란에 휩싸이게 되는데.', 'https://image.tmdb.org/t/p/w500/u83MAfeYqTX8FmWiCwtth2on8Xg.jpg', 2001, 0, 0, '2026-06-08 06:24:07.255698', 'FR');
INSERT INTO public.movies VALUES (590, 5879, '감각의 제국', '["Drama", "Romance"]', 'Nagisa Ōshima', '["Eiko Matsuda", "Tatsuya Fuji", "Aoi Nakajima", "Yasuko Matsui", "Meika Seri"]', '나가노의 요리점 <요시다야>에서 일하는 여종업원인 사다는 그 곳에서 주인인 이시다 기치조를 만나게 된다. 그녀는 순식간에 그와 격정적인 정사를 나누고픈 욕망에 빠져든다. 첫눈에 반한 두 사람은 늦은 밤 응접실이나 객실 등에서 지속적으로 밀회를 나누다가 기치조의 아내에게 발각된다. 결국 사다는 요리점을 나갈 수 밖에 없는 상황에 놓이자 기치조의 부인을 속이고 도망을 나와 요정 마사키에 틀어박혀 격렬한 사랑을 수 차례 나누게 된다. 두 사람의 사랑은 애정을 넘어서 서로의 육체에 대한 집착으로 나타나고, 결국 사다는 기치조를 영원히 자신의 남자로 만들고 싶다는 욕망에 사로잡히게 되는데...', 'https://image.tmdb.org/t/p/w500/kmGFNOo1ls61APUNtMyH8FY7YYL.jpg', 1976, 0, 0, '2026-06-06 13:25:18.769776', 'FR');
INSERT INTO public.movies VALUES (647, 18, '제5원소', '["Sci-Fi", "Action", "Adventure"]', 'Luc Besson', '["Bruce Willis", "Milla Jovovich", "Gary Oldman", "Ian Holm", "Chris Tucker"]', '1914년 이집트. 한 노학자가 피라미드의 벽에 새겨진 5개 원소의 비밀을 밝혀낸다. 2259년 뉴욕. 지구에 거대한 행성이 다가와 대통령을 비롯한 전 군대는 비상상태에 빠진다. 지구를 구할 4개 원소를 가진 몬도샤인들은 지구로 오는 도중에 모두 죽게 되고 과학자들은 남은 팔로 유전자 합성을 통해 빨간 머리 소녀 리루를 만든다. 리루는 과학자들에게서 도망치던 중 전직 연방 요원인 코벤을 만나고, 두 사람은 4개 원소를 찾기 위해 피라미드의 예언을 알고 있는 코넬리우스 신부와 함께 파라다이스 행성으로 간다. 한편 무기상인 조르그도 4개 원소를 손에 넣기 위해 그들을 뒤쫓는데...', 'https://image.tmdb.org/t/p/w500/npcHgyp5MmKMe4lWqJi2ma1CuhC.jpg', 1997, 0, 0, '2026-06-06 13:25:21.104841', 'FR');
INSERT INTO public.movies VALUES (820, 4561, '스토리 오브 O: 르네의 사생활', '["Drama"]', 'Just Jaeckin', '["Corinne Cléry", "Udo Kier", "Alain Noury", "Anthony Steel", "Jean Gaven"]', '젊고 아름다운 여류 사진 작가 0(O: 코린 클레이 분)는 매력적인 연인 르네(Rene: 유두 키에르 분)에게 이끌려 파리 근교의 신비롭고 웅장한 고성 ''르와시''에 도착한다. 반나체의 여인들과 그 여인들을 지배하는 남자들로 가득한 이곳은 성에 의해 존재하고 성에 의해 지배당하는 새로운 세계. 르네는 그녀에게 르와시에서 일어나는 모든 일에 대해 절대 복종할 것을 요구한다. 여자들을 성의 노예로 길들이는 그 곳의 남자들은 0에게 의식을 행하듯 차례로 그녀를 범하고 다른 여자들처럼 붉은 가운만을 입힌다. 남자들과 말할 수도, 바라볼 수도, 반항할 수도 없이 오직 복종만이 존재하는 것이 ''르와시''의 규칙이다. 그날부터 그녀의 몸은 구석구석 탐구 되어지고, 채찍을 맞고, 사슬에 묶인 채 밤을 지새는 등 혹독한 성적 학대를 받는다. 이 모든 것은 그녀를 훈련시키는 피에르에 의해 이루어진다. 그러나 그녀는 이 모든 것이 사랑하는 르네를 위하는 일이라고 생각하며 그들의 성적인 고문을 받아 들이고 자신의 육체가 서서히 새로운 성에 눈 뜨고 있음을 알게 된다. 밤낮 구분없이 강요되는 동물적 섹스와 수치스러운 채찍질, 엉덩이에 낙인까지 찍히는 고통속에 환희를 동시에 느끼며 새롭게 태어나는 0는 점차 변화하는 자신을 즐기며 관계를 맺는 모든 남자들을 사랑하게 된다.', 'https://image.tmdb.org/t/p/w500/hXyN2tlryPRPaF74jh8CEhRT3zu.jpg', 1975, 0, 0, '2026-06-06 13:25:27.332392', 'FR');
INSERT INTO public.movies VALUES (895, 194, '아멜리에', '["Comedy", "Romance"]', 'Jean-Pierre Jeunet', '["Audrey Tautou", "Mathieu Kassovitz", "Rufus", "Serge Merlin", "Jamel Debbouze"]', '오랜만에 느끼는 아빠의 다정한 손길에 두근거리는 심장을 심장병이라고 오해한 아빠 덕분에 학교는 구경도 못해본 아멜리에. 노틀담 성당에서 뛰어내린 관광객에 깔려 엄마가 하늘 나라로 가 버리고, 유일한 친구 금붕어마저 자살을 기도한 뒤 그녀는 정말로 외톨이가 된다. 하지만 어느날 빛 바랜 사진과 플라스틱 군인, 구슬이 가득 담긴 낡은 상자를 우연히 발견하면서, 그녀에게 마법 같은 일들이 시작된다. 주변 사람들에게 행복을 찾아주는 기쁨을 통해 삶의 행복을 발견했다고 굳게 믿던 그 순간 그녀의 심장이 또다시 두근거리기 시작하는데...', 'https://image.tmdb.org/t/p/w500/EkQ9Lu1NFnxfPSGizktuLJuxdv.jpg', 2001, 0, 0, '2026-06-06 13:25:30.422196', 'FR');
INSERT INTO public.movies VALUES (570, 11986, '베티 블루 37.2', '["Drama", "Romance"]', 'Jean-Jacques Beineix', '["Jean-Hugues Anglade", "Béatrice Dalle", "Gérard Darmon", "Consuelo De Haviland", "Clémentine Célarié"]', '별볼일 없는 서른 살의 작가 지망생 ‘조그’는 대담하고 관능적인 여인 ‘베티’를 만나고 그녀에게 걷잡을 수 없이 빠져든다. 해변에 위치한 방갈로에서 함께 살게 된 둘은 달콤한 시간을 보내며 행복감에 젖는다. 하지만 곧 삶의 무료함을 느낀 ‘베티’는 ‘조그’의 글에서 눈부신 재능을 발견하고, 그를 작가로 성공시키는데 자신의 인생을 바치기로 결심한다. 그렇게 그녀의 광기가 점차 폭발해가는데…  순수하면서도 치명적인 탐닉의 아이콘  ‘베티’를 만난 후, 모든 것이 바뀌었다.', 'https://image.tmdb.org/t/p/w500/iU8ySbTAnDkmGr9LoN1lEvqcJaq.jpg', 1986, 0, 0, '2026-06-06 13:25:17.995405', 'FR');
INSERT INTO public.movies VALUES (6126, 11845, '정사', '["Romance", "Drama", "Fantasy"]', 'Patrice Chéreau', '["Mark Rylance", "Kerry Fox", "Susannah Harker", "Alastair Galbraith", "Philippe Calvario"]', '섹스를 할 수 있는 단 하루, 매주 수요일마다 그녀를 만난다… 적막한 오후. 한 여자의 노크 소리가 남자의 낮잠을 깨운다. 뮤지션이었던 남자의 이름은 ''제이''. 아내와 아이들과 헤어져 지금은 바텐더로 일하면서 혼자 살고 있는 그는 매주 수요일마다 찾아오는 그녀에 관해 아무것도 모른다. 그렇게 둘은 수요일마다 만나 섹스를 나눈다. 아무런 말도 없이 그저 격렬한 몸짓으로... 그러던 어느 수요일. 여자는 어김 없이 섹스가 끝나자 황급히 문을 나선다. 암묵적인 약속을 깨고 갑자기 여자의 뒤를 몰래 따라가기 시작하는 제이. 그는 여자가 사라진 극장 안으로 이끌리듯 들어선다. 조용히 객석에 앉은 제이의 눈을 사로 잡은 것은 연극 무대에 선 여자, 바로 그녀다. 그리고 옆 자리에 앉은 그녀의 남편으로부터 그녀의 이름이 ''클레어''라는 사실을 전해 듣는다. 그녀 몰래 연극을 보며 제이는 클레어 남편과 가까워지고, 남편은 자신의 부인인 줄 모른 채 제이로부터 수요일의 여자 얘기를 듣게 되는데… 점점 더 그녀의 매혹에 빠져드는 ‘제이’. 그러나 어느 날 정해진 시간에 그녀가 오지 않자, 그녀의 존재가 자기를 미치게 하고 있음을 깨달은 남자는 여자의 뒤를 밟기 시작하는데…', 'https://image.tmdb.org/t/p/w500/jzw1oCWLb7DCbkBquruBeMXAmZq.jpg', 2001, 0, 0, '2026-06-08 06:54:27.080142', 'FR');
INSERT INTO public.movies VALUES (6136, 42337, '좋은 아버지', '["Drama", "Romance"]', 'Bertrand Blier', '["Patrick Dewaere", "Ariel Besse", "Maurice Ronet", "Geneviève Mnich", "Maurice Risch"]', '30대에 접어드는 피아니스트 레미는 약 10년 전 어린 딸이 있는 마르탕과 결혼했다. 음악가로서 이렇다 할 경력을 쌓지 못한 채 세월이 흐르고, 빠듯한 살림에 레미와 마르탕은 갈등을 겪는다. 그러던 어느 날, 사고로 마르탕이 갑자기 숨지고, 14살이 된 딸 마리옹은 친부에게 가야만 하는 상황에 처한다. 그러나 마리옹은 의붓아버지인 레미 곁에 머물기를 원하고, 점점 레미를 남자로 바라보게 된다. 블리에가 자신이 쓴 동명 소설을 각색했다. 의붓아버지와 의붓딸의 사랑이라는 논쟁적인 소재에도 불구하고 호평을 받았다.  (2017 영화의 전당 - [시네마테크] 서머 스페셜 2017)', 'https://image.tmdb.org/t/p/w500/mOTbCDIJnF94LL4lWDue6GzG5Zz.jpg', 1981, 0, 0, '2026-06-08 06:54:34.563482', 'FR');
INSERT INTO public.movies VALUES (6138, 24402, '엠마뉴엘', '["Drama", "Romance"]', 'Just Jaeckin', '["Sylvia Kristel", "Alain Cuny", "Marika Green", "Daniel Sarky", "Jeanne Colletin"]', '파리의 호화로운 아파트, 전화벨이 울린다. 엠마뉴엘(Emmanuelle : 실비아 크리스텔 분)이 화장대 위에 놓인 수화기를 집어들고 통화를 한다. 꽃무늬가 새겨진 가운을 걸치고 짧게 커트한 자그마한 머리가 소년의 모습을 연상케하는 엠마뉴엘은 자신의 모습이 찍힌 사진을 들여다보며 예정대로 오늘 떠나느냐는 친구의 전화에 그렇다고 대답한다. 비행기가 하늘을 날고 태국의 방콕에 도착한다. 마중나온 남편 쟝(Jean : 다니엘 샤키 분)은 19세인 엠마뉴엘보다 10년 이상의 연상인 외교관이다. 뜨거운 입맞춤으로 그녀를 반기는 남편과 함께 쾌적한 대저택에 이른 그녀는 타일랜드 하인들의 정중한 접대를 받으면서 이 새로운 세계에 대한 친밀감과 함께 막연한 기대감을 갖게 된다. 호화로운 풀장에는 외교관인 남편을 따라온 엠마뉴엘과 비슷한 신분의 여인들이 일광욕을 즐기고 있다. 그녀들은 서로 스스럼없이 자신들의 성경험에 대해 얘기하게 되고 아직 순수함을 간직하고 있는 엠마뉴엘은 그런 그녀들의 태도에 당혹감을 느낀다. 그들 가운데 엠마뉴엘은 아직 소녀티가 남아있는 마리(Marie-Ange : 크리스틴 보이슨 분)와 친해지고, 한 파티에서 방콕에 연구차 와있는 고고학자 비(Bee : 마리카 그린 분)를 만나게 된다. 비에게 반한 엠마뉴엘은 그녀와 함께 행복한 시간을 보내지만 오래지 않아 비로부터 절교를 당한다. 상심하던 엠마뉴엘은 남편의 소개로 상류사회 여인들의 선망의 대 상인 마리오를 만나 그의 독특한 성에 관한 철학을 전수받게 되고 이를 통해 서서히 본능에 눈떠가는 자신을 발견하게 된다.', 'https://image.tmdb.org/t/p/w500/aUYDbpjBtn7BaRokrzSJZbByJtl.jpg', 1974, 0, 0, '2026-06-08 06:54:36.11289', 'FR');
INSERT INTO public.movies VALUES (6144, 467938, '리벤지', '["Action", "Horror", "Thriller", "Drama"]', 'Coralie Fargeat', '["Matilda Lutz", "Kevin Janssens", "Vincent Colombe", "Guillaume Bouchède", "Jean-Louis Tribes"]', '부유한 유부남 세 명의 친구들이 사막으로 사냥여행을 떠난다. 이것이 그들만의 연례행사. 하지만 이번엔 그 중 한 명인 리처드가 애인, ‘젠’을 데려온다. 아름답고 섹시한 ‘젠’은 곧 다른 친구들의 호기심을 자극하게 되고, 급기야 끔찍한 일을 당하게 된다. 극도의 공포감에 휩싸인 ‘젠’은 세 명에게 쫓기며 도망치던 중, 낭떠러지에 떨어지고 만다. 그녀가 죽은 줄로만 알았던 세 명의 남자, 그러나 그녀는 온데간데없이 사라져 버리는데… 이제, 그녀의 핏빛 복수극이 시작된다!', 'https://image.tmdb.org/t/p/w500/uMI51JwI9O28GACFkDGB1XzKnhV.jpg', 2017, 0, 0, '2026-06-08 06:54:41.477751', 'FR');
INSERT INTO public.movies VALUES (8667, 339259, '철의 심장을 가진 남자', '["Action", "History", "Thriller"]', 'Cédric Jimenez', '["Jason Clarke", "Rosamund Pike", "Jack O''Connell", "Jack Reynor", "Mia Wasikowska"]', '1938년 체코는 독일에 의해 합병을 당한다. 나치는 체코를 독일 3제국 보호령으로 임명을 하고, 해군에서 불미스런 사건으로 강제 전역을 당한 하이드리히(제이슨 클락)를 총독 대리로 파견하게 된다. 그리고 시작된 유대인 학살 정책들. 런던에서는 하이드리히를 암살한 두 명의 요원을 파견하게 되고, 그들은 체코에 있는 비밀 결사 조직의 도움을 얻어 계획을 준비하게 된다.  점점 다가오는 하이드리히 암살 작전. 하지만 그들이 계획을 실행하기 직전 체코 비밀 조직이 적들의 습격에 당하게 되면서 계획에는 큰 차질을 빚게 된다. 과연 그들은 하이드리히의 암살 작전을 무사히 성공 시킬 수 있을 것인가?', 'https://image.tmdb.org/t/p/w500/jcJS9W8f6Lf1gW2XeQhbvMnBjEi.jpg', 2017, 0, 0, '2026-06-08 07:26:49.512656', 'FR');
INSERT INTO public.movies VALUES (6145, 173185, '서른아홉, 열아홉', '["Comedy"]', 'David Moreau', '["Virginie Efira", "Pierre Niney", "Gilles Cohen", "Amélie Glenn", "Charles Berling"]', '스포츠카 모는 39 패션에디터 ‘알리스’ 8년 동안 남자와도 담쌓고, 커리어에만 목숨 건 워커홀릭! 잃어버린 USB를 찾기 위해 브라질 출장에서 만난 발타자르와 재회하게 된 알리스는 발타자르와 키스하는 듯 찍힌 사진이 SNS에 퍼지면서 한 순간에 어린 남자와 데이트 하는 ‘쿠거족’이 된다. 기가 막힌 알리스와 달리 편집장은 그녀의 이런 거침없는 모습을 응원하고, 절친마저 발타자르를 이용하라고 부추기는데…  스쿠터 타는 19 건축학도 ‘발타자르’  이제 갓 열아홉, 그 어떤 것보다 사랑에 올인하는 러브홀릭!  우연히 만난 매력적인 연상녀 알리스에게 마음을 뺏기지만 그녀는 어린 자신에게 관심이 없는 듯해 실망스럽다. 그러나 갑자기 학교로 찾아와 자신에게 데이트 신청을 하는 알리스로 인해 당황스러우면서도 이 상황이 전혀 싫지 않은 발타자르. 그는 아름답고, 섹시하고, 프로페셔널한 알리스의 모습에 점점 빠져들게 되는데…  39-19 = 20살! 20살차이 로맨스의 모든 것이 밝혀진다!', 'https://image.tmdb.org/t/p/w500/gJu3scryRVZ85RrIcx5WenGzZuL.jpg', 2013, 0, 0, '2026-06-08 06:54:42.247894', 'FR');
INSERT INTO public.movies VALUES (6148, 158015, '더 퍼지', '["Sci-Fi", "Horror", "Thriller"]', 'James DeMonaco', '["Ethan Hawke", "Lena Headey", "Max Burkholder", "Adelaide Kane", "Edwin Hodge"]', '사상 최저 실업률과 범죄율 단 1%의 미국,  완벽한 모습 뒤엔 매년 단 하루, 12시간동안 살인은 물론 어떤 범죄도 허용되는 ‘퍼지 데이’ 가 있다. 그 날은, 모든 공권력이 무력화되고 오직 폭력과 잔혹한 본능만이 난무한다. 2022년 3월 21일 퍼지 데이,  제임스(에단 호크)는 가족을 위해 최첨단 보안 시스템을 가동해 혹시 모를 위험에 대비한다. 하지만 한 순간의 방심으로 쫓기던 낯선 남자를 집으로 들이면서 끔찍한 ‘퍼지 데이’의 밤이 시작된다. 지금부터 12시간, 제임스 가족은 ‘퍼지 데이’에 살아남을 수 있을 것인가…', 'https://image.tmdb.org/t/p/w500/Qd2crPWDD55p1ygqC9dSxm14NA.jpg', 2013, 0, 0, '2026-06-08 06:54:44.494455', 'FR');
INSERT INTO public.movies VALUES (6153, 65496, '스튜던트 서비스', '["Drama"]', 'Emmanuelle Bercot', '["Déborah François", "Mathieu Demy", "Alain Cauchi", "Benjamin Siksou", "Anna Sigalevitch"]', '학비와 생활비를 감당하지 못해 고심 중이던 19살의 여대생 로라는 인터넷에서 즐거운 시간을 함께 할 여학생을 찾고 있다는 중년 남자의 글을 읽게 된다. 1시간에 100유로를 준다는 말에 딱 한 번 만이라는 다짐을 하며 호텔에서 그와 만나는 로라. 하지만 그것은 헤어나올 수 없는 사이클의 시작일 뿐!  프랑스를 충격에 빠뜨린 실화!  그녀의 솔직하고 과감한 이야기가 시작된다!', 'https://image.tmdb.org/t/p/w500/bG3ISz4cq2JDYSCqu5P4Ory1yIm.jpg', 2010, 0, 0, '2026-06-08 06:54:48.28703', 'FR');
INSERT INTO public.movies VALUES (6161, 2899, '아스테릭스 2: 미션 클레오파트라', '["Family", "Fantasy", "Comedy", "Adventure"]', 'Alain Chabat', '["Gérard Depardieu", "Christian Clavier", "Jamel Debbouze", "Monica Bellucci", "Alain Chabat"]', '모든 지역이 로마에 지배받았던 이 시기에, 막강 로마군도 손댈 수 없는 한지역이 있었다. 그곳은 아스테릭스(크리스티앙 클라비에)와 오벨릭스(제라르 드 파르디유)가 살고 있는 골족 마을.힘이 세지는 마법이 물약 제조자 파노라믹스(클로드 리치)와 알고 지내던 누메로비스는 마법의 물약을 청하러 눈내리는 골족 마을로 온다. 마법의 물약을 노동자들에게 먹여 한사람이 열사람의 힘을 내게끔 하려는 계획.  여기에 골족의 영웅 아스테릭스와 오벨릭스, 이데픽스, 파노라믹스가 그들을 도와 이집트의 기적을 만들기 위해 이집트의 뜨거운 햇볕 아래로 여행을 시작한다.  적은 항상 가까운 곳에 있다!  누메로비스를 향한 질투에 사로잡힌 클레오파트라의 공식 건축가 사악한 아몬보피스(제자르 다르몽)와 3개월 안에 정말로 초호화 궁전이 지어질 경우 이집트 민족이 가장 위대한 민족임을 공개적으로 인정해야하는 시저.두 사람의 자존심을 해치는 이 불행한 사건이 일어나지 못하도록 아스테릭스 일행을 피라미드에 가두고, 석포를 이용하여 지어놓은 궁전을 부시는 등 교활할 계책과 강력한 군대로 점점 그들을 궁지로 몰아넣어 가는데….', 'https://image.tmdb.org/t/p/w500/shbL0IZuQ115atqB2gHd5jha6US.jpg', 2002, 0, 0, '2026-06-08 06:54:54.546785', 'FR');
INSERT INTO public.movies VALUES (6162, 796185, '삼총사 파트1: 달타냥', '["Adventure", "Action", "Drama", "History"]', 'Martin Bourboulon', '["François Civil", "Vincent Cassel", "Romain Duris", "Pio Marmaï", "Eva Green"]', '총사가 되겠다는 꿈을 안고 파리에 도착한 시골 청년 달타냥. 그러나 첫걸음부터 거대한 음모에 휘말리며 목숨을 위협받는다.  왕실을 지키는 세 명의 기사와 손을 잡고 진실을 쫓던 그는, 거대한 배신과 음모의 중심에서 가장 위험한 적, 밀라디와 맞선다.  혼란이 휘몰아치는 전쟁터 한가운데, 그가 선택해야 할 것은 단 하나. 신념을 지킬 것인가, 아니면 살아남을 것인가?', 'https://image.tmdb.org/t/p/w500/shRQnu32tmCXCyNhy4IPQIC5ZaO.jpg', 2023, 0, 0, '2026-06-08 06:54:55.340074', 'FR');
INSERT INTO public.movies VALUES (6173, 9992, '아더와 미니모이: 비밀 원정대의 출정', '["Adventure", "Fantasy", "Animation", "Family"]', 'Luc Besson', '["Freddie Highmore", "Madonna", "Mia Farrow", "Adam LeFevre", "Doug Rand"]', '호기심 많은 10살 소년 아더(프레디 하이모어)는 사랑하는 할머니(미아 패로우) 집이 며칠 뒤면 부동산개발업자에게 넘어갈 위기에 처한 것을 알게 된다. 실종된 할아버지가 비밀의 세계에 보물을 숨겨놓았다는 주술서를 발견한 아더는 1000일에 한 번 열리는 마법의 문을 통과해 미니모이 왕국으로 모험을 떠난다. 미니모이 국왕(로버트 드 니로)의 딸인 까칠 공주 셀레니아(마돈나)와 개구쟁이 발명가 왕자 베타(지미 펄론)를 만난 아더는 이블 M으로 불리는 악당 말타자르(데이빗 보위)의 위협으로부터 왕국을 지키려는 이들과 함께 비밀원정대를 결성하고 어둠의 도시로 향하는데…', 'https://image.tmdb.org/t/p/w500/6L1BaLCSkkR7vrLQebTGWtAX9Ie.jpg', 2006, 0, 0, '2026-06-08 06:55:04.21837', 'FR');
INSERT INTO public.movies VALUES (8678, 682012, '리틀 아멜리', '["Animation", "Drama", "Family"]', 'Maïlys Vallade', '["Loïse Charpentier", "Victoria Grobois", "Yumi Fujimori", "Cathy Cerda", "Marc Arnaud"]', '일본의 작은 산마을에서 태어난 소녀 ‘아멜리’. 스스로를 세상의 중심이라 여기는 ‘아멜리’는 유모 ‘니시오’와 함께 사계절을 보내며 새로운 세계를 만난다. ‘니시오’와의 행복한 우정을 나누던 ‘아멜리’는 세 번째 생일날, 예기치 못한 변화를 마주하는데… 자신을 ‘신’이라 믿는 엉뚱 발랄 세 살 소녀의 오색찬란 성장 판타지!', 'https://image.tmdb.org/t/p/w500/17dfdVQO85YRD7kB8iBdny7nv32.jpg', 2025, 0, 0, '2026-06-08 07:26:57.604376', 'FR');
INSERT INTO public.movies VALUES (8645, 5070, '사랑도 흥정이 되나요?', '["Comedy", "Drama"]', 'Bertrand Blier', '["Monica Bellucci", "Bernard Campan", "Gérard Depardieu", "Jean-Pierre Darroussin", "François Rollin"]', '모든 남자들이 탐하는 매혹적인 그녀,INSERT INTO public.movies VALUES (8646, 29259, '구멍', '["Drama", "Thriller", "Crime"]', 'Jacques Becker', '["Michel Constantin", "Jean Keraudy", "Philippe Leroy", "Raymond Meunier", "Marc Michel"]', '라 상테 형무소에서도 특히 경계가 삼엄한 감방 안에는 ‘신부’라는 별명을 가진 보슬랭, 세 차례 탈옥 경력이 있는 롤랑, 눈초리가 날카로운 마뉴, 그리고 여자를 좋아하는 조가 있다. 지하에 구멍을 파고 탈옥한다는 계획을 모의하던 네 사람은 형무소 풋내기 가스파를 계획에 가담시킨다.', 'https://image.tmdb.org/t/p/w500/e0jiNoXdEi2ilGRvhqcaoNCSglg.jpg', 1960, 0, 0, '2026-06-08 07:26:34.365166', 'FR');
INSERT INTO public.movies VALUES (8647, 630004, '웨이 다운', '["Drama", "Action", "Thriller"]', 'Jaume Balagueró', '["Freddie Highmore", "Àstrid Bergès-Frisbey", "Jose Coronado", "Liam Cunningham", "Sam Riley"]', '2010년 스페인 마드리드. 도시 전체가 대표팀의 성공적인 월드컵 참가에 열광하는 가운데, 한 무리의 대담한 도둑들이 지구상에서 가장 보안이 철저하고 경비가 삼엄한 곳에 침입할 방법을 모색합니다.', 'https://image.tmdb.org/t/p/w500/1NBC2hvtfZfRRjcqqZmD9t7m7q3.jpg', 2021, 0, 0, '2026-06-08 07:26:35.029513', 'FR');
INSERT INTO public.movies VALUES (8648, 1290432, '파리의 사생활', '["Drama", "Mystery", "Crime"]', 'Rebecca Zlotowski', '["Jodie Foster", "Daniel Auteuil", "Virginie Efira", "Mathieu Amalric", "Vincent Lacoste"]', '파리에 사는 정신과 상담의 릴리안은 어느 날 자신의 환자인 폴라가 스스로 목숨을 끊었다는 소식을 듣는다.', 'https://image.tmdb.org/t/p/w500/7aYpPqT2AK7zJIWSQ923cUrtVi5.jpg', 2025, 0, 0, '2026-06-08 07:26:35.698167', 'FR');
INSERT INTO public.movies VALUES (8649, 13387, '트랜스포터: 라스트 미션', '["Action", "Thriller", "Crime"]', 'Olivier Megaton', '["Jason Statham", "Natalya Rudakova", "François Berléand", "Robert Knepper", "Jeroen Krabbé"]', '어떤 의뢰품이든 절대 알려 하지 않고 정해진 자신의 룰에 따라 완벽하게 운반하는 전문 ‘트랜스포터’ 프랭크 마틴(제이슨 스테덤). 평화로운 삶을 살아가던 어느 날 담벼락을 뚫고 쳐들어온 아우디 한 대와 피범벅이 된 사나이, 정체 모를 한 여인을 발견한다. 그리고 그들의 손목에 채워진 폭탄팔찌. 차에서 떨어지기를 거부하던 남자를 구급차에 태워보내자 엄청난 굉음과 함께 폭발하고 만다.  불법 환경 사업가로 위장한 존슨(로버트 네퍼)은 프랭크를 납치해 그의 차에서 10m이상 떨어지면 폭 발하는 팔찌를 손목에 장착하고, 목숨을 담보로 한 위험한 거래를 제안한다. 그리고 의문의 한 여인 을 정해진 장소까지 동행하라는 명령을 받게 되는데…  살고 싶다면 스피드를 올려라!!  살기 위해서라면 질주 할 수 밖에 없는 절대 미션, 차에서 떨어지면 폭발해버리는 폭탄, 그리고 자신 을 조종하고 있는 존슨이 프랭크와 동승한 여인을 인질로 전 세계를 위험에 빠트릴 엄청난 계획을 꾸 미고 있음을 알게 된다. 시시각각 조여오는 절체절명의 순간에서 프랭크는 과연 마지막 미션을 성공 할 수 있을 것인가!!', 'https://image.tmdb.org/t/p/w500/be3aIgjt8493TXfuXM6PsxPm5Vm.jpg', 2008, 0, 0, '2026-06-08 07:26:36.375682', 'FR');
INSERT INTO public.movies VALUES (8650, 1147400, '미라큘러스 월드: 파리, 셰이디버그와 블랙클로', '["Animation", "Family", "Action", "Adventure", "Fantasy"]', 'Thomas Astruc', '["Antoine Tomé", "Anouck Hautbois", "Benjamin Bollen", "Fanny Bloc", "Marie Nonnenmacher"]', '나비 미라클스톤을 찾아 평행 세계에서 넘어온 레이디버그와 블랙캣. 근데 이 둘이 영웅이 아니라 악당이라고?', 'https://image.tmdb.org/t/p/w500/Yao0OW9gU86Hul9ms8BQQ5CkpE.jpg', 2023, 0, 0, '2026-06-08 07:26:37.034725', 'FR');
INSERT INTO public.movies VALUES (8651, 784130, '원나잇 인 프랑스', '["Romance", "Drama"]', 'Julien Hilmoine', '["Laura Müller", "Schemci Lauth"]', '결혼을 앞두고 총각파티를 하던 ‘요한’은 친구들의 짓궂은 장난으로 길바닥에 꼼짝할 수 없게 되지만, 마침 그곳을 지나던 여인 ‘액셀’이 그를 구해준다. 그렇게 대화를 시작하게 된 두 사람은 어느새 서로에게 빠져들며 평생 잊을 수 없는 하룻밤을 보내게 되는데...', 'https://image.tmdb.org/t/p/w500/8ETeZPmqQnuDN37UfY0KufnqZfO.jpg', 2021, 0, 0, '2026-06-08 07:26:37.696401', 'FR');
INSERT INTO public.movies VALUES (8652, 1168719, '침묵의 친구', '["Drama"]', 'Ildikó Enyedi', '["Tony Leung Chiu-wai", "Léa Seydoux", "Luna Wedler", "Enzo Brumm", "Sylvester Groth"]', '독일 대학의 한 식물원에는 1832년부터 인간을 바라보며 뿌리내린 장엄한 한 그루의 은행나무가 서있다. 1908년 대학 최초의 여학생. 1972년 식물과 사랑을 동시에 키우는 청년. 2020년 고독한 신경과학자. 한 세기가 넘는 시간 동안 이 은행나무는 세 사람들의 삶 속으로 고요히 가지를 뻗어 하나로 연결되기 시작한다.', 'https://image.tmdb.org/t/p/w500/5YxIvLizm9MisC4kRJo4ElPmsLl.jpg', 2026, 0, 0, '2026-06-08 07:26:38.360802', 'FR');
INSERT INTO public.movies VALUES (8679, 869922, '클레브: 열일곱의 일탈', '["Drama"]', 'Rodolphe Tissot', '["Louisiane Gouverneur", "Vincent Deniard", "Aymeric Fougeron", "Sarah Suco", "Alexandre Steiger"]', '프랑스의 시골 마을 클레브. 이 작은 마을에서, 사춘기를 맞은 솔랑주와 친구들의 관심사는 오로지 섹스다. 누가 제일 진도를 빨리, 많이 나갔는지 열심히 겨룬다. 솔랑주도 남들보다 앞서고 싶은 마음에 주위 남자들을 한 명씩 도발하기 시작한다.', 'https://image.tmdb.org/t/p/w500/y4urhGUOr9XWhsdn4xQ3ceNScMd.jpg', 2021, 0, 0, '2026-06-08 07:26:58.276472', 'FR');
INSERT INTO public.movies VALUES (8680, 47612, 'Au Bonheur des Dames', '["Drama", "Romance"]', 'Julien Duvivier', '["Dita Parlo", "Ginette Maddie", "Andrée Brabant", "Nadia Sibirskaïa", "Germaine Rouer"]', NULL, 'https://image.tmdb.org/t/p/w500/lcshMRxDFWDtT2W9ImBeyuYnbg4.jpg', 1930, 0, 0, '2026-06-08 07:26:58.944958', 'FR');
INSERT INTO public.movies VALUES (8653, 7516, '스모킹 에이스', '["Action", "Comedy", "Crime"]', 'Joe Carnahan', '["Ryan Reynolds", "Andy Garcia", "Martin Henderson", "Chris Pine", "Ray Liotta"]', '라스베가스 최고 스타의 심장에 걸린 100만 달러, 돈 냄새에 꼬여든 세계 최강 킬러들이 벌이는 살인 게임! 누구든지 빨라야 이긴다! 라스베가스 쇼에서 카드 마술로 명성을 날리는 최고의 스타 ‘이스라엘(제레미 피븐)’. 돈과 마약, 폭력에 찌든 그는 마피아와의 친분을 이용해 범죄를 저지르기 시작한다. 스스로가 마피아 조직의 보스가 되고 싶은 욕심에서 시작된 범죄 행각은 점점 대담해지고 결국 FBI의 추적을 받기 시작한다. 이스라엘이 FBI에 노출되자 덩달아 위험에 빠지게 된 마피아의 대부 ‘스파라짜’. FBI는 스파라짜의 통화를 도청하던 중 그가 이스라엘을 제거하기 위해 100만 달러를 걸었다는 정보를 입수하게 되고 이를 알게 된 이스라엘은 심각한 위협을 느끼게 된다. 결국 이스라엘은 마피아의 비밀을 FBI에 폭로하는 대가로 자신의 신변을 보호해 줄 ‘증인 보호 프로그램’을 요청한다. FBI 부국장 ‘라키(앤디 가르시아)’는 이스라엘을 보호하기 위해 그가 은신하고 있는 타호 호수에 위치한 카지노 호텔로 ‘메스너(라이언 레이놀즈)’와 ‘캐루터스(레이 리요타)’ 요원을 파견한다. 한편, 이스라엘의 심장에 100만 달러가 걸렸다는 소문은 전문 킬러들 사이에 순식간에 퍼지게 되고 날고 긴다는 최고의 킬러들이 타호 호수로 몰려든다. 섹시한 여성 킬러들인 ‘사익스(알리샤 키스)’와 ‘셔리스(타라지 헨슨)’, 미치광이 삼형제 다윈, 지브스, 레스터, 고문전문가 아코스타, 위장술의 대가인 라즐로 그리고 오직 돈을 위해 FBI와 마피아 사이에서 이스라엘을 빼내는 일을 의뢰 받은 보석 보증인 ‘듀프리(벤 애플렉)’와 전직 경찰관이었던 그의 친구들까지 합세하면서 카지노 호텔은 거친 살인 게임의 현장으로 돌변한다. 이스라엘을 보호하기 위한 FBI와 그를 제거하기 위한 킬러들의 대결은 시작되고 이들을 둘러싼 사건들은 점점 알 수 없는 음모 속으로 빠져들게 되는데.. 과연 누가 이스라엘의 심장을 가지게 될 것인가! 100만 달러를 둘러싼 거칠고 화려한 살인 게임이 시작된다!', 'https://image.tmdb.org/t/p/w500/w2d72HysBUqbumXYB0Vm8Fz8d8n.jpg', 2006, 0, 0, '2026-06-08 07:26:39.755894', 'FR');
INSERT INTO public.movies VALUES (8654, 2330, '택시', '["Action", "Comedy", "Crime", "Adventure"]', 'Gérard Pirès', '["Samy Naceri", "Frédéric Diefenthal", "Marion Cotillard", "Manuela Gourary", "Emma Wiklund"]', '피자배달계의 전설적인 존재 다니엘이 영업용 택시를 몰게된다. 그의 택시는 엄청난 마력의 엔진으로 개조된 것이다. 보닛 속에 잠들어 있는 타이거 엔진을 깨우면 경찰의 스피드건조차 그를 적발할 수 없다. 그러나 다니엘은 불행하게도 운전면허 시험에 8번이나 떨어진 에밀리앙 형사를 만난다. 에밀리앙은 메르세데스 벤츠를 몰고 다니며 17개의 은행을 연속적으로 턴 신출귀몰한 갱단을 잡기 위해 다니엘의 도움이 필요하다. 다니엘은 택시와 면허를 뺏기지 않으려면 그의 조건을 받아들일 수밖에 없다.', 'https://image.tmdb.org/t/p/w500/pzCstxUOwLlgIq4ERFF1y6NBFfO.jpg', 1998, 0, 0, '2026-06-08 07:26:40.427181', 'FR');
INSERT INTO public.movies VALUES (8655, 1284460, '알파', '["Horror", "Drama", "Sci-Fi"]', 'Julia Ducournau', '["Mélissa Boros", "Tahar Rahim", "Golshifteh Farahani", "Emma Mackey", "Finnegan Oldfield"]', NULL, 'https://image.tmdb.org/t/p/w500/iE3P4LFSJCBX5PRWxbPs7DQh7yI.jpg', 2025, 0, 0, '2026-06-08 07:26:41.083335', 'FR');
INSERT INTO public.movies VALUES (8656, 1167271, '드라이브 인 타이페이', '["Action", "Adventure", "Thriller"]', 'George Huang', '["Luke Evans", "Gwei Lun-Mei", "Sung Kang", "Wyatt Yang", "Pernell Walker"]', '마약단속국 요원, 존 로러와 전직 비밀 요원이자 대만 최고의 레이서, 조이 강. 과거의 인연을 간직한 채 운명적으로 15년 뒤 타이페이에서 마주한다. 뜻밖의 재회의 시간도 잠시, 강의 추격을 피하기 위한 급박한 추적극이 시작된다.', 'https://image.tmdb.org/t/p/w500/3dNl6JkePvkQqFYg3dz32lbJ9KY.jpg', 2024, 0, 0, '2026-06-08 07:26:41.736291', 'FR');
INSERT INTO public.movies VALUES (8657, 121875, '인 더 하우스', '["Comedy", "Drama", "Mystery", "Thriller"]', 'François Ozon', '["Fabrice Luchini", "Kristin Scott Thomas", "Ernst Umhauer", "Emmanuelle Seigner", "Bastien Ughetto"]', '한때 작가를 꿈꾸던 고등학교 문학 교사 제르망과 갤러리를 운영하는 그의 아내 쟝. 평범한 일상을 보내던 그들에게 클로드란 학생의 작문 과제가 눈에 들어온다. 친구 라파의 가족 이야기를 써낸 클로드의 작문에서 묘한 매력과 재능을 발견한 제르망. 클로드의 작문은 제르망과 쟝에게 다시금 활력과 열정을 불러일으킨다. 하지만 점점 도를 지나치는 클로드의 행동과 이를 부추기는 제르망의 호기심은 걷잡을 수 없는 방향으로 치닫는데…', 'https://image.tmdb.org/t/p/w500/prxWPzvem8EytWxaIWlZFvglpqS.jpg', 2012, 0, 0, '2026-06-08 07:26:42.406626', 'FR');
INSERT INTO public.movies VALUES (8658, 1456349, '그저 사고였을 뿐', '["Drama", "Thriller", "Crime", "Mystery"]', 'Jafar Panahi', '["Vahid Mobasseri", "Mariam Afshari", "Ebrahim Azizi", "Hadis Pakbaten", "Majid Panahi"]', '어느 날, 나를 지옥으로 이끌던 삐걱 소리가 다시 들렸다. 나는 안다. 그가 맞다. “그저 사고였을 뿐? 누군가는 그걸 평생 기억해”', 'https://image.tmdb.org/t/p/w500/5MSAOVFxVezKOX65pJ2iwyIYR7K.jpg', 2025, 0, 0, '2026-06-08 07:26:43.070894', 'FR');
INSERT INTO public.movies VALUES (8659, 476299, '베스와 베라', '["Horror", "Mystery", "Thriller"]', 'Pascal Laugier', '["Crystal Reed", "Mylène Farmer", "Anastasia Phillips", "Emilia Jones", "Taylor Hickson"]', '정체불명의 괴한으로부터 끔찍한 일을 겪은 어린 ‘베스’와 ‘베라’.  사고 이후, 언니 ‘베스’는 자전적 소설을 출간하며 성공하지만,  동생 ‘베라’는 여전히 그날의 공포에 사로잡힌 채 괴로워한다.  제발 자신을 버리지 말라고 절규하는 ‘베라’ 곁으로 다시 돌아온 ‘베스’.  하지만 끝내 끝나지 않고 되풀이되는 악몽 같은 현실과 엇갈린 진실은  두 자매를 점점 더 깊은 혼란에 빠뜨리는데…', 'https://image.tmdb.org/t/p/w500/pWczUl2IGclaExxJM1WaGvbjmT6.jpg', 2018, 0, 0, '2026-06-08 07:26:43.728879', 'FR');
INSERT INTO public.movies VALUES (8660, 54065, '밤볼라', '["Comedy", "Drama"]', 'Bigas Luna', '["Valeria Marini", "Stefano Dionisi", "Jorge Perugorría", "Manuel Bandera", "Anita Ekberg"]', '트럭 기사들을 위한 식당에서 ''밤볼라''라 불리는 미나는 엄마와 동생 파블리오와 함께 어렵게 살아간다. 그러나 엄마가 갑자기 돌아가시자 미나는 파블리오의 친구인 우고의 도움으로 식당을 연다. 그러던 어느날 미나는 수영장에 놀러갔다 세티미오라는 운명의 남자를 만나지만 미나와 세티미오의 사이를 질투하는 우고가 행패를 부리자 세티미오가 우고를 죽이는 사고가 발생한다.', 'https://image.tmdb.org/t/p/w500/65vOhsbKdc6Vi9tYcXNbLAEYNkt.jpg', 1996, 0, 0, '2026-06-08 07:26:44.399157', 'FR');
INSERT INTO public.movies VALUES (8661, 74643, '아티스트', '["Drama", "Comedy", "Romance"]', 'Michel Hazanavicius', '["Jean Dujardin", "Bérénice Bejo", "John Goodman", "James Cromwell", "Penelope Ann Miller"]', '출연하는 영화마다 흥행을 이어가던 헐리우드 최고의 스타 조지(장 뒤자르댕). 가는 곳마다 구름 같은 팬들을 몰고 다녔던 조지(장 뒤자르댕이). 하지만 유성영화의 등장으로 무성영화 배우였던 그는 졸지에 설 자리를 잃게 된다. 한편 그를 흠모하는 여인은 신인 시절 조지의 작품에 단역으로 출연하며 운명적인 만남을 가졌던 여배우 페피(베레니스 베조). 달라진 환경에서 더이상 설 자리가 없어진 조지와 달리 매력적인 목소리를 가진 페피는 할리우드 최고의 스타가 되고, 나락에 떨어진 조지를 찾아 나선다.', 'https://image.tmdb.org/t/p/w500/l9rAgUUgLjueBRyhf41rpEdRGLy.jpg', 2011, 0, 0, '2026-06-08 07:26:45.504471', 'FR');
INSERT INTO public.movies VALUES (8668, 192, '장미의 이름', '["Drama", "Thriller", "Mystery"]', 'Jean-Jacques Annaud', '["Sean Connery", "Christian Slater", "Helmut Qualtinger", "Elya Baskin", "Michael Lonsdale"]', '1327년 이탈리아 북부에 있는 베네딕트 수도원에서 그림 그리는 채식 수사 아델모의 시체가 발견되면서 수도원은 술렁이기 시작한다. 당시 교회의 청빈을 주장하는 프라시스코 수도회와 그를 반박하는 교황청 및 다른 교단들의 반목이 심화되자 이를 해결키 위해 이 수도원에서 각 교단이 모여 토론을 하기로 함으로써, 프란시스코 수사인 윌리엄(William of Baskerville: 숀 코넬리 분)은 수련 제자 아조(Adso of Melk: 크리스찬 슬레이터 분)를 데리고 이곳에 들른다.  뛰어난 두뇌의 소유자 윌리엄이 수도원이 심상치 않음을 간파하자 수도원장(The Abbot: 미쉘 론스데일 분)은 윌리엄에게 이 사건을 해결해 달라고 요청한다. 그러던 중 그리이스어 번역사가 다시 살해되고 요한 계시록의 예언대로 수사들이 죽음을 맞자 수도원은 악마의 역사가 시작됐다고 극도의 불안에 떤다. 서고를 은밀히 지키던 두 사람은 심야에도 서관에서 누군가가 책 한권을 훔쳐 달아나는 것을 목격하고 뒤를 밟았지만 그들이 발견한 것은 주방에서 정사를 벌이고 있는 마을처녀와 수도승. 가난한 마을 처녀는 그렇게 해서 식량을 구하고 있는 것이었다.  윌리엄은 사서와 보조사서의 행동을 수상쩍다고 느끼던 중 암호가 적인 양피지를 발견, 사서외엔 아무도 못들어 간다는 도서관에 비밀의 열쇠가 있다고 판단, 잠입을 시도하지만 실패한다. 한편 죽은 수사마다 혀와 손가락 끝에 검은 잉크자국이 베어 있는데. 그러던 사이에 이단 심문에서 유죄로 선고된 두 수도승, 여기에 마녀로 선고된 마을처녀도 함께 묶여서 세사람의 발아래 장작이 쌓이는 순간 윌리암은 범인을 알아내고 서고탑 안으로 들어가는데.', 'https://image.tmdb.org/t/p/w500/d6dlbTBb3N7nXDz7tQslDJs2jgv.jpg', 1986, 0, 0, '2026-06-08 07:26:50.181547', 'FR');
INSERT INTO public.movies VALUES (8669, 659, '양철북', '["Drama", "History"]', 'Volker Schlöndorff', '["Mario Adorf", "Angela Winkler", "David Bennent", "Katharina Thalbach", "Daniel Olbrychski"]', '1924년 단찌히에서 오스카가 태어난다. 놀랍도록 조숙한 아기는 독일인과 폴란드인이 섞여 살고 있는 단찌히에서, 독일인인 알프레도와 폴란드인 얀, 두 아버지 사이에서 자라 세번째 생일을 맞던 날 사다리에서 고의적으로 추락, 성장이 정지된다. 오스카는 생일날 선물로 받은 양철북을 두드리면서 나치의 행동을 분열시키는등 끊임없는 소동을 일으킨다. 서커스단 친구들과 함께 연주 여행을 떠난 오스카는 매혹적인 소녀와 사랑에 빠진다. 오스카의 악마적인 요소는 두 아버지와 어머니를 죽음으로 몰고 간다. 어떤 의무로부터도 자유로운 오스카에게도 성과 죽음은 두려운 난제로 다가온다.', 'https://image.tmdb.org/t/p/w500/f0S7Z9v0cEXmsIwSfqBg6dVVx4m.jpg', 1979, 0, 0, '2026-06-08 07:26:50.843771', 'FR');
INSERT INTO public.movies VALUES (8670, 643215, '아스테릭스: 더 미들 킹덤', '["Family", "Comedy", "Adventure", "Fantasy"]', 'Guillaume Canet', '["Guillaume Canet", "Gilles Lellouche", "Vincent Cassel", "Jonathan Cohen", "Julie Chen"]', '초인적인 힘을 가진 갈리아의 용사 ''아스테릭스''와 ''오벨릭스''는 반역자들로부터 망명한 황제의 딸의 간곡한 부탁에 팔을 걷어붙인다. 하지만 그들의 숙적 로마 황제 ''시저''와 배우자 ''클레오파트라''도 강력한 군대를 앞세워 같은 목적지로 향하고 있었는데... 주먹뿐인 두 용사와 압도적인 로마 제국의 역사에 기록되기 애매한 골때리는 전쟁, 시-작!', 'https://image.tmdb.org/t/p/w500/zoW6PYtjQ0iEPIqDm9u5DaOr6N4.jpg', 2023, 0, 0, '2026-06-08 07:26:51.513427', 'FR');
INSERT INTO public.movies VALUES (8671, 432279, '멜랑콜리 베이비', '["Romance", "Drama"]', 'Clarisse Gabus', '["Jane Birkin", "Jean-Louis Trintignant", "Jean-Luc Bideau", "François Beukelaers", "Florence Giorgetti"]', '파리에서 가난한 번역가로 활동하던 올가는 사업가인 로랑과 결혼해 스위스의 시골에 정착한다. 큰 부자인 로랑 덕에 올가는 아무 부족한 것 없이 안락한 생활을 누리지만 마음 한 구석은 점점 텅 비어 간다. 그러던 어느 날 남편의 사업상 친구인 피에르와 함께 저녁 식사를 하게 되고 올가는 점점 피에르의 매력에 빠져든다. 그리고 남편이 파리로 출장을 간 사이 올가는 결국 혼자서 피에르를 찾아 가는데...', 'https://image.tmdb.org/t/p/w500/uArNywm0DsF9pts3v8QXS9iZ5Yy.jpg', 1979, 0, 0, '2026-06-08 07:26:52.181791', 'FR');
INSERT INTO public.movies VALUES (8672, 89644, 'Elsa Fräulein SS', '["Thriller", "Horror"]', 'Patrice Rhomm', '["Malisa Longo", "Olivier Mathot", "Patrizia Gori", "Pamela Stanford", "Claudine Beccarie"]', NULL, 'https://image.tmdb.org/t/p/w500/8wtvGLZCR3k4bj1Tk1g4dYGpUtk.jpg', 1977, 0, 0, '2026-06-08 07:26:52.860866', 'FR');
INSERT INTO public.movies VALUES (8673, 848685, '더 비스츠', '["Thriller", "Drama"]', 'Rodrigo Sorogoyen', '["Marina Foïs", "Denis Ménochet", "Luis Zahera", "Diego Anido", "Marie Colomb"]', '자연과 더 가까운 삶을 꿈꾸며 스페인 갈리시아의 한 마을에 이사온 프랑스인 커플은 이웃 주민들과의 갈등을 겪게 된다. 긴장이 고조되며, 이들의 상황은 돌이킬 수 없는 지경에 이르게 된다.', 'https://image.tmdb.org/t/p/w500/porCAB66BfEpYwjI5q4cAq3g2Uk.jpg', 2022, 0, 0, '2026-06-08 07:26:54.271995', 'FR');
INSERT INTO public.movies VALUES (8674, 70410, '퍼블릭 우먼', '["Drama"]', 'Andrzej Żuławski', '["Valérie Kaprisky", "Francis Huster", "Lambert Wilson", "Patrick Bauchau", "Gisèle Pascal"]', '누드모델로 일하던 스무살의 에셀은 유럽영화제의 신진 거물감독인 캐스링에 의해 영화 악령의 ''리사''역을 제안받는다. 그러던 중 감독과 사람에 빠진 에셀은 그의 의문스런 이중생활을 알게 된다. 그후 젊은 밀란을 사랑하게 된 에셀은 캐스링과 관계된 죽은 여인 에리나가 밀란의 애인이었음을 알게 된다. 리투아니아 대주교의 암살을 강요당하며 경찰에 쫓기던 밀란은 추적 끝에 끝내 사살을 당한다. 밀란의 죽음 뒤에 진실 폭로를 두려워하여, 에셀을 다시 불러 중단시켰던 촬영을 계속하던 캐스링은...', 'https://image.tmdb.org/t/p/w500/loOhQOFVi0suGQR3ipgzm451tWv.jpg', 1984, 0, 0, '2026-06-08 07:26:54.935585', 'FR');
INSERT INTO public.movies VALUES (8675, 73134, '말타는 소녀', '["Drama", "Romance"]', 'David Hamilton', '["Anja Schüte", "Valérie Dumas", "Thierry Tevini", "Évelyne Dandry", "Elisa Servier"]', '1939년 여름, 프랑스 프로방에 살고 있는 14세의 줄리앙은 작은 호텔에서 가족과 함께 사는 그의 사촌 줄리아에게 반하게 된다. 하지만 줄리아는 그를 무시한다. 그러던 중 독일이 전쟁을 선포하며 둘은 알 수 없는 운명의 갈림길에 서게 되는데…', 'https://image.tmdb.org/t/p/w500/jITSqc5btIXBRsiZbC3RkZaoY4U.jpg', 1980, 0, 0, '2026-06-08 07:26:55.610988', 'FR');
INSERT INTO public.movies VALUES (8676, 63481, 'Calmos', '["Comedy"]', 'Bertrand Blier', '["Jean-Pierre Marielle", "Jean Rochefort", "Brigitte Fossey", "Bernard Blier", "Claude Piéplu"]', NULL, 'https://image.tmdb.org/t/p/w500/2H8q0flkjgaFXmeZGdvwQTmHwZe.jpg', 1976, 0, 0, '2026-06-08 07:26:56.271227', 'FR');
INSERT INTO public.movies VALUES (8677, 1284496, 'C''était mieux demain', '["Comedy", "Sci-Fi"]', 'Vinciane Millereau', '["Elsa Zylberstein", "Didier Bourdon", "Mathilde Le Borgne", "Céline Fuhrer", "Maxim Foster"]', NULL, 'https://image.tmdb.org/t/p/w500/f8AbVOhL39Y85J1091sK7auUd77.jpg', 2025, 0, 0, '2026-06-08 07:26:56.945976', 'FR');
INSERT INTO public.movies VALUES (8691, 6537, '오퍼나지: 비밀의계단', '["Horror", "Drama", "Thriller"]', 'J. A. Bayona', '["Belén Rueda", "Fernando Cayo", "Roger Príncep", "Mabel Rivera", "Montserrat Carulla"]', '로라, 카를로스 부부와 아들 시몬은 과거 고아원이었던 대저택으로 이사를 온다. 이 고아원에서 어린시절을 보낸 로라는 병에 걸린 시몬의 건강을 돌보기 위해 외딴 바닷가에 위치한 이곳을 고집했다.  하지만 이사온지 얼마 안돼서 시몬은 이 집에 친구들이 있다며 놀러 다닌다. 더구나 친구들로부터 자신은 입양된 아이고, 곧 죽을 것이라고 들었다며 괴로워한다. 로라는 출생의 비밀을 알아버린 시몬에게 놀라워하지만, 친구들이 있다는 소리는 말도 안 되는 아이의 장난으로 여긴다.  그러던 어느 날, 시몬의 기분 전환을 위해 동네 사람들과 파티를 열게 되는데 그 파티에서 시몬은 사라지고 만다. 시간은 점점 흐르고, 모두가 시몬이 죽었다고 생각하는 가운데 로라는 시몬이 말했던 보이지 않는 친구들의 존재가 자신의 과거와 모종의 관계가 있음을 깨닫게 되는데…', 'https://image.tmdb.org/t/p/w500/cXGi6iDUXwcJiXOHZCEE982Cfqv.jpg', 2007, 0, 0, '2026-06-08 07:27:06.264491', 'FR');
INSERT INTO public.movies VALUES (8692, 7229, '셧업', '["Comedy", "Crime"]', 'Francis Veber', '["Gérard Depardieu", "Jean Reno", "Richard Berry", "André Dussollier", "Jean-Pierre Malo"]', '전문 킬러 루비(장 르노)는 동업자인 갱두목이 배신을 하자 그의 돈을 가로채려다 경찰에 체포된다. 경찰은 루비와 갱단의 음모를 밝히기 위해 루비를 심문하지만 성격 과묵한 루비는 아예 맘먹고 침묵으로 일관하며 탈옥을 계획한다. 그러나 뛰는 놈 위에 나는 놈 있는 법. 경찰은 루비의 입을 열기 위해 기막힌 사내를 루비의 감방으로 보낸다. 감옥을 공포에 떨게 한 바로 그 남자를.INSERT INTO public.movies VALUES (8693, 342878, '원 와일드 모먼트', '["Drama", "Romance"]', 'Jean-François Richet', '["Vincent Cassel", "François Cluzet", "Alice Isaaz", "Lola Le Lann", "Philippe Nahon"]', '둘도 없는 절친 사이인 로랑(뱅상 카셀)과 앙투안(프랑수아 클루제)은 각자의 딸들을 데리고 코르시카 섬으로 힐링 & 우정 여행을 오게 된다.  이혼하고 오랫동안 혼자서 마리(앨리스 이자스)를 키워오면서 자유방임 교육을 몸소 실천해온 로랑, 애지중지 금지옥엽으로 루나(로라 르 란)을 키워온 앙투안. 경치좋은 곳에서 딸들과 함께 힐링을 하려 했건만… 마리와 루나는 전화가 안터진다, 와이파이가 안잡힌다, 별장 안에 죽은 쥐가 있다, 등등 불만만 가득! 그러던 중 교내 킹카가 코르시카 섬에 와있다는 것을 알게 되고 마리와 루나는 하루가 멀다하고 밤마다 클럽행, 두 아빠에게 새로운 헬게이트가 열리게 된다.  너무 다른 교육관을 가진 두 딸 바보 아빠, 그리고 빨리 어른(!)이 되고 싶은 명랑 당돌한 딸들의 신나고 발칙한, 그리고 평생토록 잊지 못할 그들 만의 핫 썸머 나잇!', 'https://image.tmdb.org/t/p/w500/sdIFtQA5FLeFBLgJrAmpymOYg2a.jpg', 2015, 0, 0, '2026-06-08 07:28:18.025729', 'FR');
INSERT INTO public.movies VALUES (8694, 976576, '엠마뉴엘', '["Drama", "Romance"]', 'Audrey Diwan', '["Noémie Merlant", "Will Sharpe", "Naomi Watts", "Jamie Campbell Bower", "Chacha Huang"]', NULL, 'https://image.tmdb.org/t/p/w500/s9gmKus9YPTDzdMKZQJYPh0VoGk.jpg', 2024, 0, 0, '2026-06-08 07:28:18.694458', 'FR');
INSERT INTO public.movies VALUES (8695, 649, '세브린느', '["Drama", "Romance"]', 'Luis Buñuel', '["Catherine Deneuve", "Jean Sorel", "Michel Piccoli", "Geneviève Page", "Pierre Clémenti"]', '우아하고 지적인 미녀 세브린은 의사인 남편 피엘과 행복하고 부유하게 살고 있지만 일에 열중해 있는 남편에게서 소외감을 느낀다. 물밀 듯이 밀려드는 권태감, 이를 타개하는 방편으로 그녀는, 남편과 마차를 타고 가다 자신을 창녀라고 욕을 하며 산 속에서 끌고 들어가 묶어놓고 채찍을 맞는 등 비정상적인 상상의 나래를 펼친다.  그럼에도 불구하고 걷잡을 수 없는 외로움은 그녀로 하여금 가서는 안될 곳에 발을 들여놓게 만든다. 남편 친구인 잇송씨로부터 고급 요정의 주소를 듣고, 한동안 갈등하다, 숨막힐 듯한 자신의 권태에서 벗어나고픈 일념에 남편이 병원에서 일하는 시간에 그곳에 나가 생전 처음 보는 남자들과 관계를 맺으면서 다소나마 활기를 되찾는다.  그러나 자신에게 그곳을 찾아온 잇송씨와 만난 후, 세브린은 아이를 바라는 남편에 대한 죄책감에 그만 그곳을 뛰쳐나오고 만다. 그 일을 계기로 다시 평범한 가정 주부로 돌아온 어느날 세브린 앞에 한 젊은이가 나타난다. 그는 소매치기 건달로, 하룻밤 손님으로서 그녀를 찾아왔다가 그녀를 사랑하게 되어 남편에 대한 질투심을 이기지 못하고 귀가하는 피엘에게 총을 겨눈다.  아내가 무엇인가 숨기고 있다는 사실을 눈치챈 피엘은 식물인간이 된 것처럼 가장하는데...', 'https://image.tmdb.org/t/p/w500/py2UWwbNYIL2bHP24E7jRSu1SHs.jpg', 1967, 0, 0, '2026-06-08 07:28:19.356198', 'FR');
INSERT INTO public.movies VALUES (8696, 677561, 'Les Légendaires', '["Animation", "Action", "Adventure", "Comedy", "Family", "Fantasy"]', 'Guillaume Ivernel', '["Roman Doduik", "Esthèle Dumand", "Elise Tilloloy", "Thomas Sagols", "Antoine Schoumsky"]', NULL, 'https://image.tmdb.org/t/p/w500/AlfndBQucnWC7igEIG2L0sk6tiF.jpg', 2026, 0, 0, '2026-06-08 07:28:20.02122', 'FR');
INSERT INTO public.movies VALUES (8697, 309809, '어린왕자', '["Adventure", "Animation", "Fantasy", "Family"]', 'Mark Osborne', '["Riley Osborne", "Mackenzie Foy", "Jeff Bridges", "Rachel McAdams", "Marion Cotillard"]', '친구하나 없이 엄마(레이첼 맥아담스)가 짜놓은 인생계획표대로만 살던 소녀(맥켄지 포이). 어느 날, 자신의 이야기를 들어달라는 옆집의 괴짜 조종사 할아버지(제프 브리지스)를 만나면서 오래 전 조종사가 사막에 추락했을 때 만난, 다른 행성에서 온 어린왕자의 존재를 알게 된다. 소녀는 조종사 할아버지와 친구가 되어가면서 어린왕자가 살던 소행성 B612와 다른 세계로의 여행, 모두를 꿈꾸게 하는 가슴 벅찬 모험을 시작한다.', 'https://image.tmdb.org/t/p/w500/dQ9Uz6ZFCQJ32BXonkVu0UUgRDR.jpg', 2015, 0, 0, '2026-06-08 07:28:20.69225', 'FR');
INSERT INTO public.movies VALUES (8700, 15357, '13구역: 얼티메이텀', '["Action", "Thriller", "Crime"]', 'Patrick Alessandrin', '["Cyril Raffaelli", "David Belle", "Philippe Torreton", "Daniel Duval", "Élodie Yung"]', '정부의 철저한 격리로 범죄자들과 타락한 경찰의 공간이 되어버린 13구역. 새로운 정부가 들어섰지만 여전히 법도, 정의도 없는 그 곳을 지배하는 5개의 조직은 각자 자신의 구역을 삶의 터전으로 위험하고 아슬아슬한 관계를 유지한다. 어느 날, 13구역에서 경찰이 무참히 살해당하는 사건이 발생하면서, 분노한 국민들은 13구역을 완전히 없애버리자는 여론으로 들끓고 13구역은 폭동에 휩싸인다. 하지만 유일하게 정의로운 경찰 데미안과 13구역에서 희망을 보며 살아가는 레이토는 본능적으로 그것이 정부의 은밀한 계획임을 눈치채고, 곧바로 그들의 목숨을 노리는 알 수 없는 정부 세력에 의해 쫓기게 된다.  정부도, 경찰도, 그 누구도 믿을 수 없는 상황. 그들은 13구역의 5개 조직과 의기투합, 정부의 음모에 맞서 멈추지 않는 액션 본능을 폭발하는데…', 'https://image.tmdb.org/t/p/w500/bOycqtB3Mwi0p4KkpYXFkVSqQ73.jpg', 2009, 0, 0, '2026-06-08 07:28:22.684249', 'FR');
INSERT INTO public.movies VALUES (8701, 20084, 'Andrea Bocelli - Une nuit en Toscane', '[]', NULL, '["Andrea Bocelli", "Sarah Brightman", "Zucchero", "Nuccia Focile"]', NULL, NULL, 1998, 0, 0, '2026-06-08 07:28:23.35168', 'FR');
INSERT INTO public.movies VALUES (8702, 11687, '비지터', '["Fantasy", "Comedy"]', 'Jean-Marie Poiré', '["Jean Reno", "Christian Clavier", "Valérie Lemercier", "Marie-Anne Chazel", "Christian Bujeau"]', '영국과의 전쟁에서 프랑스 왕 루이 6세의 생명을 구하는 지대한 공을 세운 기사 고드프루아는 작위를 수여받고 포상으로 풀베르 드푸이 백작의 딸인 프레네공드 드푸이와 결혼을 약속받는다. 그러나 마녀의 계략으로 환각을 유발하는 약을 먹은 그는 예비 장인인 백작을 죽이고 만다. 고드프루아는 마법사에게 부탁하여 불상사가 일어나기 전의 시점으로 되돌아가게 해주는 묘약을 처방받는다. 그러나 마법사의 실수로 중요한 재료 하나가 빠진 약을 먹게 된 그는 시종인 자쿠이와 함께 과거가 아닌 1992년으로 가게 된다. 800여년 뒤의 문화에 적응하지 못해 좌충우돌하는 이들은 출발 시점으로 귀환하기 위해 갖은 애를 쓰는 와중에 미래의 후손들을 만나게 되고 그 중 한 명이 고드프루아를 수년 전 잃어버린 자신의 사촌으로 착각하는 해프닝도 벌어진다. 고드프루아는 자신에게 묘약을 지어준 마법사의 후손을 천신만고 끝에 만나 과거로 돌아가게 해주는 약을 건네받는다. 그러는 동안 어느 노숙자 여인을 만나 사랑에 빠진 자쿠이는 주인을 따라가기를 거부하고 대신 자기 후손을 돌려 보내면서 또 다른 소동을 예고한다.', 'https://image.tmdb.org/t/p/w500/7GMTcDyi2wxBqBR8snSKO10i7sm.jpg', 1993, 0, 0, '2026-06-08 07:28:24.014466', 'FR');
INSERT INTO public.movies VALUES (150, 671, '해리 포터와 마법사의 돌', '["Adventure", "Fantasy"]', 'Chris Columbus', '["Daniel Radcliffe", "Rupert Grint", "Emma Watson", "Richard Harris", "Tom Felton"]', '해리 포터는 위압적인 버논 숙부와 냉담한 이모 페투니아, 욕심 많고 버릇없는 사촌 더즐리 밑에서 갖은 구박을 견디며 계단 밑 벽장에서 생활한다. 이모네 식구들 역시 해리와의 동거가 불편하기는 마찬가지. 이모 페투니아에겐 해리가 이상한 언니 부부에 관한 기억을 떠올리게 만드는 달갑지 않은 존재다. 11살 생일이 며칠 앞으로 다가왔지만 한번도 생일파티를 치르거나 제대로 된 생일선물을 받아 본 적이 없는 해리로서는 특별히 신날 것도 기대 할 것도 없다. 11살 생일을 며칠 앞둔 어느 날 해리에게 초록색 잉크로 쓰여진 한 통의 편지가 배달된다. 그 편지의 내용은 다름 아닌 해리의 11살 생일을 맞이하여 호그와트에서 보낸 입학 초대장이었다. 그리고 해리의 생일을 축하하러 온 거인 해그리드는 해리가 모르고 있었던 해리의 진정한 정체를 알려주는데...', 'https://image.tmdb.org/t/p/w500/8YaP48tVfngbURGldWk1I5odsBK.jpg', 2001, 0, 0, '2026-06-06 13:25:01.798154', 'GB');
INSERT INTO public.movies VALUES (249, 673, '해리 포터와 아즈카반의 죄수', '["Adventure", "Fantasy"]', 'Alfonso Cuarón', '["Daniel Radcliffe", "Rupert Grint", "Emma Watson", "Robbie Coltrane", "Michael Gambon"]', '13세가 된 해리 포터는 또 한번의 여름 방학을 이모 가족인 더즐리 일가와 우울하게 보내야 했다. 물론 마법을 쓰는 건 일체 금지. 하지만, 버논 이모부의 누이인 마지 아줌마가 더즐리 가를 방문하면서 상황은 변한다. 위압적인 마지는 해리에겐 늘 공포의 대상. 마지 아줌마 때문에 스트레스를 받던 해리는 급기야 실수로 그녀를 거대한 괴물 풍선으로 만들어 하늘 높이 띄워 보내버리고 만다. 이모와 이모부에게 벌을 받을 것도 두렵고, 일반 세상에선 마법 사용이 금지돼 있는 것을 어겼기 때문에 호그와트 마법학교와 마법부의 징계가 걱정된 해리는 밤의 어둠 속으로 도망치지만, 순식간에 근사한 보라색 3층 버스에 태워져 한 술집으로 인도되고 마는데...', 'https://image.tmdb.org/t/p/w500/anwNl1xbzXoj5Ax1nVw3WoDzHlw.jpg', 2004, 0, 0, '2026-06-06 13:25:05.620959', 'GB');
INSERT INTO public.movies VALUES (256, 1167307, '다윗', '["Animation", "Drama", "Family", "History"]', 'Phil Cunningham', '["Brandon Engman", "Brian Stivale", "Shahar Taboch", "Aaron Tavaler", "Hector"]', '소년 다윗은 어느 날 선지자 사무엘로부터 왕이 될 운명을 듣게 되지만, 그것이 무엇을 의미하는지 알기도 전에 전쟁의 한가운데로 내던져진다. 모두가 숨을 죽인 전장, 세상이 두려워한 거인 골리앗 앞에 홀로 선 다윗은 단 하나의 돌로 마침내 그를 쓰러뜨린다. 기적 같은 승리 이후, 그는 단숨에 영웅이 되지만 그 이름은 곧 사울 왕의 분노를 깨운다. 또다시 거대한 위협 앞에 맞서게 된 다윗은 자신에게 주어진 운명의 무게와 마주하게 되는데...', 'https://image.tmdb.org/t/p/w500/tGmTssnoltCCZBY7ys4lYRTFYFj.jpg', 2025, 0, 0, '2026-06-06 13:25:05.641622', 'GB');
INSERT INTO public.movies VALUES (2350, 12445, '해리 포터와 죽음의 성물 2', '["Adventure", "Fantasy"]', 'David Yates', '["Daniel Radcliffe", "Emma Watson", "Rupert Grint", "Ralph Fiennes", "Alan Rickman"]', '덤블도어 교장이 남긴 죽음의 성물의 단서를 쫓던 해리 포터는 볼드모트가 그토록 찾아 다닌 절대적인 힘을 가진 지팡이의 비밀을 통해 드디어 마지막 퍼즐을 완성한다. 볼드모트의 영혼이 담긴 다섯 번째 호크룩스를 찾기 위해 마법학교 호그와트로 돌아온 해리와 친구들은 그들을 잡으려는 보안마법에 걸려 위기를 맞지만 덤블도어의 동생인 에버포스의 도움으로 벗어난다. 그리고 그에게서 덤블도어와 어둠의 마법사 그린델왈드에 관한 놀라운 과거에 대해 알게 된다. 한편 볼드모트는 해리에 의해 호크룩스들이 파괴되었음을 느끼고 호그와트로 향한다. 해리를 주축으로 한 불사조 기사단과 죽음을 먹는 자들 간의 전투가 벌어지며 호그와트는 거대한 전쟁터로 변하게 되는데...', 'https://image.tmdb.org/t/p/w500/ehUeFvQeo8Vr2aDIKLsLbC8okcw.jpg', 2011, 0, 0, '2026-06-07 12:17:28.593318', 'GB');
INSERT INTO public.movies VALUES (347, 12779, '스웹트 어웨이', '["Comedy", "Romance"]', 'Guy Ritchie', '["Madonna", "Adriano Giannini", "Bruce Greenwood", "Jeanne Tripplehorn", "Elizabeth Banks"]', '천방지축 아줌마 엠버. 돈 많고, 능력 좋은 남편도 있지만, 모든 것이 불만스럽다. 남편 무시하기가 취미인 이 아줌마, 끝내는 여름 휴가를 가서도 불평 불만이다. 지중해 크루즈 여행이 된 여름휴가. 모든 사람을 하인 다루듯 하더니만 끝내는 선원인 주세페와는 세상에 둘도 없는 앙숙이 되어버린다.엠버는 고집을 부려 동굴탐사를 하겠다고 하고, 선원의 막내인 주세페는 하는 수 없이 그녀를 데리고 작은 고무보트를 내려 동굴이 있는 섬으로 향한다.하지만 천벌인지, 배가 난파되어 무인도에 덜렁 남겨진 엠버와 주세페. 호화로운 생활을 하던 엠버와는 달리 주세페는 금새 새로운 생활에 적응을 하게 되고, 아무것도 할 줄 아는게 없는 엠버는 주세페의 뒤를 졸졸 쫓아 다녀야 하는 상황이 되어버렸는데… 역전된 둘의 입장. 주세페, 마음 속으로 팡파레를 울린다.아무도 없는 무인도에 떨궈진 남과 여 사이에 흐르는 아리송한 분위기가...', 'https://image.tmdb.org/t/p/w500/rAa3nTeDpwgLX6XxnT3wR86C5WE.jpg', 2002, 0, 0, '2026-06-06 13:25:09.459153', 'GB');
INSERT INTO public.movies VALUES (388, 49026, '다크 나이트 라이즈', '["Action", "Crime", "Drama", "Thriller"]', 'Christopher Nolan', '["Christian Bale", "Gary Oldman", "Tom Hardy", "Joseph Gordon-Levitt", "Anne Hathaway"]', '배트맨이 조커와의 대결을 끝으로 세상에서 모습을 감춘 8년 후, 하비 덴트의 죽음에 대한 책임을 떠안은 배트맨은 모든 것을 희생하며 떠난다. 범죄방지 덴트법으로 인해 한동안 평화가 지속되던 고담시의 파멸을 예고하며 나타난 마스크를 쓴 잔인한 악당, 최강의 적 베인이 등장한다. 베인은 배트맨이 스스로 택한 유배 생활에 종지부를 찍게 하지만, 다시 돌아온 배트맨에게 베인은 만만한 상대가 아니다. 자신을 거부한 사람들의 고통을 지켜볼 것인가, 정의의 수호자로 나설 것인가. 배트맨은 승패를 알 수 없는 마지막 전투를 시작하려 하는데...', 'https://image.tmdb.org/t/p/w500/eq5P71YHwwaacEYKaQ72Wxy6BlT.jpg', 2012, 0, 0, '2026-06-06 13:25:11.020308', 'GB');
INSERT INTO public.movies VALUES (376, 1662317, '더 크래시: 사고인가, 살인인가', '["Documentary", "Crime"]', 'Gareth Johnson', '["Mackenzie Shirilla", "Tim Troup", "Rosie Graham", "Bubba Turner", "Faythe Walsh"]', '십 대 소녀가 몰던 차가 건물로 돌진해 동승했던 남자 친구와 그의 친구가 사망한다. 처음에는 비극적인 사고로 보였던 사건이 점차 살인 사건으로 밝혀지는 과정을 추적하는 다큐멘터리.INSERT INTO public.movies VALUES (2509, 411, '나니아 연대기: 사자, 마녀 그리고 옷장', '["Adventure", "Family", "Fantasy"]', 'Andrew Adamson', '["William Moseley", "Anna Popplewell", "Skandar Keynes", "Georgie Henley", "Liam Neeson"]', '제2차 세계대전 중의 영국. 공습을 피해 디고리 교수의 시골 별장으로 간 페번시가의 네 남매인 피터, 수잔, 에드먼드, 루시는 마법의 옷장을 통해 신비로운 나라 나니아로 들어선다. 말하는 동물들과 켄타우로스, 거인들이 평화롭게 어울려 사는 땅이었던 나니아는 사악한 하얀 마녀 제이디스에 의해 긴 겨울에 감금되어 있다. 게다가 이 겨울에는 크리스마스도 없다. 호기심 많은 루시, 퉁명스러운 에드먼드, 신중한 수잔, 분별 있는 맏이 피터는 고귀한 사자 아슬란의 인도로 제이디스의 싸늘한 주문을 깨는 싸움에 가담한다.', 'https://image.tmdb.org/t/p/w500/vSY6MgDWD5Ch5I87X8BaxZyydCI.jpg', 2005, 0, 0, '2026-06-07 12:17:35.790879', 'GB');
INSERT INTO public.movies VALUES (3835, 53445, '버려진 아이', '["Drama"]', 'Samantha Morton', '["Molly Windsor", "Robert Carlyle", "Susan Lynch", "Craig Parkinson", "Andrea Lowe"]', '열한 살의 루시는 아버지와 함께 살고 있다. 어느 날 아버지의 폭행이 또 시작된다. 루시는 어린이보호소에 보내지고 16살의 로렌과 같은 방을 쓰게 된다. 둘 사이에는 우정이 싹트고 로렌과 루시는 어느 날 보호소에서 도망치지만 로렌이 부츠를 훔치다가 잡혀 다시 보호소로 돌아오게 된다. 루시는 이 혼란을 벗어나 엄마를 찾으러 가지만 엄마는 루시에게 보호소로 가는 버스표를 사주고 버스 정류장까지 함께 걸어간다. 루시는 보호소로 가는 버스에 올라타 불안한 미래를 향해 돌아선다.', 'https://image.tmdb.org/t/p/w500/h8IJpERlvkOyIM6qpycvb0EsibI.jpg', 2009, 0, 0, '2026-06-08 06:24:35.9552', 'GB');
INSERT INTO public.movies VALUES (918, 32657, '퍼시잭슨과 번개도둑', '["Adventure", "Fantasy", "Family"]', 'Chris Columbus', '["Logan Lerman", "Brandon T. Jackson", "Alexandra Daddario", "Jake Abel", "Pierce Brosnan"]', '고대 그리스 신들과 함께 공존하고 있는 현대도시. 그 속에는 신과 인간 사이에서 태어나 각기 특별한 능력을 부여받은 데미갓들이 존재한다. 어느 날 세상에서 가장 강력한 무기인 제우스의 번개가 사라지는 사건이 발생하고 포세이돈의 아들인 퍼시 잭슨이 도둑으로 지명된다. 이로 인해 신들은 인간세계에 엄청난 재앙을 불러 올 대전쟁을 일으키려 하고, 물을 지배하는 능력을 소유한 퍼시잭슨은 지혜의 신 아테나의 딸 아나베스, 퍼시의 수호신 그로버와 함께 자신의 억울함을 풀고 신들의 파괴적인 전쟁을 막기위한 여정을 시작한다.  퍼시 잭슨은 그를 가로막는 신화 속 괴물 메두사 히드라 등과의 대결을 펼치고 엄마와 사라진 번개의 교환을 제안한 하데스가 살고있는 지옥의 세계로 향하는데..', 'https://image.tmdb.org/t/p/w500/lVS7ByeaOvo5zo7Ta4pB1PND4c4.jpg', 2010, 0, 0, '2026-06-06 13:25:31.195348', 'GB');
INSERT INTO public.movies VALUES (3982, 12201, '엣지 오브 다크니스', '["Crime", "Drama", "Mystery", "Thriller"]', 'Martin Campbell', '["Mel Gibson", "Ray Winstone", "Danny Huston", "Bojana Novaković", "Shawn Roberts"]', '보스턴 경찰서의 베테랑 형사이자 법과 규정에 정직한 지극히 평범한 경찰 크레이븐(멜 깁슨). 오랜만에 자신의 집에 찾아온 딸 엠마(보자나 노바코닉)와 오붓한 저녁을 즐기려던 순간, 바로 눈 앞에서 의문의 괴한에게 딸이 무참히 살해당한다.  언론과 동료들 모두 경찰인 그가 표적이었다고 파악한 후 수사에 착수하는 동안, 크레이븐은 딸의 죽음에 대한 의문을 품고 단독 수사에 나서게 된다. 그리고 딸이 ‘노스무어’라는 국가기밀연구소에서 근무했다는 사실과 그 조직이 국가와 비밀리에 계약을 맺고 있으며, 그들의 표적은 처음부터 자신이 아니라 딸이었음을 알게 된다.  국가와 연결된 거대한 음모에 가까워질수록, 그에게 다가오는 검은 위협은 계속되고… 딸의 억울한 죽음을 되갚기 위한 한 아버지의 생애 마지막 반격이 시작된다!', 'https://image.tmdb.org/t/p/w500/hVb1jGr9uRNxTbac4K6CtTkwTNV.jpg', 2010, 0, 0, '2026-06-08 06:24:41.997247', 'GB');
INSERT INTO public.movies VALUES (8764, 1040159, 'My Massive Cock', '["Documentary"]', 'Mike Nicholls', '["Matt Barr", "Julia Davis", "Andy Lee"]', NULL, 'https://image.tmdb.org/t/p/w500/wlvj1XbkHVItYE0ko4Xg4L08Ycj.jpg', 2022, 0, 0, '2026-06-08 07:29:07.356891', 'GB');
INSERT INTO public.movies VALUES (8765, 14574, '줄무늬 파자마를 입은 소년', '["Drama", "History"]', 'Mark Herman', '["Asa Butterfield", "Vera Farmiga", "David Thewlis", "Jack Scanlon", "Amber Beattie"]', '나치 장교인 아버지를 따라 베를린에서 폴란드로 이사 온 호기심 많은 8살 소년 브루노는 집 뒤 철조망 너머 농장이 궁금해진다. 어느 날 철조망을 사이에 두고 만난 줄무늬 파자마를 입은 소년 슈무엘과 친구가 된 브루노는 사라진 슈무엘의 아빠를 찾기 위해 비밀 작전을 제안하는데…', 'https://image.tmdb.org/t/p/w500/uml9iBpS6Ynuj0uFNQ3DdLIBHzq.jpg', 2008, 0, 0, '2026-06-08 07:29:08.02974', 'GB');
INSERT INTO public.movies VALUES (8766, 339403, '베이비 드라이버', '["Action", "Crime"]', 'Edgar Wright', '["Ansel Elgort", "Kevin Spacey", "Lily James", "Jon Hamm", "Jamie Foxx"]', '베이비는 탈출 전문 드라이버다. 은행 강도 등 범죄의 설계자인 박사에게 약점이 잡혀 일을 하고 있지만 손을 씻고 새로운 생활을 꿈꾼다. 어린 시절 교통사고를 당해 청력에 이상이 생긴 베이비는 이어폰을 끼고 음악을 들으며 안정을 유지한다. 어느 날 자주 가는 식당에서 종업원인 데보라를 만나 마음을 나누는 베이비. 하지만 마지막인 줄 알았던 범죄는 그의 발목을 놓아주지 않고 배츠, 버디, 달링과 함께 최후의 한탕을 준비한다.', 'https://image.tmdb.org/t/p/w500/fUfZ2zECULlN0pGPgXkez5rF7Hj.jpg', 2017, 0, 0, '2026-06-08 07:29:08.754532', 'GB');
INSERT INTO public.movies VALUES (959, 206647, '007 스펙터', '["Action", "Adventure", "Thriller"]', 'Sam Mendes', '["Daniel Craig", "Christoph Waltz", "Léa Seydoux", "Ralph Fiennes", "Monica Bellucci"]', '멕시코에서 일어난 폭발 테러 이후 MI6는 영국 정부에 의해 해체 위기에 놓인다. 자신의 과거와 연관된 암호를 추적하던 제임스 본드는 사상 최악의 조직 스펙터와 자신이 연관되어 있다는 사실을 알게 되고, 궁지에 몰린 MI6조차 그를 포기하면서 절체절명의 위기에 직면하는데...', 'https://image.tmdb.org/t/p/w500/reI1K84d4lgMwfWs583PmpWQsQ5.jpg', 2015, 0, 0, '2026-06-06 13:25:32.730876', 'GB');
INSERT INTO public.movies VALUES (8769, 929590, '시빌 워: 분열의 시대', '["Action", "Drama"]', 'Alex Garland', '["Kirsten Dunst", "Wagner Moura", "Cailee Spaeny", "Stephen McKinley Henderson", "Nelson Lee"]', '극단적 분열로 역사상 최악의 내전이 벌어진 미국. 연방 정부의 무차별 폭격과 서로를 향한 총탄이 빗발치는 상황 속에서 기자 리와 조엘, 새미 그리고 제시는 대통령을 인터뷰하기 위해 워싱턴으로 향한다. 내 편이 아니라면 바로 적이 되는 숨 막히는 현실, 이들은 전쟁의 순간을 누구보다 생생하게 마주하게 된다.', 'https://image.tmdb.org/t/p/w500/17aLLBfhf63QsSraVUJtaONnb6L.jpg', 2024, 0, 0, '2026-06-08 07:29:10.825017', 'GB');
INSERT INTO public.movies VALUES (955, 26466, '트라이앵글', '["Horror"]', 'Christopher Smith', '["Melissa George", "Liam Hemsworth", "Emma Lung", "Rachael Carpani", "Michael Dorman"]', '친구들과 요트 여행에 오른 싱글맘 제스.  갑작스러운 폭풍을 만나 일행 모두 바다에 표류하지만 운 좋게도 호화 유람선을 발견하고 도움을 청하기 위해 승선한다. 하지만 배 안에는 사람의 흔적만 느껴질 뿐 아무도 보이지 않고 바다 위, 마치 시간이 멈춰버린 듯한 거대한 크루즈 안에서 일행들은 한 명씩 의문의 죽음을 맞게 된다. 끝을 알 수 없이 계속 반복되는 죽음과 공포의 순간, 정해진 운명의 패턴을 바꿔야만 탈출에 성공할 수 있는데...  과연 제스는 반복되는 시간의 고리를 끊고 운명의 시계를 되돌릴 수 있을까?', 'https://image.tmdb.org/t/p/w500/wObkLgF4XiwuW43dVjBZ50dxZoM.jpg', 2009, 0, 0, '2026-06-06 13:25:32.720916', 'GB');
INSERT INTO public.movies VALUES (8771, 577922, '테넷', '["Action", "Thriller", "Sci-Fi"]', 'Christopher Nolan', '["John David Washington", "Robert Pattinson", "Elizabeth Debicki", "Kenneth Branagh", "Dimple Kapadia"]', '주도자는 미국의 한 요원으로 우크라이나 국립 오페라 극장의 한 사건에 투입되었다가 우크라이나 요원들에게 붙잡히게 되고 고문을 받지만 CIA가 준 자살 약을 먹고 자살을 택하게 된다. 그러나 이내 다시 눈을 뜬 주인공은 의문의 한 남자로부터 임무를 부여받는다. 그가 주도자에게 줄 수 있는 건 하나의 제스처와 하나의 단어 뿐. 시간의 흐름을 뒤집는 인버전을 통해 현재와 미래를 오가며 세상을 파괴하려는 사토르를 막기 위해 투입된 작전의 주도자는 인버전에 대한 정보를 가진 닐과 미술품 감정사이자 사토르에 대한 복수심이 가득한 그의 아내 캣과 협력해 미래의 공격에 맞서 제3차 세계대전을 막아야 한다.', 'https://image.tmdb.org/t/p/w500/i91wnVqkJf5ykDJq0XmIusvPFL3.jpg', 2020, 0, 0, '2026-06-08 07:29:12.208372', 'GB');
INSERT INTO public.movies VALUES (8772, 107, '스내치', '["Crime", "Comedy"]', 'Guy Ritchie', '["Jason Statham", "Alan Ford", "Stephen Graham", "Brad Pitt", "Dennis Farina"]', '네 손가락 프랭키는 자신이 훔친 고가의 다이아몬드를 뉴욕의 보스 아비에게 전달해야 하지만, 프랭키는 이를 도박권투에 건다. 무허가 권투 프로모터 터키쉬와 토미는 사기 도박권투를 추진한다. 아일랜드 집시 복서 미키는 4회에 쓰러지기로 했지만 오히려 상대를 기절시키고 만다. 한편, 도박권투에 참가하기로 했다가 실종된 프랭키를 찾아나선 아비는 전설적인 인물 총알 이빨 토니에게 사건을 의뢰한다. 얼마 후 프랭키는 시체로 발견되고 보석의 행방은 알 수가 없다. 이제 다이아몬드와 권투, 도박과 사기로 한데 엉킨 이들의 좌충우돌 해프닝이 시작되는데...', 'https://image.tmdb.org/t/p/w500/yfM3fJauIulaaztOUHzAb39fedo.jpg', 2000, 0, 0, '2026-06-08 07:29:12.874915', 'GB');
INSERT INTO public.movies VALUES (8776, 8009, '하이랜더', '["Adventure", "Action", "Fantasy"]', 'Russell Mulcahy', '["Christopher Lambert", "Roxanne Hart", "Clancy Brown", "Sean Connery", "Beatie Edney"]', '여명의 시간에서 태어난 우린 조용히 수세기를 살아왔다. 모임의 시기에 대비하여 투쟁하며 비밀스런 삶을 영위해왔다. 그때가 되면 선택받은 몇사람이 최후까지 싸우게 될 것이다. 아무도 우리가 사람들 속에 살았다는 것을 알 지 못한다. 지금까지도.}  맥클레인(Connor MacLeod: 크리스토퍼 램버트 분)는 지하주차장에서 장검을 휘두르며 한 사나이와 싸움을 벌인다. 결국 맥클레인이 상대의 목을 치자 그의 몸이 빛을 발하며 기를 빨아 들인다. 경찰은 사건을 조사하지만, 단서를 찾지 못한다. 경찰감식반원 브렌다(Brenda Wyatt: 록산느 하트 분)는 사건 현장에서 찾아낸 파편이 오래된 일본 사무라이 검의 일부임을 알아내고 맥클레인의 신분을 조사한다. 맥클레인은 몇번 접촉하면서 브랜다에게 정을 느껴 자신의 이야기를 털어 놓는다.  맥클레인은 450년전 스코틀랜드에서 태어난 불사신이다. 불사신으로 태어난 사람은 여럿이었지만, 불사신은 한 명만 존재해야한다는 규율 때문에 서로 결투를 하고, 상대방을 이기면 그 생명력으로 다시 연명하는 것이다. 그는 스승 라미렉스(Ramirez: 숀 코넬리 분)로부터 자신에게 숨겨져있던 힘을 찾게 되고, 이제는 어쩌면 최후가 될지도 모르는 쿠건과의 마지막 결전을 벌인다.', 'https://image.tmdb.org/t/p/w500/8Z8dptJEypuLoOQro1WugD855YE.jpg', 1986, 0, 0, '2026-06-08 07:29:15.713305', 'GB');
INSERT INTO public.movies VALUES (8777, 10764, '007 퀀텀 오브 솔러스', '["Adventure", "Action", "Thriller"]', 'Marc Forster', '["Daniel Craig", "Olga Kurylenko", "Mathieu Amalric", "Judi Dench", "Giancarlo Giannini"]', '카지노 로얄에서 최초의 임무를 성공적으로 완수한 007 제임스 본드. 하지만 첫사랑 베스퍼의 배신과 비극적인 죽음으로 강렬한 복수심에 휩싸인다. 한편 진실을 밝히기 위해 M과 함께 수수께끼의 인물 미스터 화이트를 심문하던 중, 베스퍼를 죽음으로 몰고간 배후 세력이 생각보다 훨신 거대하고 위험한 조직임을 알게 된다. 게다가 MI6 내부에까지 세력이 침투해 있어 제임스 본드가 믿을 수 있는 사람은 아무도 없다는 게 밝혀진다. 단서를 쫓던 007은 MI6 내의 누군가가 테러 조직의 돈 세탁을 위해 아이티에 은행 계좌를 만들었다는 정보를 입수하고 곧바로 아이티로 향하는데...', 'https://image.tmdb.org/t/p/w500/q1s0OFBJPQXNJ0FKeDCCOoKR70D.jpg', 2008, 0, 0, '2026-06-08 07:29:16.410126', 'GB');
INSERT INTO public.movies VALUES (8778, 758330, '굿 럭 투 유, 리오 그랜드', '["Romance", "Drama"]', 'Sophie Hyde', '["Emma Thompson", "Daryl McCormack", "Isabella Laughland", "Les Mabaleka", "Lennie Beare"]', '단 한번도 섹스에 만족해 본 적 없는 인생 6*년차 낸시. 남편과 아이들이 떠나고, 은퇴 후 혼자 남은 그녀는 자신만의 은밀한 버킷리스트를 실행해보기로 결심한다  "이끌리는 대로 다 잊고 당신만 생각해요” 외딴 호텔, 모든 게 자신 없는 ''낸시'' 앞에 젊고 매력적인 ''리오 그랜드''가 나타나고, 처음 경험하는 퍼스널 서비스는 예상치 못한 해방감을 선사하는데...  올 여름, 뜨겁게 용감해지고 싶은 당신을 위한 굿 럭 무비!', 'https://image.tmdb.org/t/p/w500/1ywjWmLHWHKAyOHGw0A3tcQclH0.jpg', 2022, 0, 0, '2026-06-08 07:29:17.078463', 'GB');
INSERT INTO public.movies VALUES (8779, 1287141, '뒷자리에 태워줘', '["Romance", "Drama", "Comedy"]', 'Harry Lighton', '["Harry Melling", "Alexander Skarsgård", "Lesley Sharp", "Douglas Hodge", "Jake Shears"]', '내성적이고 평범한 콜린은 누가 봐도 섹시한 외모의 레이와 우연히 마주친다. 그 남자의 직업도 배경도 모르지만, 단지 그의 존재만으로 콜린의 마음은 흔들린다. 레이와 만나면서 콜린은 지금까지 경험 못한 새로운 세상을 알게 된다. 비밀과 규칙으로 가득한 레이의 세계에 콜린은 조금 더 깊숙이, 가까이 다가가고 싶은데...', 'https://image.tmdb.org/t/p/w500/lUzCe4GLrtzhk4B9JCQbPTMFADw.jpg', 2025, 0, 0, '2026-06-08 07:29:17.760434', 'GB');
INSERT INTO public.movies VALUES (8780, 668489, '해벅', '["Action", "Crime", "Thriller", "Drama"]', 'Gareth Evans', '["Tom Hardy", "Jessie Mei Li", "Timothy Olyphant", "Forest Whitaker", "Justin Cornwell"]', '마약 절도 사건이 통제 불능으로 치닫는 상황. 지칠 대로 지친 경찰이 정치가의 아들을 구하기 위해 부패한 도시의 지하 범죄 세계와 싸우며 길을 헤쳐 나간다.', 'https://image.tmdb.org/t/p/w500/oYUJsUlH0aoTNiKWJ78LD0cUVov.jpg', 2025, 0, 0, '2026-06-08 07:29:18.540133', 'GB');
INSERT INTO public.movies VALUES (8781, 123069, 'Swedish Wildcats', '["Drama"]', 'Joseph W. Sarno', '["Diana Dors", "Cia Löwgren", "Solveig Andersson", "Christina Lindberg", "Peder Kinberg"]', NULL, 'https://image.tmdb.org/t/p/w500/f0NDfmHxSbVriCBOyzw6xnnx7uJ.jpg', 1972, 0, 0, '2026-06-08 07:29:19.324723', 'GB');
INSERT INTO public.movies VALUES (8782, 509, '노팅 힐', '["Romance", "Comedy"]', 'Roger Michell', '["Julia Roberts", "Hugh Grant", "Gina McKee", "Tim McInnerny", "Rhys Ifans"]', '윌리엄 태커(휴 그랜트분)는 웨스트 런던의 ‘노팅 힐’에 사는 소심한 남자. 역시 독신의 괴상한 친구 스파이크(리스 아이판스 분)와 함께 살고있는 그는, 노팅힐 시장 한쪽 구석에 위치한 조그마한 여행서적 전문점을 운영하며 살고 있다. 그에게는 미래에 대한 포부나 설계는 사치에 불과하다. 여느 때와 마찬가지로 무미건조한 하루를 보내고 있던 그는 세계적으로 유명한 인기 영화배우 안나 스콧(줄리아 로버츠 분)이 그의 책방 문을 열고 들어와 책을 사고 나가자 잠깐 동안에 일어난 이 엄청난 사건에 어쩔 줄을 모른다.', 'https://image.tmdb.org/t/p/w500/1AbAtQSgN4KKVODiiX2452dlDJD.jpg', 1999, 0, 0, '2026-06-08 07:29:20.077818', 'GB');
INSERT INTO public.movies VALUES (8783, 338953, '신비한 동물들과 덤블도어의 비밀', '["Fantasy", "Adventure"]', 'David Yates', '["Eddie Redmayne", "Jude Law", "Mads Mikkelsen", "Ezra Miller", "Dan Fogler"]', '1930년대, 제2차 세계대전에 마법사들이 개입하게 되면서 강력한 어둠의 마법사 그린델왈드의 힘이 급속도로 커진다. 덤블도어는 뉴트 스캐맨더에게 위대한 마법사 가문 후손, 마법학교의 유능한 교사, 머글 등으로 이루어진 팀에게 임무를 맡긴다. 이에 뉴트와 친구들은 머글과의 전쟁을 선포한 그린델왈드와 추종자들, 그의 위험한 신비한 동물들에 맞서 세상을 구할 거대한 전쟁에 나선다. 한편 전쟁의 위기가 최고조로 달한 상황 속에서 덤블도어는 더 이상 방관자로 머물 수 없는 순간을 맞이하고, 서서히 숨겨진 비밀이 드러나는데...', 'https://image.tmdb.org/t/p/w500/uvQbXjMgC5weQepx4jLJJ60H3N0.jpg', 2022, 0, 0, '2026-06-08 07:29:21.839355', 'GB');
INSERT INTO public.movies VALUES (6117, 591, '다빈치 코드', '["Thriller", "Mystery"]', 'Ron Howard', '["Tom Hanks", "Audrey Tautou", "Ian McKellen", "Jean Reno", "Paul Bettany"]', '특별강연을 위해 파리에 체류중이던 하버드대 기호학자 로버트 랭던(톰 행크스)은 깊은 밤 급박한 호출을 받는다. 루브르 박물관의 수석 큐레이터 자크 소니에르가 박물관 내에서 살해당한 시체로 발견된 것이다. 시체 주변에 가득한 이해할 수 없는 암호들… 그중 ‘P.S. 로버트 랭던을 찾아라’는 암호 때문에 살인누명까지 뒤집어쓴 랭던은 자크의 손녀이자 기호학자인 소피 느뷔(오드리 토투)와 함께 자크가 남긴 불가사의한 수수께끼를 풀어나가기 시작한다.  인류역사를 뒤바꿀 거대한 비밀이 벗겨지는 순간,  최초의 목격자는 당신이다!  랭던과 소피는 시시각각 좁혀오는 경찰 조직과 파슈 국장(장 르노)의 숨가쁜 포위망을 피하면서, ‘모나리자’, ‘암굴의 성모’ 등 천재화가 레오나르도 다 빈치의 작품들 속에 숨겨진 충격적인 비밀을 추적한다. 하지만 코드 속에 감춰진 실마리를 쫓아 진실에 접근할수록 비밀단체 시온 수도회가 지켜온 비밀을 지워버리려는 ‘오푸스 데이’의 추격은 더욱 격렬해지고, 마침내 두 사람은 인류 역사를 송두리째 뒤바꿀 거대한 비밀과 마주하게 되는데...', 'https://image.tmdb.org/t/p/w500/52cjQg88xZNx8JKU7GpbIf19mL1.jpg', 2006, 0, 0, '2026-06-08 06:54:19.385691', 'GB');
INSERT INTO public.movies VALUES (8787, 76025, '셰임', '["Drama"]', 'Steve McQueen', '["Michael Fassbender", "Carey Mulligan", "James Badge Dale", "Nicole Beharie", "Lucy Walters"]', '브랜든 설리반(마이클 패스벤더)은 좋은 직장과 멋진 외모에 뉴욕 시가지가 한눈에 보이는 아파트까지 소유한 여피족. 그러나 그런 화려한 외면 뒤에 섹스 중독이라는 비밀이 숨어 있다. 깔끔하고 나무랄 데 없는 집 안 곳곳에는 도색잡지들이 숨겨져 있고, 직장과 집의 컴퓨터에는 음란물이 그득하며, 여자친구 대신 콜걸들이 그의 집을 방문한다. 브랜든의 완벽함은 동생 씨씨(캐리 멀리건)의 방문으로 흔들리기 시작한다. 밤무대 가수인 그녀는 브랜든에게 잠시 머물게 해달라고 부탁한다. 은밀한 이중 생활이 위태로워지자 브랜든은 점점 더 수위 높은 쾌락을 탐닉하게 되는데…', 'https://image.tmdb.org/t/p/w500/2VIEUhHYJ0SydDc3JJt4Ao7LUpf.jpg', 2011, 0, 0, '2026-06-08 07:29:25.611726', 'GB');
INSERT INTO public.movies VALUES (964, 508, '러브 액츄얼리', '["Comedy", "Romance", "Drama"]', 'Richard Curtis', '["Hugh Grant", "Alan Rickman", "Emma Thompson", "Liam Neeson", "Martine McCutcheon"]', '크리스마스를 앞둔 런던, 다우닝가에 둥지를 튼 총리는 식음료 담당자 나탈리에게 호감을 가지며, 작가 제이미는 파출부 오렐리아에게 매력을 느낀다. 대니얼은 아내를 잃은 슬픔에 빠져 있고, 양아들 샘은 미국에서 온 조안나에게 잘 보이려고 고민 중이며, 총리의 여동생 캐런은 남편의 부정을 눈치챈다. 새라는 동료 칼을 짝사랑하며, 친구 피터와 줄리엣의 결혼을 접하는 마크의 표정은 우울하다. 여기에 마약중독에서 빠져나온 록 가수 빌리 맥, 미국 여자들과 즐기기 위해 미국행을 결심하는 콜린 등이 뒤얽히며 사랑의 갖가지 모습이 펼쳐진다.', 'https://image.tmdb.org/t/p/w500/tvaPe5kPoJCLn0xycctkHUaph7w.jpg', 2003, 0, 0, '2026-06-06 13:25:33.47498', 'GB');
INSERT INTO public.movies VALUES (8789, 630586, '데드 캠프: 리부트', '["Horror", "Thriller"]', 'Mike P. Nelson', '["Charlotte Vega", "Adain Bradley", "Bill Sage", "Emma Dumont", "Dylan McTee"]', '젠 과 그녀의 다섯 절친들은 버지니아의 마을 애팔레치안에서 하이킹과 캠핑을 하고 있다. 남북전쟁 요새를 방문하러 가는 길에 경로를 벗어났다는 걸 알았을 때 그들은 ‘재단’이라 불리는 공동체 마을을 우연히 발견하게 된다. 그곳 사람들은 1800년대 이후, 미국 전역으로부터 자신들을 차단한 채 산 중턱에서 정착하여 살아가고 있었다. 결국 외딴곳에서 외부 영향으로부터 자신들을 보호하기 위해 그 어떤 일도 서슴없이 저지르는 마을 주민들과 엮이며 끔찍한 사건에 휘말리게 되는데...', 'https://image.tmdb.org/t/p/w500/bHtwQS2Egb2T9GPRAT0aiZLWgdt.jpg', 2021, 0, 0, '2026-06-08 07:29:27.116113', 'GB');
INSERT INTO public.movies VALUES (8790, 853, '에너미 앳 더 게이트', '["History"]', 'Jean-Jacques Annaud', '["Jude Law", "Joseph Fiennes", "Rachel Weisz", "Ed Harris", "Bob Hoskins"]', '2차 세계대전 당시 독일과 소련이 대치했던 스탈린그라드 전장. 독일군의 강력한 공격으로 소련군이 궁지에 몰린 상황에서 폐허가 된 전쟁터를 헤매던 소련 선전장교 다닐로프(조셉 파인즈)는 우연히 명사수 바실리(주드 로)의 뛰어난 저격솜씨를 목격한다.  저하된 소련군의 사기를 되살리기 위해 영웅이 필요하다고 판단한 다닐로프는 바실리를 전문적인 저격수로 만들고 전장에 뿌려지는 전단을 통해 전설적인 영웅으로 부상시킨다. 바실리의 뛰어난 솜씨로 나치 장교들이 하나하나 죽어가자 독일군은 역시 저격수인 코니그 소령(에드 해리스)을 내세워 바실리를 없애려 한다.  바실리는 코니그와의 숨막히는 전쟁에 빠져드는 동시에 타냐(레이첼 와이즈)라는 소련 여군 병사를 사이에 두고 다닐로프와 묘한 연적관계에 놓이는데...', 'https://image.tmdb.org/t/p/w500/y9OPO2657z3nvc42H2l4X4MSAwH.jpg', 2001, 0, 0, '2026-06-08 07:29:27.87505', 'GB');
INSERT INTO public.movies VALUES (8791, 49047, '그래비티', '["Sci-Fi", "Thriller", "Drama"]', 'Alfonso Cuarón', '["Sandra Bullock", "George Clooney", "Ed Harris", "Orto Ignatiussen", "Phaldut Sharma"]', '허블 우주 망원경을 수리하기 위해 우주를 탐사하던 라이언 스톤 박사는 폭파된 인공위성의 잔해와 부딪히면서 우주 공간에 홀로 남겨진다. 탑승했던 왕복선은 파괴됐고 산소는 희박해져간다. 홀로 남겨졌다는 공포가 그녀를 휘감아 가던 순간, 그녀의 앞에 베테랑 동료 우주비행사인 매트 코왈스키가 구세주처럼 나타난다. 인공위성의 잔해가 지구를 한 바퀴 돌아 다시 덮쳐오기까지 걸리는 시간은 단 90분. 그 전에 그들은 우주 왕복선과 가까이 있는 ISS로 이동해서 소유즈를 활용해 지구로 귀환하기로 하는데...', 'https://image.tmdb.org/t/p/w500/u8ffl7CRAS12KA8eQEtkLuHg8Fm.jpg', 2013, 0, 0, '2026-06-08 07:29:28.625833', 'GB');
INSERT INTO public.movies VALUES (8792, 1562, '28주 후', '["Horror", "Thriller", "Sci-Fi"]', 'Juan Carlos Fresnadillo', '["Robert Carlyle", "Rose Byrne", "Jeremy Renner", "Harold Perrineau", "Catherine McCormack"]', '인간을 좀비로 만드는 분노 바이러스가 영국을 휩쓸고 지나간 후 6개월이 지난 시점. 미국 군대가 바이러스와의 전쟁을 선언한 뒤 마치 그들이 승리를 거둔 듯해 보인다. 그리고 점차 도시는 질서를 되찾는다. 런던을 떠났던 시민들은 점차 도시로 돌아오고, 헤어졌던 가족은 재회의 기쁨을 나눈다. 하지만, 사실 바이러스는 죽지 않았고, 사람들이 모르는 사이 다시금 도시를 초토화 시키려고 하는데..', 'https://image.tmdb.org/t/p/w500/2BflgoKrzMMoVgn9md0uSPJ0GTU.jpg', 2007, 0, 0, '2026-06-08 07:29:29.384104', 'GB');
INSERT INTO public.movies VALUES (8793, 516806, '라스트 센티널', '["Sci-Fi", "Thriller"]', 'Tanel Toom', '["Kate Bosworth", "Lucien Laviscount", "Martin McCann", "Thomas Kretschmann", "Ben Pullen"]', NULL, 'https://image.tmdb.org/t/p/w500/pD1o9B0ibENdNroYrBCQemG2jnr.jpg', 2023, 0, 0, '2026-06-08 07:29:30.127792', 'GB');
INSERT INTO public.movies VALUES (8797, 10140, '나니아 연대기: 새벽 출정호의 항해', '["Adventure", "Family", "Fantasy"]', 'Michael Apted', '["Georgie Henley", "Skandar Keynes", "Ben Barnes", "Will Poulter", "Anna Popplewell"]', '2차 세계대전이 한창인 영국. 페번시가의 막내들인 에드먼드(스캔다 케인스)와 루시(조지 헨리)는 까탈스럽고 불평 많은 사촌 유스터스(윌 폴터)의 집에 얹혀살고 있다. 어느 날 루시의 방에 걸려 있는 그림 속에서 갑자기 바닷물이 쏟아져 나오며 세 아이는 나니아의 세계로 빨려들어간다. 그들이 망망대해에서 만난 것은 새벽 출정호를 타고 실종된 일곱명의 영주를 찾아 헤매던 캐스피언 왕자(벤 반스) 일행. 이들은 첫 번째 항해지인 론 제도의 영주 베른에게, 아슬란에게서 받은 일곱개의 마법검을 소유한 일곱명의 영주가 사라지면서 언제부터인가 바다에서 녹색 안개가 나타나 배와 사람들을 집어삼켜왔다는 사실을 전해듣는다.', 'https://image.tmdb.org/t/p/w500/3aHCAKaLZv2XDM6hKwDniunZW0N.jpg', 2010, 0, 0, '2026-06-08 07:29:33.107265', 'GB');
INSERT INTO public.movies VALUES (8798, 1572073, 'The Deadly Little Mermaid', '["Horror"]', 'Cameron Uzoka', '["Elliott Eason", "Sophia Carroll", "Eleanor Mackenzie", "Anastasia Nikolaeva", "Maddy Baskerville"]', NULL, 'https://image.tmdb.org/t/p/w500/uye25uG7k8r3NNPLyPiKOiRnFRF.jpg', 2026, 0, 0, '2026-06-08 07:29:33.851317', 'GB');
INSERT INTO public.movies VALUES (8799, 646, '007 살인번호', '["Adventure", "Action", "Thriller"]', 'Terence Young', '["Sean Connery", "Ursula Andress", "Joseph Wiseman", "Jack Lord", "Anthony Dawson"]', '미국의 로켓 발사 실험이 계속 실패하는 상황에서 자메이카 지역에 파견된 스트랭웨이스 교수가 정체불명의 적에게 살해되는 사건이 발생한다. 살해된 스트랭웨이스 교수는 사실 영국의 비밀 첩보기관 MI6의 요원이었고, 이 불가사의한 사건을 수사하기 위해 제임스 본드는 자메이카로 향한다. 단서를 찾아 스트랭웨이스 교수의 집을 찾아간 본드는 책상 위의 사진에서 콰럴이란 이름의 어느 흑인 남성이 교수와 있는 것을 보게된다. 본드는 그를 찾아가고, 그에게 크랩 키 섬에 사는 괴짜 박사에 대한 이야기를 듣고 크랩 키 섬으로 잠입한다.', 'https://image.tmdb.org/t/p/w500/f9HsemSsBEHN5eoMble1bj6fDxs.jpg', 1962, 0, 0, '2026-06-08 07:29:34.592689', 'GB');
INSERT INTO public.movies VALUES (8800, 1140521, '머나먼나무의 숨겨진 비밀', '["Adventure", "Family", "Fantasy"]', 'Ben Gregor', '["Billie Gadsdon", "Nicola Coughlan", "Delilah Bennett-Cardy", "Phoenix Laroche", "Nonso Anozie"]', '현대 도시 생활에 지친 가족이 영국 외곽 시골로 이사를 와서 , 우연히 거대한 나를 발견하게 되고,  나무 꼭대기를 향해 오를때 마다 매번 바뀌는 환상의 세계를 모험하게 된다.', 'https://image.tmdb.org/t/p/w500/udXvLxC5gAqN8SinemyFBEcHpTf.jpg', 2026, 0, 0, '2026-06-08 07:29:35.328562', 'GB');
INSERT INTO public.movies VALUES (8801, 787699, '웡카', '["Comedy", "Family", "Fantasy"]', 'Paul King', '["Timothée Chalamet", "Calah Lane", "Keegan-Michael Key", "Hugh Grant", "Paterson Joseph"]', '마법사이자 초콜릿 메이커 윌리 웡카의 꿈은 디저트의 성지, 달콤 백화점에 자신만의 초콜릿 가게를 여는 것. 가진 것이라고는 낡은 모자 가득한 꿈과 단돈 12소베른 뿐이지만 특별한 마법의 초콜릿으로 사람들을 사로잡을 자신이 있다. 하지만 먹을 것도, 잠잘 곳도, 의지할 사람도 없는 상황 속에서 낡은 여인숙에 머물게 된 웡카는 스크러빗 부인과 블리처의 계략에 빠져 눈더미처럼 불어난 숙박비로 인해 순식간에 빚더미에 오른다. 게다가 밤마다 초콜릿을 훔쳐가는 작은 도둑 움파 룸파의 등장과 달콤 백화점을 독점한 초콜릿 카르텔의 강력한 견제까지. 세계 최고의 초콜릿 메이커가 되는 길은 험난하기만 한데…', 'https://image.tmdb.org/t/p/w500/lQ4cwauq2jeTkka9RvdMBTVPLMH.jpg', 2023, 0, 0, '2026-06-08 07:29:36.167685', 'GB');
INSERT INTO public.movies VALUES (8802, 10528, '셜록 홈즈', '["Adventure", "Crime", "Mystery"]', 'Guy Ritchie', '["Robert Downey Jr.", "Jude Law", "Rachel McAdams", "Mark Strong", "Eddie Marsan"]', '세기의 명탐정_“범죄는 흔하다. 그러나 논리는 흔치 않다” 셜록 홈즈, 천재적인 추리 능력과 주먹의 힘까지 갖추고 친구 왓슨 박사 와 함께 치밀하게 얽힌 미스터리 속에서 진실을 찾아내는 명탐정. 그에게 이제껏 경험하지 못했던 최대의 위협이자 지금껏 그토록 갈구했던 진정한 모험이 몰려오고 있었다. 예고된 살인_“홈즈, 당신과 나는 자연 법칙을 뒤집어 놓을 여정에 올랐소”다섯 명의 여인들이 종교 의식의 제물로 끔찍하게 살해되는 사건이 잇따라 발생하고, 홈즈와 왓슨은 간발의 차이로 마지막 희생자가 될뻔한 여인을 구한다. 범인은 비밀 종교집단 소속의 블랙우드. 붙잡힌 블랙우드는 사형 집행일이 다가올수록 강력한 어둠의 힘을 발휘하고, 자신의 죽음은 계획의 일부에 지나지 않는다며 홈즈에게 경고한다. 죽은 자의 부활_“증거 없는 이론은 위험하네. 사실을 이론에 맞추려 들테니” 블랙우드의 경고는 현실로 나타나고, 죽었던 그의 부활은 도시 전체를 공포 속에 몰아넣는다. 그러나 이것은 홈즈에게는 게임의 시작일 뿐. 블랙우드의 치명적인 음모를 저지하기 위해 홈즈와 왓슨은 고대의 신비한 주술과 현대의 경이로운 신기술이 혼재한 세계로 뛰어든다. 진정한 목적_“가장 사소한 단서가 가장 중요한 증거가 되는 법이지”그러나 홈즈가 해결해야 할 것은 사건만이 아니었다. 그의 앞에 헤어진 연인 아이린 이 등장해 적인지 아닌지 모호한 행동으로 그를 더욱 혼란에 빠뜨린다. 한편, 최강의 콤비 플레이로 사건을 파헤치던 홈즈와 왓슨은 단서들이 공통의 연결고리로 어떤 징후를 나타낸다는 것을 발견하고, 이것이 세상을 파멸시킬 거대한 음모였음을 알게 되는데… 정확한 논리를 무기로, 일격의 주먹을 방어막으로, 세상을 구할 홈즈의 추리가 시작된다!', 'https://image.tmdb.org/t/p/w500/57lDlyrA7tWDyscroixKSJRerFU.jpg', 2009, 0, 0, '2026-06-08 07:29:36.914499', 'GB');
INSERT INTO public.movies VALUES (8803, 37724, '007 스카이폴', '["Action", "Adventure", "Thriller"]', 'Sam Mendes', '["Daniel Craig", "Judi Dench", "Javier Bardem", "Ralph Fiennes", "Naomie Harris"]', '상관 M의 지시에 따라 현장 요원 이브와 함께 임무를 수행하던 제임스 본드는 달리는 열차 위에서 적과 치열한 결투를 벌이다 M의 명령으로 이브가 쏜 총에 맞고 추락하여 실종된다. 이에 임무가 실패로 끝나자 전세계에서 테러단체에 잠입해 임무를 수행 중이던 비밀 요원들의 정보가 분실되고 MI6는 사상 최대의 위기에 빠진다.  설상가상으로 M의 과거에 얽힌 비밀로 인해 미스터리한 적 실바에게 공격을 받은 MI6는 붕괴 위험에 처하게 되고, 이 사건으로 인해 M은 책임 추궁을 당하며 퇴출 위기에 놓인다. 이 때 죽음의 고비에서 부활한 제임스 본드가 M의 곁으로 다시 돌아오는데...', 'https://image.tmdb.org/t/p/w500/oHkZwUYpfrAnkKcJh3BdPYsBSPX.jpg', 2012, 0, 0, '2026-06-08 07:29:38.491229', 'GB');
INSERT INTO public.movies VALUES (8804, 1199193, 'Pose', '["Thriller"]', 'Jamie Adams', '["James McAvoy", "Lucas Bravo", "Leila Farzad", "Almudena Amor", "Aisling Franciosi"]', NULL, 'https://image.tmdb.org/t/p/w500/qhyyyWrHUbl6QG4udAJj17CBa5.jpg', 2026, 0, 0, '2026-06-08 07:29:39.245952', 'GB');
INSERT INTO public.movies VALUES (8807, 9392, '디센트', '["Adventure", "Horror"]', 'Neil Marshall', '["Shauna Macdonald", "Natalie Mendoza", "Alex Reid", "MyAnna Buring", "Saskia Mulder"]', '죽음을 부르는 미로 | 전세계가 놀란 $44,000,000의 충격! |  라이온스 게이트의 새로운 공포가 온다!INSERT INTO public.movies VALUES (8808, 627, '트레인스포팅', '["Drama", "Crime"]', 'Danny Boyle', '["Ewan McGregor", "Ewen Bremner", "Jonny Lee Miller", "Kevin McKidd", "Robert Carlyle"]', '스코틀랜드 에딘버러의 뒷골목에 살고 있는 렌튼, 스퍼드, 벡비, 식보이, 토미는 아무런 희망 없이 하루하루를 살아간다. 이들에게 있어 유일한 즐거움은 마약을 하는 것이다. 이들은 마약을 사기 위해 강도 행각을 벌이고, 아기가 마약을 먹고 죽는 상황까지 벌어지게 된다. 그 후 백화점을 털던 스퍼드는 실형을 선고 받고, 렌튼은 끔찍한 과정을 거쳐 마약을 끊고 취직을 한다. 건실하던 토미는 에이즈로 죽고, 벡비는 장물아비로, 식보이는 포주 노릇을 한다. 하지만 이것도 잠시, 이들은 다시 모여 마약을 팔아 큰 돈을 챙기고 렌튼은 친구들이 잠든 사이에 돈가방을 들고 혼자 달아나는 사건이 벌어지는데...', 'https://image.tmdb.org/t/p/w500/phJA8xmzrlzAElBRm1xQnr0PCWU.jpg', 1996, 0, 0, '2026-06-08 07:29:42.188198', 'GB');
INSERT INTO public.movies VALUES (2430, 1484353, 'Situationship', '["Romance"]', 'Jade Winters', '["Helen Laurens", "Sapphire Brewer-Marchant", "Rosa Armstrong", "Christina Baston"]', NULL, 'https://image.tmdb.org/t/p/w500/bj5sgq9TJh7GTA7fnyVtmbSB0Vp.jpg', 2025, 0, 0, '2026-06-07 12:17:32.12314', 'GB');
INSERT INTO public.movies VALUES (8810, 522627, '젠틀맨', '["Action", "Comedy", "Crime"]', 'Guy Ritchie', '["Matthew McConaughey", "Charlie Hunnam", "Michelle Dockery", "Jeremy Strong", "Lyne Renee"]', '유럽을 장악한 업계의 절대강자 믹키 피어슨(매튜 매커너히)은 자신이 세운 마리화나 제국을 부유한 미국인 매튜(제레미 스트롱)에게 팔아넘기려 하는데, 주변인들이 그런 그를 가만히 두지 않는다. 한 사람은 믹키에게 앙심을 품은 타블로이드지의 편집장 빅 데이브(에디 마산)가 고용한 사립탐정 플레처(휴 그랜트)다. 플레처는 믹키와 그의 오른팔 레이먼드(찰리 허냄)를 염탐한다. 다른 사람은 중국계 갱스터 드라이 아이(헨리 골딩)다. 믹키의 사업을 인수하려다 거절당한 드라이 아이는 모종의 음모를 꾸민다. 그 와중에 믹키의 대마초 재배 지하실마저 젊은 괴한들에게 공격당하는데...', 'https://image.tmdb.org/t/p/w500/361ksMhxn9tCYhVvzfkW8c2ZLYl.jpg', 2020, 0, 0, '2026-06-08 07:29:43.68699', 'GB');
INSERT INTO public.movies VALUES (8811, 747, '새벽의 황당한 저주', '["Horror", "Comedy"]', 'Edgar Wright', '["Simon Pegg", "Nick Frost", "Kate Ashfield", "Lucy Davis", "Dylan Moran"]', '별볼일 없는 주인공 숀이 여자친구 리즈에게 채일 무렵, 영국에는 정체를 알 수 없는 전염병이 돌면서 거리는 사람들을 먹어치우는 좀비들로 가득 찬다. 주위 사람들이 하나둘 좀비로 변해가는 이 뒤죽박죽의 상황에서 숀은 여자친구인 리즈를 구해내고 그녀의 사랑을 다시 얻기 위해 고군분투한다.', 'https://image.tmdb.org/t/p/w500/nHuO4izZQD3ssjk4C73jFogsRg6.jpg', 2004, 0, 0, '2026-06-08 07:29:44.44501', 'GB');
INSERT INTO public.movies VALUES (8812, 749170, '국가 원수', '["Action", "Thriller", "Comedy"]', 'Ilya Naishuller', '["John Cena", "Idris Elba", "Priyanka Chopra Jonas", "Paddy Considine", "Carla Gugino"]', '영국 총리 와 미국 대통령 의 경쟁 때문에 양국의 동맹이 위태로워진다. 그러나 강력한 적대 세력의 표적이 된 둘은 어쩔 수 없이 서로 의지하며 국경을 넘나드는 위험한 도주를 함께하고 영국 비밀정보국 요원 노엘 과 협력해 자유 진영을 위협하는 음모를 타개해야 한다.', 'https://image.tmdb.org/t/p/w500/4O7dRWoZ8PhP8i2S4bqCJRz93i0.jpg', 2025, 0, 0, '2026-06-08 07:29:45.184839', 'GB');
INSERT INTO public.movies VALUES (8813, 8413, '이벤트 호라이즌', '["Horror", "Sci-Fi", "Mystery"]', 'Paul W. S. Anderson', '["Laurence Fishburne", "Sam Neill", "Kathleen Quinlan", "Joely Richardson", "Richard T. Jones"]', '서기 2040년. 광속보다 빠른속도로 우주를 여행하던 탐사선 ''이벤트 호라이즌''호가 실종된다. 7년 후, 숱한 의문을 남긴 채 사라진 이벤트 호라이즌호에서 희미하게 생존 신호를 확인한 미 우주국은 이 우주선에 대한 여러가지 의문점과 생존자 확인을 위해 구조선 ''루이스 앤 클락''호를 파견한다. 밀러(로렌스 피쉬번)를 리더로 한 이 구조대에는 이벤트 호라이즌호를 직접 제작했던 윌리엄 위어(샘 닐) 박사도 포함돼 있다. 밀러 선장을 비롯한 루이스 앤 클락호의 대원들은 목적지인 해왕성 궤도에서 이벤트 호라이즌를 발견하고 생명의 흔적이 느껴지지 않는 이 우주선에 올라 수색작업을 벌이지만 이벤트 호라이즌호에는 대원들이 모두 숨진 상태이다. 그런데 수색 작업에 투입된 대원들이 모두 이상한 환영에 시달리게 되고 하나 둘 목숨을 잃는 일이 발생하는데...', 'https://image.tmdb.org/t/p/w500/keXPIx088rTjeLr45S1DrMlXHV7.jpg', 1997, 0, 0, '2026-06-08 07:29:45.923817', 'GB');
INSERT INTO public.movies VALUES (8814, 9693, '칠드런 오브 맨', '["Sci-Fi", "Thriller", "Action"]', 'Alfonso Cuarón', '["Clive Owen", "Clare-Hope Ashitey", "Chiwetel Ejiofor", "Julianne Moore", "Michael Caine"]', '서기 2027년, 전 세계 모든 여성이 알 수 없는 이유로 임신기능을 상실한 종말의 시대. 세계 각지에서는 폭동과 테러가 비일비재하고 대부분의 국가가 무정부 상태로 무너져 내린 가운데, 유일하게 군대가 살아남은 국가 영국에는 불법이민자들이 넘쳐 난다. 한편, 아들이 죽은 후, 세상을 바꾸겠다는 의지 따위는 모두 잃어버린 남자 테오. 그의 앞에 20년 만에 나타난 전 부인 줄리안은 기적적으로 임신한 흑인 소녀 키를 그에게 부탁한다. 믿을 수 없는 기적을 눈 앞에서 마주한 테오. 그는 키가 안전하게 출산할 수 있도록 인간프로젝트를 성공시켜야만 하는데...', 'https://image.tmdb.org/t/p/w500/bIYqTLOtCXTivWaAbjWGEY8sVnG.jpg', 2006, 0, 0, '2026-06-08 07:29:46.707722', 'GB');
INSERT INTO public.movies VALUES (8817, 2270, '스타더스트', '["Adventure", "Fantasy", "Romance", "Family"]', 'Matthew Vaughn', '["Charlie Cox", "Claire Danes", "Michelle Pfeiffer", "Mark Strong", "Jason Flemyng"]', '어느 날 신비의 별 하나가 마법의 영토 ‘스톰홀드’에 떨어진다. 첫 사랑 빅토리아(시에나 밀러)에게 사랑을 고백하던 인간 마을의 청년 트리스탄(찰리 콕스)은 그녀의 마음을 얻기 위해 하늘에서 떨어진 그 별을 갖고 오겠다는 허무맹랑한 약속을 하고 만다. 사랑을 얻기 위해 별을 찾아 금기의 땅 ‘스톰홀드’에 발을 디디게 된 트리스탄. 그리고 그 곳에서 만난 아름다운 별의 여인 이베인(클레어 데인즈).  이제 진정한 사랑을 얻으려는 청년 트린스탄(찰리 콕스)과 영원한 젊음을 쫓는 마녀 라미아(미셀 파이퍼), 스톰홀드의 왕이 되고픈 세 왕자, 그리고 정체불명의 다혈질 해적 세익스피어(로버트 드니로)까지, 원하는 모든 것을 이룰 수 있는 신비의 별, 이베인을 둘러싼 광활한 모험이 시작된다.', 'https://image.tmdb.org/t/p/w500/hOtuYZW2EvHg2MWV4Kz3ZJZWayu.jpg', 2007, 0, 0, '2026-06-08 07:29:48.976935', 'GB');
INSERT INTO public.movies VALUES (8818, 34000, '백만장자', '["Comedy"]', 'Ronald Neame', '["Gregory Peck", "Ronald Squire", "Joyce Grenfell", "A.E. Matthews", "Maurice Denham"]', '두명의 백만장자 형제는 희한한 내기를 한다. 자신들이 발행한 수표 한장을 누군가에게 건네주고 한달 후 건내받는 것이다. 그러던 중 빈털터리 신세인 헨리 아담스에게 두명의 신사가 다가와 백만파운드를 주며 제안을 한다. 헨리는 백만파운드 지폐를 소유했다는 사실만으로 어딜가나 대접을 받고, 사람들은 그들의 재산을 헨리에게 투자한다.', 'https://image.tmdb.org/t/p/w500/vB5bI215fOPg3rDkOwP1aS4Z2R.jpg', 1954, 0, 0, '2026-06-08 07:29:49.717631', 'GB');
INSERT INTO public.movies VALUES (8819, 343668, '킹스맨: 골든 서클', '["Action", "Adventure", "Comedy", "Crime", "Sci-Fi"]', 'Matthew Vaughn', '["Taron Egerton", "Colin Firth", "Julianne Moore", "Mark Strong", "Hanna Alström"]', '철저하게 비밀에 둘러싸인 채 세상을 안전하게 지키는 임무를 수행해온 독자적인 국제 정보 조직 킹스맨. 그러나 어느 날 국제적 범죄조직 골든 서클에 의해 킹스맨 본부가 무참히 파괴된다. 에그시와 멀린은 킹스맨 최후의 날 규약에 따라 발견된 위스키 병에서 미국 켄터키라는 키워드를 얻게 되고, 그 곳에서 형제 조직인 스테이츠맨의 존재를 알게 된다. 전 세계를 장악하기 위해 위협적인 비지니스를 추진 중인 골든 서클과 수장 포피. 이들의 계획을 막기 위한 킹스맨과 스테이츠맨의 작전이 시작된다.', 'https://image.tmdb.org/t/p/w500/fq0WdmuL6JnBSH3jD2rszcOex68.jpg', 2017, 0, 0, '2026-06-08 07:29:50.467654', 'GB');
INSERT INTO public.movies VALUES (8820, 36669, '007 어나더데이', '["Adventure", "Action", "Thriller"]', 'Lee Tamahori', '["Pierce Brosnan", "Halle Berry", "Toby Stephens", "Rosamund Pike", "Rick Yune"]', '북한내 무기 밀매 현장에 위장 잠입한 제임스 본드는 그곳에서 강경파 일원인 문대령과 자오를 만나게 된다. 그러나 자오에 의해 정체가 발각되고, 대결 도중 문대령이 숨지자 본드는 북한군에 붙잡히게 된다. 수개월 후, 본드는 포로협상으로 풀려나지만 누명을 쓰고 모든 지위를 박탈당한다. 그는 배후에 자오의 음모가 도사리고 있음을 직감하고 혼자서 사건 해결에 나선다. 한편 본드는 자오의 행방을 추적하던 중 신비의 여인 징크스와 베일에 쌓인 백만장자 구스타프를 만나게 된다. 본드는 구스타프와 자오 사이에 숨겨진 음모를 밝혀내기 위해 아이슬랜드로 향하는데...', 'https://image.tmdb.org/t/p/w500/zIrNbT8pg2SZPPxkbI3vOMrtEVk.jpg', 2002, 0, 0, '2026-06-08 07:29:51.247977', 'GB');
INSERT INTO public.movies VALUES (8821, 1098006, '''젊음의 샘'' - Fountain of Youth', '["Adventure", "Fantasy", "Mystery"]', 'Guy Ritchie', '["John Krasinski", "Natalie Portman", "Eiza González", "Domhnall Gleeson", "Arian Moayed"]', '보물 사냥의 귀재는 인생을 뒤바꿀 모험을 위해 팀을 꾸린다. 하지만 매 순간 닥치는 위험을 헤쳐 나가기 위해 자신보다 더 뛰어난 두뇌, 바로 소원했던 여동생이 필요하다.', 'https://image.tmdb.org/t/p/w500/futVnLcy1S4sDFuFvyjpRc2Fw8p.jpg', 2025, 0, 0, '2026-06-08 07:29:52.104948', 'GB');
INSERT INTO public.movies VALUES (8822, 10483, '데스 레이스', '["Action", "Thriller", "Sci-Fi"]', 'Paul W. S. Anderson', '["Jason Statham", "Joan Allen", "Ian McShane", "Tyrese Gibson", "Natalie Martinez"]', '오직 단 한 명만이 살아남는다!  올 가을, 강렬하고 스피디한 죽음의 레이스가 시작된다!  살인 누명을 쓰고 감옥에 들어간 전직 레이싱 선수 젠슨(제이슨 스테이섬)은 교도소장 헤네시(조안 앨런)에게 무차별 파괴 레이싱 ‘데스 레이스’의 출전을 제안받는다. ''데스 레이스''의 최고 인기 레이서인 프랑켄슈타인이 4승 후 사망하자 경기의 인기 하락을 우려한 헤네시는 프랑켄슈타인의 죽음을 숨기고 젠슨에게 프랑켄슈타인의 대역을 요구한 것. 또한 만약 1승을 올린다면 젠슨은 교도소에서 나가 자유의 몸이 될 수 있는 조건이 있다. 이에 레이싱 출전을 결심한 젠슨은 여성 파트너 케이스(나탈리 마르티네즈)의 도움을 받아 단 한 사람만이 살아남을 수 있는 죽음의 레이스를 시작한다.', 'https://image.tmdb.org/t/p/w500/pXD8j4RWUXLN9o1nitrBMPlWC9O.jpg', 2008, 0, 0, '2026-06-08 07:29:52.867342', 'GB');
INSERT INTO public.movies VALUES (8823, 7446, '트로픽 썬더', '["Action", "Comedy", "Adventure"]', 'Ben Stiller', '["Ben Stiller", "Robert Downey Jr.", "Jack Black", "Jay Baruchel", "Brandon T. Jackson"]', '할리우드 액션스타 터그 스피드맨(벤 스틸러), 오스카 5회 수상에 빛나는 연기파 배우 커크 라자러스(로버트 다우니 주니어), 악명높은 코믹배우 제프 포트노이(잭 블랙)가 출연하는 초특급 전쟁 블록버스터가 기획된다. 하지만 수습불능 자뻑 배우들의 기싸움으로 촬영장에는 끊임없이 문제가 발생하고, 결국 5일만에 제작비를 탕진한 감독은 제작자 레스 그로스맨(톰 크루즈)에게 심하게 추궁당한다. 원작자 클로버(닉 놀테)의 조언에 따라 영화의 리얼함을 위해 실제 정글로 배우들을 끌고 간 감독. 하지만 그곳에서 진짜 마약밀매업자들을 만나 생생한 전투를 벌이게 되는데... 과연 이들은 제대로 영화를 완성할 수 있을까?', 'https://image.tmdb.org/t/p/w500/y93vn3MZfsHKE3DJYTzdoZb81OL.jpg', 2008, 0, 0, '2026-06-08 07:29:54.482127', 'GB');
INSERT INTO public.movies VALUES (8824, 276907, '레전드', '["Crime", "Thriller"]', 'Brian Helgeland', '["Tom Hardy", "Emily Browning", "Christopher Eccleston", "David Thewlis", "Taron Egerton"]', '비틀즈와 함께,  60년대 영국의 아이콘이었던 쌍둥이 갱스터 형제!  레지 크레이 X 로니 크레이의 전설적인 이야기!  런던의 촌구석 이스트엔드에서 주먹 꽤나 쓰는 쌍둥이 형제로 이름을 날리던 레지 크레이 X 로니 크레이. 한날 한시에 태어났지만 정 반대의 성격을 가진 크레이 형제는 서로를 생각하는 우애만큼은 끈끈하다. 타고난 주먹과 뛰어난 사업 수완으로 마피아와 손잡고 법과 경찰을 피해 세력을 키워나가던 크레이 형제는 어느덧 런던의 밤을 장악하며 유명인사가 되어가지만, 곧 이들 형제에게 위기가 닥친다.  이성적인 형 레지는 연인 프랜시스와의 약속을 지키기 위해 위험한 갱스터 생활을 청산하고 능력 있는 사업가로 변신해 세력을 확장해 나가려 한다. 하지만 엉뚱하고 무모하기 짝이 없는 통제불능 동생 로니는 자신만의 방식으로 조직을 운영하며 사건 사고를 일으킨다.  매번 조직에 막대한 피해를 입히는 로니에게 점점 인내심을 잃어가는 레지. 자신의 방식을 인정하지 않는 형을 향한 불만을 쌓아가던 로니. 두 형제는 사사건건 부딪히기 시작하고, 급기야 로니는 수습 불가능의 대형 사고를 치고 마는데…', 'https://image.tmdb.org/t/p/w500/At85DnxWNh2SAdmlHRoSRhaKQuv.jpg', 2015, 0, 0, '2026-06-08 07:29:55.227649', 'GB');
INSERT INTO public.movies VALUES (8825, 264660, '엑스 마키나', '["Drama", "Sci-Fi"]', 'Alex Garland', '["Domhnall Gleeson", "Alicia Vikander", "Oscar Isaac", "Sonoya Mizuno", "Corey Johnson"]', '유능한 프로그래머 칼렙은 치열한 경쟁 끝에 인공지능 분야의 천재 개발자 네이든의 새로운 프로젝트에 참여하게 된다. 외부엔 알려지지 않은 그의 비밀 연구소로 초대받은 칼렙은 그 곳에서 네이든이 창조한 매혹적인 A.I. 에이바를 만나게 된다. 그녀의 인격과 감정이 진짜인지 아니면 프로그래밍 된 것인 지를 밝히는 테스트를 진행하지만. 점점 에이바도 그녀의 창조자 네이든도 그리고 자신의 존재조차 믿을 수 없게 되고 모든 것을 의심하게 되는데…', 'https://image.tmdb.org/t/p/w500/a3tuxUHT64cl4gPqWbtsLyKdzJS.jpg', 2015, 0, 0, '2026-06-08 07:29:56.018086', 'GB');
INSERT INTO public.movies VALUES (8826, 516729, '패딩턴: 페루에 가다!', '["Adventure", "Comedy", "Family"]', 'Dougal Wilson', '["Ben Whishaw", "Hugh Bonneville", "Emily Mortimer", "Samuel Joslin", "Madeleine Harris"]', '영국 국민으로 거듭난 ‘패딩턴’에게 어느 날 고향인 페루에서 날아온 의문의 편지 한 통. “루시 숙모님이 사라졌어요!” 지도 한 장만 남긴 채 감쪽같이 사라져 버린 ‘루시’ 숙모를 찾아 떠난 ‘패딩턴’과 브라운 가족은 페루의 정글을 둘러싼 비밀을 찾아 모험을 떠나게 되는데…', 'https://image.tmdb.org/t/p/w500/1rfxGlRaFe8bqKOtebXl2CFel8F.jpg', 2024, 0, 0, '2026-06-08 07:29:56.811222', 'GB');
INSERT INTO public.movies VALUES (8827, 9654, '이탈리안 잡', '["Action", "Crime"]', 'F. Gary Gray', '["Mark Wahlberg", "Charlize Theron", "Edward Norton", "Seth Green", "Jason Statham"]', '금고털이 전문범인 존 브릿저는 외동딸 스텔라의 만류로 은퇴를 결심하지만, 동료인 찰리의 권유를 뿌리치지 못 하고 마지막으로 한탕만 더하기로 한다. 이탈리아의 베니스에서 3천 5백만 달러어치의 금괴가 든 금고를 그들 각각의 두뇌 플레이와 각자의 전문 실력을 발휘하여 쥐도 새도 모르게 탈취한다. 그러나 수익금을 배분하기도 전에 같은 동료인 스티브가 이들을 배반하여 모두를 호수에 수장 시키고 금고를 빼앗아 달아나버린다. 그 와중에 멤버의 대부 격인 존은 죽고, 살아남은 찰리와 나머지 동료들은 스티브에 대한 복수를 준비 한다.  스티브가 헐리웃에 숨어산다는 정보를 입수한 이들은 스티브의 금고를 탈취할 계획을 세운다. 무슨 금고든지 열수 있는 금고 열이 최고 전문가인 존의 딸 스텔라도 아버지의 원수를 갚기 위하여 이들에게 합류한다. 한편, 죽은줄 알았던 옛 동료들이 나타나자 긴장한 스티브는 금괴가 든 금고를 멕시코로 옮길 결심을 한다.그러나 이들이 누구인가! 그들은 피라미드 저 밑에 숨겨도 찾아낼 수 있는 최고의 폭약 전문가, 컴퓨터 전문가,자동차 전문가로 구성된 실력 군단 인 것이다! 그들은 이탈리아에서 보여 주었던 그들의 실력을 다시 보여 주기 위하여 치밀한 계획 하에 스티브의 금고를 다시 나꿔챌 작전을 세우는데.', 'https://image.tmdb.org/t/p/w500/sAyAtBkqD5yirImZQKfvLzlH1EZ.jpg', 2003, 0, 0, '2026-06-08 07:29:57.852692', 'GB');
INSERT INTO public.movies VALUES (8828, 278927, '정글북', '["Adventure", "Family", "Fantasy"]', 'Jon Favreau', '["Neel Sethi", "Bill Murray", "Ben Kingsley", "Idris Elba", "Scarlett Johansson"]', '늑대 무리에서 길러진 인간 소년 모글리는 정글이 자신의 보금자리이고, 어미 늑대 락샤와 늑대들의 리더 아킬라가 자신의 부모라 여기며 살고 있다. 하지만 인간이 휘두른 횃불에 큰 상처를 입고 인간을 증오하게 된 정글의 무법자 쉬어칸은 모글리를 정글에서 쫓아내려 한다. 모글리는 쉬어칸의 위협을 피해 인간 세상으로 향하고, 그 여정에 든든한 멘토 바기라와 유쾌한 곰 발루가 동행한다. 정글을 떠나는 여정은 끝없는 위협으로 가득 차 있고, 쉬어칸 역시 그를 바짝 쫓는데...', 'https://image.tmdb.org/t/p/w500/aJfKSqabM08aGnaqijW9que0Wsp.jpg', 2016, 0, 0, '2026-06-08 07:29:58.605512', 'GB');
INSERT INTO public.movies VALUES (8829, 96721, '러시: 더 라이벌', '["Drama", "Action"]', 'Ron Howard', '["Chris Hemsworth", "Daniel Brühl", "Olivia Wilde", "Alexandra Maria Lara", "Pierfrancesco Favino"]', '타고난 천재 레이서 제임스 헌트와 철저한 노력파 천재 니키 라우다. 그들은 매 경기마다 라이벌로 부딪히며 치열한 접전을 벌이게 된다. 완벽한 설계로 승부를 완성하는 니키가 자신의 뒤를 바짝 뒤쫓자 스피드만큼은 최고라고 자신했던 제임스는 긴장하게 된다. 그리고 1976년, 레이서들에게 악명 높은 독일의 뉘르부르크링 서킷. 한치 앞을 내다볼 수 없는 두 천재 레이서의 라이벌 대결에 전 세계의 이목이 집중된 순간, 거센 비가 내리던 노르트슐라이페에서 한 대의 차량이 문제를 일으키며 불길에 휩싸이게 되는데...', 'https://image.tmdb.org/t/p/w500/yYrBvqOIdUkTZrIw5kmUxszFjtC.jpg', 2013, 0, 0, '2026-06-08 07:29:59.266181', 'GB');
INSERT INTO public.movies VALUES (8830, 440471, '이스케이프 플랜 2: 하데스', '["Action", "Thriller", "Crime", "Mystery", "Sci-Fi"]', 'Steven C. Miller', '["Sylvester Stallone", "Dave Bautista", "Jesse Metcalfe", "50 Cent", "Huang Xiaoming"]', '지상 최고의 탈출 전문가 ‘브레슬린’ 한 때 동료였던 ‘킴브럴’의 배신으로 세계 최고의 지하 감옥 하데스에 동료를 구하기 위해 스스로 들어간다. 하지만 하데스는 24시간 마다 위치가 바뀌고, 최첨단 AI 로봇 시스템으로 관리되는 탈옥 확률 0%의 최악의 감옥! 누구도 내 보낸 적 없는 최악의 감옥 하데스 VS 세계 최고의 탈출 전문가! 전대미문의 탈출이 지금 시작된다!', 'https://image.tmdb.org/t/p/w500/lLi9FliXJAAAVlZOms1ZYajeED.jpg', 2018, 0, 0, '2026-06-08 07:29:59.940528', 'GB');
INSERT INTO public.movies VALUES (8836, 13597, '라비린스', '["Adventure", "Family", "Fantasy"]', 'Jim Henson', '["David Bowie", "Jennifer Connelly", "Toby Froud", "Shelley Thompson", "Christopher Malcolm"]', '사라는 아빠와 계모 그리고 이복동생인 토비와 함께 사는 소녀이다. 부모가 외출할 때마다 토비를 돌봐야하는 사라는 어느날 밤, 토비가 울어대자 이야기책에 나오는 대로 고블린의 주문을 외우면서 고블린의 왕에게 토비를 데려가버리라고 빈다. 그 순간 고블린의 왕인 자레드가 나타나 토비를 데려가면서 토비를 찾으려면 미로 중앙의 고블린성으로 오라는 말을 남긴다. 사라는 토비를 되찾기 위해 지하세계의 미로속으로 들어가고 도중에 호글이라는 난쟁이, 루도라는 덩치 큰 원숭이, 그리고 용감한 강아지 기사 디디머스 등과 친구가 된다. 자레드의 끊임없는 방해를 이기면서 드디어 고블린성에 도착한 사라는 자레드가 정한 시간이 지나기 직전 고블린의 주문으로 토비를 되찾아 집으로 돌아온다. 토비를 귀찮아하기만 했던 사라는 미로 여행을 통해 동생에 대한 사랑과 과거의 추억에 있었던 장난감과 이야기 주인공들의 소중함을 새삼 깨닫게 된다.', 'https://image.tmdb.org/t/p/w500/8SoFSFB60RZfTtWy0O1fnozDJ7P.jpg', 1986, 0, 0, '2026-06-08 07:30:03.950571', 'GB');
INSERT INTO public.movies VALUES (8837, 657, '007 위기일발', '["Action", "Thriller", "Adventure"]', 'Terence Young', '["Sean Connery", "Daniela Bianchi", "Pedro Armendáriz", "Robert Shaw", "Lotte Lenya"]', '스펙터의 두목 블로펠트는 러시아의 새 암호 해독기를 손에 넣기 위해 터키에 있는 소련의 암호부 여직원 타티아나를 이용한다. 당시 소련의 스메르쉬 작전국 국장으로 일했던 클래브 대령은 충성심이 높은 그녀를 불러내고, 제임스 본드를 유인해 낸 후 함정에 빠뜨려서 죽이려 한다.  실비아와 달콤한 시간을 보내던 제임스 본드는 국장의 호출을 받고, 무기 담당 Q에게서 비밀장치가 있는 가방을 받는다. 스펙터 일당과 KGB의 추척을 받던 국장과 본드는 KGB가 고용한 불가리아인 살인 청부업자 크릴렌쿠를 저격하게 되는데...', 'https://image.tmdb.org/t/p/w500/kZ90T8hrgHmr2DDv6kRyhMEYta8.jpg', 1963, 0, 0, '2026-06-08 07:30:04.626621', 'GB');
INSERT INTO public.movies VALUES (8838, 452832, '세레니티', '["Thriller", "Mystery", "Drama"]', 'Steven Knight', '["Matthew McConaughey", "Anne Hathaway", "Jason Clarke", "Diane Lane", "Djimon Hounsou"]', '서로의 사정을 속속들이 아는 낯선 섬에서 누구도 잡지 못한 전설의 참치 낚시에 집착하는 선장. 어느 날, 이혼한 전처가 찾아오고 천만 달러를 건 위험한 거래를 제안한다. 평온했던 섬사람들은 변하기 시작하고 그를 조여오는 사건들이 물밀 듯이 덮쳐오는데… 규칙을 낚는 순간 상상할 수 없는 게임이 시작된다!', 'https://image.tmdb.org/t/p/w500/ryLgpeWPJ2ZwUF0oA0WBKOb73GJ.jpg', 2019, 0, 0, '2026-06-08 07:30:05.288904', 'GB');
INSERT INTO public.movies VALUES (8839, 13971, '와일드 차일드', '["Comedy", "Drama", "Romance"]', 'Nick Moore', '["Emma Roberts", "Alex Pettyfer", "Natasha Richardson", "Kimberley Nixon", "Juno Temple"]', '아빠의 여자친구가 집에 이사짐을 들여놓는 날, 파피는 친구들과 함께 그녀의 짐을 엉망으로 만든다. 화가 난 아빠는 파피를 영국으로 유학 보낸다. 부자 아빠 제리의 덕택으로 부러울게 없는 파피는 무슨일이든 자기 감정, 기분대로 말하고 행동하는 것때문에 같은방 친구와 티격태격한다. 그러나 구김없고 명랑하고 소릭한 파피에게 호감을 갖기 시작하는 친구들 키키, 케이트, 조시.  파피는 학교에서 일주일 정도만 있다가 다시 캘리포니아의 집에 돌아갈 생각으로 늘 말썽을 피우고 문제를 일으킨다. 하지만 자신의 뜻대로 되지 않자 케이트의 제안을 받아들여 퇴학 당할만한 일들을 꾸미기로 한다. 결국 그들의 계획은 교장선생님이 아들 프레디를 사귄다는 소문이 나게하자며 치밀한 계획을 세우자고 한다. 이런 계획으로 인해 프레디와 점점 가까워지고 학생회장 해리엇의 질투는 극에 달하는데….', 'https://image.tmdb.org/t/p/w500/xwbFEPubG4wroLDZdmTWRGNnnWf.jpg', 2008, 0, 0, '2026-06-08 07:30:05.960705', 'GB');
INSERT INTO public.movies VALUES (8840, 4584, '센스 앤 센서빌리티', '["Drama", "Romance"]', 'Ang Lee', '["Emma Thompson", "Kate Winslet", "Alan Rickman", "Hugh Grant", "Gemma Jones"]', '18세기 말 영국 노아랜드 파크(Norland Park)가에 슬픔이 깔린다. 대쉬우드 씨가 갑자기 사망한 것이다. 그의 재산은 유산법에 따라 첫번째 결혼에서 얻은 아들 존과 그의 아내 패니에게 돌아간다. 대쉬우드의 두 번째 부인과 그녀의 세 딸 엘리노어, 마리안네, 마가레테는 살던 집을 빼앗기고 먼 친척이 제공한 작은 오두막으로 이사한다. 연 500파운드로 그들은 살아야 한다.  그들이 새 거주지로 옮기기 전에 엘리노어는 패니의 순진한 오빠 에드워드를 알게 되고 사랑하게 된다. 그녀가 자신의 감정을 표현하기도 전에 패니는 그녀의 오빠를 런던으로 재빨리 돌려보낸다. 그곳에서 그는 자신에게 맞는 훌륭한 배필을 만나 결혼해야 한다. 새 거주지에서 대쉬우드 가족들은 쉽게 적응하고, 엘리노어는 에드워드에 대한 갈망을 감추고 가족의 경제를 책임지며 살아간다.  마리안네에게 두 명의 구혼자가 나타난다. 운명적으로 만나게 되는 신사 코로넬 브란돈과 경박하고 쾌활하며 멋있는 윌러비가 있다. 런던에서 여름휴가를 보내러 온 윌러비는 마리안네의 마음을 사로잡는다. 그러나 그는 그녀를 떠나 런던으로 돌아간다. 엘리노어는 에드워드의 약혼소식을 접하고 상처를 입는다.  대쉬우드가의 자매들은 런던으로 간다. 그곳에서 마리안네는 윌러비가 약혼한 후 곧 다른 여자와 결혼한다는 것을 알게 되고, 엘리노어도 결혼계획을 앞둔 에드워드를 만난다. 고향으로 돌아가는 길에 병이 든 마리안네는 언니와 코로넬 브란돈의 정성어린 보살핌으로 낫게 된다.  두 자매는 그들의 경험으로 인생에 대해 알게 된다. 첫사랑의 실패로 보다 성숙해진 그들은 앞으로 그들을 기다릴 진정한 만남을 기대한다.', 'https://image.tmdb.org/t/p/w500/cBK2yL3HqhFvIVd7lLtazWlRZPR.jpg', 1995, 0, 0, '2026-06-08 07:30:06.633442', 'GB');
INSERT INTO public.movies VALUES (8841, 762, '몬티 파이튼의 성배', '["Adventure", "Comedy", "Fantasy"]', 'Terry Jones', '["Graham Chapman", "John Cleese", "Eric Idle", "Terry Gilliam", "Terry Jones"]', '아더왕은 영국 전역을 돌아다니며 자신들을 보좌할 기사들을 모집한다. 결국 용맹한 기사들 랑셀럿, 로빈, 베드베어 그리고 갈라드를 합류시킨 아더왕은 신의 계시에 따라 잃어버린 성배를 찾으러간다. 각각 흩어져 성배의 수색을 하지만 용맹한만큼 멍청하기도한 기사들은 성배를 찾기는 커녕 소동만을 일으키고 만다.', 'https://image.tmdb.org/t/p/w500/h3rksLHevpCbHfSoaUXm85nt2CH.jpg', 1975, 0, 0, '2026-06-08 07:30:07.289726', 'GB');
INSERT INTO public.movies VALUES (8842, 1272, '선샤인', '["Sci-Fi", "Thriller"]', 'Danny Boyle', '["Cillian Murphy", "Rose Byrne", "Chris Evans", "Michelle Yeoh", "Cliff Curtis"]', '2057년, 태양이 죽어가고, 인류는 멸망의 위기에 처하게 된다. 지구에서는 마지막 방법으로 태양을 폭파시켜 다시 태양을 되살릴 8명의 대원들을 실은 이카루스 2호를 우주로 보낸다.  오랜 비행 끝에 마침내 태양에 근접한 이카루스 2호. 하지만 마지막 임무를 수행하려던 찰나에 예기치 않은 사고가 발생하고 대원들이 하나둘씩 사라진다. 이카루스 2호는 삽시간에 혼란에 휩싸이고 어떤 누구도 생존할 수 없을 지경에 처하게 된다. 그리고 서서히 드러나는 의문의 존재.. 과연 누군가 살아남아 태양을 구할수 있을것인가?', 'https://image.tmdb.org/t/p/w500/z7IUV9BVDdN0rvgm0UXNRrhVu8X.jpg', 2007, 0, 0, '2026-06-08 07:30:07.976456', 'GB');
INSERT INTO public.movies VALUES (8843, 1511789, 'Captain Hook: The Cursed Tides', '["Adventure", "Action", "Horror"]', 'Lars Janssen', '["Sean Cronin", "Ewen Weatherburn", "Cameron Ashplant", "Richard Rowden", "Destiny Viva"]', NULL, 'https://image.tmdb.org/t/p/w500/oKE2xPJs87V9DbDmoo8igAsDeH1.jpg', 2025, 0, 0, '2026-06-08 07:30:09.36162', 'GB');
INSERT INTO public.movies VALUES (8844, 1281, '빈', '["Family", "Adventure", "Comedy"]', 'Mel Smith', '["Rowan Atkinson", "Peter MacNicol", "Pamela Reed", "Tricia Vessey", "Andrew Lawrence"]', '영국 왕립 미술관(Royal National Gallery, London) 최악의 직원 빈(Mr. Bean: 로완 아킨슨 분)이 하는 일이란 기껏 한쪽 구석에 앉아 졸거나 빈둥돼는 것이 전부다. 하지만 모두가 꺼려하는 빈을 유독 왕립 미술관 회장만이 전폭적으로 지지하고 있다. 언제나 그렇듯 왕립 미술관 이사회의 가장 중요한 안건은 천하의 사고뭉치 빈을 쫓아내는 것.  그러던 어느날, 빈을 사라지게 할 호재가 생겼다. 미국 최고의 걸작 ''휘슬러의 어머니''의 본국 송환에 앞서 그리어슨 미술관(Grierson Art Gallery, Los Angeles)은 대대적인 기념 행사를 계획한다. 그 일환으로 영국 왕립 미술관에 저명한 박사를 초청한 것이다. 이사회는 빈을 대신 보내기로 결정하고, 빈은 열렬한 환성을 받으며 미국으로 향한다. 하지만 빈은 처음 도착한 공항에서부터 불법 총기 소지자로 오인받아 공항을 아수라장으로 만든다. 이제 그가 지나는 곳은 모두가 혼돈과 무질서의 세계로 뒤덮히기 시작한다.  한편, 영문도 모르는 채 빈을 최고의 미술학자로 오인한 그리어슨 미술관측은 소수의 관계자들만이 모인 자리에서 ''휘슬러의 어머니''를 최초로 공개한다. 모두가 잠시 자리를 뜬 사이, 빈과 ''휘슬러의 어머니''의 너무도 끔찍한 악연이 시작되는데.', 'https://image.tmdb.org/t/p/w500/IwrDPrB4d2DMcpnGkvan46yINL.jpg', 1997, 0, 0, '2026-06-08 07:30:10.038604', 'GB');
INSERT INTO public.movies VALUES (8845, 189, '씬 시티: 다크히어로의 부활', '["Action", "Crime", "Thriller"]', 'Robert Rodriguez', '["Jessica Alba", "Bruce Willis", "Mickey Rourke", "Josh Brolin", "Joseph Gordon-Levitt"]', '씬 시티의 절대권력 ‘로어크’와의 도박판에 끼어든 겁 없는 겜블러 ‘조니’(조셉 고든-레빗)는 도박에서는 승리하지만 ‘로어크’에게 처절한 응징을 당하게 되고 그를 향한 복수의 칼날을 간다. 부패한 권력의 도시 씬 시티의 마지막 로맨티스트 ‘드와이트’(조슈 브롤린)는 용서를 구하는 옛 연인 ‘아바’(에바 그린)의 유혹에 넘어가 그녀의 남편을 살해하지만 결국 그 자신도 ‘아바’에 의해 위험에 처한다. 밤의 여신 ‘낸시’(제시카 알바)는 자신의 은인이자 연인 ‘하티건’(브루스 윌리스)을 잃고 ‘하티건’을 죽음으로 몰고 간 ‘로어크’를 향한 복수를 다짐한다. 이 모든 상황을 지켜보던 도시의 지배자 ‘마브’(미키 루크)는 이들의 복수에 가세한다.  씬 시티의 절대 악 ‘로어크’는 과연 제거 될 수 있을 것인가!  다크히어로의 부활을 맞이하라!', 'https://image.tmdb.org/t/p/w500/7seL5jPNNmhY5r1KdW6rR45VJZa.jpg', 2014, 0, 0, '2026-06-08 07:30:10.718252', 'GB');
INSERT INTO public.movies VALUES (8846, 1310568, 'Murder at the Embassy', '["Mystery", "Thriller", "Action"]', 'Stephen Shimek', '["Mischa Barton", "Richard Dillane", "Mido Hamada", "Antonia Bernath", "Kojo Attah"]', NULL, 'https://image.tmdb.org/t/p/w500/3DBmBItPdy0A2ol59jgHhS54Lua.jpg', 2025, 0, 0, '2026-06-08 07:30:11.377475', 'GB');
INSERT INTO public.movies VALUES (8847, 1232569, 'Pinocchio: Unstrung', '["Horror", "Fantasy", "Mystery"]', 'Rhys Frake-Waterfield', '["Jude Evan Lloyd", "Robert Englund", "Cameron Bell", "Jessica Balmer", "Richard Brake"]', NULL, 'https://image.tmdb.org/t/p/w500/sqhfUrPEeAlFf684FsVa8v1GYCD.jpg', 2026, 0, 0, '2026-06-08 07:30:12.047037', 'GB');
INSERT INTO public.movies VALUES (8848, 794, '오멘', '["Horror", "Thriller"]', 'Richard Donner', '["Gregory Peck", "Lee Remick", "David Warner", "Billie Whitelaw", "Harvey Stephens"]', '6월 6일 새벽 6시 로마  갓 태어난 아들이 죽었다는 소식을 들은 쏜 대사는 같은 시각 같은 병원에서 태어난 데미안을 아무도 모르게 데려와 친자식처럼 키운다. 5년 뒤 유모가 데미안을 부르며 건물 난간에서 떨어져 목 매달아 죽는 이상한 사건이 발생한다. 브레넌 신부라는 사람이 쏜 대사를 찾아와 데미안은 일류의 파멸을 위해 보내진 악마의 아들이라는 사실을 듣게 된다. 또 데미안을 죽이지 않으면, 부인도 뱃속에 든 태아도 죽게 되며 데미안은 쏜 대사의 직위와 재산을 발판으로 전세계를 악마의 손아귀에 넣으려 하고, 이는 요한 계시록에 예언되어 있다고 한다. 그러던 중 신부의 예언대로 부인이 이층에서 떨어져 아이가 유산되고 신부는 비명에 횡사한다. 무당 부겐하겐을 찾아가 없애는 법을 듣고 집에 돌아온 쏜 대사는 데미안이 악마의 아들이란 표시 666이란 점이 머리카락 밑에 있는 걸 확인하고 죽이려한다. 이때 비밀이 밝혀지자 데미안을 보호하고 있는 저승 사자인 데미안의 새 유모가 쏜에게 달려들자, 결국 쏜은 유모에게 칼을 드는데...', 'https://image.tmdb.org/t/p/w500/sJ699i4etPEVM0Atb0O8PWofrCr.jpg', 1976, 0, 0, '2026-06-08 07:30:12.707922', 'GB');
INSERT INTO public.movies VALUES (8849, 947, '아라비아의 로렌스', '["Adventure", "History"]', 'David Lean', '["Peter O''Toole", "Alec Guinness", "Omar Sharif", "Anthony Quinn", "Jack Hawkins"]', '영국 정보국 소속 장교 로렌스 는 1차대전 중 중동지역의 전투에서 아랍 부족의 지원을 받기 위해 아랍 지역으로 파견된다. 그런데 그는 영국 정부가 바라던 것 이상으로 아랍의 지도자들을 사로 잡고 아랍의 독립을 위해 열심히 싸워 아랍 민족으로 부터 ‘아라비아의 로렌스’라는 영웅적인 칭호를 받게 된다. 그는 아랍 전사들을 이끌고 터키군들과 싸우면서 규율을 잡기 위해 남의 마을의 우물물을 마신 병사를 과감히 처형하는 등 독한 모습을 보여준다. 그러나 그의 그런 용맹성은 터키 군에게 포로로 잡힌 후 그곳에서 받은 성적 학대를 통해 병적으로 발전된다. 그리고 마침내 영국 정부의 소환을 받고 런던으로 돌아오지만 중동으로 보내 줄 것을 요구하면서 사막으로 돌아가길 원한다. 그러나 이미 정치적으로 타결이 된 아라비아 사막은 그를 원치 않았는데.', 'https://image.tmdb.org/t/p/w500/p2PG2nXE4e6piHdAcDLhDlCA30E.jpg', 1962, 0, 0, '2026-06-08 07:30:13.394185', 'GB');
INSERT INTO public.movies VALUES (8850, 200727, '러브, 로지', '["Romance", "Drama", "Comedy"]', 'Christian Ditter', '["Lily Collins", "Sam Claflin", "Christian Cooke", "Tamsin Egerton", "Suki Waterhouse"]', '어릴 때부터 모든 것을 함께 겪어온 단짝 로지와 알렉스는 고등학교 졸업 후 영국의 작은 고향마을을 떠나 미국 보스턴의 대학에 함께 가기로 약속한다. 하지만 서로의 감정을 숨긴 채 각자 다른 파트너와 간 졸업파티에서 한 순간의 실수로 전혀 다른 삶을 살게 된 두 사람. 미국에서 계획대로 인생을 설계해 나가는 알렉스와 달리 로지는 꿈을 접은 채 고향인 영국의 호텔에서 일한다. 몇 년 후, 보고 싶다는 알렉스의 연락을 받은 로지는 다시 한번 희망을 품고 보스톤으로 향하지만 이미 알렉스의 옆에는 다른 여자가 서있는데…', 'https://image.tmdb.org/t/p/w500/pJmYm15nC0mHm5CAoD1WhOE1Jsi.jpg', 2014, 0, 0, '2026-06-08 07:30:14.059874', 'GB');
INSERT INTO public.movies VALUES (8851, 1522923, '세이프 하우스', '["Action", "Thriller"]', 'Jamie Marshall', '["Lucien Laviscount", "Hannah John-Kamen", "Lewis Tan", "Holt McCallany", "Ethan Embry"]', '부통령의 차량이 테러를 당한 후, 안전 가옥에 모인 각기 다른 특수대원 6명이 오히려 갇히게 되고 서로를 의심하고 안가를 공격하는 테러리스들과 대결하며 범인을 찾는 이야기', 'https://image.tmdb.org/t/p/w500/k616WeRV8tC0bKOKqLv2dkS3S5J.jpg', 2025, 0, 0, '2026-06-08 07:30:14.747379', 'GB');
